window.VOCAB = {"chapters": [{"id": "p1c1", "part": 1, "chapter": 1, "title": "Political Systems", "file": "cpge_vocab_part1_chapter1_political_systems.html", "count": 58, "sections": [{"title": "A. Core political systems", "entries": [{"term": "democracy", "ipa": "/dɪˈmɒkrəsi/", "pron": "di-MOK-ruh-see", "fr": "démocratie", "def": "A political system in which citizens choose their leaders through elections and have political rights and freedoms.", "ex": "A healthy democracy requires free elections, independent courts and a free press."}, {"term": "representative democracy", "ipa": "/ˌreprɪˈzentətɪv dɪˈmɒkrəsi/", "pron": "rep-ri-ZEN-tuh-tiv di-MOK-ruh-see", "fr": "démocratie représentative", "def": "A form of democracy in which citizens elect representatives to make political decisions on their behalf.", "ex": "In a representative democracy, voters do not vote on every law directly."}, {"term": "direct democracy", "ipa": "/dəˌrekt dɪˈmɒkrəsi/", "pron": "duh-REKT di-MOK-ruh-see", "fr": "démocratie directe", "def": "A system in which citizens vote directly on laws or major decisions, often through referendums.", "ex": "Referendums are often presented as a tool of direct democracy."}, {"term": "republic", "ipa": "/rɪˈpʌblɪk/", "pron": "ri-PUB-lik", "fr": "république", "def": "A state in which power is held by elected representatives and not by a hereditary monarch.", "ex": "The United States is a federal republic."}, {"term": "monarchy", "ipa": "/ˈmɒnəki/", "pron": "MON-uh-kee", "fr": "monarchie", "def": "A political system in which a king or queen is the head of state, usually by inheritance.", "ex": "The United Kingdom is a constitutional monarchy."}, {"term": "constitutional monarchy", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈmɒnəki/", "pron": "kon-sti-TOO-shuh-nuhl MON-uh-kee", "fr": "monarchie constitutionnelle", "def": "A monarchy in which the monarch’s powers are limited by a constitution and elected institutions.", "ex": "In a constitutional monarchy, the monarch usually has a symbolic role."}, {"term": "parliamentary system", "ipa": "/ˌpɑːləˈmentəri ˈsɪstəm/", "pron": "par-luh-MEN-tuh-ree SIS-tuhm", "fr": "régime parlementaire", "def": "A system in which the government depends on the support of parliament to remain in power.", "ex": "In a parliamentary system, the prime minister usually leads the majority in parliament."}, {"term": "presidential system", "ipa": "/ˌprezɪˈdenʃəl ˈsɪstəm/", "pron": "prez-i-DEN-shuhl SIS-tuhm", "fr": "régime présidentiel", "def": "A system in which the president is both head of state and head of government, with powers separate from the legislature.", "ex": "The American political system is often described as a presidential system."}, {"term": "federal system", "ipa": "/ˈfedərəl ˈsɪstəm/", "pron": "FED-uh-ruhl SIS-tuhm", "fr": "système fédéral", "def": "A system in which power is divided between a central government and regional governments.", "ex": "Federal systems can give states or regions significant autonomy."}, {"term": "unitary state", "ipa": "/ˈjuːnɪtəri steɪt/", "pron": "YOO-ni-tuh-ree stayt", "fr": "État unitaire", "def": "A state in which political authority is mainly held by the central government.", "ex": "France is often described as a unitary state, despite decentralisation."}, {"term": "regime", "ipa": "/reɪˈʒiːm/", "pron": "ray-ZHEEM", "fr": "régime", "def": "A form of government, especially one considered in terms of how power is organised or exercised.", "ex": "The article describes how the regime tightened its control over the media."}, {"term": "authoritarianism", "ipa": "/ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme", "def": "A political system in which power is concentrated in the hands of a leader or ruling group and political freedoms are limited.", "ex": "Authoritarianism often weakens independent institutions and civil liberties."}, {"term": "dictatorship", "ipa": "/dɪkˈteɪtəʃɪp/", "pron": "dik-TAY-tuh-ship", "fr": "dictature", "def": "A system in which one person or a small group holds absolute political power, usually without free elections.", "ex": "The dictatorship banned opposition parties and censored the press."}, {"term": "autocracy", "ipa": "/ɔːˈtɒkrəsi/", "pron": "aw-TOK-ruh-see", "fr": "autocratie", "def": "A system in which one ruler has unlimited power and is not effectively controlled by laws or institutions.", "ex": "Critics argue that the country has gradually moved towards autocracy."}, {"term": "theocracy", "ipa": "/θiˈɒkrəsi/", "pron": "thee-OK-ruh-see", "fr": "théocratie", "def": "A system in which religious authorities or religious law play the central role in government.", "ex": "In a theocracy, political legitimacy is often based on religious authority."}, {"term": "oligarchy", "ipa": "/ˈɒlɪɡɑːki/", "pron": "OL-i-gar-kee", "fr": "oligarchie", "def": "A system in which a small wealthy or powerful group controls political power.", "ex": "Some observers fear that economic inequality can turn a democracy into an oligarchy."}]}, {"title": "B. Power, legitimacy and institutions", "entries": [{"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The supreme authority of a state to govern itself and make its own decisions.", "ex": "Brexit supporters often argued that leaving the EU would restore national sovereignty."}, {"term": "legitimacy", "ipa": "/lɪˈdʒɪtɪməsi/", "pron": "li-JIT-i-muh-see", "fr": "légitimité", "def": "The belief that a government, institution or leader has the right to rule or make decisions.", "ex": "A government may lose legitimacy if it ignores the rule of law."}, {"term": "authority", "ipa": "/ɔːˈθɒrəti/", "pron": "aw-THOR-uh-tee", "fr": "autorité", "def": "The official power to give orders, make decisions or enforce rules.", "ex": "The crisis challenged the authority of the central government."}, {"term": "governance", "ipa": "/ˈɡʌvənəns/", "pron": "GUV-uh-nuhns", "fr": "gouvernance", "def": "The way a country, institution or organisation is managed and controlled.", "ex": "Good governance requires transparency, accountability and competence."}, {"term": "separation of powers", "ipa": "/ˌsepəˈreɪʃən əv ˈpaʊəz/", "pron": "sep-uh-RAY-shuhn ov POW-uhz", "fr": "séparation des pouvoirs", "def": "The division of political power among different branches of government, usually the executive, legislature and judiciary.", "ex": "The separation of powers is meant to prevent one branch from becoming too powerful."}, {"term": "checks and balances", "ipa": "/ˌtʃeks ən ˈbælənsɪz/", "pron": "cheks uhn BAL-uhn-siz", "fr": "contre-pouvoirs ; système de freins et contrepoids", "def": "A system in which each branch of government can limit the power of the others.", "ex": "Checks and balances are central to the American Constitution."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including leaders and governments, must obey the law.", "ex": "Independent courts are essential to uphold the rule of law."}, {"term": "constitution", "ipa": "/ˌkɒnstɪˈtjuːʃən/", "pron": "kon-sti-TOO-shuhn", "fr": "constitution", "def": "A set of fundamental rules that define how a state is organised and how power is limited.", "ex": "A constitution can protect citizens from abuses of power."}, {"term": "executive branch", "ipa": "/ɪɡˈzekjətɪv brɑːntʃ/", "pron": "ig-ZEK-yuh-tiv branch", "fr": "pouvoir exécutif", "def": "The part of government responsible for implementing laws and running the state.", "ex": "In the United States, the president leads the executive branch."}, {"term": "legislature", "ipa": "/ˈledʒɪslətʃə/", "pron": "LEDJ-is-luh-chuh", "fr": "pouvoir législatif ; assemblée législative", "def": "The institution or body that makes laws, such as a parliament or congress.", "ex": "The legislature debated the new immigration bill for several weeks."}, {"term": "judiciary", "ipa": "/dʒuːˈdɪʃəri/", "pron": "joo-DISH-uh-ree", "fr": "pouvoir judiciaire ; système judiciaire", "def": "The system of courts and judges responsible for interpreting and applying the law.", "ex": "An independent judiciary is a key safeguard against authoritarianism."}, {"term": "civil service", "ipa": "/ˈsɪvəl ˈsɜːvɪs/", "pron": "SIV-uhl SUR-vis", "fr": "fonction publique ; administration", "def": "The permanent professional administration that helps implement government policy.", "ex": "The civil service is expected to remain politically neutral."}]}, {"title": "C. Elections, representation and participation", "entries": [{"term": "electorate", "ipa": "/ɪˈlektərət/", "pron": "i-LEK-tuh-ruht", "fr": "électorat", "def": "All the people who are allowed to vote in an election.", "ex": "The electorate was deeply divided over the issue of immigration."}, {"term": "suffrage", "ipa": "/ˈsʌfrɪdʒ/", "pron": "SUF-rij", "fr": "droit de vote ; suffrage", "def": "The right to vote in political elections.", "ex": "Universal suffrage was achieved gradually in many democracies."}, {"term": "franchise", "ipa": "/ˈfræntʃaɪz/", "pron": "FRAN-chize", "fr": "droit de vote ; franchise électorale", "def": "The legal right to vote; in politics, it is often used as a synonym for suffrage.", "ex": "Expanding the franchise changed the balance of political power."}, {"term": "constituency", "ipa": "/kənˈstɪtjuənsi/", "pron": "kuhn-STI-choo-uhn-see", "fr": "circonscription électorale", "def": "A geographical area whose voters elect a representative.", "ex": "The MP returned to her constituency after the parliamentary debate."}, {"term": "turnout", "ipa": "/ˈtɜːnaʊt/", "pron": "TURN-out", "fr": "taux de participation", "def": "The percentage or number of voters who actually vote in an election.", "ex": "Low turnout can raise questions about democratic engagement."}, {"term": "representation", "ipa": "/ˌreprɪzenˈteɪʃən/", "pron": "rep-ri-zen-TAY-shuhn", "fr": "représentation", "def": "The process or principle by which elected officials speak and act for citizens.", "ex": "Many critics argue that young people lack political representation."}, {"term": "mandate", "ipa": "/ˈmændeɪt/", "pron": "MAN-dayt", "fr": "mandat", "def": "The authority given to a politician or government by voters to carry out a programme.", "ex": "The prime minister claimed she had a clear mandate for reform."}, {"term": "referendum", "ipa": "/ˌrefəˈrendəm/", "pron": "ref-uh-REN-duhm", "fr": "référendum", "def": "A vote in which citizens are asked to accept or reject a specific proposal.", "ex": "The Brexit referendum reshaped British politics."}]}, {"title": "D. Democratic quality and political decline", "entries": [{"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected by law, such as freedom of speech, religion and assembly.", "ex": "Emergency laws can sometimes threaten civil liberties."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains ; droits de l'homme", "def": "Fundamental rights believed to belong to every person, regardless of nationality, status or identity.", "ex": "Human rights organisations condemned the arrests of opposition leaders."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; obligation de rendre des comptes", "def": "The obligation of leaders and institutions to explain their decisions and accept responsibility for them.", "ex": "Investigative journalism can increase political accountability."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PAIR-uhn-see", "fr": "transparence", "def": "Openness in decision-making, allowing citizens to see how and why decisions are made.", "ex": "Transparency is crucial to rebuild trust in public institutions."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Dishonest or illegal behaviour by people in power, often involving bribery or personal gain.", "ex": "Corruption scandals can destroy public trust in government."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "The control or suppression of information, speech, books or media by authorities.", "ex": "Censorship often increases when governments fear dissent."}, {"term": "dissent", "ipa": "/dɪˈsent/", "pron": "di-SENT", "fr": "dissidence ; désaccord politique", "def": "Public disagreement with official policies, dominant opinions or political authorities.", "ex": "Authoritarian regimes often try to silence dissent."}, {"term": "crackdown", "ipa": "/ˈkrækdaʊn/", "pron": "KRAK-down", "fr": "répression ; durcissement", "def": "Strong action taken by authorities to stop or punish behaviour they oppose.", "ex": "The crackdown on protesters was widely criticised abroad."}, {"term": "democratic backsliding", "ipa": "/ˌdeməˈkrætɪk ˈbækslaɪdɪŋ/", "pron": "dem-uh-KRAT-ik BAK-sly-ding", "fr": "recul démocratique ; régression démocratique", "def": "The gradual weakening of democratic institutions, rights and norms.", "ex": "Attacks on courts and journalists are often seen as signs of democratic backsliding."}, {"term": "illiberal democracy", "ipa": "/ɪˈlɪbərəl dɪˈmɒkrəsi/", "pron": "i-LIB-uh-ruhl di-MOK-ruh-see", "fr": "démocratie illibérale", "def": "A political system with elections but weak civil liberties, limited checks and balances, and pressure on independent institutions.", "ex": "An illiberal democracy may hold elections while restricting media freedom."}, {"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov speech", "fr": "liberté d'expression", "def": "The right to express opinions and ideas without unjustified government restriction.", "ex": "Freedom of speech is often at the centre of political debates in liberal democracies."}, {"term": "freedom of the press", "ipa": "/ˌfriːdəm əv ðə ˈpres/", "pron": "FREE-duhm ov thuh press", "fr": "liberté de la presse", "def": "The right of journalists and media organisations to report news and criticise power without censorship.", "ex": "Freedom of the press is essential for exposing corruption."}]}, {"title": "E. High-value verbs and collocations", "entries": [{"term": "to govern", "ipa": "/ˈɡʌvən/", "pron": "GUV-uhn", "fr": "gouverner", "def": "To officially control and manage a country, region or institution.", "ex": "It is easier to win an election than to govern effectively."}, {"term": "to rule", "ipa": "/ruːl/", "pron": "rool", "fr": "gouverner ; régner", "def": "To control a country or people, especially with official or political authority.", "ex": "The king ruled for more than thirty years."}, {"term": "to hold power", "ipa": "/həʊld ˈpaʊə/", "pron": "hohld POW-uh", "fr": "détenir le pouvoir", "def": "To possess political authority or control over institutions.", "ex": "The party has held power for more than a decade."}, {"term": "to come to power", "ipa": "/kʌm tə ˈpaʊə/", "pron": "kum tuh POW-uh", "fr": "arriver au pouvoir", "def": "To begin governing after an election, revolution or political change.", "ex": "The new coalition came to power after months of political deadlock."}, {"term": "to step down", "ipa": "/step ˈdaʊn/", "pron": "step down", "fr": "démissionner ; quitter ses fonctions", "def": "To leave an important position voluntarily, especially in politics.", "ex": "The minister was forced to step down after the scandal."}, {"term": "to undermine", "ipa": "/ˌʌndəˈmaɪn/", "pron": "un-duh-MYNE", "fr": "saper ; affaiblir", "def": "To weaken something gradually, especially trust, authority, democracy or institutions.", "ex": "Disinformation can undermine trust in democratic institutions."}, {"term": "to uphold", "ipa": "/ʌpˈhəʊld/", "pron": "up-HOHLD", "fr": "défendre ; faire respecter", "def": "To defend or maintain a law, principle or right.", "ex": "Courts are expected to uphold constitutional rights."}, {"term": "to enforce", "ipa": "/ɪnˈfɔːs/", "pron": "in-FORSS", "fr": "faire appliquer", "def": "To make sure that laws, rules or decisions are obeyed.", "ex": "A law is meaningless if the state cannot enforce it."}, {"term": "to curb", "ipa": "/kɜːb/", "pron": "curb", "fr": "limiter ; freiner ; endiguer", "def": "To limit or control something that is considered harmful or excessive.", "ex": "New rules were introduced to curb corruption."}, {"term": "to grant rights", "ipa": "/ɡrɑːnt ˈraɪts/", "pron": "grahnt rites", "fr": "accorder des droits", "def": "To officially give people legal or political rights.", "ex": "The reform granted voting rights to millions of citizens."}]}]}, {"id": "p1c2", "part": 1, "chapter": 2, "title": "Elections Campaigns", "file": "cpge_vocab_part1_chapter2_elections_campaigns_premium.html", "count": 65, "sections": [{"title": "A. Elections and voting basics", "entries": [{"term": "election", "ipa": "/ɪˈlekʃən/", "pron": "i-LEK-shuhn", "fr": "élection", "def": "A formal process in which people vote to choose a political leader or representative.", "ex": "The next general election is expected to focus on the economy and immigration."}, {"term": "general election", "ipa": "/ˌdʒenərəl ɪˈlekʃən/", "pron": "JEN-uh-ruhl i-LEK-shuhn", "fr": "élections législatives ; élections générales", "def": "An election in which voters choose representatives for the national legislature, and often indirectly determine the next government.", "ex": "The party hopes to win a majority in the next general election."}, {"term": "presidential election", "ipa": "/ˌprezɪˈdenʃəl ɪˈlekʃən/", "pron": "prez-i-DEN-shuhl i-LEK-shuhn", "fr": "élection présidentielle", "def": "An election in which voters choose a president.", "ex": "The presidential election has deeply divided the country."}, {"term": "midterm elections", "ipa": "/ˈmɪdtɜːm ɪˌlekʃənz/", "pron": "MID-term i-LEK-shuhnz", "fr": "élections de mi-mandat", "def": "Elections held halfway through a president’s term, especially in the United States.", "ex": "Midterm elections often become a referendum on the president’s record."}, {"term": "primary election", "ipa": "/ˈpraɪməri ɪˌlekʃən/", "pron": "PRY-muh-ree i-LEK-shuhn", "fr": "primaire", "def": "An election in which voters or party members choose a party’s candidate for a later election.", "ex": "The primary election revealed deep divisions within the party."}, {"term": "by-election", "ipa": "/ˈbaɪ ɪˌlekʃən/", "pron": "BY i-LEK-shuhn", "fr": "élection partielle", "def": "An election held to fill a political seat that has become vacant between general elections.", "ex": "The by-election was seen as a test for the government."}, {"term": "ballot", "ipa": "/ˈbælət/", "pron": "BAL-uht", "fr": "scrutin ; bulletin de vote", "def": "The process of voting, or the paper or electronic form used to vote.", "ex": "Voters will decide the issue by secret ballot."}, {"term": "ballot paper", "ipa": "/ˈbælət ˌpeɪpə/", "pron": "BAL-uht PAY-puh", "fr": "bulletin de vote", "def": "The paper on which voters mark their choice in an election.", "ex": "The candidate’s name was printed at the top of the ballot paper."}, {"term": "polling station", "ipa": "/ˈpəʊlɪŋ ˌsteɪʃən/", "pron": "POH-ling STAY-shuhn", "fr": "bureau de vote", "def": "A place where people go to vote in an election.", "ex": "Polling stations opened at 7 a.m. across the country."}, {"term": "polls", "ipa": "/pəʊlz/", "pron": "pohlz", "fr": "sondages", "def": "Surveys that measure public opinion, especially before an election.", "ex": "The polls suggest that the race is too close to call."}, {"term": "opinion poll", "ipa": "/əˈpɪnjən pəʊl/", "pron": "uh-PIN-yuhn pohl", "fr": "sondage d'opinion", "def": "A survey that asks people what they think about a political issue, party or candidate.", "ex": "An opinion poll showed growing support for the opposition."}, {"term": "exit poll", "ipa": "/ˈeksɪt pəʊl/", "pron": "EK-sit pohl", "fr": "sondage de sortie des urnes", "def": "A survey of voters taken just after they have voted, used to predict election results.", "ex": "The exit poll predicted a landslide victory for the opposition."}, {"term": "voter", "ipa": "/ˈvəʊtə/", "pron": "VOH-tuh", "fr": "électeur ; électrice", "def": "A person who has the right to vote or who votes in an election.", "ex": "Young voters played a decisive role in the election."}, {"term": "voter registration", "ipa": "/ˈvəʊtə ˌredʒɪˈstreɪʃən/", "pron": "VOH-tuh rej-i-STRAY-shuhn", "fr": "inscription sur les listes électorales", "def": "The process of officially recording people so that they are allowed to vote.", "ex": "Campaigners encouraged voter registration among students."}, {"term": "eligible voter", "ipa": "/ˈelɪdʒəbəl ˈvəʊtə/", "pron": "EL-i-juh-buhl VOH-tuh", "fr": "électeur inscrit ou autorisé à voter", "def": "A person who meets the legal requirements to vote.", "ex": "Millions of eligible voters stayed home on election day."}, {"term": "constituency", "ipa": "/kənˈstɪtjuənsi/", "pron": "kuhn-STI-choo-uhn-see", "fr": "circonscription électorale", "def": "A geographical area whose voters elect a representative.", "ex": "The candidate has represented the same constituency for twenty years."}, {"term": "electoral district", "ipa": "/ɪˌlektərəl ˈdɪstrɪkt/", "pron": "i-LEK-tuh-ruhl DIS-trikt", "fr": "circonscription électorale", "def": "An area that elects one or more representatives.", "ex": "The new map changed the boundaries of several electoral districts."}, {"term": "candidate", "ipa": "/ˈkændɪdət/", "pron": "KAN-di-duht", "fr": "candidat ; candidate", "def": "A person who competes in an election or applies for a position.", "ex": "The candidate promised to restore trust in politics."}]}, {"title": "B. Candidates, parties and campaign tools", "entries": [{"term": "incumbent", "ipa": "/ɪnˈkʌmbənt/", "pron": "in-KUM-buhnt", "fr": "titulaire du poste ; sortant", "def": "The person currently holding a political office.", "ex": "The incumbent president faces a strong challenge from the opposition."}, {"term": "running mate", "ipa": "/ˈrʌnɪŋ meɪt/", "pron": "RUN-ing mayt", "fr": "colistier ; colistière", "def": "A candidate who runs for a lower office alongside another candidate, especially a vice-presidential candidate.", "ex": "The presidential candidate announced her running mate in July."}, {"term": "front-runner", "ipa": "/ˌfrʌnt ˈrʌnə/", "pron": "frunt RUN-uh", "fr": "favori ; favorite", "def": "The candidate who seems most likely to win an election or nomination.", "ex": "The former governor quickly became the front-runner."}, {"term": "underdog", "ipa": "/ˈʌndədɒɡ/", "pron": "UN-duh-dog", "fr": "outsider ; candidat donné perdant", "def": "A candidate or party expected to lose, but who may still surprise observers.", "ex": "The underdog gained momentum after a strong debate performance."}, {"term": "manifesto", "ipa": "/ˌmænɪˈfestəʊ/", "pron": "man-i-FES-toh", "fr": "programme électoral ; manifeste", "def": "A public document in which a political party presents its ideas, promises and programme.", "ex": "The party manifesto focused on housing, healthcare and climate policy."}, {"term": "platform", "ipa": "/ˈplætfɔːm/", "pron": "PLAT-form", "fr": "programme ; plateforme politique", "def": "The set of policies and principles supported by a political party or candidate.", "ex": "The candidate ran on a platform of tax cuts and stricter border controls."}, {"term": "pledge", "ipa": "/pledʒ/", "pron": "plej", "fr": "engagement ; promesse", "def": "A serious public promise, especially during an election campaign.", "ex": "The prime minister broke a key campaign pledge on taxes."}, {"term": "campaign", "ipa": "/kæmˈpeɪn/", "pron": "kam-PAYN", "fr": "campagne", "def": "A planned series of activities designed to win an election or influence public opinion.", "ex": "The campaign focused heavily on the cost-of-living crisis."}, {"term": "campaign trail", "ipa": "/kæmˈpeɪn treɪl/", "pron": "kam-PAYN trayl", "fr": "tournée de campagne", "def": "The series of events, visits and speeches made by candidates while campaigning.", "ex": "The candidate spent three weeks on the campaign trail."}, {"term": "campaign rally", "ipa": "/kæmˈpeɪn ˈræli/", "pron": "kam-PAYN RAL-ee", "fr": "meeting de campagne", "def": "A public meeting where supporters gather to hear a candidate speak.", "ex": "Thousands attended the campaign rally in Manchester."}, {"term": "canvassing", "ipa": "/ˈkænvəsɪŋ/", "pron": "KAN-vuh-sing", "fr": "porte-à-porte électoral ; démarchage électoral", "def": "The practice of contacting voters directly to persuade them or gather information about their voting intentions.", "ex": "Volunteers spent the weekend canvassing in marginal areas."}, {"term": "door-knocking", "ipa": "/ˈdɔː ˌnɒkɪŋ/", "pron": "DAW NOK-ing", "fr": "porte-à-porte", "def": "Campaigning by visiting voters at home and speaking to them directly.", "ex": "Door-knocking remains an important part of local campaigns."}, {"term": "phone banking", "ipa": "/ˈfəʊn ˌbæŋkɪŋ/", "pron": "FOHN BANK-ing", "fr": "appels téléphoniques de campagne", "def": "A campaign activity in which volunteers call voters to persuade them or remind them to vote.", "ex": "Phone banking helped the campaign contact thousands of undecided voters."}, {"term": "leaflet", "ipa": "/ˈliːflət/", "pron": "LEEF-luht", "fr": "tract ; prospectus", "def": "A printed sheet used to give political information or persuade voters.", "ex": "The leaflet summarised the candidate’s main proposals."}, {"term": "political ad", "ipa": "/pəˈlɪtɪkəl æd/", "pron": "puh-LIT-i-kuhl ad", "fr": "publicité politique", "def": "A political advertisement designed to influence voters.", "ex": "The political ad accused the opposition of being weak on crime."}, {"term": "negative campaigning", "ipa": "/ˈneɡətɪv kæmˈpeɪnɪŋ/", "pron": "NEG-uh-tiv kam-PAY-ning", "fr": "campagne négative", "def": "A strategy that attacks an opponent rather than promoting one’s own ideas.", "ex": "Negative campaigning may discourage voters from taking part."}, {"term": "attack ad", "ipa": "/əˈtæk æd/", "pron": "uh-TAK ad", "fr": "publicité d’attaque", "def": "A political advertisement that criticises or attacks an opponent.", "ex": "The attack ad damaged the candidate’s reputation."}, {"term": "spin", "ipa": "/spɪn/", "pron": "spin", "fr": "communication orientée ; présentation biaisée", "def": "A favourable or strategic interpretation of events designed to influence public opinion.", "ex": "The minister’s team tried to put a positive spin on the poor results."}, {"term": "spin doctor", "ipa": "/ˈspɪn ˌdɒktə/", "pron": "SPIN dok-tuh", "fr": "conseiller en communication politique", "def": "A political adviser who manages public image and media messaging.", "ex": "The spin doctor helped reshape the candidate’s image after the scandal."}, {"term": "slogan", "ipa": "/ˈsləʊɡən/", "pron": "SLOH-guhn", "fr": "slogan", "def": "A short memorable phrase used in a campaign.", "ex": "The slogan was simple, emotional and easy to remember."}, {"term": "soundbite", "ipa": "/ˈsaʊndbaɪt/", "pron": "SOWND-byt", "fr": "petite phrase ; formule choc", "def": "A short phrase from a speech or interview that is memorable and widely repeated.", "ex": "The debate produced several powerful soundbites."}, {"term": "debate", "ipa": "/dɪˈbeɪt/", "pron": "di-BAYT", "fr": "débat", "def": "A formal public discussion between candidates or political opponents.", "ex": "The televised debate attracted millions of viewers."}]}, {"title": "C. Public opinion and voter behaviour", "entries": [{"term": "approval rating", "ipa": "/əˈpruːvəl ˈreɪtɪŋ/", "pron": "uh-PROO-vuhl RAY-ting", "fr": "cote de popularité ; taux d’approbation", "def": "The percentage of people who say they approve of a leader or government.", "ex": "The president’s approval rating fell after the crisis."}, {"term": "public support", "ipa": "/ˈpʌblɪk səˈpɔːt/", "pron": "PUB-lik suh-PORT", "fr": "soutien populaire", "def": "The approval or backing that a person, policy or party receives from citizens.", "ex": "The reform lost public support after weeks of protests."}, {"term": "swing voter", "ipa": "/ˈswɪŋ ˌvəʊtə/", "pron": "swing VOH-tuh", "fr": "électeur indécis ; électeur flottant", "def": "A voter who has not firmly decided which party or candidate to support.", "ex": "Swing voters may decide the outcome in key states."}, {"term": "undecided voter", "ipa": "/ˌʌndɪˈsaɪdɪd ˈvəʊtə/", "pron": "un-di-SY-did VOH-tuh", "fr": "électeur indécis", "def": "A voter who has not yet chosen a candidate or party.", "ex": "Both candidates tried to appeal to undecided voters."}, {"term": "floating voter", "ipa": "/ˌfləʊtɪŋ ˈvəʊtə/", "pron": "FLOH-ting VOH-tuh", "fr": "électeur flottant", "def": "A voter who does not always vote for the same party.", "ex": "Floating voters are crucial in close elections."}, {"term": "marginal seat", "ipa": "/ˈmɑːdʒɪnəl siːt/", "pron": "MAR-ji-nuhl seet", "fr": "siège disputé ; circonscription marginale", "def": "A parliamentary seat that is won by a small margin and could easily change hands.", "ex": "The party targeted marginal seats in the north of England."}, {"term": "safe seat", "ipa": "/ˌseɪf ˈsiːt/", "pron": "sayf seet", "fr": "circonscription acquise ; siège sûr", "def": "A parliamentary seat that one party is very likely to keep.", "ex": "The minister represents a safe seat."}, {"term": "battleground state", "ipa": "/ˈbætəlɡraʊnd steɪt/", "pron": "BAT-uhl-ground stayt", "fr": "État clé ; État disputé", "def": "A state where the result is uncertain and which may decide an election, especially in the United States.", "ex": "Pennsylvania was one of the most important battleground states."}]}, {"title": "D. Results, majorities and electoral geography", "entries": [{"term": "swing state", "ipa": "/ˈswɪŋ steɪt/", "pron": "swing stayt", "fr": "État pivot ; État indécis", "def": "A US state where both major parties have a realistic chance of winning.", "ex": "Candidates spend huge sums of money in swing states."}, {"term": "landslide victory", "ipa": "/ˈlændslaɪd ˈvɪktəri/", "pron": "LAND-slyd VIK-tuh-ree", "fr": "victoire écrasante", "def": "An election victory by a very large margin.", "ex": "The opposition won a landslide victory."}, {"term": "narrow victory", "ipa": "/ˈnærəʊ ˈvɪktəri/", "pron": "NAR-oh VIK-tuh-ree", "fr": "victoire serrée", "def": "An election victory by a small margin.", "ex": "The president secured a narrow victory in the second round."}, {"term": "hung parliament", "ipa": "/ˌhʌŋ ˈpɑːləmənt/", "pron": "hung PAR-luh-muhnt", "fr": "parlement sans majorité absolue", "def": "A parliament in which no party has an overall majority.", "ex": "The election resulted in a hung parliament."}, {"term": "coalition government", "ipa": "/ˌkəʊəˈlɪʃən ˈɡʌvənmənt/", "pron": "koh-uh-LISH-uhn GUV-uhn-muhnt", "fr": "gouvernement de coalition", "def": "A government formed by two or more political parties.", "ex": "A coalition government was formed after weeks of negotiations."}, {"term": "majority", "ipa": "/məˈdʒɒrəti/", "pron": "muh-JOR-uh-tee", "fr": "majorité", "def": "The number by which one candidate or party has more votes or seats than another; also more than half.", "ex": "The ruling party lost its majority in parliament."}, {"term": "minority government", "ipa": "/maɪˈnɒrəti ˈɡʌvənmənt/", "pron": "my-NOR-uh-tee GUV-uhn-muhnt", "fr": "gouvernement minoritaire", "def": "A government that does not control more than half the seats in parliament.", "ex": "The prime minister tried to govern with a minority government."}, {"term": "proportional representation", "ipa": "/prəˌpɔːʃənəl ˌreprɪzenˈteɪʃən/", "pron": "pruh-POR-shuh-nuhl rep-ri-zen-TAY-shuhn", "fr": "représentation proportionnelle", "def": "An electoral system in which parties receive seats roughly in proportion to their share of the vote.", "ex": "Proportional representation often benefits smaller parties."}, {"term": "first-past-the-post", "ipa": "/ˌfɜːst pɑːst ðə ˈpəʊst/", "pron": "first past thuh pohst", "fr": "scrutin uninominal majoritaire à un tour", "def": "An electoral system in which the candidate with the most votes in a constituency wins, even without an absolute majority.", "ex": "The UK uses first-past-the-post for general elections."}, {"term": "run-off election", "ipa": "/ˈrʌn ɒf ɪˌlekʃən/", "pron": "RUN-off i-LEK-shuhn", "fr": "second tour ; scrutin de départage", "def": "A second election held when no candidate wins enough votes in the first round.", "ex": "The two leading candidates faced each other in a run-off election."}]}, {"title": "E. Electoral systems and democratic integrity", "entries": [{"term": "electoral college", "ipa": "/ɪˌlektərəl ˈkɒlɪdʒ/", "pron": "i-LEK-tuh-ruhl KOL-ij", "fr": "collège électoral", "def": "The system used in US presidential elections in which states appoint electors who formally choose the president.", "ex": "A candidate can win the popular vote but lose the Electoral College."}, {"term": "popular vote", "ipa": "/ˌpɒpjələ ˈvəʊt/", "pron": "POP-yuh-luh voht", "fr": "vote populaire ; suffrage exprimé", "def": "The total number of votes cast by citizens, as opposed to votes in an electoral college or parliament.", "ex": "She won the popular vote but lost the presidency."}, {"term": "voter suppression", "ipa": "/ˈvəʊtə səˌpreʃən/", "pron": "VOH-tuh suh-PRESH-uhn", "fr": "suppression du vote ; entraves au vote", "def": "Actions or rules that make it harder for certain groups of people to vote.", "ex": "Civil rights groups denounced the law as voter suppression."}, {"term": "gerrymandering", "ipa": "/ˈdʒerimændərɪŋ/", "pron": "JER-ee-man-duh-ring", "fr": "charcutage électoral ; découpage électoral partisan", "def": "The manipulation of electoral district boundaries to benefit a party or group.", "ex": "Gerrymandering can distort representation in parliament or congress."}, {"term": "vote rigging", "ipa": "/ˈvəʊt ˌrɪɡɪŋ/", "pron": "voht RIG-ing", "fr": "fraude électorale ; trucage du vote", "def": "Illegal manipulation of an election result.", "ex": "The opposition accused the government of vote rigging."}, {"term": "electoral fraud", "ipa": "/ɪˌlektərəl ˈfrɔːd/", "pron": "i-LEK-tuh-ruhl fraud", "fr": "fraude électorale", "def": "Illegal interference with the process or results of an election.", "ex": "International observers reported signs of electoral fraud."}, {"term": "peaceful transfer of power", "ipa": "/ˈpiːsfəl ˈtrænsfɜːr əv ˈpaʊə/", "pron": "PEES-fuhl TRANS-fur ov POW-uh", "fr": "transition pacifique du pouvoir", "def": "The orderly handover of political authority from one leader or government to another after an election.", "ex": "A peaceful transfer of power is a core feature of democracy."}]}]}, {"id": "p1c3", "part": 1, "chapter": 3, "title": "Parties Ideologies", "file": "cpge_vocab_part1_chapter3_parties_ideologies_premium.html", "count": 67, "sections": [{"title": "A. Parties and party organisation", "entries": [{"term": "political party", "ipa": "/pəˈlɪtɪkəl ˈpɑːti/", "pron": "puh-LIT-i-kuhl PAR-tee", "fr": "parti politique", "def": "An organised group of people who share political ideas and try to win power through elections.", "ex": "Political parties compete to win elections and shape public policy."}, {"term": "party system", "ipa": "/ˈpɑːti ˈsɪstəm/", "pron": "PAR-tee SIS-tuhm", "fr": "système partisan", "def": "The way political parties are organised and compete within a country.", "ex": "Britain’s party system has become more fragmented in recent years."}, {"term": "two-party system", "ipa": "/ˌtuː ˈpɑːti ˈsɪstəm/", "pron": "too PAR-tee SIS-tuhm", "fr": "bipartisme ; système bipartisan", "def": "A political system dominated by two major parties.", "ex": "The United States is often described as a two-party system."}, {"term": "multi-party system", "ipa": "/ˌmʌlti ˈpɑːti ˈsɪstəm/", "pron": "MUL-tee PAR-tee SIS-tuhm", "fr": "multipartisme", "def": "A political system in which several parties have a realistic chance of influencing government.", "ex": "A multi-party system can make coalition governments more likely."}, {"term": "ruling party", "ipa": "/ˈruːlɪŋ ˈpɑːti/", "pron": "ROO-ling PAR-tee", "fr": "parti au pouvoir", "def": "The political party currently in power.", "ex": "The ruling party defended its economic record."}, {"term": "opposition party", "ipa": "/ˌɒpəˈzɪʃən ˈpɑːti/", "pron": "op-uh-ZISH-uhn PAR-tee", "fr": "parti d’opposition", "def": "A political party that is not in government and criticises or challenges the ruling party.", "ex": "Opposition parties accused the government of ignoring the crisis."}, {"term": "coalition", "ipa": "/ˌkəʊəˈlɪʃən/", "pron": "koh-uh-LISH-uhn", "fr": "coalition", "def": "An alliance between political parties or groups, often formed to govern together.", "ex": "The election result forced the parties to form a coalition."}, {"term": "grassroots", "ipa": "/ˈɡrɑːsruːts/", "pron": "GRASS-roots", "fr": "base militante ; militants de terrain", "def": "Ordinary members or supporters of a political movement, rather than its leaders.", "ex": "Grassroots activists helped the campaign gain momentum."}, {"term": "party membership", "ipa": "/ˈpɑːti ˈmembəʃɪp/", "pron": "PAR-tee MEM-buh-ship", "fr": "adhérents d’un parti", "def": "The group of people who officially belong to a political party.", "ex": "Party membership has declined in many Western democracies."}, {"term": "party leader", "ipa": "/ˈpɑːti ˈliːdə/", "pron": "PAR-tee LEE-duh", "fr": "chef de parti ; dirigeant de parti", "def": "The person who leads a political party.", "ex": "The party leader promised to rebuild public trust."}, {"term": "rank-and-file members", "ipa": "/ˌræŋk ən ˈfaɪl ˈmembəz/", "pron": "rank uhn FILE MEM-buhz", "fr": "militants de base ; membres ordinaires", "def": "Ordinary members of a party or organisation, not its leaders.", "ex": "Rank-and-file members criticised the leadership’s decision."}, {"term": "party conference", "ipa": "/ˈpɑːti ˈkɒnfərəns/", "pron": "PAR-tee KON-fuh-ruhns", "fr": "congrès d’un parti", "def": "A large formal meeting where a political party discusses policies and strategy.", "ex": "The prime minister delivered a major speech at the party conference."}, {"term": "manifesto", "ipa": "/ˌmænɪˈfestəʊ/", "pron": "man-i-FES-toh", "fr": "programme électoral ; manifeste", "def": "A public document in which a political party presents its ideas, promises and programme.", "ex": "The manifesto included pledges on taxation, housing and climate policy."}, {"term": "party platform", "ipa": "/ˈpɑːti ˈplætfɔːm/", "pron": "PAR-tee PLAT-form", "fr": "programme politique ; plateforme d’un parti", "def": "The official set of policies and principles supported by a party.", "ex": "The party platform moved further to the right on immigration."}, {"term": "policy", "ipa": "/ˈpɒləsi/", "pron": "POL-uh-see", "fr": "politique ; mesure ; ligne politique", "def": "A plan or course of action adopted by a government, party or institution.", "ex": "The party’s housing policy was popular among young voters."}, {"term": "ideology", "ipa": "/ˌaɪdiˈɒlədʒi/", "pron": "eye-dee-OL-uh-jee", "fr": "idéologie", "def": "A set of political beliefs or principles about how society should be organised.", "ex": "Political ideology shapes how parties view the role of the state."}]}, {"title": "B. Ideologies and the political spectrum", "entries": [{"term": "left-wing", "ipa": "/ˌleft ˈwɪŋ/", "pron": "left wing", "fr": "de gauche", "def": "Supporting social equality, public services and a more active role for the state in the economy.", "ex": "Left-wing parties usually support stronger welfare policies."}, {"term": "right-wing", "ipa": "/ˌraɪt ˈwɪŋ/", "pron": "right wing", "fr": "de droite", "def": "Supporting tradition, free markets, national identity or limited state intervention, depending on context.", "ex": "Right-wing parties often call for lower taxes and stricter law enforcement."}, {"term": "centre-left", "ipa": "/ˌsentə ˈleft/", "pron": "SEN-tuh left", "fr": "centre gauche", "def": "Moderately left-wing; usually supportive of welfare and equality but within a market economy.", "ex": "The centre-left party promised to protect public services."}, {"term": "centre-right", "ipa": "/ˌsentə ˈraɪt/", "pron": "SEN-tuh right", "fr": "centre droit", "def": "Moderately right-wing; usually supportive of free markets, fiscal discipline and gradual reform.", "ex": "The centre-right candidate appealed to business leaders."}, {"term": "the political spectrum", "ipa": "/ðə pəˈlɪtɪkəl ˈspektrəm/", "pron": "thuh puh-LIT-i-kuhl SPEK-truhm", "fr": "échiquier politique ; spectre politique", "def": "The range of political positions from left to right, including moderate and extreme views.", "ex": "The issue divides voters across the political spectrum."}, {"term": "moderate", "ipa": "/ˈmɒdərət/", "pron": "MOD-uh-ruht", "fr": "modéré", "def": "Having political views that are not extreme.", "ex": "Moderate voters may reject radical proposals."}, {"term": "centrist", "ipa": "/ˈsentrɪst/", "pron": "SEN-trist", "fr": "centriste", "def": "A person or party with moderate political views between the left and the right.", "ex": "The centrist party tried to attract voters tired of polarisation."}, {"term": "radical", "ipa": "/ˈrædɪkəl/", "pron": "RAD-i-kuhl", "fr": "radical", "def": "Supporting deep or fundamental political change.", "ex": "Radical movements often emerge during periods of crisis."}, {"term": "extremist", "ipa": "/ɪkˈstriːmɪst/", "pron": "ik-STREEM-ist", "fr": "extrémiste", "def": "A person or group with political views far outside the mainstream, often rejecting democratic norms.", "ex": "Extremist groups exploited anger and economic insecurity."}, {"term": "mainstream", "ipa": "/ˈmeɪnstriːm/", "pron": "MAYN-streem", "fr": "dominant ; traditionnel ; grand public", "def": "Considered normal, dominant or widely accepted in society or politics.", "ex": "The idea has moved from the margins into mainstream politics."}, {"term": "fringe party", "ipa": "/ˈfrɪndʒ ˈpɑːti/", "pron": "frinj PAR-tee", "fr": "parti marginal", "def": "A small party with views outside the political mainstream.", "ex": "The fringe party gained attention through social media."}, {"term": "populism", "ipa": "/ˈpɒpjəlɪzəm/", "pron": "POP-yuh-liz-uhm", "fr": "populisme", "def": "A political style that claims to defend ordinary people against corrupt elites.", "ex": "Populism often presents politics as a battle between the people and the elite."}, {"term": "populist", "ipa": "/ˈpɒpjəlɪst/", "pron": "POP-yuh-list", "fr": "populiste", "def": "A politician, party or movement that uses populist language or ideas.", "ex": "The populist leader promised to speak for ordinary citizens."}, {"term": "nationalism", "ipa": "/ˈnæʃənəlɪzəm/", "pron": "NASH-uh-nuh-liz-uhm", "fr": "nationalisme", "def": "A political belief that emphasises national identity, sovereignty and loyalty to the nation.", "ex": "Nationalism can unite people but can also fuel exclusion."}, {"term": "patriotism", "ipa": "/ˈpætriətɪzəm/", "pron": "PAT-ree-uh-tiz-uhm", "fr": "patriotisme", "def": "Love of and loyalty to one’s country, usually without necessarily rejecting others.", "ex": "The speech appealed to patriotism rather than hostility to foreigners."}, {"term": "conservatism", "ipa": "/kənˈsɜːvətɪzəm/", "pron": "kuhn-SUR-vuh-tiz-uhm", "fr": "conservatisme", "def": "A political ideology that values tradition, stability, gradual change and often limited government.", "ex": "Conservatism often stresses order, family and national continuity."}, {"term": "liberalism", "ipa": "/ˈlɪbərəlɪzəm/", "pron": "LIB-uh-ruh-liz-uhm", "fr": "libéralisme", "def": "A political ideology that emphasises individual rights, freedoms, democracy and the rule of law.", "ex": "Liberalism places strong emphasis on civil liberties."}, {"term": "socialism", "ipa": "/ˈsəʊʃəlɪzəm/", "pron": "SOH-shuh-liz-uhm", "fr": "socialisme", "def": "A political ideology that supports greater economic equality and public or collective control of key resources.", "ex": "Socialism has historically called for stronger workers’ rights."}]}, {"title": "C. Major political traditions", "entries": [{"term": "social democracy", "ipa": "/ˌsəʊʃəl dɪˈmɒkrəsi/", "pron": "SOH-shuhl di-MOK-ruh-see", "fr": "social-démocratie", "def": "A moderate left-wing ideology that supports democracy, welfare policies and a regulated market economy.", "ex": "Social democracy seeks to combine capitalism with social protection."}, {"term": "libertarianism", "ipa": "/ˌlɪbəˈteəriənɪzəm/", "pron": "lib-uh-TAIR-ee-uh-niz-uhm", "fr": "libertarianisme", "def": "A political ideology that emphasises individual freedom, limited government and free markets.", "ex": "Libertarianism is sceptical of state intervention."}, {"term": "neoliberalism", "ipa": "/ˌniːəʊˈlɪbərəlɪzəm/", "pron": "nee-oh-LIB-uh-ruh-liz-uhm", "fr": "néolibéralisme", "def": "An ideology favouring free markets, deregulation, privatisation and a reduced role for the state in the economy.", "ex": "Critics blame neoliberalism for rising inequality."}, {"term": "environmentalism", "ipa": "/ɪnˌvaɪrənˈmentəlɪzəm/", "pron": "in-vy-ruhn-MEN-tuh-liz-uhm", "fr": "écologisme ; environnementalisme", "def": "A political and social movement that seeks to protect the environment.", "ex": "Environmentalism has become a major force in European politics."}, {"term": "green politics", "ipa": "/ˌɡriːn ˈpɒlɪtɪks/", "pron": "green POL-i-tiks", "fr": "politique écologiste", "def": "Political ideas focused on environmental protection, sustainability and climate action.", "ex": "Green politics has pushed climate change higher on the political agenda."}, {"term": "feminism", "ipa": "/ˈfemɪnɪzəm/", "pron": "FEM-i-niz-uhm", "fr": "féminisme", "def": "A movement and ideology supporting equal rights and opportunities for women and men.", "ex": "Feminism has reshaped debates on work, family and political representation."}, {"term": "identity politics", "ipa": "/aɪˈdentəti ˈpɒlɪtɪks/", "pron": "eye-DEN-tuh-tee POL-i-tiks", "fr": "politique identitaire", "def": "Political positions based on the interests or experiences of particular identity groups.", "ex": "Critics and supporters disagree sharply over the role of identity politics."}, {"term": "culture wars", "ipa": "/ˈkʌltʃə wɔːz/", "pron": "KUL-chuh wawz", "fr": "guerres culturelles", "def": "Political conflicts over values, identity, education, religion, gender or national history.", "ex": "Culture wars have become a central feature of American politics."}, {"term": "progressive", "ipa": "/prəˈɡresɪv/", "pron": "pruh-GRES-iv", "fr": "progressiste", "def": "Supporting social reform, equality and change, especially on social issues.", "ex": "Progressive voters demanded stronger action on climate change."}, {"term": "reactionary", "ipa": "/riˈækʃənəri/", "pron": "ree-AK-shuh-nuh-ree", "fr": "réactionnaire", "def": "Opposed to social or political change and wishing to return to a previous order.", "ex": "The policy was criticised as reactionary by civil rights groups."}, {"term": "hardline", "ipa": "/ˈhɑːdlaɪn/", "pron": "HARD-line", "fr": "intransigeant ; dur", "def": "Taking a strict, uncompromising political position.", "ex": "The government adopted a hardline stance on immigration."}, {"term": "hawkish", "ipa": "/ˈhɔːkɪʃ/", "pron": "HAW-kish", "fr": "belliciste ; partisan d’une ligne dure", "def": "Supporting strong military action or a tough foreign policy.", "ex": "Hawkish lawmakers called for tougher sanctions."}]}, {"title": "D. Political attitudes and divisions", "entries": [{"term": "dovish", "ipa": "/ˈdʌvɪʃ/", "pron": "DUV-ish", "fr": "pacifique ; partisan de la conciliation", "def": "Supporting diplomacy, compromise or a softer foreign policy.", "ex": "Dovish politicians warned against military escalation."}, {"term": "pragmatic", "ipa": "/præɡˈmætɪk/", "pron": "prag-MAT-ik", "fr": "pragmatique", "def": "Focused on practical results rather than ideology.", "ex": "The mayor took a pragmatic approach to the housing crisis."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "The process by which political opinions become more divided and extreme.", "ex": "Political polarisation has made compromise more difficult."}, {"term": "partisanship", "ipa": "/ˈpɑːtizənʃɪp/", "pron": "PAR-ti-zuhn-ship", "fr": "esprit partisan ; partisanerie", "def": "Strong loyalty to a political party, sometimes at the expense of fairness or compromise.", "ex": "Extreme partisanship can weaken trust in institutions."}, {"term": "tribalism", "ipa": "/ˈtraɪbəlɪzəm/", "pron": "TRY-buh-liz-uhm", "fr": "tribalisme politique", "def": "A strong loyalty to one’s political group, often leading to hostility towards opponents.", "ex": "Social media can intensify political tribalism."}, {"term": "bipartisanship", "ipa": "/ˌbaɪˈpɑːtizənʃɪp/", "pron": "bye-PAR-ti-zuhn-ship", "fr": "coopération bipartisane", "def": "Cooperation between two major political parties.", "ex": "The reform passed thanks to rare bipartisanship."}, {"term": "cross-party support", "ipa": "/ˌkrɒs ˈpɑːti səˈpɔːt/", "pron": "kross PAR-tee suh-PORT", "fr": "soutien transpartisan", "def": "Support from members of different political parties.", "ex": "The bill received cross-party support."}, {"term": "party discipline", "ipa": "/ˈpɑːti ˈdɪsəplɪn/", "pron": "PAR-tee DIS-uh-plin", "fr": "discipline de parti", "def": "The pressure on elected representatives to vote according to their party’s position.", "ex": "Party discipline prevented many MPs from rebelling."}, {"term": "party line", "ipa": "/ˈpɑːti laɪn/", "pron": "PAR-tee line", "fr": "ligne du parti", "def": "The official position of a political party on an issue.", "ex": "Several lawmakers refused to follow the party line."}, {"term": "backbencher", "ipa": "/ˌbækˈbentʃə/", "pron": "bak-BEN-chuh", "fr": "député de base ; parlementaire sans fonction ministérielle", "def": "An ordinary MP who is not a minister or party leader, especially in the UK.", "ex": "Backbenchers put pressure on the prime minister to change course."}, {"term": "whip", "ipa": "/wɪp/", "pron": "wip", "fr": "whip ; responsable de discipline parlementaire", "def": "A party official responsible for ensuring that elected representatives vote according to the party line.", "ex": "The party whip urged MPs to support the bill."}, {"term": "rebel MP", "ipa": "/ˈrebəl ˌem ˈpiː/", "pron": "REB-uhl em pee", "fr": "député dissident", "def": "A Member of Parliament who votes against their own party’s position.", "ex": "Several rebel MPs opposed the government’s plan."}]}, {"title": "E. Party discipline, factions and strategic verbs", "entries": [{"term": "defection", "ipa": "/dɪˈfekʃən/", "pron": "di-FEK-shuhn", "fr": "défection ; changement de camp", "def": "The act of leaving one political party to join another or become independent.", "ex": "The defection embarrassed the party leadership."}, {"term": "faction", "ipa": "/ˈfækʃən/", "pron": "FAK-shuhn", "fr": "faction ; courant interne", "def": "A smaller group within a party that has its own views or interests.", "ex": "The party is divided between moderate and radical factions."}, {"term": "split", "ipa": "/splɪt/", "pron": "split", "fr": "scission ; division", "def": "A serious division within a party, movement or group.", "ex": "The leadership contest exposed a deep split within the party."}, {"term": "realignment", "ipa": "/ˌriːəˈlaɪnmənt/", "pron": "ree-uh-LYNE-muhnt", "fr": "recomposition politique ; réalignement", "def": "A major and lasting change in the support base of parties or political groups.", "ex": "The election signalled a realignment of working-class voters."}, {"term": "to shift to the right", "ipa": "/ʃɪft tə ðə ˈraɪt/", "pron": "shift tuh thuh right", "fr": "se déplacer vers la droite", "def": "To adopt more right-wing positions.", "ex": "The party shifted to the right on immigration."}, {"term": "to move to the centre", "ipa": "/muːv tə ðə ˈsentə/", "pron": "moov tuh thuh SEN-tuh", "fr": "se recentrer", "def": "To adopt more moderate positions.", "ex": "After losing the election, the party tried to move to the centre."}, {"term": "to appeal to voters", "ipa": "/əˈpiːl tə ˈvəʊtəz/", "pron": "uh-PEEL tuh VOH-tuhz", "fr": "séduire les électeurs ; parler aux électeurs", "def": "To attract or persuade voters.", "ex": "The party tried to appeal to younger voters."}, {"term": "to alienate voters", "ipa": "/ˈeɪliəneɪt ˈvəʊtəz/", "pron": "AY-lee-uh-nayt VOH-tuhz", "fr": "aliéner ; se mettre à dos les électeurs", "def": "To make voters feel rejected, ignored or hostile.", "ex": "The policy alienated many moderate voters."}, {"term": "to broaden one’s appeal", "ipa": "/ˈbrɔːdən wʌnz əˈpiːl/", "pron": "BRAW-duhn wunz uh-PEEL", "fr": "élargir son électorat ; élargir son audience", "def": "To become attractive to a wider range of voters.", "ex": "The candidate tried to broaden her appeal beyond the party base."}]}]}, {"id": "p1c4", "part": 1, "chapter": 4, "title": "Democracy Backsliding", "file": "cpge_vocab_part1_chapter4_democracy_backsliding_premium.html", "count": 72, "sections": [{"title": "A. Democratic models and principles", "entries": [{"term": "democracy", "ipa": "/dɪˈmɒkrəsi/", "pron": "di-MOK-ruh-see", "fr": "démocratie", "def": "A political system in which citizens choose their leaders through free elections and enjoy political rights and freedoms.", "ex": "Democracy depends on elections, rights, institutions and public trust."}, {"term": "liberal democracy", "ipa": "/ˈlɪbərəl dɪˈmɒkrəsi/", "pron": "LIB-uh-ruhl di-MOK-ruh-see", "fr": "démocratie libérale", "def": "A democracy that protects individual rights, minority rights, the rule of law and checks on government power.", "ex": "A liberal democracy protects citizens even when they disagree with the government."}, {"term": "constitutional democracy", "ipa": "/ˌkɒnstɪˈtjuːʃənəl dɪˈmɒkrəsi/", "pron": "kon-sti-TOO-shuh-nuhl di-MOK-ruh-see", "fr": "démocratie constitutionnelle", "def": "A democracy in which political power is limited by a constitution and legal safeguards.", "ex": "In a constitutional democracy, leaders cannot simply ignore the law."}, {"term": "electoral democracy", "ipa": "/ɪˌlektərəl dɪˈmɒkrəsi/", "pron": "i-LEK-tuh-ruhl di-MOK-ruh-see", "fr": "démocratie électorale", "def": "A political system with regular elections, though rights and institutions may be weaker than in a liberal democracy.", "ex": "An electoral democracy may hold elections while still restricting civil liberties."}, {"term": "majoritarian democracy", "ipa": "/məˌdʒɒrɪˈteəriən dɪˈmɒkrəsi/", "pron": "muh-jor-i-TAIR-ee-uhn di-MOK-ruh-see", "fr": "démocratie majoritaire", "def": "A model of democracy in which the majority has strong power to make decisions.", "ex": "Majoritarian democracy can be efficient, but it may overlook minority rights."}, {"term": "participatory democracy", "ipa": "/pɑːˌtɪsɪˈpeɪtəri dɪˈmɒkrəsi/", "pron": "par-tis-i-PAY-tuh-ree di-MOK-ruh-see", "fr": "démocratie participative", "def": "A model of democracy that encourages citizens to be actively involved in political decisions.", "ex": "Participatory democracy aims to involve citizens beyond election day."}, {"term": "deliberative democracy", "ipa": "/dɪˈlɪbərətɪv dɪˈmɒkrəsi/", "pron": "di-LIB-uh-ruh-tiv di-MOK-ruh-see", "fr": "démocratie délibérative", "def": "A model of democracy based on public discussion, debate and reasoned decision-making.", "ex": "Citizens' assemblies are often presented as examples of deliberative democracy."}, {"term": "democratic values", "ipa": "/ˌdeməˈkrætɪk ˈvæljuːz/", "pron": "dem-uh-KRAT-ik VAL-yooz", "fr": "valeurs démocratiques", "def": "Principles such as freedom, equality, fairness, tolerance and respect for the rule of law.", "ex": "Democratic values must be taught, defended and practised."}, {"term": "political pluralism", "ipa": "/pəˈlɪtɪkəl ˈplʊərəlɪzəm/", "pron": "puh-LIT-i-kuhl PLOOR-uh-liz-uhm", "fr": "pluralisme politique", "def": "The existence of different political parties, opinions and groups in society.", "ex": "Political pluralism allows citizens to choose between competing ideas."}, {"term": "free and fair elections", "ipa": "/ˌfriː ən ˌfeər ɪˈlekʃənz/", "pron": "free uhn fair i-LEK-shuhnz", "fr": "élections libres et équitables", "def": "Elections in which voters can choose freely and results are counted honestly.", "ex": "Free and fair elections are a basic requirement of democracy."}, {"term": "universal suffrage", "ipa": "/ˌjuːnɪˈvɜːsəl ˈsʌfrɪdʒ/", "pron": "yoo-ni-VUR-suhl SUF-rij", "fr": "suffrage universel", "def": "The right of all adult citizens to vote, without discrimination based on wealth, gender, race or status.", "ex": "Universal suffrage was achieved only gradually in many countries."}, {"term": "political participation", "ipa": "/pəˈlɪtɪkəl pɑːˌtɪsɪˈpeɪʃən/", "pron": "puh-LIT-i-kuhl par-tis-i-PAY-shuhn", "fr": "participation politique", "def": "The ways citizens take part in political life, such as voting, protesting, campaigning or joining organisations.", "ex": "Low political participation can weaken democratic legitimacy."}, {"term": "civic engagement", "ipa": "/ˈsɪvɪk ɪnˈɡeɪdʒmənt/", "pron": "SIV-ik in-GAYJ-muhnt", "fr": "engagement citoyen", "def": "Active involvement in public life and community or political issues.", "ex": "Civic engagement is essential for a healthy democracy."}, {"term": "civil society", "ipa": "/ˌsɪvəl səˈsaɪəti/", "pron": "SIV-uhl suh-SY-uh-tee", "fr": "société civile", "def": "Organisations and groups outside the state and the market, such as charities, unions, NGOs and associations.", "ex": "Civil society can hold governments accountable."}, {"term": "public sphere", "ipa": "/ˈpʌblɪk sfɪə/", "pron": "PUB-lik sfeer", "fr": "espace public", "def": "The space where citizens discuss public issues, through media, debate and civic life.", "ex": "Social media has transformed the public sphere."}, {"term": "public debate", "ipa": "/ˈpʌblɪk dɪˈbeɪt/", "pron": "PUB-lik di-BAYT", "fr": "débat public", "def": "Open discussion about political or social issues.", "ex": "A democracy needs informed public debate."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including leaders and governments, must obey the law.", "ex": "The rule of law protects citizens against arbitrary power."}]}, {"title": "B. Institutions and safeguards", "entries": [{"term": "independent judiciary", "ipa": "/ˌɪndɪˈpendənt dʒuːˈdɪʃəri/", "pron": "in-di-PEN-duhnt joo-DISH-uh-ree", "fr": "justice indépendante ; pouvoir judiciaire indépendant", "def": "A court system that is free from political pressure and can apply the law fairly.", "ex": "An independent judiciary can block unconstitutional measures."}, {"term": "constitutional safeguards", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈseɪfɡɑːdz/", "pron": "kon-sti-TOO-shuh-nuhl SAYF-gardz", "fr": "garanties constitutionnelles", "def": "Legal protections designed to prevent abuses of power.", "ex": "Constitutional safeguards can prevent democratic erosion."}, {"term": "checks and balances", "ipa": "/ˌtʃeks ən ˈbælənsɪz/", "pron": "cheks uhn BAL-uhn-siz", "fr": "contre-pouvoirs ; freins et contrepoids", "def": "A system in which different branches of government can limit one another’s power.", "ex": "Checks and balances make it harder for a leader to concentrate power."}, {"term": "separation of powers", "ipa": "/ˌsepəˈreɪʃən əv ˈpaʊəz/", "pron": "sep-uh-RAY-shuhn ov POW-uhz", "fr": "séparation des pouvoirs", "def": "The division of state power among the executive, legislature and judiciary.", "ex": "The separation of powers is a key principle of liberal democracy."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; obligation de rendre des comptes", "def": "The obligation of leaders and institutions to explain their actions and accept responsibility.", "ex": "Democratic accountability requires scrutiny by parliament, courts and the media."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PAIR-uhn-see", "fr": "transparence", "def": "Openness in decision-making, allowing citizens to understand how decisions are made.", "ex": "Transparency can reduce corruption and increase public trust."}, {"term": "oversight", "ipa": "/ˈəʊvəsaɪt/", "pron": "OH-vuh-syte", "fr": "contrôle ; surveillance institutionnelle", "def": "The process of monitoring and checking the actions of governments, institutions or officials.", "ex": "Parliamentary oversight is essential in a democracy."}, {"term": "independent media", "ipa": "/ˌɪndɪˈpendənt ˈmiːdiə/", "pron": "in-di-PEN-duhnt MEE-dee-uh", "fr": "médias indépendants", "def": "Media organisations that are free from government control or intimidation.", "ex": "Independent media can expose corruption and abuses of power."}, {"term": "free press", "ipa": "/ˌfriː ˈpres/", "pron": "free press", "fr": "presse libre", "def": "Media that can report, investigate and criticise power without censorship.", "ex": "A free press is one of the pillars of democracy."}, {"term": "watchdog", "ipa": "/ˈwɒtʃdɒɡ/", "pron": "WATCH-dog", "fr": "chien de garde ; organisme de contrôle", "def": "A person, group or institution that monitors those in power and exposes wrongdoing.", "ex": "Journalists often act as watchdogs in democratic societies."}, {"term": "whistleblower", "ipa": "/ˈwɪsəlbləʊə/", "pron": "WIS-uhl-bloh-uh", "fr": "lanceur d’alerte ; lanceuse d’alerte", "def": "A person who reveals secret or illegal activity within an organisation.", "ex": "The whistleblower exposed illegal surveillance practices."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected by law, such as freedom of speech, assembly and religion.", "ex": "Civil liberties can be threatened during a state of emergency."}]}, {"title": "C. Rights, freedoms and participation", "entries": [{"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov speech", "fr": "liberté d’expression", "def": "The right to express opinions and ideas without unjustified government restriction.", "ex": "Freedom of speech protects unpopular as well as popular opinions."}, {"term": "freedom of assembly", "ipa": "/ˌfriːdəm əv əˈsembli/", "pron": "FREE-duhm ov uh-SEM-blee", "fr": "liberté de réunion ; droit de rassemblement", "def": "The right to gather publicly and peacefully, often to protest or express political views.", "ex": "Freedom of assembly allows citizens to protest peacefully."}, {"term": "freedom of association", "ipa": "/ˌfriːdəm əv əˌsəʊsiˈeɪʃən/", "pron": "FREE-duhm ov uh-soh-see-AY-shuhn", "fr": "liberté d’association", "def": "The right to join groups, parties, unions or organisations.", "ex": "Freedom of association protects trade unions and political parties."}, {"term": "minority rights", "ipa": "/maɪˈnɒrəti ˈraɪts/", "pron": "my-NOR-uh-tee rites", "fr": "droits des minorités", "def": "Rights protecting groups that are smaller in number or politically less powerful.", "ex": "A democracy must protect minority rights, not only majority rule."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains ; droits de l’homme", "def": "Fundamental rights believed to belong to every human being.", "ex": "Human rights organisations criticised the government’s crackdown."}, {"term": "political rights", "ipa": "/pəˈlɪtɪkəl ˈraɪts/", "pron": "puh-LIT-i-kuhl rites", "fr": "droits politiques", "def": "Rights that allow people to participate in political life, such as voting or standing for office.", "ex": "Political rights are meaningless if elections are not free."}, {"term": "to uphold rights", "ipa": "/ʌpˈhəʊld ˈraɪts/", "pron": "up-HOHLD rites", "fr": "défendre les droits ; faire respecter les droits", "def": "To defend, respect or maintain legal and political rights.", "ex": "Courts are expected to uphold citizens’ rights."}, {"term": "to safeguard freedoms", "ipa": "/ˈseɪfɡɑːd ˈfriːdəmz/", "pron": "SAYF-gard FREE-duhmz", "fr": "préserver les libertés", "def": "To protect freedoms from threats or abuses.", "ex": "Independent institutions help safeguard freedoms."}, {"term": "democratic backsliding", "ipa": "/ˌdeməˈkrætɪk ˈbækslaɪdɪŋ/", "pron": "dem-uh-KRAT-ik BAK-sly-ding", "fr": "recul démocratique ; régression démocratique", "def": "The gradual weakening of democratic institutions, norms, rights or practices.", "ex": "Attacks on courts and journalists are signs of democratic backsliding."}, {"term": "democratic erosion", "ipa": "/ˌdeməˈkrætɪk ɪˈrəʊʒən/", "pron": "dem-uh-KRAT-ik i-ROH-zhuhn", "fr": "érosion démocratique", "def": "A gradual decline in the quality or strength of democracy.", "ex": "Democratic erosion often happens step by step rather than overnight."}]}, {"title": "D. Democratic backsliding and authoritarian drift", "entries": [{"term": "democratic decline", "ipa": "/ˌdeməˈkrætɪk dɪˈklaɪn/", "pron": "dem-uh-KRAT-ik di-KLYNE", "fr": "déclin démocratique", "def": "A reduction in democratic standards, rights or institutional independence.", "ex": "Experts warned of democratic decline after the government weakened the courts."}, {"term": "authoritarian drift", "ipa": "/ɔːˌθɒrɪˈteəriən drɪft/", "pron": "aw-thor-i-TAIR-ee-uhn drift", "fr": "dérive autoritaire", "def": "A gradual movement towards authoritarian rule.", "ex": "The new surveillance law was seen as part of an authoritarian drift."}, {"term": "illiberal democracy", "ipa": "/ɪˈlɪbərəl dɪˈmɒkrəsi/", "pron": "i-LIB-uh-ruhl di-MOK-ruh-see", "fr": "démocratie illibérale", "def": "A system with elections but weak civil liberties, limited checks and balances, and pressure on independent institutions.", "ex": "An illiberal democracy may keep elections while restricting media freedom."}, {"term": "hybrid regime", "ipa": "/ˈhaɪbrɪd reɪˈʒiːm/", "pron": "HY-brid ray-ZHEEM", "fr": "régime hybride", "def": "A political system that combines democratic features, such as elections, with authoritarian practices.", "ex": "Some analysts describe the country as a hybrid regime."}, {"term": "competitive authoritarianism", "ipa": "/kəmˈpetɪtɪv ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "kuhm-PET-i-tiv aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme compétitif", "def": "A system in which elections exist but the ruling party uses state power to make competition unfair.", "ex": "Competitive authoritarianism keeps the appearance of democracy while weakening real competition."}, {"term": "executive overreach", "ipa": "/ɪɡˈzekjətɪv ˌəʊvəˈriːtʃ/", "pron": "ig-ZEK-yuh-tiv OH-vuh-reech", "fr": "abus de pouvoir exécutif ; dépassement des pouvoirs de l’exécutif", "def": "The use of executive power beyond proper legal or constitutional limits.", "ex": "Critics accused the president of executive overreach."}, {"term": "power grab", "ipa": "/ˈpaʊə ɡræb/", "pron": "POW-uh grab", "fr": "accaparement du pouvoir ; coup de force institutionnel", "def": "An attempt to gain more power quickly or unfairly.", "ex": "The reform was denounced as a power grab."}, {"term": "concentration of power", "ipa": "/ˌkɒnsənˈtreɪʃən əv ˈpaʊə/", "pron": "kon-suhn-TRAY-shuhn ov POW-uh", "fr": "concentration du pouvoir", "def": "The accumulation of political authority in the hands of one person or institution.", "ex": "The concentration of power in the executive alarmed observers."}, {"term": "to weaken institutions", "ipa": "/ˈwiːkən ˌɪnstɪˈtjuːʃənz/", "pron": "WEE-kuhn in-sti-TOO-shuhnz", "fr": "affaiblir les institutions", "def": "To reduce the independence, authority or effectiveness of institutions.", "ex": "Authoritarian leaders often weaken institutions before attacking elections."}, {"term": "to pack the courts", "ipa": "/pæk ðə ˈkɔːts/", "pron": "pak thuh courts", "fr": "remplir les tribunaux de juges acquis à sa cause", "def": "To appoint many judges for political reasons in order to influence court decisions.", "ex": "The government was accused of trying to pack the courts."}, {"term": "to muzzle the press", "ipa": "/ˈmʌzəl ðə ˈpres/", "pron": "MUZ-uhl thuh press", "fr": "museler la presse", "def": "To silence or restrict journalists and media organisations.", "ex": "The new media law was seen as an attempt to muzzle the press."}, {"term": "to silence dissent", "ipa": "/ˈsaɪləns dɪˈsent/", "pron": "SY-luhns di-SENT", "fr": "faire taire la dissidence", "def": "To prevent people from expressing disagreement with the authorities.", "ex": "The regime used arrests to silence dissent."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "The control or suppression of information, speech or media by authorities.", "ex": "Censorship increased after the protests."}, {"term": "crackdown", "ipa": "/ˈkrækdaʊn/", "pron": "KRAK-down", "fr": "répression ; durcissement", "def": "Strong action by authorities to stop or punish behaviour they oppose.", "ex": "The crackdown on protesters drew international criticism."}, {"term": "political repression", "ipa": "/pəˈlɪtɪkəl rɪˈpreʃən/", "pron": "puh-LIT-i-kuhl ri-PRESH-uhn", "fr": "répression politique", "def": "The use of force, intimidation or law to prevent political opposition.", "ex": "Political repression often targets journalists, activists and opposition leaders."}, {"term": "state of emergency", "ipa": "/ˌsteɪt əv ɪˈmɜːdʒənsi/", "pron": "stayt ov i-MUR-juhn-see", "fr": "état d’urgence", "def": "A temporary situation in which the government claims special powers because of a crisis.", "ex": "A state of emergency can sometimes be used to limit civil liberties."}, {"term": "surveillance", "ipa": "/səˈveɪləns/", "pron": "suh-VAY-luhns", "fr": "surveillance", "def": "The monitoring of people, communications or activities, often by the state.", "ex": "Mass surveillance raises serious questions about privacy and democracy."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Information, often biased or misleading, used to promote a political cause or government.", "ex": "Propaganda can shape public opinion and discredit opponents."}]}, {"title": "E. Corruption, manipulation and resilience", "entries": [{"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately to deceive people.", "ex": "Disinformation can undermine trust in elections."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "fausse information ; information erronée", "def": "False or inaccurate information, whether spread deliberately or not.", "ex": "Misinformation spreads quickly on social media."}, {"term": "institutional capture", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈkæptʃə/", "pron": "in-sti-TOO-shuh-nuhl KAP-chuh", "fr": "capture institutionnelle", "def": "The process by which independent institutions are brought under the control of a ruling party or interest group.", "ex": "Institutional capture can turn courts and regulators into political tools."}, {"term": "clientelism", "ipa": "/ˌklaɪənˈtelɪzəm/", "pron": "kly-uhn-TEL-iz-uhm", "fr": "clientélisme", "def": "A political system in which leaders give benefits to supporters in exchange for loyalty or votes.", "ex": "Clientelism weakens equal citizenship and democratic accountability."}, {"term": "cronyism", "ipa": "/ˈkrəʊniɪzəm/", "pron": "KROH-nee-iz-uhm", "fr": "copinage ; favoritisme", "def": "The practice of giving jobs, contracts or advantages to friends and allies.", "ex": "Cronyism damaged the government’s reputation."}, {"term": "nepotism", "ipa": "/ˈnepətɪzəm/", "pron": "NEP-uh-tiz-uhm", "fr": "népotisme", "def": "The practice of giving jobs or advantages to relatives.", "ex": "The appointment was criticised as an example of nepotism."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Dishonest or illegal behaviour by people in power, often involving bribery or personal gain.", "ex": "Corruption scandals can destroy trust in public institutions."}, {"term": "bribery", "ipa": "/ˈbraɪbəri/", "pron": "BRY-buh-ree", "fr": "pot-de-vin ; corruption", "def": "The act of offering or receiving money or gifts to influence someone’s actions illegally.", "ex": "Several officials were accused of bribery."}, {"term": "democratic resilience", "ipa": "/ˌdeməˈkrætɪk rɪˈzɪliəns/", "pron": "dem-uh-KRAT-ik ri-ZIL-yuhns", "fr": "résilience démocratique", "def": "The ability of democratic institutions and citizens to resist threats and recover from crises.", "ex": "Democratic resilience depends on strong institutions and active citizens."}, {"term": "institutional resilience", "ipa": "/ˌɪnstɪˈtjuːʃənəl rɪˈzɪliəns/", "pron": "in-sti-TOO-shuh-nuhl ri-ZIL-yuhns", "fr": "résilience institutionnelle", "def": "The ability of institutions to withstand pressure, crisis or political attack.", "ex": "Institutional resilience helped prevent a constitutional crisis."}, {"term": "to defend democracy", "ipa": "/dɪˈfend dɪˈmɒkrəsi/", "pron": "di-FEND di-MOK-ruh-see", "fr": "défendre la démocratie", "def": "To protect democratic institutions, rights and norms.", "ex": "Citizens, judges and journalists all have a role to play in defending democracy."}, {"term": "to restore trust", "ipa": "/rɪˈstɔː ˈtrʌst/", "pron": "ri-STOR trust", "fr": "rétablir la confiance", "def": "To rebuild confidence in institutions, leaders or democratic processes.", "ex": "The reform aimed to restore trust in parliament."}, {"term": "to hold leaders accountable", "ipa": "/həʊld ˈliːdəz əˈkaʊntəbəl/", "pron": "hohld LEE-duhz uh-KOWN-tuh-buhl", "fr": "demander des comptes aux dirigeants", "def": "To make leaders explain their actions and accept consequences for wrongdoing.", "ex": "A free press helps hold leaders accountable."}, {"term": "to challenge abuses of power", "ipa": "/ˈtʃælɪndʒ əˈbjuːsɪz əv ˈpaʊə/", "pron": "CHAL-inj uh-BYOO-ziz ov POW-uh", "fr": "contester les abus de pouvoir", "def": "To oppose or question the improper use of authority.", "ex": "Independent courts can challenge abuses of power."}, {"term": "to protect minority rights", "ipa": "/prəˈtekt maɪˈnɒrəti ˈraɪts/", "pron": "pruh-TEKT my-NOR-uh-tee rites", "fr": "protéger les droits des minorités", "def": "To ensure that minority groups are not oppressed or ignored by the majority.", "ex": "Democracy must protect minority rights as well as majority rule."}]}]}, {"id": "p1c5", "part": 1, "chapter": 5, "title": "Populism", "file": "cpge_vocab_part1_chapter5_populism_premium.html", "count": 71, "sections": [{"title": "A. Core concepts and actors", "entries": [{"term": "populism", "ipa": "/ˈpɒpjəlɪzəm/", "pron": "POP-yuh-liz-uhm", "fr": "populisme", "def": "A political style or ideology that claims to defend ordinary people against a corrupt elite.", "ex": "Populism often presents politics as a struggle between the people and the elite."}, {"term": "populist", "ipa": "/ˈpɒpjəlɪst/", "pron": "POP-yuh-list", "fr": "populiste", "def": "A politician, party or movement that uses populist ideas or rhetoric.", "ex": "The populist leader promised to give power back to ordinary citizens."}, {"term": "anti-elitism", "ipa": "/ˌænti ɪˈliːtɪzəm/", "pron": "AN-tee i-LEE-tiz-uhm", "fr": "anti-élitisme", "def": "Hostility towards elites, especially political, economic, cultural or media elites.", "ex": "Anti-elitism is a central feature of many populist movements."}, {"term": "the elite", "ipa": "/ði ɪˈliːt/", "pron": "thee i-LEET", "fr": "l’élite", "def": "A small group of powerful or privileged people who are seen as controlling society.", "ex": "Populist speeches often blame the elite for the country’s problems."}, {"term": "ordinary people", "ipa": "/ˈɔːdənəri ˈpiːpəl/", "pron": "OR-duh-nuh-ree PEE-puhl", "fr": "les gens ordinaires", "def": "Common citizens, especially those presented as honest, hard-working and ignored by elites.", "ex": "The candidate claimed to speak for ordinary people."}, {"term": "the people", "ipa": "/ðə ˈpiːpəl/", "pron": "thuh PEE-puhl", "fr": "le peuple", "def": "In populist rhetoric, the supposedly unified and legitimate body of ordinary citizens.", "ex": "Populists often claim that only they represent the people."}, {"term": "the establishment", "ipa": "/ði ɪˈstæblɪʃmənt/", "pron": "thee i-STAB-lish-muhnt", "fr": "l’establishment ; le système", "def": "The powerful institutions and groups that are seen as controlling politics and society.", "ex": "The movement presented itself as a rebellion against the establishment."}, {"term": "the ruling class", "ipa": "/ðə ˈruːlɪŋ klɑːs/", "pron": "thuh ROO-ling klass", "fr": "la classe dirigeante", "def": "The group of people who hold political, economic or social power.", "ex": "The ruling class was accused of being disconnected from voters."}, {"term": "political outsider", "ipa": "/pəˈlɪtɪkəl aʊtˈsaɪdə/", "pron": "puh-LIT-i-kuhl owts-EYE-duh", "fr": "outsider politique", "def": "A person who does not belong to the traditional political establishment.", "ex": "The billionaire ran as a political outsider."}, {"term": "insider", "ipa": "/ɪnˈsaɪdə/", "pron": "in-SY-duh", "fr": "initié ; membre du système", "def": "A person who belongs to a powerful organisation, institution or political circle.", "ex": "Although he attacked the establishment, critics said he was an insider."}, {"term": "anti-establishment", "ipa": "/ˌænti ɪˈstæblɪʃmənt/", "pron": "AN-tee i-STAB-lish-muhnt", "fr": "anti-système", "def": "Opposed to traditional political, economic or cultural elites.", "ex": "Anti-establishment parties have gained ground in many democracies."}, {"term": "grassroots movement", "ipa": "/ˈɡrɑːsruːts ˈmuːvmənt/", "pron": "GRASS-roots MOOV-muhnt", "fr": "mouvement de base ; mouvement citoyen", "def": "A movement built from ordinary citizens or local activists rather than party elites.", "ex": "The campaign began as a grassroots movement online."}, {"term": "popular anger", "ipa": "/ˈpɒpjələ ˈæŋɡə/", "pron": "POP-yuh-luh ANG-guh", "fr": "colère populaire", "def": "Public frustration or resentment directed at leaders, institutions or policies.", "ex": "The party benefited from popular anger over inflation."}, {"term": "resentment", "ipa": "/rɪˈzentmənt/", "pron": "ri-ZENT-muhnt", "fr": "ressentiment", "def": "A feeling of bitterness caused by perceived unfair treatment.", "ex": "Populist rhetoric often feeds on social resentment."}, {"term": "grievance", "ipa": "/ˈɡriːvəns/", "pron": "GREE-vuhns", "fr": "grief ; motif de mécontentement", "def": "A complaint or feeling of injustice.", "ex": "The movement gave voice to long-standing grievances."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "réaction hostile ; retour de bâton", "def": "A strong negative reaction against social or political change.", "ex": "The reform triggered a populist backlash."}, {"term": "anti-politics", "ipa": "/ˌænti ˈpɒlɪtɪks/", "pron": "AN-tee POL-i-tiks", "fr": "rejet de la politique traditionnelle", "def": "Hostility towards professional politicians and traditional political institutions.", "ex": "Anti-politics can weaken trust in democratic institutions."}, {"term": "political disaffection", "ipa": "/pəˈlɪtɪkəl ˌdɪsəˈfekʃən/", "pron": "puh-LIT-i-kuhl dis-uh-FEK-shuhn", "fr": "désaffection politique", "def": "A feeling of alienation or dissatisfaction with politics.", "ex": "Political disaffection helped fuel support for outsider candidates."}, {"term": "distrust", "ipa": "/dɪsˈtrʌst/", "pron": "dis-TRUST", "fr": "méfiance", "def": "A lack of trust or confidence.", "ex": "Distrust of institutions is often exploited by populist leaders."}, {"term": "mistrust", "ipa": "/ˌmɪsˈtrʌst/", "pron": "mis-TRUST", "fr": "méfiance ; défiance", "def": "Suspicion or lack of confidence in someone or something.", "ex": "Mistrust of the media has grown in polarised societies."}]}, {"title": "B. Rhetoric, emotions and scapegoating", "entries": [{"term": "charismatic leader", "ipa": "/ˌkærɪzˈmætɪk ˈliːdə/", "pron": "kar-iz-MAT-ik LEE-duh", "fr": "leader charismatique", "def": "A leader who attracts followers through personal appeal, confidence and emotional communication.", "ex": "Populist movements often revolve around a charismatic leader."}, {"term": "strongman", "ipa": "/ˈstrɒŋmæn/", "pron": "STRONG-man", "fr": "homme fort", "def": "A political leader who presents himself as powerful, decisive and willing to bypass institutions.", "ex": "The strongman promised to restore order and national pride."}, {"term": "demagogue", "ipa": "/ˈdeməɡɒɡ/", "pron": "DEM-uh-gog", "fr": "démagogue", "def": "A political leader who gains support by appealing to emotions, fears and prejudices rather than reason.", "ex": "Critics described the speaker as a demagogue."}, {"term": "demagoguery", "ipa": "/ˈdeməɡɒɡəri/", "pron": "DEM-uh-gog-uh-ree", "fr": "démagogie", "def": "Political speech or behaviour that manipulates emotions and prejudices.", "ex": "The campaign relied more on demagoguery than on detailed policies."}, {"term": "rhetoric", "ipa": "/ˈretərɪk/", "pron": "RET-uh-rik", "fr": "rhétorique ; discours", "def": "The style and strategy of persuasive political language.", "ex": "The leader’s rhetoric was simple, emotional and confrontational."}, {"term": "fiery rhetoric", "ipa": "/ˈfaɪəri ˈretərɪk/", "pron": "FY-uh-ree RET-uh-rik", "fr": "rhétorique enflammée", "def": "Angry, emotional and forceful political language.", "ex": "His fiery rhetoric energised supporters but alarmed opponents."}, {"term": "divisive rhetoric", "ipa": "/dɪˈvaɪsɪv ˈretərɪk/", "pron": "di-VY-siv RET-uh-rik", "fr": "rhétorique clivante", "def": "Language that creates conflict between groups.", "ex": "Divisive rhetoric can deepen social tensions."}, {"term": "scapegoat", "ipa": "/ˈskeɪpɡəʊt/", "pron": "SKAYP-goht", "fr": "bouc émissaire", "def": "A person or group unfairly blamed for problems.", "ex": "Immigrants are often used as scapegoats in populist discourse."}, {"term": "to scapegoat", "ipa": "/ˈskeɪpɡəʊt/", "pron": "SKAYP-goht", "fr": "prendre pour bouc émissaire", "def": "To blame a person or group unfairly for political or social problems.", "ex": "The party was accused of scapegoating minorities."}, {"term": "enemy within", "ipa": "/ˈenəmi wɪˈðɪn/", "pron": "EN-uh-mee wi-THIN", "fr": "ennemi intérieur", "def": "A group portrayed as dangerous from inside the country or community.", "ex": "The government portrayed critics as the enemy within."}, {"term": "us versus them", "ipa": "/ˈʌs ˌvɜːsəs ˈðem/", "pron": "uss VUR-suhs them", "fr": "nous contre eux", "def": "A way of presenting politics as a conflict between two opposing groups.", "ex": "Populist rhetoric often relies on an us-versus-them narrative."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "The process by which political opinions become more divided and extreme.", "ex": "Populism can intensify political polarisation."}, {"term": "nativism", "ipa": "/ˈneɪtɪvɪzəm/", "pron": "NAY-tiv-iz-uhm", "fr": "nativisme ; préférence nationale", "def": "A political attitude that favours native-born citizens over immigrants.", "ex": "Nativism often appears in anti-immigration campaigns."}, {"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "zen-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Fear or hostility towards foreigners or people from other countries.", "ex": "The speech was criticised for encouraging xenophobia."}, {"term": "anti-immigration stance", "ipa": "/ˌænti ˌɪmɪˈɡreɪʃən stɑːns/", "pron": "AN-tee im-i-GRAY-shuhn stans", "fr": "position anti-immigration", "def": "A political position opposed to immigration or favouring stricter immigration controls.", "ex": "The party adopted a hardline anti-immigration stance."}, {"term": "national sovereignty", "ipa": "/ˈnæʃənəl ˈsɒvrənti/", "pron": "NASH-uh-nuhl SOV-ruhn-tee", "fr": "souveraineté nationale", "def": "The idea that a nation-state should have the final authority over its own laws and policies.", "ex": "The campaign framed the issue as a matter of national sovereignty."}, {"term": "economic insecurity", "ipa": "/ˌiːkəˈnɒmɪk ˌɪnsɪˈkjʊərəti/", "pron": "ee-kuh-NOM-ik in-si-KYOOR-uh-tee", "fr": "insécurité économique", "def": "A feeling of financial instability or fear about jobs, wages or living standards.", "ex": "Economic insecurity can make voters more receptive to populist messages."}]}, {"title": "C. Populist issues and economic grievances", "entries": [{"term": "left-wing populism", "ipa": "/ˌleft wɪŋ ˈpɒpjəlɪzəm/", "pron": "left wing POP-yuh-liz-uhm", "fr": "populisme de gauche", "def": "A form of populism that focuses on economic inequality and attacks financial or corporate elites.", "ex": "Left-wing populism often targets banks, billionaires and austerity policies."}, {"term": "right-wing populism", "ipa": "/ˌraɪt wɪŋ ˈpɒpjəlɪzəm/", "pron": "right wing POP-yuh-liz-uhm", "fr": "populisme de droite", "def": "A form of populism that often combines anti-elitism with nationalism and hostility to immigration.", "ex": "Right-wing populism has reshaped party politics in several Western countries."}, {"term": "anti-globalisation", "ipa": "/ˌænti ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "AN-tee gloh-buh-ly-ZAY-shuhn", "fr": "anti-mondialisation", "def": "Opposition to globalisation, often because of its effects on jobs, sovereignty or local communities.", "ex": "Anti-globalisation arguments became central to the campaign."}, {"term": "protectionism", "ipa": "/prəˈtekʃənɪzəm/", "pron": "pruh-TEK-shuh-niz-uhm", "fr": "protectionnisme", "def": "The policy of protecting domestic industries from foreign competition, usually through tariffs or restrictions.", "ex": "The party’s economic programme included strong protectionism."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "The government imposed tariffs to protect domestic industries."}, {"term": "anti-austerity", "ipa": "/ˌænti ɒˈsterəti/", "pron": "AN-tee aw-STAIR-uh-tee", "fr": "anti-austérité", "def": "Opposed to cuts in public spending or welfare programmes.", "ex": "The anti-austerity movement gained support after years of budget cuts."}, {"term": "welfare chauvinism", "ipa": "/ˈwelfeə ˈʃəʊvɪnɪzəm/", "pron": "WEL-fair SHOH-vin-iz-uhm", "fr": "chauvinisme social ; préférence nationale sociale", "def": "The view that welfare benefits should be reserved mainly for native citizens.", "ex": "Welfare chauvinism links social protection to national identity."}, {"term": "anti-corruption", "ipa": "/ˌænti kəˈrʌpʃən/", "pron": "AN-tee kuh-RUP-shuhn", "fr": "anti-corruption", "def": "Opposed to dishonest or illegal behaviour by people in power.", "ex": "The populist candidate built his image around an anti-corruption message."}, {"term": "drain the swamp", "ipa": "/ˌdreɪn ðə ˈswɒmp/", "pron": "drayn thuh swamp", "fr": "nettoyer le marécage ; chasser les élites corrompues", "def": "A slogan meaning to remove corruption or entrenched elites from government.", "ex": "The slogan “drain the swamp” appealed to voters angry with Washington."}, {"term": "take back control", "ipa": "/ˌteɪk bæk kənˈtrəʊl/", "pron": "tayk bak kuhn-TROHL", "fr": "reprendre le contrôle", "def": "A slogan meaning to regain national, political or democratic control.", "ex": "“Take back control” became a powerful slogan during the Brexit campaign."}, {"term": "will of the people", "ipa": "/ˌwɪl əv ðə ˈpiːpəl/", "pron": "wil ov thuh PEE-puhl", "fr": "volonté du peuple", "def": "The supposed collective desire of ordinary citizens.", "ex": "Populist leaders often claim to embody the will of the people."}]}, {"title": "D. Slogans, narratives and communication", "entries": [{"term": "silent majority", "ipa": "/ˌsaɪlənt məˈdʒɒrəti/", "pron": "SY-luhnt muh-JOR-uh-tee", "fr": "majorité silencieuse", "def": "A large group of people who are said to hold common views but not express them publicly.", "ex": "The candidate claimed to represent the silent majority."}, {"term": "forgotten people", "ipa": "/fəˈɡɒtən ˈpiːpəl/", "pron": "fuh-GOT-uhn PEE-puhl", "fr": "les oubliés ; les laissés-pour-compte", "def": "Citizens who feel ignored or neglected by political and economic elites.", "ex": "The campaign appealed to forgotten people in deindustrialised regions."}, {"term": "left behind", "ipa": "/ˌleft bɪˈhaɪnd/", "pron": "left bi-HYND", "fr": "laissés pour compte", "def": "People or places that have not benefited from economic or social change.", "ex": "Populist parties often target voters who feel left behind."}, {"term": "people versus elite narrative", "ipa": "/ˈpiːpəl ˌvɜːsəs ɪˈliːt ˈnærətɪv/", "pron": "PEE-puhl VUR-suhs i-LEET NAR-uh-tiv", "fr": "récit peuple contre élites", "def": "A political story that presents society as divided between virtuous ordinary people and corrupt elites.", "ex": "The people-versus-elite narrative simplified complex economic problems."}, {"term": "simplistic solution", "ipa": "/sɪmˈplɪstɪk səˈluːʃən/", "pron": "sim-PLIS-tik suh-LOO-shuhn", "fr": "solution simpliste", "def": "A solution that makes a complex issue seem easier than it really is.", "ex": "Critics argued that the proposal was a simplistic solution to a complex crisis."}, {"term": "soundbite politics", "ipa": "/ˈsaʊndbaɪt ˈpɒlɪtɪks/", "pron": "SOWND-byt POL-i-tiks", "fr": "politique de la petite phrase", "def": "Political communication based on short, memorable phrases rather than detailed argument.", "ex": "Soundbite politics works well on television and social media."}, {"term": "slogan politics", "ipa": "/ˈsləʊɡən ˈpɒlɪtɪks/", "pron": "SLOH-guhn POL-i-tiks", "fr": "politique du slogan", "def": "Politics based on catchy slogans rather than detailed policies.", "ex": "Slogan politics can mobilise voters but oversimplify problems."}, {"term": "post-truth politics", "ipa": "/ˌpəʊst ˈtruːθ ˈpɒlɪtɪks/", "pron": "pohst trooth POL-i-tiks", "fr": "politique post-vérité", "def": "Politics in which emotion and personal belief influence opinion more than facts.", "ex": "Post-truth politics makes fact-checking more difficult."}, {"term": "fake news", "ipa": "/ˌfeɪk ˈnjuːz/", "pron": "fayk nyooz", "fr": "fausses informations ; infox", "def": "False information presented as news, or a term used to discredit unfavourable reporting.", "ex": "The phrase fake news is often used to attack journalists."}, {"term": "conspiracy theory", "ipa": "/kənˈspɪrəsi ˈθɪəri/", "pron": "kuhn-SPIR-uh-see THEE-uh-ree", "fr": "théorie du complot", "def": "A belief that events are secretly controlled by powerful hidden groups, often without evidence.", "ex": "Conspiracy theories can spread rapidly during political crises."}, {"term": "echo chamber", "ipa": "/ˈekəʊ ˌtʃeɪmbə/", "pron": "EK-oh CHAYM-buh", "fr": "chambre d’écho", "def": "An environment in which people mainly hear opinions that confirm their existing beliefs.", "ex": "Social media can create political echo chambers."}, {"term": "filter bubble", "ipa": "/ˈfɪltə ˌbʌbəl/", "pron": "FIL-tuh BUB-uhl", "fr": "bulle de filtres", "def": "An online environment shaped by algorithms that show users information similar to what they already believe.", "ex": "Filter bubbles can reinforce polarisation."}, {"term": "viral message", "ipa": "/ˈvaɪrəl ˈmesɪdʒ/", "pron": "VY-ruhl MESS-ij", "fr": "message viral", "def": "A message that spreads very quickly online.", "ex": "The campaign’s viral message reached millions of users."}, {"term": "social media outrage", "ipa": "/ˌsəʊʃəl ˈmiːdiə ˈaʊtreɪdʒ/", "pron": "SOH-shuhl MEE-dee-uh OWT-rayj", "fr": "indignation sur les réseaux sociaux", "def": "Strong anger expressed and amplified on social media.", "ex": "Social media outrage forced the party to respond quickly."}, {"term": "to mobilise voters", "ipa": "/ˈməʊbɪlaɪz ˈvəʊtəz/", "pron": "MOH-bi-lyz VOH-tuhz", "fr": "mobiliser les électeurs", "def": "To encourage voters to take action, especially to vote or campaign.", "ex": "The party used social media to mobilise young voters."}]}, {"title": "E. Media, disinformation and mobilisation verbs", "entries": [{"term": "to exploit fears", "ipa": "/ɪkˈsplɔɪt ˈfɪəz/", "pron": "ik-SPLOYT fearz", "fr": "exploiter les peurs", "def": "To use people’s anxieties for political advantage.", "ex": "Critics accused the campaign of exploiting fears about immigration."}, {"term": "to fuel resentment", "ipa": "/ˈfjuːəl rɪˈzentmənt/", "pron": "FYOO-uhl ri-ZENT-muhnt", "fr": "alimenter le ressentiment", "def": "To intensify feelings of bitterness or injustice.", "ex": "Inflammatory speeches can fuel resentment against minorities."}, {"term": "to stir up anger", "ipa": "/stɜːr ʌp ˈæŋɡə/", "pron": "stur up ANG-guh", "fr": "attiser la colère", "def": "To deliberately make people angry.", "ex": "The leader tried to stir up anger against the government."}, {"term": "to tap into frustration", "ipa": "/tæp ˈɪntuː frʌˈstreɪʃən/", "pron": "tap IN-too frus-TRAY-shuhn", "fr": "exploiter ; capter la frustration", "def": "To make use of existing public frustration.", "ex": "The campaign tapped into frustration in rural areas."}, {"term": "to channel discontent", "ipa": "/ˈtʃænəl ˌdɪskənˈtent/", "pron": "CHAN-uhl dis-kuhn-TENT", "fr": "canaliser le mécontentement", "def": "To direct public dissatisfaction towards a political cause or movement.", "ex": "Populist parties channelled discontent into electoral gains."}, {"term": "to denounce the elite", "ipa": "/dɪˈnaʊns ði ɪˈliːt/", "pron": "di-NOWNSS thee i-LEET", "fr": "dénoncer l’élite", "def": "To publicly criticise powerful groups.", "ex": "The candidate denounced the elite as corrupt and out of touch."}, {"term": "to bypass institutions", "ipa": "/ˈbaɪpɑːs ˌɪnstɪˈtjuːʃənz/", "pron": "BY-pass in-sti-TOO-shuhnz", "fr": "contourner les institutions", "def": "To avoid or ignore normal institutional procedures.", "ex": "The leader tried to bypass institutions by appealing directly to the people."}, {"term": "to undermine trust", "ipa": "/ˌʌndəˈmaɪn ˈtrʌst/", "pron": "un-duh-MYNE trust", "fr": "saper la confiance", "def": "To weaken confidence in institutions, media or democratic processes.", "ex": "Constant attacks on the media can undermine trust in journalism."}]}]}, {"id": "p1c6", "part": 1, "chapter": 6, "title": "Far Right Extremism", "file": "cpge_vocab_part1_chapter6_far_right_extremism_premium.html", "count": 73, "sections": [{"title": "A. Far-right ideologies and labels", "entries": [{"term": "the far right", "ipa": "/ðə ˌfɑː ˈraɪt/", "pron": "thuh far right", "fr": "l’extrême droite", "def": "The part of the political spectrum associated with extreme nationalism, authoritarian views, anti-immigration politics and hostility to liberal democracy.", "ex": "The rise of the far right has become a major concern in several European democracies."}, {"term": "far-right party", "ipa": "/ˌfɑː raɪt ˈpɑːti/", "pron": "far right PAR-tee", "fr": "parti d’extrême droite", "def": "A political party positioned on the extreme right of the political spectrum.", "ex": "The far-right party gained seats after campaigning on immigration and security."}, {"term": "extreme right", "ipa": "/ɪkˌstriːm ˈraɪt/", "pron": "ik-STREEM right", "fr": "droite extrême ; extrême droite", "def": "A political current that rejects liberal democratic norms and promotes radical nationalist or authoritarian ideas.", "ex": "The report warned about the growing influence of the extreme right online."}, {"term": "radical right", "ipa": "/ˌrædɪkəl ˈraɪt/", "pron": "RAD-i-kuhl right", "fr": "droite radicale", "def": "A form of right-wing politics that is strongly nationalist and anti-immigration but may still participate in elections.", "ex": "Radical right parties often combine electoral politics with anti-establishment rhetoric."}, {"term": "right-wing extremism", "ipa": "/ˌraɪt wɪŋ ɪkˈstriːmɪzəm/", "pron": "right wing ik-STREEM-iz-uhm", "fr": "extrémisme de droite", "def": "Extreme right-wing beliefs or actions that may threaten democratic values, minorities or public safety.", "ex": "Security services have identified right-wing extremism as a growing threat."}, {"term": "extremism", "ipa": "/ɪkˈstriːmɪzəm/", "pron": "ik-STREEM-iz-uhm", "fr": "extrémisme", "def": "Political or religious views and actions that are far outside the mainstream and may reject democratic compromise.", "ex": "Extremism thrives when fear and resentment are exploited."}, {"term": "extremist", "ipa": "/ɪkˈstriːmɪst/", "pron": "ik-STREEM-ist", "fr": "extrémiste", "def": "A person or group holding extreme political or ideological views.", "ex": "Extremist groups often recruit vulnerable people online."}, {"term": "ultranationalism", "ipa": "/ˌʌltrəˈnæʃənəlɪzəm/", "pron": "UL-truh-NASH-uh-nuh-liz-uhm", "fr": "ultranationalisme", "def": "An extreme form of nationalism that places the nation above other values and often excludes minorities or foreigners.", "ex": "Ultranationalism can fuel hostility towards migrants and international institutions."}, {"term": "ethno-nationalism", "ipa": "/ˌeθnəʊ ˈnæʃənəlɪzəm/", "pron": "ETH-noh NASH-uh-nuh-liz-uhm", "fr": "ethno-nationalisme", "def": "A form of nationalism based on ethnic identity and the idea that the nation should belong to one ethnic group.", "ex": "Ethno-nationalism defines belonging in ethnic rather than civic terms."}, {"term": "white nationalism", "ipa": "/ˌwaɪt ˈnæʃənəlɪzəm/", "pron": "white NASH-uh-nuh-liz-uhm", "fr": "nationalisme blanc", "def": "A racist ideology claiming that white people should maintain political and cultural dominance.", "ex": "White nationalism has been linked to violent extremist networks."}, {"term": "white supremacy", "ipa": "/ˌwaɪt səˈpreməsi/", "pron": "white suh-PREM-uh-see", "fr": "suprémacisme blanc", "def": "The racist belief that white people are superior to other racial groups and should dominate society.", "ex": "White supremacy is incompatible with democratic equality."}, {"term": "supremacist", "ipa": "/suːˈpreməsɪst/", "pron": "soo-PREM-uh-sist", "fr": "suprémaciste", "def": "A person who believes that one group is superior and should dominate others.", "ex": "Supremacist propaganda often targets minorities and migrants."}, {"term": "neo-Nazi", "ipa": "/ˌniːəʊ ˈnɑːtsi/", "pron": "nee-oh NAHT-see", "fr": "néonazi", "def": "A person or group that supports modern versions of Nazi ideology.", "ex": "Neo-Nazi groups have used online forums to spread propaganda."}, {"term": "fascism", "ipa": "/ˈfæʃɪzəm/", "pron": "FASH-iz-uhm", "fr": "fascisme", "def": "An authoritarian nationalist ideology that rejects democracy, glorifies strong leadership and often uses violence against opponents.", "ex": "Fascism relies on hierarchy, nationalism and hostility to political pluralism."}, {"term": "fascist", "ipa": "/ˈfæʃɪst/", "pron": "FASH-ist", "fr": "fasciste", "def": "Relating to fascism, or a person who supports fascist ideas.", "ex": "The politician was accused of using fascist imagery."}, {"term": "authoritarian nationalism", "ipa": "/ɔːˌθɒrɪˈteəriən ˈnæʃənəlɪzəm/", "pron": "aw-thor-i-TAIR-ee-uhn NASH-uh-nuh-liz-uhm", "fr": "nationalisme autoritaire", "def": "A form of nationalism that supports strong central authority and weakens democratic checks.", "ex": "Authoritarian nationalism often portrays dissent as betrayal."}, {"term": "national conservatism", "ipa": "/ˈnæʃənəl kənˈsɜːvətɪzəm/", "pron": "NASH-uh-nuhl kuhn-SUR-vuh-tiz-uhm", "fr": "conservatisme national", "def": "A conservative ideology emphasising national sovereignty, tradition, borders and cultural identity.", "ex": "National conservatism has become influential in several Western right-wing parties."}, {"term": "nativism", "ipa": "/ˈneɪtɪvɪzəm/", "pron": "NAY-tiv-iz-uhm", "fr": "nativisme ; préférence nationale", "def": "A political attitude favouring native-born citizens over immigrants.", "ex": "Nativism often appears in far-right rhetoric."}]}, {"title": "B. Exclusion, identity and culture-war rhetoric", "entries": [{"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "zen-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Fear or hatred of foreigners or people from other countries.", "ex": "Xenophobia can be intensified by economic insecurity and political propaganda."}, {"term": "racism", "ipa": "/ˈreɪsɪzəm/", "pron": "RAY-siz-uhm", "fr": "racisme", "def": "The belief that people are inferior or superior because of race, or discrimination based on race.", "ex": "Racism remains a central concern in debates about far-right movements."}, {"term": "antisemitism", "ipa": "/ˌæntiˈsemɪtɪzəm/", "pron": "AN-tee-SEM-i-tiz-uhm", "fr": "antisémitisme", "def": "Hostility, prejudice or discrimination against Jewish people.", "ex": "Antisemitism has often been present in extremist conspiracy theories."}, {"term": "Islamophobia", "ipa": "/ɪzˌlæməˈfəʊbiə/", "pron": "iz-LAM-uh-FOH-bee-uh", "fr": "islamophobie", "def": "Hostility, prejudice or discrimination against Muslims.", "ex": "Islamophobia can be used politically to portray Muslims as a threat."}, {"term": "homophobia", "ipa": "/ˌhəʊməˈfəʊbiə/", "pron": "hoh-muh-FOH-bee-uh", "fr": "homophobie", "def": "Hostility, prejudice or discrimination against gay people.", "ex": "Extremist groups often combine nationalism with homophobia."}, {"term": "transphobia", "ipa": "/trænzˈfəʊbiə/", "pron": "tranz-FOH-bee-uh", "fr": "transphobie", "def": "Hostility, prejudice or discrimination against transgender people.", "ex": "Transphobia has become a recurring theme in some culture-war narratives."}, {"term": "anti-immigration rhetoric", "ipa": "/ˌænti ˌɪmɪˈɡreɪʃən ˈretərɪk/", "pron": "AN-tee im-i-GRAY-shuhn RET-uh-rik", "fr": "rhétorique anti-immigration", "def": "Political language that presents immigration as a threat or problem.", "ex": "Anti-immigration rhetoric intensified during the campaign."}, {"term": "border control", "ipa": "/ˈbɔːdə kənˈtrəʊl/", "pron": "BOR-duh kuhn-TROHL", "fr": "contrôle des frontières", "def": "Policies and measures used to regulate who enters a country.", "ex": "The party made border control a central campaign issue."}, {"term": "mass immigration", "ipa": "/ˌmæs ˌɪmɪˈɡreɪʃən/", "pron": "mass im-i-GRAY-shuhn", "fr": "immigration massive", "def": "Large-scale immigration, often used in political debate with a negative connotation.", "ex": "The phrase mass immigration is often used in alarmist political speeches."}, {"term": "cultural threat", "ipa": "/ˈkʌltʃərəl θret/", "pron": "KUL-chuh-ruhl threat", "fr": "menace culturelle", "def": "The idea that a group, policy or social change endangers a nation’s culture or identity.", "ex": "Far-right movements often frame immigration as a cultural threat."}, {"term": "identity politics", "ipa": "/aɪˈdentəti ˈpɒlɪtɪks/", "pron": "eye-DEN-tuh-tee POL-i-tiks", "fr": "politique identitaire", "def": "Politics based on the interests, identities or experiences of particular groups.", "ex": "Far-right identity politics often focuses on national or ethnic identity."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity, religion, gender, education or national history.", "ex": "Culture-war issues are often used to mobilise angry voters."}, {"term": "traditional values", "ipa": "/trəˌdɪʃənəl ˈvæljuːz/", "pron": "truh-DISH-uh-nuhl VAL-yooz", "fr": "valeurs traditionnelles", "def": "Values presented as rooted in family, religion, nation or older social norms.", "ex": "The candidate claimed to defend traditional values against liberal elites."}, {"term": "law and order", "ipa": "/ˌlɔː ən ˈɔːdə/", "pron": "law uhn OR-duh", "fr": "ordre public ; loi et ordre", "def": "A political emphasis on policing, punishment and public security.", "ex": "Far-right parties often campaign on law and order."}, {"term": "strong borders", "ipa": "/ˌstrɒŋ ˈbɔːdəz/", "pron": "strong BOR-duhz", "fr": "frontières strictes ; contrôle ferme des frontières", "def": "Strict border controls and limits on immigration.", "ex": "The movement demanded strong borders and tougher asylum rules."}, {"term": "national identity", "ipa": "/ˈnæʃənəl aɪˈdentəti/", "pron": "NASH-uh-nuhl eye-DEN-tuh-tee", "fr": "identité nationale", "def": "The sense of belonging to a nation and sharing its culture, history or values.", "ex": "Debates about national identity are often central to far-right politics."}, {"term": "sovereigntist", "ipa": "/ˈsɒvrəntɪst/", "pron": "SOV-ruhn-tist", "fr": "souverainiste", "def": "A person or movement strongly defending national sovereignty against supranational institutions.", "ex": "Sovereigntist parties often criticise the European Union."}, {"term": "Euroscepticism", "ipa": "/ˌjʊərəʊˈskeptɪsɪzəm/", "pron": "YOOR-oh-SKEP-ti-siz-uhm", "fr": "euroscepticisme", "def": "Criticism of the European Union or opposition to European integration.", "ex": "Euroscepticism has become a common feature of many far-right parties."}, {"term": "anti-globalism", "ipa": "/ˌænti ˈɡləʊbəlɪzəm/", "pron": "AN-tee GLOH-buh-liz-uhm", "fr": "anti-mondialisme", "def": "Opposition to globalism, often linked to hostility towards international institutions, elites or migration.", "ex": "Anti-globalism is often mixed with conspiracy theories."}, {"term": "replacement theory", "ipa": "/rɪˈpleɪsmənt ˈθɪəri/", "pron": "ri-PLAYS-muhnt THEE-uh-ree", "fr": "théorie du grand remplacement", "def": "A racist conspiracy theory claiming that native populations are being deliberately replaced by immigrants.", "ex": "Replacement theory has inspired extremist propaganda and violence."}]}, {"title": "C. Conspiracy theories, hatred and violence", "entries": [{"term": "conspiracy theory", "ipa": "/kənˈspɪrəsi ˈθɪəri/", "pron": "kuhn-SPIR-uh-see THEE-uh-ree", "fr": "théorie du complot", "def": "A belief that hidden powerful groups secretly control events, often without evidence.", "ex": "Conspiracy theories can help extremist narratives spread."}, {"term": "scapegoating", "ipa": "/ˈskeɪpɡəʊtɪŋ/", "pron": "SKAYP-goht-ing", "fr": "désignation d’un bouc émissaire", "def": "The act of blaming a person or group unfairly for social or political problems.", "ex": "Scapegoating minorities is a common extremist strategy."}, {"term": "dehumanisation", "ipa": "/diːˌhjuːmənaɪˈzeɪʃən/", "pron": "dee-HYOO-muh-ny-ZAY-shuhn", "fr": "déshumanisation", "def": "The act of portraying people as less than human, often to justify discrimination or violence.", "ex": "Dehumanisation can make violence against minorities seem acceptable."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hayt speech", "fr": "discours de haine", "def": "Speech that attacks or incites hatred against people based on identity, religion, race or other characteristics.", "ex": "Online hate speech can normalise extremist ideas."}, {"term": "incitement", "ipa": "/ɪnˈsaɪtmənt/", "pron": "in-SYTE-muhnt", "fr": "incitation", "def": "The act of encouraging people to commit violence, hatred or illegal actions.", "ex": "The speech was investigated for incitement to violence."}, {"term": "political violence", "ipa": "/pəˈlɪtɪkəl ˈvaɪələns/", "pron": "puh-LIT-i-kuhl VY-uh-luhns", "fr": "violence politique", "def": "Violence used to achieve political goals or intimidate opponents.", "ex": "Political violence can be fuelled by extremist propaganda."}, {"term": "domestic terrorism", "ipa": "/dəˌmestɪk ˈterərɪzəm/", "pron": "duh-MES-tik TER-uh-riz-uhm", "fr": "terrorisme intérieur", "def": "Terrorism carried out within a country by its own citizens or residents.", "ex": "Domestic terrorism has become a major security concern."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "The process by which someone adopts extreme political or religious views.", "ex": "Online communities can accelerate radicalisation."}, {"term": "online radicalisation", "ipa": "/ˌɒnlaɪn ˌrædɪkəlaɪˈzeɪʃən/", "pron": "ON-line rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation en ligne", "def": "Radicalisation that takes place through internet forums, social media or online propaganda.", "ex": "Online radicalisation is difficult for authorities to monitor."}, {"term": "extremist network", "ipa": "/ɪkˈstriːmɪst ˈnetwɜːk/", "pron": "ik-STREEM-ist NET-wurk", "fr": "réseau extrémiste", "def": "A connected group of extremist individuals or organisations.", "ex": "Police uncovered an extremist network planning attacks."}, {"term": "militia", "ipa": "/məˈlɪʃə/", "pron": "muh-LISH-uh", "fr": "milice", "def": "An armed group of civilians, often organised around political or ideological goals.", "ex": "Some far-right militias present themselves as defenders of freedom."}, {"term": "paramilitary group", "ipa": "/ˌpærəˈmɪlɪtəri ɡruːp/", "pron": "par-uh-MIL-i-tuh-ree group", "fr": "groupe paramilitaire", "def": "An armed group organised like a military force but not part of the official army.", "ex": "The paramilitary group intimidated local communities."}, {"term": "vigilantism", "ipa": "/ˌvɪdʒɪˈlæntɪzəm/", "pron": "vij-i-LAN-tiz-uhm", "fr": "justice expéditive ; vigilantisme", "def": "Taking the law into one’s own hands, often through intimidation or violence.", "ex": "Vigilantism can undermine the rule of law."}, {"term": "street movement", "ipa": "/ˈstriːt ˌmuːvmənt/", "pron": "street MOOV-muhnt", "fr": "mouvement de rue", "def": "A political movement that mobilises supporters through demonstrations, marches or confrontations in public spaces.", "ex": "The street movement organised rallies against immigration."}, {"term": "rally", "ipa": "/ˈræli/", "pron": "RAL-ee", "fr": "rassemblement ; meeting", "def": "A large public meeting or demonstration in support of a cause or political figure.", "ex": "The rally attracted both supporters and counter-protesters."}, {"term": "counter-protest", "ipa": "/ˈkaʊntə ˌprəʊtest/", "pron": "KOWN-tuh PROH-test", "fr": "contre-manifestation", "def": "A protest organised against another protest or movement.", "ex": "A counter-protest was organised by anti-racist groups."}, {"term": "dog whistle", "ipa": "/ˈdɒɡ ˌwɪsəl/", "pron": "dog WIS-uhl", "fr": "message codé ; appel du pied", "def": "A coded political message understood by a particular audience but not always obvious to others.", "ex": "Critics accused the candidate of using racist dog whistles."}, {"term": "coded language", "ipa": "/ˌkəʊdɪd ˈlæŋɡwɪdʒ/", "pron": "KOH-did LANG-gwij", "fr": "langage codé", "def": "Language that indirectly communicates controversial or extremist ideas.", "ex": "Coded language allows extremist ideas to reach mainstream audiences."}]}, {"title": "D. Mainstreaming and coded communication", "entries": [{"term": "mainstreaming", "ipa": "/ˈmeɪnstriːmɪŋ/", "pron": "MAYN-streem-ing", "fr": "banalisation ; intégration dans le courant dominant", "def": "The process by which ideas once considered extreme become more widely accepted.", "ex": "The mainstreaming of far-right rhetoric has changed public debate."}, {"term": "normalisation", "ipa": "/ˌnɔːməlaɪˈzeɪʃən/", "pron": "nor-muh-ly-ZAY-shuhn", "fr": "normalisation ; banalisation", "def": "The process by which unacceptable ideas or behaviour come to seem normal.", "ex": "The normalisation of hate speech worries civil rights groups."}, {"term": "sanitised language", "ipa": "/ˈsænɪtaɪzd ˈlæŋɡwɪdʒ/", "pron": "SAN-i-tyzd LANG-gwij", "fr": "langage édulcoré", "def": "Language that makes extreme ideas sound more acceptable or moderate.", "ex": "The group used sanitised language to appeal to mainstream voters."}, {"term": "respectability politics", "ipa": "/rɪˌspektəˈbɪləti ˈpɒlɪtɪks/", "pron": "ri-spek-tuh-BIL-uh-tee POL-i-tiks", "fr": "stratégie de respectabilité", "def": "A strategy of appearing moderate or respectable to gain acceptance.", "ex": "The party adopted respectability politics to distance itself from its extremist roots."}, {"term": "to whitewash", "ipa": "/ˈwaɪtwɒʃ/", "pron": "WHITE-wosh", "fr": "blanchir ; minimiser ; réhabiliter abusivement", "def": "To hide or minimise unpleasant facts about a person, group or history.", "ex": "The documentary was accused of trying to whitewash the movement’s violent past."}, {"term": "to rebrand", "ipa": "/ˌriːˈbrænd/", "pron": "ree-BRAND", "fr": "rebaptiser ; changer d’image", "def": "To change the image of a party, movement or idea to make it more attractive.", "ex": "The party tried to rebrand itself as patriotic rather than extremist."}, {"term": "to radicalise", "ipa": "/ˈrædɪkəlaɪz/", "pron": "RAD-i-kuh-lyz", "fr": "radicaliser", "def": "To make someone adopt extreme political or religious views.", "ex": "Online propaganda can radicalise isolated individuals."}, {"term": "to incite hatred", "ipa": "/ɪnˈsaɪt ˈheɪtrɪd/", "pron": "in-SYTE HAY-trid", "fr": "inciter à la haine", "def": "To encourage hatred against a person or group.", "ex": "The post was removed because it incited hatred."}, {"term": "to spread propaganda", "ipa": "/spred ˌprɒpəˈɡændə/", "pron": "spred prop-uh-GAN-duh", "fr": "diffuser de la propagande", "def": "To circulate biased or misleading political information.", "ex": "Extremist networks use memes to spread propaganda."}, {"term": "to fuel division", "ipa": "/ˈfjuːəl dɪˈvɪʒən/", "pron": "FYOO-uhl di-VIZH-uhn", "fr": "attiser les divisions", "def": "To make social or political divisions worse.", "ex": "Inflammatory speeches can fuel division."}]}, {"title": "E. High-value verbs for analysis", "entries": [{"term": "to exploit fear", "ipa": "/ɪkˈsplɔɪt ˈfɪə/", "pron": "ik-SPLOYT fear", "fr": "exploiter la peur", "def": "To use people’s fear for political advantage.", "ex": "The campaign exploited fear of crime and immigration."}, {"term": "to demonise opponents", "ipa": "/ˈdiːmənaɪz əˈpəʊnənts/", "pron": "DEE-muh-nyz uh-POH-nuhnts", "fr": "diaboliser ses adversaires", "def": "To portray opponents as evil, dangerous or illegitimate.", "ex": "Extremist rhetoric often demonises opponents."}, {"term": "to target minorities", "ipa": "/ˈtɑːɡɪt maɪˈnɒrətiz/", "pron": "TAR-git my-NOR-uh-teez", "fr": "cibler les minorités", "def": "To single out minority groups for blame, discrimination or attacks.", "ex": "Far-right propaganda frequently targets minorities."}, {"term": "to clamp down on", "ipa": "/ˈklæmp daʊn ɒn/", "pron": "klamp down on", "fr": "réprimer ; sévir contre", "def": "To take strong action to stop or punish something.", "ex": "Authorities promised to clamp down on extremist violence."}, {"term": "to ban a group", "ipa": "/bæn ə ˈɡruːp/", "pron": "ban uh group", "fr": "interdire un groupe", "def": "To officially prohibit an organisation from operating.", "ex": "The government decided to ban the group after violent incidents."}, {"term": "to monitor extremists", "ipa": "/ˈmɒnɪtə ɪkˈstriːmɪsts/", "pron": "MON-i-tuh ik-STREEM-ists", "fr": "surveiller les extrémistes", "def": "To watch extremist individuals or groups for security reasons.", "ex": "Security agencies monitor extremists online and offline."}, {"term": "to counter extremism", "ipa": "/ˈkaʊntə ɪkˈstriːmɪzəm/", "pron": "KOWN-tuh ik-STREEM-iz-uhm", "fr": "lutter contre l’extrémisme", "def": "To take action to prevent or reduce extremist influence.", "ex": "Education can help counter extremism by strengthening critical thinking."}]}]}, {"id": "p1c7", "part": 1, "chapter": 7, "title": "Parliament Congress Institutions", "file": "cpge_vocab_part1_chapter7_parliament_congress_institutions_premium.html", "count": 94, "sections": [{"title": "A. Parliaments, chambers and representatives", "entries": [{"term": "parliament", "ipa": "/ˈpɑːləmənt/", "pron": "PAR-luh-muhnt", "fr": "parlement", "def": "A national law-making institution made up of elected or appointed representatives.", "ex": "Parliament debated the bill for several days before voting on it."}, {"term": "Congress", "ipa": "/ˈkɒŋɡres/", "pron": "KON-gress", "fr": "Congrès américain", "def": "The national legislature of the United States, made up of the House of Representatives and the Senate.", "ex": "Congress has the power to pass federal laws and approve the budget."}, {"term": "legislature", "ipa": "/ˈledʒɪslətʃə/", "pron": "LEDJ-is-luh-chuh", "fr": "pouvoir législatif ; assemblée législative", "def": "The institution responsible for making laws in a political system.", "ex": "The legislature rejected the government’s proposal."}, {"term": "bicameral legislature", "ipa": "/ˌbaɪˈkæmərəl ˈledʒɪslətʃə/", "pron": "bye-KAM-uh-ruhl LEDJ-is-luh-chuh", "fr": "parlement bicaméral", "def": "A legislature with two chambers or houses.", "ex": "The United States has a bicameral legislature."}, {"term": "unicameral legislature", "ipa": "/ˌjuːnɪˈkæmərəl ˈledʒɪslətʃə/", "pron": "yoo-ni-KAM-uh-ruhl LEDJ-is-luh-chuh", "fr": "parlement monocaméral", "def": "A legislature with only one chamber.", "ex": "Some smaller countries have a unicameral legislature."}, {"term": "lower house", "ipa": "/ˌləʊə ˈhaʊs/", "pron": "LOH-uh howss", "fr": "chambre basse", "def": "The chamber of a parliament that is often more directly representative of the people.", "ex": "The lower house passed the bill by a narrow majority."}, {"term": "upper house", "ipa": "/ˌʌpə ˈhaʊs/", "pron": "UP-uh howss", "fr": "chambre haute", "def": "The chamber of a parliament that often reviews or revises legislation.", "ex": "The upper house can delay or amend legislation."}, {"term": "House of Commons", "ipa": "/ˌhaʊs əv ˈkɒmənz/", "pron": "howss ov KOM-uhnz", "fr": "Chambre des communes", "def": "The elected lower house of the UK Parliament.", "ex": "The Prime Minister answers questions in the House of Commons every week."}, {"term": "House of Lords", "ipa": "/ˌhaʊs əv ˈlɔːdz/", "pron": "howss ov lordz", "fr": "Chambre des lords", "def": "The upper chamber of the UK Parliament, made up of appointed and hereditary members as well as bishops.", "ex": "The House of Lords reviewed the controversial legislation."}, {"term": "House of Representatives", "ipa": "/ˌhaʊs əv ˌreprɪˈzentətɪvz/", "pron": "howss ov rep-ri-ZEN-tuh-tivz", "fr": "Chambre des représentants", "def": "The lower chamber of the United States Congress.", "ex": "The House of Representatives voted to pass the spending bill."}, {"term": "Senate", "ipa": "/ˈsenət/", "pron": "SEN-uht", "fr": "Sénat", "def": "The upper chamber of the United States Congress or of some other legislatures.", "ex": "The Senate must confirm many presidential appointments."}, {"term": "MP", "ipa": "/ˌem ˈpiː/", "pron": "em pee", "fr": "député ; membre du Parlement", "def": "A Member of Parliament, especially in the United Kingdom.", "ex": "The MP raised the issue during a parliamentary debate."}, {"term": "senator", "ipa": "/ˈsenətə/", "pron": "SEN-uh-tuh", "fr": "sénateur ; sénatrice", "def": "An elected member of a senate.", "ex": "The senator called for stricter gun control."}, {"term": "representative", "ipa": "/ˌreprɪˈzentətɪv/", "pron": "rep-ri-ZEN-tuh-tiv", "fr": "représentant ; élu", "def": "An elected official who speaks and votes on behalf of citizens.", "ex": "Each representative serves a specific district."}, {"term": "lawmaker", "ipa": "/ˈlɔːˌmeɪkə/", "pron": "LAW-may-kuh", "fr": "législateur ; élu", "def": "A person who helps make laws, especially a member of a legislature.", "ex": "Lawmakers are under pressure to reform the immigration system."}, {"term": "backbencher", "ipa": "/ˌbækˈbentʃə/", "pron": "bak-BEN-chuh", "fr": "député de base ; parlementaire sans fonction ministérielle", "def": "An ordinary MP who does not hold a ministerial position, especially in the UK.", "ex": "Backbenchers criticised the government’s handling of the crisis."}, {"term": "frontbencher", "ipa": "/ˌfrʌntˈbentʃə/", "pron": "frunt-BEN-chuh", "fr": "membre de premier plan ; ministre ou membre du cabinet fantôme", "def": "A senior MP who is a minister or shadow minister, especially in the UK.", "ex": "The frontbencher defended the party’s economic policy."}, {"term": "speaker", "ipa": "/ˈspiːkə/", "pron": "SPEE-kuh", "fr": "président de séance ; Speaker", "def": "The official who presides over debates in a legislative chamber.", "ex": "The Speaker asked MPs to respect parliamentary rules."}, {"term": "whip", "ipa": "/wɪp/", "pron": "wip", "fr": "whip ; responsable de discipline parlementaire", "def": "A party official responsible for ensuring that members vote according to the party line.", "ex": "The whip urged party members to support the bill."}, {"term": "party whip", "ipa": "/ˈpɑːti wɪp/", "pron": "PAR-tee wip", "fr": "consigne de vote ; responsable de discipline de parti", "def": "A person or instruction used to enforce party discipline in a legislature.", "ex": "Several MPs defied the party whip."}, {"term": "constituent", "ipa": "/kənˈstɪtjuənt/", "pron": "kuhn-STI-choo-uhnt", "fr": "électeur d’une circonscription ; administré", "def": "A person represented by an elected official.", "ex": "The MP received hundreds of emails from constituents."}, {"term": "constituency", "ipa": "/kənˈstɪtjuənsi/", "pron": "kuhn-STI-choo-uhn-see", "fr": "circonscription électorale", "def": "A geographical area represented by an elected official.", "ex": "The candidate campaigned across the constituency."}, {"term": "seat", "ipa": "/siːt/", "pron": "seet", "fr": "siège", "def": "A position in a legislature held by an elected representative.", "ex": "The party lost several seats in the election."}, {"term": "majority", "ipa": "/məˈdʒɒrəti/", "pron": "muh-JOR-uh-tee", "fr": "majorité", "def": "More than half of the votes or seats in a legislature.", "ex": "The government has a comfortable majority in parliament."}, {"term": "minority", "ipa": "/maɪˈnɒrəti/", "pron": "my-NOR-uh-tee", "fr": "minorité", "def": "Less than half of the votes or seats in a legislature.", "ex": "The party remained in the minority after the election."}, {"term": "opposition", "ipa": "/ˌɒpəˈzɪʃən/", "pron": "op-uh-ZISH-uhn", "fr": "opposition", "def": "The parties or politicians who are not in government and challenge the ruling party.", "ex": "The opposition accused the government of avoiding scrutiny."}, {"term": "ruling majority", "ipa": "/ˈruːlɪŋ məˈdʒɒrəti/", "pron": "ROO-ling muh-JOR-uh-tee", "fr": "majorité gouvernementale", "def": "The group of lawmakers supporting the government and holding most seats.", "ex": "The ruling majority pushed the reform through parliament."}, {"term": "minority government", "ipa": "/maɪˈnɒrəti ˈɡʌvənmənt/", "pron": "my-NOR-uh-tee GUV-uhn-muhnt", "fr": "gouvernement minoritaire", "def": "A government that does not control more than half the seats in parliament.", "ex": "A minority government often needs support from smaller parties."}, {"term": "coalition government", "ipa": "/ˌkəʊəˈlɪʃən ˈɡʌvənmənt/", "pron": "koh-uh-LISH-uhn GUV-uhn-muhnt", "fr": "gouvernement de coalition", "def": "A government formed by two or more political parties.", "ex": "The coalition government struggled to agree on tax reform."}, {"term": "hung parliament", "ipa": "/ˌhʌŋ ˈpɑːləmənt/", "pron": "hung PAR-luh-muhnt", "fr": "parlement sans majorité absolue", "def": "A parliament in which no party has an overall majority.", "ex": "The election produced a hung parliament."}, {"term": "bill", "ipa": "/bɪl/", "pron": "bil", "fr": "projet de loi ; proposition de loi", "def": "A proposed law that is discussed and voted on by a legislature.", "ex": "The bill would introduce tougher rules on online platforms."}]}, {"title": "B. Law-making vocabulary", "entries": [{"term": "law", "ipa": "/lɔː/", "pron": "law", "fr": "loi", "def": "A rule officially adopted and enforced by the state.", "ex": "The new law will come into force next year."}, {"term": "legislation", "ipa": "/ˌledʒɪsˈleɪʃən/", "pron": "lej-is-LAY-shuhn", "fr": "législation", "def": "Laws considered collectively, or the process of making laws.", "ex": "The government introduced new legislation on data privacy."}, {"term": "statute", "ipa": "/ˈstætʃuːt/", "pron": "STAT-choot", "fr": "loi écrite ; texte législatif", "def": "A written law formally passed by a legislative body.", "ex": "The court interpreted the statute narrowly."}, {"term": "amendment", "ipa": "/əˈmendmənt/", "pron": "uh-MEND-muhnt", "fr": "amendement", "def": "A change proposed or made to a bill, law or constitution.", "ex": "The opposition tabled an amendment to the bill."}, {"term": "clause", "ipa": "/klɔːz/", "pron": "klawz", "fr": "clause ; article", "def": "A specific section or provision in a legal document or bill.", "ex": "One clause of the bill caused particular controversy."}, {"term": "motion", "ipa": "/ˈməʊʃən/", "pron": "MOH-shuhn", "fr": "motion", "def": "A formal proposal put forward for debate or vote.", "ex": "MPs voted on a motion of no confidence."}, {"term": "resolution", "ipa": "/ˌrezəˈluːʃən/", "pron": "rez-uh-LOO-shuhn", "fr": "résolution", "def": "A formal statement or decision adopted by a legislative body.", "ex": "The Senate passed a resolution condemning the violence."}, {"term": "committee", "ipa": "/kəˈmɪti/", "pron": "kuh-MIT-ee", "fr": "commission ; comité", "def": "A small group of lawmakers appointed to study, examine or revise specific issues or bills.", "ex": "The committee investigated the government’s pandemic response."}, {"term": "select committee", "ipa": "/sɪˈlekt kəˌmɪti/", "pron": "si-LEKT kuh-MIT-ee", "fr": "commission parlementaire spécialisée", "def": "A parliamentary committee that examines government work or specific policy areas, especially in the UK.", "ex": "The select committee questioned senior officials."}, {"term": "standing committee", "ipa": "/ˈstændɪŋ kəˌmɪti/", "pron": "STAN-ding kuh-MIT-ee", "fr": "commission permanente", "def": "A permanent committee responsible for a particular policy area.", "ex": "The standing committee reviewed the education bill."}, {"term": "committee hearing", "ipa": "/kəˈmɪti ˈhɪərɪŋ/", "pron": "kuh-MIT-ee HEER-ing", "fr": "audition en commission", "def": "A formal meeting where a committee hears evidence from witnesses or experts.", "ex": "The committee hearing revealed serious failures."}, {"term": "witness", "ipa": "/ˈwɪtnəs/", "pron": "WIT-nuhs", "fr": "témoin", "def": "A person who gives evidence to a committee or court.", "ex": "Several witnesses testified before Congress."}, {"term": "testimony", "ipa": "/ˈtestɪməni/", "pron": "TES-ti-muh-nee", "fr": "témoignage ; déposition", "def": "A formal statement given by a witness, especially before a court or committee.", "ex": "Her testimony contradicted the minister’s account."}, {"term": "hearing", "ipa": "/ˈhɪərɪŋ/", "pron": "HEER-ing", "fr": "audition ; audience", "def": "A formal session where evidence or arguments are presented.", "ex": "The hearing focused on social media regulation."}, {"term": "inquiry", "ipa": "/ɪnˈkwaɪəri/", "pron": "in-KWY-uh-ree", "fr": "enquête officielle ; commission d’enquête", "def": "An official investigation into a public issue or failure.", "ex": "The government launched an inquiry into the scandal."}, {"term": "scrutiny", "ipa": "/ˈskruːtəni/", "pron": "SKROO-tuh-nee", "fr": "examen minutieux ; contrôle", "def": "Careful examination of decisions, policies or actions.", "ex": "Parliamentary scrutiny is essential for accountability."}, {"term": "oversight", "ipa": "/ˈəʊvəsaɪt/", "pron": "OH-vuh-syte", "fr": "contrôle ; surveillance institutionnelle", "def": "The monitoring of government actions by another institution.", "ex": "Congressional oversight can limit presidential power."}]}, {"title": "C. Scrutiny, committees and accountability", "entries": [{"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; obligation de rendre des comptes", "def": "The obligation of leaders and institutions to explain and take responsibility for their actions.", "ex": "Parliamentary questions are a tool of democratic accountability."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PAIR-uhn-see", "fr": "transparence", "def": "Openness that allows citizens to understand how decisions are made.", "ex": "Transparency helps citizens trust political institutions."}, {"term": "Prime Minister’s Questions", "ipa": "/ˌpraɪm ˈmɪnɪstəz ˈkwestʃənz/", "pron": "prym MIN-is-tuhz KWES-chuhnz", "fr": "questions au Premier ministre", "def": "A weekly session in the UK House of Commons where MPs question the Prime Minister.", "ex": "Prime Minister’s Questions can be theatrical but politically important."}, {"term": "question time", "ipa": "/ˈkwestʃən taɪm/", "pron": "KWES-chuhn tyme", "fr": "séance de questions au gouvernement", "def": "A period in parliament when government ministers answer questions from lawmakers.", "ex": "Question time allows the opposition to challenge ministers."}, {"term": "vote", "ipa": "/vəʊt/", "pron": "voht", "fr": "vote", "def": "A formal choice made by lawmakers or citizens.", "ex": "The vote was delayed until the following week."}, {"term": "to vote on a bill", "ipa": "/vəʊt ɒn ə ˈbɪl/", "pron": "voht on uh bil", "fr": "voter sur un projet de loi", "def": "To formally decide whether to approve or reject a proposed law.", "ex": "Lawmakers will vote on the bill tomorrow."}, {"term": "to pass a bill", "ipa": "/pɑːs ə ˈbɪl/", "pron": "pass uh bil", "fr": "adopter un projet de loi", "def": "To approve a proposed law through a vote.", "ex": "Parliament passed the bill by a large majority."}, {"term": "to reject a bill", "ipa": "/rɪˈdʒekt ə ˈbɪl/", "pron": "ri-JEKT uh bil", "fr": "rejeter un projet de loi", "def": "To vote against a proposed law.", "ex": "The Senate rejected the bill after a heated debate."}, {"term": "to amend a bill", "ipa": "/əˈmend ə ˈbɪl/", "pron": "uh-MEND uh bil", "fr": "amender un projet de loi", "def": "To make changes to a proposed law.", "ex": "MPs tried to amend the bill to protect civil liberties."}, {"term": "to table an amendment", "ipa": "/ˈteɪbəl ən əˈmendmənt/", "pron": "TAY-buhl uhn uh-MEND-muhnt", "fr": "déposer un amendement", "def": "To formally propose a change to a bill, especially in parliamentary language.", "ex": "The opposition tabled an amendment on workers’ rights."}, {"term": "to repeal a law", "ipa": "/rɪˈpiːl ə ˈlɔː/", "pron": "ri-PEEL uh law", "fr": "abroger une loi", "def": "To officially cancel or remove a law.", "ex": "The new government promised to repeal the controversial law."}, {"term": "to enact legislation", "ipa": "/ɪˈnækt ˌledʒɪsˈleɪʃən/", "pron": "i-NAKT lej-is-LAY-shuhn", "fr": "promulguer ; adopter une loi", "def": "To formally make legislation into law.", "ex": "Congress enacted legislation to protect consumers."}, {"term": "to introduce a bill", "ipa": "/ˌɪntrəˈdjuːs ə ˈbɪl/", "pron": "in-truh-DYOOSS uh bil", "fr": "présenter un projet de loi", "def": "To formally present a proposed law to a legislature.", "ex": "The government introduced a bill on climate targets."}]}, {"title": "D. Votes, procedures and constitutional tools", "entries": [{"term": "to filibuster", "ipa": "/ˈfɪlɪbʌstə/", "pron": "FIL-i-bus-tuh", "fr": "faire de l’obstruction parlementaire", "def": "To delay or block a vote by making long speeches, especially in the US Senate.", "ex": "Senators threatened to filibuster the bill."}, {"term": "filibuster", "ipa": "/ˈfɪlɪbʌstə/", "pron": "FIL-i-bus-tuh", "fr": "obstruction parlementaire", "def": "A tactic used to delay or block legislative action by prolonged debate.", "ex": "The filibuster made it difficult to pass voting rights legislation."}, {"term": "veto", "ipa": "/ˈviːtəʊ/", "pron": "VEE-toh", "fr": "veto", "def": "The power to reject or block a decision or bill.", "ex": "The president used his veto to block the bill."}, {"term": "to veto", "ipa": "/ˈviːtəʊ/", "pron": "VEE-toh", "fr": "opposer son veto", "def": "To reject or block a bill or decision officially.", "ex": "The president threatened to veto the legislation."}, {"term": "override a veto", "ipa": "/ˌəʊvəˈraɪd ə ˈviːtəʊ/", "pron": "OH-vuh-ryd uh VEE-toh", "fr": "passer outre un veto", "def": "To pass a law despite a veto, usually by a special majority.", "ex": "Congress failed to override the veto."}, {"term": "confidence vote", "ipa": "/ˈkɒnfɪdəns vəʊt/", "pron": "KON-fi-duhns voht", "fr": "vote de confiance", "def": "A vote used to show whether a government still has the support of parliament.", "ex": "The prime minister survived a confidence vote."}, {"term": "vote of no confidence", "ipa": "/ˌvəʊt əv nəʊ ˈkɒnfɪdəns/", "pron": "voht ov noh KON-fi-duhns", "fr": "motion de censure ; vote de défiance", "def": "A vote showing that parliament no longer supports the government or leader.", "ex": "The opposition called for a vote of no confidence."}, {"term": "impeachment", "ipa": "/ɪmˈpiːtʃmənt/", "pron": "im-PEECH-muhnt", "fr": "procédure de destitution", "def": "A formal process of charging a high official, especially a president, with serious misconduct.", "ex": "The impeachment inquiry dominated the political agenda."}, {"term": "to impeach", "ipa": "/ɪmˈpiːtʃ/", "pron": "im-PEECH", "fr": "mettre en accusation ; engager une procédure de destitution", "def": "To formally accuse a high official of serious misconduct in office.", "ex": "The House voted to impeach the president."}, {"term": "confirmation hearing", "ipa": "/ˌkɒnfəˈmeɪʃən ˈhɪərɪŋ/", "pron": "kon-fuh-MAY-shuhn HEER-ing", "fr": "audition de confirmation", "def": "A hearing used to assess whether a nominee should be approved for a position.", "ex": "The confirmation hearing focused on the nominee’s judicial record."}, {"term": "nominee", "ipa": "/ˌnɒmɪˈniː/", "pron": "nom-i-NEE", "fr": "personne nommée ; candidat désigné", "def": "A person formally proposed for a position or office.", "ex": "The Supreme Court nominee faced difficult questions."}, {"term": "appointment", "ipa": "/əˈpɔɪntmənt/", "pron": "uh-POINT-muhnt", "fr": "nomination", "def": "The act of choosing someone for an official position.", "ex": "The appointment sparked controversy."}, {"term": "budget", "ipa": "/ˈbʌdʒɪt/", "pron": "BUJ-it", "fr": "budget", "def": "A plan for government income and spending.", "ex": "Parliament must approve the annual budget."}, {"term": "spending bill", "ipa": "/ˈspendɪŋ bɪl/", "pron": "SPEN-ding bil", "fr": "loi de finances ; projet de dépenses", "def": "A proposed law authorising government spending.", "ex": "The spending bill included extra funding for hospitals."}, {"term": "appropriations", "ipa": "/əˌprəʊpriˈeɪʃənz/", "pron": "uh-proh-pree-AY-shuhnz", "fr": "crédits budgétaires", "def": "Money officially allocated by a legislature for government spending.", "ex": "The committee oversees defence appropriations."}, {"term": "government shutdown", "ipa": "/ˈɡʌvənmənt ˈʃʌtdaʊn/", "pron": "GUV-uhn-muhnt SHUT-down", "fr": "fermeture partielle de l’administration", "def": "A situation in the US when parts of the federal government stop operating because funding has not been approved.", "ex": "The budget deadlock led to a government shutdown."}, {"term": "deadlock", "ipa": "/ˈdedlɒk/", "pron": "DED-lok", "fr": "blocage ; impasse", "def": "A situation in which no agreement can be reached.", "ex": "The talks ended in political deadlock."}, {"term": "gridlock", "ipa": "/ˈɡrɪdlɒk/", "pron": "GRID-lok", "fr": "blocage institutionnel", "def": "A political situation in which institutions cannot make decisions because of disagreement.", "ex": "Partisan gridlock prevented major reforms."}, {"term": "bipartisan", "ipa": "/ˌbaɪˈpɑːtɪzən/", "pron": "bye-PAR-ti-zuhn", "fr": "bipartisan ; transpartisan", "def": "Supported by two major political parties.", "ex": "The bill received bipartisan support."}]}, {"title": "E. Budget, deadlock, lobbying and high-value verbs", "entries": [{"term": "cross-party", "ipa": "/ˌkrɒs ˈpɑːti/", "pron": "kross PAR-tee", "fr": "transpartisan", "def": "Involving or supported by several political parties.", "ex": "A cross-party group called for electoral reform."}, {"term": "partisan", "ipa": "/ˈpɑːtɪzən/", "pron": "PAR-ti-zuhn", "fr": "partisan", "def": "Strongly loyal to a political party, sometimes in a biased way.", "ex": "The debate became increasingly partisan."}, {"term": "lobby", "ipa": "/ˈlɒbi/", "pron": "LOB-ee", "fr": "lobby ; groupe de pression", "def": "A group that tries to influence politicians or policy.", "ex": "The energy lobby opposed the new climate law."}, {"term": "lobbyist", "ipa": "/ˈlɒbiɪst/", "pron": "LOB-ee-ist", "fr": "lobbyiste", "def": "A person paid to influence politicians or government decisions.", "ex": "Lobbyists met lawmakers before the vote."}, {"term": "lobbying", "ipa": "/ˈlɒbiɪŋ/", "pron": "LOB-ee-ing", "fr": "lobbying ; pression politique", "def": "The activity of trying to influence political decisions.", "ex": "Lobbying can raise concerns about transparency."}, {"term": "interest group", "ipa": "/ˈɪntrəst ɡruːp/", "pron": "IN-truhst group", "fr": "groupe d’intérêt", "def": "An organised group that tries to influence policy on behalf of its members or cause.", "ex": "Interest groups play an important role in policy debates."}, {"term": "pressure group", "ipa": "/ˈpreʃə ɡruːp/", "pron": "PRESH-uh group", "fr": "groupe de pression", "def": "An organisation that tries to influence government policy without seeking office.", "ex": "Pressure groups campaigned against the reform."}, {"term": "think tank", "ipa": "/ˈθɪŋk tæŋk/", "pron": "think tank", "fr": "groupe de réflexion ; think tank", "def": "An organisation that produces research and policy ideas.", "ex": "A conservative think tank published a report on tax cuts."}, {"term": "to lobby lawmakers", "ipa": "/ˈlɒbi ˈlɔːˌmeɪkəz/", "pron": "LOB-ee LAW-may-kuhz", "fr": "faire pression sur les élus", "def": "To try to influence elected officials.", "ex": "Technology firms lobbied lawmakers over data regulation."}, {"term": "to hold hearings", "ipa": "/həʊld ˈhɪərɪŋz/", "pron": "hohld HEER-ingz", "fr": "tenir des auditions", "def": "To organise formal sessions to gather evidence or question witnesses.", "ex": "The committee held hearings on police reform."}, {"term": "to scrutinise government", "ipa": "/ˈskruːtɪnaɪz ˈɡʌvənmənt/", "pron": "SKROO-ti-nyz GUV-uhn-muhnt", "fr": "contrôler ; examiner l’action du gouvernement", "def": "To examine government actions carefully.", "ex": "Parliament has a duty to scrutinise government."}, {"term": "to hold to account", "ipa": "/həʊld tuː əˈkaʊnt/", "pron": "hohld too uh-KOWNT", "fr": "demander des comptes", "def": "To make someone explain and accept responsibility for their actions.", "ex": "Committees can hold ministers to account."}, {"term": "to block legislation", "ipa": "/blɒk ˌledʒɪsˈleɪʃən/", "pron": "blok lej-is-LAY-shuhn", "fr": "bloquer une loi", "def": "To prevent a proposed law from being passed.", "ex": "The upper house tried to block the legislation."}, {"term": "to push through a reform", "ipa": "/pʊʃ θruː ə rɪˈfɔːm/", "pron": "push throo uh ri-FORM", "fr": "faire passer une réforme en force", "def": "To get a reform approved despite opposition.", "ex": "The government used its majority to push through the reform."}]}]}, {"id": "p1c8", "part": 1, "chapter": 8, "title": "Constitutions Rights Rule Of Law", "file": "cpge_vocab_part1_chapter8_constitutions_rights_rule_of_law_premium.html", "count": 94, "sections": [{"title": "A. Constitutions and constitutional principles", "entries": [{"term": "constitution", "ipa": "/ˌkɒnstɪˈtjuːʃən/", "pron": "kon-sti-TOO-shuhn", "fr": "constitution", "def": "A set of fundamental rules that define how a state is organised and how power is limited.", "ex": "A constitution can protect citizens from abuses of power."}, {"term": "written constitution", "ipa": "/ˌrɪtən ˌkɒnstɪˈtjuːʃən/", "pron": "RIT-uhn kon-sti-TOO-shuhn", "fr": "constitution écrite", "def": "A constitution contained mainly in one formal written document.", "ex": "The United States has a written constitution."}, {"term": "unwritten constitution", "ipa": "/ˌʌnˈrɪtən ˌkɒnstɪˈtjuːʃən/", "pron": "un-RIT-uhn kon-sti-TOO-shuhn", "fr": "constitution non codifiée", "def": "A constitution based on laws, conventions, precedents and traditions rather than one single codified text.", "ex": "The UK is often described as having an unwritten constitution."}, {"term": "constitutional framework", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈfreɪmwɜːk/", "pron": "kon-sti-TOO-shuh-nuhl FRAYM-wurk", "fr": "cadre constitutionnel", "def": "The overall structure of constitutional rules, institutions and principles in a political system.", "ex": "The crisis exposed weaknesses in the constitutional framework."}, {"term": "constitutional principle", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈprɪnsəpəl/", "pron": "kon-sti-TOO-shuh-nuhl PRIN-suh-puhl", "fr": "principe constitutionnel", "def": "A fundamental idea guiding constitutional interpretation and political practice.", "ex": "The separation of powers is a key constitutional principle."}, {"term": "constitutional convention", "ipa": "/ˌkɒnstɪˈtjuːʃənəl kənˈvenʃən/", "pron": "kon-sti-TOO-shuh-nuhl kuhn-VEN-shuhn", "fr": "convention constitutionnelle", "def": "An unwritten political rule or practice considered binding by tradition.", "ex": "By constitutional convention, the British monarch remains politically neutral."}, {"term": "constitutional amendment", "ipa": "/ˌkɒnstɪˈtjuːʃənəl əˈmendmənt/", "pron": "kon-sti-TOO-shuh-nuhl uh-MEND-muhnt", "fr": "amendement constitutionnel", "def": "A formal change made to a constitution.", "ex": "The First Amendment protects freedom of speech."}, {"term": "constitutional law", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈlɔː/", "pron": "kon-sti-TOO-shuh-nuhl law", "fr": "droit constitutionnel", "def": "The area of law dealing with the constitution, institutions, rights and limits on power.", "ex": "The ruling reshaped constitutional law."}, {"term": "constitutional court", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈkɔːt/", "pron": "kon-sti-TOO-shuh-nuhl court", "fr": "cour constitutionnelle", "def": "A court responsible for deciding whether laws comply with the constitution.", "ex": "The constitutional court struck down the law."}, {"term": "constitutional crisis", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈkraɪsɪs/", "pron": "kon-sti-TOO-shuh-nuhl KRY-sis", "fr": "crise constitutionnelle", "def": "A serious conflict or breakdown involving constitutional rules or institutions.", "ex": "The refusal to accept the election result triggered a constitutional crisis."}, {"term": "constitutional order", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈɔːdə/", "pron": "kon-sti-TOO-shuh-nuhl OR-duh", "fr": "ordre constitutionnel", "def": "The established constitutional rules and institutions of a state.", "ex": "The court said the decree threatened the constitutional order."}, {"term": "founding document", "ipa": "/ˈfaʊndɪŋ ˈdɒkjəmənt/", "pron": "FOWN-ding DOK-yuh-muhnt", "fr": "texte fondateur", "def": "A document that establishes the basic principles of a political system.", "ex": "The Constitution is one of America’s founding documents."}, {"term": "founding fathers", "ipa": "/ˌfaʊndɪŋ ˈfɑːðəz/", "pron": "FOWN-ding FAR-thuhz", "fr": "Pères fondateurs", "def": "The political leaders who helped create the United States and its constitutional system.", "ex": "The Founding Fathers designed a system of checks and balances."}, {"term": "Bill of Rights", "ipa": "/ˌbɪl əv ˈraɪts/", "pron": "bil ov rites", "fr": "déclaration des droits ; Bill of Rights", "def": "A formal list of fundamental rights protected by law or by a constitution.", "ex": "The American Bill of Rights protects individual freedoms."}, {"term": "preamble", "ipa": "/ˈpriːæmbəl/", "pron": "PREE-am-buhl", "fr": "préambule", "def": "The introductory statement of a constitution or legal text, often explaining its aims.", "ex": "The preamble sets out the values behind the constitution."}, {"term": "article", "ipa": "/ˈɑːtɪkəl/", "pron": "AR-ti-kuhl", "fr": "article", "def": "A numbered section of a constitution, treaty or legal text.", "ex": "Article I of the US Constitution deals with Congress."}, {"term": "clause", "ipa": "/klɔːz/", "pron": "klawz", "fr": "clause ; disposition", "def": "A specific provision or section in a legal or constitutional text.", "ex": "The clause has been interpreted differently by judges."}, {"term": "provision", "ipa": "/prəˈvɪʒən/", "pron": "pruh-VIZH-uhn", "fr": "disposition", "def": "A rule, condition or requirement included in a legal document.", "ex": "The provision protects citizens from arbitrary detention."}, {"term": "to enshrine", "ipa": "/ɪnˈʃraɪn/", "pron": "in-SHRYNE", "fr": "inscrire ; consacrer", "def": "To formally include a right or principle in a law or constitution.", "ex": "Freedom of religion is enshrined in the constitution."}, {"term": "to amend the constitution", "ipa": "/əˈmend ðə ˌkɒnstɪˈtjuːʃən/", "pron": "uh-MEND thuh kon-sti-TOO-shuhn", "fr": "modifier la constitution", "def": "To make a formal change to a constitution.", "ex": "It is difficult to amend the US Constitution."}, {"term": "to interpret the constitution", "ipa": "/ɪnˈtɜːprɪt ðə ˌkɒnstɪˈtjuːʃən/", "pron": "in-TUR-prit thuh kon-sti-TOO-shuhn", "fr": "interpréter la constitution", "def": "To decide what constitutional rules mean and how they apply.", "ex": "The Supreme Court interprets the Constitution."}]}, {"title": "B. Rule of law and limits on power", "entries": [{"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including leaders and governments, must obey the law.", "ex": "The rule of law prevents leaders from acting above the law."}, {"term": "constitutionalism", "ipa": "/ˌkɒnstɪˈtjuːʃənəlɪzəm/", "pron": "kon-sti-TOO-shuh-nuhl-iz-uhm", "fr": "constitutionnalisme", "def": "The belief that government power must be limited by constitutional rules.", "ex": "Constitutionalism is designed to prevent arbitrary rule."}, {"term": "limited government", "ipa": "/ˌlɪmɪtɪd ˈɡʌvənmənt/", "pron": "LIM-it-id GUV-uhn-muhnt", "fr": "gouvernement limité", "def": "A system in which government power is restricted by law, rights and institutions.", "ex": "Limited government is central to liberal democracy."}, {"term": "arbitrary power", "ipa": "/ˈɑːbɪtrəri ˈpaʊə/", "pron": "AR-bi-truh-ree POW-uh", "fr": "pouvoir arbitraire", "def": "Power exercised without clear legal limits, fairness or accountability.", "ex": "The rule of law protects citizens from arbitrary power."}, {"term": "abuse of power", "ipa": "/əˌbjuːs əv ˈpaʊə/", "pron": "uh-BYOOSS ov POW-uh", "fr": "abus de pouvoir", "def": "The improper or illegal use of authority.", "ex": "Independent courts can challenge abuses of power."}, {"term": "checks and balances", "ipa": "/ˌtʃeks ən ˈbælənsɪz/", "pron": "cheks uhn BAL-uhn-siz", "fr": "freins et contrepoids ; contre-pouvoirs", "def": "A system in which branches of government limit and supervise one another.", "ex": "Checks and balances prevent the concentration of power."}, {"term": "separation of powers", "ipa": "/ˌsepəˈreɪʃən əv ˈpaʊəz/", "pron": "sep-uh-RAY-shuhn ov POW-uhz", "fr": "séparation des pouvoirs", "def": "The division of state power among the executive, legislature and judiciary.", "ex": "The separation of powers protects citizens from tyranny."}, {"term": "executive power", "ipa": "/ɪɡˈzekjətɪv ˈpaʊə/", "pron": "ig-ZEK-yuh-tiv POW-uh", "fr": "pouvoir exécutif", "def": "The authority to implement laws and run government.", "ex": "Executive power often expands during crises."}, {"term": "legislative power", "ipa": "/ˈledʒɪslətɪv ˈpaʊə/", "pron": "LEDJ-is-luh-tiv POW-uh", "fr": "pouvoir législatif", "def": "The authority to make laws.", "ex": "Legislative power belongs to parliament or congress."}, {"term": "judicial power", "ipa": "/dʒuːˈdɪʃəl ˈpaʊə/", "pron": "joo-DISH-uhl POW-uh", "fr": "pouvoir judiciaire", "def": "The authority of courts to interpret and apply the law.", "ex": "Judicial power can limit executive overreach."}, {"term": "executive overreach", "ipa": "/ɪɡˈzekjətɪv ˌəʊvəˈriːtʃ/", "pron": "ig-ZEK-yuh-tiv OH-vuh-reech", "fr": "abus de pouvoir exécutif", "def": "The use of executive authority beyond proper legal or constitutional limits.", "ex": "Critics accused the president of executive overreach."}, {"term": "concentration of power", "ipa": "/ˌkɒnsənˈtreɪʃən əv ˈpaʊə/", "pron": "kon-suhn-TRAY-shuhn ov POW-uh", "fr": "concentration du pouvoir", "def": "The accumulation of political authority in one institution or leader.", "ex": "The concentration of power in the executive alarmed observers."}, {"term": "constitutional safeguard", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈseɪfɡɑːd/", "pron": "kon-sti-TOO-shuh-nuhl SAYF-gard", "fr": "garantie constitutionnelle", "def": "A constitutional rule or mechanism designed to prevent abuses of power.", "ex": "Constitutional safeguards can prevent democratic erosion."}, {"term": "institutional safeguard", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈseɪfɡɑːd/", "pron": "in-sti-TOO-shuh-nuhl SAYF-gard", "fr": "garantie institutionnelle", "def": "An institutional mechanism that protects democracy, rights or accountability.", "ex": "Independent regulators can act as institutional safeguards."}, {"term": "oversight", "ipa": "/ˈəʊvəsaɪt/", "pron": "OH-vuh-syte", "fr": "contrôle ; surveillance institutionnelle", "def": "The monitoring of government actions by another body or institution.", "ex": "Congressional oversight can limit presidential power."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; obligation de rendre des comptes", "def": "The obligation of leaders and institutions to explain and take responsibility for their actions.", "ex": "Accountability is essential in a democracy."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PAIR-uhn-see", "fr": "transparence", "def": "Openness that allows citizens to understand how decisions are made.", "ex": "Transparency helps rebuild trust in institutions."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected by law, such as freedom of speech or assembly.", "ex": "Civil liberties can be threatened during a state of emergency."}]}, {"title": "C. Rights and freedoms", "entries": [{"term": "civil rights", "ipa": "/ˌsɪvəl ˈraɪts/", "pron": "SIV-uhl rites", "fr": "droits civiques", "def": "Rights protecting people from discrimination and guaranteeing equal treatment under the law.", "ex": "The civil rights movement fought segregation."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains ; droits de l’homme", "def": "Fundamental rights believed to belong to every human being.", "ex": "Human rights organisations criticised the crackdown."}, {"term": "political rights", "ipa": "/pəˈlɪtɪkəl ˈraɪts/", "pron": "puh-LIT-i-kuhl rites", "fr": "droits politiques", "def": "Rights allowing people to participate in political life, such as voting or standing for office.", "ex": "Political rights mean little without free elections."}, {"term": "constitutional rights", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈraɪts/", "pron": "kon-sti-TOO-shuh-nuhl rites", "fr": "droits constitutionnels", "def": "Rights protected by a constitution.", "ex": "The ruling expanded constitutional rights."}, {"term": "individual rights", "ipa": "/ˌɪndɪˈvɪdʒuəl ˈraɪts/", "pron": "in-di-VIJ-oo-uhl rites", "fr": "droits individuels", "def": "Rights belonging to each person as an individual.", "ex": "Individual rights may conflict with collective security."}, {"term": "minority rights", "ipa": "/maɪˈnɒrəti ˈraɪts/", "pron": "my-NOR-uh-tee rites", "fr": "droits des minorités", "def": "Rights protecting groups that are smaller in number or less powerful.", "ex": "Liberal democracy must protect minority rights."}, {"term": "voting rights", "ipa": "/ˈvəʊtɪŋ raɪts/", "pron": "VOH-ting rites", "fr": "droit de vote ; droits électoraux", "def": "The legal rights that allow citizens to vote.", "ex": "Voting rights remain a central issue in American politics."}, {"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov speech", "fr": "liberté d’expression", "def": "The right to express opinions and ideas without unjustified government restriction.", "ex": "Freedom of speech protects unpopular opinions too."}, {"term": "freedom of the press", "ipa": "/ˌfriːdəm əv ðə ˈpres/", "pron": "FREE-duhm ov thuh press", "fr": "liberté de la presse", "def": "The right of journalists to report news and criticise power without censorship.", "ex": "Freedom of the press is vital for accountability."}, {"term": "freedom of religion", "ipa": "/ˌfriːdəm əv rɪˈlɪdʒən/", "pron": "FREE-duhm ov ri-LIJ-uhn", "fr": "liberté religieuse", "def": "The right to practise, change or reject a religion.", "ex": "Freedom of religion is protected by the First Amendment."}, {"term": "freedom of assembly", "ipa": "/ˌfriːdəm əv əˈsembli/", "pron": "FREE-duhm ov uh-SEM-blee", "fr": "liberté de réunion ; droit de rassemblement", "def": "The right to gather peacefully in public.", "ex": "Freedom of assembly protects peaceful protest."}, {"term": "freedom of association", "ipa": "/ˌfriːdəm əv əˌsəʊsiˈeɪʃən/", "pron": "FREE-duhm ov uh-soh-see-AY-shuhn", "fr": "liberté d’association", "def": "The right to join groups, unions, parties or organisations.", "ex": "Freedom of association protects trade unions."}, {"term": "right to privacy", "ipa": "/ˌraɪt tə ˈprɪvəsi/", "pron": "rite tuh PRIV-uh-see", "fr": "droit à la vie privée", "def": "The right to keep personal life and information protected from unjustified interference.", "ex": "Digital surveillance raises questions about the right to privacy."}, {"term": "right to protest", "ipa": "/ˌraɪt tə prəˈtest/", "pron": "rite tuh pruh-TEST", "fr": "droit de manifester", "def": "The right to demonstrate publicly and peacefully.", "ex": "The right to protest is a basic democratic freedom."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "dyoo PROH-sess", "fr": "procédure régulière ; garanties procédurales", "def": "Fair legal procedures that must be followed before someone is punished or deprived of rights.", "ex": "Due process protects citizens from arbitrary punishment."}, {"term": "equal protection", "ipa": "/ˌiːkwəl prəˈtekʃən/", "pron": "EE-kwuhl pruh-TEK-shuhn", "fr": "égale protection de la loi", "def": "The principle that the law must protect people equally.", "ex": "Equal protection is central to civil rights cases."}, {"term": "equality before the law", "ipa": "/iˈkwɒləti bɪˌfɔː ðə ˈlɔː/", "pron": "i-KWOL-uh-tee bi-FOR thuh law", "fr": "égalité devant la loi", "def": "The principle that all people are subject to the same laws and legal protections.", "ex": "Equality before the law is a pillar of the rule of law."}, {"term": "judiciary", "ipa": "/dʒuːˈdɪʃəri/", "pron": "joo-DISH-uh-ree", "fr": "pouvoir judiciaire ; système judiciaire", "def": "The system of courts and judges that interprets and applies the law.", "ex": "An independent judiciary is a safeguard against authoritarianism."}, {"term": "judge", "ipa": "/dʒʌdʒ/", "pron": "juj", "fr": "juge", "def": "A public official who decides cases in a court.", "ex": "The judge ruled that the measure was unconstitutional."}, {"term": "justice", "ipa": "/ˈdʒʌstɪs/", "pron": "JUS-tis", "fr": "juge ; magistrat d’une haute cour", "def": "A judge of a high court, especially a supreme court.", "ex": "The justice wrote a powerful dissenting opinion."}]}, {"title": "D. Courts and judicial review", "entries": [{"term": "chief justice", "ipa": "/ˌtʃiːf ˈdʒʌstɪs/", "pron": "cheef JUS-tis", "fr": "président de la Cour suprême", "def": "The leading judge of a supreme court.", "ex": "The Chief Justice presided over the case."}, {"term": "supreme court", "ipa": "/suːˌpriːm ˈkɔːt/", "pron": "soo-PREEM court", "fr": "cour suprême", "def": "The highest court in a legal system.", "ex": "The Supreme Court overturned the previous ruling."}, {"term": "federal court", "ipa": "/ˈfedərəl kɔːt/", "pron": "FED-uh-ruhl court", "fr": "tribunal fédéral", "def": "A court dealing with federal law, especially in the United States.", "ex": "The case was heard in a federal court."}, {"term": "appellate court", "ipa": "/əˈpelət kɔːt/", "pron": "uh-PEL-uht court", "fr": "cour d’appel", "def": "A court that reviews decisions made by lower courts.", "ex": "The appellate court upheld the ruling."}, {"term": "lower court", "ipa": "/ˌləʊə ˈkɔːt/", "pron": "LOH-uh court", "fr": "juridiction inférieure", "def": "A court whose decisions may be reviewed by a higher court.", "ex": "The lower court had ruled against the government."}, {"term": "court ruling", "ipa": "/ˈkɔːt ˌruːlɪŋ/", "pron": "court ROO-ling", "fr": "décision de justice", "def": "An official decision made by a court.", "ex": "The court ruling sparked nationwide protests."}, {"term": "landmark ruling", "ipa": "/ˈlændmɑːk ˌruːlɪŋ/", "pron": "LAND-mark ROO-ling", "fr": "arrêt historique ; décision majeure", "def": "A court decision that is highly important and changes law or society.", "ex": "The landmark ruling transformed abortion rights."}, {"term": "judicial review", "ipa": "/dʒuːˌdɪʃəl rɪˈvjuː/", "pron": "joo-DISH-uhl ri-VYOO", "fr": "contrôle juridictionnel ; contrôle de constitutionnalité", "def": "The power of courts to examine whether laws or actions are constitutional or lawful.", "ex": "Judicial review allows courts to limit government power."}, {"term": "precedent", "ipa": "/ˈpresɪdənt/", "pron": "PRES-i-duhnt", "fr": "précédent juridique", "def": "A previous legal decision that guides future cases.", "ex": "The ruling set an important precedent."}, {"term": "legal challenge", "ipa": "/ˈliːɡəl ˈtʃælɪndʒ/", "pron": "LEE-guhl CHAL-inj", "fr": "recours juridique ; contestation en justice", "def": "A formal attempt to oppose a law or decision in court.", "ex": "Civil rights groups launched a legal challenge."}, {"term": "lawsuit", "ipa": "/ˈlɔːsuːt/", "pron": "LAW-soot", "fr": "procès ; action en justice", "def": "A legal case brought before a court.", "ex": "The company faced a lawsuit over privacy violations."}, {"term": "litigation", "ipa": "/ˌlɪtɪˈɡeɪʃən/", "pron": "lit-i-GAY-shuhn", "fr": "contentieux ; procédure judiciaire", "def": "The process of taking legal action in court.", "ex": "The policy led to years of litigation."}, {"term": "plaintiff", "ipa": "/ˈpleɪntɪf/", "pron": "PLAYN-tif", "fr": "plaignant ; demandeur", "def": "The person or group that brings a case against another party in court.", "ex": "The plaintiff argued that the law violated free speech."}, {"term": "defendant", "ipa": "/dɪˈfendənt/", "pron": "di-FEN-duhnt", "fr": "défendeur ; accusé", "def": "The person or organisation accused or sued in a legal case.", "ex": "The defendant denied any wrongdoing."}, {"term": "legal interpretation", "ipa": "/ˈliːɡəl ɪnˌtɜːprɪˈteɪʃən/", "pron": "LEE-guhl in-tur-pri-TAY-shuhn", "fr": "interprétation juridique", "def": "The process of deciding what a law means.", "ex": "The case depends on legal interpretation."}, {"term": "constitutional interpretation", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ɪnˌtɜːprɪˈteɪʃən/", "pron": "kon-sti-TOO-shuh-nuhl in-tur-pri-TAY-shuhn", "fr": "interprétation constitutionnelle", "def": "The process of deciding what constitutional provisions mean.", "ex": "Constitutional interpretation often divides judges."}, {"term": "originalism", "ipa": "/əˈrɪdʒənəlɪzəm/", "pron": "uh-RIJ-uh-nuhl-iz-uhm", "fr": "originalisme", "def": "A method of constitutional interpretation based on the original meaning of the text.", "ex": "Originalism is influential among conservative judges."}, {"term": "living constitution", "ipa": "/ˌlɪvɪŋ ˌkɒnstɪˈtjuːʃən/", "pron": "LIV-ing kon-sti-TOO-shuhn", "fr": "constitution vivante", "def": "The view that a constitution should be interpreted in light of changing society.", "ex": "Supporters of a living constitution argue that rights evolve over time."}, {"term": "dissenting opinion", "ipa": "/dɪˈsentɪŋ əˈpɪnjən/", "pron": "di-SEN-ting uh-PIN-yuhn", "fr": "opinion dissidente", "def": "An opinion written by a judge who disagrees with the majority decision.", "ex": "The dissenting opinion warned of serious consequences."}, {"term": "majority opinion", "ipa": "/məˈdʒɒrəti əˈpɪnjən/", "pron": "muh-JOR-uh-tee uh-PIN-yuhn", "fr": "opinion majoritaire", "def": "The official opinion of the majority of judges in a case.", "ex": "The majority opinion upheld the law."}, {"term": "to uphold the constitution", "ipa": "/ʌpˈhəʊld ðə ˌkɒnstɪˈtjuːʃən/", "pron": "up-HOHLD thuh kon-sti-TOO-shuhn", "fr": "défendre la constitution", "def": "To defend or maintain constitutional rules and principles.", "ex": "Courts are expected to uphold the constitution."}]}, {"title": "E. High-value CPGE verbs and legal expressions", "entries": [{"term": "to defend civil liberties", "ipa": "/dɪˈfend ˌsɪvəl ˈlɪbətiz/", "pron": "di-FEND SIV-uhl LIB-uh-teez", "fr": "défendre les libertés civiles", "def": "To protect basic freedoms from unjustified restrictions.", "ex": "Activists organised to defend civil liberties."}, {"term": "to challenge a law", "ipa": "/ˈtʃælɪndʒ ə ˈlɔː/", "pron": "CHAL-inj uh law", "fr": "contester une loi", "def": "To formally oppose a law, often in court.", "ex": "The organisation challenged the law in court."}, {"term": "to strike down a law", "ipa": "/straɪk daʊn ə ˈlɔː/", "pron": "stryke down uh law", "fr": "annuler ; invalider une loi", "def": "For a court to declare a law invalid or unconstitutional.", "ex": "The Supreme Court struck down the law."}, {"term": "to overturn a ruling", "ipa": "/ˌəʊvəˈtɜːn ə ˈruːlɪŋ/", "pron": "OH-vuh-turn uh ROO-ling", "fr": "renverser ; annuler une décision de justice", "def": "To reverse a previous court decision.", "ex": "The court overturned a decades-old ruling."}, {"term": "to limit executive power", "ipa": "/ˈlɪmɪt ɪɡˈzekjətɪv ˈpaʊə/", "pron": "LIM-it ig-ZEK-yuh-tiv POW-uh", "fr": "limiter le pouvoir exécutif", "def": "To restrict the authority of the executive branch.", "ex": "The ruling limited executive power."}, {"term": "to protect minority rights", "ipa": "/prəˈtekt maɪˈnɒrəti ˈraɪts/", "pron": "pruh-TEKT my-NOR-uh-tee rites", "fr": "protéger les droits des minorités", "def": "To ensure that minorities are not oppressed or ignored by the majority.", "ex": "Democracy must protect minority rights."}, {"term": "to safeguard freedoms", "ipa": "/ˈseɪfɡɑːd ˈfriːdəmz/", "pron": "SAYF-gard FREE-duhmz", "fr": "préserver les libertés", "def": "To protect freedoms against threats or abuses.", "ex": "Strong institutions help safeguard freedoms."}, {"term": "to expand rights", "ipa": "/ɪkˈspænd ˈraɪts/", "pron": "ik-SPAND rites", "fr": "étendre les droits", "def": "To broaden legal protections or freedoms.", "ex": "The ruling expanded rights for same-sex couples."}, {"term": "to restrict rights", "ipa": "/rɪˈstrɪkt ˈraɪts/", "pron": "ri-STRIKT rites", "fr": "restreindre les droits", "def": "To limit legal protections or freedoms.", "ex": "The new law restricts voting rights."}, {"term": "to weaken institutions", "ipa": "/ˈwiːkən ˌɪnstɪˈtjuːʃənz/", "pron": "WEE-kuhn in-sti-TOO-shuhnz", "fr": "affaiblir les institutions", "def": "To reduce the independence or effectiveness of institutions.", "ex": "Authoritarian leaders often weaken institutions."}, {"term": "to undermine the rule of law", "ipa": "/ˌʌndəˈmaɪn ðə ˌruːl əv ˈlɔː/", "pron": "un-duh-MYNE thuh rool ov law", "fr": "saper l’État de droit", "def": "To damage respect for legal limits and equal application of the law.", "ex": "Political interference in courts can undermine the rule of law."}, {"term": "to strengthen safeguards", "ipa": "/ˈstreŋθən ˈseɪfɡɑːdz/", "pron": "STRENG-thuhn SAYF-gardz", "fr": "renforcer les garanties", "def": "To make protective rules or institutions stronger.", "ex": "The reform aimed to strengthen democratic safeguards."}, {"term": "to set a precedent", "ipa": "/set ə ˈpresɪdənt/", "pron": "set uh PRES-i-duhnt", "fr": "créer un précédent", "def": "To establish a legal example that may guide future decisions.", "ex": "The case set a precedent for future privacy disputes."}, {"term": "to trigger a constitutional crisis", "ipa": "/ˈtrɪɡə ə ˌkɒnstɪˈtjuːʃənəl ˈkraɪsɪs/", "pron": "TRIG-uh uh kon-sti-TOO-shuh-nuhl KRY-sis", "fr": "déclencher une crise constitutionnelle", "def": "To cause a serious conflict involving constitutional rules or institutions.", "ex": "The refusal to leave office could trigger a constitutional crisis."}]}]}, {"id": "p1c9", "part": 1, "chapter": 9, "title": "Lobbying Interest Groups", "file": "cpge_vocab_part1_chapter9_lobbying_interest_groups_premium.html", "count": 99, "sections": [{"title": "A. Lobbying actors and interest groups", "entries": [{"term": "lobbying", "ipa": "/ˈlɒbiɪŋ/", "pron": "LOB-ee-ing", "fr": "lobbying ; pression politique", "def": "The activity of trying to influence political decisions, laws or public policy.", "ex": "Lobbying can raise questions about transparency and democratic accountability."}, {"term": "lobby", "ipa": "/ˈlɒbi/", "pron": "LOB-ee", "fr": "lobby ; groupe de pression", "def": "A group that tries to influence politicians or policy in favour of a specific interest.", "ex": "The energy lobby opposed stricter climate legislation."}, {"term": "lobbyist", "ipa": "/ˈlɒbiɪst/", "pron": "LOB-ee-ist", "fr": "lobbyiste", "def": "A person paid to influence lawmakers, officials or government decisions.", "ex": "Lobbyists met lawmakers before the vote on the bill."}, {"term": "interest group", "ipa": "/ˈɪntrəst ɡruːp/", "pron": "IN-truhst group", "fr": "groupe d’intérêt", "def": "An organised group that tries to influence public policy on behalf of its members or cause.", "ex": "Interest groups play an important role in policy debates."}, {"term": "pressure group", "ipa": "/ˈpreʃə ɡruːp/", "pron": "PRESH-uh group", "fr": "groupe de pression", "def": "An organisation that tries to influence government policy without seeking to govern directly.", "ex": "Pressure groups campaigned against the reform."}, {"term": "advocacy group", "ipa": "/ˈædvəkəsi ɡruːp/", "pron": "AD-vuh-kuh-see group", "fr": "groupe de défense ; association militante", "def": "An organisation that publicly supports a particular cause or policy.", "ex": "An advocacy group called for stronger protections for workers."}, {"term": "campaign group", "ipa": "/kæmˈpeɪn ɡruːp/", "pron": "kam-PAYN group", "fr": "collectif militant ; groupe de campagne", "def": "A group organised to promote or oppose a specific political or social issue.", "ex": "The campaign group urged MPs to reject the proposal."}, {"term": "special interest", "ipa": "/ˌspeʃəl ˈɪntrəst/", "pron": "SPESH-uhl IN-truhst", "fr": "intérêt particulier", "def": "A particular group or cause seeking influence, often contrasted with the public interest.", "ex": "Critics accused the law of favouring special interests."}, {"term": "special interest group", "ipa": "/ˌspeʃəl ˈɪntrəst ɡruːp/", "pron": "SPESH-uhl IN-truhst group", "fr": "groupe d’intérêt particulier", "def": "A group seeking political advantages for a specific industry, profession or cause.", "ex": "Special interest groups spent millions on the campaign."}, {"term": "public interest", "ipa": "/ˌpʌblɪk ˈɪntrəst/", "pron": "PUB-lik IN-truhst", "fr": "intérêt général", "def": "The welfare or benefit of society as a whole.", "ex": "Politicians should place the public interest above private gain."}, {"term": "vested interest", "ipa": "/ˌvestɪd ˈɪntrəst/", "pron": "VES-tid IN-truhst", "fr": "intérêt personnel ; intérêt acquis", "def": "A personal, financial or organisational stake in keeping or changing a policy.", "ex": "Powerful vested interests resisted the reform."}, {"term": "stakeholder", "ipa": "/ˈsteɪkhəʊldə/", "pron": "STAYK-hohl-duh", "fr": "partie prenante", "def": "A person, group or organisation affected by a decision and interested in its outcome.", "ex": "The government consulted key stakeholders before drafting the bill."}, {"term": "trade association", "ipa": "/ˈtreɪd əˌsəʊsiˈeɪʃən/", "pron": "trayd uh-soh-see-AY-shuhn", "fr": "organisation professionnelle ; fédération sectorielle", "def": "An organisation representing companies or professionals in a particular industry.", "ex": "The trade association lobbied against new safety rules."}, {"term": "business lobby", "ipa": "/ˈbɪznəs ˈlɒbi/", "pron": "BIZ-nuhs LOB-ee", "fr": "lobby patronal ; lobby économique", "def": "A group representing business interests and trying to influence policy.", "ex": "The business lobby warned that the tax increase would hurt investment."}, {"term": "corporate lobby", "ipa": "/ˈkɔːpərət ˈlɒbi/", "pron": "KOR-puh-ruht LOB-ee", "fr": "lobby des grandes entreprises", "def": "A lobbying network representing large companies or corporate interests.", "ex": "The corporate lobby pushed for deregulation."}, {"term": "industry lobby", "ipa": "/ˈɪndəstri ˈlɒbi/", "pron": "IN-duh-stree LOB-ee", "fr": "lobby industriel ; lobby sectoriel", "def": "A lobbying group representing a specific industry.", "ex": "The fossil-fuel industry lobby opposed stricter emissions rules."}, {"term": "trade union", "ipa": "/ˌtreɪd ˈjuːniən/", "pron": "trayd YOO-nee-uhn", "fr": "syndicat", "def": "An organisation representing workers and defending their rights and interests.", "ex": "Trade unions demanded higher wages and better working conditions."}, {"term": "union leader", "ipa": "/ˈjuːniən ˈliːdə/", "pron": "YOO-nee-uhn LEE-duh", "fr": "dirigeant syndical", "def": "A person who leads or represents a trade union.", "ex": "Union leaders met government officials during the strike."}, {"term": "professional body", "ipa": "/prəˈfeʃənəl ˈbɒdi/", "pron": "pruh-FESH-uh-nuhl BOD-ee", "fr": "ordre professionnel ; organisme professionnel", "def": "An organisation representing a profession and often setting standards for it.", "ex": "The professional body issued ethical guidelines."}, {"term": "think tank", "ipa": "/ˈθɪŋk tæŋk/", "pron": "think tank", "fr": "groupe de réflexion ; think tank", "def": "An organisation that produces research, policy proposals and political analysis.", "ex": "A free-market think tank published a report on tax reform."}, {"term": "NGO", "ipa": "/ˌen dʒiː ˈəʊ/", "pron": "en jee oh", "fr": "ONG", "def": "A non-governmental organisation, often working on humanitarian, social, environmental or rights issues.", "ex": "The NGO criticised the government’s migration policy."}, {"term": "charity", "ipa": "/ˈtʃærəti/", "pron": "CHAR-uh-tee", "fr": "association caritative ; œuvre de bienfaisance", "def": "An organisation that helps people, communities or causes, often through donations or voluntary work.", "ex": "The charity campaigned for better housing conditions."}, {"term": "civil society organisation", "ipa": "/ˌsɪvəl səˈsaɪəti ˌɔːɡənaɪˈzeɪʃən/", "pron": "SIV-uhl suh-SY-uh-tee or-guh-ny-ZAY-shuhn", "fr": "organisation de la société civile", "def": "An organisation outside the state and market that represents citizens or social causes.", "ex": "Civil society organisations called for greater transparency."}, {"term": "grassroots organisation", "ipa": "/ˈɡrɑːsruːts ˌɔːɡənaɪˈzeɪʃən/", "pron": "GRASS-roots or-guh-ny-ZAY-shuhn", "fr": "organisation de terrain ; mouvement de base", "def": "An organisation built from local activists or ordinary citizens rather than elites.", "ex": "The grassroots organisation mobilised thousands of volunteers."}, {"term": "watchdog", "ipa": "/ˈwɒtʃdɒɡ/", "pron": "WATCH-dog", "fr": "organisme de contrôle ; chien de garde", "def": "A person or organisation that monitors those in power and exposes wrongdoing.", "ex": "The watchdog accused ministers of breaking ethics rules."}, {"term": "regulator", "ipa": "/ˈreɡjʊleɪtə/", "pron": "REG-yuh-lay-tuh", "fr": "autorité de régulation ; régulateur", "def": "An official body responsible for supervising a sector and enforcing rules.", "ex": "The regulator fined the company for misleading consumers."}, {"term": "regulatory agency", "ipa": "/ˈreɡjʊlətəri ˈeɪdʒənsi/", "pron": "REG-yuh-luh-tuh-ree AY-juhn-see", "fr": "agence de régulation", "def": "A public agency that creates or enforces rules in a specific sector.", "ex": "The regulatory agency investigated the pharmaceutical company."}, {"term": "policy-maker", "ipa": "/ˈpɒləsi ˌmeɪkə/", "pron": "POL-uh-see MAY-kuh", "fr": "décideur politique", "def": "A person involved in making public policy, especially in government.", "ex": "Policy-makers face pressure from both industry and activists."}, {"term": "public official", "ipa": "/ˌpʌblɪk əˈfɪʃəl/", "pron": "PUB-lik uh-FISH-uhl", "fr": "responsable public ; fonctionnaire", "def": "A person holding a position in government or public administration.", "ex": "Public officials must avoid conflicts of interest."}, {"term": "elected official", "ipa": "/ɪˌlektɪd əˈfɪʃəl/", "pron": "i-LEK-tid uh-FISH-uhl", "fr": "élu ; responsable élu", "def": "A person chosen by voters to hold public office.", "ex": "Lobbyists often seek access to elected officials."}, {"term": "lawmakers", "ipa": "/ˈlɔːˌmeɪkəz/", "pron": "LAW-may-kuhz", "fr": "législateurs ; élus", "def": "People who make laws, especially members of parliament or congress.", "ex": "Lawmakers were urged to reject the bill."}, {"term": "to lobby", "ipa": "/ˈlɒbi/", "pron": "LOB-ee", "fr": "faire du lobbying ; faire pression", "def": "To try to influence politicians, officials or policy decisions.", "ex": "Technology companies lobbied against stricter privacy rules."}]}, {"title": "B. Influence strategies and political action", "entries": [{"term": "to lobby lawmakers", "ipa": "/ˈlɒbi ˈlɔːˌmeɪkəz/", "pron": "LOB-ee LAW-may-kuhz", "fr": "faire pression sur les élus", "def": "To try to influence elected officials who make laws.", "ex": "Environmental groups lobbied lawmakers before the climate vote."}, {"term": "to influence policy", "ipa": "/ˈɪnfluəns ˈpɒləsi/", "pron": "IN-floo-uhns POL-uh-see", "fr": "influencer les politiques publiques", "def": "To affect government decisions or public policy.", "ex": "Large donors can influence policy in subtle ways."}, {"term": "to shape legislation", "ipa": "/ʃeɪp ˌledʒɪsˈleɪʃən/", "pron": "shayp lej-is-LAY-shuhn", "fr": "façonner la législation", "def": "To influence the content or direction of laws.", "ex": "Lobbyists helped shape the legislation."}, {"term": "to draft a bill", "ipa": "/drɑːft ə ˈbɪl/", "pron": "draft uh bil", "fr": "rédiger un projet de loi", "def": "To write the first version of a proposed law.", "ex": "Industry lawyers helped draft the bill."}, {"term": "to table an amendment", "ipa": "/ˈteɪbəl ən əˈmendmənt/", "pron": "TAY-buhl uhn uh-MEND-muhnt", "fr": "déposer un amendement", "def": "To formally propose a change to a bill.", "ex": "The group persuaded MPs to table an amendment."}, {"term": "to exert pressure", "ipa": "/ɪɡˈzɜːt ˈpreʃə/", "pron": "ig-ZURT PRESH-uh", "fr": "exercer une pression", "def": "To apply influence or pressure on someone or something.", "ex": "Campaigners exerted pressure on the minister."}, {"term": "to put pressure on", "ipa": "/pʊt ˈpreʃə ɒn/", "pron": "put PRESH-uh on", "fr": "mettre la pression sur", "def": "To try to make someone act or change their position.", "ex": "Activists put pressure on the government to act."}, {"term": "to sway a decision", "ipa": "/sweɪ ə dɪˈsɪʒən/", "pron": "sway uh di-SIZH-uhn", "fr": "faire pencher une décision ; influencer", "def": "To influence or change a decision.", "ex": "Donations should not be allowed to sway political decisions."}, {"term": "to push for reform", "ipa": "/pʊʃ fə rɪˈfɔːm/", "pron": "push fuh ri-FORM", "fr": "faire pression pour une réforme", "def": "To strongly support and demand reform.", "ex": "Civil rights groups pushed for reform of the police."}, {"term": "to campaign for", "ipa": "/kæmˈpeɪn fɔː/", "pron": "kam-PAYN for", "fr": "militer pour", "def": "To actively work to support a cause or change.", "ex": "The organisation campaigned for stricter gun laws."}, {"term": "to campaign against", "ipa": "/kæmˈpeɪn əˈɡenst/", "pron": "kam-PAYN uh-GENST", "fr": "faire campagne contre ; militer contre", "def": "To actively work to oppose a policy, person or proposal.", "ex": "Parents campaigned against school closures."}, {"term": "to advocate for", "ipa": "/ˈædvəkeɪt fɔː/", "pron": "AD-vuh-kayt for", "fr": "plaider pour ; défendre", "def": "To publicly support or recommend a policy or cause.", "ex": "The group advocates for stronger environmental protections."}, {"term": "to oppose a bill", "ipa": "/əˈpəʊz ə ˈbɪl/", "pron": "uh-POHZ uh bil", "fr": "s’opposer à un projet de loi", "def": "To be against a proposed law.", "ex": "The business lobby opposed the bill."}, {"term": "to back a proposal", "ipa": "/bæk ə prəˈpəʊzəl/", "pron": "bak uh pruh-POH-zuhl", "fr": "soutenir une proposition", "def": "To support a plan or proposal.", "ex": "Several unions backed the proposal."}, {"term": "to fund a campaign", "ipa": "/fʌnd ə kæmˈpeɪn/", "pron": "fund uh kam-PAYN", "fr": "financer une campagne", "def": "To provide money for a political campaign or cause.", "ex": "Wealthy donors funded the campaign."}, {"term": "to donate", "ipa": "/dəʊˈneɪt/", "pron": "doh-NAYT", "fr": "faire un don", "def": "To give money or resources to a person, organisation or cause.", "ex": "Companies donated to both major parties."}, {"term": "donation", "ipa": "/dəʊˈneɪʃən/", "pron": "doh-NAY-shuhn", "fr": "don ; contribution", "def": "Money or resources given to a party, candidate or organisation.", "ex": "Large donations can create suspicion of undue influence."}]}, {"title": "C. Money, donations and campaign finance", "entries": [{"term": "political donation", "ipa": "/pəˈlɪtɪkəl dəʊˈneɪʃən/", "pron": "puh-LIT-i-kuhl doh-NAY-shuhn", "fr": "don politique", "def": "Money given to a party, candidate or political campaign.", "ex": "The investigation focused on political donations."}, {"term": "donor", "ipa": "/ˈdəʊnə/", "pron": "DOH-nuh", "fr": "donateur ; donatrice", "def": "A person or organisation that gives money to a party, candidate or cause.", "ex": "Major donors were invited to private meetings."}, {"term": "megadonor", "ipa": "/ˈmeɡəˌdəʊnə/", "pron": "MEG-uh-DOH-nuh", "fr": "très gros donateur", "def": "A very wealthy donor who gives large amounts of money to political campaigns.", "ex": "Megadonors can gain privileged access to candidates."}, {"term": "campaign finance", "ipa": "/kæmˈpeɪn ˈfaɪnæns/", "pron": "kam-PAYN FY-nans", "fr": "financement des campagnes", "def": "The money raised and spent to support political campaigns.", "ex": "Campaign finance rules vary widely between countries."}, {"term": "campaign spending", "ipa": "/kæmˈpeɪn ˈspendɪŋ/", "pron": "kam-PAYN SPEN-ding", "fr": "dépenses de campagne", "def": "Money spent during an election campaign.", "ex": "Campaign spending reached record levels."}, {"term": "political action committee", "ipa": "/pəˈlɪtɪkəl ˈækʃən kəˌmɪti/", "pron": "puh-LIT-i-kuhl AK-shuhn kuh-MIT-ee", "fr": "comité d’action politique", "def": "A US organisation that raises and spends money to support or oppose candidates or policies.", "ex": "Political action committees play a major role in US elections."}, {"term": "PAC", "ipa": "/ˌpiː eɪ ˈsiː/", "pron": "pee ay see", "fr": "PAC ; comité d’action politique", "def": "Short for political action committee.", "ex": "The PAC spent millions on advertising."}, {"term": "Super PAC", "ipa": "/ˈsuːpə pæk/", "pron": "SOO-puh pak", "fr": "Super PAC", "def": "A US political committee that can raise and spend unlimited money independently of candidates.", "ex": "Super PACs have transformed campaign finance."}, {"term": "dark money", "ipa": "/ˌdɑːk ˈmʌni/", "pron": "dark MUN-ee", "fr": "argent opaque ; financement politique opaque", "def": "Political spending by groups that do not fully disclose their donors.", "ex": "Dark money makes political influence harder to trace."}, {"term": "soft money", "ipa": "/ˌsɒft ˈmʌni/", "pron": "soft MUN-ee", "fr": "financement indirect de campagne", "def": "Political contributions not given directly to a candidate but used to influence campaigns or party activity.", "ex": "Soft money has long been controversial in US politics."}, {"term": "fundraising", "ipa": "/ˈfʌndˌreɪzɪŋ/", "pron": "FUND-ray-zing", "fr": "collecte de fonds", "def": "The process of collecting money for a political campaign, party or cause.", "ex": "Fundraising is now a permanent part of American politics."}, {"term": "fundraiser", "ipa": "/ˈfʌndˌreɪzə/", "pron": "FUND-ray-zuh", "fr": "collecte de fonds ; événement de collecte", "def": "An event or person involved in raising money for a cause or campaign.", "ex": "The candidate attended a private fundraiser."}, {"term": "access", "ipa": "/ˈækses/", "pron": "AK-sess", "fr": "accès", "def": "The ability to meet or communicate with decision-makers.", "ex": "Donors often seek access to powerful officials."}, {"term": "privileged access", "ipa": "/ˈprɪvəlɪdʒd ˈækses/", "pron": "PRIV-uh-lijd AK-sess", "fr": "accès privilégié", "def": "Special access to politicians or officials not available to ordinary citizens.", "ex": "Privileged access can undermine public trust."}, {"term": "undue influence", "ipa": "/ˌʌnˈdjuː ˈɪnfluəns/", "pron": "un-DYOO IN-floo-uhns", "fr": "influence indue ; influence excessive", "def": "Excessive or improper influence over decisions.", "ex": "Critics warned of undue influence by corporate donors."}, {"term": "conflict of interest", "ipa": "/ˌkɒnflɪkt əv ˈɪntrəst/", "pron": "KON-flikt ov IN-truhst", "fr": "conflit d’intérêts", "def": "A situation in which someone’s private interests could influence their public duties.", "ex": "The minister denied any conflict of interest."}, {"term": "revolving door", "ipa": "/rɪˌvɒlvɪŋ ˈdɔː/", "pron": "ri-VOL-ving door", "fr": "pantouflage ; porte tournante", "def": "The movement of people between government positions and private-sector lobbying jobs.", "ex": "The revolving door between government and industry raises ethical concerns."}, {"term": "former official", "ipa": "/ˌfɔːmə əˈfɪʃəl/", "pron": "FOR-muh uh-FISH-uhl", "fr": "ancien responsable public", "def": "Someone who previously held a public position.", "ex": "Former officials often become lobbyists."}]}, {"title": "D. Ethics, corruption and transparency", "entries": [{"term": "insider access", "ipa": "/ɪnˈsaɪdə ˈækses/", "pron": "in-SY-duh AK-sess", "fr": "accès d’initié", "def": "Privileged access based on personal connections inside political institutions.", "ex": "Insider access gives some groups more influence than others."}, {"term": "political connections", "ipa": "/pəˈlɪtɪkəl kəˈnekʃənz/", "pron": "puh-LIT-i-kuhl kuh-NEK-shuhnz", "fr": "relations politiques ; réseaux politiques", "def": "Links with politicians, parties or officials that may provide influence.", "ex": "The company benefited from strong political connections."}, {"term": "influence peddling", "ipa": "/ˈɪnfluəns ˌpedlɪŋ/", "pron": "IN-floo-uhns PED-ling", "fr": "trafic d’influence", "def": "Using connections or power to obtain favours, often improperly or illegally.", "ex": "The scandal involved allegations of influence peddling."}, {"term": "bribery", "ipa": "/ˈbraɪbəri/", "pron": "BRY-buh-ree", "fr": "corruption ; pot-de-vin", "def": "The act of offering or receiving money or gifts to influence someone illegally.", "ex": "Several officials were accused of bribery."}, {"term": "kickback", "ipa": "/ˈkɪkbæk/", "pron": "KIK-bak", "fr": "commission occulte ; pot-de-vin", "def": "An illegal payment made in return for a favour or contract.", "ex": "The contract involved secret kickbacks."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Dishonest or illegal behaviour by people in power, often involving personal gain.", "ex": "Corruption scandals can destroy public trust."}, {"term": "cronyism", "ipa": "/ˈkrəʊniɪzəm/", "pron": "KROH-nee-iz-uhm", "fr": "copinage ; favoritisme", "def": "Giving jobs, contracts or advantages to friends and allies.", "ex": "Cronyism weakened trust in public procurement."}, {"term": "transparency rules", "ipa": "/trænsˈpærənsi ruːlz/", "pron": "trans-PAIR-uhn-see roolz", "fr": "règles de transparence", "def": "Rules requiring openness about decisions, meetings, money or influence.", "ex": "Transparency rules require lobbyists to disclose meetings."}, {"term": "disclosure", "ipa": "/dɪsˈkləʊʒə/", "pron": "dis-KLOH-zhuh", "fr": "divulgation ; déclaration publique", "def": "The act of making information public, especially about money, interests or influence.", "ex": "Disclosure of political donations should be mandatory."}, {"term": "disclosure rules", "ipa": "/dɪsˈkləʊʒə ruːlz/", "pron": "dis-KLOH-zhuh roolz", "fr": "règles de divulgation", "def": "Rules requiring people or organisations to reveal relevant information.", "ex": "Disclosure rules help voters see who funds campaigns."}, {"term": "lobbying register", "ipa": "/ˈlɒbiɪŋ ˈredʒɪstə/", "pron": "LOB-ee-ing REJ-i-stuh", "fr": "registre des lobbys", "def": "An official list recording lobbyists and their clients or activities.", "ex": "A lobbying register can make influence more visible."}, {"term": "ethics rules", "ipa": "/ˈeθɪks ruːlz/", "pron": "ETH-iks roolz", "fr": "règles d’éthique", "def": "Rules designed to ensure honest and responsible conduct in public life.", "ex": "Ethics rules restrict gifts from lobbyists."}, {"term": "cooling-off period", "ipa": "/ˌkuːlɪŋ ˈɒf ˌpɪəriəd/", "pron": "KOO-ling off PEER-ee-uhd", "fr": "période de carence", "def": "A required waiting period before former officials can work as lobbyists.", "ex": "A cooling-off period can reduce revolving-door conflicts."}, {"term": "gift ban", "ipa": "/ˈɡɪft bæn/", "pron": "gift ban", "fr": "interdiction des cadeaux", "def": "A rule forbidding officials from accepting gifts from lobbyists or interested groups.", "ex": "The gift ban was introduced after a lobbying scandal."}, {"term": "public consultation", "ipa": "/ˌpʌblɪk ˌkɒnsəlˈteɪʃən/", "pron": "PUB-lik kon-suhl-TAY-shuhn", "fr": "consultation publique", "def": "A process in which citizens or stakeholders are invited to comment on a policy proposal.", "ex": "The government launched a public consultation on transport policy."}, {"term": "stakeholder consultation", "ipa": "/ˈsteɪkhəʊldə ˌkɒnsəlˈteɪʃən/", "pron": "STAYK-hohl-duh kon-suhl-TAY-shuhn", "fr": "consultation des parties prenantes", "def": "A process of consulting groups affected by a policy.", "ex": "Stakeholder consultation helped improve the legislation."}, {"term": "grassroots lobbying", "ipa": "/ˈɡrɑːsruːts ˈlɒbiɪŋ/", "pron": "GRASS-roots LOB-ee-ing", "fr": "lobbying citoyen ; mobilisation de terrain", "def": "Lobbying that mobilises ordinary citizens to contact decision-makers.", "ex": "Grassroots lobbying pressured senators to support the bill."}, {"term": "astroturfing", "ipa": "/ˈæstrəʊtɜːfɪŋ/", "pron": "AS-troh-turf-ing", "fr": "fausse mobilisation citoyenne", "def": "A fake grassroots campaign created or funded by powerful interests.", "ex": "The campaign was criticised as astroturfing."}, {"term": "public affairs", "ipa": "/ˌpʌblɪk əˈfeəz/", "pron": "PUB-lik uh-FAIRZ", "fr": "affaires publiques", "def": "Professional work focused on influencing policy, managing reputation and communicating with government.", "ex": "Many companies hire public affairs consultants."}, {"term": "public relations", "ipa": "/ˌpʌblɪk rɪˈleɪʃənz/", "pron": "PUB-lik ri-LAY-shuhnz", "fr": "relations publiques", "def": "The practice of managing an organisation’s public image.", "ex": "The company used public relations to defend its record."}, {"term": "advocacy campaign", "ipa": "/ˈædvəkəsi kæmˌpeɪn/", "pron": "AD-vuh-kuh-see kam-PAYN", "fr": "campagne de plaidoyer", "def": "A campaign designed to influence policy or public opinion on a cause.", "ex": "The advocacy campaign highlighted child poverty."}]}, {"title": "E. Public advocacy and high-value verbs", "entries": [{"term": "petition", "ipa": "/pəˈtɪʃən/", "pron": "puh-TISH-uhn", "fr": "pétition", "def": "A written request signed by many people asking for action.", "ex": "The petition called for a ban on single-use plastics."}, {"term": "open letter", "ipa": "/ˌəʊpən ˈletə/", "pron": "OH-puhn LET-uh", "fr": "lettre ouverte", "def": "A public letter addressed to a person or institution, often used to influence debate.", "ex": "Scientists published an open letter to the government."}, {"term": "public pressure", "ipa": "/ˌpʌblɪk ˈpreʃə/", "pron": "PUB-lik PRESH-uh", "fr": "pression publique", "def": "Pressure from citizens, media or public opinion.", "ex": "Public pressure forced the minister to resign."}, {"term": "media campaign", "ipa": "/ˈmiːdiə kæmˌpeɪn/", "pron": "MEE-dee-uh kam-PAYN", "fr": "campagne médiatique", "def": "A coordinated effort to influence public opinion through the media.", "ex": "The group launched a media campaign against the policy."}, {"term": "awareness campaign", "ipa": "/əˈweənəs kæmˌpeɪn/", "pron": "uh-WAIR-nuhs kam-PAYN", "fr": "campagne de sensibilisation", "def": "A campaign designed to inform the public about an issue.", "ex": "The awareness campaign focused on air pollution."}, {"term": "to raise awareness", "ipa": "/reɪz əˈweənəs/", "pron": "rayz uh-WAIR-nuhs", "fr": "sensibiliser", "def": "To make people more aware of an issue.", "ex": "The charity works to raise awareness of homelessness."}, {"term": "to mobilise support", "ipa": "/ˈməʊbɪlaɪz səˈpɔːt/", "pron": "MOH-bi-lyz suh-PORT", "fr": "mobiliser des soutiens", "def": "To encourage people to support a campaign or cause.", "ex": "The union mobilised support for the strike."}, {"term": "to shape public opinion", "ipa": "/ʃeɪp ˌpʌblɪk əˈpɪnjən/", "pron": "shayp PUB-lik uh-PIN-yuhn", "fr": "façonner l’opinion publique", "def": "To influence what people think about an issue.", "ex": "Lobbying campaigns often try to shape public opinion."}, {"term": "to disclose donations", "ipa": "/dɪsˈkləʊz dəʊˈneɪʃənz/", "pron": "dis-KLOHZ doh-NAY-shuhnz", "fr": "déclarer les dons", "def": "To make political donations public.", "ex": "Parties should disclose donations above a certain threshold."}, {"term": "to regulate lobbying", "ipa": "/ˈreɡjʊleɪt ˈlɒbiɪŋ/", "pron": "REG-yuh-layt LOB-ee-ing", "fr": "encadrer le lobbying", "def": "To create and enforce rules governing lobbying activities.", "ex": "Many democracies have tried to regulate lobbying more strictly."}, {"term": "to curb undue influence", "ipa": "/kɜːb ˌʌnˈdjuː ˈɪnfluəns/", "pron": "curb un-DYOO IN-floo-uhns", "fr": "limiter l’influence indue", "def": "To limit improper or excessive political influence.", "ex": "Transparency laws aim to curb undue influence."}]}]}, {"id": "p1c10", "part": 1, "chapter": 10, "title": "Public Opinion Polling", "file": "cpge_vocab_part1_chapter10_public_opinion_polling_premium.html", "count": 94, "sections": [{"title": "A. Polling basics and methodology", "entries": [{"term": "public opinion", "ipa": "/ˌpʌblɪk əˈpɪnjən/", "pron": "PUB-lik uh-PIN-yuhn", "fr": "opinion publique", "def": "The views and attitudes held by the public on political or social issues.", "ex": "Public opinion shifted after the televised debate."}, {"term": "poll", "ipa": "/pəʊl/", "pron": "pohl", "fr": "sondage", "def": "A survey used to measure public opinion, especially before an election.", "ex": "The latest poll shows the two candidates are tied."}, {"term": "opinion poll", "ipa": "/əˈpɪnjən pəʊl/", "pron": "uh-PIN-yuhn pohl", "fr": "sondage d’opinion", "def": "A survey asking people what they think about a political issue, party or candidate.", "ex": "An opinion poll suggested growing support for the reform."}, {"term": "polling", "ipa": "/ˈpəʊlɪŋ/", "pron": "POH-ling", "fr": "sondages ; pratique du sondage", "def": "The activity of conducting polls or measuring public opinion.", "ex": "Polling has become central to modern political campaigns."}, {"term": "pollster", "ipa": "/ˈpəʊlstə/", "pron": "POHL-stuh", "fr": "sondeur ; institut de sondage", "def": "A person or organisation that conducts opinion polls.", "ex": "Pollsters underestimated support for the challenger."}, {"term": "survey", "ipa": "/ˈsɜːveɪ/", "pron": "SUR-vay", "fr": "enquête ; sondage", "def": "A set of questions used to collect information from a group of people.", "ex": "The survey asked voters about healthcare and inflation."}, {"term": "questionnaire", "ipa": "/ˌkwestʃəˈneə/", "pron": "kwes-chuh-NAIR", "fr": "questionnaire", "def": "A written or online list of questions used to gather information.", "ex": "The questionnaire included questions about voting intentions."}, {"term": "sample", "ipa": "/ˈsɑːmpəl/", "pron": "SAM-puhl", "fr": "échantillon", "def": "A smaller group of people selected to represent a larger population.", "ex": "A poll is only reliable if the sample is representative."}, {"term": "representative sample", "ipa": "/ˌreprɪˈzentətɪv ˈsɑːmpəl/", "pron": "rep-ri-ZEN-tuh-tiv SAM-puhl", "fr": "échantillon représentatif", "def": "A sample that reflects the characteristics of the wider population.", "ex": "The poll used a representative sample of 2,000 adults."}, {"term": "sample size", "ipa": "/ˈsɑːmpəl saɪz/", "pron": "SAM-puhl syze", "fr": "taille de l’échantillon", "def": "The number of people included in a survey or poll.", "ex": "A larger sample size can reduce statistical uncertainty."}, {"term": "respondent", "ipa": "/rɪˈspɒndənt/", "pron": "ri-SPON-duhnt", "fr": "répondant ; personne interrogée", "def": "A person who answers questions in a survey or poll.", "ex": "Only 34% of respondents trusted the government."}, {"term": "demographic group", "ipa": "/ˌdeməˈɡræfɪk ɡruːp/", "pron": "dem-uh-GRAF-ik group", "fr": "groupe démographique", "def": "A category of people defined by features such as age, gender, income, education or location.", "ex": "The candidate performed well among younger demographic groups."}, {"term": "breakdown", "ipa": "/ˈbreɪkdaʊn/", "pron": "BRAYK-down", "fr": "répartition ; ventilation des résultats", "def": "A detailed analysis showing how results differ between groups.", "ex": "The poll included a breakdown by age and region."}, {"term": "margin of error", "ipa": "/ˌmɑːdʒɪn əv ˈerə/", "pron": "MAR-jin ov AIR-uh", "fr": "marge d’erreur", "def": "The amount by which poll results may differ from the true value in the population.", "ex": "The lead is within the margin of error."}, {"term": "confidence level", "ipa": "/ˈkɒnfɪdəns ˈlevəl/", "pron": "KON-fi-duhns LEV-uhl", "fr": "niveau de confiance", "def": "A statistical measure showing how likely it is that poll results fall within the margin of error.", "ex": "The poll had a 95% confidence level."}, {"term": "weighting", "ipa": "/ˈweɪtɪŋ/", "pron": "WAY-ting", "fr": "pondération", "def": "A statistical adjustment used to make survey results better reflect the population.", "ex": "Weighting can correct imbalances in a polling sample."}, {"term": "methodology", "ipa": "/ˌmeθəˈdɒlədʒi/", "pron": "meth-uh-DOL-uh-jee", "fr": "méthodologie", "def": "The methods and procedures used to conduct a survey or poll.", "ex": "The poll’s methodology was criticised by analysts."}, {"term": "data", "ipa": "/ˈdeɪtə/", "pron": "DAY-tuh", "fr": "données", "def": "Information collected for analysis, especially numbers or survey responses.", "ex": "The data show a sharp decline in trust."}, {"term": "raw data", "ipa": "/ˌrɔː ˈdeɪtə/", "pron": "raw DAY-tuh", "fr": "données brutes", "def": "Data before it has been processed or adjusted.", "ex": "The raw data were later adjusted through weighting."}, {"term": "cross-tabulation", "ipa": "/ˌkrɒs ˌtæbjʊˈleɪʃən/", "pron": "kross tab-yuh-LAY-shuhn", "fr": "tableau croisé", "def": "A table showing how answers vary across different categories or groups.", "ex": "The cross-tabulation showed a gender gap in voting intentions."}, {"term": "trend", "ipa": "/trend/", "pron": "trend", "fr": "tendance", "def": "A general direction of change over time.", "ex": "The trend suggests rising concern about climate change."}, {"term": "long-term trend", "ipa": "/ˌlɒŋ tɜːm ˈtrend/", "pron": "long term trend", "fr": "tendance de long terme", "def": "A pattern of change observed over a long period.", "ex": "The long-term trend shows declining party loyalty."}, {"term": "snapshot", "ipa": "/ˈsnæpʃɒt/", "pron": "SNAP-shot", "fr": "instantané ; photographie à un moment donné", "def": "A picture of public opinion at one moment in time.", "ex": "A poll is only a snapshot, not a prediction."}]}, {"title": "B. Approval, voting intentions and electoral uncertainty", "entries": [{"term": "approval rating", "ipa": "/əˈpruːvəl ˈreɪtɪŋ/", "pron": "uh-PROO-vuhl RAY-ting", "fr": "taux d’approbation ; cote de popularité", "def": "The percentage of people who approve of a leader, government or institution.", "ex": "The president’s approval rating fell after the scandal."}, {"term": "disapproval rating", "ipa": "/ˌdɪsəˈpruːvəl ˈreɪtɪŋ/", "pron": "dis-uh-PROO-vuhl RAY-ting", "fr": "taux de désapprobation", "def": "The percentage of people who disapprove of a leader, government or institution.", "ex": "The prime minister’s disapproval rating reached a record high."}, {"term": "net approval", "ipa": "/ˌnet əˈpruːvəl/", "pron": "net uh-PROO-vuhl", "fr": "solde d’approbation", "def": "The difference between approval and disapproval ratings.", "ex": "The leader’s net approval turned negative."}, {"term": "favourability rating", "ipa": "/ˌfeɪvərəˈbɪləti ˈreɪtɪŋ/", "pron": "fay-vuh-ruh-BIL-uh-tee RAY-ting", "fr": "cote de sympathie ; image favorable", "def": "A measure of whether people have a positive or negative view of a person, party or institution.", "ex": "The candidate’s favourability rating improved after the debate."}, {"term": "trust rating", "ipa": "/ˈtrʌst ˈreɪtɪŋ/", "pron": "trust RAY-ting", "fr": "niveau de confiance", "def": "A measure of how much people trust a person, party or institution.", "ex": "The media’s trust rating has declined in many countries."}, {"term": "voting intention", "ipa": "/ˈvəʊtɪŋ ɪnˌtenʃən/", "pron": "VOH-ting in-TEN-shuhn", "fr": "intention de vote", "def": "The candidate or party a voter says they plan to support.", "ex": "Voting intention polls showed a narrow lead for the opposition."}, {"term": "likely voter", "ipa": "/ˌlaɪkli ˈvəʊtə/", "pron": "LYK-lee VOH-tuh", "fr": "électeur probable", "def": "A person considered likely to vote in an upcoming election.", "ex": "Polls of likely voters may differ from polls of all adults."}, {"term": "registered voter", "ipa": "/ˌredʒɪstəd ˈvəʊtə/", "pron": "REJ-i-stuhd VOH-tuh", "fr": "électeur inscrit", "def": "A person officially registered to vote.", "ex": "The poll surveyed registered voters only."}, {"term": "undecided voter", "ipa": "/ˌʌndɪˈsaɪdɪd ˈvəʊtə/", "pron": "un-di-SY-did VOH-tuh", "fr": "électeur indécis", "def": "A voter who has not yet chosen a candidate or party.", "ex": "Undecided voters could decide the election."}, {"term": "swing voter", "ipa": "/ˈswɪŋ ˌvəʊtə/", "pron": "swing VOH-tuh", "fr": "électeur flottant ; électeur indécis", "def": "A voter who may switch between parties or candidates.", "ex": "Both parties targeted swing voters in suburban areas."}, {"term": "floating voter", "ipa": "/ˌfləʊtɪŋ ˈvəʊtə/", "pron": "FLOH-ting VOH-tuh", "fr": "électeur flottant", "def": "A voter who does not consistently support the same party.", "ex": "Floating voters are crucial in close contests."}, {"term": "base voter", "ipa": "/ˈbeɪs ˌvəʊtə/", "pron": "base VOH-tuh", "fr": "électeur de base ; soutien fidèle", "def": "A loyal supporter of a party or candidate.", "ex": "The speech was designed to energise base voters."}, {"term": "swing state", "ipa": "/ˈswɪŋ steɪt/", "pron": "swing stayt", "fr": "État pivot ; État indécis", "def": "A US state where both major parties have a realistic chance of winning.", "ex": "Polls in swing states received intense media attention."}, {"term": "battleground state", "ipa": "/ˈbætəlɡraʊnd steɪt/", "pron": "BAT-uhl-ground stayt", "fr": "État clé ; État disputé", "def": "A state where the electoral result is uncertain and politically decisive.", "ex": "The campaign spent heavily in battleground states."}, {"term": "too close to call", "ipa": "/tuː ˌkləʊs tə ˈkɔːl/", "pron": "too klohss tuh call", "fr": "trop serré pour être prédit", "def": "So close that the result cannot be predicted with confidence.", "ex": "The race is still too close to call."}, {"term": "neck and neck", "ipa": "/ˌnek ən ˈnek/", "pron": "nek uhn nek", "fr": "au coude-à-coude", "def": "Very close in a race or competition.", "ex": "The two candidates are neck and neck in the latest poll."}, {"term": "lead", "ipa": "/liːd/", "pron": "leed", "fr": "avance", "def": "An advantage over another candidate, party or option.", "ex": "The opposition has a five-point lead."}, {"term": "narrow lead", "ipa": "/ˌnærəʊ ˈliːd/", "pron": "NAR-oh leed", "fr": "faible avance", "def": "A small advantage in a poll or election.", "ex": "The incumbent has only a narrow lead."}, {"term": "commanding lead", "ipa": "/kəˌmɑːndɪŋ ˈliːd/", "pron": "kuh-MAN-ding leed", "fr": "avance confortable", "def": "A large and convincing advantage.", "ex": "The candidate has a commanding lead among older voters."}, {"term": "lead widens", "ipa": "/ˈliːd ˈwaɪdənz/", "pron": "leed WY-duhnz", "fr": "l’avance se creuse", "def": "A situation in which a candidate’s advantage becomes larger.", "ex": "The president’s lead widened after the debate."}, {"term": "lead narrows", "ipa": "/ˈliːd ˈnærəʊz/", "pron": "leed NAR-ohz", "fr": "l’avance se réduit", "def": "A situation in which a candidate’s advantage becomes smaller.", "ex": "The opposition’s lead narrowed in the final week."}, {"term": "surge", "ipa": "/sɜːdʒ/", "pron": "surj", "fr": "bond ; poussée", "def": "A sudden increase in support or popularity.", "ex": "The party enjoyed a surge in support."}, {"term": "slump", "ipa": "/slʌmp/", "pron": "slump", "fr": "chute ; recul", "def": "A sudden or significant fall in support or popularity.", "ex": "The government suffered a slump in the polls."}, {"term": "bounce", "ipa": "/baʊns/", "pron": "bownss", "fr": "rebond", "def": "A temporary rise in popularity after an event such as a convention, debate or speech.", "ex": "The candidate received a post-debate bounce."}, {"term": "momentum", "ipa": "/məˈmentəm/", "pron": "muh-MEN-tuhm", "fr": "dynamique ; élan", "def": "A sense of growing political support or success.", "ex": "The campaign gained momentum after the primary victory."}, {"term": "polling average", "ipa": "/ˈpəʊlɪŋ ˈævərɪdʒ/", "pron": "POH-ling AV-uh-rij", "fr": "moyenne des sondages", "def": "An average of several polls used to reduce uncertainty.", "ex": "The polling average showed a stable race."}, {"term": "forecast", "ipa": "/ˈfɔːkɑːst/", "pron": "FOR-kast", "fr": "prévision", "def": "A prediction about a future event, such as an election result.", "ex": "The election forecast gave the opposition a 60% chance of winning."}, {"term": "projection", "ipa": "/prəˈdʒekʃən/", "pron": "pruh-JEK-shuhn", "fr": "projection", "def": "An estimate of a future result based on current data.", "ex": "Early projections suggested a hung parliament."}, {"term": "exit poll", "ipa": "/ˈeksɪt pəʊl/", "pron": "EK-sit pohl", "fr": "sondage de sortie des urnes", "def": "A survey of voters just after they have voted, used to predict results.", "ex": "The exit poll predicted a landslide victory."}]}, {"title": "C. Social groups, divides and voter blocs", "entries": [{"term": "tracking poll", "ipa": "/ˈtrækɪŋ pəʊl/", "pron": "TRAK-ing pohl", "fr": "sondage de suivi", "def": "A poll repeated regularly to measure changes over time.", "ex": "The tracking poll showed daily changes in support."}, {"term": "focus group", "ipa": "/ˈfəʊkəs ɡruːp/", "pron": "FOH-kuhs group", "fr": "groupe de discussion", "def": "A small group of people asked to discuss opinions about a candidate, policy or message.", "ex": "The campaign tested its slogan with a focus group."}, {"term": "qualitative research", "ipa": "/ˈkwɒlɪtətɪv rɪˈsɜːtʃ/", "pron": "KWOL-i-tuh-tiv ri-SURCH", "fr": "recherche qualitative", "def": "Research based on detailed opinions, explanations or interviews rather than numbers alone.", "ex": "Focus groups are a form of qualitative research."}, {"term": "quantitative research", "ipa": "/ˈkwɒntɪtətɪv rɪˈsɜːtʃ/", "pron": "KWON-ti-tuh-tiv ri-SURCH", "fr": "recherche quantitative", "def": "Research based on numbers, measurements and statistical analysis.", "ex": "Opinion polls are a form of quantitative research."}, {"term": "approval gap", "ipa": "/əˈpruːvəl ɡæp/", "pron": "uh-PROO-vuhl gap", "fr": "écart d’approbation", "def": "A difference in approval between groups, regions or parties.", "ex": "There is a large approval gap between urban and rural voters."}, {"term": "gender gap", "ipa": "/ˈdʒendə ɡæp/", "pron": "JEN-duh gap", "fr": "écart hommes-femmes", "def": "A difference between men and women in political opinions or voting behaviour.", "ex": "The gender gap widened during the campaign."}, {"term": "generation gap", "ipa": "/ˌdʒenəˈreɪʃən ɡæp/", "pron": "jen-uh-RAY-shuhn gap", "fr": "écart générationnel", "def": "A difference between age groups in attitudes or voting behaviour.", "ex": "The generation gap is clear on climate policy."}, {"term": "urban-rural divide", "ipa": "/ˌɜːbən ˈrʊərəl dɪˈvaɪd/", "pron": "UR-buhn ROOR-uhl di-VYDE", "fr": "fracture urbain-rural", "def": "A political difference between cities and rural areas.", "ex": "The urban-rural divide shaped the election result."}, {"term": "partisan divide", "ipa": "/ˌpɑːtɪzən dɪˈvaɪd/", "pron": "PAR-ti-zuhn di-VYDE", "fr": "clivage partisan", "def": "A difference in opinion based on party allegiance.", "ex": "The partisan divide on immigration has grown."}, {"term": "education divide", "ipa": "/ˌedjʊˈkeɪʃən dɪˈvaɪd/", "pron": "ej-yoo-KAY-shuhn di-VYDE", "fr": "fracture liée au niveau d’éducation", "def": "A political difference linked to levels of education.", "ex": "The education divide has reshaped voting patterns."}, {"term": "income group", "ipa": "/ˈɪnkʌm ɡruːp/", "pron": "IN-kum group", "fr": "groupe de revenu", "def": "A category of people based on income level.", "ex": "Support varied significantly by income group."}, {"term": "working-class voters", "ipa": "/ˌwɜːkɪŋ klɑːs ˈvəʊtəz/", "pron": "WUR-king klass VOH-tuhz", "fr": "électeurs populaires ; électorat ouvrier", "def": "Voters belonging to or identifying with the working class.", "ex": "Working-class voters shifted away from the party."}, {"term": "suburban voters", "ipa": "/səˈbɜːbən ˈvəʊtəz/", "pron": "suh-BUR-buhn VOH-tuhz", "fr": "électeurs des banlieues résidentielles", "def": "Voters living in suburban areas.", "ex": "Suburban voters became crucial in the election."}, {"term": "youth vote", "ipa": "/ˈjuːθ vəʊt/", "pron": "yooth voht", "fr": "vote des jeunes", "def": "The voting behaviour or support of young voters.", "ex": "The youth vote strongly favoured climate action."}, {"term": "senior voters", "ipa": "/ˈsiːniə ˈvəʊtəz/", "pron": "SEE-nee-uh VOH-tuhz", "fr": "électeurs âgés ; seniors", "def": "Older voters, often retirees or people over a certain age.", "ex": "Senior voters were more likely to support the incumbent."}]}, {"title": "D. Public mood, trust and political attitudes", "entries": [{"term": "public mood", "ipa": "/ˌpʌblɪk ˈmuːd/", "pron": "PUB-lik mood", "fr": "état d’esprit de l’opinion", "def": "The general emotional attitude of the public at a given time.", "ex": "The public mood was gloomy after months of inflation."}, {"term": "national mood", "ipa": "/ˌnæʃənəl ˈmuːd/", "pron": "NASH-uh-nuhl mood", "fr": "climat national ; humeur du pays", "def": "The general feeling across a country about politics or society.", "ex": "The national mood favoured change."}, {"term": "mood of the country", "ipa": "/ˌmuːd əv ðə ˈkʌntri/", "pron": "mood ov thuh KUN-tree", "fr": "état d’esprit du pays", "def": "The overall political or emotional atmosphere in a country.", "ex": "The mood of the country was hostile to the ruling party."}, {"term": "public confidence", "ipa": "/ˌpʌblɪk ˈkɒnfɪdəns/", "pron": "PUB-lik KON-fi-duhns", "fr": "confiance du public", "def": "The level of trust citizens have in institutions or leaders.", "ex": "Public confidence in parliament fell sharply."}, {"term": "trust in institutions", "ipa": "/ˌtrʌst ɪn ˌɪnstɪˈtjuːʃənz/", "pron": "trust in in-sti-TOO-shuhnz", "fr": "confiance dans les institutions", "def": "The degree to which citizens believe institutions are reliable and legitimate.", "ex": "Trust in institutions is essential for democracy."}, {"term": "political trust", "ipa": "/pəˌlɪtɪkəl ˈtrʌst/", "pron": "puh-LIT-i-kuhl trust", "fr": "confiance politique", "def": "Confidence in political leaders, parties or institutions.", "ex": "Political trust declined after the corruption scandal."}, {"term": "distrust", "ipa": "/dɪsˈtrʌst/", "pron": "dis-TRUST", "fr": "méfiance ; défiance", "def": "A lack of trust or confidence.", "ex": "Distrust of politicians has increased."}, {"term": "disillusionment", "ipa": "/ˌdɪsɪˈluːʒənmənt/", "pron": "dis-i-LOO-zhuhn-muhnt", "fr": "désillusion ; désenchantement", "def": "A feeling of disappointment after losing faith in someone or something.", "ex": "Disillusionment with politics fuelled abstention."}, {"term": "political apathy", "ipa": "/pəˈlɪtɪkəl ˈæpəθi/", "pron": "puh-LIT-i-kuhl AP-uh-thee", "fr": "apathie politique", "def": "A lack of interest in politics.", "ex": "Political apathy can lead to low turnout."}, {"term": "voter fatigue", "ipa": "/ˈvəʊtə fəˈtiːɡ/", "pron": "VOH-tuh fuh-TEEG", "fr": "lassitude électorale", "def": "A loss of voter interest or motivation, often after repeated elections or campaigns.", "ex": "Voter fatigue may explain the low turnout."}, {"term": "issue salience", "ipa": "/ˈɪʃuː ˈseɪliəns/", "pron": "ISH-oo SAY-lee-uhns", "fr": "importance d’un enjeu pour les électeurs", "def": "The importance of an issue in voters’ minds.", "ex": "Issue salience increased after the crisis."}, {"term": "top concern", "ipa": "/ˌtɒp kənˈsɜːn/", "pron": "top kuhn-SURN", "fr": "préoccupation principale", "def": "The issue that worries voters the most.", "ex": "Inflation remained voters’ top concern."}, {"term": "kitchen-table issue", "ipa": "/ˌkɪtʃən ˈteɪbəl ˈɪʃuː/", "pron": "KITCH-uhn TAY-buhl ISH-oo", "fr": "problème du quotidien ; enjeu de pouvoir d’achat", "def": "An everyday economic issue affecting households, such as wages, bills or prices.", "ex": "The campaign focused on kitchen-table issues."}, {"term": "cost-of-living concern", "ipa": "/ˌkɒst əv ˈlɪvɪŋ kənˈsɜːn/", "pron": "kost ov LIV-ing kuhn-SURN", "fr": "préoccupation liée au coût de la vie", "def": "Public worry about rising prices and household expenses.", "ex": "Cost-of-living concerns dominated the poll."}, {"term": "perception", "ipa": "/pəˈsepʃən/", "pron": "puh-SEP-shuhn", "fr": "perception", "def": "The way people see, understand or interpret something.", "ex": "Public perception of the policy was negative."}, {"term": "to poll well", "ipa": "/pəʊl ˈwel/", "pron": "pohl wel", "fr": "être bien placé dans les sondages", "def": "To receive good results in opinion polls.", "ex": "The candidate polls well among younger voters."}]}, {"title": "E. High-value verbs and exam-ready polling expressions", "entries": [{"term": "to poll badly", "ipa": "/pəʊl ˈbædli/", "pron": "pohl BAD-lee", "fr": "être mal placé dans les sondages", "def": "To receive poor results in opinion polls.", "ex": "The party polls badly in rural areas."}, {"term": "to gain ground", "ipa": "/ɡeɪn ˈɡraʊnd/", "pron": "gayn grownd", "fr": "gagner du terrain", "def": "To become more popular or successful.", "ex": "The opposition is gaining ground."}, {"term": "to lose ground", "ipa": "/luːz ˈɡraʊnd/", "pron": "looz grownd", "fr": "perdre du terrain", "def": "To become less popular or successful.", "ex": "The government is losing ground in the polls."}, {"term": "to lead in the polls", "ipa": "/liːd ɪn ðə ˈpəʊlz/", "pron": "leed in thuh pohlz", "fr": "être en tête dans les sondages", "def": "To be ahead of others in opinion polls.", "ex": "The incumbent leads in the polls."}, {"term": "to trail behind", "ipa": "/treɪl bɪˈhaɪnd/", "pron": "trayl bi-HYND", "fr": "être à la traîne ; être derrière", "def": "To be behind another candidate or party.", "ex": "The challenger is trailing behind by six points."}, {"term": "to close the gap", "ipa": "/kləʊz ðə ˈɡæp/", "pron": "klohz thuh gap", "fr": "réduire l’écart", "def": "To reduce the difference between two candidates or parties.", "ex": "The opposition closed the gap in the final week."}, {"term": "to shape public opinion", "ipa": "/ʃeɪp ˌpʌblɪk əˈpɪnjən/", "pron": "shayp PUB-lik uh-PIN-yuhn", "fr": "façonner l’opinion publique", "def": "To influence what people think about an issue.", "ex": "Media coverage can shape public opinion."}, {"term": "to sway voters", "ipa": "/sweɪ ˈvəʊtəz/", "pron": "sway VOH-tuhz", "fr": "faire changer d’avis les électeurs", "def": "To influence voters and change their opinion or choice.", "ex": "The scandal may sway undecided voters."}, {"term": "to predict the outcome", "ipa": "/prɪˈdɪkt ði ˈaʊtkʌm/", "pron": "pri-DIKT thee OWT-kum", "fr": "prédire le résultat", "def": "To forecast the result of an election or political event.", "ex": "Polls cannot always predict the outcome accurately."}, {"term": "to misread public opinion", "ipa": "/ˌmɪsˈriːd ˌpʌblɪk əˈpɪnjən/", "pron": "mis-REED PUB-lik uh-PIN-yuhn", "fr": "mal interpréter l’opinion publique", "def": "To misunderstand what the public thinks.", "ex": "The government misread public opinion on the reform."}, {"term": "to track voter sentiment", "ipa": "/træk ˈvəʊtə ˈsentɪmənt/", "pron": "trak VOH-tuh SEN-ti-muhnt", "fr": "suivre l’état d’esprit des électeurs", "def": "To follow changes in how voters feel.", "ex": "Campaigns use polling to track voter sentiment."}]}]}, {"id": "p2c11", "part": 2, "chapter": 11, "title": "American Political Institutions", "file": "cpge_vocab_part2_chapter11_american_political_institutions_premium.html", "count": 84, "sections": [{"title": "A. Federalism and levels of government", "entries": [{"term": "American institutions", "ipa": "/əˈmerɪkən ˌɪnstɪˈtjuːʃənz/", "pron": "uh-MER-i-kuhn in-sti-TOO-shuhnz", "fr": "institutions américaines", "def": "The main political bodies and rules that organise power in the United States.", "ex": "American institutions are based on federalism, checks and balances, and the separation of powers."}, {"term": "federal government", "ipa": "/ˈfedərəl ˈɡʌvənmənt/", "pron": "FED-uh-ruhl GUV-uhn-muhnt", "fr": "gouvernement fédéral", "def": "The national government of the United States.", "ex": "The federal government is divided into three branches."}, {"term": "federalism", "ipa": "/ˈfedərəlɪzəm/", "pron": "FED-uh-ruh-liz-uhm", "fr": "fédéralisme", "def": "A system in which power is divided between the national government and the states.", "ex": "Federalism gives US states significant political authority."}, {"term": "federal system", "ipa": "/ˈfedərəl ˈsɪstəm/", "pron": "FED-uh-ruhl SIS-tuhm", "fr": "système fédéral", "def": "A political system in which powers are shared between central and regional governments.", "ex": "The United States has a federal system."}, {"term": "state government", "ipa": "/ˌsteɪt ˈɡʌvənmənt/", "pron": "stayt GUV-uhn-muhnt", "fr": "gouvernement d’un État fédéré", "def": "The government of one of the US states.", "ex": "State governments control many areas such as education and policing."}, {"term": "state legislature", "ipa": "/ˌsteɪt ˈledʒɪslətʃə/", "pron": "stayt LEDJ-is-luh-chuh", "fr": "assemblée législative d’un État", "def": "The law-making body of a US state.", "ex": "The state legislature passed new voting rules."}, {"term": "governor", "ipa": "/ˈɡʌvənə/", "pron": "GUV-uh-nuh", "fr": "gouverneur ; gouverneure", "def": "The elected head of a US state government.", "ex": "The governor declared a state of emergency."}, {"term": "local government", "ipa": "/ˌləʊkəl ˈɡʌvənmənt/", "pron": "LOH-kuhl GUV-uhn-muhnt", "fr": "collectivités locales ; gouvernement local", "def": "Government at city, county or local level.", "ex": "Local government is responsible for many everyday services."}, {"term": "county", "ipa": "/ˈkaʊnti/", "pron": "KOWN-tee", "fr": "comté", "def": "A local administrative area in many US states.", "ex": "The county is responsible for local elections."}, {"term": "city council", "ipa": "/ˌsɪti ˈkaʊnsəl/", "pron": "SIT-ee KOWN-suhl", "fr": "conseil municipal", "def": "A local elected body that governs a city.", "ex": "The city council voted to increase public transport funding."}, {"term": "mayor", "ipa": "/meə/", "pron": "mair", "fr": "maire", "def": "The elected head of a city or town government.", "ex": "The mayor announced new housing measures."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The authority of a political body to govern itself.", "ex": "Federalism divides sovereignty between Washington and the states."}, {"term": "reserved powers", "ipa": "/rɪˈzɜːvd ˈpaʊəz/", "pron": "ri-ZURVD POW-uhz", "fr": "pouvoirs réservés aux États", "def": "Powers kept by the states rather than given to the federal government.", "ex": "Education is often linked to reserved powers."}, {"term": "delegated powers", "ipa": "/ˈdelɪɡeɪtɪd ˈpaʊəz/", "pron": "DEL-i-gay-tid POW-uhz", "fr": "pouvoirs délégués au gouvernement fédéral", "def": "Powers specifically granted to the federal government by the Constitution.", "ex": "The power to declare war is one of Congress’s delegated powers."}, {"term": "concurrent powers", "ipa": "/kənˈkʌrənt ˈpaʊəz/", "pron": "kuhn-KUR-uhnt POW-uhz", "fr": "pouvoirs concurrents", "def": "Powers shared by the federal and state governments.", "ex": "Taxation is an example of concurrent powers."}, {"term": "states’ rights", "ipa": "/ˌsteɪts ˈraɪts/", "pron": "stayts rites", "fr": "droits des États fédérés", "def": "The idea that US states should retain significant political authority against federal power.", "ex": "States’ rights are often invoked in debates over abortion and gun laws."}, {"term": "supremacy clause", "ipa": "/suːˈpreməsi klɔːz/", "pron": "soo-PREM-uh-see klawz", "fr": "clause de suprématie", "def": "The constitutional rule that federal law takes precedence over state law when they conflict.", "ex": "The Supremacy Clause gives federal law priority over state law."}, {"term": "the Constitution", "ipa": "/ðə ˌkɒnstɪˈtjuːʃən/", "pron": "thuh kon-sti-TOO-shuhn", "fr": "la Constitution américaine", "def": "The founding legal document that establishes the US system of government.", "ex": "The Constitution created a system of separated powers."}]}, {"title": "B. The Constitution and founding principles", "entries": [{"term": "constitutional republic", "ipa": "/ˌkɒnstɪˈtjuːʃənəl rɪˈpʌblɪk/", "pron": "kon-sti-TOO-shuh-nuhl ri-PUB-lik", "fr": "république constitutionnelle", "def": "A republic governed according to a constitution that limits political power.", "ex": "The United States is a constitutional republic."}, {"term": "the Bill of Rights", "ipa": "/ðə ˌbɪl əv ˈraɪts/", "pron": "thuh bil ov rites", "fr": "Bill of Rights ; déclaration des droits", "def": "The first ten amendments to the US Constitution, protecting fundamental rights.", "ex": "The Bill of Rights protects freedom of speech and religion."}, {"term": "amendment", "ipa": "/əˈmendmənt/", "pron": "uh-MEND-muhnt", "fr": "amendement", "def": "A formal change or addition to the Constitution.", "ex": "The Fourteenth Amendment is central to civil rights law."}, {"term": "First Amendment", "ipa": "/ˌfɜːst əˈmendmənt/", "pron": "first uh-MEND-muhnt", "fr": "Premier amendement", "def": "The amendment protecting speech, religion, press, assembly and petition rights.", "ex": "The First Amendment protects freedom of speech."}, {"term": "Second Amendment", "ipa": "/ˌsekənd əˈmendmənt/", "pron": "SEK-uhnd uh-MEND-muhnt", "fr": "Deuxième amendement", "def": "The amendment often associated with the right to keep and bear arms.", "ex": "The Second Amendment is central to gun control debates."}, {"term": "Fourteenth Amendment", "ipa": "/ˌfɔːˈtiːnθ əˈmendmənt/", "pron": "for-TEENTH uh-MEND-muhnt", "fr": "Quatorzième amendement", "def": "The amendment protecting citizenship, due process and equal protection.", "ex": "The Fourteenth Amendment has shaped civil rights cases."}, {"term": "checks and balances", "ipa": "/ˌtʃeks ən ˈbælənsɪz/", "pron": "cheks uhn BAL-uhn-siz", "fr": "freins et contrepoids ; contre-pouvoirs", "def": "A system in which each branch of government can limit the power of the others.", "ex": "Checks and balances prevent one branch from dominating the others."}, {"term": "separation of powers", "ipa": "/ˌsepəˈreɪʃən əv ˈpaʊəz/", "pron": "sep-uh-RAY-shuhn ov POW-uhz", "fr": "séparation des pouvoirs", "def": "The division of power between the executive, legislative and judicial branches.", "ex": "The separation of powers is central to US institutions."}, {"term": "branch of government", "ipa": "/ˌbrɑːntʃ əv ˈɡʌvənmənt/", "pron": "branch ov GUV-uhn-muhnt", "fr": "branche du gouvernement", "def": "One of the main parts of government: executive, legislative or judicial.", "ex": "Each branch of government has different powers."}, {"term": "executive branch", "ipa": "/ɪɡˈzekjətɪv brɑːntʃ/", "pron": "ig-ZEK-yuh-tiv branch", "fr": "pouvoir exécutif", "def": "The branch led by the president and responsible for enforcing laws.", "ex": "The executive branch includes the president and federal agencies."}, {"term": "legislative branch", "ipa": "/ˈledʒɪslətɪv brɑːntʃ/", "pron": "LEDJ-is-luh-tiv branch", "fr": "pouvoir législatif", "def": "The branch responsible for making laws, mainly Congress.", "ex": "The legislative branch can pass laws and approve budgets."}, {"term": "judicial branch", "ipa": "/dʒuːˈdɪʃəl brɑːntʃ/", "pron": "joo-DISH-uhl branch", "fr": "pouvoir judiciaire", "def": "The branch made up of courts that interpret and apply the law.", "ex": "The judicial branch can review the constitutionality of laws."}]}, {"title": "C. The executive and legislative branches", "entries": [{"term": "President", "ipa": "/ˈprezɪdənt/", "pron": "PREZ-i-duhnt", "fr": "président", "def": "The elected head of state and head of government in the United States.", "ex": "The President can veto bills passed by Congress."}, {"term": "Vice President", "ipa": "/ˌvaɪs ˈprezɪdənt/", "pron": "vyss PREZ-i-duhnt", "fr": "vice-président", "def": "The official who supports the president and presides over the Senate.", "ex": "The Vice President can cast a tie-breaking vote in the Senate."}, {"term": "Cabinet", "ipa": "/ˈkæbɪnət/", "pron": "KAB-i-nuht", "fr": "cabinet ; gouvernement présidentiel", "def": "The group of senior officials heading federal departments and advising the president.", "ex": "The Cabinet includes the Secretary of State and the Secretary of Defense."}, {"term": "federal agency", "ipa": "/ˈfedərəl ˈeɪdʒənsi/", "pron": "FED-uh-ruhl AY-juhn-see", "fr": "agence fédérale", "def": "A government organisation responsible for a specific area of federal policy.", "ex": "Federal agencies enforce environmental and labour regulations."}, {"term": "executive order", "ipa": "/ɪɡˈzekjətɪv ˈɔːdə/", "pron": "ig-ZEK-yuh-tiv OR-duh", "fr": "décret présidentiel", "def": "A directive issued by the president to manage federal government operations.", "ex": "The president signed an executive order on immigration."}, {"term": "veto", "ipa": "/ˈviːtəʊ/", "pron": "VEE-toh", "fr": "veto", "def": "The president’s power to reject a bill passed by Congress.", "ex": "The president used his veto to block the bill."}, {"term": "commander-in-chief", "ipa": "/kəˌmɑːndər ɪn ˈtʃiːf/", "pron": "kuh-MAN-duhr in cheef", "fr": "commandant en chef", "def": "The president’s role as head of the armed forces.", "ex": "As commander-in-chief, the president oversees the military."}, {"term": "Congress", "ipa": "/ˈkɒŋɡres/", "pron": "KON-gress", "fr": "Congrès américain", "def": "The national legislature of the United States.", "ex": "Congress is made up of the Senate and the House of Representatives."}, {"term": "House of Representatives", "ipa": "/ˌhaʊs əv ˌreprɪˈzentətɪvz/", "pron": "howss ov rep-ri-ZEN-tuh-tivz", "fr": "Chambre des représentants", "def": "The lower chamber of Congress, with members elected by district.", "ex": "The House of Representatives has 435 voting members."}, {"term": "Senate", "ipa": "/ˈsenət/", "pron": "SEN-uht", "fr": "Sénat", "def": "The upper chamber of Congress, with two senators from each state.", "ex": "The Senate confirms many presidential appointments."}, {"term": "representative", "ipa": "/ˌreprɪˈzentətɪv/", "pron": "rep-ri-ZEN-tuh-tiv", "fr": "représentant ; élu de la Chambre", "def": "An elected member of the House of Representatives.", "ex": "The representative introduced a bill on healthcare."}, {"term": "senator", "ipa": "/ˈsenətə/", "pron": "SEN-uh-tuh", "fr": "sénateur ; sénatrice", "def": "An elected member of the Senate.", "ex": "Each state elects two senators."}, {"term": "congressional district", "ipa": "/kənˈɡreʃənəl ˈdɪstrɪkt/", "pron": "kuhn-GRESH-uh-nuhl DIS-trikt", "fr": "circonscription congressionnelle", "def": "A geographical area that elects one member of the House of Representatives.", "ex": "The district became more competitive after redistricting."}, {"term": "Speaker of the House", "ipa": "/ˌspiːkər əv ðə ˈhaʊs/", "pron": "SPEE-kuhr ov thuh howss", "fr": "président de la Chambre des représentants", "def": "The presiding officer and political leader of the House of Representatives.", "ex": "The Speaker of the House controls much of the legislative agenda."}, {"term": "majority leader", "ipa": "/məˈdʒɒrəti ˈliːdə/", "pron": "muh-JOR-uh-tee LEE-duh", "fr": "chef de la majorité", "def": "A congressional leader of the party with the most seats.", "ex": "The majority leader negotiated the final bill."}, {"term": "minority leader", "ipa": "/maɪˈnɒrəti ˈliːdə/", "pron": "my-NOR-uh-tee LEE-duh", "fr": "chef de la minorité", "def": "A congressional leader of the party with fewer seats.", "ex": "The minority leader criticised the spending plan."}, {"term": "committee", "ipa": "/kəˈmɪti/", "pron": "kuh-MIT-ee", "fr": "commission ; comité", "def": "A smaller group of lawmakers that examines specific issues or bills.", "ex": "The committee held hearings on social media regulation."}, {"term": "congressional hearing", "ipa": "/kənˈɡreʃənəl ˈhɪərɪŋ/", "pron": "kuhn-GRESH-uh-nuhl HEER-ing", "fr": "audition au Congrès", "def": "A formal session where Congress gathers evidence or questions witnesses.", "ex": "The congressional hearing exposed failures in oversight."}, {"term": "bill", "ipa": "/bɪl/", "pron": "bil", "fr": "projet de loi", "def": "A proposed law debated and voted on by Congress.", "ex": "The bill passed the House but failed in the Senate."}, {"term": "federal law", "ipa": "/ˌfedərəl ˈlɔː/", "pron": "FED-uh-ruhl law", "fr": "loi fédérale", "def": "A law passed by the national government and applying across the United States.", "ex": "Federal law takes precedence over conflicting state law."}, {"term": "Supreme Court", "ipa": "/suːˌpriːm ˈkɔːt/", "pron": "soo-PREEM court", "fr": "Cour suprême", "def": "The highest court in the United States.", "ex": "The Supreme Court plays a major role in constitutional interpretation."}, {"term": "justice", "ipa": "/ˈdʒʌstɪs/", "pron": "JUS-tis", "fr": "juge de la Cour suprême", "def": "A judge on the Supreme Court.", "ex": "The justice wrote a dissenting opinion."}]}, {"title": "D. Courts, judicial review and appointments", "entries": [{"term": "Chief Justice", "ipa": "/ˌtʃiːf ˈdʒʌstɪs/", "pron": "cheef JUS-tis", "fr": "président de la Cour suprême", "def": "The presiding justice of the Supreme Court.", "ex": "The Chief Justice leads the Supreme Court."}, {"term": "federal court", "ipa": "/ˈfedərəl kɔːt/", "pron": "FED-uh-ruhl court", "fr": "tribunal fédéral", "def": "A court that deals with cases involving federal law or constitutional questions.", "ex": "A federal court blocked the executive order."}, {"term": "district court", "ipa": "/ˈdɪstrɪkt kɔːt/", "pron": "DIS-trikt court", "fr": "tribunal fédéral de première instance", "def": "A trial-level federal court in the United States.", "ex": "The case began in a district court."}, {"term": "court of appeals", "ipa": "/ˌkɔːt əv əˈpiːlz/", "pron": "court ov uh-PEELZ", "fr": "cour d’appel fédérale", "def": "A federal court that reviews decisions from lower courts.", "ex": "The court of appeals upheld the ruling."}, {"term": "judicial review", "ipa": "/dʒuːˌdɪʃəl rɪˈvjuː/", "pron": "joo-DISH-uhl ri-VYOO", "fr": "contrôle de constitutionnalité", "def": "The power of courts to decide whether laws or actions are constitutional.", "ex": "Judicial review allows courts to limit government power."}, {"term": "landmark ruling", "ipa": "/ˈlændmɑːk ˈruːlɪŋ/", "pron": "LAND-mark ROO-ling", "fr": "arrêt historique ; décision majeure", "def": "A highly important court decision that changes law or society.", "ex": "The landmark ruling reshaped abortion rights."}, {"term": "precedent", "ipa": "/ˈpresɪdənt/", "pron": "PRES-i-duhnt", "fr": "précédent juridique", "def": "A previous legal decision that guides future cases.", "ex": "The ruling set an important precedent."}, {"term": "federal judge", "ipa": "/ˈfedərəl dʒʌdʒ/", "pron": "FED-uh-ruhl juj", "fr": "juge fédéral", "def": "A judge serving in the federal court system.", "ex": "A federal judge ruled that the law was unconstitutional."}, {"term": "appointment", "ipa": "/əˈpɔɪntmənt/", "pron": "uh-POINT-muhnt", "fr": "nomination", "def": "The act of choosing someone for an official position.", "ex": "Supreme Court appointments can shape law for decades."}, {"term": "confirmation", "ipa": "/ˌkɒnfəˈmeɪʃən/", "pron": "kon-fuh-MAY-shuhn", "fr": "confirmation ; approbation", "def": "Formal approval of a presidential nominee, usually by the Senate.", "ex": "The Senate confirmation process was highly controversial."}, {"term": "nominee", "ipa": "/ˌnɒmɪˈniː/", "pron": "nom-i-NEE", "fr": "personne nommée ; candidat désigné", "def": "A person formally proposed for a position or office.", "ex": "The Supreme Court nominee faced difficult questions."}, {"term": "electoral college", "ipa": "/ɪˌlektərəl ˈkɒlɪdʒ/", "pron": "i-LEK-tuh-ruhl KOL-ij", "fr": "collège électoral", "def": "The system used to formally elect the US president through state electors.", "ex": "A candidate can win the popular vote but lose the Electoral College."}, {"term": "popular vote", "ipa": "/ˌpɒpjələ ˈvəʊt/", "pron": "POP-yuh-luh voht", "fr": "vote populaire ; suffrage exprimé", "def": "The total number of votes cast by citizens nationwide or in a state.", "ex": "She won the popular vote but lost the presidency."}, {"term": "swing state", "ipa": "/ˈswɪŋ steɪt/", "pron": "swing stayt", "fr": "État pivot ; État indécis", "def": "A state where both major parties have a realistic chance of winning.", "ex": "Swing states receive intense attention during presidential elections."}, {"term": "red state", "ipa": "/ˌred ˈsteɪt/", "pron": "red stayt", "fr": "État républicain", "def": "A US state that usually votes Republican.", "ex": "Texas has long been considered a red state."}, {"term": "blue state", "ipa": "/ˌbluː ˈsteɪt/", "pron": "bloo stayt", "fr": "État démocrate", "def": "A US state that usually votes Democratic.", "ex": "California is a strongly blue state."}, {"term": "purple state", "ipa": "/ˌpɜːpəl ˈsteɪt/", "pron": "PUR-puhl stayt", "fr": "État politiquement partagé", "def": "A state where Democrats and Republicans both have significant support.", "ex": "Georgia has become a more purple state."}]}, {"title": "E. Elections, impeachment and high-value verbs", "entries": [{"term": "primary election", "ipa": "/ˈpraɪməri ɪˌlekʃən/", "pron": "PRY-muh-ree i-LEK-shuhn", "fr": "primaire", "def": "An election used to choose a party’s candidate.", "ex": "The primary election divided the party."}, {"term": "caucus", "ipa": "/ˈkɔːkəs/", "pron": "KAW-kuhs", "fr": "caucus ; assemblée partisane", "def": "A meeting where party members discuss and choose candidates or policies.", "ex": "Iowa is famous for its presidential caucuses."}, {"term": "midterm elections", "ipa": "/ˈmɪdtɜːm ɪˌlekʃənz/", "pron": "MID-term i-LEK-shuhnz", "fr": "élections de mi-mandat", "def": "Elections held halfway through a president’s four-year term.", "ex": "Midterm elections often punish the president’s party."}, {"term": "term limit", "ipa": "/ˈtɜːm ˌlɪmɪt/", "pron": "term LIM-it", "fr": "limite de mandat", "def": "A legal limit on how long someone can hold an office.", "ex": "The president is subject to a two-term limit."}, {"term": "impeachment", "ipa": "/ɪmˈpiːtʃmənt/", "pron": "im-PEECH-muhnt", "fr": "procédure de destitution", "def": "A formal process for charging a high official with serious misconduct.", "ex": "The impeachment process dominated the news."}, {"term": "to impeach", "ipa": "/ɪmˈpiːtʃ/", "pron": "im-PEECH", "fr": "mettre en accusation ; engager une procédure de destitution", "def": "To formally accuse a high official of serious misconduct.", "ex": "The House voted to impeach the president."}, {"term": "to confirm a nominee", "ipa": "/kənˈfɜːm ə ˌnɒmɪˈniː/", "pron": "kuhn-FURM uh nom-i-NEE", "fr": "confirmer une nomination", "def": "To formally approve a person proposed for an official post.", "ex": "The Senate confirmed the nominee by a narrow vote."}, {"term": "to veto a bill", "ipa": "/ˈviːtəʊ ə ˈbɪl/", "pron": "VEE-toh uh bil", "fr": "opposer son veto à un projet de loi", "def": "To reject a proposed law officially.", "ex": "The president threatened to veto the bill."}, {"term": "to override a veto", "ipa": "/ˌəʊvəˈraɪd ə ˈviːtəʊ/", "pron": "OH-vuh-ryd uh VEE-toh", "fr": "passer outre un veto", "def": "To pass a bill despite a presidential veto, usually with a special majority.", "ex": "Congress failed to override the veto."}, {"term": "to pass legislation", "ipa": "/pɑːs ˌledʒɪsˈleɪʃən/", "pron": "pass lej-is-LAY-shuhn", "fr": "adopter une loi ; adopter une législation", "def": "To approve laws through the legislative process.", "ex": "Congress struggled to pass legislation on immigration."}, {"term": "to uphold a law", "ipa": "/ʌpˈhəʊld ə ˈlɔː/", "pron": "up-HOHLD uh law", "fr": "confirmer la validité d’une loi", "def": "For a court to confirm that a law is valid.", "ex": "The Supreme Court upheld the law."}, {"term": "to strike down a law", "ipa": "/straɪk daʊn ə ˈlɔː/", "pron": "stryke down uh law", "fr": "annuler ; invalider une loi", "def": "For a court to declare a law invalid or unconstitutional.", "ex": "The Court struck down the state law."}, {"term": "to challenge federal authority", "ipa": "/ˈtʃælɪndʒ ˈfedərəl ɔːˈθɒrəti/", "pron": "CHAL-inj FED-uh-ruhl aw-THOR-uh-tee", "fr": "contester l’autorité fédérale", "def": "To dispute the power of the national government.", "ex": "Several states challenged federal authority in court."}, {"term": "to defend states’ rights", "ipa": "/dɪˈfend ˌsteɪts ˈraɪts/", "pron": "di-FEND stayts rites", "fr": "défendre les droits des États", "def": "To argue that states should retain significant powers.", "ex": "Conservatives often defend states’ rights in constitutional debates."}, {"term": "to expand federal power", "ipa": "/ɪkˈspænd ˈfedərəl ˈpaʊə/", "pron": "ik-SPAND FED-uh-ruhl POW-uh", "fr": "étendre le pouvoir fédéral", "def": "To increase the authority of the national government.", "ex": "The crisis led to an expansion of federal power."}]}]}, {"id": "p2c12", "part": 2, "chapter": 12, "title": "The Presidency", "file": "cpge_vocab_part2_chapter12_the_presidency_premium.html", "count": 94, "sections": [{"title": "A. The presidential office and symbolic roles", "entries": [{"term": "presidency", "ipa": "/ˈprezɪdənsi/", "pron": "PREZ-i-duhn-see", "fr": "présidence", "def": "The office, role or period of service of a president.", "ex": "The presidency gives one person enormous visibility and symbolic power."}, {"term": "President", "ipa": "/ˈprezɪdənt/", "pron": "PREZ-i-duhnt", "fr": "président", "def": "The elected head of state and head of government in the United States.", "ex": "The President appoints judges, signs bills and directs foreign policy."}, {"term": "head of state", "ipa": "/ˌhed əv ˈsteɪt/", "pron": "hed ov stayt", "fr": "chef de l’État", "def": "The official representative of a country, especially in ceremonial and diplomatic matters.", "ex": "In the US, the President is both head of state and head of government."}, {"term": "head of government", "ipa": "/ˌhed əv ˈɡʌvənmənt/", "pron": "hed ov GUV-uhn-muhnt", "fr": "chef du gouvernement", "def": "The political leader responsible for running the government.", "ex": "The President acts as head of government by leading the executive branch."}, {"term": "commander-in-chief", "ipa": "/kəˌmɑːndər ɪn ˈtʃiːf/", "pron": "kuh-MAN-duhr in cheef", "fr": "commandant en chef", "def": "The president’s constitutional role as head of the armed forces.", "ex": "As commander-in-chief, the President can direct military operations."}, {"term": "chief executive", "ipa": "/ˌtʃiːf ɪɡˈzekjətɪv/", "pron": "cheef ig-ZEK-yuh-tiv", "fr": "chef de l’exécutif", "def": "The president’s role as leader of the executive branch.", "ex": "As chief executive, the President oversees federal agencies."}, {"term": "chief diplomat", "ipa": "/ˌtʃiːf ˈdɪpləmæt/", "pron": "cheef DIP-luh-mat", "fr": "chef de la diplomatie", "def": "The president’s role in directing foreign policy and representing the country abroad.", "ex": "As chief diplomat, the President meets foreign leaders."}, {"term": "party leader", "ipa": "/ˈpɑːti ˈliːdə/", "pron": "PAR-tee LEE-duh", "fr": "chef de parti", "def": "The president’s political role as leader of their party.", "ex": "The President also acts as party leader during election campaigns."}, {"term": "bully pulpit", "ipa": "/ˈbʊli ˈpʊlpɪt/", "pron": "BUL-ee PUL-pit", "fr": "tribune présidentielle ; pouvoir d’influence médiatique", "def": "The president’s ability to use the visibility of the office to influence public opinion.", "ex": "The President used the bully pulpit to push for healthcare reform."}, {"term": "Oval Office", "ipa": "/ˌəʊvəl ˈɒfɪs/", "pron": "OH-vuhl OFF-is", "fr": "Bureau ovale", "def": "The president’s official office in the White House.", "ex": "The speech was delivered from the Oval Office."}, {"term": "White House", "ipa": "/ˌwaɪt ˈhaʊs/", "pron": "white howss", "fr": "Maison-Blanche", "def": "The official residence and workplace of the US President; also used to refer to the president’s administration.", "ex": "The White House denied the allegations."}, {"term": "administration", "ipa": "/ədˌmɪnɪˈstreɪʃən/", "pron": "ad-min-i-STRAY-shuhn", "fr": "administration ; gouvernement présidentiel", "def": "The government led by a particular president.", "ex": "The Biden administration introduced new climate measures."}, {"term": "Vice President", "ipa": "/ˌvaɪs ˈprezɪdənt/", "pron": "vyss PREZ-i-duhnt", "fr": "vice-président ; vice-présidente", "def": "The official who replaces the president if needed and presides over the Senate.", "ex": "The Vice President cast a tie-breaking vote in the Senate."}, {"term": "First Lady", "ipa": "/ˌfɜːst ˈleɪdi/", "pron": "first LAY-dee", "fr": "Première dame", "def": "The wife of the President, often involved in public causes but holding no elected office.", "ex": "The First Lady launched a campaign on children’s health."}, {"term": "presidential term", "ipa": "/ˌprezɪˈdenʃəl tɜːm/", "pron": "prez-i-DEN-shuhl term", "fr": "mandat présidentiel", "def": "The period during which a president holds office, four years in the United States.", "ex": "A presidential term lasts four years."}, {"term": "term limit", "ipa": "/ˈtɜːm ˌlɪmɪt/", "pron": "term LIM-it", "fr": "limite de mandat", "def": "A legal limit on how many terms someone can serve.", "ex": "The Twenty-Second Amendment created a two-term limit for presidents."}, {"term": "lame duck", "ipa": "/ˌleɪm ˈdʌk/", "pron": "laym duck", "fr": "responsable en fin de mandat ; canard boiteux", "def": "An elected official whose successor has been chosen or whose time in office is ending, reducing their power.", "ex": "A lame-duck president may struggle to pass major reforms."}, {"term": "president-elect", "ipa": "/ˌprezɪdənt ɪˈlekt/", "pron": "PREZ-i-duhnt i-LEKT", "fr": "président élu", "def": "A person elected president but not yet sworn into office.", "ex": "The president-elect announced his Cabinet nominees."}, {"term": "inauguration", "ipa": "/ɪˌnɔːɡjəˈreɪʃən/", "pron": "i-naw-gyuh-RAY-shuhn", "fr": "investiture", "def": "The ceremony marking the beginning of a president’s term.", "ex": "The inauguration takes place in January."}, {"term": "inaugural address", "ipa": "/ɪˌnɔːɡjərəl əˈdres/", "pron": "i-NAW-gyuh-ruhl uh-DRESS", "fr": "discours d’investiture", "def": "The speech given by a president at the start of their term.", "ex": "The inaugural address called for national unity."}, {"term": "oath of office", "ipa": "/ˌəʊθ əv ˈɒfɪs/", "pron": "ohth ov OFF-is", "fr": "serment d’investiture", "def": "The formal promise made by a president before taking office.", "ex": "The President takes the oath of office before assuming power."}, {"term": "to take office", "ipa": "/teɪk ˈɒfɪs/", "pron": "tayk OFF-is", "fr": "entrer en fonction", "def": "To officially begin a political position.", "ex": "The new President took office in January."}, {"term": "to be sworn in", "ipa": "/bi ˌswɔːn ˈɪn/", "pron": "bee sworn in", "fr": "prêter serment", "def": "To officially take an oath and begin a position.", "ex": "The President was sworn in on the steps of the Capitol."}, {"term": "executive branch", "ipa": "/ɪɡˈzekjətɪv brɑːntʃ/", "pron": "ig-ZEK-yuh-tiv branch", "fr": "pouvoir exécutif", "def": "The branch of government led by the President and responsible for enforcing laws.", "ex": "The executive branch includes federal departments and agencies."}]}, {"title": "B. Executive powers and the administration", "entries": [{"term": "executive power", "ipa": "/ɪɡˈzekjətɪv ˈpaʊə/", "pron": "ig-ZEK-yuh-tiv POW-uh", "fr": "pouvoir exécutif", "def": "The authority to enforce laws and manage government operations.", "ex": "Executive power tends to expand during emergencies."}, {"term": "executive authority", "ipa": "/ɪɡˈzekjətɪv ɔːˈθɒrəti/", "pron": "ig-ZEK-yuh-tiv aw-THOR-uh-tee", "fr": "autorité exécutive", "def": "The legal power held by the executive branch.", "ex": "The order tested the limits of executive authority."}, {"term": "executive order", "ipa": "/ɪɡˈzekjətɪv ˈɔːdə/", "pron": "ig-ZEK-yuh-tiv OR-duh", "fr": "décret présidentiel", "def": "A directive issued by the President to manage federal government operations.", "ex": "The President signed an executive order on immigration."}, {"term": "presidential memorandum", "ipa": "/ˌprezɪˈdenʃəl ˌmeməˈrændəm/", "pron": "prez-i-DEN-shuhl mem-uh-RAN-duhm", "fr": "mémorandum présidentiel", "def": "A presidential directive used to manage executive policy or administration.", "ex": "The administration issued a presidential memorandum on workplace rules."}, {"term": "proclamation", "ipa": "/ˌprɒkləˈmeɪʃən/", "pron": "prok-luh-MAY-shuhn", "fr": "proclamation", "def": "An official public statement issued by the President.", "ex": "The President issued a proclamation marking a national holiday."}, {"term": "state of emergency", "ipa": "/ˌsteɪt əv ɪˈmɜːdʒənsi/", "pron": "stayt ov i-MUR-juhn-see", "fr": "état d’urgence", "def": "A situation in which the executive claims special powers because of a crisis.", "ex": "The President declared a state of emergency after the disaster."}, {"term": "emergency powers", "ipa": "/ɪˈmɜːdʒənsi ˈpaʊəz/", "pron": "i-MUR-juhn-see POW-uhz", "fr": "pouvoirs d’urgence", "def": "Special powers used by the executive during a crisis.", "ex": "Emergency powers can raise concerns about civil liberties."}, {"term": "pardon", "ipa": "/ˈpɑːdən/", "pron": "PAR-duhn", "fr": "grâce présidentielle", "def": "The president’s power to forgive a federal crime or remove punishment.", "ex": "The President granted a controversial pardon."}, {"term": "commutation", "ipa": "/ˌkɒmjʊˈteɪʃən/", "pron": "kom-yoo-TAY-shuhn", "fr": "commutation de peine", "def": "A reduction of a criminal sentence by executive authority.", "ex": "The President issued a commutation for the prisoner."}, {"term": "cabinet", "ipa": "/ˈkæbɪnət/", "pron": "KAB-i-nuht", "fr": "cabinet ; gouvernement présidentiel", "def": "The group of senior officials heading departments and advising the President.", "ex": "The Cabinet discussed the crisis at the White House."}, {"term": "cabinet secretary", "ipa": "/ˌkæbɪnət ˈsekrətəri/", "pron": "KAB-i-nuht SEK-ruh-tuh-ree", "fr": "secrétaire de cabinet ; ministre américain", "def": "The head of a federal department in the president’s Cabinet.", "ex": "The Cabinet secretary defended the administration’s policy."}, {"term": "Secretary of State", "ipa": "/ˌsekrətəri əv ˈsteɪt/", "pron": "SEK-ruh-tuh-ree ov stayt", "fr": "secrétaire d’État américain ; ministre des Affaires étrangères", "def": "The Cabinet official responsible for foreign affairs.", "ex": "The Secretary of State met European allies."}, {"term": "Secretary of Defense", "ipa": "/ˌsekrətəri əv dɪˈfens/", "pron": "SEK-ruh-tuh-ree ov di-FENSS", "fr": "secrétaire à la Défense", "def": "The Cabinet official responsible for the Department of Defense.", "ex": "The Secretary of Defense briefed Congress."}, {"term": "Attorney General", "ipa": "/əˌtɜːni ˈdʒenərəl/", "pron": "uh-TUR-nee JEN-uh-ruhl", "fr": "ministre de la Justice ; procureur général", "def": "The head of the Department of Justice and chief legal officer of the federal government.", "ex": "The Attorney General announced a federal investigation."}, {"term": "Department of Justice", "ipa": "/dɪˌpɑːtmənt əv ˈdʒʌstɪs/", "pron": "di-PART-muhnt ov JUS-tis", "fr": "ministère de la Justice", "def": "The federal department responsible for law enforcement and legal affairs.", "ex": "The Department of Justice challenged the state law."}, {"term": "federal agency", "ipa": "/ˈfedərəl ˈeɪdʒənsi/", "pron": "FED-uh-ruhl AY-juhn-see", "fr": "agence fédérale", "def": "A government organisation responsible for a specific area of federal policy.", "ex": "Federal agencies implement presidential policy."}, {"term": "bureaucracy", "ipa": "/bjʊəˈrɒkrəsi/", "pron": "byoo-ROK-ruh-see", "fr": "bureaucratie ; administration", "def": "The administrative system of departments and officials that carries out government policy.", "ex": "Presidents often struggle to control the federal bureaucracy."}, {"term": "civil servant", "ipa": "/ˌsɪvəl ˈsɜːvənt/", "pron": "SIV-uhl SUR-vuhnt", "fr": "fonctionnaire", "def": "A professional government employee who works in the public administration.", "ex": "Civil servants are expected to serve different administrations."}, {"term": "adviser", "ipa": "/ədˈvaɪzə/", "pron": "ad-VY-zuh", "fr": "conseiller ; conseillère", "def": "A person who gives advice to the President or a political leader.", "ex": "Senior advisers shaped the President’s response."}, {"term": "White House staff", "ipa": "/ˌwaɪt haʊs ˈstɑːf/", "pron": "white howss staff", "fr": "personnel de la Maison-Blanche", "def": "The team of advisers and employees working directly for the President.", "ex": "White House staff coordinated the announcement."}, {"term": "Chief of Staff", "ipa": "/ˌtʃiːf əv ˈstɑːf/", "pron": "cheef ov staff", "fr": "chef de cabinet de la Maison-Blanche", "def": "The senior aide who manages the White House staff and controls access to the President.", "ex": "The Chief of Staff resigned after the scandal."}, {"term": "National Security Council", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti ˈkaʊnsəl/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee KOWN-suhl", "fr": "Conseil de sécurité nationale", "def": "A White House body advising the President on national security and foreign policy.", "ex": "The National Security Council met after the attack."}, {"term": "presidential adviser", "ipa": "/ˌprezɪˈdenʃəl ədˈvaɪzə/", "pron": "prez-i-DEN-shuhl ad-VY-zuh", "fr": "conseiller présidentiel", "def": "A person who advises the President on policy, politics or strategy.", "ex": "A presidential adviser defended the decision."}, {"term": "press secretary", "ipa": "/ˈpres ˌsekrətəri/", "pron": "press SEK-ruh-tuh-ree", "fr": "porte-parole de la Maison-Blanche", "def": "The official who speaks to the media on behalf of the White House.", "ex": "The press secretary answered questions about the policy."}, {"term": "briefing room", "ipa": "/ˈbriːfɪŋ ruːm/", "pron": "BREEF-ing room", "fr": "salle de presse ; salle de briefing", "def": "The room where White House press briefings take place.", "ex": "Reporters gathered in the briefing room."}, {"term": "State of the Union", "ipa": "/ˌsteɪt əv ði ˈjuːniən/", "pron": "stayt ov thee YOO-nee-uhn", "fr": "discours sur l’état de l’Union", "def": "The annual speech in which the President addresses Congress and presents priorities.", "ex": "The State of the Union focused on the economy."}]}, {"title": "C. Presidential agenda, leadership and communication", "entries": [{"term": "approval rating", "ipa": "/əˈpruːvəl ˈreɪtɪŋ/", "pron": "uh-PROO-vuhl RAY-ting", "fr": "taux d’approbation ; cote de popularité", "def": "The percentage of people who approve of the President’s performance.", "ex": "The President’s approval rating fell sharply."}, {"term": "public mandate", "ipa": "/ˌpʌblɪk ˈmændeɪt/", "pron": "PUB-lik MAN-dayt", "fr": "mandat populaire", "def": "The authority a president claims from voters to carry out a programme.", "ex": "The President claimed a public mandate for reform."}, {"term": "honeymoon period", "ipa": "/ˈhʌnimuːn ˌpɪəriəd/", "pron": "HUN-ee-moon PEER-ee-uhd", "fr": "état de grâce", "def": "The early period of a presidency when public and political support may be higher.", "ex": "The honeymoon period ended after the first major crisis."}, {"term": "presidential agenda", "ipa": "/ˌprezɪˈdenʃəl əˈdʒendə/", "pron": "prez-i-DEN-shuhl uh-JEN-duh", "fr": "programme présidentiel ; agenda présidentiel", "def": "The president’s list of policy priorities.", "ex": "Congress blocked much of the presidential agenda."}, {"term": "domestic agenda", "ipa": "/dəˈmestɪk əˈdʒendə/", "pron": "duh-MES-tik uh-JEN-duh", "fr": "programme intérieur", "def": "A president’s priorities on internal national issues.", "ex": "The domestic agenda focused on healthcare and jobs."}, {"term": "foreign policy agenda", "ipa": "/ˈfɒrən ˈpɒləsi əˈdʒendə/", "pron": "FOR-uhn POL-uh-see uh-JEN-duh", "fr": "agenda de politique étrangère", "def": "A president’s priorities in international relations.", "ex": "The foreign policy agenda included support for allies."}, {"term": "campaign promise", "ipa": "/kæmˈpeɪn ˈprɒmɪs/", "pron": "kam-PAYN PROM-is", "fr": "promesse de campagne", "def": "A promise made during an election campaign.", "ex": "The tax cut fulfilled a major campaign promise."}, {"term": "policy priority", "ipa": "/ˈpɒləsi praɪˈɒrəti/", "pron": "POL-uh-see pry-OR-uh-tee", "fr": "priorité politique", "def": "An issue or action considered especially important by an administration.", "ex": "Climate change became a policy priority."}, {"term": "legacy", "ipa": "/ˈleɡəsi/", "pron": "LEG-uh-see", "fr": "héritage politique", "def": "The long-term impact by which a president is remembered.", "ex": "The President hoped healthcare reform would define his legacy."}, {"term": "presidential leadership", "ipa": "/ˌprezɪˈdenʃəl ˈliːdəʃɪp/", "pron": "prez-i-DEN-shuhl LEE-duh-ship", "fr": "leadership présidentiel", "def": "The ability of a president to guide policy, persuade others and respond to crises.", "ex": "Presidential leadership is tested during national emergencies."}, {"term": "crisis management", "ipa": "/ˈkraɪsɪs ˈmænɪdʒmənt/", "pron": "KRY-sis MAN-ij-muhnt", "fr": "gestion de crise", "def": "The handling of emergencies or serious problems by leaders or institutions.", "ex": "The pandemic became a test of presidential crisis management."}, {"term": "Commander-in-chief power", "ipa": "/kəˌmɑːndər ɪn ˈtʃiːf ˈpaʊə/", "pron": "kuh-MAN-duhr in cheef POW-uh", "fr": "pouvoir de commandant en chef", "def": "The president’s authority over the military as commander-in-chief.", "ex": "Commander-in-chief power is central in wartime."}, {"term": "war powers", "ipa": "/ˈwɔː ˌpaʊəz/", "pron": "war POW-uhz", "fr": "pouvoirs de guerre", "def": "The legal and constitutional powers related to starting or conducting war.", "ex": "War powers are divided between Congress and the President."}, {"term": "War Powers Resolution", "ipa": "/ˈwɔː ˌpaʊəz ˌrezəˈluːʃən/", "pron": "war POW-uhz rez-uh-LOO-shuhn", "fr": "War Powers Resolution ; loi sur les pouvoirs de guerre", "def": "A US law intended to limit the president’s ability to deploy troops without congressional approval.", "ex": "The War Powers Resolution remains controversial."}]}, {"title": "D. Foreign policy, war powers and national security", "entries": [{"term": "treaty", "ipa": "/ˈtriːti/", "pron": "TREE-tee", "fr": "traité", "def": "A formal agreement between countries, which in the US requires Senate approval.", "ex": "The treaty required a two-thirds Senate vote."}, {"term": "executive agreement", "ipa": "/ɪɡˈzekjətɪv əˈɡriːmənt/", "pron": "ig-ZEK-yuh-tiv uh-GREE-muhnt", "fr": "accord exécutif", "def": "An international agreement made by the President without the full treaty process.", "ex": "Presidents often use executive agreements in foreign policy."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Political or economic penalties imposed on a country, group or individual.", "ex": "The President announced new sanctions against the regime."}, {"term": "diplomatic recognition", "ipa": "/ˌdɪpləˈmætɪk ˌrekəɡˈnɪʃən/", "pron": "dip-luh-MAT-ik rek-uhg-NISH-uhn", "fr": "reconnaissance diplomatique", "def": "The formal acceptance of another state or government as legitimate.", "ex": "The administration granted diplomatic recognition to the new government."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "The protection of a country from threats, especially military, terrorist or strategic threats.", "ex": "National security arguments are often used to justify secrecy."}, {"term": "executive privilege", "ipa": "/ɪɡˈzekjətɪv ˈprɪvəlɪdʒ/", "pron": "ig-ZEK-yuh-tiv PRIV-uh-lij", "fr": "privilège exécutif", "def": "The claimed right of the President to keep some communications confidential.", "ex": "The President invoked executive privilege to withhold documents."}, {"term": "classified information", "ipa": "/ˌklæsɪfaɪd ˌɪnfəˈmeɪʃən/", "pron": "KLAS-i-fyd in-fuh-MAY-shuhn", "fr": "information classifiée", "def": "Secret government information whose release is restricted for security reasons.", "ex": "The investigation concerned classified information."}, {"term": "checks and balances", "ipa": "/ˌtʃeks ən ˈbælənsɪz/", "pron": "cheks uhn BAL-uhn-siz", "fr": "freins et contrepoids ; contre-pouvoirs", "def": "A system in which each branch of government can limit the power of the others.", "ex": "Checks and balances limit presidential power."}, {"term": "congressional oversight", "ipa": "/kənˈɡreʃənəl ˈəʊvəsaɪt/", "pron": "kuhn-GRESH-uh-nuhl OH-vuh-syte", "fr": "contrôle du Congrès", "def": "The power of Congress to monitor and investigate the executive branch.", "ex": "Congressional oversight can expose executive misconduct."}, {"term": "confirmation hearing", "ipa": "/ˌkɒnfəˈmeɪʃən ˈhɪərɪŋ/", "pron": "kon-fuh-MAY-shuhn HEER-ing", "fr": "audition de confirmation", "def": "A Senate hearing used to examine a presidential nominee.", "ex": "The confirmation hearing became highly partisan."}, {"term": "Senate confirmation", "ipa": "/ˌsenət ˌkɒnfəˈmeɪʃən/", "pron": "SEN-uht kon-fuh-MAY-shuhn", "fr": "confirmation par le Sénat", "def": "The Senate’s formal approval of a presidential appointment.", "ex": "Supreme Court justices require Senate confirmation."}, {"term": "impeachment", "ipa": "/ɪmˈpiːtʃmənt/", "pron": "im-PEECH-muhnt", "fr": "procédure de destitution", "def": "The process of charging a president or high official with serious misconduct.", "ex": "Impeachment is a constitutional check on presidential abuse."}]}, {"title": "E. Checks, impeachment and high-value presidential verbs", "entries": [{"term": "House impeachment", "ipa": "/ˌhaʊs ɪmˈpiːtʃmənt/", "pron": "howss im-PEECH-muhnt", "fr": "mise en accusation par la Chambre", "def": "The House of Representatives’ formal accusation of a president or official.", "ex": "House impeachment does not automatically remove a president."}, {"term": "Senate trial", "ipa": "/ˌsenət ˈtraɪəl/", "pron": "SEN-uht TRY-uhl", "fr": "procès au Sénat", "def": "The Senate process that follows impeachment and decides whether to remove the official.", "ex": "The Senate trial ended in acquittal."}, {"term": "removal from office", "ipa": "/rɪˈmuːvəl frəm ˈɒfɪs/", "pron": "ri-MOO-vuhl frum OFF-is", "fr": "destitution ; révocation", "def": "The act of forcing an official to leave their position.", "ex": "Removal from office requires conviction in the Senate."}, {"term": "executive overreach", "ipa": "/ɪɡˈzekjətɪv ˌəʊvəˈriːtʃ/", "pron": "ig-ZEK-yuh-tiv OH-vuh-reech", "fr": "abus de pouvoir exécutif", "def": "The use of presidential or executive power beyond proper limits.", "ex": "Critics accused the administration of executive overreach."}, {"term": "imperial presidency", "ipa": "/ɪmˈpɪəriəl ˈprezɪdənsi/", "pron": "im-PEER-ee-uhl PREZ-i-duhn-see", "fr": "présidence impériale", "def": "A term used to criticise a presidency seen as too powerful and insufficiently checked.", "ex": "The war revived fears of an imperial presidency."}, {"term": "unitary executive theory", "ipa": "/ˈjuːnɪtəri ɪɡˈzekjətɪv ˈθɪəri/", "pron": "YOO-ni-tuh-ree ig-ZEK-yuh-tiv THEE-uh-ree", "fr": "théorie de l’exécutif unitaire", "def": "The theory that the President has broad control over the executive branch.", "ex": "Supporters of unitary executive theory favour strong presidential control."}, {"term": "abuse of office", "ipa": "/əˌbjuːs əv ˈɒfɪs/", "pron": "uh-BYOOSS ov OFF-is", "fr": "abus de fonction", "def": "The improper use of an official position for personal or political gain.", "ex": "The inquiry examined allegations of abuse of office."}, {"term": "obstruction of justice", "ipa": "/əbˌstrʌkʃən əv ˈdʒʌstɪs/", "pron": "uhb-STRUK-shuhn ov JUS-tis", "fr": "entrave à la justice", "def": "Interference with an investigation or legal process.", "ex": "The report raised questions about obstruction of justice."}, {"term": "to sign a bill into law", "ipa": "/saɪn ə ˈbɪl ˈɪntuː ˈlɔː/", "pron": "syne uh bil IN-too law", "fr": "promulguer une loi", "def": "To approve a bill officially so that it becomes law.", "ex": "The President signed the bill into law."}, {"term": "to veto legislation", "ipa": "/ˈviːtəʊ ˌledʒɪsˈleɪʃən/", "pron": "VEE-toh lej-is-LAY-shuhn", "fr": "opposer son veto à une loi", "def": "To reject legislation passed by Congress.", "ex": "The President threatened to veto the legislation."}, {"term": "to issue an executive order", "ipa": "/ˈɪʃuː ən ɪɡˈzekjətɪv ˈɔːdə/", "pron": "ISH-oo uhn ig-ZEK-yuh-tiv OR-duh", "fr": "émettre un décret présidentiel", "def": "To formally release a presidential directive.", "ex": "The President issued an executive order on border security."}, {"term": "to appoint judges", "ipa": "/əˈpɔɪnt ˈdʒʌdʒɪz/", "pron": "uh-POINT JUJ-iz", "fr": "nommer des juges", "def": "To choose judges for official positions.", "ex": "Presidents can shape the judiciary by appointing judges."}, {"term": "to nominate a justice", "ipa": "/ˈnɒmɪneɪt ə ˈdʒʌstɪs/", "pron": "NOM-i-nayt uh JUS-tis", "fr": "nommer un juge à la Cour suprême", "def": "To formally propose someone for the Supreme Court.", "ex": "The President nominated a conservative justice."}, {"term": "to face impeachment", "ipa": "/feɪs ɪmˈpiːtʃmənt/", "pron": "fays im-PEECH-muhnt", "fr": "faire face à une procédure de destitution", "def": "To be subject to possible impeachment proceedings.", "ex": "The President faced impeachment after the scandal."}, {"term": "to invoke executive privilege", "ipa": "/ɪnˈvəʊk ɪɡˈzekjətɪv ˈprɪvəlɪdʒ/", "pron": "in-VOHK ig-ZEK-yuh-tiv PRIV-uh-lij", "fr": "invoquer le privilège exécutif", "def": "To claim the right to keep presidential communications confidential.", "ex": "The White House invoked executive privilege."}, {"term": "to bypass Congress", "ipa": "/ˈbaɪpɑːs ˈkɒŋɡres/", "pron": "BY-pass KON-gress", "fr": "contourner le Congrès", "def": "To act without going through Congress.", "ex": "The executive order was seen as an attempt to bypass Congress."}, {"term": "to expand presidential power", "ipa": "/ɪkˈspænd ˌprezɪˈdenʃəl ˈpaʊə/", "pron": "ik-SPAND prez-i-DEN-shuhl POW-uh", "fr": "étendre le pouvoir présidentiel", "def": "To increase the authority or influence of the presidency.", "ex": "National crises often expand presidential power."}, {"term": "to constrain the president", "ipa": "/kənˈstreɪn ðə ˈprezɪdənt/", "pron": "kuhn-STRAYN thuh PREZ-i-duhnt", "fr": "limiter le président", "def": "To limit what the president can do.", "ex": "Courts and Congress can constrain the president."}]}]}, {"id": "p2c13", "part": 2, "chapter": 13, "title": "Congress", "file": "cpge_vocab_part2_chapter13_congress_premium.html", "count": 92, "sections": [{"title": "A. Members, chambers and congressional leadership", "entries": [{"term": "Congress", "ipa": "/ˈkɒŋɡres/", "pron": "KON-gress", "fr": "Congrès américain", "def": "The national legislature of the United States, made up of the Senate and the House of Representatives.", "ex": "Congress has the power to make federal laws and approve government spending."}, {"term": "bicameral legislature", "ipa": "/ˌbaɪˈkæmərəl ˈledʒɪslətʃə/", "pron": "bye-KAM-uh-ruhl LEDJ-is-luh-chuh", "fr": "parlement bicaméral", "def": "A legislature with two chambers or houses.", "ex": "Congress is a bicameral legislature."}, {"term": "House of Representatives", "ipa": "/ˌhaʊs əv ˌreprɪˈzentətɪvz/", "pron": "howss ov rep-ri-ZEN-tuh-tivz", "fr": "Chambre des représentants", "def": "The lower chamber of the US Congress, with members elected by congressional district.", "ex": "The House of Representatives has 435 voting members."}, {"term": "Senate", "ipa": "/ˈsenət/", "pron": "SEN-uht", "fr": "Sénat", "def": "The upper chamber of the US Congress, with two senators from each state.", "ex": "The Senate confirms many presidential appointments."}, {"term": "representative", "ipa": "/ˌreprɪˈzentətɪv/", "pron": "rep-ri-ZEN-tuh-tiv", "fr": "représentant ; élu de la Chambre", "def": "An elected member of the House of Representatives.", "ex": "The representative introduced a bill on healthcare."}, {"term": "senator", "ipa": "/ˈsenətə/", "pron": "SEN-uh-tuh", "fr": "sénateur ; sénatrice", "def": "An elected member of the Senate.", "ex": "Each state elects two senators."}, {"term": "congressman", "ipa": "/ˈkɒŋɡresmən/", "pron": "KON-gress-muhn", "fr": "membre masculin du Congrès", "def": "A male member of Congress, especially of the House of Representatives.", "ex": "The congressman supported the infrastructure bill."}, {"term": "congresswoman", "ipa": "/ˈkɒŋɡresˌwʊmən/", "pron": "KON-gress-woo-muhn", "fr": "membre féminin du Congrès", "def": "A female member of Congress, especially of the House of Representatives.", "ex": "The congresswoman questioned the witness during the hearing."}, {"term": "member of Congress", "ipa": "/ˌmembər əv ˈkɒŋɡres/", "pron": "MEM-buhr ov KON-gress", "fr": "membre du Congrès", "def": "A senator or representative serving in the US Congress.", "ex": "Members of Congress often split their time between Washington and their home states."}, {"term": "congressional district", "ipa": "/kənˈɡreʃənəl ˈdɪstrɪkt/", "pron": "kuhn-GRESH-uh-nuhl DIS-trikt", "fr": "circonscription congressionnelle", "def": "A geographical area that elects one member of the House of Representatives.", "ex": "Redistricting changed the boundaries of several congressional districts."}, {"term": "constituent", "ipa": "/kənˈstɪtjuənt/", "pron": "kuhn-STI-choo-uhnt", "fr": "électeur d’une circonscription ; administré", "def": "A person represented by an elected official.", "ex": "The senator received thousands of emails from constituents."}, {"term": "congressional seat", "ipa": "/kənˈɡreʃənəl siːt/", "pron": "kuhn-GRESH-uh-nuhl seet", "fr": "siège au Congrès", "def": "A position held by a member of Congress.", "ex": "The party hopes to win several congressional seats."}, {"term": "term of office", "ipa": "/ˌtɜːm əv ˈɒfɪs/", "pron": "term ov OFF-is", "fr": "mandat", "def": "The period during which an elected official serves.", "ex": "Representatives serve a two-year term of office."}, {"term": "re-election", "ipa": "/ˌriː ɪˈlekʃən/", "pron": "ree i-LEK-shuhn", "fr": "réélection", "def": "The process of being elected again to the same office.", "ex": "Several senators are seeking re-election."}, {"term": "incumbent", "ipa": "/ɪnˈkʌmbənt/", "pron": "in-KUM-buhnt", "fr": "sortant ; titulaire du poste", "def": "The person currently holding a political office.", "ex": "Incumbents often have an advantage in congressional races."}, {"term": "freshman lawmaker", "ipa": "/ˈfreʃmən ˈlɔːˌmeɪkə/", "pron": "FRESH-muhn LAW-may-kuh", "fr": "nouvel élu au Congrès", "def": "A newly elected member of Congress serving their first term.", "ex": "The freshman lawmaker quickly gained media attention."}, {"term": "Speaker of the House", "ipa": "/ˌspiːkər əv ðə ˈhaʊs/", "pron": "SPEE-kuhr ov thuh howss", "fr": "président de la Chambre des représentants", "def": "The presiding officer and political leader of the House of Representatives.", "ex": "The Speaker of the House controls much of the legislative agenda."}, {"term": "House majority leader", "ipa": "/ˌhaʊs məˈdʒɒrəti ˈliːdə/", "pron": "howss muh-JOR-uh-tee LEE-duh", "fr": "chef de la majorité à la Chambre", "def": "The leader of the majority party in the House of Representatives.", "ex": "The House majority leader negotiated the final version of the bill."}, {"term": "House minority leader", "ipa": "/ˌhaʊs maɪˈnɒrəti ˈliːdə/", "pron": "howss my-NOR-uh-tee LEE-duh", "fr": "chef de la minorité à la Chambre", "def": "The leader of the minority party in the House of Representatives.", "ex": "The House minority leader criticised the budget deal."}, {"term": "Senate majority leader", "ipa": "/ˌsenət məˈdʒɒrəti ˈliːdə/", "pron": "SEN-uht muh-JOR-uh-tee LEE-duh", "fr": "chef de la majorité au Sénat", "def": "The leader of the majority party in the Senate.", "ex": "The Senate majority leader decides which bills reach the floor."}, {"term": "Senate minority leader", "ipa": "/ˌsenət maɪˈnɒrəti ˈliːdə/", "pron": "SEN-uht my-NOR-uh-tee LEE-duh", "fr": "chef de la minorité au Sénat", "def": "The leader of the minority party in the Senate.", "ex": "The Senate minority leader opposed the nomination."}, {"term": "party caucus", "ipa": "/ˈpɑːti ˈkɔːkəs/", "pron": "PAR-tee KAW-kuhs", "fr": "groupe parlementaire d’un parti", "def": "A group of lawmakers from the same party who meet to discuss strategy.", "ex": "The party caucus met before the vote."}, {"term": "congressional caucus", "ipa": "/kənˈɡreʃənəl ˈkɔːkəs/", "pron": "kuhn-GRESH-uh-nuhl KAW-kuhs", "fr": "caucus parlementaire ; groupe au Congrès", "def": "A group of members of Congress organised around a party, identity, region or issue.", "ex": "The Congressional Black Caucus pushed for police reform."}, {"term": "bipartisan group", "ipa": "/ˌbaɪˈpɑːtɪzən ɡruːp/", "pron": "bye-PAR-ti-zuhn group", "fr": "groupe bipartisan ; groupe transpartisan", "def": "A group including members of both major parties.", "ex": "A bipartisan group introduced a compromise bill."}]}, {"title": "B. Committees, hearings and oversight", "entries": [{"term": "committee", "ipa": "/kəˈmɪti/", "pron": "kuh-MIT-ee", "fr": "commission ; comité", "def": "A smaller group of lawmakers that examines bills, policies or investigations.", "ex": "The committee held hearings on social media regulation."}, {"term": "standing committee", "ipa": "/ˈstændɪŋ kəˌmɪti/", "pron": "STAN-ding kuh-MIT-ee", "fr": "commission permanente", "def": "A permanent congressional committee dealing with a specific policy area.", "ex": "The standing committee reviewed the defence budget."}, {"term": "select committee", "ipa": "/sɪˈlekt kəˌmɪti/", "pron": "si-LEKT kuh-MIT-ee", "fr": "commission spéciale", "def": "A temporary or special committee created for a specific investigation or issue.", "ex": "The select committee investigated the attack on the Capitol."}, {"term": "joint committee", "ipa": "/ˌdʒɔɪnt kəˈmɪti/", "pron": "joynt kuh-MIT-ee", "fr": "commission mixte", "def": "A committee including members from both the House and the Senate.", "ex": "A joint committee examined economic forecasts."}, {"term": "conference committee", "ipa": "/ˈkɒnfərəns kəˌmɪti/", "pron": "KON-fuh-ruhns kuh-MIT-ee", "fr": "commission de conciliation", "def": "A temporary committee that reconciles different House and Senate versions of a bill.", "ex": "The conference committee produced a compromise version of the bill."}, {"term": "committee chair", "ipa": "/kəˈmɪti tʃeə/", "pron": "kuh-MIT-ee chair", "fr": "président de commission", "def": "The lawmaker who leads a committee.", "ex": "The committee chair scheduled the hearing."}, {"term": "ranking member", "ipa": "/ˈræŋkɪŋ ˈmembə/", "pron": "RANK-ing MEM-buh", "fr": "membre le plus haut placé de la minorité", "def": "The most senior member of the minority party on a committee.", "ex": "The ranking member issued a separate statement."}, {"term": "hearing", "ipa": "/ˈhɪərɪŋ/", "pron": "HEER-ing", "fr": "audition", "def": "A formal session where lawmakers hear evidence or question witnesses.", "ex": "The hearing focused on data privacy."}, {"term": "congressional hearing", "ipa": "/kənˈɡreʃənəl ˈhɪərɪŋ/", "pron": "kuhn-GRESH-uh-nuhl HEER-ing", "fr": "audition au Congrès", "def": "A hearing organised by Congress to gather information or scrutinise officials.", "ex": "The congressional hearing was broadcast live."}, {"term": "witness", "ipa": "/ˈwɪtnəs/", "pron": "WIT-nuhs", "fr": "témoin", "def": "A person who gives evidence before a committee or court.", "ex": "The witness described pressure from the White House."}, {"term": "testimony", "ipa": "/ˈtestɪməni/", "pron": "TES-ti-muh-nee", "fr": "témoignage ; déposition", "def": "A formal statement given by a witness.", "ex": "Her testimony contradicted earlier accounts."}, {"term": "subpoena", "ipa": "/səˈpiːnə/", "pron": "suh-PEE-nuh", "fr": "assignation ; citation à comparaître", "def": "A legal order requiring someone to provide documents or testify.", "ex": "The committee issued a subpoena for documents."}, {"term": "to subpoena", "ipa": "/səˈpiːnə/", "pron": "suh-PEE-nuh", "fr": "assigner ; citer à comparaître", "def": "To order someone legally to provide evidence or appear before a committee or court.", "ex": "Congress voted to subpoena former officials."}, {"term": "oversight", "ipa": "/ˈəʊvəsaɪt/", "pron": "OH-vuh-syte", "fr": "contrôle institutionnel ; surveillance", "def": "The monitoring of government actions by Congress or another institution.", "ex": "Congressional oversight can expose abuses of power."}, {"term": "congressional oversight", "ipa": "/kənˈɡreʃənəl ˈəʊvəsaɪt/", "pron": "kuhn-GRESH-uh-nuhl OH-vuh-syte", "fr": "contrôle du Congrès", "def": "The power of Congress to monitor the executive branch.", "ex": "Congressional oversight is a key check on the presidency."}, {"term": "scrutiny", "ipa": "/ˈskruːtəni/", "pron": "SKROO-tuh-nee", "fr": "examen minutieux ; contrôle", "def": "Careful examination of decisions, policies or actions.", "ex": "The policy came under intense congressional scrutiny."}, {"term": "bill", "ipa": "/bɪl/", "pron": "bil", "fr": "projet de loi", "def": "A proposed law debated and voted on by Congress.", "ex": "The bill was introduced in the House."}]}, {"title": "C. Law-making procedures and voting rules", "entries": [{"term": "legislation", "ipa": "/ˌledʒɪsˈleɪʃən/", "pron": "lej-is-LAY-shuhn", "fr": "législation", "def": "Laws or the process of making laws.", "ex": "Congress passed major civil rights legislation in the 1960s."}, {"term": "law-making process", "ipa": "/ˈlɔː meɪkɪŋ ˈprəʊses/", "pron": "LAW-may-king PROH-sess", "fr": "processus législatif", "def": "The steps through which a bill becomes law.", "ex": "The law-making process can be slow and complex."}, {"term": "draft bill", "ipa": "/ˌdrɑːft ˈbɪl/", "pron": "draft bil", "fr": "avant-projet de loi", "def": "An early version of a proposed law.", "ex": "The draft bill was criticised by civil liberties groups."}, {"term": "sponsor", "ipa": "/ˈspɒnsə/", "pron": "SPON-suh", "fr": "auteur ; parrain d’un projet de loi", "def": "A lawmaker who formally introduces or supports a bill.", "ex": "The bill’s sponsor defended the measure."}, {"term": "co-sponsor", "ipa": "/ˌkəʊ ˈspɒnsə/", "pron": "koh SPON-suh", "fr": "co-parrain ; cosignataire", "def": "A lawmaker who adds their support to a bill introduced by another member.", "ex": "The proposal attracted dozens of co-sponsors."}, {"term": "amendment", "ipa": "/əˈmendmənt/", "pron": "uh-MEND-muhnt", "fr": "amendement", "def": "A proposed change to a bill or law.", "ex": "The Senate adopted an amendment on border security."}, {"term": "markup", "ipa": "/ˈmɑːkʌp/", "pron": "MARK-up", "fr": "examen et modification d’un projet en commission", "def": "A committee session where lawmakers revise and amend a bill.", "ex": "The bill changed significantly during markup."}, {"term": "floor debate", "ipa": "/ˌflɔː dɪˈbeɪt/", "pron": "floor di-BAYT", "fr": "débat en séance plénière", "def": "A debate involving all members of a chamber before a vote.", "ex": "The floor debate lasted several hours."}, {"term": "floor vote", "ipa": "/ˌflɔː ˈvəʊt/", "pron": "floor voht", "fr": "vote en séance plénière", "def": "A vote by the full House or Senate.", "ex": "The floor vote was delayed until Friday."}, {"term": "roll-call vote", "ipa": "/ˌrəʊl kɔːl ˈvəʊt/", "pron": "rohl-call voht", "fr": "vote nominatif", "def": "A recorded vote showing how each lawmaker voted.", "ex": "The roll-call vote revealed divisions within the party."}, {"term": "voice vote", "ipa": "/ˈvɔɪs vəʊt/", "pron": "voyss voht", "fr": "vote oral", "def": "A vote in which members say yes or no aloud and the result is judged by volume.", "ex": "The bill passed by voice vote."}, {"term": "majority vote", "ipa": "/məˈdʒɒrəti vəʊt/", "pron": "muh-JOR-uh-tee voht", "fr": "vote à la majorité", "def": "A vote requiring more than half of those voting to approve something.", "ex": "Most bills pass by majority vote."}, {"term": "supermajority", "ipa": "/ˌsuːpəməˈdʒɒrəti/", "pron": "SOO-puh-muh-JOR-uh-tee", "fr": "supermajorité ; majorité qualifiée", "def": "A majority larger than a simple majority, often two-thirds or three-fifths.", "ex": "Overriding a veto requires a supermajority."}, {"term": "simple majority", "ipa": "/ˌsɪmpəl məˈdʒɒrəti/", "pron": "SIM-puhl muh-JOR-uh-tee", "fr": "majorité simple", "def": "More than half of the votes cast.", "ex": "A simple majority was enough to pass the bill."}, {"term": "cloture", "ipa": "/ˈkləʊtʃə/", "pron": "KLOH-chuh", "fr": "clôture des débats au Sénat", "def": "A Senate procedure used to end debate and overcome a filibuster.", "ex": "The Senate failed to reach the votes needed for cloture."}, {"term": "filibuster", "ipa": "/ˈfɪlɪbʌstə/", "pron": "FIL-i-bus-tuh", "fr": "obstruction parlementaire", "def": "A tactic used in the Senate to delay or block a vote through prolonged debate or procedural rules.", "ex": "The filibuster made it hard to pass voting rights legislation."}, {"term": "reconciliation", "ipa": "/ˌrekənsɪliˈeɪʃən/", "pron": "rek-uhn-sil-ee-AY-shuhn", "fr": "procédure de réconciliation budgétaire", "def": "A special budget procedure in Congress that allows some bills to pass the Senate with a simple majority.", "ex": "The party used reconciliation to pass parts of its economic agenda."}, {"term": "conference report", "ipa": "/ˈkɒnfərəns rɪˌpɔːt/", "pron": "KON-fuh-ruhns ri-PORT", "fr": "rapport de conférence ; texte de compromis", "def": "The final compromise text produced by a conference committee.", "ex": "Both chambers approved the conference report."}, {"term": "to introduce a bill", "ipa": "/ˌɪntrəˈdjuːs ə ˈbɪl/", "pron": "in-truh-DYOOSS uh bil", "fr": "présenter un projet de loi", "def": "To formally present a proposed law in Congress.", "ex": "A senator introduced a bill on gun safety."}, {"term": "to pass a bill", "ipa": "/pɑːs ə ˈbɪl/", "pron": "pass uh bil", "fr": "adopter un projet de loi", "def": "To approve a proposed law through a vote.", "ex": "The House passed the bill with bipartisan support."}, {"term": "to amend a bill", "ipa": "/əˈmend ə ˈbɪl/", "pron": "uh-MEND uh bil", "fr": "amender un projet de loi", "def": "To change a proposed law.", "ex": "Lawmakers amended the bill in committee."}, {"term": "to block legislation", "ipa": "/blɒk ˌledʒɪsˈleɪʃən/", "pron": "blok lej-is-LAY-shuhn", "fr": "bloquer une loi", "def": "To prevent a law from passing.", "ex": "A filibuster can block legislation in the Senate."}, {"term": "to send a bill to the president", "ipa": "/send ə ˈbɪl tə ðə ˈprezɪdənt/", "pron": "send uh bil tuh thuh PREZ-i-duhnt", "fr": "transmettre un projet de loi au président", "def": "To pass a bill through Congress so that the president can sign or veto it.", "ex": "Congress sent the bill to the president."}, {"term": "appropriations", "ipa": "/əˌprəʊpriˈeɪʃənz/", "pron": "uh-proh-pree-AY-shuhnz", "fr": "crédits budgétaires", "def": "Money formally allocated by Congress for government spending.", "ex": "The appropriations bill funded federal agencies."}, {"term": "budget resolution", "ipa": "/ˈbʌdʒɪt ˌrezəˈluːʃən/", "pron": "BUJ-it rez-uh-LOO-shuhn", "fr": "résolution budgétaire", "def": "A congressional framework setting overall spending and revenue goals.", "ex": "The budget resolution set spending targets."}]}, {"title": "D. Budget, gridlock and party politics", "entries": [{"term": "spending bill", "ipa": "/ˈspendɪŋ bɪl/", "pron": "SPEN-ding bil", "fr": "loi de finances ; texte de dépenses", "def": "A bill authorising government expenditure.", "ex": "The spending bill prevented a shutdown."}, {"term": "debt ceiling", "ipa": "/ˈdet ˌsiːlɪŋ/", "pron": "det SEE-ling", "fr": "plafond de la dette", "def": "A legal limit on how much the federal government can borrow.", "ex": "A fight over the debt ceiling threatened financial turmoil."}, {"term": "government shutdown", "ipa": "/ˈɡʌvənmənt ˈʃʌtdaʊn/", "pron": "GUV-uhn-muhnt SHUT-down", "fr": "fermeture partielle de l’administration fédérale", "def": "A situation in which parts of the federal government stop operating because funding has not been approved.", "ex": "The budget dispute caused a government shutdown."}, {"term": "pork-barrel spending", "ipa": "/ˈpɔːk bærəl ˈspendɪŋ/", "pron": "PORK BAR-uhl SPEN-ding", "fr": "dépenses clientélistes ; financement local opportuniste", "def": "Government spending directed to local projects to please voters or lawmakers.", "ex": "Critics denounced the bill as pork-barrel spending."}, {"term": "earmark", "ipa": "/ˈɪəmɑːk/", "pron": "EER-mark", "fr": "affectation budgétaire spécifique", "def": "Money set aside in a bill for a specific local project.", "ex": "The senator defended the earmark for a bridge project."}, {"term": "tax bill", "ipa": "/ˈtæks bɪl/", "pron": "taks bil", "fr": "projet de loi fiscal", "def": "A proposed law dealing with taxation.", "ex": "The tax bill favoured high-income households."}, {"term": "budget deadlock", "ipa": "/ˈbʌdʒɪt ˈdedlɒk/", "pron": "BUJ-it DED-lok", "fr": "blocage budgétaire", "def": "A situation in which lawmakers cannot agree on a budget.", "ex": "Budget deadlock raised fears of a shutdown."}, {"term": "gridlock", "ipa": "/ˈɡrɪdlɒk/", "pron": "GRID-lok", "fr": "blocage institutionnel", "def": "A political situation in which institutions cannot make decisions because of disagreement.", "ex": "Partisan gridlock prevented major reforms."}, {"term": "partisan gridlock", "ipa": "/ˈpɑːtɪzən ˈɡrɪdlɒk/", "pron": "PAR-ti-zuhn GRID-lok", "fr": "blocage partisan", "def": "Institutional blockage caused by intense party conflict.", "ex": "Partisan gridlock has become common in Washington."}, {"term": "divided government", "ipa": "/dɪˌvaɪdɪd ˈɡʌvənmənt/", "pron": "di-VY-did GUV-uhn-muhnt", "fr": "gouvernement divisé", "def": "A situation in which different parties control the presidency and at least one chamber of Congress.", "ex": "Divided government often leads to compromise or gridlock."}, {"term": "unified government", "ipa": "/ˌjuːnɪfaɪd ˈɡʌvənmənt/", "pron": "YOO-ni-fyd GUV-uhn-muhnt", "fr": "gouvernement unifié", "def": "A situation in which one party controls the presidency and both chambers of Congress.", "ex": "Unified government makes it easier to pass legislation."}, {"term": "bipartisan support", "ipa": "/ˌbaɪˈpɑːtɪzən səˈpɔːt/", "pron": "bye-PAR-ti-zuhn suh-PORT", "fr": "soutien bipartisan ; soutien transpartisan", "def": "Support from both major parties.", "ex": "The bill received rare bipartisan support."}, {"term": "party-line vote", "ipa": "/ˌpɑːti laɪn ˈvəʊt/", "pron": "PAR-tee line voht", "fr": "vote selon les lignes partisanes", "def": "A vote in which lawmakers vote according to party affiliation.", "ex": "The reform passed on a party-line vote."}, {"term": "whip count", "ipa": "/ˈwɪp kaʊnt/", "pron": "wip kownt", "fr": "décompte des voix par les whips", "def": "An estimate of how lawmakers are likely to vote.", "ex": "The whip count suggested the bill would fail."}, {"term": "to reach across the aisle", "ipa": "/riːtʃ əˌkrɒs ði ˈaɪl/", "pron": "reech uh-kross thee aisle", "fr": "coopérer avec l’autre camp", "def": "To cooperate with members of the opposing party.", "ex": "The senator tried to reach across the aisle."}, {"term": "to break ranks", "ipa": "/breɪk ˈræŋks/", "pron": "brayk ranks", "fr": "rompre avec la ligne du parti", "def": "To refuse to follow one’s party position.", "ex": "Several Republicans broke ranks and supported the bill."}, {"term": "party discipline", "ipa": "/ˈpɑːti ˈdɪsəplɪn/", "pron": "PAR-tee DIS-uh-plin", "fr": "discipline de parti", "def": "The pressure on lawmakers to vote with their party.", "ex": "Party discipline is weaker in the US Congress than in many parliaments."}, {"term": "lobbyist", "ipa": "/ˈlɒbiɪst/", "pron": "LOB-ee-ist", "fr": "lobbyiste", "def": "A person paid to influence lawmakers or government decisions.", "ex": "Lobbyists contacted senators before the vote."}, {"term": "special interest group", "ipa": "/ˌspeʃəl ˈɪntrəst ɡruːp/", "pron": "SPESH-uhl IN-truhst group", "fr": "groupe d’intérêt particulier", "def": "A group seeking influence for a specific cause, industry or profession.", "ex": "Special interest groups spent heavily on the campaign."}, {"term": "campaign donation", "ipa": "/kæmˈpeɪn dəʊˈneɪʃən/", "pron": "kam-PAYN doh-NAY-shuhn", "fr": "don de campagne", "def": "Money given to support a political campaign.", "ex": "Campaign donations can give donors access to lawmakers."}, {"term": "PAC", "ipa": "/ˌpiː eɪ ˈsiː/", "pron": "pee ay see", "fr": "PAC ; comité d’action politique", "def": "A political action committee that raises and spends money to support or oppose candidates.", "ex": "The PAC funded ads in several congressional races."}]}, {"title": "E. Lobbying, money and high-value congressional verbs", "entries": [{"term": "Super PAC", "ipa": "/ˈsuːpə pæk/", "pron": "SOO-puh pak", "fr": "Super PAC", "def": "A political committee that can spend unlimited money independently of candidates.", "ex": "Super PAC spending has increased the cost of elections."}, {"term": "to lobby Congress", "ipa": "/ˈlɒbi ˈkɒŋɡres/", "pron": "LOB-ee KON-gress", "fr": "faire pression sur le Congrès", "def": "To try to influence members of Congress or congressional policy.", "ex": "Tech companies lobbied Congress over data regulation."}, {"term": "to fund a campaign", "ipa": "/fʌnd ə kæmˈpeɪn/", "pron": "fund uh kam-PAYN", "fr": "financer une campagne", "def": "To provide money for an electoral campaign.", "ex": "Wealthy donors helped fund the campaign."}, {"term": "to shape the agenda", "ipa": "/ʃeɪp ði əˈdʒendə/", "pron": "shayp thee uh-JEN-duh", "fr": "façonner l’agenda politique", "def": "To influence which issues are discussed or prioritised.", "ex": "Committee chairs can shape the agenda."}, {"term": "to hold lawmakers accountable", "ipa": "/həʊld ˈlɔːˌmeɪkəz əˈkaʊntəbəl/", "pron": "hohld LAW-may-kuhz uh-KOWN-tuh-buhl", "fr": "demander des comptes aux élus", "def": "To make elected officials answer for their decisions.", "ex": "Voters can hold lawmakers accountable at the next election."}]}]}, {"id": "p2c14", "part": 2, "chapter": 14, "title": "Supreme Court", "file": "cpge_vocab_part2_chapter14_supreme_court_premium.html", "count": 100, "sections": [{"title": "A. The Court, justices and appointments", "entries": [{"term": "Supreme Court", "ipa": "/suːˌpriːm ˈkɔːt/", "pron": "soo-PREEM court", "fr": "Cour suprême", "def": "The highest court in the United States and the final interpreter of the Constitution.", "ex": "The Supreme Court plays a decisive role in American political life."}, {"term": "SCOTUS", "ipa": "/ˈskəʊtəs/", "pron": "SKOH-tuhs", "fr": "SCOTUS ; Cour suprême des États-Unis", "def": "An acronym for the Supreme Court of the United States.", "ex": "SCOTUS rulings can reshape national policy."}, {"term": "the Court", "ipa": "/ðə ˈkɔːt/", "pron": "thuh court", "fr": "la Cour", "def": "A common shortened way to refer to the Supreme Court in political and legal articles.", "ex": "The Court heard arguments in a major abortion case."}, {"term": "justice", "ipa": "/ˈdʒʌstɪs/", "pron": "JUS-tis", "fr": "juge de la Cour suprême", "def": "A judge serving on the Supreme Court.", "ex": "Each justice has a lifetime appointment."}, {"term": "Chief Justice", "ipa": "/ˌtʃiːf ˈdʒʌstɪs/", "pron": "cheef JUS-tis", "fr": "président de la Cour suprême", "def": "The leading justice who presides over the Supreme Court.", "ex": "The Chief Justice wrote the majority opinion."}, {"term": "Associate Justice", "ipa": "/əˌsəʊsiət ˈdʒʌstɪs/", "pron": "uh-SOH-see-uht JUS-tis", "fr": "juge assesseur de la Cour suprême", "def": "A Supreme Court justice other than the Chief Justice.", "ex": "The Associate Justice joined the dissenting opinion."}, {"term": "bench", "ipa": "/bentʃ/", "pron": "bench", "fr": "magistrature ; juges d’une cour", "def": "The judges of a court considered collectively.", "ex": "The current bench has a conservative majority."}, {"term": "nine-member court", "ipa": "/ˌnaɪn ˈmembə kɔːt/", "pron": "nine MEM-buh court", "fr": "Cour à neuf juges", "def": "The Supreme Court composed of nine justices, as it currently is.", "ex": "The nine-member Court can be deeply divided on ideological lines."}, {"term": "lifetime appointment", "ipa": "/ˌlaɪftaɪm əˈpɔɪntmənt/", "pron": "LYF-tyme uh-POINT-muhnt", "fr": "nomination à vie", "def": "An appointment that lasts for the rest of a justice’s life, unless they resign, retire or are removed.", "ex": "Lifetime appointments make Supreme Court nominations extremely consequential."}, {"term": "judicial independence", "ipa": "/dʒuːˌdɪʃəl ˌɪndɪˈpendəns/", "pron": "joo-DISH-uhl in-di-PEN-duhns", "fr": "indépendance judiciaire", "def": "The principle that judges should decide cases without political pressure.", "ex": "Judicial independence is essential to the rule of law."}, {"term": "nomination", "ipa": "/ˌnɒmɪˈneɪʃən/", "pron": "nom-i-NAY-shuhn", "fr": "nomination", "def": "The act of formally proposing someone for a position, such as the Supreme Court.", "ex": "The nomination sparked a fierce political battle."}, {"term": "nominee", "ipa": "/ˌnɒmɪˈniː/", "pron": "nom-i-NEE", "fr": "personne nommée ; candidat désigné", "def": "A person formally proposed for a position.", "ex": "The nominee faced questions about abortion and executive power."}, {"term": "confirmation", "ipa": "/ˌkɒnfəˈmeɪʃən/", "pron": "kon-fuh-MAY-shuhn", "fr": "confirmation ; approbation", "def": "Formal approval of a nominee, usually by the Senate.", "ex": "The confirmation vote was extremely close."}, {"term": "confirmation hearing", "ipa": "/ˌkɒnfəˈmeɪʃən ˈhɪərɪŋ/", "pron": "kon-fuh-MAY-shuhn HEER-ing", "fr": "audition de confirmation", "def": "A Senate hearing used to question a nominee before confirmation.", "ex": "The confirmation hearing became a national media event."}, {"term": "Senate Judiciary Committee", "ipa": "/ˌsenət dʒuːˈdɪʃəri kəˈmɪti/", "pron": "SEN-uht joo-DISH-uh-ree kuh-MIT-ee", "fr": "commission judiciaire du Sénat", "def": "The Senate committee that reviews judicial nominations and legal issues.", "ex": "The Senate Judiciary Committee questioned the nominee for several days."}, {"term": "senatorial approval", "ipa": "/ˌsenəˈtɔːriəl əˈpruːvəl/", "pron": "sen-uh-TOR-ee-uhl uh-PROO-vuhl", "fr": "approbation du Sénat", "def": "Approval by the Senate, especially of a presidential nominee.", "ex": "Supreme Court nominees require senatorial approval."}, {"term": "to nominate a justice", "ipa": "/ˈnɒmɪneɪt ə ˈdʒʌstɪs/", "pron": "NOM-i-nayt uh JUS-tis", "fr": "nommer un juge à la Cour suprême", "def": "To formally propose someone for a seat on the Supreme Court.", "ex": "The President nominated a conservative justice."}, {"term": "to confirm a nominee", "ipa": "/kənˈfɜːm ə ˌnɒmɪˈniː/", "pron": "kuhn-FURM uh nom-i-NEE", "fr": "confirmer une nomination", "def": "To formally approve a person proposed for a position.", "ex": "The Senate confirmed the nominee by a narrow margin."}, {"term": "to appoint a justice", "ipa": "/əˈpɔɪnt ə ˈdʒʌstɪs/", "pron": "uh-POINT uh JUS-tis", "fr": "nommer officiellement un juge", "def": "To officially choose someone to serve on the Supreme Court.", "ex": "Presidents can shape the Court by appointing justices."}]}, {"title": "B. Judicial review and constitutional interpretation", "entries": [{"term": "judicial review", "ipa": "/dʒuːˌdɪʃəl rɪˈvjuː/", "pron": "joo-DISH-uhl ri-VYOO", "fr": "contrôle de constitutionnalité", "def": "The power of courts to decide whether laws or government actions are constitutional.", "ex": "Judicial review allows the Supreme Court to strike down laws."}, {"term": "constitutionality", "ipa": "/ˌkɒnstɪtjuːʃəˈnæləti/", "pron": "kon-sti-too-shuh-NAL-uh-tee", "fr": "constitutionnalité", "def": "The quality of being allowed or valid under the Constitution.", "ex": "The case questioned the constitutionality of the law."}, {"term": "unconstitutional", "ipa": "/ˌʌnˌkɒnstɪˈtjuːʃənəl/", "pron": "un-kon-sti-TOO-shuh-nuhl", "fr": "inconstitutionnel", "def": "Not allowed by the Constitution.", "ex": "The Court ruled that the law was unconstitutional."}, {"term": "constitutional", "ipa": "/ˌkɒnstɪˈtjuːʃənəl/", "pron": "kon-sti-TOO-shuh-nuhl", "fr": "constitutionnel", "def": "Allowed by or related to the Constitution.", "ex": "The justices disagreed over the constitutional meaning of the text."}, {"term": "constitutional interpretation", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ɪnˌtɜːprɪˈteɪʃən/", "pron": "kon-sti-TOO-shuh-nuhl in-tur-pri-TAY-shuhn", "fr": "interprétation constitutionnelle", "def": "The process of deciding what constitutional provisions mean.", "ex": "Constitutional interpretation often divides liberal and conservative justices."}, {"term": "legal interpretation", "ipa": "/ˈliːɡəl ɪnˌtɜːprɪˈteɪʃən/", "pron": "LEE-guhl in-tur-pri-TAY-shuhn", "fr": "interprétation juridique", "def": "The process of deciding the meaning of laws or legal texts.", "ex": "The ruling depended on legal interpretation."}, {"term": "originalism", "ipa": "/əˈrɪdʒənəlɪzəm/", "pron": "uh-RIJ-uh-nuhl-iz-uhm", "fr": "originalisme", "def": "A method of interpretation based on the original meaning of the constitutional text.", "ex": "Originalism is influential among conservative justices."}, {"term": "textualism", "ipa": "/ˈtekstʃuəlɪzəm/", "pron": "TEKS-choo-uh-liz-uhm", "fr": "textualisme", "def": "A method of interpretation focused on the ordinary meaning of the legal text.", "ex": "Textualism gives priority to the words of the statute."}, {"term": "living constitution", "ipa": "/ˌlɪvɪŋ ˌkɒnstɪˈtjuːʃən/", "pron": "LIV-ing kon-sti-TOO-shuhn", "fr": "constitution vivante", "def": "The view that the Constitution should be interpreted in light of changing social conditions.", "ex": "Supporters of a living constitution argue that rights evolve over time."}, {"term": "strict construction", "ipa": "/ˌstrɪkt kənˈstrʌkʃən/", "pron": "strikt kuhn-STRUK-shuhn", "fr": "interprétation stricte", "def": "A narrow interpretation of the Constitution or legal text.", "ex": "Strict construction limits judicial creativity."}, {"term": "broad interpretation", "ipa": "/ˌbrɔːd ɪnˌtɜːprɪˈteɪʃən/", "pron": "broad in-tur-pri-TAY-shuhn", "fr": "interprétation large", "def": "An interpretation that gives a legal text a wider meaning or application.", "ex": "A broad interpretation of rights can expand legal protections."}, {"term": "judicial philosophy", "ipa": "/dʒuːˌdɪʃəl fɪˈlɒsəfi/", "pron": "joo-DISH-uhl fi-LOS-uh-fee", "fr": "philosophie judiciaire", "def": "A judge’s general approach to interpreting law and the Constitution.", "ex": "A nominee’s judicial philosophy is heavily scrutinised."}, {"term": "judicial restraint", "ipa": "/dʒuːˌdɪʃəl rɪˈstreɪnt/", "pron": "joo-DISH-uhl ri-STRAYNT", "fr": "retenue judiciaire", "def": "The view that judges should avoid overturning laws or making broad policy decisions.", "ex": "Supporters of judicial restraint say courts should defer to elected branches."}, {"term": "judicial activism", "ipa": "/dʒuːˌdɪʃəl ˈæktɪvɪzəm/", "pron": "joo-DISH-uhl AK-ti-viz-uhm", "fr": "activisme judiciaire", "def": "The criticism or idea that judges use their power to shape policy rather than merely interpret law.", "ex": "Critics accused the Court of judicial activism."}, {"term": "conservative majority", "ipa": "/kənˈsɜːvətɪv məˈdʒɒrəti/", "pron": "kuhn-SUR-vuh-tiv muh-JOR-uh-tee", "fr": "majorité conservatrice", "def": "A majority of justices with conservative legal or political leanings.", "ex": "The conservative majority changed the direction of the Court."}, {"term": "liberal minority", "ipa": "/ˈlɪbərəl maɪˈnɒrəti/", "pron": "LIB-uh-ruhl my-NOR-uh-tee", "fr": "minorité libérale", "def": "A minority of justices with liberal legal or political leanings.", "ex": "The liberal minority dissented strongly."}, {"term": "ideological balance", "ipa": "/ˌaɪdiəˈlɒdʒɪkəl ˈbæləns/", "pron": "eye-dee-uh-LOJ-i-kuhl BAL-uhns", "fr": "équilibre idéologique", "def": "The distribution of ideological views among justices.", "ex": "A single appointment can shift the Court’s ideological balance."}, {"term": "court packing", "ipa": "/ˈkɔːt ˌpækɪŋ/", "pron": "court PAK-ing", "fr": "élargissement stratégique de la Cour ; court packing", "def": "The proposal or practice of adding judges to a court to change its ideological balance.", "ex": "Court packing is controversial because it may politicise the judiciary."}, {"term": "to pack the Court", "ipa": "/pæk ðə ˈkɔːt/", "pron": "pak thuh court", "fr": "ajouter des juges pour changer l’équilibre de la Cour", "def": "To add justices to the Supreme Court for political advantage.", "ex": "Some activists urged Democrats to pack the Court."}, {"term": "case", "ipa": "/keɪs/", "pron": "kayss", "fr": "affaire ; dossier judiciaire", "def": "A legal dispute brought before a court.", "ex": "The case reached the Supreme Court."}]}, {"title": "C. Cases, procedure and legal actors", "entries": [{"term": "lawsuit", "ipa": "/ˈlɔːsuːt/", "pron": "LAW-soot", "fr": "procès ; action en justice", "def": "A legal case brought by one party against another.", "ex": "The lawsuit challenged the state’s abortion law."}, {"term": "litigation", "ipa": "/ˌlɪtɪˈɡeɪʃən/", "pron": "lit-i-GAY-shuhn", "fr": "contentieux ; procédure judiciaire", "def": "The process of taking legal action in court.", "ex": "Years of litigation followed the new regulation."}, {"term": "legal challenge", "ipa": "/ˈliːɡəl ˈtʃælɪndʒ/", "pron": "LEE-guhl CHAL-inj", "fr": "recours juridique ; contestation en justice", "def": "A formal attempt to oppose a law or decision in court.", "ex": "Civil rights groups filed a legal challenge."}, {"term": "petition", "ipa": "/pəˈtɪʃən/", "pron": "puh-TISH-uhn", "fr": "requête ; demande à la Cour", "def": "A formal request to a court asking it to take action.", "ex": "The petition asked the Court to review the case."}, {"term": "appeal", "ipa": "/əˈpiːl/", "pron": "uh-PEEL", "fr": "appel ; recours", "def": "A request for a higher court to review a lower court’s decision.", "ex": "The appeal was heard by the Supreme Court."}, {"term": "to hear a case", "ipa": "/hɪə ə ˈkeɪs/", "pron": "heer uh kayss", "fr": "examiner une affaire", "def": "For a court to consider and examine a legal case.", "ex": "The Court agreed to hear the case."}, {"term": "to take up a case", "ipa": "/teɪk ʌp ə ˈkeɪs/", "pron": "tayk up uh kayss", "fr": "se saisir d’une affaire", "def": "To agree to examine a legal case.", "ex": "The justices decided to take up the case."}, {"term": "to decline to hear a case", "ipa": "/dɪˈklaɪn tə hɪə ə ˈkeɪs/", "pron": "di-KLYNE tuh heer uh kayss", "fr": "refuser d’examiner une affaire", "def": "To refuse to review a case.", "ex": "The Court declined to hear the appeal."}, {"term": "oral arguments", "ipa": "/ˌɔːrəl ˈɑːɡjəmənts/", "pron": "OR-uhl AR-gyuh-muhnts", "fr": "plaidoiries orales", "def": "Spoken presentations by lawyers before a court.", "ex": "The justices asked sharp questions during oral arguments."}, {"term": "brief", "ipa": "/briːf/", "pron": "breef", "fr": "mémoire juridique", "def": "A written legal argument submitted to a court.", "ex": "The lawyers filed a brief defending the law."}, {"term": "amicus brief", "ipa": "/əˈmiːkəs briːf/", "pron": "uh-MEE-kuhs breef", "fr": "mémoire d’amicus curiae ; contribution extérieure", "def": "A legal brief submitted by someone who is not a party to the case but has an interest in it.", "ex": "Several civil rights organisations filed amicus briefs."}, {"term": "plaintiff", "ipa": "/ˈpleɪntɪf/", "pron": "PLAYN-tif", "fr": "plaignant ; demandeur", "def": "The person or group bringing a legal case.", "ex": "The plaintiff argued that the law violated the Constitution."}, {"term": "defendant", "ipa": "/dɪˈfendənt/", "pron": "di-FEN-duhnt", "fr": "défendeur ; accusé", "def": "The person, organisation or government being sued or accused.", "ex": "The defendant was the state government."}, {"term": "appellant", "ipa": "/əˈpelənt/", "pron": "uh-PEL-uhnt", "fr": "appelant ; requérant en appel", "def": "The party that appeals a lower court decision.", "ex": "The appellant asked the Court to overturn the ruling."}, {"term": "respondent", "ipa": "/rɪˈspɒndənt/", "pron": "ri-SPON-duhnt", "fr": "défendeur au pourvoi ; intimé", "def": "The party responding to an appeal or petition.", "ex": "The respondent defended the lower court’s decision."}, {"term": "ruling", "ipa": "/ˈruːlɪŋ/", "pron": "ROO-ling", "fr": "décision de justice", "def": "An official decision made by a court.", "ex": "The ruling sparked intense political debate."}, {"term": "decision", "ipa": "/dɪˈsɪʒən/", "pron": "di-SIZH-uhn", "fr": "décision", "def": "A court’s formal answer to a legal question.", "ex": "The decision changed the legal landscape."}, {"term": "opinion", "ipa": "/əˈpɪnjən/", "pron": "uh-PIN-yuhn", "fr": "opinion ; avis de la Cour", "def": "A written explanation of a court’s decision.", "ex": "The opinion was more than one hundred pages long."}, {"term": "majority opinion", "ipa": "/məˈdʒɒrəti əˈpɪnjən/", "pron": "muh-JOR-uh-tee uh-PIN-yuhn", "fr": "opinion majoritaire", "def": "The opinion joined by most justices and representing the Court’s ruling.", "ex": "The majority opinion struck down the law."}, {"term": "dissenting opinion", "ipa": "/dɪˈsentɪŋ əˈpɪnjən/", "pron": "di-SEN-ting uh-PIN-yuhn", "fr": "opinion dissidente", "def": "An opinion written by a justice who disagrees with the majority.", "ex": "The dissenting opinion warned that rights were being weakened."}]}, {"title": "D. Rulings, opinions and precedent", "entries": [{"term": "concurring opinion", "ipa": "/kənˈkɜːrɪŋ əˈpɪnjən/", "pron": "kuhn-KUR-ing uh-PIN-yuhn", "fr": "opinion concordante", "def": "An opinion agreeing with the result but giving different reasons.", "ex": "The justice wrote a concurring opinion."}, {"term": "unanimous decision", "ipa": "/juːˈnænɪməs dɪˈsɪʒən/", "pron": "yoo-NAN-i-muhs di-SIZH-uhn", "fr": "décision unanime", "def": "A decision supported by all justices.", "ex": "The Court issued a unanimous decision."}, {"term": "split decision", "ipa": "/ˌsplɪt dɪˈsɪʒən/", "pron": "split di-SIZH-uhn", "fr": "décision partagée", "def": "A decision in which justices are divided.", "ex": "The case ended in a 5–4 split decision."}, {"term": "5–4 ruling", "ipa": "/ˌfaɪv fə ˈfɔː ˈruːlɪŋ/", "pron": "five-fuh-four ROO-ling", "fr": "décision à cinq contre quatre", "def": "A Supreme Court ruling decided by five justices against four.", "ex": "The controversial 5–4 ruling divided the country."}, {"term": "landmark ruling", "ipa": "/ˈlændmɑːk ˈruːlɪŋ/", "pron": "LAND-mark ROO-ling", "fr": "arrêt historique ; décision majeure", "def": "A major court decision that has a lasting impact on law or society.", "ex": "The landmark ruling transformed abortion rights."}, {"term": "precedent", "ipa": "/ˈpresɪdənt/", "pron": "PRES-i-duhnt", "fr": "précédent juridique", "def": "A previous legal decision that guides future cases.", "ex": "The ruling set an important precedent."}, {"term": "binding precedent", "ipa": "/ˌbaɪndɪŋ ˈpresɪdənt/", "pron": "BYN-ding PRES-i-duhnt", "fr": "précédent contraignant", "def": "A precedent that lower courts must follow.", "ex": "Lower courts must follow binding precedent."}, {"term": "stare decisis", "ipa": "/ˌsteəri dɪˈsaɪsɪs/", "pron": "STAIR-ee di-SY-sis", "fr": "stare decisis ; respect des précédents", "def": "The legal principle that courts should generally follow precedent.", "ex": "The justices disagreed over the meaning of stare decisis."}, {"term": "to set a precedent", "ipa": "/set ə ˈpresɪdənt/", "pron": "set uh PRES-i-duhnt", "fr": "créer un précédent", "def": "To establish a legal example that may guide future cases.", "ex": "The case set a precedent for privacy law."}, {"term": "to overturn a precedent", "ipa": "/ˌəʊvəˈtɜːn ə ˈpresɪdənt/", "pron": "OH-vuh-turn uh PRES-i-duhnt", "fr": "renverser un précédent", "def": "To reject or reverse a previous legal rule.", "ex": "The Court overturned a long-standing precedent."}, {"term": "to uphold a law", "ipa": "/ʌpˈhəʊld ə ˈlɔː/", "pron": "up-HOHLD uh law", "fr": "confirmer la validité d’une loi", "def": "For a court to decide that a law is valid.", "ex": "The Supreme Court upheld the law."}, {"term": "to strike down a law", "ipa": "/straɪk daʊn ə ˈlɔː/", "pron": "stryke down uh law", "fr": "annuler ; invalider une loi", "def": "For a court to declare a law invalid or unconstitutional.", "ex": "The Court struck down the state law."}, {"term": "to overturn a ruling", "ipa": "/ˌəʊvəˈtɜːn ə ˈruːlɪŋ/", "pron": "OH-vuh-turn uh ROO-ling", "fr": "annuler ; renverser une décision", "def": "To reverse a previous court decision.", "ex": "The Court overturned the lower court’s ruling."}, {"term": "to narrow a ruling", "ipa": "/ˈnærəʊ ə ˈruːlɪŋ/", "pron": "NAR-oh uh ROO-ling", "fr": "restreindre la portée d’une décision", "def": "To limit the scope or effect of a previous decision.", "ex": "The Court narrowed the earlier ruling."}, {"term": "to broaden rights", "ipa": "/ˈbrɔːdən ˈraɪts/", "pron": "BRAW-duhn rites", "fr": "élargir les droits", "def": "To expand the scope of legal protections.", "ex": "The decision broadened rights for criminal defendants."}, {"term": "to restrict rights", "ipa": "/rɪˈstrɪkt ˈraɪts/", "pron": "ri-STRIKT rites", "fr": "restreindre les droits", "def": "To limit the scope of legal protections.", "ex": "Critics said the ruling restricted voting rights."}, {"term": "to rule in favour of", "ipa": "/ruːl ɪn ˈfeɪvər əv/", "pron": "rool in FAY-vuhr ov", "fr": "statuer en faveur de", "def": "To decide that one side in a case is right.", "ex": "The Court ruled in favour of the plaintiffs."}, {"term": "to rule against", "ipa": "/ruːl əˈɡenst/", "pron": "rool uh-GENST", "fr": "statuer contre", "def": "To decide against one side in a case.", "ex": "The Court ruled against the administration."}, {"term": "Roe v. Wade", "ipa": "/ˌrəʊ vɜːsəs ˈweɪd/", "pron": "roh VUR-suhs wayd", "fr": "Roe v. Wade", "def": "The 1973 Supreme Court ruling that recognised a constitutional right to abortion before being overturned in 2022.", "ex": "Roe v. Wade became a central symbol in abortion-rights debates."}, {"term": "Dobbs v. Jackson Women’s Health Organization", "ipa": "/dɒbz vɜːsəs ˈdʒæksən ˈwɪmɪnz helθ ˌɔːɡənaɪˈzeɪʃən/", "pron": "dobz VUR-suhs JAK-suhn WIM-inz health or-guh-ny-ZAY-shuhn", "fr": "Dobbs v. Jackson Women’s Health Organization", "def": "The 2022 Supreme Court ruling that overturned Roe v. Wade.", "ex": "Dobbs returned abortion regulation largely to the states."}, {"term": "abortion rights", "ipa": "/əˈbɔːʃən raɪts/", "pron": "uh-BOR-shuhn rites", "fr": "droits liés à l’avortement", "def": "Legal rights relating to access to abortion.", "ex": "Abortion rights became a major election issue after Dobbs."}]}, {"title": "E. Major issues, legitimacy and high-value verbs", "entries": [{"term": "gun rights", "ipa": "/ˈɡʌn raɪts/", "pron": "gun rites", "fr": "droit de posséder ou porter des armes", "def": "Legal rights related to owning or carrying firearms.", "ex": "Gun rights cases often involve the Second Amendment."}, {"term": "voting rights", "ipa": "/ˈvəʊtɪŋ raɪts/", "pron": "VOH-ting rites", "fr": "droit de vote ; droits électoraux", "def": "Legal rights protecting citizens’ ability to vote.", "ex": "Voting rights cases often reach the Supreme Court."}, {"term": "civil rights", "ipa": "/ˌsɪvəl ˈraɪts/", "pron": "SIV-uhl rites", "fr": "droits civiques", "def": "Rights protecting people from discrimination and guaranteeing equal treatment.", "ex": "Civil rights rulings have shaped American society."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected by law, such as speech, religion and assembly.", "ex": "Civil liberties can be limited during security crises."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "The right to express opinions without unjustified government restriction.", "ex": "Free speech cases are central to First Amendment law."}, {"term": "religious freedom", "ipa": "/rɪˌlɪdʒəs ˈfriːdəm/", "pron": "ri-LIJ-uhs FREE-duhm", "fr": "liberté religieuse", "def": "The right to practise or reject a religion without unjustified state interference.", "ex": "Religious freedom cases often raise difficult constitutional questions."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to increase opportunities for groups historically discriminated against.", "ex": "The Court limited the use of affirmative action in university admissions."}, {"term": "equal protection", "ipa": "/ˌiːkwəl prəˈtekʃən/", "pron": "EE-kwuhl pruh-TEK-shuhn", "fr": "égale protection de la loi", "def": "The constitutional principle that the law must protect people equally.", "ex": "Equal protection is central to civil rights litigation."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "dyoo PROH-sess", "fr": "procédure régulière ; garanties procédurales", "def": "Fair legal procedures required before the state deprives someone of rights, liberty or property.", "ex": "Due process protects individuals from arbitrary punishment."}, {"term": "privacy rights", "ipa": "/ˈprɪvəsi raɪts/", "pron": "PRIV-uh-see rites", "fr": "droit à la vie privée", "def": "Legal protections for personal autonomy and private life.", "ex": "Privacy rights have been debated in abortion and surveillance cases."}, {"term": "federalism case", "ipa": "/ˈfedərəlɪzəm keɪs/", "pron": "FED-uh-ruh-liz-uhm kayss", "fr": "affaire liée au fédéralisme", "def": "A case involving the division of power between federal and state governments.", "ex": "Many federalism cases concern the limits of federal authority."}, {"term": "states’ rights", "ipa": "/ˌsteɪts ˈraɪts/", "pron": "stayts rites", "fr": "droits des États fédérés", "def": "The idea that states should retain substantial powers against federal authority.", "ex": "States’ rights arguments are common in abortion and gun cases."}, {"term": "public confidence in the Court", "ipa": "/ˌpʌblɪk ˈkɒnfɪdəns ɪn ðə ˈkɔːt/", "pron": "PUB-lik KON-fi-duhns in thuh court", "fr": "confiance du public dans la Cour", "def": "The degree to which citizens trust the Supreme Court as an institution.", "ex": "Public confidence in the Court declined after several controversial rulings."}, {"term": "legitimacy of the Court", "ipa": "/lɪˈdʒɪtɪməsi əv ðə ˈkɔːt/", "pron": "li-JIT-i-muh-see ov thuh court", "fr": "légitimité de la Cour", "def": "The belief that the Supreme Court has the authority and credibility to decide major legal questions.", "ex": "Highly partisan rulings can weaken the legitimacy of the Court."}, {"term": "politicisation of the judiciary", "ipa": "/pəˌlɪtɪsaɪˈzeɪʃən əv ðə dʒuːˈdɪʃəri/", "pron": "puh-lit-i-sy-ZAY-shuhn ov thuh joo-DISH-uh-ree", "fr": "politisation du pouvoir judiciaire", "def": "The process by which courts or judicial appointments become strongly shaped by party politics.", "ex": "The politicisation of the judiciary worries many observers."}, {"term": "to erode trust in the Court", "ipa": "/ɪˈrəʊd ˈtrʌst ɪn ðə ˈkɔːt/", "pron": "i-ROHD trust in thuh court", "fr": "éroder la confiance dans la Cour", "def": "To gradually weaken public confidence in the Supreme Court.", "ex": "Ethics scandals can erode trust in the Court."}, {"term": "to reshape American law", "ipa": "/riːˈʃeɪp əˈmerɪkən ˈlɔː/", "pron": "ree-SHAYP uh-MER-i-kuhn law", "fr": "remodeler le droit américain", "def": "To change the direction or structure of US law in a lasting way.", "ex": "A conservative majority can reshape American law for decades."}, {"term": "to fuel political backlash", "ipa": "/ˈfjuːəl pəˈlɪtɪkəl ˈbæklæʃ/", "pron": "FYOO-uhl puh-LIT-i-kuhl BAK-lash", "fr": "alimenter une réaction politique hostile", "def": "To intensify a strong political reaction against a decision or policy.", "ex": "The ruling fuelled political backlash across the country."}, {"term": "to divide the country", "ipa": "/dɪˈvaɪd ðə ˈkʌntri/", "pron": "di-VYDE thuh KUN-tree", "fr": "diviser le pays", "def": "To create or deepen national political disagreement.", "ex": "The decision divided the country along ideological lines."}, {"term": "to test the limits of federal power", "ipa": "/test ðə ˈlɪmɪts əv ˈfedərəl ˈpaʊə/", "pron": "test thuh LIM-its ov FED-uh-ruhl POW-uh", "fr": "tester les limites du pouvoir fédéral", "def": "To raise legal questions about how far federal authority can go.", "ex": "The case tested the limits of federal power."}]}]}, {"id": "p2c15", "part": 2, "chapter": 15, "title": "Federalism", "file": "cpge_vocab_part2_chapter15_federalism_premium.html", "count": 95, "sections": [{"title": "A. Levels of government and federal structure", "entries": [{"term": "federalism", "ipa": "/ˈfedərəlɪzəm/", "pron": "FED-uh-ruh-liz-uhm", "fr": "fédéralisme", "def": "A political system in which power is divided between a national government and regional governments.", "ex": "Federalism is one of the defining features of the American political system."}, {"term": "federal system", "ipa": "/ˈfedərəl ˈsɪstəm/", "pron": "FED-uh-ruhl SIS-tuhm", "fr": "système fédéral", "def": "A system of government in which authority is shared between central and regional levels.", "ex": "The United States has a federal system with fifty states."}, {"term": "federal government", "ipa": "/ˈfedərəl ˈɡʌvənmənt/", "pron": "FED-uh-ruhl GUV-uhn-muhnt", "fr": "gouvernement fédéral", "def": "The national government of the United States.", "ex": "The federal government controls defence, foreign policy and federal law."}, {"term": "state government", "ipa": "/ˌsteɪt ˈɡʌvənmənt/", "pron": "stayt GUV-uhn-muhnt", "fr": "gouvernement d’un État fédéré", "def": "The government of one of the US states.", "ex": "State governments have major powers over education, policing and elections."}, {"term": "state authority", "ipa": "/ˌsteɪt ɔːˈθɒrəti/", "pron": "stayt aw-THOR-uh-tee", "fr": "autorité des États fédérés", "def": "The power held by state governments.", "ex": "The ruling strengthened state authority over abortion policy."}, {"term": "local government", "ipa": "/ˌləʊkəl ˈɡʌvənmənt/", "pron": "LOH-kuhl GUV-uhn-muhnt", "fr": "gouvernement local ; collectivités locales", "def": "Government at city, county or municipal level.", "ex": "Local government manages many everyday public services."}, {"term": "county", "ipa": "/ˈkaʊnti/", "pron": "KOWN-tee", "fr": "comté", "def": "A local administrative area within a US state.", "ex": "The county is responsible for organising local elections."}, {"term": "municipality", "ipa": "/mjuːˌnɪsɪˈpæləti/", "pron": "myoo-nis-i-PAL-uh-tee", "fr": "municipalité", "def": "A city or town with its own local government.", "ex": "The municipality introduced new housing rules."}, {"term": "state legislature", "ipa": "/ˌsteɪt ˈledʒɪslətʃə/", "pron": "stayt LEDJ-is-luh-chuh", "fr": "assemblée législative d’un État", "def": "The law-making body of a US state.", "ex": "The state legislature passed a restrictive voting law."}, {"term": "governor", "ipa": "/ˈɡʌvənə/", "pron": "GUV-uh-nuh", "fr": "gouverneur ; gouverneure", "def": "The elected head of a US state government.", "ex": "The governor signed the bill into law."}, {"term": "state constitution", "ipa": "/ˌsteɪt ˌkɒnstɪˈtjuːʃən/", "pron": "stayt kon-sti-TOO-shuhn", "fr": "constitution d’un État fédéré", "def": "The constitution of a US state, setting out its own institutions and rights.", "ex": "Some state constitutions provide broader rights than the federal Constitution."}, {"term": "state law", "ipa": "/ˌsteɪt ˈlɔː/", "pron": "stayt law", "fr": "loi d’un État fédéré", "def": "A law passed by a state government.", "ex": "State law varies widely across the United States."}, {"term": "federal law", "ipa": "/ˌfedərəl ˈlɔː/", "pron": "FED-uh-ruhl law", "fr": "loi fédérale", "def": "A law passed by the national government and applying across the United States.", "ex": "Federal law takes priority when it conflicts with state law."}, {"term": "national authority", "ipa": "/ˌnæʃənəl ɔːˈθɒrəti/", "pron": "NASH-uh-nuhl aw-THOR-uh-tee", "fr": "autorité nationale ; pouvoir fédéral", "def": "The power held by the national government.", "ex": "National authority expanded during the twentieth century."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The authority to govern and make laws.", "ex": "American federalism divides sovereignty between Washington and the states."}, {"term": "dual sovereignty", "ipa": "/ˌdjuːəl ˈsɒvrənti/", "pron": "DYOO-uhl SOV-ruhn-tee", "fr": "double souveraineté", "def": "The idea that both the federal government and state governments have their own authority.", "ex": "Dual sovereignty creates tensions between national and state power."}, {"term": "division of powers", "ipa": "/dɪˌvɪʒən əv ˈpaʊəz/", "pron": "di-VIZH-uhn ov POW-uhz", "fr": "répartition des pouvoirs", "def": "The allocation of authority between different levels or branches of government.", "ex": "The division of powers is central to federalism."}, {"term": "shared powers", "ipa": "/ˌʃeəd ˈpaʊəz/", "pron": "shaird POW-uhz", "fr": "pouvoirs partagés", "def": "Powers exercised by both federal and state governments.", "ex": "Taxation is one example of shared powers."}]}, {"title": "B. Constitutional powers and federal clauses", "entries": [{"term": "delegated powers", "ipa": "/ˈdelɪɡeɪtɪd ˈpaʊəz/", "pron": "DEL-i-gay-tid POW-uhz", "fr": "pouvoirs délégués au gouvernement fédéral", "def": "Powers specifically granted to the federal government by the Constitution.", "ex": "Declaring war is one of Congress’s delegated powers."}, {"term": "enumerated powers", "ipa": "/ɪˈnjuːməreɪtɪd ˈpaʊəz/", "pron": "i-NYOO-muh-ray-tid POW-uhz", "fr": "pouvoirs énumérés", "def": "Powers explicitly listed in the Constitution.", "ex": "The Constitution gives Congress enumerated powers."}, {"term": "implied powers", "ipa": "/ɪmˈplaɪd ˈpaʊəz/", "pron": "im-PLYD POW-uhz", "fr": "pouvoirs implicites", "def": "Powers not explicitly stated but considered necessary to carry out constitutional responsibilities.", "ex": "Implied powers have allowed federal authority to expand."}, {"term": "reserved powers", "ipa": "/rɪˈzɜːvd ˈpaʊəz/", "pron": "ri-ZURVD POW-uhz", "fr": "pouvoirs réservés aux États", "def": "Powers kept by the states rather than given to the federal government.", "ex": "The Tenth Amendment protects reserved powers."}, {"term": "concurrent powers", "ipa": "/kənˈkʌrənt ˈpaʊəz/", "pron": "kuhn-KUR-uhnt POW-uhz", "fr": "pouvoirs concurrents", "def": "Powers shared by both federal and state governments.", "ex": "Both federal and state governments have concurrent powers to tax."}, {"term": "police powers", "ipa": "/pəˈliːs ˈpaʊəz/", "pron": "puh-LEESS POW-uhz", "fr": "pouvoirs de police des États", "def": "State powers to regulate health, safety, welfare and morality.", "ex": "Police powers give states authority over many public health rules."}, {"term": "home rule", "ipa": "/ˌhəʊm ˈruːl/", "pron": "hohm rool", "fr": "autonomie locale", "def": "The power of local governments to manage their own affairs.", "ex": "Home rule allows cities to adopt local policies."}, {"term": "state autonomy", "ipa": "/ˌsteɪt ɔːˈtɒnəmi/", "pron": "stayt aw-TON-uh-mee", "fr": "autonomie des États fédérés", "def": "The ability of states to govern themselves in certain areas.", "ex": "State autonomy is a recurring theme in American politics."}, {"term": "Tenth Amendment", "ipa": "/ˌtenθ əˈmendmənt/", "pron": "tenth uh-MEND-muhnt", "fr": "Dixième amendement", "def": "The amendment stating that powers not delegated to the federal government are reserved to the states or the people.", "ex": "The Tenth Amendment is often invoked in states’ rights arguments."}, {"term": "Supremacy Clause", "ipa": "/suːˈpreməsi klɔːz/", "pron": "soo-PREM-uh-see klawz", "fr": "clause de suprématie", "def": "The constitutional rule that federal law is superior to conflicting state law.", "ex": "The Supremacy Clause makes federal law the supreme law of the land."}, {"term": "Necessary and Proper Clause", "ipa": "/ˈnesəsəri ænd ˈprɒpə klɔːz/", "pron": "NESS-uh-suh-ree and PROP-uh klawz", "fr": "clause nécessaire et appropriée", "def": "The clause allowing Congress to pass laws needed to carry out its constitutional powers.", "ex": "The Necessary and Proper Clause supports implied powers."}, {"term": "Commerce Clause", "ipa": "/ˈkɒmɜːs klɔːz/", "pron": "KOM-urs klawz", "fr": "clause du commerce", "def": "The constitutional clause giving Congress power to regulate interstate commerce.", "ex": "The Commerce Clause has been used to justify federal regulation."}, {"term": "Full Faith and Credit Clause", "ipa": "/ˌfʊl feɪθ ən ˈkredɪt klɔːz/", "pron": "full fayth uhn KRED-it klawz", "fr": "clause de pleine foi et crédit", "def": "The clause requiring states to respect the public acts, records and judicial decisions of other states.", "ex": "The Full Faith and Credit Clause helps link state legal systems."}, {"term": "federal preemption", "ipa": "/ˈfedərəl priːˈempʃən/", "pron": "FED-uh-ruhl pree-EMP-shuhn", "fr": "préemption fédérale", "def": "The principle that federal law can override state law in certain areas.", "ex": "Federal preemption can limit state regulation."}, {"term": "preemption", "ipa": "/priːˈempʃən/", "pron": "pree-EMP-shuhn", "fr": "préemption", "def": "The legal principle by which a higher authority overrides lower-level law.", "ex": "Preemption disputes often arise in environmental law."}, {"term": "constitutional conflict", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈkɒnflɪkt/", "pron": "kon-sti-TOO-shuh-nuhl KON-flikt", "fr": "conflit constitutionnel", "def": "A disagreement involving constitutional powers or rules.", "ex": "The case created a constitutional conflict between the state and federal governments."}, {"term": "states’ rights", "ipa": "/ˌsteɪts ˈraɪts/", "pron": "stayts rites", "fr": "droits des États fédérés", "def": "The belief that US states should retain significant authority against federal power.", "ex": "States’ rights arguments are common in abortion and gun debates."}]}, {"title": "C. States’ rights, centralisation and models of federalism", "entries": [{"term": "state sovereignty", "ipa": "/ˌsteɪt ˈsɒvrənti/", "pron": "stayt SOV-ruhn-tee", "fr": "souveraineté des États fédérés", "def": "The authority of a state to govern itself within the federal system.", "ex": "State sovereignty is limited by the federal Constitution."}, {"term": "federal authority", "ipa": "/ˈfedərəl ɔːˈθɒrəti/", "pron": "FED-uh-ruhl aw-THOR-uh-tee", "fr": "autorité fédérale", "def": "The power of the national government.", "ex": "The Court upheld federal authority over immigration."}, {"term": "federal mandate", "ipa": "/ˈfedərəl ˈmændeɪt/", "pron": "FED-uh-ruhl MAN-dayt", "fr": "obligation fédérale ; mandat fédéral", "def": "A requirement imposed by the federal government on states or individuals.", "ex": "Governors criticised the federal mandate."}, {"term": "unfunded mandate", "ipa": "/ˌʌnˈfʌndɪd ˈmændeɪt/", "pron": "un-FUN-did MAN-dayt", "fr": "obligation non financée", "def": "A federal requirement imposed on states without providing enough funding.", "ex": "States complained that the education law created unfunded mandates."}, {"term": "state resistance", "ipa": "/ˌsteɪt rɪˈzɪstəns/", "pron": "stayt ri-ZIS-tuhns", "fr": "résistance des États", "def": "Opposition by state governments to federal laws or policies.", "ex": "State resistance complicated the implementation of federal policy."}, {"term": "nullification", "ipa": "/ˌnʌlɪfɪˈkeɪʃən/", "pron": "nul-i-fi-KAY-shuhn", "fr": "annulation par un État ; nullification", "def": "The disputed idea that a state can declare a federal law invalid within its borders.", "ex": "Nullification has been rejected by federal courts."}, {"term": "secession", "ipa": "/sɪˈseʃən/", "pron": "si-SESH-uhn", "fr": "sécession", "def": "The act of formally leaving a political union or state.", "ex": "Secession was at the heart of the American Civil War."}, {"term": "devolution", "ipa": "/ˌdiːvəˈluːʃən/", "pron": "dee-vuh-LOO-shuhn", "fr": "dévolution", "def": "The transfer of powers from central government to regional or local authorities.", "ex": "American federalism differs from British devolution."}, {"term": "decentralisation", "ipa": "/ˌdiːsentrəlaɪˈzeɪʃən/", "pron": "dee-sen-truh-ly-ZAY-shuhn", "fr": "décentralisation", "def": "The transfer or distribution of power away from central government.", "ex": "Federalism involves a high degree of decentralisation."}, {"term": "centralisation", "ipa": "/ˌsentrəlaɪˈzeɪʃən/", "pron": "sen-truh-ly-ZAY-shuhn", "fr": "centralisation", "def": "The concentration of power in the central government.", "ex": "Critics argue that federal programmes have increased centralisation."}, {"term": "cooperative federalism", "ipa": "/kəʊˌɒpərətɪv ˈfedərəlɪzəm/", "pron": "koh-OP-uh-ruh-tiv FED-uh-ruh-liz-uhm", "fr": "fédéralisme coopératif", "def": "A model in which federal and state governments work together on policy.", "ex": "Cooperative federalism expanded during the New Deal."}, {"term": "dual federalism", "ipa": "/ˌdjuːəl ˈfedərəlɪzəm/", "pron": "DYOO-uhl FED-uh-ruh-liz-uhm", "fr": "fédéralisme dual", "def": "A model in which federal and state powers are clearly separated.", "ex": "Dual federalism is often compared to a layer cake."}, {"term": "competitive federalism", "ipa": "/kəmˌpetɪtɪv ˈfedərəlɪzəm/", "pron": "kuhm-PET-i-tiv FED-uh-ruh-liz-uhm", "fr": "fédéralisme concurrentiel", "def": "A model in which states compete with each other over policies, taxes or economic conditions.", "ex": "Competitive federalism can encourage policy innovation or a race to the bottom."}, {"term": "fiscal federalism", "ipa": "/ˌfɪskəl ˈfedərəlɪzəm/", "pron": "FIS-kuhl FED-uh-ruh-liz-uhm", "fr": "fédéralisme fiscal", "def": "The financial relationship between federal, state and local governments.", "ex": "Fiscal federalism shapes education, healthcare and infrastructure policy."}, {"term": "marble-cake federalism", "ipa": "/ˌmɑːbəl keɪk ˈfedərəlɪzəm/", "pron": "MAR-buhl-kayk FED-uh-ruh-liz-uhm", "fr": "fédéralisme imbriqué ; modèle du gâteau marbré", "def": "A metaphor for cooperative federalism, where federal and state powers are mixed together.", "ex": "Marble-cake federalism describes overlapping responsibilities."}, {"term": "layer-cake federalism", "ipa": "/ˌleɪə keɪk ˈfedərəlɪzəm/", "pron": "LAY-uh-kayk FED-uh-ruh-liz-uhm", "fr": "fédéralisme en couches séparées", "def": "A metaphor for dual federalism, where federal and state powers are separate layers.", "ex": "Layer-cake federalism suggests clear boundaries between levels of government."}, {"term": "laboratories of democracy", "ipa": "/ləˈbɒrətriz əv dɪˈmɒkrəsi/", "pron": "luh-BOR-uh-treez ov di-MOK-ruh-see", "fr": "laboratoires de la démocratie", "def": "A phrase describing states as places where policies can be tested before spreading nationally.", "ex": "States are often called laboratories of democracy."}, {"term": "policy experimentation", "ipa": "/ˈpɒləsi ɪkˌsperɪmenˈteɪʃən/", "pron": "POL-uh-see ik-sper-i-men-TAY-shuhn", "fr": "expérimentation politique", "def": "The testing of different policies by states or local governments.", "ex": "Federalism allows policy experimentation across states."}, {"term": "policy patchwork", "ipa": "/ˈpɒləsi ˈpætʃwɜːk/", "pron": "POL-uh-see PATCH-wurk", "fr": "mosaïque de politiques publiques", "def": "A situation where rules vary widely from one state or place to another.", "ex": "After Dobbs, abortion access became a state-by-state policy patchwork."}, {"term": "state-by-state", "ipa": "/ˌsteɪt baɪ ˈsteɪt/", "pron": "stayt by stayt", "fr": "État par État", "def": "Varying from one state to another.", "ex": "Marijuana laws differ state-by-state."}, {"term": "interstate variation", "ipa": "/ˌɪntəsteɪt ˌveəriˈeɪʃən/", "pron": "IN-tuh-stayt vair-ee-AY-shuhn", "fr": "variation entre États", "def": "Differences between states in law, policy or outcomes.", "ex": "Interstate variation is a major feature of American healthcare."}, {"term": "regional disparity", "ipa": "/ˌriːdʒənəl dɪˈspærəti/", "pron": "REE-juh-nuhl di-SPAR-uh-tee", "fr": "disparité régionale", "def": "A significant difference between regions in wealth, rights, access or outcomes.", "ex": "Federalism can worsen regional disparities."}]}, {"title": "D. Funding, policy areas and state-by-state variation", "entries": [{"term": "race to the bottom", "ipa": "/ˌreɪs tə ðə ˈbɒtəm/", "pron": "rays tuh thuh BOT-uhm", "fr": "nivellement par le bas", "def": "Competition that leads governments to lower standards to attract business or avoid costs.", "ex": "Critics say competitive federalism can create a race to the bottom."}, {"term": "race to the top", "ipa": "/ˌreɪs tə ðə ˈtɒp/", "pron": "rays tuh thuh top", "fr": "course vers le haut", "def": "Competition that encourages higher standards or better policies.", "ex": "Federal grants can encourage a race to the top in education."}, {"term": "federal grant", "ipa": "/ˈfedərəl ɡrɑːnt/", "pron": "FED-uh-ruhl grant", "fr": "subvention fédérale", "def": "Money given by the federal government to states or local authorities.", "ex": "Federal grants help states fund transport projects."}, {"term": "block grant", "ipa": "/ˈblɒk ɡrɑːnt/", "pron": "blok grant", "fr": "dotation globale ; subvention globale", "def": "A broad federal grant that states can use with some flexibility.", "ex": "Block grants give states more discretion."}, {"term": "categorical grant", "ipa": "/ˌkætəˈɡɒrɪkəl ɡrɑːnt/", "pron": "kat-uh-GOR-i-kuhl grant", "fr": "subvention ciblée", "def": "A federal grant for a specific purpose with conditions attached.", "ex": "Categorical grants can shape state policy."}, {"term": "matching funds", "ipa": "/ˈmætʃɪŋ fʌndz/", "pron": "MATCH-ing fundz", "fr": "fonds de contrepartie", "def": "Funds provided when a state or local government contributes its own money too.", "ex": "Medicaid relies partly on matching funds."}, {"term": "federal funding", "ipa": "/ˈfedərəl ˈfʌndɪŋ/", "pron": "FED-uh-ruhl FUN-ding", "fr": "financement fédéral", "def": "Money provided by the national government.", "ex": "States rely on federal funding for many programmes."}, {"term": "conditional funding", "ipa": "/kənˈdɪʃənəl ˈfʌndɪŋ/", "pron": "kuhn-DISH-uh-nuhl FUN-ding", "fr": "financement conditionnel", "def": "Funding given only if states meet certain requirements.", "ex": "Conditional funding can pressure states to follow federal priorities."}, {"term": "Medicaid", "ipa": "/ˈmedɪkeɪd/", "pron": "MED-i-kayd", "fr": "Medicaid ; assurance santé publique pour bas revenus", "def": "A US health programme for low-income people, jointly funded by federal and state governments.", "ex": "Medicaid shows how federal and state responsibilities overlap."}, {"term": "public education", "ipa": "/ˌpʌblɪk ˌedjʊˈkeɪʃən/", "pron": "PUB-lik ej-yoo-KAY-shuhn", "fr": "enseignement public", "def": "Education provided or funded by government, mainly controlled by states and local districts in the US.", "ex": "Public education is largely governed at state and local level."}, {"term": "criminal justice", "ipa": "/ˌkrɪmɪnəl ˈdʒʌstɪs/", "pron": "KRIM-i-nuhl JUS-tis", "fr": "justice pénale", "def": "The system of police, courts and prisons dealing with crime.", "ex": "Criminal justice policy varies significantly between states."}, {"term": "environmental regulation", "ipa": "/ɪnˌvaɪrənˈmentəl ˌreɡjʊˈleɪʃən/", "pron": "in-vy-ruhn-MEN-tuhl reg-yuh-LAY-shuhn", "fr": "réglementation environnementale", "def": "Rules designed to protect the environment, made by federal or state authorities.", "ex": "Environmental regulation often involves federal-state conflict."}, {"term": "abortion law", "ipa": "/əˈbɔːʃən lɔː/", "pron": "uh-BOR-shuhn law", "fr": "droit de l’avortement ; législation sur l’avortement", "def": "Law regulating access to abortion.", "ex": "After Dobbs, abortion law became mainly a state issue."}, {"term": "gun law", "ipa": "/ˈɡʌn lɔː/", "pron": "gun law", "fr": "législation sur les armes à feu", "def": "Law regulating firearms ownership, purchase or use.", "ex": "Gun laws vary widely from state to state."}, {"term": "voting law", "ipa": "/ˈvəʊtɪŋ lɔː/", "pron": "VOH-ting law", "fr": "loi électorale ; loi sur le vote", "def": "Law regulating elections, voter registration and voting procedures.", "ex": "Voting laws have become highly contested in several states."}, {"term": "immigration enforcement", "ipa": "/ˌɪmɪˈɡreɪʃən ɪnˈfɔːsmənt/", "pron": "im-i-GRAY-shuhn in-FORSS-muhnt", "fr": "application des lois sur l’immigration", "def": "The implementation of immigration laws, usually by federal authorities.", "ex": "Immigration enforcement is mainly a federal responsibility."}, {"term": "sanctuary city", "ipa": "/ˈsæŋktʃuəri ˈsɪti/", "pron": "SANK-choo-air-ee SIT-ee", "fr": "ville sanctuaire", "def": "A city that limits cooperation with federal immigration enforcement.", "ex": "Sanctuary cities have clashed with federal immigration authorities."}, {"term": "red state", "ipa": "/ˌred ˈsteɪt/", "pron": "red stayt", "fr": "État républicain", "def": "A US state that usually votes Republican.", "ex": "Red states often adopt more conservative policies."}, {"term": "blue state", "ipa": "/ˌbluː ˈsteɪt/", "pron": "bloo stayt", "fr": "État démocrate", "def": "A US state that usually votes Democratic.", "ex": "Blue states tend to adopt more progressive social policies."}, {"term": "purple state", "ipa": "/ˌpɜːpəl ˈsteɪt/", "pron": "PUR-puhl stayt", "fr": "État politiquement partagé", "def": "A state where both Democrats and Republicans have significant support.", "ex": "Purple states often become election battlegrounds."}, {"term": "state-level policy", "ipa": "/ˌsteɪt levəl ˈpɒləsi/", "pron": "stayt LEV-uhl POL-uh-see", "fr": "politique au niveau des États", "def": "Policy made or implemented by state governments.", "ex": "State-level policy has become crucial after Supreme Court rulings."}, {"term": "federal-state conflict", "ipa": "/ˌfedərəl steɪt ˈkɒnflɪkt/", "pron": "FED-uh-ruhl stayt KON-flikt", "fr": "conflit entre État fédéral et États fédérés", "def": "A disagreement between national and state governments over power or policy.", "ex": "Federal-state conflict is common in immigration policy."}, {"term": "interstate commerce", "ipa": "/ˌɪntəsteɪt ˈkɒmɜːs/", "pron": "IN-tuh-stayt KOM-urs", "fr": "commerce entre États", "def": "Trade or economic activity between states.", "ex": "Congress can regulate interstate commerce."}, {"term": "redistricting", "ipa": "/ˌriːˈdɪstrɪktɪŋ/", "pron": "ree-DIS-trik-ting", "fr": "redécoupage électoral", "def": "The redrawing of electoral district boundaries.", "ex": "Redistricting is controlled largely at state level."}, {"term": "gerrymandering", "ipa": "/ˈdʒerimændərɪŋ/", "pron": "JER-ee-man-duh-ring", "fr": "charcutage électoral ; découpage partisan", "def": "The manipulation of electoral district boundaries for political advantage.", "ex": "Gerrymandering can distort representation."}, {"term": "ballot access", "ipa": "/ˈbælət ˈækses/", "pron": "BAL-uht AK-sess", "fr": "accès au scrutin ; accès au vote", "def": "Rules determining who can appear on the ballot or who can vote.", "ex": "Ballot access rules differ across states."}, {"term": "voter ID law", "ipa": "/ˌvəʊtər aɪ ˈdiː lɔː/", "pron": "VOH-tuhr eye-dee law", "fr": "loi exigeant une pièce d’identité pour voter", "def": "A law requiring voters to show identification before voting.", "ex": "Voter ID laws are defended as security measures and criticised as barriers to voting."}]}, {"title": "E. Electoral federalism and high-value verbs", "entries": [{"term": "to expand federal power", "ipa": "/ɪkˈspænd ˈfedərəl ˈpaʊə/", "pron": "ik-SPAND FED-uh-ruhl POW-uh", "fr": "étendre le pouvoir fédéral", "def": "To increase the authority of the national government.", "ex": "The New Deal expanded federal power."}, {"term": "to limit federal authority", "ipa": "/ˈlɪmɪt ˈfedərəl ɔːˈθɒrəti/", "pron": "LIM-it FED-uh-ruhl aw-THOR-uh-tee", "fr": "limiter l’autorité fédérale", "def": "To restrict the power of the national government.", "ex": "The Court limited federal authority in the case."}, {"term": "to defend states’ rights", "ipa": "/dɪˈfend ˌsteɪts ˈraɪts/", "pron": "di-FEND stayts rites", "fr": "défendre les droits des États", "def": "To argue that states should retain significant powers.", "ex": "Conservatives often defend states’ rights."}, {"term": "to override state law", "ipa": "/ˌəʊvəˈraɪd steɪt lɔː/", "pron": "OH-vuh-ryd stayt law", "fr": "passer outre une loi d’État", "def": "For federal law or authority to take priority over state law.", "ex": "Federal law can override state law under the Supremacy Clause."}, {"term": "to challenge a federal mandate", "ipa": "/ˈtʃælɪndʒ ə ˈfedərəl ˈmændeɪt/", "pron": "CHAL-inj uh FED-uh-ruhl MAN-dayt", "fr": "contester une obligation fédérale", "def": "To legally or politically contest a federal requirement.", "ex": "Several states challenged the federal mandate in court."}, {"term": "to decentralise power", "ipa": "/diːˈsentrəlaɪz ˈpaʊə/", "pron": "dee-SEN-truh-lyz POW-uh", "fr": "décentraliser le pouvoir", "def": "To transfer power away from central government.", "ex": "Federalism decentralises power across states."}, {"term": "to centralise authority", "ipa": "/ˈsentrəlaɪz ɔːˈθɒrəti/", "pron": "SEN-truh-lyz aw-THOR-uh-tee", "fr": "centraliser l’autorité", "def": "To concentrate power in the national government.", "ex": "Crises often centralise authority."}, {"term": "to vary from state to state", "ipa": "/ˈveəri frəm steɪt tə steɪt/", "pron": "VAIR-ee frum stayt tuh stayt", "fr": "varier d’un État à l’autre", "def": "To be different in each state.", "ex": "Abortion access now varies from state to state."}, {"term": "to comply with federal law", "ipa": "/kəmˈplaɪ wɪð ˈfedərəl lɔː/", "pron": "kuhm-PLY with FED-uh-ruhl law", "fr": "se conformer à la loi fédérale", "def": "To follow or obey federal law.", "ex": "States must comply with federal law."}, {"term": "to resist federal intervention", "ipa": "/rɪˈzɪst ˈfedərəl ˌɪntəˈvenʃən/", "pron": "ri-ZIST FED-uh-ruhl in-tuh-VEN-shuhn", "fr": "résister à l’intervention fédérale", "def": "To oppose action by the national government.", "ex": "Some governors resisted federal intervention."}, {"term": "to create a policy patchwork", "ipa": "/kriˈeɪt ə ˈpɒləsi ˈpætʃwɜːk/", "pron": "kree-AYT uh POL-uh-see PATCH-wurk", "fr": "créer une mosaïque de politiques publiques", "def": "To produce uneven laws or rules across different states.", "ex": "The ruling created a policy patchwork across the country."}]}]}, {"id": "p2c16", "part": 2, "chapter": 16, "title": "Race Relations", "file": "cpge_vocab_part2_chapter16_race_relations_premium.html", "count": 112, "sections": [{"title": "A. Core vocabulary: race, identity and discrimination", "entries": [{"term": "race relations", "ipa": "/ˈreɪs rɪˌleɪʃənz/", "pron": "rays ri-LAY-shuhnz", "fr": "relations raciales", "def": "The relationships, tensions and inequalities between racial groups in society.", "ex": "Race relations remain a central issue in American politics."}, {"term": "racial inequality", "ipa": "/ˌreɪʃəl ˌɪnɪˈkwɒləti/", "pron": "RAY-shuhl in-i-KWOL-uh-tee", "fr": "inégalité raciale", "def": "Unequal treatment or outcomes between racial groups.", "ex": "Racial inequality can be seen in housing, education, healthcare and criminal justice."}, {"term": "racial discrimination", "ipa": "/ˌreɪʃəl dɪˌskrɪmɪˈneɪʃən/", "pron": "RAY-shuhl dis-krim-i-NAY-shuhn", "fr": "discrimination raciale", "def": "Unfair treatment of people because of their race or ethnicity.", "ex": "The lawsuit alleged racial discrimination in hiring."}, {"term": "racism", "ipa": "/ˈreɪsɪzəm/", "pron": "RAY-siz-uhm", "fr": "racisme", "def": "Beliefs, practices or systems that treat people unfairly because of race.", "ex": "Racism can be individual, institutional or structural."}, {"term": "systemic racism", "ipa": "/sɪˌstemɪk ˈreɪsɪzəm/", "pron": "sis-TEM-ik RAY-siz-uhm", "fr": "racisme systémique", "def": "Racism embedded in institutions, policies and social structures.", "ex": "Activists argue that systemic racism shapes policing and housing."}, {"term": "structural racism", "ipa": "/ˌstrʌktʃərəl ˈreɪsɪzəm/", "pron": "STRUK-chuh-ruhl RAY-siz-uhm", "fr": "racisme structurel", "def": "Racism produced by long-term social, economic and political structures.", "ex": "Structural racism can persist even without explicit racist laws."}, {"term": "institutional racism", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈreɪsɪzəm/", "pron": "in-sti-TOO-shuh-nuhl RAY-siz-uhm", "fr": "racisme institutionnel", "def": "Racist outcomes produced by the policies or practices of institutions.", "ex": "The report accused the police department of institutional racism."}, {"term": "racial bias", "ipa": "/ˌreɪʃəl ˈbaɪəs/", "pron": "RAY-shuhl BY-uhs", "fr": "préjugé racial ; biais racial", "def": "A prejudice or unfair tendency affecting judgement about racial groups.", "ex": "Racial bias can influence sentencing decisions."}, {"term": "implicit bias", "ipa": "/ɪmˌplɪsɪt ˈbaɪəs/", "pron": "im-PLIS-it BY-uhs", "fr": "biais implicite", "def": "Unconscious attitudes or stereotypes that affect behaviour or decisions.", "ex": "Implicit bias training is used in some workplaces."}, {"term": "racial prejudice", "ipa": "/ˌreɪʃəl ˈpredʒədɪs/", "pron": "RAY-shuhl PREJ-uh-dis", "fr": "préjugé racial", "def": "A negative judgement or attitude towards people because of their race.", "ex": "Racial prejudice has often been reinforced by stereotypes."}, {"term": "stereotype", "ipa": "/ˈsteriətaɪp/", "pron": "STAIR-ee-uh-type", "fr": "stéréotype", "def": "A fixed and oversimplified idea about a group of people.", "ex": "Media representation can reinforce racial stereotypes."}, {"term": "minority group", "ipa": "/maɪˈnɒrəti ɡruːp/", "pron": "my-NOR-uh-tee group", "fr": "groupe minoritaire ; minorité", "def": "A group that is smaller in number or less powerful than the dominant group.", "ex": "Minority groups have often faced discrimination in the United States."}, {"term": "ethnic minority", "ipa": "/ˌeθnɪk maɪˈnɒrəti/", "pron": "ETH-nik my-NOR-uh-tee", "fr": "minorité ethnique", "def": "A group with a shared cultural, national or ethnic identity that differs from the majority.", "ex": "Ethnic minorities are often underrepresented in political institutions."}, {"term": "people of colour", "ipa": "/ˌpiːpəl əv ˈkʌlə/", "pron": "PEE-puhl ov KUL-uh", "fr": "personnes racisées ; personnes non blanches", "def": "A broad term for people who are not white, especially in discussions of racism and inequality.", "ex": "People of colour are disproportionately affected by some policing practices."}, {"term": "African American", "ipa": "/ˌæfrɪkən əˈmerɪkən/", "pron": "AF-ri-kuhn uh-MER-i-kuhn", "fr": "Afro-Américain ; Afro-Américaine", "def": "An American person with African ancestry, especially descended from enslaved Africans in the United States.", "ex": "African American history is central to understanding the United States."}, {"term": "Black American", "ipa": "/ˌblæk əˈmerɪkən/", "pron": "blak uh-MER-i-kuhn", "fr": "Américain noir ; Américaine noire", "def": "An American person identified as Black.", "ex": "Black Americans have played a major role in the struggle for civil rights."}, {"term": "Latino", "ipa": "/ləˈtiːnəʊ/", "pron": "luh-TEE-noh", "fr": "Latino", "def": "A person in the US with Latin American origin or ancestry, especially male or used generically.", "ex": "Latino voters are a diverse and growing electorate."}, {"term": "Latina", "ipa": "/ləˈtiːnə/", "pron": "luh-TEE-nuh", "fr": "Latina", "def": "A woman or girl in the US with Latin American origin or ancestry.", "ex": "Latina activists campaigned for immigration reform."}, {"term": "Hispanic", "ipa": "/hɪˈspænɪk/", "pron": "his-PAN-ik", "fr": "Hispanique", "def": "A person with Spanish-speaking origin or ancestry.", "ex": "The term Hispanic refers mainly to language background."}, {"term": "Native American", "ipa": "/ˌneɪtɪv əˈmerɪkən/", "pron": "NAY-tiv uh-MER-i-kuhn", "fr": "Amérindien ; Autochtone américain", "def": "A member of one of the Indigenous peoples of the United States.", "ex": "Native American communities continue to fight for land and sovereignty rights."}, {"term": "Indigenous peoples", "ipa": "/ɪnˌdɪdʒənəs ˈpiːpəlz/", "pron": "in-DIJ-uh-nuhs PEE-puhlz", "fr": "peuples autochtones", "def": "The original peoples of a territory before colonisation.", "ex": "Indigenous peoples have faced dispossession and cultural erasure."}, {"term": "Asian American", "ipa": "/ˌeɪʒən əˈmerɪkən/", "pron": "AY-zhuhn uh-MER-i-kuhn", "fr": "Américain d’origine asiatique", "def": "An American person with Asian origin or ancestry.", "ex": "Asian Americans have faced both stereotypes and anti-Asian racism."}, {"term": "white Americans", "ipa": "/ˌwaɪt əˈmerɪkənz/", "pron": "white uh-MER-i-kuhnz", "fr": "Américains blancs", "def": "Americans socially identified as white.", "ex": "White Americans remain the largest racial group in the United States."}, {"term": "racial identity", "ipa": "/ˌreɪʃəl aɪˈdentəti/", "pron": "RAY-shuhl eye-DEN-tuh-tee", "fr": "identité raciale", "def": "A person’s or group’s identity in relation to socially defined race.", "ex": "Racial identity can shape political experience and social belonging."}, {"term": "ethnicity", "ipa": "/eθˈnɪsəti/", "pron": "eth-NIS-uh-tee", "fr": "ethnicité ; origine ethnique", "def": "Shared cultural background, ancestry, language or traditions.", "ex": "Ethnicity is not the same as race, though the two often overlap."}, {"term": "segregation", "ipa": "/ˌseɡrɪˈɡeɪʃən/", "pron": "seg-ri-GAY-shuhn", "fr": "ségrégation", "def": "The enforced separation of racial groups in schools, housing or public spaces.", "ex": "Segregation was legally enforced in the American South."}]}, {"title": "B. Historical background: slavery, segregation and civil rights", "entries": [{"term": "racial segregation", "ipa": "/ˌreɪʃəl ˌseɡrɪˈɡeɪʃən/", "pron": "RAY-shuhl seg-ri-GAY-shuhn", "fr": "ségrégation raciale", "def": "The separation of people based on race.", "ex": "Racial segregation shaped housing and education for generations."}, {"term": "Jim Crow laws", "ipa": "/ˌdʒɪm ˈkrəʊ lɔːz/", "pron": "jim kroh lawz", "fr": "lois Jim Crow", "def": "State and local laws that enforced racial segregation in the American South.", "ex": "Jim Crow laws denied Black Americans equal citizenship."}, {"term": "slavery", "ipa": "/ˈsleɪvəri/", "pron": "SLAY-vuh-ree", "fr": "esclavage", "def": "A system in which people are treated as property and forced to work without freedom.", "ex": "The legacy of slavery continues to shape racial inequality."}, {"term": "enslavement", "ipa": "/ɪnˈsleɪvmənt/", "pron": "in-SLAYV-muhnt", "fr": "mise en esclavage ; esclavage", "def": "The act or condition of being made a slave.", "ex": "The enslavement of Africans was foundational to the US economy."}, {"term": "abolition", "ipa": "/ˌæbəˈlɪʃən/", "pron": "ab-uh-LISH-uhn", "fr": "abolition", "def": "The ending of slavery or another institution by law.", "ex": "Abolition did not immediately bring racial equality."}, {"term": "abolitionist", "ipa": "/ˌæbəˈlɪʃənɪst/", "pron": "ab-uh-LISH-uhn-ist", "fr": "abolitionniste", "def": "A person who campaigned to end slavery.", "ex": "Abolitionists fought against slavery before the Civil War."}, {"term": "Civil War", "ipa": "/ˌsɪvəl ˈwɔː/", "pron": "SIV-uhl war", "fr": "guerre de Sécession", "def": "The 1861–1865 war between the Union and the Confederacy over slavery, secession and federal authority.", "ex": "The Civil War ended slavery but not racism."}, {"term": "Reconstruction", "ipa": "/ˌriːkənˈstrʌkʃən/", "pron": "ree-kuhn-STRUK-shuhn", "fr": "Reconstruction", "def": "The period after the Civil War when the US tried to rebuild the South and define the rights of formerly enslaved people.", "ex": "Reconstruction briefly expanded Black political rights."}, {"term": "sharecropping", "ipa": "/ˈʃeəkrɒpɪŋ/", "pron": "SHAIR-krop-ing", "fr": "métayage", "def": "A farming system in which tenants worked land in exchange for a share of crops, often trapping Black farmers in debt.", "ex": "Sharecropping replaced slavery with economic dependency for many families."}, {"term": "lynching", "ipa": "/ˈlɪntʃɪŋ/", "pron": "LIN-ching", "fr": "lynchage", "def": "The illegal killing of someone by a mob, often used as racial terror against Black Americans.", "ex": "Lynching was used to intimidate Black communities."}, {"term": "racial terror", "ipa": "/ˌreɪʃəl ˈterə/", "pron": "RAY-shuhl TERR-uh", "fr": "terreur raciale", "def": "Violence and intimidation used to control racial groups.", "ex": "Racial terror enforced white supremacy after Reconstruction."}, {"term": "white supremacy", "ipa": "/ˌwaɪt səˈpreməsi/", "pron": "white suh-PREM-uh-see", "fr": "suprémacisme blanc", "def": "The racist belief or system that white people should dominate other racial groups.", "ex": "White supremacy was built into many laws and institutions."}, {"term": "civil rights", "ipa": "/ˌsɪvəl ˈraɪts/", "pron": "SIV-uhl rites", "fr": "droits civiques", "def": "Rights protecting people from discrimination and guaranteeing equal treatment under the law.", "ex": "Civil rights are central to American constitutional history."}, {"term": "civil rights movement", "ipa": "/ˌsɪvəl ˈraɪts ˌmuːvmənt/", "pron": "SIV-uhl rites MOOV-muhnt", "fr": "mouvement des droits civiques", "def": "The movement, especially in the 1950s and 1960s, that fought racial segregation and discrimination.", "ex": "The civil rights movement transformed American law and society."}, {"term": "civil rights activist", "ipa": "/ˌsɪvəl ˈraɪts ˈæktɪvɪst/", "pron": "SIV-uhl rites AK-ti-vist", "fr": "militant des droits civiques", "def": "A person who campaigns for equal civil rights.", "ex": "Civil rights activists organised boycotts, marches and legal challenges."}, {"term": "desegregation", "ipa": "/ˌdiːseɡrɪˈɡeɪʃən/", "pron": "dee-seg-ri-GAY-shuhn", "fr": "déségrégation", "def": "The process of ending racial segregation.", "ex": "School desegregation faced fierce resistance."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The inclusion of different racial groups in the same schools, workplaces or public spaces.", "ex": "Integration was a major goal of civil rights activists."}, {"term": "Brown v. Board of Education", "ipa": "/braʊn vɜːsəs bɔːd əv ˌedjʊˈkeɪʃən/", "pron": "brown VUR-suhs board ov ej-yoo-KAY-shuhn", "fr": "Brown v. Board of Education", "def": "The 1954 Supreme Court ruling that declared racial segregation in public schools unconstitutional.", "ex": "Brown v. Board of Education overturned school segregation."}, {"term": "Montgomery bus boycott", "ipa": "/mɒntˈɡʌməri bʌs ˈbɔɪkɒt/", "pron": "mont-GUM-uh-ree bus BOY-kot", "fr": "boycott des bus de Montgomery", "def": "A 1955–1956 protest against bus segregation in Montgomery, Alabama.", "ex": "The Montgomery bus boycott became a landmark civil rights protest."}, {"term": "March on Washington", "ipa": "/ˌmɑːtʃ ɒn ˈwɒʃɪŋtən/", "pron": "march on WOSH-ing-tuhn", "fr": "Marche sur Washington", "def": "The 1963 civil rights demonstration where Martin Luther King Jr. delivered his famous speech.", "ex": "The March on Washington demanded jobs and freedom."}, {"term": "Civil Rights Act", "ipa": "/ˌsɪvəl ˈraɪts ækt/", "pron": "SIV-uhl rites akt", "fr": "Civil Rights Act ; loi sur les droits civiques", "def": "The 1964 law banning discrimination in public places, employment and federally funded programmes.", "ex": "The Civil Rights Act outlawed many forms of segregation."}, {"term": "Voting Rights Act", "ipa": "/ˈvəʊtɪŋ raɪts ækt/", "pron": "VOH-ting rites akt", "fr": "Voting Rights Act ; loi sur le droit de vote", "def": "The 1965 law designed to protect minority voting rights.", "ex": "The Voting Rights Act targeted discriminatory voting practices."}, {"term": "equal protection", "ipa": "/ˌiːkwəl prəˈtekʃən/", "pron": "EE-kwuhl pruh-TEK-shuhn", "fr": "égale protection de la loi", "def": "The constitutional principle that the law must protect people equally.", "ex": "Equal protection is central to civil rights cases."}]}, {"title": "C. Policing, criminal justice and racial justice", "entries": [{"term": "Fourteenth Amendment", "ipa": "/ˌfɔːˈtiːnθ əˈmendmənt/", "pron": "for-TEENTH uh-MEND-muhnt", "fr": "Quatorzième amendement", "def": "The constitutional amendment guaranteeing citizenship, due process and equal protection.", "ex": "The Fourteenth Amendment underpins many civil rights decisions."}, {"term": "Fifteenth Amendment", "ipa": "/ˌfɪfˈtiːnθ əˈmendmənt/", "pron": "fif-TEENTH uh-MEND-muhnt", "fr": "Quinzième amendement", "def": "The amendment prohibiting denial of the vote based on race.", "ex": "The Fifteenth Amendment aimed to protect Black male suffrage."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to increase opportunities for groups historically discriminated against.", "ex": "Affirmative action remains controversial in university admissions."}, {"term": "racial justice", "ipa": "/ˌreɪʃəl ˈdʒʌstɪs/", "pron": "RAY-shuhl JUS-tis", "fr": "justice raciale", "def": "Fair treatment and equal outcomes across racial groups.", "ex": "Protesters demanded racial justice after the killing."}, {"term": "social justice", "ipa": "/ˌsəʊʃəl ˈdʒʌstɪs/", "pron": "SOH-shuhl JUS-tis", "fr": "justice sociale", "def": "The pursuit of fairness in social, economic and political life.", "ex": "Social justice movements often address race, class and gender together."}, {"term": "Black Lives Matter", "ipa": "/ˌblæk laɪvz ˈmætə/", "pron": "black lives MAT-uh", "fr": "Black Lives Matter ; les vies noires comptent", "def": "A movement protesting anti-Black racism and police violence.", "ex": "Black Lives Matter gained global attention after George Floyd’s murder."}, {"term": "BLM", "ipa": "/ˌbiː el ˈem/", "pron": "bee el em", "fr": "BLM", "def": "Abbreviation for Black Lives Matter.", "ex": "BLM protests called for police accountability."}, {"term": "police brutality", "ipa": "/pəˈliːs bruːˈtæləti/", "pron": "puh-LEESS broo-TAL-uh-tee", "fr": "violences policières", "def": "Excessive or violent force used by police officers.", "ex": "Police brutality has sparked nationwide protests."}, {"term": "police accountability", "ipa": "/pəˈliːs əˌkaʊntəˈbɪləti/", "pron": "puh-LEESS uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité de la police ; redevabilité policière", "def": "The principle that police officers and departments should answer for misconduct.", "ex": "Campaigners demanded stronger police accountability."}, {"term": "racial profiling", "ipa": "/ˌreɪʃəl ˈprəʊfaɪlɪŋ/", "pron": "RAY-shuhl PROH-fy-ling", "fr": "profilage racial", "def": "Police or security targeting based on race rather than evidence.", "ex": "Racial profiling can damage trust between communities and police."}, {"term": "stop-and-frisk", "ipa": "/ˌstɒp ən ˈfrɪsk/", "pron": "stop uhn frisk", "fr": "contrôle et fouille ; stop-and-frisk", "def": "A policing practice involving stopping and searching people in public, often criticised for racial bias.", "ex": "Stop-and-frisk disproportionately affected Black and Latino communities."}, {"term": "mass incarceration", "ipa": "/ˌmæs ɪnˌkɑːsəˈreɪʃən/", "pron": "mass in-kar-suh-RAY-shuhn", "fr": "incarcération de masse", "def": "The large-scale imprisonment of people, especially in the United States.", "ex": "Mass incarceration has disproportionately affected Black Americans."}]}, {"title": "D. Socio-economic inequalities and voting rights", "entries": [{"term": "criminal justice reform", "ipa": "/ˌkrɪmɪnəl ˈdʒʌstɪs rɪˌfɔːm/", "pron": "KRIM-i-nuhl JUS-tis ri-FORM", "fr": "réforme de la justice pénale", "def": "Changes aimed at making the policing, courts and prison system fairer.", "ex": "Criminal justice reform became a bipartisan issue in some states."}, {"term": "sentencing disparity", "ipa": "/ˈsentənsɪŋ dɪˈspærəti/", "pron": "SEN-tuhn-sing di-SPAR-uh-tee", "fr": "disparité des peines", "def": "Unequal punishment for similar crimes, often affecting racial groups differently.", "ex": "Sentencing disparities have contributed to racial inequality."}, {"term": "school-to-prison pipeline", "ipa": "/ˌskuːl tə ˈprɪzən ˈpaɪplaɪn/", "pron": "school tuh PRIZ-uhn PYPE-line", "fr": "pipeline école-prison", "def": "The process by which harsh school discipline pushes students, especially minority students, into the criminal justice system.", "ex": "The school-to-prison pipeline is a major concern for civil rights groups."}, {"term": "wealth gap", "ipa": "/ˈwelθ ɡæp/", "pron": "welth gap", "fr": "écart de patrimoine", "def": "The difference in wealth between groups.", "ex": "The racial wealth gap reflects generations of unequal opportunity."}, {"term": "racial wealth gap", "ipa": "/ˌreɪʃəl ˈwelθ ɡæp/", "pron": "RAY-shuhl welth gap", "fr": "écart de patrimoine racial", "def": "The difference in accumulated wealth between racial groups.", "ex": "The racial wealth gap is much larger than the income gap."}, {"term": "income gap", "ipa": "/ˈɪnkʌm ɡæp/", "pron": "IN-kum gap", "fr": "écart de revenus", "def": "The difference in income between groups.", "ex": "The income gap affects access to housing and education."}, {"term": "housing discrimination", "ipa": "/ˈhaʊzɪŋ dɪˌskrɪmɪˈneɪʃən/", "pron": "HOW-zing dis-krim-i-NAY-shuhn", "fr": "discrimination au logement", "def": "Unfair treatment in housing based on race or other protected characteristics.", "ex": "Housing discrimination helped create segregated neighbourhoods."}, {"term": "redlining", "ipa": "/ˈredlaɪnɪŋ/", "pron": "RED-line-ing", "fr": "redlining ; discrimination bancaire territoriale", "def": "A discriminatory practice denying loans or services to neighbourhoods based on racial composition.", "ex": "Redlining prevented many Black families from building wealth."}, {"term": "residential segregation", "ipa": "/ˌrezɪˈdenʃəl ˌseɡrɪˈɡeɪʃən/", "pron": "rez-i-DEN-shuhl seg-ri-GAY-shuhn", "fr": "ségrégation résidentielle", "def": "The separation of racial groups into different neighbourhoods.", "ex": "Residential segregation affects school funding and health outcomes."}, {"term": "food desert", "ipa": "/ˈfuːd ˌdezət/", "pron": "food DEZ-uht", "fr": "désert alimentaire", "def": "An area with limited access to affordable and healthy food.", "ex": "Food deserts are often found in low-income minority neighbourhoods."}, {"term": "educational inequality", "ipa": "/ˌedjʊˈkeɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "ej-yoo-KAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité éducative", "def": "Unequal access to quality education.", "ex": "Educational inequality often reflects housing segregation."}, {"term": "school funding", "ipa": "/ˈskuːl ˌfʌndɪŋ/", "pron": "school FUN-ding", "fr": "financement des écoles", "def": "Money available to schools, often linked to local taxes in the US.", "ex": "School funding varies widely between districts."}, {"term": "achievement gap", "ipa": "/əˈtʃiːvmənt ɡæp/", "pron": "uh-CHEEV-muhnt gap", "fr": "écart de réussite scolaire", "def": "Differences in educational performance between groups.", "ex": "The achievement gap is linked to poverty and unequal resources."}, {"term": "health disparities", "ipa": "/ˈhelθ dɪˌspærətiz/", "pron": "helth di-SPAR-uh-teez", "fr": "disparités de santé", "def": "Differences in health outcomes between groups.", "ex": "Health disparities were exposed during the pandemic."}, {"term": "environmental racism", "ipa": "/ɪnˌvaɪrənˈmentəl ˈreɪsɪzəm/", "pron": "in-vy-ruhn-MEN-tuhl RAY-siz-uhm", "fr": "racisme environnemental", "def": "Environmental harm that disproportionately affects racial minorities.", "ex": "Environmental racism places polluting industries near minority communities."}, {"term": "voter suppression", "ipa": "/ˈvəʊtə səˌpreʃən/", "pron": "VOH-tuh suh-PRESH-uhn", "fr": "entraves au vote ; suppression du vote", "def": "Actions or laws that make it harder for certain groups to vote.", "ex": "Civil rights groups denounced the law as voter suppression."}, {"term": "voting access", "ipa": "/ˈvəʊtɪŋ ˈækses/", "pron": "VOH-ting AK-sess", "fr": "accès au vote", "def": "The ease with which citizens can vote.", "ex": "Voting access varies significantly from state to state."}, {"term": "voter ID law", "ipa": "/ˌvəʊtər aɪ ˈdiː lɔː/", "pron": "VOH-tuhr eye-dee law", "fr": "loi exigeant une pièce d’identité pour voter", "def": "A law requiring voters to show identification before voting.", "ex": "Critics say voter ID laws can suppress minority turnout."}, {"term": "felony disenfranchisement", "ipa": "/ˈfeləni ˌdɪsɪnˈfræntʃaɪzmənt/", "pron": "FEL-uh-nee dis-in-FRAN-chyz-muhnt", "fr": "privation du droit de vote des personnes condamnées", "def": "Laws that restrict voting rights for people convicted of felonies.", "ex": "Felony disenfranchisement disproportionately affects Black Americans."}, {"term": "gerrymandering", "ipa": "/ˈdʒerimændərɪŋ/", "pron": "JER-ee-man-duh-ring", "fr": "charcutage électoral ; découpage partisan", "def": "Manipulating electoral district boundaries for political advantage.", "ex": "Racial gerrymandering can weaken minority representation."}, {"term": "minority representation", "ipa": "/maɪˈnɒrəti ˌreprɪzenˈteɪʃən/", "pron": "my-NOR-uh-tee rep-ri-zen-TAY-shuhn", "fr": "représentation des minorités", "def": "The presence and political voice of minority groups in institutions.", "ex": "Minority representation has increased but remains uneven."}]}, {"title": "E. Culture wars, policy debates and high-value verbs", "entries": [{"term": "descriptive representation", "ipa": "/dɪˈskrɪptɪv ˌreprɪzenˈteɪʃən/", "pron": "di-SKRIP-tiv rep-ri-zen-TAY-shuhn", "fr": "représentation descriptive", "def": "Representation in which elected officials share characteristics with the people they represent.", "ex": "Descriptive representation can increase trust in institutions."}, {"term": "substantive representation", "ipa": "/ˈsʌbstəntɪv ˌreprɪzenˈteɪʃən/", "pron": "SUB-stuhn-tiv rep-ri-zen-TAY-shuhn", "fr": "représentation substantielle", "def": "Representation based on defending a group’s interests, regardless of the representative’s identity.", "ex": "Substantive representation matters as much as symbolic diversity."}, {"term": "identity politics", "ipa": "/aɪˈdentəti ˈpɒlɪtɪks/", "pron": "eye-DEN-tuh-tee POL-i-tiks", "fr": "politique identitaire", "def": "Politics based on the interests and experiences of identity groups.", "ex": "Debates over race are often framed as identity politics."}, {"term": "woke", "ipa": "/wəʊk/", "pron": "wohk", "fr": "woke ; conscient des injustices sociales", "def": "Originally meaning alert to racial injustice; now often used politically and sometimes pejoratively.", "ex": "The term woke has become a culture-war label."}, {"term": "critical race theory", "ipa": "/ˌkrɪtɪkəl ˈreɪs ˈθɪəri/", "pron": "KRIT-i-kuhl rays THEE-uh-ree", "fr": "théorie critique de la race", "def": "An academic framework examining how law and institutions reproduce racial inequality.", "ex": "Critical race theory became a major conservative target in education debates."}, {"term": "culture-war issue", "ipa": "/ˈkʌltʃə wɔː ˈɪʃuː/", "pron": "KUL-chuh war ISH-oo", "fr": "enjeu de guerre culturelle", "def": "A divisive issue linked to values, identity or national history.", "ex": "Race education has become a culture-war issue."}, {"term": "diversity", "ipa": "/daɪˈvɜːsəti/", "pron": "dy-VUR-suh-tee", "fr": "diversité", "def": "The presence of different groups in a society or institution.", "ex": "Universities often defend diversity as an educational value."}, {"term": "equity", "ipa": "/ˈekwəti/", "pron": "EK-wuh-tee", "fr": "équité", "def": "Fairness that may require addressing unequal starting points or barriers.", "ex": "Equity policies aim to reduce structural disadvantages."}, {"term": "inclusion", "ipa": "/ɪnˈkluːʒən/", "pron": "in-KLOO-zhuhn", "fr": "inclusion", "def": "The practice of ensuring that people feel accepted and able to participate fully.", "ex": "Inclusion goes beyond numerical diversity."}, {"term": "DEI", "ipa": "/ˌdiː iː ˈaɪ/", "pron": "dee ee eye", "fr": "DEI ; diversité, équité et inclusion", "def": "Diversity, Equity and Inclusion policies or programmes.", "ex": "DEI programmes have become politically controversial."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "réaction hostile ; retour de bâton", "def": "A strong negative reaction against social or political change.", "ex": "The civil rights gains of the 1960s triggered a political backlash."}, {"term": "racial backlash", "ipa": "/ˌreɪʃəl ˈbæklæʃ/", "pron": "RAY-shuhl BAK-lash", "fr": "réaction raciale hostile", "def": "A negative political reaction against racial progress or minority rights.", "ex": "Some analysts link voter behaviour to racial backlash."}, {"term": "white grievance", "ipa": "/ˌwaɪt ˈɡriːvəns/", "pron": "white GREE-vuhns", "fr": "ressentiment blanc", "def": "A sense among some white people that they are being unfairly disadvantaged.", "ex": "Politicians sometimes exploit white grievance."}, {"term": "colour-blindness", "ipa": "/ˈkʌlə blaɪndnəs/", "pron": "KUL-uh BLYND-nuhs", "fr": "indifférence à la race ; approche color-blind", "def": "The idea that race should not be considered in law or policy.", "ex": "Critics argue that colour-blindness can ignore structural inequality."}, {"term": "race-conscious policy", "ipa": "/ˈreɪs ˌkɒnʃəs ˈpɒləsi/", "pron": "rays KON-shuhs POL-uh-see", "fr": "politique tenant compte de la race", "def": "A policy that explicitly considers race to address inequality.", "ex": "Affirmative action is a race-conscious policy."}, {"term": "reparations", "ipa": "/ˌrepəˈreɪʃənz/", "pron": "rep-uh-RAY-shuhnz", "fr": "réparations", "def": "Compensation or measures intended to repair historical injustice, especially slavery and discrimination.", "ex": "Reparations remain a controversial proposal in US politics."}, {"term": "to discriminate against", "ipa": "/dɪˈskrɪmɪneɪt əˈɡenst/", "pron": "dis-KRIM-i-nayt uh-GENST", "fr": "discriminer", "def": "To treat someone unfairly because of race, gender, religion or another characteristic.", "ex": "The company was accused of discriminating against minority applicants."}, {"term": "to desegregate schools", "ipa": "/ˌdiːˈseɡrɪɡeɪt ˈskuːlz/", "pron": "dee-SEG-ri-gayt schoolz", "fr": "déségréguer les écoles", "def": "To end racial segregation in schools.", "ex": "Federal courts ordered districts to desegregate schools."}, {"term": "to fight discrimination", "ipa": "/faɪt dɪˌskrɪmɪˈneɪʃən/", "pron": "fyte dis-krim-i-NAY-shuhn", "fr": "lutter contre la discrimination", "def": "To oppose unfair treatment based on identity.", "ex": "Civil rights organisations fight discrimination in courts."}, {"term": "to challenge segregation", "ipa": "/ˈtʃælɪndʒ ˌseɡrɪˈɡeɪʃən/", "pron": "CHAL-inj seg-ri-GAY-shuhn", "fr": "contester la ségrégation", "def": "To oppose racial separation through activism, law or protest.", "ex": "Activists challenged segregation through boycotts and lawsuits."}, {"term": "to demand equal rights", "ipa": "/dɪˈmɑːnd ˌiːkwəl ˈraɪts/", "pron": "di-MAND EE-kwuhl rites", "fr": "exiger l’égalité des droits", "def": "To call for the same legal and social rights for all groups.", "ex": "Marchers demanded equal rights and voting access."}, {"term": "to address racial inequality", "ipa": "/əˈdres ˌreɪʃəl ˌɪnɪˈkwɒləti/", "pron": "uh-DRESS RAY-shuhl in-i-KWOL-uh-tee", "fr": "s’attaquer aux inégalités raciales", "def": "To take action to reduce racial inequality.", "ex": "The policy aims to address racial inequality in education."}, {"term": "to close the racial wealth gap", "ipa": "/kləʊz ðə ˌreɪʃəl ˈwelθ ɡæp/", "pron": "klohz thuh RAY-shuhl welth gap", "fr": "réduire l’écart de patrimoine racial", "def": "To reduce wealth differences between racial groups.", "ex": "Housing reform could help close the racial wealth gap."}, {"term": "to protest police brutality", "ipa": "/prəˈtest pəˈliːs bruːˈtæləti/", "pron": "pruh-TEST puh-LEESS broo-TAL-uh-tee", "fr": "protester contre les violences policières", "def": "To demonstrate against violent or excessive police force.", "ex": "Thousands took to the streets to protest police brutality."}, {"term": "to reform policing", "ipa": "/rɪˈfɔːm pəˈliːsɪŋ/", "pron": "ri-FORM puh-LEESS-ing", "fr": "réformer la police", "def": "To change police practices and institutions.", "ex": "Activists called on lawmakers to reform policing."}, {"term": "to suppress minority votes", "ipa": "/səˈpres maɪˈnɒrəti vəʊts/", "pron": "suh-PRESS my-NOR-uh-tee vohts", "fr": "entraver le vote des minorités", "def": "To make it harder for minority voters to vote.", "ex": "Critics said the law would suppress minority votes."}, {"term": "to expand voting access", "ipa": "/ɪkˈspænd ˈvəʊtɪŋ ˈækses/", "pron": "ik-SPAND VOH-ting AK-sess", "fr": "élargir l’accès au vote", "def": "To make voting easier or more accessible.", "ex": "The bill sought to expand voting access."}, {"term": "to reckon with the past", "ipa": "/ˈrekən wɪð ðə ˈpɑːst/", "pron": "REK-uhn with thuh past", "fr": "faire face au passé", "def": "To confront and examine historical injustice honestly.", "ex": "The country continues to reckon with the past of slavery and segregation."}, {"term": "to perpetuate inequality", "ipa": "/pəˈpetʃueɪt ˌɪnɪˈkwɒləti/", "pron": "puh-PET-choo-ayt in-i-KWOL-uh-tee", "fr": "perpétuer les inégalités", "def": "To cause inequality to continue.", "ex": "Unequal school funding can perpetuate inequality."}, {"term": "to dismantle systemic racism", "ipa": "/dɪsˈmæntəl sɪˌstemɪk ˈreɪsɪzəm/", "pron": "dis-MAN-tuhl sis-TEM-ik RAY-siz-uhm", "fr": "démanteler le racisme systémique", "def": "To remove structures and practices that maintain racial inequality.", "ex": "Protesters demanded reforms to dismantle systemic racism."}]}]}, {"id": "p2c17", "part": 2, "chapter": 17, "title": "Immigration", "file": "cpge_vocab_part2_chapter17_immigration_premium.html", "count": 94, "sections": [{"title": "A. Core immigration vocabulary and legal status", "entries": [{"term": "immigration", "ipa": "/ˌɪmɪˈɡreɪʃən/", "pron": "im-i-GRAY-shuhn", "fr": "immigration", "def": "The movement of people into a country to live, work or settle there.", "ex": "Immigration has long been central to American identity and political debate."}, {"term": "immigrant", "ipa": "/ˈɪmɪɡrənt/", "pron": "IM-i-gruhnt", "fr": "immigré ; immigrée", "def": "A person who moves to another country to live there.", "ex": "Many immigrants come to the United States in search of work, safety or opportunity."}, {"term": "migrant", "ipa": "/ˈmaɪɡrənt/", "pron": "MY-gruhnt", "fr": "migrant ; migrante", "def": "A person who moves from one place to another, often for work, safety or better living conditions.", "ex": "Migrants often face dangerous journeys and uncertain legal status."}, {"term": "migration", "ipa": "/maɪˈɡreɪʃən/", "pron": "my-GRAY-shuhn", "fr": "migration", "def": "The movement of people from one place to another.", "ex": "Migration is driven by war, poverty, climate change and economic opportunity."}, {"term": "foreign-born", "ipa": "/ˌfɒrən ˈbɔːn/", "pron": "FOR-uhn born", "fr": "né à l’étranger", "def": "Born in another country.", "ex": "The foreign-born population has increased in several states."}, {"term": "first-generation immigrant", "ipa": "/ˌfɜːst dʒenəˈreɪʃən ˈɪmɪɡrənt/", "pron": "first jen-uh-RAY-shuhn IM-i-gruhnt", "fr": "immigré de première génération", "def": "A person who was born abroad and immigrated to another country.", "ex": "First-generation immigrants often face language barriers."}, {"term": "second-generation immigrant", "ipa": "/ˌsekənd dʒenəˈreɪʃən ˈɪmɪɡrənt/", "pron": "SEK-uhnd jen-uh-RAY-shuhn IM-i-gruhnt", "fr": "enfant d’immigrés ; immigré de deuxième génération", "def": "A person born in a country to immigrant parents.", "ex": "Second-generation immigrants often navigate two cultural identities."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community of people living outside their ancestral homeland.", "ex": "The Mexican diaspora has strong cultural and economic ties with Mexico."}, {"term": "border", "ipa": "/ˈbɔːdə/", "pron": "BOR-duh", "fr": "frontière", "def": "The line separating two countries or political territories.", "ex": "The US-Mexico border is a major focus of immigration policy."}, {"term": "border security", "ipa": "/ˈbɔːdə sɪˌkjʊərəti/", "pron": "BOR-duh si-KYOOR-uh-tee", "fr": "sécurité aux frontières", "def": "Measures used to control and monitor a country’s borders.", "ex": "Border security is a key demand of many conservative politicians."}, {"term": "border control", "ipa": "/ˈbɔːdə kənˌtrəʊl/", "pron": "BOR-duh kuhn-TROHL", "fr": "contrôle des frontières", "def": "The regulation of who enters and leaves a country.", "ex": "The government promised tougher border control."}, {"term": "border patrol", "ipa": "/ˈbɔːdə pəˌtrəʊl/", "pron": "BOR-duh puh-TROHL", "fr": "patrouille frontalière", "def": "Officers responsible for monitoring and policing a country’s borders.", "ex": "Border Patrol agents detained migrants near the crossing."}, {"term": "border wall", "ipa": "/ˈbɔːdə wɔːl/", "pron": "BOR-duh wall", "fr": "mur frontalier", "def": "A physical barrier built along a border to prevent unauthorised crossing.", "ex": "The border wall became a powerful political symbol."}, {"term": "border crossing", "ipa": "/ˈbɔːdə ˈkrɒsɪŋ/", "pron": "BOR-duh KROSS-ing", "fr": "poste-frontière ; point de passage", "def": "An official place where people may enter or leave a country.", "ex": "The border crossing was closed after the incident."}, {"term": "undocumented immigrant", "ipa": "/ʌnˈdɒkjʊmentɪd ˈɪmɪɡrənt/", "pron": "un-DOK-yuh-men-tid IM-i-gruhnt", "fr": "sans-papiers ; immigré en situation irrégulière", "def": "An immigrant who does not have legal authorisation to live in a country.", "ex": "Undocumented immigrants often work in low-paid and insecure jobs."}, {"term": "illegal immigrant", "ipa": "/ɪˈliːɡəl ˈɪmɪɡrənt/", "pron": "i-LEE-guhl IM-i-gruhnt", "fr": "immigré illégal ; terme controversé", "def": "A controversial term for a person living in a country without legal permission.", "ex": "The term illegal immigrant is often criticised as dehumanising."}, {"term": "unauthorised immigrant", "ipa": "/ʌnˈɔːθəraɪzd ˈɪmɪɡrənt/", "pron": "un-AW-thuh-ryzd IM-i-gruhnt", "fr": "immigré non autorisé ; en situation irrégulière", "def": "A person living in a country without official authorisation.", "ex": "Unauthorised immigrants may fear reporting crimes."}, {"term": "legal immigrant", "ipa": "/ˈliːɡəl ˈɪmɪɡrənt/", "pron": "LEE-guhl IM-i-gruhnt", "fr": "immigré légal ; immigré régulier", "def": "A person who has official permission to live in a country.", "ex": "Legal immigrants can often apply for permanent residency."}, {"term": "lawful permanent resident", "ipa": "/ˈlɔːfəl ˈpɜːmənənt ˈrezɪdənt/", "pron": "LAW-fuhl PUR-muh-nuhnt REZ-i-duhnt", "fr": "résident permanent légal", "def": "A non-citizen legally allowed to live permanently in the United States.", "ex": "A lawful permanent resident may later apply for citizenship."}, {"term": "green card", "ipa": "/ˈɡriːn kɑːd/", "pron": "green card", "fr": "carte verte", "def": "A document giving a non-citizen permanent resident status in the United States.", "ex": "A green card allows immigrants to live and work permanently in the US."}, {"term": "visa", "ipa": "/ˈviːzə/", "pron": "VEE-zuh", "fr": "visa", "def": "An official document allowing a person to enter, stay or work in a country for a specific purpose or period.", "ex": "Students need a visa to study in the United States."}, {"term": "work visa", "ipa": "/ˈwɜːk ˌviːzə/", "pron": "work VEE-zuh", "fr": "visa de travail", "def": "A visa allowing a person to work legally in a country.", "ex": "Many technology companies rely on skilled workers with work visas."}, {"term": "asylum", "ipa": "/əˈsaɪləm/", "pron": "uh-SY-luhm", "fr": "asile", "def": "Protection granted to someone fleeing persecution in their home country.", "ex": "The family applied for asylum after fleeing political violence."}, {"term": "asylum seeker", "ipa": "/əˈsaɪləm ˌsiːkə/", "pron": "uh-SY-luhm SEE-kuh", "fr": "demandeur d’asile", "def": "A person who has requested protection as a refugee but whose claim has not yet been decided.", "ex": "Asylum seekers often wait months or years for a decision."}, {"term": "refugee", "ipa": "/ˌrefjʊˈdʒiː/", "pron": "REF-yoo-JEE", "fr": "réfugié ; réfugiée", "def": "A person forced to leave their country because of war, persecution or violence.", "ex": "Refugees are protected under international law."}, {"term": "persecution", "ipa": "/ˌpɜːsɪˈkjuːʃən/", "pron": "pur-si-KYOO-shuhn", "fr": "persécution", "def": "Mistreatment or violence against people because of identity, beliefs or politics.", "ex": "Victims of persecution may qualify for asylum."}, {"term": "humanitarian protection", "ipa": "/hjuːˌmænɪˈteəriən prəˈtekʃən/", "pron": "hyoo-man-i-TAIR-ee-uhn pruh-TEK-shuhn", "fr": "protection humanitaire", "def": "Protection granted for humanitarian reasons to people at risk.", "ex": "Humanitarian protection is often debated during refugee crises."}, {"term": "resettlement", "ipa": "/ˌriːˈsetəlmənt/", "pron": "ree-SET-uhl-muhnt", "fr": "réinstallation", "def": "The process of moving refugees to a safe country where they can rebuild their lives.", "ex": "Refugee resettlement programmes require international cooperation."}]}, {"title": "B. Asylum, refugees and legal pathways", "entries": [{"term": "family reunification", "ipa": "/ˌfæməli riːˌjuːnɪfɪˈkeɪʃən/", "pron": "FAM-uh-lee ree-yoo-ni-fi-KAY-shuhn", "fr": "regroupement familial", "def": "The process by which family members are allowed to join relatives in another country.", "ex": "Family reunification is a major pathway for legal immigration."}, {"term": "chain migration", "ipa": "/ˈtʃeɪn maɪˌɡreɪʃən/", "pron": "chayn my-GRAY-shuhn", "fr": "migration en chaîne ; terme politisé", "def": "A politicised term for immigration through family sponsorship networks.", "ex": "Critics use the term chain migration to attack family-based immigration."}, {"term": "family-based immigration", "ipa": "/ˈfæməli beɪst ˌɪmɪˈɡreɪʃən/", "pron": "FAM-uh-lee bayst im-i-GRAY-shuhn", "fr": "immigration familiale", "def": "Immigration based on sponsorship by family members already living in the country.", "ex": "Family-based immigration has long been part of US immigration policy."}, {"term": "employment-based immigration", "ipa": "/ɪmˈplɔɪmənt beɪst ˌɪmɪˈɡreɪʃən/", "pron": "im-PLOY-muhnt bayst im-i-GRAY-shuhn", "fr": "immigration professionnelle", "def": "Immigration based on work, skills or employer sponsorship.", "ex": "Employment-based immigration is important for skilled sectors."}, {"term": "skilled worker", "ipa": "/ˌskɪld ˈwɜːkə/", "pron": "skild WUR-kuh", "fr": "travailleur qualifié", "def": "A worker with specialised training, education or expertise.", "ex": "The technology sector relies on skilled workers from abroad."}, {"term": "seasonal worker", "ipa": "/ˌsiːzənəl ˈwɜːkə/", "pron": "SEE-zuh-nuhl WUR-kuh", "fr": "travailleur saisonnier", "def": "A worker employed for a limited season, often in agriculture or tourism.", "ex": "Seasonal workers harvest crops across the country."}, {"term": "migrant labour", "ipa": "/ˈmaɪɡrənt ˈleɪbə/", "pron": "MY-gruhnt LAY-buh", "fr": "main-d’œuvre immigrée", "def": "Work done by migrants, often in sectors with labour shortages.", "ex": "Migrant labour is crucial to the US food supply chain."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˈʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A situation in which there are not enough workers for available jobs.", "ex": "Immigration can help address labour shortages."}, {"term": "remittances", "ipa": "/rɪˈmɪtənsɪz/", "pron": "ri-MIT-uhn-siz", "fr": "transferts d’argent ; remises migratoires", "def": "Money sent by migrants to family or communities in their home country.", "ex": "Remittances support families and local economies abroad."}, {"term": "naturalisation", "ipa": "/ˌnætʃərəlaɪˈzeɪʃən/", "pron": "nach-uh-ruh-ly-ZAY-shuhn", "fr": "naturalisation", "def": "The process of becoming a citizen of another country.", "ex": "Naturalisation requires meeting legal and language requirements."}, {"term": "citizenship", "ipa": "/ˈsɪtɪzənʃɪp/", "pron": "SIT-i-zuhn-ship", "fr": "citoyenneté", "def": "The legal status of being a member of a country with rights and duties.", "ex": "Citizenship gives immigrants the right to vote."}, {"term": "birthright citizenship", "ipa": "/ˌbɜːθraɪt ˈsɪtɪzənʃɪp/", "pron": "BURTH-ryt SIT-i-zuhn-ship", "fr": "citoyenneté de naissance ; droit du sol", "def": "Citizenship granted to anyone born in a country, especially under the Fourteenth Amendment in the US.", "ex": "Birthright citizenship is often debated in US immigration politics."}, {"term": "DACA", "ipa": "/ˈdækə/", "pron": "DAK-uh", "fr": "DACA", "def": "Deferred Action for Childhood Arrivals, a programme protecting some undocumented immigrants brought to the US as children.", "ex": "DACA protects many Dreamers from deportation."}, {"term": "Dreamers", "ipa": "/ˈdriːməz/", "pron": "DREE-muhz", "fr": "Dreamers ; jeunes sans-papiers arrivés enfants", "def": "Undocumented immigrants brought to the US as children, often associated with DACA.", "ex": "Dreamers grew up in the United States but lack full legal security."}, {"term": "deportation", "ipa": "/ˌdiːpɔːˈteɪʃən/", "pron": "dee-por-TAY-shuhn", "fr": "expulsion ; reconduite à la frontière", "def": "The forced removal of a non-citizen from a country.", "ex": "Deportation can separate families."}, {"term": "removal proceedings", "ipa": "/rɪˈmuːvəl prəˈsiːdɪŋz/", "pron": "ri-MOO-vuhl pruh-SEE-dingz", "fr": "procédure d’expulsion", "def": "Legal proceedings to decide whether a non-citizen should be deported.", "ex": "The immigrant faced removal proceedings."}, {"term": "detention centre", "ipa": "/dɪˈtenʃən ˌsentə/", "pron": "di-TEN-shuhn SEN-tuh", "fr": "centre de rétention ; centre de détention", "def": "A facility where migrants or asylum seekers are held by authorities.", "ex": "Conditions in detention centres have been criticised."}, {"term": "immigration detention", "ipa": "/ˌɪmɪˈɡreɪʃən dɪˈtenʃən/", "pron": "im-i-GRAY-shuhn di-TEN-shuhn", "fr": "rétention administrative liée à l’immigration", "def": "The detention of migrants by immigration authorities.", "ex": "Immigration detention has raised human rights concerns."}, {"term": "family separation", "ipa": "/ˌfæməli ˌsepəˈreɪʃən/", "pron": "FAM-uh-lee sep-uh-RAY-shuhn", "fr": "séparation des familles", "def": "The separation of migrant children from their parents by authorities.", "ex": "Family separation sparked national outrage."}, {"term": "zero-tolerance policy", "ipa": "/ˌzɪərəʊ ˈtɒlərəns ˈpɒləsi/", "pron": "ZEER-oh TOL-uh-ruhns POL-uh-see", "fr": "politique de tolérance zéro", "def": "A strict enforcement policy with little or no discretion.", "ex": "The zero-tolerance policy led to family separations."}, {"term": "immigration court", "ipa": "/ˌɪmɪˈɡreɪʃən kɔːt/", "pron": "im-i-GRAY-shuhn court", "fr": "tribunal de l’immigration", "def": "A court that handles immigration cases such as deportation and asylum claims.", "ex": "Immigration courts face huge backlogs."}, {"term": "backlog", "ipa": "/ˈbæklɒɡ/", "pron": "BAK-log", "fr": "arriéré ; accumulation de dossiers", "def": "A large number of cases waiting to be processed.", "ex": "The asylum backlog has grown rapidly."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "dyoo PROH-sess", "fr": "procédure régulière ; garanties procédurales", "def": "Fair legal procedures before the state restricts rights or removes someone.", "ex": "Migrants are entitled to due process in immigration courts."}]}, {"title": "C. Deportation, detention and enforcement", "entries": [{"term": "sanctuary city", "ipa": "/ˈsæŋktʃuəri ˈsɪti/", "pron": "SANK-choo-air-ee SIT-ee", "fr": "ville sanctuaire", "def": "A city that limits cooperation with federal immigration enforcement.", "ex": "Sanctuary cities are often criticised by immigration hardliners."}, {"term": "sanctuary policy", "ipa": "/ˈsæŋktʃuəri ˈpɒləsi/", "pron": "SANK-choo-air-ee POL-uh-see", "fr": "politique de ville sanctuaire", "def": "A policy limiting local cooperation with federal immigration enforcement.", "ex": "The sanctuary policy protected undocumented residents."}, {"term": "ICE", "ipa": "/ˌaɪ siː ˈiː/", "pron": "eye see ee", "fr": "ICE ; agence américaine de contrôle de l’immigration", "def": "US Immigration and Customs Enforcement, the agency responsible for immigration enforcement inside the country.", "ex": "ICE raids have become politically controversial."}, {"term": "CBP", "ipa": "/ˌsiː biː ˈpiː/", "pron": "see bee pee", "fr": "CBP ; douanes et protection des frontières", "def": "US Customs and Border Protection, the agency responsible for border security and customs.", "ex": "CBP officers patrol the border and inspect ports of entry."}, {"term": "immigration enforcement", "ipa": "/ˌɪmɪˈɡreɪʃən ɪnˈfɔːsmənt/", "pron": "im-i-GRAY-shuhn in-FORSS-muhnt", "fr": "application des lois sur l’immigration", "def": "The implementation of immigration laws by authorities.", "ex": "Immigration enforcement increased after the policy change."}, {"term": "raid", "ipa": "/reɪd/", "pron": "rayd", "fr": "descente ; raid", "def": "A sudden operation by authorities to arrest or inspect people.", "ex": "ICE raids created fear in immigrant communities."}, {"term": "to deport", "ipa": "/dɪˈpɔːt/", "pron": "di-PORT", "fr": "expulser", "def": "To force a non-citizen to leave a country.", "ex": "The administration promised to deport more undocumented immigrants."}, {"term": "to detain", "ipa": "/dɪˈteɪn/", "pron": "di-TAYN", "fr": "détenir ; placer en rétention", "def": "To hold someone in custody.", "ex": "Border authorities detained migrants near the crossing."}, {"term": "to grant asylum", "ipa": "/ɡrɑːnt əˈsaɪləm/", "pron": "grahnt uh-SY-luhm", "fr": "accorder l’asile", "def": "To give legal protection to a person fleeing persecution.", "ex": "The judge granted asylum to the applicant."}, {"term": "to seek asylum", "ipa": "/siːk əˈsaɪləm/", "pron": "seek uh-SY-luhm", "fr": "demander l’asile", "def": "To request protection in another country because of persecution or danger.", "ex": "The family crossed the border to seek asylum."}, {"term": "to process claims", "ipa": "/ˈprəʊses kleɪmz/", "pron": "PROH-sess klaymz", "fr": "traiter des demandes", "def": "To examine and decide legal applications or requests.", "ex": "The government struggled to process asylum claims."}, {"term": "to tighten immigration rules", "ipa": "/ˈtaɪtən ˌɪmɪˈɡreɪʃən ruːlz/", "pron": "TY-tuhn im-i-GRAY-shuhn roolz", "fr": "durcir les règles d’immigration", "def": "To make immigration rules stricter.", "ex": "The administration moved to tighten immigration rules."}, {"term": "to secure the border", "ipa": "/sɪˈkjʊə ðə ˈbɔːdə/", "pron": "si-KYOOR thuh BOR-duh", "fr": "sécuriser la frontière", "def": "To strengthen border control and prevent unauthorised crossings.", "ex": "Conservatives argued that the government had failed to secure the border."}, {"term": "to crack down on immigration", "ipa": "/ˈkræk daʊn ɒn ˌɪmɪˈɡreɪʃən/", "pron": "KRAK down on im-i-GRAY-shuhn", "fr": "durcir la répression de l’immigration", "def": "To take strict action against immigration, especially unauthorised immigration.", "ex": "The government vowed to crack down on illegal immigration."}, {"term": "to regularise status", "ipa": "/ˈreɡjʊləraɪz ˈsteɪtəs/", "pron": "REG-yuh-luh-ryz STAY-tuhs", "fr": "régulariser la situation", "def": "To give legal status to people who were previously undocumented.", "ex": "Advocates called for a path to regularise status."}, {"term": "pathway to citizenship", "ipa": "/ˈpɑːθweɪ tə ˈsɪtɪzənʃɪp/", "pron": "PATH-way tuh SIT-i-zuhn-ship", "fr": "voie vers la citoyenneté", "def": "A legal process allowing immigrants to eventually become citizens.", "ex": "Democrats supported a pathway to citizenship for Dreamers."}, {"term": "amnesty", "ipa": "/ˈæmnəsti/", "pron": "AM-nuh-stee", "fr": "amnistie", "def": "A policy forgiving immigration violations and granting legal status, often controversial.", "ex": "Opponents denounced the proposal as amnesty."}, {"term": "comprehensive immigration reform", "ipa": "/ˌkɒmprɪˈhensɪv ˌɪmɪˈɡreɪʃən rɪˈfɔːm/", "pron": "kom-pri-HEN-siv im-i-GRAY-shuhn ri-FORM", "fr": "réforme globale de l’immigration", "def": "Broad reform addressing legal immigration, border security, undocumented migrants and enforcement.", "ex": "Comprehensive immigration reform has repeatedly failed in Congress."}, {"term": "merit-based immigration", "ipa": "/ˈmerɪt beɪst ˌɪmɪˈɡreɪʃən/", "pron": "MER-it bayst im-i-GRAY-shuhn", "fr": "immigration au mérite ; immigration choisie", "def": "An immigration system prioritising skills, qualifications or economic contribution.", "ex": "Supporters of merit-based immigration emphasise skills and productivity."}, {"term": "points-based system", "ipa": "/ˈpɔɪnts beɪst ˈsɪstəm/", "pron": "points bayst SIS-tuhm", "fr": "système à points", "def": "An immigration system that awards points for skills, education, language or work experience.", "ex": "A points-based system favours highly qualified applicants."}, {"term": "border crisis", "ipa": "/ˈbɔːdə ˈkraɪsɪs/", "pron": "BOR-duh KRY-sis", "fr": "crise à la frontière", "def": "A politically loaded term describing a sharp increase in border crossings or pressure on border systems.", "ex": "Republicans described the rise in crossings as a border crisis."}, {"term": "pull factor", "ipa": "/ˈpʊl ˌfæktə/", "pron": "pull FAK-tuh", "fr": "facteur d’attraction", "def": "A condition attracting migrants to a destination country.", "ex": "Jobs and family ties are powerful pull factors."}, {"term": "push factor", "ipa": "/ˈpʊʃ ˌfæktə/", "pron": "push FAK-tuh", "fr": "facteur de départ ; facteur répulsif", "def": "A condition forcing or encouraging people to leave their home country.", "ex": "Violence and poverty are major push factors."}, {"term": "economic migrant", "ipa": "/ˌiːkəˈnɒmɪk ˈmaɪɡrənt/", "pron": "ee-kuh-NOM-ik MY-gruhnt", "fr": "migrant économique", "def": "A person who migrates primarily for economic opportunities.", "ex": "Economic migrants may not qualify for asylum."}, {"term": "human trafficking", "ipa": "/ˌhjuːmən ˈtræfɪkɪŋ/", "pron": "HYOO-muhn TRAF-i-king", "fr": "traite des êtres humains", "def": "The illegal exploitation of people through force, fraud or coercion.", "ex": "Migrants can be vulnerable to human trafficking."}]}, {"title": "D. Reform, border politics and migration pressures", "entries": [{"term": "smuggling", "ipa": "/ˈsmʌɡlɪŋ/", "pron": "SMUG-ling", "fr": "passeurs ; trafic illicite", "def": "Illegally helping people or goods cross borders, usually for money.", "ex": "Smuggling networks profit from restrictive border policies."}, {"term": "people smuggler", "ipa": "/ˈpiːpəl ˌsmʌɡlə/", "pron": "PEE-puhl SMUG-luh", "fr": "passeur", "def": "A person who illegally helps migrants cross borders for payment.", "ex": "People smugglers often exploit desperate migrants."}, {"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "zen-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Fear or hostility towards foreigners or immigrants.", "ex": "Anti-immigration rhetoric can fuel xenophobia."}, {"term": "nativism", "ipa": "/ˈneɪtɪvɪzəm/", "pron": "NAY-tiv-iz-uhm", "fr": "nativisme ; préférence nationale", "def": "A political attitude favouring native-born citizens over immigrants.", "ex": "Nativism has shaped several periods of US immigration history."}, {"term": "anti-immigration rhetoric", "ipa": "/ˌænti ˌɪmɪˈɡreɪʃən ˈretərɪk/", "pron": "AN-tee im-i-GRAY-shuhn RET-uh-rik", "fr": "rhétorique anti-immigration", "def": "Political language presenting immigration as a threat.", "ex": "Anti-immigration rhetoric intensified during the campaign."}, {"term": "scapegoating", "ipa": "/ˈskeɪpɡəʊtɪŋ/", "pron": "SKAYP-goht-ing", "fr": "désignation d’un bouc émissaire", "def": "Blaming a group unfairly for social or economic problems.", "ex": "Scapegoating immigrants can mobilise angry voters."}, {"term": "cultural assimilation", "ipa": "/ˌkʌltʃərəl əˌsɪmɪˈleɪʃən/", "pron": "KUL-chuh-ruhl uh-sim-i-LAY-shuhn", "fr": "assimilation culturelle", "def": "The process by which immigrants adopt the culture of the host country.", "ex": "Debates about cultural assimilation often reveal fears about national identity."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The process by which immigrants become part of social, economic and political life.", "ex": "Language learning can support integration."}, {"term": "multiculturalism", "ipa": "/ˌmʌltiˈkʌltʃərəlɪzəm/", "pron": "MUL-tee-KUL-chuh-ruh-liz-uhm", "fr": "multiculturalisme", "def": "A model in which different cultural groups coexist and are recognised within society.", "ex": "Multiculturalism is often contrasted with assimilation."}, {"term": "melting pot", "ipa": "/ˈmeltɪŋ pɒt/", "pron": "MEL-ting pot", "fr": "creuset culturel ; melting pot", "def": "A metaphor describing a society where different cultures blend into one.", "ex": "The United States has often been described as a melting pot."}, {"term": "salad bowl", "ipa": "/ˈsæləd bəʊl/", "pron": "SAL-uhd bohl", "fr": "saladier culturel", "def": "A metaphor for multicultural society where groups keep distinct identities while coexisting.", "ex": "The salad bowl metaphor emphasises diversity rather than assimilation."}, {"term": "American identity", "ipa": "/əˌmerɪkən aɪˈdentəti/", "pron": "uh-MER-i-kuhn eye-DEN-tuh-tee", "fr": "identité américaine", "def": "The sense of belonging, values and narratives associated with being American.", "ex": "Immigration constantly reshapes American identity."}, {"term": "nation of immigrants", "ipa": "/ˌneɪʃən əv ˈɪmɪɡrənts/", "pron": "NAY-shuhn ov IM-i-gruhnts", "fr": "nation d’immigrants", "def": "A phrase describing the United States as a country built by immigrants.", "ex": "The phrase nation of immigrants is central to American self-image."}, {"term": "to contribute to the economy", "ipa": "/kənˈtrɪbjuːt tə ði iˈkɒnəmi/", "pron": "kuhn-TRIB-yoot tuh thee i-KON-uh-mee", "fr": "contribuer à l’économie", "def": "To add value to economic activity through work, taxes or entrepreneurship.", "ex": "Immigrants contribute to the economy as workers and business owners."}, {"term": "to fill labour gaps", "ipa": "/fɪl ˈleɪbə ɡæps/", "pron": "fil LAY-buh gaps", "fr": "combler les pénuries de main-d’œuvre", "def": "To provide workers where there are labour shortages.", "ex": "Migrant workers fill labour gaps in agriculture and healthcare."}, {"term": "to fuel political polarisation", "ipa": "/ˈfjuːəl pəˈlɪtɪkəl ˌpəʊləraɪˈzeɪʃən/", "pron": "FYOO-uhl puh-LIT-i-kuhl poh-luh-ry-ZAY-shuhn", "fr": "alimenter la polarisation politique", "def": "To make political divisions worse.", "ex": "Immigration debates often fuel political polarisation."}, {"term": "to frame immigrants as a threat", "ipa": "/freɪm ˈɪmɪɡrənts æz ə θret/", "pron": "fraym IM-i-gruhnts az uh thret", "fr": "présenter les immigrés comme une menace", "def": "To present immigrants as dangerous or harmful.", "ex": "Populist campaigns often frame immigrants as a threat."}, {"term": "to balance security and compassion", "ipa": "/ˈbæləns sɪˈkjʊərəti ənd kəmˈpæʃən/", "pron": "BAL-uhns si-KYOOR-uh-tee and kuhm-PASH-uhn", "fr": "concilier sécurité et compassion", "def": "To try to combine border control with humanitarian values.", "ex": "Immigration policy must balance security and compassion."}]}, {"title": "E. Identity, integration and high-value debate phrases", "entries": []}]}, {"id": "p2c18", "part": 2, "chapter": 18, "title": "Gun Control", "file": "cpge_vocab_part2_chapter18_gun_control_premium.html", "count": 101, "sections": [{"title": "A. Constitutional vocabulary and core debate", "entries": [{"term": "gun control", "ipa": "/ˈɡʌn kənˌtrəʊl/", "pron": "gun kuhn-TROHL", "fr": "contrôle des armes à feu", "def": "Laws and policies regulating the sale, ownership and use of firearms.", "ex": "Gun control remains one of the most divisive issues in American politics."}, {"term": "firearm", "ipa": "/ˈfaɪərɑːm/", "pron": "FY-uhr-arm", "fr": "arme à feu", "def": "A gun or weapon from which bullets are fired.", "ex": "Federal law regulates who can buy a firearm."}, {"term": "gun ownership", "ipa": "/ˈɡʌn ˌəʊnəʃɪp/", "pron": "gun OH-nuh-ship", "fr": "possession d’armes à feu", "def": "The possession of firearms by private individuals.", "ex": "Gun ownership is often defended as a constitutional right."}, {"term": "gun rights", "ipa": "/ˈɡʌn raɪts/", "pron": "gun rites", "fr": "droit de posséder ou porter des armes", "def": "The claimed legal or constitutional rights to own, carry or use firearms.", "ex": "Gun rights activists oppose many restrictions on firearms."}, {"term": "right to bear arms", "ipa": "/ˌraɪt tə beər ˈɑːmz/", "pron": "rite tuh bair armz", "fr": "droit de porter des armes", "def": "The constitutional right, linked to the Second Amendment, to keep and carry weapons.", "ex": "The right to bear arms is central to Second Amendment debates."}, {"term": "Second Amendment", "ipa": "/ˌsekənd əˈmendmənt/", "pron": "SEK-uhnd uh-MEND-muhnt", "fr": "Deuxième amendement", "def": "The amendment to the US Constitution often interpreted as protecting the right to keep and bear arms.", "ex": "The Second Amendment is frequently invoked by gun rights supporters."}, {"term": "well-regulated militia", "ipa": "/ˌwel ˌreɡjʊleɪtɪd məˈlɪʃə/", "pron": "wel REG-yuh-lay-tid muh-LISH-uh", "fr": "milice bien organisée", "def": "A phrase from the Second Amendment referring to an organised citizen militia.", "ex": "The phrase well-regulated militia is central to debates over constitutional interpretation."}, {"term": "individual right", "ipa": "/ˌɪndɪˈvɪdʒuəl raɪt/", "pron": "in-di-VIJ-oo-uhl rite", "fr": "droit individuel", "def": "A right held by a person as an individual rather than by a collective group.", "ex": "The Supreme Court has interpreted gun ownership as an individual right."}, {"term": "collective right", "ipa": "/kəˌlektɪv ˈraɪt/", "pron": "kuh-LEK-tiv rite", "fr": "droit collectif", "def": "A right held by a group or community rather than by individuals alone.", "ex": "Some scholars once argued that the Second Amendment protected a collective right linked to militias."}, {"term": "constitutional right", "ipa": "/ˌkɒnstɪˈtjuːʃənəl raɪt/", "pron": "kon-sti-TOO-shuh-nuhl rite", "fr": "droit constitutionnel", "def": "A right protected by a constitution.", "ex": "Gun rights advocates describe firearm ownership as a constitutional right."}, {"term": "firearms regulation", "ipa": "/ˈfaɪərɑːmz ˌreɡjʊˈleɪʃən/", "pron": "FY-uhr-armz reg-yuh-LAY-shuhn", "fr": "réglementation des armes à feu", "def": "Rules controlling the manufacture, sale, possession or use of firearms.", "ex": "Firearms regulation varies widely from state to state."}, {"term": "gun legislation", "ipa": "/ˈɡʌn ˌledʒɪsˈleɪʃən/", "pron": "gun lej-is-LAY-shuhn", "fr": "législation sur les armes à feu", "def": "Laws dealing with firearms.", "ex": "Gun legislation often faces strong opposition in Congress."}, {"term": "gun law", "ipa": "/ˈɡʌn lɔː/", "pron": "gun law", "fr": "loi sur les armes à feu", "def": "A law regulating firearms.", "ex": "Gun laws are much stricter in some states than in others."}, {"term": "state gun law", "ipa": "/ˌsteɪt ˈɡʌn lɔː/", "pron": "stayt gun law", "fr": "loi d’un État sur les armes à feu", "def": "A firearm law passed by a US state.", "ex": "State gun laws differ dramatically across the country."}, {"term": "federal gun law", "ipa": "/ˌfedərəl ˈɡʌn lɔː/", "pron": "FED-uh-ruhl gun law", "fr": "loi fédérale sur les armes à feu", "def": "A firearm law passed by the national government.", "ex": "Federal gun law sets minimum rules for firearm purchases."}, {"term": "background check", "ipa": "/ˈbækɡraʊnd tʃek/", "pron": "BAK-ground chek", "fr": "vérification des antécédents", "def": "A check of a person’s criminal or mental health record before allowing a gun purchase.", "ex": "Many voters support universal background checks."}, {"term": "universal background checks", "ipa": "/ˌjuːnɪˈvɜːsəl ˈbækɡraʊnd tʃeks/", "pron": "yoo-ni-VUR-suhl BAK-ground cheks", "fr": "vérifications universelles des antécédents", "def": "Background checks required for nearly all gun sales, including private sales.", "ex": "Universal background checks are a common gun control proposal."}, {"term": "waiting period", "ipa": "/ˈweɪtɪŋ ˌpɪəriəd/", "pron": "WAY-ting PEER-ee-uhd", "fr": "délai d’attente", "def": "A required delay between buying a firearm and receiving it.", "ex": "A waiting period may reduce impulsive gun violence."}, {"term": "licensing", "ipa": "/ˈlaɪsənsɪŋ/", "pron": "LY-suhn-sing", "fr": "système de licence ; permis", "def": "A system requiring official permission to own, buy or carry a firearm.", "ex": "Licensing rules can make gun ownership more regulated."}, {"term": "permit", "ipa": "/ˈpɜːmɪt/", "pron": "PUR-mit", "fr": "permis ; autorisation", "def": "An official document allowing someone to own, buy or carry a gun.", "ex": "Some states require a permit to carry a handgun."}, {"term": "registration", "ipa": "/ˌredʒɪˈstreɪʃən/", "pron": "rej-i-STRAY-shuhn", "fr": "enregistrement", "def": "The official recording of firearm ownership.", "ex": "Gun registration is controversial among gun rights supporters."}, {"term": "gun registry", "ipa": "/ˈɡʌn ˌredʒɪstri/", "pron": "gun REJ-i-stree", "fr": "registre des armes", "def": "An official list of firearms or firearm owners.", "ex": "Opponents fear that a gun registry could lead to confiscation."}]}, {"title": "B. Firearms, carrying rules and safety measures", "entries": [{"term": "assault weapon", "ipa": "/əˈsɔːlt ˌwepən/", "pron": "uh-SAWLT WEP-uhn", "fr": "arme d’assaut", "def": "A politically contested term for certain semi-automatic firearms with military-style features.", "ex": "An assault weapon ban is often proposed after mass shootings."}, {"term": "assault weapons ban", "ipa": "/əˈsɔːlt ˌwepənz bæn/", "pron": "uh-SAWLT WEP-uhnz ban", "fr": "interdiction des armes d’assaut", "def": "A law banning certain semi-automatic firearms defined as assault weapons.", "ex": "Democrats have repeatedly called for an assault weapons ban."}, {"term": "semi-automatic weapon", "ipa": "/ˌsemi ɔːtəˈmætɪk ˈwepən/", "pron": "SEM-ee aw-tuh-MAT-ik WEP-uhn", "fr": "arme semi-automatique", "def": "A firearm that fires one round per trigger pull and reloads automatically.", "ex": "Semi-automatic weapons are often used in mass shootings."}, {"term": "automatic weapon", "ipa": "/ˌɔːtəˈmætɪk ˈwepən/", "pron": "aw-tuh-MAT-ik WEP-uhn", "fr": "arme automatique", "def": "A weapon that continues firing while the trigger is held down.", "ex": "Automatic weapons are heavily restricted under federal law."}, {"term": "handgun", "ipa": "/ˈhændɡʌn/", "pron": "HAND-gun", "fr": "arme de poing", "def": "A small firearm designed to be held in one hand.", "ex": "Handguns are involved in many firearm deaths."}, {"term": "rifle", "ipa": "/ˈraɪfəl/", "pron": "RY-fuhl", "fr": "fusil", "def": "A long firearm designed to be fired from the shoulder.", "ex": "Some rifles are used for hunting or sport shooting."}, {"term": "shotgun", "ipa": "/ˈʃɒtɡʌn/", "pron": "SHOT-gun", "fr": "fusil de chasse", "def": "A long firearm that fires shells, often used for hunting or home defence.", "ex": "Shotguns are commonly owned in rural areas."}, {"term": "AR-15-style rifle", "ipa": "/ˌeɪ ɑː ˌfɪfˈtiːn staɪl ˈraɪfəl/", "pron": "ay ar fif-TEEN style RY-fuhl", "fr": "fusil de type AR-15", "def": "A civilian semi-automatic rifle model often discussed in mass shooting debates.", "ex": "AR-15-style rifles have become symbols in the gun control debate."}, {"term": "high-capacity magazine", "ipa": "/ˌhaɪ kəˈpæsəti ˌmæɡəˈziːn/", "pron": "hy kuh-PAS-uh-tee mag-uh-ZEEN", "fr": "chargeur grande capacité", "def": "A device holding many rounds of ammunition for a firearm.", "ex": "High-capacity magazines can increase the number of shots fired without reloading."}, {"term": "ammunition", "ipa": "/ˌæmjəˈnɪʃən/", "pron": "am-yuh-NISH-uhn", "fr": "munitions", "def": "Bullets or other projectiles used in firearms.", "ex": "Some proposals seek to regulate ammunition sales."}, {"term": "bullet", "ipa": "/ˈbʊlɪt/", "pron": "BUL-it", "fr": "balle", "def": "A projectile fired from a gun.", "ex": "The bullet was recovered as evidence."}, {"term": "bump stock", "ipa": "/ˈbʌmp stɒk/", "pron": "bump stok", "fr": "crosse bump stock", "def": "A device that allows a semi-automatic weapon to fire more rapidly.", "ex": "Bump stocks became controversial after the Las Vegas shooting."}, {"term": "silencer", "ipa": "/ˈsaɪlənsə/", "pron": "SY-luhn-suh", "fr": "silencieux", "def": "A device attached to a firearm to reduce noise, also called a suppressor.", "ex": "Silencers are regulated under federal law."}, {"term": "concealed carry", "ipa": "/kənˌsiːld ˈkæri/", "pron": "kuhn-SEELD KARR-ee", "fr": "port d’arme dissimulé", "def": "The practice of carrying a hidden firearm in public.", "ex": "Concealed carry laws vary by state."}, {"term": "open carry", "ipa": "/ˌəʊpən ˈkæri/", "pron": "OH-puhn KARR-ee", "fr": "port d’arme visible", "def": "The practice of visibly carrying a firearm in public.", "ex": "Open carry is legal in some states."}, {"term": "permitless carry", "ipa": "/ˌpɜːmɪtləs ˈkæri/", "pron": "PUR-mit-less KARR-ee", "fr": "port d’arme sans permis", "def": "The legal ability to carry a firearm without a permit.", "ex": "Several states have adopted permitless carry."}, {"term": "campus carry", "ipa": "/ˈkæmpəs ˈkæri/", "pron": "KAM-puhs KARR-ee", "fr": "port d’arme sur les campus", "def": "Laws allowing firearms on college or university campuses.", "ex": "Campus carry has sparked debate over safety and academic freedom."}, {"term": "stand-your-ground law", "ipa": "/ˌstænd jə ˈɡraʊnd lɔː/", "pron": "stand yuh ground law", "fr": "loi Stand Your Ground ; loi de légitime défense élargie", "def": "A law allowing people to use force without retreating if they believe they face a threat.", "ex": "Stand-your-ground laws are criticised for encouraging violent confrontations."}, {"term": "castle doctrine", "ipa": "/ˈkɑːsəl ˌdɒktrɪn/", "pron": "KAR-suhl DOK-trin", "fr": "doctrine du château ; défense du domicile", "def": "A legal principle allowing people to use force to defend their home.", "ex": "The castle doctrine is often cited in self-defence cases."}, {"term": "self-defence", "ipa": "/ˌself dɪˈfens/", "pron": "self di-FENSS", "fr": "légitime défense", "def": "The use of force to protect oneself from harm.", "ex": "Many gun owners cite self-defence as their main reason for owning a gun."}, {"term": "home defence", "ipa": "/ˌhəʊm dɪˈfens/", "pron": "hohm di-FENSS", "fr": "défense du domicile", "def": "Protection of one’s home against intruders.", "ex": "Home defence is a common argument for gun ownership."}, {"term": "responsible gun ownership", "ipa": "/rɪˌspɒnsəbəl ˈɡʌn ˌəʊnəʃɪp/", "pron": "ri-SPON-suh-buhl gun OH-nuh-ship", "fr": "possession responsable d’armes", "def": "Safe and lawful possession and use of firearms.", "ex": "Supporters say responsible gun ownership should not be punished."}, {"term": "gun safety", "ipa": "/ˈɡʌn ˌseɪfti/", "pron": "gun SAYF-tee", "fr": "sécurité liée aux armes à feu", "def": "Practices or policies designed to prevent firearm accidents and violence.", "ex": "Gun safety education can prevent accidental shootings."}, {"term": "safe storage", "ipa": "/ˌseɪf ˈstɔːrɪdʒ/", "pron": "sayf STOR-ij", "fr": "stockage sécurisé", "def": "Rules or practices requiring guns to be stored securely.", "ex": "Safe storage laws aim to protect children from accidental shootings."}, {"term": "trigger lock", "ipa": "/ˈtrɪɡə lɒk/", "pron": "TRIG-uh lok", "fr": "verrou de détente", "def": "A device that prevents a gun from being fired.", "ex": "A trigger lock can reduce accidental firearm use."}, {"term": "red flag law", "ipa": "/ˌred ˈflæɡ lɔː/", "pron": "red flag law", "fr": "loi d’alerte ; red flag law", "def": "A law allowing authorities to temporarily remove guns from people judged dangerous to themselves or others.", "ex": "Red flag laws are meant to prevent suicides and mass shootings."}, {"term": "extreme risk protection order", "ipa": "/ɪkˌstriːm rɪsk prəˈtekʃən ˌɔːdə/", "pron": "ik-STREEM risk pruh-TEK-shuhn OR-duh", "fr": "ordonnance de protection contre les risques extrêmes", "def": "A court order temporarily restricting firearm access for a person considered dangerous.", "ex": "Extreme risk protection orders are often linked to red flag laws."}, {"term": "domestic abuser", "ipa": "/dəˌmestɪk əˈbjuːzə/", "pron": "duh-MES-tik uh-BYOO-zuh", "fr": "auteur de violences domestiques", "def": "A person who commits abuse against a partner or family member.", "ex": "Many advocates want to keep guns away from domestic abusers."}, {"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl helth", "fr": "santé mentale", "def": "A person’s psychological and emotional well-being.", "ex": "Mental health is often mentioned after mass shootings, though most people with mental illness are not violent."}, {"term": "gun violence", "ipa": "/ˈɡʌn ˌvaɪələns/", "pron": "gun VY-uh-luhns", "fr": "violence par armes à feu", "def": "Violence involving firearms.", "ex": "Gun violence kills tens of thousands of Americans each year."}, {"term": "firearm death", "ipa": "/ˈfaɪərɑːm deθ/", "pron": "FY-uhr-arm deth", "fr": "mort par arme à feu", "def": "A death caused by a gun.", "ex": "Firearm deaths include homicides, suicides and accidents."}]}, {"title": "C. Gun violence, mass shootings and public health", "entries": [{"term": "gun homicide", "ipa": "/ˈɡʌn ˈhɒmɪsaɪd/", "pron": "gun HOM-i-syde", "fr": "homicide par arme à feu", "def": "A murder committed with a firearm.", "ex": "Gun homicides are concentrated in some urban areas."}, {"term": "gun suicide", "ipa": "/ˈɡʌn ˈsuːɪsaɪd/", "pron": "gun SOO-i-syde", "fr": "suicide par arme à feu", "def": "A suicide committed with a firearm.", "ex": "Gun suicides make up a large share of firearm deaths."}, {"term": "accidental shooting", "ipa": "/ˌæksɪdentəl ˈʃuːtɪŋ/", "pron": "ak-si-DEN-tuhl SHOO-ting", "fr": "tir accidentel", "def": "A shooting that happens unintentionally.", "ex": "Safe storage can reduce accidental shootings."}, {"term": "mass shooting", "ipa": "/ˌmæs ˈʃuːtɪŋ/", "pron": "mass SHOO-ting", "fr": "fusillade de masse", "def": "A shooting incident involving multiple victims, though definitions vary.", "ex": "Mass shootings often reignite the gun control debate."}, {"term": "school shooting", "ipa": "/ˈskuːl ˌʃuːtɪŋ/", "pron": "school SHOO-ting", "fr": "fusillade en milieu scolaire", "def": "A shooting that takes place in or near a school.", "ex": "School shootings have traumatised communities and shaped political debate."}, {"term": "active shooter", "ipa": "/ˌæktɪv ˈʃuːtə/", "pron": "AK-tiv SHOO-tuh", "fr": "tireur actif", "def": "A person actively engaged in killing or attempting to kill people in a populated area.", "ex": "Schools now practise active shooter drills."}, {"term": "active shooter drill", "ipa": "/ˌæktɪv ˈʃuːtə drɪl/", "pron": "AK-tiv SHOO-tuh dril", "fr": "exercice en cas de tireur actif", "def": "A practice exercise preparing people for an active shooter situation.", "ex": "Active shooter drills have become common in American schools."}, {"term": "survivor", "ipa": "/səˈvaɪvə/", "pron": "suh-VY-vuh", "fr": "survivant ; survivante", "def": "A person who lives through a violent or traumatic event.", "ex": "Survivors of school shootings often campaign for reform."}, {"term": "victim", "ipa": "/ˈvɪktɪm/", "pron": "VIK-tim", "fr": "victime", "def": "A person harmed, injured or killed by violence or crime.", "ex": "Victims’ families called for stronger gun laws."}, {"term": "public safety", "ipa": "/ˌpʌblɪk ˈseɪfti/", "pron": "PUB-lik SAYF-tee", "fr": "sécurité publique", "def": "The protection of people from crime, violence or danger.", "ex": "Gun control supporters frame the issue as a matter of public safety."}, {"term": "public health crisis", "ipa": "/ˌpʌblɪk ˈhelθ ˈkraɪsɪs/", "pron": "PUB-lik helth KRY-sis", "fr": "crise de santé publique", "def": "A widespread threat to health requiring collective action.", "ex": "Many doctors describe gun violence as a public health crisis."}, {"term": "trauma", "ipa": "/ˈtrɔːmə/", "pron": "TRAW-muh", "fr": "traumatisme", "def": "Severe emotional or psychological harm after a disturbing event.", "ex": "Gun violence leaves long-lasting trauma."}, {"term": "community violence", "ipa": "/kəˌmjuːnəti ˈvaɪələns/", "pron": "kuh-MYOO-nuh-tee VY-uh-luhns", "fr": "violence communautaire ; violence dans les quartiers", "def": "Violence affecting everyday life in a local community.", "ex": "Community violence is often overlooked compared with mass shootings."}, {"term": "urban violence", "ipa": "/ˌɜːbən ˈvaɪələns/", "pron": "UR-buhn VY-uh-luhns", "fr": "violence urbaine", "def": "Violence occurring in city environments, often linked to poverty and inequality.", "ex": "Urban violence is frequently politicised in gun debates."}, {"term": "domestic violence", "ipa": "/dəˌmestɪk ˈvaɪələns/", "pron": "duh-MES-tik VY-uh-luhns", "fr": "violence domestique ; violences conjugales", "def": "Violence within a household or intimate relationship.", "ex": "Guns make domestic violence more deadly."}, {"term": "suicide prevention", "ipa": "/ˈsuːɪsaɪd prɪˌvenʃən/", "pron": "SOO-i-syde pri-VEN-shuhn", "fr": "prévention du suicide", "def": "Measures designed to reduce suicides.", "ex": "Gun safety policies can be part of suicide prevention."}, {"term": "NRA", "ipa": "/ˌen ɑːr ˈeɪ/", "pron": "en ar ay", "fr": "NRA ; National Rifle Association", "def": "The National Rifle Association, a powerful US gun rights organisation.", "ex": "The NRA has long influenced Republican politics."}, {"term": "gun lobby", "ipa": "/ˈɡʌn ˌlɒbi/", "pron": "gun LOB-ee", "fr": "lobby des armes", "def": "Groups that lobby to protect gun rights and oppose firearm restrictions.", "ex": "The gun lobby opposes most federal gun control measures."}, {"term": "gun control advocate", "ipa": "/ˈɡʌn kənˌtrəʊl ˈædvəkət/", "pron": "gun kuhn-TROHL AD-vuh-kuht", "fr": "partisan du contrôle des armes", "def": "A person who supports stricter firearm regulation.", "ex": "Gun control advocates called for action after the shooting."}, {"term": "gun rights activist", "ipa": "/ˈɡʌn raɪts ˈæktɪvɪst/", "pron": "gun rites AK-ti-vist", "fr": "militant pro-armes", "def": "A person who campaigns to protect or expand gun rights.", "ex": "Gun rights activists argued that the law violated the Second Amendment."}, {"term": "Second Amendment absolutist", "ipa": "/ˌsekənd əˈmendmənt ˈæbsəluːtɪst/", "pron": "SEK-uhnd uh-MEND-muhnt AB-suh-loot-ist", "fr": "absolutiste du Deuxième amendement", "def": "A person who believes firearm rights should face almost no restrictions.", "ex": "Second Amendment absolutists reject most gun control proposals."}]}, {"title": "D. Politics, lobbying and Supreme Court cases", "entries": [{"term": "public opinion", "ipa": "/ˌpʌblɪk əˈpɪnjən/", "pron": "PUB-lik uh-PIN-yuhn", "fr": "opinion publique", "def": "The views of the public on an issue.", "ex": "Public opinion often supports background checks."}, {"term": "political gridlock", "ipa": "/pəˌlɪtɪkəl ˈɡrɪdlɒk/", "pron": "puh-LIT-i-kuhl GRID-lok", "fr": "blocage politique", "def": "A situation in which political disagreement prevents action.", "ex": "Political gridlock has blocked major gun reform."}, {"term": "partisan divide", "ipa": "/ˌpɑːtɪzən dɪˈvaɪd/", "pron": "PAR-ti-zuhn di-VYDE", "fr": "clivage partisan", "def": "A political division based on party allegiance.", "ex": "The partisan divide on gun control has widened."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Gun ownership has become a culture-war issue."}, {"term": "rural voters", "ipa": "/ˌrʊərəl ˈvəʊtəz/", "pron": "ROOR-uhl VOH-tuhz", "fr": "électeurs ruraux", "def": "Voters living outside cities, often in countryside areas.", "ex": "Rural voters are often more supportive of gun rights."}, {"term": "urban voters", "ipa": "/ˌɜːbən ˈvəʊtəz/", "pron": "UR-buhn VOH-tuhz", "fr": "électeurs urbains", "def": "Voters living in cities.", "ex": "Urban voters are often more supportive of gun control."}, {"term": "constitutional challenge", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈtʃælɪndʒ/", "pron": "kon-sti-TOO-shuh-nuhl CHAL-inj", "fr": "recours constitutionnel", "def": "A legal challenge arguing that a law violates the Constitution.", "ex": "The gun law faced a constitutional challenge."}, {"term": "Supreme Court ruling", "ipa": "/suːˌpriːm ˈkɔːt ˈruːlɪŋ/", "pron": "soo-PREEM court ROO-ling", "fr": "décision de la Cour suprême", "def": "A decision made by the US Supreme Court.", "ex": "A Supreme Court ruling expanded gun rights."}, {"term": "District of Columbia v. Heller", "ipa": "/ˈdɪstrɪkt əv kəˈlʌmbiə vɜːsəs ˈhelə/", "pron": "DIS-trikt ov kuh-LUM-bee-uh VUR-suhs HEL-uh", "fr": "District of Columbia v. Heller", "def": "The 2008 Supreme Court case recognising an individual right to possess firearms for lawful purposes such as self-defence.", "ex": "District of Columbia v. Heller reshaped Second Amendment law."}, {"term": "New York State Rifle & Pistol Association v. Bruen", "ipa": "/njuː ˈjɔːk steɪt ˈraɪfəl ənd ˈpɪstəl əˌsəʊsiˈeɪʃən vɜːsəs ˈbruːən/", "pron": "nyoo york state RY-fuhl and PIS-tuhl uh-soh-see-AY-shuhn VUR-suhs BROO-uhn", "fr": "New York State Rifle & Pistol Association v. Bruen", "def": "The 2022 Supreme Court case limiting states’ ability to restrict public carry of firearms.", "ex": "Bruen made it harder for states to justify some gun restrictions."}, {"term": "constitutional interpretation", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ɪnˌtɜːprɪˈteɪʃən/", "pron": "kon-sti-TOO-shuh-nuhl in-tur-pri-TAY-shuhn", "fr": "interprétation constitutionnelle", "def": "The process of deciding what constitutional text means.", "ex": "Gun cases often depend on constitutional interpretation."}, {"term": "originalism", "ipa": "/əˈrɪdʒənəlɪzəm/", "pron": "uh-RIJ-uh-nuhl-iz-uhm", "fr": "originalisme", "def": "A method of constitutional interpretation based on original meaning.", "ex": "Originalism plays a major role in Second Amendment cases."}, {"term": "history-and-tradition test", "ipa": "/ˌhɪstəri ənd trəˈdɪʃən test/", "pron": "HIS-tuh-ree and truh-DISH-uhn test", "fr": "test de l’histoire et de la tradition", "def": "A legal test asking whether gun restrictions are consistent with historical firearm regulation.", "ex": "The history-and-tradition test changed how courts assess gun laws."}, {"term": "to regulate firearms", "ipa": "/ˈreɡjʊleɪt ˈfaɪərɑːmz/", "pron": "REG-yuh-layt FY-uhr-armz", "fr": "réglementer les armes à feu", "def": "To make rules controlling firearms.", "ex": "States have different powers to regulate firearms."}, {"term": "to restrict gun access", "ipa": "/rɪˈstrɪkt ˈɡʌn ˈækses/", "pron": "ri-STRIKT gun AK-sess", "fr": "restreindre l’accès aux armes", "def": "To limit who can obtain firearms.", "ex": "Gun control advocates want to restrict gun access for dangerous individuals."}, {"term": "to expand gun rights", "ipa": "/ɪkˈspænd ˈɡʌn raɪts/", "pron": "ik-SPAND gun rites", "fr": "élargir le droit aux armes", "def": "To broaden legal protections for firearm possession or carry.", "ex": "Some Supreme Court rulings have expanded gun rights."}, {"term": "to close loopholes", "ipa": "/kləʊz ˈluːphəʊlz/", "pron": "klohz LOOP-hohlz", "fr": "combler les failles juridiques", "def": "To remove gaps or weaknesses in the law.", "ex": "Reformers want to close loopholes in background check laws."}, {"term": "gun show loophole", "ipa": "/ˈɡʌn ʃəʊ ˈluːphəʊl/", "pron": "gun show LOOP-hohl", "fr": "faille des foires aux armes", "def": "A term for gaps allowing some firearm sales at gun shows without background checks.", "ex": "The gun show loophole is frequently mentioned in reform debates."}]}, {"title": "E. High-value verbs and exam-ready expressions", "entries": [{"term": "private sale loophole", "ipa": "/ˌpraɪvət ˈseɪl ˈluːphəʊl/", "pron": "PRY-vuht sayl LOOP-hohl", "fr": "faille des ventes privées", "def": "A gap allowing some private firearm sales without standard background checks.", "ex": "Universal background checks would close the private sale loophole."}, {"term": "to ban assault weapons", "ipa": "/bæn əˈsɔːlt ˌwepənz/", "pron": "ban uh-SAWLT WEP-uhnz", "fr": "interdire les armes d’assaut", "def": "To prohibit the sale or possession of certain semi-automatic firearms.", "ex": "Many Democrats want to ban assault weapons."}, {"term": "to arm teachers", "ipa": "/ɑːm ˈtiːtʃəz/", "pron": "arm TEE-chuhz", "fr": "armer les enseignants", "def": "To give teachers firearms or allow them to carry guns in schools.", "ex": "Some conservatives have suggested arming teachers after school shootings."}, {"term": "to harden schools", "ipa": "/ˈhɑːdən ˈskuːlz/", "pron": "HAR-duhn schoolz", "fr": "renforcer la sécurité des écoles", "def": "To increase school security through guards, doors, cameras or armed staff.", "ex": "Critics say hardening schools does not address easy gun access."}, {"term": "to prevent mass shootings", "ipa": "/prɪˈvent mæs ˈʃuːtɪŋz/", "pron": "pri-VENT mass SHOO-tingz", "fr": "prévenir les fusillades de masse", "def": "To take measures to stop mass shooting events.", "ex": "Red flag laws are designed to prevent mass shootings."}, {"term": "to reduce gun deaths", "ipa": "/rɪˈdjuːs ˈɡʌn deθs/", "pron": "ri-DYOOSS gun deths", "fr": "réduire les morts par armes à feu", "def": "To lower the number of deaths caused by firearms.", "ex": "Public health experts focus on reducing gun deaths."}, {"term": "to protect public safety", "ipa": "/prəˈtekt ˌpʌblɪk ˈseɪfti/", "pron": "pruh-TEKT PUB-lik SAYF-tee", "fr": "protéger la sécurité publique", "def": "To keep people safe from harm or violence.", "ex": "Supporters argue that gun restrictions protect public safety."}, {"term": "to infringe on rights", "ipa": "/ɪnˈfrɪndʒ ɒn raɪts/", "pron": "in-FRINJ on rites", "fr": "porter atteinte aux droits", "def": "To violate or limit rights unfairly.", "ex": "Opponents say gun control infringes on constitutional rights."}, {"term": "to balance rights and safety", "ipa": "/ˈbæləns raɪts ənd ˈseɪfti/", "pron": "BAL-uhns rites and SAYF-tee", "fr": "concilier droits et sécurité", "def": "To reconcile individual freedoms with collective security.", "ex": "The challenge is to balance rights and safety."}]}]}, {"id": "p2c19", "part": 2, "chapter": 19, "title": "Abortion", "file": "cpge_vocab_part2_chapter19_abortion_premium.html", "count": 103, "sections": [{"title": "A. Core vocabulary: pregnancy, rights and medical terms", "entries": [{"term": "abortion", "ipa": "/əˈbɔːʃən/", "pron": "uh-BOR-shuhn", "fr": "avortement", "def": "The medical ending of a pregnancy before birth.", "ex": "Abortion remains one of the most divisive issues in American politics."}, {"term": "abortion rights", "ipa": "/əˈbɔːʃən raɪts/", "pron": "uh-BOR-shuhn rites", "fr": "droits liés à l’avortement", "def": "Legal rights relating to access to abortion.", "ex": "Abortion rights became a major election issue after Roe v. Wade was overturned."}, {"term": "reproductive rights", "ipa": "/ˌriːprəˈdʌktɪv raɪts/", "pron": "ree-pruh-DUK-tiv rites", "fr": "droits reproductifs", "def": "Rights relating to contraception, pregnancy, abortion and reproductive healthcare.", "ex": "Activists framed abortion access as part of reproductive rights."}, {"term": "reproductive freedom", "ipa": "/ˌriːprəˈdʌktɪv ˈfriːdəm/", "pron": "ree-pruh-DUK-tiv FREE-duhm", "fr": "liberté reproductive", "def": "The freedom to make personal decisions about reproduction and pregnancy.", "ex": "Supporters argue that reproductive freedom is central to bodily autonomy."}, {"term": "bodily autonomy", "ipa": "/ˌbɒdɪli ɔːˈtɒnəmi/", "pron": "BOD-i-lee aw-TON-uh-mee", "fr": "autonomie corporelle", "def": "The right to make decisions about one’s own body.", "ex": "The debate often turns on bodily autonomy and state power."}, {"term": "pregnancy", "ipa": "/ˈpreɡnənsi/", "pron": "PREG-nuhn-see", "fr": "grossesse", "def": "The condition of carrying a developing embryo or foetus.", "ex": "Pregnancy can involve serious medical risks."}, {"term": "unwanted pregnancy", "ipa": "/ʌnˌwɒntɪd ˈpreɡnənsi/", "pron": "un-WON-tid PREG-nuhn-see", "fr": "grossesse non désirée", "def": "A pregnancy that a person does not wish to continue.", "ex": "Abortion bans can force people to carry unwanted pregnancies."}, {"term": "unplanned pregnancy", "ipa": "/ʌnˌplænd ˈpreɡnənsi/", "pron": "un-PLAND PREG-nuhn-see", "fr": "grossesse non planifiée", "def": "A pregnancy that was not intended or expected.", "ex": "Access to contraception can reduce unplanned pregnancies."}, {"term": "foetus", "ipa": "/ˈfiːtəs/", "pron": "FEE-tuhs", "fr": "fœtus", "def": "A developing unborn baby, especially after the early stages of pregnancy.", "ex": "The legal status of the foetus is central to abortion debates."}, {"term": "embryo", "ipa": "/ˈembriəʊ/", "pron": "EM-bree-oh", "fr": "embryon", "def": "A developing organism in the earliest stages of pregnancy.", "ex": "Some laws define personhood from the embryo stage."}, {"term": "viability", "ipa": "/ˌvaɪəˈbɪləti/", "pron": "vy-uh-BIL-uh-tee", "fr": "viabilité", "def": "The stage at which a foetus may survive outside the womb.", "ex": "Viability was once a key legal threshold in abortion law."}, {"term": "trimester", "ipa": "/traɪˈmestə/", "pron": "try-MES-tuh", "fr": "trimestre de grossesse", "def": "One of the three three-month stages of pregnancy.", "ex": "Earlier abortion law often referred to trimesters."}, {"term": "maternal health", "ipa": "/məˌtɜːnəl ˈhelθ/", "pron": "muh-TUR-nuhl helth", "fr": "santé maternelle", "def": "The health of a person during pregnancy, childbirth and the period after birth.", "ex": "Doctors warned that strict bans could endanger maternal health."}, {"term": "miscarriage", "ipa": "/ˈmɪskærɪdʒ/", "pron": "MIS-kar-ij", "fr": "fausse couche", "def": "The natural loss of a pregnancy before birth.", "ex": "Abortion restrictions can complicate miscarriage care."}, {"term": "ectopic pregnancy", "ipa": "/ekˌtɒpɪk ˈpreɡnənsi/", "pron": "ek-TOP-ik PREG-nuhn-see", "fr": "grossesse extra-utérine", "def": "A dangerous pregnancy occurring outside the uterus, usually requiring urgent treatment.", "ex": "An ectopic pregnancy can be life-threatening."}, {"term": "abortion access", "ipa": "/əˈbɔːʃən ˈækses/", "pron": "uh-BOR-shuhn AK-sess", "fr": "accès à l’avortement", "def": "The practical ability to obtain an abortion, not just the legal right.", "ex": "Abortion access varies dramatically from state to state."}, {"term": "abortion ban", "ipa": "/əˈbɔːʃən bæn/", "pron": "uh-BOR-shuhn ban", "fr": "interdiction de l’avortement", "def": "A law prohibiting abortion in most or all circumstances.", "ex": "Several states enacted abortion bans after Dobbs."}, {"term": "near-total ban", "ipa": "/ˌnɪə ˈtəʊtəl bæn/", "pron": "neer TOH-tuhl ban", "fr": "interdiction quasi totale", "def": "A ban allowing abortion only in very limited circumstances.", "ex": "The near-total ban included only narrow medical exceptions."}, {"term": "six-week ban", "ipa": "/ˌsɪks wiːk ˈbæn/", "pron": "six-week ban", "fr": "interdiction après six semaines", "def": "A law banning most abortions after about six weeks of pregnancy.", "ex": "Critics say a six-week ban applies before many people know they are pregnant."}, {"term": "heartbeat bill", "ipa": "/ˈhɑːtbiːt bɪl/", "pron": "HART-beet bil", "fr": "loi dite du battement de cœur", "def": "A law banning abortion once embryonic cardiac activity can be detected.", "ex": "Heartbeat bills have been passed in several conservative states."}, {"term": "trigger law", "ipa": "/ˈtrɪɡə lɔː/", "pron": "TRIG-uh law", "fr": "loi à déclenchement automatique", "def": "A law designed to take effect automatically if Roe v. Wade was overturned.", "ex": "Trigger laws took effect after the Dobbs decision."}, {"term": "gestational limit", "ipa": "/dʒeˈsteɪʃənəl ˈlɪmɪt/", "pron": "je-STAY-shuh-nuhl LIM-it", "fr": "limite gestationnelle", "def": "A legal limit based on how far a pregnancy has progressed.", "ex": "Many abortion laws set gestational limits."}, {"term": "medical exception", "ipa": "/ˈmedɪkəl ɪkˈsepʃən/", "pron": "MED-i-kuhl ik-SEP-shuhn", "fr": "exception médicale", "def": "An exception allowing abortion when the pregnant person’s health or life is at risk.", "ex": "Doctors criticised the law’s medical exception as unclear."}, {"term": "rape exception", "ipa": "/ˈreɪp ɪkˌsepʃən/", "pron": "rayp ik-SEP-shuhn", "fr": "exception en cas de viol", "def": "An exception allowing abortion when pregnancy results from rape.", "ex": "Some abortion bans do not include a rape exception."}, {"term": "incest exception", "ipa": "/ˈɪnsest ɪkˌsepʃən/", "pron": "IN-sest ik-SEP-shuhn", "fr": "exception en cas d’inceste", "def": "An exception allowing abortion when pregnancy results from incest.", "ex": "The law included rape and incest exceptions."}, {"term": "life of the mother exception", "ipa": "/ˌlaɪf əv ðə ˈmʌðər ɪkˌsepʃən/", "pron": "life ov thuh MUTH-uh ik-SEP-shuhn", "fr": "exception pour sauver la vie de la mère", "def": "An exception allowing abortion when the pregnant person’s life is endangered.", "ex": "The exception was criticised for leaving doctors uncertain."}, {"term": "abortion clinic", "ipa": "/əˈbɔːʃən ˈklɪnɪk/", "pron": "uh-BOR-shuhn KLIN-ik", "fr": "clinique pratiquant l’avortement", "def": "A medical facility where abortions are provided.", "ex": "Many abortion clinics closed after state bans."}, {"term": "provider", "ipa": "/prəˈvaɪdə/", "pron": "pruh-VY-duh", "fr": "prestataire de soins ; praticien", "def": "A doctor, clinic or organisation that provides healthcare services.", "ex": "Abortion providers faced legal uncertainty."}, {"term": "medication abortion", "ipa": "/ˌmedɪˈkeɪʃən əˈbɔːʃən/", "pron": "med-i-KAY-shuhn uh-BOR-shuhn", "fr": "avortement médicamenteux", "def": "Abortion using pills rather than surgery.", "ex": "Medication abortion has become central to post-Roe access."}, {"term": "abortion pill", "ipa": "/əˈbɔːʃən pɪl/", "pron": "uh-BOR-shuhn pil", "fr": "pilule abortive", "def": "A pill used as part of medication abortion.", "ex": "Legal battles over the abortion pill reached federal courts."}, {"term": "mifepristone", "ipa": "/mɪˈfeprɪstəʊn/", "pron": "mi-FEP-ri-stohn", "fr": "mifépristone", "def": "A drug used in medication abortion, often with misoprostol.", "ex": "Mifepristone access became a major legal issue."}, {"term": "misoprostol", "ipa": "/ˌmaɪsəʊˈprɒstɒl/", "pron": "my-soh-PROS-tol", "fr": "misoprostol", "def": "A drug used in medication abortion and miscarriage care.", "ex": "Misoprostol can also be used for miscarriage treatment."}, {"term": "surgical abortion", "ipa": "/ˈsɜːdʒɪkəl əˈbɔːʃən/", "pron": "SUR-ji-kuhl uh-BOR-shuhn", "fr": "avortement chirurgical", "def": "Abortion performed through a medical procedure rather than pills.", "ex": "Surgical abortion may be necessary later in pregnancy."}, {"term": "telemedicine abortion", "ipa": "/ˌtelɪˈmedɪsɪn əˈbɔːʃən/", "pron": "tel-i-MED-i-sin uh-BOR-shuhn", "fr": "avortement par télémédecine", "def": "Abortion care provided partly through remote medical consultation.", "ex": "Telemedicine abortion became more important after clinic closures."}, {"term": "self-managed abortion", "ipa": "/ˌself ˈmænɪdʒd əˈbɔːʃən/", "pron": "self MAN-ijd uh-BOR-shuhn", "fr": "avortement auto-géré", "def": "An abortion managed outside the formal medical system, often using pills.", "ex": "Self-managed abortion raises legal and safety questions."}, {"term": "crisis pregnancy centre", "ipa": "/ˌkraɪsɪs ˈpreɡnənsi ˈsentə/", "pron": "KRY-sis PREG-nuhn-see SEN-tuh", "fr": "centre anti-avortement se présentant comme aide à la grossesse", "def": "An organisation often discouraging abortion while presenting itself as pregnancy support.", "ex": "Critics accuse crisis pregnancy centres of misleading patients."}, {"term": "family planning", "ipa": "/ˌfæməli ˈplænɪŋ/", "pron": "FAM-uh-lee PLAN-ing", "fr": "planning familial", "def": "Services and information helping people control pregnancy and contraception.", "ex": "Family planning services reduce unintended pregnancies."}, {"term": "contraception", "ipa": "/ˌkɒntrəˈsepʃən/", "pron": "kon-truh-SEP-shuhn", "fr": "contraception", "def": "Methods used to prevent pregnancy.", "ex": "Access to contraception is closely linked to abortion rates."}, {"term": "birth control", "ipa": "/ˈbɜːθ kənˌtrəʊl/", "pron": "birth kuhn-TROHL", "fr": "contraception", "def": "Methods used to prevent pregnancy.", "ex": "Some conservatives have also challenged birth control access."}]}, {"title": "B. Roe, Dobbs and constitutional law", "entries": [{"term": "Roe v. Wade", "ipa": "/ˌrəʊ vɜːsəs ˈweɪd/", "pron": "roh VUR-suhs wayd", "fr": "Roe v. Wade", "def": "The 1973 Supreme Court ruling that recognised a constitutional right to abortion.", "ex": "Roe v. Wade shaped abortion law for nearly fifty years."}, {"term": "Dobbs v. Jackson Women’s Health Organization", "ipa": "/dɒbz vɜːsəs ˈdʒæksən ˈwɪmɪnz helθ ˌɔːɡənaɪˈzeɪʃən/", "pron": "dobz VUR-suhs JAK-suhn WIM-inz health or-guh-ny-ZAY-shuhn", "fr": "Dobbs v. Jackson Women’s Health Organization", "def": "The 2022 Supreme Court ruling that overturned Roe v. Wade.", "ex": "Dobbs returned abortion regulation largely to the states."}, {"term": "Planned Parenthood v. Casey", "ipa": "/plænd ˈpeərənhʊd vɜːsəs ˈkeɪsi/", "pron": "pland PAIR-uhn-hood VUR-suhs KAY-see", "fr": "Planned Parenthood v. Casey", "def": "The 1992 Supreme Court ruling that upheld Roe while allowing some restrictions.", "ex": "Casey introduced the undue burden standard."}, {"term": "undue burden", "ipa": "/ˌʌnˈdjuː ˈbɜːdən/", "pron": "un-DYOO BUR-duhn", "fr": "contrainte excessive ; obstacle indu", "def": "A legal standard from Casey: a restriction that places a substantial obstacle in the path of abortion access.", "ex": "The undue burden standard shaped abortion law before Dobbs."}, {"term": "constitutional right to abortion", "ipa": "/ˌkɒnstɪˈtjuːʃənəl raɪt tə əˈbɔːʃən/", "pron": "kon-sti-TOO-shuh-nuhl rite tuh uh-BOR-shuhn", "fr": "droit constitutionnel à l’avortement", "def": "A right to abortion protected by constitutional interpretation.", "ex": "Dobbs held that there was no federal constitutional right to abortion."}, {"term": "right to privacy", "ipa": "/ˌraɪt tə ˈprɪvəsi/", "pron": "rite tuh PRIV-uh-see", "fr": "droit à la vie privée", "def": "The right to personal autonomy and private life, used in earlier abortion jurisprudence.", "ex": "Roe was connected to the right to privacy."}, {"term": "substantive due process", "ipa": "/ˈsʌbstəntɪv ˌdjuː ˈprəʊses/", "pron": "SUB-stuhn-tiv dyoo PROH-sess", "fr": "due process substantiel", "def": "A doctrine protecting certain fundamental rights from government interference.", "ex": "Substantive due process has been central to privacy and liberty cases."}, {"term": "Fourteenth Amendment", "ipa": "/ˌfɔːˈtiːnθ əˈmendmənt/", "pron": "for-TEENTH uh-MEND-muhnt", "fr": "Quatorzième amendement", "def": "The constitutional amendment protecting citizenship, due process and equal protection.", "ex": "Earlier abortion rights were linked to the Fourteenth Amendment."}, {"term": "judicial precedent", "ipa": "/dʒuːˌdɪʃəl ˈpresɪdənt/", "pron": "joo-DISH-uhl PRES-i-duhnt", "fr": "précédent judiciaire", "def": "A previous court decision that guides future cases.", "ex": "Dobbs overturned a major judicial precedent."}, {"term": "stare decisis", "ipa": "/ˌsteəri dɪˈsaɪsɪs/", "pron": "STAIR-ee di-SY-sis", "fr": "stare decisis ; respect des précédents", "def": "The legal principle that courts should generally follow precedent.", "ex": "Critics argued that Dobbs weakened stare decisis."}, {"term": "to overturn Roe", "ipa": "/ˌəʊvəˈtɜːn ˈrəʊ/", "pron": "OH-vuh-turn roh", "fr": "renverser Roe v. Wade", "def": "To reverse the Roe v. Wade ruling.", "ex": "The Supreme Court voted to overturn Roe."}, {"term": "to uphold a restriction", "ipa": "/ʌpˈhəʊld ə rɪˈstrɪkʃən/", "pron": "up-HOHLD uh ri-STRIK-shuhn", "fr": "confirmer une restriction", "def": "For a court to decide that a restriction is legally valid.", "ex": "The Court upheld the state restriction."}, {"term": "to strike down a ban", "ipa": "/straɪk daʊn ə ˈbæn/", "pron": "stryke down uh ban", "fr": "annuler une interdiction", "def": "For a court to invalidate an abortion ban.", "ex": "A state court struck down the ban."}, {"term": "to return the issue to the states", "ipa": "/rɪˈtɜːn ði ˈɪʃuː tə ðə ˈsteɪts/", "pron": "ri-TURN thee ISH-oo tuh thuh stayts", "fr": "renvoyer la question aux États", "def": "To let states decide abortion policy instead of federal constitutional law.", "ex": "Dobbs returned the issue to the states."}, {"term": "state-by-state patchwork", "ipa": "/ˌsteɪt baɪ steɪt ˈpætʃwɜːk/", "pron": "state-by-state PATCH-wurk", "fr": "mosaïque État par État", "def": "A situation where abortion laws differ widely across states.", "ex": "Dobbs created a state-by-state patchwork of abortion access."}, {"term": "red state", "ipa": "/ˌred ˈsteɪt/", "pron": "red state", "fr": "État républicain", "def": "A US state that usually votes Republican.", "ex": "Many red states passed strict abortion bans."}, {"term": "blue state", "ipa": "/ˌbluː ˈsteɪt/", "pron": "bloo state", "fr": "État démocrate", "def": "A US state that usually votes Democratic.", "ex": "Blue states moved to protect abortion access."}]}, {"title": "C. State-by-state access and political geography", "entries": [{"term": "abortion haven", "ipa": "/əˈbɔːʃən ˈheɪvən/", "pron": "uh-BOR-shuhn HAY-vuhn", "fr": "refuge pour l’accès à l’avortement", "def": "A state or place where abortion remains accessible to people from restrictive states.", "ex": "Some blue states became abortion havens."}, {"term": "abortion desert", "ipa": "/əˈbɔːʃən ˈdezət/", "pron": "uh-BOR-shuhn DEZ-uht", "fr": "désert médical pour l’avortement", "def": "An area with little or no practical access to abortion services.", "ex": "Large parts of the South became abortion deserts."}, {"term": "interstate travel", "ipa": "/ˌɪntəsteɪt ˈtrævəl/", "pron": "IN-tuh-state TRAV-uhl", "fr": "déplacement entre États", "def": "Travel between states, often to access abortion services after bans.", "ex": "Interstate travel for abortion became politically contentious."}, {"term": "out-of-state care", "ipa": "/ˌaʊt əv steɪt ˈkeə/", "pron": "owt-ov-state care", "fr": "soins dans un autre État", "def": "Healthcare obtained in another state.", "ex": "Many patients had to seek out-of-state care."}, {"term": "shield law", "ipa": "/ˈʃiːld lɔː/", "pron": "sheeld law", "fr": "loi bouclier", "def": "A law protecting providers or patients from out-of-state abortion investigations.", "ex": "Some states passed shield laws to protect abortion providers."}, {"term": "extraterritorial enforcement", "ipa": "/ˌekstrəˌterɪˈtɔːriəl ɪnˈfɔːsmənt/", "pron": "ek-struh-ter-i-TOR-ee-uhl in-FORSS-muhnt", "fr": "application extraterritoriale", "def": "Attempts to apply a state’s law beyond its borders.", "ex": "Extraterritorial enforcement raised complex legal questions."}, {"term": "pro-choice", "ipa": "/ˌprəʊ ˈtʃɔɪs/", "pron": "proh choice", "fr": "pro-choice ; favorable au droit à l’avortement", "def": "Supporting legal access to abortion as a matter of choice and rights.", "ex": "Pro-choice campaigners defended reproductive freedom."}, {"term": "pro-life", "ipa": "/ˌprəʊ ˈlaɪf/", "pron": "proh life", "fr": "pro-life ; anti-avortement", "def": "Opposing abortion on the grounds of protecting unborn life.", "ex": "Pro-life activists celebrated the Dobbs ruling."}, {"term": "anti-abortion", "ipa": "/ˌænti əˈbɔːʃən/", "pron": "AN-tee uh-BOR-shuhn", "fr": "anti-avortement", "def": "Opposed to abortion.", "ex": "Anti-abortion groups pushed for stricter bans."}, {"term": "abortion opponent", "ipa": "/əˈbɔːʃən əˈpəʊnənt/", "pron": "uh-BOR-shuhn uh-POH-nuhnt", "fr": "opposant à l’avortement", "def": "A person who opposes abortion.", "ex": "Abortion opponents argue that life begins before birth."}, {"term": "abortion advocate", "ipa": "/əˈbɔːʃən ˈædvəkət/", "pron": "uh-BOR-shuhn AD-vuh-kuht", "fr": "défenseur du droit à l’avortement", "def": "A person who supports abortion rights or access.", "ex": "Abortion advocates warned of health risks after bans."}]}, {"title": "D. Political camps, values and elections", "entries": [{"term": "reproductive justice", "ipa": "/ˌriːprəˈdʌktɪv ˈdʒʌstɪs/", "pron": "ree-pruh-DUK-tiv JUS-tis", "fr": "justice reproductive", "def": "A framework linking reproductive rights to social justice, race, poverty and healthcare access.", "ex": "Reproductive justice emphasises inequality in access to care."}, {"term": "women’s rights", "ipa": "/ˈwɪmɪnz raɪts/", "pron": "WIM-inz rites", "fr": "droits des femmes", "def": "Rights concerning women’s equality, freedom and autonomy.", "ex": "Many see abortion access as a women’s rights issue."}, {"term": "gender equality", "ipa": "/ˌdʒendər iˈkwɒləti/", "pron": "JEN-duhr i-KWOL-uh-tee", "fr": "égalité de genre", "def": "Equal rights and opportunities regardless of gender.", "ex": "Abortion restrictions can affect gender equality."}, {"term": "religious conservatism", "ipa": "/rɪˌlɪdʒəs kənˈsɜːvətɪzəm/", "pron": "ri-LIJ-uhs kuhn-SUR-vuh-tiz-uhm", "fr": "conservatisme religieux", "def": "A political outlook based on conservative religious values.", "ex": "Religious conservatism has strongly shaped anti-abortion politics."}, {"term": "evangelical voters", "ipa": "/ˌiːvænˈdʒelɪkəl ˈvəʊtəz/", "pron": "ee-van-JEL-i-kuhl VOH-tuhz", "fr": "électeurs évangéliques", "def": "Voters belonging to or influenced by evangelical Christianity.", "ex": "Evangelical voters have been key to the anti-abortion movement."}, {"term": "Catholic voters", "ipa": "/ˈkæθəlɪk ˈvəʊtəz/", "pron": "KATH-uh-lik VOH-tuhz", "fr": "électeurs catholiques", "def": "Voters belonging to or influenced by Catholicism.", "ex": "Catholic voters are divided on abortion policy."}, {"term": "moral issue", "ipa": "/ˈmɒrəl ˈɪʃuː/", "pron": "MOR-uhl ISH-oo", "fr": "enjeu moral", "def": "An issue framed in terms of right and wrong.", "ex": "Abortion is often framed as a moral issue."}, {"term": "culture-war issue", "ipa": "/ˈkʌltʃə wɔː ˈɪʃuː/", "pron": "KUL-chuh war ISH-oo", "fr": "enjeu de guerre culturelle", "def": "A divisive issue linked to values, identity and social conflict.", "ex": "Abortion has become a defining culture-war issue."}, {"term": "single-issue voter", "ipa": "/ˌsɪŋɡəl ˈɪʃuː ˈvəʊtə/", "pron": "SING-guhl ISH-oo VOH-tuh", "fr": "électeur motivé par une seule question", "def": "A voter who bases their choice mainly on one issue.", "ex": "Some single-issue voters focus almost entirely on abortion."}, {"term": "gender gap", "ipa": "/ˈdʒendə ɡæp/", "pron": "JEN-duh gap", "fr": "écart hommes-femmes", "def": "A difference between men and women in political attitudes or voting.", "ex": "Dobbs may have widened the gender gap in some elections."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "réaction hostile ; retour de bâton", "def": "A strong negative reaction against a decision or social change.", "ex": "The ruling triggered a political backlash."}, {"term": "ballot measure", "ipa": "/ˈbælət ˌmeʒə/", "pron": "BAL-uht MEZH-uh", "fr": "référendum d’initiative ; mesure soumise au vote", "def": "A policy question directly voted on by citizens.", "ex": "Abortion ballot measures mobilised voters in several states."}, {"term": "referendum", "ipa": "/ˌrefəˈrendəm/", "pron": "ref-uh-REN-duhm", "fr": "référendum", "def": "A direct vote by citizens on a specific issue.", "ex": "The referendum protected abortion rights in the state constitution."}, {"term": "constitutional amendment at state level", "ipa": "/ˌkɒnstɪˈtjuːʃənəl əˈmendmənt ət steɪt ˈlevəl/", "pron": "kon-sti-TOO-shuh-nuhl uh-MEND-muhnt at state LEV-uhl", "fr": "amendement constitutionnel au niveau d’un État", "def": "A formal change to a state constitution.", "ex": "Voters approved a state constitutional amendment on abortion."}, {"term": "maternal mortality", "ipa": "/məˌtɜːnəl mɔːˈtæləti/", "pron": "muh-TUR-nuhl mor-TAL-uh-tee", "fr": "mortalité maternelle", "def": "Deaths related to pregnancy or childbirth.", "ex": "The US already has a high maternal mortality rate compared with similar countries."}, {"term": "healthcare access", "ipa": "/ˈhelθkeər ˈækses/", "pron": "HELTH-care AK-sess", "fr": "accès aux soins", "def": "The practical ability to obtain medical care.", "ex": "Abortion bans can worsen unequal healthcare access."}, {"term": "low-income women", "ipa": "/ˌləʊ ˈɪnkʌm ˈwɪmɪn/", "pron": "loh IN-kum WIM-in", "fr": "femmes à faibles revenus", "def": "Women with limited income or financial resources.", "ex": "Low-income women are disproportionately affected by travel costs."}]}, {"title": "E. Healthcare impact, legal risks and high-value verbs", "entries": [{"term": "rural women", "ipa": "/ˌrʊərəl ˈwɪmɪn/", "pron": "ROOR-uhl WIM-in", "fr": "femmes rurales", "def": "Women living in rural areas.", "ex": "Rural women may live far from abortion providers."}, {"term": "minority women", "ipa": "/maɪˈnɒrəti ˈwɪmɪn/", "pron": "my-NOR-uh-tee WIM-in", "fr": "femmes issues de minorités", "def": "Women belonging to racial, ethnic or other minority groups.", "ex": "Minority women often face greater barriers to healthcare."}, {"term": "medical uncertainty", "ipa": "/ˈmedɪkəl ʌnˈsɜːtənti/", "pron": "MED-i-kuhl un-SUR-tuhn-tee", "fr": "incertitude médicale", "def": "Unclear legal or clinical conditions affecting medical decisions.", "ex": "Medical uncertainty can delay emergency care."}, {"term": "chilling effect", "ipa": "/ˈtʃɪlɪŋ ɪˌfekt/", "pron": "CHIL-ing i-FEKT", "fr": "effet dissuasif ; effet paralysant", "def": "A situation where fear of punishment discourages lawful or necessary action.", "ex": "The threat of prosecution had a chilling effect on doctors."}, {"term": "criminal liability", "ipa": "/ˈkrɪmɪnəl ˌlaɪəˈbɪləti/", "pron": "KRIM-i-nuhl ly-uh-BIL-uh-tee", "fr": "responsabilité pénale", "def": "Legal responsibility for a crime.", "ex": "Doctors feared criminal liability under unclear abortion laws."}, {"term": "civil liability", "ipa": "/ˈsɪvəl ˌlaɪəˈbɪləti/", "pron": "SIV-uhl ly-uh-BIL-uh-tee", "fr": "responsabilité civile", "def": "Legal responsibility in a civil lawsuit rather than a criminal case.", "ex": "Some laws create civil liability for helping someone get an abortion."}, {"term": "bounty law", "ipa": "/ˈbaʊnti lɔː/", "pron": "BOWN-tee law", "fr": "loi à prime ; mécanisme de dénonciation privée", "def": "A law allowing private citizens to sue people who help provide banned abortions.", "ex": "Texas’s bounty law allowed private lawsuits against abortion providers."}, {"term": "to criminalise abortion", "ipa": "/ˈkrɪmɪnəlaɪz əˈbɔːʃən/", "pron": "KRIM-i-nuh-lyz uh-BOR-shuhn", "fr": "criminaliser l’avortement", "def": "To make abortion a crime.", "ex": "Activists warned that some states could criminalise abortion."}, {"term": "to protect abortion access", "ipa": "/prəˈtekt əˈbɔːʃən ˈækses/", "pron": "pruh-TEKT uh-BOR-shuhn AK-sess", "fr": "protéger l’accès à l’avortement", "def": "To defend or preserve the ability to obtain abortion care.", "ex": "Blue states moved to protect abortion access."}, {"term": "to restrict abortion access", "ipa": "/rɪˈstrɪkt əˈbɔːʃən ˈækses/", "pron": "ri-STRIKT uh-BOR-shuhn AK-sess", "fr": "restreindre l’accès à l’avortement", "def": "To limit the ability to obtain abortion care.", "ex": "Waiting periods and clinic regulations can restrict abortion access."}, {"term": "to ban abortion", "ipa": "/bæn əˈbɔːʃən/", "pron": "ban uh-BOR-shuhn", "fr": "interdire l’avortement", "def": "To prohibit abortion by law.", "ex": "Several states moved to ban abortion after Dobbs."}, {"term": "to codify Roe", "ipa": "/ˈkəʊdɪfaɪ ˈrəʊ/", "pron": "KOH-di-fy roh", "fr": "inscrire Roe dans la loi", "def": "To pass a law protecting abortion rights similar to Roe v. Wade.", "ex": "Democrats called on Congress to codify Roe."}, {"term": "to cross state lines", "ipa": "/krɒs steɪt laɪnz/", "pron": "kross state lynz", "fr": "franchir les frontières entre États", "def": "To travel from one state to another, often to access abortion care.", "ex": "Patients crossed state lines to obtain abortions."}, {"term": "to seek care out of state", "ipa": "/siːk keər aʊt əv steɪt/", "pron": "seek care out ov state", "fr": "chercher des soins dans un autre État", "def": "To obtain healthcare in another state.", "ex": "Many patients had to seek care out of state."}, {"term": "to prosecute providers", "ipa": "/ˈprɒsɪkjuːt prəˈvaɪdəz/", "pron": "PROS-i-kyoot pruh-VY-duhz", "fr": "poursuivre des prestataires de soins", "def": "To bring criminal charges against healthcare providers.", "ex": "Some laws threaten to prosecute providers."}, {"term": "to deter doctors", "ipa": "/dɪˈtɜː ˈdɒktəz/", "pron": "di-TUR DOK-tuhz", "fr": "dissuader les médecins", "def": "To discourage doctors from acting because of legal risk.", "ex": "Unclear laws may deter doctors from providing emergency care."}, {"term": "to mobilise voters", "ipa": "/ˈməʊbɪlaɪz ˈvəʊtəz/", "pron": "MOH-bi-lyz VOH-tuhz", "fr": "mobiliser les électeurs", "def": "To encourage voters to act or vote on an issue.", "ex": "Abortion rights mobilised voters in midterm elections."}, {"term": "to galvanise the electorate", "ipa": "/ˈɡælvənaɪz ði ɪˈlektərət/", "pron": "GAL-vuh-nyz thee i-LEK-tuh-ruht", "fr": "galvaniser l’électorat", "def": "To strongly motivate voters to take political action.", "ex": "The Dobbs decision galvanised the electorate."}, {"term": "to reshape American politics", "ipa": "/riːˈʃeɪp əˈmerɪkən ˈpɒlɪtɪks/", "pron": "ree-SHAYP uh-MER-i-kuhn POL-i-tiks", "fr": "remodeler la politique américaine", "def": "To significantly change American political debate or voting behaviour.", "ex": "The abortion issue has reshaped American politics."}]}]}, {"id": "p2c20", "part": 2, "chapter": 20, "title": "American Dream", "file": "cpge_vocab_part2_chapter20_american_dream_premium.html", "count": 124, "sections": [{"title": "A. Core concepts: dream, merit and opportunity", "entries": [{"term": "American Dream", "ipa": "/əˌmerɪkən ˈdriːm/", "pron": "uh-MER-i-kuhn dreem", "fr": "rêve américain", "def": "The belief that anyone in the United States can achieve success, prosperity and upward mobility through hard work.", "ex": "The American Dream remains powerful, but many argue that it has become harder to achieve."}, {"term": "upward mobility", "ipa": "/ˌʌpwəd məʊˈbɪləti/", "pron": "UP-wuhd moh-BIL-uh-tee", "fr": "ascension sociale", "def": "The ability to move to a higher social or economic position.", "ex": "Upward mobility is often presented as the promise of the American Dream."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes, either upward or downward.", "ex": "Declining social mobility challenges the idea of equal opportunity."}, {"term": "economic mobility", "ipa": "/ˌiːkəˈnɒmɪk məʊˈbɪləti/", "pron": "ee-kuh-NOM-ik moh-BIL-uh-tee", "fr": "mobilité économique", "def": "The ability to improve one’s economic position over time.", "ex": "Economic mobility depends heavily on education, housing and family wealth."}, {"term": "intergenerational mobility", "ipa": "/ˌɪntədʒenəˈreɪʃənəl məʊˈbɪləti/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl moh-BIL-uh-tee", "fr": "mobilité intergénérationnelle", "def": "The extent to which children achieve a different social or economic status from their parents.", "ex": "Intergenerational mobility has slowed in many parts of the United States."}, {"term": "rags to riches", "ipa": "/ˌræɡz tə ˈrɪtʃɪz/", "pron": "ragz tuh RICH-iz", "fr": "de la misère à la richesse", "def": "A story of rising from poverty to wealth.", "ex": "The rags-to-riches story is central to American mythology."}, {"term": "self-made man", "ipa": "/ˌself meɪd ˈmæn/", "pron": "self-made man", "fr": "self-made man ; homme qui s’est fait tout seul", "def": "A person who becomes successful through their own effort rather than inherited privilege.", "ex": "The self-made man is a classic figure of the American Dream."}, {"term": "self-made success", "ipa": "/ˌself meɪd səkˈses/", "pron": "self-made suhk-SESS", "fr": "réussite personnelle acquise par ses propres efforts", "def": "Success achieved through personal effort rather than family privilege.", "ex": "The billionaire presented himself as a self-made success."}, {"term": "meritocracy", "ipa": "/ˌmerɪˈtɒkrəsi/", "pron": "mer-i-TOK-ruh-see", "fr": "méritocratie", "def": "A system in which success is supposed to depend on talent and effort.", "ex": "The American Dream is often linked to meritocracy."}, {"term": "meritocratic ideal", "ipa": "/ˌmerɪtəˈkrætɪk aɪˈdɪəl/", "pron": "mer-i-tuh-KRAT-ik eye-DEE-uhl", "fr": "idéal méritocratique", "def": "The belief that people should succeed according to ability and hard work.", "ex": "The meritocratic ideal can hide structural inequalities."}, {"term": "hard work", "ipa": "/ˌhɑːd ˈwɜːk/", "pron": "hard work", "fr": "travail acharné", "def": "Great effort and dedication.", "ex": "The American Dream suggests that hard work should be rewarded."}, {"term": "work ethic", "ipa": "/ˈwɜːk ˌeθɪk/", "pron": "work ETH-ik", "fr": "éthique du travail", "def": "A belief in the moral value of hard work and discipline.", "ex": "The Protestant work ethic influenced American attitudes to success."}, {"term": "individual effort", "ipa": "/ˌɪndɪˈvɪdʒuəl ˈefət/", "pron": "in-di-VIJ-oo-uhl EF-uht", "fr": "effort individuel", "def": "Personal work, determination and responsibility.", "ex": "Supporters of the American Dream emphasise individual effort."}, {"term": "personal responsibility", "ipa": "/ˌpɜːsənəl rɪˌspɒnsəˈbɪləti/", "pron": "PUR-suh-nuhl ri-spon-suh-BIL-uh-tee", "fr": "responsabilité individuelle", "def": "The idea that individuals are responsible for their own choices and outcomes.", "ex": "Personal responsibility is a key theme in conservative accounts of success."}, {"term": "ambition", "ipa": "/æmˈbɪʃən/", "pron": "am-BISH-uhn", "fr": "ambition", "def": "A strong desire to succeed or achieve something.", "ex": "Ambition is often celebrated in American culture."}, {"term": "determination", "ipa": "/dɪˌtɜːmɪˈneɪʃən/", "pron": "di-tur-mi-NAY-shuhn", "fr": "détermination", "def": "The quality of continuing to work towards a goal despite difficulty.", "ex": "Determination is often portrayed as the key to success."}, {"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-yuhns", "fr": "résilience", "def": "The ability to recover from difficulties or setbacks.", "ex": "The American Dream celebrates resilience in the face of hardship."}, {"term": "opportunity", "ipa": "/ˌɒpəˈtjuːnəti/", "pron": "op-uh-TYOO-nuh-tee", "fr": "opportunité ; occasion", "def": "A chance to improve one’s life or achieve success.", "ex": "America has often been described as a land of opportunity."}, {"term": "land of opportunity", "ipa": "/ˌlænd əv ˌɒpəˈtjuːnəti/", "pron": "land ov op-uh-TYOO-nuh-tee", "fr": "terre d’opportunités", "def": "A phrase describing the United States as a place where people can succeed.", "ex": "For many immigrants, the US represented a land of opportunity."}, {"term": "equal opportunity", "ipa": "/ˌiːkwəl ˌɒpəˈtjuːnəti/", "pron": "EE-kwuhl op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "The principle that everyone should have the same chances to succeed.", "ex": "Equal opportunity is central to the promise of the American Dream."}, {"term": "equality of opportunity", "ipa": "/iˌkwɒləti əv ˌɒpəˈtjuːnəti/", "pron": "i-KWOL-uh-tee ov op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "The idea that people should have fair chances, regardless of background.", "ex": "The American Dream rests on equality of opportunity rather than equality of outcome."}, {"term": "equality of outcome", "ipa": "/iˌkwɒləti əv ˈaʊtkʌm/", "pron": "i-KWOL-uh-tee ov OWT-kum", "fr": "égalité des résultats", "def": "The idea that people should end up with similar results or living standards.", "ex": "Critics of redistribution often reject equality of outcome."}, {"term": "level playing field", "ipa": "/ˌlevəl ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl PLAY-ing field", "fr": "conditions équitables ; terrain de jeu égal", "def": "A fair situation in which everyone has the same chance to succeed.", "ex": "Many argue that America no longer offers a level playing field."}, {"term": "fair shot", "ipa": "/ˌfeə ˈʃɒt/", "pron": "fair shot", "fr": "chance équitable", "def": "A fair chance to succeed.", "ex": "Politicians often promise every child a fair shot."}, {"term": "life chances", "ipa": "/ˈlaɪf ˌtʃɑːnsɪz/", "pron": "life CHAN-siz", "fr": "chances dans la vie", "def": "The opportunities a person has for success, health, education and security.", "ex": "Life chances are strongly shaped by family background."}, {"term": "starting point", "ipa": "/ˈstɑːtɪŋ pɔɪnt/", "pron": "STAR-ting point", "fr": "point de départ", "def": "A person’s initial social or economic position in life.", "ex": "Not everyone begins from the same starting point."}, {"term": "birth lottery", "ipa": "/ˈbɜːθ ˌlɒtəri/", "pron": "birth LOT-uh-ree", "fr": "loterie de la naissance", "def": "The idea that life outcomes are heavily shaped by the circumstances into which someone is born.", "ex": "The birth lottery contradicts the myth of pure meritocracy."}, {"term": "American exceptionalism", "ipa": "/əˌmerɪkən ɪkˈsepʃənəlɪzəm/", "pron": "uh-MER-i-kuhn ik-SEP-shuh-nuh-liz-uhm", "fr": "exceptionnalisme américain", "def": "The belief that the United States is uniquely free, successful or morally special.", "ex": "The American Dream is closely linked to American exceptionalism."}, {"term": "frontier spirit", "ipa": "/ˈfrʌntɪə ˈspɪrɪt/", "pron": "FRUN-teer SPIR-it", "fr": "esprit de la frontière", "def": "The cultural ideal of independence, risk-taking and expansion associated with the frontier.", "ex": "The frontier spirit shaped myths of self-reliance."}, {"term": "self-reliance", "ipa": "/ˌself rɪˈlaɪəns/", "pron": "self ri-LY-uhns", "fr": "autosuffisance ; autonomie", "def": "The ability or belief in depending on oneself rather than others.", "ex": "Self-reliance is a major American cultural value."}, {"term": "rugged individualism", "ipa": "/ˌrʌɡɪd ˌɪndɪˈvɪdʒuəlɪzəm/", "pron": "RUG-id in-di-VIJ-oo-uh-liz-uhm", "fr": "individualisme farouche", "def": "A strong belief in individual independence and limited reliance on government.", "ex": "Rugged individualism can make welfare policies politically controversial."}, {"term": "pursuit of happiness", "ipa": "/pəˌsjuːt əv ˈhæpinəs/", "pron": "puh-SYOOT ov HAP-ee-nuhs", "fr": "quête du bonheur", "def": "A phrase from the Declaration of Independence referring to the right to seek fulfilment.", "ex": "The pursuit of happiness is part of America’s founding language."}, {"term": "founding myth", "ipa": "/ˈfaʊndɪŋ mɪθ/", "pron": "FOWN-ding myth", "fr": "mythe fondateur", "def": "A story that helps define a nation’s identity and values.", "ex": "The American Dream functions as a founding myth."}, {"term": "national myth", "ipa": "/ˌnæʃənəl ˈmɪθ/", "pron": "NASH-uh-nuhl myth", "fr": "mythe national", "def": "A widely shared story about a nation’s identity, often simplified or idealised.", "ex": "The national myth of opportunity hides many inequalities."}, {"term": "promise of America", "ipa": "/ˈprɒmɪs əv əˈmerɪkə/", "pron": "PROM-is ov uh-MER-i-kuh", "fr": "promesse américaine", "def": "The ideal that America offers freedom, opportunity and dignity.", "ex": "Civil rights leaders demanded that America fulfil the promise of America."}, {"term": "upward climb", "ipa": "/ˌʌpwəd ˈklaɪm/", "pron": "UP-wuhd klyme", "fr": "ascension sociale difficile", "def": "The struggle to rise socially or economically.", "ex": "For many families, the upward climb has become steeper."}]}, {"title": "B. Class, wealth and economic inequality", "entries": [{"term": "middle class", "ipa": "/ˌmɪdəl ˈklɑːs/", "pron": "MID-uhl klass", "fr": "classe moyenne", "def": "The social group between the working class and the wealthy, often associated with stability and comfort.", "ex": "Homeownership has long been a marker of middle-class success."}, {"term": "working class", "ipa": "/ˌwɜːkɪŋ ˈklɑːs/", "pron": "WUR-king klass", "fr": "classe ouvrière ; classes populaires", "def": "People employed in manual, service or lower-paid work, often with less economic security.", "ex": "Many working-class Americans feel the Dream has slipped away."}, {"term": "lower class", "ipa": "/ˌləʊə ˈklɑːs/", "pron": "LOH-uh klass", "fr": "classe défavorisée", "def": "A social group with low income, wealth and status.", "ex": "Class labels are often avoided in American political rhetoric."}, {"term": "upper class", "ipa": "/ˌʌpə ˈklɑːs/", "pron": "UP-uh klass", "fr": "classe supérieure", "def": "The wealthiest and most privileged social group.", "ex": "The upper class benefits from inherited wealth and elite networks."}, {"term": "elite", "ipa": "/ɪˈliːt/", "pron": "i-LEET", "fr": "élite", "def": "A small group with significant wealth, power or status.", "ex": "The American Dream is often criticised for favouring the elite."}, {"term": "wealth", "ipa": "/welθ/", "pron": "welth", "fr": "patrimoine ; richesse", "def": "Assets and resources owned by a person or household.", "ex": "Wealth matters more than income for long-term security."}, {"term": "income", "ipa": "/ˈɪnkʌm/", "pron": "IN-kum", "fr": "revenu", "def": "Money received from work, investments or benefits.", "ex": "Income inequality has increased in recent decades."}, {"term": "wealth gap", "ipa": "/ˈwelθ ɡæp/", "pron": "welth gap", "fr": "écart de patrimoine", "def": "The difference in wealth between groups.", "ex": "The wealth gap limits social mobility."}, {"term": "income inequality", "ipa": "/ˈɪnkʌm ˌɪnɪˈkwɒləti/", "pron": "IN-kum in-i-KWOL-uh-tee", "fr": "inégalité de revenus", "def": "Unequal distribution of income across society.", "ex": "Income inequality undermines belief in the American Dream."}, {"term": "wealth inequality", "ipa": "/ˈwelθ ˌɪnɪˈkwɒləti/", "pron": "welth in-i-KWOL-uh-tee", "fr": "inégalité patrimoniale", "def": "Unequal distribution of assets and wealth.", "ex": "Wealth inequality can reproduce privilege across generations."}, {"term": "racial wealth gap", "ipa": "/ˌreɪʃəl ˈwelθ ɡæp/", "pron": "RAY-shuhl welth gap", "fr": "écart de patrimoine racial", "def": "The difference in accumulated wealth between racial groups.", "ex": "The racial wealth gap reveals the limits of equal opportunity."}, {"term": "class divide", "ipa": "/ˈklɑːs dɪˌvaɪd/", "pron": "klass di-VYDE", "fr": "fracture de classe", "def": "A social division between classes.", "ex": "The class divide has become more visible in debates about education."}, {"term": "social ladder", "ipa": "/ˌsəʊʃəl ˈlædə/", "pron": "SOH-shuhl LAD-uh", "fr": "échelle sociale", "def": "A metaphor for moving up or down in social status.", "ex": "Education is often seen as a way up the social ladder."}, {"term": "glass ceiling", "ipa": "/ˌɡlɑːs ˈsiːlɪŋ/", "pron": "glass SEE-ling", "fr": "plafond de verre", "def": "An invisible barrier preventing certain groups from reaching top positions.", "ex": "The glass ceiling limits women and minorities in elite careers."}, {"term": "sticky floor", "ipa": "/ˌstɪki ˈflɔː/", "pron": "STIK-ee floor", "fr": "plancher collant ; blocage dans les emplois précaires", "def": "A situation where people remain trapped in low-paid or low-status jobs.", "ex": "The sticky floor prevents many workers from moving up."}, {"term": "poverty trap", "ipa": "/ˈpɒvəti træp/", "pron": "POV-uh-tee trap", "fr": "piège de la pauvreté", "def": "A situation in which poverty makes it difficult to escape poverty.", "ex": "Debt and low wages can create a poverty trap."}, {"term": "cycle of poverty", "ipa": "/ˌsaɪkəl əv ˈpɒvəti/", "pron": "SY-kuhl ov POV-uh-tee", "fr": "cycle de la pauvreté", "def": "The repeated transmission of poverty from one generation to the next.", "ex": "The cycle of poverty challenges the promise of mobility."}, {"term": "working poor", "ipa": "/ˌwɜːkɪŋ ˈpɔː/", "pron": "WUR-king poor", "fr": "travailleurs pauvres", "def": "People who work but remain poor because wages are low or costs are high.", "ex": "The working poor reveal that hard work does not always guarantee security."}, {"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal hourly pay.", "ex": "A low minimum wage can make the American Dream unreachable."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "Campaigners argue that workers deserve a living wage."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "emploi précaire", "def": "Unstable or insecure work with low protection.", "ex": "Precarious work makes upward mobility harder."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots ; gig economy", "def": "A labour market based on short-term, freelance or platform-based work.", "ex": "The gig economy offers flexibility but little security."}, {"term": "economic insecurity", "ipa": "/ˌiːkəˈnɒmɪk ˌɪnsɪˈkjʊərəti/", "pron": "ee-kuh-NOM-ik in-si-KYOOR-uh-tee", "fr": "insécurité économique", "def": "Uncertainty about income, work, housing or financial stability.", "ex": "Economic insecurity has weakened faith in the American Dream."}, {"term": "cost of living", "ipa": "/ˌkɒst əv ˈlɪvɪŋ/", "pron": "kost ov LIV-ing", "fr": "coût de la vie", "def": "The amount of money needed to pay for basic expenses.", "ex": "The rising cost of living makes it harder to save."}, {"term": "homeownership", "ipa": "/ˈhəʊmˌəʊnəʃɪp/", "pron": "HOHM-oh-nuh-ship", "fr": "accession à la propriété ; propriété immobilière", "def": "The state of owning one’s home.", "ex": "Homeownership has long symbolised the American Dream."}, {"term": "property ownership", "ipa": "/ˈprɒpəti ˌəʊnəʃɪp/", "pron": "PROP-uh-tee OH-nuh-ship", "fr": "propriété immobilière", "def": "The legal ownership of land or housing.", "ex": "Property ownership is a major source of wealth."}]}, {"title": "C. Housing, education, debt and the safety net", "entries": [{"term": "suburbs", "ipa": "/ˈsʌbɜːbz/", "pron": "SUB-urbz", "fr": "banlieues résidentielles", "def": "Residential areas outside a city.", "ex": "The suburbs became a symbol of postwar middle-class success."}, {"term": "suburban life", "ipa": "/səˈbɜːbən laɪf/", "pron": "suh-BUR-buhn life", "fr": "vie en banlieue résidentielle", "def": "Life in residential areas outside the city, often associated with family, comfort and homeownership.", "ex": "Suburban life was once central to the American Dream."}, {"term": "white picket fence", "ipa": "/ˌwaɪt ˈpɪkɪt fens/", "pron": "white PIK-it fens", "fr": "clôture blanche ; symbole du rêve pavillonnaire", "def": "A symbol of suburban homeownership, family life and middle-class stability.", "ex": "The white picket fence became an image of the traditional American Dream."}, {"term": "mortgage", "ipa": "/ˈmɔːɡɪdʒ/", "pron": "MOR-gij", "fr": "prêt immobilier", "def": "A loan used to buy a house.", "ex": "Higher interest rates make mortgages less affordable."}, {"term": "housing affordability", "ipa": "/ˈhaʊzɪŋ əˌfɔːdəˈbɪləti/", "pron": "HOW-zing uh-for-duh-BIL-uh-tee", "fr": "accessibilité financière du logement", "def": "The extent to which people can afford housing.", "ex": "Housing affordability is a major barrier to the American Dream."}, {"term": "rent burden", "ipa": "/ˈrent ˌbɜːdən/", "pron": "rent BUR-duhn", "fr": "poids du loyer", "def": "A situation in which rent takes up a large share of income.", "ex": "Rent burden prevents many households from saving."}, {"term": "student debt", "ipa": "/ˈstjuːdənt det/", "pron": "STYOO-duhnt det", "fr": "dette étudiante", "def": "Money borrowed to pay for higher education.", "ex": "Student debt can delay homeownership and family formation."}, {"term": "college degree", "ipa": "/ˈkɒlɪdʒ dɪˌɡriː/", "pron": "KOL-ij di-GREE", "fr": "diplôme universitaire", "def": "A qualification awarded by a college or university.", "ex": "A college degree is often seen as a path to mobility."}, {"term": "higher education", "ipa": "/ˌhaɪər ˌedjʊˈkeɪʃən/", "pron": "HY-uhr ej-yoo-KAY-shuhn", "fr": "enseignement supérieur", "def": "Education at college or university level.", "ex": "Higher education can create opportunity but also debt."}, {"term": "elite university", "ipa": "/eɪˌliːt ˌjuːnɪˈvɜːsəti/", "pron": "ay-LEET yoo-ni-VUR-suh-tee", "fr": "université d’élite", "def": "A highly selective and prestigious university.", "ex": "Elite universities can reproduce social privilege."}, {"term": "legacy admission", "ipa": "/ˈleɡəsi ədˌmɪʃən/", "pron": "LEG-uh-see ad-MISH-uhn", "fr": "admission favorisant les anciens élèves", "def": "Preferential admission for applicants whose family members attended the institution.", "ex": "Legacy admissions contradict meritocratic ideals."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to improve opportunities for groups historically discriminated against.", "ex": "Affirmative action has been defended as a way to widen opportunity."}, {"term": "school funding", "ipa": "/ˈskuːl ˌfʌndɪŋ/", "pron": "school FUN-ding", "fr": "financement des écoles", "def": "Money available to schools, often tied to local property taxes in the US.", "ex": "Unequal school funding limits equal opportunity."}, {"term": "educational inequality", "ipa": "/ˌedjʊˈkeɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "ej-yoo-KAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité éducative", "def": "Unequal access to good education.", "ex": "Educational inequality is a major obstacle to social mobility."}, {"term": "achievement gap", "ipa": "/əˈtʃiːvmənt ɡæp/", "pron": "uh-CHEEV-muhnt gap", "fr": "écart de réussite scolaire", "def": "Differences in educational performance between groups.", "ex": "The achievement gap often reflects poverty and unequal resources."}, {"term": "opportunity gap", "ipa": "/ˌɒpəˈtjuːnəti ɡæp/", "pron": "op-uh-TYOO-nuh-tee gap", "fr": "écart d’opportunités", "def": "Unequal access to opportunities that shape success.", "ex": "The opportunity gap begins long before college."}, {"term": "healthcare costs", "ipa": "/ˈhelθkeə kɒsts/", "pron": "HELTH-care kosts", "fr": "coûts de santé", "def": "The money people must pay for medical care.", "ex": "Healthcare costs can push families into debt."}, {"term": "medical debt", "ipa": "/ˈmedɪkəl det/", "pron": "MED-i-kuhl det", "fr": "dette médicale", "def": "Debt caused by medical bills.", "ex": "Medical debt can destroy financial security."}, {"term": "safety net", "ipa": "/ˈseɪfti net/", "pron": "SAYF-tee net", "fr": "filet de sécurité sociale", "def": "Government programmes that protect people from extreme poverty or hardship.", "ex": "A weak safety net can make failure more punishing."}, {"term": "welfare", "ipa": "/ˈwelfeə/", "pron": "WEL-fair", "fr": "aide sociale ; prestations sociales", "def": "Government support for people with low income or in need.", "ex": "Welfare is often politically controversial in the United States."}, {"term": "social security", "ipa": "/ˌsəʊʃəl sɪˈkjʊərəti/", "pron": "SOH-shuhl si-KYOOR-uh-tee", "fr": "sécurité sociale américaine ; retraite publique", "def": "A US federal programme providing income support, especially for retirees and disabled people.", "ex": "Social Security protects millions of older Americans from poverty."}, {"term": "food stamps", "ipa": "/ˈfuːd stæmps/", "pron": "food stamps", "fr": "bons alimentaires ; aide alimentaire", "def": "A common term for government food assistance for low-income people.", "ex": "Food stamps help families afford groceries."}]}, {"title": "D. The Dream in crisis: decline, work and insecurity", "entries": [{"term": "Medicaid", "ipa": "/ˈmedɪkeɪd/", "pron": "MED-i-kayd", "fr": "Medicaid ; assurance santé pour bas revenus", "def": "A public health insurance programme for low-income people in the US.", "ex": "Medicaid expansion improved healthcare access in some states."}, {"term": "bootstrap narrative", "ipa": "/ˈbuːtstræp ˈnærətɪv/", "pron": "BOOT-strap NAR-uh-tiv", "fr": "récit de réussite par ses propres moyens", "def": "The story that people can succeed purely by their own effort.", "ex": "The bootstrap narrative can blame the poor for structural problems."}, {"term": "to pull oneself up by one’s bootstraps", "ipa": "/pʊl wʌnˈself ʌp baɪ wʌnz ˈbuːtstræps/", "pron": "pull wun-SELF up by wunz BOOT-straps", "fr": "s’en sortir par ses propres moyens", "def": "To improve one’s situation through one’s own effort, without help.", "ex": "Politicians often praise people who pull themselves up by their bootstraps."}, {"term": "myth of meritocracy", "ipa": "/ˌmɪθ əv ˌmerɪˈtɒkrəsi/", "pron": "mith ov mer-i-TOK-ruh-see", "fr": "mythe de la méritocratie", "def": "The idea that meritocracy is more imagined than real because inequality shapes outcomes.", "ex": "The myth of meritocracy hides inherited privilege."}, {"term": "broken ladder", "ipa": "/ˌbrəʊkən ˈlædə/", "pron": "BROH-kuhn LAD-uh", "fr": "échelle sociale brisée", "def": "A metaphor suggesting that upward mobility has become difficult or impossible.", "ex": "For many Americans, the social ladder feels broken."}, {"term": "American Dream in decline", "ipa": "/əˌmerɪkən ˈdriːm ɪn dɪˈklaɪn/", "pron": "uh-MER-i-kuhn dreem in di-KLYNE", "fr": "déclin du rêve américain", "def": "The idea that the American Dream is weakening or becoming less achievable.", "ex": "Many commentators describe the American Dream as in decline."}, {"term": "dream deferred", "ipa": "/ˌdriːm dɪˈfɜːd/", "pron": "dreem di-FURD", "fr": "rêve différé ; espoir repoussé", "def": "A delayed or frustrated hope for equality or success, echoing Langston Hughes.", "ex": "For many minorities, the American Dream has long been a dream deferred."}, {"term": "disillusionment", "ipa": "/ˌdɪsɪˈluːʒənmənt/", "pron": "dis-i-LOO-zhuhn-muhnt", "fr": "désillusion", "def": "A feeling of disappointment after losing faith in an ideal.", "ex": "Economic insecurity has produced disillusionment with the American Dream."}, {"term": "downward mobility", "ipa": "/ˌdaʊnwəd məʊˈbɪləti/", "pron": "DOWN-wuhd moh-BIL-uh-tee", "fr": "déclassement ; mobilité descendante", "def": "Movement to a lower social or economic position.", "ex": "Fear of downward mobility fuels political anxiety."}, {"term": "left behind", "ipa": "/ˌleft bɪˈhaɪnd/", "pron": "left bi-HYND", "fr": "laissés pour compte", "def": "People or communities that have not benefited from economic or social change.", "ex": "Many voters feel left behind by globalisation."}, {"term": "forgotten Americans", "ipa": "/fəˌɡɒtən əˈmerɪkənz/", "pron": "fuh-GOT-uhn uh-MER-i-kuhnz", "fr": "Américains oubliés", "def": "Citizens who feel ignored by political and economic elites.", "ex": "Populist campaigns often appeal to forgotten Americans."}, {"term": "economic anxiety", "ipa": "/ˌiːkəˈnɒmɪk æŋˈzaɪəti/", "pron": "ee-kuh-NOM-ik ang-ZY-uh-tee", "fr": "anxiété économique", "def": "Worry about jobs, wages, debt or living standards.", "ex": "Economic anxiety has shaped recent elections."}, {"term": "deindustrialisation", "ipa": "/diːɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "dee-in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "désindustrialisation", "def": "The decline of manufacturing industries in a region or country.", "ex": "Deindustrialisation weakened many working-class communities."}, {"term": "Rust Belt", "ipa": "/ˈrʌst belt/", "pron": "rust belt", "fr": "Rust Belt ; ceinture de la rouille", "def": "A region in the northern US affected by industrial decline.", "ex": "The Rust Belt became a symbol of economic decline."}, {"term": "blue-collar worker", "ipa": "/ˌbluː ˈkɒlə ˈwɜːkə/", "pron": "bloo KOL-uh WUR-kuh", "fr": "ouvrier ; travailleur manuel", "def": "A worker doing manual, industrial or service work.", "ex": "Blue-collar workers once had a clearer path to middle-class life."}, {"term": "white-collar worker", "ipa": "/ˌwaɪt ˈkɒlə ˈwɜːkə/", "pron": "white KOL-uh WUR-kuh", "fr": "employé de bureau ; col blanc", "def": "A worker doing office, professional or administrative work.", "ex": "White-collar jobs usually require more formal education."}, {"term": "middle-class squeeze", "ipa": "/ˌmɪdəl klɑːs ˈskwiːz/", "pron": "MID-uhl klass skweez", "fr": "pression sur la classe moyenne", "def": "Pressure on middle-class households from stagnant wages and rising costs.", "ex": "The middle-class squeeze has weakened confidence in the American Dream."}, {"term": "wage stagnation", "ipa": "/ˈweɪdʒ stæɡˌneɪʃən/", "pron": "wayj stag-NAY-shuhn", "fr": "stagnation des salaires", "def": "A situation where wages do not rise much over time.", "ex": "Wage stagnation makes upward mobility harder."}, {"term": "income stagnation", "ipa": "/ˈɪnkʌm stæɡˌneɪʃən/", "pron": "IN-kum stag-NAY-shuhn", "fr": "stagnation des revenus", "def": "A situation where household income stops growing.", "ex": "Income stagnation has affected many middle-class families."}, {"term": "outsourcing", "ipa": "/ˈaʊtsɔːsɪŋ/", "pron": "OWT-sor-sing", "fr": "externalisation ; délocalisation", "def": "Moving jobs or business activities to outside companies or other countries.", "ex": "Outsourcing contributed to job losses in manufacturing towns."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "The use of machines or technology to perform tasks once done by humans.", "ex": "Automation threatens some traditional pathways to middle-class employment."}, {"term": "entrepreneurship", "ipa": "/ˌɒntrəprəˈnɜːʃɪp/", "pron": "on-truh-pruh-NUR-ship", "fr": "entrepreneuriat", "def": "The activity of starting and running businesses.", "ex": "Entrepreneurship is often celebrated as a route to the American Dream."}]}, {"title": "E. High-value verbs and exam-ready expressions", "entries": [{"term": "small business owner", "ipa": "/ˌsmɔːl ˈbɪznəs ˌəʊnə/", "pron": "small BIZ-nuhs OH-nuh", "fr": "propriétaire de petite entreprise", "def": "A person who owns and runs a small company.", "ex": "The small business owner is a familiar American Dream figure."}, {"term": "start-up culture", "ipa": "/ˈstɑːt ʌp ˌkʌltʃə/", "pron": "START-up KUL-chuh", "fr": "culture des start-up", "def": "A culture celebrating innovation, entrepreneurship and rapid business growth.", "ex": "Start-up culture offers a modern version of the American Dream."}, {"term": "Silicon Valley", "ipa": "/ˌsɪlɪkən ˈvæli/", "pron": "SIL-i-kuhn VAL-ee", "fr": "Silicon Valley", "def": "A region in California associated with technology companies and start-ups.", "ex": "Silicon Valley promotes a high-tech version of self-made success."}, {"term": "to achieve the American Dream", "ipa": "/əˈtʃiːv ði əˌmerɪkən ˈdriːm/", "pron": "uh-CHEEV thee uh-MER-i-kuhn dreem", "fr": "réaliser le rêve américain", "def": "To reach the prosperity, freedom or success associated with the American Dream.", "ex": "Many families still hope to achieve the American Dream."}, {"term": "to climb the social ladder", "ipa": "/klaɪm ðə ˌsəʊʃəl ˈlædə/", "pron": "klyme thuh SOH-shuhl LAD-uh", "fr": "gravir l’échelle sociale", "def": "To rise in social or economic status.", "ex": "Education is often seen as the best way to climb the social ladder."}, {"term": "to rise from poverty", "ipa": "/raɪz frəm ˈpɒvəti/", "pron": "ryze frum POV-uh-tee", "fr": "sortir de la pauvreté", "def": "To move from poverty to a better economic situation.", "ex": "The novel tells the story of a family rising from poverty."}, {"term": "to break the cycle of poverty", "ipa": "/breɪk ðə ˌsaɪkəl əv ˈpɒvəti/", "pron": "brayk thuh SY-kuhl ov POV-uh-tee", "fr": "briser le cycle de la pauvreté", "def": "To stop poverty from being passed from one generation to the next.", "ex": "Early education can help break the cycle of poverty."}, {"term": "to widen the opportunity gap", "ipa": "/ˈwaɪdən ði ˌɒpəˈtjuːnəti ɡæp/", "pron": "WY-duhn thee op-uh-TYOO-nuh-tee gap", "fr": "creuser l’écart d’opportunités", "def": "To increase unequal access to chances for success.", "ex": "Unequal schools widen the opportunity gap."}, {"term": "to level the playing field", "ipa": "/ˈlevəl ðə ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl thuh PLAY-ing field", "fr": "rendre les conditions plus équitables", "def": "To make conditions fairer for everyone.", "ex": "Public investment can help level the playing field."}, {"term": "to inherit privilege", "ipa": "/ɪnˈherɪt ˈprɪvəlɪdʒ/", "pron": "in-HER-it PRIV-uh-lij", "fr": "hériter d’un privilège", "def": "To receive advantages because of family background.", "ex": "Many elite students inherit privilege rather than earn it."}, {"term": "to reproduce inequality", "ipa": "/ˌriːprəˈdjuːs ˌɪnɪˈkwɒləti/", "pron": "ree-pruh-DYOOSS in-i-KWOL-uh-tee", "fr": "reproduire les inégalités", "def": "To cause inequality to continue across time or generations.", "ex": "The education system can reproduce inequality."}, {"term": "to reward hard work", "ipa": "/rɪˈwɔːd ˌhɑːd ˈwɜːk/", "pron": "ri-WARD hard work", "fr": "récompenser le travail acharné", "def": "To give success or compensation in return for effort.", "ex": "The American Dream assumes that society rewards hard work."}, {"term": "to fall behind", "ipa": "/fɔːl bɪˈhaɪnd/", "pron": "fall bi-HYND", "fr": "prendre du retard ; être laissé derrière", "def": "To fail to keep up economically, socially or educationally.", "ex": "Families fall behind when wages stagnate and costs rise."}, {"term": "to make ends meet", "ipa": "/meɪk endz ˈmiːt/", "pron": "mayk endz meet", "fr": "joindre les deux bouts", "def": "To have just enough money to pay for basic needs.", "ex": "Many workers struggle to make ends meet."}, {"term": "to live paycheck to paycheck", "ipa": "/lɪv ˈpeɪtʃek tə ˈpeɪtʃek/", "pron": "liv PAY-chek tuh PAY-chek", "fr": "vivre d’un salaire à l’autre", "def": "To spend nearly all income before the next wage payment arrives.", "ex": "Millions of Americans live paycheck to paycheck."}, {"term": "to own a home", "ipa": "/əʊn ə ˈhəʊm/", "pron": "ohn uh hohm", "fr": "être propriétaire de son logement", "def": "To possess one’s house or apartment.", "ex": "Owning a home has long symbolised middle-class stability."}, {"term": "to be priced out", "ipa": "/bi praɪst ˈaʊt/", "pron": "bee pryst owt", "fr": "être exclu par les prix", "def": "To be unable to afford something because prices have become too high.", "ex": "Young families are being priced out of the housing market."}, {"term": "to question the American Dream", "ipa": "/ˈkwestʃən ði əˌmerɪkən ˈdriːm/", "pron": "KWES-chuhn thee uh-MER-i-kuhn dreem", "fr": "remettre en question le rêve américain", "def": "To doubt whether the American Dream is still real or achievable.", "ex": "Rising inequality has led many to question the American Dream."}]}]}, {"id": "p2c21", "part": 2, "chapter": 21, "title": "Culture Wars", "file": "cpge_vocab_part2_chapter21_culture_wars_premium.html", "count": 121, "sections": [{"title": "A. Core culture-war vocabulary and political divides", "entries": [{"term": "culture wars", "ipa": "/ˈkʌltʃə wɔːz/", "pron": "KUL-chuh warz", "fr": "guerres culturelles", "def": "Political conflicts over values, identity, morality, education, religion and social norms.", "ex": "Culture wars have become central to American political polarisation."}, {"term": "culture-war issue", "ipa": "/ˈkʌltʃə wɔː ˈɪʃuː/", "pron": "KUL-chuh war ISH-oo", "fr": "enjeu de guerre culturelle", "def": "A divisive issue linked to values, identity or social change.", "ex": "Abortion, guns and race education are major culture-war issues."}, {"term": "identity politics", "ipa": "/aɪˈdentəti ˈpɒlɪtɪks/", "pron": "eye-DEN-tuh-tee POL-i-tiks", "fr": "politique identitaire", "def": "Politics organised around the interests and experiences of identity groups.", "ex": "Critics often accuse progressive movements of promoting identity politics."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "The process by which political opinions become more extreme and divided.", "ex": "Culture wars have deepened political polarisation."}, {"term": "political polarisation", "ipa": "/pəˌlɪtɪkəl ˌpəʊləraɪˈzeɪʃən/", "pron": "puh-LIT-i-kuhl poh-luh-ry-ZAY-shuhn", "fr": "polarisation politique", "def": "Deep division between political groups or parties.", "ex": "Political polarisation makes compromise increasingly difficult."}, {"term": "partisan divide", "ipa": "/ˌpɑːtɪzən dɪˈvaɪd/", "pron": "PAR-ti-zuhn di-VYDE", "fr": "clivage partisan", "def": "A split in opinions based on party allegiance.", "ex": "The partisan divide over education has widened."}, {"term": "ideological divide", "ipa": "/ˌaɪdiəˈlɒdʒɪkəl dɪˈvaɪd/", "pron": "eye-dee-uh-LOJ-i-kuhl di-VYDE", "fr": "clivage idéologique", "def": "A division based on political ideas or values.", "ex": "The ideological divide is visible in debates about gender and race."}, {"term": "values divide", "ipa": "/ˈvæljuːz dɪˌvaɪd/", "pron": "VAL-yooz di-VYDE", "fr": "fracture des valeurs", "def": "A conflict between different moral or cultural values.", "ex": "The values divide often overlaps with geography and religion."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "Public fear, often exaggerated, that a group or trend threatens society’s values.", "ex": "Some commentators describe the backlash against drag shows as a moral panic."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "réaction hostile ; retour de bâton", "def": "A strong negative reaction against social or political change.", "ex": "Progressive reforms often trigger conservative backlash."}, {"term": "conservative backlash", "ipa": "/kənˈsɜːvətɪv ˈbæklæʃ/", "pron": "kuhn-SUR-vuh-tiv BAK-lash", "fr": "réaction conservatrice", "def": "A negative reaction by conservatives against social or cultural change.", "ex": "The conservative backlash focused on schools and gender identity."}, {"term": "progressive activism", "ipa": "/prəˈɡresɪv ˈæktɪvɪzəm/", "pron": "pruh-GRESS-iv AK-ti-viz-uhm", "fr": "militantisme progressiste", "def": "Political activism supporting social reform, equality and inclusion.", "ex": "Progressive activism has pushed institutions to address racism and sexism."}, {"term": "social conservatism", "ipa": "/ˌsəʊʃəl kənˈsɜːvətɪzəm/", "pron": "SOH-shuhl kuhn-SUR-vuh-tiz-uhm", "fr": "conservatisme social", "def": "A political outlook defending traditional values, family structures and moral norms.", "ex": "Social conservatism is influential in debates on abortion and LGBTQ+ rights."}, {"term": "religious right", "ipa": "/rɪˌlɪdʒəs ˈraɪt/", "pron": "ri-LIJ-uhs right", "fr": "droite religieuse", "def": "A conservative political movement shaped by religious values, especially evangelical Christianity.", "ex": "The religious right has strongly influenced Republican politics."}, {"term": "evangelical Christianity", "ipa": "/ˌiːvænˈdʒelɪkəl ˌkrɪstiˈænəti/", "pron": "ee-van-JEL-i-kuhl kris-tee-AN-uh-tee", "fr": "christianisme évangélique", "def": "A branch of Protestant Christianity often associated with conservative politics in the US.", "ex": "Evangelical Christianity plays a major role in culture-war politics."}, {"term": "Christian nationalism", "ipa": "/ˌkrɪstʃən ˈnæʃənəlɪzəm/", "pron": "KRIS-chuhn NASH-uh-nuh-liz-uhm", "fr": "nationalisme chrétien", "def": "The belief that a nation should be defined by Christianity and governed according to Christian values.", "ex": "Christian nationalism has become a controversial force in American politics."}, {"term": "secularism", "ipa": "/ˈsekjələrɪzəm/", "pron": "SEK-yuh-luh-riz-uhm", "fr": "laïcité ; sécularisme", "def": "The principle of separating religion from government and public institutions.", "ex": "Secularism is often defended in debates over school prayer."}, {"term": "secular liberalism", "ipa": "/ˈsekjələ ˈlɪbərəlɪzəm/", "pron": "SEK-yuh-luh LIB-uh-ruhl-iz-uhm", "fr": "libéralisme séculier", "def": "A liberal worldview based on individual rights and limited religious influence in public policy.", "ex": "Secular liberalism is often criticised by the religious right."}, {"term": "traditional values", "ipa": "/trəˌdɪʃənəl ˈvæljuːz/", "pron": "truh-DISH-uh-nuhl VAL-yooz", "fr": "valeurs traditionnelles", "def": "Moral or family values seen as inherited from the past.", "ex": "Politicians often promise to defend traditional values."}, {"term": "family values", "ipa": "/ˈfæməli ˈvæljuːz/", "pron": "FAM-uh-lee VAL-yooz", "fr": "valeurs familiales", "def": "Conservative moral values centred on marriage, parenting and family life.", "ex": "Family values are frequently invoked in debates over education."}, {"term": "liberal values", "ipa": "/ˈlɪbərəl ˈvæljuːz/", "pron": "LIB-uh-ruhl VAL-yooz", "fr": "valeurs libérales", "def": "Values emphasising individual freedom, equality and tolerance.", "ex": "Liberal values are often defended in debates over minority rights."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "The right to express opinions without unjustified government restriction.", "ex": "Free speech has become a key culture-war battleground."}]}, {"title": "B. Free speech, wokeness and campus debates", "entries": [{"term": "political correctness", "ipa": "/pəˌlɪtɪkəl kəˈrektnəs/", "pron": "puh-LIT-i-kuhl kuh-REKT-nuhs", "fr": "politiquement correct", "def": "Language or behaviour intended to avoid offending marginalised groups, often criticised by opponents.", "ex": "Critics claim political correctness restricts open debate."}, {"term": "woke", "ipa": "/wəʊk/", "pron": "wohk", "fr": "woke ; conscient des injustices sociales", "def": "Originally meaning alert to social injustice; now often used politically and sometimes pejoratively.", "ex": "The word woke has become a powerful conservative attack label."}, {"term": "wokeness", "ipa": "/ˈwəʊknəs/", "pron": "WOHK-nuhs", "fr": "wokisme ; conscience sociale progressiste", "def": "A politicised term for progressive concern with race, gender and social justice.", "ex": "Conservatives often denounce wokeness in schools and companies."}, {"term": "anti-woke", "ipa": "/ˌænti ˈwəʊk/", "pron": "AN-tee wohk", "fr": "anti-woke", "def": "Opposed to progressive identity-based politics or social justice language.", "ex": "Anti-woke campaigns have become central to Republican strategy."}, {"term": "cancel culture", "ipa": "/ˈkænsəl ˌkʌltʃə/", "pron": "KAN-suhl KUL-chuh", "fr": "cancel culture ; culture de l’annulation", "def": "The practice or accusation of publicly shaming or excluding people for offensive views or behaviour.", "ex": "Cancel culture is often presented as a threat to free speech."}, {"term": "call-out culture", "ipa": "/ˈkɔːl aʊt ˌkʌltʃə/", "pron": "call-out KUL-chuh", "fr": "culture de l’interpellation publique", "def": "The practice of publicly criticising someone for harmful language or behaviour.", "ex": "Call-out culture can promote accountability but also public shaming."}, {"term": "deplatforming", "ipa": "/diːˈplætfɔːmɪŋ/", "pron": "dee-PLAT-form-ing", "fr": "déplateformisation ; retrait de tribune", "def": "Removing someone’s ability to speak on a platform because of controversial views.", "ex": "Deplatforming is controversial on university campuses."}, {"term": "safe space", "ipa": "/ˈseɪf speɪs/", "pron": "sayf space", "fr": "espace sûr", "def": "A place or environment intended to protect people from discrimination, harassment or trauma.", "ex": "Safe spaces are defended as inclusive and criticised as overprotective."}, {"term": "trigger warning", "ipa": "/ˈtrɪɡə ˌwɔːnɪŋ/", "pron": "TRIG-uh WAR-ning", "fr": "avertissement de contenu sensible", "def": "A warning that content may be disturbing or traumatic.", "ex": "Trigger warnings are common in debates over campus culture."}, {"term": "microaggression", "ipa": "/ˌmaɪkrəʊəˈɡreʃən/", "pron": "MY-kroh-uh-GRESH-uhn", "fr": "micro-agression", "def": "A subtle comment or action that may express prejudice towards a marginalised group.", "ex": "Microaggressions are discussed in diversity training."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity such as race, religion, gender or sexuality.", "ex": "The line between hate speech and free speech is fiercely debated."}, {"term": "offensive speech", "ipa": "/əˌfensɪv ˈspiːtʃ/", "pron": "uh-FEN-siv speech", "fr": "propos offensants", "def": "Speech that insults, shocks or offends people.", "ex": "Liberal democracies often protect offensive speech."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "The suppression or restriction of speech, books, media or ideas.", "ex": "Both sides accuse each other of censorship."}, {"term": "book ban", "ipa": "/ˈbʊk bæn/", "pron": "book ban", "fr": "interdiction de livres", "def": "A restriction or removal of books from schools or libraries.", "ex": "Book bans have become a flashpoint in school politics."}, {"term": "banned book", "ipa": "/ˌbænd ˈbʊk/", "pron": "band book", "fr": "livre interdit", "def": "A book removed or restricted because of its content.", "ex": "Many banned books deal with race, sexuality or gender."}, {"term": "curriculum", "ipa": "/kəˈrɪkjʊləm/", "pron": "kuh-RIK-yuh-luhm", "fr": "programme scolaire", "def": "The subjects and content taught in schools.", "ex": "The curriculum became a battleground over American history."}]}, {"title": "C. Schools, race, history and national memory", "entries": [{"term": "school board", "ipa": "/ˈskuːl bɔːd/", "pron": "school board", "fr": "conseil scolaire local", "def": "A local elected or appointed body overseeing schools.", "ex": "School board meetings have become politically heated."}, {"term": "parents’ rights", "ipa": "/ˈpeərənts raɪts/", "pron": "PAIR-uhnts rites", "fr": "droits des parents", "def": "The claim that parents should control or influence what schools teach children.", "ex": "Parents’ rights became a major slogan in education debates."}, {"term": "parental control", "ipa": "/pəˈrentəl kənˌtrəʊl/", "pron": "puh-REN-tuhl kuhn-TROHL", "fr": "contrôle parental", "def": "The ability of parents to influence children’s education or exposure to content.", "ex": "Conservatives called for greater parental control over school materials."}, {"term": "indoctrination", "ipa": "/ɪnˌdɒktrɪˈneɪʃən/", "pron": "in-dok-tri-NAY-shuhn", "fr": "endoctrinement", "def": "The teaching of beliefs in a way that discourages critical thinking.", "ex": "Both sides accuse schools of indoctrination."}, {"term": "critical race theory", "ipa": "/ˌkrɪtɪkəl ˈreɪs ˈθɪəri/", "pron": "KRIT-i-kuhl rays THEE-uh-ree", "fr": "théorie critique de la race", "def": "An academic framework examining how law and institutions reproduce racial inequality.", "ex": "Critical race theory became a conservative target in education politics."}, {"term": "CRT", "ipa": "/ˌsiː ɑː ˈtiː/", "pron": "see ar tee", "fr": "CRT", "def": "Abbreviation for critical race theory.", "ex": "CRT is often used broadly in political debates."}, {"term": "race education", "ipa": "/ˈreɪs ˌedjʊˈkeɪʃən/", "pron": "rays ej-yoo-KAY-shuhn", "fr": "enseignement sur les questions raciales", "def": "Teaching about race, racism and racial inequality.", "ex": "Race education has become highly contested in schools."}, {"term": "slavery curriculum", "ipa": "/ˈsleɪvəri kəˈrɪkjʊləm/", "pron": "SLAY-vuh-ree kuh-RIK-yuh-luhm", "fr": "programme sur l’esclavage", "def": "Teaching content about slavery and its legacy.", "ex": "Debates over the slavery curriculum reveal conflicts over national memory."}, {"term": "patriotic education", "ipa": "/ˌpætriˈɒtɪk ˌedjʊˈkeɪʃən/", "pron": "pat-ree-OT-ik ej-yoo-KAY-shuhn", "fr": "éducation patriotique", "def": "Teaching history in a way that emphasises national pride.", "ex": "Some conservatives call for patriotic education."}, {"term": "national history", "ipa": "/ˌnæʃənəl ˈhɪstəri/", "pron": "NASH-uh-nuhl HIS-tuh-ree", "fr": "histoire nationale", "def": "The story a country tells about its past.", "ex": "National history is often contested in culture wars."}, {"term": "historical reckoning", "ipa": "/hɪˌstɒrɪkəl ˈrekənɪŋ/", "pron": "hi-STOR-i-kuhl REK-uhn-ing", "fr": "examen critique du passé", "def": "A serious confrontation with past injustice.", "ex": "The Black Lives Matter movement encouraged a historical reckoning."}, {"term": "statue removal", "ipa": "/ˈstætʃuː rɪˌmuːvəl/", "pron": "STAT-choo ri-MOO-vuhl", "fr": "retrait de statues", "def": "The removal of public statues seen as offensive or linked to injustice.", "ex": "Statue removal sparked debates about history and memory."}, {"term": "Confederate monument", "ipa": "/kənˈfedərət ˈmɒnjʊmənt/", "pron": "kuhn-FED-uh-ruht MON-yuh-muhnt", "fr": "monument confédéré", "def": "A monument honouring the Confederacy or its leaders.", "ex": "Confederate monuments became symbols of contested memory."}, {"term": "LGBTQ+ rights", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs raɪts/", "pron": "el jee bee tee kyoo plus rites", "fr": "droits LGBTQ+", "def": "Rights protecting lesbian, gay, bisexual, transgender, queer and other sexual or gender minorities.", "ex": "LGBTQ+ rights are at the centre of many culture-war debates."}, {"term": "same-sex marriage", "ipa": "/ˌseɪm seks ˈmærɪdʒ/", "pron": "same-sex MARR-ij", "fr": "mariage homosexuel ; mariage pour tous", "def": "Marriage between two people of the same sex.", "ex": "Same-sex marriage became legal nationwide in 2015."}, {"term": "transgender rights", "ipa": "/trænzˌdʒendə ˈraɪts/", "pron": "tranz-JEN-duh rites", "fr": "droits des personnes transgenres", "def": "Rights protecting transgender people from discrimination.", "ex": "Transgender rights are heavily contested in schools and sports."}]}, {"title": "D. Gender, sexuality, religion and public health conflicts", "entries": [{"term": "gender identity", "ipa": "/ˈdʒendər aɪˌdentəti/", "pron": "JEN-duhr eye-DEN-tuh-tee", "fr": "identité de genre", "def": "A person’s internal sense of gender.", "ex": "Gender identity policies have sparked state-level legislation."}, {"term": "gender-affirming care", "ipa": "/ˌdʒendər əˈfɜːmɪŋ keə/", "pron": "JEN-duhr uh-FUR-ming care", "fr": "soins d’affirmation de genre", "def": "Healthcare supporting a person’s gender identity.", "ex": "Several states have restricted gender-affirming care for minors."}, {"term": "bathroom bill", "ipa": "/ˈbɑːθruːm bɪl/", "pron": "BATH-room bil", "fr": "loi sur l’accès aux toilettes", "def": "A law restricting which bathrooms transgender people may use.", "ex": "Bathroom bills became an early flashpoint in transgender rights debates."}, {"term": "trans athletes", "ipa": "/trænz ˈæθliːts/", "pron": "tranz ATH-leets", "fr": "athlètes transgenres", "def": "Transgender athletes, often discussed in debates over sports participation.", "ex": "Trans athletes have become a major culture-war issue."}, {"term": "drag queen", "ipa": "/ˈdræɡ kwiːn/", "pron": "drag queen", "fr": "drag queen", "def": "A performer, often male, who dresses in exaggerated feminine style for entertainment.", "ex": "Drag queen story hours have been targeted by conservative activists."}, {"term": "drag show", "ipa": "/ˈdræɡ ʃəʊ/", "pron": "drag show", "fr": "spectacle drag", "def": "A performance involving drag artists.", "ex": "Some states tried to restrict drag shows."}, {"term": "Don’t Say Gay law", "ipa": "/ˌdəʊnt seɪ ˈɡeɪ lɔː/", "pron": "don't say gay law", "fr": "loi dite Don’t Say Gay", "def": "A nickname for laws restricting classroom discussion of sexual orientation or gender identity.", "ex": "Critics say Don’t Say Gay laws stigmatise LGBTQ+ students."}, {"term": "religious freedom", "ipa": "/rɪˌlɪdʒəs ˈfriːdəm/", "pron": "ri-LIJ-uhs FREE-duhm", "fr": "liberté religieuse", "def": "The right to practise religion without unjustified interference.", "ex": "Religious freedom is often invoked in conflicts over LGBTQ+ rights."}, {"term": "conscience clause", "ipa": "/ˈkɒnʃəns klɔːz/", "pron": "KON-shuhns klawz", "fr": "clause de conscience", "def": "A legal provision allowing refusal to act against one’s moral or religious beliefs.", "ex": "Conscience clauses are debated in healthcare and wedding services."}, {"term": "religious exemption", "ipa": "/rɪˌlɪdʒəs ɪɡˈzempʃən/", "pron": "ri-LIJ-uhs ig-ZEMP-shuhn", "fr": "exemption religieuse", "def": "An exemption from a law based on religious beliefs.", "ex": "Religious exemptions can conflict with anti-discrimination law."}, {"term": "anti-discrimination law", "ipa": "/ˌænti dɪˌskrɪmɪˈneɪʃən lɔː/", "pron": "AN-tee dis-krim-i-NAY-shuhn law", "fr": "loi anti-discrimination", "def": "A law banning unfair treatment based on protected characteristics.", "ex": "Anti-discrimination laws protect minority groups."}, {"term": "abortion debate", "ipa": "/əˈbɔːʃən dɪˌbeɪt/", "pron": "uh-BOR-shuhn di-BAYT", "fr": "débat sur l’avortement", "def": "The political and moral debate over abortion rights and restrictions.", "ex": "The abortion debate is one of the oldest culture-war conflicts."}, {"term": "pro-choice", "ipa": "/ˌprəʊ ˈtʃɔɪs/", "pron": "proh choice", "fr": "pro-choice ; favorable au droit à l’avortement", "def": "Supporting legal access to abortion.", "ex": "Pro-choice activists frame the issue as bodily autonomy."}, {"term": "pro-life", "ipa": "/ˌprəʊ ˈlaɪf/", "pron": "proh life", "fr": "pro-life ; anti-avortement", "def": "Opposing abortion on the grounds of protecting unborn life.", "ex": "Pro-life voters are often highly mobilised."}, {"term": "gun rights culture", "ipa": "/ˈɡʌn raɪts ˌkʌltʃə/", "pron": "gun rites KUL-chuh", "fr": "culture pro-armes", "def": "A culture that treats gun ownership as a symbol of freedom and identity.", "ex": "Gun rights culture is especially strong in rural America."}, {"term": "Second Amendment culture", "ipa": "/ˌsekənd əˈmendmənt ˌkʌltʃə/", "pron": "SEK-uhnd uh-MEND-muhnt KUL-chuh", "fr": "culture du Deuxième amendement", "def": "A political culture built around the right to bear arms.", "ex": "Second Amendment culture overlaps with distrust of government."}, {"term": "mask mandate", "ipa": "/ˈmɑːsk ˌmændeɪt/", "pron": "mask MAN-dayt", "fr": "obligation de porter un masque", "def": "A rule requiring people to wear masks, especially during a pandemic.", "ex": "Mask mandates became culture-war symbols during Covid-19."}, {"term": "vaccine mandate", "ipa": "/ˈvæksiːn ˌmændeɪt/", "pron": "VAK-seen MAN-dayt", "fr": "obligation vaccinale", "def": "A rule requiring vaccination for certain activities or jobs.", "ex": "Vaccine mandates triggered protests over personal freedom."}, {"term": "public health mandate", "ipa": "/ˌpʌblɪk ˈhelθ ˌmændeɪt/", "pron": "PUB-lik helth MAN-dayt", "fr": "mesure sanitaire obligatoire", "def": "A health rule imposed by authorities to protect the public.", "ex": "Public health mandates were framed by opponents as government overreach."}, {"term": "personal freedom", "ipa": "/ˌpɜːsənəl ˈfriːdəm/", "pron": "PUR-suh-nuhl FREE-duhm", "fr": "liberté individuelle", "def": "The ability of individuals to make choices without government interference.", "ex": "Personal freedom is a recurring argument in culture wars."}, {"term": "government overreach", "ipa": "/ˈɡʌvənmənt ˌəʊvəˈriːtʃ/", "pron": "GUV-uhn-muhnt OH-vuh-reech", "fr": "abus de pouvoir de l’État", "def": "Excessive or improper expansion of government power.", "ex": "Opponents called vaccine mandates government overreach."}, {"term": "climate scepticism", "ipa": "/ˈklaɪmət ˈskeptɪsɪzəm/", "pron": "KLY-muht SKEP-ti-siz-uhm", "fr": "climatoscepticisme", "def": "Doubt or rejection of mainstream climate science or policy.", "ex": "Climate scepticism has become part of conservative identity politics."}, {"term": "ESG", "ipa": "/ˌiː es ˈdʒiː/", "pron": "ee es jee", "fr": "ESG ; critères environnementaux, sociaux et de gouvernance", "def": "Environmental, social and governance criteria used in business and investment.", "ex": "ESG policies are attacked by some conservatives as woke capitalism."}, {"term": "woke capitalism", "ipa": "/ˌwəʊk ˈkæpɪtəlɪzəm/", "pron": "wohk KAP-i-tuh-liz-uhm", "fr": "capitalisme woke", "def": "A critical term for companies adopting progressive social or environmental positions.", "ex": "Woke capitalism became a target for anti-ESG campaigns."}]}, {"title": "E. Media outrage, geography and high-value verbs", "entries": [{"term": "corporate activism", "ipa": "/ˌkɔːpərət ˈæktɪvɪzəm/", "pron": "KOR-puh-ruht AK-ti-viz-uhm", "fr": "activisme d’entreprise", "def": "Companies taking public positions on social or political issues.", "ex": "Corporate activism can attract both praise and boycotts."}, {"term": "brand boycott", "ipa": "/ˈbrænd ˌbɔɪkɒt/", "pron": "brand BOY-kot", "fr": "boycott de marque", "def": "A refusal to buy from a company because of political or moral disagreement.", "ex": "Brand boycotts have become common in culture-war disputes."}, {"term": "consumer backlash", "ipa": "/kənˌsjuːmə ˈbæklæʃ/", "pron": "kuhn-SYOO-muh BAK-lash", "fr": "réaction hostile des consommateurs", "def": "A negative reaction by customers against a company or product.", "ex": "The campaign triggered a consumer backlash."}, {"term": "media outrage", "ipa": "/ˈmiːdiə ˈaʊtreɪdʒ/", "pron": "MEE-dee-uh OWT-rayj", "fr": "indignation médiatique", "def": "Intense anger amplified by media coverage.", "ex": "Media outrage can turn small incidents into national controversies."}, {"term": "outrage cycle", "ipa": "/ˈaʊtreɪdʒ ˌsaɪkəl/", "pron": "OWT-rayj SY-kuhl", "fr": "cycle de l’indignation", "def": "A repeated pattern of anger, media amplification and political reaction.", "ex": "Social media accelerates the outrage cycle."}, {"term": "social media storm", "ipa": "/ˌsəʊʃəl ˈmiːdiə stɔːm/", "pron": "SOH-shuhl MEE-dee-uh storm", "fr": "tempête sur les réseaux sociaux", "def": "A sudden wave of online criticism or controversy.", "ex": "A social media storm forced the company to apologise."}, {"term": "viral controversy", "ipa": "/ˈvaɪrəl ˈkɒntrəvɜːsi/", "pron": "VY-ruhl KON-truh-vur-see", "fr": "controverse virale", "def": "A controversy that spreads rapidly online.", "ex": "The video sparked a viral controversy."}, {"term": "echo chamber", "ipa": "/ˈekəʊ ˌtʃeɪmbə/", "pron": "EK-oh CHAYM-buh", "fr": "chambre d’écho", "def": "An environment where people mostly hear opinions they already agree with.", "ex": "Echo chambers reinforce culture-war polarisation."}, {"term": "filter bubble", "ipa": "/ˈfɪltə ˌbʌbəl/", "pron": "FIL-tuh BUB-uhl", "fr": "bulle de filtres", "def": "An online environment shaped by algorithms that show users similar content.", "ex": "Filter bubbles can deepen ideological division."}, {"term": "algorithmic amplification", "ipa": "/ˌælɡəˈrɪðmɪk ˌæmplɪfɪˈkeɪʃən/", "pron": "al-guh-RITH-mik am-pli-fi-KAY-shuhn", "fr": "amplification algorithmique", "def": "The way algorithms make some content more visible and influential.", "ex": "Algorithmic amplification rewards outrage and conflict."}, {"term": "culture-war entrepreneur", "ipa": "/ˈkʌltʃə wɔː ˌɒntrəprəˈnɜː/", "pron": "KUL-chuh war on-truh-pruh-NUR", "fr": "entrepreneur de guerre culturelle", "def": "A political or media figure who gains attention by fuelling cultural conflict.", "ex": "Culture-war entrepreneurs benefit from permanent outrage."}, {"term": "grievance politics", "ipa": "/ˈɡriːvəns ˈpɒlɪtɪks/", "pron": "GREE-vuhns POL-i-tiks", "fr": "politique du ressentiment", "def": "Politics based on resentment and a sense of being wronged.", "ex": "Grievance politics can mobilise voters who feel ignored."}, {"term": "resentment", "ipa": "/rɪˈzentmənt/", "pron": "ri-ZENT-muhnt", "fr": "ressentiment", "def": "A feeling of anger or bitterness about perceived unfairness.", "ex": "Culture-war rhetoric often feeds resentment."}, {"term": "victimhood narrative", "ipa": "/ˈvɪktɪmhʊd ˈnærətɪv/", "pron": "VIK-tim-hood NAR-uh-tiv", "fr": "récit victimaire", "def": "A story presenting a group as unfairly persecuted or silenced.", "ex": "Both sides sometimes use victimhood narratives."}, {"term": "elite contempt", "ipa": "/ɪˌliːt kənˈtempt/", "pron": "i-LEET kuhn-TEMPT", "fr": "mépris des élites", "def": "The belief that elites look down on ordinary people.", "ex": "Populists often denounce elite contempt."}, {"term": "liberal elite", "ipa": "/ˈlɪbərəl ɪˈliːt/", "pron": "LIB-uh-ruhl i-LEET", "fr": "élite libérale ; élite progressiste", "def": "A term used to describe educated, progressive and influential groups.", "ex": "The liberal elite is often blamed for cultural change."}, {"term": "silent majority", "ipa": "/ˌsaɪlənt məˈdʒɒrəti/", "pron": "SY-luhnt muh-JOR-uh-tee", "fr": "majorité silencieuse", "def": "A claimed majority of ordinary people whose views are supposedly ignored.", "ex": "Politicians invoke the silent majority in culture-war speeches."}, {"term": "ordinary Americans", "ipa": "/ˌɔːdənəri əˈmerɪkənz/", "pron": "OR-duh-ner-ee uh-MER-i-kuhnz", "fr": "Américains ordinaires", "def": "Average citizens, often contrasted with elites.", "ex": "Culture-war campaigns claim to defend ordinary Americans."}, {"term": "heartland", "ipa": "/ˈhɑːtlænd/", "pron": "HART-land", "fr": "cœur du pays ; Amérique profonde", "def": "The central or rural parts of the US, often presented as more traditional.", "ex": "The heartland is often contrasted with coastal cities."}, {"term": "coastal elites", "ipa": "/ˌkəʊstəl ɪˈliːts/", "pron": "KOH-stuhl i-LEETS", "fr": "élites côtières", "def": "Educated and wealthy groups living in coastal metropolitan areas, often criticised by conservatives.", "ex": "The phrase coastal elites is common in populist rhetoric."}, {"term": "red America", "ipa": "/ˌred əˈmerɪkə/", "pron": "red uh-MER-i-kuh", "fr": "Amérique rouge ; Amérique républicaine", "def": "Conservative or Republican-leaning America.", "ex": "Red America is often associated with rural and religious communities."}, {"term": "blue America", "ipa": "/ˌbluː əˈmerɪkə/", "pron": "bloo uh-MER-i-kuh", "fr": "Amérique bleue ; Amérique démocrate", "def": "Liberal or Democratic-leaning America.", "ex": "Blue America is often associated with urban and diverse communities."}, {"term": "urban-rural divide", "ipa": "/ˌɜːbən ˈrʊərəl dɪˈvaɪd/", "pron": "UR-buhn ROOR-uhl di-VYDE", "fr": "fracture urbain-rural", "def": "A political and cultural gap between cities and rural areas.", "ex": "The urban-rural divide fuels culture-war politics."}, {"term": "generational divide", "ipa": "/ˌdʒenəˈreɪʃənəl dɪˈvaɪd/", "pron": "jen-uh-RAY-shuh-nuhl di-VYDE", "fr": "fracture générationnelle", "def": "A difference in values or opinions between age groups.", "ex": "The generational divide is visible on LGBTQ+ rights."}, {"term": "gender divide", "ipa": "/ˈdʒendə dɪˌvaɪd/", "pron": "JEN-duh di-VYDE", "fr": "fracture de genre", "def": "A difference in political attitudes between men and women.", "ex": "The gender divide has widened on abortion."}, {"term": "racial divide", "ipa": "/ˈreɪʃəl dɪˌvaɪd/", "pron": "RAY-shuhl di-VYDE", "fr": "fracture raciale", "def": "A division in experiences or political views linked to race.", "ex": "The racial divide shapes debates about policing and education."}, {"term": "to politicise an issue", "ipa": "/pəˈlɪtɪsaɪz ən ˈɪʃuː/", "pron": "puh-LIT-i-syz uhn ISH-oo", "fr": "politiser une question", "def": "To turn an issue into a matter of political conflict.", "ex": "Politicians politicised school curricula."}, {"term": "to weaponise an issue", "ipa": "/ˈwepənaɪz ən ˈɪʃuː/", "pron": "WEP-uhn-yz uhn ISH-oo", "fr": "instrumentaliser une question", "def": "To use an issue as a political weapon.", "ex": "Campaigns weaponised parental fears."}, {"term": "to fuel polarisation", "ipa": "/ˈfjuːəl ˌpəʊləraɪˈzeɪʃən/", "pron": "FYOO-uhl poh-luh-ry-ZAY-shuhn", "fr": "alimenter la polarisation", "def": "To make political division stronger.", "ex": "Social media can fuel polarisation."}, {"term": "to stoke resentment", "ipa": "/stəʊk rɪˈzentmənt/", "pron": "stohk ri-ZENT-muhnt", "fr": "attiser le ressentiment", "def": "To deliberately increase anger or bitterness.", "ex": "Culture-war rhetoric stokes resentment."}, {"term": "to mobilise the base", "ipa": "/ˈməʊbɪlaɪz ðə beɪs/", "pron": "MOH-bi-lyz thuh base", "fr": "mobiliser la base électorale", "def": "To motivate loyal supporters to vote or act.", "ex": "Culture-war issues help parties mobilise the base."}, {"term": "to appeal to voters", "ipa": "/əˈpiːl tə ˈvəʊtəz/", "pron": "uh-PEEL tuh VOH-tuhz", "fr": "séduire les électeurs", "def": "To attract or persuade voters.", "ex": "Anti-woke rhetoric appeals to some conservative voters."}, {"term": "to defend traditional values", "ipa": "/dɪˈfend trəˌdɪʃənəl ˈvæljuːz/", "pron": "di-FEND truh-DISH-uh-nuhl VAL-yooz", "fr": "défendre les valeurs traditionnelles", "def": "To protect older moral, religious or family norms.", "ex": "Republican candidates promised to defend traditional values."}, {"term": "to promote inclusion", "ipa": "/prəˈməʊt ɪnˈkluːʒən/", "pron": "pruh-MOHT in-KLOO-zhuhn", "fr": "promouvoir l’inclusion", "def": "To encourage equal participation and acceptance.", "ex": "Schools introduced policies to promote inclusion."}, {"term": "to challenge discrimination", "ipa": "/ˈtʃælɪndʒ dɪˌskrɪmɪˈneɪʃən/", "pron": "CHAL-inj dis-krim-i-NAY-shuhn", "fr": "contester la discrimination", "def": "To oppose unfair treatment based on identity.", "ex": "Activists challenged discrimination against LGBTQ+ students."}, {"term": "to restrict classroom discussion", "ipa": "/rɪˈstrɪkt ˈklɑːsruːm dɪˌskʌʃən/", "pron": "ri-STRIKT KLASS-room di-SKUSH-uhn", "fr": "restreindre les discussions en classe", "def": "To limit what teachers can discuss in school.", "ex": "New laws restrict classroom discussion of gender identity."}, {"term": "to ban books", "ipa": "/bæn bʊks/", "pron": "ban books", "fr": "interdire des livres", "def": "To remove or prohibit books from schools or libraries.", "ex": "Campaigners tried to ban books dealing with race and sexuality."}, {"term": "to silence dissent", "ipa": "/ˈsaɪləns dɪˈsent/", "pron": "SY-luhns di-SENT", "fr": "faire taire la dissidence", "def": "To prevent disagreement or criticism from being heard.", "ex": "Critics argue that cancel culture silences dissent."}, {"term": "to protect free speech", "ipa": "/prəˈtekt friː ˈspiːtʃ/", "pron": "pruh-TEKT free speech", "fr": "protéger la liberté d’expression", "def": "To defend the right to express opinions.", "ex": "Universities must protect free speech while preventing harassment."}, {"term": "to draw a line between speech and harm", "ipa": "/drɔː ə laɪn bɪˈtwiːn spiːtʃ ənd hɑːm/", "pron": "draw uh line bi-TWEEN speech and harm", "fr": "tracer une frontière entre parole et préjudice", "def": "To distinguish expression from damaging or dangerous conduct.", "ex": "The debate tries to draw a line between speech and harm."}, {"term": "to turn schools into battlegrounds", "ipa": "/tɜːn skuːlz ˈɪntuː ˈbætəlɡraʊndz/", "pron": "turn schoolz IN-too BAT-uhl-groundz", "fr": "transformer les écoles en champs de bataille idéologiques", "def": "To make schools central sites of political conflict.", "ex": "Culture wars have turned schools into battlegrounds."}, {"term": "to reshape public debate", "ipa": "/riːˈʃeɪp ˌpʌblɪk dɪˈbeɪt/", "pron": "ree-SHAYP PUB-lik di-BAYT", "fr": "remodeler le débat public", "def": "To significantly change the way issues are discussed publicly.", "ex": "Social media has reshaped public debate."}, {"term": "to deepen social divisions", "ipa": "/ˈdiːpən ˈsəʊʃəl dɪˈvɪʒənz/", "pron": "DEE-puhn SOH-shuhl di-VIZH-uhnz", "fr": "creuser les divisions sociales", "def": "To make social conflicts stronger.", "ex": "Culture-war rhetoric can deepen social divisions."}]}]}, {"id": "p3c22", "part": 3, "chapter": 22, "title": "British Political Institutions", "file": "cpge_vocab_part3_chapter22_british_political_institutions_premium.html", "count": 100, "sections": [{"title": "A. The UK state, monarchy and Westminster model", "entries": [{"term": "British political institutions", "ipa": "/ˈbrɪtɪʃ pəˌlɪtɪkəl ˌɪnstɪˈtjuːʃənz/", "pron": "BRIT-ish puh-LIT-i-kuhl in-sti-TOO-shuhnz", "fr": "institutions politiques britanniques", "def": "The bodies, rules and conventions that organise political power in the United Kingdom.", "ex": "British political institutions combine monarchy, Parliament, government and constitutional conventions."}, {"term": "United Kingdom", "ipa": "/juːˌnaɪtɪd ˈkɪŋdəm/", "pron": "yoo-NY-tid KING-duhm", "fr": "Royaume-Uni", "def": "A sovereign state made up of England, Scotland, Wales and Northern Ireland.", "ex": "The United Kingdom is a union of four nations."}, {"term": "Great Britain", "ipa": "/ˌɡreɪt ˈbrɪtən/", "pron": "great BRIT-uhn", "fr": "Grande-Bretagne", "def": "The island containing England, Scotland and Wales, but not Northern Ireland.", "ex": "Great Britain is not the same as the United Kingdom."}, {"term": "Westminster", "ipa": "/ˈwestmɪnstə/", "pron": "WEST-min-stuh", "fr": "Westminster ; système politique britannique", "def": "The area where Parliament is located; also a shorthand for the UK political system.", "ex": "Westminster has become shorthand for British central government."}, {"term": "Westminster system", "ipa": "/ˈwestmɪnstə ˈsɪstəm/", "pron": "WEST-min-stuh SIS-tuhm", "fr": "système de Westminster", "def": "A parliamentary system based on the UK model, with government drawn from Parliament.", "ex": "The Westminster system relies heavily on parliamentary confidence."}, {"term": "parliamentary democracy", "ipa": "/ˌpɑːləˈmentəri dɪˈmɒkrəsi/", "pron": "par-luh-MEN-tuh-ree di-MOK-ruh-see", "fr": "démocratie parlementaire", "def": "A system in which the government depends on support from Parliament.", "ex": "The UK is a parliamentary democracy."}, {"term": "constitutional monarchy", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈmɒnəki/", "pron": "kon-sti-TOO-shuh-nuhl MON-uh-kee", "fr": "monarchie constitutionnelle", "def": "A system in which a monarch is head of state but elected institutions hold political power.", "ex": "The UK is a constitutional monarchy."}, {"term": "monarch", "ipa": "/ˈmɒnək/", "pron": "MON-uhk", "fr": "monarque", "def": "A king or queen who serves as head of state.", "ex": "The monarch performs mainly ceremonial duties."}, {"term": "head of state", "ipa": "/ˌhed əv ˈsteɪt/", "pron": "hed ov state", "fr": "chef de l’État", "def": "The official representative of a country, often with symbolic duties.", "ex": "In Britain, the monarch is head of state."}, {"term": "head of government", "ipa": "/ˌhed əv ˈɡʌvənmənt/", "pron": "hed ov GUV-uhn-muhnt", "fr": "chef du gouvernement", "def": "The political leader who runs the government.", "ex": "The Prime Minister is the head of government."}, {"term": "the Crown", "ipa": "/ðə ˈkraʊn/", "pron": "thuh crown", "fr": "la Couronne", "def": "The legal and symbolic authority of the state, formally represented by the monarch.", "ex": "Government authority is formally exercised in the name of the Crown."}, {"term": "royal prerogative", "ipa": "/ˌrɔɪəl prɪˈrɒɡətɪv/", "pron": "ROY-uhl pri-ROG-uh-tiv", "fr": "prérogative royale", "def": "Traditional executive powers formally held by the monarch but mostly exercised by ministers.", "ex": "The royal prerogative is used in foreign affairs and defence."}, {"term": "Parliament", "ipa": "/ˈpɑːləmənt/", "pron": "PAR-luh-muhnt", "fr": "Parlement", "def": "The UK’s supreme legislative body, made up of the monarch, Commons and Lords.", "ex": "Parliament can pass, amend or repeal any law."}, {"term": "House of Commons", "ipa": "/ˌhaʊs əv ˈkɒmənz/", "pron": "howss ov KOM-uhnz", "fr": "Chambre des communes", "def": "The elected lower chamber of the UK Parliament.", "ex": "The government must command a majority in the House of Commons."}, {"term": "House of Lords", "ipa": "/ˌhaʊs əv ˈlɔːdz/", "pron": "howss ov lordz", "fr": "Chambre des lords", "def": "The unelected upper chamber of Parliament, which revises legislation.", "ex": "The House of Lords can delay and scrutinise bills."}, {"term": "Member of Parliament", "ipa": "/ˌmembər əv ˈpɑːləmənt/", "pron": "MEM-buh ov PAR-luh-muhnt", "fr": "député ; membre du Parlement", "def": "An elected representative in the House of Commons, usually abbreviated MP.", "ex": "Each MP represents a constituency."}, {"term": "MP", "ipa": "/ˌem ˈpiː/", "pron": "em pee", "fr": "député ; MP", "def": "Abbreviation for Member of Parliament.", "ex": "The MP raised the issue during Prime Minister’s Questions."}, {"term": "constituency", "ipa": "/kənˈstɪtjuənsi/", "pron": "kuhn-STI-choo-uhn-see", "fr": "circonscription", "def": "A geographical area represented by one MP.", "ex": "Voters choose one MP for their constituency."}, {"term": "constituent", "ipa": "/kənˈstɪtjuənt/", "pron": "kuhn-STI-choo-uhnt", "fr": "électeur d’une circonscription ; administré", "def": "A person represented by an elected politician.", "ex": "MPs often hold surgeries to meet constituents."}, {"term": "Speaker of the House of Commons", "ipa": "/ˌspiːkər əv ðə ˌhaʊs əv ˈkɒmənz/", "pron": "SPEE-kuh ov thuh howss ov KOM-uhnz", "fr": "président de la Chambre des communes", "def": "The official who chairs debates and maintains order in the House of Commons.", "ex": "The Speaker must remain politically impartial."}]}, {"title": "B. Government, Cabinet and Whitehall", "entries": [{"term": "Prime Minister", "ipa": "/ˌpraɪm ˈmɪnɪstə/", "pron": "prime MIN-i-stuh", "fr": "Premier ministre", "def": "The head of the UK government and leader of the ruling party or coalition.", "ex": "The Prime Minister appoints ministers and sets the government’s agenda."}, {"term": "PM", "ipa": "/ˌpiː ˈem/", "pron": "pee em", "fr": "Premier ministre", "def": "Abbreviation for Prime Minister.", "ex": "The PM faced criticism over the policy."}, {"term": "Downing Street", "ipa": "/ˈdaʊnɪŋ striːt/", "pron": "DOWN-ing street", "fr": "Downing Street ; bureau du Premier ministre", "def": "The Prime Minister’s official residence and office; also the Prime Minister’s team.", "ex": "Downing Street denied that a reshuffle was planned."}, {"term": "Number 10", "ipa": "/ˌnʌmbə ˈten/", "pron": "NUM-buh ten", "fr": "10 Downing Street", "def": "10 Downing Street, the official residence and office of the Prime Minister.", "ex": "Number 10 announced the new policy."}, {"term": "Cabinet", "ipa": "/ˈkæbɪnət/", "pron": "KAB-i-nuht", "fr": "cabinet ; gouvernement", "def": "The group of senior ministers who lead departments and make major policy decisions.", "ex": "The Cabinet met to discuss the crisis."}, {"term": "minister", "ipa": "/ˈmɪnɪstə/", "pron": "MIN-i-stuh", "fr": "ministre", "def": "A politician appointed to lead or assist with a government department.", "ex": "The minister defended the bill in Parliament."}, {"term": "Secretary of State", "ipa": "/ˌsekrətəri əv ˈsteɪt/", "pron": "SEK-ruh-tuh-ree ov state", "fr": "secrétaire d’État ; ministre britannique", "def": "A senior minister in charge of a government department.", "ex": "The Secretary of State for Health announced reforms."}, {"term": "Home Secretary", "ipa": "/ˈhəʊm ˌsekrətəri/", "pron": "home SEK-ruh-tuh-ree", "fr": "ministre de l’Intérieur britannique", "def": "The minister responsible for immigration, policing and security.", "ex": "The Home Secretary announced tougher immigration rules."}, {"term": "Foreign Secretary", "ipa": "/ˈfɒrən ˌsekrətəri/", "pron": "FOR-uhn SEK-ruh-tuh-ree", "fr": "ministre britannique des Affaires étrangères", "def": "The minister responsible for foreign affairs.", "ex": "The Foreign Secretary met European leaders."}, {"term": "Chancellor of the Exchequer", "ipa": "/ˈtʃɑːnsələ əv ði ɪksˈtʃekə/", "pron": "CHAN-suh-luh ov thee iks-CHEK-uh", "fr": "ministre des Finances ; chancelier de l’Échiquier", "def": "The senior minister responsible for finance and the economy.", "ex": "The Chancellor presented the Budget."}, {"term": "Treasury", "ipa": "/ˈtreʒəri/", "pron": "TREZH-uh-ree", "fr": "Trésor britannique ; ministère des Finances", "def": "The government department responsible for public finance and economic policy.", "ex": "The Treasury warned of spending cuts."}, {"term": "Home Office", "ipa": "/ˈhəʊm ˌɒfɪs/", "pron": "home OFF-is", "fr": "ministère de l’Intérieur britannique", "def": "The department responsible for immigration, policing, security and domestic affairs.", "ex": "The Home Office faced criticism over asylum delays."}, {"term": "Foreign Office", "ipa": "/ˈfɒrən ˌɒfɪs/", "pron": "FOR-uhn OFF-is", "fr": "Foreign Office ; ministère des Affaires étrangères britannique", "def": "The government department responsible for foreign policy.", "ex": "The Foreign Office issued travel advice."}, {"term": "civil service", "ipa": "/ˌsɪvəl ˈsɜːvɪs/", "pron": "SIV-uhl SUR-vis", "fr": "fonction publique", "def": "The permanent administrative staff who serve the government.", "ex": "The civil service is expected to be politically neutral."}, {"term": "civil servant", "ipa": "/ˌsɪvəl ˈsɜːvənt/", "pron": "SIV-uhl SUR-vuhnt", "fr": "fonctionnaire", "def": "A professional employee of the state administration.", "ex": "Civil servants advise ministers and implement policy."}, {"term": "Whitehall", "ipa": "/ˈwaɪthɔːl/", "pron": "WHITE-hall", "fr": "Whitehall ; administration centrale", "def": "The area of London with many departments; also central administration.", "ex": "Whitehall prepared the policy documents."}, {"term": "government department", "ipa": "/ˈɡʌvənmənt dɪˌpɑːtmənt/", "pron": "GUV-uhn-muhnt di-PART-muhnt", "fr": "ministère ; département ministériel", "def": "A major administrative body responsible for a policy area.", "ex": "Each government department is led by a minister."}, {"term": "quango", "ipa": "/ˈkwæŋɡəʊ/", "pron": "KWANG-goh", "fr": "organisme parapublic ; quango", "def": "A semi-independent public body funded by government but not directly run by ministers.", "ex": "Quangos are often criticised for lacking accountability."}]}, {"title": "C. Devolution and constitutional principles", "entries": [{"term": "devolution", "ipa": "/ˌdiːvəˈluːʃən/", "pron": "dee-vuh-LOO-shuhn", "fr": "dévolution", "def": "The transfer of powers from central government to regional governments.", "ex": "Devolution has changed the UK’s constitutional structure."}, {"term": "devolved administration", "ipa": "/dɪˌvɒlvd ədˌmɪnɪˈstreɪʃən/", "pron": "di-VOLVD ad-min-i-STRAY-shuhn", "fr": "administration dévolue", "def": "A government in Scotland, Wales or Northern Ireland with powers transferred from Westminster.", "ex": "Devolved administrations control areas such as health and education."}, {"term": "Scottish Parliament", "ipa": "/ˌskɒtɪʃ ˈpɑːləmənt/", "pron": "SKOT-ish PAR-luh-muhnt", "fr": "Parlement écossais", "def": "The devolved legislature of Scotland.", "ex": "The Scottish Parliament has powers over health and education."}, {"term": "Welsh Parliament", "ipa": "/ˌwelʃ ˈpɑːləmənt/", "pron": "Welsh PAR-luh-muhnt", "fr": "Parlement gallois ; Senedd", "def": "The devolved legislature of Wales, also called the Senedd.", "ex": "The Welsh Parliament can pass laws in devolved areas."}, {"term": "Senedd", "ipa": "/ˈsenɛð/", "pron": "SEN-eth", "fr": "Senedd ; Parlement gallois", "def": "The Welsh Parliament.", "ex": "The Senedd debates Welsh domestic policy."}, {"term": "Northern Ireland Assembly", "ipa": "/ˌnɔːðən ˈaɪələnd əˈsembli/", "pron": "NOR-thuhn EYE-uh-luhnd uh-SEM-blee", "fr": "Assemblée d’Irlande du Nord", "def": "The devolved legislature of Northern Ireland.", "ex": "The Northern Ireland Assembly depends on power-sharing."}, {"term": "reserved matter", "ipa": "/rɪˌzɜːvd ˈmætə/", "pron": "ri-ZURVD MAT-uh", "fr": "compétence réservée", "def": "A policy area kept under Westminster control rather than devolved.", "ex": "Foreign policy is a reserved matter."}, {"term": "devolved matter", "ipa": "/dɪˌvɒlvd ˈmætə/", "pron": "di-VOLVD MAT-uh", "fr": "compétence dévolue", "def": "A policy area controlled by a devolved administration.", "ex": "Education is a devolved matter in Scotland."}, {"term": "unitary state", "ipa": "/ˌjuːnɪtəri ˈsteɪt/", "pron": "YOO-ni-tuh-ree state", "fr": "État unitaire", "def": "A state where ultimate legal authority rests with the central government.", "ex": "The UK remains a unitary state despite devolution."}, {"term": "parliamentary sovereignty", "ipa": "/ˌpɑːləˈmentəri ˈsɒvrənti/", "pron": "par-luh-MEN-tuh-ree SOV-ruhn-tee", "fr": "souveraineté parlementaire", "def": "The principle that Parliament can make or unmake any law.", "ex": "Brexit revived debates about parliamentary sovereignty."}, {"term": "uncodified constitution", "ipa": "/ʌnˌkəʊdɪfaɪd ˌkɒnstɪˈtjuːʃən/", "pron": "un-KOH-di-fyd kon-sti-TOO-shuhn", "fr": "constitution non codifiée", "def": "A constitution not contained in one single written document.", "ex": "The UK has an uncodified constitution."}, {"term": "constitutional convention", "ipa": "/ˌkɒnstɪˈtjuːʃənəl kənˈvenʃən/", "pron": "kon-sti-TOO-shuh-nuhl kuhn-VEN-shuhn", "fr": "convention constitutionnelle", "def": "An unwritten rule considered binding in political practice.", "ex": "By convention, the monarch acts on ministerial advice."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including government, must obey the law.", "ex": "The rule of law limits arbitrary power."}, {"term": "ministerial responsibility", "ipa": "/ˌmɪnɪˈstɪəriəl rɪˌspɒnsəˈbɪləti/", "pron": "min-i-STEER-ee-uhl ri-spon-suh-BIL-uh-tee", "fr": "responsabilité ministérielle", "def": "The principle that ministers are accountable to Parliament.", "ex": "Ministerial responsibility is central to parliamentary scrutiny."}, {"term": "collective responsibility", "ipa": "/kəˌlektɪv rɪˌspɒnsəˈbɪləti/", "pron": "kuh-LEK-tiv ri-spon-suh-BIL-uh-tee", "fr": "responsabilité collective du cabinet", "def": "The principle that Cabinet ministers must publicly support government decisions or resign.", "ex": "Collective responsibility helps maintain government unity."}]}, {"title": "D. Elections, opposition and party discipline", "entries": [{"term": "vote of confidence", "ipa": "/ˌvəʊt əv ˈkɒnfɪdəns/", "pron": "voht ov KON-fi-duhns", "fr": "vote de confiance", "def": "A parliamentary vote showing whether the government still has support.", "ex": "Losing a vote of confidence can bring down a government."}, {"term": "no-confidence vote", "ipa": "/ˌnəʊ ˈkɒnfɪdəns vəʊt/", "pron": "noh KON-fi-duhns voht", "fr": "motion de censure ; vote de défiance", "def": "A vote declaring that Parliament no longer supports the government.", "ex": "A no-confidence vote can trigger a general election."}, {"term": "general election", "ipa": "/ˌdʒenərəl ɪˈlekʃən/", "pron": "JEN-uh-ruhl i-LEK-shuhn", "fr": "élections législatives britanniques", "def": "A national election to choose MPs and determine the next government.", "ex": "A general election must be held at least every five years."}, {"term": "by-election", "ipa": "/ˈbaɪ ɪˌlekʃən/", "pron": "BY i-LEK-shuhn", "fr": "élection partielle", "def": "An election held in a single constituency to fill a vacant seat.", "ex": "The by-election was seen as a test for the government."}, {"term": "first-past-the-post", "ipa": "/ˌfɜːst pɑːst ðə ˈpəʊst/", "pron": "first past thuh post", "fr": "scrutin uninominal majoritaire à un tour", "def": "The electoral system where the candidate with the most votes wins.", "ex": "First-past-the-post often favours larger parties."}, {"term": "hung parliament", "ipa": "/ˌhʌŋ ˈpɑːləmənt/", "pron": "hung PAR-luh-muhnt", "fr": "Parlement sans majorité absolue", "def": "A Parliament in which no party has an overall majority.", "ex": "A hung parliament can lead to coalition talks."}, {"term": "overall majority", "ipa": "/ˌəʊvərɔːl məˈdʒɒrəti/", "pron": "OH-vuh-rawl muh-JOR-uh-tee", "fr": "majorité absolue", "def": "A majority of seats held by one party in the House of Commons.", "ex": "The party won a large overall majority."}, {"term": "minority government", "ipa": "/maɪˌnɒrəti ˈɡʌvənmənt/", "pron": "my-NOR-uh-tee GUV-uhn-muhnt", "fr": "gouvernement minoritaire", "def": "A government formed by a party that does not hold a majority of seats.", "ex": "A minority government depends on support from other parties."}, {"term": "coalition government", "ipa": "/ˌkəʊəˈlɪʃən ˈɡʌvənmənt/", "pron": "koh-uh-LISH-uhn GUV-uhn-muhnt", "fr": "gouvernement de coalition", "def": "A government formed by two or more parties working together.", "ex": "The 2010 election produced a coalition government."}, {"term": "opposition", "ipa": "/ˌɒpəˈzɪʃən/", "pron": "op-uh-ZISH-uhn", "fr": "opposition", "def": "The parties or politicians not in government who scrutinise and challenge it.", "ex": "The opposition accused ministers of incompetence."}, {"term": "Leader of the Opposition", "ipa": "/ˌliːdər əv ði ˌɒpəˈzɪʃən/", "pron": "LEE-duh ov thee op-uh-ZISH-uhn", "fr": "chef de l’opposition", "def": "The leader of the largest party not in government.", "ex": "The Leader of the Opposition challenged the Prime Minister."}, {"term": "Shadow Cabinet", "ipa": "/ˈʃædəʊ ˈkæbɪnət/", "pron": "SHAD-oh KAB-i-nuht", "fr": "cabinet fantôme", "def": "The senior opposition team that scrutinises corresponding government ministers.", "ex": "The Shadow Cabinet proposed an alternative budget."}, {"term": "backbencher", "ipa": "/ˌbækˈbentʃə/", "pron": "bak-BEN-chuh", "fr": "député de base", "def": "An MP who is not a minister or party leader.", "ex": "Backbenchers can rebel against their own party."}, {"term": "frontbencher", "ipa": "/ˌfrʌntˈbentʃə/", "pron": "frunt-BEN-chuh", "fr": "membre du gouvernement ou de l’opposition officielle", "def": "A senior MP, usually a minister or shadow minister.", "ex": "Frontbenchers speak for their party on policy."}, {"term": "whip", "ipa": "/wɪp/", "pron": "wip", "fr": "whip ; responsable de discipline parlementaire", "def": "A party official who ensures MPs vote according to the party line.", "ex": "The whips tried to prevent a rebellion."}, {"term": "party discipline", "ipa": "/ˈpɑːti ˈdɪsəplɪn/", "pron": "PAR-tee DIS-uh-plin", "fr": "discipline de parti", "def": "Pressure on MPs to vote with their party.", "ex": "Party discipline is strong in the Westminster system."}, {"term": "rebellion", "ipa": "/rɪˈbeljən/", "pron": "ri-BEL-yuhn", "fr": "rébellion parlementaire", "def": "A situation where MPs vote against their party leadership.", "ex": "The government faced a backbench rebellion."}, {"term": "free vote", "ipa": "/ˌfriː ˈvəʊt/", "pron": "free voht", "fr": "vote libre", "def": "A vote where MPs may vote according to conscience rather than party instructions.", "ex": "Moral issues are sometimes decided by a free vote."}, {"term": "bill", "ipa": "/bɪl/", "pron": "bil", "fr": "projet de loi", "def": "A proposed law debated by Parliament.", "ex": "The bill passed its second reading."}, {"term": "Act of Parliament", "ipa": "/ˌækt əv ˈpɑːləmənt/", "pron": "akt ov PAR-luh-muhnt", "fr": "loi du Parlement", "def": "A law passed by Parliament.", "ex": "The Human Rights Act is an Act of Parliament."}]}, {"title": "E. Law-making, scrutiny and high-value verbs", "entries": [{"term": "legislation", "ipa": "/ˌledʒɪsˈleɪʃən/", "pron": "lej-is-LAY-shuhn", "fr": "législation", "def": "Laws or the process of making laws.", "ex": "The government introduced new legislation."}, {"term": "primary legislation", "ipa": "/ˌpraɪməri ˌledʒɪsˈleɪʃən/", "pron": "PRY-muh-ree lej-is-LAY-shuhn", "fr": "législation primaire", "def": "Main laws passed directly by Parliament.", "ex": "Primary legislation receives detailed parliamentary scrutiny."}, {"term": "secondary legislation", "ipa": "/ˌsekəndəri ˌledʒɪsˈleɪʃən/", "pron": "SEK-uhn-duh-ree lej-is-LAY-shuhn", "fr": "législation secondaire", "def": "Detailed rules made by ministers under powers granted by Parliament.", "ex": "Secondary legislation can be controversial because scrutiny is limited."}, {"term": "statutory instrument", "ipa": "/ˌstætʃʊtəri ˈɪnstrəmənt/", "pron": "STACH-oo-tuh-ree IN-struh-muhnt", "fr": "instrument réglementaire", "def": "A form of secondary legislation used to make detailed legal changes.", "ex": "Statutory instruments are often used to implement policy."}, {"term": "reading", "ipa": "/ˈriːdɪŋ/", "pron": "REE-ding", "fr": "lecture parlementaire", "def": "A formal stage in the passage of a bill through Parliament.", "ex": "The bill faced opposition at second reading."}, {"term": "committee stage", "ipa": "/kəˈmɪti steɪdʒ/", "pron": "kuh-MIT-ee stage", "fr": "examen en commission", "def": "The stage where a bill is examined in detail and amendments can be proposed.", "ex": "The bill was amended during committee stage."}, {"term": "amendment", "ipa": "/əˈmendmənt/", "pron": "uh-MEND-muhnt", "fr": "amendement", "def": "A proposed change to a bill or law.", "ex": "Peers proposed several amendments to the bill."}, {"term": "royal assent", "ipa": "/ˌrɔɪəl əˈsent/", "pron": "ROY-uhl uh-SENT", "fr": "sanction royale", "def": "The monarch’s formal approval of a bill, making it law.", "ex": "After royal assent, the bill became an Act."}, {"term": "parliamentary scrutiny", "ipa": "/ˌpɑːləˈmentəri ˈskruːtəni/", "pron": "par-luh-MEN-tuh-ree SKROO-tuh-nee", "fr": "contrôle parlementaire", "def": "The examination of government actions and laws by Parliament.", "ex": "Parliamentary scrutiny is essential for accountability."}, {"term": "select committee", "ipa": "/sɪˈlekt kəˌmɪti/", "pron": "si-LEKT kuh-MIT-ee", "fr": "commission spéciale ; commission parlementaire", "def": "A parliamentary committee that investigates policy areas or departments.", "ex": "Select committees can question ministers and experts."}, {"term": "Prime Minister’s Questions", "ipa": "/ˌpraɪm ˈmɪnɪstəz ˈkwestʃənz/", "pron": "prime MIN-i-stuhz KWES-chuhnz", "fr": "questions au Premier ministre ; PMQs", "def": "A weekly session where MPs question the Prime Minister.", "ex": "Prime Minister’s Questions are often combative."}, {"term": "PMQs", "ipa": "/ˌpiː em ˈkjuːz/", "pron": "pee-em-KYOOZ", "fr": "PMQs ; questions au Premier ministre", "def": "Abbreviation for Prime Minister’s Questions.", "ex": "PMQs are a highly visible part of British politics."}, {"term": "division", "ipa": "/dɪˈvɪʒən/", "pron": "di-VIZH-uhn", "fr": "vote formel ; division", "def": "A formal vote in the House of Commons or Lords.", "ex": "MPs were called to vote in a division."}, {"term": "to table an amendment", "ipa": "/ˈteɪbəl ən əˈmendmənt/", "pron": "TAY-buhl uhn uh-MEND-muhnt", "fr": "déposer un amendement", "def": "To formally propose a change to a bill or motion.", "ex": "Opposition MPs tabled amendments."}, {"term": "to pass a bill", "ipa": "/pɑːs ə bɪl/", "pron": "pass uh bil", "fr": "adopter un projet de loi", "def": "To approve a proposed law through Parliament.", "ex": "Parliament passed the bill after months of debate."}, {"term": "to repeal a law", "ipa": "/rɪˈpiːl ə lɔː/", "pron": "ri-PEEL uh law", "fr": "abroger une loi", "def": "To cancel or remove a law.", "ex": "Parliament can repeal any law."}, {"term": "to scrutinise the government", "ipa": "/ˈskruːtənaɪz ðə ˈɡʌvənmənt/", "pron": "SKROO-tuh-nyz thuh GUV-uhn-muhnt", "fr": "contrôler le gouvernement", "def": "To examine and challenge government decisions.", "ex": "MPs are expected to scrutinise the government."}, {"term": "to hold ministers accountable", "ipa": "/həʊld ˈmɪnɪstəz əˈkaʊntəbəl/", "pron": "hohld MIN-i-stuhz uh-KOWN-tuh-buhl", "fr": "demander des comptes aux ministres", "def": "To make ministers answer for decisions and failures.", "ex": "Parliament should hold ministers accountable."}, {"term": "to command a majority", "ipa": "/kəˈmɑːnd ə məˈdʒɒrəti/", "pron": "kuh-MAND uh muh-JOR-uh-tee", "fr": "disposer d’une majorité", "def": "To have enough parliamentary support to govern.", "ex": "The Prime Minister must command a majority in the Commons."}, {"term": "to lose the confidence of Parliament", "ipa": "/luːz ðə ˈkɒnfɪdəns əv ˈpɑːləmənt/", "pron": "looz thuh KON-fi-duhns ov PAR-luh-muhnt", "fr": "perdre la confiance du Parlement", "def": "To no longer have enough parliamentary support to remain in office.", "ex": "A government that loses the confidence of Parliament may fall."}, {"term": "to call a general election", "ipa": "/kɔːl ə ˌdʒenərəl ɪˈlekʃən/", "pron": "call uh JEN-uh-ruhl i-LEK-shuhn", "fr": "convoquer des élections législatives", "def": "To announce or trigger a national election.", "ex": "The Prime Minister called a general election."}, {"term": "to form a government", "ipa": "/fɔːm ə ˈɡʌvənmənt/", "pron": "form uh GUV-uhn-muhnt", "fr": "former un gouvernement", "def": "To create a government after an election or agreement.", "ex": "The largest party tried to form a government."}, {"term": "to resign", "ipa": "/rɪˈzaɪn/", "pron": "ri-ZYNE", "fr": "démissionner", "def": "To leave a job or political office voluntarily.", "ex": "The minister was forced to resign."}, {"term": "to reshuffle the Cabinet", "ipa": "/riːˈʃʌfəl ðə ˈkæbɪnət/", "pron": "ree-SHUF-uhl thuh KAB-i-nuht", "fr": "remanie le cabinet ; procéder à un remaniement ministériel", "def": "To change which ministers hold which government positions.", "ex": "The Prime Minister reshuffled the Cabinet after the scandal."}, {"term": "to prorogue Parliament", "ipa": "/prəˈrəʊɡ ˈpɑːləmənt/", "pron": "pruh-ROHG PAR-luh-muhnt", "fr": "proroger le Parlement", "def": "To formally suspend a parliamentary session.", "ex": "The decision to prorogue Parliament triggered a constitutional crisis."}, {"term": "to dissolve Parliament", "ipa": "/dɪˈzɒlv ˈpɑːləmənt/", "pron": "di-ZOLV PAR-luh-muhnt", "fr": "dissoudre le Parlement", "def": "To formally end a Parliament before a general election.", "ex": "Parliament is dissolved before a general election."}, {"term": "to restore parliamentary sovereignty", "ipa": "/rɪˈstɔː ˌpɑːləˈmentəri ˈsɒvrənti/", "pron": "ri-STORE par-luh-MEN-tuh-ree SOV-ruhn-tee", "fr": "restaurer la souveraineté parlementaire", "def": "To bring legislative authority back to Parliament, often used in Brexit debates.", "ex": "Brexit supporters claimed they wanted to restore parliamentary sovereignty."}]}]}, {"id": "p3c23", "part": 3, "chapter": 23, "title": "The Monarchy", "file": "cpge_vocab_part3_chapter23_the_monarchy_premium.html", "count": 110, "sections": [{"title": "A. Core monarchy vocabulary and succession", "entries": [{"term": "monarchy", "ipa": "/ˈmɒnəki/", "pron": "MON-uh-kee", "fr": "monarchie", "def": "A political system in which a king or queen serves as head of state.", "ex": "The British monarchy is both a political institution and a national symbol."}, {"term": "constitutional monarchy", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈmɒnəki/", "pron": "kon-sti-TOO-shuh-nuhl MON-uh-kee", "fr": "monarchie constitutionnelle", "def": "A system in which a monarch is head of state but political power is limited by law and exercised by elected institutions.", "ex": "The UK is a constitutional monarchy, not an absolute monarchy."}, {"term": "absolute monarchy", "ipa": "/ˌæbsəluːt ˈmɒnəki/", "pron": "AB-suh-loot MON-uh-kee", "fr": "monarchie absolue", "def": "A monarchy in which the monarch has very broad or unlimited political power.", "ex": "Britain moved away from absolute monarchy after centuries of constitutional conflict."}, {"term": "monarch", "ipa": "/ˈmɒnək/", "pron": "MON-uhk", "fr": "monarque", "def": "A king or queen who serves as head of state.", "ex": "The monarch formally appoints the Prime Minister."}, {"term": "king", "ipa": "/kɪŋ/", "pron": "king", "fr": "roi", "def": "A male monarch.", "ex": "The king performs ceremonial duties."}, {"term": "queen", "ipa": "/kwiːn/", "pron": "kween", "fr": "reine", "def": "A female monarch.", "ex": "Queen Elizabeth II reigned for more than seventy years."}, {"term": "sovereign", "ipa": "/ˈsɒvrɪn/", "pron": "SOV-rin", "fr": "souverain ; souveraine", "def": "A formal term for the monarch as the supreme symbolic authority of the state.", "ex": "The sovereign opens Parliament every year."}, {"term": "head of state", "ipa": "/ˌhed əv ˈsteɪt/", "pron": "hed ov state", "fr": "chef de l’État", "def": "The official representative of a country in constitutional and ceremonial matters.", "ex": "In Britain, the monarch is head of state."}, {"term": "head of government", "ipa": "/ˌhed əv ˈɡʌvənmənt/", "pron": "hed ov GUV-uhn-muhnt", "fr": "chef du gouvernement", "def": "The political leader who runs the government.", "ex": "The Prime Minister, not the monarch, is head of government."}, {"term": "the Crown", "ipa": "/ðə ˈkraʊn/", "pron": "thuh crown", "fr": "la Couronne", "def": "The legal and symbolic authority of the state, formally embodied by the monarch.", "ex": "Ministers exercise power in the name of the Crown."}, {"term": "Crown Estate", "ipa": "/ˌkraʊn ɪˈsteɪt/", "pron": "crown i-STAYT", "fr": "Crown Estate ; patrimoine de la Couronne", "def": "A large property portfolio belonging to the Crown but managed independently, with profits mostly going to the Treasury.", "ex": "The Crown Estate is often discussed in debates about royal finances."}, {"term": "royal family", "ipa": "/ˌrɔɪəl ˈfæməli/", "pron": "ROY-uhl FAM-uh-lee", "fr": "famille royale", "def": "The monarch’s family, especially senior members with public roles.", "ex": "The royal family attracts intense media attention."}, {"term": "House of Windsor", "ipa": "/ˌhaʊs əv ˈwɪnzə/", "pron": "howss ov WIN-zuh", "fr": "maison de Windsor", "def": "The current royal house of the United Kingdom.", "ex": "The House of Windsor has ruled Britain since 1917."}, {"term": "heir", "ipa": "/eə/", "pron": "air", "fr": "héritier ; héritière", "def": "The person expected to inherit the throne.", "ex": "The heir to the throne often prepares for a lifetime of public duty."}, {"term": "heir apparent", "ipa": "/ˌeər əˈpærənt/", "pron": "air uh-PARR-uhnt", "fr": "héritier présomptif direct", "def": "The person who is certain to inherit the throne unless they die first.", "ex": "The Prince of Wales is traditionally the heir apparent."}, {"term": "line of succession", "ipa": "/ˌlaɪn əv səkˈseʃən/", "pron": "line ov suhk-SESH-uhn", "fr": "ordre de succession", "def": "The order in which people are entitled to inherit the throne.", "ex": "The line of succession is regulated by law."}, {"term": "succession", "ipa": "/səkˈseʃən/", "pron": "suhk-SESH-uhn", "fr": "succession", "def": "The process by which the throne passes from one monarch to the next.", "ex": "The succession was carefully planned after the Queen’s death."}, {"term": "coronation", "ipa": "/ˌkɒrəˈneɪʃən/", "pron": "kor-uh-NAY-shuhn", "fr": "couronnement", "def": "The ceremony in which a monarch is formally crowned.", "ex": "The coronation is a religious and constitutional ceremony."}, {"term": "accession", "ipa": "/əkˈseʃən/", "pron": "uhk-SESH-uhn", "fr": "avènement ; accession au trône", "def": "The moment when a new monarch takes the throne.", "ex": "The king’s accession occurred immediately after the queen’s death."}, {"term": "reign", "ipa": "/reɪn/", "pron": "rayn", "fr": "règne", "def": "The period during which a monarch rules or serves as monarch.", "ex": "Elizabeth II’s reign was the longest in British history."}, {"term": "abdication", "ipa": "/ˌæbdɪˈkeɪʃən/", "pron": "ab-di-KAY-shuhn", "fr": "abdication", "def": "The act of giving up the throne voluntarily.", "ex": "Edward VIII’s abdication created a constitutional crisis."}, {"term": "to abdicate", "ipa": "/ˈæbdɪkeɪt/", "pron": "AB-di-kayt", "fr": "abdiquer", "def": "To give up the throne voluntarily.", "ex": "Edward VIII abdicated in 1936."}, {"term": "regent", "ipa": "/ˈriːdʒənt/", "pron": "REE-juhnt", "fr": "régent ; régente", "def": "A person who rules temporarily when the monarch is unable to do so.", "ex": "A regent may be appointed if the monarch is incapacitated."}, {"term": "royal assent", "ipa": "/ˌrɔɪəl əˈsent/", "pron": "ROY-uhl uh-SENT", "fr": "sanction royale", "def": "The monarch’s formal approval of a bill, making it law.", "ex": "Royal assent is now a constitutional formality."}]}, {"title": "B. Constitutional role, ceremonies and symbolic power", "entries": [{"term": "royal prerogative", "ipa": "/ˌrɔɪəl prɪˈrɒɡətɪv/", "pron": "ROY-uhl pri-ROG-uh-tiv", "fr": "prérogative royale", "def": "Traditional executive powers formally held by the monarch but exercised by ministers.", "ex": "The royal prerogative is important in foreign policy and defence."}, {"term": "reserve powers", "ipa": "/rɪˈzɜːv ˈpaʊəz/", "pron": "ri-ZURV POW-uhz", "fr": "pouvoirs de réserve", "def": "Exceptional powers that a monarch or representative may theoretically use in a constitutional crisis.", "ex": "Reserve powers are rarely used in modern Britain."}, {"term": "ceremonial role", "ipa": "/ˌserəˈməʊniəl rəʊl/", "pron": "ser-uh-MOH-nee-uhl rohl", "fr": "rôle cérémoniel", "def": "A symbolic public role involving ceremonies rather than direct political power.", "ex": "The monarch’s role is largely ceremonial."}, {"term": "symbolic role", "ipa": "/sɪmˈbɒlɪk rəʊl/", "pron": "sim-BOL-ik rohl", "fr": "rôle symbolique", "def": "A role based on representing unity, continuity or national identity.", "ex": "The monarchy plays a symbolic role in national life."}, {"term": "political neutrality", "ipa": "/pəˌlɪtɪkəl njuːˈtræləti/", "pron": "puh-LIT-i-kuhl nyoo-TRAL-uh-tee", "fr": "neutralité politique", "def": "The principle of not publicly taking sides in party politics.", "ex": "Political neutrality is essential to the modern monarchy."}, {"term": "above politics", "ipa": "/əˌbʌv ˈpɒlɪtɪks/", "pron": "uh-BUV POL-i-tiks", "fr": "au-dessus de la politique", "def": "Not involved in partisan political conflict.", "ex": "The monarch is expected to remain above politics."}, {"term": "impartiality", "ipa": "/ˌɪmpɑːʃiˈæləti/", "pron": "im-par-shee-AL-uh-tee", "fr": "impartialité", "def": "Fairness and neutrality between opposing sides.", "ex": "Royal impartiality helps preserve the monarchy’s legitimacy."}, {"term": "soft power", "ipa": "/ˈsɒft ˌpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; pouvoir d’influence", "def": "Influence based on attraction, culture and diplomacy rather than force.", "ex": "The royal family contributes to Britain’s soft power."}, {"term": "national unity", "ipa": "/ˌnæʃənəl ˈjuːnəti/", "pron": "NASH-uh-nuhl YOO-nuh-tee", "fr": "unité nationale", "def": "A sense that citizens belong to the same national community.", "ex": "Supporters argue that the monarchy represents national unity."}, {"term": "continuity", "ipa": "/ˌkɒntɪˈnjuːəti/", "pron": "kon-ti-NYOO-uh-tee", "fr": "continuité", "def": "The sense of stability and connection with the past.", "ex": "The monarchy provides a sense of continuity during political change."}, {"term": "tradition", "ipa": "/trəˈdɪʃən/", "pron": "truh-DISH-uhn", "fr": "tradition", "def": "Customs and practices inherited from the past.", "ex": "Royal ceremonies are rich in tradition."}, {"term": "pageantry", "ipa": "/ˈpædʒəntri/", "pron": "PAJ-uhn-tree", "fr": "apparat ; cérémonial fastueux", "def": "Elaborate public ceremony, costumes and display.", "ex": "Royal pageantry attracts tourists and global media coverage."}, {"term": "pomp and circumstance", "ipa": "/ˌpɒmp ən ˈsɜːkəmstəns/", "pron": "pomp uhn SUR-kuhm-stans", "fr": "apparat et solennité", "def": "Formal ceremony, splendour and spectacle.", "ex": "The coronation was full of pomp and circumstance."}, {"term": "royal ceremony", "ipa": "/ˌrɔɪəl ˈserəməni/", "pron": "ROY-uhl SERR-uh-muh-nee", "fr": "cérémonie royale", "def": "A formal public event involving the monarch or royal family.", "ex": "Royal ceremonies reinforce national tradition."}, {"term": "State Opening of Parliament", "ipa": "/ˌsteɪt ˈəʊpənɪŋ əv ˈpɑːləmənt/", "pron": "state OH-puh-ning ov PAR-luh-muhnt", "fr": "ouverture officielle du Parlement", "def": "The ceremony marking the beginning of a parliamentary session, including the monarch’s speech.", "ex": "The State Opening of Parliament combines politics and royal ritual."}, {"term": "King’s Speech", "ipa": "/ˌkɪŋz ˈspiːtʃ/", "pron": "kingz speech", "fr": "discours du roi", "def": "The speech delivered by the monarch setting out the government’s legislative agenda.", "ex": "The King’s Speech is written by the government."}, {"term": "Queen’s Speech", "ipa": "/ˌkwiːnz ˈspiːtʃ/", "pron": "kweenz speech", "fr": "discours de la reine", "def": "The same parliamentary speech when the monarch is a queen.", "ex": "The Queen’s Speech outlined the government’s priorities."}, {"term": "Privy Council", "ipa": "/ˌprɪvi ˈkaʊnsəl/", "pron": "PRIV-ee KOWN-suhl", "fr": "Conseil privé", "def": "A formal advisory body to the monarch, now mostly ceremonial but still used for certain official acts.", "ex": "Orders in Council are formally approved through the Privy Council."}, {"term": "Order in Council", "ipa": "/ˌɔːdər ɪn ˈkaʊnsəl/", "pron": "OR-duh in KOWN-suhl", "fr": "décret en conseil", "def": "A legal instrument formally made by the monarch with the Privy Council.", "ex": "Some executive decisions are made through Orders in Council."}, {"term": "to appoint the Prime Minister", "ipa": "/əˈpɔɪnt ðə ˌpraɪm ˈmɪnɪstə/", "pron": "uh-POINT thuh prime MIN-i-stuh", "fr": "nommer le Premier ministre", "def": "To formally name the person who can command Commons confidence as Prime Minister.", "ex": "The monarch appoints the Prime Minister after a general election."}, {"term": "to open Parliament", "ipa": "/ˈəʊpən ˈpɑːləmənt/", "pron": "OH-puhn PAR-luh-muhnt", "fr": "ouvrir le Parlement", "def": "To formally begin a parliamentary session through ceremony.", "ex": "The monarch opens Parliament in a highly symbolic ceremony."}, {"term": "to grant royal assent", "ipa": "/ɡrɑːnt ˌrɔɪəl əˈsent/", "pron": "grant ROY-uhl uh-SENT", "fr": "donner la sanction royale", "def": "To formally approve a bill so that it becomes law.", "ex": "The monarch grants royal assent to bills passed by Parliament."}, {"term": "to act on advice", "ipa": "/ækt ɒn ədˈvaɪs/", "pron": "akt on ad-VYSS", "fr": "agir sur avis ministériel", "def": "To follow the advice of ministers, as the monarch normally does.", "ex": "The monarch normally acts on the advice of the Prime Minister."}, {"term": "to remain politically neutral", "ipa": "/rɪˈmeɪn pəˌlɪtɪkəli ˈnjuːtrəl/", "pron": "ri-MAYN puh-LIT-i-kuh-lee NYOO-truhl", "fr": "rester politiquement neutre", "def": "To avoid taking public political positions.", "ex": "The monarch must remain politically neutral."}, {"term": "to embody the nation", "ipa": "/ɪmˈbɒdi ðə ˈneɪʃən/", "pron": "im-BOD-ee thuh NAY-shuhn", "fr": "incarner la nation", "def": "To represent the nation symbolically.", "ex": "Supporters claim the monarch embodies the nation."}]}, {"title": "C. Royal duties, Commonwealth and public service", "entries": [{"term": "to symbolise continuity", "ipa": "/ˈsɪmbəlaɪz ˌkɒntɪˈnjuːəti/", "pron": "SIM-buh-lyz kon-ti-NYOO-uh-tee", "fr": "symboliser la continuité", "def": "To represent stability and historical connection.", "ex": "The monarchy symbolises continuity in a changing society."}, {"term": "royal household", "ipa": "/ˌrɔɪəl ˈhaʊshəʊld/", "pron": "ROY-uhl HOWSS-hohld", "fr": "maison royale", "def": "The organisation that supports the monarch and royal family.", "ex": "The royal household manages official engagements."}, {"term": "royal duties", "ipa": "/ˌrɔɪəl ˈdjuːtiz/", "pron": "ROY-uhl DYOO-teez", "fr": "devoirs royaux", "def": "Official responsibilities performed by members of the royal family.", "ex": "Senior royals carry out hundreds of royal duties each year."}, {"term": "official engagement", "ipa": "/əˌfɪʃəl ɪnˈɡeɪdʒmənt/", "pron": "uh-FISH-uhl in-GAYJ-muhnt", "fr": "engagement officiel", "def": "A public event attended by a royal as part of their duties.", "ex": "The princess attended an official engagement at a hospital."}, {"term": "patronage", "ipa": "/ˈpætrənɪdʒ/", "pron": "PAT-ruh-nij", "fr": "patronage ; soutien officiel", "def": "Support given by a royal to a charity, organisation or cause.", "ex": "Royal patronage can raise a charity’s profile."}, {"term": "charity work", "ipa": "/ˈtʃærəti wɜːk/", "pron": "CHARR-uh-tee work", "fr": "travail caritatif", "def": "Work supporting charitable causes.", "ex": "Charity work is a major part of modern royal activity."}, {"term": "public service", "ipa": "/ˌpʌblɪk ˈsɜːvɪs/", "pron": "PUB-lik SUR-vis", "fr": "service public", "def": "Work performed for the benefit of the public.", "ex": "The monarchy presents itself as devoted to public service."}, {"term": "royal tour", "ipa": "/ˌrɔɪəl ˈtʊə/", "pron": "ROY-uhl tour", "fr": "tournée royale", "def": "An official visit by a royal to another country or region.", "ex": "Royal tours can strengthen diplomatic ties but also provoke criticism."}, {"term": "Commonwealth", "ipa": "/ˈkɒmənwelθ/", "pron": "KOM-uhn-welth", "fr": "Commonwealth", "def": "An association of countries, many formerly part of the British Empire.", "ex": "The monarch is Head of the Commonwealth."}, {"term": "Head of the Commonwealth", "ipa": "/ˌhed əv ðə ˈkɒmənwelθ/", "pron": "hed ov thuh KOM-uhn-welth", "fr": "chef du Commonwealth", "def": "The symbolic leader of the Commonwealth.", "ex": "The title Head of the Commonwealth is not hereditary in the same way as the Crown."}, {"term": "Commonwealth realm", "ipa": "/ˈkɒmənwelθ relm/", "pron": "KOM-uhn-welth relm", "fr": "royaume du Commonwealth", "def": "A Commonwealth country where the British monarch is also head of state.", "ex": "Canada and Australia are Commonwealth realms."}, {"term": "realm", "ipa": "/relm/", "pron": "relm", "fr": "royaume", "def": "A kingdom or state under a monarch.", "ex": "The monarch is sovereign of several realms."}, {"term": "republicanism", "ipa": "/rɪˈpʌblɪkənɪzəm/", "pron": "ri-PUB-li-kuh-niz-uhm", "fr": "républicanisme", "def": "Support for replacing the monarchy with a republic.", "ex": "Republicanism remains a minority view in Britain, but it has gained visibility."}, {"term": "republican", "ipa": "/rɪˈpʌblɪkən/", "pron": "ri-PUB-li-kuhn", "fr": "républicain ; opposant à la monarchie", "def": "A person who supports replacing the monarchy with an elected head of state.", "ex": "Republicans argue that the monarchy is undemocratic."}, {"term": "anti-monarchist", "ipa": "/ˌænti ˈmɒnəkɪst/", "pron": "AN-tee MON-uh-kist", "fr": "anti-monarchiste", "def": "Opposed to monarchy.", "ex": "Anti-monarchist campaigners protested during the coronation."}, {"term": "abolition of the monarchy", "ipa": "/ˌæbəˈlɪʃən əv ðə ˈmɒnəki/", "pron": "ab-uh-LISH-uhn ov thuh MON-uh-kee", "fr": "abolition de la monarchie", "def": "The act of ending the monarchy as an institution.", "ex": "Some campaigners call for the abolition of the monarchy."}, {"term": "elected head of state", "ipa": "/ɪˌlektɪd ˌhed əv ˈsteɪt/", "pron": "i-LEK-tid hed ov state", "fr": "chef de l’État élu", "def": "A head of state chosen by election rather than inheritance.", "ex": "Republicans want an elected head of state."}, {"term": "hereditary privilege", "ipa": "/həˌredɪtəri ˈprɪvəlɪdʒ/", "pron": "huh-RED-i-tuh-ree PRIV-uh-lij", "fr": "privilège héréditaire", "def": "Advantages passed down by birth within a family.", "ex": "Critics say monarchy is based on hereditary privilege."}, {"term": "inherited status", "ipa": "/ɪnˌherɪtɪd ˈsteɪtəs/", "pron": "in-HER-i-tid STAY-tuhs", "fr": "statut hérité", "def": "Social position received by birth rather than merit.", "ex": "The monarchy embodies inherited status."}]}, {"title": "D. Criticism, legitimacy, money and national identity", "entries": [{"term": "democratic legitimacy", "ipa": "/ˌdeməˈkrætɪk lɪˈdʒɪtɪməsi/", "pron": "dem-uh-KRAT-ik li-JIT-i-muh-see", "fr": "légitimité démocratique", "def": "The right to hold power because of democratic consent.", "ex": "Critics question the monarchy’s democratic legitimacy."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "The obligation to answer for decisions, spending or behaviour.", "ex": "Royal accountability is a recurring issue."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PARR-uhn-see", "fr": "transparence", "def": "Openness about decisions, finances or actions.", "ex": "Campaigners demand more transparency over royal finances."}, {"term": "public funding", "ipa": "/ˌpʌblɪk ˈfʌndɪŋ/", "pron": "PUB-lik FUN-ding", "fr": "financement public", "def": "Money provided by taxpayers or the state.", "ex": "Public funding of the monarchy is controversial."}, {"term": "taxpayer money", "ipa": "/ˈtækspeɪə ˈmʌni/", "pron": "TAKS-pay-uh MUN-ee", "fr": "argent des contribuables", "def": "Money paid by citizens through taxes.", "ex": "Critics object to taxpayer money funding royal ceremonies."}, {"term": "Sovereign Grant", "ipa": "/ˌsɒvrɪn ˈɡrɑːnt/", "pron": "SOV-rin grant", "fr": "Sovereign Grant ; dotation souveraine", "def": "Public money used to fund the monarch’s official duties.", "ex": "The Sovereign Grant funds official royal work."}, {"term": "royal finances", "ipa": "/ˌrɔɪəl ˈfaɪnænsɪz/", "pron": "ROY-uhl FY-nan-siz", "fr": "finances royales", "def": "The money, property and funding arrangements of the monarchy.", "ex": "Royal finances are often criticised for lacking transparency."}, {"term": "cost of the monarchy", "ipa": "/ˌkɒst əv ðə ˈmɒnəki/", "pron": "kost ov thuh MON-uh-kee", "fr": "coût de la monarchie", "def": "The financial cost of maintaining the monarchy.", "ex": "The cost of the monarchy is debated during economic hardship."}, {"term": "tourism revenue", "ipa": "/ˈtʊərɪzəm ˈrevənjuː/", "pron": "TOOR-iz-uhm REV-uhn-yoo", "fr": "revenus touristiques", "def": "Money generated by visitors and tourism.", "ex": "Supporters argue that the monarchy brings tourism revenue."}, {"term": "brand Britain", "ipa": "/ˌbrænd ˈbrɪtən/", "pron": "brand BRIT-uhn", "fr": "marque Royaume-Uni ; image internationale du Royaume-Uni", "def": "The global image and attractiveness of the UK as a national brand.", "ex": "The monarchy is often presented as part of Brand Britain."}, {"term": "national identity", "ipa": "/ˌnæʃənəl aɪˈdentəti/", "pron": "NASH-uh-nuhl eye-DEN-tuh-tee", "fr": "identité nationale", "def": "A shared sense of belonging to a nation.", "ex": "The monarchy remains tied to British national identity."}, {"term": "Britishness", "ipa": "/ˈbrɪtɪʃnəs/", "pron": "BRIT-ish-nuhs", "fr": "britannicité ; identité britannique", "def": "The quality or identity of being British.", "ex": "The monarchy is often used as a symbol of Britishness."}, {"term": "patriotism", "ipa": "/ˈpætriətɪzəm/", "pron": "PAT-ree-uh-tiz-uhm", "fr": "patriotisme", "def": "Love or pride in one’s country.", "ex": "Royal events often generate displays of patriotism."}, {"term": "loyalty", "ipa": "/ˈlɔɪəlti/", "pron": "LOY-uhl-tee", "fr": "loyauté", "def": "Faithful support for a person, institution or country.", "ex": "The monarchy depends partly on public loyalty."}, {"term": "royalist", "ipa": "/ˈrɔɪəlɪst/", "pron": "ROY-uh-list", "fr": "royaliste", "def": "A person who supports the monarchy.", "ex": "Royalists see the monarchy as a source of stability."}, {"term": "public support", "ipa": "/ˌpʌblɪk səˈpɔːt/", "pron": "PUB-lik suh-PORT", "fr": "soutien public", "def": "Approval or backing from the public.", "ex": "Public support for the monarchy varies by age group."}, {"term": "approval rating", "ipa": "/əˈpruːvəl ˈreɪtɪŋ/", "pron": "uh-PROO-vuhl RAY-ting", "fr": "taux d’approbation ; cote de popularité", "def": "A measure of how many people approve of someone or something.", "ex": "The monarch’s approval rating remains important for legitimacy."}, {"term": "generational divide", "ipa": "/ˌdʒenəˈreɪʃənəl dɪˈvaɪd/", "pron": "jen-uh-RAY-shuh-nuhl di-VYDE", "fr": "fracture générationnelle", "def": "A difference in opinion between age groups.", "ex": "There is a generational divide in attitudes towards the monarchy."}, {"term": "media scrutiny", "ipa": "/ˈmiːdiə ˈskruːtəni/", "pron": "MEE-dee-uh SKROO-tuh-nee", "fr": "surveillance médiatique ; examen médiatique", "def": "Close examination by newspapers, television and online media.", "ex": "The royal family lives under constant media scrutiny."}, {"term": "tabloid press", "ipa": "/ˈtæblɔɪd pres/", "pron": "TAB-loyd press", "fr": "presse tabloïd", "def": "Popular newspapers often focused on scandal, celebrities and sensational stories.", "ex": "The tabloid press has shaped the public image of the royals."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "The right to keep personal life away from public attention.", "ex": "Royal privacy often clashes with public interest."}, {"term": "public interest", "ipa": "/ˌpʌblɪk ˈɪntrəst/", "pron": "PUB-lik IN-truhst", "fr": "intérêt public", "def": "The idea that information should be known because it matters to society.", "ex": "Journalists defend royal coverage as a matter of public interest."}, {"term": "scandal", "ipa": "/ˈskændəl/", "pron": "SKAN-duhl", "fr": "scandale", "def": "An event involving wrongdoing or disgrace that attracts public criticism.", "ex": "Royal scandals can damage the monarchy’s reputation."}]}, {"title": "E. Media, modernisation, empire and high-value verbs", "entries": [{"term": "reputation", "ipa": "/ˌrepjʊˈteɪʃən/", "pron": "rep-yuh-TAY-shuhn", "fr": "réputation", "def": "The general opinion people have of someone or something.", "ex": "The monarchy’s reputation depends on public trust."}, {"term": "crisis management", "ipa": "/ˈkraɪsɪs ˈmænɪdʒmənt/", "pron": "KRY-sis MAN-ij-muhnt", "fr": "gestion de crise", "def": "The handling of serious public problems or scandals.", "ex": "The royal household has often struggled with crisis management."}, {"term": "modernisation", "ipa": "/ˌmɒdənaɪˈzeɪʃən/", "pron": "MOD-uh-ny-ZAY-shuhn", "fr": "modernisation", "def": "The process of updating an institution to fit modern expectations.", "ex": "Many argue that the monarchy needs modernisation."}, {"term": "slimmed-down monarchy", "ipa": "/ˌslɪmd daʊn ˈmɒnəki/", "pron": "slimd-down MON-uh-kee", "fr": "monarchie réduite ; monarchie allégée", "def": "A monarchy with fewer working royals and lower public cost.", "ex": "A slimmed-down monarchy may be more acceptable to taxpayers."}, {"term": "relevance", "ipa": "/ˈreləvəns/", "pron": "REL-uh-vuhns", "fr": "pertinence", "def": "The quality of still being useful, meaningful or important.", "ex": "The monarchy must prove its relevance to younger generations."}, {"term": "anachronism", "ipa": "/əˈnækrənɪzəm/", "pron": "uh-NAK-ruh-niz-uhm", "fr": "anachronisme", "def": "Something that seems outdated or belonging to a past era.", "ex": "Critics call the monarchy an anachronism."}, {"term": "colonial legacy", "ipa": "/kəˌləʊniəl ˈleɡəsi/", "pron": "kuh-LOH-nee-uhl LEG-uh-see", "fr": "héritage colonial", "def": "The lasting effects of colonial rule and empire.", "ex": "The monarchy is increasingly judged through Britain’s colonial legacy."}, {"term": "British Empire", "ipa": "/ˌbrɪtɪʃ ˈempaɪə/", "pron": "BRIT-ish EM-py-uh", "fr": "Empire britannique", "def": "The former global empire ruled or controlled by Britain.", "ex": "The monarchy was closely linked to the British Empire."}, {"term": "decolonisation", "ipa": "/ˌdiːkɒlənaɪˈzeɪʃən/", "pron": "dee-kol-uh-ny-ZAY-shuhn", "fr": "décolonisation", "def": "The process by which colonies became independent from imperial rule.", "ex": "Decolonisation changed the monarchy’s global role."}, {"term": "Commonwealth criticism", "ipa": "/ˈkɒmənwelθ ˈkrɪtɪsɪzəm/", "pron": "KOM-uhn-welth KRIT-i-siz-uhm", "fr": "critique de la monarchie dans le Commonwealth", "def": "Criticism of the monarchy’s role in Commonwealth countries.", "ex": "Commonwealth criticism has grown in some Caribbean countries."}, {"term": "reparations debate", "ipa": "/ˌrepəˈreɪʃənz dɪˌbeɪt/", "pron": "rep-uh-RAY-shuhnz di-BAYT", "fr": "débat sur les réparations", "def": "Debate over compensation or apology for slavery and colonialism.", "ex": "The reparations debate has put pressure on the monarchy."}, {"term": "to defend the monarchy", "ipa": "/dɪˈfend ðə ˈmɒnəki/", "pron": "di-FEND thuh MON-uh-kee", "fr": "défendre la monarchie", "def": "To argue in favour of keeping the monarchy.", "ex": "Royalists defend the monarchy as a stabilising institution."}, {"term": "to abolish the monarchy", "ipa": "/əˈbɒlɪʃ ðə ˈmɒnəki/", "pron": "uh-BOL-ish thuh MON-uh-kee", "fr": "abolir la monarchie", "def": "To end the monarchy and replace it with another system.", "ex": "Republicans want to abolish the monarchy."}, {"term": "to question royal privilege", "ipa": "/ˈkwestʃən ˈrɔɪəl ˈprɪvəlɪdʒ/", "pron": "KWES-chuhn ROY-uhl PRIV-uh-lij", "fr": "remettre en question les privilèges royaux", "def": "To challenge the advantages enjoyed by the royal family.", "ex": "Younger voters are more likely to question royal privilege."}, {"term": "to maintain political neutrality", "ipa": "/meɪnˈteɪn pəˌlɪtɪkəl njuːˈtræləti/", "pron": "mayn-TAYN puh-LIT-i-kuhl nyoo-TRAL-uh-tee", "fr": "maintenir la neutralité politique", "def": "To avoid partisan political positions.", "ex": "The monarch must maintain political neutrality."}, {"term": "to attract media attention", "ipa": "/əˈtrækt ˈmiːdiə əˈtenʃən/", "pron": "uh-TRAKT MEE-dee-uh uh-TEN-shuhn", "fr": "attirer l’attention des médias", "def": "To draw coverage from newspapers, television or online media.", "ex": "Royal disputes attract media attention worldwide."}, {"term": "to boost tourism", "ipa": "/buːst ˈtʊərɪzəm/", "pron": "boost TOOR-iz-uhm", "fr": "stimuler le tourisme", "def": "To increase tourism activity or revenue.", "ex": "Supporters claim royal events boost tourism."}, {"term": "to damage public trust", "ipa": "/ˈdæmɪdʒ ˌpʌblɪk ˈtrʌst/", "pron": "DAM-ij PUB-lik trust", "fr": "nuire à la confiance du public", "def": "To reduce public confidence in an institution.", "ex": "Scandals can damage public trust in the monarchy."}, {"term": "to adapt to modern society", "ipa": "/əˈdæpt tə ˈmɒdən səˈsaɪəti/", "pron": "uh-DAPT tuh MOD-uhn suh-SY-uh-tee", "fr": "s’adapter à la société moderne", "def": "To change in order to remain relevant in contemporary life.", "ex": "The monarchy must adapt to modern society."}]}]}, {"id": "p3c24", "part": 3, "chapter": 24, "title": "Brexit", "file": "cpge_vocab_part3_chapter24_brexit_premium.html", "count": 115, "sections": [{"title": "A. Core Brexit vocabulary and campaign language", "entries": [{"term": "Brexit", "ipa": "/ˈbreksɪt/", "pron": "BREK-sit", "fr": "Brexit", "def": "The United Kingdom’s withdrawal from the European Union.", "ex": "Brexit reshaped British politics, trade and national identity."}, {"term": "European Union", "ipa": "/ˌjʊərəpiːən ˈjuːniən/", "pron": "YOO-ruh-pee-uhn YOO-nee-uhn", "fr": "Union européenne", "def": "A political and economic union of European member states.", "ex": "The UK voted to leave the European Union in 2016."}, {"term": "EU membership", "ipa": "/ˌiː juː ˈmembəʃɪp/", "pron": "ee-yoo MEM-buh-ship", "fr": "appartenance à l’Union européenne", "def": "The status of belonging to the European Union.", "ex": "EU membership gave Britain access to the single market."}, {"term": "withdrawal", "ipa": "/wɪðˈdrɔːəl/", "pron": "with-DRAW-uhl", "fr": "retrait", "def": "The act of leaving an organisation, treaty or agreement.", "ex": "The withdrawal from the EU required complex negotiations."}, {"term": "withdrawal agreement", "ipa": "/wɪðˈdrɔːəl əˌɡriːmənt/", "pron": "with-DRAW-uhl uh-GREE-muhnt", "fr": "accord de retrait", "def": "The treaty setting out the terms of the UK’s departure from the EU.", "ex": "The withdrawal agreement was fiercely debated in Parliament."}, {"term": "referendum", "ipa": "/ˌrefəˈrendəm/", "pron": "ref-uh-REN-duhm", "fr": "référendum", "def": "A direct vote by citizens on a specific political question.", "ex": "The 2016 referendum asked voters whether the UK should remain in or leave the EU."}, {"term": "Leave campaign", "ipa": "/ˈliːv kæmˌpeɪn/", "pron": "leev kam-PAYN", "fr": "campagne du Leave ; campagne pour la sortie", "def": "The campaign supporting the UK’s departure from the EU.", "ex": "The Leave campaign promised to take back control."}, {"term": "Remain campaign", "ipa": "/rɪˈmeɪn kæmˌpeɪn/", "pron": "ri-MAYN kam-PAYN", "fr": "campagne du Remain ; campagne pour le maintien", "def": "The campaign supporting continued UK membership of the EU.", "ex": "The Remain campaign warned of economic disruption."}, {"term": "Leave voter", "ipa": "/ˈliːv ˌvəʊtə/", "pron": "leev VOH-tuh", "fr": "électeur pro-Brexit", "def": "A person who voted for the UK to leave the EU.", "ex": "Many Leave voters saw Brexit as a way to regain sovereignty."}, {"term": "Remain voter", "ipa": "/rɪˈmeɪn ˌvəʊtə/", "pron": "ri-MAYN VOH-tuh", "fr": "électeur pro-Remain", "def": "A person who voted for the UK to remain in the EU.", "ex": "Remain voters tended to be younger and more urban."}, {"term": "Brexiteer", "ipa": "/ˌbreksɪˈtɪə/", "pron": "brek-si-TEER", "fr": "partisan du Brexit", "def": "A supporter of Brexit.", "ex": "Hardline Brexiteers opposed a soft Brexit."}, {"term": "Eurosceptic", "ipa": "/ˌjʊərəʊˈskeptɪk/", "pron": "YOO-roh-SKEP-tik", "fr": "eurosceptique", "def": "A person who is critical of the European Union or European integration.", "ex": "Eurosceptic politicians had campaigned against the EU for decades."}, {"term": "Euroscepticism", "ipa": "/ˌjʊərəʊˈskeptɪsɪzəm/", "pron": "YOO-roh-SKEP-ti-siz-uhm", "fr": "euroscepticisme", "def": "Criticism of the EU or opposition to European integration.", "ex": "Euroscepticism grew within the Conservative Party."}, {"term": "Europhile", "ipa": "/ˈjʊərəfaɪl/", "pron": "YOO-ruh-file", "fr": "europhile", "def": "A person who supports the EU or European integration.", "ex": "Europhiles saw Brexit as a historic mistake."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The supreme authority of a state to make its own laws and decisions.", "ex": "Sovereignty was a central argument in the Brexit debate."}, {"term": "parliamentary sovereignty", "ipa": "/ˌpɑːləˈmentəri ˈsɒvrənti/", "pron": "par-luh-MEN-tuh-ree SOV-ruhn-tee", "fr": "souveraineté parlementaire", "def": "The principle that the UK Parliament is the supreme law-making body.", "ex": "Brexit supporters claimed they wanted to restore parliamentary sovereignty."}, {"term": "national sovereignty", "ipa": "/ˌnæʃənəl ˈsɒvrənti/", "pron": "NASH-uh-nuhl SOV-ruhn-tee", "fr": "souveraineté nationale", "def": "A country’s ability to govern itself without outside control.", "ex": "National sovereignty was presented as being limited by EU law."}, {"term": "take back control", "ipa": "/ˌteɪk bæk kənˈtrəʊl/", "pron": "tayk bak kuhn-TROHL", "fr": "reprendre le contrôle", "def": "A famous Brexit slogan meaning the UK should regain control over laws, borders and money.", "ex": "Take back control became the defining slogan of the Leave campaign."}, {"term": "control of borders", "ipa": "/kənˌtrəʊl əv ˈbɔːdəz/", "pron": "kuhn-TROHL ov BOR-duhz", "fr": "contrôle des frontières", "def": "The ability to decide who can enter and live in a country.", "ex": "Control of borders was a major Leave argument."}, {"term": "immigration control", "ipa": "/ˌɪmɪˈɡreɪʃən kənˌtrəʊl/", "pron": "im-i-GRAY-shuhn kuhn-TROHL", "fr": "contrôle de l’immigration", "def": "Policies limiting or regulating immigration.", "ex": "Immigration control was central to the Brexit campaign."}, {"term": "free movement", "ipa": "/ˌfriː ˈmuːvmənt/", "pron": "free MOOV-muhnt", "fr": "libre circulation", "def": "The EU principle allowing citizens to live and work in other member states.", "ex": "Ending free movement was a major Brexit objective."}]}, {"title": "B. Trade, single market and post-Brexit arrangements", "entries": [{"term": "single market", "ipa": "/ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "SING-guhl MAR-kit", "fr": "marché unique", "def": "The EU area allowing free movement of goods, services, capital and people.", "ex": "Leaving the single market created barriers for British businesses."}, {"term": "customs union", "ipa": "/ˈkʌstəmz ˌjuːniən/", "pron": "KUS-tuhmz YOO-nee-uhn", "fr": "union douanière", "def": "An arrangement where members apply common tariffs to goods from outside the union.", "ex": "Leaving the customs union allowed the UK to negotiate its own trade deals."}, {"term": "common external tariff", "ipa": "/ˌkɒmən ɪkˈstɜːnəl ˈtærɪf/", "pron": "KOM-uhn ik-STUR-nuhl TAR-if", "fr": "tarif extérieur commun", "def": "A shared tariff applied by customs union members to imports from outside.", "ex": "The EU customs union has a common external tariff."}, {"term": "trade barrier", "ipa": "/ˈtreɪd ˌbæriə/", "pron": "trade BARR-ee-uh", "fr": "barrière commerciale", "def": "A rule, cost or restriction that makes trade more difficult.", "ex": "Brexit created new trade barriers with the EU."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "A free trade deal can reduce tariffs."}, {"term": "non-tariff barrier", "ipa": "/ˌnɒn ˈtærɪf ˌbæriə/", "pron": "non TAR-if BARR-ee-uh", "fr": "barrière non tarifaire", "def": "A rule or administrative requirement that restricts trade without being a tax.", "ex": "Paperwork and checks became non-tariff barriers after Brexit."}, {"term": "red tape", "ipa": "/ˌred ˈteɪp/", "pron": "red tape", "fr": "paperasserie ; lourdeurs administratives", "def": "Excessive paperwork or bureaucracy.", "ex": "Businesses complained about red tape after Brexit."}, {"term": "regulatory divergence", "ipa": "/ˌreɡjʊlətəri daɪˈvɜːdʒəns/", "pron": "REG-yuh-luh-tuh-ree dy-VUR-juhns", "fr": "divergence réglementaire", "def": "The process by which UK and EU rules become different over time.", "ex": "Regulatory divergence may increase trade friction."}, {"term": "alignment", "ipa": "/əˈlaɪnmənt/", "pron": "uh-LYNE-muhnt", "fr": "alignement", "def": "The state of keeping rules or policies similar.", "ex": "Some firms favour close alignment with EU standards."}, {"term": "level playing field", "ipa": "/ˌlevəl ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl PLAY-ing field", "fr": "conditions de concurrence équitables", "def": "Fair competition rules preventing one side from gaining unfair advantage.", "ex": "The EU insisted on level playing field commitments."}, {"term": "trade deal", "ipa": "/ˈtreɪd diːl/", "pron": "trade deel", "fr": "accord commercial", "def": "An agreement setting rules for trade between countries or blocs.", "ex": "The UK signed a trade deal with the EU."}, {"term": "free trade agreement", "ipa": "/ˌfriː ˈtreɪd əˌɡriːmənt/", "pron": "free trade uh-GREE-muhnt", "fr": "accord de libre-échange", "def": "An agreement reducing trade barriers between countries.", "ex": "The Trade and Cooperation Agreement is a free trade agreement."}, {"term": "Trade and Cooperation Agreement", "ipa": "/ˌtreɪd ənd kəʊˌɒpəˈreɪʃən əˈɡriːmənt/", "pron": "trade and koh-op-uh-RAY-shuhn uh-GREE-muhnt", "fr": "Accord de commerce et de coopération", "def": "The 2020 UK-EU agreement governing post-Brexit trade and cooperation.", "ex": "The Trade and Cooperation Agreement avoided tariffs but created new paperwork."}, {"term": "TCA", "ipa": "/ˌtiː siː ˈeɪ/", "pron": "tee see ay", "fr": "TCA ; accord de commerce et de coopération", "def": "Abbreviation for the Trade and Cooperation Agreement.", "ex": "The TCA governs much of the UK-EU relationship."}, {"term": "hard Brexit", "ipa": "/ˌhɑːd ˈbreksɪt/", "pron": "hard BREK-sit", "fr": "Brexit dur", "def": "A form of Brexit involving leaving the single market and customs union.", "ex": "A hard Brexit prioritised sovereignty over economic integration."}, {"term": "soft Brexit", "ipa": "/ˌsɒft ˈbreksɪt/", "pron": "soft BREK-sit", "fr": "Brexit doux", "def": "A form of Brexit keeping close economic ties with the EU.", "ex": "A soft Brexit would have reduced trade disruption."}, {"term": "no-deal Brexit", "ipa": "/ˌnəʊ diːl ˈbreksɪt/", "pron": "noh-deel BREK-sit", "fr": "Brexit sans accord", "def": "The UK leaving the EU without a withdrawal or trade agreement.", "ex": "Businesses feared the disruption of a no-deal Brexit."}, {"term": "cliff edge", "ipa": "/ˈklɪf edʒ/", "pron": "klif ej", "fr": "falaise ; rupture brutale", "def": "A sudden, risky break in rules or arrangements.", "ex": "A no-deal Brexit was described as a cliff edge."}, {"term": "transition period", "ipa": "/trænˈzɪʃən ˌpɪəriəd/", "pron": "tran-ZISH-uhn PEER-ee-uhd", "fr": "période de transition", "def": "A temporary period after withdrawal during which old rules continued while new arrangements were negotiated.", "ex": "The transition period gave businesses time to adjust."}, {"term": "Article 50", "ipa": "/ˌɑːtɪkəl ˈfɪfti/", "pron": "AR-ti-kuhl FIF-tee", "fr": "Article 50", "def": "The EU treaty article allowing a member state to leave the EU.", "ex": "The UK triggered Article 50 in 2017."}]}, {"title": "C. Negotiations, Article 50 and parliamentary deadlock", "entries": [{"term": "to trigger Article 50", "ipa": "/ˈtrɪɡər ˌɑːtɪkəl ˈfɪfti/", "pron": "TRIG-uh AR-ti-kuhl FIF-tee", "fr": "déclencher l’article 50", "def": "To formally start the EU withdrawal process.", "ex": "Theresa May triggered Article 50 after the referendum."}, {"term": "negotiation", "ipa": "/nɪˌɡəʊʃiˈeɪʃən/", "pron": "ni-goh-shee-AY-shuhn", "fr": "négociation", "def": "A formal discussion aimed at reaching an agreement.", "ex": "Brexit negotiations were long and politically difficult."}, {"term": "chief negotiator", "ipa": "/ˌtʃiːf nɪˈɡəʊʃieɪtə/", "pron": "cheef ni-GOH-shee-ay-tuh", "fr": "négociateur en chef", "def": "The main person responsible for leading negotiations.", "ex": "The EU’s chief negotiator insisted on protecting the single market."}, {"term": "red line", "ipa": "/ˌred ˈlaɪn/", "pron": "red line", "fr": "ligne rouge", "def": "A non-negotiable political demand or limit.", "ex": "Ending free movement was a red line for the UK government."}, {"term": "compromise", "ipa": "/ˈkɒmprəmaɪz/", "pron": "KOM-pruh-myze", "fr": "compromis", "def": "An agreement in which both sides make concessions.", "ex": "Every Brexit deal required compromise."}, {"term": "concession", "ipa": "/kənˈseʃən/", "pron": "kuhn-SESH-uhn", "fr": "concession", "def": "Something given up in a negotiation.", "ex": "Both sides made concessions in the final agreement."}, {"term": "deadlock", "ipa": "/ˈdedlɒk/", "pron": "DED-lok", "fr": "blocage ; impasse", "def": "A situation in which agreement is impossible because neither side will move.", "ex": "Parliamentary deadlock delayed Brexit."}, {"term": "impasse", "ipa": "/ˈæmpɑːs/", "pron": "AM-pass", "fr": "impasse", "def": "A situation where no progress can be made.", "ex": "The negotiations reached an impasse over Northern Ireland."}, {"term": "extension", "ipa": "/ɪkˈstenʃən/", "pron": "ik-STEN-shuhn", "fr": "prolongation ; extension", "def": "Extra time added to a deadline.", "ex": "The UK requested an extension to the Article 50 deadline."}, {"term": "backstop", "ipa": "/ˈbækstɒp/", "pron": "BAK-stop", "fr": "backstop ; filet de sécurité irlandais", "def": "A proposed safety mechanism to avoid a hard border in Ireland if no future deal was reached.", "ex": "The Irish backstop became the most controversial part of Theresa May’s deal."}, {"term": "Irish border", "ipa": "/ˌaɪrɪʃ ˈbɔːdə/", "pron": "EYE-rish BOR-duh", "fr": "frontière irlandaise", "def": "The border between Northern Ireland and the Republic of Ireland.", "ex": "Brexit made the Irish border a central constitutional problem."}, {"term": "hard border", "ipa": "/ˌhɑːd ˈbɔːdə/", "pron": "hard BOR-duh", "fr": "frontière dure", "def": "A border with physical checks, customs controls or infrastructure.", "ex": "Both sides wanted to avoid a hard border on the island of Ireland."}, {"term": "Good Friday Agreement", "ipa": "/ˌɡʊd ˈfraɪdeɪ əˈɡriːmənt/", "pron": "good FRY-day uh-GREE-muhnt", "fr": "Accord du Vendredi saint", "def": "The 1998 peace agreement that helped end the Northern Ireland conflict.", "ex": "Brexit raised concerns about the Good Friday Agreement."}, {"term": "Northern Ireland Protocol", "ipa": "/ˌnɔːðən ˈaɪələnd ˈprəʊtəkɒl/", "pron": "NOR-thuhn EYE-uh-luhnd PROH-tuh-kol", "fr": "protocole sur l’Irlande du Nord", "def": "The post-Brexit arrangement keeping Northern Ireland aligned with some EU rules to avoid a hard border.", "ex": "The Northern Ireland Protocol created checks in the Irish Sea."}, {"term": "Irish Sea border", "ipa": "/ˌaɪrɪʃ siː ˈbɔːdə/", "pron": "EYE-rish see BOR-duh", "fr": "frontière en mer d’Irlande", "def": "A term for checks between Great Britain and Northern Ireland after Brexit.", "ex": "Unionists criticised the Irish Sea border."}, {"term": "Windsor Framework", "ipa": "/ˌwɪnzə ˈfreɪmwɜːk/", "pron": "WIN-zuh FRAME-wurk", "fr": "cadre de Windsor", "def": "The 2023 UK-EU agreement modifying the Northern Ireland Protocol.", "ex": "The Windsor Framework aimed to reduce trade frictions in Northern Ireland."}, {"term": "unionist", "ipa": "/ˈjuːniənɪst/", "pron": "YOO-nee-uhn-ist", "fr": "unioniste", "def": "A person in Northern Ireland who supports remaining part of the UK.", "ex": "Unionists opposed rules that separated Northern Ireland from Great Britain."}]}, {"title": "D. Northern Ireland, the Union and constitutional conflict", "entries": [{"term": "nationalist", "ipa": "/ˈnæʃənəlɪst/", "pron": "NASH-uh-nuh-list", "fr": "nationaliste irlandais", "def": "In Northern Ireland, a person who supports Irish unity.", "ex": "Nationalists generally opposed Brexit."}, {"term": "Irish unity", "ipa": "/ˌaɪrɪʃ ˈjuːnəti/", "pron": "EYE-rish YOO-nuh-tee", "fr": "unité irlandaise", "def": "The idea of Northern Ireland joining the Republic of Ireland.", "ex": "Brexit renewed debates about Irish unity."}, {"term": "Scottish independence", "ipa": "/ˌskɒtɪʃ ˌɪndɪˈpendəns/", "pron": "SKOT-ish in-di-PEN-duhns", "fr": "indépendance écossaise", "def": "The idea that Scotland should become an independent country.", "ex": "Brexit strengthened arguments for Scottish independence."}, {"term": "Union", "ipa": "/ˈjuːniən/", "pron": "YOO-nee-uhn", "fr": "Union britannique", "def": "The political union of the countries that make up the UK.", "ex": "Brexit put pressure on the Union."}, {"term": "constitutional crisis", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈkraɪsɪs/", "pron": "kon-sti-TOO-shuh-nuhl KRY-sis", "fr": "crise constitutionnelle", "def": "A serious conflict over how constitutional rules should operate.", "ex": "The prorogation dispute was described as a constitutional crisis."}, {"term": "prorogation", "ipa": "/ˌprəʊrəˈɡeɪʃən/", "pron": "proh-ruh-GAY-shuhn", "fr": "prorogation du Parlement", "def": "The formal suspension of a parliamentary session.", "ex": "The 2019 prorogation triggered legal and political controversy."}, {"term": "Supreme Court ruling", "ipa": "/suːˌpriːm ˈkɔːt ˈruːlɪŋ/", "pron": "soo-PREEM court ROO-ling", "fr": "décision de la Cour suprême", "def": "A decision made by the UK Supreme Court.", "ex": "The Supreme Court ruling found the prorogation unlawful."}, {"term": "meaningful vote", "ipa": "/ˌmiːnɪŋfəl ˈvəʊt/", "pron": "MEE-ning-fuhl voht", "fr": "vote significatif", "def": "A parliamentary vote on the Brexit withdrawal agreement.", "ex": "Theresa May’s deal was rejected in several meaningful votes."}, {"term": "backbench rebellion", "ipa": "/ˌbækbentʃ rɪˈbeljən/", "pron": "BAK-bench ri-BEL-yuhn", "fr": "rébellion des députés de base", "def": "A revolt by MPs against their own party leadership.", "ex": "Brexit caused repeated backbench rebellions."}, {"term": "party split", "ipa": "/ˈpɑːti splɪt/", "pron": "PAR-tee split", "fr": "division interne du parti", "def": "A serious division within a political party.", "ex": "Brexit created deep party splits."}, {"term": "parliamentary deadlock", "ipa": "/ˌpɑːləˈmentəri ˈdedlɒk/", "pron": "par-luh-MEN-tuh-ree DED-lok", "fr": "blocage parlementaire", "def": "A situation in which Parliament cannot agree on a way forward.", "ex": "Parliamentary deadlock led to political chaos."}, {"term": "second referendum", "ipa": "/ˌsekənd ˌrefəˈrendəm/", "pron": "SEK-uhnd ref-uh-REN-duhm", "fr": "deuxième référendum", "def": "A proposed new vote on Brexit after the first referendum.", "ex": "Campaigners demanded a second referendum."}, {"term": "People’s Vote", "ipa": "/ˌpiːpəlz ˈvəʊt/", "pron": "PEE-puhlz voht", "fr": "People’s Vote ; vote populaire", "def": "The campaign for a second referendum on the final Brexit deal.", "ex": "The People’s Vote campaign attracted large demonstrations."}, {"term": "Brexit fatigue", "ipa": "/ˈbreksɪt fəˌtiːɡ/", "pron": "BREK-sit fuh-TEEG", "fr": "fatigue liée au Brexit", "def": "Public exhaustion with years of Brexit debate.", "ex": "Brexit fatigue helped Boris Johnson’s message resonate."}, {"term": "Get Brexit Done", "ipa": "/ˌɡet ˈbreksɪt dʌn/", "pron": "get BREK-sit dun", "fr": "réaliser le Brexit ; slogan Get Brexit Done", "def": "Boris Johnson’s 2019 election slogan promising to end the Brexit process.", "ex": "Get Brexit Done was a simple and effective campaign message."}, {"term": "economic impact", "ipa": "/ˌiːkəˈnɒmɪk ˈɪmpækt/", "pron": "ee-kuh-NOM-ik IM-pakt", "fr": "impact économique", "def": "The effect of a policy or event on the economy.", "ex": "The economic impact of Brexit remains contested."}, {"term": "trade friction", "ipa": "/ˈtreɪd ˌfrɪkʃən/", "pron": "trade FRIK-shuhn", "fr": "friction commerciale", "def": "Extra difficulty, cost or delay in trade.", "ex": "New customs checks increased trade friction."}, {"term": "supply chain disruption", "ipa": "/səˈplaɪ tʃeɪn dɪsˌrʌpʃən/", "pron": "suh-PLY chayn dis-RUP-shuhn", "fr": "perturbation des chaînes d’approvisionnement", "def": "Problems interrupting the flow of goods and materials.", "ex": "Brexit contributed to supply chain disruption."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˈʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A situation where there are not enough workers for available jobs.", "ex": "Sectors such as agriculture and care reported labour shortages."}, {"term": "skills shortage", "ipa": "/ˈskɪlz ˌʃɔːtɪdʒ/", "pron": "skilz SHOR-tij", "fr": "pénurie de compétences", "def": "A lack of workers with needed qualifications or expertise.", "ex": "Brexit worsened skills shortages in some industries."}]}, {"title": "E. Economic impact, identity and high-value verbs", "entries": [{"term": "investment uncertainty", "ipa": "/ɪnˈvestmənt ʌnˈsɜːtənti/", "pron": "in-VEST-muhnt un-SUR-tuhn-tee", "fr": "incertitude pour les investissements", "def": "Lack of clarity discouraging businesses from investing.", "ex": "Investment uncertainty affected business planning."}, {"term": "business confidence", "ipa": "/ˈbɪznəs ˈkɒnfɪdəns/", "pron": "BIZ-nuhs KON-fi-duhns", "fr": "confiance des entreprises", "def": "The degree to which businesses feel positive about future economic conditions.", "ex": "Business confidence fell during periods of Brexit uncertainty."}, {"term": "financial services", "ipa": "/faɪˌnænʃəl ˈsɜːvɪsɪz/", "pron": "fy-NAN-shuhl SUR-vis-iz", "fr": "services financiers", "def": "Banking, insurance, investment and related economic activities.", "ex": "Financial services lost some automatic access to EU markets."}, {"term": "City of London", "ipa": "/ˌsɪti əv ˈlʌndən/", "pron": "SIT-ee ov LUN-duhn", "fr": "City de Londres ; place financière londonienne", "def": "London’s financial district and the UK financial sector more broadly.", "ex": "The City of London was worried about losing EU access."}, {"term": "passporting rights", "ipa": "/ˈpɑːspɔːtɪŋ raɪts/", "pron": "PASS-port-ing rites", "fr": "droits de passeport financier", "def": "Rights allowing financial firms to operate across the EU from one member state.", "ex": "UK firms lost many passporting rights after Brexit."}, {"term": "equivalence", "ipa": "/ɪˈkwɪvələns/", "pron": "i-KWIV-uh-luhns", "fr": "équivalence réglementaire", "def": "A system allowing market access when regulations are judged sufficiently similar.", "ex": "Financial firms hoped for EU equivalence decisions."}, {"term": "fishing rights", "ipa": "/ˈfɪʃɪŋ raɪts/", "pron": "FISH-ing rites", "fr": "droits de pêche", "def": "Rules about who can fish in which waters.", "ex": "Fishing rights became politically symbolic despite their limited economic weight."}, {"term": "fisheries", "ipa": "/ˈfɪʃəriz/", "pron": "FISH-uh-reez", "fr": "pêcheries ; secteur de la pêche", "def": "The fishing industry or fishing grounds.", "ex": "Fisheries became a sensitive part of negotiations."}, {"term": "agriculture", "ipa": "/ˈæɡrɪkʌltʃə/", "pron": "AG-ri-kul-chuh", "fr": "agriculture", "def": "Farming and food production.", "ex": "Agriculture was affected by labour shortages and export checks."}, {"term": "export checks", "ipa": "/ˈekspɔːt tʃeks/", "pron": "EK-sport cheks", "fr": "contrôles à l’exportation", "def": "Inspections or paperwork required for goods leaving a country.", "ex": "Export checks delayed some food shipments."}, {"term": "rules of origin", "ipa": "/ˌruːlz əv ˈɒrɪdʒɪn/", "pron": "roolz ov OR-i-jin", "fr": "règles d’origine", "def": "Rules determining where goods are considered to come from for trade purposes.", "ex": "Rules of origin created paperwork for manufacturers."}, {"term": "Northern Ireland trade", "ipa": "/ˌnɔːðən ˈaɪələnd treɪd/", "pron": "NOR-thuhn EYE-uh-luhnd trade", "fr": "commerce avec l’Irlande du Nord", "def": "Trade involving Northern Ireland under special post-Brexit arrangements.", "ex": "Northern Ireland trade remained politically sensitive."}, {"term": "European identity", "ipa": "/ˌjʊərəpiːən aɪˈdentəti/", "pron": "YOO-ruh-pee-uhn eye-DEN-tuh-tee", "fr": "identité européenne", "def": "A sense of belonging to Europe or the EU.", "ex": "Many Remain voters felt a strong European identity."}, {"term": "British identity", "ipa": "/ˌbrɪtɪʃ aɪˈdentəti/", "pron": "BRIT-ish eye-DEN-tuh-tee", "fr": "identité britannique", "def": "A sense of belonging to Britain or the UK.", "ex": "Brexit exposed competing visions of British identity."}, {"term": "English nationalism", "ipa": "/ˌɪŋɡlɪʃ ˈnæʃənəlɪzəm/", "pron": "ING-glish NASH-uh-nuh-liz-uhm", "fr": "nationalisme anglais", "def": "A political identity centred on England rather than Britain as a whole.", "ex": "English nationalism helped drive support for Brexit."}, {"term": "cosmopolitanism", "ipa": "/ˌkɒzməˈpɒlɪtənɪzəm/", "pron": "koz-muh-POL-i-tuh-niz-uhm", "fr": "cosmopolitisme", "def": "An outlook open to international cultures, mobility and cooperation.", "ex": "Remain voters were often associated with cosmopolitanism."}, {"term": "global Britain", "ipa": "/ˌɡləʊbəl ˈbrɪtən/", "pron": "GLOH-buhl BRIT-uhn", "fr": "Global Britain ; Royaume-Uni mondial", "def": "A post-Brexit slogan presenting the UK as an outward-looking global actor.", "ex": "Global Britain was used to promote a post-EU foreign policy vision."}, {"term": "levelling up", "ipa": "/ˌlevəlɪŋ ˈʌp/", "pron": "LEV-uhl-ing up", "fr": "nivellement par le haut ; rééquilibrage territorial", "def": "A policy slogan about reducing regional inequality across the UK.", "ex": "Levelling up was linked to winning former Labour seats after Brexit."}, {"term": "left-behind communities", "ipa": "/ˌleft bɪˈhaɪnd kəˈmjuːnətiz/", "pron": "left bi-HYND kuh-MYOO-nuh-teez", "fr": "communautés laissées pour compte", "def": "Communities seen as neglected by globalisation, London and political elites.", "ex": "Brexit appealed to many left-behind communities."}, {"term": "metropolitan elite", "ipa": "/ˌmetrəˈpɒlɪtən ɪˈliːt/", "pron": "met-ruh-POL-i-tuhn i-LEET", "fr": "élite métropolitaine", "def": "Educated, urban and socially liberal elites, often criticised by populists.", "ex": "Brexit rhetoric often attacked the metropolitan elite."}, {"term": "London bubble", "ipa": "/ˈlʌndən ˌbʌbəl/", "pron": "LUN-duhn BUB-uhl", "fr": "bulle londonienne", "def": "A term criticising London-based politicians and media as disconnected from the rest of the country.", "ex": "Leave supporters accused the London bubble of ignoring ordinary voters."}, {"term": "will of the people", "ipa": "/ˌwɪl əv ðə ˈpiːpəl/", "pron": "wil ov thuh PEE-puhl", "fr": "volonté du peuple", "def": "A political phrase claiming democratic legitimacy from popular vote.", "ex": "Brexiteers argued that Parliament had to respect the will of the people."}, {"term": "popular mandate", "ipa": "/ˌpɒpjələ ˈmændeɪt/", "pron": "POP-yuh-luh MAN-dayt", "fr": "mandat populaire", "def": "Authority claimed from voters after an election or referendum.", "ex": "The referendum was presented as a popular mandate."}, {"term": "democratic legitimacy", "ipa": "/ˌdeməˈkrætɪk lɪˈdʒɪtɪməsi/", "pron": "dem-uh-KRAT-ik li-JIT-i-muh-see", "fr": "légitimité démocratique", "def": "The right to make decisions because of democratic consent.", "ex": "The Brexit process raised questions of democratic legitimacy."}, {"term": "representative democracy", "ipa": "/ˌreprɪˈzentətɪv dɪˈmɒkrəsi/", "pron": "rep-ri-ZEN-tuh-tiv di-MOK-ruh-see", "fr": "démocratie représentative", "def": "A system where elected representatives make decisions on behalf of citizens.", "ex": "Brexit created tension between direct and representative democracy."}, {"term": "direct democracy", "ipa": "/dəˌrekt dɪˈmɒkrəsi/", "pron": "di-REKT di-MOK-ruh-see", "fr": "démocratie directe", "def": "A system where citizens vote directly on policy questions.", "ex": "The referendum was an example of direct democracy."}, {"term": "post-Brexit Britain", "ipa": "/ˌpəʊst ˈbreksɪt ˈbrɪtən/", "pron": "post BREK-sit BRIT-uhn", "fr": "Royaume-Uni post-Brexit", "def": "The UK after leaving the EU.", "ex": "Post-Brexit Britain is still redefining its role in the world."}, {"term": "to leave the EU", "ipa": "/liːv ði ˌiː ˈjuː/", "pron": "leev thee ee-yoo", "fr": "quitter l’Union européenne", "def": "To withdraw from the European Union.", "ex": "The UK voted to leave the EU."}, {"term": "to remain in the EU", "ipa": "/rɪˈmeɪn ɪn ði ˌiː ˈjuː/", "pron": "ri-MAYN in thee ee-yoo", "fr": "rester dans l’Union européenne", "def": "To continue being a member of the European Union.", "ex": "Scotland voted to remain in the EU."}, {"term": "to negotiate a deal", "ipa": "/nɪˈɡəʊʃieɪt ə diːl/", "pron": "ni-GOH-shee-ayt uh deel", "fr": "négocier un accord", "def": "To discuss terms in order to reach an agreement.", "ex": "The government tried to negotiate a deal before the deadline."}, {"term": "to reject a deal", "ipa": "/rɪˈdʒekt ə diːl/", "pron": "ri-JEKT uh deel", "fr": "rejeter un accord", "def": "To vote against or refuse an agreement.", "ex": "MPs repeatedly rejected the withdrawal deal."}, {"term": "to ratify an agreement", "ipa": "/ˈrætɪfaɪ ən əˈɡriːmənt/", "pron": "RAT-i-fy uhn uh-GREE-muhnt", "fr": "ratifier un accord", "def": "To formally approve an agreement so that it becomes legally valid.", "ex": "Parliament had to ratify the agreement."}, {"term": "to regain sovereignty", "ipa": "/rɪˈɡeɪn ˈsɒvrənti/", "pron": "ri-GAYN SOV-ruhn-tee", "fr": "retrouver sa souveraineté", "def": "To recover supreme national authority.", "ex": "Leave supporters claimed Brexit would regain sovereignty."}, {"term": "to restore control of borders", "ipa": "/rɪˈstɔː kənˌtrəʊl əv ˈbɔːdəz/", "pron": "ri-STORE kuhn-TROHL ov BOR-duhz", "fr": "rétablir le contrôle des frontières", "def": "To bring border policy back under national control.", "ex": "The government promised to restore control of borders."}, {"term": "to create trade friction", "ipa": "/kriˈeɪt ˈtreɪd ˌfrɪkʃən/", "pron": "kree-AYT trade FRIK-shuhn", "fr": "créer des frictions commerciales", "def": "To create new costs, checks or delays in trade.", "ex": "Leaving the single market created trade friction."}, {"term": "to deepen divisions", "ipa": "/ˈdiːpən dɪˈvɪʒənz/", "pron": "DEE-puhn di-VIZH-uhnz", "fr": "creuser les divisions", "def": "To make political or social divisions stronger.", "ex": "Brexit deepened divisions between generations and regions."}, {"term": "to reshape British politics", "ipa": "/riːˈʃeɪp ˌbrɪtɪʃ ˈpɒlɪtɪks/", "pron": "ree-SHAYP BRIT-ish POL-i-tiks", "fr": "remodeler la politique britannique", "def": "To significantly change British political life.", "ex": "Brexit reshaped British politics for a generation."}]}]}, {"id": "p3c25", "part": 3, "chapter": 25, "title": "British Identity", "file": "cpge_vocab_part3_chapter25_british_identity_premium.html", "count": 137, "sections": [{"title": "A. Core concepts: Britishness, symbols and national myths", "entries": [{"term": "British identity", "ipa": "/ˌbrɪtɪʃ aɪˈdentəti/", "pron": "BRIT-ish eye-DEN-tuh-tee", "fr": "identité britannique", "def": "A sense of belonging to Britain or the United Kingdom, shaped by history, culture, institutions and values.", "ex": "British identity has become more contested since Brexit."}, {"term": "Britishness", "ipa": "/ˈbrɪtɪʃnəs/", "pron": "BRIT-ish-nuhs", "fr": "britannicité ; identité britannique", "def": "The quality, feeling or idea of being British.", "ex": "Britishness can mean different things in England, Scotland, Wales and Northern Ireland."}, {"term": "national identity", "ipa": "/ˌnæʃənəl aɪˈdentəti/", "pron": "NASH-uh-nuhl eye-DEN-tuh-tee", "fr": "identité nationale", "def": "A shared sense of belonging to a nation.", "ex": "National identity can be inclusive, exclusive or politically contested."}, {"term": "shared identity", "ipa": "/ˌʃeəd aɪˈdentəti/", "pron": "shaird eye-DEN-tuh-tee", "fr": "identité partagée", "def": "A sense of belonging based on common values, symbols or history.", "ex": "The monarchy is often presented as part of a shared identity."}, {"term": "collective memory", "ipa": "/kəˌlektɪv ˈmeməri/", "pron": "kuh-LEK-tiv MEM-uh-ree", "fr": "mémoire collective", "def": "The way a society remembers and interprets its past.", "ex": "Collective memory shapes debates about empire and war."}, {"term": "national narrative", "ipa": "/ˌnæʃənəl ˈnærətɪv/", "pron": "NASH-uh-nuhl NAR-uh-tiv", "fr": "récit national", "def": "The story a nation tells about itself.", "ex": "The national narrative often celebrates resilience and liberty."}, {"term": "imagined community", "ipa": "/ɪˌmædʒɪnd kəˈmjuːnəti/", "pron": "i-MAJ-ind kuh-MYOO-nuh-tee", "fr": "communauté imaginée", "def": "A nation understood as a community whose members feel connected despite not knowing each other personally.", "ex": "British identity can be analysed as an imagined community."}, {"term": "sense of belonging", "ipa": "/ˌsens əv bɪˈlɒŋɪŋ/", "pron": "sens ov bi-LONG-ing", "fr": "sentiment d’appartenance", "def": "The feeling of being accepted as part of a group or place.", "ex": "Citizenship can strengthen a sense of belonging."}, {"term": "patriotism", "ipa": "/ˈpætriətɪzəm/", "pron": "PAT-ree-uh-tiz-uhm", "fr": "patriotisme", "def": "Love, pride or loyalty towards one’s country.", "ex": "Patriotism can be inclusive or used to exclude critics."}, {"term": "national pride", "ipa": "/ˌnæʃənəl ˈpraɪd/", "pron": "NASH-uh-nuhl pryde", "fr": "fierté nationale", "def": "A feeling of satisfaction or pride in one’s country.", "ex": "Royal ceremonies often produce displays of national pride."}, {"term": "national symbols", "ipa": "/ˌnæʃənəl ˈsɪmbəlz/", "pron": "NASH-uh-nuhl SIM-buhlz", "fr": "symboles nationaux", "def": "Objects, flags, songs or institutions representing a nation.", "ex": "Flags, anthems and ceremonies are powerful national symbols."}, {"term": "Union Jack", "ipa": "/ˌjuːniən ˈdʒæk/", "pron": "YOO-nee-uhn jak", "fr": "Union Jack ; drapeau britannique", "def": "The national flag of the United Kingdom.", "ex": "The Union Jack symbolises the union of several nations."}, {"term": "Union Flag", "ipa": "/ˈjuːniən flæɡ/", "pron": "YOO-nee-uhn flag", "fr": "Union Flag ; drapeau de l’Union", "def": "Another name for the Union Jack, especially in formal contexts.", "ex": "The Union Flag appears at state ceremonies."}, {"term": "national anthem", "ipa": "/ˌnæʃənəl ˈænθəm/", "pron": "NASH-uh-nuhl AN-thuhm", "fr": "hymne national", "def": "A song officially representing a country.", "ex": "The national anthem is sung at royal and sporting events."}, {"term": "God Save the King", "ipa": "/ˌɡɒd seɪv ðə ˈkɪŋ/", "pron": "god sayv thuh king", "fr": "God Save the King", "def": "The UK national anthem when the monarch is a king.", "ex": "God Save the King links national identity to the monarchy."}, {"term": "Remembrance Day", "ipa": "/rɪˈmembrəns deɪ/", "pron": "ri-MEM-bruhns day", "fr": "jour du Souvenir", "def": "A day commemorating those who died in war.", "ex": "Remembrance Day remains central to British collective memory."}, {"term": "poppy", "ipa": "/ˈpɒpi/", "pron": "POP-ee", "fr": "coquelicot du souvenir", "def": "A red flower worn as a symbol of remembrance for war dead.", "ex": "The poppy is a symbol of remembrance in Britain."}, {"term": "Blitz spirit", "ipa": "/ˈblɪts ˌspɪrɪt/", "pron": "blits SPIR-it", "fr": "esprit du Blitz ; résilience britannique", "def": "The idea of British resilience and unity during the Second World War bombing of cities.", "ex": "Politicians often invoke the Blitz spirit during crises."}, {"term": "Keep Calm and Carry On", "ipa": "/ˌkiːp kɑːm ənd ˌkæri ˈɒn/", "pron": "keep karm and KARR-ee on", "fr": "Keep Calm and Carry On ; garder son calme", "def": "A wartime slogan now associated with British stoicism.", "ex": "Keep Calm and Carry On became a popular symbol of British stoicism."}, {"term": "stoicism", "ipa": "/ˈstəʊɪsɪzəm/", "pron": "STOH-i-siz-uhm", "fr": "stoïcisme", "def": "The ability to endure difficulty without emotional display.", "ex": "British stoicism is often presented as a national trait."}, {"term": "stiff upper lip", "ipa": "/ˌstɪf ˌʌpə ˈlɪp/", "pron": "stif UP-uh lip", "fr": "flegme britannique ; retenue émotionnelle", "def": "A stereotypically British ability to remain calm and unemotional under pressure.", "ex": "The stiff upper lip is both admired and mocked."}, {"term": "politeness", "ipa": "/pəˈlaɪtnəs/", "pron": "puh-LYTE-nuhs", "fr": "politesse", "def": "Respectful and socially acceptable behaviour.", "ex": "Politeness is a common stereotype of British behaviour."}, {"term": "queueing", "ipa": "/ˈkjuːɪŋ/", "pron": "KYOO-ing", "fr": "faire la queue", "def": "Waiting in line in an orderly way, often seen as stereotypically British.", "ex": "Queueing is sometimes jokingly described as a British national habit."}, {"term": "understatement", "ipa": "/ˌʌndəˈsteɪtmənt/", "pron": "UN-duh-STAYT-muhnt", "fr": "litote ; euphémisme ; retenue", "def": "Expressing something in a restrained or less dramatic way than expected.", "ex": "Understatement is a classic feature of British humour."}, {"term": "self-deprecation", "ipa": "/ˌself deprəˈkeɪʃən/", "pron": "self dep-ruh-KAY-shuhn", "fr": "autodérision", "def": "Making modest or humorous criticism of oneself.", "ex": "Self-deprecation is often associated with British humour."}, {"term": "dry humour", "ipa": "/ˌdraɪ ˈhjuːmə/", "pron": "dry HYOO-muh", "fr": "humour pince-sans-rire", "def": "Humour delivered in a calm, understated or deadpan way.", "ex": "Dry humour is a common British stereotype."}, {"term": "class system", "ipa": "/ˈklɑːs ˌsɪstəm/", "pron": "klass SIS-tuhm", "fr": "système de classes", "def": "A social hierarchy based on wealth, education, accent, occupation and background.", "ex": "The class system still shapes British identity."}]}, {"title": "B. Class, accents and elite institutions", "entries": [{"term": "social class", "ipa": "/ˌsəʊʃəl ˈklɑːs/", "pron": "SOH-shuhl klass", "fr": "classe sociale", "def": "A group defined by economic position, education, occupation and cultural habits.", "ex": "Social class remains important in Britain."}, {"term": "working class", "ipa": "/ˌwɜːkɪŋ ˈklɑːs/", "pron": "WUR-king klass", "fr": "classe ouvrière ; classes populaires", "def": "People associated with manual, service or lower-paid work.", "ex": "Working-class identity has changed with deindustrialisation."}, {"term": "middle class", "ipa": "/ˌmɪdəl ˈklɑːs/", "pron": "MID-uhl klass", "fr": "classe moyenne", "def": "People associated with professional work, education and relative economic comfort.", "ex": "Middle-class norms often dominate public institutions."}, {"term": "upper class", "ipa": "/ˌʌpə ˈklɑːs/", "pron": "UP-uh klass", "fr": "classe supérieure", "def": "The wealthiest and most socially privileged class.", "ex": "The upper class is linked to private schools and inherited wealth."}, {"term": "class consciousness", "ipa": "/ˈklɑːs ˌkɒnʃəsnəs/", "pron": "klass KON-shuhs-nuhs", "fr": "conscience de classe", "def": "Awareness of class identity and class divisions.", "ex": "Class consciousness remains visible in British politics."}, {"term": "class divide", "ipa": "/ˈklɑːs dɪˌvaɪd/", "pron": "klass di-VYDE", "fr": "fracture de classe", "def": "A social gap between classes.", "ex": "The class divide affects education, health and housing."}, {"term": "accent", "ipa": "/ˈæksent/", "pron": "AK-sent", "fr": "accent", "def": "A way of pronouncing language associated with region, class or background.", "ex": "Accent can strongly shape perceptions of class in Britain."}, {"term": "regional accent", "ipa": "/ˌriːdʒənəl ˈæksent/", "pron": "REE-juh-nuhl AK-sent", "fr": "accent régional", "def": "An accent associated with a particular region.", "ex": "Regional accents can be a source of pride or discrimination."}, {"term": "Received Pronunciation", "ipa": "/rɪˌsiːvd prəˌnʌnsiˈeɪʃən/", "pron": "ri-SEEVD pruh-nun-see-AY-shuhn", "fr": "Received Pronunciation ; accent britannique standard prestigieux", "def": "A prestigious British accent historically associated with the upper classes and the BBC.", "ex": "Received Pronunciation once dominated broadcasting."}, {"term": "RP", "ipa": "/ˌɑː ˈpiː/", "pron": "ar pee", "fr": "RP", "def": "Abbreviation for Received Pronunciation.", "ex": "RP is often associated with elite education."}, {"term": "posh", "ipa": "/pɒʃ/", "pron": "posh", "fr": "chic ; huppé ; bourgeois", "def": "Informal word for upper-class, expensive or socially privileged.", "ex": "A posh accent can affect how speakers are judged."}, {"term": "elite education", "ipa": "/eɪˌliːt ˌedjʊˈkeɪʃən/", "pron": "ay-LEET ej-yoo-KAY-shuhn", "fr": "éducation d’élite", "def": "Education in prestigious schools or universities.", "ex": "Elite education is often criticised for reproducing privilege."}, {"term": "public school", "ipa": "/ˌpʌblɪk ˈskuːl/", "pron": "PUB-lik school", "fr": "école privée prestigieuse britannique", "def": "In Britain, an expensive private school, often historically prestigious.", "ex": "Public schools have produced many British political leaders."}, {"term": "private school", "ipa": "/ˌpraɪvət ˈskuːl/", "pron": "PRY-vuht school", "fr": "école privée", "def": "A fee-paying school not funded by the state.", "ex": "Private schools play a major role in elite reproduction."}, {"term": "Oxbridge", "ipa": "/ˈɒksbrɪdʒ/", "pron": "OKS-brij", "fr": "Oxbridge ; Oxford et Cambridge", "def": "Oxford and Cambridge universities considered together.", "ex": "Oxbridge remains influential in British public life."}, {"term": "establishment", "ipa": "/ɪˈstæblɪʃmənt/", "pron": "i-STAB-lish-muhnt", "fr": "establishment ; élite dirigeante", "def": "The network of powerful people and institutions controlling society.", "ex": "The British establishment is often criticised as closed and privileged."}, {"term": "old boys’ network", "ipa": "/ˌəʊld ˈbɔɪz ˌnetwɜːk/", "pron": "ohld boyz NET-wurk", "fr": "réseau des anciens ; entre-soi masculin élitiste", "def": "Informal connections among privileged men educated at elite institutions.", "ex": "The old boys’ network can limit social mobility."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes.", "ex": "Low social mobility challenges Britain’s meritocratic image."}, {"term": "meritocracy", "ipa": "/ˌmerɪˈtɒkrəsi/", "pron": "mer-i-TOK-ruh-see", "fr": "méritocratie", "def": "A system where success is based on talent and effort.", "ex": "Critics argue that Britain is not a true meritocracy."}, {"term": "inherited privilege", "ipa": "/ɪnˌherɪtɪd ˈprɪvəlɪdʒ/", "pron": "in-HER-i-tid PRIV-uh-lij", "fr": "privilège hérité", "def": "Advantages passed down through family background.", "ex": "Inherited privilege remains visible in education and politics."}, {"term": "four nations", "ipa": "/ˌfɔː ˈneɪʃənz/", "pron": "four NAY-shuhnz", "fr": "quatre nations", "def": "England, Scotland, Wales and Northern Ireland within the UK.", "ex": "The UK is often described as a union of four nations."}, {"term": "England", "ipa": "/ˈɪŋɡlənd/", "pron": "ING-gluhnd", "fr": "Angleterre", "def": "The largest nation of the United Kingdom.", "ex": "England dominates the UK demographically and politically."}]}, {"title": "C. Four nations, devolution and competing identities", "entries": [{"term": "Scotland", "ipa": "/ˈskɒtlənd/", "pron": "SKOT-luhnd", "fr": "Écosse", "def": "A nation within the UK with its own devolved Parliament.", "ex": "Scotland voted strongly to remain in the EU."}, {"term": "Wales", "ipa": "/weɪlz/", "pron": "waylz", "fr": "Pays de Galles", "def": "A nation within the UK with its own devolved Parliament.", "ex": "Wales has a distinct language and national identity."}, {"term": "Northern Ireland", "ipa": "/ˌnɔːðən ˈaɪələnd/", "pron": "NOR-thuhn EYE-uh-luhnd", "fr": "Irlande du Nord", "def": "A nation or region within the UK with a complex constitutional status.", "ex": "Northern Ireland has a contested identity."}, {"term": "Englishness", "ipa": "/ˈɪŋɡlɪʃnəs/", "pron": "ING-glish-nuhs", "fr": "identité anglaise", "def": "The identity or quality of being English.", "ex": "Englishness is not the same as Britishness."}, {"term": "Scottishness", "ipa": "/ˈskɒtɪʃnəs/", "pron": "SKOT-ish-nuhs", "fr": "identité écossaise", "def": "The identity or quality of being Scottish.", "ex": "Scottishness has been strengthened by devolution."}, {"term": "Welshness", "ipa": "/ˈwelʃnəs/", "pron": "WELSH-nuhs", "fr": "identité galloise", "def": "The identity or quality of being Welsh.", "ex": "Welshness is closely linked to language and culture."}, {"term": "Irishness", "ipa": "/ˈaɪrɪʃnəs/", "pron": "EYE-rish-nuhs", "fr": "identité irlandaise", "def": "The identity or quality of being Irish.", "ex": "Irishness is central to nationalist identity in Northern Ireland."}, {"term": "British Isles", "ipa": "/ˌbrɪtɪʃ ˈaɪlz/", "pron": "BRIT-ish eye-ulz", "fr": "îles Britanniques", "def": "A geographical term for the islands of Great Britain, Ireland and nearby islands, sometimes politically sensitive.", "ex": "The term British Isles can be controversial in Ireland."}, {"term": "Union", "ipa": "/ˈjuːniən/", "pron": "YOO-nee-uhn", "fr": "Union britannique", "def": "The political union of the UK’s nations.", "ex": "The Union has been weakened by Brexit and Scottish nationalism."}, {"term": "unionism", "ipa": "/ˈjuːniənɪzəm/", "pron": "YOO-nee-uhn-iz-uhm", "fr": "unionisme", "def": "Support for keeping the United Kingdom together.", "ex": "Unionism is strong in parts of Scotland and Northern Ireland."}, {"term": "unionist", "ipa": "/ˈjuːniənɪst/", "pron": "YOO-nee-uhn-ist", "fr": "unioniste", "def": "A person who supports the Union or Northern Ireland’s place in the UK.", "ex": "Unionists defend Northern Ireland’s place in the UK."}, {"term": "nationalism", "ipa": "/ˈnæʃənəlɪzəm/", "pron": "NASH-uh-nuh-liz-uhm", "fr": "nationalisme", "def": "Political support for a nation’s independence, sovereignty or identity.", "ex": "Nationalism can challenge British unity."}, {"term": "Scottish nationalism", "ipa": "/ˌskɒtɪʃ ˈnæʃənəlɪzəm/", "pron": "SKOT-ish NASH-uh-nuh-liz-uhm", "fr": "nationalisme écossais", "def": "Support for Scottish identity and often Scottish independence.", "ex": "Scottish nationalism has grown since devolution."}, {"term": "English nationalism", "ipa": "/ˌɪŋɡlɪʃ ˈnæʃənəlɪzəm/", "pron": "ING-glish NASH-uh-nuh-liz-uhm", "fr": "nationalisme anglais", "def": "A political identity centred on England rather than the UK.", "ex": "English nationalism was one factor behind Brexit."}, {"term": "Welsh nationalism", "ipa": "/ˌwelʃ ˈnæʃənəlɪzəm/", "pron": "WELSH NASH-uh-nuh-liz-uhm", "fr": "nationalisme gallois", "def": "Support for Welsh identity and sometimes Welsh independence.", "ex": "Welsh nationalism has gained visibility in recent years."}, {"term": "Irish nationalism", "ipa": "/ˌaɪrɪʃ ˈnæʃənəlɪzəm/", "pron": "EYE-rish NASH-uh-nuh-liz-uhm", "fr": "nationalisme irlandais", "def": "Support for Irish national identity and often Irish unity.", "ex": "Irish nationalism is central to Northern Ireland politics."}, {"term": "Scottish independence", "ipa": "/ˌskɒtɪʃ ˌɪndɪˈpendəns/", "pron": "SKOT-ish in-di-PEN-duhns", "fr": "indépendance écossaise", "def": "The idea that Scotland should become an independent country.", "ex": "Scottish independence remains a major constitutional issue."}, {"term": "Irish unity", "ipa": "/ˌaɪrɪʃ ˈjuːnəti/", "pron": "EYE-rish YOO-nuh-tee", "fr": "unité irlandaise", "def": "The idea that Northern Ireland should join the Republic of Ireland.", "ex": "Brexit renewed debates about Irish unity."}, {"term": "devolution", "ipa": "/ˌdiːvəˈluːʃən/", "pron": "dee-vuh-LOO-shuhn", "fr": "dévolution", "def": "The transfer of powers from Westminster to Scotland, Wales and Northern Ireland.", "ex": "Devolution has changed how people think about British identity."}, {"term": "asymmetrical devolution", "ipa": "/ˌeɪsɪˈmetrɪkəl ˌdiːvəˈluːʃən/", "pron": "ay-si-MET-ri-kuhl dee-vuh-LOO-shuhn", "fr": "dévolution asymétrique", "def": "A system where different parts of the UK have different levels of devolved power.", "ex": "Asymmetrical devolution makes the UK constitution complex."}, {"term": "multinational state", "ipa": "/ˌmʌltiˈnæʃənəl steɪt/", "pron": "MUL-tee-NASH-uh-nuhl state", "fr": "État multinational", "def": "A state made up of several nations.", "ex": "The UK is a multinational state."}, {"term": "multiculturalism", "ipa": "/ˌmʌltiˈkʌltʃərəlɪzəm/", "pron": "MUL-tee-KUL-chuh-ruh-liz-uhm", "fr": "multiculturalisme", "def": "A model in which different cultural groups coexist and are recognised.", "ex": "British identity has been reshaped by multiculturalism."}, {"term": "multicultural Britain", "ipa": "/ˌmʌltiˌkʌltʃərəl ˈbrɪtən/", "pron": "MUL-tee-KUL-chuh-ruhl BRIT-uhn", "fr": "Grande-Bretagne multiculturelle", "def": "Britain understood as a diverse society with many ethnic, religious and cultural communities.", "ex": "Multicultural Britain challenges older images of national identity."}, {"term": "diversity", "ipa": "/daɪˈvɜːsəti/", "pron": "dy-VUR-suh-tee", "fr": "diversité", "def": "The presence of different groups, cultures or identities.", "ex": "Diversity is a central feature of modern Britain."}]}, {"title": "D. Multicultural Britain, race, religion and empire", "entries": [{"term": "ethnic diversity", "ipa": "/ˌeθnɪk daɪˈvɜːsəti/", "pron": "ETH-nik dy-VUR-suh-tee", "fr": "diversité ethnique", "def": "The presence of different ethnic groups in society.", "ex": "Ethnic diversity is especially visible in major cities."}, {"term": "minority ethnic", "ipa": "/maɪˌnɒrəti ˈeθnɪk/", "pron": "my-NOR-uh-tee ETH-nik", "fr": "issu d’une minorité ethnique", "def": "A term used in Britain for people from ethnic minority backgrounds.", "ex": "Minority ethnic Britons have shaped politics, culture and business."}, {"term": "ethnic minority", "ipa": "/ˌeθnɪk maɪˈnɒrəti/", "pron": "ETH-nik my-NOR-uh-tee", "fr": "minorité ethnique", "def": "A group with a shared ethnic background that is smaller or less powerful than the majority.", "ex": "Ethnic minorities can face discrimination in housing and employment."}, {"term": "Black British", "ipa": "/ˌblæk ˈbrɪtɪʃ/", "pron": "black BRIT-ish", "fr": "Noir britannique ; Afro-Britannique", "def": "British people of African or Caribbean descent.", "ex": "Black British culture has transformed music, sport and politics."}, {"term": "British Asian", "ipa": "/ˌbrɪtɪʃ ˈeɪʒən/", "pron": "BRIT-ish AY-zhuhn", "fr": "Britannique d’origine asiatique", "def": "British people with South Asian or broader Asian heritage.", "ex": "British Asian communities are highly diverse."}, {"term": "Windrush generation", "ipa": "/ˈwɪndrʌʃ ˌdʒenəˈreɪʃən/", "pron": "WIND-rush jen-uh-RAY-shuhn", "fr": "génération Windrush", "def": "People from Caribbean countries who came to Britain from 1948 onwards to help rebuild the country.", "ex": "The Windrush generation is central to post-war British identity."}, {"term": "Windrush scandal", "ipa": "/ˈwɪndrʌʃ ˈskændəl/", "pron": "WIND-rush SKAN-duhl", "fr": "scandale Windrush", "def": "A scandal in which legal residents from the Windrush generation were wrongly detained, denied rights or deported.", "ex": "The Windrush scandal exposed the cruelty of immigration policy."}, {"term": "post-war immigration", "ipa": "/ˌpəʊst wɔː ˌɪmɪˈɡreɪʃən/", "pron": "post-war im-i-GRAY-shuhn", "fr": "immigration d’après-guerre", "def": "Immigration to Britain after the Second World War.", "ex": "Post-war immigration changed British society."}, {"term": "Commonwealth migration", "ipa": "/ˈkɒmənwelθ maɪˌɡreɪʃən/", "pron": "KOM-uhn-welth my-GRAY-shuhn", "fr": "migration du Commonwealth", "def": "Migration from Commonwealth countries to Britain.", "ex": "Commonwealth migration helped rebuild Britain after the war."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The process by which people become part of social, economic and political life.", "ex": "Integration debates often focus on language, education and employment."}, {"term": "assimilation", "ipa": "/əˌsɪmɪˈleɪʃən/", "pron": "uh-sim-i-LAY-shuhn", "fr": "assimilation", "def": "The process of adopting the majority culture, sometimes at the cost of minority identity.", "ex": "Assimilation is often contrasted with multiculturalism."}, {"term": "social cohesion", "ipa": "/ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "SOH-shuhl koh-HEE-zhuhn", "fr": "cohésion sociale", "def": "The degree of trust, connection and cooperation within society.", "ex": "Politicians often link integration to social cohesion."}, {"term": "community relations", "ipa": "/kəˌmjuːnəti rɪˈleɪʃənz/", "pron": "kuh-MYOO-nuh-tee ri-LAY-shuhnz", "fr": "relations intercommunautaires", "def": "Relations between different groups within society.", "ex": "Community relations can be strained by racism and inequality."}, {"term": "racial tension", "ipa": "/ˌreɪʃəl ˈtenʃən/", "pron": "RAY-shuhl TEN-shuhn", "fr": "tension raciale", "def": "Conflict or mistrust between racial groups.", "ex": "Racial tension has sometimes erupted after police incidents."}, {"term": "racism", "ipa": "/ˈreɪsɪzəm/", "pron": "RAY-siz-uhm", "fr": "racisme", "def": "Beliefs, practices or systems that discriminate based on race.", "ex": "Racism remains a challenge in British society."}, {"term": "institutional racism", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈreɪsɪzəm/", "pron": "in-sti-TOO-shuh-nuhl RAY-siz-uhm", "fr": "racisme institutionnel", "def": "Racist outcomes produced by institutions, policies or practices.", "ex": "The Macpherson Report popularised the term institutional racism."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by hostility towards identity such as race, religion or sexuality.", "ex": "Hate crime often rises after polarising political events."}, {"term": "Islamophobia", "ipa": "/ɪzˌlæməˈfəʊbiə/", "pron": "iz-lam-uh-FOH-bee-uh", "fr": "islamophobie", "def": "Hostility, prejudice or discrimination against Muslims.", "ex": "Islamophobia affects many British Muslims."}, {"term": "antisemitism", "ipa": "/ˌæntiˈsemɪtɪzəm/", "pron": "AN-tee-SEM-i-tiz-uhm", "fr": "antisémitisme", "def": "Hostility, prejudice or discrimination against Jewish people.", "ex": "Antisemitism has become a major political concern."}, {"term": "British Muslim", "ipa": "/ˌbrɪtɪʃ ˈmʊzlɪm/", "pron": "BRIT-ish MUZ-lim", "fr": "musulman britannique", "def": "A British person who is Muslim.", "ex": "British Muslims are part of Britain’s religious diversity."}, {"term": "secular society", "ipa": "/ˌsekjələ səˈsaɪəti/", "pron": "SEK-yuh-luh suh-SY-uh-tee", "fr": "société sécularisée", "def": "A society where religion has limited formal influence on public life.", "ex": "Britain is often described as a secular society with religious traditions."}, {"term": "Church of England", "ipa": "/ˌtʃɜːtʃ əv ˈɪŋɡlənd/", "pron": "church ov ING-gluhnd", "fr": "Église d’Angleterre", "def": "The established Christian church in England.", "ex": "The Church of England remains linked to the state."}, {"term": "established church", "ipa": "/ɪˌstæblɪʃt ˈtʃɜːtʃ/", "pron": "i-STAB-lisht church", "fr": "Église établie", "def": "A church officially recognised and supported by the state.", "ex": "The Church of England is an established church."}, {"term": "post-imperial Britain", "ipa": "/ˌpəʊst ɪmˈpɪəriəl ˈbrɪtən/", "pron": "post im-PEER-ee-uhl BRIT-uhn", "fr": "Grande-Bretagne post-impériale", "def": "Britain after the decline and end of its empire.", "ex": "Post-imperial Britain has struggled to redefine its global role."}, {"term": "British Empire", "ipa": "/ˌbrɪtɪʃ ˈempaɪə/", "pron": "BRIT-ish EM-py-uh", "fr": "Empire britannique", "def": "The former empire ruled or controlled by Britain.", "ex": "The British Empire remains central to debates about national memory."}, {"term": "imperial legacy", "ipa": "/ɪmˌpɪəriəl ˈleɡəsi/", "pron": "im-PEER-ee-uhl LEG-uh-see", "fr": "héritage impérial", "def": "The lasting impact of empire on politics, culture and society.", "ex": "The imperial legacy is increasingly debated in schools and museums."}, {"term": "colonial legacy", "ipa": "/kəˌləʊniəl ˈleɡəsi/", "pron": "kuh-LOH-nee-uhl LEG-uh-see", "fr": "héritage colonial", "def": "The lasting effects of colonial rule.", "ex": "The colonial legacy complicates patriotic narratives."}, {"term": "decolonisation", "ipa": "/ˌdiːkɒlənaɪˈzeɪʃən/", "pron": "dee-kol-uh-ny-ZAY-shuhn", "fr": "décolonisation", "def": "The process by which colonies became independent from imperial rule.", "ex": "Decolonisation transformed Britain’s role in the world."}]}, {"title": "E. Brexit, regional divides, values and high-value verbs", "entries": [{"term": "decolonising the curriculum", "ipa": "/ˌdiːˈkɒlənaɪzɪŋ ðə kəˈrɪkjʊləm/", "pron": "dee-KOL-uh-ny-zing thuh kuh-RIK-yuh-luhm", "fr": "décoloniser les programmes scolaires", "def": "Changing education to include colonial history and non-European perspectives.", "ex": "Decolonising the curriculum has become a culture-war issue."}, {"term": "statue debate", "ipa": "/ˈstætʃuː dɪˌbeɪt/", "pron": "STAT-choo di-BAYT", "fr": "débat sur les statues", "def": "Debate over public statues linked to empire, slavery or historical injustice.", "ex": "The statue debate shows how history shapes identity."}, {"term": "contested memory", "ipa": "/kənˌtestɪd ˈmeməri/", "pron": "kuhn-TES-tid MEM-uh-ree", "fr": "mémoire contestée", "def": "Disagreement over how the past should be remembered.", "ex": "Empire has become a site of contested memory."}, {"term": "national reckoning", "ipa": "/ˌnæʃənəl ˈrekənɪŋ/", "pron": "NASH-uh-nuhl REK-uhn-ing", "fr": "examen national du passé", "def": "A society’s serious confrontation with its past mistakes or injustices.", "ex": "Some historians call for a national reckoning with empire."}, {"term": "nostalgia", "ipa": "/nɒˈstældʒə/", "pron": "no-STAL-juh", "fr": "nostalgie", "def": "A sentimental longing for the past.", "ex": "Brexit rhetoric sometimes drew on imperial nostalgia."}, {"term": "imperial nostalgia", "ipa": "/ɪmˌpɪəriəl nɒˈstældʒə/", "pron": "im-PEER-ee-uhl no-STAL-juh", "fr": "nostalgie impériale", "def": "Nostalgia for Britain’s imperial power and global status.", "ex": "Imperial nostalgia can distort debates about Britain’s future."}, {"term": "Brexit identity divide", "ipa": "/ˈbreksɪt aɪˈdentəti dɪˌvaɪd/", "pron": "BREK-sit eye-DEN-tuh-tee di-VYDE", "fr": "fracture identitaire liée au Brexit", "def": "A division in identity and values exposed or intensified by Brexit.", "ex": "The Brexit identity divide cut across class, age and geography."}, {"term": "Leave identity", "ipa": "/ˈliːv aɪˌdentəti/", "pron": "leev eye-DEN-tuh-tee", "fr": "identité pro-Brexit", "def": "Political identity associated with support for Brexit.", "ex": "Leave identity often emphasised sovereignty and national control."}, {"term": "Remain identity", "ipa": "/rɪˈmeɪn aɪˌdentəti/", "pron": "ri-MAYN eye-DEN-tuh-tee", "fr": "identité pro-Remain", "def": "Political identity associated with opposition to Brexit.", "ex": "Remain identity often stressed European belonging and openness."}, {"term": "cosmopolitanism", "ipa": "/ˌkɒzməˈpɒlɪtənɪzəm/", "pron": "koz-muh-POL-i-tuh-niz-uhm", "fr": "cosmopolitisme", "def": "An outlook open to international mobility, diversity and global connections.", "ex": "Cosmopolitanism is often associated with big cities and Remain voters."}, {"term": "localism", "ipa": "/ˈləʊkəlɪzəm/", "pron": "LOH-kuh-liz-uhm", "fr": "localisme ; attachement local", "def": "Attachment to local communities and local control.", "ex": "Localism can challenge metropolitan politics."}, {"term": "metropolitan elite", "ipa": "/ˌmetrəˈpɒlɪtən ɪˈliːt/", "pron": "met-ruh-POL-i-tuhn i-LEET", "fr": "élite métropolitaine", "def": "Educated, urban and socially liberal elites, often criticised by populists.", "ex": "The metropolitan elite was a target of pro-Brexit rhetoric."}, {"term": "London-centric", "ipa": "/ˌlʌndən ˈsentrɪk/", "pron": "LUN-duhn SEN-trik", "fr": "centré sur Londres", "def": "Too focused on London and its interests.", "ex": "Many voters see politics as London-centric."}, {"term": "left-behind communities", "ipa": "/ˌleft bɪˈhaɪnd kəˈmjuːnətiz/", "pron": "left bi-HYND kuh-MYOO-nuh-teez", "fr": "communautés laissées pour compte", "def": "Communities that feel neglected by economic and political change.", "ex": "Left-behind communities often feel excluded from national success."}, {"term": "regional inequality", "ipa": "/ˌriːdʒənəl ˌɪnɪˈkwɒləti/", "pron": "REE-juh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité régionale", "def": "Unequal wealth, opportunity or services between regions.", "ex": "Regional inequality shapes British political resentment."}, {"term": "North-South divide", "ipa": "/ˌnɔːθ saʊθ dɪˈvaɪd/", "pron": "north-south di-VYDE", "fr": "fracture Nord-Sud", "def": "The economic and social gap between southern England and northern England.", "ex": "The North-South divide remains a major British issue."}, {"term": "levelling up", "ipa": "/ˌlevəlɪŋ ˈʌp/", "pron": "LEV-uhl-ing up", "fr": "rééquilibrage territorial ; levelling up", "def": "A policy slogan about reducing regional inequality.", "ex": "Levelling up promised investment outside London and the South East."}, {"term": "citizenship", "ipa": "/ˈsɪtɪzənʃɪp/", "pron": "SIT-i-zuhn-ship", "fr": "citoyenneté", "def": "Legal membership of a state, with rights and responsibilities.", "ex": "Citizenship can be legal, cultural and emotional."}, {"term": "British citizen", "ipa": "/ˌbrɪtɪʃ ˈsɪtɪzən/", "pron": "BRIT-ish SIT-i-zuhn", "fr": "citoyen britannique", "def": "A person with British citizenship.", "ex": "A British citizen has the right to live in the UK."}, {"term": "British values", "ipa": "/ˌbrɪtɪʃ ˈvæljuːz/", "pron": "BRIT-ish VAL-yooz", "fr": "valeurs britanniques", "def": "Values officially promoted in schools, such as democracy, rule of law, tolerance and individual liberty.", "ex": "British values are taught in schools but can be politically contested."}, {"term": "tolerance", "ipa": "/ˈtɒlərəns/", "pron": "TOL-uh-ruhns", "fr": "tolérance", "def": "Acceptance of different beliefs, identities or ways of life.", "ex": "Tolerance is often presented as a British value."}, {"term": "fair play", "ipa": "/ˌfeə ˈpleɪ/", "pron": "fair play", "fr": "fair-play ; esprit sportif", "def": "A British ideal of honesty, decency and playing by the rules.", "ex": "Fair play is part of Britain’s self-image."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including government, must obey the law.", "ex": "The rule of law is one of the official British values."}, {"term": "individual liberty", "ipa": "/ˌɪndɪˈvɪdʒuəl ˈlɪbəti/", "pron": "in-di-VIJ-oo-uhl LIB-uh-tee", "fr": "liberté individuelle", "def": "The freedom of individuals to make choices and express themselves.", "ex": "Individual liberty is presented as a core British value."}, {"term": "mutual respect", "ipa": "/ˌmjuːtʃuəl rɪˈspekt/", "pron": "MYOO-choo-uhl ri-SPEKT", "fr": "respect mutuel", "def": "Respect between people with different backgrounds or views.", "ex": "Schools are expected to promote mutual respect."}, {"term": "to belong to Britain", "ipa": "/bɪˈlɒŋ tə ˈbrɪtən/", "pron": "bi-LONG tuh BRIT-uhn", "fr": "appartenir à la Grande-Bretagne", "def": "To feel accepted as part of Britain.", "ex": "Many people belong to Britain in different ways."}, {"term": "to define Britishness", "ipa": "/dɪˈfaɪn ˈbrɪtɪʃnəs/", "pron": "di-FYNE BRIT-ish-nuhs", "fr": "définir la britannicité", "def": "To explain what being British means.", "ex": "Politicians often try to define Britishness."}, {"term": "to challenge national myths", "ipa": "/ˈtʃælɪndʒ ˌnæʃənəl ˈmɪθs/", "pron": "CHAL-inj NASH-uh-nuhl myths", "fr": "remettre en cause les mythes nationaux", "def": "To question simplified or idealised stories about the nation.", "ex": "Historians challenge national myths about empire."}, {"term": "to celebrate diversity", "ipa": "/ˈselɪbreɪt daɪˈvɜːsəti/", "pron": "SEL-i-brayt dy-VUR-suh-tee", "fr": "célébrer la diversité", "def": "To value and publicly recognise social and cultural diversity.", "ex": "Multicultural Britain celebrates diversity."}, {"term": "to foster social cohesion", "ipa": "/ˈfɒstə ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "FOS-tuh SOH-shuhl koh-HEE-zhuhn", "fr": "favoriser la cohésion sociale", "def": "To encourage trust and connection between groups.", "ex": "Good integration policies can foster social cohesion."}, {"term": "to expose divisions", "ipa": "/ɪkˈspəʊz dɪˈvɪʒənz/", "pron": "ik-SPOHZ di-VIZH-uhnz", "fr": "révéler les divisions", "def": "To reveal social or political divisions.", "ex": "Brexit exposed divisions within British society."}, {"term": "to fuel resentment", "ipa": "/ˈfjuːəl rɪˈzentmənt/", "pron": "FYOO-uhl ri-ZENT-muhnt", "fr": "alimenter le ressentiment", "def": "To intensify anger or bitterness.", "ex": "Regional inequality can fuel resentment."}, {"term": "to strengthen the Union", "ipa": "/ˈstreŋθən ðə ˈjuːniən/", "pron": "STRENG-thuhn thuh YOO-nee-uhn", "fr": "renforcer l’Union", "def": "To make the United Kingdom more stable or united.", "ex": "Some reforms aim to strengthen the Union."}, {"term": "to weaken the Union", "ipa": "/ˈwiːkən ðə ˈjuːniən/", "pron": "WEE-kuhn thuh YOO-nee-uhn", "fr": "affaiblir l’Union", "def": "To make the United Kingdom less stable or united.", "ex": "Brexit may have weakened the Union."}, {"term": "to reckon with empire", "ipa": "/ˈrekən wɪð ˈempaɪə/", "pron": "REK-uhn with EM-py-uh", "fr": "faire face à l’héritage impérial", "def": "To confront the legacy of the British Empire honestly.", "ex": "Britain is still learning to reckon with empire."}, {"term": "to redefine Britain’s place in the world", "ipa": "/ˌriːdɪˈfaɪn ˈbrɪtənz pleɪs ɪn ðə wɜːld/", "pron": "ree-di-FYNE BRIT-uhnz place in thuh world", "fr": "redéfinir la place du Royaume-Uni dans le monde", "def": "To rethink Britain’s international role and identity.", "ex": "Post-Brexit Britain must redefine its place in the world."}]}]}, {"id": "p3c26", "part": 3, "chapter": 26, "title": "Immigration In Britain", "file": "cpge_vocab_part3_chapter26_immigration_in_britain_premium.html", "count": 124, "sections": [{"title": "A. Core immigration vocabulary and post-war history", "entries": [{"term": "immigration in Britain", "ipa": "/ˌɪmɪˈɡreɪʃən ɪn ˈbrɪtən/", "pron": "im-i-GRAY-shuhn in BRIT-uhn", "fr": "immigration en Grande-Bretagne", "def": "The movement of people into Britain to live, work, study or seek protection.", "ex": "Immigration in Britain has shaped politics, identity and public services."}, {"term": "immigrant", "ipa": "/ˈɪmɪɡrənt/", "pron": "IM-i-gruhnt", "fr": "immigré ; immigrée", "def": "A person who moves to another country to live there.", "ex": "Immigrants have contributed to Britain’s economy and culture."}, {"term": "migrant", "ipa": "/ˈmaɪɡrənt/", "pron": "MY-gruhnt", "fr": "migrant ; migrante", "def": "A person who moves from one place to another, often for work, safety or better opportunities.", "ex": "Migrants are often discussed in debates about borders and labour shortages."}, {"term": "migration", "ipa": "/maɪˈɡreɪʃən/", "pron": "my-GRAY-shuhn", "fr": "migration", "def": "The movement of people across borders or within a country.", "ex": "Migration can be driven by conflict, poverty, education or work."}, {"term": "net migration", "ipa": "/ˌnet maɪˈɡreɪʃən/", "pron": "net my-GRAY-shuhn", "fr": "solde migratoire", "def": "The difference between the number of people entering and leaving a country.", "ex": "Net migration has become a major political issue in Britain."}, {"term": "foreign-born population", "ipa": "/ˌfɒrən bɔːn ˌpɒpjʊˈleɪʃən/", "pron": "FOR-uhn born pop-yuh-LAY-shuhn", "fr": "population née à l’étranger", "def": "The share of residents who were born outside the country.", "ex": "The foreign-born population is especially high in London."}, {"term": "ethnic minority", "ipa": "/ˌeθnɪk maɪˈnɒrəti/", "pron": "ETH-nik my-NOR-uh-tee", "fr": "minorité ethnique", "def": "A group with a shared ethnic background that is smaller or less powerful than the majority.", "ex": "Ethnic minority communities are part of modern British identity."}, {"term": "minority ethnic background", "ipa": "/maɪˌnɒrəti ˈeθnɪk ˈbækɡraʊnd/", "pron": "my-NOR-uh-tee ETH-nik BAK-ground", "fr": "origine issue d’une minorité ethnique", "def": "A background associated with an ethnic minority group.", "ex": "People from minority ethnic backgrounds can face discrimination."}, {"term": "British Asian", "ipa": "/ˌbrɪtɪʃ ˈeɪʒən/", "pron": "BRIT-ish AY-zhuhn", "fr": "Britannique d’origine asiatique", "def": "A British person with South Asian or broader Asian heritage.", "ex": "British Asian communities have shaped British food, business and politics."}, {"term": "Black British", "ipa": "/ˌblæk ˈbrɪtɪʃ/", "pron": "black BRIT-ish", "fr": "Noir britannique ; Afro-Britannique", "def": "A British person of African or Caribbean heritage.", "ex": "Black British culture has strongly influenced music and sport."}, {"term": "Commonwealth migration", "ipa": "/ˈkɒmənwelθ maɪˌɡreɪʃən/", "pron": "KOM-uhn-welth my-GRAY-shuhn", "fr": "migration du Commonwealth", "def": "Migration from Commonwealth countries to Britain.", "ex": "Commonwealth migration helped rebuild post-war Britain."}, {"term": "post-war immigration", "ipa": "/ˌpəʊst wɔː ˌɪmɪˈɡreɪʃən/", "pron": "post-war im-i-GRAY-shuhn", "fr": "immigration d’après-guerre", "def": "Immigration to Britain after the Second World War.", "ex": "Post-war immigration transformed British society."}, {"term": "Windrush generation", "ipa": "/ˈwɪndrʌʃ ˌdʒenəˈreɪʃən/", "pron": "WIND-rush jen-uh-RAY-shuhn", "fr": "génération Windrush", "def": "People from the Caribbean who came to Britain from 1948 onwards, especially to help rebuild the country.", "ex": "The Windrush generation is central to Britain’s post-war history."}, {"term": "Empire Windrush", "ipa": "/ˌempaɪə ˈwɪndrʌʃ/", "pron": "EM-py-uh WIND-rush", "fr": "Empire Windrush", "def": "The ship that brought Caribbean passengers to Britain in 1948, symbolising post-war migration.", "ex": "The arrival of the Empire Windrush became a symbolic moment."}, {"term": "Windrush scandal", "ipa": "/ˈwɪndrʌʃ ˈskændəl/", "pron": "WIND-rush SKAN-duhl", "fr": "scandale Windrush", "def": "A scandal in which legal residents were wrongly detained, denied rights or deported.", "ex": "The Windrush scandal exposed the human cost of hostile immigration policy."}, {"term": "hostile environment", "ipa": "/ˌhɒstaɪl ɪnˈvaɪrənmənt/", "pron": "HOS-tyle in-VY-ruhn-muhnt", "fr": "environnement hostile", "def": "A set of policies designed to make life difficult for undocumented migrants in the UK.", "ex": "The hostile environment policy was widely criticised after the Windrush scandal."}, {"term": "right to remain", "ipa": "/ˌraɪt tə rɪˈmeɪn/", "pron": "rite tuh ri-MAYN", "fr": "droit de séjour", "def": "Legal permission to stay in a country.", "ex": "Some Windrush victims struggled to prove their right to remain."}, {"term": "leave to remain", "ipa": "/ˌliːv tə rɪˈmeɪn/", "pron": "leev tuh ri-MAYN", "fr": "autorisation de séjour", "def": "Official permission for a non-citizen to stay in the UK.", "ex": "Migrants may apply for indefinite leave to remain."}, {"term": "indefinite leave to remain", "ipa": "/ɪnˌdefɪnət ˌliːv tə rɪˈmeɪn/", "pron": "in-DEF-i-nuht leev tuh ri-MAYN", "fr": "autorisation de séjour illimitée", "def": "Permission to live in the UK without a time limit.", "ex": "Indefinite leave to remain is a key step before citizenship."}, {"term": "settled status", "ipa": "/ˌsetəld ˈsteɪtəs/", "pron": "SET-uhld STAY-tuhs", "fr": "statut de résident permanent pour citoyens européens", "def": "A post-Brexit status allowing eligible EU citizens to continue living in the UK.", "ex": "Many EU citizens applied for settled status after Brexit."}, {"term": "pre-settled status", "ipa": "/ˌpriː ˈsetəld ˈsteɪtəs/", "pron": "pree-SET-uhld STAY-tuhs", "fr": "pré-statut de résident permanent", "def": "Temporary status for EU citizens who had not yet lived in the UK long enough for settled status.", "ex": "Pre-settled status created legal uncertainty for some residents."}, {"term": "EU citizens", "ipa": "/ˌiː juː ˈsɪtɪzənz/", "pron": "ee-yoo SIT-i-zuhnz", "fr": "citoyens de l’Union européenne", "def": "Citizens of European Union member states.", "ex": "EU citizens lost automatic free movement rights after Brexit."}, {"term": "free movement", "ipa": "/ˌfriː ˈmuːvmənt/", "pron": "free MOOV-muhnt", "fr": "libre circulation", "def": "The EU principle allowing citizens to live and work in other member states.", "ex": "Brexit ended free movement between the UK and the EU."}, {"term": "EU Settlement Scheme", "ipa": "/ˌiː juː ˈsetəlmənt skiːm/", "pron": "ee-yoo SET-uhl-muhnt skeem", "fr": "système de statut de résident pour citoyens européens", "def": "The UK system allowing eligible EU citizens to apply for post-Brexit residence rights.", "ex": "The EU Settlement Scheme affected millions of Europeans in Britain."}]}, {"title": "B. Visas, status, borders and the Home Office", "entries": [{"term": "points-based immigration system", "ipa": "/ˈpɔɪnts beɪst ˌɪmɪˈɡreɪʃən ˈsɪstəm/", "pron": "points bayst im-i-GRAY-shuhn SIS-tuhm", "fr": "système d’immigration à points", "def": "An immigration system that awards points for skills, salary, language and job offers.", "ex": "Britain introduced a points-based immigration system after Brexit."}, {"term": "skilled worker visa", "ipa": "/ˌskɪld ˈwɜːkə ˈviːzə/", "pron": "skild WUR-kuh VEE-zuh", "fr": "visa de travailleur qualifié", "def": "A visa allowing qualified workers to take eligible jobs in the UK.", "ex": "The skilled worker visa aims to attract workers in shortage occupations."}, {"term": "shortage occupation", "ipa": "/ˈʃɔːtɪdʒ ˌɒkjʊˈpeɪʃən/", "pron": "SHOR-tij ok-yuh-PAY-shuhn", "fr": "métier en tension", "def": "A job category where there are not enough workers.", "ex": "Care work has often been treated as a shortage occupation."}, {"term": "work visa", "ipa": "/ˈwɜːk ˌviːzə/", "pron": "work VEE-zuh", "fr": "visa de travail", "def": "A visa allowing a person to work legally in a country.", "ex": "Many migrants need a work visa to take a job in Britain."}, {"term": "student visa", "ipa": "/ˈstjuːdənt ˌviːzə/", "pron": "STYOO-duhnt VEE-zuh", "fr": "visa étudiant", "def": "A visa allowing a person to study in another country.", "ex": "International students contribute to British universities."}, {"term": "international student", "ipa": "/ˌɪntəˈnæʃənəl ˈstjuːdənt/", "pron": "IN-tuh-NASH-uh-nuhl STYOO-duhnt", "fr": "étudiant international", "def": "A student studying in a country other than their own.", "ex": "International students are included in migration statistics."}, {"term": "dependent", "ipa": "/dɪˈpendənt/", "pron": "di-PEN-duhnt", "fr": "personne à charge", "def": "A family member allowed to accompany or join a migrant under certain conditions.", "ex": "Restrictions on dependents became politically controversial."}, {"term": "family reunion", "ipa": "/ˌfæməli riːˈjuːniən/", "pron": "FAM-uh-lee ree-YOO-nee-uhn", "fr": "regroupement familial", "def": "The process of family members joining a relative already living in a country.", "ex": "Family reunion is important for refugees and settled migrants."}, {"term": "spouse visa", "ipa": "/spaʊs ˈviːzə/", "pron": "spowss VEE-zuh", "fr": "visa de conjoint", "def": "A visa allowing someone to join their husband, wife or partner in the UK.", "ex": "The spouse visa includes income requirements."}, {"term": "income threshold", "ipa": "/ˈɪnkʌm ˈθreʃhəʊld/", "pron": "IN-kum THRESH-hohld", "fr": "seuil de revenu", "def": "A minimum income required to qualify for a visa or benefit.", "ex": "The income threshold for family visas has been criticised as unfair."}, {"term": "border control", "ipa": "/ˈbɔːdə kənˌtrəʊl/", "pron": "BOR-duh kuhn-TROHL", "fr": "contrôle des frontières", "def": "The regulation of who enters and leaves a country.", "ex": "Border control was a central Brexit promise."}, {"term": "border security", "ipa": "/ˈbɔːdə sɪˌkjʊərəti/", "pron": "BOR-duh si-KYOOR-uh-tee", "fr": "sécurité aux frontières", "def": "Measures used to protect and monitor borders.", "ex": "The government promised stronger border security."}, {"term": "Home Office", "ipa": "/ˈhəʊm ˌɒfɪs/", "pron": "home OFF-is", "fr": "ministère de l’Intérieur britannique", "def": "The UK government department responsible for immigration, policing and security.", "ex": "The Home Office manages immigration applications."}, {"term": "Home Secretary", "ipa": "/ˈhəʊm ˌsekrətəri/", "pron": "home SEK-ruh-tuh-ree", "fr": "ministre de l’Intérieur britannique", "def": "The minister responsible for the Home Office.", "ex": "The Home Secretary announced a new migration policy."}, {"term": "UK Border Force", "ipa": "/ˌjuː keɪ ˈbɔːdə fɔːs/", "pron": "yoo-kay BOR-duh force", "fr": "police britannique aux frontières", "def": "The law enforcement command responsible for border control in the UK.", "ex": "UK Border Force officers check passports and goods."}, {"term": "asylum", "ipa": "/əˈsaɪləm/", "pron": "uh-SY-luhm", "fr": "asile", "def": "Protection granted to someone fleeing persecution or serious danger.", "ex": "Asylum claims have become a major political issue."}]}, {"title": "C. Asylum, small boats and enforcement", "entries": [{"term": "asylum seeker", "ipa": "/əˈsaɪləm ˌsiːkə/", "pron": "uh-SY-luhm SEE-kuh", "fr": "demandeur d’asile", "def": "A person who has applied for refugee protection and is awaiting a decision.", "ex": "Asylum seekers often wait months or years for a decision."}, {"term": "refugee", "ipa": "/ˌrefjʊˈdʒiː/", "pron": "REF-yoo-JEE", "fr": "réfugié ; réfugiée", "def": "A person forced to leave their country because of war, persecution or violence.", "ex": "Refugees have legal protection under international law."}, {"term": "persecution", "ipa": "/ˌpɜːsɪˈkjuːʃən/", "pron": "pur-si-KYOO-shuhn", "fr": "persécution", "def": "Mistreatment because of identity, religion, politics or social group.", "ex": "Victims of persecution may qualify for asylum."}, {"term": "humanitarian protection", "ipa": "/hjuːˌmænɪˈteəriən prəˈtekʃən/", "pron": "hyoo-man-i-TAIR-ee-uhn pruh-TEK-shuhn", "fr": "protection humanitaire", "def": "Protection granted to people at serious risk if returned to their country.", "ex": "Humanitarian protection applies when return would be dangerous."}, {"term": "refugee resettlement", "ipa": "/ˌrefjʊˈdʒiː riːˈsetəlmənt/", "pron": "REF-yoo-JEE ree-SET-uhl-muhnt", "fr": "réinstallation de réfugiés", "def": "The organised movement of refugees to a safe country where they can rebuild their lives.", "ex": "Refugee resettlement schemes have helped Syrians and Ukrainians."}, {"term": "safe and legal routes", "ipa": "/ˌseɪf ənd ˈliːɡəl ruːts/", "pron": "sayf and LEE-guhl roots", "fr": "voies sûres et légales", "def": "Official pathways for refugees or migrants to enter a country legally and safely.", "ex": "Critics argue that Britain needs more safe and legal routes."}, {"term": "small boats", "ipa": "/ˌsmɔːl ˈbəʊts/", "pron": "small boats", "fr": "petites embarcations ; small boats", "def": "Small vessels used by migrants to cross the English Channel, often dangerously.", "ex": "Small boats have become a symbol of the asylum debate."}, {"term": "Channel crossing", "ipa": "/ˈtʃænəl ˌkrɒsɪŋ/", "pron": "CHAN-uhl KROSS-ing", "fr": "traversée de la Manche", "def": "A journey across the English Channel, especially by migrants in small boats.", "ex": "Channel crossings are politically sensitive and dangerous."}, {"term": "English Channel", "ipa": "/ˌɪŋɡlɪʃ ˈtʃænəl/", "pron": "ING-glish CHAN-uhl", "fr": "Manche", "def": "The sea between southern England and northern France.", "ex": "The English Channel has become a migration route."}, {"term": "people smuggler", "ipa": "/ˈpiːpəl ˌsmʌɡlə/", "pron": "PEE-puhl SMUG-luh", "fr": "passeur", "def": "A person who illegally helps migrants cross borders for money.", "ex": "People smugglers exploit desperate migrants."}, {"term": "smuggling network", "ipa": "/ˈsmʌɡlɪŋ ˌnetwɜːk/", "pron": "SMUG-ling NET-wurk", "fr": "réseau de passeurs", "def": "An organised group illegally helping people or goods cross borders.", "ex": "The government promised to break smuggling networks."}, {"term": "human trafficking", "ipa": "/ˌhjuːmən ˈtræfɪkɪŋ/", "pron": "HYOO-muhn TRAF-i-king", "fr": "traite des êtres humains", "def": "The illegal exploitation of people through force, coercion or deception.", "ex": "Migrants can be vulnerable to human trafficking."}, {"term": "detention centre", "ipa": "/dɪˈtenʃən ˌsentə/", "pron": "di-TEN-shuhn SEN-tuh", "fr": "centre de rétention ; centre de détention", "def": "A facility where migrants are held by the authorities.", "ex": "Immigration detention centres have faced criticism."}, {"term": "immigration detention", "ipa": "/ˌɪmɪˈɡreɪʃən dɪˈtenʃən/", "pron": "im-i-GRAY-shuhn di-TEN-shuhn", "fr": "rétention administrative liée à l’immigration", "def": "The holding of migrants by immigration authorities.", "ex": "Immigration detention raises human rights concerns."}, {"term": "deportation", "ipa": "/ˌdiːpɔːˈteɪʃən/", "pron": "dee-por-TAY-shuhn", "fr": "expulsion ; reconduite à la frontière", "def": "The forced removal of a non-citizen from a country.", "ex": "Deportation can separate families and communities."}, {"term": "removal", "ipa": "/rɪˈmuːvəl/", "pron": "ri-MOO-vuhl", "fr": "éloignement ; expulsion", "def": "The official process of forcing someone to leave the country.", "ex": "The Home Office planned removals of rejected asylum seekers."}, {"term": "Rwanda plan", "ipa": "/ruːˈændə plæn/", "pron": "roo-AN-duh plan", "fr": "plan Rwanda", "def": "A UK policy proposal to send some asylum seekers to Rwanda for processing or settlement.", "ex": "The Rwanda plan became one of Britain’s most controversial asylum policies."}, {"term": "offshore processing", "ipa": "/ˌɒfʃɔː ˈprəʊsesɪŋ/", "pron": "OFF-shor PROH-sess-ing", "fr": "traitement offshore des demandes d’asile", "def": "Processing asylum claims outside the country where asylum is sought.", "ex": "Offshore processing was defended as a deterrent and criticised as inhumane."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "A policy designed to discourage people from doing something.", "ex": "The government framed the Rwanda plan as deterrence."}, {"term": "illegal migration", "ipa": "/ɪˌliːɡəl maɪˈɡreɪʃən/", "pron": "i-LEE-guhl my-GRAY-shuhn", "fr": "migration illégale ; terme politisé", "def": "Migration that breaks immigration law; a politically charged phrase.", "ex": "Illegal migration is often used in government rhetoric."}, {"term": "irregular migration", "ipa": "/ɪˌreɡjʊlə maɪˈɡreɪʃən/", "pron": "i-REG-yuh-luh my-GRAY-shuhn", "fr": "migration irrégulière", "def": "Migration outside regular legal channels.", "ex": "Irregular migration can be driven by lack of safe routes."}, {"term": "undocumented migrant", "ipa": "/ʌnˈdɒkjʊmentɪd ˈmaɪɡrənt/", "pron": "un-DOK-yuh-men-tid MY-gruhnt", "fr": "migrant sans papiers ; migrant en situation irrégulière", "def": "A migrant without legal documents or permission to stay.", "ex": "Undocumented migrants often avoid public services out of fear."}, {"term": "overstayer", "ipa": "/ˈəʊvəsteɪə/", "pron": "OH-vuh-stay-uh", "fr": "personne ayant dépassé la durée de son visa", "def": "A person who remains in a country after their visa has expired.", "ex": "Some undocumented migrants are visa overstayers."}, {"term": "illegal working", "ipa": "/ɪˌliːɡəl ˈwɜːkɪŋ/", "pron": "i-LEE-guhl WUR-king", "fr": "travail illégal", "def": "Work carried out without legal permission.", "ex": "Employers can be fined for illegal working."}, {"term": "right to work check", "ipa": "/ˌraɪt tə ˈwɜːk tʃek/", "pron": "rite tuh work chek", "fr": "vérification du droit au travail", "def": "A check employers must make to confirm someone can legally work in the UK.", "ex": "Right to work checks are part of the hostile environment."}, {"term": "right to rent check", "ipa": "/ˌraɪt tə ˈrent tʃek/", "pron": "rite tuh rent chek", "fr": "vérification du droit de louer", "def": "A check landlords must make to confirm someone can legally rent housing in England.", "ex": "Right to rent checks have been criticised for encouraging discrimination."}, {"term": "overcrowded housing", "ipa": "/ˌəʊvəˌkraʊdɪd ˈhaʊzɪŋ/", "pron": "OH-vuh-KROW-did HOW-zing", "fr": "logement surpeuplé", "def": "Housing with too many people living in too little space.", "ex": "Some migrant families face overcrowded housing."}, {"term": "asylum accommodation", "ipa": "/əˈsaɪləm əˌkɒməˈdeɪʃən/", "pron": "uh-SY-luhm uh-kom-uh-DAY-shuhn", "fr": "hébergement des demandeurs d’asile", "def": "Housing provided to asylum seekers while their claims are processed.", "ex": "Asylum accommodation has been criticised as inadequate."}]}, {"title": "D. Integration, citizenship, labour and public services", "entries": [{"term": "hotel accommodation", "ipa": "/həʊˈtel əˌkɒməˈdeɪʃən/", "pron": "hoh-TEL uh-kom-uh-DAY-shuhn", "fr": "hébergement en hôtel", "def": "Use of hotels to house asylum seekers temporarily.", "ex": "Hotel accommodation for asylum seekers became politically controversial."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The process by which migrants become part of social, economic and political life.", "ex": "Language learning can support integration."}, {"term": "assimilation", "ipa": "/əˌsɪmɪˈleɪʃən/", "pron": "uh-sim-i-LAY-shuhn", "fr": "assimilation", "def": "The process of adopting the majority culture, sometimes at the cost of minority identity.", "ex": "Assimilation is often contrasted with multiculturalism."}, {"term": "multiculturalism", "ipa": "/ˌmʌltiˈkʌltʃərəlɪzəm/", "pron": "MUL-tee-KUL-chuh-ruh-liz-uhm", "fr": "multiculturalisme", "def": "A model where different cultural groups coexist and are recognised.", "ex": "Multiculturalism has shaped modern Britain."}, {"term": "social cohesion", "ipa": "/ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "SOH-shuhl koh-HEE-zhuhn", "fr": "cohésion sociale", "def": "Trust and connection between groups in society.", "ex": "Integration policies aim to strengthen social cohesion."}, {"term": "community relations", "ipa": "/kəˌmjuːnəti rɪˈleɪʃənz/", "pron": "kuh-MYOO-nuh-tee ri-LAY-shuhnz", "fr": "relations intercommunautaires", "def": "Relations between different groups within society.", "ex": "Community relations can be damaged by racism and political scapegoating."}, {"term": "parallel lives", "ipa": "/ˌpærəlel ˈlaɪvz/", "pron": "PARR-uh-lel lyvz", "fr": "vies parallèles ; communautés séparées", "def": "A phrase describing communities living separately with limited interaction.", "ex": "The phrase parallel lives was used in debates about segregation."}, {"term": "segregation", "ipa": "/ˌseɡrɪˈɡeɪʃən/", "pron": "seg-ri-GAY-shuhn", "fr": "ségrégation", "def": "The separation of groups in housing, schools or social life.", "ex": "Critics of multiculturalism sometimes warn of segregation."}, {"term": "British values", "ipa": "/ˌbrɪtɪʃ ˈvæljuːz/", "pron": "BRIT-ish VAL-yooz", "fr": "valeurs britanniques", "def": "Values officially promoted in schools, such as democracy, tolerance and the rule of law.", "ex": "British values are often mentioned in integration debates."}, {"term": "citizenship test", "ipa": "/ˈsɪtɪzənʃɪp test/", "pron": "SIT-i-zuhn-ship test", "fr": "test de citoyenneté", "def": "A test on language, culture and institutions required for citizenship.", "ex": "The citizenship test has been criticised for obscure questions."}, {"term": "Life in the UK test", "ipa": "/ˌlaɪf ɪn ðə ˌjuː ˈkeɪ test/", "pron": "life in thuh yoo-kay test", "fr": "test Life in the UK", "def": "The test required for British citizenship or settlement.", "ex": "The Life in the UK test assesses knowledge of British life."}, {"term": "English language requirement", "ipa": "/ˌɪŋɡlɪʃ ˈlæŋɡwɪdʒ rɪˈkwaɪəmənt/", "pron": "ING-glish LANG-gwij ri-KWY-uh-muhnt", "fr": "condition de maîtrise de l’anglais", "def": "A rule requiring migrants to prove English ability.", "ex": "The English language requirement is part of citizenship policy."}, {"term": "naturalisation", "ipa": "/ˌnætʃərəlaɪˈzeɪʃən/", "pron": "nach-uh-ruh-ly-ZAY-shuhn", "fr": "naturalisation", "def": "The process of becoming a citizen of another country.", "ex": "Naturalisation can be expensive and bureaucratic."}, {"term": "British citizenship", "ipa": "/ˌbrɪtɪʃ ˈsɪtɪzənʃɪp/", "pron": "BRIT-ish SIT-i-zuhn-ship", "fr": "citoyenneté britannique", "def": "Legal membership of the United Kingdom.", "ex": "British citizenship grants the right to vote in general elections."}, {"term": "dual nationality", "ipa": "/ˌdjuːəl ˌnæʃəˈnæləti/", "pron": "DYOO-uhl nash-uh-NAL-uh-tee", "fr": "double nationalité", "def": "The status of holding two nationalities.", "ex": "Many migrants hold dual nationality."}, {"term": "belonging", "ipa": "/bɪˈlɒŋɪŋ/", "pron": "bi-LONG-ing", "fr": "appartenance", "def": "A feeling of being accepted as part of a place or community.", "ex": "Belonging is not only legal but also emotional."}, {"term": "identity", "ipa": "/aɪˈdentəti/", "pron": "eye-DEN-tuh-tee", "fr": "identité", "def": "A person’s sense of who they are, including nationality, culture and background.", "ex": "Migration can create layered identities."}, {"term": "hyphenated identity", "ipa": "/ˈhaɪfəneɪtɪd aɪˈdentəti/", "pron": "HY-fuh-nay-tid eye-DEN-tuh-tee", "fr": "identité composée ; identité à trait d’union", "def": "An identity combining two national or cultural labels.", "ex": "British-Pakistani is an example of a hyphenated identity."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community living outside its ancestral homeland.", "ex": "Diaspora communities keep links with countries of origin."}, {"term": "remittances", "ipa": "/rɪˈmɪtənsɪz/", "pron": "ri-MIT-uhn-siz", "fr": "transferts d’argent ; remises migratoires", "def": "Money sent by migrants to family or communities in their country of origin.", "ex": "Remittances support families abroad."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˈʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A lack of workers for available jobs.", "ex": "Immigration can help address labour shortages."}, {"term": "NHS workforce", "ipa": "/ˌen eɪtʃ ˈes ˈwɜːkfɔːs/", "pron": "en-aych-ess WURK-force", "fr": "personnel du NHS", "def": "The workers employed by the National Health Service.", "ex": "The NHS workforce depends heavily on migrant workers."}, {"term": "care sector", "ipa": "/ˈkeə ˌsektə/", "pron": "care SEK-tuh", "fr": "secteur du soin et de l’aide à la personne", "def": "The sector providing care for elderly, disabled or vulnerable people.", "ex": "The care sector has recruited many overseas workers."}, {"term": "seasonal worker", "ipa": "/ˌsiːzənəl ˈwɜːkə/", "pron": "SEE-zuh-nuhl WUR-kuh", "fr": "travailleur saisonnier", "def": "A worker employed for a limited season, often in agriculture.", "ex": "Seasonal workers are important in British farming."}, {"term": "low-paid work", "ipa": "/ˌləʊ peɪd ˈwɜːk/", "pron": "loh payd work", "fr": "travail mal payé", "def": "Work with low wages.", "ex": "Migrants are often concentrated in low-paid work."}, {"term": "exploitation", "ipa": "/ˌeksplɔɪˈteɪʃən/", "pron": "ek-sploy-TAY-shuhn", "fr": "exploitation", "def": "Unfair treatment of workers for profit or advantage.", "ex": "Visa dependency can increase the risk of exploitation."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brayn drayn", "fr": "fuite des cerveaux", "def": "The emigration of skilled workers from one country to another.", "ex": "Recruiting health workers abroad can create brain drain elsewhere."}, {"term": "public services", "ipa": "/ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "PUB-lik SUR-vis-iz", "fr": "services publics", "def": "Services provided by the state, such as healthcare, education and housing.", "ex": "Immigration debates often focus on pressure on public services."}]}, {"title": "E. Politics, rhetoric and high-value verbs", "entries": [{"term": "pressure on housing", "ipa": "/ˈpreʃər ɒn ˈhaʊzɪŋ/", "pron": "PRESH-uh on HOW-zing", "fr": "pression sur le logement", "def": "Strain on housing supply or affordability.", "ex": "Some politicians link immigration to pressure on housing."}, {"term": "tax contribution", "ipa": "/ˈtæks ˌkɒntrɪˈbjuːʃən/", "pron": "taks kon-tri-BYOO-shuhn", "fr": "contribution fiscale", "def": "Money paid in taxes by individuals or groups.", "ex": "Migrants make an important tax contribution."}, {"term": "economic contribution", "ipa": "/ˌiːkəˈnɒmɪk ˌkɒntrɪˈbjuːʃən/", "pron": "ee-kuh-NOM-ik kon-tri-BYOO-shuhn", "fr": "contribution économique", "def": "The value added to the economy through work, taxes or business.", "ex": "The economic contribution of migrants is often overlooked."}, {"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "zen-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Fear or hostility towards foreigners or migrants.", "ex": "Anti-migrant rhetoric can fuel xenophobia."}, {"term": "racism", "ipa": "/ˈreɪsɪzəm/", "pron": "RAY-siz-uhm", "fr": "racisme", "def": "Discrimination or prejudice based on race or ethnicity.", "ex": "Racism affects many migrant and minority communities."}, {"term": "anti-immigrant rhetoric", "ipa": "/ˌænti ˈɪmɪɡrənt ˈretərɪk/", "pron": "AN-tee IM-i-gruhnt RET-uh-rik", "fr": "rhétorique anti-immigrés", "def": "Language presenting migrants as a threat or burden.", "ex": "Anti-immigrant rhetoric intensifies during election campaigns."}, {"term": "scapegoating", "ipa": "/ˈskeɪpɡəʊtɪŋ/", "pron": "SKAYP-goht-ing", "fr": "désignation d’un bouc émissaire", "def": "Blaming a group unfairly for wider problems.", "ex": "Scapegoating migrants can distract from policy failures."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "Public fear, often exaggerated, that a group threatens society.", "ex": "Small boat arrivals triggered a moral panic in parts of the media."}, {"term": "tabloid press", "ipa": "/ˈtæblɔɪd pres/", "pron": "TAB-loyd press", "fr": "presse tabloïd", "def": "Popular newspapers often using sensationalist coverage.", "ex": "The tabloid press has shaped immigration debates."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Immigration has become a culture-war issue."}, {"term": "populist rhetoric", "ipa": "/ˈpɒpjʊlɪst ˈretərɪk/", "pron": "POP-yuh-list RET-uh-rik", "fr": "rhétorique populiste", "def": "Language claiming to defend ordinary people against elites and outsiders.", "ex": "Populist rhetoric often targets immigration."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The power of a state to control its own laws and borders.", "ex": "Sovereignty was central to Brexit immigration debates."}, {"term": "control of borders", "ipa": "/kənˌtrəʊl əv ˈbɔːdəz/", "pron": "kuhn-TROHL ov BOR-duhz", "fr": "contrôle des frontières", "def": "The ability to decide who can enter and stay in a country.", "ex": "Control of borders was a key Leave slogan."}, {"term": "take back control", "ipa": "/ˌteɪk bæk kənˈtrəʊl/", "pron": "tayk bak kuhn-TROHL", "fr": "reprendre le contrôle", "def": "A Brexit slogan meaning the UK should regain control over laws, borders and money.", "ex": "Take back control was strongly linked to immigration."}, {"term": "to curb immigration", "ipa": "/kɜːb ˌɪmɪˈɡreɪʃən/", "pron": "kurb im-i-GRAY-shuhn", "fr": "freiner l’immigration", "def": "To reduce or limit immigration.", "ex": "Several governments promised to curb immigration."}, {"term": "to reduce net migration", "ipa": "/rɪˈdjuːs net maɪˈɡreɪʃən/", "pron": "ri-DYOOSS net my-GRAY-shuhn", "fr": "réduire le solde migratoire", "def": "To lower the difference between arrivals and departures.", "ex": "The government pledged to reduce net migration."}, {"term": "to tighten immigration rules", "ipa": "/ˈtaɪtən ˌɪmɪˈɡreɪʃən ruːlz/", "pron": "TY-tuhn im-i-GRAY-shuhn roolz", "fr": "durcir les règles d’immigration", "def": "To make immigration rules stricter.", "ex": "Ministers moved to tighten immigration rules."}, {"term": "to loosen immigration rules", "ipa": "/ˈluːsən ˌɪmɪˈɡreɪʃən ruːlz/", "pron": "LOO-suhn im-i-GRAY-shuhn roolz", "fr": "assouplir les règles d’immigration", "def": "To make immigration rules less strict.", "ex": "Business leaders called for loosening immigration rules."}, {"term": "to seek asylum", "ipa": "/siːk əˈsaɪləm/", "pron": "seek uh-SY-luhm", "fr": "demander l’asile", "def": "To request protection because of persecution or danger.", "ex": "People fleeing persecution have the right to seek asylum."}, {"term": "to process asylum claims", "ipa": "/ˈprəʊses əˈsaɪləm kleɪmz/", "pron": "PROH-sess uh-SY-luhm klaymz", "fr": "traiter les demandes d’asile", "def": "To examine and decide applications for asylum.", "ex": "Delays in processing asylum claims created huge backlogs."}, {"term": "to clear the backlog", "ipa": "/klɪə ðə ˈbæklɒɡ/", "pron": "kleer thuh BAK-log", "fr": "résorber l’arriéré", "def": "To reduce or remove accumulated unresolved cases.", "ex": "The Home Office promised to clear the asylum backlog."}, {"term": "to deport someone", "ipa": "/dɪˈpɔːt ˈsʌmwʌn/", "pron": "di-PORT SUM-wun", "fr": "expulser quelqu’un", "def": "To force someone to leave the country.", "ex": "The policy made it easier to deport some migrants."}, {"term": "to grant refugee status", "ipa": "/ɡrɑːnt ˌrefjʊˈdʒiː ˈsteɪtəs/", "pron": "grant REF-yoo-JEE STAY-tuhs", "fr": "accorder le statut de réfugié", "def": "To officially recognise someone as a refugee.", "ex": "The tribunal granted refugee status to the applicant."}, {"term": "to regularise status", "ipa": "/ˈreɡjʊləraɪz ˈsteɪtəs/", "pron": "REG-yuh-luh-ryz STAY-tuhs", "fr": "régulariser la situation", "def": "To give legal status to someone who lacked it.", "ex": "Campaigners called for a way to regularise status."}, {"term": "to integrate into society", "ipa": "/ˈɪntɪɡreɪt ˈɪntuː səˈsaɪəti/", "pron": "IN-ti-grayt IN-too suh-SY-uh-tee", "fr": "s’intégrer dans la société", "def": "To become part of social, economic and civic life.", "ex": "Language classes help migrants integrate into society."}, {"term": "to contribute to the economy", "ipa": "/kənˈtrɪbjuːt tə ði iˈkɒnəmi/", "pron": "kuhn-TRIB-yoot tuh thee i-KON-uh-mee", "fr": "contribuer à l’économie", "def": "To add value through work, taxes or entrepreneurship.", "ex": "Migrants contribute to the economy in many sectors."}, {"term": "to fill labour shortages", "ipa": "/fɪl ˈleɪbə ˈʃɔːtɪdʒɪz/", "pron": "fil LAY-buh SHOR-tij-iz", "fr": "combler les pénuries de main-d’œuvre", "def": "To provide workers where there are not enough staff.", "ex": "Migrant workers fill labour shortages in health and care."}, {"term": "to fuel political polarisation", "ipa": "/ˈfjuːəl pəˈlɪtɪkəl ˌpəʊləraɪˈzeɪʃən/", "pron": "FYOO-uhl puh-LIT-i-kuhl poh-luh-ry-ZAY-shuhn", "fr": "alimenter la polarisation politique", "def": "To intensify political division.", "ex": "Immigration debates can fuel political polarisation."}]}]}, {"id": "p3c27", "part": 3, "chapter": 27, "title": "Devolution", "file": "cpge_vocab_part3_chapter27_devolution_premium.html", "count": 92, "sections": [{"title": "A. Core devolution vocabulary and constitutional concepts", "entries": [{"term": "devolution", "ipa": "/ˌdiːvəˈluːʃən/", "pron": "dee-vuh-LOO-shuhn", "fr": "dévolution", "def": "The transfer of powers from central government to regional or national governments within a state.", "ex": "Devolution has transformed the constitutional structure of the United Kingdom."}, {"term": "devolved power", "ipa": "/dɪˌvɒlvd ˈpaʊə/", "pron": "di-VOLVD POW-uh", "fr": "pouvoir dévolu", "def": "A power transferred from Westminster to a devolved administration.", "ex": "Health and education are devolved powers in Scotland."}, {"term": "devolved administration", "ipa": "/dɪˌvɒlvd ədˌmɪnɪˈstreɪʃən/", "pron": "di-VOLVD ad-min-i-STRAY-shuhn", "fr": "administration dévolue", "def": "A government in Scotland, Wales or Northern Ireland with powers transferred from Westminster.", "ex": "Devolved administrations can make policy in areas such as health and education."}, {"term": "devolved legislature", "ipa": "/dɪˌvɒlvd ˈledʒɪslətʃə/", "pron": "di-VOLVD LEDJ-is-luh-chuh", "fr": "assemblée législative dévolue", "def": "A law-making body with powers transferred from Westminster.", "ex": "The Scottish Parliament is a devolved legislature."}, {"term": "reserved matter", "ipa": "/rɪˌzɜːvd ˈmætə/", "pron": "ri-ZURVD MAT-uh", "fr": "compétence réservée", "def": "A policy area kept under Westminster control rather than devolved.", "ex": "Defence and immigration are reserved matters."}, {"term": "devolved matter", "ipa": "/dɪˌvɒlvd ˈmætə/", "pron": "di-VOLVD MAT-uh", "fr": "compétence dévolue", "def": "A policy area controlled by a devolved administration.", "ex": "Education is a devolved matter in Scotland and Wales."}, {"term": "reserved powers", "ipa": "/rɪˌzɜːvd ˈpaʊəz/", "pron": "ri-ZURVD POW-uhz", "fr": "pouvoirs réservés", "def": "Powers kept by the central UK Parliament or government.", "ex": "Reserved powers remain under Westminster control."}, {"term": "transferred powers", "ipa": "/trænsˌfɜːd ˈpaʊəz/", "pron": "trans-FURD POW-uhz", "fr": "pouvoirs transférés", "def": "Powers moved from central government to a devolved institution.", "ex": "Transferred powers allow more local decision-making."}, {"term": "asymmetrical devolution", "ipa": "/ˌeɪsɪˈmetrɪkəl ˌdiːvəˈluːʃən/", "pron": "ay-si-MET-ri-kuhl dee-vuh-LOO-shuhn", "fr": "dévolution asymétrique", "def": "A system in which different parts of a state receive different levels of power.", "ex": "The UK has asymmetrical devolution because Scotland, Wales and Northern Ireland do not have identical powers."}, {"term": "centralisation", "ipa": "/ˌsentrəlaɪˈzeɪʃən/", "pron": "sen-truh-ly-ZAY-shuhn", "fr": "centralisation", "def": "The concentration of power in central government.", "ex": "Britain has historically been a highly centralised state."}, {"term": "decentralisation", "ipa": "/ˌdiːsentrəlaɪˈzeɪʃən/", "pron": "dee-sen-truh-ly-ZAY-shuhn", "fr": "décentralisation", "def": "The transfer or spread of power away from central government.", "ex": "Devolution is a form of decentralisation."}, {"term": "unitary state", "ipa": "/ˌjuːnɪtəri ˈsteɪt/", "pron": "YOO-ni-tuh-ree state", "fr": "État unitaire", "def": "A state in which ultimate legal authority belongs to the central government.", "ex": "The UK remains a unitary state despite devolution."}, {"term": "federal state", "ipa": "/ˌfedərəl ˈsteɪt/", "pron": "FED-uh-ruhl state", "fr": "État fédéral", "def": "A state where power is constitutionally divided between central and regional governments.", "ex": "The UK is not a federal state like the United States or Germany."}, {"term": "federalism", "ipa": "/ˈfedərəlɪzəm/", "pron": "FED-uh-ruh-liz-uhm", "fr": "fédéralisme", "def": "A system in which power is divided between national and regional governments.", "ex": "Some argue that federalism could solve the UK’s constitutional tensions."}, {"term": "quasi-federal", "ipa": "/ˌkweɪzaɪ ˈfedərəl/", "pron": "KWAY-zy FED-uh-ruhl", "fr": "quasi fédéral", "def": "Partly similar to federalism without being fully federal.", "ex": "The UK has sometimes been described as quasi-federal."}, {"term": "multinational state", "ipa": "/ˌmʌltiˈnæʃənəl steɪt/", "pron": "MUL-tee-NASH-uh-nuhl state", "fr": "État multinational", "def": "A state made up of several nations.", "ex": "The UK is a multinational state composed of England, Scotland, Wales and Northern Ireland."}, {"term": "four nations", "ipa": "/ˌfɔː ˈneɪʃənz/", "pron": "four NAY-shuhnz", "fr": "quatre nations", "def": "England, Scotland, Wales and Northern Ireland within the UK.", "ex": "Devolution reflects the different identities of the four nations."}, {"term": "Union", "ipa": "/ˈjuːniən/", "pron": "YOO-nee-uhn", "fr": "Union britannique", "def": "The political union of the UK’s nations.", "ex": "Devolution has both preserved and challenged the Union."}, {"term": "Act of Union", "ipa": "/ˌækt əv ˈjuːniən/", "pron": "akt ov YOO-nee-uhn", "fr": "Acte d’Union", "def": "A law creating or formalising a political union, especially between England and Scotland in 1707.", "ex": "The Act of Union created the Kingdom of Great Britain."}, {"term": "Westminster", "ipa": "/ˈwestmɪnstə/", "pron": "WEST-min-stuh", "fr": "Westminster ; pouvoir central britannique", "def": "The UK Parliament and central government, based in London.", "ex": "Westminster retains sovereignty over devolved institutions."}, {"term": "parliamentary sovereignty", "ipa": "/ˌpɑːləˈmentəri ˈsɒvrənti/", "pron": "par-luh-MEN-tuh-ree SOV-ruhn-tee", "fr": "souveraineté parlementaire", "def": "The principle that the UK Parliament can make or unmake any law.", "ex": "Parliamentary sovereignty means Westminster can legally alter devolved powers."}, {"term": "constitutional settlement", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈsetəlmənt/", "pron": "kon-sti-TOO-shuh-nuhl SET-uhl-muhnt", "fr": "arrangement constitutionnel", "def": "The set of rules and arrangements defining how political power is organised.", "ex": "Devolution created a new constitutional settlement."}, {"term": "devolution settlement", "ipa": "/ˌdiːvəˈluːʃən ˈsetəlmənt/", "pron": "dee-vuh-LOO-shuhn SET-uhl-muhnt", "fr": "accord de dévolution ; cadre de dévolution", "def": "The legal and political arrangements governing devolved powers.", "ex": "The devolution settlement is different in each part of the UK."}, {"term": "constitutional reform", "ipa": "/ˌkɒnstɪˈtjuːʃənəl rɪˈfɔːm/", "pron": "kon-sti-TOO-shuh-nuhl ri-FORM", "fr": "réforme constitutionnelle", "def": "Changes to the rules and institutions of government.", "ex": "Devolution was part of wider constitutional reform under New Labour."}, {"term": "New Labour", "ipa": "/ˌnjuː ˈleɪbə/", "pron": "nyoo LAY-buh", "fr": "New Labour", "def": "The modernised Labour Party associated with Tony Blair in the late 1990s and 2000s.", "ex": "New Labour introduced devolution after its 1997 election victory."}, {"term": "referendum", "ipa": "/ˌrefəˈrendəm/", "pron": "ref-uh-REN-duhm", "fr": "référendum", "def": "A direct vote by citizens on a specific political question.", "ex": "Devolution was approved by referendums in Scotland and Wales."}, {"term": "devolution referendum", "ipa": "/ˌdiːvəˈluːʃən ˌrefəˈrendəm/", "pron": "dee-vuh-LOO-shuhn ref-uh-REN-duhm", "fr": "référendum sur la dévolution", "def": "A referendum asking voters whether powers should be transferred to a devolved institution.", "ex": "The 1997 devolution referendum led to the creation of the Scottish Parliament."}, {"term": "Scottish Parliament", "ipa": "/ˌskɒtɪʃ ˈpɑːləmənt/", "pron": "SKOT-ish PAR-luh-muhnt", "fr": "Parlement écossais", "def": "The devolved legislature of Scotland.", "ex": "The Scottish Parliament can pass laws in devolved areas."}]}, {"title": "B. Scotland: Holyrood, the SNP and independence", "entries": [{"term": "Holyrood", "ipa": "/ˈhɒliruːd/", "pron": "HOL-i-rood", "fr": "Holyrood ; Parlement écossais", "def": "The Scottish Parliament, named after its location in Edinburgh.", "ex": "Holyrood has become the centre of Scottish political life."}, {"term": "Scottish Government", "ipa": "/ˌskɒtɪʃ ˈɡʌvənmənt/", "pron": "SKOT-ish GUV-uhn-muhnt", "fr": "gouvernement écossais", "def": "The devolved government of Scotland.", "ex": "The Scottish Government manages health, education and justice in Scotland."}, {"term": "First Minister of Scotland", "ipa": "/ˌfɜːst ˈmɪnɪstə əv ˈskɒtlənd/", "pron": "first MIN-i-stuh ov SKOT-luhnd", "fr": "Premier ministre d’Écosse", "def": "The head of the Scottish Government.", "ex": "The First Minister of Scotland leads the devolved government."}, {"term": "Scottish National Party", "ipa": "/ˌskɒtɪʃ ˈnæʃənəl ˈpɑːti/", "pron": "SKOT-ish NASH-uh-nuhl PAR-tee", "fr": "Parti national écossais ; SNP", "def": "A party supporting Scottish self-government and independence.", "ex": "The Scottish National Party has used devolution to push for independence."}, {"term": "SNP", "ipa": "/ˌes en ˈpiː/", "pron": "ess en pee", "fr": "SNP", "def": "Abbreviation for the Scottish National Party.", "ex": "The SNP argues that Scotland should have the right to choose independence."}, {"term": "Scottish independence", "ipa": "/ˌskɒtɪʃ ˌɪndɪˈpendəns/", "pron": "SKOT-ish in-di-PEN-duhns", "fr": "indépendance écossaise", "def": "The idea that Scotland should become an independent country.", "ex": "Scottish independence remains a major challenge to the Union."}, {"term": "independence referendum", "ipa": "/ˌɪndɪˈpendəns ˌrefəˈrendəm/", "pron": "in-di-PEN-duhns ref-uh-REN-duhm", "fr": "référendum d’indépendance", "def": "A referendum on whether a territory should become independent.", "ex": "The 2014 independence referendum kept Scotland in the UK."}, {"term": "indyref2", "ipa": "/ˈɪndi ref tuː/", "pron": "IN-dee ref too", "fr": "deuxième référendum d’indépendance écossais", "def": "Informal term for a proposed second Scottish independence referendum.", "ex": "The SNP has repeatedly called for indyref2."}, {"term": "self-determination", "ipa": "/ˌself dɪˌtɜːmɪˈneɪʃən/", "pron": "self di-tur-mi-NAY-shuhn", "fr": "autodétermination", "def": "The right of a people or nation to decide its political future.", "ex": "Scottish nationalists frame independence as self-determination."}, {"term": "Welsh Parliament", "ipa": "/ˌwelʃ ˈpɑːləmənt/", "pron": "Welsh PAR-luh-muhnt", "fr": "Parlement gallois ; Senedd", "def": "The devolved legislature of Wales, also known as the Senedd.", "ex": "The Welsh Parliament has gained more powers over time."}]}, {"title": "C. Wales and Northern Ireland: Senedd, Stormont and power-sharing", "entries": [{"term": "Senedd", "ipa": "/ˈsenɛð/", "pron": "SEN-eth", "fr": "Senedd ; Parlement gallois", "def": "The Welsh Parliament.", "ex": "The Senedd debates Welsh domestic policy."}, {"term": "Welsh Government", "ipa": "/ˌwelʃ ˈɡʌvənmənt/", "pron": "Welsh GUV-uhn-muhnt", "fr": "gouvernement gallois", "def": "The devolved government of Wales.", "ex": "The Welsh Government controls health and education in Wales."}, {"term": "First Minister of Wales", "ipa": "/ˌfɜːst ˈmɪnɪstə əv ˈweɪlz/", "pron": "first MIN-i-stuh ov WAYLZ", "fr": "Premier ministre du Pays de Galles", "def": "The head of the Welsh Government.", "ex": "The First Minister of Wales leads the devolved administration."}, {"term": "Welsh language", "ipa": "/ˌwelʃ ˈlæŋɡwɪdʒ/", "pron": "Welsh LANG-gwij", "fr": "langue galloise", "def": "The Celtic language spoken in Wales.", "ex": "The Welsh language is protected by devolved policy."}, {"term": "Plaid Cymru", "ipa": "/ˌplaɪd ˈkʌmri/", "pron": "plyde KUM-ree", "fr": "Plaid Cymru ; parti nationaliste gallois", "def": "A Welsh nationalist party supporting greater autonomy or independence for Wales.", "ex": "Plaid Cymru campaigns for Welsh self-government."}, {"term": "Welsh independence", "ipa": "/ˌwelʃ ˌɪndɪˈpendəns/", "pron": "Welsh in-di-PEN-duhns", "fr": "indépendance galloise", "def": "The idea that Wales should become an independent country.", "ex": "Welsh independence has gained some visibility in recent years."}, {"term": "Northern Ireland Assembly", "ipa": "/ˌnɔːðən ˈaɪələnd əˈsembli/", "pron": "NOR-thuhn EYE-uh-luhnd uh-SEM-blee", "fr": "Assemblée d’Irlande du Nord", "def": "The devolved legislature of Northern Ireland.", "ex": "The Northern Ireland Assembly depends on power-sharing."}, {"term": "Stormont", "ipa": "/ˈstɔːmənt/", "pron": "STOR-muhnt", "fr": "Stormont ; institutions nord-irlandaises", "def": "The Northern Ireland Assembly and executive, named after its location near Belfast.", "ex": "Stormont has repeatedly collapsed because of political disputes."}, {"term": "Northern Ireland Executive", "ipa": "/ˌnɔːðən ˈaɪələnd ɪɡˈzekjʊtɪv/", "pron": "NOR-thuhn EYE-uh-luhnd ig-ZEK-yuh-tiv", "fr": "Exécutif d’Irlande du Nord", "def": "The devolved government of Northern Ireland.", "ex": "The Northern Ireland Executive is based on power-sharing."}, {"term": "power-sharing", "ipa": "/ˈpaʊə ˌʃeərɪŋ/", "pron": "POW-uh shair-ing", "fr": "partage du pouvoir", "def": "A system in which rival groups share government power.", "ex": "Power-sharing is central to Northern Ireland’s devolved institutions."}, {"term": "consociationalism", "ipa": "/kənˌsəʊʃiˈeɪʃənəlɪzəm/", "pron": "kuhn-soh-shee-AY-shuh-nuh-liz-uhm", "fr": "consociationalisme ; démocratie consociative", "def": "A system where different communities share power to manage deep divisions.", "ex": "Northern Ireland uses consociationalism to balance unionist and nationalist communities."}, {"term": "Good Friday Agreement", "ipa": "/ˌɡʊd ˈfraɪdeɪ əˈɡriːmənt/", "pron": "good FRY-day uh-GREE-muhnt", "fr": "Accord du Vendredi saint", "def": "The 1998 peace agreement that created power-sharing institutions in Northern Ireland.", "ex": "The Good Friday Agreement is the foundation of Northern Ireland devolution."}, {"term": "Belfast Agreement", "ipa": "/ˌbelfɑːst əˈɡriːmənt/", "pron": "BEL-fast uh-GREE-muhnt", "fr": "Accord de Belfast", "def": "Another name for the Good Friday Agreement.", "ex": "The Belfast Agreement helped end decades of conflict."}, {"term": "unionist", "ipa": "/ˈjuːniənɪst/", "pron": "YOO-nee-uhn-ist", "fr": "unioniste", "def": "A person who supports Northern Ireland remaining part of the UK.", "ex": "Unionists defend Northern Ireland’s place in the Union."}, {"term": "nationalist", "ipa": "/ˈnæʃənəlɪst/", "pron": "NASH-uh-nuh-list", "fr": "nationaliste irlandais", "def": "In Northern Ireland, a person who supports Irish national identity and often Irish unity.", "ex": "Nationalists generally support closer ties with the Republic of Ireland."}, {"term": "Irish unity", "ipa": "/ˌaɪrɪʃ ˈjuːnəti/", "pron": "EYE-rish YOO-nuh-tee", "fr": "unité irlandaise", "def": "The idea that Northern Ireland should join the Republic of Ireland.", "ex": "Brexit renewed debates about Irish unity."}, {"term": "border poll", "ipa": "/ˈbɔːdə pəʊl/", "pron": "BOR-duh pohl", "fr": "référendum sur l’unification irlandaise", "def": "A referendum on whether Northern Ireland should remain in the UK or join a united Ireland.", "ex": "A border poll could be held if support for Irish unity appears likely."}, {"term": "direct rule", "ipa": "/dəˌrekt ˈruːl/", "pron": "di-REKT rool", "fr": "administration directe depuis Londres", "def": "Governance of Northern Ireland directly from Westminster when devolved institutions collapse.", "ex": "Direct rule has returned during periods of political deadlock."}, {"term": "English question", "ipa": "/ˌɪŋɡlɪʃ ˈkwestʃən/", "pron": "ING-glish KWES-chuhn", "fr": "question anglaise", "def": "The constitutional problem of how England should be governed within a devolved UK.", "ex": "The English question remains unresolved."}]}, {"title": "D. England, regional devolution and local government", "entries": [{"term": "English votes for English laws", "ipa": "/ˌɪŋɡlɪʃ vəʊts fər ˌɪŋɡlɪʃ ˈlɔːz/", "pron": "ING-glish vohts for ING-glish lawz", "fr": "votes anglais pour les lois anglaises", "def": "A former procedure limiting some votes on England-only legislation to English MPs.", "ex": "English votes for English laws tried to address the English question."}, {"term": "English Parliament", "ipa": "/ˌɪŋɡlɪʃ ˈpɑːləmənt/", "pron": "ING-glish PAR-luh-muhnt", "fr": "Parlement anglais", "def": "A proposed separate parliament for England.", "ex": "Some argue that an English Parliament would balance devolution."}, {"term": "regional devolution", "ipa": "/ˌriːdʒənəl ˌdiːvəˈluːʃən/", "pron": "REE-juh-nuhl dee-vuh-LOO-shuhn", "fr": "dévolution régionale", "def": "The transfer of powers to regions within England.", "ex": "Regional devolution in England has been uneven."}, {"term": "metro mayor", "ipa": "/ˌmetrəʊ ˈmeə/", "pron": "MET-roh MAY-uh", "fr": "maire métropolitain", "def": "An elected mayor leading a combined authority in an English city-region.", "ex": "Metro mayors control transport, planning and local economic strategy."}, {"term": "combined authority", "ipa": "/kəmˌbaɪnd ɔːˈθɒrəti/", "pron": "kuhm-BYND aw-THOR-uh-tee", "fr": "autorité combinée", "def": "A group of local councils working together under a shared governance structure.", "ex": "Combined authorities are central to English regional devolution."}, {"term": "city-region", "ipa": "/ˈsɪti ˌriːdʒən/", "pron": "SIT-ee REE-juhn", "fr": "région urbaine", "def": "A city and its surrounding economic area.", "ex": "City-region devolution aims to boost local growth."}, {"term": "levelling up", "ipa": "/ˌlevəlɪŋ ˈʌp/", "pron": "LEV-uhl-ing up", "fr": "rééquilibrage territorial ; levelling up", "def": "A policy slogan about reducing regional inequality.", "ex": "Levelling up was linked to English regional devolution."}, {"term": "regional inequality", "ipa": "/ˌriːdʒənəl ˌɪnɪˈkwɒləti/", "pron": "REE-juh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité régionale", "def": "Unequal wealth, services or opportunities between regions.", "ex": "Regional inequality strengthens demands for more local power."}, {"term": "local government", "ipa": "/ˌləʊkəl ˈɡʌvənmənt/", "pron": "LOH-kuhl GUV-uhn-muhnt", "fr": "collectivités locales ; gouvernement local", "def": "Government at city, county or district level.", "ex": "Local government in England has fewer powers than devolved administrations."}, {"term": "local authority", "ipa": "/ˌləʊkəl ɔːˈθɒrəti/", "pron": "LOH-kuhl aw-THOR-uh-tee", "fr": "collectivité locale ; autorité locale", "def": "A local council responsible for services in an area.", "ex": "Local authorities deliver social care, housing and waste services."}, {"term": "subsidiarity", "ipa": "/səbˌsɪdiˈærəti/", "pron": "suhb-sid-ee-ARR-uh-tee", "fr": "subsidiarité", "def": "The principle that decisions should be taken as closely as possible to citizens.", "ex": "Subsidiarity is often used to justify devolution."}, {"term": "self-government", "ipa": "/ˌself ˈɡʌvənmənt/", "pron": "self GUV-uhn-muhnt", "fr": "autonomie gouvernementale", "def": "The ability of a region or nation to govern its own affairs.", "ex": "Devolution gives Scotland a degree of self-government."}, {"term": "home rule", "ipa": "/ˌhəʊm ˈruːl/", "pron": "home rool", "fr": "autonomie politique ; home rule", "def": "The right of a region or nation to govern itself within a larger state.", "ex": "Home rule has a long history in Irish and Scottish debates."}, {"term": "autonomy", "ipa": "/ɔːˈtɒnəmi/", "pron": "aw-TON-uh-mee", "fr": "autonomie", "def": "The ability to make decisions independently.", "ex": "Devolution grants limited autonomy to the UK’s nations."}, {"term": "fiscal devolution", "ipa": "/ˌfɪskəl ˌdiːvəˈluːʃən/", "pron": "FIS-kuhl dee-vuh-LOO-shuhn", "fr": "dévolution fiscale", "def": "The transfer of tax and spending powers to devolved governments.", "ex": "Fiscal devolution gives Scotland some tax powers."}, {"term": "tax-raising powers", "ipa": "/ˈtæks reɪzɪŋ ˈpaʊəz/", "pron": "taks RAY-zing POW-uhz", "fr": "pouvoirs fiscaux", "def": "The authority to create or vary taxes.", "ex": "Tax-raising powers make devolved governments more accountable."}]}, {"title": "E. Fiscal powers, constitutional tensions and high-value verbs", "entries": [{"term": "block grant", "ipa": "/ˈblɒk ɡrɑːnt/", "pron": "blok grant", "fr": "dotation globale", "def": "A lump sum of money given by the UK government to a devolved administration.", "ex": "The block grant funds many devolved services."}, {"term": "Barnett formula", "ipa": "/ˈbɑːnɪt ˌfɔːmjʊlə/", "pron": "BAR-nit FOR-myuh-luh", "fr": "formule Barnett", "def": "The formula used to allocate public spending to Scotland, Wales and Northern Ireland.", "ex": "The Barnett formula is often criticised as outdated."}, {"term": "policy divergence", "ipa": "/ˈpɒləsi daɪˈvɜːdʒəns/", "pron": "POL-uh-see dy-VUR-juhns", "fr": "divergence des politiques publiques", "def": "The process by which different governments adopt different policies.", "ex": "Devolution has led to policy divergence across the UK."}, {"term": "postcode lottery", "ipa": "/ˈpəʊstkəʊd ˌlɒtəri/", "pron": "POST-kohd LOT-uh-ree", "fr": "loterie du code postal ; inégalités territoriales", "def": "Unequal access to services depending on where people live.", "ex": "Policy divergence can create a postcode lottery."}, {"term": "constitutional tension", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈtenʃən/", "pron": "kon-sti-TOO-shuh-nuhl TEN-shuhn", "fr": "tension constitutionnelle", "def": "A conflict or strain within constitutional arrangements.", "ex": "Brexit created constitutional tension between Westminster and Holyrood."}, {"term": "intergovernmental relations", "ipa": "/ˌɪntəɡʌvənˈmentəl rɪˈleɪʃənz/", "pron": "IN-tuh-guv-uhn-MEN-tuhl ri-LAY-shuhnz", "fr": "relations intergouvernementales", "def": "Relations between different levels of government.", "ex": "Intergovernmental relations became strained during Brexit and Covid."}, {"term": "legislative consent motion", "ipa": "/ˌledʒɪslətɪv kənˈsent ˌməʊʃən/", "pron": "LEDJ-is-luh-tiv kuhn-SENT MOH-shuhn", "fr": "motion de consentement législatif", "def": "A motion by which a devolved legislature agrees that Westminster may legislate on a devolved matter.", "ex": "Legislative consent motions became controversial during Brexit."}, {"term": "Sewel Convention", "ipa": "/ˈsuːəl kənˌvenʃən/", "pron": "SOO-uhl kuhn-VEN-shuhn", "fr": "Convention Sewel", "def": "The convention that Westminster will not normally legislate on devolved matters without consent.", "ex": "The Sewel Convention has been tested repeatedly since Brexit."}, {"term": "to devolve power", "ipa": "/dɪˈvɒlv ˈpaʊə/", "pron": "di-VOLV POW-uh", "fr": "dévoluer le pouvoir", "def": "To transfer power from central government to a lower or regional level.", "ex": "The UK devolved power to Scotland, Wales and Northern Ireland."}, {"term": "to transfer powers", "ipa": "/trænsˈfɜː ˈpaʊəz/", "pron": "trans-FUR POW-uhz", "fr": "transférer des pouvoirs", "def": "To move powers from one institution to another.", "ex": "The reform transferred powers to the Welsh Parliament."}, {"term": "to reserve powers", "ipa": "/rɪˈzɜːv ˈpaʊəz/", "pron": "ri-ZURV POW-uhz", "fr": "réserver des pouvoirs", "def": "To keep certain powers under central control.", "ex": "The UK government reserves powers over defence and immigration."}, {"term": "to grant autonomy", "ipa": "/ɡrɑːnt ɔːˈtɒnəmi/", "pron": "grant aw-TON-uh-mee", "fr": "accorder l’autonomie", "def": "To give a region or institution self-governing powers.", "ex": "Devolution grants autonomy without full independence."}, {"term": "to strengthen the Union", "ipa": "/ˈstreŋθən ðə ˈjuːniən/", "pron": "STRENG-thuhn thuh YOO-nee-uhn", "fr": "renforcer l’Union", "def": "To make the UK more stable and united.", "ex": "Some politicians argue that devolution can strengthen the Union."}, {"term": "to weaken the Union", "ipa": "/ˈwiːkən ðə ˈjuːniən/", "pron": "WEE-kuhn thuh YOO-nee-uhn", "fr": "affaiblir l’Union", "def": "To make the UK less stable or more divided.", "ex": "Critics say devolution has weakened the Union."}, {"term": "to demand independence", "ipa": "/dɪˈmɑːnd ˌɪndɪˈpendəns/", "pron": "di-MAND in-di-PEN-duhns", "fr": "réclamer l’indépendance", "def": "To call for a nation or region to become independent.", "ex": "Scottish nationalists continue to demand independence."}, {"term": "to challenge Westminster authority", "ipa": "/ˈtʃælɪndʒ ˈwestmɪnstər ɔːˈθɒrəti/", "pron": "CHAL-inj WEST-min-stuh aw-THOR-uh-tee", "fr": "contester l’autorité de Westminster", "def": "To question or oppose the power of the UK central government.", "ex": "Devolved governments sometimes challenge Westminster authority."}, {"term": "to create policy divergence", "ipa": "/kriˈeɪt ˈpɒləsi daɪˈvɜːdʒəns/", "pron": "kree-AYT POL-uh-see dy-VUR-juhns", "fr": "créer une divergence des politiques publiques", "def": "To produce different policies in different parts of the country.", "ex": "Devolution can create policy divergence across the UK."}, {"term": "to manage territorial tensions", "ipa": "/ˈmænɪdʒ ˌterɪˈtɔːriəl ˈtenʃənz/", "pron": "MAN-ij ter-i-TOR-ee-uhl TEN-shuhnz", "fr": "gérer les tensions territoriales", "def": "To handle conflicts between regions or nations within a state.", "ex": "The UK must manage territorial tensions carefully."}, {"term": "to reshape the constitution", "ipa": "/riːˈʃeɪp ðə ˌkɒnstɪˈtjuːʃən/", "pron": "ree-SHAYP thuh kon-sti-TOO-shuhn", "fr": "remodeler la constitution", "def": "To significantly change constitutional arrangements.", "ex": "Devolution has reshaped the British constitution."}]}]}, {"id": "p3c28", "part": 3, "chapter": 28, "title": "Northern Ireland", "file": "cpge_vocab_part3_chapter28_northern_ireland_premium.html", "count": 111, "sections": [{"title": "A. Core geography, identity and constitutional vocabulary", "entries": [{"term": "Northern Ireland", "ipa": "/ˌnɔːðən ˈaɪələnd/", "pron": "NOR-thuhn EYE-uh-luhnd", "fr": "Irlande du Nord", "def": "A nation or region within the United Kingdom with a complex constitutional and political status.", "ex": "Northern Ireland remains one of the most sensitive issues in British politics."}, {"term": "Ulster", "ipa": "/ˈʌlstə/", "pron": "UL-stuh", "fr": "Ulster", "def": "A historic province of Ireland; often used politically to refer to Northern Ireland, though not all Ulster is in the UK.", "ex": "The term Ulster is often associated with unionist identity."}, {"term": "the six counties", "ipa": "/ðə ˌsɪks ˈkaʊntiz/", "pron": "thuh six KOWN-teez", "fr": "les six comtés", "def": "A nationalist term for Northern Ireland, referring to its six counties.", "ex": "Some Irish nationalists call Northern Ireland the six counties."}, {"term": "the province", "ipa": "/ðə ˈprɒvɪns/", "pron": "thuh PROV-inss", "fr": "la province", "def": "A common term for Northern Ireland, especially in British or unionist contexts.", "ex": "The province has experienced decades of constitutional tension."}, {"term": "partition", "ipa": "/pɑːˈtɪʃən/", "pron": "par-TISH-uhn", "fr": "partition", "def": "The division of Ireland into Northern Ireland and what became the Republic of Ireland.", "ex": "Partition created a border between Northern Ireland and the rest of Ireland."}, {"term": "Government of Ireland Act", "ipa": "/ˌɡʌvənmənt əv ˈaɪələnd ækt/", "pron": "GUV-uhn-muhnt ov EYE-uh-luhnd akt", "fr": "Government of Ireland Act", "def": "The 1920 Act that partitioned Ireland and created Northern Ireland.", "ex": "The Government of Ireland Act laid the legal basis for partition."}, {"term": "Irish Free State", "ipa": "/ˌaɪrɪʃ ˈfriː steɪt/", "pron": "EYE-rish free state", "fr": "État libre d’Irlande", "def": "The state created in 1922 after the Anglo-Irish Treaty, later becoming the Republic of Ireland.", "ex": "The Irish Free State did not include Northern Ireland."}, {"term": "Republic of Ireland", "ipa": "/rɪˌpʌblɪk əv ˈaɪələnd/", "pron": "ri-PUB-lik ov EYE-uh-luhnd", "fr": "République d’Irlande", "def": "The sovereign state covering most of the island of Ireland.", "ex": "Northern Ireland shares a land border with the Republic of Ireland."}, {"term": "border", "ipa": "/ˈbɔːdə/", "pron": "BOR-duh", "fr": "frontière", "def": "The line separating Northern Ireland from the Republic of Ireland.", "ex": "The Irish border became central to Brexit negotiations."}, {"term": "Irish border", "ipa": "/ˌaɪrɪʃ ˈbɔːdə/", "pron": "EYE-rish BOR-duh", "fr": "frontière irlandaise", "def": "The border between Northern Ireland and the Republic of Ireland.", "ex": "The Irish border is both a practical and symbolic issue."}, {"term": "hard border", "ipa": "/ˌhɑːd ˈbɔːdə/", "pron": "hard BOR-duh", "fr": "frontière dure", "def": "A border with physical checks, customs controls or infrastructure.", "ex": "The Good Friday Agreement helped remove the hard border."}, {"term": "soft border", "ipa": "/ˌsɒft ˈbɔːdə/", "pron": "soft BOR-duh", "fr": "frontière souple", "def": "A border with minimal or invisible checks.", "ex": "A soft border supported peace and everyday cross-border life."}, {"term": "cross-border cooperation", "ipa": "/ˌkrɒs ˈbɔːdə kəʊˌɒpəˈreɪʃən/", "pron": "kross BOR-duh koh-op-uh-RAY-shuhn", "fr": "coopération transfrontalière", "def": "Cooperation between institutions or communities on both sides of a border.", "ex": "Cross-border cooperation is a key part of the peace process."}, {"term": "all-Ireland", "ipa": "/ˌɔːl ˈaɪələnd/", "pron": "awl EYE-uh-luhnd", "fr": "panirlandais ; à l’échelle de l’île d’Irlande", "def": "Relating to the whole island of Ireland, north and south.", "ex": "Some institutions operate on an all-Ireland basis."}, {"term": "unionist", "ipa": "/ˈjuːniənɪst/", "pron": "YOO-nee-uhn-ist", "fr": "unioniste", "def": "A person who supports Northern Ireland remaining part of the United Kingdom.", "ex": "Unionists usually identify strongly with Britain."}, {"term": "unionism", "ipa": "/ˈjuːniənɪzəm/", "pron": "YOO-nee-uhn-iz-uhm", "fr": "unionisme", "def": "Support for Northern Ireland’s continued place in the United Kingdom.", "ex": "Unionism remains a major political force in Northern Ireland."}, {"term": "loyalist", "ipa": "/ˈlɔɪəlɪst/", "pron": "LOY-uh-list", "fr": "loyaliste", "def": "A working-class or militant form of unionism, often linked historically to paramilitary groups.", "ex": "Loyalist groups opposed Irish republicanism."}, {"term": "loyalism", "ipa": "/ˈlɔɪəlɪzəm/", "pron": "LOY-uh-liz-uhm", "fr": "loyalisme", "def": "A strongly pro-British political identity in Northern Ireland, sometimes associated with Protestant working-class communities.", "ex": "Loyalism has often been linked to street protests and paramilitary history."}, {"term": "nationalist", "ipa": "/ˈnæʃənəlɪst/", "pron": "NASH-uh-nuh-list", "fr": "nationaliste irlandais", "def": "In Northern Ireland, a person who supports Irish national identity and often Irish unity.", "ex": "Nationalists generally support closer ties with the Republic of Ireland."}, {"term": "nationalism", "ipa": "/ˈnæʃənəlɪzəm/", "pron": "NASH-uh-nuh-liz-uhm", "fr": "nationalisme irlandais", "def": "Support for Irish national identity and, in this context, often Irish unity.", "ex": "Irish nationalism challenges Northern Ireland’s place in the UK."}, {"term": "republican", "ipa": "/rɪˈpʌblɪkən/", "pron": "ri-PUB-li-kuhn", "fr": "républicain irlandais", "def": "A person who supports a united Irish republic and rejects British rule in Northern Ireland.", "ex": "Republicans traditionally opposed British sovereignty in Northern Ireland."}, {"term": "republicanism", "ipa": "/rɪˈpʌblɪkənɪzəm/", "pron": "ri-PUB-li-kuh-niz-uhm", "fr": "républicanisme irlandais", "def": "The political movement supporting a united Irish republic.", "ex": "Republicanism was central to the conflict known as the Troubles."}, {"term": "Irish unity", "ipa": "/ˌaɪrɪʃ ˈjuːnəti/", "pron": "EYE-rish YOO-nuh-tee", "fr": "unité irlandaise", "def": "The idea that Northern Ireland should join the Republic of Ireland.", "ex": "Brexit renewed debates about Irish unity."}, {"term": "united Ireland", "ipa": "/juːˌnaɪtɪd ˈaɪələnd/", "pron": "yoo-NY-tid EYE-uh-luhnd", "fr": "Irlande unifiée", "def": "A single Irish state including both Northern Ireland and the Republic of Ireland.", "ex": "Support for a united Ireland has increased in some polls."}, {"term": "British identity", "ipa": "/ˌbrɪtɪʃ aɪˈdentəti/", "pron": "BRIT-ish eye-DEN-tuh-tee", "fr": "identité britannique", "def": "A sense of belonging to Britain or the UK.", "ex": "British identity is central to many unionists."}, {"term": "Irish identity", "ipa": "/ˌaɪrɪʃ aɪˈdentəti/", "pron": "EYE-rish eye-DEN-tuh-tee", "fr": "identité irlandaise", "def": "A sense of belonging to Ireland.", "ex": "Irish identity is central to many nationalists."}, {"term": "Northern Irish identity", "ipa": "/ˌnɔːðən ˈaɪrɪʃ aɪˈdentəti/", "pron": "NOR-thuhn EYE-rish eye-DEN-tuh-tee", "fr": "identité nord-irlandaise", "def": "A sense of belonging specifically to Northern Ireland.", "ex": "Northern Irish identity can bridge or complicate traditional divisions."}, {"term": "Protestant community", "ipa": "/ˈprɒtɪstənt kəˌmjuːnəti/", "pron": "PROT-i-stuhnt kuh-MYOO-nuh-tee", "fr": "communauté protestante", "def": "The community historically associated with unionism and British identity.", "ex": "The Protestant community has often supported unionist parties."}, {"term": "Catholic community", "ipa": "/ˈkæθəlɪk kəˌmjuːnəti/", "pron": "KATH-uh-lik kuh-MYOO-nuh-tee", "fr": "communauté catholique", "def": "The community historically associated with nationalism and Irish identity.", "ex": "The Catholic community has often supported nationalist parties."}, {"term": "sectarianism", "ipa": "/sekˈteəriənɪzəm/", "pron": "sek-TAIR-ee-uh-niz-uhm", "fr": "sectarisme", "def": "Hostility or discrimination between religious or communal groups.", "ex": "Sectarianism has left a deep mark on Northern Irish society."}, {"term": "sectarian divide", "ipa": "/sekˌteəriən dɪˈvaɪd/", "pron": "sek-TAIR-ee-uhn di-VYDE", "fr": "fracture communautaire ; division sectaire", "def": "The division between Protestant/unionist and Catholic/nationalist communities.", "ex": "The sectarian divide affects housing, education and politics."}, {"term": "community division", "ipa": "/kəˌmjuːnəti dɪˈvɪʒən/", "pron": "kuh-MYOO-nuh-tee di-VIZH-uhn", "fr": "division communautaire", "def": "Separation or tension between social or political communities.", "ex": "Community division remains visible in some neighbourhoods."}, {"term": "segregated housing", "ipa": "/ˌseɡrɪɡeɪtɪd ˈhaʊzɪŋ/", "pron": "SEG-ri-gay-tid HOW-zing", "fr": "logement ségrégué", "def": "Housing patterns where communities live largely separately.", "ex": "Segregated housing reflects the legacy of the conflict."}, {"term": "integrated education", "ipa": "/ˌɪntɪɡreɪtɪd ˌedjʊˈkeɪʃən/", "pron": "IN-ti-gray-tid ej-yoo-KAY-shuhn", "fr": "éducation intégrée", "def": "Education bringing Protestant and Catholic pupils together.", "ex": "Integrated education is often promoted as a path to reconciliation."}, {"term": "peace wall", "ipa": "/ˈpiːs wɔːl/", "pron": "peace wall", "fr": "mur de la paix", "def": "A barrier separating communities in parts of Northern Ireland.", "ex": "Peace walls still divide some Belfast communities."}, {"term": "interface area", "ipa": "/ˈɪntəfeɪs ˌeəriə/", "pron": "IN-tuh-fays AIR-ee-uh", "fr": "zone d’interface communautaire", "def": "An area where rival communities live next to each other and tensions may occur.", "ex": "Interface areas can be flashpoints during marching season."}, {"term": "marching season", "ipa": "/ˈmɑːtʃɪŋ ˌsiːzən/", "pron": "MAR-ching SEE-zuhn", "fr": "saison des marches orangistes", "def": "The period when loyalist and unionist parades take place, often politically sensitive.", "ex": "Marching season can increase community tensions."}, {"term": "Orange Order", "ipa": "/ˈɒrɪndʒ ˌɔːdə/", "pron": "OR-inj OR-duh", "fr": "Ordre d’Orange", "def": "A Protestant fraternal organisation associated with unionism and loyalist parades.", "ex": "The Orange Order is central to many unionist traditions."}, {"term": "parade", "ipa": "/pəˈreɪd/", "pron": "puh-RAYD", "fr": "défilé ; marche", "def": "A public march, often politically or culturally symbolic in Northern Ireland.", "ex": "Parades can become controversial when routes pass nationalist areas."}, {"term": "commemoration", "ipa": "/kəˌmeməˈreɪʃən/", "pron": "kuh-mem-uh-RAY-shuhn", "fr": "commémoration", "def": "An event remembering a person, group or historical event.", "ex": "Commemorations often reveal contested memories of the conflict."}, {"term": "contested memory", "ipa": "/kənˌtestɪd ˈmeməri/", "pron": "kuhn-TES-tid MEM-uh-ree", "fr": "mémoire contestée", "def": "Disagreement over how the past should be remembered.", "ex": "Northern Ireland is marked by contested memory."}]}, {"title": "B. The Troubles: conflict, policing and paramilitaries", "entries": [{"term": "the Troubles", "ipa": "/ðə ˈtrʌbəlz/", "pron": "thuh TRUB-uhlz", "fr": "les Troubles", "def": "The period of violent conflict in Northern Ireland, mainly from the late 1960s to 1998.", "ex": "The Troubles caused more than three thousand deaths."}, {"term": "civil rights movement", "ipa": "/ˌsɪvəl ˈraɪts ˌmuːvmənt/", "pron": "SIV-uhl rites MOOV-muhnt", "fr": "mouvement pour les droits civiques", "def": "A movement demanding equal rights, especially for Catholics in Northern Ireland in the 1960s.", "ex": "The civil rights movement challenged discrimination in housing and voting."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity, religion or community background.", "ex": "Discrimination against Catholics helped fuel unrest."}, {"term": "gerrymandering", "ipa": "/ˈdʒerimændərɪŋ/", "pron": "JERR-ee-man-duh-ring", "fr": "charcutage électoral", "def": "Manipulating electoral boundaries to favour one group or party.", "ex": "Gerrymandering was one of the grievances raised by civil rights activists."}, {"term": "policing", "ipa": "/pəˈliːsɪŋ/", "pron": "puh-LEE-sing", "fr": "maintien de l’ordre ; action policière", "def": "The work and methods of the police.", "ex": "Policing was deeply controversial during the Troubles."}, {"term": "Royal Ulster Constabulary", "ipa": "/ˌrɔɪəl ˈʌlstə kənˈstæbjʊləri/", "pron": "ROY-uhl UL-stuh kuhn-STAB-yuh-luh-ree", "fr": "Royal Ulster Constabulary ; RUC", "def": "The former police force in Northern Ireland, replaced by the PSNI.", "ex": "The Royal Ulster Constabulary was distrusted by many nationalists."}, {"term": "RUC", "ipa": "/ˌɑː juː ˈsiː/", "pron": "ar-yoo-see", "fr": "RUC", "def": "Abbreviation for Royal Ulster Constabulary.", "ex": "The RUC was reformed after the peace agreement."}, {"term": "Police Service of Northern Ireland", "ipa": "/pəˌliːs ˌsɜːvɪs əv ˌnɔːðən ˈaɪələnd/", "pron": "puh-LEESS SUR-vis ov NOR-thuhn EYE-uh-luhnd", "fr": "Police Service of Northern Ireland ; PSNI", "def": "The current police force in Northern Ireland.", "ex": "The PSNI was created as part of policing reform."}, {"term": "PSNI", "ipa": "/ˌpiː es en ˈaɪ/", "pron": "pee-ess-en-eye", "fr": "PSNI", "def": "Abbreviation for Police Service of Northern Ireland.", "ex": "The PSNI aims to be more representative and trusted."}, {"term": "British Army", "ipa": "/ˌbrɪtɪʃ ˈɑːmi/", "pron": "BRIT-ish AR-mee", "fr": "armée britannique", "def": "The UK’s army, deployed in Northern Ireland during the Troubles.", "ex": "The British Army’s role remains controversial in nationalist communities."}, {"term": "Operation Banner", "ipa": "/ˌɒpəˈreɪʃən ˈbænə/", "pron": "op-uh-RAY-shuhn BAN-uh", "fr": "Operation Banner", "def": "The British Army’s long deployment in Northern Ireland from 1969 to 2007.", "ex": "Operation Banner was the longest continuous deployment in British military history."}, {"term": "Bloody Sunday", "ipa": "/ˌblʌdi ˈsʌndeɪ/", "pron": "BLUD-ee SUN-day", "fr": "Bloody Sunday ; dimanche sanglant", "def": "The 1972 event in Derry/Londonderry when British soldiers shot civil rights marchers.", "ex": "Bloody Sunday became a symbol of injustice for many nationalists."}, {"term": "Derry/Londonderry", "ipa": "/ˈderi ˈlʌndənderi/", "pron": "DERR-ee LUN-duhn-derr-ee", "fr": "Derry/Londonderry", "def": "A city in Northern Ireland whose name is politically contested.", "ex": "The name Derry or Londonderry can signal political identity."}, {"term": "paramilitary group", "ipa": "/ˌpærəˈmɪlɪtəri ɡruːp/", "pron": "par-uh-MIL-i-tuh-ree group", "fr": "groupe paramilitaire", "def": "An armed organisation operating like a military force but outside the official army.", "ex": "Paramilitary groups were responsible for much of the violence."}, {"term": "IRA", "ipa": "/ˌaɪ ɑːr ˈeɪ/", "pron": "eye-ar-ay", "fr": "IRA ; Armée républicaine irlandaise", "def": "The Irish Republican Army, a republican paramilitary organisation seeking to end British rule in Northern Ireland.", "ex": "The IRA carried out bombings and shootings during the Troubles."}, {"term": "Provisional IRA", "ipa": "/prəˌvɪʒənəl ˌaɪ ɑːr ˈeɪ/", "pron": "pruh-VIZH-uh-nuhl eye-ar-ay", "fr": "IRA provisoire", "def": "The main republican paramilitary group during the Troubles.", "ex": "The Provisional IRA declared a ceasefire in the 1990s."}, {"term": "loyalist paramilitaries", "ipa": "/ˈlɔɪəlɪst ˌpærəˈmɪlɪtriz/", "pron": "LOY-uh-list par-uh-MIL-i-treez", "fr": "paramilitaires loyalistes", "def": "Armed groups supporting the Union and opposing Irish republicanism.", "ex": "Loyalist paramilitaries targeted Catholic civilians and republicans."}, {"term": "UVF", "ipa": "/ˌjuː viː ˈef/", "pron": "yoo-vee-eff", "fr": "UVF ; Ulster Volunteer Force", "def": "Ulster Volunteer Force, a loyalist paramilitary organisation.", "ex": "The UVF was one of the main loyalist paramilitary groups."}, {"term": "UDA", "ipa": "/ˌjuː diː ˈeɪ/", "pron": "yoo-dee-ay", "fr": "UDA ; Ulster Defence Association", "def": "Ulster Defence Association, a loyalist paramilitary organisation.", "ex": "The UDA was linked to sectarian violence."}, {"term": "ceasefire", "ipa": "/ˈsiːsfaɪə/", "pron": "SEESS-fire", "fr": "cessez-le-feu", "def": "An agreement or announcement to stop fighting.", "ex": "Ceasefires paved the way for peace negotiations."}, {"term": "peace process", "ipa": "/ˈpiːs ˌprəʊses/", "pron": "peace PROH-sess", "fr": "processus de paix", "def": "The political process that led to the end of most violence and the creation of new institutions.", "ex": "The peace process required compromise from all sides."}, {"term": "Good Friday Agreement", "ipa": "/ˌɡʊd ˈfraɪdeɪ əˈɡriːmənt/", "pron": "good FRY-day uh-GREE-muhnt", "fr": "Accord du Vendredi saint", "def": "The 1998 peace agreement that created power-sharing and recognised consent principles.", "ex": "The Good Friday Agreement is the cornerstone of peace in Northern Ireland."}, {"term": "Belfast Agreement", "ipa": "/ˌbelfɑːst əˈɡriːmənt/", "pron": "BEL-fast uh-GREE-muhnt", "fr": "Accord de Belfast", "def": "Another name for the Good Friday Agreement.", "ex": "The Belfast Agreement created a framework for shared government."}, {"term": "principle of consent", "ipa": "/ˌprɪnsəpəl əv kənˈsent/", "pron": "PRIN-suh-puhl ov kuhn-SENT", "fr": "principe de consentement", "def": "The idea that Northern Ireland’s status cannot change without majority consent.", "ex": "The principle of consent reassured unionists after the peace agreement."}]}, {"title": "C. Peace process, Stormont and political parties", "entries": [{"term": "power-sharing", "ipa": "/ˈpaʊə ˌʃeərɪŋ/", "pron": "POW-uh shair-ing", "fr": "partage du pouvoir", "def": "A system in which rival communities share government power.", "ex": "Power-sharing is designed to prevent domination by one community."}, {"term": "cross-community support", "ipa": "/ˌkrɒs kəˈmjuːnəti səˈpɔːt/", "pron": "kross kuh-MYOO-nuh-tee suh-PORT", "fr": "soutien intercommunautaire", "def": "Support from both unionist and nationalist representatives.", "ex": "Important decisions often require cross-community support."}, {"term": "Northern Ireland Assembly", "ipa": "/ˌnɔːðən ˈaɪələnd əˈsembli/", "pron": "NOR-thuhn EYE-uh-luhnd uh-SEM-blee", "fr": "Assemblée d’Irlande du Nord", "def": "The devolved legislature created by the peace process.", "ex": "The Northern Ireland Assembly sits at Stormont."}, {"term": "Stormont", "ipa": "/ˈstɔːmənt/", "pron": "STOR-muhnt", "fr": "Stormont ; institutions nord-irlandaises", "def": "The Northern Ireland Assembly and Executive, named after the estate near Belfast.", "ex": "Stormont has repeatedly collapsed during political crises."}, {"term": "Northern Ireland Executive", "ipa": "/ˌnɔːðən ˈaɪələnd ɪɡˈzekjʊtɪv/", "pron": "NOR-thuhn EYE-uh-luhnd ig-ZEK-yuh-tiv", "fr": "Exécutif d’Irlande du Nord", "def": "The devolved power-sharing government of Northern Ireland.", "ex": "The Northern Ireland Executive includes unionist and nationalist parties."}, {"term": "First Minister", "ipa": "/ˌfɜːst ˈmɪnɪstə/", "pron": "first MIN-i-stuh", "fr": "Premier ministre d’Irlande du Nord", "def": "One of the joint heads of Northern Ireland’s Executive.", "ex": "The First Minister shares power with the deputy First Minister."}, {"term": "deputy First Minister", "ipa": "/ˌdepjʊti ˌfɜːst ˈmɪnɪstə/", "pron": "DEP-yuh-tee first MIN-i-stuh", "fr": "vice-Premier ministre d’Irlande du Nord", "def": "The joint head of government alongside the First Minister.", "ex": "The deputy First Minister has equal power to the First Minister."}, {"term": "mandatory coalition", "ipa": "/ˌmændətəri ˌkəʊəˈlɪʃən/", "pron": "MAN-duh-tuh-ree koh-uh-LISH-uhn", "fr": "coalition obligatoire", "def": "A coalition government required by institutional rules, including major parties from different communities.", "ex": "Northern Ireland uses mandatory coalition to share power."}, {"term": "DUP", "ipa": "/ˌdiː juː ˈpiː/", "pron": "dee-yoo-pee", "fr": "DUP ; Parti unioniste démocrate", "def": "The Democratic Unionist Party, a major unionist party.", "ex": "The DUP opposed aspects of the Northern Ireland Protocol."}, {"term": "Sinn Féin", "ipa": "/ˌʃɪn ˈfeɪn/", "pron": "shin FAYN", "fr": "Sinn Féin", "def": "A major Irish republican and nationalist party.", "ex": "Sinn Féin supports Irish unity."}, {"term": "Alliance Party", "ipa": "/əˈlaɪəns ˈpɑːti/", "pron": "uh-LY-uhns PAR-tee", "fr": "Alliance Party ; Parti de l’Alliance", "def": "A cross-community party that does not identify as unionist or nationalist.", "ex": "The Alliance Party has grown as more voters reject traditional labels."}, {"term": "SDLP", "ipa": "/ˌes diː el ˈpiː/", "pron": "ess-dee-el-pee", "fr": "SDLP ; Parti social-démocrate et travailliste", "def": "The Social Democratic and Labour Party, a nationalist party.", "ex": "The SDLP played an important role in the peace process."}, {"term": "Ulster Unionist Party", "ipa": "/ˌʌlstə ˈjuːniənɪst ˈpɑːti/", "pron": "UL-stuh YOO-nee-uhn-ist PAR-tee", "fr": "Parti unioniste d’Ulster", "def": "A traditional unionist party in Northern Ireland.", "ex": "The Ulster Unionist Party supported the Good Friday Agreement."}, {"term": "UUP", "ipa": "/ˌjuː juː ˈpiː/", "pron": "yoo-yoo-pee", "fr": "UUP", "def": "Abbreviation for Ulster Unionist Party.", "ex": "The UUP was once the dominant unionist party."}, {"term": "legacy issue", "ipa": "/ˈleɡəsi ˌɪʃuː/", "pron": "LEG-uh-see ISH-oo", "fr": "question héritée du conflit", "def": "An unresolved issue from the Troubles, especially justice and accountability for past violence.", "ex": "Legacy issues remain deeply sensitive."}, {"term": "victim", "ipa": "/ˈvɪktɪm/", "pron": "VIK-tim", "fr": "victime", "def": "A person harmed, injured or killed by violence or injustice.", "ex": "Victims’ families continue to seek truth and justice."}, {"term": "reconciliation", "ipa": "/ˌrekənsɪliˈeɪʃən/", "pron": "rek-uhn-sil-ee-AY-shuhn", "fr": "réconciliation", "def": "The process of rebuilding trust after conflict.", "ex": "Reconciliation remains difficult when memories of violence are still raw."}, {"term": "truth recovery", "ipa": "/ˈtruːθ rɪˌkʌvəri/", "pron": "trooth ri-KUV-uh-ree", "fr": "recherche de la vérité", "def": "Efforts to establish the truth about past violence or abuses.", "ex": "Truth recovery is important for victims’ families."}, {"term": "amnesty", "ipa": "/ˈæmnəsti/", "pron": "AM-nuh-stee", "fr": "amnistie", "def": "A policy forgiving past crimes or preventing prosecution.", "ex": "Proposed amnesties for Troubles-era crimes have been controversial."}]}, {"title": "D. Legacy issues, Brexit and the Protocol", "entries": [{"term": "justice campaign", "ipa": "/ˈdʒʌstɪs kæmˌpeɪn/", "pron": "JUS-tis kam-PAYN", "fr": "campagne pour la justice", "def": "A campaign demanding accountability for past wrongdoing.", "ex": "Justice campaigns keep legacy issues in the public eye."}, {"term": "Brexit", "ipa": "/ˈbreksɪt/", "pron": "BREK-sit", "fr": "Brexit", "def": "The UK’s withdrawal from the European Union.", "ex": "Brexit destabilised Northern Ireland’s political settlement."}, {"term": "Northern Ireland Protocol", "ipa": "/ˌnɔːðən ˈaɪələnd ˈprəʊtəkɒl/", "pron": "NOR-thuhn EYE-uh-luhnd PROH-tuh-kol", "fr": "protocole sur l’Irlande du Nord", "def": "The post-Brexit arrangement keeping Northern Ireland aligned with some EU rules to avoid a hard border.", "ex": "The Northern Ireland Protocol created checks in the Irish Sea."}, {"term": "Irish Sea border", "ipa": "/ˌaɪrɪʃ siː ˈbɔːdə/", "pron": "EYE-rish see BOR-duh", "fr": "frontière en mer d’Irlande", "def": "A term for checks between Great Britain and Northern Ireland after Brexit.", "ex": "Unionists saw the Irish Sea border as weakening Northern Ireland’s place in the UK."}, {"term": "Windsor Framework", "ipa": "/ˌwɪnzə ˈfreɪmwɜːk/", "pron": "WIN-zuh FRAME-wurk", "fr": "cadre de Windsor", "def": "The 2023 UK-EU agreement modifying the Northern Ireland Protocol.", "ex": "The Windsor Framework aimed to reduce trade frictions."}, {"term": "green lane", "ipa": "/ˌɡriːn ˈleɪn/", "pron": "green lane", "fr": "voie verte", "def": "A simplified route for goods moving from Great Britain to Northern Ireland and staying there.", "ex": "The green lane was designed to reduce checks on internal UK trade."}, {"term": "red lane", "ipa": "/ˌred ˈleɪn/", "pron": "red lane", "fr": "voie rouge", "def": "A route for goods at risk of entering the EU single market and therefore requiring more checks.", "ex": "Goods entering the Republic of Ireland use the red lane."}, {"term": "EU single market", "ipa": "/ˌiː juː ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "ee-yoo SING-guhl MAR-kit", "fr": "marché unique européen", "def": "The EU area allowing free movement of goods, services, capital and people.", "ex": "Northern Ireland kept partial access to the EU single market for goods."}, {"term": "customs checks", "ipa": "/ˈkʌstəmz tʃeks/", "pron": "KUS-tuhmz cheks", "fr": "contrôles douaniers", "def": "Inspections or paperwork required for goods crossing customs boundaries.", "ex": "Customs checks became controversial after Brexit."}, {"term": "trade friction", "ipa": "/ˈtreɪd ˌfrɪkʃən/", "pron": "trade FRIK-shuhn", "fr": "friction commerciale", "def": "Extra cost, paperwork or delay in trade.", "ex": "The Protocol created trade friction between Great Britain and Northern Ireland."}, {"term": "constitutional status", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈsteɪtəs/", "pron": "kon-sti-TOO-shuh-nuhl STAY-tuhs", "fr": "statut constitutionnel", "def": "A territory’s legal and political position within or outside a state.", "ex": "Northern Ireland’s constitutional status depends on consent."}, {"term": "border poll", "ipa": "/ˈbɔːdə pəʊl/", "pron": "BOR-duh pohl", "fr": "référendum sur l’unification irlandaise", "def": "A referendum on whether Northern Ireland should remain in the UK or join a united Ireland.", "ex": "Brexit increased discussion of a future border poll."}, {"term": "demographic change", "ipa": "/ˌdeməɡræfɪk ˈtʃeɪndʒ/", "pron": "dem-uh-GRAF-ik chaynj", "fr": "changement démographique", "def": "Changes in the composition of a population.", "ex": "Demographic change has affected debates about Irish unity."}, {"term": "middle ground", "ipa": "/ˌmɪdəl ˈɡraʊnd/", "pron": "MID-uhl ground", "fr": "terrain d’entente ; centre modéré", "def": "A moderate or non-aligned political position between opposing sides.", "ex": "The Alliance Party appeals to voters in the middle ground."}, {"term": "shared future", "ipa": "/ˌʃeəd ˈfjuːtʃə/", "pron": "shaird FYOO-chuh", "fr": "avenir partagé", "def": "A political vision of different communities living together peacefully.", "ex": "Many civic groups promote a shared future beyond sectarian labels."}, {"term": "normalisation", "ipa": "/ˌnɔːməlaɪˈzeɪʃən/", "pron": "NOR-muh-ly-ZAY-shuhn", "fr": "normalisation", "def": "The process of making political and social life more normal after conflict.", "ex": "Normalisation has been uneven since the peace agreement."}, {"term": "to remain part of the UK", "ipa": "/rɪˈmeɪn pɑːt əv ðə ˌjuː ˈkeɪ/", "pron": "ri-MAYN part ov thuh yoo-kay", "fr": "rester dans le Royaume-Uni", "def": "To continue belonging to the United Kingdom.", "ex": "Unionists want Northern Ireland to remain part of the UK."}, {"term": "to join a united Ireland", "ipa": "/dʒɔɪn ə juːˌnaɪtɪd ˈaɪələnd/", "pron": "joyn uh yoo-NY-tid EYE-uh-luhnd", "fr": "rejoindre une Irlande unifiée", "def": "To become part of a single Irish state.", "ex": "Nationalists want Northern Ireland to join a united Ireland."}, {"term": "to share power", "ipa": "/ʃeə ˈpaʊə/", "pron": "shair POW-uh", "fr": "partager le pouvoir", "def": "To divide political authority between rival groups.", "ex": "Unionists and nationalists are required to share power."}, {"term": "to collapse Stormont", "ipa": "/kəˈlæps ˈstɔːmənt/", "pron": "kuh-LAPS STOR-muhnt", "fr": "faire tomber Stormont", "def": "To cause the devolved institutions to stop functioning.", "ex": "Political disputes can collapse Stormont."}]}, {"title": "E. Future of Northern Ireland and high-value verbs", "entries": [{"term": "to restore devolution", "ipa": "/rɪˈstɔː ˌdiːvəˈluːʃən/", "pron": "ri-STORE dee-vuh-LOO-shuhn", "fr": "rétablir la dévolution", "def": "To bring devolved government back after suspension or collapse.", "ex": "Talks aimed to restore devolution after a long deadlock."}, {"term": "to avoid a hard border", "ipa": "/əˈvɔɪd ə ˌhɑːd ˈbɔːdə/", "pron": "uh-VOID uh hard BOR-duh", "fr": "éviter une frontière dure", "def": "To prevent the return of physical border checks or infrastructure.", "ex": "The Protocol was designed to avoid a hard border."}, {"term": "to preserve the peace process", "ipa": "/prɪˈzɜːv ðə ˈpiːs ˌprəʊses/", "pron": "pri-ZURV thuh peace PROH-sess", "fr": "préserver le processus de paix", "def": "To protect the institutions and trust created by peace negotiations.", "ex": "Brexit negotiators claimed they wanted to preserve the peace process."}, {"term": "to fuel sectarian tensions", "ipa": "/ˈfjuːəl sekˌteəriən ˈtenʃənz/", "pron": "FYOO-uhl sek-TAIR-ee-uhn TEN-shuhnz", "fr": "alimenter les tensions communautaires", "def": "To intensify tensions between communities.", "ex": "Provocative rhetoric can fuel sectarian tensions."}, {"term": "to seek reconciliation", "ipa": "/siːk ˌrekənsɪliˈeɪʃən/", "pron": "seek rek-uhn-sil-ee-AY-shuhn", "fr": "rechercher la réconciliation", "def": "To try to rebuild relationships after conflict.", "ex": "Victims’ groups and civic leaders continue to seek reconciliation."}, {"term": "to confront the past", "ipa": "/kənˈfrʌnt ðə pɑːst/", "pron": "kuhn-FRUNT thuh past", "fr": "affronter le passé", "def": "To face and examine painful historical events honestly.", "ex": "Northern Ireland still struggles to confront the past."}, {"term": "to destabilise the settlement", "ipa": "/diːˈsteɪbəlaɪz ðə ˈsetəlmənt/", "pron": "dee-STAY-buh-lyz thuh SET-uhl-muhnt", "fr": "déstabiliser l’accord politique", "def": "To weaken or unsettle the political agreement that supports peace.", "ex": "Brexit risked destabilising the settlement."}]}]}, {"id": "p4c29", "part": 4, "chapter": 29, "title": "Education", "file": "cpge_vocab_part4_chapter29_education_premium.html", "count": 130, "sections": [{"title": "A. School systems and types of institutions", "entries": [{"term": "education", "ipa": "/ˌedjʊˈkeɪʃən/", "pron": "ej-yoo-KAY-shuhn", "fr": "éducation ; enseignement", "def": "The process of teaching, learning and developing knowledge, skills and values.", "ex": "Education is often presented as the key to social mobility."}, {"term": "schooling", "ipa": "/ˈskuːlɪŋ/", "pron": "SKOO-ling", "fr": "scolarisation", "def": "Formal education received at school.", "ex": "Schooling is compulsory for children in Britain and the United States."}, {"term": "state education", "ipa": "/ˌsteɪt ˌedjʊˈkeɪʃən/", "pron": "state ej-yoo-KAY-shuhn", "fr": "enseignement public", "def": "Education provided or funded by the government.", "ex": "State education is supposed to provide equal opportunity."}, {"term": "public education", "ipa": "/ˌpʌblɪk ˌedjʊˈkeɪʃən/", "pron": "PUB-lik ej-yoo-KAY-shuhn", "fr": "enseignement public", "def": "Government-funded education; in the US, this means state schools.", "ex": "Public education is central to democratic citizenship."}, {"term": "state school", "ipa": "/ˈsteɪt skuːl/", "pron": "state school", "fr": "école publique britannique", "def": "In Britain, a school funded by the government and free to attend.", "ex": "Most British children attend state schools."}, {"term": "public school", "ipa": "/ˌpʌblɪk ˈskuːl/", "pron": "PUB-lik school", "fr": "école privée prestigieuse britannique ; école publique américaine", "def": "In Britain, an expensive private school; in the US, a government-funded school.", "ex": "The term public school means very different things in Britain and the United States."}, {"term": "private school", "ipa": "/ˌpraɪvət ˈskuːl/", "pron": "PRY-vuht school", "fr": "école privée", "def": "A fee-paying school not funded by the state.", "ex": "Private schools often benefit from smaller classes and extensive resources."}, {"term": "independent school", "ipa": "/ˌɪndɪˈpendənt skuːl/", "pron": "in-di-PEN-duhnt school", "fr": "école indépendante ; école privée", "def": "A British private school funded mainly by fees rather than the state.", "ex": "Independent schools educate a small but influential minority."}, {"term": "fee-paying school", "ipa": "/ˈfiː peɪɪŋ skuːl/", "pron": "fee-PAY-ing school", "fr": "école payante", "def": "A school for which families pay tuition fees.", "ex": "Fee-paying schools raise questions about privilege."}, {"term": "boarding school", "ipa": "/ˈbɔːdɪŋ skuːl/", "pron": "BOR-ding school", "fr": "internat", "def": "A school where pupils live during term time.", "ex": "Boarding schools are often associated with Britain’s elite."}, {"term": "grammar school", "ipa": "/ˈɡræmə skuːl/", "pron": "GRAM-uh school", "fr": "grammar school ; lycée sélectif public", "def": "A selective state school in Britain admitting pupils based on academic ability.", "ex": "Grammar schools remain controversial because they select pupils at a young age."}, {"term": "comprehensive school", "ipa": "/ˌkɒmprɪˈhensɪv skuːl/", "pron": "kom-pri-HEN-siv school", "fr": "établissement secondaire public non sélectif", "def": "A non-selective state secondary school for pupils of all abilities.", "ex": "Comprehensive schools were designed to reduce class barriers."}, {"term": "academy", "ipa": "/əˈkædəmi/", "pron": "uh-KAD-uh-mee", "fr": "academy ; école publique autonome", "def": "In England, a state-funded school with greater independence from local authority control.", "ex": "Academies have more freedom over budgets and curriculum."}, {"term": "free school", "ipa": "/ˈfriː skuːl/", "pron": "free school", "fr": "free school ; école publique autonome", "def": "In England, a state-funded school set up by groups such as parents, charities or trusts.", "ex": "Free schools were promoted as a way to increase choice."}, {"term": "faith school", "ipa": "/ˈfeɪθ skuːl/", "pron": "faith school", "fr": "école confessionnelle", "def": "A school linked to a religious group or tradition.", "ex": "Faith schools raise debates about religion and social cohesion."}, {"term": "single-sex school", "ipa": "/ˌsɪŋɡəl seks ˈskuːl/", "pron": "SING-guhl seks school", "fr": "école non mixte", "def": "A school for either boys or girls only.", "ex": "Single-sex schools are sometimes defended as improving confidence."}, {"term": "co-educational school", "ipa": "/ˌkəʊ edjʊˈkeɪʃənəl skuːl/", "pron": "koh ej-yoo-KAY-shuh-nuhl school", "fr": "école mixte", "def": "A school for both boys and girls.", "ex": "Most modern schools are co-educational."}, {"term": "nursery school", "ipa": "/ˈnɜːsəri skuːl/", "pron": "NUR-suh-ree school", "fr": "école maternelle ; crèche éducative", "def": "A school or setting for very young children before primary school.", "ex": "Early nursery education can improve later outcomes."}, {"term": "primary school", "ipa": "/ˈpraɪməri skuːl/", "pron": "PRY-muh-ree school", "fr": "école primaire", "def": "A school for younger children, before secondary education.", "ex": "Primary school builds the foundations of literacy and numeracy."}, {"term": "secondary school", "ipa": "/ˈsekəndəri skuːl/", "pron": "SEK-uhn-duh-ree school", "fr": "collège/lycée ; établissement secondaire", "def": "A school for older children and teenagers.", "ex": "Secondary school prepares pupils for exams and further study."}, {"term": "sixth form", "ipa": "/ˈsɪksθ fɔːm/", "pron": "sixth form", "fr": "sixth form ; classes de 16 à 18 ans", "def": "The final two years of secondary education in England, usually for ages 16 to 18.", "ex": "Students often take A-levels in sixth form."}, {"term": "college", "ipa": "/ˈkɒlɪdʒ/", "pron": "KOL-ij", "fr": "college ; établissement post-16 ou université selon contexte", "def": "In Britain, often a post-16 or vocational institution; in the US, a university-level institution.", "ex": "The word college has different meanings in Britain and America."}, {"term": "university", "ipa": "/ˌjuːnɪˈvɜːsəti/", "pron": "yoo-ni-VUR-suh-tee", "fr": "université", "def": "An institution offering higher education and degrees.", "ex": "University is often seen as a route to better employment."}, {"term": "higher education", "ipa": "/ˌhaɪər ˌedjʊˈkeɪʃən/", "pron": "HY-uhr ej-yoo-KAY-shuhn", "fr": "enseignement supérieur", "def": "Education at university or equivalent level.", "ex": "Higher education has expanded dramatically in recent decades."}, {"term": "further education", "ipa": "/ˌfɜːðər ˌedjʊˈkeɪʃən/", "pron": "FUR-thuh ej-yoo-KAY-shuhn", "fr": "formation post-secondaire ; further education", "def": "Education after compulsory schooling but below or outside university level.", "ex": "Further education colleges provide vocational and academic courses."}, {"term": "vocational education", "ipa": "/vəʊˌkeɪʃənəl ˌedjʊˈkeɪʃən/", "pron": "voh-KAY-shuh-nuhl ej-yoo-KAY-shuhn", "fr": "enseignement professionnel", "def": "Education focused on practical skills and specific jobs.", "ex": "Vocational education is crucial for technical careers."}, {"term": "technical education", "ipa": "/ˈteknɪkəl ˌedjʊˈkeɪʃən/", "pron": "TEK-ni-kuhl ej-yoo-KAY-shuhn", "fr": "enseignement technique", "def": "Education focused on technical knowledge and applied skills.", "ex": "Technical education can help address skills shortages."}, {"term": "apprenticeship", "ipa": "/əˈprentɪsʃɪp/", "pron": "uh-PREN-tis-ship", "fr": "apprentissage", "def": "A programme combining paid work with training.", "ex": "Apprenticeships offer an alternative to university."}, {"term": "degree", "ipa": "/dɪˈɡriː/", "pron": "di-GREE", "fr": "diplôme universitaire", "def": "A qualification awarded by a university or college.", "ex": "A degree can improve job prospects but may also create debt."}, {"term": "undergraduate", "ipa": "/ˌʌndəˈɡrædʒuət/", "pron": "UN-duh-GRAJ-oo-uht", "fr": "étudiant de licence ; undergraduate", "def": "A student studying for a first university degree.", "ex": "Undergraduates often pay tuition fees."}, {"term": "postgraduate", "ipa": "/ˌpəʊstˈɡrædʒuət/", "pron": "post-GRAJ-oo-uht", "fr": "étudiant de master/doctorat ; postgraduate", "def": "A student studying after a first degree.", "ex": "Postgraduate study can be expensive."}, {"term": "tuition fees", "ipa": "/tjuːˈɪʃən fiːz/", "pron": "tyoo-ISH-uhn feez", "fr": "frais de scolarité", "def": "Money paid for teaching, especially at university or private school.", "ex": "Tuition fees have made higher education more financially risky."}, {"term": "student debt", "ipa": "/ˈstjuːdənt det/", "pron": "STYOO-duhnt det", "fr": "dette étudiante", "def": "Money borrowed to pay for education.", "ex": "Student debt can delay home ownership and family formation."}, {"term": "student loan", "ipa": "/ˈstjuːdənt ləʊn/", "pron": "STYOO-duhnt lohn", "fr": "prêt étudiant", "def": "Money borrowed by a student to pay for education and living costs.", "ex": "Many graduates repay student loans for years."}, {"term": "grant", "ipa": "/ɡrɑːnt/", "pron": "grant", "fr": "bourse ; subvention", "def": "Money given to support study, research or institutions, usually not repaid.", "ex": "Grants can make education more accessible."}, {"term": "scholarship", "ipa": "/ˈskɒləʃɪp/", "pron": "SKOL-uh-ship", "fr": "bourse d’études", "def": "Financial support awarded to a student, often based on merit or need.", "ex": "Scholarships help talented students from poorer backgrounds."}, {"term": "bursary", "ipa": "/ˈbɜːsəri/", "pron": "BUR-suh-ree", "fr": "bourse d’aide sociale", "def": "Financial support for students, often based on need.", "ex": "Bursaries can reduce barriers to higher education."}, {"term": "curriculum", "ipa": "/kəˈrɪkjʊləm/", "pron": "kuh-RIK-yuh-luhm", "fr": "programme scolaire", "def": "The subjects and content taught in a school or course.", "ex": "The curriculum often becomes a political battleground."}]}, {"title": "B. Curriculum, learning methods and assessment", "entries": [{"term": "national curriculum", "ipa": "/ˌnæʃənəl kəˈrɪkjʊləm/", "pron": "NASH-uh-nuhl kuh-RIK-yuh-luhm", "fr": "programme national", "def": "The official set of subjects and standards taught in state schools.", "ex": "The national curriculum defines what pupils are expected to learn."}, {"term": "syllabus", "ipa": "/ˈsɪləbəs/", "pron": "SIL-uh-buhs", "fr": "programme de cours ; syllabus", "def": "The detailed content of a course or exam.", "ex": "The syllabus lists the texts and topics for the exam."}, {"term": "core subject", "ipa": "/ˌkɔː ˈsʌbdʒɪkt/", "pron": "core SUB-jikt", "fr": "matière fondamentale", "def": "A central compulsory subject, such as English, maths or science.", "ex": "Maths and English are core subjects."}, {"term": "STEM", "ipa": "/stem/", "pron": "stem", "fr": "STEM ; sciences, technologie, ingénierie et mathématiques", "def": "Science, technology, engineering and mathematics.", "ex": "Governments often promote STEM to improve competitiveness."}, {"term": "humanities", "ipa": "/hjuːˈmænətiz/", "pron": "hyoo-MAN-uh-teez", "fr": "sciences humaines", "def": "Subjects such as history, literature, philosophy and languages.", "ex": "The humanities help students think critically about society."}, {"term": "literacy", "ipa": "/ˈlɪtərəsi/", "pron": "LIT-uh-ruh-see", "fr": "maîtrise de la lecture et de l’écriture", "def": "The ability to read and write effectively.", "ex": "Literacy is a foundation for educational success."}, {"term": "numeracy", "ipa": "/ˈnjuːmərəsi/", "pron": "NYOO-muh-ruh-see", "fr": "maîtrise du calcul", "def": "The ability to use numbers and basic mathematics effectively.", "ex": "Numeracy matters in everyday life and employment."}, {"term": "critical thinking", "ipa": "/ˌkrɪtɪkəl ˈθɪŋkɪŋ/", "pron": "KRIT-i-kuhl THINK-ing", "fr": "esprit critique", "def": "The ability to analyse information carefully and judge arguments.", "ex": "Critical thinking is essential in the age of misinformation."}, {"term": "rote learning", "ipa": "/ˌrəʊt ˈlɜːnɪŋ/", "pron": "roht LUR-ning", "fr": "apprentissage par cœur", "def": "Learning by repetition and memorisation, often without deep understanding.", "ex": "Critics argue that excessive testing encourages rote learning."}, {"term": "active learning", "ipa": "/ˌæktɪv ˈlɜːnɪŋ/", "pron": "AK-tiv LUR-ning", "fr": "apprentissage actif", "def": "Learning through participation, problem-solving and discussion.", "ex": "Active learning can improve engagement."}, {"term": "blended learning", "ipa": "/ˌblendɪd ˈlɜːnɪŋ/", "pron": "BLEN-did LUR-ning", "fr": "apprentissage hybride", "def": "A mix of online and face-to-face learning.", "ex": "Blended learning expanded after the pandemic."}, {"term": "remote learning", "ipa": "/rɪˌməʊt ˈlɜːnɪŋ/", "pron": "ri-MOHT LUR-ning", "fr": "enseignement à distance", "def": "Learning from home or another location using digital tools.", "ex": "Remote learning exposed inequalities in access to technology."}, {"term": "online learning", "ipa": "/ˌɒnlaɪn ˈlɜːnɪŋ/", "pron": "ON-lyne LUR-ning", "fr": "apprentissage en ligne", "def": "Learning delivered through the internet.", "ex": "Online learning can be flexible but isolating."}, {"term": "assessment", "ipa": "/əˈsesmənt/", "pron": "uh-SESS-muhnt", "fr": "évaluation", "def": "The process of evaluating learning or performance.", "ex": "Assessment can be formative or summative."}, {"term": "exam", "ipa": "/ɪɡˈzæm/", "pron": "ig-ZAM", "fr": "examen", "def": "A formal test of knowledge or skills.", "ex": "High-stakes exams can put pressure on pupils."}, {"term": "standardised test", "ipa": "/ˈstændədaɪzd test/", "pron": "STAN-duh-dyzd test", "fr": "test standardisé", "def": "A test administered and scored in the same way for all candidates.", "ex": "Standardised tests are often criticised for narrowing the curriculum."}, {"term": "high-stakes testing", "ipa": "/ˌhaɪ steɪks ˈtestɪŋ/", "pron": "hy-stayks TEST-ing", "fr": "évaluation à forts enjeux", "def": "Testing with important consequences for pupils, teachers or schools.", "ex": "High-stakes testing can distort teaching priorities."}, {"term": "grade", "ipa": "/ɡreɪd/", "pron": "grayd", "fr": "note ; niveau", "def": "A mark or level awarded for schoolwork or an exam.", "ex": "Grades influence access to higher education."}, {"term": "GCSE", "ipa": "/ˌdʒiː siː es ˈiː/", "pron": "jee-see-ess-ee", "fr": "GCSE ; examens de fin de secondaire inférieur", "def": "Exams usually taken in England, Wales and Northern Ireland around age 16.", "ex": "GCSE results affect future study options."}, {"term": "A-level", "ipa": "/ˈeɪ levəl/", "pron": "AY-level", "fr": "A-level ; examen de fin de secondaire", "def": "Advanced exams usually taken in England, Wales and Northern Ireland around age 18.", "ex": "A-levels are used for university admissions."}, {"term": "SAT", "ipa": "/ˌes eɪ ˈtiː/", "pron": "ess-ay-tee", "fr": "SAT ; test d’entrée universitaire américain", "def": "A standardised test used in US college admissions.", "ex": "The SAT has become optional at many US colleges."}, {"term": "GPA", "ipa": "/ˌdʒiː piː ˈeɪ/", "pron": "jee-pee-ay", "fr": "moyenne générale américaine", "def": "Grade point average, a measure of academic performance in the US.", "ex": "A high GPA can improve college applications."}, {"term": "league table", "ipa": "/ˈliːɡ ˌteɪbəl/", "pron": "leeg TAY-buhl", "fr": "classement", "def": "A ranking of schools or universities by performance.", "ex": "School league tables can shape parental choice."}, {"term": "school inspection", "ipa": "/ˈskuːl ɪnˌspekʃən/", "pron": "school in-SPEK-shuhn", "fr": "inspection scolaire", "def": "An official evaluation of a school’s quality.", "ex": "School inspections can affect reputation and funding."}, {"term": "Ofsted", "ipa": "/ˈɒfsted/", "pron": "OF-sted", "fr": "Ofsted ; organisme d’inspection scolaire anglais", "def": "The body inspecting schools and children’s services in England.", "ex": "Ofsted ratings are highly influential in England."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "The obligation to justify performance or decisions.", "ex": "Accountability systems can improve standards but also create pressure."}, {"term": "school funding", "ipa": "/ˈskuːl ˌfʌndɪŋ/", "pron": "school FUN-ding", "fr": "financement des écoles", "def": "Money available to schools from government, fees or other sources.", "ex": "Unequal school funding affects educational outcomes."}, {"term": "funding gap", "ipa": "/ˈfʌndɪŋ ɡæp/", "pron": "FUN-ding gap", "fr": "écart de financement", "def": "A difference in financial resources between schools or areas.", "ex": "The funding gap widens educational inequality."}, {"term": "underfunded school", "ipa": "/ˌʌndəˈfʌndɪd skuːl/", "pron": "UN-duh-FUN-did school", "fr": "école sous-financée", "def": "A school with insufficient money or resources.", "ex": "Underfunded schools struggle to recruit teachers."}, {"term": "overcrowded classroom", "ipa": "/ˌəʊvəˌkraʊdɪd ˈklɑːsruːm/", "pron": "OH-vuh-KROW-did KLASS-room", "fr": "classe surchargée", "def": "A classroom with too many pupils for effective teaching.", "ex": "Overcrowded classrooms make individual support harder."}]}, {"title": "C. Funding, teachers, inclusion and inequality", "entries": [{"term": "teacher shortage", "ipa": "/ˈtiːtʃə ˌʃɔːtɪdʒ/", "pron": "TEE-chuh SHOR-tij", "fr": "pénurie d’enseignants", "def": "A lack of enough qualified teachers.", "ex": "Teacher shortages are severe in some subjects."}, {"term": "teacher retention", "ipa": "/ˈtiːtʃə rɪˌtenʃən/", "pron": "TEE-chuh ri-TEN-shuhn", "fr": "maintien des enseignants dans le métier", "def": "The ability to keep teachers in the profession.", "ex": "Workload affects teacher retention."}, {"term": "workload", "ipa": "/ˈwɜːkləʊd/", "pron": "WURK-lohd", "fr": "charge de travail", "def": "The amount of work someone has to do.", "ex": "Teacher workload is a major cause of burnout."}, {"term": "burnout", "ipa": "/ˈbɜːnaʊt/", "pron": "BURN-owt", "fr": "épuisement professionnel", "def": "Exhaustion caused by long-term stress and overwork.", "ex": "Teacher burnout threatens the quality of education."}, {"term": "special educational needs", "ipa": "/ˌspeʃəl ˌedjʊˈkeɪʃənəl niːdz/", "pron": "SPESH-uhl ej-yoo-KAY-shuh-nuhl needz", "fr": "besoins éducatifs particuliers", "def": "Learning or support needs requiring additional help in education.", "ex": "Pupils with special educational needs often need tailored support."}, {"term": "SEN", "ipa": "/ˌes iː ˈen/", "pron": "ess-ee-en", "fr": "BEP ; besoins éducatifs particuliers", "def": "Abbreviation for special educational needs.", "ex": "SEN provision is under pressure in many schools."}, {"term": "inclusive education", "ipa": "/ɪnˌkluːsɪv ˌedjʊˈkeɪʃən/", "pron": "in-KLOO-siv ej-yoo-KAY-shuhn", "fr": "éducation inclusive", "def": "Education designed to include all learners, regardless of need or background.", "ex": "Inclusive education requires resources and training."}, {"term": "disability support", "ipa": "/ˌdɪsəˈbɪləti səˈpɔːt/", "pron": "dis-uh-BIL-uh-tee suh-PORT", "fr": "accompagnement du handicap", "def": "Assistance provided to students with disabilities.", "ex": "Disability support is essential for equal access."}, {"term": "achievement gap", "ipa": "/əˈtʃiːvmənt ɡæp/", "pron": "uh-CHEEV-muhnt gap", "fr": "écart de réussite scolaire", "def": "A difference in academic performance between groups.", "ex": "The achievement gap often reflects poverty and unequal resources."}, {"term": "attainment gap", "ipa": "/əˈteɪnmənt ɡæp/", "pron": "uh-TAYN-muhnt gap", "fr": "écart de niveau scolaire", "def": "A difference in educational results between groups.", "ex": "The attainment gap widened during school closures."}, {"term": "opportunity gap", "ipa": "/ˌɒpəˈtjuːnəti ɡæp/", "pron": "op-uh-TYOO-nuh-tee gap", "fr": "écart d’opportunités", "def": "Unequal access to learning opportunities and resources.", "ex": "The opportunity gap begins before children enter school."}, {"term": "educational inequality", "ipa": "/ˌedjʊˈkeɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "ej-yoo-KAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité éducative", "def": "Unequal access to quality education or unequal outcomes.", "ex": "Educational inequality undermines social mobility."}, {"term": "postcode lottery", "ipa": "/ˈpəʊstkəʊd ˌlɒtəri/", "pron": "POST-kohd LOT-uh-ree", "fr": "loterie du code postal ; inégalités territoriales", "def": "Unequal access to services depending on where someone lives.", "ex": "School quality can become a postcode lottery."}, {"term": "catchment area", "ipa": "/ˈkætʃmənt ˌeəriə/", "pron": "KATCH-muhnt AIR-ee-uh", "fr": "secteur scolaire", "def": "The geographical area from which a school admits pupils.", "ex": "House prices often rise in good school catchment areas."}, {"term": "school choice", "ipa": "/ˈskuːl tʃɔɪs/", "pron": "school choice", "fr": "choix de l’école", "def": "Policies allowing families to choose between schools.", "ex": "School choice may benefit informed middle-class parents."}, {"term": "parental involvement", "ipa": "/pəˌrentəl ɪnˈvɒlvmənt/", "pron": "puh-REN-tuhl in-VOLV-muhnt", "fr": "implication des parents", "def": "Parents’ participation in a child’s education.", "ex": "Parental involvement strongly affects school success."}, {"term": "private tutoring", "ipa": "/ˌpraɪvət ˈtjuːtərɪŋ/", "pron": "PRY-vuht TYOO-tuh-ring", "fr": "cours particuliers", "def": "Paid extra teaching outside school.", "ex": "Private tutoring can widen inequality."}, {"term": "shadow education", "ipa": "/ˌʃædəʊ ˌedjʊˈkeɪʃən/", "pron": "SHAD-oh ej-yoo-KAY-shuhn", "fr": "éducation parallèle ; soutien privé", "def": "Private supplementary tutoring outside the formal school system.", "ex": "Shadow education gives richer pupils an advantage."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes.", "ex": "Education is often seen as a driver of social mobility."}, {"term": "meritocracy", "ipa": "/ˌmerɪˈtɒkrəsi/", "pron": "mer-i-TOK-ruh-see", "fr": "méritocratie", "def": "A system where success is supposed to depend on talent and effort.", "ex": "Education systems often claim to be meritocratic."}, {"term": "elite reproduction", "ipa": "/eɪˌliːt ˌriːprəˈdʌkʃən/", "pron": "ay-LEET ree-pruh-DUK-shuhn", "fr": "reproduction des élites", "def": "The process by which privileged groups maintain their status across generations.", "ex": "Elite schools can contribute to elite reproduction."}, {"term": "access to education", "ipa": "/ˌækses tə ˌedjʊˈkeɪʃən/", "pron": "AK-sess tuh ej-yoo-KAY-shuhn", "fr": "accès à l’éducation", "def": "The ability to receive education, regardless of background.", "ex": "Access to education is a key equality issue."}, {"term": "equal opportunity", "ipa": "/ˌiːkwəl ˌɒpəˈtjuːnəti/", "pron": "EE-kwuhl op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "The principle that everyone should have the same chance to succeed.", "ex": "Equal opportunity is impossible without fair schooling."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to improve access for historically disadvantaged groups.", "ex": "Affirmative action in US universities has been fiercely contested."}, {"term": "legacy admission", "ipa": "/ˈleɡəsi ədˌmɪʃən/", "pron": "LEG-uh-see ad-MISH-uhn", "fr": "admission préférentielle des enfants d’anciens élèves", "def": "Preferential university admission for applicants whose relatives attended the institution.", "ex": "Legacy admissions are criticised as unfair and elitist."}, {"term": "college admissions", "ipa": "/ˈkɒlɪdʒ ədˌmɪʃənz/", "pron": "KOL-ij ad-MISH-uhnz", "fr": "admissions universitaires", "def": "The process of applying and being accepted to university or college, especially in the US.", "ex": "College admissions can reflect inequality as much as merit."}, {"term": "Ivy League", "ipa": "/ˈaɪvi liːɡ/", "pron": "EYE-vee leeg", "fr": "Ivy League", "def": "A group of prestigious US universities often associated with elite status.", "ex": "Ivy League universities are symbols of privilege and excellence."}, {"term": "Oxbridge", "ipa": "/ˈɒksbrɪdʒ/", "pron": "OKS-brij", "fr": "Oxbridge ; Oxford et Cambridge", "def": "Oxford and Cambridge universities considered together.", "ex": "Oxbridge has long been linked to Britain’s establishment."}, {"term": "campus", "ipa": "/ˈkæmpəs/", "pron": "KAM-puhs", "fr": "campus", "def": "The buildings and grounds of a university or college.", "ex": "Campus politics often reflects wider culture wars."}, {"term": "campus free speech", "ipa": "/ˌkæmpəs friː ˈspiːtʃ/", "pron": "KAM-puhs free speech", "fr": "liberté d’expression sur les campus", "def": "Debates over expression and censorship at universities.", "ex": "Campus free speech has become a culture-war issue."}]}, {"title": "D. Higher education, admissions and culture wars", "entries": [{"term": "safe space", "ipa": "/ˈseɪf speɪs/", "pron": "sayf space", "fr": "espace sûr", "def": "An environment intended to protect people from discrimination, harassment or trauma.", "ex": "Safe spaces are defended as inclusive and criticised as overprotective."}, {"term": "trigger warning", "ipa": "/ˈtrɪɡə ˌwɔːnɪŋ/", "pron": "TRIG-uh WAR-ning", "fr": "avertissement de contenu sensible", "def": "A warning that content may be disturbing or traumatic.", "ex": "Trigger warnings are debated in universities."}, {"term": "deplatforming", "ipa": "/diːˈplætfɔːmɪŋ/", "pron": "dee-PLAT-form-ing", "fr": "déplateformisation ; retrait de tribune", "def": "Preventing a speaker from appearing on a platform because of controversial views.", "ex": "Deplatforming raises questions about free speech and harm."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Education has become a major culture-war battlefield."}, {"term": "critical race theory", "ipa": "/ˌkrɪtɪkəl ˈreɪs ˈθɪəri/", "pron": "KRIT-i-kuhl rays THEE-uh-ree", "fr": "théorie critique de la race", "def": "An academic framework examining how institutions reproduce racial inequality.", "ex": "Critical race theory became controversial in US school debates."}, {"term": "book ban", "ipa": "/ˈbʊk bæn/", "pron": "book ban", "fr": "interdiction de livres", "def": "A restriction or removal of books from schools or libraries.", "ex": "Book bans often target works about race, gender or sexuality."}, {"term": "parents’ rights", "ipa": "/ˈpeərənts raɪts/", "pron": "PAIR-uhnts rites", "fr": "droits des parents", "def": "The claim that parents should control or influence what schools teach children.", "ex": "Parents’ rights has become a powerful political slogan."}, {"term": "indoctrination", "ipa": "/ɪnˌdɒktrɪˈneɪʃən/", "pron": "in-dok-tri-NAY-shuhn", "fr": "endoctrinement", "def": "Teaching beliefs in a way that discourages critical thinking.", "ex": "Both conservatives and progressives accuse schools of indoctrination."}, {"term": "character education", "ipa": "/ˈkærəktər ˌedjʊˈkeɪʃən/", "pron": "KARR-uhk-tuh ej-yoo-KAY-shuhn", "fr": "éducation morale ; formation du caractère", "def": "Teaching values, behaviour and personal qualities.", "ex": "Character education can support civic responsibility."}, {"term": "citizenship education", "ipa": "/ˈsɪtɪzənʃɪp ˌedjʊˈkeɪʃən/", "pron": "SIT-i-zuhn-ship ej-yoo-KAY-shuhn", "fr": "éducation civique", "def": "Education about rights, responsibilities, democracy and civic life.", "ex": "Citizenship education helps prepare students for democracy."}, {"term": "school-to-prison pipeline", "ipa": "/ˌskuːl tə ˈprɪzən ˌpaɪplaɪn/", "pron": "school tuh PRIZ-uhn PIPE-line", "fr": "pipeline école-prison", "def": "A process where harsh school discipline pushes disadvantaged pupils towards the criminal justice system.", "ex": "The school-to-prison pipeline is a major concern in US education debates."}, {"term": "school discipline", "ipa": "/ˈskuːl ˌdɪsəplɪn/", "pron": "school DIS-uh-plin", "fr": "discipline scolaire", "def": "Rules and punishments used to manage pupil behaviour.", "ex": "School discipline can be applied unequally."}, {"term": "exclusion", "ipa": "/ɪkˈskluːʒən/", "pron": "ik-SKLOO-zhuhn", "fr": "exclusion scolaire", "def": "The removal of a pupil from school as a disciplinary measure.", "ex": "Exclusion rates are often higher for vulnerable pupils."}, {"term": "school dropout", "ipa": "/ˈskuːl ˌdrɒpaʊt/", "pron": "school DROP-owt", "fr": "décrocheur scolaire", "def": "A student who leaves school before completing a qualification.", "ex": "School dropouts face weaker job prospects."}, {"term": "dropout rate", "ipa": "/ˈdrɒpaʊt reɪt/", "pron": "DROP-owt rayt", "fr": "taux de décrochage", "def": "The percentage of students leaving school or college before completing.", "ex": "The dropout rate is linked to poverty and lack of support."}, {"term": "school meal", "ipa": "/ˈskuːl miːl/", "pron": "school meel", "fr": "repas scolaire", "def": "Food provided to pupils at school.", "ex": "Free school meals can reduce child hunger."}, {"term": "free school meals", "ipa": "/ˌfriː skuːl ˈmiːlz/", "pron": "free school meelz", "fr": "repas scolaires gratuits", "def": "Meals provided at no cost to pupils from low-income families.", "ex": "Eligibility for free school meals is used as a poverty indicator."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "Unequal access to digital devices, internet or digital skills.", "ex": "The pandemic exposed the digital divide among pupils."}, {"term": "learning loss", "ipa": "/ˈlɜːnɪŋ lɒs/", "pron": "LUR-ning loss", "fr": "perte d’apprentissage", "def": "Loss of knowledge or skills due to interrupted education.", "ex": "School closures caused learning loss, especially among disadvantaged pupils."}, {"term": "mental health support", "ipa": "/ˌmentəl ˈhelθ səˌpɔːt/", "pron": "MEN-tuhl helth suh-PORT", "fr": "soutien psychologique", "def": "Support for students’ psychological well-being.", "ex": "Schools increasingly provide mental health support."}, {"term": "pastoral care", "ipa": "/ˌpɑːstərəl ˈkeə/", "pron": "PAH-stuh-ruhl care", "fr": "accompagnement éducatif et social", "def": "Support for pupils’ well-being, behaviour and personal development.", "ex": "Pastoral care is vital for vulnerable students."}, {"term": "safeguarding", "ipa": "/ˈseɪfɡɑːdɪŋ/", "pron": "SAYF-gar-ding", "fr": "protection de l’enfance", "def": "Measures to protect children from harm or abuse.", "ex": "Safeguarding is a core responsibility of schools."}, {"term": "to widen access", "ipa": "/ˈwaɪdən ˈækses/", "pron": "WY-duhn AK-sess", "fr": "élargir l’accès", "def": "To make education available to more people, especially disadvantaged groups.", "ex": "Universities have programmes to widen access."}, {"term": "to close the attainment gap", "ipa": "/kləʊz ði əˈteɪnmənt ɡæp/", "pron": "klohz thee uh-TAYN-muhnt gap", "fr": "réduire l’écart de niveau scolaire", "def": "To reduce differences in educational results between groups.", "ex": "Targeted funding can help close the attainment gap."}, {"term": "to level the playing field", "ipa": "/ˈlevəl ðə ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl thuh PLAY-ing field", "fr": "rendre les conditions plus équitables", "def": "To make conditions fairer for everyone.", "ex": "Good public education should level the playing field."}]}, {"title": "E. Well-being, social issues and high-value verbs", "entries": [{"term": "to reproduce inequality", "ipa": "/ˌriːprəˈdjuːs ˌɪnɪˈkwɒləti/", "pron": "ree-pruh-DYOOSS in-i-KWOL-uh-tee", "fr": "reproduire les inégalités", "def": "To make inequality continue across generations.", "ex": "Selective education can reproduce inequality."}, {"term": "to improve outcomes", "ipa": "/ɪmˈpruːv ˈaʊtkʌmz/", "pron": "im-PROOV OWT-kumz", "fr": "améliorer les résultats", "def": "To improve results or long-term consequences.", "ex": "Early intervention can improve outcomes."}, {"term": "to raise standards", "ipa": "/reɪz ˈstændədz/", "pron": "rayz STAN-duhdz", "fr": "élever le niveau", "def": "To improve quality or performance in education.", "ex": "Governments often promise to raise standards."}, {"term": "to narrow the curriculum", "ipa": "/ˈnærəʊ ðə kəˈrɪkjʊləm/", "pron": "NARR-oh thuh kuh-RIK-yuh-luhm", "fr": "réduire l’éventail du programme", "def": "To reduce the range of subjects or skills taught.", "ex": "High-stakes testing can narrow the curriculum."}, {"term": "to promote critical thinking", "ipa": "/prəˈməʊt ˌkrɪtɪkəl ˈθɪŋkɪŋ/", "pron": "pruh-MOHT KRIT-i-kuhl THINK-ing", "fr": "promouvoir l’esprit critique", "def": "To encourage analytical and independent thought.", "ex": "Education should promote critical thinking, not just exam performance."}, {"term": "to prepare students for the labour market", "ipa": "/prɪˈpeə ˈstjuːdənts fə ðə ˈleɪbə ˌmɑːkɪt/", "pron": "pri-PAIR STYOO-duhnts for thuh LAY-buh MAR-kit", "fr": "préparer les étudiants au marché du travail", "def": "To equip students with skills needed for work.", "ex": "Vocational education prepares students for the labour market."}, {"term": "to empower learners", "ipa": "/ɪmˈpaʊə ˈlɜːnəz/", "pron": "im-POW-uh LUR-nuhz", "fr": "donner du pouvoir d’agir aux apprenants", "def": "To give learners confidence, skills and agency.", "ex": "Inclusive teaching can empower learners."}]}]}, {"id": "p4c30", "part": 4, "chapter": 30, "title": "Social Mobility", "file": "cpge_vocab_part4_chapter30_social_mobility_premium.html", "count": 149, "sections": [{"title": "A. Core concepts: types of social mobility", "entries": [{"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes or positions in society.", "ex": "Social mobility is often used to measure whether a society offers real equal opportunity."}, {"term": "upward mobility", "ipa": "/ˌʌpwəd məʊˈbɪləti/", "pron": "UP-wuhd moh-BIL-uh-tee", "fr": "ascension sociale", "def": "Movement to a higher social or economic position.", "ex": "Education is often presented as the main path to upward mobility."}, {"term": "downward mobility", "ipa": "/ˌdaʊnwəd məʊˈbɪləti/", "pron": "DOWN-wuhd moh-BIL-uh-tee", "fr": "déclassement ; mobilité descendante", "def": "Movement to a lower social or economic position.", "ex": "Economic crises can increase fears of downward mobility."}, {"term": "intergenerational mobility", "ipa": "/ˌɪntədʒenəˈreɪʃənəl məʊˈbɪləti/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl moh-BIL-uh-tee", "fr": "mobilité intergénérationnelle", "def": "The extent to which children reach a different social or economic position from their parents.", "ex": "Intergenerational mobility is lower when family background strongly determines success."}, {"term": "intragenerational mobility", "ipa": "/ˌɪntrədʒenəˈreɪʃənəl məʊˈbɪləti/", "pron": "IN-truh-jen-uh-RAY-shuh-nuhl moh-BIL-uh-tee", "fr": "mobilité intragénérationnelle", "def": "Social or economic movement within one person’s lifetime.", "ex": "Intragenerational mobility can happen through career progression."}, {"term": "absolute mobility", "ipa": "/ˌæbsəluːt məʊˈbɪləti/", "pron": "AB-suh-loot moh-BIL-uh-tee", "fr": "mobilité absolue", "def": "Whether people are better off than their parents in real living standards.", "ex": "Absolute mobility was easier during periods of strong economic growth."}, {"term": "relative mobility", "ipa": "/ˌrelətɪv məʊˈbɪləti/", "pron": "REL-uh-tiv moh-BIL-uh-tee", "fr": "mobilité relative", "def": "Whether people change position compared with others in society.", "ex": "Relative mobility remains limited when privilege is strongly inherited."}, {"term": "class mobility", "ipa": "/ˌklɑːs məʊˈbɪləti/", "pron": "klass moh-BIL-uh-tee", "fr": "mobilité de classe", "def": "Movement between social classes.", "ex": "Class mobility is closely linked to education, wealth and social networks."}, {"term": "economic mobility", "ipa": "/ˌiːkəˈnɒmɪk məʊˈbɪləti/", "pron": "ee-kuh-NOM-ik moh-BIL-uh-tee", "fr": "mobilité économique", "def": "The ability to improve one’s income, wealth or economic position.", "ex": "Economic mobility is harder when wages stagnate and housing costs rise."}, {"term": "occupational mobility", "ipa": "/ˌɒkjʊˈpeɪʃənəl məʊˈbɪləti/", "pron": "ok-yuh-PAY-shuh-nuhl moh-BIL-uh-tee", "fr": "mobilité professionnelle", "def": "Movement between jobs or occupational categories.", "ex": "Occupational mobility may require training and qualifications."}, {"term": "income mobility", "ipa": "/ˈɪnkʌm məʊˈbɪləti/", "pron": "IN-kum moh-BIL-uh-tee", "fr": "mobilité des revenus", "def": "Movement up or down the income distribution.", "ex": "Income mobility is limited when low-paid workers remain trapped in insecure jobs."}, {"term": "wealth mobility", "ipa": "/ˈwelθ məʊˈbɪləti/", "pron": "welth moh-BIL-uh-tee", "fr": "mobilité patrimoniale", "def": "Movement up or down the wealth distribution.", "ex": "Wealth mobility is strongly affected by inheritance and property ownership."}, {"term": "geographical mobility", "ipa": "/ˌdʒiːəˈɡræfɪkəl məʊˈbɪləti/", "pron": "jee-uh-GRAF-i-kuhl moh-BIL-uh-tee", "fr": "mobilité géographique", "def": "The ability or willingness to move to another place for better opportunities.", "ex": "High housing costs can limit geographical mobility."}, {"term": "social ladder", "ipa": "/ˌsəʊʃəl ˈlædə/", "pron": "SOH-shuhl LAD-uh", "fr": "échelle sociale", "def": "A metaphor for the hierarchy of social positions.", "ex": "Many people feel that the social ladder is harder to climb."}, {"term": "ladder of opportunity", "ipa": "/ˌlædər əv ˌɒpəˈtjuːnəti/", "pron": "LAD-uh ov op-uh-TYOO-nuh-tee", "fr": "échelle des opportunités", "def": "A metaphor for routes that allow people to improve their lives.", "ex": "Good schools are supposed to provide a ladder of opportunity."}, {"term": "glass ceiling", "ipa": "/ˌɡlɑːs ˈsiːlɪŋ/", "pron": "glass SEE-ling", "fr": "plafond de verre", "def": "An invisible barrier preventing certain groups from reaching top positions.", "ex": "The glass ceiling limits women and minorities in elite professions."}, {"term": "sticky floor", "ipa": "/ˌstɪki ˈflɔː/", "pron": "STIK-ee floor", "fr": "plancher collant ; blocage dans les emplois précaires", "def": "A situation where people remain trapped in low-paid or low-status jobs.", "ex": "The sticky floor prevents many workers from moving up."}, {"term": "poverty trap", "ipa": "/ˈpɒvəti træp/", "pron": "POV-uh-tee trap", "fr": "piège de la pauvreté", "def": "A situation in which poverty itself makes it difficult to escape poverty.", "ex": "Low wages, debt and poor housing can create a poverty trap."}, {"term": "cycle of poverty", "ipa": "/ˌsaɪkəl əv ˈpɒvəti/", "pron": "SY-kuhl ov POV-uh-tee", "fr": "cycle de la pauvreté", "def": "The transmission of poverty from one generation to the next.", "ex": "Early intervention can help break the cycle of poverty."}, {"term": "social background", "ipa": "/ˌsəʊʃəl ˈbækɡraʊnd/", "pron": "SOH-shuhl BAK-ground", "fr": "origine sociale", "def": "A person’s family class, education, income and social environment.", "ex": "Social background still shapes educational achievement."}]}, {"title": "B. Background, privilege, capital and meritocracy", "entries": [{"term": "family background", "ipa": "/ˌfæməli ˈbækɡraʊnd/", "pron": "FAM-uh-lee BAK-ground", "fr": "milieu familial", "def": "The social, economic and educational circumstances of a person’s family.", "ex": "Family background often affects children’s life chances."}, {"term": "class background", "ipa": "/ˌklɑːs ˈbækɡraʊnd/", "pron": "klass BAK-ground", "fr": "origine de classe", "def": "The social class into which a person is born or raised.", "ex": "Class background can influence confidence and cultural codes."}, {"term": "socio-economic status", "ipa": "/ˌsəʊsiəʊ iːkəˈnɒmɪk ˈsteɪtəs/", "pron": "SOH-see-oh ee-kuh-NOM-ik STAY-tuhs", "fr": "statut socio-économique", "def": "A person’s position based on income, education and occupation.", "ex": "Socio-economic status is a strong predictor of educational outcomes."}, {"term": "life chances", "ipa": "/ˈlaɪf ˌtʃɑːnsɪz/", "pron": "life CHAN-siz", "fr": "chances dans la vie", "def": "The opportunities a person has for success, health and security.", "ex": "Life chances are shaped long before adulthood."}, {"term": "starting point", "ipa": "/ˈstɑːtɪŋ pɔɪnt/", "pron": "STAR-ting point", "fr": "point de départ", "def": "The social or economic position from which someone begins life.", "ex": "Not everyone starts from the same starting point."}, {"term": "birth lottery", "ipa": "/ˈbɜːθ ˌlɒtəri/", "pron": "birth LOT-uh-ree", "fr": "loterie de la naissance", "def": "The idea that life outcomes are heavily shaped by circumstances of birth.", "ex": "The birth lottery contradicts the ideal of pure meritocracy."}, {"term": "inherited advantage", "ipa": "/ɪnˌherɪtɪd ədˈvɑːntɪdʒ/", "pron": "in-HER-i-tid ad-VAN-tij", "fr": "avantage hérité", "def": "Benefits received from family background, wealth or networks.", "ex": "Inherited advantage gives some children a head start."}, {"term": "inherited privilege", "ipa": "/ɪnˌherɪtɪd ˈprɪvəlɪdʒ/", "pron": "in-HER-i-tid PRIV-uh-lij", "fr": "privilège hérité", "def": "Social advantages passed down through family status or wealth.", "ex": "Inherited privilege undermines the idea of equal opportunity."}, {"term": "inherited wealth", "ipa": "/ɪnˌherɪtɪd ˈwelθ/", "pron": "in-HER-i-tid welth", "fr": "patrimoine hérité", "def": "Money, property or assets passed from one generation to another.", "ex": "Inherited wealth gives families long-term security."}, {"term": "family wealth", "ipa": "/ˌfæməli ˈwelθ/", "pron": "FAM-uh-lee welth", "fr": "patrimoine familial", "def": "Assets and resources owned by a family.", "ex": "Family wealth often matters more than income for life chances."}, {"term": "cultural capital", "ipa": "/ˌkʌltʃərəl ˈkæpɪtəl/", "pron": "KUL-chuh-ruhl KAP-i-tuhl", "fr": "capital culturel", "def": "Knowledge, habits, language and tastes that help people succeed in institutions.", "ex": "Middle-class pupils often arrive at school with more cultural capital."}, {"term": "social capital", "ipa": "/ˌsəʊʃəl ˈkæpɪtəl/", "pron": "SOH-shuhl KAP-i-tuhl", "fr": "capital social", "def": "Useful relationships, networks and connections.", "ex": "Social capital can open doors to internships and jobs."}, {"term": "economic capital", "ipa": "/ˌiːkəˈnɒmɪk ˈkæpɪtəl/", "pron": "ee-kuh-NOM-ik KAP-i-tuhl", "fr": "capital économique", "def": "Money, property and financial resources.", "ex": "Economic capital allows families to buy better housing and education."}, {"term": "network", "ipa": "/ˈnetwɜːk/", "pron": "NET-wurk", "fr": "réseau", "def": "A group of contacts that can provide information or opportunities.", "ex": "Professional networks often reproduce privilege."}, {"term": "connections", "ipa": "/kəˈnekʃənz/", "pron": "kuh-NEK-shuhnz", "fr": "relations ; réseau", "def": "Useful personal or professional relationships.", "ex": "Connections can matter as much as qualifications."}, {"term": "old boys’ network", "ipa": "/ˌəʊld ˈbɔɪz ˌnetwɜːk/", "pron": "ohld boyz NET-wurk", "fr": "réseau des anciens ; entre-soi masculin élitiste", "def": "Informal elite connections, often among men educated at prestigious institutions.", "ex": "The old boys’ network is often criticised in Britain."}, {"term": "meritocracy", "ipa": "/ˌmerɪˈtɒkrəsi/", "pron": "mer-i-TOK-ruh-see", "fr": "méritocratie", "def": "A system where success is supposed to depend on talent and effort.", "ex": "Meritocracy is powerful as an ideal but contested in practice."}, {"term": "meritocratic ideal", "ipa": "/ˌmerɪtəˈkrætɪk aɪˈdɪəl/", "pron": "mer-i-tuh-KRAT-ik eye-DEE-uhl", "fr": "idéal méritocratique", "def": "The belief that people should succeed according to talent and hard work.", "ex": "The meritocratic ideal can hide structural inequalities."}, {"term": "myth of meritocracy", "ipa": "/ˌmɪθ əv ˌmerɪˈtɒkrəsi/", "pron": "mith ov mer-i-TOK-ruh-see", "fr": "mythe de la méritocratie", "def": "The argument that meritocracy is more imagined than real because privilege shapes outcomes.", "ex": "The myth of meritocracy can blame individuals for structural barriers."}, {"term": "equal opportunity", "ipa": "/ˌiːkwəl ˌɒpəˈtjuːnəti/", "pron": "EE-kwuhl op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "The principle that everyone should have the same chance to succeed.", "ex": "Equal opportunity requires more than formal rights."}, {"term": "equality of opportunity", "ipa": "/iˌkwɒləti əv ˌɒpəˈtjuːnəti/", "pron": "i-KWOL-uh-tee ov op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "A fair distribution of chances, regardless of background.", "ex": "Education policy often claims to promote equality of opportunity."}, {"term": "equality of outcome", "ipa": "/iˌkwɒləti əv ˈaʊtkʌm/", "pron": "i-KWOL-uh-tee ov OWT-kum", "fr": "égalité des résultats", "def": "The idea that people should end up with similar results or living standards.", "ex": "Critics of redistribution often reject equality of outcome."}, {"term": "level playing field", "ipa": "/ˌlevəl ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl PLAY-ing field", "fr": "conditions équitables ; terrain de jeu égal", "def": "A fair situation in which everyone has comparable chances.", "ex": "Public education should help level the playing field."}, {"term": "fair shot", "ipa": "/ˌfeə ˈʃɒt/", "pron": "fair shot", "fr": "chance équitable", "def": "A fair chance to succeed.", "ex": "Politicians often promise that every child deserves a fair shot."}, {"term": "fairness", "ipa": "/ˈfeənəs/", "pron": "FAIR-nuhs", "fr": "équité ; justice", "def": "Justice and equal treatment.", "ex": "Fairness is central to debates about mobility."}, {"term": "structural inequality", "ipa": "/ˌstrʌktʃərəl ˌɪnɪˈkwɒləti/", "pron": "STRUK-chuh-ruhl in-i-KWOL-uh-tee", "fr": "inégalité structurelle", "def": "Inequality produced by institutions, systems and social structures.", "ex": "Structural inequality limits individual effort."}, {"term": "systemic barrier", "ipa": "/sɪˌstemɪk ˈbæriə/", "pron": "si-STEM-ik BARR-ee-uh", "fr": "obstacle systémique", "def": "A barrier created by a system rather than one individual.", "ex": "Systemic barriers prevent many talented students from progressing."}, {"term": "social barrier", "ipa": "/ˌsəʊʃəl ˈbæriə/", "pron": "SOH-shuhl BARR-ee-uh", "fr": "barrière sociale", "def": "A social obstacle that limits opportunity.", "ex": "Accent and class codes can act as social barriers."}, {"term": "glass escalator", "ipa": "/ˌɡlɑːs ˈeskəleɪtə/", "pron": "glass ES-kuh-lay-tuh", "fr": "ascenseur de verre", "def": "An advantage that helps some men rise quickly in female-dominated professions.", "ex": "The glass escalator shows that gender can shape mobility."}, {"term": "elite reproduction", "ipa": "/eɪˌliːt ˌriːprəˈdʌkʃən/", "pron": "ay-LEET ree-pruh-DUK-shuhn", "fr": "reproduction des élites", "def": "The process by which privileged groups maintain their status across generations.", "ex": "Elite reproduction can occur through schools, universities and networks."}]}, {"title": "C. Class, elites, education and access", "entries": [{"term": "class reproduction", "ipa": "/ˌklɑːs ˌriːprəˈdʌkʃən/", "pron": "klass ree-pruh-DUK-shuhn", "fr": "reproduction sociale", "def": "The transmission of class position from parents to children.", "ex": "Class reproduction makes mobility more difficult."}, {"term": "social reproduction", "ipa": "/ˌsəʊʃəl ˌriːprəˈdʌkʃən/", "pron": "SOH-shuhl ree-pruh-DUK-shuhn", "fr": "reproduction sociale", "def": "The way social structures and inequalities are passed across generations.", "ex": "Social reproduction can happen through education and housing."}, {"term": "class system", "ipa": "/ˈklɑːs ˌsɪstəm/", "pron": "klass SIS-tuhm", "fr": "système de classes", "def": "A social hierarchy based on wealth, education, occupation and culture.", "ex": "The British class system remains deeply influential."}, {"term": "working class", "ipa": "/ˌwɜːkɪŋ ˈklɑːs/", "pron": "WUR-king klass", "fr": "classe ouvrière ; classes populaires", "def": "People associated with manual, service or lower-paid work.", "ex": "Working-class students are underrepresented in elite universities."}, {"term": "middle class", "ipa": "/ˌmɪdəl ˈklɑːs/", "pron": "MID-uhl klass", "fr": "classe moyenne", "def": "People associated with professional work, education and relative security.", "ex": "Middle-class parents often know how to navigate school systems."}, {"term": "upper class", "ipa": "/ˌʌpə ˈklɑːs/", "pron": "UP-uh klass", "fr": "classe supérieure", "def": "The wealthiest and most socially privileged class.", "ex": "The upper class benefits from inherited wealth and elite networks."}, {"term": "underclass", "ipa": "/ˈʌndəklɑːs/", "pron": "UN-duh-klass", "fr": "sous-classe ; terme controversé", "def": "A controversial term for a highly disadvantaged group seen as excluded from mainstream society.", "ex": "The word underclass can stigmatise poverty."}, {"term": "working poor", "ipa": "/ˌwɜːkɪŋ ˈpɔː/", "pron": "WUR-king poor", "fr": "travailleurs pauvres", "def": "People who work but remain poor because wages are low or costs are high.", "ex": "The working poor show that employment does not always guarantee mobility."}, {"term": "precariat", "ipa": "/prɪˈkeəriət/", "pron": "pri-KAIR-ee-uht", "fr": "précariat", "def": "People living with insecure jobs, low wages and unstable conditions.", "ex": "The precariat faces limited prospects of upward mobility."}, {"term": "elite", "ipa": "/ɪˈliːt/", "pron": "i-LEET", "fr": "élite", "def": "A small group with significant power, wealth or prestige.", "ex": "Elite recruitment often favours privileged backgrounds."}, {"term": "establishment", "ipa": "/ɪˈstæblɪʃmənt/", "pron": "i-STAB-lish-muhnt", "fr": "establishment ; élite dirigeante", "def": "Powerful institutions and people who dominate public life.", "ex": "The establishment is often accused of being closed to outsiders."}, {"term": "social closure", "ipa": "/ˌsəʊʃəl ˈkləʊʒə/", "pron": "SOH-shuhl KLOH-zhuh", "fr": "fermeture sociale", "def": "The process by which groups protect privileges by limiting access.", "ex": "Credential requirements can create social closure."}, {"term": "credentialism", "ipa": "/krɪˈdenʃəlɪzəm/", "pron": "kri-DEN-shuhl-iz-uhm", "fr": "diplômisme ; culte du diplôme", "def": "Overreliance on formal qualifications as proof of ability.", "ex": "Credentialism can exclude capable people without elite degrees."}, {"term": "elite university", "ipa": "/eɪˌliːt ˌjuːnɪˈvɜːsəti/", "pron": "ay-LEET yoo-ni-VUR-suh-tee", "fr": "université d’élite", "def": "A prestigious and highly selective university.", "ex": "Elite universities can function as gateways to top careers."}, {"term": "Oxbridge", "ipa": "/ˈɒksbrɪdʒ/", "pron": "OKS-brij", "fr": "Oxbridge ; Oxford et Cambridge", "def": "Oxford and Cambridge universities considered together.", "ex": "Oxbridge is strongly associated with Britain’s elite."}, {"term": "Ivy League", "ipa": "/ˈaɪvi liːɡ/", "pron": "EYE-vee leeg", "fr": "Ivy League", "def": "A group of prestigious universities in the United States.", "ex": "The Ivy League is often seen as a route to elite careers."}, {"term": "legacy admission", "ipa": "/ˈleɡəsi ədˌmɪʃən/", "pron": "LEG-uh-see ad-MISH-uhn", "fr": "admission préférentielle des enfants d’anciens élèves", "def": "Preferential admission for applicants whose relatives attended the institution.", "ex": "Legacy admission is criticised for privileging the already privileged."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to improve access for historically disadvantaged groups.", "ex": "Affirmative action aims to make elite education more representative."}, {"term": "widening participation", "ipa": "/ˌwaɪdənɪŋ pɑːˌtɪsɪˈpeɪʃən/", "pron": "WY-duh-ning par-tis-i-PAY-shuhn", "fr": "élargissement de la participation", "def": "Policies encouraging underrepresented groups to enter higher education.", "ex": "Widening participation programmes target disadvantaged students."}, {"term": "access programme", "ipa": "/ˈækses ˌprəʊɡræm/", "pron": "AK-sess PROH-gram", "fr": "programme d’accès ; dispositif d’ouverture sociale", "def": "A scheme helping disadvantaged students access education or careers.", "ex": "Access programmes can demystify elite universities."}, {"term": "scholarship", "ipa": "/ˈskɒləʃɪp/", "pron": "SKOL-uh-ship", "fr": "bourse d’études", "def": "Financial support awarded to a student, often based on need or merit.", "ex": "Scholarships can reduce financial barriers."}, {"term": "bursary", "ipa": "/ˈbɜːsəri/", "pron": "BUR-suh-ree", "fr": "bourse d’aide sociale", "def": "Need-based financial support for students.", "ex": "Bursaries help low-income students afford study."}, {"term": "private tutoring", "ipa": "/ˌpraɪvət ˈtjuːtərɪŋ/", "pron": "PRY-vuht TYOO-tuh-ring", "fr": "cours particuliers", "def": "Paid teaching outside school.", "ex": "Private tutoring gives wealthy families an advantage."}, {"term": "shadow education", "ipa": "/ˌʃædəʊ ˌedjʊˈkeɪʃən/", "pron": "SHAD-oh ej-yoo-KAY-shuhn", "fr": "éducation parallèle ; soutien privé", "def": "Private supplementary tutoring outside the formal system.", "ex": "Shadow education can widen the opportunity gap."}, {"term": "school funding", "ipa": "/ˈskuːl ˌfʌndɪŋ/", "pron": "school FUN-ding", "fr": "financement des écoles", "def": "Money available to schools.", "ex": "Unequal school funding affects mobility."}, {"term": "funding gap", "ipa": "/ˈfʌndɪŋ ɡæp/", "pron": "FUN-ding gap", "fr": "écart de financement", "def": "A difference in financial resources between institutions or areas.", "ex": "The funding gap often reflects local inequality."}, {"term": "underfunded school", "ipa": "/ˌʌndəˈfʌndɪd skuːl/", "pron": "UN-duh-FUN-did school", "fr": "école sous-financée", "def": "A school with insufficient money or resources.", "ex": "Underfunded schools struggle to provide individual support."}, {"term": "catchment area", "ipa": "/ˈkætʃmənt ˌeəriə/", "pron": "KATCH-muhnt AIR-ee-uh", "fr": "secteur scolaire", "def": "The geographical area from which a school admits pupils.", "ex": "Wealthier families can buy homes in good catchment areas."}]}, {"title": "D. Childhood, place, deprivation and opportunity gaps", "entries": [{"term": "postcode lottery", "ipa": "/ˈpəʊstkəʊd ˌlɒtəri/", "pron": "POST-kohd LOT-uh-ree", "fr": "loterie du code postal ; inégalités territoriales", "def": "Unequal access to services depending on where someone lives.", "ex": "School quality can become a postcode lottery."}, {"term": "early years education", "ipa": "/ˌɜːli jɪəz ˌedjʊˈkeɪʃən/", "pron": "UR-lee yearz ej-yoo-KAY-shuhn", "fr": "éducation de la petite enfance", "def": "Education and care for very young children before formal schooling.", "ex": "Early years education can improve life chances."}, {"term": "early intervention", "ipa": "/ˌɜːli ˌɪntəˈvenʃən/", "pron": "UR-lee in-tuh-VEN-shuhn", "fr": "intervention précoce", "def": "Action taken early to prevent later problems.", "ex": "Early intervention can reduce the attainment gap."}, {"term": "attainment gap", "ipa": "/əˈteɪnmənt ɡæp/", "pron": "uh-TAYN-muhnt gap", "fr": "écart de niveau scolaire", "def": "A difference in educational results between groups.", "ex": "The attainment gap often appears before secondary school."}, {"term": "achievement gap", "ipa": "/əˈtʃiːvmənt ɡæp/", "pron": "uh-CHEEV-muhnt gap", "fr": "écart de réussite scolaire", "def": "A difference in academic performance between groups.", "ex": "The achievement gap is linked to poverty and resources."}, {"term": "opportunity gap", "ipa": "/ˌɒpəˈtjuːnəti ɡæp/", "pron": "op-uh-TYOO-nuh-tee gap", "fr": "écart d’opportunités", "def": "Unequal access to opportunities that shape success.", "ex": "The opportunity gap starts in childhood."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "Unequal access to digital devices, internet or digital skills.", "ex": "Remote learning exposed the digital divide."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Unreliable access to enough affordable, nutritious food.", "ex": "Food insecurity affects pupils’ concentration and achievement."}, {"term": "child poverty", "ipa": "/ˌtʃaɪld ˈpɒvəti/", "pron": "child POV-uh-tee", "fr": "pauvreté infantile", "def": "Poverty experienced by children.", "ex": "Child poverty is one of the strongest barriers to mobility."}, {"term": "housing insecurity", "ipa": "/ˈhaʊzɪŋ ˌɪnsɪˈkjʊərəti/", "pron": "HOW-zing in-si-KYOOR-uh-tee", "fr": "précarité du logement", "def": "Unstable, unaffordable or unsafe housing.", "ex": "Housing insecurity disrupts education and work."}, {"term": "neighbourhood effect", "ipa": "/ˈneɪbəhʊd ɪˌfekt/", "pron": "NAY-buh-hood i-FEKT", "fr": "effet de quartier", "def": "The influence of local area conditions on life chances.", "ex": "Neighbourhood effects shape access to schools, safety and networks."}, {"term": "place-based inequality", "ipa": "/ˌpleɪs beɪst ˌɪnɪˈkwɒləti/", "pron": "place-bayst in-i-KWOL-uh-tee", "fr": "inégalité territoriale", "def": "Inequality linked to where people live.", "ex": "Place-based inequality explains many regional mobility gaps."}, {"term": "regional inequality", "ipa": "/ˌriːdʒənəl ˌɪnɪˈkwɒləti/", "pron": "REE-juh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité régionale", "def": "Unequal wealth, services or opportunities between regions.", "ex": "Regional inequality limits opportunities outside major cities."}, {"term": "levelling up", "ipa": "/ˌlevəlɪŋ ˈʌp/", "pron": "LEV-uhl-ing up", "fr": "rééquilibrage territorial ; levelling up", "def": "A British policy slogan about reducing regional inequality.", "ex": "Levelling up aimed to improve opportunities in left-behind areas."}, {"term": "left-behind communities", "ipa": "/ˌleft bɪˈhaɪnd kəˈmjuːnətiz/", "pron": "left bi-HYND kuh-MYOO-nuh-teez", "fr": "communautés laissées pour compte", "def": "Communities that feel neglected by economic and political change.", "ex": "Left-behind communities often have weak mobility prospects."}, {"term": "social exclusion", "ipa": "/ˌsəʊʃəl ɪkˈskluːʒən/", "pron": "SOH-shuhl ik-SKLOO-zhuhn", "fr": "exclusion sociale", "def": "Being cut off from opportunities, services and participation in society.", "ex": "Social exclusion can become self-reinforcing."}, {"term": "marginalisation", "ipa": "/ˌmɑːdʒɪnəlaɪˈzeɪʃən/", "pron": "mar-ji-nuh-ly-ZAY-shuhn", "fr": "marginalisation", "def": "The process of pushing groups to the edge of society.", "ex": "Marginalisation reduces political voice and opportunity."}, {"term": "deprivation", "ipa": "/ˌdeprɪˈveɪʃən/", "pron": "dep-ri-VAY-shuhn", "fr": "privation ; défavorisation", "def": "A serious lack of resources, services or living conditions.", "ex": "Areas of high deprivation often have lower educational outcomes."}, {"term": "disadvantage", "ipa": "/ˌdɪsədˈvɑːntɪdʒ/", "pron": "dis-ad-VAN-tij", "fr": "désavantage", "def": "An unfavourable social or economic condition.", "ex": "Disadvantage can accumulate over a lifetime."}, {"term": "cumulative disadvantage", "ipa": "/ˌkjuːmjʊlətɪv ˌdɪsədˈvɑːntɪdʒ/", "pron": "KYOO-myuh-luh-tiv dis-ad-VAN-tij", "fr": "désavantage cumulatif", "def": "The build-up of disadvantages over time.", "ex": "Cumulative disadvantage makes mobility harder with age."}, {"term": "cumulative advantage", "ipa": "/ˌkjuːmjʊlətɪv ədˈvɑːntɪdʒ/", "pron": "KYOO-myuh-luh-tiv ad-VAN-tij", "fr": "avantage cumulatif", "def": "The build-up of advantages over time.", "ex": "Cumulative advantage helps privileged children stay ahead."}, {"term": "labour market", "ipa": "/ˈleɪbə ˌmɑːkɪt/", "pron": "LAY-buh MAR-kit", "fr": "marché du travail", "def": "The system through which workers find jobs and employers find workers.", "ex": "The labour market rewards some qualifications more than others."}, {"term": "job market", "ipa": "/ˈdʒɒb ˌmɑːkɪt/", "pron": "job MAR-kit", "fr": "marché de l’emploi", "def": "The availability of jobs and employment opportunities.", "ex": "A weak job market reduces mobility for young graduates."}, {"term": "good job", "ipa": "/ˌɡʊd ˈdʒɒb/", "pron": "good job", "fr": "bon emploi", "def": "A stable, well-paid job with prospects.", "ex": "Access to good jobs is unevenly distributed."}, {"term": "dead-end job", "ipa": "/ˌded end ˈdʒɒb/", "pron": "ded-end job", "fr": "emploi sans perspective", "def": "A job with little chance of promotion or improvement.", "ex": "Dead-end jobs trap workers in low income."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "emploi précaire", "def": "Unstable or insecure work with low protection.", "ex": "Precarious work weakens economic mobility."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots ; gig economy", "def": "A labour market based on short-term, freelance or platform work.", "ex": "The gig economy offers flexibility but often little security."}]}, {"title": "E. Work, wealth, policy and high-value verbs", "entries": [{"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal hourly pay.", "ex": "A low minimum wage can keep workers in poverty."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "A living wage can support mobility and security."}, {"term": "wage stagnation", "ipa": "/ˈweɪdʒ stæɡˌneɪʃən/", "pron": "wayj stag-NAY-shuhn", "fr": "stagnation des salaires", "def": "A situation where wages do not rise much over time.", "ex": "Wage stagnation has weakened middle-class security."}, {"term": "career progression", "ipa": "/kəˈrɪə prəˌɡreʃən/", "pron": "kuh-REER pruh-GRESH-uhn", "fr": "progression de carrière", "def": "Advancement to better jobs or responsibilities over time.", "ex": "Career progression is harder without training and networks."}, {"term": "professional ladder", "ipa": "/prəˌfeʃənəl ˈlædə/", "pron": "pruh-FESH-uh-nuhl LAD-uh", "fr": "échelle professionnelle", "def": "The stages through which someone advances in a career.", "ex": "Internships can provide the first step on the professional ladder."}, {"term": "unpaid internship", "ipa": "/ʌnˌpeɪd ˈɪntɜːnʃɪp/", "pron": "un-PAYD IN-turn-ship", "fr": "stage non rémunéré", "def": "A work placement without pay.", "ex": "Unpaid internships favour students whose families can support them."}, {"term": "work experience", "ipa": "/ˈwɜːk ɪkˌspɪəriəns/", "pron": "work ik-SPEER-ee-uhns", "fr": "expérience professionnelle ; stage d’observation", "def": "Short-term experience in a workplace.", "ex": "Work experience can improve employability."}, {"term": "employability", "ipa": "/ɪmˌplɔɪəˈbɪləti/", "pron": "im-ploy-uh-BIL-uh-tee", "fr": "employabilité", "def": "The ability to get and keep a job.", "ex": "Universities increasingly focus on employability."}, {"term": "skills gap", "ipa": "/ˈskɪlz ɡæp/", "pron": "skilz gap", "fr": "déficit de compétences", "def": "A mismatch between workers’ skills and employers’ needs.", "ex": "The skills gap can limit productivity and mobility."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion ; acquisition de nouvelles compétences", "def": "Training people in new skills for different jobs.", "ex": "Reskilling is essential in an automated economy."}, {"term": "upskilling", "ipa": "/ˌʌpˈskɪlɪŋ/", "pron": "up-SKIL-ing", "fr": "montée en compétences", "def": "Training people to improve existing skills.", "ex": "Upskilling can help workers move into better-paid jobs."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "The use of technology to perform tasks once done by humans.", "ex": "Automation may reduce mobility for workers in routine jobs."}, {"term": "social safety net", "ipa": "/ˌsəʊʃəl ˈseɪfti net/", "pron": "SOH-shuhl SAYF-tee net", "fr": "filet de sécurité sociale", "def": "Public support protecting people from poverty and hardship.", "ex": "A strong safety net can make mobility less risky."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system in which the state provides support such as healthcare, benefits and pensions.", "ex": "The welfare state can reduce barriers to mobility."}, {"term": "redistribution", "ipa": "/ˌriːdɪstrɪˈbjuːʃən/", "pron": "ree-dis-tri-BYOO-shuhn", "fr": "redistribution", "def": "The transfer of resources through taxes and public spending.", "ex": "Redistribution can reduce inequality of opportunity."}, {"term": "progressive taxation", "ipa": "/prəˌɡresɪv tækˈseɪʃən/", "pron": "pruh-GRESS-iv tak-SAY-shuhn", "fr": "impôt progressif", "def": "A tax system where richer people pay a higher share of income.", "ex": "Progressive taxation can fund public services that support mobility."}, {"term": "universal basic income", "ipa": "/ˌjuːnɪvɜːsəl ˌbeɪsɪk ˈɪnkʌm/", "pron": "yoo-ni-VUR-suhl BAY-sik IN-kum", "fr": "revenu universel de base", "def": "A regular payment given to all citizens regardless of work or income.", "ex": "Universal basic income is proposed as a response to automation."}, {"term": "affordable housing", "ipa": "/əˌfɔːdəbəl ˈhaʊzɪŋ/", "pron": "uh-FOR-duh-buhl HOW-zing", "fr": "logement abordable", "def": "Housing that people on ordinary incomes can afford.", "ex": "Affordable housing supports geographical and social mobility."}, {"term": "home ownership", "ipa": "/ˈhəʊm ˌəʊnəʃɪp/", "pron": "HOHM OH-nuh-ship", "fr": "propriété immobilière ; accession à la propriété", "def": "The state of owning one’s home.", "ex": "Home ownership is a major source of wealth accumulation."}, {"term": "property ladder", "ipa": "/ˈprɒpəti ˌlædə/", "pron": "PROP-uh-tee LAD-uh", "fr": "échelle immobilière", "def": "The progression from buying a first home to more valuable property.", "ex": "Young adults struggle to get onto the property ladder."}, {"term": "rent burden", "ipa": "/ˈrent ˌbɜːdən/", "pron": "rent BUR-duhn", "fr": "poids du loyer", "def": "A situation where rent takes up a large share of income.", "ex": "Rent burden prevents households from saving."}, {"term": "wealth gap", "ipa": "/ˈwelθ ɡæp/", "pron": "welth gap", "fr": "écart de patrimoine", "def": "The difference in wealth between groups.", "ex": "The wealth gap is a major barrier to social mobility."}, {"term": "racial wealth gap", "ipa": "/ˌreɪʃəl ˈwelθ ɡæp/", "pron": "RAY-shuhl welth gap", "fr": "écart de patrimoine racial", "def": "The difference in accumulated wealth between racial groups.", "ex": "The racial wealth gap reflects historical and structural inequality."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart salarial entre hommes et femmes", "def": "The difference between average earnings of men and women.", "ex": "The gender pay gap affects women’s lifetime wealth."}, {"term": "intersectionality", "ipa": "/ˌɪntəsekʃəˈnæləti/", "pron": "IN-tuh-sek-shuh-NAL-uh-tee", "fr": "intersectionnalité", "def": "The way different forms of inequality combine, such as class, race and gender.", "ex": "Intersectionality helps explain why barriers to mobility differ between groups."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity or background.", "ex": "Discrimination can block mobility even for qualified candidates."}, {"term": "class discrimination", "ipa": "/ˌklɑːs dɪˌskrɪmɪˈneɪʃən/", "pron": "klass dis-krim-i-NAY-shuhn", "fr": "discrimination de classe", "def": "Unfair treatment based on social class or background.", "ex": "Class discrimination can occur through accent, dress or cultural codes."}, {"term": "accent bias", "ipa": "/ˈæksent ˌbaɪəs/", "pron": "AK-sent BY-uhs", "fr": "préjugé lié à l’accent", "def": "Prejudice based on the way someone speaks.", "ex": "Accent bias can affect job interviews."}, {"term": "name discrimination", "ipa": "/ˈneɪm dɪˌskrɪmɪˈneɪʃən/", "pron": "name dis-krim-i-NAY-shuhn", "fr": "discrimination liée au nom", "def": "Discrimination based on a person’s name, often linked to ethnicity or class.", "ex": "Name discrimination can reduce interview chances."}, {"term": "to climb the social ladder", "ipa": "/klaɪm ðə ˌsəʊʃəl ˈlædə/", "pron": "klyme thuh SOH-shuhl LAD-uh", "fr": "gravir l’échelle sociale", "def": "To move to a higher social position.", "ex": "Education can help people climb the social ladder."}, {"term": "to move up in society", "ipa": "/muːv ʌp ɪn səˈsaɪəti/", "pron": "moov up in suh-SY-uh-tee", "fr": "s’élever socialement", "def": "To improve one’s social or economic position.", "ex": "Many families hope their children will move up in society."}, {"term": "to break the cycle of poverty", "ipa": "/breɪk ðə ˌsaɪkəl əv ˈpɒvəti/", "pron": "brayk thuh SY-kuhl ov POV-uh-tee", "fr": "briser le cycle de la pauvreté", "def": "To stop poverty from being passed from one generation to the next.", "ex": "Early years support can break the cycle of poverty."}, {"term": "to level the playing field", "ipa": "/ˈlevəl ðə ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl thuh PLAY-ing field", "fr": "rendre les conditions plus équitables", "def": "To make conditions fairer for everyone.", "ex": "Public investment can level the playing field."}, {"term": "to widen access", "ipa": "/ˈwaɪdən ˈækses/", "pron": "WY-duhn AK-sess", "fr": "élargir l’accès", "def": "To make education, jobs or services available to more people.", "ex": "Universities use outreach programmes to widen access."}, {"term": "to close the opportunity gap", "ipa": "/kləʊz ði ˌɒpəˈtjuːnəti ɡæp/", "pron": "klohz thee op-uh-TYOO-nuh-tee gap", "fr": "réduire l’écart d’opportunités", "def": "To reduce unequal access to opportunities.", "ex": "Early intervention can close the opportunity gap."}, {"term": "to reproduce privilege", "ipa": "/ˌriːprəˈdjuːs ˈprɪvəlɪdʒ/", "pron": "ree-pruh-DYOOSS PRIV-uh-lij", "fr": "reproduire les privilèges", "def": "To allow privileged groups to keep advantages across generations.", "ex": "Elite education can reproduce privilege."}, {"term": "to reinforce inequality", "ipa": "/ˌriːɪnˈfɔːs ˌɪnɪˈkwɒləti/", "pron": "ree-in-FORSS in-i-KWOL-uh-tee", "fr": "renforcer les inégalités", "def": "To make inequality stronger or more persistent.", "ex": "Housing markets can reinforce inequality."}, {"term": "to remove barriers", "ipa": "/rɪˈmuːv ˈbæriəz/", "pron": "ri-MOOV BARR-ee-uhz", "fr": "lever les obstacles", "def": "To eliminate obstacles that prevent progress.", "ex": "Scholarships remove barriers to higher education."}, {"term": "to unlock potential", "ipa": "/ʌnˈlɒk pəˈtenʃəl/", "pron": "un-LOK puh-TEN-shuhl", "fr": "libérer le potentiel", "def": "To allow people’s abilities to develop fully.", "ex": "Good schools can unlock children’s potential."}, {"term": "to fulfil one’s potential", "ipa": "/fʊlˈfɪl wʌnz pəˈtenʃəl/", "pron": "fuhl-FIL wunz puh-TEN-shuhl", "fr": "réaliser son potentiel", "def": "To achieve what one is capable of.", "ex": "Social mobility means giving everyone a chance to fulfil their potential."}, {"term": "to be born into privilege", "ipa": "/bi bɔːn ˈɪntuː ˈprɪvəlɪdʒ/", "pron": "bee born IN-too PRIV-uh-lij", "fr": "naître dans le privilège", "def": "To begin life in a socially or economically advantaged family.", "ex": "Those born into privilege often benefit from invisible advantages."}, {"term": "to be trapped in poverty", "ipa": "/bi træpt ɪn ˈpɒvəti/", "pron": "bee trapped in POV-uh-tee", "fr": "être piégé dans la pauvreté", "def": "To be unable to escape poverty.", "ex": "Low wages and high rents can leave families trapped in poverty."}, {"term": "to pass privilege down", "ipa": "/pɑːs ˈprɪvəlɪdʒ daʊn/", "pron": "pass PRIV-uh-lij down", "fr": "transmettre les privilèges", "def": "To transmit advantages to the next generation.", "ex": "Inheritance allows families to pass privilege down."}, {"term": "to make mobility possible", "ipa": "/meɪk məʊˈbɪləti ˈpɒsəbəl/", "pron": "mayk moh-BIL-uh-tee POSS-uh-buhl", "fr": "rendre la mobilité possible", "def": "To create conditions that allow people to improve their position.", "ex": "Affordable housing and strong schools make mobility possible."}]}]}, {"id": "p4c31", "part": 4, "chapter": 31, "title": "Poverty And Inequality", "file": "cpge_vocab_part4_chapter31_poverty_and_inequality_premium.html", "count": 139, "sections": [{"title": "A. Core poverty and inequality vocabulary", "entries": [{"term": "poverty", "ipa": "/ˈpɒvəti/", "pron": "POV-uh-tee", "fr": "pauvreté", "def": "The state of lacking enough money or resources to meet basic needs.", "ex": "Poverty affects health, education, housing and life chances."}, {"term": "inequality", "ipa": "/ˌɪnɪˈkwɒləti/", "pron": "in-i-KWOL-uh-tee", "fr": "inégalité", "def": "An unfair or uneven distribution of resources, opportunities or outcomes.", "ex": "Inequality has become a central issue in modern democracies."}, {"term": "economic inequality", "ipa": "/ˌiːkəˈnɒmɪk ˌɪnɪˈkwɒləti/", "pron": "ee-kuh-NOM-ik in-i-KWOL-uh-tee", "fr": "inégalité économique", "def": "Unequal distribution of income, wealth and economic opportunities.", "ex": "Economic inequality can weaken trust in institutions."}, {"term": "social inequality", "ipa": "/ˌsəʊʃəl ˌɪnɪˈkwɒləti/", "pron": "SOH-shuhl in-i-KWOL-uh-tee", "fr": "inégalité sociale", "def": "Unequal access to status, rights, services or opportunities in society.", "ex": "Social inequality is often reproduced through education and housing."}, {"term": "income inequality", "ipa": "/ˈɪnkʌm ˌɪnɪˈkwɒləti/", "pron": "IN-kum in-i-KWOL-uh-tee", "fr": "inégalité des revenus", "def": "Unequal distribution of income across people or households.", "ex": "Income inequality has widened in many developed economies."}, {"term": "wealth inequality", "ipa": "/ˈwelθ ˌɪnɪˈkwɒləti/", "pron": "welth in-i-KWOL-uh-tee", "fr": "inégalité patrimoniale", "def": "Unequal distribution of assets such as property, savings and investments.", "ex": "Wealth inequality is often greater than income inequality."}, {"term": "absolute poverty", "ipa": "/ˌæbsəluːt ˈpɒvəti/", "pron": "AB-suh-loot POV-uh-tee", "fr": "pauvreté absolue", "def": "Poverty measured against a fixed basic standard of living.", "ex": "Absolute poverty means being unable to meet basic needs."}, {"term": "relative poverty", "ipa": "/ˌrelətɪv ˈpɒvəti/", "pron": "REL-uh-tiv POV-uh-tee", "fr": "pauvreté relative", "def": "Poverty defined in relation to average living standards in a society.", "ex": "Relative poverty can exist even in wealthy countries."}, {"term": "extreme poverty", "ipa": "/ɪkˌstriːm ˈpɒvəti/", "pron": "ik-STREEM POV-uh-tee", "fr": "extrême pauvreté", "def": "Severe poverty involving very low income and deprivation.", "ex": "Extreme poverty is often linked to hunger, unsafe housing and poor health."}, {"term": "deep poverty", "ipa": "/ˌdiːp ˈpɒvəti/", "pron": "deep POV-uh-tee", "fr": "grande pauvreté", "def": "A very severe form of poverty far below the poverty line.", "ex": "Families in deep poverty often rely on emergency support."}, {"term": "persistent poverty", "ipa": "/pəˌsɪstənt ˈpɒvəti/", "pron": "puh-SIS-tuhnt POV-uh-tee", "fr": "pauvreté persistante", "def": "Poverty that continues over a long period.", "ex": "Persistent poverty can damage children’s long-term prospects."}, {"term": "child poverty", "ipa": "/ˌtʃaɪld ˈpɒvəti/", "pron": "child POV-uh-tee", "fr": "pauvreté infantile", "def": "Poverty experienced by children.", "ex": "Child poverty affects educational attainment and mental health."}, {"term": "working poverty", "ipa": "/ˌwɜːkɪŋ ˈpɒvəti/", "pron": "WUR-king POV-uh-tee", "fr": "pauvreté laborieuse", "def": "Poverty among people who are employed.", "ex": "Working poverty shows that employment does not always ensure security."}, {"term": "working poor", "ipa": "/ˌwɜːkɪŋ ˈpɔː/", "pron": "WUR-king poor", "fr": "travailleurs pauvres", "def": "People who work but remain poor.", "ex": "The working poor often face low wages and high housing costs."}, {"term": "in-work poverty", "ipa": "/ˌɪn wɜːk ˈpɒvəti/", "pron": "in-work POV-uh-tee", "fr": "pauvreté au travail", "def": "Poverty affecting households where at least one adult works.", "ex": "In-work poverty has increased with insecure employment."}, {"term": "food poverty", "ipa": "/ˈfuːd ˌpɒvəti/", "pron": "food POV-uh-tee", "fr": "précarité alimentaire", "def": "Lack of money to buy enough nutritious food.", "ex": "Food poverty can affect children’s concentration at school."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Unreliable access to enough affordable and nutritious food.", "ex": "Food insecurity has risen during the cost-of-living crisis."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford adequate heating or energy.", "ex": "Fuel poverty forces families to choose between heating and eating."}, {"term": "energy poverty", "ipa": "/ˈenədʒi ˌpɒvəti/", "pron": "EN-uh-jee POV-uh-tee", "fr": "pauvreté énergétique", "def": "Lack of affordable access to energy for basic needs.", "ex": "Energy poverty became more visible after energy prices surged."}, {"term": "period poverty", "ipa": "/ˈpɪəriəd ˌpɒvəti/", "pron": "PEER-ee-uhd POV-uh-tee", "fr": "précarité menstruelle", "def": "Lack of access to menstrual products because of poverty.", "ex": "Period poverty can make girls miss school."}, {"term": "housing poverty", "ipa": "/ˈhaʊzɪŋ ˌpɒvəti/", "pron": "HOW-zing POV-uh-tee", "fr": "pauvreté liée au logement", "def": "Poverty linked to unaffordable, unsafe or inadequate housing.", "ex": "Housing poverty is worsened by high rents."}, {"term": "homelessness", "ipa": "/ˈhəʊmləsnəs/", "pron": "HOHM-luhs-nuhs", "fr": "sans-abrisme ; absence de logement", "def": "The condition of having no stable or safe home.", "ex": "Homelessness is the most visible form of housing exclusion."}, {"term": "rough sleeping", "ipa": "/ˌrʌf ˈsliːpɪŋ/", "pron": "ruff SLEE-ping", "fr": "sans-abrisme de rue", "def": "Sleeping outside because of homelessness.", "ex": "Rough sleeping is dangerous and strongly linked to poor health."}, {"term": "hidden homelessness", "ipa": "/ˌhɪdən ˈhəʊmləsnəs/", "pron": "HID-uhn HOHM-luhs-nuhs", "fr": "sans-abrisme caché", "def": "Homelessness not visible in official statistics, such as sofa-surfing.", "ex": "Hidden homelessness affects many young people."}]}, {"title": "B. Deprivation, hardship and measurement", "entries": [{"term": "sofa-surfing", "ipa": "/ˈsəʊfə ˌsɜːfɪŋ/", "pron": "SOH-fuh SUR-fing", "fr": "hébergement temporaire chez des proches", "def": "Staying temporarily with friends or relatives because one has no home.", "ex": "Sofa-surfing can hide the true scale of homelessness."}, {"term": "deprivation", "ipa": "/ˌdeprɪˈveɪʃən/", "pron": "dep-ri-VAY-shuhn", "fr": "privation ; défavorisation", "def": "A serious lack of resources, services or living conditions.", "ex": "Deprivation is often concentrated in specific neighbourhoods."}, {"term": "material deprivation", "ipa": "/məˌtɪəriəl ˌdeprɪˈveɪʃən/", "pron": "muh-TEER-ee-uhl dep-ri-VAY-shuhn", "fr": "privation matérielle", "def": "Lack of basic goods and living conditions considered necessary.", "ex": "Material deprivation may include lack of heating, food or clothing."}, {"term": "severe deprivation", "ipa": "/sɪˌvɪə ˌdeprɪˈveɪʃən/", "pron": "si-VEER dep-ri-VAY-shuhn", "fr": "privation sévère", "def": "Extreme lack of basic resources and living standards.", "ex": "Severe deprivation requires urgent public intervention."}, {"term": "multiple deprivation", "ipa": "/ˌmʌltɪpəl ˌdeprɪˈveɪʃən/", "pron": "MUL-ti-puhl dep-ri-VAY-shuhn", "fr": "défavorisation multiple", "def": "Several forms of disadvantage occurring together, such as poor health, low income and bad housing.", "ex": "Multiple deprivation is difficult to solve with one policy alone."}, {"term": "social exclusion", "ipa": "/ˌsəʊʃəl ɪkˈskluːʒən/", "pron": "SOH-shuhl ik-SKLOO-zhuhn", "fr": "exclusion sociale", "def": "Being cut off from opportunities, services and participation in society.", "ex": "Poverty often leads to social exclusion."}, {"term": "marginalisation", "ipa": "/ˌmɑːdʒɪnəlaɪˈzeɪʃən/", "pron": "mar-ji-nuh-ly-ZAY-shuhn", "fr": "marginalisation", "def": "The process of pushing groups to the edge of society.", "ex": "Marginalisation reduces voice and access to power."}, {"term": "vulnerability", "ipa": "/ˌvʌlnərəˈbɪləti/", "pron": "vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité", "def": "Exposure to harm, insecurity or hardship.", "ex": "Poverty increases vulnerability to illness and exploitation."}, {"term": "precariousness", "ipa": "/prɪˈkeəriəsnəs/", "pron": "pri-KAIR-ee-uhs-nuhs", "fr": "précarité", "def": "A state of insecurity and instability.", "ex": "Precariousness affects work, housing and mental health."}, {"term": "precarity", "ipa": "/prɪˈkeərəti/", "pron": "pri-KAIR-uh-tee", "fr": "précarité", "def": "A condition of unstable work, income or living conditions.", "ex": "Precarity has become a defining feature of many low-income lives."}, {"term": "hardship", "ipa": "/ˈhɑːdʃɪp/", "pron": "HARD-ship", "fr": "difficultés matérielles ; épreuve", "def": "Serious difficulty caused by lack of money, resources or support.", "ex": "Many households face hardship during inflationary periods."}, {"term": "financial hardship", "ipa": "/faɪˌnænʃəl ˈhɑːdʃɪp/", "pron": "fy-NAN-shuhl HARD-ship", "fr": "difficultés financières", "def": "Difficulty paying for basic needs because of lack of money.", "ex": "Financial hardship can push families into debt."}, {"term": "cost-of-living crisis", "ipa": "/ˌkɒst əv ˈlɪvɪŋ ˈkraɪsɪs/", "pron": "kost ov LIV-ing KRY-sis", "fr": "crise du coût de la vie", "def": "A period when everyday expenses rise faster than incomes.", "ex": "The cost-of-living crisis has increased demand for food banks."}, {"term": "living standards", "ipa": "/ˈlɪvɪŋ ˌstændədz/", "pron": "LIV-ing STAN-duhdz", "fr": "niveau de vie", "def": "The material conditions in which people live.", "ex": "Falling living standards fuel public anger."}, {"term": "standard of living", "ipa": "/ˌstændəd əv ˈlɪvɪŋ/", "pron": "STAN-duhd ov LIV-ing", "fr": "niveau de vie", "def": "The level of comfort and material well-being available to a person or group.", "ex": "A decent standard of living should include housing, food and healthcare."}, {"term": "subsistence", "ipa": "/səbˈsɪstəns/", "pron": "suhb-SIS-tuhns", "fr": "subsistance", "def": "The minimum resources needed to stay alive.", "ex": "Some wages barely cover subsistence."}, {"term": "destitution", "ipa": "/ˌdestɪˈtjuːʃən/", "pron": "des-ti-TYOO-shuhn", "fr": "dénuement extrême", "def": "Extreme poverty with no means to meet basic needs.", "ex": "Destitution is a failure of the social safety net."}, {"term": "poverty line", "ipa": "/ˈpɒvəti laɪn/", "pron": "POV-uh-tee line", "fr": "seuil de pauvreté", "def": "The income level below which someone is considered poor.", "ex": "Many families live below the poverty line."}, {"term": "low-income household", "ipa": "/ˌləʊ ˈɪnkʌm ˈhaʊshəʊld/", "pron": "loh IN-kum HOWSS-hohld", "fr": "ménage à faible revenu", "def": "A household with limited income compared with the wider population.", "ex": "Low-income households are most affected by rising food prices."}, {"term": "household income", "ipa": "/ˌhaʊshəʊld ˈɪnkʌm/", "pron": "HOWSS-hohld IN-kum", "fr": "revenu du ménage", "def": "The total income of all people living in a household.", "ex": "Household income determines access to housing and services."}, {"term": "disposable income", "ipa": "/dɪˌspəʊzəbəl ˈɪnkʌm/", "pron": "di-SPOH-zuh-buhl IN-kum", "fr": "revenu disponible", "def": "Income left after taxes and essential deductions.", "ex": "Disposable income falls when energy bills rise."}, {"term": "real income", "ipa": "/ˌrɪəl ˈɪnkʌm/", "pron": "REE-uhl IN-kum", "fr": "revenu réel", "def": "Income adjusted for inflation.", "ex": "Real incomes can fall even when wages rise slightly."}, {"term": "median income", "ipa": "/ˌmiːdiən ˈɪnkʌm/", "pron": "MEE-dee-uhn IN-kum", "fr": "revenu médian", "def": "The income level in the middle of the income distribution.", "ex": "Relative poverty is often measured against median income."}, {"term": "income distribution", "ipa": "/ˈɪnkʌm ˌdɪstrɪˈbjuːʃən/", "pron": "IN-kum dis-tri-BYOO-shuhn", "fr": "répartition des revenus", "def": "The way income is spread across a population.", "ex": "Income distribution has become more unequal in many countries."}, {"term": "wealth distribution", "ipa": "/ˈwelθ ˌdɪstrɪˈbjuːʃən/", "pron": "welth dis-tri-BYOO-shuhn", "fr": "répartition du patrimoine", "def": "The way assets are spread across a population.", "ex": "Wealth distribution is shaped by inheritance and housing markets."}, {"term": "wealth gap", "ipa": "/ˈwelθ ɡæp/", "pron": "welth gap", "fr": "écart de patrimoine", "def": "The difference in wealth between groups.", "ex": "The wealth gap is a major barrier to social mobility."}, {"term": "racial wealth gap", "ipa": "/ˌreɪʃəl ˈwelθ ɡæp/", "pron": "RAY-shuhl welth gap", "fr": "écart de patrimoine racial", "def": "The difference in accumulated wealth between racial groups.", "ex": "The racial wealth gap reflects historical discrimination."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart salarial entre hommes et femmes", "def": "The difference between men’s and women’s average earnings.", "ex": "The gender pay gap contributes to women’s lower lifetime wealth."}]}, {"title": "C. Wealth, class and income distribution", "entries": [{"term": "pay gap", "ipa": "/ˈpeɪ ɡæp/", "pron": "pay gap", "fr": "écart de rémunération", "def": "A difference in pay between groups.", "ex": "Pay gaps can reveal discrimination or occupational segregation."}, {"term": "wage gap", "ipa": "/ˈweɪdʒ ɡæp/", "pron": "wayj gap", "fr": "écart de salaire", "def": "A difference in wages between workers or groups.", "ex": "The wage gap widened between high-skilled and low-skilled workers."}, {"term": "top earners", "ipa": "/ˌtɒp ˈɜːnəz/", "pron": "top UR-nuhz", "fr": "hauts revenus", "def": "People with the highest incomes.", "ex": "Top earners have captured a large share of income growth."}, {"term": "bottom earners", "ipa": "/ˌbɒtəm ˈɜːnəz/", "pron": "BOT-uhm UR-nuhz", "fr": "bas revenus", "def": "People with the lowest incomes.", "ex": "Bottom earners are vulnerable to inflation."}, {"term": "top one percent", "ipa": "/ˌtɒp wʌn pəˈsent/", "pron": "top wun puh-SENT", "fr": "1 % les plus riches", "def": "The richest one percent of the population.", "ex": "The top one percent owns a large share of wealth."}, {"term": "the super-rich", "ipa": "/ðə ˌsuːpə ˈrɪtʃ/", "pron": "thuh SOO-puh rich", "fr": "les ultra-riches", "def": "Extremely wealthy people.", "ex": "The super-rich often benefit from global tax planning."}, {"term": "high-net-worth individual", "ipa": "/ˌhaɪ net wɜːθ ˌɪndɪˈvɪdʒuəl/", "pron": "hy net worth in-di-VIJ-oo-uhl", "fr": "personne à très haut patrimoine", "def": "A person with very large financial assets.", "ex": "High-net-worth individuals may use complex wealth management strategies."}, {"term": "elite", "ipa": "/ɪˈliːt/", "pron": "i-LEET", "fr": "élite", "def": "A small group with significant power, wealth or status.", "ex": "Economic elites often have strong political influence."}, {"term": "underclass", "ipa": "/ˈʌndəklɑːs/", "pron": "UN-duh-klass", "fr": "sous-classe ; terme controversé", "def": "A controversial term for a very disadvantaged group seen as excluded from mainstream society.", "ex": "The term underclass can stigmatise poor communities."}, {"term": "class divide", "ipa": "/ˈklɑːs dɪˌvaɪd/", "pron": "klass di-VYDE", "fr": "fracture de classe", "def": "A social gap between classes.", "ex": "The class divide is visible in education and housing."}, {"term": "social stratification", "ipa": "/ˌsəʊʃəl ˌstrætɪfɪˈkeɪʃən/", "pron": "SOH-shuhl strat-i-fi-KAY-shuhn", "fr": "stratification sociale", "def": "The ranking of people into social layers based on wealth, power or status.", "ex": "Social stratification shapes life chances."}, {"term": "Gini coefficient", "ipa": "/ˈdʒiːni ˌkəʊɪˈfɪʃənt/", "pron": "JEE-nee koh-i-FISH-uhnt", "fr": "coefficient de Gini", "def": "A statistical measure of income or wealth inequality.", "ex": "A higher Gini coefficient indicates greater inequality."}, {"term": "poverty rate", "ipa": "/ˈpɒvəti reɪt/", "pron": "POV-uh-tee rayt", "fr": "taux de pauvreté", "def": "The percentage of people living in poverty.", "ex": "The poverty rate rose after cuts to welfare benefits."}, {"term": "income quintile", "ipa": "/ˈɪnkʌm ˈkwɪntaɪl/", "pron": "IN-kum KWIN-tyle", "fr": "quintile de revenu", "def": "One of five equal groups in the income distribution.", "ex": "Children from the lowest income quintile face more barriers."}, {"term": "income decile", "ipa": "/ˈɪnkʌm ˈdesaɪl/", "pron": "IN-kum DESS-yle", "fr": "décile de revenu", "def": "One of ten equal groups in the income distribution.", "ex": "The top income decile has benefited from rising asset prices."}, {"term": "social safety net", "ipa": "/ˌsəʊʃəl ˈseɪfti net/", "pron": "SOH-shuhl SAYF-tee net", "fr": "filet de sécurité sociale", "def": "Public support protecting people from poverty and hardship.", "ex": "A strong social safety net reduces extreme poverty."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system in which the state provides social protection and services.", "ex": "The welfare state reduces poverty through healthcare, education and benefits."}, {"term": "welfare", "ipa": "/ˈwelfeə/", "pron": "WEL-fair", "fr": "aide sociale ; prestations sociales", "def": "Government support for people in need.", "ex": "Welfare is often politically controversial."}, {"term": "benefits", "ipa": "/ˈbenɪfɪts/", "pron": "BEN-i-fits", "fr": "allocations ; prestations sociales", "def": "Payments or support provided by the state.", "ex": "Benefits help low-income households survive."}, {"term": "means-tested benefit", "ipa": "/ˈmiːnz testɪd ˈbenɪfɪt/", "pron": "meenz TEST-id BEN-i-fit", "fr": "prestation sous condition de ressources", "def": "A benefit available only to people below a certain income or wealth level.", "ex": "Means-tested benefits target the poorest households."}, {"term": "universal benefit", "ipa": "/ˌjuːnɪˈvɜːsəl ˈbenɪfɪt/", "pron": "yoo-ni-VUR-suhl BEN-i-fit", "fr": "prestation universelle", "def": "A benefit available to everyone in a category, regardless of income.", "ex": "Universal benefits can reduce stigma."}, {"term": "Universal Credit", "ipa": "/ˌjuːnɪˈvɜːsəl ˈkredɪt/", "pron": "yoo-ni-VUR-suhl KRED-it", "fr": "Universal Credit ; prestation sociale britannique", "def": "A UK benefit combining several forms of support for low-income or unemployed people.", "ex": "Universal Credit has been criticised for delays and sanctions."}, {"term": "food bank", "ipa": "/ˈfuːd bæŋk/", "pron": "food bank", "fr": "banque alimentaire", "def": "A charity or organisation distributing food to people in need.", "ex": "Food bank use has risen sharply in recent years."}, {"term": "emergency aid", "ipa": "/ɪˌmɜːdʒənsi ˈeɪd/", "pron": "i-MUR-juhn-see aid", "fr": "aide d’urgence", "def": "Urgent support given during crisis or hardship.", "ex": "Emergency aid cannot replace long-term poverty reduction."}]}, {"title": "D. Welfare, housing, debt and low-paid work", "entries": [{"term": "charity", "ipa": "/ˈtʃærəti/", "pron": "CHARR-uh-tee", "fr": "association caritative", "def": "An organisation that helps people or causes in need.", "ex": "Charities often fill gaps left by the state."}, {"term": "mutual aid", "ipa": "/ˌmjuːtʃuəl ˈeɪd/", "pron": "MYOO-choo-uhl aid", "fr": "entraide", "def": "Community support based on people helping each other.", "ex": "Mutual aid groups expanded during the pandemic."}, {"term": "social housing", "ipa": "/ˌsəʊʃəl ˈhaʊzɪŋ/", "pron": "SOH-shuhl HOW-zing", "fr": "logement social", "def": "Affordable housing provided by councils or housing associations.", "ex": "Social housing can reduce homelessness and insecurity."}, {"term": "council housing", "ipa": "/ˈkaʊnsəl ˌhaʊzɪŋ/", "pron": "KOWN-suhl HOW-zing", "fr": "logement municipal britannique", "def": "Public housing provided by local councils in Britain.", "ex": "Council housing was once a major part of the British welfare state."}, {"term": "affordable housing", "ipa": "/əˌfɔːdəbəl ˈhaʊzɪŋ/", "pron": "uh-FOR-duh-buhl HOW-zing", "fr": "logement abordable", "def": "Housing that people on ordinary incomes can afford.", "ex": "Affordable housing is essential for reducing inequality."}, {"term": "rent burden", "ipa": "/ˈrent ˌbɜːdən/", "pron": "rent BUR-duhn", "fr": "poids du loyer", "def": "A situation in which rent takes up a large share of income.", "ex": "Rent burden prevents families from saving."}, {"term": "eviction", "ipa": "/ɪˈvɪkʃən/", "pron": "i-VIK-shuhn", "fr": "expulsion locative", "def": "The forced removal of a tenant from a property.", "ex": "Eviction can push families into homelessness."}, {"term": "debt", "ipa": "/det/", "pron": "det", "fr": "dette", "def": "Money that is owed.", "ex": "Debt can trap low-income households."}, {"term": "personal debt", "ipa": "/ˌpɜːsənəl ˈdet/", "pron": "PUR-suh-nuhl det", "fr": "dette personnelle", "def": "Money owed by an individual or household.", "ex": "Personal debt rises when wages fail to cover essentials."}, {"term": "debt trap", "ipa": "/ˈdet træp/", "pron": "det trap", "fr": "piège de l’endettement", "def": "A situation where debt becomes difficult to escape.", "ex": "High-interest loans can create a debt trap."}, {"term": "payday loan", "ipa": "/ˈpeɪdeɪ ləʊn/", "pron": "PAY-day lohn", "fr": "prêt sur salaire", "def": "A short-term, high-interest loan due on the borrower’s next payday.", "ex": "Payday loans can worsen financial hardship."}, {"term": "financial exclusion", "ipa": "/faɪˌnænʃəl ɪkˈskluːʒən/", "pron": "fy-NAN-shuhl ik-SKLOO-zhuhn", "fr": "exclusion bancaire ; exclusion financière", "def": "Lack of access to banking, credit or financial services.", "ex": "Financial exclusion makes poverty more expensive."}, {"term": "poverty premium", "ipa": "/ˈpɒvəti ˌpriːmiəm/", "pron": "POV-uh-tee PREE-mee-uhm", "fr": "surcoût de la pauvreté", "def": "Extra costs paid by poor households for basic goods or services.", "ex": "The poverty premium means poor people often pay more for energy and credit."}, {"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal hourly pay.", "ex": "A higher minimum wage can reduce in-work poverty."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "Campaigners argue that workers need a living wage."}, {"term": "low-paid work", "ipa": "/ˌləʊ peɪd ˈwɜːk/", "pron": "loh payd work", "fr": "travail mal payé", "def": "Work with low wages.", "ex": "Low-paid work is often insecure and physically demanding."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "emploi précaire", "def": "Unstable or insecure work with little protection.", "ex": "Precarious work increases financial insecurity."}, {"term": "zero-hours contract", "ipa": "/ˌzɪərəʊ aʊəz ˈkɒntrækt/", "pron": "ZEER-oh ow-uhz KON-trakt", "fr": "contrat zéro heure", "def": "A contract with no guaranteed minimum working hours.", "ex": "Zero-hours contracts make income unpredictable."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots ; gig economy", "def": "A labour market based on short-term, freelance or platform work.", "ex": "The gig economy can create flexibility but also insecurity."}, {"term": "job insecurity", "ipa": "/ˈdʒɒb ˌɪnsɪˈkjʊərəti/", "pron": "job in-si-KYOOR-uh-tee", "fr": "insécurité de l’emploi", "def": "Uncertainty about keeping one’s job.", "ex": "Job insecurity damages mental health and planning."}, {"term": "wage stagnation", "ipa": "/ˈweɪdʒ stæɡˌneɪʃən/", "pron": "wayj stag-NAY-shuhn", "fr": "stagnation des salaires", "def": "A situation where wages do not rise significantly over time.", "ex": "Wage stagnation contributes to inequality."}, {"term": "underemployment", "ipa": "/ˌʌndərɪmˈplɔɪmənt/", "pron": "UN-duh-rim-PLOY-muhnt", "fr": "sous-emploi", "def": "Working fewer hours or in lower-skilled work than desired or qualified for.", "ex": "Underemployment can hide economic hardship."}, {"term": "unemployment", "ipa": "/ˌʌnɪmˈplɔɪmənt/", "pron": "un-im-PLOY-muhnt", "fr": "chômage", "def": "The state of being without a job while seeking work.", "ex": "Unemployment is a major cause of poverty."}, {"term": "long-term unemployment", "ipa": "/ˌlɒŋ tɜːm ˌʌnɪmˈplɔɪmənt/", "pron": "long-term un-im-PLOY-muhnt", "fr": "chômage de longue durée", "def": "Unemployment lasting for an extended period.", "ex": "Long-term unemployment can erode skills and confidence."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies aimed at reducing public spending, often through cuts to services and benefits.", "ex": "Austerity policies increased pressure on public services."}, {"term": "public spending", "ipa": "/ˌpʌblɪk ˈspendɪŋ/", "pron": "PUB-lik SPEN-ding", "fr": "dépenses publiques", "def": "Money spent by government on services, benefits and infrastructure.", "ex": "Public spending choices shape inequality."}, {"term": "spending cuts", "ipa": "/ˈspendɪŋ kʌts/", "pron": "SPEN-ding kuts", "fr": "coupes budgétaires", "def": "Reductions in government spending.", "ex": "Spending cuts can hit the poorest communities hardest."}, {"term": "taxation", "ipa": "/tækˈseɪʃən/", "pron": "tak-SAY-shuhn", "fr": "fiscalité ; imposition", "def": "The system of collecting money from people or companies to fund the state.", "ex": "Taxation is central to redistribution."}, {"term": "progressive taxation", "ipa": "/prəˌɡresɪv tækˈseɪʃən/", "pron": "pruh-GRESS-iv tak-SAY-shuhn", "fr": "impôt progressif", "def": "A tax system where richer people pay a higher share of income.", "ex": "Progressive taxation can reduce inequality."}, {"term": "regressive tax", "ipa": "/rɪˌɡresɪv ˈtæks/", "pron": "ri-GRESS-iv taks", "fr": "impôt régressif", "def": "A tax that takes a larger share of income from poorer people.", "ex": "Sales taxes can be regressive."}, {"term": "tax avoidance", "ipa": "/ˈtæks əˌvɔɪdəns/", "pron": "taks uh-VOID-uhns", "fr": "évitement fiscal", "def": "Legal methods used to reduce tax payments.", "ex": "Tax avoidance by the wealthy can undermine public trust."}, {"term": "tax evasion", "ipa": "/ˈtæks ɪˌveɪʒən/", "pron": "taks i-VAY-zhuhn", "fr": "fraude fiscale", "def": "Illegal non-payment or underpayment of taxes.", "ex": "Tax evasion reduces money available for public services."}, {"term": "tax haven", "ipa": "/ˈtæks ˌheɪvən/", "pron": "taks HAY-vuhn", "fr": "paradis fiscal", "def": "A place with very low taxes used to reduce tax bills.", "ex": "Tax havens allow wealth to be hidden offshore."}]}, {"title": "E. Policy, structural inequality and high-value verbs", "entries": [{"term": "redistribution", "ipa": "/ˌriːdɪstrɪˈbjuːʃən/", "pron": "ree-dis-tri-BYOO-shuhn", "fr": "redistribution", "def": "The transfer of resources through taxes and public spending.", "ex": "Redistribution can reduce poverty and inequality."}, {"term": "universal basic income", "ipa": "/ˌjuːnɪvɜːsəl ˌbeɪsɪk ˈɪnkʌm/", "pron": "yoo-ni-VUR-suhl BAY-sik IN-kum", "fr": "revenu universel de base", "def": "A regular payment given to all citizens regardless of work or income.", "ex": "Universal basic income is proposed as a response to insecurity."}, {"term": "wealth tax", "ipa": "/ˈwelθ tæks/", "pron": "welth taks", "fr": "impôt sur la fortune ; taxe sur le patrimoine", "def": "A tax on accumulated wealth rather than income.", "ex": "A wealth tax is often proposed to reduce inequality."}, {"term": "inheritance tax", "ipa": "/ɪnˈherɪtəns tæks/", "pron": "in-HER-i-tuhns taks", "fr": "droits de succession", "def": "A tax on wealth passed on after death.", "ex": "Inheritance tax is politically sensitive because it affects family wealth."}, {"term": "public services", "ipa": "/ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "PUB-lik SUR-vis-iz", "fr": "services publics", "def": "Services provided or funded by the state, such as health, education and transport.", "ex": "Strong public services can reduce inequality."}, {"term": "health inequality", "ipa": "/ˈhelθ ˌɪnɪˈkwɒləti/", "pron": "helth in-i-KWOL-uh-tee", "fr": "inégalité de santé", "def": "Unequal health outcomes between groups.", "ex": "Health inequality is strongly linked to poverty."}, {"term": "educational inequality", "ipa": "/ˌedjʊˈkeɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "ej-yoo-KAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité éducative", "def": "Unequal access to quality education or unequal educational outcomes.", "ex": "Educational inequality reproduces class divisions."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "Unequal access to internet, devices and digital skills.", "ex": "The digital divide worsens educational inequality."}, {"term": "intersectionality", "ipa": "/ˌɪntəsekʃəˈnæləti/", "pron": "IN-tuh-sek-shuh-NAL-uh-tee", "fr": "intersectionnalité", "def": "The way different forms of inequality combine, such as class, race and gender.", "ex": "Intersectionality helps explain why poverty affects groups differently."}, {"term": "structural inequality", "ipa": "/ˌstrʌktʃərəl ˌɪnɪˈkwɒləti/", "pron": "STRUK-chuh-ruhl in-i-KWOL-uh-tee", "fr": "inégalité structurelle", "def": "Inequality produced by institutions, policies and social structures.", "ex": "Structural inequality cannot be solved by individual effort alone."}, {"term": "systemic disadvantage", "ipa": "/sɪˌstemɪk ˌdɪsədˈvɑːntɪdʒ/", "pron": "si-STEM-ik dis-ad-VAN-tij", "fr": "désavantage systémique", "def": "Disadvantage built into systems and institutions.", "ex": "Systemic disadvantage limits social mobility."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity, background or status.", "ex": "Discrimination can deepen economic inequality."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes or positions.", "ex": "High inequality often reduces social mobility."}, {"term": "to live in poverty", "ipa": "/lɪv ɪn ˈpɒvəti/", "pron": "liv in POV-uh-tee", "fr": "vivre dans la pauvreté", "def": "To lack enough resources for basic needs.", "ex": "Millions of children live in poverty."}, {"term": "to fall into poverty", "ipa": "/fɔːl ˈɪntuː ˈpɒvəti/", "pron": "fall IN-too POV-uh-tee", "fr": "tomber dans la pauvreté", "def": "To become poor after a change such as job loss or illness.", "ex": "A sudden rent increase can make families fall into poverty."}, {"term": "to lift people out of poverty", "ipa": "/lɪft ˈpiːpəl aʊt əv ˈpɒvəti/", "pron": "lift PEE-puhl owt ov POV-uh-tee", "fr": "sortir les gens de la pauvreté", "def": "To help people escape poverty.", "ex": "Child benefits can lift families out of poverty."}, {"term": "to tackle poverty", "ipa": "/ˈtækəl ˈpɒvəti/", "pron": "TAK-uhl POV-uh-tee", "fr": "lutter contre la pauvreté", "def": "To take action to reduce poverty.", "ex": "Governments must tackle poverty with housing, wages and services."}, {"term": "to reduce inequality", "ipa": "/rɪˈdjuːs ˌɪnɪˈkwɒləti/", "pron": "ri-DYOOSS in-i-KWOL-uh-tee", "fr": "réduire les inégalités", "def": "To make inequality smaller.", "ex": "Progressive taxation can reduce inequality."}, {"term": "to widen inequality", "ipa": "/ˈwaɪdən ˌɪnɪˈkwɒləti/", "pron": "WY-duhn in-i-KWOL-uh-tee", "fr": "creuser les inégalités", "def": "To make inequality greater.", "ex": "Austerity can widen inequality."}, {"term": "to bridge the gap", "ipa": "/brɪdʒ ðə ɡæp/", "pron": "brij thuh gap", "fr": "combler l’écart", "def": "To reduce a difference between groups.", "ex": "Better school funding can bridge the gap."}, {"term": "to widen the gap", "ipa": "/ˈwaɪdən ðə ɡæp/", "pron": "WY-duhn thuh gap", "fr": "creuser l’écart", "def": "To increase a difference between groups.", "ex": "Rising asset prices widen the gap between owners and renters."}, {"term": "to make ends meet", "ipa": "/meɪk endz miːt/", "pron": "mayk endz meet", "fr": "joindre les deux bouts", "def": "To have enough money to pay for basic needs.", "ex": "Many working families struggle to make ends meet."}, {"term": "to live paycheck to paycheck", "ipa": "/lɪv ˈpeɪtʃek tə ˈpeɪtʃek/", "pron": "liv PAY-chek tuh PAY-chek", "fr": "vivre d’un salaire à l’autre", "def": "To spend nearly all income before the next wage payment arrives.", "ex": "Low-paid workers often live paycheck to paycheck."}, {"term": "to rely on food banks", "ipa": "/rɪˈlaɪ ɒn ˈfuːd bæŋks/", "pron": "ri-LY on food banks", "fr": "dépendre des banques alimentaires", "def": "To depend on food aid for survival.", "ex": "More families now rely on food banks."}, {"term": "to be priced out", "ipa": "/bi praɪst aʊt/", "pron": "bee pryst owt", "fr": "être exclu par les prix", "def": "To be unable to afford something because prices have become too high.", "ex": "Young people are priced out of the housing market."}, {"term": "to trap people in poverty", "ipa": "/træp ˈpiːpəl ɪn ˈpɒvəti/", "pron": "trap PEE-puhl in POV-uh-tee", "fr": "piéger les gens dans la pauvreté", "def": "To keep people unable to escape poverty.", "ex": "Debt and insecure work can trap people in poverty."}, {"term": "to break the cycle of poverty", "ipa": "/breɪk ðə ˌsaɪkəl əv ˈpɒvəti/", "pron": "brayk thuh SY-kuhl ov POV-uh-tee", "fr": "briser le cycle de la pauvreté", "def": "To stop poverty from passing from one generation to the next.", "ex": "Early childhood support can break the cycle of poverty."}, {"term": "to strengthen the safety net", "ipa": "/ˈstreŋθən ðə ˈseɪfti net/", "pron": "STRENG-thuhn thuh SAYF-tee net", "fr": "renforcer le filet de sécurité sociale", "def": "To improve public support for people in hardship.", "ex": "A crisis should be a reason to strengthen the safety net."}, {"term": "to redistribute wealth", "ipa": "/ˌriːdɪˈstrɪbjuːt welθ/", "pron": "ree-dis-TRIB-yoot welth", "fr": "redistribuer les richesses", "def": "To transfer wealth through taxes, services or benefits.", "ex": "Some voters support policies to redistribute wealth."}, {"term": "to address root causes", "ipa": "/əˈdres ruːt ˈkɔːzɪz/", "pron": "uh-DRESS root KAW-ziz", "fr": "s’attaquer aux causes profondes", "def": "To deal with the underlying reasons for a problem.", "ex": "Poverty policy must address root causes, not just symptoms."}]}]}, {"id": "p4c32", "part": 4, "chapter": 32, "title": "Housing", "file": "cpge_vocab_part4_chapter32_housing_premium.html", "count": 146, "sections": [{"title": "A. Core housing vocabulary and affordability", "entries": [{"term": "housing", "ipa": "/ˈhaʊzɪŋ/", "pron": "HOW-zing", "fr": "logement", "def": "Homes, flats and accommodation available for people to live in.", "ex": "Housing has become one of the central issues in modern societies."}, {"term": "housing crisis", "ipa": "/ˈhaʊzɪŋ ˈkraɪsɪs/", "pron": "HOW-zing KRY-sis", "fr": "crise du logement", "def": "A serious shortage or unaffordability of decent homes.", "ex": "The housing crisis affects renters, young people and low-income families."}, {"term": "housing market", "ipa": "/ˈhaʊzɪŋ ˌmɑːkɪt/", "pron": "HOW-zing MAR-kit", "fr": "marché du logement", "def": "The system through which homes are bought, sold and rented.", "ex": "The housing market has become increasingly unaffordable."}, {"term": "property market", "ipa": "/ˈprɒpəti ˌmɑːkɪt/", "pron": "PROP-uh-tee MAR-kit", "fr": "marché immobilier", "def": "The market for buying and selling land, houses and flats.", "ex": "The property market has widened the wealth gap."}, {"term": "real estate", "ipa": "/ˈrɪəl ɪˌsteɪt/", "pron": "REE-uhl i-STAYT", "fr": "immobilier", "def": "Property consisting of land and buildings.", "ex": "Real estate is a major source of wealth."}, {"term": "home", "ipa": "/həʊm/", "pron": "hohm", "fr": "foyer ; logement", "def": "A place where someone lives and feels secure or rooted.", "ex": "A home is more than a physical shelter."}, {"term": "house", "ipa": "/haʊs/", "pron": "howss", "fr": "maison", "def": "A building for people to live in, usually for one household.", "ex": "Owning a house has become harder for younger generations."}, {"term": "flat", "ipa": "/flæt/", "pron": "flat", "fr": "appartement", "def": "British English for an apartment.", "ex": "Many young professionals rent a flat in large cities."}, {"term": "apartment", "ipa": "/əˈpɑːtmənt/", "pron": "uh-PART-muhnt", "fr": "appartement", "def": "A set of rooms for living in, usually in a larger building.", "ex": "Apartment living is common in dense urban areas."}, {"term": "tenant", "ipa": "/ˈtenənt/", "pron": "TEN-uhnt", "fr": "locataire", "def": "A person who rents a home from a landlord.", "ex": "Tenants often face rent increases and insecurity."}, {"term": "landlord", "ipa": "/ˈlændlɔːd/", "pron": "LAND-lord", "fr": "propriétaire bailleur", "def": "A person or company that rents property to tenants.", "ex": "Landlords have been criticised for poor housing conditions."}, {"term": "homeowner", "ipa": "/ˈhəʊmˌəʊnə/", "pron": "HOHM-oh-nuh", "fr": "propriétaire occupant", "def": "A person who owns their home.", "ex": "Homeowners have benefited from rising house prices."}, {"term": "home ownership", "ipa": "/ˈhəʊm ˌəʊnəʃɪp/", "pron": "HOHM OH-nuh-ship", "fr": "propriété immobilière ; accession à la propriété", "def": "The state of owning one’s home.", "ex": "Home ownership is a major source of wealth accumulation."}, {"term": "owner-occupier", "ipa": "/ˌəʊnər ˈɒkjʊpaɪə/", "pron": "OH-nuh OK-yuh-py-uh", "fr": "propriétaire occupant", "def": "Someone who owns and lives in their home.", "ex": "Owner-occupiers often benefit from property price rises."}, {"term": "renter", "ipa": "/ˈrentə/", "pron": "REN-tuh", "fr": "locataire", "def": "A person who pays to live in a property they do not own.", "ex": "Renters often have less security than homeowners."}, {"term": "private renter", "ipa": "/ˌpraɪvət ˈrentə/", "pron": "PRY-vuht REN-tuh", "fr": "locataire du parc privé", "def": "A person who rents from a private landlord.", "ex": "Private renters are exposed to market rents."}, {"term": "social tenant", "ipa": "/ˌsəʊʃəl ˈtenənt/", "pron": "SOH-shuhl TEN-uhnt", "fr": "locataire du logement social", "def": "A person renting social housing.", "ex": "Social tenants usually pay below-market rents."}, {"term": "mortgage", "ipa": "/ˈmɔːɡɪdʒ/", "pron": "MOR-gij", "fr": "prêt immobilier ; hypothèque", "def": "A loan used to buy a home, repaid over time.", "ex": "Higher interest rates make mortgages more expensive."}, {"term": "deposit", "ipa": "/dɪˈpɒzɪt/", "pron": "di-POZ-it", "fr": "apport ; dépôt de garantie", "def": "Money paid upfront to buy a home or secure a rental property.", "ex": "Saving for a deposit is difficult for many young adults."}, {"term": "down payment", "ipa": "/ˌdaʊn ˈpeɪmənt/", "pron": "down PAY-muhnt", "fr": "apport initial", "def": "US term for money paid upfront when buying a home.", "ex": "A large down payment is often required to buy property."}, {"term": "rent", "ipa": "/rent/", "pron": "rent", "fr": "loyer", "def": "Money paid regularly to live in someone else’s property.", "ex": "Rent has risen faster than wages in many cities."}, {"term": "rent increase", "ipa": "/ˈrent ˌɪnkriːs/", "pron": "rent IN-kreess", "fr": "augmentation de loyer", "def": "A rise in the amount of rent tenants must pay.", "ex": "Rent increases can force families to move."}, {"term": "rent burden", "ipa": "/ˈrent ˌbɜːdən/", "pron": "rent BUR-duhn", "fr": "poids du loyer", "def": "A situation where rent takes up a large share of income.", "ex": "Rent burden prevents households from saving."}, {"term": "housing cost", "ipa": "/ˈhaʊzɪŋ kɒst/", "pron": "HOW-zing kost", "fr": "coût du logement", "def": "The money spent on rent, mortgage payments, bills and housing-related expenses.", "ex": "Housing costs have become a major driver of poverty."}, {"term": "housing affordability", "ipa": "/ˈhaʊzɪŋ əˌfɔːd əˈbɪləti/", "pron": "HOW-zing uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière du logement", "def": "The extent to which people can afford decent housing.", "ex": "Housing affordability has deteriorated in many urban areas."}, {"term": "affordable housing", "ipa": "/əˌfɔːdəbəl ˈhaʊzɪŋ/", "pron": "uh-FOR-duh-buhl HOW-zing", "fr": "logement abordable", "def": "Housing that people on ordinary or low incomes can afford.", "ex": "Affordable housing is essential for social stability."}, {"term": "social housing", "ipa": "/ˌsəʊʃəl ˈhaʊzɪŋ/", "pron": "SOH-shuhl HOW-zing", "fr": "logement social", "def": "Affordable housing provided by councils or housing associations.", "ex": "Social housing can reduce homelessness and insecurity."}, {"term": "council housing", "ipa": "/ˈkaʊnsəl ˌhaʊzɪŋ/", "pron": "KOWN-suhl HOW-zing", "fr": "logement municipal britannique", "def": "Public housing provided by local councils in Britain.", "ex": "Council housing was once central to the British welfare state."}, {"term": "public housing", "ipa": "/ˌpʌblɪk ˈhaʊzɪŋ/", "pron": "PUB-lik HOW-zing", "fr": "logement public", "def": "Housing provided or funded by the state, especially in the US.", "ex": "Public housing is often underfunded and stigmatised."}, {"term": "housing association", "ipa": "/ˈhaʊzɪŋ əˌsəʊsiˈeɪʃən/", "pron": "HOW-zing uh-soh-see-AY-shuhn", "fr": "organisme de logement social", "def": "A non-profit organisation providing affordable or social housing.", "ex": "Housing associations manage many affordable homes."}, {"term": "subsidised housing", "ipa": "/ˈsʌbsɪdaɪzd ˈhaʊzɪŋ/", "pron": "SUB-si-dyzd HOW-zing", "fr": "logement subventionné", "def": "Housing made cheaper through public financial support.", "ex": "Subsidised housing helps low-income families."}, {"term": "rent control", "ipa": "/ˈrent kənˌtrəʊl/", "pron": "rent kuhn-TROHL", "fr": "encadrement des loyers", "def": "Rules limiting how much landlords can raise rents.", "ex": "Rent control is debated as a solution to unaffordable housing."}, {"term": "rent cap", "ipa": "/ˈrent kæp/", "pron": "rent kap", "fr": "plafonnement des loyers", "def": "A maximum limit on rent or rent increases.", "ex": "A rent cap can protect tenants from sudden increases."}, {"term": "housing benefit", "ipa": "/ˈhaʊzɪŋ ˌbenɪfɪt/", "pron": "HOW-zing BEN-i-fit", "fr": "allocation logement", "def": "State support helping low-income people pay rent.", "ex": "Housing benefit can prevent homelessness."}, {"term": "local housing allowance", "ipa": "/ˌləʊkəl ˈhaʊzɪŋ əˈlaʊəns/", "pron": "LOH-kuhl HOW-zing uh-LOW-uhns", "fr": "allocation logement locale britannique", "def": "UK support used to help private renters on low incomes pay rent.", "ex": "Local housing allowance often fails to match market rents."}, {"term": "right to buy", "ipa": "/ˌraɪt tə ˈbaɪ/", "pron": "rite tuh buy", "fr": "Right to Buy ; droit d’achat du logement social", "def": "A UK policy allowing council tenants to buy their homes at a discount.", "ex": "Right to Buy reduced the stock of council housing."}]}, {"title": "B. Housing supply, planning and urban change", "entries": [{"term": "housing stock", "ipa": "/ˈhaʊzɪŋ stɒk/", "pron": "HOW-zing stok", "fr": "parc de logements", "def": "The total number of homes available in an area or country.", "ex": "The social housing stock has declined in many areas."}, {"term": "housing supply", "ipa": "/ˈhaʊzɪŋ səˌplaɪ/", "pron": "HOW-zing suh-PLY", "fr": "offre de logements", "def": "The number of homes available to buy or rent.", "ex": "A lack of housing supply pushes prices up."}, {"term": "housing demand", "ipa": "/ˈhaʊzɪŋ dɪˌmɑːnd/", "pron": "HOW-zing di-MAND", "fr": "demande de logements", "def": "The number of people wanting homes in a place.", "ex": "Housing demand is high in major cities."}, {"term": "shortage of homes", "ipa": "/ˈʃɔːtɪdʒ əv həʊmz/", "pron": "SHOR-tij ov hohmz", "fr": "pénurie de logements", "def": "A lack of enough homes for the population.", "ex": "The shortage of homes has driven up rents."}, {"term": "housing shortage", "ipa": "/ˈhaʊzɪŋ ˌʃɔːtɪdʒ/", "pron": "HOW-zing SHOR-tij", "fr": "pénurie de logements", "def": "A lack of sufficient housing.", "ex": "The housing shortage is particularly acute in London."}, {"term": "new-build housing", "ipa": "/ˌnjuː bɪld ˈhaʊzɪŋ/", "pron": "nyoo-bild HOW-zing", "fr": "logements neufs", "def": "Recently constructed housing.", "ex": "New-build housing is often marketed as a solution to shortages."}, {"term": "housebuilding", "ipa": "/ˈhaʊsˌbɪldɪŋ/", "pron": "HOWSS-bil-ding", "fr": "construction de logements", "def": "The construction of new homes.", "ex": "Housebuilding has not kept pace with demand."}, {"term": "planning permission", "ipa": "/ˈplænɪŋ pəˌmɪʃən/", "pron": "PLAN-ing puh-MISH-uhn", "fr": "permis de construire", "def": "Official approval to build or change buildings.", "ex": "Planning permission can delay new housing projects."}, {"term": "zoning", "ipa": "/ˈzəʊnɪŋ/", "pron": "ZOH-ning", "fr": "zonage", "def": "Rules controlling how land can be used.", "ex": "Zoning restrictions can limit housing supply."}, {"term": "land use", "ipa": "/ˈlænd juːs/", "pron": "land yooss", "fr": "usage des sols", "def": "The way land is used for housing, business, farming or public space.", "ex": "Land use policy affects housing affordability."}, {"term": "green belt", "ipa": "/ˌɡriːn ˈbelt/", "pron": "green belt", "fr": "ceinture verte", "def": "Protected land around cities where building is restricted.", "ex": "Green belt policy is controversial in housing debates."}, {"term": "urban sprawl", "ipa": "/ˌɜːbən ˈsprɔːl/", "pron": "UR-buhn sprawl", "fr": "étalement urbain", "def": "Uncontrolled expansion of cities into surrounding areas.", "ex": "Urban sprawl can damage the environment and increase car dependence."}, {"term": "densification", "ipa": "/ˌdensɪfɪˈkeɪʃən/", "pron": "den-si-fi-KAY-shuhn", "fr": "densification", "def": "Increasing the number of homes or people in an urban area.", "ex": "Densification can create more homes near jobs and transport."}, {"term": "high-rise building", "ipa": "/ˌhaɪ raɪz ˈbɪldɪŋ/", "pron": "hy-ryze BIL-ding", "fr": "immeuble de grande hauteur", "def": "A very tall building with many floors.", "ex": "High-rise buildings can provide density but raise safety concerns."}, {"term": "housing development", "ipa": "/ˈhaʊzɪŋ dɪˌveləpmənt/", "pron": "HOW-zing di-VEL-uhp-muhnt", "fr": "programme immobilier résidentiel", "def": "A planned group of new homes.", "ex": "New housing developments often face local opposition."}, {"term": "real-estate developer", "ipa": "/ˈrɪəl ɪˌsteɪt dɪˌveləpə/", "pron": "REE-uhl i-STAYT di-VEL-uh-puh", "fr": "promoteur immobilier", "def": "A person or company that builds or renovates property for profit.", "ex": "Real-estate developers are often accused of prioritising profit."}, {"term": "NIMBY", "ipa": "/ˈnɪmbi/", "pron": "NIM-bee", "fr": "NIMBY ; opposant local à un projet", "def": "Someone who opposes development near where they live; from “Not In My Back Yard.”", "ex": "NIMBY opposition can block new housing."}, {"term": "YIMBY", "ipa": "/ˈjɪmbi/", "pron": "YIM-bee", "fr": "YIMBY ; partisan de la construction locale", "def": "Someone who supports more housing development; from “Yes In My Back Yard.”", "ex": "YIMBY activists call for more homes in high-demand areas."}, {"term": "gentrification", "ipa": "/ˌdʒentrɪfɪˈkeɪʃən/", "pron": "jen-tri-fi-KAY-shuhn", "fr": "gentrification", "def": "The transformation of a poorer area by wealthier residents, often raising prices and displacing locals.", "ex": "Gentrification can bring investment but also displacement."}, {"term": "displacement", "ipa": "/dɪsˈpleɪsmənt/", "pron": "dis-PLAYS-muhnt", "fr": "déplacement forcé ; éviction sociale", "def": "The forced movement of residents due to rising costs or redevelopment.", "ex": "Displacement often affects low-income communities."}, {"term": "regeneration", "ipa": "/rɪˌdʒenəˈreɪʃən/", "pron": "ri-JEN-uh-RAY-shuhn", "fr": "régénération urbaine", "def": "Investment and renewal in a declining urban area.", "ex": "Urban regeneration can improve areas but may exclude existing residents."}, {"term": "urban renewal", "ipa": "/ˌɜːbən rɪˈnjuːəl/", "pron": "UR-buhn ri-NYOO-uhl", "fr": "rénovation urbaine", "def": "The redevelopment of urban areas, often replacing old buildings.", "ex": "Urban renewal has sometimes destroyed working-class communities."}, {"term": "neighbourhood", "ipa": "/ˈneɪbəhʊd/", "pron": "NAY-buh-hood", "fr": "quartier", "def": "A local area where people live.", "ex": "Neighbourhood quality affects life chances."}, {"term": "deprived area", "ipa": "/dɪˌpraɪvd ˈeəriə/", "pron": "di-PRYVD AIR-ee-uh", "fr": "quartier défavorisé", "def": "An area lacking resources, services and opportunities.", "ex": "Deprived areas often face poor housing and underfunded services."}, {"term": "deprived neighbourhood", "ipa": "/dɪˌpraɪvd ˈneɪbəhʊd/", "pron": "di-PRYVD NAY-buh-hood", "fr": "quartier défavorisé", "def": "A neighbourhood affected by poverty and lack of services.", "ex": "Children in deprived neighbourhoods face multiple barriers."}, {"term": "inner city", "ipa": "/ˌɪnə ˈsɪti/", "pron": "IN-uh SIT-ee", "fr": "centre-ville populaire ; quartiers centraux", "def": "The central area of a city, often associated with poverty or density in some contexts.", "ex": "Inner-city housing has changed through gentrification."}, {"term": "suburb", "ipa": "/ˈsʌbɜːb/", "pron": "SUB-urb", "fr": "banlieue résidentielle", "def": "A residential area outside the centre of a city.", "ex": "Suburbs are often associated with home ownership."}, {"term": "suburbanisation", "ipa": "/səˌbɜːbənaɪˈzeɪʃən/", "pron": "suh-BUR-buh-ny-ZAY-shuhn", "fr": "périurbanisation ; suburbanisation", "def": "The growth of suburbs as people move away from city centres.", "ex": "Suburbanisation has reshaped commuting and housing patterns."}, {"term": "urban poverty", "ipa": "/ˌɜːbən ˈpɒvəti/", "pron": "UR-buhn POV-uh-tee", "fr": "pauvreté urbaine", "def": "Poverty concentrated in cities.", "ex": "Urban poverty is often linked to housing costs."}, {"term": "rural housing crisis", "ipa": "/ˌrʊərəl ˈhaʊzɪŋ ˈkraɪsɪs/", "pron": "ROOR-uhl HOW-zing KRY-sis", "fr": "crise du logement rural", "def": "A shortage or unaffordability of homes in rural areas.", "ex": "Second homes can worsen the rural housing crisis."}, {"term": "second home", "ipa": "/ˌsekənd ˈhəʊm/", "pron": "SEK-uhnd hohm", "fr": "résidence secondaire", "def": "A home owned in addition to a main residence.", "ex": "Second homes can price local residents out of rural areas."}, {"term": "holiday let", "ipa": "/ˈhɒlədeɪ let/", "pron": "HOL-uh-day let", "fr": "location saisonnière", "def": "A property rented to tourists for short stays.", "ex": "Holiday lets reduce the supply of homes for local residents."}]}, {"title": "C. Insecurity, conditions and homelessness", "entries": [{"term": "short-term rental", "ipa": "/ˌʃɔːt tɜːm ˈrentəl/", "pron": "short-term REN-tuhl", "fr": "location courte durée", "def": "A property rented for a short period, often through online platforms.", "ex": "Short-term rentals can push up rents in tourist cities."}, {"term": "Airbnb effect", "ipa": "/ˈeəbienbi ɪˌfekt/", "pron": "AIR-bee-en-bee i-FEKT", "fr": "effet Airbnb", "def": "The impact of short-term rentals on housing supply, rents and neighbourhoods.", "ex": "The Airbnb effect is controversial in major cities."}, {"term": "housing insecurity", "ipa": "/ˈhaʊzɪŋ ˌɪnsɪˈkjʊərəti/", "pron": "HOW-zing in-si-KYOOR-uh-tee", "fr": "précarité du logement", "def": "Unstable, unaffordable or unsafe housing.", "ex": "Housing insecurity affects work, health and education."}, {"term": "tenure insecurity", "ipa": "/ˈtenjə ˌɪnsɪˈkjʊərəti/", "pron": "TEN-yuh in-si-KYOOR-uh-tee", "fr": "insécurité résidentielle", "def": "Lack of security about staying in one’s home.", "ex": "Short leases create tenure insecurity for renters."}, {"term": "eviction", "ipa": "/ɪˈvɪkʃən/", "pron": "i-VIK-shuhn", "fr": "expulsion locative", "def": "The forced removal of a tenant from a property.", "ex": "Eviction can push families into homelessness."}, {"term": "no-fault eviction", "ipa": "/ˌnəʊ fɔːlt ɪˈvɪkʃən/", "pron": "noh-fawlt i-VIK-shuhn", "fr": "expulsion sans faute", "def": "An eviction where tenants can be asked to leave without being blamed for wrongdoing.", "ex": "No-fault evictions are criticised for creating insecurity."}, {"term": "eviction notice", "ipa": "/ɪˈvɪkʃən ˌnəʊtɪs/", "pron": "i-VIK-shuhn NOH-tis", "fr": "avis d’expulsion", "def": "An official notice telling a tenant to leave a property.", "ex": "An eviction notice can trigger a homelessness crisis."}, {"term": "arrears", "ipa": "/əˈrɪəz/", "pron": "uh-REERZ", "fr": "arriérés", "def": "Money that is owed and overdue, especially rent or mortgage payments.", "ex": "Rent arrears can lead to eviction."}, {"term": "rent arrears", "ipa": "/ˈrent əˌrɪəz/", "pron": "rent uh-REERZ", "fr": "arriérés de loyer", "def": "Overdue rent owed to a landlord.", "ex": "Rent arrears rose during the cost-of-living crisis."}, {"term": "mortgage arrears", "ipa": "/ˈmɔːɡɪdʒ əˌrɪəz/", "pron": "MOR-gij uh-REERZ", "fr": "arriérés de prêt immobilier", "def": "Overdue mortgage payments.", "ex": "Mortgage arrears can lead to repossession."}, {"term": "repossession", "ipa": "/ˌriːpəˈzeʃən/", "pron": "ree-puh-ZESH-uhn", "fr": "saisie immobilière", "def": "The process by which a lender takes back a home when mortgage payments are not made.", "ex": "Repossession is a risk when households cannot meet mortgage payments."}, {"term": "overcrowding", "ipa": "/ˌəʊvəˈkraʊdɪŋ/", "pron": "OH-vuh-KROW-ding", "fr": "surpeuplement", "def": "Too many people living in too little space.", "ex": "Overcrowding damages health and children’s education."}, {"term": "overcrowded housing", "ipa": "/ˌəʊvəˌkraʊdɪd ˈhaʊzɪŋ/", "pron": "OH-vuh-KROW-did HOW-zing", "fr": "logement surpeuplé", "def": "Housing with too many residents for the available space.", "ex": "Overcrowded housing is common among low-income families."}, {"term": "poor housing conditions", "ipa": "/ˌpɔː ˈhaʊzɪŋ kənˌdɪʃənz/", "pron": "poor HOW-zing kuhn-DISH-uhnz", "fr": "mauvaises conditions de logement", "def": "Unsafe, unhealthy or inadequate conditions in a home.", "ex": "Poor housing conditions worsen respiratory illness."}, {"term": "substandard housing", "ipa": "/ˌsʌbˈstændəd ˈhaʊzɪŋ/", "pron": "sub-STAN-duhd HOW-zing", "fr": "logement insalubre ou non conforme", "def": "Housing below acceptable quality or safety standards.", "ex": "Substandard housing is often found in neglected rental markets."}, {"term": "damp", "ipa": "/dæmp/", "pron": "damp", "fr": "humidité", "def": "Moisture in walls or buildings, often causing health problems.", "ex": "Damp can trigger asthma and other health issues."}, {"term": "mould", "ipa": "/məʊld/", "pron": "mohld", "fr": "moisissure", "def": "Fungal growth caused by damp, often harmful to health.", "ex": "Mould in housing is a serious public health issue."}, {"term": "insulation", "ipa": "/ˌɪnsjʊˈleɪʃən/", "pron": "IN-syuh-LAY-shuhn", "fr": "isolation", "def": "Material that keeps heat inside a building.", "ex": "Poor insulation increases energy bills."}, {"term": "energy efficiency", "ipa": "/ˈenədʒi ɪˌfɪʃənsi/", "pron": "EN-uh-jee i-FISH-uhn-see", "fr": "efficacité énergétique", "def": "Using less energy to provide the same heating, lighting or comfort.", "ex": "Energy efficiency can reduce fuel poverty."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford adequate heating or energy.", "ex": "Fuel poverty is linked to poor insulation and low incomes."}, {"term": "homelessness", "ipa": "/ˈhəʊmləsnəs/", "pron": "HOHM-luhs-nuhs", "fr": "sans-abrisme ; absence de logement", "def": "The condition of having no stable or safe home.", "ex": "Homelessness is both a housing and poverty issue."}, {"term": "rough sleeping", "ipa": "/ˌrʌf ˈsliːpɪŋ/", "pron": "ruff SLEE-ping", "fr": "sans-abrisme de rue", "def": "Sleeping outside because one has no home.", "ex": "Rough sleeping is the most visible form of homelessness."}, {"term": "hidden homelessness", "ipa": "/ˌhɪdən ˈhəʊmləsnəs/", "pron": "HID-uhn HOHM-luhs-nuhs", "fr": "sans-abrisme caché", "def": "Homelessness not visible in official counts, such as staying temporarily with others.", "ex": "Hidden homelessness is difficult to measure."}, {"term": "temporary accommodation", "ipa": "/ˌtempərəri əˌkɒməˈdeɪʃən/", "pron": "TEM-puh-ruh-ree uh-kom-uh-DAY-shuhn", "fr": "hébergement temporaire", "def": "Short-term housing provided to people without a permanent home.", "ex": "Many families spend months in temporary accommodation."}, {"term": "emergency shelter", "ipa": "/ɪˌmɜːdʒənsi ˈʃeltə/", "pron": "i-MUR-juhn-see SHEL-tuh", "fr": "hébergement d’urgence", "def": "A place providing urgent short-term accommodation.", "ex": "Emergency shelters save lives but do not solve homelessness."}, {"term": "shelter", "ipa": "/ˈʃeltə/", "pron": "SHEL-tuh", "fr": "abri ; centre d’hébergement", "def": "A place giving protection or accommodation.", "ex": "A shelter can provide immediate help to rough sleepers."}, {"term": "social cleansing", "ipa": "/ˌsəʊʃəl ˈklenzɪŋ/", "pron": "SOH-shuhl KLEN-zing", "fr": "nettoyage social ; éviction des classes populaires", "def": "A critical term for pushing poorer residents out of valuable urban areas.", "ex": "Critics say some regeneration projects amount to social cleansing."}, {"term": "right to housing", "ipa": "/ˌraɪt tə ˈhaʊzɪŋ/", "pron": "rite tuh HOW-zing", "fr": "droit au logement", "def": "The idea that everyone should have access to adequate housing as a basic right.", "ex": "Housing campaigners argue for a right to housing."}]}, {"title": "D. Policy, investment and property markets", "entries": [{"term": "housing justice", "ipa": "/ˈhaʊzɪŋ ˌdʒʌstɪs/", "pron": "HOW-zing JUS-tis", "fr": "justice du logement", "def": "Fair access to safe, affordable and stable housing.", "ex": "Housing justice links housing to inequality and human rights."}, {"term": "tenant rights", "ipa": "/ˌtenənt ˈraɪts/", "pron": "TEN-uhnt rites", "fr": "droits des locataires", "def": "Legal protections and rights for renters.", "ex": "Stronger tenant rights can reduce exploitation."}, {"term": "renters’ rights", "ipa": "/ˈrentəz raɪts/", "pron": "REN-tuhz rites", "fr": "droits des locataires", "def": "Rights protecting people who rent their homes.", "ex": "Renters’ rights have become a major political issue."}, {"term": "landlord regulation", "ipa": "/ˈlændlɔːd ˌreɡjʊˈleɪʃən/", "pron": "LAND-lord reg-yuh-LAY-shuhn", "fr": "réglementation des propriétaires bailleurs", "def": "Rules controlling landlord behaviour and housing standards.", "ex": "Landlord regulation aims to improve rental conditions."}, {"term": "housing policy", "ipa": "/ˈhaʊzɪŋ ˌpɒləsi/", "pron": "HOW-zing POL-uh-see", "fr": "politique du logement", "def": "Government action on housing supply, affordability, rights and homelessness.", "ex": "Housing policy must balance supply, affordability and tenant protection."}, {"term": "urban policy", "ipa": "/ˈɜːbən ˌpɒləsi/", "pron": "UR-buhn POL-uh-see", "fr": "politique urbaine", "def": "Government policy concerning cities and urban life.", "ex": "Urban policy shapes transport, housing and public space."}, {"term": "local authority", "ipa": "/ˌləʊkəl ɔːˈθɒrəti/", "pron": "LOH-kuhl aw-THOR-uh-tee", "fr": "collectivité locale ; autorité locale", "def": "A local government body responsible for services in an area.", "ex": "Local authorities play a major role in homelessness support."}, {"term": "housing waiting list", "ipa": "/ˈhaʊzɪŋ ˈweɪtɪŋ lɪst/", "pron": "HOW-zing WAY-ting list", "fr": "liste d’attente pour un logement social", "def": "A list of people waiting for social housing.", "ex": "Housing waiting lists are extremely long in many cities."}, {"term": "housing allocation", "ipa": "/ˈhaʊzɪŋ ˌæləˈkeɪʃən/", "pron": "HOW-zing al-uh-KAY-shuhn", "fr": "attribution de logements", "def": "The process of deciding who receives available social housing.", "ex": "Housing allocation often prioritises need."}, {"term": "section 8 voucher", "ipa": "/ˌsekʃən ˈeɪt ˈvaʊtʃə/", "pron": "SEK-shuhn ayt VOW-chuh", "fr": "voucher logement Section 8 américain", "def": "A US housing voucher helping low-income tenants pay rent.", "ex": "Section 8 vouchers help tenants access private rentals."}, {"term": "housing voucher", "ipa": "/ˈhaʊzɪŋ ˈvaʊtʃə/", "pron": "HOW-zing VOW-chuh", "fr": "aide au logement sous forme de bon", "def": "Financial support that helps low-income households rent housing.", "ex": "Housing vouchers can reduce rent burden."}, {"term": "public-private partnership", "ipa": "/ˌpʌblɪk ˌpraɪvət ˈpɑːtnəʃɪp/", "pron": "PUB-lik PRY-vuht PART-nuh-ship", "fr": "partenariat public-privé", "def": "Cooperation between government and private companies to deliver projects.", "ex": "Public-private partnerships are used in urban development."}, {"term": "community land trust", "ipa": "/kəˌmjuːnəti ˈlænd trʌst/", "pron": "kuh-MYOO-nuh-tee land trust", "fr": "foncière communautaire ; community land trust", "def": "A community-led organisation owning land to provide affordable housing.", "ex": "Community land trusts keep homes affordable over time."}, {"term": "co-operative housing", "ipa": "/kəʊˌɒpərətɪv ˈhaʊzɪŋ/", "pron": "koh-OP-uh-ruh-tiv HOW-zing", "fr": "habitat coopératif", "def": "Housing owned or managed collectively by residents.", "ex": "Co-operative housing gives residents more control."}, {"term": "build-to-rent", "ipa": "/ˌbɪld tə ˈrent/", "pron": "bild tuh rent", "fr": "logements construits pour la location", "def": "Housing built specifically for rental rather than sale.", "ex": "Build-to-rent schemes are growing in major cities."}, {"term": "buy-to-let", "ipa": "/ˌbaɪ tə ˈlet/", "pron": "by tuh let", "fr": "achat pour louer", "def": "Buying property in order to rent it out.", "ex": "Buy-to-let investment has been blamed for reducing affordability."}, {"term": "property investor", "ipa": "/ˈprɒpəti ɪnˌvestə/", "pron": "PROP-uh-tee in-VES-tuh", "fr": "investisseur immobilier", "def": "A person or company that buys property to make profit.", "ex": "Property investors can drive up prices in popular areas."}, {"term": "speculation", "ipa": "/ˌspekjʊˈleɪʃən/", "pron": "spek-yuh-LAY-shuhn", "fr": "spéculation", "def": "Buying assets hoping their value will rise.", "ex": "Property speculation can make housing less affordable."}, {"term": "empty home", "ipa": "/ˌempti ˈhəʊm/", "pron": "EMP-tee hohm", "fr": "logement vacant", "def": "A property left unoccupied.", "ex": "Empty homes are controversial during a housing crisis."}, {"term": "vacancy", "ipa": "/ˈveɪkənsi/", "pron": "VAY-kuhn-see", "fr": "vacance ; logement disponible", "def": "An empty property or available rental unit.", "ex": "Low vacancy rates push rents upward."}, {"term": "property tax", "ipa": "/ˈprɒpəti tæks/", "pron": "PROP-uh-tee taks", "fr": "taxe foncière ; impôt immobilier", "def": "A tax on property or land ownership.", "ex": "Property taxes can influence housing markets."}, {"term": "mansion tax", "ipa": "/ˈmænʃən tæks/", "pron": "MAN-shuhn taks", "fr": "taxe sur les grandes fortunes immobilières", "def": "A proposed tax on very expensive homes.", "ex": "A mansion tax is often proposed as a way to reduce wealth inequality."}, {"term": "stamp duty", "ipa": "/ˌstæmp ˈdjuːti/", "pron": "stamp DYOO-tee", "fr": "droit de timbre immobilier britannique", "def": "A UK tax paid when buying property above a certain price.", "ex": "Stamp duty affects the cost of buying a home."}, {"term": "housing bubble", "ipa": "/ˈhaʊzɪŋ ˌbʌbəl/", "pron": "HOW-zing BUB-uhl", "fr": "bulle immobilière", "def": "A rapid rise in house prices that may not be sustainable.", "ex": "A housing bubble can burst and damage the economy."}, {"term": "property ladder", "ipa": "/ˈprɒpəti ˌlædə/", "pron": "PROP-uh-tee LAD-uh", "fr": "échelle immobilière", "def": "The progression from buying a first home to more valuable property.", "ex": "Young people struggle to get onto the property ladder."}, {"term": "first-time buyer", "ipa": "/ˌfɜːst taɪm ˈbaɪə/", "pron": "first-time BY-uh", "fr": "primo-accédant", "def": "A person buying their first home.", "ex": "First-time buyers often depend on family help."}, {"term": "generation rent", "ipa": "/ˌdʒenəˈreɪʃən ˈrent/", "pron": "jen-uh-RAY-shuhn rent", "fr": "génération location", "def": "Young adults who are unable to buy homes and remain renters.", "ex": "Generation rent faces insecurity and delayed wealth accumulation."}, {"term": "housing ladder", "ipa": "/ˈhaʊzɪŋ ˌlædə/", "pron": "HOW-zing LAD-uh", "fr": "échelle du logement", "def": "Another term for the property ladder.", "ex": "Rising prices make the housing ladder harder to climb."}, {"term": "negative equity", "ipa": "/ˌneɡətɪv ˈekwəti/", "pron": "NEG-uh-tiv EK-wuh-tee", "fr": "valeur nette négative", "def": "A situation where a home is worth less than the mortgage owed on it.", "ex": "Negative equity can trap homeowners after a price crash."}, {"term": "interest rate", "ipa": "/ˈɪntrəst reɪt/", "pron": "IN-truhst rayt", "fr": "taux d’intérêt", "def": "The cost of borrowing money, expressed as a percentage.", "ex": "Rising interest rates increase mortgage payments."}]}, {"title": "E. Generational inequality and high-value verbs", "entries": [{"term": "housing wealth", "ipa": "/ˈhaʊzɪŋ welθ/", "pron": "HOW-zing welth", "fr": "patrimoine immobilier", "def": "Wealth held in the value of homes or property.", "ex": "Housing wealth has become central to intergenerational inequality."}, {"term": "intergenerational inequality", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité intergénérationnelle", "def": "Inequality between age groups or generations.", "ex": "Housing has intensified intergenerational inequality."}, {"term": "to afford housing", "ipa": "/əˈfɔːd ˈhaʊzɪŋ/", "pron": "uh-FORD HOW-zing", "fr": "pouvoir se loger", "def": "To have enough money to pay for housing.", "ex": "Many workers can no longer afford housing near their jobs."}, {"term": "to rent a flat", "ipa": "/rent ə flæt/", "pron": "rent uh flat", "fr": "louer un appartement", "def": "To pay regularly to live in a flat.", "ex": "Students often rent a flat with friends."}, {"term": "to buy a home", "ipa": "/baɪ ə həʊm/", "pron": "by uh hohm", "fr": "acheter un logement", "def": "To purchase a place to live.", "ex": "Many young adults cannot afford to buy a home."}, {"term": "to get on the property ladder", "ipa": "/ɡet ɒn ðə ˈprɒpəti ˌlædə/", "pron": "get on thuh PROP-uh-tee LAD-uh", "fr": "accéder à la propriété", "def": "To buy one’s first home.", "ex": "Saving a deposit is the first step to get on the property ladder."}, {"term": "to be priced out", "ipa": "/bi praɪst aʊt/", "pron": "bee pryst owt", "fr": "être exclu par les prix", "def": "To be unable to afford something because prices have risen too high.", "ex": "Local residents are priced out of their own neighbourhoods."}, {"term": "to push up rents", "ipa": "/pʊʃ ʌp rents/", "pron": "push up rents", "fr": "faire monter les loyers", "def": "To make rents increase.", "ex": "Short-term rentals can push up rents."}, {"term": "to drive up house prices", "ipa": "/draɪv ʌp haʊs ˈpraɪsɪz/", "pron": "dryv up HOWSS PRY-siz", "fr": "faire grimper les prix de l’immobilier", "def": "To cause house prices to rise.", "ex": "Speculation can drive up house prices."}, {"term": "to build more homes", "ipa": "/bɪld mɔː həʊmz/", "pron": "bild more hohmz", "fr": "construire davantage de logements", "def": "To increase housing supply by constructing homes.", "ex": "Many economists argue that cities need to build more homes."}, {"term": "to increase housing supply", "ipa": "/ɪnˈkriːs ˈhaʊzɪŋ səˌplaɪ/", "pron": "in-KREESS HOW-zing suh-PLY", "fr": "augmenter l’offre de logements", "def": "To make more homes available.", "ex": "Planning reform aims to increase housing supply."}, {"term": "to tackle homelessness", "ipa": "/ˈtækəl ˈhəʊmləsnəs/", "pron": "TAK-uhl HOHM-luhs-nuhs", "fr": "lutter contre le sans-abrisme", "def": "To take action to reduce homelessness.", "ex": "Tackling homelessness requires housing and support services."}, {"term": "to face eviction", "ipa": "/feɪs ɪˈvɪkʃən/", "pron": "fays i-VIK-shuhn", "fr": "risquer l’expulsion", "def": "To be at risk of being forced to leave one’s home.", "ex": "Many renters face eviction after falling into arrears."}, {"term": "to fall behind on rent", "ipa": "/fɔːl bɪˈhaɪnd ɒn rent/", "pron": "fall bi-HYND on rent", "fr": "prendre du retard sur le loyer", "def": "To fail to pay rent on time.", "ex": "Low-income tenants may fall behind on rent."}, {"term": "to improve housing conditions", "ipa": "/ɪmˈpruːv ˈhaʊzɪŋ kənˌdɪʃənz/", "pron": "im-PROOV HOW-zing kuhn-DISH-uhnz", "fr": "améliorer les conditions de logement", "def": "To make homes safer, healthier or better maintained.", "ex": "Regulation can improve housing conditions."}, {"term": "to protect tenants", "ipa": "/prəˈtekt ˈtenənts/", "pron": "pruh-TEKT TEN-uhnts", "fr": "protéger les locataires", "def": "To defend renters from unfair treatment or insecurity.", "ex": "Renters’ rights laws aim to protect tenants."}, {"term": "to regulate landlords", "ipa": "/ˈreɡjʊleɪt ˈlændlɔːdz/", "pron": "REG-yuh-layt LAND-lordz", "fr": "réglementer les propriétaires bailleurs", "def": "To impose rules on landlords.", "ex": "Governments may regulate landlords to improve standards."}, {"term": "to curb speculation", "ipa": "/kɜːb ˌspekjʊˈleɪʃən/", "pron": "kurb spek-yuh-LAY-shuhn", "fr": "freiner la spéculation", "def": "To limit speculative buying of property.", "ex": "Tax reform could curb speculation."}, {"term": "to reduce overcrowding", "ipa": "/rɪˈdjuːs ˌəʊvəˈkraʊdɪŋ/", "pron": "ri-DYOOSS OH-vuh-KROW-ding", "fr": "réduire le surpeuplement", "def": "To decrease the number of people living in cramped homes.", "ex": "More social housing could reduce overcrowding."}, {"term": "to make housing affordable", "ipa": "/meɪk ˈhaʊzɪŋ əˌfɔːdəbəl/", "pron": "mayk HOW-zing uh-FOR-duh-buhl", "fr": "rendre le logement abordable", "def": "To ensure people can pay for decent homes.", "ex": "Policy must make housing affordable for ordinary workers."}]}]}, {"id": "p4c33", "part": 4, "chapter": 33, "title": "Healthcare", "file": "cpge_vocab_part4_chapter33_healthcare_premium.html", "count": 192, "sections": [{"title": "A. Core healthcare systems and funding", "entries": [{"term": "healthcare", "ipa": "/ˈhelθkeə/", "pron": "HELTH-care", "fr": "soins de santé ; système de santé", "def": "The organised provision of medical services to prevent, diagnose and treat illness.", "ex": "Healthcare is often considered a basic public good."}, {"term": "healthcare system", "ipa": "/ˈhelθkeə ˌsɪstəm/", "pron": "HELTH-care SIS-tuhm", "fr": "système de santé", "def": "The institutions, services and funding arrangements that provide medical care.", "ex": "Every healthcare system must balance access, quality and cost."}, {"term": "health system", "ipa": "/ˈhelθ ˌsɪstəm/", "pron": "helth SIS-tuhm", "fr": "système de santé", "def": "The broader network of organisations, workers and policies that affect health.", "ex": "A strong health system includes prevention, hospitals and public health."}, {"term": "public health", "ipa": "/ˌpʌblɪk ˈhelθ/", "pron": "PUB-lik helth", "fr": "santé publique", "def": "The protection and improvement of health at population level.", "ex": "Public health focuses on prevention rather than only treatment."}, {"term": "universal healthcare", "ipa": "/ˌjuːnɪˈvɜːsəl ˈhelθkeə/", "pron": "yoo-ni-VUR-suhl HELTH-care", "fr": "couverture santé universelle", "def": "A system in which everyone has access to healthcare regardless of income.", "ex": "Universal healthcare aims to prevent medical care from depending on wealth."}, {"term": "universal coverage", "ipa": "/ˌjuːnɪˈvɜːsəl ˈkʌvərɪdʒ/", "pron": "yoo-ni-VUR-suhl KUV-uh-rij", "fr": "couverture universelle", "def": "Health coverage available to all members of a population.", "ex": "Universal coverage is a key goal of many healthcare reforms."}, {"term": "healthcare access", "ipa": "/ˈhelθkeə ˌækses/", "pron": "HELTH-care AK-sess", "fr": "accès aux soins", "def": "The ability to obtain needed medical services.", "ex": "Healthcare access remains unequal between regions and social groups."}, {"term": "access to care", "ipa": "/ˌækses tə ˈkeə/", "pron": "AK-sess tuh care", "fr": "accès aux soins", "def": "The ability to receive medical treatment, advice or support when needed.", "ex": "Rural patients may have limited access to care."}, {"term": "healthcare coverage", "ipa": "/ˈhelθkeə ˌkʌvərɪdʒ/", "pron": "HELTH-care KUV-uh-rij", "fr": "couverture santé", "def": "Insurance or public protection allowing people to receive healthcare.", "ex": "Millions of Americans still struggle with insufficient healthcare coverage."}, {"term": "health insurance", "ipa": "/ˈhelθ ɪnˌʃʊərəns/", "pron": "helth in-SHOOR-uhns", "fr": "assurance maladie ; assurance santé", "def": "Insurance that helps pay for medical care.", "ex": "Health insurance can reduce the risk of catastrophic medical bills."}, {"term": "private health insurance", "ipa": "/ˌpraɪvət helθ ɪnˈʃʊərəns/", "pron": "PRY-vuht helth in-SHOOR-uhns", "fr": "assurance santé privée", "def": "Health insurance bought privately or provided by an employer.", "ex": "Private health insurance can create unequal access to faster care."}, {"term": "public healthcare", "ipa": "/ˌpʌblɪk ˈhelθkeə/", "pron": "PUB-lik HELTH-care", "fr": "système de santé public", "def": "Healthcare funded or provided by the state.", "ex": "Public healthcare is usually funded through taxation or social insurance."}, {"term": "private healthcare", "ipa": "/ˌpraɪvət ˈhelθkeə/", "pron": "PRY-vuht HELTH-care", "fr": "soins privés ; système de santé privé", "def": "Healthcare funded by private payment or insurance.", "ex": "Private healthcare can reduce waiting times for those who can afford it."}, {"term": "mixed healthcare system", "ipa": "/ˌmɪkst ˈhelθkeə ˌsɪstəm/", "pron": "mikst HELTH-care SIS-tuhm", "fr": "système de santé mixte", "def": "A system combining public and private healthcare provision or funding.", "ex": "Most countries have a mixed healthcare system."}, {"term": "National Health Service", "ipa": "/ˌnæʃənəl ˈhelθ ˌsɜːvɪs/", "pron": "NASH-uh-nuhl helth SUR-vis", "fr": "National Health Service ; NHS", "def": "The UK’s publicly funded healthcare system, commonly called the NHS.", "ex": "The National Health Service is central to the British welfare state."}, {"term": "NHS", "ipa": "/ˌen eɪtʃ ˈes/", "pron": "en-aych-ess", "fr": "NHS", "def": "Abbreviation for the UK National Health Service.", "ex": "The NHS faces pressure from ageing, staff shortages and waiting lists."}, {"term": "Medicare", "ipa": "/ˈmedɪkeə/", "pron": "MED-i-care", "fr": "Medicare", "def": "A US federal health insurance programme mainly for older people.", "ex": "Medicare provides health coverage for many elderly Americans."}, {"term": "Medicaid", "ipa": "/ˈmedɪkeɪd/", "pron": "MED-i-kayd", "fr": "Medicaid", "def": "A US public health insurance programme for low-income people.", "ex": "Medicaid helps many low-income families access care."}, {"term": "single-payer system", "ipa": "/ˌsɪŋɡəl ˈpeɪə ˌsɪstəm/", "pron": "SING-guhl PAY-uh SIS-tuhm", "fr": "système à payeur unique", "def": "A healthcare system where one public body pays for healthcare costs.", "ex": "Supporters of a single-payer system argue it reduces administrative costs."}, {"term": "out-of-pocket expenses", "ipa": "/ˌaʊt əv ˈpɒkɪt ɪkˌspensɪz/", "pron": "owt ov POK-it ik-SPEN-siz", "fr": "reste à charge ; dépenses directes", "def": "Medical costs paid directly by patients.", "ex": "High out-of-pocket expenses can discourage people from seeking care."}, {"term": "co-payment", "ipa": "/ˌkəʊ ˈpeɪmənt/", "pron": "koh-PAY-muhnt", "fr": "ticket modérateur ; quote-part", "def": "A fixed amount paid by a patient for a medical service.", "ex": "Co-payments may make patients delay treatment."}, {"term": "deductible", "ipa": "/dɪˈdʌktəbəl/", "pron": "di-DUK-tuh-buhl", "fr": "franchise", "def": "The amount a patient must pay before insurance starts covering costs.", "ex": "High deductibles can make insured patients effectively underinsured."}, {"term": "medical bill", "ipa": "/ˈmedɪkəl bɪl/", "pron": "MED-i-kuhl bil", "fr": "facture médicale", "def": "A charge for medical treatment or services.", "ex": "Medical bills are a major cause of debt in the United States."}, {"term": "medical debt", "ipa": "/ˈmedɪkəl det/", "pron": "MED-i-kuhl det", "fr": "dette médicale", "def": "Debt caused by the cost of healthcare.", "ex": "Medical debt can push families into poverty."}, {"term": "uninsured", "ipa": "/ˌʌnɪnˈʃʊəd/", "pron": "un-in-SHOORD", "fr": "non assuré", "def": "Not covered by health insurance.", "ex": "Uninsured patients may avoid treatment because of cost."}, {"term": "underinsured", "ipa": "/ˌʌndərɪnˈʃʊəd/", "pron": "UN-duh-rin-SHOORD", "fr": "sous-assuré", "def": "Having insurance that does not cover enough medical costs.", "ex": "Underinsured patients can still face unaffordable bills."}, {"term": "healthcare affordability", "ipa": "/ˈhelθkeə əˌfɔːdəˈbɪləti/", "pron": "HELTH-care uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière des soins", "def": "The extent to which people can afford healthcare.", "ex": "Healthcare affordability is a major political issue."}, {"term": "healthcare funding", "ipa": "/ˈhelθkeə ˌfʌndɪŋ/", "pron": "HELTH-care FUN-ding", "fr": "financement de la santé", "def": "The money used to pay for healthcare services.", "ex": "Healthcare funding is under pressure in ageing societies."}, {"term": "taxpayer-funded healthcare", "ipa": "/ˈtækspeɪə ˌfʌndɪd ˈhelθkeə/", "pron": "TAKS-pay-uh FUN-did HELTH-care", "fr": "santé financée par l’impôt", "def": "Healthcare paid for through taxes.", "ex": "The NHS is largely a taxpayer-funded healthcare system."}, {"term": "healthcare expenditure", "ipa": "/ˈhelθkeə ɪkˌspendɪtʃə/", "pron": "HELTH-care ik-SPEN-di-chuh", "fr": "dépenses de santé", "def": "Money spent on healthcare by government, insurers or individuals.", "ex": "Healthcare expenditure rises as populations age."}, {"term": "public expenditure", "ipa": "/ˌpʌblɪk ɪkˈspendɪtʃə/", "pron": "PUB-lik ik-SPEN-di-chuh", "fr": "dépenses publiques", "def": "Government spending on services, benefits and infrastructure.", "ex": "Healthcare is a major part of public expenditure."}, {"term": "budget cuts", "ipa": "/ˈbʌdʒɪt kʌts/", "pron": "BUJ-it kuts", "fr": "coupes budgétaires", "def": "Reductions in planned public spending.", "ex": "Budget cuts can weaken hospitals and community care."}, {"term": "healthcare reform", "ipa": "/ˈhelθkeə rɪˌfɔːm/", "pron": "HELTH-care ri-FORM", "fr": "réforme du système de santé", "def": "Changes designed to improve how healthcare is funded, organised or delivered.", "ex": "Healthcare reform often triggers fierce political debate."}, {"term": "primary care", "ipa": "/ˌpraɪməri ˈkeə/", "pron": "PRY-muh-ree care", "fr": "soins primaires", "def": "First-contact healthcare, usually provided by GPs, family doctors or clinics.", "ex": "Strong primary care can reduce pressure on hospitals."}, {"term": "secondary care", "ipa": "/ˌsekəndəri ˈkeə/", "pron": "SEK-uhn-duh-ree care", "fr": "soins secondaires", "def": "Specialist care usually accessed after referral from primary care.", "ex": "Secondary care includes many hospital-based services."}]}, {"title": "B. Hospitals, primary care and healthcare workers", "entries": [{"term": "tertiary care", "ipa": "/ˌtɜːʃəri ˈkeə/", "pron": "TUR-shuh-ree care", "fr": "soins tertiaires spécialisés", "def": "Highly specialised medical care, often in major hospitals.", "ex": "Tertiary care includes complex surgery and specialist treatment."}, {"term": "GP", "ipa": "/ˌdʒiː ˈpiː/", "pron": "jee-pee", "fr": "médecin généraliste", "def": "British abbreviation for general practitioner, a family doctor.", "ex": "A GP is often the first point of contact in the NHS."}, {"term": "general practitioner", "ipa": "/ˌdʒenərəl prækˈtɪʃənə/", "pron": "JEN-uh-ruhl prak-TISH-uh-nuh", "fr": "médecin généraliste", "def": "A doctor providing primary care for common medical problems.", "ex": "General practitioners coordinate referrals to specialists."}, {"term": "family doctor", "ipa": "/ˌfæməli ˈdɒktə/", "pron": "FAM-uh-lee DOK-tuh", "fr": "médecin de famille", "def": "A doctor providing general medical care for individuals and families.", "ex": "A family doctor knows the patient’s medical history."}, {"term": "clinic", "ipa": "/ˈklɪnɪk/", "pron": "KLIN-ik", "fr": "clinique ; centre de soins", "def": "A healthcare facility for outpatient care, diagnosis or treatment.", "ex": "Community clinics improve access to basic care."}, {"term": "hospital", "ipa": "/ˈhɒspɪtəl/", "pron": "HOS-pi-tuhl", "fr": "hôpital", "def": "A medical institution where patients receive treatment, surgery or emergency care.", "ex": "Hospitals are under pressure when waiting lists grow."}, {"term": "emergency department", "ipa": "/ɪˈmɜːdʒənsi dɪˌpɑːtmənt/", "pron": "i-MUR-juhn-see di-PART-muhnt", "fr": "service des urgences", "def": "The hospital department treating urgent and serious conditions.", "ex": "Emergency departments often suffer from overcrowding."}, {"term": "A&E", "ipa": "/ˌeɪ ənd ˈiː/", "pron": "ay-and-ee", "fr": "urgences hospitalières britanniques", "def": "British abbreviation for Accident and Emergency department.", "ex": "A&E waiting times are closely watched by the media."}, {"term": "ER", "ipa": "/ˌiː ˈɑː/", "pron": "ee-ar", "fr": "urgences américaines", "def": "US abbreviation for emergency room.", "ex": "Patients without insurance may rely on the ER for basic care."}, {"term": "intensive care unit", "ipa": "/ɪnˌtensɪv ˈkeə ˌjuːnɪt/", "pron": "in-TEN-siv care YOO-nit", "fr": "unité de soins intensifs", "def": "A hospital unit for critically ill patients needing constant monitoring.", "ex": "ICU capacity became a major issue during the pandemic."}, {"term": "ICU", "ipa": "/ˌaɪ siː ˈjuː/", "pron": "eye-see-yoo", "fr": "USI ; soins intensifs", "def": "Abbreviation for intensive care unit.", "ex": "ICU beds are limited and expensive."}, {"term": "operating theatre", "ipa": "/ˈɒpəreɪtɪŋ ˌθɪətə/", "pron": "OP-uh-ray-ting THEE-uh-tuh", "fr": "bloc opératoire ; salle d’opération", "def": "British term for a room where surgery is performed.", "ex": "Operating theatres require specialist staff and equipment."}, {"term": "operating room", "ipa": "/ˈɒpəreɪtɪŋ ruːm/", "pron": "OP-uh-ray-ting room", "fr": "salle d’opération", "def": "US term for a room where surgery is performed.", "ex": "The patient was taken to the operating room."}, {"term": "waiting list", "ipa": "/ˈweɪtɪŋ lɪst/", "pron": "WAY-ting list", "fr": "liste d’attente", "def": "A list of patients waiting for treatment or appointments.", "ex": "Long waiting lists are a major problem for the NHS."}, {"term": "waiting time", "ipa": "/ˈweɪtɪŋ taɪm/", "pron": "WAY-ting time", "fr": "délai d’attente", "def": "The time a patient waits before receiving care.", "ex": "Reducing waiting times is a key political promise."}, {"term": "hospital bed", "ipa": "/ˈhɒspɪtəl bed/", "pron": "HOS-pi-tuhl bed", "fr": "lit d’hôpital", "def": "A bed available for patient care in a hospital.", "ex": "A shortage of hospital beds can delay admissions."}, {"term": "bed shortage", "ipa": "/ˈbed ˌʃɔːtɪdʒ/", "pron": "bed SHOR-tij", "fr": "pénurie de lits", "def": "A lack of available hospital beds.", "ex": "Bed shortages can cause overcrowding in emergency departments."}, {"term": "patient", "ipa": "/ˈpeɪʃənt/", "pron": "PAY-shuhnt", "fr": "patient", "def": "A person receiving medical care.", "ex": "Patient safety must be at the centre of healthcare policy."}, {"term": "patient care", "ipa": "/ˈpeɪʃənt keə/", "pron": "PAY-shuhnt care", "fr": "soins aux patients", "def": "Medical and personal care provided to patients.", "ex": "Good patient care requires time, staff and communication."}, {"term": "patient safety", "ipa": "/ˈpeɪʃənt ˌseɪfti/", "pron": "PAY-shuhnt SAYF-tee", "fr": "sécurité des patients", "def": "The prevention of avoidable harm in healthcare.", "ex": "Patient safety can be threatened by understaffing."}, {"term": "quality of care", "ipa": "/ˈkwɒləti əv keə/", "pron": "KWOL-uh-tee ov care", "fr": "qualité des soins", "def": "The standard and effectiveness of healthcare provided.", "ex": "Quality of care varies between hospitals and regions."}, {"term": "healthcare workforce", "ipa": "/ˈhelθkeə ˌwɜːkfɔːs/", "pron": "HELTH-care WURK-force", "fr": "personnel de santé", "def": "All workers involved in providing healthcare.", "ex": "The healthcare workforce is under severe strain."}, {"term": "doctor", "ipa": "/ˈdɒktə/", "pron": "DOK-tuh", "fr": "médecin", "def": "A medically qualified professional who diagnoses and treats patients.", "ex": "Doctors face heavy workloads in underfunded systems."}, {"term": "physician", "ipa": "/fɪˈzɪʃən/", "pron": "fi-ZISH-uhn", "fr": "médecin", "def": "Formal or US term for a doctor, especially one who practises medicine rather than surgery.", "ex": "Physicians play a key role in diagnosis and treatment."}, {"term": "nurse", "ipa": "/nɜːs/", "pron": "nurs", "fr": "infirmier ; infirmière", "def": "A healthcare professional trained to care for patients.", "ex": "Nurses are essential to patient care."}, {"term": "nursing staff", "ipa": "/ˈnɜːsɪŋ stɑːf/", "pron": "NUR-sing staff", "fr": "personnel infirmier", "def": "Nurses and healthcare assistants working in patient care.", "ex": "Nursing staff shortages increase pressure on hospitals."}, {"term": "surgeon", "ipa": "/ˈsɜːdʒən/", "pron": "SUR-juhn", "fr": "chirurgien ; chirurgienne", "def": "A doctor who performs operations.", "ex": "Surgeons depend on operating theatre capacity."}, {"term": "specialist", "ipa": "/ˈspeʃəlɪst/", "pron": "SPESH-uh-list", "fr": "spécialiste", "def": "A medical professional with expertise in a specific field.", "ex": "Patients may wait months to see a specialist."}, {"term": "consultant", "ipa": "/kənˈsʌltənt/", "pron": "kuhn-SUL-tuhnt", "fr": "médecin hospitalier senior ; consultant", "def": "In Britain, a senior hospital doctor.", "ex": "Consultants supervise specialist hospital care."}, {"term": "paramedic", "ipa": "/ˌpærəˈmedɪk/", "pron": "par-uh-MED-ik", "fr": "ambulancier paramédical ; secouriste médicalisé", "def": "An emergency medical professional, often working in ambulances.", "ex": "Paramedics provide life-saving care before hospital arrival."}, {"term": "ambulance", "ipa": "/ˈæmbjʊləns/", "pron": "AM-byuh-luhns", "fr": "ambulance", "def": "A vehicle used to transport patients needing urgent medical care.", "ex": "Ambulance delays can endanger patients."}, {"term": "pharmacist", "ipa": "/ˈfɑːməsɪst/", "pron": "FAR-muh-sist", "fr": "pharmacien ; pharmacienne", "def": "A professional who prepares, dispenses and advises on medicines.", "ex": "Pharmacists can support prevention and primary care."}, {"term": "caregiver", "ipa": "/ˈkeəˌɡɪvə/", "pron": "CARE-giv-uh", "fr": "aidant ; soignant", "def": "A person who looks after someone who is ill, elderly or disabled.", "ex": "Informal caregivers are often unpaid family members."}, {"term": "healthcare staffing shortage", "ipa": "/ˈhelθkeə ˈstɑːfɪŋ ˌʃɔːtɪdʒ/", "pron": "HELTH-care STAR-fing SHOR-tij", "fr": "pénurie de personnel de santé", "def": "A lack of enough healthcare workers.", "ex": "Staffing shortages increase waiting times and burnout."}, {"term": "burnout", "ipa": "/ˈbɜːnaʊt/", "pron": "BURN-owt", "fr": "épuisement professionnel", "def": "Physical and emotional exhaustion caused by long-term stress.", "ex": "Burnout is widespread among healthcare workers."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brayn drayn", "fr": "fuite des cerveaux", "def": "The emigration of skilled professionals from one country to another.", "ex": "Poorer countries may suffer brain drain when doctors leave."}, {"term": "diagnosis", "ipa": "/ˌdaɪəɡˈnəʊsɪs/", "pron": "dy-uhg-NOH-sis", "fr": "diagnostic", "def": "The identification of a disease or condition.", "ex": "Early diagnosis improves survival rates."}, {"term": "to diagnose", "ipa": "/ˈdaɪəɡnəʊz/", "pron": "DY-uhg-nohz", "fr": "diagnostiquer", "def": "To identify a disease or condition.", "ex": "Doctors use tests and symptoms to diagnose disease."}, {"term": "treatment", "ipa": "/ˈtriːtmənt/", "pron": "TREET-muhnt", "fr": "traitement", "def": "Medical care given to cure, manage or relieve a condition.", "ex": "Treatment can be delayed by long waiting lists."}]}, {"title": "C. Treatment, prevention and public health", "entries": [{"term": "therapy", "ipa": "/ˈθerəpi/", "pron": "THERR-uh-pee", "fr": "thérapie ; traitement", "def": "Treatment for illness, injury or mental distress.", "ex": "Therapy can be physical, psychological or medical."}, {"term": "medicine", "ipa": "/ˈmedsən/", "pron": "MED-suhn", "fr": "médicament ; médecine", "def": "A drug or substance used to treat illness; also the field of medical practice.", "ex": "Access to medicine is unequal across the world."}, {"term": "medication", "ipa": "/ˌmedɪˈkeɪʃən/", "pron": "med-i-KAY-shuhn", "fr": "médicament", "def": "A drug prescribed or taken to treat a condition.", "ex": "Some patients cannot afford their medication."}, {"term": "prescription", "ipa": "/prɪˈskrɪpʃən/", "pron": "pri-SKRIP-shuhn", "fr": "ordonnance", "def": "An official instruction from a doctor for medicine or treatment.", "ex": "Prescription charges can affect low-income patients."}, {"term": "side effect", "ipa": "/ˈsaɪd ɪˌfekt/", "pron": "side i-FEKT", "fr": "effet secondaire", "def": "An unintended effect of a medicine or treatment.", "ex": "Patients must be informed about possible side effects."}, {"term": "clinical trial", "ipa": "/ˌklɪnɪkəl ˈtraɪəl/", "pron": "KLIN-i-kuhl TRY-uhl", "fr": "essai clinique", "def": "A research study testing the safety or effectiveness of a treatment.", "ex": "Clinical trials are essential before approving new drugs."}, {"term": "evidence-based medicine", "ipa": "/ˌevɪdəns beɪst ˈmedsən/", "pron": "EV-i-duhns bayst MED-suhn", "fr": "médecine fondée sur les preuves", "def": "Medical practice based on the best available scientific evidence.", "ex": "Evidence-based medicine helps avoid ineffective treatments."}, {"term": "screening", "ipa": "/ˈskriːnɪŋ/", "pron": "SKREE-ning", "fr": "dépistage", "def": "Testing people to detect disease before symptoms appear.", "ex": "Cancer screening can save lives through early detection."}, {"term": "early detection", "ipa": "/ˌɜːli dɪˈtekʃən/", "pron": "UR-lee di-TEK-shuhn", "fr": "détection précoce", "def": "Finding a disease at an early stage.", "ex": "Early detection often improves treatment outcomes."}, {"term": "prevention", "ipa": "/prɪˈvenʃən/", "pron": "pri-VEN-shuhn", "fr": "prévention", "def": "Actions taken to stop disease or harm before it happens.", "ex": "Prevention is usually cheaper than treatment."}, {"term": "preventive medicine", "ipa": "/prɪˌventɪv ˈmedsən/", "pron": "pri-VEN-tiv MED-suhn", "fr": "médecine préventive", "def": "Medical practice focused on preventing disease.", "ex": "Preventive medicine includes vaccination and screening."}, {"term": "vaccination", "ipa": "/ˌvæksɪˈneɪʃən/", "pron": "vak-si-NAY-shuhn", "fr": "vaccination", "def": "The act of giving a vaccine to protect against disease.", "ex": "Vaccination protects individuals and communities."}, {"term": "immunisation", "ipa": "/ˌɪmjʊnaɪˈzeɪʃən/", "pron": "im-yuh-ny-ZAY-shuhn", "fr": "immunisation", "def": "The process of becoming protected against a disease, often through vaccination.", "ex": "Childhood immunisation prevents deadly diseases."}, {"term": "vaccine hesitancy", "ipa": "/ˈvæksiːn ˈhezɪtənsi/", "pron": "VAK-seen HEZ-i-tuhn-see", "fr": "hésitation vaccinale", "def": "Reluctance or refusal to receive vaccines despite availability.", "ex": "Vaccine hesitancy can undermine public health campaigns."}, {"term": "health promotion", "ipa": "/ˈhelθ prəˌməʊʃən/", "pron": "helth pruh-MOH-shuhn", "fr": "promotion de la santé", "def": "Efforts to encourage healthier behaviour and environments.", "ex": "Health promotion includes campaigns on diet, exercise and smoking."}, {"term": "health education", "ipa": "/ˈhelθ ˌedjʊˈkeɪʃən/", "pron": "helth ej-yoo-KAY-shuhn", "fr": "éducation à la santé", "def": "Teaching people about health risks and healthy behaviour.", "ex": "Health education can improve prevention."}, {"term": "health literacy", "ipa": "/ˈhelθ ˌlɪtərəsi/", "pron": "helth LIT-uh-ruh-see", "fr": "littératie en santé", "def": "The ability to understand and use health information.", "ex": "Low health literacy can lead to poorer outcomes."}, {"term": "public awareness campaign", "ipa": "/ˌpʌblɪk əˈweənəs kæmˌpeɪn/", "pron": "PUB-lik uh-WAIR-nuhs kam-PAYN", "fr": "campagne de sensibilisation", "def": "A campaign informing people about a public issue.", "ex": "Public awareness campaigns can change health behaviour."}, {"term": "risk factor", "ipa": "/ˈrɪsk ˌfæktə/", "pron": "risk FAK-tuh", "fr": "facteur de risque", "def": "Something that increases the likelihood of disease or harm.", "ex": "Smoking is a major risk factor for lung cancer."}, {"term": "healthy lifestyle", "ipa": "/ˌhelθi ˈlaɪfstaɪl/", "pron": "HEL-thee LIFE-style", "fr": "mode de vie sain", "def": "A way of living that supports physical and mental health.", "ex": "A healthy lifestyle can reduce the risk of chronic disease."}, {"term": "balanced diet", "ipa": "/ˌbælənst ˈdaɪət/", "pron": "BAL-uhnst DY-uht", "fr": "alimentation équilibrée", "def": "A diet containing the right variety and amount of nutrients.", "ex": "A balanced diet supports long-term health."}, {"term": "physical activity", "ipa": "/ˌfɪzɪkəl ækˈtɪvəti/", "pron": "FIZ-i-kuhl ak-TIV-uh-tee", "fr": "activité physique", "def": "Body movement that uses energy and supports health.", "ex": "Physical activity reduces the risk of many diseases."}, {"term": "sedentary lifestyle", "ipa": "/ˈsedəntəri ˈlaɪfstaɪl/", "pron": "SED-uhn-tuh-ree LIFE-style", "fr": "mode de vie sédentaire", "def": "A lifestyle involving too much sitting and too little physical activity.", "ex": "A sedentary lifestyle is linked to obesity and heart disease."}, {"term": "obesity", "ipa": "/əʊˈbiːsəti/", "pron": "oh-BEE-suh-tee", "fr": "obésité", "def": "A medical condition involving excessive body fat that may harm health.", "ex": "Obesity is influenced by poverty, food systems and lifestyle."}, {"term": "smoking", "ipa": "/ˈsməʊkɪŋ/", "pron": "SMOH-king", "fr": "tabagisme", "def": "The act of inhaling tobacco smoke.", "ex": "Smoking remains a leading preventable cause of death."}, {"term": "alcohol abuse", "ipa": "/ˈælkəhɒl əˌbjuːs/", "pron": "AL-kuh-hol uh-BYOOSS", "fr": "abus d’alcool", "def": "Harmful or excessive use of alcohol.", "ex": "Alcohol abuse can damage physical and mental health."}, {"term": "substance abuse", "ipa": "/ˈsʌbstəns əˌbjuːs/", "pron": "SUB-stuhns uh-BYOOSS", "fr": "toxicomanie ; abus de substances", "def": "Harmful use of drugs or other substances.", "ex": "Substance abuse requires health and social support."}, {"term": "disease", "ipa": "/dɪˈziːz/", "pron": "di-ZEEZ", "fr": "maladie", "def": "A medical condition affecting the body or mind.", "ex": "Disease prevention is a major goal of public health."}, {"term": "illness", "ipa": "/ˈɪlnəs/", "pron": "IL-nuhs", "fr": "maladie ; état de maladie", "def": "The experience or condition of being unwell.", "ex": "Illness can affect work, family and social life."}, {"term": "condition", "ipa": "/kənˈdɪʃən/", "pron": "kuhn-DISH-uhn", "fr": "affection ; pathologie", "def": "A medical problem or state of health.", "ex": "A chronic condition may require lifelong management."}, {"term": "symptom", "ipa": "/ˈsɪmptəm/", "pron": "SIMP-tuhm", "fr": "symptôme", "def": "A sign or feeling indicating illness.", "ex": "Patients should seek help if symptoms worsen."}, {"term": "chronic disease", "ipa": "/ˌkrɒnɪk dɪˈziːz/", "pron": "KRON-ik di-ZEEZ", "fr": "maladie chronique", "def": "A long-lasting disease that often requires ongoing care.", "ex": "Chronic disease is a growing burden on healthcare systems."}, {"term": "infectious disease", "ipa": "/ɪnˌfekʃəs dɪˈziːz/", "pron": "in-FEK-shuhs di-ZEEZ", "fr": "maladie infectieuse", "def": "A disease caused by pathogens and capable of spreading.", "ex": "Infectious diseases can spread quickly without vaccination."}, {"term": "communicable disease", "ipa": "/kəˌmjuːnɪkəbəl dɪˈziːz/", "pron": "kuh-MYOO-ni-kuh-buhl di-ZEEZ", "fr": "maladie transmissible", "def": "A disease that can be transmitted between people or organisms.", "ex": "Public health measures aim to control communicable diseases."}, {"term": "non-communicable disease", "ipa": "/ˌnɒn kəˌmjuːnɪkəbəl dɪˈziːz/", "pron": "non kuh-MYOO-ni-kuh-buhl di-ZEEZ", "fr": "maladie non transmissible", "def": "A disease not transmitted between people, such as diabetes or heart disease.", "ex": "Non-communicable diseases are strongly linked to lifestyle and inequality."}, {"term": "epidemic", "ipa": "/ˌepɪˈdemɪk/", "pron": "ep-i-DEM-ik", "fr": "épidémie", "def": "A sudden increase of disease cases in a particular place.", "ex": "An epidemic requires rapid public health action."}, {"term": "pandemic", "ipa": "/pænˈdemɪk/", "pron": "pan-DEM-ik", "fr": "pandémie", "def": "An epidemic spreading across many countries or worldwide.", "ex": "The COVID-19 pandemic exposed weaknesses in health systems."}]}, {"title": "D. Disease, mental health and health inequalities", "entries": [{"term": "outbreak", "ipa": "/ˈaʊtbreɪk/", "pron": "OWT-brayk", "fr": "foyer épidémique ; flambée", "def": "A sudden occurrence of disease cases in a community or region.", "ex": "An outbreak must be detected quickly."}, {"term": "life expectancy", "ipa": "/ˈlaɪf ɪkˌspektənsi/", "pron": "life ik-SPEK-tuhn-see", "fr": "espérance de vie", "def": "The average number of years a person is expected to live.", "ex": "Life expectancy differs sharply between rich and poor areas."}, {"term": "mortality rate", "ipa": "/mɔːˈtæləti reɪt/", "pron": "mor-TAL-uh-tee rayt", "fr": "taux de mortalité", "def": "The number of deaths in a population during a period.", "ex": "Mortality rates are higher in deprived communities."}, {"term": "infant mortality", "ipa": "/ˌɪnfənt mɔːˈtæləti/", "pron": "IN-fuhnt mor-TAL-uh-tee", "fr": "mortalité infantile", "def": "Deaths of babies before their first birthday.", "ex": "Infant mortality is a key indicator of health inequality."}, {"term": "morbidity", "ipa": "/mɔːˈbɪdəti/", "pron": "mor-BID-uh-tee", "fr": "morbidité", "def": "The level or rate of disease in a population.", "ex": "Morbidity data helps assess the burden of disease."}, {"term": "burden of disease", "ipa": "/ˌbɜːdən əv dɪˈziːz/", "pron": "BUR-duhn ov di-ZEEZ", "fr": "charge de morbidité", "def": "The overall impact of disease on a population.", "ex": "The burden of disease is increasingly linked to chronic illness."}, {"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl helth", "fr": "santé mentale", "def": "A person’s emotional, psychological and social well-being.", "ex": "Mental health is now recognised as a major public health issue."}, {"term": "mental illness", "ipa": "/ˌmentəl ˈɪlnəs/", "pron": "MEN-tuhl IL-nuhs", "fr": "maladie mentale ; trouble psychique", "def": "A condition affecting mood, thinking or behaviour.", "ex": "Mental illness is still surrounded by stigma."}, {"term": "depression", "ipa": "/dɪˈpreʃən/", "pron": "di-PRESH-uhn", "fr": "dépression", "def": "A mental health condition involving persistent sadness, hopelessness or loss of interest.", "ex": "Depression can affect study, work and relationships."}, {"term": "anxiety", "ipa": "/æŋˈzaɪəti/", "pron": "ang-ZY-uh-tee", "fr": "anxiété", "def": "A mental health condition involving excessive worry or fear.", "ex": "Anxiety among young people has increased in recent years."}, {"term": "stress", "ipa": "/stres/", "pron": "stress", "fr": "stress", "def": "Mental or physical pressure caused by difficult situations.", "ex": "Chronic stress can damage health."}, {"term": "psychological distress", "ipa": "/ˌsaɪkəˈlɒdʒɪkəl dɪˈstres/", "pron": "sy-kuh-LOJ-i-kuhl di-STRESS", "fr": "détresse psychologique", "def": "Mental suffering or emotional strain.", "ex": "Financial insecurity can cause psychological distress."}, {"term": "counselling", "ipa": "/ˈkaʊnsəlɪŋ/", "pron": "KOWN-suh-ling", "fr": "accompagnement psychologique ; conseil", "def": "Professional support through talking and guidance.", "ex": "Counselling can help people manage grief, stress or anxiety."}, {"term": "psychotherapy", "ipa": "/ˌsaɪkəʊˈθerəpi/", "pron": "sy-koh-THERR-uh-pee", "fr": "psychothérapie", "def": "Treatment of mental health problems through structured talking therapy.", "ex": "Psychotherapy may be difficult to access quickly."}, {"term": "psychiatrist", "ipa": "/saɪˈkaɪətrɪst/", "pron": "sy-KY-uh-trist", "fr": "psychiatre", "def": "A medical doctor specialising in mental illness.", "ex": "A psychiatrist can prescribe medication."}, {"term": "psychologist", "ipa": "/saɪˈkɒlədʒɪst/", "pron": "sy-KOL-uh-jist", "fr": "psychologue", "def": "A professional specialising in behaviour and mental processes.", "ex": "A psychologist may provide therapy and assessment."}, {"term": "suicide prevention", "ipa": "/ˈsuːɪsaɪd prɪˌvenʃən/", "pron": "SOO-i-side pri-VEN-shuhn", "fr": "prévention du suicide", "def": "Measures designed to reduce suicide risk.", "ex": "Suicide prevention requires accessible mental healthcare."}, {"term": "self-harm", "ipa": "/ˌself ˈhɑːm/", "pron": "self harm", "fr": "automutilation", "def": "Intentional injury to oneself, often linked to psychological distress.", "ex": "Self-harm should be treated as a sign of distress, not attention-seeking."}, {"term": "stigma", "ipa": "/ˈstɪɡmə/", "pron": "STIG-muh", "fr": "stigmatisation", "def": "Negative judgement or shame attached to a condition or identity.", "ex": "Stigma prevents many people from seeking mental healthcare."}, {"term": "mental health crisis", "ipa": "/ˌmentəl ˈhelθ ˈkraɪsɪs/", "pron": "MEN-tuhl helth KRY-sis", "fr": "crise de santé mentale", "def": "A severe situation involving urgent psychological distress or risk.", "ex": "Schools and universities report a mental health crisis among students."}, {"term": "health inequality", "ipa": "/ˈhelθ ˌɪnɪˈkwɒləti/", "pron": "helth in-i-KWOL-uh-tee", "fr": "inégalité de santé", "def": "Unequal health outcomes between social groups.", "ex": "Health inequality often mirrors income inequality."}, {"term": "health disparity", "ipa": "/ˈhelθ dɪˌspærəti/", "pron": "helth di-SPARR-uh-tee", "fr": "disparité de santé", "def": "A difference in health outcomes between groups.", "ex": "Health disparities are visible along racial and class lines."}, {"term": "healthcare inequality", "ipa": "/ˈhelθkeə ˌɪnɪˈkwɒləti/", "pron": "HELTH-care in-i-KWOL-uh-tee", "fr": "inégalité d’accès aux soins", "def": "Unequal access to healthcare or unequal quality of care.", "ex": "Healthcare inequality can be geographic, racial or economic."}, {"term": "social determinants of health", "ipa": "/ˌsəʊʃəl dɪˌtɜːmɪnənts əv ˈhelθ/", "pron": "SOH-shuhl di-TUR-mi-nuhnts ov helth", "fr": "déterminants sociaux de la santé", "def": "The social and economic conditions that shape health outcomes.", "ex": "Housing, income and education are social determinants of health."}, {"term": "health outcome", "ipa": "/ˈhelθ ˌaʊtkʌm/", "pron": "helth OWT-kum", "fr": "résultat de santé", "def": "The result of healthcare, living conditions or disease on a person’s health.", "ex": "Health outcomes are worse in deprived areas."}, {"term": "deprived area", "ipa": "/dɪˌpraɪvd ˈeəriə/", "pron": "di-PRYVD AIR-ee-uh", "fr": "zone défavorisée", "def": "An area lacking resources, services and opportunities.", "ex": "People in deprived areas often have shorter life expectancy."}, {"term": "vulnerable population", "ipa": "/ˈvʌlnərəbəl ˌpɒpjʊˈleɪʃən/", "pron": "VUL-nuh-ruh-buhl pop-yuh-LAY-shuhn", "fr": "population vulnérable", "def": "A group at higher risk of poor health or harm.", "ex": "Public health policy must protect vulnerable populations."}, {"term": "underserved community", "ipa": "/ˌʌndəˈsɜːvd kəˈmjuːnəti/", "pron": "UN-duh-SURVD kuh-MYOO-nuh-tee", "fr": "communauté mal desservie", "def": "A community with limited access to services, including healthcare.", "ex": "Underserved communities often lack clinics and specialists."}, {"term": "healthcare desert", "ipa": "/ˈhelθkeə ˌdezət/", "pron": "HELTH-care DEZ-uht", "fr": "désert médical", "def": "An area with very limited access to healthcare services.", "ex": "Rural healthcare deserts make prevention and treatment difficult."}, {"term": "medical bias", "ipa": "/ˈmedɪkəl ˌbaɪəs/", "pron": "MED-i-kuhl BY-uhs", "fr": "biais médical", "def": "Unfair assumptions or unequal treatment in medical care.", "ex": "Medical bias can lead to misdiagnosis or undertreatment."}, {"term": "healthcare discrimination", "ipa": "/ˈhelθkeə dɪˌskrɪmɪˈneɪʃən/", "pron": "HELTH-care dis-krim-i-NAY-shuhn", "fr": "discrimination dans les soins", "def": "Unfair treatment in healthcare based on identity or status.", "ex": "Healthcare discrimination damages trust in medical institutions."}, {"term": "racial disparities", "ipa": "/ˌreɪʃəl dɪˈspærətiz/", "pron": "RAY-shuhl di-SPARR-uh-teez", "fr": "disparités raciales", "def": "Differences between racial groups in outcomes or treatment.", "ex": "Racial disparities in maternal mortality are a major concern."}, {"term": "gender disparities", "ipa": "/ˌdʒendə dɪˈspærətiz/", "pron": "JEN-duh di-SPARR-uh-teez", "fr": "disparités de genre", "def": "Differences between genders in treatment or outcomes.", "ex": "Gender disparities can affect diagnosis and pain management."}, {"term": "environmental health", "ipa": "/ɪnˌvaɪrənmentəl ˈhelθ/", "pron": "in-VY-ruhn-men-tuhl helth", "fr": "santé environnementale", "def": "The impact of the environment on human health.", "ex": "Pollution is a major environmental health issue."}, {"term": "occupational health", "ipa": "/ˌɒkjʊˈpeɪʃənəl ˈhelθ/", "pron": "ok-yuh-PAY-shuh-nuhl helth", "fr": "santé au travail", "def": "Health and safety related to work and workplaces.", "ex": "Occupational health includes prevention of workplace injuries."}, {"term": "ageing population", "ipa": "/ˌeɪdʒɪŋ ˌpɒpjʊˈleɪʃən/", "pron": "AY-jing pop-yuh-LAY-shuhn", "fr": "vieillissement de la population", "def": "A population with a rising proportion of older people.", "ex": "An ageing population increases demand for healthcare and long-term care."}, {"term": "ageing society", "ipa": "/ˌeɪdʒɪŋ səˈsaɪəti/", "pron": "AY-jing suh-SY-uh-tee", "fr": "société vieillissante", "def": "A society in which older people form a growing share of the population.", "ex": "Ageing societies must rethink pensions, healthcare and care work."}, {"term": "long-term care", "ipa": "/ˌlɒŋ tɜːm ˈkeə/", "pron": "long-term care", "fr": "soins de longue durée ; dépendance", "def": "Ongoing support for people with chronic illness, disability or old age.", "ex": "Long-term care is expensive and often understaffed."}, {"term": "care home", "ipa": "/ˈkeə həʊm/", "pron": "care hohm", "fr": "maison de retraite ; établissement de soins", "def": "A residential institution for people needing care, especially older adults.", "ex": "Care homes were heavily affected during the pandemic."}]}, {"title": "E. Ageing, innovation, ethics and high-value verbs", "entries": [{"term": "nursing home", "ipa": "/ˈnɜːsɪŋ həʊm/", "pron": "NUR-sing hohm", "fr": "maison de retraite médicalisée", "def": "A residential facility providing medical and personal care.", "ex": "Nursing homes need qualified staff around the clock."}, {"term": "dementia", "ipa": "/dɪˈmenʃə/", "pron": "di-MEN-shuh", "fr": "démence", "def": "A group of conditions involving decline in memory and thinking.", "ex": "Dementia care is a growing challenge for ageing societies."}, {"term": "Alzheimer’s disease", "ipa": "/ˈæltsˌhaɪməz dɪˌziːz/", "pron": "ALTS-hy-muhz di-ZEEZ", "fr": "maladie d’Alzheimer", "def": "A common form of dementia affecting memory and cognition.", "ex": "Alzheimer’s disease places pressure on families and care systems."}, {"term": "telemedicine", "ipa": "/ˈtelɪˌmedsən/", "pron": "TEL-i-MED-suhn", "fr": "télémédecine", "def": "Medical consultation or care delivered remotely using technology.", "ex": "Telemedicine can improve access in rural areas."}, {"term": "remote consultation", "ipa": "/rɪˌməʊt ˌkɒnsəlˈteɪʃən/", "pron": "ri-MOHT kon-suhl-TAY-shuhn", "fr": "consultation à distance", "def": "A medical appointment conducted by phone or video.", "ex": "Remote consultations can be convenient but may miss important symptoms."}, {"term": "digital health", "ipa": "/ˌdɪdʒɪtəl ˈhelθ/", "pron": "DIJ-i-tuhl helth", "fr": "santé numérique", "def": "The use of digital tools and data in healthcare.", "ex": "Digital health raises questions about access and privacy."}, {"term": "AI in healthcare", "ipa": "/ˌeɪ ˈaɪ ɪn ˈhelθkeə/", "pron": "ay-eye in HELTH-care", "fr": "IA dans la santé", "def": "Use of artificial intelligence for diagnosis, treatment, administration or research.", "ex": "AI in healthcare may improve diagnosis but also create bias risks."}, {"term": "personalised medicine", "ipa": "/ˈpɜːsənəlaɪzd ˈmedsən/", "pron": "PUR-suh-nuh-lyzd MED-suhn", "fr": "médecine personnalisée", "def": "Medical care tailored to a patient’s genes, lifestyle or characteristics.", "ex": "Personalised medicine promises more targeted treatment."}, {"term": "genetic screening", "ipa": "/dʒəˌnetɪk ˈskriːnɪŋ/", "pron": "juh-NET-ik SKREE-ning", "fr": "dépistage génétique", "def": "Testing DNA to assess disease risk or inherited conditions.", "ex": "Genetic screening raises ethical and privacy concerns."}, {"term": "organ donation", "ipa": "/ˈɔːɡən dəʊˌneɪʃən/", "pron": "OR-guhn doh-NAY-shuhn", "fr": "don d’organes", "def": "Giving organs for transplantation after death or while alive.", "ex": "Organ donation can save lives."}, {"term": "organ transplant", "ipa": "/ˈɔːɡən ˈtrænsplɑːnt/", "pron": "OR-guhn TRANS-plant", "fr": "greffe d’organe", "def": "Surgery to replace a failing organ with a donated organ.", "ex": "Organ transplants depend on donation systems and waiting lists."}, {"term": "assisted dying", "ipa": "/əˌsɪstɪd ˈdaɪɪŋ/", "pron": "uh-SIS-tid DY-ing", "fr": "aide à mourir", "def": "Helping a terminally ill person end their life under legal conditions.", "ex": "Assisted dying is ethically and politically controversial."}, {"term": "euthanasia", "ipa": "/ˌjuːθəˈneɪziə/", "pron": "yoo-thuh-NAY-zee-uh", "fr": "euthanasie", "def": "The act of deliberately ending life to relieve suffering, usually in a medical context.", "ex": "Euthanasia debates involve autonomy, suffering and medical ethics."}, {"term": "reproductive rights", "ipa": "/ˌriːprəˈdʌktɪv raɪts/", "pron": "ree-pruh-DUK-tiv rites", "fr": "droits reproductifs", "def": "Rights concerning contraception, pregnancy, abortion and reproductive healthcare.", "ex": "Reproductive rights are central to healthcare and gender equality."}, {"term": "maternal healthcare", "ipa": "/məˌtɜːnəl ˈhelθkeə/", "pron": "muh-TUR-nuhl HELTH-care", "fr": "santé maternelle", "def": "Healthcare related to pregnancy, childbirth and after birth.", "ex": "Maternal healthcare can reduce deaths in childbirth."}, {"term": "healthcare capacity", "ipa": "/ˈhelθkeə kəˌpæsəti/", "pron": "HELTH-care kuh-PASS-uh-tee", "fr": "capacité du système de santé", "def": "The ability of a system to provide care, including staff, beds and equipment.", "ex": "Healthcare capacity can be overwhelmed during crises."}, {"term": "excess mortality", "ipa": "/ˌekses mɔːˈtæləti/", "pron": "EK-sess mor-TAL-uh-tee", "fr": "surmortalité", "def": "Deaths above the expected number in a given period.", "ex": "Excess mortality reveals the wider impact of a health crisis."}, {"term": "hospital admission rate", "ipa": "/ˈhɒspɪtəl ədˌmɪʃən reɪt/", "pron": "HOS-pi-tuhl ad-MISH-uhn rayt", "fr": "taux d’hospitalisation", "def": "The rate at which people are admitted to hospital.", "ex": "Hospital admission rates rise during epidemics."}, {"term": "readmission rate", "ipa": "/ˌriːədˈmɪʃən reɪt/", "pron": "ree-ad-MISH-uhn rayt", "fr": "taux de réadmission", "def": "The rate at which patients return to hospital after discharge.", "ex": "High readmission rates may indicate poor follow-up care."}, {"term": "vaccination rate", "ipa": "/ˌvæksɪˈneɪʃən reɪt/", "pron": "vak-si-NAY-shuhn rayt", "fr": "taux de vaccination", "def": "The proportion of a population that has been vaccinated.", "ex": "A high vaccination rate protects vulnerable people."}, {"term": "patient outcome", "ipa": "/ˈpeɪʃənt ˌaʊtkʌm/", "pron": "PAY-shuhnt OWT-kum", "fr": "résultat pour le patient", "def": "The result of medical care for a patient.", "ex": "Patient outcomes improve when care is timely and coordinated."}, {"term": "cost-effectiveness", "ipa": "/ˌkɒst ɪˈfektɪvnəs/", "pron": "kost i-FEK-tiv-nuhs", "fr": "rapport coût-efficacité", "def": "The value of a treatment compared with its cost.", "ex": "Cost-effectiveness matters when health budgets are limited."}, {"term": "efficiency", "ipa": "/ɪˈfɪʃənsi/", "pron": "i-FISH-uhn-see", "fr": "efficacité ; efficience", "def": "The ability to achieve results with minimal waste.", "ex": "Efficiency must not come at the expense of patient care."}, {"term": "to provide healthcare", "ipa": "/prəˈvaɪd ˈhelθkeə/", "pron": "pruh-VYDE HELTH-care", "fr": "fournir des soins de santé", "def": "To make medical services available.", "ex": "The state has a duty to provide healthcare."}, {"term": "to improve health outcomes", "ipa": "/ɪmˈpruːv ˈhelθ ˌaʊtkʌmz/", "pron": "im-PROOV helth OWT-kumz", "fr": "améliorer les résultats de santé", "def": "To make health results better for patients or populations.", "ex": "Preventive policies can improve health outcomes."}, {"term": "to reduce mortality", "ipa": "/rɪˈdjuːs mɔːˈtæləti/", "pron": "ri-DYOOSS mor-TAL-uh-tee", "fr": "réduire la mortalité", "def": "To lower the number of deaths.", "ex": "Vaccination can reduce mortality."}, {"term": "to increase life expectancy", "ipa": "/ɪnˈkriːs ˈlaɪf ɪkˌspektənsi/", "pron": "in-KREESS life ik-SPEK-tuhn-see", "fr": "augmenter l’espérance de vie", "def": "To raise the average number of years people live.", "ex": "Public health measures can increase life expectancy."}, {"term": "to prevent disease", "ipa": "/prɪˈvent dɪˈziːz/", "pron": "pri-VENT di-ZEEZ", "fr": "prévenir les maladies", "def": "To stop disease from occurring.", "ex": "Prevention campaigns aim to prevent disease."}, {"term": "to expand access to care", "ipa": "/ɪkˈspænd ˈækses tə keə/", "pron": "ik-SPAND AK-sess tuh care", "fr": "élargir l’accès aux soins", "def": "To make healthcare available to more people.", "ex": "Telemedicine can expand access to care."}, {"term": "to tackle health inequalities", "ipa": "/ˈtækəl helθ ˌɪnɪˈkwɒlətiz/", "pron": "TAK-uhl helth in-i-KWOL-uh-teez", "fr": "lutter contre les inégalités de santé", "def": "To take action against unequal health outcomes or access.", "ex": "Governments must tackle health inequalities at their roots."}, {"term": "to strengthen public health", "ipa": "/ˈstreŋθən ˌpʌblɪk ˈhelθ/", "pron": "STRENG-thuhn PUB-lik helth", "fr": "renforcer la santé publique", "def": "To improve prevention, surveillance and population health systems.", "ex": "The pandemic showed the need to strengthen public health."}, {"term": "to fund healthcare", "ipa": "/fʌnd ˈhelθkeə/", "pron": "fund HELTH-care", "fr": "financer les soins de santé", "def": "To provide money for healthcare services.", "ex": "Ageing societies must find ways to fund healthcare."}, {"term": "to cut healthcare spending", "ipa": "/kʌt ˈhelθkeə ˈspendɪŋ/", "pron": "kut HELTH-care SPEN-ding", "fr": "réduire les dépenses de santé", "def": "To reduce money spent on healthcare.", "ex": "Cutting healthcare spending can increase waiting times."}, {"term": "to reform the healthcare system", "ipa": "/rɪˈfɔːm ðə ˈhelθkeə ˌsɪstəm/", "pron": "ri-FORM thuh HELTH-care SIS-tuhm", "fr": "réformer le système de santé", "def": "To change how healthcare is organised, funded or delivered.", "ex": "Many parties promise to reform the healthcare system."}, {"term": "to ease pressure on hospitals", "ipa": "/iːz ˈpreʃər ɒn ˈhɒspɪtəlz/", "pron": "eez PRESH-uh on HOS-pi-tuhlz", "fr": "soulager la pression sur les hôpitaux", "def": "To reduce strain on hospitals.", "ex": "Better primary care can ease pressure on hospitals."}, {"term": "to reduce waiting times", "ipa": "/rɪˈdjuːs ˈweɪtɪŋ taɪmz/", "pron": "ri-DYOOSS WAY-ting tymz", "fr": "réduire les délais d’attente", "def": "To shorten delays before appointments or treatment.", "ex": "Reducing waiting times requires staff, beds and funding."}, {"term": "to address mental health issues", "ipa": "/əˈdres ˌmentəl ˈhelθ ˌɪʃuːz/", "pron": "uh-DRESS MEN-tuhl helth ISH-ooz", "fr": "traiter les problèmes de santé mentale", "def": "To deal with problems related to mental health.", "ex": "Schools need resources to address mental health issues."}, {"term": "to improve patient care", "ipa": "/ɪmˈpruːv ˈpeɪʃənt keə/", "pron": "im-PROOV PAY-shuhnt care", "fr": "améliorer les soins aux patients", "def": "To make care safer, kinder or more effective.", "ex": "Better staffing can improve patient care."}, {"term": "to save lives", "ipa": "/seɪv laɪvz/", "pron": "sayv lyvz", "fr": "sauver des vies", "def": "To prevent people from dying.", "ex": "Early treatment can save lives."}, {"term": "to treat a condition", "ipa": "/triːt ə kənˈdɪʃən/", "pron": "treet uh kuhn-DISH-uhn", "fr": "traiter une affection", "def": "To provide care for a medical problem.", "ex": "Some conditions require long-term medication."}, {"term": "to vaccinate the population", "ipa": "/ˈvæksɪneɪt ðə ˌpɒpjʊˈleɪʃən/", "pron": "VAK-si-nayt thuh pop-yuh-LAY-shuhn", "fr": "vacciner la population", "def": "To give vaccines to a large group of people.", "ex": "The campaign aimed to vaccinate the population quickly."}, {"term": "to relieve pressure on the NHS", "ipa": "/rɪˈliːv ˈpreʃər ɒn ði ˌen eɪtʃ ˈes/", "pron": "ri-LEEV PRESH-uh on thee en-aych-ess", "fr": "soulager la pression sur le NHS", "def": "To reduce strain on the UK National Health Service.", "ex": "Preventive care can relieve pressure on the NHS."}]}]}, {"id": "p4c34", "part": 4, "chapter": 34, "title": "Crime And Justice", "file": "cpge_vocab_part4_chapter34_crime_and_justice_premium.html", "count": 171, "sections": [{"title": "A. Core crime, policing and investigation vocabulary", "entries": [{"term": "crime", "ipa": "/kraɪm/", "pron": "kryme", "fr": "crime ; criminalité", "def": "Illegal behaviour punishable by law.", "ex": "Crime is often used by politicians to discuss security and social order."}, {"term": "criminal justice", "ipa": "/ˌkrɪmɪnəl ˈdʒʌstɪs/", "pron": "KRIM-i-nuhl JUS-tis", "fr": "justice pénale", "def": "The system of police, courts and prisons dealing with crime.", "ex": "Criminal justice systems must balance punishment, prevention and rights."}, {"term": "justice system", "ipa": "/ˈdʒʌstɪs ˌsɪstəm/", "pron": "JUS-tis SIS-tuhm", "fr": "système judiciaire", "def": "The institutions that apply the law and resolve legal disputes.", "ex": "Trust in the justice system depends on fairness and transparency."}, {"term": "law enforcement", "ipa": "/ˈlɔː ɪnˌfɔːsmənt/", "pron": "law in-FORSS-muhnt", "fr": "application de la loi ; maintien de l’ordre", "def": "The work of making sure laws are obeyed, especially by police.", "ex": "Law enforcement is controversial when it is seen as discriminatory."}, {"term": "policing", "ipa": "/pəˈliːsɪŋ/", "pron": "puh-LEE-sing", "fr": "maintien de l’ordre ; action policière", "def": "The work, methods and organisation of the police.", "ex": "Policing methods can affect trust between citizens and the state."}, {"term": "police force", "ipa": "/pəˈliːs fɔːs/", "pron": "puh-LEESS force", "fr": "force de police", "def": "An organised body of police officers.", "ex": "The police force has faced criticism over institutional bias."}, {"term": "police officer", "ipa": "/pəˈliːs ˌɒfɪsə/", "pron": "puh-LEESS OFF-i-suh", "fr": "policier ; policière", "def": "A person whose job is to enforce the law.", "ex": "Police officers are expected to protect the public."}, {"term": "constable", "ipa": "/ˈkʌnstəbəl/", "pron": "KUN-stuh-buhl", "fr": "agent de police britannique", "def": "A police officer, especially in Britain.", "ex": "A constable has powers of arrest."}, {"term": "detective", "ipa": "/dɪˈtektɪv/", "pron": "di-TEK-tiv", "fr": "inspecteur ; enquêteur", "def": "A police officer who investigates crimes.", "ex": "Detectives investigate serious offences."}, {"term": "investigation", "ipa": "/ɪnˌvestɪˈɡeɪʃən/", "pron": "in-ves-ti-GAY-shuhn", "fr": "enquête", "def": "A formal inquiry into a crime or event.", "ex": "The investigation revealed failures in police procedure."}, {"term": "criminal investigation", "ipa": "/ˌkrɪmɪnəl ɪnˌvestɪˈɡeɪʃən/", "pron": "KRIM-i-nuhl in-ves-ti-GAY-shuhn", "fr": "enquête pénale", "def": "An inquiry into suspected criminal behaviour.", "ex": "A criminal investigation must gather reliable evidence."}, {"term": "suspect", "ipa": "/ˈsʌspekt/", "pron": "SUS-pekt", "fr": "suspect", "def": "A person believed to have committed a crime.", "ex": "A suspect is innocent until proven guilty."}, {"term": "victim", "ipa": "/ˈvɪktɪm/", "pron": "VIK-tim", "fr": "victime", "def": "A person harmed by a crime or wrongdoing.", "ex": "Victims often need protection and support during trials."}, {"term": "witness", "ipa": "/ˈwɪtnəs/", "pron": "WIT-nuhs", "fr": "témoin", "def": "A person who saw an event or can give evidence.", "ex": "A witness may be called to testify in court."}, {"term": "evidence", "ipa": "/ˈevɪdəns/", "pron": "EV-i-duhns", "fr": "preuves", "def": "Information, objects or testimony used to prove facts in a case.", "ex": "Evidence must be collected legally to be admissible."}, {"term": "forensic evidence", "ipa": "/fəˈrenzɪk ˈevɪdəns/", "pron": "fuh-REN-zik EV-i-duhns", "fr": "preuves médico-légales ; preuves scientifiques", "def": "Scientific evidence used in a criminal investigation.", "ex": "Forensic evidence can strengthen a prosecution case."}, {"term": "DNA evidence", "ipa": "/ˌdiː en ˈeɪ ˈevɪdəns/", "pron": "dee-en-ay EV-i-duhns", "fr": "preuve ADN", "def": "Genetic evidence used to identify people in investigations.", "ex": "DNA evidence has overturned wrongful convictions."}, {"term": "fingerprint", "ipa": "/ˈfɪŋɡəprɪnt/", "pron": "FIN-guh-print", "fr": "empreinte digitale", "def": "A mark left by the pattern of a person’s finger.", "ex": "Fingerprints can link a suspect to a crime scene."}, {"term": "crime scene", "ipa": "/ˈkraɪm siːn/", "pron": "kryme seen", "fr": "scène de crime", "def": "The place where a crime happened.", "ex": "The crime scene must be protected from contamination."}, {"term": "alibi", "ipa": "/ˈælɪbaɪ/", "pron": "AL-i-by", "fr": "alibi", "def": "Proof or claim that someone was elsewhere when a crime occurred.", "ex": "The defendant had a strong alibi."}, {"term": "motive", "ipa": "/ˈməʊtɪv/", "pron": "MOH-tiv", "fr": "mobile ; motif", "def": "The reason why someone commits a crime.", "ex": "Investigators looked for a possible motive."}, {"term": "offence", "ipa": "/əˈfens/", "pron": "uh-FENSS", "fr": "infraction", "def": "A crime or illegal act, especially in British English.", "ex": "The offence carries a maximum prison sentence."}, {"term": "felony", "ipa": "/ˈfeləni/", "pron": "FEL-uh-nee", "fr": "crime grave américain", "def": "A serious crime in the US legal system.", "ex": "A felony can lead to a long prison sentence."}, {"term": "misdemeanour", "ipa": "/ˌmɪsdɪˈmiːnə/", "pron": "mis-di-MEE-nuh", "fr": "délit mineur américain", "def": "A less serious crime in the US legal system.", "ex": "A misdemeanour is less serious than a felony."}]}, {"title": "B. Types of crime and criminal behaviour", "entries": [{"term": "violent crime", "ipa": "/ˌvaɪələnt ˈkraɪm/", "pron": "VY-uh-luhnt kryme", "fr": "crime violent", "def": "Crime involving force or threat of force.", "ex": "Violent crime often receives strong media attention."}, {"term": "property crime", "ipa": "/ˈprɒpəti kraɪm/", "pron": "PROP-uh-tee kryme", "fr": "atteinte aux biens", "def": "Crime involving theft or damage to property.", "ex": "Property crime includes burglary and vandalism."}, {"term": "white-collar crime", "ipa": "/ˌwaɪt ˈkɒlə kraɪm/", "pron": "white KOL-uh kryme", "fr": "criminalité en col blanc", "def": "Financial or corporate crime committed by professionals.", "ex": "White-collar crime can cause enormous economic harm."}, {"term": "organised crime", "ipa": "/ˌɔːɡənaɪzd ˈkraɪm/", "pron": "OR-guh-nyzd kryme", "fr": "crime organisé", "def": "Crime committed by structured criminal groups.", "ex": "Organised crime often involves trafficking and money laundering."}, {"term": "gang crime", "ipa": "/ˈɡæŋ kraɪm/", "pron": "gang kryme", "fr": "criminalité de gangs", "def": "Crime linked to street gangs or organised groups.", "ex": "Gang crime is often connected to poverty and exclusion."}, {"term": "knife crime", "ipa": "/ˈnaɪf kraɪm/", "pron": "nyfe kryme", "fr": "criminalité au couteau", "def": "Crime involving knives, especially assaults or threats.", "ex": "Knife crime has become a major concern in Britain."}, {"term": "gun crime", "ipa": "/ˈɡʌn kraɪm/", "pron": "gun kryme", "fr": "criminalité armée", "def": "Crime involving firearms.", "ex": "Gun crime is central to US debates about violence."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by hostility towards identity such as race, religion or sexuality.", "ex": "Hate crime can make whole communities feel unsafe."}, {"term": "domestic violence", "ipa": "/dəˌmestɪk ˈvaɪələns/", "pron": "duh-MES-tik VY-uh-luhns", "fr": "violence domestique ; violences conjugales", "def": "Violence or abuse within a family or intimate relationship.", "ex": "Domestic violence often remains hidden."}, {"term": "sexual assault", "ipa": "/ˌsekʃuəl əˈsɔːlt/", "pron": "SEK-shoo-uhl uh-SAWLT", "fr": "agression sexuelle", "def": "A sexual act committed without consent.", "ex": "Sexual assault cases require sensitive handling."}, {"term": "rape", "ipa": "/reɪp/", "pron": "rayp", "fr": "viol", "def": "Forced sexual intercourse or sexual penetration without consent.", "ex": "Rape victims often face stigma and disbelief."}, {"term": "harassment", "ipa": "/ˈhærəsmənt/", "pron": "HARR-uhs-muhnt", "fr": "harcèlement", "def": "Repeated behaviour that intimidates, threatens or humiliates someone.", "ex": "Online harassment can silence public voices."}, {"term": "stalking", "ipa": "/ˈstɔːkɪŋ/", "pron": "STAW-king", "fr": "harcèlement obsessionnel ; stalking", "def": "Repeated unwanted following or monitoring of someone.", "ex": "Stalking can escalate into violence."}, {"term": "burglary", "ipa": "/ˈbɜːɡləri/", "pron": "BUR-gluh-ree", "fr": "cambriolage", "def": "Entering a building illegally to steal.", "ex": "Burglary can leave victims feeling unsafe at home."}, {"term": "robbery", "ipa": "/ˈrɒbəri/", "pron": "ROB-uh-ree", "fr": "vol avec violence", "def": "Stealing from a person using force or threats.", "ex": "Robbery is treated as a serious violent offence."}, {"term": "theft", "ipa": "/θeft/", "pron": "theft", "fr": "vol", "def": "The act of stealing property.", "ex": "Theft can range from shoplifting to car theft."}, {"term": "shoplifting", "ipa": "/ˈʃɒplɪftɪŋ/", "pron": "SHOP-lif-ting", "fr": "vol à l’étalage", "def": "Stealing goods from a shop.", "ex": "Shoplifting often rises during periods of hardship."}, {"term": "fraud", "ipa": "/frɔːd/", "pron": "fraud", "fr": "fraude ; escroquerie", "def": "Deception for financial or personal gain.", "ex": "Fraud is increasingly committed online."}, {"term": "scam", "ipa": "/skæm/", "pron": "skam", "fr": "arnaque", "def": "A dishonest scheme designed to trick people out of money.", "ex": "Elderly people are often targeted by scams."}, {"term": "identity theft", "ipa": "/aɪˈdentəti θeft/", "pron": "eye-DEN-tuh-tee theft", "fr": "usurpation d’identité", "def": "Stealing someone’s personal information to commit fraud.", "ex": "Identity theft is a growing cybercrime."}, {"term": "money laundering", "ipa": "/ˈmʌni ˌlɔːndərɪŋ/", "pron": "MUN-ee LAWN-duh-ring", "fr": "blanchiment d’argent", "def": "Hiding the illegal origin of money.", "ex": "Money laundering allows criminal profits to enter the legal economy."}, {"term": "tax evasion", "ipa": "/ˈtæks ɪˌveɪʒən/", "pron": "taks i-VAY-zhuhn", "fr": "fraude fiscale", "def": "Illegal non-payment or underpayment of taxes.", "ex": "Tax evasion deprives the state of public revenue."}, {"term": "bribery", "ipa": "/ˈbraɪbəri/", "pron": "BRY-buh-ree", "fr": "corruption ; pot-de-vin", "def": "Giving or receiving money or favours to influence someone dishonestly.", "ex": "Bribery undermines trust in public institutions."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Dishonest abuse of power for personal gain.", "ex": "Corruption weakens democracy and the rule of law."}, {"term": "cybercrime", "ipa": "/ˈsaɪbəkraɪm/", "pron": "SY-buh-kryme", "fr": "cybercriminalité", "def": "Crime committed using computers or the internet.", "ex": "Cybercrime includes hacking, fraud and data theft."}, {"term": "hacking", "ipa": "/ˈhækɪŋ/", "pron": "HAK-ing", "fr": "piratage informatique", "def": "Gaining unauthorised access to computer systems.", "ex": "Hacking can target companies, governments or individuals."}, {"term": "phishing", "ipa": "/ˈfɪʃɪŋ/", "pron": "FISH-ing", "fr": "hameçonnage ; phishing", "def": "Fraudulent messages designed to steal information or money.", "ex": "Phishing emails often imitate banks or official services."}, {"term": "human trafficking", "ipa": "/ˌhjuːmən ˈtræfɪkɪŋ/", "pron": "HYOO-muhn TRAF-i-king", "fr": "traite des êtres humains", "def": "The exploitation of people through force, fraud or coercion.", "ex": "Human trafficking is a serious form of organised crime."}, {"term": "drug trafficking", "ipa": "/ˈdrʌɡ ˌtræfɪkɪŋ/", "pron": "drug TRAF-i-king", "fr": "trafic de drogue", "def": "The illegal trade in drugs.", "ex": "Drug trafficking funds organised crime networks."}, {"term": "smuggling", "ipa": "/ˈsmʌɡlɪŋ/", "pron": "SMUG-ling", "fr": "contrebande ; trafic", "def": "Illegally moving goods or people across borders.", "ex": "Smuggling networks exploit vulnerable migrants."}, {"term": "criminal record", "ipa": "/ˌkrɪmɪnəl ˈrekɔːd/", "pron": "KRIM-i-nuhl REK-awd", "fr": "casier judiciaire", "def": "An official record of someone’s crimes or convictions.", "ex": "A criminal record can limit employment opportunities."}]}, {"title": "C. Arrest, trial and court procedure", "entries": [{"term": "arrest", "ipa": "/əˈrest/", "pron": "uh-REST", "fr": "arrestation", "def": "The act of legally taking someone into custody.", "ex": "An arrest must usually be based on reasonable suspicion."}, {"term": "to arrest", "ipa": "/əˈrest/", "pron": "uh-REST", "fr": "arrêter", "def": "To take someone into police custody.", "ex": "Police arrested the suspect after the attack."}, {"term": "custody", "ipa": "/ˈkʌstədi/", "pron": "KUS-tuh-dee", "fr": "garde à vue ; détention", "def": "Legal detention by police or authorities.", "ex": "The suspect was held in custody overnight."}, {"term": "detention", "ipa": "/dɪˈtenʃən/", "pron": "di-TEN-shuhn", "fr": "détention ; rétention", "def": "The state of being held by authorities.", "ex": "Pre-trial detention should not become punishment before conviction."}, {"term": "bail", "ipa": "/beɪl/", "pron": "bayl", "fr": "libération sous caution", "def": "Temporary release while waiting for trial, sometimes with conditions.", "ex": "The judge granted bail with strict conditions."}, {"term": "charge", "ipa": "/tʃɑːdʒ/", "pron": "charj", "fr": "chef d’accusation ; inculpation", "def": "A formal accusation that someone has committed a crime.", "ex": "The suspect faced several charges."}, {"term": "to charge someone with", "ipa": "/tʃɑːdʒ ˈsʌmwʌn wɪð/", "pron": "charj SUM-wun with", "fr": "inculper quelqu’un de", "def": "To formally accuse someone of a crime.", "ex": "The police charged him with burglary."}, {"term": "prosecution", "ipa": "/ˌprɒsɪˈkjuːʃən/", "pron": "pros-i-KYOO-shuhn", "fr": "poursuites ; accusation", "def": "The legal process of bringing a criminal case against someone.", "ex": "The prosecution must prove guilt beyond reasonable doubt."}, {"term": "prosecutor", "ipa": "/ˈprɒsɪkjuːtə/", "pron": "PROS-i-kyoo-tuh", "fr": "procureur ; procureure", "def": "A lawyer who brings a criminal case on behalf of the state.", "ex": "The prosecutor presented evidence to the jury."}, {"term": "defence", "ipa": "/dɪˈfens/", "pron": "di-FENSS", "fr": "défense", "def": "The argument or lawyers representing the accused.", "ex": "The defence challenged the reliability of the witness."}, {"term": "defendant", "ipa": "/dɪˈfendənt/", "pron": "di-FEN-duhnt", "fr": "prévenu ; accusé", "def": "A person accused in a court case.", "ex": "The defendant pleaded not guilty."}, {"term": "accused", "ipa": "/əˈkjuːzd/", "pron": "uh-KYOOZD", "fr": "accusé", "def": "The person charged with or suspected of a crime.", "ex": "The accused has the right to a fair trial."}, {"term": "trial", "ipa": "/ˈtraɪəl/", "pron": "TRY-uhl", "fr": "procès", "def": "A court process deciding whether someone is guilty.", "ex": "A trial must be fair and impartial."}, {"term": "court", "ipa": "/kɔːt/", "pron": "court", "fr": "tribunal ; cour", "def": "A place or institution where legal cases are heard.", "ex": "The case went to court after a long investigation."}, {"term": "courtroom", "ipa": "/ˈkɔːtruːm/", "pron": "COURT-room", "fr": "salle d’audience", "def": "The room where a trial or hearing takes place.", "ex": "The courtroom was full of journalists."}, {"term": "judge", "ipa": "/dʒʌdʒ/", "pron": "juj", "fr": "juge", "def": "An official who applies the law in court.", "ex": "The judge explained the sentence."}, {"term": "jury", "ipa": "/ˈdʒʊəri/", "pron": "JOOR-ee", "fr": "jury", "def": "A group of citizens who decide facts in some trials.", "ex": "The jury found the defendant guilty."}, {"term": "juror", "ipa": "/ˈdʒʊərə/", "pron": "JOOR-uh", "fr": "juré", "def": "A member of a jury.", "ex": "Jurors must consider the evidence carefully."}, {"term": "verdict", "ipa": "/ˈvɜːdɪkt/", "pron": "VUR-dikt", "fr": "verdict", "def": "The decision of a jury or court on guilt or liability.", "ex": "The jury reached a guilty verdict."}, {"term": "guilty", "ipa": "/ˈɡɪlti/", "pron": "GIL-tee", "fr": "coupable", "def": "Responsible for committing a crime.", "ex": "A person is guilty only if the evidence proves it."}, {"term": "not guilty", "ipa": "/ˌnɒt ˈɡɪlti/", "pron": "not GIL-tee", "fr": "non coupable", "def": "A verdict meaning guilt has not been proved.", "ex": "The defendant was found not guilty."}, {"term": "innocent", "ipa": "/ˈɪnəsənt/", "pron": "IN-uh-suhnt", "fr": "innocent", "def": "Not guilty of a crime.", "ex": "The presumption of innocence protects the accused."}, {"term": "presumption of innocence", "ipa": "/prɪˌzʌmpʃən əv ˈɪnəsəns/", "pron": "pri-ZUMP-shuhn ov IN-uh-suhns", "fr": "présomption d’innocence", "def": "The principle that a person is innocent until proven guilty.", "ex": "The presumption of innocence is central to the rule of law."}, {"term": "burden of proof", "ipa": "/ˌbɜːdən əv ˈpruːf/", "pron": "BUR-duhn ov proof", "fr": "charge de la preuve", "def": "The duty to prove an accusation or claim.", "ex": "In criminal cases, the burden of proof lies with the prosecution."}, {"term": "beyond reasonable doubt", "ipa": "/bɪˌjɒnd ˌriːzənəbəl ˈdaʊt/", "pron": "bee-YOND REE-zuh-nuh-buhl dowt", "fr": "au-delà de tout doute raisonnable", "def": "The high standard needed to convict someone in a criminal trial.", "ex": "Guilt must be proved beyond reasonable doubt."}, {"term": "plea bargain", "ipa": "/ˈpliː ˌbɑːɡɪn/", "pron": "plee BAR-gin", "fr": "plaider-coupable négocié", "def": "An agreement where the accused pleads guilty in exchange for a lighter charge or sentence.", "ex": "Plea bargains are common in the US justice system."}, {"term": "to plead guilty", "ipa": "/pliːd ˈɡɪlti/", "pron": "pleed GIL-tee", "fr": "plaider coupable", "def": "To formally admit guilt in court.", "ex": "The defendant decided to plead guilty."}, {"term": "to plead not guilty", "ipa": "/pliːd ˌnɒt ˈɡɪlti/", "pron": "pleed not GIL-tee", "fr": "plaider non coupable", "def": "To formally deny guilt in court.", "ex": "She pleaded not guilty to all charges."}, {"term": "sentence", "ipa": "/ˈsentəns/", "pron": "SEN-tuhns", "fr": "peine ; condamnation", "def": "The punishment given by a court.", "ex": "The sentence was criticised as too lenient."}, {"term": "sentencing", "ipa": "/ˈsentənsɪŋ/", "pron": "SEN-tuhn-sing", "fr": "détermination de la peine", "def": "The process of deciding a punishment after conviction.", "ex": "Sentencing guidelines aim to make punishments consistent."}, {"term": "punishment", "ipa": "/ˈpʌnɪʃmənt/", "pron": "PUN-ish-muhnt", "fr": "punition ; peine", "def": "A penalty imposed for wrongdoing or crime.", "ex": "Punishment alone may not reduce reoffending."}, {"term": "fine", "ipa": "/faɪn/", "pron": "fine", "fr": "amende", "def": "Money paid as punishment for an offence.", "ex": "The court imposed a heavy fine."}, {"term": "community service", "ipa": "/kəˌmjuːnəti ˈsɜːvɪs/", "pron": "kuh-MYOO-nuh-tee SUR-vis", "fr": "travaux d’intérêt général", "def": "Unpaid work ordered by a court as punishment.", "ex": "Community service can be an alternative to prison."}, {"term": "probation", "ipa": "/prəˈbeɪʃən/", "pron": "pruh-BAY-shuhn", "fr": "mise à l’épreuve ; probation", "def": "A sentence allowing someone to remain in the community under supervision.", "ex": "Probation aims to monitor and rehabilitate offenders."}, {"term": "imprisonment", "ipa": "/ɪmˈprɪzənmənt/", "pron": "im-PRIZ-uhn-muhnt", "fr": "emprisonnement", "def": "The punishment of being kept in prison.", "ex": "Imprisonment is costly and can worsen social exclusion."}, {"term": "prison sentence", "ipa": "/ˈprɪzən ˌsentəns/", "pron": "PRIZ-uhn SEN-tuhns", "fr": "peine de prison", "def": "A punishment requiring time in prison.", "ex": "The crime carries a long prison sentence."}, {"term": "life sentence", "ipa": "/ˈlaɪf ˌsentəns/", "pron": "life SEN-tuhns", "fr": "réclusion à perpétuité", "def": "A prison sentence that can last for the rest of someone’s life.", "ex": "A life sentence is reserved for very serious crimes."}, {"term": "mandatory minimum sentence", "ipa": "/ˌmændətəri ˌmɪnɪməm ˈsentəns/", "pron": "MAN-duh-tuh-ree MIN-i-muhm SEN-tuhns", "fr": "peine plancher obligatoire", "def": "A legally required minimum punishment for an offence.", "ex": "Mandatory minimum sentences reduce judicial discretion."}]}, {"title": "D. Sentencing, prison and rehabilitation", "entries": [{"term": "capital punishment", "ipa": "/ˌkæpɪtəl ˈpʌnɪʃmənt/", "pron": "KAP-i-tuhl PUN-ish-muhnt", "fr": "peine capitale", "def": "The death penalty imposed by the state.", "ex": "Capital punishment remains controversial in the United States."}, {"term": "death penalty", "ipa": "/ˈdeθ ˌpenəlti/", "pron": "death PEN-uhl-tee", "fr": "peine de mort", "def": "Execution as punishment for a crime.", "ex": "Opponents argue that the death penalty risks wrongful execution."}, {"term": "prison", "ipa": "/ˈprɪzən/", "pron": "PRIZ-uhn", "fr": "prison", "def": "A place where convicted or detained people are held.", "ex": "Prisons are often overcrowded."}, {"term": "jail", "ipa": "/dʒeɪl/", "pron": "jayl", "fr": "prison ; maison d’arrêt", "def": "A place of detention; in the US often for short-term custody.", "ex": "Many people in jail have not yet been convicted."}, {"term": "inmate", "ipa": "/ˈɪnmeɪt/", "pron": "IN-mayt", "fr": "détenu", "def": "A person held in prison or jail.", "ex": "Inmates often have high rates of mental illness."}, {"term": "prisoner", "ipa": "/ˈprɪzənə/", "pron": "PRIZ-uh-nuh", "fr": "prisonnier ; détenu", "def": "A person kept in prison.", "ex": "Prisoners retain basic human rights."}, {"term": "detention centre", "ipa": "/dɪˈtenʃən ˌsentə/", "pron": "di-TEN-shuhn SEN-tuh", "fr": "centre de détention ; centre de rétention", "def": "A place where people are held by authorities.", "ex": "Detention centres are often criticised by rights groups."}, {"term": "solitary confinement", "ipa": "/ˌsɒlɪtəri kənˈfaɪnmənt/", "pron": "SOL-i-tuh-ree kuhn-FYNE-muhnt", "fr": "isolement carcéral", "def": "Keeping a prisoner alone with little human contact.", "ex": "Solitary confinement can damage mental health."}, {"term": "overcrowding", "ipa": "/ˌəʊvəˈkraʊdɪŋ/", "pron": "OH-vuh-KROW-ding", "fr": "surpopulation", "def": "A situation where too many people are held in too little space.", "ex": "Prison overcrowding undermines safety and rehabilitation."}, {"term": "prison overcrowding", "ipa": "/ˈprɪzən ˌəʊvəˈkraʊdɪŋ/", "pron": "PRIZ-uhn OH-vuh-KROW-ding", "fr": "surpopulation carcérale", "def": "Too many prisoners for the available prison capacity.", "ex": "Prison overcrowding is a major problem in many countries."}, {"term": "rehabilitation", "ipa": "/ˌriːhəˌbɪlɪˈteɪʃən/", "pron": "ree-huh-bil-i-TAY-shuhn", "fr": "réinsertion ; réhabilitation", "def": "Helping offenders change behaviour and reintegrate into society.", "ex": "Rehabilitation can reduce reoffending."}, {"term": "reintegration", "ipa": "/ˌriːɪntɪˈɡreɪʃən/", "pron": "ree-in-ti-GRAY-shuhn", "fr": "réinsertion", "def": "The process of returning to society after prison or exclusion.", "ex": "Reintegration requires housing, work and support."}, {"term": "reoffending", "ipa": "/ˌriːəˈfendɪŋ/", "pron": "ree-uh-FEN-ding", "fr": "récidive", "def": "Committing another crime after being punished or released.", "ex": "Education in prison can reduce reoffending."}, {"term": "recidivism", "ipa": "/rɪˈsɪdɪvɪzəm/", "pron": "ri-SID-i-viz-uhm", "fr": "récidive", "def": "The tendency to reoffend after punishment.", "ex": "High recidivism suggests that prisons are failing."}, {"term": "parole", "ipa": "/pəˈrəʊl/", "pron": "puh-ROHL", "fr": "libération conditionnelle", "def": "Early release from prison under supervision and conditions.", "ex": "Parole allows supervised reintegration into society."}, {"term": "criminalisation", "ipa": "/ˌkrɪmɪnəlaɪˈzeɪʃən/", "pron": "KRIM-i-nuh-ly-ZAY-shuhn", "fr": "criminalisation", "def": "Making an action illegal or treating people as criminals.", "ex": "The criminalisation of poverty can worsen exclusion."}, {"term": "decriminalisation", "ipa": "/ˌdiːkrɪmɪnəlaɪˈzeɪʃən/", "pron": "dee-KRIM-i-nuh-ly-ZAY-shuhn", "fr": "dépénalisation", "def": "Removing criminal penalties from an act.", "ex": "Decriminalisation of drug possession is debated as a public health approach."}, {"term": "restorative justice", "ipa": "/rɪˌstɔːrətɪv ˈdʒʌstɪs/", "pron": "ri-STORE-uh-tiv JUS-tis", "fr": "justice réparatrice", "def": "An approach focused on repairing harm between offender, victim and community.", "ex": "Restorative justice gives victims a voice in the process."}, {"term": "retributive justice", "ipa": "/rɪˌtrɪbjʊtɪv ˈdʒʌstɪs/", "pron": "ri-TRIB-yuh-tiv JUS-tis", "fr": "justice rétributive", "def": "Justice focused on punishment because wrongdoing deserves it.", "ex": "Retributive justice emphasises punishment and moral responsibility."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "The use of punishment to discourage crime.", "ex": "The deterrent effect of harsh sentences is often debated."}, {"term": "public safety", "ipa": "/ˌpʌblɪk ˈseɪfti/", "pron": "PUB-lik SAYF-tee", "fr": "sécurité publique", "def": "Protection of the public from harm or danger.", "ex": "Public safety is a legitimate goal of criminal justice."}, {"term": "victim support", "ipa": "/ˈvɪktɪm səˌpɔːt/", "pron": "VIK-tim suh-PORT", "fr": "aide aux victimes", "def": "Services helping victims of crime recover and navigate justice.", "ex": "Victim support can reduce trauma after crime."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit ; primauté du droit", "def": "The principle that everyone, including the state, is subject to law.", "ex": "The rule of law requires fair trials and independent courts."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "DYOO PROH-sess", "fr": "procédure régulière ; garanties procédurales", "def": "Fair legal procedures protecting individual rights.", "ex": "Due process prevents arbitrary punishment."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected from state interference.", "ex": "Counter-terrorism policies can threaten civil liberties."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights belonging to all people.", "ex": "Human rights apply even to prisoners."}, {"term": "police brutality", "ipa": "/pəˈliːs bruːˈtæləti/", "pron": "puh-LEESS broo-TAL-uh-tee", "fr": "violences policières", "def": "Excessive or violent use of force by police.", "ex": "Police brutality can trigger protests and demands for reform."}, {"term": "excessive force", "ipa": "/ɪkˌsesɪv ˈfɔːs/", "pron": "ik-SESS-iv force", "fr": "usage excessif de la force", "def": "More force than is necessary or lawful.", "ex": "Officers were accused of using excessive force."}, {"term": "racial profiling", "ipa": "/ˌreɪʃəl ˈprəʊfaɪlɪŋ/", "pron": "RAY-shuhl PROH-fy-ling", "fr": "profilage racial", "def": "Targeting people for suspicion based on race or ethnicity.", "ex": "Racial profiling damages trust in the police."}, {"term": "stop and search", "ipa": "/ˌstɒp ənd ˈsɜːtʃ/", "pron": "stop and search", "fr": "contrôle et fouille", "def": "Police power to stop someone and search them for illegal items.", "ex": "Stop and search is controversial when used disproportionately."}, {"term": "mass incarceration", "ipa": "/ˌmæs ɪnˌkɑːsəˈreɪʃən/", "pron": "mass in-kar-suh-RAY-shuhn", "fr": "incarcération de masse", "def": "The imprisonment of very large numbers of people.", "ex": "Mass incarceration is a major issue in the United States."}, {"term": "prison-industrial complex", "ipa": "/ˌprɪzən ɪnˈdʌstriəl ˈkɒmpleks/", "pron": "PRIZ-uhn in-DUS-tree-uhl KOM-pleks", "fr": "complexe carcéro-industriel", "def": "The network of prisons, companies and interests benefiting from incarceration.", "ex": "Critics say the prison-industrial complex profits from punishment."}]}, {"title": "E. Rights, reform, public order and high-value verbs", "entries": [{"term": "school-to-prison pipeline", "ipa": "/ˌskuːl tə ˈprɪzən ˌpaɪplaɪn/", "pron": "school tuh PRIZ-uhn PIPE-line", "fr": "pipeline école-prison", "def": "Processes pushing students, especially disadvantaged ones, from school into the justice system.", "ex": "Harsh school discipline can feed the school-to-prison pipeline."}, {"term": "institutional racism", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈreɪsɪzəm/", "pron": "in-sti-TOO-shuh-nuhl RAY-siz-uhm", "fr": "racisme institutionnel", "def": "Racist outcomes produced by institutions, policies or practices.", "ex": "Institutional racism has been identified in policing and courts."}, {"term": "wrongful conviction", "ipa": "/ˌrɒŋfəl kənˈvɪkʃən/", "pron": "RONG-fuhl kuhn-VIK-shuhn", "fr": "erreur judiciaire ; condamnation injustifiée", "def": "A conviction of someone who did not commit the crime.", "ex": "Wrongful convictions reveal flaws in the justice system."}, {"term": "miscarriage of justice", "ipa": "/mɪsˌkærɪdʒ əv ˈdʒʌstɪs/", "pron": "mis-KARR-ij ov JUS-tis", "fr": "erreur judiciaire", "def": "A serious failure of justice, especially a wrongful conviction.", "ex": "The case became a symbol of miscarriage of justice."}, {"term": "appeal", "ipa": "/əˈpiːl/", "pron": "uh-PEEL", "fr": "appel", "def": "A request for a higher court to review a decision.", "ex": "The defendant filed an appeal against the conviction."}, {"term": "to appeal", "ipa": "/əˈpiːl/", "pron": "uh-PEEL", "fr": "faire appel", "def": "To ask a higher court to review a decision.", "ex": "She appealed the sentence."}, {"term": "acquittal", "ipa": "/əˈkwɪtəl/", "pron": "uh-KWIT-uhl", "fr": "acquittement", "def": "A legal decision that someone is not guilty.", "ex": "The acquittal provoked public debate."}, {"term": "conviction", "ipa": "/kənˈvɪkʃən/", "pron": "kuhn-VIK-shuhn", "fr": "condamnation", "def": "A formal finding that someone is guilty of a crime.", "ex": "A conviction can have lifelong consequences."}, {"term": "to convict", "ipa": "/kənˈvɪkt/", "pron": "kuhn-VIKT", "fr": "condamner ; déclarer coupable", "def": "To find someone guilty of a crime.", "ex": "The jury convicted the defendant of fraud."}, {"term": "to acquit", "ipa": "/əˈkwɪt/", "pron": "uh-KWIT", "fr": "acquitter", "def": "To find someone not guilty.", "ex": "The court acquitted the accused."}, {"term": "crime prevention", "ipa": "/ˈkraɪm prɪˌvenʃən/", "pron": "kryme pri-VEN-shuhn", "fr": "prévention de la criminalité", "def": "Actions designed to reduce crime before it happens.", "ex": "Crime prevention includes education, lighting and youth programmes."}, {"term": "surveillance", "ipa": "/səˈveɪləns/", "pron": "suh-VAY-luhns", "fr": "surveillance", "def": "Monitoring people, places or communications.", "ex": "Surveillance can improve security but threaten privacy."}, {"term": "CCTV", "ipa": "/ˌsiː siː tiː ˈviː/", "pron": "see-see-tee-vee", "fr": "vidéosurveillance", "def": "Closed-circuit television used for surveillance.", "ex": "CCTV is common in British cities."}, {"term": "facial recognition", "ipa": "/ˌfeɪʃəl rekəɡˈnɪʃən/", "pron": "FAY-shuhl rek-uhg-NISH-uhn", "fr": "reconnaissance faciale", "def": "Technology identifying people by their face.", "ex": "Facial recognition raises civil liberties concerns."}, {"term": "predictive policing", "ipa": "/prɪˌdɪktɪv pəˈliːsɪŋ/", "pron": "pri-DIK-tiv puh-LEE-sing", "fr": "police prédictive", "def": "Using data or algorithms to predict crime risks.", "ex": "Predictive policing can reproduce existing bias."}, {"term": "body camera", "ipa": "/ˈbɒdi ˌkæmərə/", "pron": "BOD-ee KAM-uh-ruh", "fr": "caméra-piéton", "def": "A camera worn by police officers to record interactions.", "ex": "Body cameras may increase accountability."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "The obligation to explain actions and face consequences.", "ex": "Police accountability is essential in a democracy."}, {"term": "transparency", "ipa": "/trænsˈpærənsi/", "pron": "trans-PARR-uhn-see", "fr": "transparence", "def": "Openness and clarity about decisions and actions.", "ex": "Transparency can rebuild trust in justice institutions."}, {"term": "criminal justice reform", "ipa": "/ˌkrɪmɪnəl ˈdʒʌstɪs rɪˌfɔːm/", "pron": "KRIM-i-nuhl JUS-tis ri-FORM", "fr": "réforme de la justice pénale", "def": "Changes intended to improve fairness, effectiveness or humanity in the justice system.", "ex": "Criminal justice reform often targets sentencing and prisons."}, {"term": "police reform", "ipa": "/pəˈliːs rɪˌfɔːm/", "pron": "puh-LEESS ri-FORM", "fr": "réforme de la police", "def": "Changes designed to improve policing methods, accountability or fairness.", "ex": "Police reform became a major demand after high-profile deaths."}, {"term": "prison reform", "ipa": "/ˈprɪzən rɪˌfɔːm/", "pron": "PRIZ-uhn ri-FORM", "fr": "réforme carcérale", "def": "Changes intended to improve prison conditions or reduce reoffending.", "ex": "Prison reform focuses on overcrowding, rehabilitation and rights."}, {"term": "sentencing reform", "ipa": "/ˈsentənsɪŋ rɪˌfɔːm/", "pron": "SEN-tuhn-sing ri-FORM", "fr": "réforme des peines", "def": "Changes to the rules governing punishment.", "ex": "Sentencing reform can reduce excessive imprisonment."}, {"term": "bail reform", "ipa": "/ˈbeɪl rɪˌfɔːm/", "pron": "bayl ri-FORM", "fr": "réforme de la caution", "def": "Changes to the system deciding who is released before trial.", "ex": "Bail reform aims to reduce detention based on poverty."}, {"term": "drug policy reform", "ipa": "/ˈdrʌɡ ˌpɒləsi rɪˌfɔːm/", "pron": "drug POL-uh-see ri-FORM", "fr": "réforme de la politique des drogues", "def": "Changes to laws and policies on drug use and trafficking.", "ex": "Drug policy reform can shift from punishment to public health."}, {"term": "war on drugs", "ipa": "/ˌwɔːr ɒn ˈdrʌɡz/", "pron": "war on drugz", "fr": "guerre contre la drogue", "def": "A punitive policy campaign against illegal drugs.", "ex": "The war on drugs contributed to mass incarceration."}, {"term": "tough on crime", "ipa": "/ˌtʌf ɒn ˈkraɪm/", "pron": "tuff on kryme", "fr": "dur envers la criminalité", "def": "A political stance favouring harsh punishment and strong policing.", "ex": "Tough-on-crime rhetoric often rises before elections."}, {"term": "law and order", "ipa": "/ˌlɔː ənd ˈɔːdə/", "pron": "law and OR-duh", "fr": "ordre public ; sécurité", "def": "A political phrase emphasising policing, punishment and public order.", "ex": "Law-and-order politics can appeal to fears about crime."}, {"term": "public order", "ipa": "/ˌpʌblɪk ˈɔːdə/", "pron": "PUB-lik OR-duh", "fr": "ordre public", "def": "Peace, safety and acceptable behaviour in public spaces.", "ex": "Public order laws can restrict protest."}, {"term": "civil unrest", "ipa": "/ˌsɪvəl ʌnˈrest/", "pron": "SIV-uhl un-REST", "fr": "troubles civils", "def": "Public disorder, protests or riots involving social tension.", "ex": "Civil unrest often follows perceived injustice."}, {"term": "riot", "ipa": "/ˈraɪət/", "pron": "RY-uht", "fr": "émeute", "def": "A violent disturbance by a crowd.", "ex": "Riots can be triggered by anger at policing."}, {"term": "protest", "ipa": "/ˈprəʊtest/", "pron": "PROH-test", "fr": "manifestation ; protestation", "def": "A public expression of opposition or demand for change.", "ex": "Protest is protected in democratic societies."}, {"term": "to commit a crime", "ipa": "/kəˈmɪt ə kraɪm/", "pron": "kuh-MIT uh kryme", "fr": "commettre un crime", "def": "To do something illegal.", "ex": "Poverty does not automatically make people commit crime."}, {"term": "to report a crime", "ipa": "/rɪˈpɔːt ə kraɪm/", "pron": "ri-PORT uh kryme", "fr": "signaler un crime", "def": "To inform the police that a crime has happened.", "ex": "Many victims do not report a crime because they fear disbelief."}, {"term": "to investigate a crime", "ipa": "/ɪnˈvestɪɡeɪt ə kraɪm/", "pron": "in-VES-ti-gayt uh kryme", "fr": "enquêter sur un crime", "def": "To examine a crime to find the offender and evidence.", "ex": "Police investigated the crime for several months."}, {"term": "to gather evidence", "ipa": "/ˈɡæðər ˈevɪdəns/", "pron": "GATH-uh EV-i-duhns", "fr": "rassembler des preuves", "def": "To collect proof or information for a case.", "ex": "Investigators must gather evidence carefully."}, {"term": "to press charges", "ipa": "/pres ˈtʃɑːdʒɪz/", "pron": "press CHAR-jiz", "fr": "porter plainte ; engager des poursuites", "def": "To formally accuse someone of a crime.", "ex": "The victim decided to press charges."}, {"term": "to stand trial", "ipa": "/stænd ˈtraɪəl/", "pron": "stand TRY-uhl", "fr": "être jugé", "def": "To be tried in court.", "ex": "The former minister will stand trial for corruption."}, {"term": "to face charges", "ipa": "/feɪs ˈtʃɑːdʒɪz/", "pron": "fays CHAR-jiz", "fr": "faire face à des accusations", "def": "To be formally accused of offences.", "ex": "The company faces charges of fraud."}, {"term": "to serve a sentence", "ipa": "/sɜːv ə ˈsentəns/", "pron": "surv uh SEN-tuhns", "fr": "purger une peine", "def": "To spend time under a court punishment, especially in prison.", "ex": "He served a sentence for robbery."}, {"term": "to reduce reoffending", "ipa": "/rɪˈdjuːs ˌriːəˈfendɪŋ/", "pron": "ri-DYOOSS ree-uh-FEN-ding", "fr": "réduire la récidive", "def": "To lower the likelihood that offenders commit new crimes.", "ex": "Education and housing support can reduce reoffending."}, {"term": "to deter crime", "ipa": "/dɪˈtɜː kraɪm/", "pron": "di-TUR kryme", "fr": "dissuader la criminalité", "def": "To discourage people from committing crimes.", "ex": "Harsh sentences do not always deter crime."}, {"term": "to rehabilitate offenders", "ipa": "/ˌriːhəˈbɪlɪteɪt əˈfendəz/", "pron": "ree-huh-BIL-i-tayt uh-FEN-duhz", "fr": "réhabiliter les délinquants", "def": "To help offenders change and reintegrate.", "ex": "Prison should rehabilitate offenders, not only punish them."}, {"term": "to protect the public", "ipa": "/prəˈtekt ðə ˈpʌblɪk/", "pron": "pruh-TEKT thuh PUB-lik", "fr": "protéger le public", "def": "To keep society safe from harm.", "ex": "The justice system must protect the public while respecting rights."}, {"term": "to uphold the rule of law", "ipa": "/ʌpˈhəʊld ðə ˌruːl əv ˈlɔː/", "pron": "up-HOHLD thuh rool ov law", "fr": "faire respecter l’État de droit", "def": "To defend and apply legal principles fairly.", "ex": "Independent courts uphold the rule of law."}, {"term": "to reform policing", "ipa": "/rɪˈfɔːm pəˈliːsɪŋ/", "pron": "ri-FORM puh-LEE-sing", "fr": "réformer la police", "def": "To change police practices or institutions.", "ex": "Many campaigners call for reforms to policing."}, {"term": "to hold the police accountable", "ipa": "/həʊld ðə pəˈliːs əˈkaʊntəbəl/", "pron": "hohld thuh puh-LEESS uh-KOWN-tuh-buhl", "fr": "tenir la police responsable", "def": "To make police answer for misconduct or abuse.", "ex": "Democracies must hold the police accountable."}]}]}, {"id": "p4c35", "part": 4, "chapter": 35, "title": "Religion", "file": "cpge_vocab_part4_chapter35_religion_premium.html", "count": 154, "sections": [{"title": "A. Core religion, belief and secularisation vocabulary", "entries": [{"term": "religion", "ipa": "/rɪˈlɪdʒən/", "pron": "ri-LIJ-uhn", "fr": "religion", "def": "A system of beliefs, practices and values concerning the sacred, God or gods.", "ex": "Religion continues to shape politics, identity and public debate."}, {"term": "faith", "ipa": "/feɪθ/", "pron": "faith", "fr": "foi", "def": "Strong belief in a religion, God or spiritual principles.", "ex": "Faith can provide meaning, community and moral guidance."}, {"term": "belief", "ipa": "/bɪˈliːf/", "pron": "bi-LEEF", "fr": "croyance", "def": "Something accepted as true, especially in religious or moral matters.", "ex": "Religious beliefs can influence political choices."}, {"term": "religious belief", "ipa": "/rɪˌlɪdʒəs bɪˈliːf/", "pron": "ri-LIJ-uhs bi-LEEF", "fr": "croyance religieuse", "def": "A belief connected to a religion or spiritual tradition.", "ex": "Democracies protect freedom of religious belief."}, {"term": "spirituality", "ipa": "/ˌspɪrɪtʃuˈæləti/", "pron": "spir-i-choo-AL-uh-tee", "fr": "spiritualité", "def": "Personal search for meaning, connection or transcendence, not always linked to organised religion.", "ex": "Many people describe themselves as spiritual but not religious."}, {"term": "organised religion", "ipa": "/ˌɔːɡənaɪzd rɪˈlɪdʒən/", "pron": "OR-guh-nyzd ri-LIJ-uhn", "fr": "religion organisée", "def": "Religion practised through institutions, clergy and formal rules.", "ex": "Organised religion has lost influence in many Western societies."}, {"term": "institutional religion", "ipa": "/ˌɪnstɪˈtjuːʃənəl rɪˈlɪdʒən/", "pron": "in-sti-TOO-shuh-nuhl ri-LIJ-uhn", "fr": "religion institutionnelle", "def": "Religion expressed through established institutions and hierarchies.", "ex": "Institutional religion is often criticised for conservatism or abuse of power."}, {"term": "religious practice", "ipa": "/rɪˌlɪdʒəs ˈpræktɪs/", "pron": "ri-LIJ-uhs PRAK-tis", "fr": "pratique religieuse", "def": "Actions connected to religion, such as prayer, worship or rituals.", "ex": "Religious practice has declined faster than religious identity in some countries."}, {"term": "worship", "ipa": "/ˈwɜːʃɪp/", "pron": "WUR-ship", "fr": "culte ; adoration", "def": "Acts of devotion, prayer or praise directed towards God or a deity.", "ex": "Places of worship can also serve as community centres."}, {"term": "prayer", "ipa": "/preə/", "pron": "prayer", "fr": "prière", "def": "Words or thoughts addressed to God or a spiritual power.", "ex": "Prayer can be private or collective."}, {"term": "ritual", "ipa": "/ˈrɪtʃuəl/", "pron": "RICH-oo-uhl", "fr": "rituel", "def": "A formal repeated religious or symbolic action.", "ex": "Rituals help create a sense of belonging."}, {"term": "ceremony", "ipa": "/ˈserəməni/", "pron": "SERR-uh-muh-nee", "fr": "cérémonie", "def": "A formal event, often religious or symbolic.", "ex": "Religious ceremonies mark birth, marriage and death."}, {"term": "sacred", "ipa": "/ˈseɪkrɪd/", "pron": "SAY-krid", "fr": "sacré", "def": "Connected with God, religion or spiritual importance.", "ex": "Sacred places often become politically sensitive."}, {"term": "secular", "ipa": "/ˈsekjələ/", "pron": "SEK-yuh-luh", "fr": "laïque ; séculier", "def": "Not religious or not controlled by religion.", "ex": "A secular state does not impose one religion."}, {"term": "secularism", "ipa": "/ˈsekjələrɪzəm/", "pron": "SEK-yuh-luh-riz-uhm", "fr": "laïcité ; sécularisme", "def": "The principle that religion and state should be separate.", "ex": "Secularism can protect both believers and non-believers."}, {"term": "secularisation", "ipa": "/ˌsekjələraɪˈzeɪʃən/", "pron": "sek-yuh-luh-ry-ZAY-shuhn", "fr": "sécularisation", "def": "The decline of religious influence in society and institutions.", "ex": "Secularisation has transformed many Western societies."}, {"term": "secular society", "ipa": "/ˌsekjələ səˈsaɪəti/", "pron": "SEK-yuh-luh suh-SY-uh-tee", "fr": "société sécularisée", "def": "A society where religion has limited formal influence on public life.", "ex": "Britain is often described as a secular society with religious traditions."}, {"term": "post-secular", "ipa": "/ˌpəʊst ˈsekjələ/", "pron": "post SEK-yuh-luh", "fr": "post-séculier", "def": "Describing a society where religion remains publicly relevant despite secularisation.", "ex": "Some scholars argue that Europe has entered a post-secular age."}, {"term": "atheism", "ipa": "/ˈeɪθiɪzəm/", "pron": "AY-thee-iz-uhm", "fr": "athéisme", "def": "The belief that God or gods do not exist.", "ex": "Atheism has become more visible in public debate."}, {"term": "atheist", "ipa": "/ˈeɪθiɪst/", "pron": "AY-thee-ist", "fr": "athée", "def": "A person who does not believe in God or gods.", "ex": "Atheists may still defend freedom of religion."}, {"term": "agnostic", "ipa": "/æɡˈnɒstɪk/", "pron": "ag-NOS-tik", "fr": "agnostique", "def": "A person who believes it is impossible or uncertain to know whether God exists.", "ex": "Many young people identify as agnostic rather than religious."}, {"term": "non-believer", "ipa": "/ˌnɒn bɪˈliːvə/", "pron": "non bi-LEE-vuh", "fr": "non-croyant", "def": "A person without religious belief.", "ex": "Non-believers also need protection from discrimination."}, {"term": "religious affiliation", "ipa": "/rɪˌlɪdʒəs əˌfɪliˈeɪʃən/", "pron": "ri-LIJ-uhs uh-fil-ee-AY-shuhn", "fr": "appartenance religieuse", "def": "Connection or membership of a religious group.", "ex": "Religious affiliation has declined in census data."}, {"term": "religious identity", "ipa": "/rɪˌlɪdʒəs aɪˈdentəti/", "pron": "ri-LIJ-uhs eye-DEN-tuh-tee", "fr": "identité religieuse", "def": "The part of identity connected to religion.", "ex": "Religious identity can overlap with ethnicity and culture."}, {"term": "religious community", "ipa": "/rɪˌlɪdʒəs kəˈmjuːnəti/", "pron": "ri-LIJ-uhs kuh-MYOO-nuh-tee", "fr": "communauté religieuse", "def": "A group of people sharing a religion or place of worship.", "ex": "Religious communities often provide social support."}, {"term": "denomination", "ipa": "/dɪˌnɒmɪˈneɪʃən/", "pron": "di-nom-i-NAY-shuhn", "fr": "confession ; dénomination", "def": "A branch or group within a religion, especially Christianity.", "ex": "Christian denominations differ in doctrine and worship."}, {"term": "sect", "ipa": "/sekt/", "pron": "sekt", "fr": "secte ; groupe religieux", "def": "A smaller religious group, sometimes seen as separate or extreme.", "ex": "The word sect can be pejorative."}, {"term": "cult", "ipa": "/kʌlt/", "pron": "kult", "fr": "secte ; culte controversé", "def": "A controversial term for a religious or spiritual group seen as controlling or extreme.", "ex": "The term cult is often used negatively."}, {"term": "clergy", "ipa": "/ˈklɜːdʒi/", "pron": "KLUR-jee", "fr": "clergé", "def": "Religious leaders such as priests, ministers, rabbis or imams.", "ex": "The clergy can influence moral and political debate."}, {"term": "priest", "ipa": "/priːst/", "pron": "preest", "fr": "prêtre", "def": "A religious leader in some Christian traditions.", "ex": "The priest led the ceremony."}]}, {"title": "B. Leaders, places of worship and major religions", "entries": [{"term": "minister", "ipa": "/ˈmɪnɪstə/", "pron": "MIN-i-stuh", "fr": "pasteur ; ministre du culte", "def": "A Christian religious leader, especially in Protestant churches.", "ex": "The minister spoke about poverty and justice."}, {"term": "pastor", "ipa": "/ˈpɑːstə/", "pron": "PAH-stuh", "fr": "pasteur", "def": "A Christian leader responsible for a congregation.", "ex": "The pastor organised community support after the disaster."}, {"term": "bishop", "ipa": "/ˈbɪʃəp/", "pron": "BISH-uhp", "fr": "évêque", "def": "A senior Christian religious leader.", "ex": "Bishops sit in the House of Lords in the UK."}, {"term": "archbishop", "ipa": "/ˌɑːtʃˈbɪʃəp/", "pron": "arch-BISH-uhp", "fr": "archevêque", "def": "A high-ranking bishop.", "ex": "The Archbishop of Canterbury is a major figure in the Church of England."}, {"term": "pope", "ipa": "/pəʊp/", "pron": "pope", "fr": "pape", "def": "The leader of the Roman Catholic Church.", "ex": "The pope often speaks on poverty, war and climate change."}, {"term": "rabbi", "ipa": "/ˈræbaɪ/", "pron": "RAB-eye", "fr": "rabbin", "def": "A Jewish religious teacher or leader.", "ex": "A rabbi may lead worship and interpret Jewish law."}, {"term": "imam", "ipa": "/ɪˈmɑːm/", "pron": "i-MAHM", "fr": "imam", "def": "A Muslim religious leader who may lead prayer and teach.", "ex": "The imam called for peace after the attack."}, {"term": "monk", "ipa": "/mʌŋk/", "pron": "munk", "fr": "moine", "def": "A man living in a religious community under vows.", "ex": "The monk lived in a monastery."}, {"term": "nun", "ipa": "/nʌn/", "pron": "nun", "fr": "religieuse ; nonne", "def": "A woman living in a religious community under vows.", "ex": "The nun worked in education and healthcare."}, {"term": "place of worship", "ipa": "/ˌpleɪs əv ˈwɜːʃɪp/", "pron": "place ov WUR-ship", "fr": "lieu de culte", "def": "A building or site used for religious worship.", "ex": "Places of worship can become targets of hate crime."}, {"term": "church", "ipa": "/tʃɜːtʃ/", "pron": "church", "fr": "église", "def": "A Christian place of worship or institution.", "ex": "The church plays a visible role in local life."}, {"term": "mosque", "ipa": "/mɒsk/", "pron": "mosk", "fr": "mosquée", "def": "A Muslim place of worship.", "ex": "The mosque opened its doors to the wider community."}, {"term": "synagogue", "ipa": "/ˈsɪnəɡɒɡ/", "pron": "SIN-uh-gog", "fr": "synagogue", "def": "A Jewish place of worship and community gathering.", "ex": "Security at the synagogue was increased after threats."}, {"term": "temple", "ipa": "/ˈtempəl/", "pron": "TEM-puhl", "fr": "temple", "def": "A place of worship in several religions, including Hinduism and Buddhism.", "ex": "The temple is an important cultural and religious centre."}, {"term": "cathedral", "ipa": "/kəˈθiːdrəl/", "pron": "kuh-THEE-druhl", "fr": "cathédrale", "def": "A major Christian church led by a bishop.", "ex": "Cathedrals are both religious and historical landmarks."}, {"term": "Christianity", "ipa": "/ˌkrɪstiˈænəti/", "pron": "kris-tee-AN-uh-tee", "fr": "christianisme", "def": "The religion based on the life and teachings of Jesus Christ.", "ex": "Christianity has deeply shaped European history."}, {"term": "Christian", "ipa": "/ˈkrɪstʃən/", "pron": "KRIS-chuhn", "fr": "chrétien", "def": "A person who follows Christianity.", "ex": "Christian identity can be religious, cultural or political."}, {"term": "Catholicism", "ipa": "/kəˈθɒlɪsɪzəm/", "pron": "kuh-THOL-i-siz-uhm", "fr": "catholicisme", "def": "The branch of Christianity led by the pope.", "ex": "Catholicism remains influential in debates on abortion and education."}, {"term": "Protestantism", "ipa": "/ˈprɒtɪstəntɪzəm/", "pron": "PROT-i-stuhn-tiz-uhm", "fr": "protestantisme", "def": "Branches of Christianity that emerged from the Reformation.", "ex": "Protestantism shaped British and American political culture."}, {"term": "Anglicanism", "ipa": "/ˈæŋɡlɪkənɪzəm/", "pron": "ANG-gli-kuh-niz-uhm", "fr": "anglicanisme", "def": "The Christian tradition of the Church of England and related churches.", "ex": "Anglicanism is linked to the British monarchy."}, {"term": "Church of England", "ipa": "/ˌtʃɜːtʃ əv ˈɪŋɡlənd/", "pron": "church ov ING-gluhnd", "fr": "Église d’Angleterre", "def": "The established Christian church in England.", "ex": "The Church of England remains connected to the state."}, {"term": "established church", "ipa": "/ɪˌstæblɪʃt ˈtʃɜːtʃ/", "pron": "i-STAB-lisht church", "fr": "Église établie", "def": "A church officially recognised and supported by the state.", "ex": "The Church of England is an established church."}, {"term": "Islam", "ipa": "/ˈɪzlɑːm/", "pron": "IZ-lahm", "fr": "islam", "def": "The religion based on the Qur’an and the teachings of Muhammad.", "ex": "Islam is one of the world’s largest religions."}, {"term": "Muslim", "ipa": "/ˈmʊzlɪm/", "pron": "MUZ-lim", "fr": "musulman", "def": "A person who follows Islam.", "ex": "Muslim communities are highly diverse."}, {"term": "Judaism", "ipa": "/ˈdʒuːdeɪɪzəm/", "pron": "JOO-day-iz-uhm", "fr": "judaïsme", "def": "The religion, culture and tradition of the Jewish people.", "ex": "Judaism has ancient roots and many traditions."}, {"term": "Jewish", "ipa": "/ˈdʒuːɪʃ/", "pron": "JOO-ish", "fr": "juif ; juive", "def": "Relating to Jews, Judaism or Jewish identity.", "ex": "Jewish identity can be religious, cultural and ethnic."}, {"term": "Hinduism", "ipa": "/ˈhɪnduːɪzəm/", "pron": "HIN-doo-iz-uhm", "fr": "hindouisme", "def": "A major religion originating in India.", "ex": "Hinduism includes many gods, traditions and philosophies."}, {"term": "Hindu", "ipa": "/ˈhɪnduː/", "pron": "HIN-doo", "fr": "hindou", "def": "A person who follows Hinduism.", "ex": "Hindu communities have shaped British multicultural life."}, {"term": "Buddhism", "ipa": "/ˈbʊdɪzəm/", "pron": "BUUD-iz-uhm", "fr": "bouddhisme", "def": "A religion and philosophy based on the teachings of the Buddha.", "ex": "Buddhism is often associated with meditation and compassion."}, {"term": "Buddhist", "ipa": "/ˈbʊdɪst/", "pron": "BUUD-ist", "fr": "bouddhiste", "def": "A person who follows Buddhism.", "ex": "Buddhist practice varies across cultures."}, {"term": "Sikhism", "ipa": "/ˈsiːkɪzəm/", "pron": "SEEK-iz-uhm", "fr": "sikhisme", "def": "A monotheistic religion founded in Punjab.", "ex": "Sikhism emphasises service, equality and devotion."}, {"term": "Sikh", "ipa": "/siːk/", "pron": "seek", "fr": "sikh", "def": "A person who follows Sikhism.", "ex": "Sikh identity is visible through symbols such as the turban."}, {"term": "religious minority", "ipa": "/rɪˌlɪdʒəs maɪˈnɒrəti/", "pron": "ri-LIJ-uhs my-NOR-uh-tee", "fr": "minorité religieuse", "def": "A religious group smaller or less powerful than the majority.", "ex": "Religious minorities may face discrimination."}, {"term": "majority religion", "ipa": "/məˌdʒɒrəti rɪˈlɪdʒən/", "pron": "muh-JOR-uh-tee ri-LIJ-uhn", "fr": "religion majoritaire", "def": "The dominant religion in a society.", "ex": "A majority religion can shape public holidays and institutions."}, {"term": "religious diversity", "ipa": "/rɪˌlɪdʒəs daɪˈvɜːsəti/", "pron": "ri-LIJ-uhs dy-VUR-suh-tee", "fr": "diversité religieuse", "def": "The presence of different religions in society.", "ex": "Religious diversity challenges states to protect pluralism."}, {"term": "pluralism", "ipa": "/ˈplʊərəlɪzəm/", "pron": "PLOOR-uh-liz-uhm", "fr": "pluralisme", "def": "The acceptance of different beliefs, groups and ways of life.", "ex": "Pluralism is essential in multicultural democracies."}, {"term": "interfaith dialogue", "ipa": "/ˌɪntəfeɪθ ˈdaɪəlɒɡ/", "pron": "IN-tuh-faith DY-uh-log", "fr": "dialogue interreligieux", "def": "Discussion and cooperation between different religious groups.", "ex": "Interfaith dialogue can reduce prejudice."}, {"term": "religious tolerance", "ipa": "/rɪˌlɪdʒəs ˈtɒlərəns/", "pron": "ri-LIJ-uhs TOL-uh-ruhns", "fr": "tolérance religieuse", "def": "Acceptance of different religious beliefs and practices.", "ex": "Religious tolerance is a cornerstone of liberal democracy."}, {"term": "freedom of religion", "ipa": "/ˌfriːdəm əv rɪˈlɪdʒən/", "pron": "FREE-duhm ov ri-LIJ-uhn", "fr": "liberté de religion", "def": "The right to hold, practise or change one’s religion.", "ex": "Freedom of religion includes the right not to believe."}, {"term": "freedom of conscience", "ipa": "/ˌfriːdəm əv ˈkɒnʃəns/", "pron": "FREE-duhm ov KON-shuhns", "fr": "liberté de conscience", "def": "The right to follow one’s moral or religious convictions.", "ex": "Freedom of conscience protects believers and non-believers."}]}, {"title": "C. Freedom of religion, pluralism and discrimination", "entries": [{"term": "religious freedom", "ipa": "/rɪˌlɪdʒəs ˈfriːdəm/", "pron": "ri-LIJ-uhs FREE-duhm", "fr": "liberté religieuse", "def": "The freedom to practise religion without persecution.", "ex": "Religious freedom is often invoked in culture-war debates."}, {"term": "freedom of worship", "ipa": "/ˌfriːdəm əv ˈwɜːʃɪp/", "pron": "FREE-duhm ov WUR-ship", "fr": "liberté de culte", "def": "The right to practise worship publicly or privately.", "ex": "Freedom of worship protects religious ceremonies and services."}, {"term": "religious discrimination", "ipa": "/rɪˌlɪdʒəs dɪˌskrɪmɪˈneɪʃən/", "pron": "ri-LIJ-uhs dis-krim-i-NAY-shuhn", "fr": "discrimination religieuse", "def": "Unfair treatment based on religion or belief.", "ex": "Religious discrimination can occur in workplaces and schools."}, {"term": "persecution", "ipa": "/ˌpɜːsɪˈkjuːʃən/", "pron": "pur-si-KYOO-shuhn", "fr": "persécution", "def": "Mistreatment because of identity, beliefs or religion.", "ex": "Religious persecution forces many people to flee their countries."}, {"term": "religious persecution", "ipa": "/rɪˌlɪdʒəs ˌpɜːsɪˈkjuːʃən/", "pron": "ri-LIJ-uhs pur-si-KYOO-shuhn", "fr": "persécution religieuse", "def": "Mistreatment of people because of their religion.", "ex": "Religious persecution remains widespread in many regions."}, {"term": "blasphemy", "ipa": "/ˈblæsfəmi/", "pron": "BLAS-fuh-mee", "fr": "blasphème", "def": "Speech or behaviour considered insulting to God or sacred things.", "ex": "Blasphemy laws raise questions about free speech."}, {"term": "apostasy", "ipa": "/əˈpɒstəsi/", "pron": "uh-POS-tuh-see", "fr": "apostasie", "def": "Abandoning or renouncing a religion.", "ex": "In some countries, apostasy is severely punished."}, {"term": "proselytising", "ipa": "/ˈprɒsəlɪtaɪzɪŋ/", "pron": "PROS-uh-li-ty-zing", "fr": "prosélytisme", "def": "Trying to convert others to a religion.", "ex": "Proselytising can be protected speech or viewed as pressure."}, {"term": "conversion", "ipa": "/kənˈvɜːʃən/", "pron": "kuhn-VUR-zhuhn", "fr": "conversion", "def": "Changing from one religion or belief to another.", "ex": "Religious conversion can be a deeply personal choice."}, {"term": "religious dress", "ipa": "/rɪˌlɪdʒəs ˈdres/", "pron": "ri-LIJ-uhs dress", "fr": "tenue religieuse", "def": "Clothing worn for religious reasons.", "ex": "Religious dress is often debated in secular societies."}, {"term": "headscarf", "ipa": "/ˈhedskɑːf/", "pron": "HED-skarf", "fr": "foulard", "def": "A scarf worn over the head, sometimes for religious reasons.", "ex": "The headscarf has become a controversial symbol in Europe."}, {"term": "hijab", "ipa": "/hɪˈdʒɑːb/", "pron": "hi-JAHB", "fr": "hijab ; voile islamique", "def": "A head covering worn by some Muslim women.", "ex": "The hijab is often discussed in debates about secularism and women’s rights."}, {"term": "veil", "ipa": "/veɪl/", "pron": "vayl", "fr": "voile", "def": "Cloth covering the face or head, often for religious or cultural reasons.", "ex": "Debates over the veil reveal tensions between freedom and secularism."}, {"term": "turban", "ipa": "/ˈtɜːbən/", "pron": "TUR-buhn", "fr": "turban", "def": "A head covering worn by many Sikh men and some other groups.", "ex": "The turban is an important Sikh religious symbol."}, {"term": "cross", "ipa": "/krɒs/", "pron": "kross", "fr": "croix", "def": "A Christian symbol representing the crucifixion of Jesus.", "ex": "Wearing a cross can be an expression of faith."}, {"term": "religious symbol", "ipa": "/rɪˌlɪdʒəs ˈsɪmbəl/", "pron": "ri-LIJ-uhs SIM-buhl", "fr": "symbole religieux", "def": "An object or sign representing a religion.", "ex": "Public display of religious symbols can be politically sensitive."}, {"term": "faith school", "ipa": "/ˈfeɪθ skuːl/", "pron": "faith school", "fr": "école confessionnelle", "def": "A school linked to a religious group or tradition.", "ex": "Faith schools raise debates about integration and parental choice."}, {"term": "religious education", "ipa": "/rɪˌlɪdʒəs ˌedjʊˈkeɪʃən/", "pron": "ri-LIJ-uhs ej-yoo-KAY-shuhn", "fr": "enseignement religieux ; culture religieuse", "def": "Teaching about religion, belief and ethics.", "ex": "Religious education can promote understanding if taught inclusively."}, {"term": "creationism", "ipa": "/kriˈeɪʃənɪzəm/", "pron": "kree-AY-shuh-niz-uhm", "fr": "créationnisme", "def": "The belief that life and the universe were created by God, often opposed to evolution.", "ex": "Creationism has sparked debates in American schools."}, {"term": "evolution", "ipa": "/ˌiːvəˈluːʃən/", "pron": "ee-vuh-LOO-shuhn", "fr": "évolution", "def": "The scientific theory explaining how living things change over time.", "ex": "Evolution is sometimes contested by religious conservatives."}, {"term": "religion and science", "ipa": "/rɪˌlɪdʒən ənd ˈsaɪəns/", "pron": "ri-LIJ-uhn and SY-uhns", "fr": "religion et science", "def": "The relationship, conflict or dialogue between religious belief and scientific knowledge.", "ex": "Religion and science are often wrongly presented as always opposed."}, {"term": "church and state", "ipa": "/ˌtʃɜːtʃ ənd ˈsteɪt/", "pron": "church and state", "fr": "Église et État", "def": "The relationship between religious institutions and government.", "ex": "The separation of church and state is a key secular principle."}, {"term": "separation of church and state", "ipa": "/ˌsepəˈreɪʃən əv ˌtʃɜːtʃ ənd ˈsteɪt/", "pron": "sep-uh-RAY-shuhn ov church and state", "fr": "séparation de l’Église et de l’État", "def": "The principle that government and religion should remain institutionally separate.", "ex": "The US Constitution is often associated with separation of church and state."}, {"term": "state religion", "ipa": "/ˌsteɪt rɪˈlɪdʒən/", "pron": "state ri-LIJ-uhn", "fr": "religion d’État", "def": "A religion officially recognised or supported by the state.", "ex": "A state religion can create tensions with religious minorities."}, {"term": "theocracy", "ipa": "/θiˈɒkrəsi/", "pron": "thee-OK-ruh-see", "fr": "théocratie", "def": "A system of government ruled by religious authorities or religious law.", "ex": "Iran is often described as a theocracy."}, {"term": "religious law", "ipa": "/rɪˌlɪdʒəs ˈlɔː/", "pron": "ri-LIJ-uhs law", "fr": "droit religieux", "def": "Law based on religious texts or principles.", "ex": "Religious law can conflict with secular law."}, {"term": "sharia", "ipa": "/ʃəˈriːə/", "pron": "shuh-REE-uh", "fr": "charia", "def": "Islamic law and moral guidance derived from religious sources.", "ex": "Sharia is often misunderstood in Western political debates."}, {"term": "canon law", "ipa": "/ˈkænən lɔː/", "pron": "KAN-uhn law", "fr": "droit canonique", "def": "The law of the Christian Church, especially the Catholic Church.", "ex": "Canon law governs internal church matters."}, {"term": "religious lobby", "ipa": "/rɪˌlɪdʒəs ˈlɒbi/", "pron": "ri-LIJ-uhs LOB-ee", "fr": "lobby religieux", "def": "A group trying to influence politics based on religious values.", "ex": "Religious lobbies influence debates on abortion and education."}, {"term": "religious right", "ipa": "/rɪˌlɪdʒəs ˈraɪt/", "pron": "ri-LIJ-uhs right", "fr": "droite religieuse", "def": "Conservative religious political movements, especially in the US.", "ex": "The religious right plays a major role in US politics."}, {"term": "Christian right", "ipa": "/ˌkrɪstʃən ˈraɪt/", "pron": "KRIS-chuhn right", "fr": "droite chrétienne", "def": "Politically conservative Christian movements, especially in the United States.", "ex": "The Christian right has influenced abortion and school debates."}, {"term": "evangelical", "ipa": "/ˌiːvænˈdʒelɪkəl/", "pron": "ee-van-JEL-i-kuhl", "fr": "évangélique", "def": "Relating to a Protestant movement emphasising personal faith and the Bible.", "ex": "Evangelical voters are important in US elections."}]}, {"title": "D. Religion, politics, culture wars and extremism", "entries": [{"term": "fundamentalism", "ipa": "/ˌfʌndəˈmentəlɪzəm/", "pron": "fun-duh-MEN-tuh-liz-uhm", "fr": "fondamentalisme", "def": "Strict adherence to religious texts or principles, often rejecting liberal interpretation.", "ex": "Fundamentalism can exist in different religions."}, {"term": "religious fundamentalism", "ipa": "/rɪˌlɪdʒəs ˌfʌndəˈmentəlɪzəm/", "pron": "ri-LIJ-uhs fun-duh-MEN-tuh-liz-uhm", "fr": "fondamentalisme religieux", "def": "A strict, literal and often politically assertive form of religion.", "ex": "Religious fundamentalism can challenge pluralism."}, {"term": "extremism", "ipa": "/ɪkˈstriːmɪzəm/", "pron": "ik-STREEM-iz-uhm", "fr": "extrémisme", "def": "Extreme political or religious views that may reject democratic norms or justify violence.", "ex": "Extremism should not be confused with ordinary religious belief."}, {"term": "religious extremism", "ipa": "/rɪˌlɪdʒəs ɪkˈstriːmɪzəm/", "pron": "ri-LIJ-uhs ik-STREEM-iz-uhm", "fr": "extrémisme religieux", "def": "Extremism justified by religious ideology.", "ex": "Religious extremism can fuel terrorism and discrimination."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "The process of adopting extreme views, sometimes leading to violence.", "ex": "Online propaganda can contribute to radicalisation."}, {"term": "terrorism", "ipa": "/ˈterərɪzəm/", "pron": "TERR-uh-riz-uhm", "fr": "terrorisme", "def": "The use of violence against civilians for political or ideological aims.", "ex": "Terrorism is often wrongly used to stigmatise whole communities."}, {"term": "Islamophobia", "ipa": "/ɪzˌlæməˈfəʊbiə/", "pron": "iz-lam-uh-FOH-bee-uh", "fr": "islamophobie", "def": "Hostility, prejudice or discrimination against Muslims.", "ex": "Islamophobia increased after several terrorist attacks."}, {"term": "antisemitism", "ipa": "/ˌæntiˈsemɪtɪzəm/", "pron": "AN-tee-SEM-i-tiz-uhm", "fr": "antisémitisme", "def": "Hostility, prejudice or discrimination against Jewish people.", "ex": "Antisemitism remains a serious threat in many societies."}, {"term": "anti-Catholicism", "ipa": "/ˌænti kəˈθɒlɪsɪzəm/", "pron": "AN-tee kuh-THOL-i-siz-uhm", "fr": "anticatholicisme", "def": "Hostility or prejudice against Catholics.", "ex": "Anti-Catholicism shaped parts of British history."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity, religion or group membership.", "ex": "Hate speech can target religious minorities."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by hostility towards identity such as religion or ethnicity.", "ex": "Religious hate crime can make communities feel unsafe."}, {"term": "blasphemy law", "ipa": "/ˈblæsfəmi lɔː/", "pron": "BLAS-fuh-mee law", "fr": "loi sur le blasphème", "def": "A law punishing speech considered insulting to religion.", "ex": "Blasphemy laws raise free speech concerns."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "The right to express opinions without censorship or punishment.", "ex": "Free speech may clash with protection from religious hatred."}, {"term": "offence", "ipa": "/əˈfens/", "pron": "uh-FENSS", "fr": "offense ; atteinte", "def": "Hurt or anger caused by something insulting or disrespectful.", "ex": "In liberal democracies, causing offence is not always illegal."}, {"term": "religious offence", "ipa": "/rɪˌlɪdʒəs əˈfens/", "pron": "ri-LIJ-uhs uh-FENSS", "fr": "offense religieuse", "def": "Insult or disrespect perceived towards religious beliefs or symbols.", "ex": "Debates over religious offence often involve satire."}, {"term": "satire", "ipa": "/ˈsætaɪə/", "pron": "SAT-eye-uh", "fr": "satire", "def": "Humour or criticism using irony, exaggeration or ridicule.", "ex": "Religious satire tests the limits of tolerance and free speech."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Religion often becomes a culture-war issue."}, {"term": "moral values", "ipa": "/ˌmɒrəl ˈvæljuːz/", "pron": "MOR-uhl VAL-yooz", "fr": "valeurs morales", "def": "Ideas about right and wrong behaviour.", "ex": "Religious groups often argue from moral values."}, {"term": "family values", "ipa": "/ˌfæməli ˈvæljuːz/", "pron": "FAM-uh-lee VAL-yooz", "fr": "valeurs familiales", "def": "Conservative ideas about family, marriage and morality.", "ex": "Family values are often invoked in religious politics."}, {"term": "abortion debate", "ipa": "/əˈbɔːʃən dɪˌbeɪt/", "pron": "uh-BOR-shuhn di-BAYT", "fr": "débat sur l’avortement", "def": "Public debate over the legality and morality of abortion.", "ex": "Religion plays a major role in the abortion debate."}, {"term": "reproductive rights", "ipa": "/ˌriːprəˈdʌktɪv raɪts/", "pron": "ree-pruh-DUK-tiv rites", "fr": "droits reproductifs", "def": "Rights concerning contraception, pregnancy and abortion.", "ex": "Reproductive rights often clash with religious conservatism."}, {"term": "same-sex marriage", "ipa": "/ˌseɪm seks ˈmærɪdʒ/", "pron": "same-seks MARR-ij", "fr": "mariage homosexuel", "def": "Marriage between two people of the same sex.", "ex": "Many religious groups opposed same-sex marriage."}, {"term": "LGBTQ+ rights", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs raɪts/", "pron": "el-jee-bee-tee-KYOO-plus rites", "fr": "droits LGBTQ+", "def": "Rights protecting lesbian, gay, bisexual, transgender and queer people.", "ex": "LGBTQ+ rights can conflict with conservative religious doctrine."}, {"term": "conscientious objection", "ipa": "/ˌkɒnʃiˈenʃəs əbˈdʒekʃən/", "pron": "kon-shee-EN-shuhs ub-JEK-shuhn", "fr": "objection de conscience", "def": "Refusal to do something because of moral or religious beliefs.", "ex": "Conscientious objection is debated in healthcare and military service."}, {"term": "religious exemption", "ipa": "/rɪˌlɪdʒəs ɪɡˈzempʃən/", "pron": "ri-LIJ-uhs ig-ZEMP-shuhn", "fr": "exemption religieuse", "def": "An exception to a rule granted for religious reasons.", "ex": "Religious exemptions can conflict with equality law."}, {"term": "faith-based organisation", "ipa": "/ˈfeɪθ beɪst ˌɔːɡənaɪˈzeɪʃən/", "pron": "faith-bayst OR-guh-ny-ZAY-shuhn", "fr": "organisation confessionnelle", "def": "An organisation inspired by or connected to religion.", "ex": "Faith-based organisations often provide charity and social services."}, {"term": "charity", "ipa": "/ˈtʃærəti/", "pron": "CHARR-uh-tee", "fr": "association caritative", "def": "An organisation helping people in need.", "ex": "Religious charities play a major role in humanitarian work."}, {"term": "humanitarian work", "ipa": "/hjuːˌmænɪˈteəriən wɜːk/", "pron": "hyoo-man-i-TAIR-ee-uhn work", "fr": "action humanitaire", "def": "Work intended to reduce suffering and protect human dignity.", "ex": "Many religious groups are involved in humanitarian work."}, {"term": "social justice", "ipa": "/ˌsəʊʃəl ˈdʒʌstɪs/", "pron": "SOH-shuhl JUS-tis", "fr": "justice sociale", "def": "Fairness in society, especially regarding poverty, rights and opportunity.", "ex": "Religion can inspire movements for social justice."}, {"term": "liberation theology", "ipa": "/ˌlɪbəˈreɪʃən θiˌɒlədʒi/", "pron": "lib-uh-RAY-shuhn thee-OL-uh-jee", "fr": "théologie de la libération", "def": "A Christian movement linking faith with the struggle against poverty and oppression.", "ex": "Liberation theology connects religion with social justice."}, {"term": "civil rights movement", "ipa": "/ˌsɪvəl ˈraɪts ˌmuːvmənt/", "pron": "SIV-uhl rites MOOV-muhnt", "fr": "mouvement des droits civiques", "def": "A movement fighting for equal rights, especially for African Americans in the US.", "ex": "Churches played a major role in the civil rights movement."}, {"term": "religious nationalism", "ipa": "/rɪˌlɪdʒəs ˈnæʃənəlɪzəm/", "pron": "ri-LIJ-uhs NASH-uh-nuh-liz-uhm", "fr": "nationalisme religieux", "def": "Nationalism that links national identity to a religion.", "ex": "Religious nationalism can exclude minorities."}, {"term": "Christian nationalism", "ipa": "/ˌkrɪstʃən ˈnæʃənəlɪzəm/", "pron": "KRIS-chuhn NASH-uh-nuh-liz-uhm", "fr": "nationalisme chrétien", "def": "A political ideology linking national identity to Christianity.", "ex": "Christian nationalism has become a concern in US politics."}, {"term": "Hindu nationalism", "ipa": "/ˌhɪnduː ˈnæʃənəlɪzəm/", "pron": "HIN-doo NASH-uh-nuh-liz-uhm", "fr": "nationalisme hindou", "def": "A political ideology linking Indian national identity to Hinduism.", "ex": "Hindu nationalism raises concerns about minority rights."}, {"term": "communalism", "ipa": "/kəˈmjuːnəlɪzəm/", "pron": "kuh-MYOO-nuh-liz-uhm", "fr": "communautarisme conflictuel ; tensions communautaires", "def": "Political conflict organised around religious or ethnic communities.", "ex": "Communalism can fuel violence between religious groups."}, {"term": "sectarianism", "ipa": "/sekˈteəriənɪzəm/", "pron": "sek-TAIR-ee-uh-niz-uhm", "fr": "sectarisme", "def": "Hostility between religious or communal groups.", "ex": "Sectarianism has shaped conflicts in Northern Ireland and the Middle East."}]}, {"title": "E. Social role, nationalism, conflict and high-value verbs", "entries": [{"term": "religious conflict", "ipa": "/rɪˌlɪdʒəs ˈkɒnflɪkt/", "pron": "ri-LIJ-uhs KON-flikt", "fr": "conflit religieux", "def": "Conflict involving religious identity, belief or institutions.", "ex": "Religious conflict is often mixed with politics, territory and power."}, {"term": "to practise a religion", "ipa": "/ˈpræktɪs ə rɪˈlɪdʒən/", "pron": "PRAK-tis uh ri-LIJ-uhn", "fr": "pratiquer une religion", "def": "To follow the rituals, beliefs or duties of a religion.", "ex": "Citizens must be free to practise a religion."}, {"term": "to worship", "ipa": "/ˈwɜːʃɪp/", "pron": "WUR-ship", "fr": "adorer ; pratiquer le culte", "def": "To show devotion to God or a deity.", "ex": "People gather to worship every week."}, {"term": "to pray", "ipa": "/preɪ/", "pron": "pray", "fr": "prier", "def": "To speak or think words addressed to God or a spiritual power.", "ex": "Some students ask for a quiet room to pray."}, {"term": "to convert to", "ipa": "/kənˈvɜːt tuː/", "pron": "kuhn-VURT too", "fr": "se convertir à", "def": "To change to a different religion or belief.", "ex": "He converted to Islam as an adult."}, {"term": "to discriminate against", "ipa": "/dɪˈskrɪmɪneɪt əˌɡenst/", "pron": "di-SKRIM-i-nayt uh-GENST", "fr": "discriminer", "def": "To treat someone unfairly because of identity or belief.", "ex": "Employers must not discriminate against religious minorities."}, {"term": "to persecute", "ipa": "/ˈpɜːsɪkjuːt/", "pron": "PUR-si-kyoot", "fr": "persécuter", "def": "To mistreat people because of identity, belief or religion.", "ex": "Authoritarian regimes may persecute religious minorities."}, {"term": "to protect religious freedom", "ipa": "/prəˈtekt rɪˌlɪdʒəs ˈfriːdəm/", "pron": "pruh-TEKT ri-LIJ-uhs FREE-duhm", "fr": "protéger la liberté religieuse", "def": "To defend the right to believe, worship or not believe.", "ex": "Liberal democracies must protect religious freedom."}, {"term": "to separate church and state", "ipa": "/ˈsepəreɪt ˌtʃɜːtʃ ənd ˈsteɪt/", "pron": "SEP-uh-rayt church and state", "fr": "séparer l’Église et l’État", "def": "To keep religious institutions and government distinct.", "ex": "Secularism seeks to separate church and state."}, {"term": "to challenge secular values", "ipa": "/ˈtʃælɪndʒ ˈsekjələ ˈvæljuːz/", "pron": "CHAL-inj SEK-yuh-luh VAL-yooz", "fr": "remettre en cause les valeurs laïques", "def": "To question values based on non-religious public principles.", "ex": "Religious conservatism can challenge secular values."}, {"term": "to fuel religious tensions", "ipa": "/ˈfjuːəl rɪˌlɪdʒəs ˈtenʃənz/", "pron": "FYOO-uhl ri-LIJ-uhs TEN-shuhnz", "fr": "alimenter les tensions religieuses", "def": "To intensify conflict between religious groups.", "ex": "Inflammatory rhetoric can fuel religious tensions."}, {"term": "to promote tolerance", "ipa": "/prəˈməʊt ˈtɒlərəns/", "pron": "pruh-MOHT TOL-uh-ruhns", "fr": "promouvoir la tolérance", "def": "To encourage acceptance of different beliefs and identities.", "ex": "Education can promote tolerance in diverse societies."}, {"term": "to defend pluralism", "ipa": "/dɪˈfend ˈplʊərəlɪzəm/", "pron": "di-FEND PLOOR-uh-liz-uhm", "fr": "défendre le pluralisme", "def": "To protect coexistence between different beliefs and groups.", "ex": "Democracies must defend pluralism against extremism."}, {"term": "to balance rights", "ipa": "/ˈbæləns raɪts/", "pron": "BAL-uhns rites", "fr": "équilibrer les droits", "def": "To weigh different rights or freedoms against each other.", "ex": "Courts often balance rights in religious freedom cases."}, {"term": "to clash with secular law", "ipa": "/klæʃ wɪð ˈsekjələ lɔː/", "pron": "klash with SEK-yuh-luh law", "fr": "entrer en conflit avec la loi laïque", "def": "To conflict with non-religious state law.", "ex": "Religious practices may sometimes clash with secular law."}, {"term": "to shape public debate", "ipa": "/ʃeɪp ˌpʌblɪk dɪˈbeɪt/", "pron": "shayp PUB-lik di-BAYT", "fr": "façonner le débat public", "def": "To influence what people discuss and how they frame issues.", "ex": "Religion continues to shape public debate on morality and rights."}]}]}, {"id": "p4c36", "part": 4, "chapter": 36, "title": "Multiculturalism", "file": "cpge_vocab_part4_chapter36_multiculturalism_premium.html", "count": 155, "sections": [{"title": "A. Core multiculturalism, identity and cohesion vocabulary", "entries": [{"term": "multiculturalism", "ipa": "/ˌmʌltiˈkʌltʃərəlɪzəm/", "pron": "MUL-tee-KUL-chuh-ruh-liz-uhm", "fr": "multiculturalisme", "def": "The idea or policy that different cultural groups can coexist and be recognised within one society.", "ex": "Multiculturalism has shaped modern Britain, Canada and many immigrant societies."}, {"term": "multicultural society", "ipa": "/ˌmʌltiˈkʌltʃərəl səˈsaɪəti/", "pron": "MUL-tee-KUL-chuh-ruhl suh-SY-uh-tee", "fr": "société multiculturelle", "def": "A society made up of several cultural, ethnic or religious groups.", "ex": "A multicultural society must balance diversity and social cohesion."}, {"term": "cultural diversity", "ipa": "/ˌkʌltʃərəl daɪˈvɜːsəti/", "pron": "KUL-chuh-ruhl dy-VUR-suh-tee", "fr": "diversité culturelle", "def": "The presence of different cultures within a society or institution.", "ex": "Cultural diversity can enrich public life and creativity."}, {"term": "ethnic diversity", "ipa": "/ˌeθnɪk daɪˈvɜːsəti/", "pron": "ETH-nik dy-VUR-suh-tee", "fr": "diversité ethnique", "def": "The presence of different ethnic groups within a population.", "ex": "Ethnic diversity has increased in many Western cities."}, {"term": "religious diversity", "ipa": "/rɪˌlɪdʒəs daɪˈvɜːsəti/", "pron": "ri-LIJ-uhs dy-VUR-suh-tee", "fr": "diversité religieuse", "def": "The presence of different religions in one society.", "ex": "Religious diversity raises questions about secularism and tolerance."}, {"term": "pluralism", "ipa": "/ˈplʊərəlɪzəm/", "pron": "PLOOR-uh-liz-uhm", "fr": "pluralisme", "def": "The acceptance of different beliefs, identities and ways of life within a society.", "ex": "Pluralism is central to liberal democracy."}, {"term": "cultural pluralism", "ipa": "/ˌkʌltʃərəl ˈplʊərəlɪzəm/", "pron": "KUL-chuh-ruhl PLOOR-uh-liz-uhm", "fr": "pluralisme culturel", "def": "A model where different cultures coexist without being forced to assimilate.", "ex": "Cultural pluralism rejects the idea that everyone must adopt one dominant culture."}, {"term": "diversity", "ipa": "/daɪˈvɜːsəti/", "pron": "dy-VUR-suh-tee", "fr": "diversité", "def": "The presence of difference within a group or society.", "ex": "Diversity can be a strength if institutions are inclusive."}, {"term": "inclusion", "ipa": "/ɪnˈkluːʒən/", "pron": "in-KLOO-zhuhn", "fr": "inclusion", "def": "The process of making people feel accepted and able to participate fully.", "ex": "Inclusion goes beyond simply having diversity."}, {"term": "inclusive society", "ipa": "/ɪnˌkluːsɪv səˈsaɪəti/", "pron": "in-KLOO-siv suh-SY-uh-tee", "fr": "société inclusive", "def": "A society where people from different backgrounds can participate equally.", "ex": "An inclusive society must fight discrimination and exclusion."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The process by which individuals or groups become part of society while participating in public life.", "ex": "Integration requires both effort from newcomers and openness from society."}, {"term": "assimilation", "ipa": "/əˌsɪmɪˈleɪʃən/", "pron": "uh-sim-i-LAY-shuhn", "fr": "assimilation", "def": "The process of adopting the dominant culture, often by giving up minority cultural traits.", "ex": "Assimilation is often criticised for erasing minority identities."}, {"term": "acculturation", "ipa": "/əˌkʌltʃəˈreɪʃən/", "pron": "uh-KUL-chuh-RAY-shuhn", "fr": "acculturation", "def": "The process of adapting to another culture through contact with it.", "ex": "Acculturation can change language, habits and social norms."}, {"term": "social cohesion", "ipa": "/ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "SOH-shuhl koh-HEE-zhuhn", "fr": "cohésion sociale", "def": "The degree of trust, solidarity and connection within society.", "ex": "Social cohesion can be weakened by inequality and segregation."}, {"term": "community cohesion", "ipa": "/kəˌmjuːnəti kəʊˈhiːʒən/", "pron": "kuh-MYOO-nuh-tee koh-HEE-zhuhn", "fr": "cohésion communautaire", "def": "Positive relations and trust between groups in a local area.", "ex": "Community cohesion depends on shared spaces and mutual trust."}, {"term": "social fabric", "ipa": "/ˌsəʊʃəl ˈfæbrɪk/", "pron": "SOH-shuhl FAB-rik", "fr": "tissu social", "def": "The relationships, values and institutions that hold society together.", "ex": "Discrimination and poverty can damage the social fabric."}, {"term": "belonging", "ipa": "/bɪˈlɒŋɪŋ/", "pron": "bi-LONG-ing", "fr": "appartenance", "def": "A feeling of being accepted and part of a community.", "ex": "Belonging is essential for successful integration."}, {"term": "sense of belonging", "ipa": "/ˌsens əv bɪˈlɒŋɪŋ/", "pron": "sens ov bi-LONG-ing", "fr": "sentiment d’appartenance", "def": "The feeling that one is accepted as part of a group or society.", "ex": "A weak sense of belonging can fuel alienation."}, {"term": "identity", "ipa": "/aɪˈdentəti/", "pron": "eye-DEN-tuh-tee", "fr": "identité", "def": "A person’s sense of who they are, including culture, nationality, ethnicity and values.", "ex": "Multicultural societies often produce layered identities."}, {"term": "cultural identity", "ipa": "/ˌkʌltʃərəl aɪˈdentəti/", "pron": "KUL-chuh-ruhl eye-DEN-tuh-tee", "fr": "identité culturelle", "def": "A person’s sense of belonging to a culture or tradition.", "ex": "Cultural identity can be maintained across generations."}, {"term": "ethnic identity", "ipa": "/ˌeθnɪk aɪˈdentəti/", "pron": "ETH-nik eye-DEN-tuh-tee", "fr": "identité ethnique", "def": "A sense of belonging to an ethnic group.", "ex": "Ethnic identity can be a source of pride or discrimination."}, {"term": "national identity", "ipa": "/ˌnæʃənəl aɪˈdentəti/", "pron": "NASH-uh-nuhl eye-DEN-tuh-tee", "fr": "identité nationale", "def": "A sense of belonging to a nation.", "ex": "National identity is often debated in multicultural societies."}, {"term": "hyphenated identity", "ipa": "/ˈhaɪfəneɪtɪd aɪˈdentəti/", "pron": "HY-fuh-nay-tid eye-DEN-tuh-tee", "fr": "identité composée ; identité à trait d’union", "def": "An identity combining two cultural or national labels.", "ex": "British-Pakistani is an example of a hyphenated identity."}, {"term": "dual identity", "ipa": "/ˌdjuːəl aɪˈdentəti/", "pron": "DYOO-uhl eye-DEN-tuh-tee", "fr": "double identité", "def": "A sense of belonging to two groups, cultures or nations.", "ex": "Dual identity can enrich rather than weaken citizenship."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community living outside its ancestral homeland.", "ex": "Diaspora communities often maintain transnational links."}, {"term": "minority", "ipa": "/maɪˈnɒrəti/", "pron": "my-NOR-uh-tee", "fr": "minorité", "def": "A group that is smaller or less powerful than the majority.", "ex": "Minorities may need protection against discrimination."}, {"term": "ethnic minority", "ipa": "/ˌeθnɪk maɪˈnɒrəti/", "pron": "ETH-nik my-NOR-uh-tee", "fr": "minorité ethnique", "def": "A minority group sharing a common ethnic background.", "ex": "Ethnic minority communities are not homogeneous."}, {"term": "visible minority", "ipa": "/ˌvɪzəbəl maɪˈnɒrəti/", "pron": "VIZ-uh-buhl my-NOR-uh-tee", "fr": "minorité visible", "def": "A person or group visibly different from the majority population, often used in Canada.", "ex": "The term visible minority is used in Canadian public policy."}, {"term": "majority group", "ipa": "/məˈdʒɒrəti ɡruːp/", "pron": "muh-JOR-uh-tee group", "fr": "groupe majoritaire", "def": "The dominant or largest group in a society.", "ex": "Majority groups may see their norms as neutral."}, {"term": "minority group", "ipa": "/maɪˈnɒrəti ɡruːp/", "pron": "my-NOR-uh-tee group", "fr": "groupe minoritaire", "def": "A group with less numerical or social power.", "ex": "Minority groups can face stereotypes and exclusion."}, {"term": "host society", "ipa": "/ˈhəʊst səˌsaɪəti/", "pron": "host suh-SY-uh-tee", "fr": "société d’accueil", "def": "The society that receives migrants or minority groups.", "ex": "The host society also has responsibilities in integration."}, {"term": "mainstream society", "ipa": "/ˈmeɪnstriːm səˌsaɪəti/", "pron": "MAYN-streem suh-SY-uh-tee", "fr": "société dominante", "def": "The dominant social and cultural life of a country.", "ex": "Some communities feel excluded from mainstream society."}, {"term": "dominant culture", "ipa": "/ˈdɒmɪnənt ˈkʌltʃə/", "pron": "DOM-i-nuhnt KUL-chuh", "fr": "culture dominante", "def": "The culture with the most social power in a society.", "ex": "Assimilation pressures minorities to adopt the dominant culture."}, {"term": "minority culture", "ipa": "/maɪˌnɒrəti ˈkʌltʃə/", "pron": "my-NOR-uh-tee KUL-chuh", "fr": "culture minoritaire", "def": "A culture practised by a smaller or less powerful group.", "ex": "Minority cultures can survive through language, religion and family traditions."}, {"term": "heritage", "ipa": "/ˈherɪtɪdʒ/", "pron": "HERR-i-tij", "fr": "héritage culturel", "def": "Cultural traditions, history and values passed down through generations.", "ex": "Heritage can be preserved through festivals and education."}, {"term": "cultural heritage", "ipa": "/ˌkʌltʃərəl ˈherɪtɪdʒ/", "pron": "KUL-chuh-ruhl HERR-i-tij", "fr": "patrimoine culturel", "def": "Traditions, language, art and history inherited from a culture.", "ex": "Cultural heritage is central to identity."}, {"term": "mother tongue", "ipa": "/ˌmʌðə ˈtʌŋ/", "pron": "MUTH-uh tung", "fr": "langue maternelle", "def": "The first language learned at home.", "ex": "A mother tongue can connect children to family heritage."}, {"term": "heritage language", "ipa": "/ˈherɪtɪdʒ ˌlæŋɡwɪdʒ/", "pron": "HERR-i-tij LANG-gwij", "fr": "langue d’héritage", "def": "A language spoken by a family or community but not dominant in society.", "ex": "Heritage language classes help maintain cultural identity."}, {"term": "bilingualism", "ipa": "/baɪˈlɪŋɡwəlɪzəm/", "pron": "by-LING-gwuh-liz-uhm", "fr": "bilinguisme", "def": "The ability to use two languages.", "ex": "Bilingualism can be an advantage in multicultural societies."}, {"term": "multilingualism", "ipa": "/ˌmʌltiˈlɪŋɡwəlɪzəm/", "pron": "MUL-tee-LING-gwuh-liz-uhm", "fr": "multilinguisme", "def": "The ability or presence of several languages in a society.", "ex": "Multilingualism reflects migration and cultural diversity."}, {"term": "code-switching", "ipa": "/ˈkəʊd ˌswɪtʃɪŋ/", "pron": "code SWITCH-ing", "fr": "alternance codique ; changement de registre", "def": "Switching between languages or styles depending on context.", "ex": "Code-switching is common among bilingual speakers."}, {"term": "cultural exchange", "ipa": "/ˌkʌltʃərəl ɪksˈtʃeɪndʒ/", "pron": "KUL-chuh-ruhl iks-CHAYNJ", "fr": "échange culturel", "def": "The sharing of ideas, customs and practices between cultures.", "ex": "Cultural exchange can reduce prejudice."}]}, {"title": "B. Cultural exchange, language, stereotypes and discrimination", "entries": [{"term": "cross-cultural", "ipa": "/ˌkrɒs ˈkʌltʃərəl/", "pron": "kross KUL-chuh-ruhl", "fr": "interculturel", "def": "Involving or comparing different cultures.", "ex": "Cross-cultural communication requires sensitivity."}, {"term": "intercultural dialogue", "ipa": "/ˌɪntəˈkʌltʃərəl ˈdaɪəlɒɡ/", "pron": "IN-tuh-KUL-chuh-ruhl DY-uh-log", "fr": "dialogue interculturel", "def": "Conversation and exchange between cultures.", "ex": "Intercultural dialogue can strengthen social cohesion."}, {"term": "cultural awareness", "ipa": "/ˌkʌltʃərəl əˈweənəs/", "pron": "KUL-chuh-ruhl uh-WAIR-nuhs", "fr": "sensibilité culturelle", "def": "Understanding and sensitivity towards different cultures.", "ex": "Cultural awareness is important in schools and workplaces."}, {"term": "cultural sensitivity", "ipa": "/ˌkʌltʃərəl ˌsensɪˈtɪvəti/", "pron": "KUL-chuh-ruhl sen-si-TIV-uh-tee", "fr": "sensibilité culturelle", "def": "Respectful awareness of cultural differences.", "ex": "Cultural sensitivity helps avoid stereotypes."}, {"term": "cultural appropriation", "ipa": "/ˌkʌltʃərəl əˌprəʊpriˈeɪʃən/", "pron": "KUL-chuh-ruhl uh-proh-pree-AY-shuhn", "fr": "appropriation culturelle", "def": "Using elements of another culture, often without respect, understanding or permission.", "ex": "Cultural appropriation is debated in fashion, music and entertainment."}, {"term": "cultural appreciation", "ipa": "/ˌkʌltʃərəl əˌpriːʃiˈeɪʃən/", "pron": "KUL-chuh-ruhl uh-pree-shee-AY-shuhn", "fr": "appréciation culturelle", "def": "Respectful learning from and valuing of another culture.", "ex": "Cultural appreciation requires context and respect."}, {"term": "stereotype", "ipa": "/ˈsteriətaɪp/", "pron": "STERR-ee-uh-type", "fr": "stéréotype", "def": "A fixed and oversimplified idea about a group.", "ex": "Stereotypes reduce individuals to group clichés."}, {"term": "prejudice", "ipa": "/ˈpredʒʊdɪs/", "pron": "PREJ-uh-dis", "fr": "préjugé", "def": "A negative opinion formed without fair knowledge or experience.", "ex": "Prejudice can lead to discrimination."}, {"term": "bias", "ipa": "/ˈbaɪəs/", "pron": "BY-uhs", "fr": "biais", "def": "A tendency to judge unfairly in favour of or against a group.", "ex": "Unconscious bias can affect hiring decisions."}, {"term": "unconscious bias", "ipa": "/ʌnˌkɒnʃəs ˈbaɪəs/", "pron": "un-KON-shuhs BY-uhs", "fr": "biais inconscient", "def": "Unintentional prejudiced assumptions affecting judgement.", "ex": "Unconscious bias training is common but debated."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity or background.", "ex": "Discrimination undermines equal citizenship."}, {"term": "racial discrimination", "ipa": "/ˌreɪʃəl dɪˌskrɪmɪˈneɪʃən/", "pron": "RAY-shuhl dis-krim-i-NAY-shuhn", "fr": "discrimination raciale", "def": "Unfair treatment based on race or ethnicity.", "ex": "Racial discrimination can affect housing, work and policing."}, {"term": "ethnic discrimination", "ipa": "/ˌeθnɪk dɪˌskrɪmɪˈneɪʃən/", "pron": "ETH-nik dis-krim-i-NAY-shuhn", "fr": "discrimination ethnique", "def": "Unfair treatment based on ethnic background.", "ex": "Ethnic discrimination can be direct or indirect."}, {"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "zen-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Fear or hostility towards foreigners or migrants.", "ex": "Xenophobia often intensifies during economic crises."}, {"term": "racism", "ipa": "/ˈreɪsɪzəm/", "pron": "RAY-siz-uhm", "fr": "racisme", "def": "Prejudice, discrimination or systems of inequality based on race.", "ex": "Racism can be individual, institutional or structural."}, {"term": "institutional racism", "ipa": "/ˌɪnstɪˈtjuːʃənəl ˈreɪsɪzəm/", "pron": "in-sti-TOO-shuh-nuhl RAY-siz-uhm", "fr": "racisme institutionnel", "def": "Racist outcomes produced by institutions, policies or practices.", "ex": "Institutional racism has been documented in policing and education."}, {"term": "structural racism", "ipa": "/ˌstrʌktʃərəl ˈreɪsɪzəm/", "pron": "STRUK-chuh-ruhl RAY-siz-uhm", "fr": "racisme structurel", "def": "Racism embedded in social, economic and political structures.", "ex": "Structural racism cannot be solved only by individual goodwill."}, {"term": "systemic racism", "ipa": "/sɪˌstemɪk ˈreɪsɪzəm/", "pron": "si-STEM-ik RAY-siz-uhm", "fr": "racisme systémique", "def": "Racism produced or reinforced by systems and institutions.", "ex": "Systemic racism shapes outcomes in health, housing and education."}, {"term": "racial profiling", "ipa": "/ˌreɪʃəl ˈprəʊfaɪlɪŋ/", "pron": "RAY-shuhl PROH-fy-ling", "fr": "profilage racial", "def": "Targeting people for suspicion based on race or ethnicity.", "ex": "Racial profiling damages trust in the police."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by hostility towards identity, religion or ethnicity.", "ex": "Hate crimes can intimidate whole communities."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking or dehumanising people based on identity.", "ex": "Hate speech tests the limits of free speech."}, {"term": "microaggression", "ipa": "/ˌmaɪkrəʊəˈɡreʃən/", "pron": "MY-kroh-uh-GRESH-uhn", "fr": "micro-agression", "def": "A subtle comment or action that expresses prejudice, often unintentionally.", "ex": "Microaggressions can accumulate and cause harm."}, {"term": "tokenism", "ipa": "/ˈtəʊkənɪzəm/", "pron": "TOH-kuh-niz-uhm", "fr": "symbolisme ; diversité de façade", "def": "Superficial inclusion of minority individuals to appear diverse without real change.", "ex": "Tokenism is not the same as genuine inclusion."}, {"term": "representation", "ipa": "/ˌreprɪzenˈteɪʃən/", "pron": "rep-ri-zen-TAY-shuhn", "fr": "représentation", "def": "The presence or portrayal of groups in politics, media or institutions.", "ex": "Representation matters because it shapes belonging and visibility."}, {"term": "underrepresentation", "ipa": "/ˌʌndəˌreprɪzenˈteɪʃən/", "pron": "UN-duh-rep-ri-zen-TAY-shuhn", "fr": "sous-représentation", "def": "Insufficient presence of a group in an institution or field.", "ex": "Underrepresentation remains common in elite professions."}, {"term": "overrepresentation", "ipa": "/ˌəʊvəˌreprɪzenˈteɪʃən/", "pron": "OH-vuh-rep-ri-zen-TAY-shuhn", "fr": "surreprésentation", "def": "Disproportionately high presence of a group in a category or institution.", "ex": "Minorities may be overrepresented in prison statistics."}, {"term": "diversity and inclusion", "ipa": "/daɪˌvɜːsəti ənd ɪnˈkluːʒən/", "pron": "dy-VUR-suh-tee and in-KLOO-zhuhn", "fr": "diversité et inclusion", "def": "Policies and practices promoting representation and equal participation.", "ex": "Diversity and inclusion policies are now common in workplaces."}, {"term": "DEI", "ipa": "/ˌdiː iː ˈaɪ/", "pron": "dee-ee-eye", "fr": "diversité, équité et inclusion", "def": "Diversity, equity and inclusion.", "ex": "DEI programmes have become controversial in US politics."}, {"term": "equity", "ipa": "/ˈekwəti/", "pron": "EK-wuh-tee", "fr": "équité", "def": "Fairness that recognises different needs and barriers.", "ex": "Equity differs from simple equal treatment."}, {"term": "equality", "ipa": "/iˈkwɒləti/", "pron": "i-KWOL-uh-tee", "fr": "égalité", "def": "The state of having the same rights, status or opportunities.", "ex": "Equality is a legal and moral principle."}, {"term": "equal opportunity", "ipa": "/ˌiːkwəl ˌɒpəˈtjuːnəti/", "pron": "EE-kwuhl op-uh-TYOO-nuh-tee", "fr": "égalité des chances", "def": "The principle that everyone should have the same chance to succeed.", "ex": "Equal opportunity requires removing barriers."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to improve access for historically disadvantaged groups.", "ex": "Affirmative action is strongly debated in the United States."}, {"term": "positive discrimination", "ipa": "/ˌpɒzətɪv dɪˌskrɪmɪˈneɪʃən/", "pron": "POZ-uh-tiv dis-krim-i-NAY-shuhn", "fr": "discrimination positive", "def": "British term for favouring disadvantaged groups; often legally restricted.", "ex": "Positive discrimination remains controversial in Britain."}, {"term": "positive action", "ipa": "/ˌpɒzətɪv ˈækʃən/", "pron": "POZ-uh-tiv AK-shuhn", "fr": "action positive", "def": "Steps to help disadvantaged groups without automatic preference.", "ex": "Positive action can encourage underrepresented candidates."}, {"term": "anti-racism", "ipa": "/ˌænti ˈreɪsɪzəm/", "pron": "AN-tee RAY-siz-uhm", "fr": "antiracisme", "def": "Active opposition to racism and racist structures.", "ex": "Anti-racism demands more than passive tolerance."}, {"term": "anti-discrimination law", "ipa": "/ˌænti dɪˌskrɪmɪˈneɪʃən lɔː/", "pron": "AN-tee dis-krim-i-NAY-shuhn law", "fr": "loi anti-discrimination", "def": "Law protecting people from unfair treatment based on identity.", "ex": "Anti-discrimination law protects minority rights."}, {"term": "minority rights", "ipa": "/maɪˌnɒrəti ˈraɪts/", "pron": "my-NOR-uh-tee rites", "fr": "droits des minorités", "def": "Rights protecting minority groups from discrimination or exclusion.", "ex": "Minority rights are essential in pluralist democracies."}, {"term": "civil rights", "ipa": "/ˌsɪvəl ˈraɪts/", "pron": "SIV-uhl rites", "fr": "droits civiques", "def": "Rights protecting equal treatment and participation in society.", "ex": "Civil rights movements have challenged racial inequality."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected from state interference.", "ex": "Civil liberties include speech, religion and assembly."}, {"term": "citizenship", "ipa": "/ˈsɪtɪzənʃɪp/", "pron": "SIT-i-zuhn-ship", "fr": "citoyenneté", "def": "Legal membership of a state and participation in civic life.", "ex": "Citizenship is both a legal status and a sense of belonging."}]}, {"title": "C. Equality, representation, segregation and community relations", "entries": [{"term": "civic participation", "ipa": "/ˌsɪvɪk pɑːˌtɪsɪˈpeɪʃən/", "pron": "SIV-ik par-tis-i-PAY-shuhn", "fr": "participation civique", "def": "Involvement in public and political life.", "ex": "Civic participation helps integration."}, {"term": "equal citizenship", "ipa": "/ˌiːkwəl ˈsɪtɪzənʃɪp/", "pron": "EE-kwuhl SIT-i-zuhn-ship", "fr": "citoyenneté égale", "def": "The idea that all citizens should have equal status and rights.", "ex": "Equal citizenship is weakened by discrimination."}, {"term": "shared values", "ipa": "/ˌʃeəd ˈvæljuːz/", "pron": "shaird VAL-yooz", "fr": "valeurs communes", "def": "Common principles meant to unite society.", "ex": "Shared values can help maintain cohesion in diverse societies."}, {"term": "British values", "ipa": "/ˌbrɪtɪʃ ˈvæljuːz/", "pron": "BRIT-ish VAL-yooz", "fr": "valeurs britanniques", "def": "Values officially promoted in the UK, such as democracy, tolerance and the rule of law.", "ex": "British values are often discussed in integration debates."}, {"term": "American melting pot", "ipa": "/əˌmerɪkən ˈmeltɪŋ pɒt/", "pron": "uh-MERR-i-kuhn MEL-ting pot", "fr": "melting pot américain", "def": "The idea that immigrants blend into one American identity.", "ex": "The melting pot metaphor suggests assimilation into a shared culture."}, {"term": "melting pot", "ipa": "/ˈmeltɪŋ pɒt/", "pron": "MEL-ting pot", "fr": "creuset culturel ; melting pot", "def": "A society where different groups merge into a common culture.", "ex": "The melting pot is often contrasted with multiculturalism."}, {"term": "salad bowl", "ipa": "/ˈsæləd bəʊl/", "pron": "SAL-uhd bowl", "fr": "salad bowl ; mosaïque culturelle", "def": "A metaphor for a society where cultures coexist while keeping distinct identities.", "ex": "The salad bowl model values difference rather than complete assimilation."}, {"term": "cultural mosaic", "ipa": "/ˌkʌltʃərəl məʊˈzeɪɪk/", "pron": "KUL-chuh-ruhl moh-ZAY-ik", "fr": "mosaïque culturelle", "def": "A metaphor, often Canadian, for diverse cultures forming one society without merging entirely.", "ex": "Canada is often described as a cultural mosaic."}, {"term": "colour-blindness", "ipa": "/ˈkʌlə blaɪndnəs/", "pron": "KUL-uh BLYND-nuhs", "fr": "indifférence à la couleur ; colorblindness", "def": "The idea of ignoring racial differences, often criticised for ignoring inequality.", "ex": "Colour-blindness can hide structural racism."}, {"term": "race-conscious policy", "ipa": "/ˈreɪs ˌkɒnʃəs ˈpɒləsi/", "pron": "race KON-shuhs POL-uh-see", "fr": "politique tenant compte de la race", "def": "Policy that explicitly considers race to address inequality.", "ex": "Race-conscious policies are controversial but aim to address historical injustice."}, {"term": "segregation", "ipa": "/ˌseɡrɪˈɡeɪʃən/", "pron": "seg-ri-GAY-shuhn", "fr": "ségrégation", "def": "The separation of groups in housing, education or public life.", "ex": "Segregation can be legal, social or economic."}, {"term": "residential segregation", "ipa": "/ˌrezɪdenʃəl ˌseɡrɪˈɡeɪʃən/", "pron": "rez-i-DEN-shuhl seg-ri-GAY-shuhn", "fr": "ségrégation résidentielle", "def": "The separation of groups into different neighbourhoods.", "ex": "Residential segregation limits access to schools and services."}, {"term": "school segregation", "ipa": "/ˈskuːl ˌseɡrɪˈɡeɪʃən/", "pron": "school seg-ri-GAY-shuhn", "fr": "ségrégation scolaire", "def": "Separation of pupils by race, class, religion or ethnicity in schools.", "ex": "School segregation reinforces inequality."}, {"term": "de facto segregation", "ipa": "/ˌdeɪ ˈfæktəʊ ˌseɡrɪˈɡeɪʃən/", "pron": "day FAK-toh seg-ri-GAY-shuhn", "fr": "ségrégation de fait", "def": "Segregation that exists in practice even if not required by law.", "ex": "De facto segregation can result from housing markets."}, {"term": "parallel lives", "ipa": "/ˌpærəlel ˈlaɪvz/", "pron": "PARR-uh-lel lyvz", "fr": "vies parallèles", "def": "A phrase describing communities living separately with little interaction.", "ex": "Parallel lives can weaken social cohesion."}, {"term": "ghettoisation", "ipa": "/ˌɡetəʊaɪˈzeɪʃən/", "pron": "GET-oh-eye-ZAY-shuhn", "fr": "ghettoïsation", "def": "The concentration and isolation of a minority group in a poor area.", "ex": "Ghettoisation is often linked to poverty and exclusion."}, {"term": "enclave", "ipa": "/ˈenkleɪv/", "pron": "EN-klayv", "fr": "enclave", "def": "A distinct community or area within a larger society.", "ex": "Ethnic enclaves can provide support but also risk isolation."}, {"term": "ethnic enclave", "ipa": "/ˌeθnɪk ˈenkleɪv/", "pron": "ETH-nik EN-klayv", "fr": "enclave ethnique", "def": "A neighbourhood or community dominated by one ethnic group.", "ex": "Ethnic enclaves can help newcomers find jobs and services."}, {"term": "community relations", "ipa": "/kəˌmjuːnəti rɪˈleɪʃənz/", "pron": "kuh-MYOO-nuh-tee ri-LAY-shuhnz", "fr": "relations intercommunautaires", "def": "Relations between different groups in society.", "ex": "Community relations can be harmed by hate crime."}, {"term": "intercommunity tension", "ipa": "/ˌɪntəkəˈmjuːnəti ˈtenʃən/", "pron": "IN-tuh-kuh-MYOO-nuh-tee TEN-shuhn", "fr": "tension intercommunautaire", "def": "Tension between different communities.", "ex": "Economic hardship can fuel intercommunity tension."}, {"term": "social unrest", "ipa": "/ˌsəʊʃəl ʌnˈrest/", "pron": "SOH-shuhl un-REST", "fr": "troubles sociaux", "def": "Public disorder or protest caused by social tensions.", "ex": "Social unrest may follow police violence or discrimination."}, {"term": "race riot", "ipa": "/ˈreɪs ˌraɪət/", "pron": "race RY-uht", "fr": "émeute raciale", "def": "Violent unrest involving racial tensions.", "ex": "Race riots often reveal deep social inequality."}, {"term": "community leader", "ipa": "/kəˌmjuːnəti ˈliːdə/", "pron": "kuh-MYOO-nuh-tee LEE-duh", "fr": "responsable communautaire", "def": "A person who represents or influences a community.", "ex": "Community leaders called for calm after the attack."}, {"term": "grassroots organisation", "ipa": "/ˌɡrɑːsruːts ˌɔːɡənaɪˈzeɪʃən/", "pron": "grass-roots OR-guh-ny-ZAY-shuhn", "fr": "organisation de terrain", "def": "A local organisation created by ordinary people rather than elites.", "ex": "Grassroots organisations often support migrants and minorities."}, {"term": "community organising", "ipa": "/kəˌmjuːnəti ˈɔːɡənaɪzɪŋ/", "pron": "kuh-MYOO-nuh-tee OR-guh-ny-zing", "fr": "organisation communautaire", "def": "Collective action by local communities to achieve change.", "ex": "Community organising can empower marginalised groups."}, {"term": "identity politics", "ipa": "/aɪˈdentəti ˌpɒlətɪks/", "pron": "eye-DEN-tuh-tee POL-uh-tiks", "fr": "politique identitaire", "def": "Politics focused on the interests and experiences of particular identity groups.", "ex": "Identity politics is praised for visibility and criticised for fragmentation."}, {"term": "woke", "ipa": "/wəʊk/", "pron": "wohk", "fr": "woke ; conscient des injustices sociales", "def": "Originally meaning alert to social injustice; now often used politically, sometimes pejoratively.", "ex": "The word woke has become a culture-war label."}, {"term": "political correctness", "ipa": "/pəˌlɪtɪkəl kəˈrektnəs/", "pron": "puh-LIT-i-kuhl kuh-REKT-nuhs", "fr": "politiquement correct", "def": "Avoiding language or actions that may offend marginalised groups, often used critically.", "ex": "Political correctness is often invoked in debates about speech."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Multiculturalism is frequently drawn into culture-war debates."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction against social or political change.", "ex": "Diversity policies can trigger a political backlash."}, {"term": "anti-immigrant sentiment", "ipa": "/ˌænti ˈɪmɪɡrənt ˈsentɪmənt/", "pron": "AN-tee IM-i-gruhnt SEN-ti-muhnt", "fr": "sentiment anti-immigrés", "def": "Hostility or suspicion towards immigrants.", "ex": "Anti-immigrant sentiment often rises during economic uncertainty."}, {"term": "anti-multiculturalism", "ipa": "/ˌænti ˌmʌltiˈkʌltʃərəlɪzəm/", "pron": "AN-tee MUL-tee-KUL-chuh-ruh-liz-uhm", "fr": "anti-multiculturalisme", "def": "Opposition to multiculturalism as a policy or ideal.", "ex": "Anti-multiculturalism argues that diversity weakens cohesion."}, {"term": "nativism", "ipa": "/ˈneɪtɪvɪzəm/", "pron": "NAY-tiv-iz-uhm", "fr": "nativisme", "def": "Political preference for native-born people over immigrants.", "ex": "Nativism is often linked to populism and xenophobia."}, {"term": "populism", "ipa": "/ˈpɒpjʊlɪzəm/", "pron": "POP-yuh-liz-uhm", "fr": "populisme", "def": "Politics claiming to defend ordinary people against elites and outsiders.", "ex": "Populism often targets multicultural elites and migrants."}, {"term": "scapegoating", "ipa": "/ˈskeɪpɡəʊtɪŋ/", "pron": "SKAYP-goht-ing", "fr": "désignation d’un bouc émissaire", "def": "Blaming a group unfairly for wider problems.", "ex": "Scapegoating minorities can distract from policy failures."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "Public fear, often exaggerated, that a group threatens society.", "ex": "Media coverage can create a moral panic about immigration."}, {"term": "integration policy", "ipa": "/ˌɪntɪˈɡreɪʃən ˈpɒləsi/", "pron": "in-ti-GRAY-shuhn POL-uh-see", "fr": "politique d’intégration", "def": "Government policy designed to help migrants and minorities participate in society.", "ex": "Integration policy often focuses on language, work and education."}, {"term": "language requirement", "ipa": "/ˈlæŋɡwɪdʒ rɪˌkwaɪəmənt/", "pron": "LANG-gwij ri-KWY-uh-muhnt", "fr": "condition linguistique", "def": "A rule requiring knowledge of a language for citizenship, work or residence.", "ex": "Language requirements can support integration but exclude some migrants."}, {"term": "citizenship test", "ipa": "/ˈsɪtɪzənʃɪp test/", "pron": "SIT-i-zuhn-ship test", "fr": "test de citoyenneté", "def": "A test required for citizenship or settlement in some countries.", "ex": "Citizenship tests can define what a society considers important."}, {"term": "naturalisation", "ipa": "/ˌnætʃərəlaɪˈzeɪʃən/", "pron": "nach-uh-ruh-ly-ZAY-shuhn", "fr": "naturalisation", "def": "The process of becoming a citizen of another country.", "ex": "Naturalisation can be expensive and bureaucratic."}]}, {"title": "D. Culture wars, integration policy and models of citizenship", "entries": [{"term": "civic integration", "ipa": "/ˌsɪvɪk ˌɪntɪˈɡreɪʃən/", "pron": "SIV-ik in-ti-GRAY-shuhn", "fr": "intégration civique", "def": "Integration through knowledge of language, laws, values and civic life.", "ex": "Civic integration is often tested through exams and courses."}, {"term": "multicultural policy", "ipa": "/ˌmʌltiˈkʌltʃərəl ˈpɒləsi/", "pron": "MUL-tee-KUL-chuh-ruhl POL-uh-see", "fr": "politique multiculturaliste", "def": "Policy recognising cultural diversity and minority rights.", "ex": "Multicultural policy is stronger in Canada than in France."}, {"term": "interculturalism", "ipa": "/ˌɪntəˈkʌltʃərəlɪzəm/", "pron": "IN-tuh-KUL-chuh-ruh-liz-uhm", "fr": "interculturalisme", "def": "A model emphasising interaction and dialogue between cultures.", "ex": "Interculturalism stresses contact rather than separate coexistence."}, {"term": "colour-blind universalism", "ipa": "/ˌkʌlə blaɪnd ˌjuːnɪˈvɜːsəlɪzəm/", "pron": "KUL-uh-blynd yoo-ni-VUR-suh-liz-uhm", "fr": "universalisme indifférent à la couleur", "def": "A model claiming to treat everyone equally without recognising ethnic or racial categories.", "ex": "Colour-blind universalism is associated with French republicanism."}, {"term": "republican model", "ipa": "/rɪˈpʌblɪkən ˈmɒdəl/", "pron": "ri-PUB-li-kuhn MOD-uhl", "fr": "modèle républicain", "def": "A model of citizenship stressing universal rights and common identity over group identities.", "ex": "The republican model is often contrasted with multiculturalism."}, {"term": "communitarianism", "ipa": "/kəˌmjuːnɪˈteəriənɪzəm/", "pron": "kuh-myoo-ni-TAIR-ee-uh-niz-uhm", "fr": "communautarisme ; pensée communautarienne", "def": "An approach emphasising the importance of communities in shaping identity and values.", "ex": "Communitarianism can be defended as solidarity or criticised as fragmentation."}, {"term": "communalism", "ipa": "/kəˈmjuːnəlɪzəm/", "pron": "kuh-MYOO-nuhl-iz-uhm", "fr": "communautarisme conflictuel", "def": "Politics organised around religious or ethnic communities, often divisive.", "ex": "Communalism can undermine shared citizenship."}, {"term": "minority accommodation", "ipa": "/maɪˌnɒrəti əˌkɒməˈdeɪʃən/", "pron": "my-NOR-uh-tee uh-kom-uh-DAY-shuhn", "fr": "accommodement des minorités", "def": "Adjusting institutions or rules to include minority practices.", "ex": "Minority accommodation can include religious holidays or dress rules."}, {"term": "reasonable accommodation", "ipa": "/ˌriːzənəbəl əˌkɒməˈdeɪʃən/", "pron": "REE-zuh-nuh-buhl uh-kom-uh-DAY-shuhn", "fr": "accommodement raisonnable", "def": "Practical adjustment allowing someone to exercise rights or participate equally.", "ex": "Reasonable accommodation is common in workplace equality law."}, {"term": "multicultural education", "ipa": "/ˌmʌltiˈkʌltʃərəl ˌedjʊˈkeɪʃən/", "pron": "MUL-tee-KUL-chuh-ruhl ej-yoo-KAY-shuhn", "fr": "éducation multiculturelle", "def": "Education that reflects and respects cultural diversity.", "ex": "Multicultural education can challenge stereotypes."}, {"term": "inclusive curriculum", "ipa": "/ɪnˌkluːsɪv kəˈrɪkjʊləm/", "pron": "in-KLOO-siv kuh-RIK-yuh-luhm", "fr": "programme inclusif", "def": "A curriculum representing different groups and experiences.", "ex": "An inclusive curriculum can make pupils feel seen."}, {"term": "decolonising the curriculum", "ipa": "/diːˈkɒlənaɪzɪŋ ðə kəˈrɪkjʊləm/", "pron": "dee-KOL-uh-ny-zing thuh kuh-RIK-yuh-luhm", "fr": "décolonisation des programmes", "def": "Reassessing teaching content to include perspectives shaped by colonial history.", "ex": "Decolonising the curriculum is debated in universities."}, {"term": "representation in the media", "ipa": "/ˌreprɪzenˈteɪʃən ɪn ðə ˈmiːdiə/", "pron": "rep-ri-zen-TAY-shuhn in thuh MEE-dee-uh", "fr": "représentation dans les médias", "def": "The way different groups appear or are portrayed in media.", "ex": "Representation in the media influences stereotypes and belonging."}, {"term": "cultural visibility", "ipa": "/ˌkʌltʃərəl ˌvɪzəˈbɪləti/", "pron": "KUL-chuh-ruhl viz-uh-BIL-uh-tee", "fr": "visibilité culturelle", "def": "The degree to which a culture is seen and recognised publicly.", "ex": "Cultural visibility can strengthen minority pride."}, {"term": "symbolic recognition", "ipa": "/sɪmˌbɒlɪk ˌrekəɡˈnɪʃən/", "pron": "sim-BOL-ik rek-uhg-NISH-uhn", "fr": "reconnaissance symbolique", "def": "Public acknowledgement of a group’s identity, history or contribution.", "ex": "Symbolic recognition can matter, but material equality also matters."}, {"term": "historical injustice", "ipa": "/hɪˌstɒrɪkəl ɪnˈdʒʌstɪs/", "pron": "hi-STOR-i-kuhl in-JUS-tis", "fr": "injustice historique", "def": "Past wrongdoing whose effects continue today.", "ex": "Historical injustice shapes debates about reparations."}, {"term": "colonial legacy", "ipa": "/kəˌləʊniəl ˈleɡəsi/", "pron": "kuh-LOH-nee-uhl LEG-uh-see", "fr": "héritage colonial", "def": "The continuing effects of colonialism.", "ex": "The colonial legacy shapes migration, identity and racism."}, {"term": "postcolonial", "ipa": "/ˌpəʊstkəˈləʊniəl/", "pron": "post-kuh-LOH-nee-uhl", "fr": "postcolonial", "def": "Relating to the period and effects after colonial rule.", "ex": "Postcolonial perspectives challenge dominant historical narratives."}, {"term": "reparations", "ipa": "/ˌrepəˈreɪʃənz/", "pron": "rep-uh-RAY-shuhnz", "fr": "réparations", "def": "Compensation or repair for historical injustice.", "ex": "Reparations for slavery remain politically controversial."}, {"term": "to integrate into society", "ipa": "/ˈɪntɪɡreɪt ˈɪntuː səˈsaɪəti/", "pron": "IN-ti-grayt IN-too suh-SY-uh-tee", "fr": "s’intégrer dans la société", "def": "To become part of a society’s social, economic and civic life.", "ex": "Language and employment help newcomers integrate into society."}, {"term": "to assimilate", "ipa": "/əˈsɪməleɪt/", "pron": "uh-SIM-uh-layt", "fr": "s’assimiler", "def": "To adopt the dominant culture and become similar to the majority group.", "ex": "Some policies expect minorities to assimilate rather than preserve difference."}, {"term": "to preserve cultural identity", "ipa": "/prɪˈzɜːv ˌkʌltʃərəl aɪˈdentəti/", "pron": "pri-ZURV KUL-chuh-ruhl eye-DEN-tuh-tee", "fr": "préserver l’identité culturelle", "def": "To maintain cultural traditions, language or values.", "ex": "Diaspora communities often preserve cultural identity through language and religion."}, {"term": "to foster social cohesion", "ipa": "/ˈfɒstə ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "FOS-tuh SOH-shuhl koh-HEE-zhuhn", "fr": "favoriser la cohésion sociale", "def": "To encourage trust and unity within society.", "ex": "Shared schools and public spaces can foster social cohesion."}, {"term": "to promote diversity", "ipa": "/prəˈməʊt daɪˈvɜːsəti/", "pron": "pruh-MOHT dy-VUR-suh-tee", "fr": "promouvoir la diversité", "def": "To encourage the presence and recognition of difference.", "ex": "Universities often claim to promote diversity."}, {"term": "to combat discrimination", "ipa": "/ˈkɒmbæt dɪˌskrɪmɪˈneɪʃən/", "pron": "KOM-bat dis-krim-i-NAY-shuhn", "fr": "lutter contre la discrimination", "def": "To fight unfair treatment based on identity.", "ex": "Anti-discrimination laws aim to combat discrimination."}, {"term": "to challenge stereotypes", "ipa": "/ˈtʃælɪndʒ ˈsteriətaɪps/", "pron": "CHAL-inj STERR-ee-uh-types", "fr": "remettre en cause les stéréotypes", "def": "To question and undermine oversimplified ideas about groups.", "ex": "Education can challenge stereotypes."}, {"term": "to bridge cultural divides", "ipa": "/brɪdʒ ˌkʌltʃərəl dɪˈvaɪdz/", "pron": "brij KUL-chuh-ruhl di-VYDZ", "fr": "combler les fractures culturelles", "def": "To reduce gaps or tensions between cultural groups.", "ex": "Community projects can bridge cultural divides."}, {"term": "to strengthen belonging", "ipa": "/ˈstreŋθən bɪˈlɒŋɪŋ/", "pron": "STRENG-thuhn bi-LONG-ing", "fr": "renforcer le sentiment d’appartenance", "def": "To increase people’s feeling of being accepted.", "ex": "Representation can strengthen belonging among minority pupils."}, {"term": "to marginalise minorities", "ipa": "/ˈmɑːdʒɪnəlaɪz maɪˈnɒrətiz/", "pron": "MAR-ji-nuh-lyz my-NOR-uh-teez", "fr": "marginaliser les minorités", "def": "To push minority groups to the edge of society.", "ex": "Discriminatory policies marginalise minorities."}, {"term": "to fuel racial tensions", "ipa": "/ˈfjuːəl ˈreɪʃəl ˈtenʃənz/", "pron": "FYOO-uhl RAY-shuhl TEN-shuhnz", "fr": "alimenter les tensions raciales", "def": "To intensify tensions between racial or ethnic groups.", "ex": "Inflammatory rhetoric can fuel racial tensions."}, {"term": "to scapegoat migrants", "ipa": "/ˈskeɪpɡəʊt ˈmaɪɡrənts/", "pron": "SKAYP-goht MY-gruhnts", "fr": "faire des migrants des boucs émissaires", "def": "To unfairly blame migrants for wider problems.", "ex": "Populist rhetoric may scapegoat migrants."}, {"term": "to defend pluralism", "ipa": "/dɪˈfend ˈplʊərəlɪzəm/", "pron": "di-FEND PLOOR-uh-liz-uhm", "fr": "défendre le pluralisme", "def": "To protect coexistence between different identities and beliefs.", "ex": "Democracies must defend pluralism against intolerance."}]}, {"title": "E. Education, recognition, colonial legacy and high-value verbs", "entries": [{"term": "to balance diversity and unity", "ipa": "/ˈbæləns daɪˈvɜːsəti ənd ˈjuːnəti/", "pron": "BAL-uhns dy-VUR-suh-tee and YOO-nuh-tee", "fr": "équilibrer diversité et unité", "def": "To combine respect for difference with shared social bonds.", "ex": "Multicultural societies must balance diversity and unity."}]}]}, {"id": "p4c37", "part": 4, "chapter": 37, "title": "Gender Issues", "file": "cpge_vocab_part4_chapter37_gender_issues_premium.html", "count": 176, "sections": [{"title": "A. Core gender concepts, feminism and discrimination", "entries": [{"term": "gender", "ipa": "/ˈdʒendə/", "pron": "JEN-duh", "fr": "genre", "def": "The social and cultural roles, expectations and identities associated with being male, female or non-binary.", "ex": "Gender shapes how people are treated in families, schools, workplaces and politics."}, {"term": "sex", "ipa": "/seks/", "pron": "seks", "fr": "sexe biologique", "def": "Biological characteristics often classified as male or female.", "ex": "Sex and gender are related but not identical concepts."}, {"term": "gender identity", "ipa": "/ˌdʒendər aɪˈdentəti/", "pron": "JEN-duh eye-DEN-tuh-tee", "fr": "identité de genre", "def": "A person’s internal sense of their gender.", "ex": "Gender identity may or may not match the sex assigned at birth."}, {"term": "gender role", "ipa": "/ˈdʒendə rəʊl/", "pron": "JEN-duh rohl", "fr": "rôle de genre", "def": "A social expectation about how men or women should behave.", "ex": "Traditional gender roles can limit both women and men."}, {"term": "gender norm", "ipa": "/ˈdʒendə nɔːm/", "pron": "JEN-duh norm", "fr": "norme de genre", "def": "A social rule about expected behaviour based on gender.", "ex": "Gender norms influence clothing, careers and family life."}, {"term": "gender stereotype", "ipa": "/ˈdʒendə ˌsteriətaɪp/", "pron": "JEN-duh STERR-ee-uh-type", "fr": "stéréotype de genre", "def": "A fixed and oversimplified idea about men or women.", "ex": "Gender stereotypes discourage girls from STEM and boys from care work."}, {"term": "femininity", "ipa": "/ˌfeməˈnɪnəti/", "pron": "fem-uh-NIN-uh-tee", "fr": "féminité", "def": "Qualities or behaviours socially associated with women or girls.", "ex": "Femininity is defined differently across cultures and periods."}, {"term": "masculinity", "ipa": "/ˌmæskjʊˈlɪnəti/", "pron": "mas-kyuh-LIN-uh-tee", "fr": "masculinité", "def": "Qualities or behaviours socially associated with men or boys.", "ex": "Masculinity can be positive, but rigid masculinity may harm men and women."}, {"term": "toxic masculinity", "ipa": "/ˌtɒksɪk ˌmæskjʊˈlɪnəti/", "pron": "TOK-sik mas-kyuh-LIN-uh-tee", "fr": "masculinité toxique", "def": "Harmful expectations of masculinity, such as aggression or emotional repression.", "ex": "Toxic masculinity can contribute to violence and poor mental health."}, {"term": "patriarchy", "ipa": "/ˈpeɪtriɑːki/", "pron": "PAY-tree-ar-kee", "fr": "patriarcat", "def": "A social system in which men hold more power than women.", "ex": "Patriarchy affects laws, culture, work and family structures."}, {"term": "male-dominated", "ipa": "/ˌmeɪl ˈdɒmɪneɪtɪd/", "pron": "male DOM-i-nay-tid", "fr": "dominé par les hommes", "def": "Controlled or mostly occupied by men.", "ex": "Politics and finance remain male-dominated fields."}, {"term": "female-dominated", "ipa": "/ˌfiːmeɪl ˈdɒmɪneɪtɪd/", "pron": "FEE-male DOM-i-nay-tid", "fr": "dominé par les femmes", "def": "Mostly occupied by women.", "ex": "Care work is often female-dominated and undervalued."}, {"term": "gender equality", "ipa": "/ˌdʒendər iˈkwɒləti/", "pron": "JEN-duh i-KWOL-uh-tee", "fr": "égalité des genres ; égalité femmes-hommes", "def": "Equal rights, opportunities and treatment regardless of gender.", "ex": "Gender equality is a core democratic and human-rights issue."}, {"term": "gender equity", "ipa": "/ˌdʒendər ˈekwəti/", "pron": "JEN-duh EK-wuh-tee", "fr": "équité de genre", "def": "Fairness that takes gender-based barriers into account.", "ex": "Gender equity may require targeted policies."}, {"term": "women’s rights", "ipa": "/ˈwɪmɪnz raɪts/", "pron": "WIM-inz rites", "fr": "droits des femmes", "def": "Rights protecting women’s equality, freedom and dignity.", "ex": "Women’s rights have been won through long political struggles."}, {"term": "feminism", "ipa": "/ˈfemɪnɪzəm/", "pron": "FEM-i-niz-uhm", "fr": "féminisme", "def": "The belief and movement supporting gender equality and women’s rights.", "ex": "Feminism challenges social, political and economic inequality."}, {"term": "feminist", "ipa": "/ˈfemɪnɪst/", "pron": "FEM-i-nist", "fr": "féministe", "def": "A person or idea supporting feminism.", "ex": "Feminist movements are diverse and sometimes disagree with each other."}, {"term": "liberal feminism", "ipa": "/ˌlɪbərəl ˈfemɪnɪzəm/", "pron": "LIB-uh-ruhl FEM-i-niz-uhm", "fr": "féminisme libéral", "def": "A form of feminism focused on equal rights and opportunities within existing institutions.", "ex": "Liberal feminism often emphasises law, education and workplace equality."}, {"term": "radical feminism", "ipa": "/ˌrædɪkəl ˈfemɪnɪzəm/", "pron": "RAD-i-kuhl FEM-i-niz-uhm", "fr": "féminisme radical", "def": "A form of feminism focusing on patriarchy as a deep social structure.", "ex": "Radical feminism argues that gender inequality is rooted in patriarchal power."}, {"term": "intersectional feminism", "ipa": "/ˌɪntəsekʃənəl ˈfemɪnɪzəm/", "pron": "IN-tuh-sek-shuh-nuhl FEM-i-niz-uhm", "fr": "féminisme intersectionnel", "def": "Feminism that considers how gender combines with race, class, sexuality and disability.", "ex": "Intersectional feminism highlights differences between women’s experiences."}, {"term": "intersectionality", "ipa": "/ˌɪntəsekʃəˈnæləti/", "pron": "IN-tuh-sek-shuh-NAL-uh-tee", "fr": "intersectionnalité", "def": "The way different forms of inequality combine and shape people’s lives.", "ex": "Intersectionality shows that sexism is experienced differently depending on race or class."}, {"term": "sexism", "ipa": "/ˈseksɪzəm/", "pron": "SEK-siz-uhm", "fr": "sexisme", "def": "Prejudice or discrimination based on sex or gender.", "ex": "Sexism can be open, subtle or institutional."}, {"term": "misogyny", "ipa": "/mɪˈsɒdʒəni/", "pron": "mi-SOJ-uh-nee", "fr": "misogynie", "def": "Hatred, contempt or deep prejudice against women.", "ex": "Online misogyny can silence women in public life."}, {"term": "misandry", "ipa": "/mɪˈsændri/", "pron": "mi-SAN-dree", "fr": "misandrie", "def": "Hatred or prejudice against men.", "ex": "Misandry is sometimes invoked in debates about feminism."}, {"term": "gender discrimination", "ipa": "/ˈdʒendə dɪˌskrɪmɪˈneɪʃən/", "pron": "JEN-duh dis-krim-i-NAY-shuhn", "fr": "discrimination de genre", "def": "Unfair treatment based on gender.", "ex": "Gender discrimination remains common in hiring and promotion."}, {"term": "sexual harassment", "ipa": "/ˌsekʃuəl ˈhærəsmənt/", "pron": "SEK-shoo-uhl HARR-uhs-muhnt", "fr": "harcèlement sexuel", "def": "Unwanted sexual behaviour that intimidates, humiliates or violates someone.", "ex": "Sexual harassment can occur in workplaces, schools and public spaces."}, {"term": "harassment", "ipa": "/ˈhærəsmənt/", "pron": "HARR-uhs-muhnt", "fr": "harcèlement", "def": "Repeated behaviour that intimidates or humiliates someone.", "ex": "Harassment often goes unreported because victims fear retaliation."}, {"term": "catcalling", "ipa": "/ˈkætkɔːlɪŋ/", "pron": "KAT-kaw-ling", "fr": "harcèlement de rue ; interpellation sexiste", "def": "Unwanted comments or whistles directed at someone in public, usually women.", "ex": "Catcalling is often dismissed as harmless, but it restricts women’s freedom."}, {"term": "street harassment", "ipa": "/ˈstriːt ˈhærəsmənt/", "pron": "street HARR-uhs-muhnt", "fr": "harcèlement de rue", "def": "Unwanted comments, gestures or behaviour in public spaces.", "ex": "Street harassment affects how women move through cities."}, {"term": "gender-based violence", "ipa": "/ˈdʒendə beɪst ˈvaɪələns/", "pron": "JEN-duh-bayst VY-uh-luhns", "fr": "violence fondée sur le genre", "def": "Violence directed at someone because of their gender.", "ex": "Gender-based violence is both a private and public issue."}, {"term": "violence against women", "ipa": "/ˈvaɪələns əˌɡenst ˈwɪmɪn/", "pron": "VY-uh-luhns uh-GENST WIM-in", "fr": "violence contre les femmes", "def": "Physical, sexual or psychological violence targeting women.", "ex": "Violence against women is a global human-rights concern."}, {"term": "domestic violence", "ipa": "/dəˌmestɪk ˈvaɪələns/", "pron": "duh-MES-tik VY-uh-luhns", "fr": "violence domestique ; violences conjugales", "def": "Violence or abuse within a family or intimate relationship.", "ex": "Domestic violence often remains hidden behind closed doors."}, {"term": "intimate partner violence", "ipa": "/ˌɪntɪmət ˈpɑːtnə ˈvaɪələns/", "pron": "IN-ti-muht PART-nuh VY-uh-luhns", "fr": "violence conjugale", "def": "Violence by a current or former partner.", "ex": "Intimate partner violence affects people across social classes."}, {"term": "coercive control", "ipa": "/kəʊˌɜːsɪv kənˈtrəʊl/", "pron": "koh-UR-siv kuhn-TROHL", "fr": "contrôle coercitif", "def": "A pattern of controlling behaviour that isolates, frightens or dominates a partner.", "ex": "Coercive control can exist without visible physical violence."}, {"term": "femicide", "ipa": "/ˈfemɪsaɪd/", "pron": "FEM-i-side", "fr": "féminicide", "def": "The killing of a woman because she is a woman, often by a partner or ex-partner.", "ex": "Femicide reveals the extreme end of gender-based violence."}, {"term": "rape", "ipa": "/reɪp/", "pron": "rayp", "fr": "viol", "def": "Forced sexual intercourse or penetration without consent.", "ex": "Rape cases often expose myths about victims and consent."}, {"term": "sexual assault", "ipa": "/ˌsekʃuəl əˈsɔːlt/", "pron": "SEK-shoo-uhl uh-SAWLT", "fr": "agression sexuelle", "def": "A sexual act committed without consent.", "ex": "Sexual assault survivors often face shame and disbelief."}, {"term": "consent", "ipa": "/kənˈsent/", "pron": "kuhn-SENT", "fr": "consentement", "def": "Clear and voluntary agreement to something, especially sexual activity.", "ex": "Consent must be freely given and can be withdrawn."}, {"term": "rape culture", "ipa": "/ˈreɪp ˌkʌltʃə/", "pron": "rayp KUL-chuh", "fr": "culture du viol", "def": "Social attitudes that normalise or excuse sexual violence.", "ex": "Rape culture shifts blame from perpetrators to victims."}, {"term": "victim-blaming", "ipa": "/ˈvɪktɪm ˌbleɪmɪŋ/", "pron": "VIK-tim BLAY-ming", "fr": "culpabilisation de la victime", "def": "Blaming victims for harm done to them.", "ex": "Victim-blaming discourages survivors from reporting abuse."}, {"term": "survivor", "ipa": "/səˈvaɪvə/", "pron": "suh-VY-vuh", "fr": "survivant ; survivante", "def": "A person who has lived through violence, abuse or trauma.", "ex": "Many activists use the word survivor rather than victim."}, {"term": "perpetrator", "ipa": "/ˈpɜːpətreɪtə/", "pron": "PUR-puh-tray-tuh", "fr": "auteur de violences ; agresseur", "def": "A person who commits a crime or harmful act.", "ex": "Perpetrators are often known to their victims."}, {"term": "restraining order", "ipa": "/rɪˈstreɪnɪŋ ˌɔːdə/", "pron": "ri-STRAY-ning OR-duh", "fr": "ordonnance d’éloignement", "def": "A court order preventing someone from contacting or approaching another person.", "ex": "A restraining order can protect victims from further abuse."}, {"term": "safe house", "ipa": "/ˈseɪf haʊs/", "pron": "sayf howss", "fr": "refuge ; hébergement sécurisé", "def": "A place where victims of violence can stay safely.", "ex": "Safe houses are essential for women fleeing domestic violence."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart salarial entre hommes et femmes", "def": "The difference between men’s and women’s average earnings.", "ex": "The gender pay gap reflects unequal work, promotion and care responsibilities."}]}, {"title": "B. Violence, consent, work and care inequalities", "entries": [{"term": "equal pay", "ipa": "/ˌiːkwəl ˈpeɪ/", "pron": "EE-kwuhl pay", "fr": "égalité salariale", "def": "The principle of paying people equally for equal work.", "ex": "Equal pay laws do not always eliminate pay gaps."}, {"term": "pay transparency", "ipa": "/ˈpeɪ trænsˌpærənsi/", "pron": "pay trans-PARR-uhn-see", "fr": "transparence salariale", "def": "Openness about salaries or pay structures.", "ex": "Pay transparency can expose discrimination."}, {"term": "glass ceiling", "ipa": "/ˌɡlɑːs ˈsiːlɪŋ/", "pron": "glass SEE-ling", "fr": "plafond de verre", "def": "An invisible barrier preventing women or minorities from reaching top positions.", "ex": "The glass ceiling remains strong in boardrooms and politics."}, {"term": "glass cliff", "ipa": "/ˌɡlɑːs ˈklɪf/", "pron": "glass klif", "fr": "falaise de verre", "def": "A situation where women are promoted to leadership during crisis, when failure is more likely.", "ex": "The glass cliff can set women leaders up to fail."}, {"term": "sticky floor", "ipa": "/ˌstɪki ˈflɔː/", "pron": "STIK-ee floor", "fr": "plancher collant", "def": "A situation where workers, often women, remain trapped in low-paid jobs.", "ex": "The sticky floor keeps many women in poorly paid care work."}, {"term": "motherhood penalty", "ipa": "/ˈmʌðəhʊd ˌpenəlti/", "pron": "MUTH-uh-hood PEN-uhl-tee", "fr": "pénalité de maternité", "def": "The career and pay disadvantage experienced by mothers.", "ex": "The motherhood penalty widens gender inequality over a lifetime."}, {"term": "fatherhood premium", "ipa": "/ˈfɑːðəhʊd ˌpriːmiəm/", "pron": "FAH-thuh-hood PREE-mee-uhm", "fr": "prime à la paternité", "def": "The tendency for fathers to gain status or earnings at work.", "ex": "The fatherhood premium contrasts sharply with the motherhood penalty."}, {"term": "care work", "ipa": "/ˈkeə wɜːk/", "pron": "care work", "fr": "travail de soin ; care", "def": "Work involving caring for children, elderly people, sick people or disabled people.", "ex": "Care work is essential but often undervalued."}, {"term": "unpaid care work", "ipa": "/ʌnˌpeɪd ˈkeə wɜːk/", "pron": "un-PAYD care work", "fr": "travail domestique et de soin non rémunéré", "def": "Care work done without pay, often within families.", "ex": "Women still perform most unpaid care work."}, {"term": "emotional labour", "ipa": "/ɪˌməʊʃənəl ˈleɪbə/", "pron": "i-MOH-shuh-nuhl LAY-buh", "fr": "travail émotionnel", "def": "Managing emotions and relationships as part of work or family life.", "ex": "Emotional labour is often expected from women."}, {"term": "domestic labour", "ipa": "/dəˌmestɪk ˈleɪbə/", "pron": "duh-MES-tik LAY-buh", "fr": "travail domestique", "def": "Household work such as cleaning, cooking and organising family life.", "ex": "Domestic labour remains unevenly shared."}, {"term": "double burden", "ipa": "/ˌdʌbəl ˈbɜːdən/", "pron": "DUB-uhl BUR-duhn", "fr": "double journée", "def": "The burden of paid work plus unpaid domestic or care work.", "ex": "The double burden affects many working mothers."}, {"term": "mental load", "ipa": "/ˈmentəl ləʊd/", "pron": "MEN-tuhl lohd", "fr": "charge mentale", "def": "The invisible planning and organising work required to manage family life.", "ex": "The mental load is often carried by women."}, {"term": "work-life balance", "ipa": "/ˌwɜːk laɪf ˈbæləns/", "pron": "work-life BAL-uhns", "fr": "équilibre vie professionnelle-vie personnelle", "def": "The balance between professional responsibilities and personal life.", "ex": "Work-life balance is harder when care duties are unequal."}, {"term": "flexible working", "ipa": "/ˌfleksəbəl ˈwɜːkɪŋ/", "pron": "FLEK-suh-buhl WUR-king", "fr": "travail flexible", "def": "Work arrangements allowing flexibility in hours or location.", "ex": "Flexible working can support parents but may limit promotion."}, {"term": "part-time work", "ipa": "/ˌpɑːt taɪm ˈwɜːk/", "pron": "part-time work", "fr": "travail à temps partiel", "def": "Work done for fewer hours than a full-time job.", "ex": "Part-time work is often linked to lower pay and fewer career opportunities."}, {"term": "career break", "ipa": "/kəˈrɪə breɪk/", "pron": "kuh-REER brayk", "fr": "interruption de carrière", "def": "A period away from work, often for childcare or caring responsibilities.", "ex": "Career breaks can reduce long-term earnings."}, {"term": "parental leave", "ipa": "/pəˌrentəl ˈliːv/", "pron": "puh-REN-tuhl leev", "fr": "congé parental", "def": "Time off work to care for a new child.", "ex": "Parental leave policy shapes gender equality at home and work."}, {"term": "maternity leave", "ipa": "/məˈtɜːnəti liːv/", "pron": "muh-TUR-nuh-tee leev", "fr": "congé maternité", "def": "Time off work for a mother before or after childbirth.", "ex": "Paid maternity leave protects mothers’ health and employment."}, {"term": "paternity leave", "ipa": "/pəˈtɜːnəti liːv/", "pron": "puh-TUR-nuh-tee leev", "fr": "congé paternité", "def": "Time off work for a father after a child is born or adopted.", "ex": "Paternity leave can encourage fathers to share childcare."}, {"term": "childcare", "ipa": "/ˈtʃaɪldkeə/", "pron": "CHYLD-care", "fr": "garde d’enfants", "def": "Care for children while parents work or study.", "ex": "Affordable childcare is crucial for women’s employment."}, {"term": "affordable childcare", "ipa": "/əˌfɔːdəbəl ˈtʃaɪldkeə/", "pron": "uh-FOR-duh-buhl CHYLD-care", "fr": "garde d’enfants abordable", "def": "Childcare that families can pay for without financial hardship.", "ex": "Affordable childcare can reduce the gender employment gap."}, {"term": "gender employment gap", "ipa": "/ˈdʒendər ɪmˈplɔɪmənt ɡæp/", "pron": "JEN-duh im-PLOY-muhnt gap", "fr": "écart d’emploi entre hommes et femmes", "def": "The difference between men’s and women’s employment rates.", "ex": "The gender employment gap is linked to care responsibilities."}, {"term": "occupational segregation", "ipa": "/ˌɒkjʊˈpeɪʃənəl ˌseɡrɪˈɡeɪʃən/", "pron": "ok-yuh-PAY-shuh-nuhl seg-ri-GAY-shuhn", "fr": "ségrégation professionnelle", "def": "The concentration of men and women in different types of jobs.", "ex": "Occupational segregation contributes to the gender pay gap."}, {"term": "pink-collar job", "ipa": "/ˌpɪŋk ˈkɒlə dʒɒb/", "pron": "pink KOL-uh job", "fr": "emploi féminisé ; emploi de care", "def": "A job traditionally associated with women, often in care or service work.", "ex": "Pink-collar jobs are often undervalued and underpaid."}, {"term": "leadership gap", "ipa": "/ˈliːdəʃɪp ɡæp/", "pron": "LEE-duh-ship gap", "fr": "écart de leadership", "def": "The underrepresentation of women in leadership positions.", "ex": "The leadership gap remains visible in business and politics."}, {"term": "boardroom", "ipa": "/ˈbɔːdruːm/", "pron": "BORD-room", "fr": "conseil d’administration ; direction", "def": "The room or group where company directors make decisions.", "ex": "Women remain underrepresented in the boardroom."}, {"term": "gender quota", "ipa": "/ˈdʒendə ˌkwəʊtə/", "pron": "JEN-duh KWOH-tuh", "fr": "quota de genre", "def": "A required minimum share of men or women in a group or institution.", "ex": "Gender quotas can increase women’s representation."}, {"term": "positive action", "ipa": "/ˌpɒzətɪv ˈækʃən/", "pron": "POZ-uh-tiv AK-shuhn", "fr": "action positive", "def": "Steps to help underrepresented groups without automatic preference.", "ex": "Positive action can help women enter male-dominated sectors."}, {"term": "affirmative action", "ipa": "/əˌfɜːmətɪv ˈækʃən/", "pron": "uh-FUR-muh-tiv AK-shuhn", "fr": "discrimination positive", "def": "Policies designed to improve access for historically disadvantaged groups.", "ex": "Affirmative action is controversial but aims to address inequality."}, {"term": "STEM", "ipa": "/stem/", "pron": "stem", "fr": "STEM ; sciences, technologie, ingénierie et mathématiques", "def": "Science, technology, engineering and mathematics.", "ex": "Girls are still underrepresented in many STEM fields."}, {"term": "women in STEM", "ipa": "/ˈwɪmɪn ɪn stem/", "pron": "WIM-in in stem", "fr": "femmes dans les STEM", "def": "Women studying or working in science, technology, engineering and maths.", "ex": "Encouraging women in STEM can reduce skills gaps."}, {"term": "gender bias", "ipa": "/ˈdʒendə ˌbaɪəs/", "pron": "JEN-duh BY-uhs", "fr": "biais de genre", "def": "A tendency to judge or treat people unfairly based on gender.", "ex": "Gender bias can affect recruitment, diagnosis and evaluation."}, {"term": "unconscious bias", "ipa": "/ʌnˌkɒnʃəs ˈbaɪəs/", "pron": "un-KON-shuhs BY-uhs", "fr": "biais inconscient", "def": "Unintentional assumptions that affect judgement.", "ex": "Unconscious bias may influence promotion decisions."}, {"term": "gender mainstreaming", "ipa": "/ˈdʒendə ˌmeɪnstriːmɪŋ/", "pron": "JEN-duh MAYN-streem-ing", "fr": "intégration transversale du genre", "def": "Including gender equality considerations in all policies and institutions.", "ex": "Gender mainstreaming aims to make policy more inclusive."}, {"term": "gender-responsive policy", "ipa": "/ˈdʒendə rɪˌspɒnsɪv ˈpɒləsi/", "pron": "JEN-duh ri-SPON-siv POL-uh-see", "fr": "politique sensible au genre", "def": "Policy designed to take gendered needs and impacts into account.", "ex": "Gender-responsive policy considers how laws affect men and women differently."}, {"term": "gender budgeting", "ipa": "/ˈdʒendə ˈbʌdʒɪtɪŋ/", "pron": "JEN-duh BUJ-it-ing", "fr": "budgétisation sensible au genre", "def": "Budget planning that considers gender equality impacts.", "ex": "Gender budgeting reveals whether public spending benefits women and men equally."}, {"term": "women’s representation", "ipa": "/ˈwɪmɪnz ˌreprɪzenˈteɪʃən/", "pron": "WIM-inz rep-ri-zen-TAY-shuhn", "fr": "représentation des femmes", "def": "The presence of women in politics, media, leadership or institutions.", "ex": "Women’s representation affects which issues receive attention."}, {"term": "political representation", "ipa": "/pəˌlɪtɪkəl ˌreprɪzenˈteɪʃən/", "pron": "puh-LIT-i-kuhl rep-ri-zen-TAY-shuhn", "fr": "représentation politique", "def": "The presence and voice of groups in political institutions.", "ex": "Political representation matters for democratic legitimacy."}, {"term": "parity", "ipa": "/ˈpærəti/", "pron": "PARR-uh-tee", "fr": "parité", "def": "Equal representation or status, especially between men and women.", "ex": "Parity laws aim to increase women’s political representation."}, {"term": "gender parity", "ipa": "/ˈdʒendə ˈpærəti/", "pron": "JEN-duh PARR-uh-tee", "fr": "parité femmes-hommes", "def": "Equal participation or representation of genders.", "ex": "Gender parity in parliament remains uneven across countries."}, {"term": "women in politics", "ipa": "/ˈwɪmɪn ɪn ˈpɒlətɪks/", "pron": "WIM-in in POL-uh-tiks", "fr": "femmes en politique", "def": "Women participating in elected office or political leadership.", "ex": "Women in politics often face online abuse."}, {"term": "female leadership", "ipa": "/ˈfiːmeɪl ˈliːdəʃɪp/", "pron": "FEE-male LEE-duh-ship", "fr": "leadership féminin", "def": "Leadership by women.", "ex": "Female leadership can challenge stereotypes."}]}, {"title": "C. Representation, leadership and workplace culture", "entries": [{"term": "role model", "ipa": "/ˈrəʊl ˌmɒdəl/", "pron": "rohl MOD-uhl", "fr": "modèle ; exemple à suivre", "def": "A person whose behaviour or success inspires others.", "ex": "Female role models can encourage girls to aim higher."}, {"term": "token woman", "ipa": "/ˌtəʊkən ˈwʊmən/", "pron": "TOH-kuhn WUUM-uhn", "fr": "femme alibi", "def": "A woman included superficially to appear diverse.", "ex": "Being the token woman can be isolating."}, {"term": "mansplaining", "ipa": "/ˈmænˌspleɪnɪŋ/", "pron": "MAN-splay-ning", "fr": "mecsplication ; mansplaining", "def": "A man explaining something to a woman in a patronising way.", "ex": "Mansplaining reflects unequal assumptions about competence."}, {"term": "manterrupting", "ipa": "/ˈmæntəˌrʌptɪŋ/", "pron": "MAN-tuh-rup-ting", "fr": "interruption masculine répétée", "def": "Men repeatedly interrupting women in conversation.", "ex": "Manterrupting can silence women in meetings."}, {"term": "bro culture", "ipa": "/ˈbrəʊ ˌkʌltʃə/", "pron": "bro KUL-chuh", "fr": "culture masculine excluante ; bro culture", "def": "A male-dominated workplace culture associated with exclusion or sexism.", "ex": "Bro culture has been criticised in tech companies."}, {"term": "old boys’ network", "ipa": "/ˌəʊld ˈbɔɪz ˌnetwɜːk/", "pron": "ohld boyz NET-wurk", "fr": "réseau masculin d’anciens ; entre-soi masculin", "def": "Informal male elite networks that preserve privilege.", "ex": "The old boys’ network can block women’s advancement."}, {"term": "reproductive rights", "ipa": "/ˌriːprəˈdʌktɪv raɪts/", "pron": "ree-pruh-DUK-tiv rites", "fr": "droits reproductifs", "def": "Rights concerning contraception, pregnancy, abortion and reproductive healthcare.", "ex": "Reproductive rights are central to bodily autonomy."}, {"term": "bodily autonomy", "ipa": "/ˌbɒdɪli ɔːˈtɒnəmi/", "pron": "BOD-i-lee aw-TON-uh-mee", "fr": "autonomie corporelle", "def": "The right to make decisions about one’s own body.", "ex": "Bodily autonomy is a key argument in abortion debates."}, {"term": "contraception", "ipa": "/ˌkɒntrəˈsepʃən/", "pron": "kon-truh-SEP-shuhn", "fr": "contraception", "def": "Methods used to prevent pregnancy.", "ex": "Access to contraception affects education and employment."}, {"term": "abortion", "ipa": "/əˈbɔːʃən/", "pron": "uh-BOR-shuhn", "fr": "avortement", "def": "The ending of a pregnancy.", "ex": "Abortion remains one of the most divisive gender issues."}, {"term": "abortion rights", "ipa": "/əˈbɔːʃən raɪts/", "pron": "uh-BOR-shuhn rites", "fr": "droit à l’avortement", "def": "The right to access abortion legally and safely.", "ex": "Abortion rights vary widely between countries and US states."}, {"term": "pro-choice", "ipa": "/ˌprəʊ ˈtʃɔɪs/", "pron": "proh-choice", "fr": "pro-choix ; favorable au droit à l’avortement", "def": "Supporting the right to choose abortion.", "ex": "Pro-choice activists frame abortion as healthcare."}, {"term": "pro-life", "ipa": "/ˌprəʊ ˈlaɪf/", "pron": "proh-life", "fr": "pro-vie ; opposé à l’avortement", "def": "Opposing abortion, usually on moral or religious grounds.", "ex": "Pro-life movements often argue that life begins before birth."}, {"term": "maternal health", "ipa": "/məˌtɜːnəl ˈhelθ/", "pron": "muh-TUR-nuhl helth", "fr": "santé maternelle", "def": "Health related to pregnancy, childbirth and the period after birth.", "ex": "Maternal health outcomes reveal deep inequalities."}, {"term": "maternal mortality", "ipa": "/məˌtɜːnəl mɔːˈtæləti/", "pron": "muh-TUR-nuhl mor-TAL-uh-tee", "fr": "mortalité maternelle", "def": "Deaths related to pregnancy or childbirth.", "ex": "Maternal mortality is higher among some minority groups."}, {"term": "period poverty", "ipa": "/ˈpɪəriəd ˌpɒvəti/", "pron": "PEER-ee-uhd POV-uh-tee", "fr": "précarité menstruelle", "def": "Lack of access to menstrual products because of poverty.", "ex": "Period poverty can cause girls to miss school."}, {"term": "menstruation", "ipa": "/ˌmenstruˈeɪʃən/", "pron": "men-stroo-AY-shuhn", "fr": "menstruation ; règles", "def": "The monthly bleeding experienced by many people with a uterus.", "ex": "Menstruation is still surrounded by stigma in many societies."}, {"term": "menstrual leave", "ipa": "/ˈmenstruəl liːv/", "pron": "MEN-stroo-uhl leev", "fr": "congé menstruel", "def": "Time off work for severe period pain or related symptoms.", "ex": "Menstrual leave is debated as support or potential stigma."}, {"term": "fertility", "ipa": "/fəˈtɪləti/", "pron": "fuh-TIL-uh-tee", "fr": "fertilité ; fécondité", "def": "The ability to have children, or the birth rate in a population.", "ex": "Fertility debates often involve women’s choices and economic pressure."}, {"term": "IVF", "ipa": "/ˌaɪ viː ˈef/", "pron": "eye-vee-eff", "fr": "FIV ; fécondation in vitro", "def": "In vitro fertilisation, a medical technique to help people conceive.", "ex": "IVF access raises questions about cost and equality."}, {"term": "surrogacy", "ipa": "/ˈsʌrəɡəsi/", "pron": "SUR-uh-guh-see", "fr": "gestation pour autrui ; GPA", "def": "An arrangement where someone carries a pregnancy for another person or couple.", "ex": "Surrogacy raises ethical questions about exploitation and family."}, {"term": "child marriage", "ipa": "/ˈtʃaɪld ˌmærɪdʒ/", "pron": "CHYLD MARR-ij", "fr": "mariage d’enfant", "def": "Marriage involving someone under the legal adult age.", "ex": "Child marriage limits girls’ education and autonomy."}, {"term": "forced marriage", "ipa": "/ˌfɔːst ˈmærɪdʒ/", "pron": "forst MARR-ij", "fr": "mariage forcé", "def": "Marriage without free and full consent.", "ex": "Forced marriage is a violation of human rights."}, {"term": "FGM", "ipa": "/ˌef dʒiː ˈem/", "pron": "eff-jee-em", "fr": "MGF ; mutilations génitales féminines", "def": "Female genital mutilation.", "ex": "FGM is internationally condemned as gender-based violence."}, {"term": "female genital mutilation", "ipa": "/ˌfiːmeɪl ˌdʒenɪtəl ˌmjuːtɪˈleɪʃən/", "pron": "FEE-male JEN-i-tuhl myoo-ti-LAY-shuhn", "fr": "mutilations génitales féminines", "def": "The cutting or injury of female genital organs for non-medical reasons.", "ex": "Female genital mutilation has serious physical and psychological consequences."}, {"term": "honour killing", "ipa": "/ˈɒnə ˌkɪlɪŋ/", "pron": "ON-uh KIL-ing", "fr": "crime d’honneur", "def": "The murder of a person, often a woman, claimed to protect family honour.", "ex": "Honour killings are linked to control over women’s sexuality."}, {"term": "gender-selective abortion", "ipa": "/ˈdʒendə sɪˌlektɪv əˈbɔːʃən/", "pron": "JEN-duh si-LEK-tiv uh-BOR-shuhn", "fr": "avortement sélectif selon le sexe", "def": "Abortion based on the sex of the foetus.", "ex": "Gender-selective abortion reflects son preference in some societies."}, {"term": "son preference", "ipa": "/ˈsʌn ˌprefərəns/", "pron": "sun PREF-uh-ruhns", "fr": "préférence pour les garçons", "def": "A cultural preference for male children.", "ex": "Son preference can distort sex ratios."}, {"term": "beauty standards", "ipa": "/ˈbjuːti ˌstændədz/", "pron": "BYOO-tee STAN-duhdz", "fr": "normes de beauté", "def": "Social ideals about physical appearance.", "ex": "Beauty standards can damage girls’ self-esteem."}, {"term": "body image", "ipa": "/ˈbɒdi ˌɪmɪdʒ/", "pron": "BOD-ee IM-ij", "fr": "image corporelle", "def": "How someone sees and feels about their body.", "ex": "Social media strongly affects body image."}, {"term": "objectification", "ipa": "/ɒbˌdʒektɪfɪˈkeɪʃən/", "pron": "ob-jek-ti-fi-KAY-shuhn", "fr": "objectification", "def": "Treating a person as an object, often sexually.", "ex": "Objectification reduces women to appearance or sexual appeal."}, {"term": "sexualisation", "ipa": "/ˌsekʃuəlaɪˈzeɪʃən/", "pron": "sek-shoo-uh-ly-ZAY-shuhn", "fr": "sexualisation", "def": "Making someone or something appear sexual, often inappropriately.", "ex": "The sexualisation of girls is a major media concern."}, {"term": "beauty industry", "ipa": "/ˈbjuːti ˌɪndəstri/", "pron": "BYOO-tee IN-duh-stree", "fr": "industrie de la beauté", "def": "The industry selling products and services related to appearance.", "ex": "The beauty industry profits from insecurity."}]}, {"title": "D. Reproductive rights, bodies and gender identity", "entries": [{"term": "diet culture", "ipa": "/ˈdaɪət ˌkʌltʃə/", "pron": "DY-uht KUL-chuh", "fr": "culture des régimes", "def": "Social pressure to control body size through dieting and thinness ideals.", "ex": "Diet culture can harm mental and physical health."}, {"term": "body positivity", "ipa": "/ˈbɒdi ˌpɒzətɪvəti/", "pron": "BOD-ee POZ-uh-tiv-uh-tee", "fr": "body positivity ; acceptation corporelle", "def": "A movement promoting acceptance of diverse bodies.", "ex": "Body positivity challenges narrow beauty standards."}, {"term": "media representation", "ipa": "/ˈmiːdiə ˌreprɪzenˈteɪʃən/", "pron": "MEE-dee-uh rep-ri-zen-TAY-shuhn", "fr": "représentation médiatique", "def": "The way groups are portrayed in media.", "ex": "Media representation shapes gender norms."}, {"term": "gendered advertising", "ipa": "/ˈdʒendəd ˈædvətaɪzɪŋ/", "pron": "JEN-duhd AD-vuh-ty-zing", "fr": "publicité genrée", "def": "Advertising that targets or represents people through gender stereotypes.", "ex": "Gendered advertising influences children’s ideas about roles."}, {"term": "pink tax", "ipa": "/ˈpɪŋk tæks/", "pron": "pink taks", "fr": "taxe rose", "def": "The higher price sometimes charged for products marketed to women.", "ex": "The pink tax makes everyday products more expensive for women."}, {"term": "gender-neutral", "ipa": "/ˌdʒendə ˈnjuːtrəl/", "pron": "JEN-duh NYOO-truhl", "fr": "neutre en genre", "def": "Not specific to one gender.", "ex": "Gender-neutral language can make communication more inclusive."}, {"term": "gender-inclusive", "ipa": "/ˈdʒendər ɪnˌkluːsɪv/", "pron": "JEN-duh in-KLOO-siv", "fr": "inclusif en matière de genre", "def": "Designed to include people of all genders.", "ex": "Gender-inclusive policies can protect transgender and non-binary people."}, {"term": "non-binary", "ipa": "/ˌnɒn ˈbaɪnəri/", "pron": "non BY-nuh-ree", "fr": "non binaire", "def": "Not identifying exclusively as male or female.", "ex": "Non-binary people challenge rigid gender categories."}, {"term": "transgender", "ipa": "/trænzˈdʒendə/", "pron": "tranz-JEN-duh", "fr": "transgenre", "def": "Having a gender identity different from the sex assigned at birth.", "ex": "Transgender rights are a major contemporary debate."}, {"term": "cisgender", "ipa": "/sɪsˈdʒendə/", "pron": "sis-JEN-duh", "fr": "cisgenre", "def": "Having a gender identity that matches the sex assigned at birth.", "ex": "Cisgender people usually do not face discrimination over gender identity."}, {"term": "transition", "ipa": "/trænˈzɪʃən/", "pron": "tran-ZISH-uhn", "fr": "transition", "def": "The process by which a transgender person changes social, legal or medical aspects of gender expression.", "ex": "Transition can be social, legal, medical or a combination."}, {"term": "gender dysphoria", "ipa": "/ˈdʒendə dɪsˈfɔːriə/", "pron": "JEN-duh dis-FOR-ee-uh", "fr": "dysphorie de genre", "def": "Distress caused by mismatch between gender identity and assigned sex.", "ex": "Gender dysphoria may require psychological or medical support."}, {"term": "gender-affirming care", "ipa": "/ˈdʒendər əˌfɜːmɪŋ keə/", "pron": "JEN-duh uh-FUR-ming care", "fr": "soins d’affirmation de genre", "def": "Healthcare supporting a person’s gender identity.", "ex": "Gender-affirming care is politically contested in many countries."}, {"term": "pronouns", "ipa": "/ˈprəʊnaʊnz/", "pron": "PROH-nownz", "fr": "pronoms", "def": "Words used to refer to someone, such as she, he or they.", "ex": "Using someone’s pronouns can be a sign of respect."}, {"term": "deadnaming", "ipa": "/ˈdedˌneɪmɪŋ/", "pron": "DED-nay-ming", "fr": "deadnaming ; utilisation de l’ancien prénom", "def": "Calling a transgender person by a former name they no longer use.", "ex": "Deadnaming can be hurtful and disrespectful."}, {"term": "gender recognition", "ipa": "/ˈdʒendə ˌrekəɡˈnɪʃən/", "pron": "JEN-duh rek-uhg-NISH-uhn", "fr": "reconnaissance juridique du genre", "def": "Legal recognition of a person’s gender identity.", "ex": "Gender recognition laws vary widely."}, {"term": "single-sex space", "ipa": "/ˌsɪŋɡəl seks ˈspeɪs/", "pron": "SING-guhl seks space", "fr": "espace non mixte", "def": "A space reserved for one sex, such as some shelters or changing rooms.", "ex": "Single-sex spaces are debated in relation to safety and trans rights."}, {"term": "gender-critical", "ipa": "/ˈdʒendə ˌkrɪtɪkəl/", "pron": "JEN-duh KRIT-i-kuhl", "fr": "critique du genre ; gender-critical", "def": "A position critical of some claims about gender identity, often stressing biological sex.", "ex": "Gender-critical views are highly controversial in public debate."}, {"term": "trans rights", "ipa": "/ˈtrænz raɪts/", "pron": "tranz rites", "fr": "droits des personnes trans", "def": "Rights protecting transgender people from discrimination and exclusion.", "ex": "Trans rights are part of broader equality debates."}, {"term": "gender culture war", "ipa": "/ˈdʒendə ˌkʌltʃə wɔː/", "pron": "JEN-duh KUL-chuh war", "fr": "guerre culturelle autour du genre", "def": "A political conflict over gender, sexuality, identity and social norms.", "ex": "Gender culture wars often polarise public debate."}, {"term": "MeToo movement", "ipa": "/ˌmiː ˈtuː ˌmuːvmənt/", "pron": "mee-too MOOV-muhnt", "fr": "mouvement MeToo", "def": "A movement exposing sexual harassment and assault.", "ex": "The MeToo movement changed conversations about consent and power."}, {"term": "hashtag activism", "ipa": "/ˈhæʃtæɡ ˌæktɪvɪzəm/", "pron": "HASH-tag AK-ti-viz-uhm", "fr": "activisme par hashtag", "def": "Activism organised or amplified through social media hashtags.", "ex": "Hashtag activism can give visibility to survivors."}, {"term": "online abuse", "ipa": "/ˌɒnlaɪn əˈbjuːs/", "pron": "ON-lyne uh-BYOOSS", "fr": "harcèlement en ligne", "def": "Harassment, threats or hateful behaviour online.", "ex": "Women in public life face high levels of online abuse."}, {"term": "cyber harassment", "ipa": "/ˈsaɪbə ˈhærəsmənt/", "pron": "SY-buh HARR-uhs-muhnt", "fr": "cyberharcèlement", "def": "Harassment using digital tools or platforms.", "ex": "Cyber harassment can include threats and stalking."}, {"term": "revenge porn", "ipa": "/rɪˈvendʒ pɔːn/", "pron": "ri-VENJ porn", "fr": "pornodivulgation ; revenge porn", "def": "Sharing intimate images without consent, often to harm someone.", "ex": "Revenge porn is a serious violation of privacy."}, {"term": "image-based abuse", "ipa": "/ˈɪmɪdʒ beɪst əˌbjuːs/", "pron": "IM-ij-bayst uh-BYOOSS", "fr": "violence par image intime", "def": "Abuse involving non-consensual creation or sharing of intimate images.", "ex": "Image-based abuse is increasingly targeted by law reform."}, {"term": "incel", "ipa": "/ˈɪnsel/", "pron": "IN-sel", "fr": "incel ; célibataire involontaire", "def": "A person, usually male, identifying as involuntarily celibate, often linked to misogynistic online communities.", "ex": "Incel ideology can fuel misogyny and violence."}, {"term": "male entitlement", "ipa": "/ˌmeɪl ɪnˈtaɪtəlmənt/", "pron": "male in-TY-tuhl-muhnt", "fr": "sentiment de droit masculin", "def": "The belief that men deserve women’s attention, labour or bodies.", "ex": "Male entitlement is often discussed in debates about misogyny."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction against social change.", "ex": "Gender equality movements often provoke backlash."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "Gender issues have become central to culture wars."}, {"term": "conservative backlash", "ipa": "/kənˌsɜːvətɪv ˈbæklæʃ/", "pron": "kuhn-SUR-vuh-tiv BAK-lash", "fr": "réaction conservatrice", "def": "A reaction by conservatives against progressive social change.", "ex": "The conservative backlash often targets feminism and LGBTQ+ rights."}, {"term": "gender ideology", "ipa": "/ˈdʒendər ˌaɪdiˈɒlədʒi/", "pron": "JEN-duh eye-dee-OL-uh-jee", "fr": "idéologie du genre", "def": "A phrase often used by opponents of progressive gender policies.", "ex": "The term gender ideology is used in culture-war debates."}, {"term": "family values", "ipa": "/ˌfæməli ˈvæljuːz/", "pron": "FAM-uh-lee VAL-yooz", "fr": "valeurs familiales", "def": "Conservative ideas about family, marriage and gender roles.", "ex": "Family values rhetoric often opposes feminist or LGBTQ+ reforms."}, {"term": "traditional family", "ipa": "/trəˌdɪʃənəl ˈfæməli/", "pron": "truh-DISH-uh-nuhl FAM-uh-lee", "fr": "famille traditionnelle", "def": "A family model usually based on a heterosexual couple and gendered roles.", "ex": "The traditional family is often idealised in conservative politics."}, {"term": "gender equality policy", "ipa": "/ˈdʒendər iˈkwɒləti ˈpɒləsi/", "pron": "JEN-duh i-KWOL-uh-tee POL-uh-see", "fr": "politique d’égalité femmes-hommes", "def": "Policy designed to reduce gender inequality.", "ex": "Gender equality policy includes pay, violence prevention and childcare."}, {"term": "anti-discrimination law", "ipa": "/ˌænti dɪˌskrɪmɪˈneɪʃən lɔː/", "pron": "AN-tee dis-krim-i-NAY-shuhn law", "fr": "loi anti-discrimination", "def": "Law protecting people from unfair treatment based on identity.", "ex": "Anti-discrimination law can protect women and gender minorities."}, {"term": "workplace equality", "ipa": "/ˈwɜːkpleɪs iˈkwɒləti/", "pron": "WURK-place i-KWOL-uh-tee", "fr": "égalité au travail", "def": "Equal treatment and opportunity at work.", "ex": "Workplace equality requires more than formal rules."}]}, {"title": "E. Culture wars, education, policy and high-value verbs", "entries": [{"term": "diversity training", "ipa": "/daɪˈvɜːsəti ˈtreɪnɪŋ/", "pron": "dy-VUR-suh-tee TRAY-ning", "fr": "formation à la diversité", "def": "Training intended to reduce prejudice and improve inclusion.", "ex": "Diversity training is common but its effectiveness is debated."}, {"term": "sexual consent education", "ipa": "/ˌsekʃuəl kənˈsent ˌedjʊˈkeɪʃən/", "pron": "SEK-shoo-uhl kuhn-SENT ej-yoo-KAY-shuhn", "fr": "éducation au consentement", "def": "Education teaching what consent means in relationships and sex.", "ex": "Sexual consent education can help prevent assault."}, {"term": "relationship education", "ipa": "/rɪˈleɪʃənʃɪp ˌedjʊˈkeɪʃən/", "pron": "ri-LAY-shuhn-ship ej-yoo-KAY-shuhn", "fr": "éducation aux relations", "def": "Education about healthy relationships, respect and communication.", "ex": "Relationship education can challenge harmful gender norms."}, {"term": "sex education", "ipa": "/ˈseks ˌedjʊˈkeɪʃən/", "pron": "seks ej-yoo-KAY-shuhn", "fr": "éducation sexuelle", "def": "Education about sexuality, bodies, contraception, consent and relationships.", "ex": "Sex education is often controversial in conservative communities."}, {"term": "gender studies", "ipa": "/ˈdʒendə ˌstʌdiz/", "pron": "JEN-duh STUD-eez", "fr": "études de genre", "def": "An academic field studying gender, sexuality and power.", "ex": "Gender studies is often attacked in culture-war rhetoric."}, {"term": "to challenge gender stereotypes", "ipa": "/ˈtʃælɪndʒ ˈdʒendə ˌsteriətaɪps/", "pron": "CHAL-inj JEN-duh STERR-ee-uh-types", "fr": "remettre en cause les stéréotypes de genre", "def": "To question fixed ideas about men and women.", "ex": "Schools can challenge gender stereotypes from an early age."}, {"term": "to close the gender pay gap", "ipa": "/kləʊz ðə ˈdʒendə ˈpeɪ ɡæp/", "pron": "klohz thuh JEN-duh pay gap", "fr": "réduire l’écart salarial femmes-hommes", "def": "To reduce or eliminate unequal average earnings between men and women.", "ex": "Pay transparency can help close the gender pay gap."}, {"term": "to break the glass ceiling", "ipa": "/breɪk ðə ˌɡlɑːs ˈsiːlɪŋ/", "pron": "brayk thuh glass SEE-ling", "fr": "briser le plafond de verre", "def": "To overcome invisible barriers to leadership.", "ex": "Mentoring and quotas can help women break the glass ceiling."}, {"term": "to empower women", "ipa": "/ɪmˈpaʊə ˈwɪmɪn/", "pron": "im-POW-uh WIM-in", "fr": "autonomiser les femmes ; donner du pouvoir aux femmes", "def": "To give women power, confidence, rights or resources.", "ex": "Education can empower women economically and politically."}, {"term": "to promote gender equality", "ipa": "/prəˈməʊt ˈdʒendər iˈkwɒləti/", "pron": "pruh-MOHT JEN-duh i-KWOL-uh-tee", "fr": "promouvoir l’égalité des genres", "def": "To encourage equal rights and opportunities regardless of gender.", "ex": "Governments use law and policy to promote gender equality."}, {"term": "to combat sexism", "ipa": "/ˈkɒmbæt ˈseksɪzəm/", "pron": "KOM-bat SEK-siz-uhm", "fr": "lutter contre le sexisme", "def": "To fight sexist attitudes, behaviour or institutions.", "ex": "Workplaces must combat sexism actively."}, {"term": "to tackle gender-based violence", "ipa": "/ˈtækəl ˈdʒendə beɪst ˈvaɪələns/", "pron": "TAK-uhl JEN-duh-bayst VY-uh-luhns", "fr": "lutter contre les violences fondées sur le genre", "def": "To take action against violence linked to gender.", "ex": "Education, shelters and law enforcement must tackle gender-based violence together."}, {"term": "to share domestic labour", "ipa": "/ʃeə dəˌmestɪk ˈleɪbə/", "pron": "shair duh-MES-tik LAY-buh", "fr": "partager le travail domestique", "def": "To divide household work more equally.", "ex": "Gender equality requires couples to share domestic labour."}, {"term": "to protect reproductive rights", "ipa": "/prəˈtekt ˌriːprəˈdʌktɪv raɪts/", "pron": "pruh-TEKT ree-pruh-DUK-tiv rites", "fr": "protéger les droits reproductifs", "def": "To defend access to contraception, abortion and reproductive healthcare.", "ex": "Activists campaign to protect reproductive rights."}, {"term": "to ensure bodily autonomy", "ipa": "/ɪnˈʃɔː ˌbɒdɪli ɔːˈtɒnəmi/", "pron": "in-SHOR BOD-i-lee aw-TON-uh-mee", "fr": "garantir l’autonomie corporelle", "def": "To guarantee control over one’s own body.", "ex": "Abortion-rights campaigners argue that the law must ensure bodily autonomy."}, {"term": "to hold perpetrators accountable", "ipa": "/həʊld ˈpɜːpətreɪtəz əˈkaʊntəbəl/", "pron": "hohld PUR-puh-tray-tuhz uh-KOWN-tuh-buhl", "fr": "tenir les agresseurs responsables", "def": "To make offenders face consequences for harmful acts.", "ex": "Justice systems must hold perpetrators accountable."}, {"term": "to support survivors", "ipa": "/səˈpɔːt səˈvaɪvəz/", "pron": "suh-PORT suh-VY-vuhz", "fr": "soutenir les survivantes et survivants", "def": "To provide help, protection and recognition to people who experienced abuse.", "ex": "Support services should believe and support survivors."}, {"term": "to make workplaces safer", "ipa": "/meɪk ˈwɜːkpleɪsɪz ˈseɪfə/", "pron": "mayk WURK-play-siz SAY-fuh", "fr": "rendre les lieux de travail plus sûrs", "def": "To reduce harassment, discrimination and risk at work.", "ex": "Clear reporting procedures can make workplaces safer."}]}]}, {"id": "p4c38", "part": 4, "chapter": 38, "title": "Lgbtq Issues", "file": "cpge_vocab_part4_chapter38_lgbtq_issues_premium.html", "count": 164, "sections": [{"title": "A. Core LGBTQ+ identities and concepts", "entries": [{"term": "LGBTQ+", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs/", "pron": "el-jee-bee-tee-KYOO-plus", "fr": "LGBTQ+", "def": "An acronym for lesbian, gay, bisexual, transgender, queer/questioning and other sexual or gender minorities.", "ex": "LGBTQ+ rights have become central to contemporary culture-war debates."}, {"term": "sexual orientation", "ipa": "/ˌsekʃuəl ˌɔːriənˈteɪʃən/", "pron": "SEK-shoo-uhl OR-ee-en-TAY-shuhn", "fr": "orientation sexuelle", "def": "A person’s emotional, romantic or sexual attraction to others.", "ex": "Sexual orientation is protected by anti-discrimination law in many countries."}, {"term": "gender identity", "ipa": "/ˌdʒendər aɪˈdentəti/", "pron": "JEN-duh eye-DEN-tuh-tee", "fr": "identité de genre", "def": "A person’s internal sense of their gender.", "ex": "Gender identity may differ from the sex assigned at birth."}, {"term": "gender expression", "ipa": "/ˌdʒendər ɪkˈspreʃən/", "pron": "JEN-duh ik-SPRESH-uhn", "fr": "expression de genre", "def": "How a person presents their gender through clothing, behaviour, voice or appearance.", "ex": "Gender expression does not always fit traditional norms."}, {"term": "sex assigned at birth", "ipa": "/seks əˌsaɪnd ət ˈbɜːθ/", "pron": "seks uh-SYND at birth", "fr": "sexe assigné à la naissance", "def": "The sex recorded for a baby at birth, usually male or female.", "ex": "Transgender people may not identify with the sex assigned at birth."}, {"term": "cisgender", "ipa": "/sɪsˈdʒendə/", "pron": "sis-JEN-duh", "fr": "cisgenre", "def": "Having a gender identity that matches the sex assigned at birth.", "ex": "Cisgender people usually do not face discrimination over gender identity."}, {"term": "transgender", "ipa": "/trænzˈdʒendə/", "pron": "tranz-JEN-duh", "fr": "transgenre", "def": "Having a gender identity different from the sex assigned at birth.", "ex": "Transgender rights have become highly politicised."}, {"term": "trans", "ipa": "/trænz/", "pron": "tranz", "fr": "trans", "def": "Short form of transgender.", "ex": "Trans people often face barriers in healthcare, work and public life."}, {"term": "non-binary", "ipa": "/ˌnɒn ˈbaɪnəri/", "pron": "non BY-nuh-ree", "fr": "non binaire", "def": "Not identifying exclusively as male or female.", "ex": "Non-binary identities challenge the idea that gender is only binary."}, {"term": "genderqueer", "ipa": "/ˈdʒendəkwɪə/", "pron": "JEN-duh-kweer", "fr": "genderqueer", "def": "An identity outside conventional gender categories.", "ex": "Genderqueer people may reject fixed gender labels."}, {"term": "gender-fluid", "ipa": "/ˈdʒendə ˌfluːɪd/", "pron": "JEN-duh FLOO-id", "fr": "genre fluide", "def": "Having a gender identity or expression that changes over time.", "ex": "A gender-fluid person may use different pronouns in different contexts."}, {"term": "agender", "ipa": "/eɪˈdʒendə/", "pron": "ay-JEN-duh", "fr": "agenre", "def": "Having no gender or not identifying with any gender.", "ex": "Agender people may reject gender categories altogether."}, {"term": "intersex", "ipa": "/ˈɪntəseks/", "pron": "IN-tuh-seks", "fr": "intersexe", "def": "Having biological sex characteristics that do not fit typical male or female categories.", "ex": "Intersex people have long been harmed by unnecessary medical interventions."}, {"term": "lesbian", "ipa": "/ˈlezbiən/", "pron": "LEZ-bee-uhn", "fr": "lesbienne", "def": "A woman who is romantically or sexually attracted to women.", "ex": "Lesbian visibility has often been overshadowed in public debate."}, {"term": "gay", "ipa": "/ɡeɪ/", "pron": "gay", "fr": "gay ; homosexuel", "def": "A person attracted to people of the same gender; often used for men.", "ex": "Gay rights campaigns changed marriage and adoption laws."}, {"term": "bisexual", "ipa": "/baɪˈsekʃuəl/", "pron": "by-SEK-shoo-uhl", "fr": "bisexuel", "def": "Attracted to more than one gender.", "ex": "Bisexual people can face misunderstanding from both straight and gay communities."}, {"term": "pansexual", "ipa": "/pænˈsekʃuəl/", "pron": "pan-SEK-shoo-uhl", "fr": "pansexuel", "def": "Attracted to people regardless of gender.", "ex": "Pansexuality emphasises attraction beyond gender categories."}, {"term": "asexual", "ipa": "/eɪˈsekʃuəl/", "pron": "ay-SEK-shoo-uhl", "fr": "asexuel", "def": "Experiencing little or no sexual attraction.", "ex": "Asexual people may still have romantic relationships."}, {"term": "aromantic", "ipa": "/ˌeɪrəʊˈmæntɪk/", "pron": "ay-roh-MAN-tik", "fr": "aromantique", "def": "Experiencing little or no romantic attraction.", "ex": "Aromantic identity challenges assumptions about romance."}, {"term": "queer", "ipa": "/kwɪə/", "pron": "kweer", "fr": "queer", "def": "An umbrella term for non-heterosexual or non-cisgender identities; formerly an insult, now reclaimed by many.", "ex": "Queer can be empowering, but some people still find the term painful."}, {"term": "questioning", "ipa": "/ˈkwestʃənɪŋ/", "pron": "KWES-chuh-ning", "fr": "en questionnement", "def": "Exploring or unsure about one’s sexual orientation or gender identity.", "ex": "Questioning young people need safe spaces and support."}, {"term": "straight", "ipa": "/streɪt/", "pron": "strayt", "fr": "hétérosexuel", "def": "Informal term for heterosexual.", "ex": "Straight people are usually represented as the social norm."}, {"term": "heterosexual", "ipa": "/ˌhetərəˈsekʃuəl/", "pron": "het-uh-roh-SEK-shoo-uhl", "fr": "hétérosexuel", "def": "Attracted to people of the opposite sex or gender.", "ex": "Heterosexuality is often treated as the default."}, {"term": "homosexual", "ipa": "/ˌhəʊməˈsekʃuəl/", "pron": "hoh-muh-SEK-shoo-uhl", "fr": "homosexuel", "def": "Attracted to people of the same sex or gender; now often considered formal or outdated in everyday use.", "ex": "The word homosexual can sound clinical in ordinary conversation."}, {"term": "homophobia", "ipa": "/ˌhəʊməˈfəʊbiə/", "pron": "hoh-muh-FOH-bee-uh", "fr": "homophobie", "def": "Hostility, prejudice or discrimination against gay people or homosexuality.", "ex": "Homophobia can appear in schools, sport, media and politics."}, {"term": "biphobia", "ipa": "/baɪˈfəʊbiə/", "pron": "by-FOH-bee-uh", "fr": "biphobie", "def": "Hostility, prejudice or discrimination against bisexual people.", "ex": "Biphobia often involves denying that bisexuality is real."}, {"term": "transphobia", "ipa": "/trænzˈfəʊbiə/", "pron": "tranz-FOH-bee-uh", "fr": "transphobie", "def": "Hostility, prejudice or discrimination against transgender people.", "ex": "Transphobia has intensified in many online debates."}, {"term": "queerphobia", "ipa": "/ˈkwɪəfəʊbiə/", "pron": "KWEER-foh-bee-uh", "fr": "queerphobie", "def": "Hostility towards queer people or identities.", "ex": "Queerphobia can target people who do not conform to gender norms."}, {"term": "heteronormativity", "ipa": "/ˌhetərəʊˌnɔːməˈtɪvəti/", "pron": "het-uh-roh-nor-muh-TIV-uh-tee", "fr": "hétéronormativité", "def": "The assumption that heterosexuality is normal, natural or default.", "ex": "Heteronormativity shapes education, advertising and family policy."}, {"term": "cisnormativity", "ipa": "/sɪsˌnɔːməˈtɪvəti/", "pron": "sis-nor-muh-TIV-uh-tee", "fr": "cisnormativité", "def": "The assumption that everyone is or should be cisgender.", "ex": "Cisnormativity makes trans and non-binary people invisible."}, {"term": "gender binary", "ipa": "/ˈdʒendə ˈbaɪnəri/", "pron": "JEN-duh BY-nuh-ree", "fr": "binarité de genre", "def": "The idea that there are only two opposite genders, male and female.", "ex": "The gender binary is challenged by non-binary identities."}, {"term": "coming out", "ipa": "/ˌkʌmɪŋ ˈaʊt/", "pron": "KUM-ing owt", "fr": "coming out ; révélation de son orientation ou identité", "def": "The process of telling others about one’s sexual orientation or gender identity.", "ex": "Coming out can be liberating but also risky."}, {"term": "to come out", "ipa": "/kʌm ˈaʊt/", "pron": "kum owt", "fr": "faire son coming out", "def": "To disclose one’s LGBTQ+ identity to others.", "ex": "Many people come out several times in different contexts."}, {"term": "outing", "ipa": "/ˈaʊtɪŋ/", "pron": "OWT-ing", "fr": "outing ; révélation forcée", "def": "Revealing someone’s LGBTQ+ identity without their consent.", "ex": "Outing someone can put them in danger."}, {"term": "closeted", "ipa": "/ˈklɒzɪtɪd/", "pron": "KLOZ-it-id", "fr": "dans le placard ; non déclaré", "def": "Not openly disclosing one’s LGBTQ+ identity.", "ex": "Closeted workers may fear losing their jobs."}, {"term": "visibility", "ipa": "/ˌvɪzəˈbɪləti/", "pron": "viz-uh-BIL-uh-tee", "fr": "visibilité", "def": "Public presence and recognition of a group or identity.", "ex": "LGBTQ+ visibility can reduce isolation."}, {"term": "representation", "ipa": "/ˌreprɪzenˈteɪʃən/", "pron": "rep-ri-zen-TAY-shuhn", "fr": "représentation", "def": "The presence or portrayal of a group in media, politics or institutions.", "ex": "Representation matters for LGBTQ+ young people."}, {"term": "role model", "ipa": "/ˈrəʊl ˌmɒdəl/", "pron": "rohl MOD-uhl", "fr": "modèle ; exemple à suivre", "def": "A person whose life or success inspires others.", "ex": "LGBTQ+ role models can help teenagers feel less alone."}, {"term": "ally", "ipa": "/ˈælaɪ/", "pron": "AL-eye", "fr": "allié", "def": "A person who supports a marginalised group they do not belong to.", "ex": "Allies can challenge homophobia and transphobia."}, {"term": "allyship", "ipa": "/ˈælaɪʃɪp/", "pron": "AL-eye-ship", "fr": "alliance active ; soutien allié", "def": "Active support for a marginalised group.", "ex": "Allyship requires listening and action, not just symbols."}]}, {"title": "B. Visibility, community, rights and family equality", "entries": [{"term": "safe space", "ipa": "/ˈseɪf speɪs/", "pron": "sayf space", "fr": "espace sûr", "def": "A space intended to protect people from hostility, harassment or discrimination.", "ex": "Safe spaces can help LGBTQ+ students speak openly."}, {"term": "chosen family", "ipa": "/ˌtʃəʊzən ˈfæməli/", "pron": "CHOH-zuhn FAM-uh-lee", "fr": "famille choisie", "def": "Supportive friends or community treated as family, especially when biological family rejects someone.", "ex": "Chosen family has been vital for many LGBTQ+ people."}, {"term": "Pride", "ipa": "/praɪd/", "pron": "pryde", "fr": "Pride ; marche des fiertés", "def": "Celebrations, protests and events affirming LGBTQ+ identities and rights.", "ex": "Pride began as protest and remains political."}, {"term": "Pride march", "ipa": "/ˈpraɪd mɑːtʃ/", "pron": "pryde march", "fr": "marche des fiertés", "def": "A public demonstration celebrating LGBTQ+ identity and demanding rights.", "ex": "A Pride march can be both festive and activist."}, {"term": "rainbow flag", "ipa": "/ˈreɪnbəʊ flæɡ/", "pron": "RAYN-boh flag", "fr": "drapeau arc-en-ciel", "def": "A flag symbolising LGBTQ+ pride and diversity.", "ex": "The rainbow flag is recognised worldwide."}, {"term": "Stonewall riots", "ipa": "/ˈstəʊnwɔːl ˌraɪəts/", "pron": "STOHN-wall RY-uhts", "fr": "émeutes de Stonewall", "def": "1969 protests in New York often seen as a turning point in LGBTQ+ activism.", "ex": "The Stonewall riots helped launch modern LGBTQ+ rights movements."}, {"term": "LGBTQ+ rights", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs raɪts/", "pron": "el-jee-bee-tee-KYOO-plus rites", "fr": "droits LGBTQ+", "def": "Rights protecting LGBTQ+ people from discrimination and unequal treatment.", "ex": "LGBTQ+ rights include marriage, adoption, safety and healthcare."}, {"term": "gay rights", "ipa": "/ˈɡeɪ raɪts/", "pron": "gay rites", "fr": "droits des personnes gays", "def": "Rights protecting gay people from discrimination and inequality.", "ex": "Gay rights campaigns transformed many Western legal systems."}, {"term": "trans rights", "ipa": "/ˈtrænz raɪts/", "pron": "tranz rites", "fr": "droits des personnes trans", "def": "Rights protecting transgender people from discrimination and exclusion.", "ex": "Trans rights are one of the most polarising current debates."}, {"term": "equal rights", "ipa": "/ˌiːkwəl ˈraɪts/", "pron": "EE-kwuhl rites", "fr": "égalité des droits", "def": "The same legal rights and protections for all people.", "ex": "Equal rights do not automatically guarantee equal lived experience."}, {"term": "civil rights", "ipa": "/ˌsɪvəl ˈraɪts/", "pron": "SIV-uhl rites", "fr": "droits civiques", "def": "Rights protecting equal treatment and participation in society.", "ex": "LGBTQ+ activism is often framed as a civil rights struggle."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights belonging to all people.", "ex": "Many activists frame LGBTQ+ rights as human rights."}, {"term": "anti-discrimination law", "ipa": "/ˌænti dɪˌskrɪmɪˈneɪʃən lɔː/", "pron": "AN-tee dis-krim-i-NAY-shuhn law", "fr": "loi anti-discrimination", "def": "Law protecting people from unfair treatment based on identity.", "ex": "Anti-discrimination law can protect LGBTQ+ workers and students."}, {"term": "protected characteristic", "ipa": "/prəˌtektɪd ˌkærəktəˈrɪstɪk/", "pron": "pruh-TEK-tid KARR-uhk-tuh-RIS-tik", "fr": "caractéristique protégée", "def": "A legally protected identity category, such as sex, race or sexual orientation.", "ex": "Sexual orientation is a protected characteristic in UK equality law."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by hostility towards identity, including sexuality or gender identity.", "ex": "LGBTQ+ hate crime can make communities feel unsafe."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity.", "ex": "Hate speech against LGBTQ+ people spreads quickly online."}, {"term": "conversion therapy", "ipa": "/kənˈvɜːʃən ˌθerəpi/", "pron": "kuhn-VUR-zhuhn THERR-uh-pee", "fr": "thérapie de conversion", "def": "Practices attempting to change someone’s sexual orientation or gender identity.", "ex": "Conversion therapy is widely condemned as harmful."}, {"term": "ban on conversion therapy", "ipa": "/ˌbæn ɒn kənˈvɜːʃən ˌθerəpi/", "pron": "ban on kuhn-VUR-zhuhn THERR-uh-pee", "fr": "interdiction des thérapies de conversion", "def": "A legal prohibition of conversion therapy.", "ex": "A ban on conversion therapy is debated in several countries."}, {"term": "marriage equality", "ipa": "/ˈmærɪdʒ iˌkwɒləti/", "pron": "MARR-ij i-KWOL-uh-tee", "fr": "égalité du mariage", "def": "Equal marriage rights for same-sex couples.", "ex": "Marriage equality was a major milestone for LGBTQ+ rights."}, {"term": "same-sex marriage", "ipa": "/ˌseɪm seks ˈmærɪdʒ/", "pron": "same-seks MARR-ij", "fr": "mariage homosexuel ; mariage pour tous", "def": "Marriage between two people of the same sex.", "ex": "Same-sex marriage remains illegal in many countries."}, {"term": "civil partnership", "ipa": "/ˌsɪvəl ˈpɑːtnəʃɪp/", "pron": "SIV-uhl PART-nuh-ship", "fr": "partenariat civil", "def": "A legally recognised partnership similar to marriage.", "ex": "Civil partnerships were introduced before same-sex marriage in the UK."}, {"term": "adoption rights", "ipa": "/əˈdɒpʃən raɪts/", "pron": "uh-DOP-shuhn rites", "fr": "droit à l’adoption", "def": "The right to adopt children, including for same-sex couples.", "ex": "Adoption rights are part of family equality."}, {"term": "family recognition", "ipa": "/ˈfæməli ˌrekəɡˈnɪʃən/", "pron": "FAM-uh-lee rek-uhg-NISH-uhn", "fr": "reconnaissance familiale", "def": "Legal and social recognition of diverse family forms.", "ex": "Family recognition protects children of same-sex parents."}, {"term": "parental rights", "ipa": "/pəˌrentəl ˈraɪts/", "pron": "puh-REN-tuhl rites", "fr": "droits parentaux", "def": "Legal rights and responsibilities of parents.", "ex": "Parental rights for LGBTQ+ families vary across legal systems."}, {"term": "surrogacy", "ipa": "/ˈsʌrəɡəsi/", "pron": "SUR-uh-guh-see", "fr": "gestation pour autrui ; GPA", "def": "An arrangement where someone carries a pregnancy for another person or couple.", "ex": "Surrogacy raises ethical and legal questions for LGBTQ+ families."}, {"term": "IVF", "ipa": "/ˌaɪ viː ˈef/", "pron": "eye-vee-eff", "fr": "FIV ; fécondation in vitro", "def": "In vitro fertilisation, a medical technique to help people conceive.", "ex": "IVF access can be unequal for lesbian couples."}, {"term": "donor conception", "ipa": "/ˈdəʊnə kənˌsepʃən/", "pron": "DOH-nuh kuhn-SEP-shuhn", "fr": "conception avec donneur", "def": "Conception using donated sperm, eggs or embryos.", "ex": "Donor conception is important for many LGBTQ+ families."}, {"term": "legal gender recognition", "ipa": "/ˈliːɡəl ˈdʒendə ˌrekəɡˈnɪʃən/", "pron": "LEE-guhl JEN-duh rek-uhg-NISH-uhn", "fr": "reconnaissance juridique du genre", "def": "Legal recognition of a person’s gender identity.", "ex": "Legal gender recognition can affect documents, privacy and dignity."}, {"term": "gender marker", "ipa": "/ˈdʒendə ˌmɑːkə/", "pron": "JEN-duh MAR-kuh", "fr": "mention de genre", "def": "A gender label on official documents, such as M, F or X.", "ex": "Some countries allow an X gender marker on passports."}, {"term": "self-identification", "ipa": "/ˌself aɪˌdentɪfɪˈkeɪʃən/", "pron": "self eye-den-ti-fi-KAY-shuhn", "fr": "auto-identification", "def": "Legal or social recognition based on a person’s own declaration of identity.", "ex": "Self-identification is controversial in gender recognition debates."}, {"term": "transition", "ipa": "/trænˈzɪʃən/", "pron": "tran-ZISH-uhn", "fr": "transition", "def": "The process of changing social, legal or medical aspects of gender expression or recognition.", "ex": "Transition may include name changes, pronouns, hormones or surgery."}, {"term": "social transition", "ipa": "/ˌsəʊʃəl trænˈzɪʃən/", "pron": "SOH-shuhl tran-ZISH-uhn", "fr": "transition sociale", "def": "Changing name, pronouns, clothing or social role to match gender identity.", "ex": "Social transition does not necessarily involve medical treatment."}, {"term": "medical transition", "ipa": "/ˌmedɪkəl trænˈzɪʃən/", "pron": "MED-i-kuhl tran-ZISH-uhn", "fr": "transition médicale", "def": "Medical steps such as hormones or surgery taken as part of transition.", "ex": "Medical transition should be based on informed care."}, {"term": "gender-affirming care", "ipa": "/ˈdʒendər əˌfɜːmɪŋ keə/", "pron": "JEN-duh uh-FUR-ming care", "fr": "soins d’affirmation de genre", "def": "Healthcare supporting a person’s gender identity.", "ex": "Gender-affirming care is intensely debated for minors."}, {"term": "gender dysphoria", "ipa": "/ˈdʒendə dɪsˈfɔːriə/", "pron": "JEN-duh dis-FOR-ee-uh", "fr": "dysphorie de genre", "def": "Distress caused by mismatch between gender identity and assigned sex.", "ex": "Gender dysphoria can affect mental health."}]}, {"title": "C. Trans rights, schools and culture-war debates", "entries": [{"term": "puberty blockers", "ipa": "/ˈpjuːbəti ˌblɒkəz/", "pron": "PYOO-buh-tee BLOK-uhz", "fr": "bloqueurs de puberté", "def": "Medication delaying puberty, sometimes used in gender care for young people.", "ex": "Puberty blockers are at the centre of medical and political controversy."}, {"term": "hormone therapy", "ipa": "/ˈhɔːməʊn ˌθerəpi/", "pron": "HOR-mohn THERR-uh-pee", "fr": "hormonothérapie", "def": "Medical treatment using hormones.", "ex": "Hormone therapy may be part of gender-affirming care."}, {"term": "pronouns", "ipa": "/ˈprəʊnaʊnz/", "pron": "PROH-nownz", "fr": "pronoms", "def": "Words used to refer to someone, such as she, he or they.", "ex": "Respecting pronouns can reduce everyday exclusion."}, {"term": "chosen name", "ipa": "/ˌtʃəʊzən ˈneɪm/", "pron": "CHOH-zuhn name", "fr": "prénom choisi", "def": "The name a person chooses to use, often replacing a birth name.", "ex": "Using a chosen name can affirm someone’s identity."}, {"term": "deadnaming", "ipa": "/ˈdedˌneɪmɪŋ/", "pron": "DED-nay-ming", "fr": "deadnaming ; utilisation de l’ancien prénom", "def": "Calling a trans person by a former name they no longer use.", "ex": "Deadnaming can be humiliating and unsafe."}, {"term": "misgendering", "ipa": "/ˌmɪsˈdʒendərɪŋ/", "pron": "mis-JEN-duh-ring", "fr": "mégenrage", "def": "Referring to someone with the wrong gender or pronouns.", "ex": "Repeated misgendering can be experienced as harassment."}, {"term": "bathroom bill", "ipa": "/ˈbɑːθruːm bɪl/", "pron": "BATH-room bil", "fr": "loi sur l’accès aux toilettes", "def": "A law or proposal restricting which toilets transgender people may use.", "ex": "Bathroom bills have become a symbol of anti-trans politics."}, {"term": "single-sex space", "ipa": "/ˌsɪŋɡəl seks ˈspeɪs/", "pron": "SING-guhl seks space", "fr": "espace non mixte", "def": "A space reserved for one sex, such as some shelters or changing rooms.", "ex": "Single-sex spaces are debated in relation to safety and inclusion."}, {"term": "inclusive policy", "ipa": "/ɪnˌkluːsɪv ˈpɒləsi/", "pron": "in-KLOO-siv POL-uh-see", "fr": "politique inclusive", "def": "A policy designed to include marginalised or diverse groups.", "ex": "Inclusive policies can make schools safer for LGBTQ+ students."}, {"term": "school inclusion", "ipa": "/ˈskuːl ɪnˌkluːʒən/", "pron": "school in-KLOO-zhuhn", "fr": "inclusion scolaire", "def": "The inclusion of diverse identities and pupils within school life.", "ex": "School inclusion can reduce bullying and isolation."}, {"term": "LGBTQ+ education", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs ˌedjʊˈkeɪʃən/", "pron": "el-jee-bee-tee-KYOO-plus ej-yoo-KAY-shuhn", "fr": "éducation aux questions LGBTQ+", "def": "Education about LGBTQ+ identities, rights and history.", "ex": "LGBTQ+ education is often attacked in culture-war debates."}, {"term": "inclusive curriculum", "ipa": "/ɪnˌkluːsɪv kəˈrɪkjʊləm/", "pron": "in-KLOO-siv kuh-RIK-yuh-luhm", "fr": "programme inclusif", "def": "A curriculum that represents diverse groups and experiences.", "ex": "An inclusive curriculum can reduce stigma."}, {"term": "relationship education", "ipa": "/rɪˈleɪʃənʃɪp ˌedjʊˈkeɪʃən/", "pron": "ri-LAY-shuhn-ship ej-yoo-KAY-shuhn", "fr": "éducation aux relations", "def": "Education about healthy relationships, respect and communication.", "ex": "Relationship education may include same-sex relationships."}, {"term": "sex education", "ipa": "/ˈseks ˌedjʊˈkeɪʃən/", "pron": "seks ej-yoo-KAY-shuhn", "fr": "éducation sexuelle", "def": "Education about sexuality, bodies, consent, relationships and contraception.", "ex": "Sex education is often politically sensitive."}, {"term": "parental rights", "ipa": "/pəˌrentəl ˈraɪts/", "pron": "puh-REN-tuhl rites", "fr": "droits des parents", "def": "The claim that parents should control or influence children’s education and upbringing.", "ex": "Parental rights rhetoric is often used against LGBTQ+ education."}, {"term": "book ban", "ipa": "/ˈbʊk bæn/", "pron": "book ban", "fr": "interdiction de livres", "def": "A restriction or removal of books from schools or libraries.", "ex": "Book bans often target LGBTQ+ stories."}, {"term": "Don't Say Gay law", "ipa": "/ˌdəʊnt seɪ ˈɡeɪ lɔː/", "pron": "dohnt say gay law", "fr": "loi dite “Don’t Say Gay”", "def": "A nickname for laws restricting discussion of sexual orientation or gender identity in schools.", "ex": "Don't Say Gay laws have become a major US controversy."}, {"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A political conflict over values, identity and social norms.", "ex": "LGBTQ+ issues are a major culture-war battlefield."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "A public fear, often exaggerated, that a group threatens society.", "ex": "Moral panic about LGBTQ+ education can fuel censorship."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction against social change.", "ex": "Progress on LGBTQ+ rights has provoked backlash."}, {"term": "anti-LGBTQ+ rhetoric", "ipa": "/ˌænti el dʒiː biː tiː ˈkjuː plʌs ˈretərɪk/", "pron": "AN-tee el-jee-bee-tee-KYOO-plus RET-uh-rik", "fr": "rhétorique anti-LGBTQ+", "def": "Language attacking or demonising LGBTQ+ people.", "ex": "Anti-LGBTQ+ rhetoric can increase real-world hostility."}, {"term": "grooming slur", "ipa": "/ˈɡruːmɪŋ slɜː/", "pron": "GROOM-ing slur", "fr": "accusation diffamatoire de prédation", "def": "A false smear portraying LGBTQ+ people as threats to children.", "ex": "The grooming slur has reappeared in anti-LGBTQ+ politics."}, {"term": "religious freedom", "ipa": "/rɪˌlɪdʒəs ˈfriːdəm/", "pron": "ri-LIJ-uhs FREE-duhm", "fr": "liberté religieuse", "def": "The freedom to practise religion without persecution.", "ex": "Religious freedom can clash with LGBTQ+ equality claims."}, {"term": "conscientious objection", "ipa": "/ˌkɒnʃiˈenʃəs əbˈdʒekʃən/", "pron": "kon-shee-EN-shuhs ub-JEK-shuhn", "fr": "objection de conscience", "def": "Refusal to do something for moral or religious reasons.", "ex": "Conscientious objection is debated in healthcare and services."}, {"term": "religious exemption", "ipa": "/rɪˌlɪdʒəs ɪɡˈzempʃən/", "pron": "ri-LIJ-uhs ig-ZEMP-shuhn", "fr": "exemption religieuse", "def": "An exception to a law granted for religious reasons.", "ex": "Religious exemptions can conflict with anti-discrimination rules."}, {"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov speech", "fr": "liberté d’expression", "def": "The right to express opinions without censorship or punishment.", "ex": "Freedom of speech is often invoked in gender debates."}, {"term": "free speech dispute", "ipa": "/ˌfriː ˈspiːtʃ dɪˌspjuːt/", "pron": "free speech di-SPYOOT", "fr": "débat sur la liberté d’expression", "def": "A disagreement about whether speech should be protected or restricted.", "ex": "Free speech disputes often arise around pronouns and trans rights."}, {"term": "hate speech law", "ipa": "/ˈheɪt spiːtʃ lɔː/", "pron": "hate speech law", "fr": "loi contre les discours de haine", "def": "Law restricting speech that attacks people based on identity.", "ex": "Hate speech laws must balance protection and free expression."}, {"term": "anti-trans legislation", "ipa": "/ˌænti ˈtrænz ˌledʒɪsˈleɪʃən/", "pron": "AN-tee tranz lej-is-LAY-shuhn", "fr": "législation anti-trans", "def": "Laws restricting transgender rights or access to services.", "ex": "Anti-trans legislation has expanded in several US states."}, {"term": "bathroom access", "ipa": "/ˈbɑːθruːm ˌækses/", "pron": "BATH-room AK-sess", "fr": "accès aux toilettes", "def": "The ability to use toilets matching one’s gender identity.", "ex": "Bathroom access affects safety and dignity for trans people."}, {"term": "sports participation", "ipa": "/ˈspɔːts pɑːˌtɪsɪˈpeɪʃən/", "pron": "sports par-tis-i-PAY-shuhn", "fr": "participation sportive", "def": "Taking part in sport, often debated in relation to gender categories.", "ex": "Trans sports participation has become politically contentious."}, {"term": "women’s sport", "ipa": "/ˈwɪmɪnz spɔːt/", "pron": "WIM-inz sport", "fr": "sport féminin", "def": "Sport categories for women and girls.", "ex": "Women’s sport is often invoked in debates on trans inclusion."}, {"term": "fairness in sport", "ipa": "/ˈfeənəs ɪn spɔːt/", "pron": "FAIR-nuhs in sport", "fr": "équité dans le sport", "def": "The principle that competition should be fair and safe.", "ex": "Fairness in sport must be balanced with inclusion and evidence."}, {"term": "LGBTQ+ youth", "ipa": "/ˌel dʒiː biː tiː ˈkjuː plʌs juːθ/", "pron": "el-jee-bee-tee-KYOO-plus yooth", "fr": "jeunes LGBTQ+", "def": "Young people who are LGBTQ+.", "ex": "LGBTQ+ youth are at higher risk of bullying and isolation."}, {"term": "bullying", "ipa": "/ˈbʊliɪŋ/", "pron": "BUUL-ee-ing", "fr": "harcèlement scolaire ; intimidation", "def": "Repeated aggressive behaviour intended to hurt or intimidate someone.", "ex": "Homophobic bullying can damage mental health."}, {"term": "school bullying", "ipa": "/ˈskuːl ˌbʊliɪŋ/", "pron": "school BUUL-ee-ing", "fr": "harcèlement scolaire", "def": "Bullying taking place in school settings.", "ex": "School bullying often targets gender nonconformity."}]}, {"title": "D. Health, workplace inclusion and intersectionality", "entries": [{"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl helth", "fr": "santé mentale", "def": "Emotional, psychological and social well-being.", "ex": "LGBTQ+ mental health is shaped by stigma and support."}, {"term": "minority stress", "ipa": "/maɪˌnɒrəti ˈstres/", "pron": "my-NOR-uh-tee stress", "fr": "stress minoritaire", "def": "Stress caused by stigma, discrimination and marginalisation of minority groups.", "ex": "Minority stress helps explain mental health inequalities."}, {"term": "suicide risk", "ipa": "/ˈsuːɪsaɪd rɪsk/", "pron": "SOO-i-side risk", "fr": "risque suicidaire", "def": "The likelihood of suicidal thoughts or behaviour.", "ex": "Supportive environments can reduce suicide risk among LGBTQ+ youth."}, {"term": "self-harm", "ipa": "/ˌself ˈhɑːm/", "pron": "self harm", "fr": "automutilation", "def": "Intentional injury to oneself, often linked to psychological distress.", "ex": "Self-harm should be treated as a sign of distress."}, {"term": "affirming environment", "ipa": "/əˌfɜːmɪŋ ɪnˈvaɪrənmənt/", "pron": "uh-FUR-ming in-VY-ruhn-muhnt", "fr": "environnement affirmatif et soutenant", "def": "A setting that recognises and supports someone’s identity.", "ex": "An affirming environment improves well-being."}, {"term": "family rejection", "ipa": "/ˈfæməli rɪˌdʒekʃən/", "pron": "FAM-uh-lee ri-JEK-shuhn", "fr": "rejet familial", "def": "Rejection by relatives because of identity or orientation.", "ex": "Family rejection can lead to homelessness."}, {"term": "family acceptance", "ipa": "/ˈfæməli əkˌseptəns/", "pron": "FAM-uh-lee ak-SEP-tuhns", "fr": "acceptation familiale", "def": "Support and acceptance by relatives.", "ex": "Family acceptance protects LGBTQ+ young people."}, {"term": "youth homelessness", "ipa": "/ˈjuːθ ˈhəʊmləsnəs/", "pron": "yooth HOHM-luhs-nuhs", "fr": "sans-abrisme des jeunes", "def": "Homelessness affecting young people.", "ex": "LGBTQ+ youth are overrepresented among homeless young people."}, {"term": "workplace discrimination", "ipa": "/ˈwɜːkpleɪs dɪˌskrɪmɪˈneɪʃən/", "pron": "WURK-place dis-krim-i-NAY-shuhn", "fr": "discrimination au travail", "def": "Unfair treatment at work based on identity.", "ex": "Workplace discrimination can affect hiring, promotion and safety."}, {"term": "inclusive workplace", "ipa": "/ɪnˌkluːsɪv ˈwɜːkpleɪs/", "pron": "in-KLOO-siv WURK-place", "fr": "lieu de travail inclusif", "def": "A workplace where different identities are respected and included.", "ex": "An inclusive workplace supports productivity and well-being."}, {"term": "employee resource group", "ipa": "/ɪmˈplɔɪiː rɪˈzɔːs ɡruːp/", "pron": "im-PLOY-ee ri-ZORSS group", "fr": "réseau d’employés", "def": "A workplace group supporting employees with shared identities or interests.", "ex": "LGBTQ+ employee resource groups can improve inclusion."}, {"term": "diversity training", "ipa": "/daɪˈvɜːsəti ˈtreɪnɪŋ/", "pron": "dy-VUR-suh-tee TRAY-ning", "fr": "formation à la diversité", "def": "Training intended to reduce prejudice and improve inclusion.", "ex": "Diversity training may include LGBTQ+ awareness."}, {"term": "inclusive language", "ipa": "/ɪnˌkluːsɪv ˈlæŋɡwɪdʒ/", "pron": "in-KLOO-siv LANG-gwij", "fr": "langage inclusif", "def": "Language that avoids excluding or stereotyping groups.", "ex": "Inclusive language can make institutions more welcoming."}, {"term": "gender-neutral language", "ipa": "/ˌdʒendə ˈnjuːtrəl ˈlæŋɡwɪdʒ/", "pron": "JEN-duh NYOO-truhl LANG-gwij", "fr": "langage neutre en genre", "def": "Language not specific to one gender.", "ex": "Gender-neutral language includes singular they."}, {"term": "singular they", "ipa": "/ˌsɪŋɡjələ ˈðeɪ/", "pron": "SING-gyuh-luh thay", "fr": "they singulier", "def": "The use of they to refer to one person, often when gender is unknown or non-binary.", "ex": "Singular they is common in inclusive English."}, {"term": "inclusive healthcare", "ipa": "/ɪnˌkluːsɪv ˈhelθkeə/", "pron": "in-KLOO-siv HELTH-care", "fr": "soins inclusifs", "def": "Healthcare that recognises and respects diverse identities.", "ex": "Inclusive healthcare requires training and trust."}, {"term": "health disparity", "ipa": "/ˈhelθ dɪˌspærəti/", "pron": "helth di-SPARR-uh-tee", "fr": "disparité de santé", "def": "A difference in health outcomes between groups.", "ex": "LGBTQ+ health disparities are linked to stigma and access barriers."}, {"term": "HIV/AIDS", "ipa": "/ˌeɪtʃ aɪ ˈviː ˌeɪdz/", "pron": "aych-eye-vee aydez", "fr": "VIH/sida", "def": "HIV is a virus affecting the immune system; AIDS is the advanced stage of infection.", "ex": "HIV/AIDS shaped modern LGBTQ+ activism and public health."}, {"term": "HIV stigma", "ipa": "/ˌeɪtʃ aɪ ˈviː ˈstɪɡmə/", "pron": "aych-eye-vee STIG-muh", "fr": "stigmatisation liée au VIH", "def": "Negative judgement and discrimination related to HIV.", "ex": "HIV stigma discourages testing and treatment."}, {"term": "PrEP", "ipa": "/prep/", "pron": "prep", "fr": "PrEP ; prophylaxie pré-exposition", "def": "Pre-exposure prophylaxis, medicine taken to prevent HIV infection.", "ex": "PrEP has transformed HIV prevention."}, {"term": "public health campaign", "ipa": "/ˌpʌblɪk ˈhelθ kæmˌpeɪn/", "pron": "PUB-lik helth kam-PAYN", "fr": "campagne de santé publique", "def": "A campaign aimed at improving population health.", "ex": "Public health campaigns helped fight misinformation about HIV."}, {"term": "blood donation ban", "ipa": "/ˈblʌd dəʊˌneɪʃən bæn/", "pron": "blud doh-NAY-shuhn ban", "fr": "interdiction de don du sang", "def": "A restriction preventing some groups from donating blood.", "ex": "Blood donation bans targeting gay men have been criticised as discriminatory."}, {"term": "intersectionality", "ipa": "/ˌɪntəsekʃəˈnæləti/", "pron": "IN-tuh-sek-shuh-NAL-uh-tee", "fr": "intersectionnalité", "def": "The way different forms of inequality combine, such as sexuality, race, class and disability.", "ex": "Intersectionality shows that LGBTQ+ experiences are not all the same."}, {"term": "queer people of colour", "ipa": "/ˌkwɪə ˈpiːpəl əv ˈkʌlə/", "pron": "kweer PEE-puhl ov KUL-uh", "fr": "personnes queer racisées", "def": "LGBTQ+ people who are not white.", "ex": "Queer people of colour can face both racism and homophobia."}, {"term": "double discrimination", "ipa": "/ˌdʌbəl dɪˌskrɪmɪˈneɪʃən/", "pron": "DUB-uhl dis-krim-i-NAY-shuhn", "fr": "double discrimination", "def": "Discrimination based on more than one identity.", "ex": "A Black lesbian may face double discrimination."}, {"term": "multiple marginalisation", "ipa": "/ˌmʌltɪpəl ˌmɑːdʒɪnəlaɪˈzeɪʃən/", "pron": "MUL-ti-puhl mar-ji-nuh-ly-ZAY-shuhn", "fr": "marginalisation multiple", "def": "Being marginalised because of several identities or factors.", "ex": "Multiple marginalisation affects access to justice and healthcare."}, {"term": "asylum seeker", "ipa": "/əˈsaɪləm ˌsiːkə/", "pron": "uh-SY-luhm SEE-kuh", "fr": "demandeur d’asile", "def": "A person seeking protection in another country.", "ex": "LGBTQ+ asylum seekers may flee criminalisation or violence."}, {"term": "refugee", "ipa": "/ˌrefjʊˈdʒiː/", "pron": "REF-yoo-jee", "fr": "réfugié", "def": "A person forced to flee persecution, war or violence.", "ex": "Some LGBTQ+ refugees flee persecution based on sexuality or gender identity."}, {"term": "criminalisation", "ipa": "/ˌkrɪmɪnəlaɪˈzeɪʃən/", "pron": "KRIM-i-nuh-ly-ZAY-shuhn", "fr": "criminalisation", "def": "Making an action illegal or treating people as criminals.", "ex": "The criminalisation of homosexuality persists in many countries."}, {"term": "decriminalisation", "ipa": "/ˌdiːkrɪmɪnəlaɪˈzeɪʃən/", "pron": "dee-KRIM-i-nuh-ly-ZAY-shuhn", "fr": "dépénalisation", "def": "Removing criminal penalties from an act.", "ex": "Decriminalisation is a first step towards LGBTQ+ equality."}, {"term": "persecution", "ipa": "/ˌpɜːsɪˈkjuːʃən/", "pron": "pur-si-KYOO-shuhn", "fr": "persécution", "def": "Mistreatment because of identity, belief or status.", "ex": "LGBTQ+ persecution can justify asylum claims."}, {"term": "state-sponsored discrimination", "ipa": "/ˌsteɪt ˈspɒnsəd dɪˌskrɪmɪˈneɪʃən/", "pron": "state SPON-suhd dis-krim-i-NAY-shuhn", "fr": "discrimination soutenue par l’État", "def": "Discrimination supported or imposed by the state.", "ex": "State-sponsored discrimination makes minorities vulnerable."}]}, {"title": "E. Global rights, persecution and high-value verbs", "entries": [{"term": "anti-gay law", "ipa": "/ˌænti ˈɡeɪ lɔː/", "pron": "AN-tee gay law", "fr": "loi anti-gay", "def": "A law targeting or restricting gay people or same-sex relationships.", "ex": "Anti-gay laws are often justified through tradition or religion."}, {"term": "death penalty for homosexuality", "ipa": "/ˈdeθ ˌpenəlti fə ˌhəʊməsekʃuˈæləti/", "pron": "death PEN-uhl-tee for hoh-muh-sek-shoo-AL-uh-tee", "fr": "peine de mort pour homosexualité", "def": "Execution as a legal punishment for same-sex relations.", "ex": "The death penalty for homosexuality exists in a small number of legal systems."}, {"term": "international human rights law", "ipa": "/ˌɪntəˈnæʃənəl ˌhjuːmən ˈraɪts lɔː/", "pron": "IN-tuh-NASH-uh-nuhl HYOO-muhn rites law", "fr": "droit international des droits humains", "def": "International legal principles protecting basic human rights.", "ex": "International human rights law increasingly addresses LGBTQ+ persecution."}, {"term": "culture clash", "ipa": "/ˈkʌltʃə klæʃ/", "pron": "KUL-chuh klash", "fr": "choc culturel ; conflit de valeurs", "def": "A conflict between different cultural values or norms.", "ex": "LGBTQ+ rights can be framed as a culture clash."}, {"term": "Western values", "ipa": "/ˌwestən ˈvæljuːz/", "pron": "WES-tuhn VAL-yooz", "fr": "valeurs occidentales", "def": "Values associated, rightly or wrongly, with Western liberal societies.", "ex": "Some governments portray LGBTQ+ rights as foreign Western values."}, {"term": "universal rights", "ipa": "/ˌjuːnɪˈvɜːsəl raɪts/", "pron": "yoo-ni-VUR-suhl rites", "fr": "droits universels", "def": "Rights that apply to all people everywhere.", "ex": "Activists argue that LGBTQ+ rights are universal rights."}, {"term": "to protect LGBTQ+ rights", "ipa": "/prəˈtekt ˌel dʒiː biː tiː ˈkjuː plʌs raɪts/", "pron": "pruh-TEKT el-jee-bee-tee-KYOO-plus rites", "fr": "protéger les droits LGBTQ+", "def": "To defend legal and social protections for LGBTQ+ people.", "ex": "Courts and parliaments can protect LGBTQ+ rights."}, {"term": "to challenge homophobia", "ipa": "/ˈtʃælɪndʒ ˌhəʊməˈfəʊbiə/", "pron": "CHAL-inj hoh-muh-FOH-bee-uh", "fr": "combattre l’homophobie", "def": "To question and oppose anti-gay prejudice.", "ex": "Schools must challenge homophobia rather than ignore it."}, {"term": "to combat transphobia", "ipa": "/ˈkɒmbæt trænzˈfəʊbiə/", "pron": "KOM-bat tranz-FOH-bee-uh", "fr": "lutter contre la transphobie", "def": "To fight prejudice and discrimination against transgender people.", "ex": "Inclusive policies can combat transphobia."}, {"term": "to ban conversion therapy", "ipa": "/bæn kənˈvɜːʃən ˌθerəpi/", "pron": "ban kuhn-VUR-zhuhn THERR-uh-pee", "fr": "interdire les thérapies de conversion", "def": "To legally prohibit practices attempting to change LGBTQ+ identity.", "ex": "Many activists want governments to ban conversion therapy."}, {"term": "to legalise same-sex marriage", "ipa": "/ˈliːɡəlaɪz ˌseɪm seks ˈmærɪdʒ/", "pron": "LEE-guh-lyz same-seks MARR-ij", "fr": "légaliser le mariage homosexuel", "def": "To make marriage between same-sex couples legal.", "ex": "Several countries have legalised same-sex marriage since the 2000s."}, {"term": "to recognise diverse families", "ipa": "/ˈrekəɡnaɪz daɪˌvɜːs ˈfæməliz/", "pron": "REK-uhg-nyz dy-VURSS FAM-uh-leez", "fr": "reconnaître les familles diverses", "def": "To give legal and social recognition to different family forms.", "ex": "Law should recognise diverse families to protect children."}, {"term": "to respect pronouns", "ipa": "/rɪˈspekt ˈprəʊnaʊnz/", "pron": "ri-SPEKT PROH-nownz", "fr": "respecter les pronoms", "def": "To use the pronouns a person asks others to use.", "ex": "Respecting pronouns is a simple form of inclusion."}, {"term": "to create safe spaces", "ipa": "/kriˈeɪt ˈseɪf speɪsɪz/", "pron": "kree-AYT sayf SPAY-siz", "fr": "créer des espaces sûrs", "def": "To build environments where people are protected from hostility.", "ex": "Schools can create safe spaces for LGBTQ+ pupils."}, {"term": "to make schools inclusive", "ipa": "/meɪk skuːlz ɪnˈkluːsɪv/", "pron": "mayk schoolz in-KLOO-siv", "fr": "rendre les écoles inclusives", "def": "To ensure schools include and protect all pupils.", "ex": "LGBTQ+ education can make schools inclusive."}, {"term": "to face discrimination", "ipa": "/feɪs dɪˌskrɪmɪˈneɪʃən/", "pron": "fays dis-krim-i-NAY-shuhn", "fr": "subir une discrimination", "def": "To experience unfair treatment.", "ex": "Many LGBTQ+ people still face discrimination."}, {"term": "to seek asylum", "ipa": "/siːk əˈsaɪləm/", "pron": "seek uh-SY-luhm", "fr": "demander l’asile", "def": "To ask for protection in another country.", "ex": "Some LGBTQ+ people seek asylum to escape persecution."}, {"term": "to flee persecution", "ipa": "/fliː ˌpɜːsɪˈkjuːʃən/", "pron": "flee pur-si-KYOO-shuhn", "fr": "fuir la persécution", "def": "To escape mistreatment or danger because of identity or belief.", "ex": "LGBTQ+ refugees may flee persecution by families or states."}, {"term": "to balance rights", "ipa": "/ˈbæləns raɪts/", "pron": "BAL-uhns rites", "fr": "équilibrer les droits", "def": "To weigh different rights or freedoms against each other.", "ex": "Courts often balance rights in religious freedom and equality cases."}, {"term": "to fuel a moral panic", "ipa": "/ˈfjuːəl ə ˌmɒrəl ˈpænɪk/", "pron": "FYOO-uhl uh MOR-uhl PAN-ik", "fr": "alimenter une panique morale", "def": "To intensify exaggerated public fear.", "ex": "Politicians may fuel a moral panic about LGBTQ+ education."}, {"term": "to push back against backlash", "ipa": "/pʊʃ bæk əˌɡenst ˈbæklæʃ/", "pron": "push bak uh-GENST BAK-lash", "fr": "résister au retour de bâton", "def": "To resist a negative reaction against progress.", "ex": "Activists push back against backlash through courts and campaigns."}]}]}, {"id": "p4c39", "part": 4, "chapter": 39, "title": "Ageing Populations", "file": "cpge_vocab_part4_chapter39_ageing_populations_premium.html", "count": 159, "sections": [{"title": "A. Demography and population trends", "entries": [{"term": "ageing population", "ipa": "/ˌeɪdʒɪŋ ˌpɒpjʊˈleɪʃən/", "pron": "AY-jing pop-yuh-LAY-shuhn", "fr": "vieillissement de la population", "def": "A population in which the proportion of older people is increasing.", "ex": "An ageing population puts pressure on pensions, healthcare and public finances."}, {"term": "ageing society", "ipa": "/ˌeɪdʒɪŋ səˈsaɪəti/", "pron": "AY-jing suh-SY-uh-tee", "fr": "société vieillissante", "def": "A society where older adults represent a growing share of the population.", "ex": "Japan is often cited as an example of an ageing society."}, {"term": "demographic ageing", "ipa": "/ˌdeməɡræfɪk ˈeɪdʒɪŋ/", "pron": "dem-uh-GRAF-ik AY-jing", "fr": "vieillissement démographique", "def": "The process by which the average age of a population rises.", "ex": "Demographic ageing is caused by low fertility and longer life expectancy."}, {"term": "population ageing", "ipa": "/ˌpɒpjʊˈleɪʃən ˈeɪdʒɪŋ/", "pron": "pop-yuh-LAY-shuhn AY-jing", "fr": "vieillissement de la population", "def": "The increase in the number and share of older people in a population.", "ex": "Population ageing forces governments to rethink healthcare and work."}, {"term": "demographic transition", "ipa": "/ˌdeməɡræfɪk trænˈzɪʃən/", "pron": "dem-uh-GRAF-ik tran-ZISH-uhn", "fr": "transition démographique", "def": "The shift from high birth and death rates to low birth and death rates as societies develop.", "ex": "The demographic transition eventually leads to slower population growth."}, {"term": "demographic shift", "ipa": "/ˌdeməɡræfɪk ˈʃɪft/", "pron": "dem-uh-GRAF-ik shift", "fr": "changement démographique", "def": "A significant change in the structure of a population.", "ex": "The demographic shift towards older citizens affects voting patterns."}, {"term": "demographic change", "ipa": "/ˌdeməɡræfɪk ˈtʃeɪndʒ/", "pron": "dem-uh-GRAF-ik chaynj", "fr": "évolution démographique", "def": "Changes in population size, age, fertility, mortality or migration.", "ex": "Demographic change is reshaping labour markets."}, {"term": "population growth", "ipa": "/ˌpɒpjʊˈleɪʃən ɡrəʊθ/", "pron": "pop-yuh-LAY-shuhn growth", "fr": "croissance démographique", "def": "An increase in the number of people in a population.", "ex": "Some countries still experience rapid population growth."}, {"term": "population decline", "ipa": "/ˌpɒpjʊˈleɪʃən dɪˈklaɪn/", "pron": "pop-yuh-LAY-shuhn di-KLYNE", "fr": "déclin démographique", "def": "A decrease in the number of people in a population.", "ex": "Population decline can weaken rural areas and local economies."}, {"term": "population stagnation", "ipa": "/ˌpɒpjʊˈleɪʃən stæɡˈneɪʃən/", "pron": "pop-yuh-LAY-shuhn stag-NAY-shuhn", "fr": "stagnation démographique", "def": "A situation where the population stops growing significantly.", "ex": "Population stagnation can reduce economic dynamism."}, {"term": "shrinking population", "ipa": "/ˌʃrɪŋkɪŋ ˌpɒpjʊˈleɪʃən/", "pron": "SHRINK-ing pop-yuh-LAY-shuhn", "fr": "population en diminution", "def": "A population that is becoming smaller over time.", "ex": "A shrinking population may lead to school closures and labour shortages."}, {"term": "fertility rate", "ipa": "/fəˈtɪləti reɪt/", "pron": "fuh-TIL-uh-tee rayt", "fr": "taux de fécondité", "def": "The average number of children born to a woman during her lifetime.", "ex": "A low fertility rate accelerates population ageing."}, {"term": "birth rate", "ipa": "/ˈbɜːθ reɪt/", "pron": "birth rayt", "fr": "taux de natalité", "def": "The number of births in a population during a given period.", "ex": "Falling birth rates worry policymakers in ageing countries."}, {"term": "death rate", "ipa": "/ˈdeθ reɪt/", "pron": "death rayt", "fr": "taux de mortalité", "def": "The number of deaths in a population during a given period.", "ex": "Death rates rise when a population becomes older."}, {"term": "life expectancy", "ipa": "/ˈlaɪf ɪkˌspektənsi/", "pron": "life ik-SPEK-tuhn-see", "fr": "espérance de vie", "def": "The average number of years a person is expected to live.", "ex": "Rising life expectancy is one of the great achievements of modern societies."}, {"term": "healthy life expectancy", "ipa": "/ˌhelθi ˈlaɪf ɪkˌspektənsi/", "pron": "HEL-thee life ik-SPEK-tuhn-see", "fr": "espérance de vie en bonne santé", "def": "The average number of years a person can expect to live in good health.", "ex": "Healthy life expectancy matters as much as total life expectancy."}, {"term": "longevity", "ipa": "/lɒnˈdʒevəti/", "pron": "lon-JEV-uh-tee", "fr": "longévité", "def": "Long life or the tendency to live longer.", "ex": "Longevity creates opportunities as well as fiscal challenges."}, {"term": "centenarian", "ipa": "/ˌsentɪˈneəriən/", "pron": "sen-ti-NAIR-ee-uhn", "fr": "centenaire", "def": "A person who is at least 100 years old.", "ex": "The number of centenarians is rising in many countries."}, {"term": "supercentenarian", "ipa": "/ˌsuːpəˌsentɪˈneəriən/", "pron": "SOO-puh-sen-ti-NAIR-ee-uhn", "fr": "supercentenaire", "def": "A person who is at least 110 years old.", "ex": "Supercentenarians remain rare, but they fascinate demographers."}, {"term": "population pyramid", "ipa": "/ˌpɒpjʊˈleɪʃən ˈpɪrəmɪd/", "pron": "pop-yuh-LAY-shuhn PIR-uh-mid", "fr": "pyramide des âges", "def": "A chart showing the age and sex structure of a population.", "ex": "A narrow-based population pyramid reveals low fertility."}, {"term": "age structure", "ipa": "/ˈeɪdʒ ˌstrʌktʃə/", "pron": "ayj STRUK-chuh", "fr": "structure par âge", "def": "The distribution of people across age groups in a population.", "ex": "A country’s age structure affects schools, pensions and healthcare."}, {"term": "median age", "ipa": "/ˌmiːdiən ˈeɪdʒ/", "pron": "MEE-dee-uhn ayj", "fr": "âge médian", "def": "The age that divides a population into two equal halves.", "ex": "The median age has risen sharply in many developed countries."}, {"term": "replacement level fertility", "ipa": "/rɪˈpleɪsmənt ˌlevəl fəˈtɪləti/", "pron": "ri-PLAYS-muhnt LEV-uhl fuh-TIL-uh-tee", "fr": "seuil de renouvellement des générations", "def": "The fertility rate needed to keep a population stable without migration.", "ex": "Many countries are below replacement level fertility."}, {"term": "below-replacement fertility", "ipa": "/bɪˌləʊ rɪˈpleɪsmənt fəˈtɪləti/", "pron": "bi-LOH ri-PLAYS-muhnt fuh-TIL-uh-tee", "fr": "fécondité sous le seuil de renouvellement", "def": "A fertility rate too low to replace the population over time without migration.", "ex": "Below-replacement fertility is common in Europe and East Asia."}, {"term": "declining fertility", "ipa": "/dɪˌklaɪnɪŋ fəˈtɪləti/", "pron": "di-KLY-ning fuh-TIL-uh-tee", "fr": "baisse de la fécondité", "def": "A decrease in the average number of children people have.", "ex": "Declining fertility is linked to education, urbanisation and economic pressure."}]}, {"title": "B. Fertility, family policy and births", "entries": [{"term": "low fertility", "ipa": "/ˌləʊ fəˈtɪləti/", "pron": "loh fuh-TIL-uh-tee", "fr": "faible fécondité", "def": "A fertility rate that is too low to maintain population size without migration.", "ex": "Low fertility creates long-term pension challenges."}, {"term": "childlessness", "ipa": "/ˈtʃaɪldləsnəs/", "pron": "CHYLD-luhs-nuhs", "fr": "absence d’enfants", "def": "The state of not having children, whether by choice or circumstance.", "ex": "Rising childlessness reflects changing values and economic constraints."}, {"term": "delayed parenthood", "ipa": "/dɪˌleɪd ˈpeərənthʊd/", "pron": "di-LAYD PAIR-uhnt-hood", "fr": "parentalité tardive", "def": "Having children later in life.", "ex": "Delayed parenthood can reduce the total number of children people have."}, {"term": "late motherhood", "ipa": "/ˌleɪt ˈmʌðəhʊd/", "pron": "late MUTH-uh-hood", "fr": "maternité tardive", "def": "Becoming a mother later than previous generations typically did.", "ex": "Late motherhood is increasingly common in developed economies."}, {"term": "family planning", "ipa": "/ˌfæməli ˈplænɪŋ/", "pron": "FAM-uh-lee PLAN-ing", "fr": "planification familiale", "def": "Decisions and services related to when and how many children to have.", "ex": "Family planning has contributed to lower fertility rates."}, {"term": "reproductive choices", "ipa": "/ˌriːprəˈdʌktɪv ˈtʃɔɪsɪz/", "pron": "ree-pruh-DUK-tiv CHOY-siz", "fr": "choix reproductifs", "def": "Choices concerning contraception, pregnancy and childbirth.", "ex": "Reproductive choices are shaped by work, housing and gender equality."}, {"term": "pro-natalist policy", "ipa": "/ˌprəʊ ˈneɪtəlɪst ˈpɒləsi/", "pron": "proh-NAY-tuh-list POL-uh-see", "fr": "politique nataliste", "def": "A policy designed to encourage people to have more children.", "ex": "Pro-natalist policies may include childcare support and baby bonuses."}, {"term": "baby bonus", "ipa": "/ˈbeɪbi ˌbəʊnəs/", "pron": "BAY-bee BOH-nuhs", "fr": "prime à la naissance", "def": "A payment offered by the state to encourage childbirth.", "ex": "A baby bonus alone rarely reverses low fertility."}, {"term": "childcare support", "ipa": "/ˈtʃaɪldkeə səˌpɔːt/", "pron": "CHYLD-care suh-PORT", "fr": "aide à la garde d’enfants", "def": "Financial or practical help with looking after children.", "ex": "Childcare support can make it easier to combine work and family."}, {"term": "parental leave", "ipa": "/pəˌrentəl ˈliːv/", "pron": "puh-REN-tuhl leev", "fr": "congé parental", "def": "Time off work to care for a new child.", "ex": "Generous parental leave can support fertility and gender equality."}, {"term": "work-life balance", "ipa": "/ˌwɜːk laɪf ˈbæləns/", "pron": "work-life BAL-uhns", "fr": "équilibre vie professionnelle-vie personnelle", "def": "The balance between employment and personal or family life.", "ex": "Poor work-life balance discourages some people from having children."}, {"term": "cost of raising children", "ipa": "/ˌkɒst əv ˈreɪzɪŋ ˈtʃɪldrən/", "pron": "kost ov RAY-zing CHIL-druhn", "fr": "coût de l’éducation des enfants", "def": "The financial cost of bringing up children.", "ex": "The high cost of raising children contributes to low fertility."}, {"term": "housing affordability", "ipa": "/ˈhaʊzɪŋ əˌfɔːdəˈbɪləti/", "pron": "HOW-zing uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière du logement", "def": "The extent to which people can afford decent housing.", "ex": "Housing affordability strongly affects family formation."}, {"term": "fertility crisis", "ipa": "/fəˈtɪləti ˈkraɪsɪs/", "pron": "fuh-TIL-uh-tee KRY-sis", "fr": "crise de la fécondité", "def": "A situation where fertility falls so low that it threatens demographic stability.", "ex": "Some governments describe low birth rates as a fertility crisis."}, {"term": "demographic winter", "ipa": "/ˌdeməɡræfɪk ˈwɪntə/", "pron": "dem-uh-GRAF-ik WIN-tuh", "fr": "hiver démographique", "def": "A dramatic term for very low fertility and population ageing.", "ex": "Demographic winter is often used in conservative or alarmist rhetoric."}, {"term": "dependency ratio", "ipa": "/dɪˈpendənsi ˌreɪʃiəʊ/", "pron": "di-PEN-duhn-see RAY-shee-oh", "fr": "taux de dépendance", "def": "The ratio of dependants to working-age people.", "ex": "A rising dependency ratio puts pressure on workers and taxpayers."}, {"term": "old-age dependency ratio", "ipa": "/ˌəʊld eɪdʒ dɪˈpendənsi ˌreɪʃiəʊ/", "pron": "ohld-ayj di-PEN-duhn-see RAY-shee-oh", "fr": "taux de dépendance des personnes âgées", "def": "The ratio of older people to working-age people.", "ex": "The old-age dependency ratio is rising across Europe."}, {"term": "dependant", "ipa": "/dɪˈpendənt/", "pron": "di-PEN-duhnt", "fr": "personne dépendante", "def": "A person who relies on others for support, such as a child or elderly person.", "ex": "An ageing society has more elderly dependants."}]}, {"title": "C. Dependency, pensions and the welfare state", "entries": [{"term": "pensioner", "ipa": "/ˈpenʃənə/", "pron": "PEN-shuhn-uh", "fr": "retraité ; pensionné", "def": "A person receiving a pension, especially after retirement.", "ex": "Pensioners are an influential voting group."}, {"term": "retiree", "ipa": "/rɪˌtaɪəˈriː/", "pron": "ri-ty-uh-REE", "fr": "retraité", "def": "A person who has stopped working because of age.", "ex": "Retirees may still contribute through volunteering or family support."}, {"term": "retirement", "ipa": "/rɪˈtaɪəmənt/", "pron": "ri-TY-uh-muhnt", "fr": "retraite", "def": "The period after someone stops working, usually in later life.", "ex": "Longer retirement requires more savings and public funding."}, {"term": "retirement age", "ipa": "/rɪˈtaɪəmənt eɪdʒ/", "pron": "ri-TY-uh-muhnt ayj", "fr": "âge de départ à la retraite", "def": "The age at which people normally stop working and receive a pension.", "ex": "Raising the retirement age is politically sensitive."}, {"term": "state pension", "ipa": "/ˌsteɪt ˈpenʃən/", "pron": "state PEN-shuhn", "fr": "pension de retraite publique", "def": "A pension paid by the government.", "ex": "The state pension is a pillar of social protection."}, {"term": "private pension", "ipa": "/ˌpraɪvət ˈpenʃən/", "pron": "PRY-vuht PEN-shuhn", "fr": "retraite privée", "def": "A pension funded privately by individuals or employers.", "ex": "Private pensions depend on savings and investment returns."}, {"term": "pension system", "ipa": "/ˈpenʃən ˌsɪstəm/", "pron": "PEN-shuhn SIS-tuhm", "fr": "système de retraite", "def": "The rules and institutions that provide retirement income.", "ex": "Ageing populations threaten the sustainability of pension systems."}, {"term": "pension reform", "ipa": "/ˈpenʃən rɪˌfɔːm/", "pron": "PEN-shuhn ri-FORM", "fr": "réforme des retraites", "def": "Changes to pension rules, funding or retirement age.", "ex": "Pension reform often triggers protests."}, {"term": "pension fund", "ipa": "/ˈpenʃən fʌnd/", "pron": "PEN-shuhn fund", "fr": "fonds de pension", "def": "A fund that collects and invests money to pay pensions.", "ex": "Pension funds are major investors in financial markets."}, {"term": "pay-as-you-go pension", "ipa": "/ˌpeɪ əz juː ˈɡəʊ ˈpenʃən/", "pron": "pay-az-yoo-go PEN-shuhn", "fr": "retraite par répartition", "def": "A pension system where current workers fund current retirees.", "ex": "Pay-as-you-go pensions struggle when there are fewer workers per retiree."}, {"term": "funded pension scheme", "ipa": "/ˌfʌndɪd ˈpenʃən skiːm/", "pron": "FUN-did PEN-shuhn skeem", "fr": "retraite par capitalisation", "def": "A pension system based on accumulated savings and investment.", "ex": "Funded pension schemes are exposed to market risks."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system in which the state provides social protection such as healthcare, pensions and benefits.", "ex": "The welfare state must adapt to demographic ageing."}, {"term": "social security", "ipa": "/ˌsəʊʃəl sɪˈkjʊərəti/", "pron": "SOH-shuhl si-KYOOR-uh-tee", "fr": "sécurité sociale", "def": "Public systems providing income support, pensions and protection.", "ex": "Social security spending rises as populations age."}, {"term": "social protection", "ipa": "/ˌsəʊʃəl prəˈtekʃən/", "pron": "SOH-shuhl pruh-TEK-shuhn", "fr": "protection sociale", "def": "Policies protecting people from poverty, illness, unemployment or old age.", "ex": "Social protection is crucial in later life."}, {"term": "healthcare spending", "ipa": "/ˈhelθkeə ˈspendɪŋ/", "pron": "HELTH-care SPEN-ding", "fr": "dépenses de santé", "def": "Money spent on healthcare services.", "ex": "Healthcare spending tends to increase with age."}, {"term": "public expenditure", "ipa": "/ˌpʌblɪk ɪkˈspendɪtʃə/", "pron": "PUB-lik ik-SPEN-di-chuh", "fr": "dépenses publiques", "def": "Government spending on services, benefits and infrastructure.", "ex": "Ageing populations increase public expenditure."}, {"term": "fiscal burden", "ipa": "/ˌfɪskəl ˈbɜːdən/", "pron": "FIS-kuhl BUR-duhn", "fr": "charge budgétaire", "def": "Pressure on public finances caused by spending or debt.", "ex": "Pensions and healthcare can become a fiscal burden."}, {"term": "tax base", "ipa": "/ˈtæks beɪs/", "pron": "taks bays", "fr": "assiette fiscale", "def": "The total income, wealth or activity that can be taxed.", "ex": "A shrinking workforce can weaken the tax base."}, {"term": "intergenerational contract", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈkɒntrækt/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl KON-trakt", "fr": "contrat intergénérationnel", "def": "The implicit agreement that working generations support older generations.", "ex": "The intergenerational contract is strained when the population ages."}, {"term": "generational solidarity", "ipa": "/ˌdʒenəˈreɪʃənəl ˌsɒlɪˈdærəti/", "pron": "jen-uh-RAY-shuh-nuhl sol-i-DARR-uh-tee", "fr": "solidarité intergénérationnelle", "def": "Mutual support between generations.", "ex": "Generational solidarity is essential to sustain pensions."}, {"term": "public finances", "ipa": "/ˌpʌblɪk ˈfaɪnænsɪz/", "pron": "PUB-lik FY-nan-siz", "fr": "finances publiques", "def": "Government revenue, spending and debt.", "ex": "Ageing societies create long-term pressure on public finances."}, {"term": "long-term care", "ipa": "/ˌlɒŋ tɜːm ˈkeə/", "pron": "long-term care", "fr": "soins de longue durée ; dépendance", "def": "Ongoing support for people who cannot fully care for themselves.", "ex": "Long-term care is one of the biggest challenges of ageing."}, {"term": "nursing home", "ipa": "/ˈnɜːsɪŋ həʊm/", "pron": "NUR-sing hohm", "fr": "maison de retraite médicalisée", "def": "A residential facility providing medical and personal care.", "ex": "Nursing homes need trained staff and stable funding."}, {"term": "care home", "ipa": "/ˈkeə həʊm/", "pron": "care hohm", "fr": "maison de retraite ; établissement de soins", "def": "A residential facility where older or vulnerable people receive care.", "ex": "Care homes were heavily affected during the pandemic."}, {"term": "retirement home", "ipa": "/rɪˈtaɪəmənt həʊm/", "pron": "ri-TY-uh-muhnt hohm", "fr": "résidence pour personnes âgées", "def": "A residential setting for older people, often with support services.", "ex": "Some retirees choose retirement homes for security and community."}, {"term": "assisted living", "ipa": "/əˌsɪstɪd ˈlɪvɪŋ/", "pron": "uh-SIS-tid LIV-ing", "fr": "résidence avec services ; logement assisté", "def": "Housing with support for older or disabled people who need some help.", "ex": "Assisted living allows more independence than a nursing home."}, {"term": "home care", "ipa": "/ˈhəʊm keə/", "pron": "hohm care", "fr": "soins à domicile ; aide à domicile", "def": "Care provided in a person’s own home.", "ex": "Home care can help older people remain independent."}]}, {"title": "D. Healthcare, long-term care and later life", "entries": [{"term": "caregiver", "ipa": "/ˈkeəˌɡɪvə/", "pron": "CARE-giv-uh", "fr": "aidant ; soignant", "def": "A person who provides care to someone who is ill, disabled or elderly.", "ex": "Caregivers often face emotional and financial strain."}, {"term": "informal caregiver", "ipa": "/ɪnˌfɔːməl ˈkeəˌɡɪvə/", "pron": "in-FOR-muhl CARE-giv-uh", "fr": "aidant informel", "def": "An unpaid caregiver, often a family member or friend.", "ex": "Informal caregivers save public systems large amounts of money."}, {"term": "family caregiver", "ipa": "/ˌfæməli ˈkeəˌɡɪvə/", "pron": "FAM-uh-lee CARE-giv-uh", "fr": "aidant familial", "def": "A relative who provides care to an older, ill or disabled person.", "ex": "Family caregivers need respite and financial recognition."}, {"term": "respite care", "ipa": "/ˈrespaɪt keə/", "pron": "RESS-pyte care", "fr": "répit pour aidants", "def": "Temporary care that gives regular caregivers a break.", "ex": "Respite care helps prevent caregiver burnout."}, {"term": "caregiver burden", "ipa": "/ˈkeəˌɡɪvə ˈbɜːdən/", "pron": "CARE-giv-uh BUR-duhn", "fr": "charge de l’aidant", "def": "The physical, emotional or financial strain of caring for someone.", "ex": "Caregiver burden is often invisible."}, {"term": "dementia", "ipa": "/dɪˈmenʃə/", "pron": "di-MEN-shuh", "fr": "démence", "def": "A group of conditions involving decline in memory and thinking.", "ex": "Dementia cases increase as populations age."}, {"term": "Alzheimer’s disease", "ipa": "/ˈæltsˌhaɪməz dɪˌziːz/", "pron": "ALTS-hy-muhz di-ZEEZ", "fr": "maladie d’Alzheimer", "def": "A common form of dementia affecting memory and cognition.", "ex": "Alzheimer’s disease places great pressure on families."}, {"term": "frailty", "ipa": "/ˈfreɪlti/", "pron": "FRAYL-tee", "fr": "fragilité", "def": "Physical vulnerability and reduced resilience in older age.", "ex": "Frailty increases the risk of falls and hospitalisation."}, {"term": "chronic disease", "ipa": "/ˌkrɒnɪk dɪˈziːz/", "pron": "KRON-ik di-ZEEZ", "fr": "maladie chronique", "def": "A long-lasting disease that requires ongoing management.", "ex": "Chronic disease becomes more common with age."}, {"term": "age-related disease", "ipa": "/ˈeɪdʒ rɪˌleɪtɪd dɪˈziːz/", "pron": "ayj ri-LAY-tid di-ZEEZ", "fr": "maladie liée à l’âge", "def": "A disease more common in older age.", "ex": "Cancer and dementia are examples of age-related diseases."}, {"term": "healthy ageing", "ipa": "/ˌhelθi ˈeɪdʒɪŋ/", "pron": "HEL-thee AY-jing", "fr": "vieillissement en bonne santé", "def": "Ageing while maintaining physical, mental and social well-being.", "ex": "Healthy ageing should be a policy goal, not just longer life."}, {"term": "active ageing", "ipa": "/ˌæktɪv ˈeɪdʒɪŋ/", "pron": "AK-tiv AY-jing", "fr": "vieillissement actif", "def": "Older people remaining active, independent and socially engaged.", "ex": "Active ageing can reduce isolation and healthcare costs."}, {"term": "geriatric care", "ipa": "/ˌdʒeriˈætrɪk keə/", "pron": "jerr-ee-AT-rik care", "fr": "soins gériatriques", "def": "Medical care specialised for older adults.", "ex": "Geriatric care requires specific expertise."}, {"term": "elderly care", "ipa": "/ˈeldəli keə/", "pron": "EL-duh-lee care", "fr": "soins aux personnes âgées", "def": "Care and support for older people.", "ex": "Elderly care is often undervalued and understaffed."}, {"term": "palliative care", "ipa": "/ˈpæliətɪv keə/", "pron": "PAL-ee-uh-tiv care", "fr": "soins palliatifs", "def": "Care focused on comfort and quality of life for serious illness.", "ex": "Palliative care supports dignity at the end of life."}, {"term": "end-of-life care", "ipa": "/ˌend əv ˈlaɪf keə/", "pron": "end-ov-life care", "fr": "soins de fin de vie", "def": "Care provided to people near the end of life.", "ex": "End-of-life care raises ethical and emotional questions."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˌʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A lack of enough workers to fill available jobs.", "ex": "Ageing populations can create labour shortages."}, {"term": "workforce", "ipa": "/ˈwɜːkfɔːs/", "pron": "WURK-force", "fr": "population active ; main-d’œuvre", "def": "All people available for work in an economy or organisation.", "ex": "A shrinking workforce can slow economic growth."}, {"term": "labour force participation", "ipa": "/ˈleɪbə fɔːs pɑːˌtɪsɪˈpeɪʃən/", "pron": "LAY-buh force par-tis-i-PAY-shuhn", "fr": "taux d’activité", "def": "The share of people working or looking for work.", "ex": "Higher labour force participation among older workers can offset ageing."}, {"term": "ageing workforce", "ipa": "/ˌeɪdʒɪŋ ˈwɜːkfɔːs/", "pron": "AY-jing WURK-force", "fr": "main-d’œuvre vieillissante", "def": "A workforce with a rising average age.", "ex": "An ageing workforce requires workplace adaptation."}, {"term": "older workers", "ipa": "/ˌəʊldə ˈwɜːkəz/", "pron": "OHLD-uh WUR-kuhz", "fr": "travailleurs âgés ; seniors actifs", "def": "Workers in later stages of their career.", "ex": "Older workers may face age discrimination."}, {"term": "retirement wave", "ipa": "/rɪˈtaɪəmənt weɪv/", "pron": "ri-TY-uh-muhnt wayv", "fr": "vague de départs à la retraite", "def": "A large number of workers retiring around the same time.", "ex": "A retirement wave can create skills shortages."}, {"term": "silver economy", "ipa": "/ˈsɪlvər iˌkɒnəmi/", "pron": "SIL-vuh i-KON-uh-mee", "fr": "silver economy ; économie des seniors", "def": "Economic activity related to the needs and purchasing power of older people.", "ex": "The silver economy includes healthcare, housing, travel and technology."}, {"term": "economic productivity", "ipa": "/ˌiːkəˈnɒmɪk ˌprɒdʌkˈtɪvəti/", "pron": "ee-kuh-NOM-ik prod-uk-TIV-uh-tee", "fr": "productivité économique", "def": "Output produced by an economy in relation to labour or resources.", "ex": "Population ageing may affect economic productivity."}, {"term": "skills shortage", "ipa": "/ˈskɪlz ˌʃɔːtɪdʒ/", "pron": "skilz SHOR-tij", "fr": "pénurie de compétences", "def": "A lack of workers with the required skills.", "ex": "Retirements can worsen skills shortages in healthcare and engineering."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "Technology performing tasks previously done by humans.", "ex": "Automation may compensate for labour shortages."}, {"term": "robotics", "ipa": "/rəʊˈbɒtɪks/", "pron": "roh-BOT-iks", "fr": "robotique", "def": "The design and use of robots.", "ex": "Robotics can support care, mobility and manufacturing."}, {"term": "artificial intelligence", "ipa": "/ˌɑːtɪfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks requiring human intelligence.", "ex": "Artificial intelligence could help manage healthcare demand."}]}, {"title": "E. Labour market, technology and the silver economy", "entries": [{"term": "labour-saving technology", "ipa": "/ˈleɪbə ˌseɪvɪŋ tekˈnɒlədʒi/", "pron": "LAY-buh SAY-ving tek-NOL-uh-jee", "fr": "technologie économisant la main-d’œuvre", "def": "Technology that reduces the amount of human work needed.", "ex": "Labour-saving technology can mitigate workforce decline."}, {"term": "lifelong learning", "ipa": "/ˌlaɪflɒŋ ˈlɜːnɪŋ/", "pron": "life-long LUR-ning", "fr": "formation tout au long de la vie", "def": "Continuous education and skill development throughout life.", "ex": "Lifelong learning helps older workers stay employable."}, {"term": "retraining", "ipa": "/ˌriːˈtreɪnɪŋ/", "pron": "ree-TRAY-ning", "fr": "reconversion", "def": "Training people for a different job or sector.", "ex": "Retraining can help older workers adapt to technological change."}, {"term": "upskilling", "ipa": "/ˌʌpˈskɪlɪŋ/", "pron": "up-SKIL-ing", "fr": "montée en compétences", "def": "Training workers to improve or update their skills.", "ex": "Upskilling can extend working lives."}, {"term": "delayed retirement", "ipa": "/dɪˌleɪd rɪˈtaɪəmənt/", "pron": "di-LAYD ri-TY-uh-muhnt", "fr": "retraite retardée", "def": "Retiring later than usual or later than previous generations.", "ex": "Delayed retirement can support pension sustainability."}, {"term": "flexible retirement", "ipa": "/ˌfleksəbəl rɪˈtaɪəmənt/", "pron": "FLEK-suh-buhl ri-TY-uh-muhnt", "fr": "retraite flexible", "def": "A gradual or adaptable transition from work to retirement.", "ex": "Flexible retirement allows people to work part-time in later life."}, {"term": "ageism", "ipa": "/ˈeɪdʒɪzəm/", "pron": "AY-jiz-uhm", "fr": "âgisme", "def": "Prejudice or discrimination based on age.", "ex": "Ageism is one of the most overlooked forms of discrimination."}, {"term": "age discrimination", "ipa": "/ˈeɪdʒ dɪˌskrɪmɪˈneɪʃən/", "pron": "ayj dis-krim-i-NAY-shuhn", "fr": "discrimination liée à l’âge", "def": "Unfair treatment because of someone’s age.", "ex": "Age discrimination can affect hiring, healthcare and media representation."}, {"term": "elderly people", "ipa": "/ˈeldəli ˈpiːpəl/", "pron": "EL-duh-lee PEE-puhl", "fr": "personnes âgées", "def": "Older people, especially those in later old age.", "ex": "The phrase elderly people can sound respectful or slightly distant depending on context."}, {"term": "senior citizens", "ipa": "/ˌsiːniə ˈsɪtɪzənz/", "pron": "SEE-nee-uh SIT-i-zuhnz", "fr": "seniors ; personnes âgées", "def": "Older adults, especially retired people.", "ex": "Senior citizens often benefit from discounts and public services."}, {"term": "older adults", "ipa": "/ˌəʊldər əˈdʌlts/", "pron": "OHLD-uhr uh-DULTS", "fr": "personnes âgées ; adultes âgés", "def": "A neutral term for people in later adulthood.", "ex": "Older adults are a diverse group, not a single stereotype."}, {"term": "vulnerable population", "ipa": "/ˈvʌlnərəbəl ˌpɒpjʊˈleɪʃən/", "pron": "VUL-nuh-ruh-buhl pop-yuh-LAY-shuhn", "fr": "population vulnérable", "def": "A group at higher risk of harm or exclusion.", "ex": "Older adults living alone can be a vulnerable population."}, {"term": "social isolation", "ipa": "/ˌsəʊʃəl ˌaɪsəˈleɪʃən/", "pron": "SOH-shuhl eye-suh-LAY-shuhn", "fr": "isolement social", "def": "A lack of social contact or connection.", "ex": "Social isolation can damage physical and mental health."}, {"term": "loneliness", "ipa": "/ˈləʊnlinəs/", "pron": "LOHN-lee-nuhs", "fr": "solitude", "def": "A painful feeling of being alone or disconnected.", "ex": "Loneliness among older people is a major public health issue."}, {"term": "social exclusion", "ipa": "/ˌsəʊʃəl ɪkˈskluːʒən/", "pron": "SOH-shuhl ik-SKLOO-zhuhn", "fr": "exclusion sociale", "def": "Being cut off from opportunities, services or social participation.", "ex": "Digital services can worsen social exclusion for older adults."}, {"term": "intergenerational justice", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈdʒʌstɪs/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl JUS-tis", "fr": "justice intergénérationnelle", "def": "Fairness between generations in rights, duties and resources.", "ex": "Climate change and pensions both raise intergenerational justice issues."}, {"term": "intergenerational equity", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈekwəti/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl EK-wuh-tee", "fr": "équité intergénérationnelle", "def": "Fair distribution of costs and benefits between generations.", "ex": "Intergenerational equity is central to pension reform."}, {"term": "intergenerational conflict", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈkɒnflɪkt/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl KON-flikt", "fr": "conflit intergénérationnel", "def": "Tension between age groups over resources, values or power.", "ex": "Housing and pensions can fuel intergenerational conflict."}]}, {"title": "F. Society, generations and inclusion", "entries": [{"term": "generational divide", "ipa": "/ˌdʒenəˈreɪʃənəl dɪˈvaɪd/", "pron": "jen-uh-RAY-shuh-nuhl di-VYDE", "fr": "fracture générationnelle", "def": "A gap between generations in wealth, values or opportunities.", "ex": "The generational divide is visible in housing markets."}, {"term": "generation gap", "ipa": "/ˈdʒenəreɪʃən ɡæp/", "pron": "JEN-uh-ray-shuhn gap", "fr": "fossé générationnel", "def": "Differences in views, habits or experiences between age groups.", "ex": "Technology often widens the generation gap."}, {"term": "baby boomers", "ipa": "/ˈbeɪbi ˌbuːməz/", "pron": "BAY-bee BOO-muhz", "fr": "baby-boomers", "def": "People born during the post-war baby boom, often between 1946 and 1964.", "ex": "Baby boomers are often portrayed as wealthier than younger generations."}, {"term": "millennials", "ipa": "/mɪˈleniəlz/", "pron": "mi-LEN-ee-uhlz", "fr": "millennials ; génération Y", "def": "People born roughly between the early 1980s and mid-1990s.", "ex": "Millennials often face high housing costs and insecure work."}, {"term": "Generation Z", "ipa": "/ˌdʒenəreɪʃən ˈzed/", "pron": "JEN-uh-ray-shuhn zed", "fr": "génération Z", "def": "People born roughly from the late 1990s to early 2010s.", "ex": "Generation Z will inherit the long-term costs of ageing societies."}, {"term": "social cohesion", "ipa": "/ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "SOH-shuhl koh-HEE-zhuhn", "fr": "cohésion sociale", "def": "Trust and solidarity holding society together.", "ex": "Intergenerational solidarity strengthens social cohesion."}, {"term": "community support", "ipa": "/kəˌmjuːnəti səˈpɔːt/", "pron": "kuh-MYOO-nuh-tee suh-PORT", "fr": "soutien communautaire", "def": "Help provided by local networks, charities or neighbours.", "ex": "Community support can reduce loneliness among older adults."}, {"term": "age-friendly city", "ipa": "/ˈeɪdʒ ˌfrendli ˈsɪti/", "pron": "ayj-FREND-lee SIT-ee", "fr": "ville amie des aînés", "def": "A city designed to be accessible and supportive for older people.", "ex": "Age-friendly cities improve transport, housing and public space."}, {"term": "accessible housing", "ipa": "/əkˌsesəbəl ˈhaʊzɪŋ/", "pron": "ak-SES-uh-buhl HOW-zing", "fr": "logement accessible", "def": "Housing designed for people with mobility or disability needs.", "ex": "Accessible housing helps older adults remain independent."}, {"term": "universal design", "ipa": "/ˌjuːnɪˈvɜːsəl dɪˈzaɪn/", "pron": "yoo-ni-VUR-suhl di-ZYNE", "fr": "conception universelle", "def": "Design usable by people of all ages and abilities.", "ex": "Universal design benefits older people, disabled people and families."}, {"term": "digital exclusion", "ipa": "/ˌdɪdʒɪtəl ɪkˈskluːʒən/", "pron": "DIJ-i-tuhl ik-SKLOO-zhuhn", "fr": "exclusion numérique", "def": "Lack of access or ability to use digital tools and services.", "ex": "Digital exclusion affects older adults as services move online."}, {"term": "digital literacy", "ipa": "/ˌdɪdʒɪtəl ˈlɪtərəsi/", "pron": "DIJ-i-tuhl LIT-uh-ruh-see", "fr": "littératie numérique", "def": "The ability to use digital tools effectively.", "ex": "Digital literacy training can reduce isolation."}, {"term": "immigration", "ipa": "/ˌɪmɪˈɡreɪʃən/", "pron": "im-i-GRAY-shuhn", "fr": "immigration", "def": "The movement of people into a country to live there.", "ex": "Immigration is often presented as a partial answer to ageing."}, {"term": "migrant workforce", "ipa": "/ˈmaɪɡrənt ˈwɜːkfɔːs/", "pron": "MY-gruhnt WURK-force", "fr": "main-d’œuvre immigrée", "def": "Workers who have moved from another country.", "ex": "The migrant workforce is vital in care and healthcare."}, {"term": "skilled migration", "ipa": "/ˌskɪld maɪˈɡreɪʃən/", "pron": "skild my-GRAY-shuhn", "fr": "migration qualifiée", "def": "Migration by people with qualifications or specialised skills.", "ex": "Skilled migration can ease shortages in medicine and engineering."}, {"term": "labour migration", "ipa": "/ˈleɪbə maɪˌɡreɪʃən/", "pron": "LAY-buh my-GRAY-shuhn", "fr": "migration de travail", "def": "Migration for work.", "ex": "Labour migration can replenish shrinking workforces."}, {"term": "demographic solution", "ipa": "/ˌdeməɡræfɪk səˈluːʃən/", "pron": "dem-uh-GRAF-ik suh-LOO-shuhn", "fr": "solution démographique", "def": "A policy or trend that helps address population ageing or decline.", "ex": "Immigration is not a complete demographic solution."}, {"term": "population replacement", "ipa": "/ˌpɒpjʊˈleɪʃən rɪˈpleɪsmənt/", "pron": "pop-yuh-LAY-shuhn ri-PLAYS-muhnt", "fr": "remplacement démographique", "def": "The replacement of population decline through births or migration.", "ex": "The term population replacement can be misused in extremist rhetoric."}, {"term": "migration policy", "ipa": "/maɪˈɡreɪʃən ˈpɒləsi/", "pron": "my-GRAY-shuhn POL-uh-see", "fr": "politique migratoire", "def": "Government policy controlling migration flows and integration.", "ex": "Migration policy affects demographic sustainability."}, {"term": "selective immigration", "ipa": "/sɪˌlektɪv ˌɪmɪˈɡreɪʃən/", "pron": "si-LEK-tiv im-i-GRAY-shuhn", "fr": "immigration sélective", "def": "Immigration policy favouring certain skills or profiles.", "ex": "Selective immigration can target healthcare workers."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brayn drayn", "fr": "fuite des cerveaux", "def": "The emigration of skilled workers from one country to another.", "ex": "Rich ageing countries may worsen brain drain in poorer countries."}, {"term": "integration", "ipa": "/ˌɪntɪˈɡreɪʃən/", "pron": "in-ti-GRAY-shuhn", "fr": "intégration", "def": "The process by which migrants become part of society.", "ex": "Integration is essential if immigration is to support ageing societies."}, {"term": "economic contribution", "ipa": "/ˌiːkəˈnɒmɪk ˌkɒntrɪˈbjuːʃən/", "pron": "ee-kuh-NOM-ik kon-tri-BYOO-shuhn", "fr": "contribution économique", "def": "The value someone or a group adds to the economy.", "ex": "Migrants make an important economic contribution through work and taxes."}, {"term": "workforce replenishment", "ipa": "/ˈwɜːkfɔːs rɪˈplenɪʃmənt/", "pron": "WURK-force ri-PLEN-ish-muhnt", "fr": "renouvellement de la main-d’œuvre", "def": "The replacement or renewal of workers in the labour force.", "ex": "Workforce replenishment is difficult without births or migration."}, {"term": "demographic sustainability", "ipa": "/ˌdeməɡræfɪk səˌsteɪnəˈbɪləti/", "pron": "dem-uh-GRAF-ik suh-stay-nuh-BIL-uh-tee", "fr": "soutenabilité démographique", "def": "A population structure that can support long-term social and economic systems.", "ex": "Demographic sustainability requires workers, taxpayers and carers."}, {"term": "population renewal", "ipa": "/ˌpɒpjʊˈleɪʃən rɪˈnjuːəl/", "pron": "pop-yuh-LAY-shuhn ri-NYOO-uhl", "fr": "renouvellement de la population", "def": "The replenishment of a population through births or migration.", "ex": "Population renewal is central to long-term planning."}, {"term": "to raise the retirement age", "ipa": "/reɪz ðə rɪˈtaɪəmənt eɪdʒ/", "pron": "rayz thuh ri-TY-uh-muhnt ayj", "fr": "relever l’âge de la retraite", "def": "To increase the age at which people can retire or claim a pension.", "ex": "Governments often raise the retirement age to reduce pension costs."}, {"term": "to reform the pension system", "ipa": "/rɪˈfɔːm ðə ˈpenʃən ˌsɪstəm/", "pron": "ri-FORM thuh PEN-shuhn SIS-tuhm", "fr": "réformer le système de retraite", "def": "To change pension rules, funding or benefits.", "ex": "Ageing societies must reform the pension system carefully."}]}, {"title": "G. Immigration, solutions and high-value verbs", "entries": [{"term": "to address demographic decline", "ipa": "/əˈdres ˌdeməɡræfɪk dɪˈklaɪn/", "pron": "uh-DRESS dem-uh-GRAF-ik di-KLYNE", "fr": "faire face au déclin démographique", "def": "To deal with a falling or ageing population.", "ex": "Policy must address demographic decline without panic."}, {"term": "to tackle labour shortages", "ipa": "/ˈtækəl ˈleɪbə ˌʃɔːtɪdʒɪz/", "pron": "TAK-uhl LAY-buh SHOR-tij-iz", "fr": "lutter contre les pénuries de main-d’œuvre", "def": "To take action against a lack of workers.", "ex": "Immigration and automation can help tackle labour shortages."}, {"term": "to support families", "ipa": "/səˈpɔːt ˈfæməliz/", "pron": "suh-PORT FAM-uh-leez", "fr": "soutenir les familles", "def": "To help families financially, socially or through services.", "ex": "Affordable childcare can support families and fertility."}, {"term": "to encourage childbirth", "ipa": "/ɪnˈkʌrɪdʒ ˈtʃaɪldbɜːθ/", "pron": "in-KUR-ij CHYLD-birth", "fr": "encourager les naissances", "def": "To create conditions that make people more likely to have children.", "ex": "Cash payments alone rarely encourage childbirth."}, {"term": "to increase fertility rates", "ipa": "/ɪnˈkriːs fəˈtɪləti reɪts/", "pron": "in-KREESS fuh-TIL-uh-tee rayts", "fr": "augmenter les taux de fécondité", "def": "To raise the average number of children people have.", "ex": "Governments try to increase fertility rates through family policy."}, {"term": "to promote active ageing", "ipa": "/prəˈməʊt ˌæktɪv ˈeɪdʒɪŋ/", "pron": "pruh-MOHT AK-tiv AY-jing", "fr": "promouvoir le vieillissement actif", "def": "To encourage older people to remain active and engaged.", "ex": "Local councils can promote active ageing through sport and community programmes."}, {"term": "to reduce social isolation", "ipa": "/rɪˈdjuːs ˌsəʊʃəl ˌaɪsəˈleɪʃən/", "pron": "ri-DYOOSS SOH-shuhl eye-suh-LAY-shuhn", "fr": "réduire l’isolement social", "def": "To lessen loneliness and lack of social contact.", "ex": "Community projects can reduce social isolation."}, {"term": "to ensure intergenerational fairness", "ipa": "/ɪnˈʃɔː ˌɪntədʒenəˈreɪʃənəl ˈfeənəs/", "pron": "in-SHOR IN-tuh-jen-uh-RAY-shuh-nuhl FAIR-nuhs", "fr": "garantir l’équité intergénérationnelle", "def": "To make sure costs and benefits are fair between generations.", "ex": "Pension reform must ensure intergenerational fairness."}, {"term": "to strengthen healthcare systems", "ipa": "/ˈstreŋθən ˈhelθkeə ˌsɪstəmz/", "pron": "STRENG-thuhn HELTH-care SIS-tuhmz", "fr": "renforcer les systèmes de santé", "def": "To make healthcare systems more resilient and effective.", "ex": "Ageing populations require governments to strengthen healthcare systems."}, {"term": "to attract skilled migrants", "ipa": "/əˈtrækt skɪld ˈmaɪɡrənts/", "pron": "uh-TRAKT skild MY-gruhnts", "fr": "attirer des migrants qualifiés", "def": "To encourage qualified migrants to move to a country.", "ex": "Many countries compete to attract skilled migrants."}, {"term": "to offset population decline", "ipa": "/ˈɒfset ˌpɒpjʊˈleɪʃən dɪˈklaɪn/", "pron": "OF-set pop-yuh-LAY-shuhn di-KLYNE", "fr": "compenser le déclin démographique", "def": "To compensate for a shrinking population.", "ex": "Immigration can partly offset population decline."}, {"term": "to adapt to demographic change", "ipa": "/əˈdæpt tə ˌdeməɡræfɪk ˈtʃeɪndʒ/", "pron": "uh-DAPT tuh dem-uh-GRAF-ik chaynj", "fr": "s’adapter au changement démographique", "def": "To adjust policies, services and work to population changes.", "ex": "Societies must adapt to demographic change rather than deny it."}, {"term": "to sustain the welfare state", "ipa": "/səˈsteɪn ðə ˈwelfeə steɪt/", "pron": "suh-STAYN thuh WEL-fair state", "fr": "maintenir l’État-providence", "def": "To keep public social protection financially viable.", "ex": "A larger workforce helps sustain the welfare state."}, {"term": "to age healthily", "ipa": "/eɪdʒ ˈhelθɪli/", "pron": "ayj HEL-thi-lee", "fr": "vieillir en bonne santé", "def": "To grow older while maintaining good health and autonomy.", "ex": "The goal is not just to live longer, but to age healthily."}, {"term": "to live independently", "ipa": "/lɪv ˌɪndɪˈpendəntli/", "pron": "liv in-di-PEN-duhnt-lee", "fr": "vivre de manière autonome", "def": "To live without constant help from others.", "ex": "Accessible housing helps older people live independently."}]}]}, {"id": "p5c40", "part": 5, "chapter": 40, "title": "Economic Growth", "file": "cpge_vocab_part5_chapter40_economic_growth_premium.html", "count": 158, "sections": [{"title": "A. Core growth vocabulary and business cycles", "entries": [{"term": "economic growth", "ipa": "/ˌiːkəˈnɒmɪk ɡrəʊθ/", "pron": "ee-kuh-NOM-ik growth", "fr": "croissance économique", "def": "An increase in the production of goods and services in an economy.", "ex": "Economic growth is often used as a key measure of national success."}, {"term": "growth rate", "ipa": "/ˈɡrəʊθ reɪt/", "pron": "growth rayt", "fr": "taux de croissance", "def": "The speed at which an economy, output or indicator increases.", "ex": "A low growth rate can make debt harder to manage."}, {"term": "GDP", "ipa": "/ˌdʒiː diː ˈpiː/", "pron": "jee-dee-pee", "fr": "PIB", "def": "Gross Domestic Product: the total value of goods and services produced in a country.", "ex": "GDP is useful, but it does not measure well-being perfectly."}, {"term": "gross domestic product", "ipa": "/ˌɡrəʊs dəˌmestɪk ˈprɒdʌkt/", "pron": "grohss duh-MES-tik PROD-ukt", "fr": "produit intérieur brut", "def": "The total value of goods and services produced within a country.", "ex": "Gross domestic product can rise even when inequality worsens."}, {"term": "GDP per capita", "ipa": "/ˌdʒiː diː piː pə ˈkæpɪtə/", "pron": "jee-dee-pee puh KAP-i-tuh", "fr": "PIB par habitant", "def": "GDP divided by the population, used as an average income measure.", "ex": "GDP per capita is often used to compare living standards."}, {"term": "real GDP", "ipa": "/ˌrɪəl ˌdʒiː diː ˈpiː/", "pron": "REE-uhl jee-dee-pee", "fr": "PIB réel", "def": "GDP adjusted for inflation.", "ex": "Real GDP shows whether output has grown after inflation."}, {"term": "nominal GDP", "ipa": "/ˌnɒmɪnəl ˌdʒiː diː ˈpiː/", "pron": "NOM-i-nuhl jee-dee-pee", "fr": "PIB nominal", "def": "GDP measured in current prices, not adjusted for inflation.", "ex": "Nominal GDP can rise simply because prices rise."}, {"term": "potential growth", "ipa": "/pəˌtenʃəl ˈɡrəʊθ/", "pron": "puh-TEN-shuhl growth", "fr": "croissance potentielle", "def": "The maximum sustainable growth rate of an economy without creating inflation.", "ex": "Potential growth depends on labour, capital and productivity."}, {"term": "sustainable growth", "ipa": "/səˌsteɪnəbəl ˈɡrəʊθ/", "pron": "suh-STAY-nuh-buhl growth", "fr": "croissance durable", "def": "Growth that can continue without damaging the economy, society or environment.", "ex": "Sustainable growth should not destroy natural resources."}, {"term": "inclusive growth", "ipa": "/ɪnˌkluːsɪv ˈɡrəʊθ/", "pron": "in-KLOO-siv growth", "fr": "croissance inclusive", "def": "Growth that benefits a broad range of people, not only elites.", "ex": "Inclusive growth aims to reduce inequality while expanding the economy."}, {"term": "green growth", "ipa": "/ˌɡriːn ˈɡrəʊθ/", "pron": "green growth", "fr": "croissance verte", "def": "Economic growth that is compatible with environmental protection.", "ex": "Green growth promises prosperity without rising emissions."}, {"term": "low growth", "ipa": "/ˌləʊ ˈɡrəʊθ/", "pron": "loh growth", "fr": "faible croissance", "def": "A period when the economy expands slowly.", "ex": "Low growth can fuel political frustration."}, {"term": "slowdown", "ipa": "/ˈsləʊdaʊn/", "pron": "SLOH-down", "fr": "ralentissement", "def": "A reduction in the speed of economic activity or growth.", "ex": "A global slowdown can reduce exports and investment."}, {"term": "stagnation", "ipa": "/stæɡˈneɪʃən/", "pron": "stag-NAY-shuhn", "fr": "stagnation", "def": "A period of little or no economic growth.", "ex": "Stagnation can make voters lose trust in governments."}, {"term": "secular stagnation", "ipa": "/ˌsekjələ stæɡˈneɪʃən/", "pron": "SEK-yuh-luh stag-NAY-shuhn", "fr": "stagnation séculaire", "def": "A long-term period of weak growth, low investment and low interest rates.", "ex": "Secular stagnation is often linked to ageing and weak demand."}, {"term": "recession", "ipa": "/rɪˈseʃən/", "pron": "ri-SESH-uhn", "fr": "récession", "def": "A period of falling economic activity, often defined by falling GDP.", "ex": "A recession usually increases unemployment."}, {"term": "depression", "ipa": "/dɪˈpreʃən/", "pron": "di-PRESH-uhn", "fr": "dépression économique", "def": "A severe and prolonged economic downturn.", "ex": "The Great Depression transformed economic policy."}, {"term": "boom", "ipa": "/buːm/", "pron": "boom", "fr": "boom économique", "def": "A period of rapid economic growth.", "ex": "A boom can create jobs but also inflationary pressure."}, {"term": "bust", "ipa": "/bʌst/", "pron": "bust", "fr": "effondrement ; crise après un boom", "def": "A sudden economic downturn after a boom.", "ex": "A credit boom can be followed by a painful bust."}, {"term": "business cycle", "ipa": "/ˈbɪznəs ˌsaɪkəl/", "pron": "BIZ-nuhs SY-kuhl", "fr": "cycle économique", "def": "The repeated pattern of expansion and contraction in economic activity.", "ex": "The business cycle affects employment and investment."}, {"term": "economic expansion", "ipa": "/ˌiːkəˈnɒmɪk ɪkˈspænʃən/", "pron": "ee-kuh-NOM-ik ik-SPAN-shuhn", "fr": "expansion économique", "def": "A period when economic activity is increasing.", "ex": "Economic expansion can improve public finances."}, {"term": "economic downturn", "ipa": "/ˌiːkəˈnɒmɪk ˈdaʊntɜːn/", "pron": "ee-kuh-NOM-ik DOWN-turn", "fr": "ralentissement économique ; crise", "def": "A period of falling or weakening economic activity.", "ex": "An economic downturn hits vulnerable workers hardest."}, {"term": "output", "ipa": "/ˈaʊtpʊt/", "pron": "OWT-put", "fr": "production ; output", "def": "The amount of goods and services produced.", "ex": "Higher output can result from more workers or better productivity."}, {"term": "economic output", "ipa": "/ˌiːkəˈnɒmɪk ˈaʊtpʊt/", "pron": "ee-kuh-NOM-ik OWT-put", "fr": "production économique", "def": "The total production of an economy.", "ex": "Economic output fell sharply during the crisis."}, {"term": "productivity", "ipa": "/ˌprɒdʌkˈtɪvəti/", "pron": "prod-uk-TIV-uh-tee", "fr": "productivité", "def": "The amount produced per worker or per unit of input.", "ex": "Productivity growth is crucial for long-term prosperity."}]}, {"title": "B. Productivity, innovation, capital and infrastructure", "entries": [{"term": "labour productivity", "ipa": "/ˈleɪbə ˌprɒdʌkˈtɪvəti/", "pron": "LAY-buh prod-uk-TIV-uh-tee", "fr": "productivité du travail", "def": "Output produced per worker or per hour worked.", "ex": "Labour productivity rises when workers have better tools and skills."}, {"term": "total factor productivity", "ipa": "/ˌtəʊtəl ˈfæktə prɒdʌkˈtɪvəti/", "pron": "TOH-tuhl FAK-tuh prod-uk-TIV-uh-tee", "fr": "productivité globale des facteurs", "def": "Efficiency gains not explained simply by more labour or capital.", "ex": "Innovation can increase total factor productivity."}, {"term": "productivity gap", "ipa": "/ˌprɒdʌkˈtɪvəti ɡæp/", "pron": "prod-uk-TIV-uh-tee gap", "fr": "écart de productivité", "def": "A difference in productivity between countries, regions or firms.", "ex": "The productivity gap explains part of the income gap."}, {"term": "productivity puzzle", "ipa": "/ˌprɒdʌkˈtɪvəti ˈpʌzəl/", "pron": "prod-uk-TIV-uh-tee PUZ-uhl", "fr": "énigme de la productivité", "def": "The difficulty of explaining weak productivity despite technology or investment.", "ex": "The UK productivity puzzle has worried economists for years."}, {"term": "innovation", "ipa": "/ˌɪnəˈveɪʃən/", "pron": "in-uh-VAY-shuhn", "fr": "innovation", "def": "The creation and use of new ideas, products or methods.", "ex": "Innovation drives long-term economic growth."}, {"term": "technological progress", "ipa": "/ˌteknəˈlɒdʒɪkəl ˈprəʊɡres/", "pron": "tek-nuh-LOJ-i-kuhl PROH-gress", "fr": "progrès technologique", "def": "Improvement in technology that allows more efficient production.", "ex": "Technological progress can raise productivity but disrupt jobs."}, {"term": "research and development", "ipa": "/rɪˌsɜːtʃ ənd dɪˈveləpmənt/", "pron": "ri-SURCH and di-VEL-uhp-muhnt", "fr": "recherche et développement", "def": "Work aimed at creating new knowledge, products or technologies.", "ex": "Research and development is essential for innovation."}, {"term": "R&D", "ipa": "/ˌɑːr ən ˈdiː/", "pron": "ar-and-dee", "fr": "R&D ; recherche et développement", "def": "Abbreviation for research and development.", "ex": "R&D spending can support future growth."}, {"term": "capital", "ipa": "/ˈkæpɪtəl/", "pron": "KAP-i-tuhl", "fr": "capital", "def": "Resources used to produce goods and services, such as machines, buildings or money.", "ex": "Investment increases the stock of capital."}, {"term": "human capital", "ipa": "/ˌhjuːmən ˈkæpɪtəl/", "pron": "HYOO-muhn KAP-i-tuhl", "fr": "capital humain", "def": "The skills, education and health of workers.", "ex": "Education improves human capital and productivity."}, {"term": "physical capital", "ipa": "/ˌfɪzɪkəl ˈkæpɪtəl/", "pron": "FIZ-i-kuhl KAP-i-tuhl", "fr": "capital physique", "def": "Machines, buildings and equipment used in production.", "ex": "Physical capital helps workers produce more."}, {"term": "capital accumulation", "ipa": "/ˈkæpɪtəl əˌkjuːmjʊˈleɪʃən/", "pron": "KAP-i-tuhl uh-kyoo-myuh-LAY-shuhn", "fr": "accumulation du capital", "def": "The growth of capital stock through investment.", "ex": "Capital accumulation is a traditional driver of growth."}, {"term": "investment", "ipa": "/ɪnˈvestmənt/", "pron": "in-VEST-muhnt", "fr": "investissement", "def": "Spending on assets, equipment or projects expected to generate future value.", "ex": "Investment today can raise productivity tomorrow."}, {"term": "public investment", "ipa": "/ˌpʌblɪk ɪnˈvestmənt/", "pron": "PUB-lik in-VEST-muhnt", "fr": "investissement public", "def": "Government spending on infrastructure, education or long-term assets.", "ex": "Public investment can support growth in neglected regions."}, {"term": "private investment", "ipa": "/ˌpraɪvət ɪnˈvestmənt/", "pron": "PRY-vuht in-VEST-muhnt", "fr": "investissement privé", "def": "Investment made by businesses or individuals.", "ex": "Private investment depends on confidence and profitability."}, {"term": "foreign direct investment", "ipa": "/ˌfɒrən dəˌrekt ɪnˈvestmənt/", "pron": "FOR-uhn di-REKT in-VEST-muhnt", "fr": "investissement direct étranger", "def": "Investment by a foreign company in productive activity in another country.", "ex": "Foreign direct investment can bring capital and technology."}, {"term": "FDI", "ipa": "/ˌef diː ˈaɪ/", "pron": "eff-dee-eye", "fr": "IDE ; investissement direct étranger", "def": "Abbreviation for foreign direct investment.", "ex": "FDI can help emerging economies industrialise."}, {"term": "infrastructure", "ipa": "/ˈɪnfrəˌstrʌktʃə/", "pron": "IN-fruh-struk-chuh", "fr": "infrastructures", "def": "Basic systems such as transport, energy, water and digital networks.", "ex": "Poor infrastructure can limit economic growth."}, {"term": "transport infrastructure", "ipa": "/ˈtrænspɔːt ˌɪnfrəˌstrʌktʃə/", "pron": "TRAN-sport IN-fruh-struk-chuh", "fr": "infrastructures de transport", "def": "Roads, railways, ports and airports supporting movement.", "ex": "Transport infrastructure connects workers, firms and markets."}, {"term": "digital infrastructure", "ipa": "/ˌdɪdʒɪtəl ˈɪnfrəˌstrʌktʃə/", "pron": "DIJ-i-tuhl IN-fruh-struk-chuh", "fr": "infrastructure numérique", "def": "Internet, data and communication systems supporting the digital economy.", "ex": "Digital infrastructure is vital for modern growth."}, {"term": "energy infrastructure", "ipa": "/ˈenədʒi ˌɪnfrəˌstrʌktʃə/", "pron": "EN-uh-jee IN-fruh-struk-chuh", "fr": "infrastructures énergétiques", "def": "Systems for producing, transporting and distributing energy.", "ex": "Green growth requires major energy infrastructure investment."}, {"term": "industrialisation", "ipa": "/ɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "industrialisation", "def": "The development of manufacturing and industrial activity.", "ex": "Industrialisation transformed living standards in the nineteenth century."}, {"term": "deindustrialisation", "ipa": "/ˌdiːɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "dee-in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "désindustrialisation", "def": "The decline of manufacturing and industrial employment.", "ex": "Deindustrialisation can damage towns dependent on factories."}, {"term": "reindustrialisation", "ipa": "/ˌriːɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "ree-in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "réindustrialisation", "def": "The revival or rebuilding of industrial capacity.", "ex": "Reindustrialisation is linked to strategic autonomy and green industry."}, {"term": "manufacturing", "ipa": "/ˌmænjʊˈfæktʃərɪŋ/", "pron": "man-yuh-FAK-chuh-ring", "fr": "industrie manufacturière", "def": "The production of goods in factories.", "ex": "Manufacturing remains important for exports and productivity."}, {"term": "service economy", "ipa": "/ˈsɜːvɪs iˌkɒnəmi/", "pron": "SUR-vis i-KON-uh-mee", "fr": "économie de services", "def": "An economy dominated by services rather than manufacturing.", "ex": "Advanced economies are usually service economies."}]}, {"title": "C. Sectors, development and living standards", "entries": [{"term": "knowledge economy", "ipa": "/ˈnɒlɪdʒ iˌkɒnəmi/", "pron": "NOL-ij i-KON-uh-mee", "fr": "économie de la connaissance", "def": "An economy based on knowledge, technology and skilled labour.", "ex": "Universities play a key role in the knowledge economy."}, {"term": "digital economy", "ipa": "/ˌdɪdʒɪtəl iˈkɒnəmi/", "pron": "DIJ-i-tuhl i-KON-uh-mee", "fr": "économie numérique", "def": "Economic activity based on digital technologies and data.", "ex": "The digital economy creates growth but raises privacy concerns."}, {"term": "creative economy", "ipa": "/kriˌeɪtɪv iˈkɒnəmi/", "pron": "kree-AY-tiv i-KON-uh-mee", "fr": "économie créative", "def": "Economic activity based on culture, design, media and creativity.", "ex": "The creative economy can support urban regeneration."}, {"term": "green economy", "ipa": "/ˌɡriːn iˈkɒnəmi/", "pron": "green i-KON-uh-mee", "fr": "économie verte", "def": "An economy designed to reduce environmental risks and carbon emissions.", "ex": "The green economy can create new jobs in clean energy."}, {"term": "circular economy", "ipa": "/ˌsɜːkjələ iˈkɒnəmi/", "pron": "SUR-kyuh-luh i-KON-uh-mee", "fr": "économie circulaire", "def": "An economy that reuses, repairs and recycles resources to reduce waste.", "ex": "A circular economy reduces dependence on raw materials."}, {"term": "informal economy", "ipa": "/ɪnˌfɔːməl iˈkɒnəmi/", "pron": "in-FOR-muhl i-KON-uh-mee", "fr": "économie informelle", "def": "Economic activity not fully regulated or taxed by the state.", "ex": "The informal economy provides income but little protection."}, {"term": "underground economy", "ipa": "/ˌʌndəɡraʊnd iˈkɒnəmi/", "pron": "UN-duh-ground i-KON-uh-mee", "fr": "économie souterraine", "def": "Hidden or illegal economic activity outside official statistics.", "ex": "The underground economy reduces tax revenue."}, {"term": "emerging economy", "ipa": "/ɪˈmɜːdʒɪŋ iˌkɒnəmi/", "pron": "i-MUR-jing i-KON-uh-mee", "fr": "économie émergente", "def": "A developing economy becoming more integrated into global markets.", "ex": "Emerging economies can grow quickly but remain vulnerable."}, {"term": "developed economy", "ipa": "/dɪˌveləpt iˈkɒnəmi/", "pron": "di-VEL-uhpt i-KON-uh-mee", "fr": "économie développée", "def": "A wealthy, industrialised economy with advanced infrastructure and institutions.", "ex": "Developed economies often face slow growth and ageing populations."}, {"term": "developing economy", "ipa": "/dɪˌveləpɪŋ iˈkɒnəmi/", "pron": "di-VEL-uh-ping i-KON-uh-mee", "fr": "économie en développement", "def": "An economy with lower income levels and ongoing industrial or institutional development.", "ex": "Developing economies need investment in education and infrastructure."}, {"term": "low-income country", "ipa": "/ˌləʊ ˈɪnkʌm ˈkʌntri/", "pron": "loh IN-kum KUN-tree", "fr": "pays à faible revenu", "def": "A country with a low average income level.", "ex": "Low-income countries often lack infrastructure and capital."}, {"term": "middle-income country", "ipa": "/ˌmɪdəl ˈɪnkʌm ˈkʌntri/", "pron": "MID-uhl IN-kum KUN-tree", "fr": "pays à revenu intermédiaire", "def": "A country with an intermediate average income level.", "ex": "Middle-income countries may struggle to move into high-tech sectors."}, {"term": "high-income country", "ipa": "/ˌhaɪ ˈɪnkʌm ˈkʌntri/", "pron": "hy IN-kum KUN-tree", "fr": "pays à revenu élevé", "def": "A wealthy country with a high average income level.", "ex": "High-income countries often shift towards services and innovation."}, {"term": "middle-income trap", "ipa": "/ˌmɪdəl ˈɪnkʌm træp/", "pron": "MID-uhl IN-kum trap", "fr": "piège du revenu intermédiaire", "def": "A situation where a country struggles to move from middle-income to high-income status.", "ex": "Escaping the middle-income trap requires innovation and better institutions."}, {"term": "economic development", "ipa": "/ˌiːkəˈnɒmɪk dɪˈveləpmənt/", "pron": "ee-kuh-NOM-ik di-VEL-uhp-muhnt", "fr": "développement économique", "def": "Long-term improvement in income, living standards and institutions.", "ex": "Economic development is broader than GDP growth."}, {"term": "development", "ipa": "/dɪˈveləpmənt/", "pron": "di-VEL-uhp-muhnt", "fr": "développement", "def": "The process of improving economic and social conditions.", "ex": "Development includes health, education and political stability."}, {"term": "human development", "ipa": "/ˌhjuːmən dɪˈveləpmənt/", "pron": "HYOO-muhn di-VEL-uhp-muhnt", "fr": "développement humain", "def": "Development measured through health, education and living standards.", "ex": "Human development focuses on people’s capabilities."}, {"term": "human development index", "ipa": "/ˌhjuːmən dɪˈveləpmənt ˈɪndeks/", "pron": "HYOO-muhn di-VEL-uhp-muhnt IN-deks", "fr": "indice de développement humain", "def": "A measure combining life expectancy, education and income.", "ex": "The Human Development Index gives a broader view than GDP."}, {"term": "HDI", "ipa": "/ˌeɪtʃ diː ˈaɪ/", "pron": "aych-dee-eye", "fr": "IDH", "def": "Abbreviation for Human Development Index.", "ex": "HDI rankings highlight differences in life chances."}, {"term": "living standards", "ipa": "/ˈlɪvɪŋ ˌstændədz/", "pron": "LIV-ing STAN-duhdz", "fr": "niveau de vie", "def": "The material conditions in which people live.", "ex": "Growth should improve living standards, not just statistics."}, {"term": "standard of living", "ipa": "/ˌstændəd əv ˈlɪvɪŋ/", "pron": "STAN-duhd ov LIV-ing", "fr": "niveau de vie", "def": "The level of comfort and material well-being available to people.", "ex": "A higher standard of living usually requires rising productivity."}, {"term": "prosperity", "ipa": "/prɒˈsperəti/", "pron": "pros-PERR-uh-tee", "fr": "prospérité", "def": "Economic success, wealth and well-being.", "ex": "Prosperity should be broadly shared."}, {"term": "well-being", "ipa": "/ˌwel ˈbiːɪŋ/", "pron": "wel-BEE-ing", "fr": "bien-être", "def": "People’s health, happiness and quality of life.", "ex": "Well-being can improve even when GDP grows slowly."}, {"term": "quality of life", "ipa": "/ˌkwɒləti əv ˈlaɪf/", "pron": "KWOL-uh-tee ov life", "fr": "qualité de vie", "def": "The general level of health, comfort and happiness in life.", "ex": "Quality of life depends on housing, work, environment and health."}, {"term": "poverty reduction", "ipa": "/ˈpɒvəti rɪˌdʌkʃən/", "pron": "POV-uh-tee ri-DUK-shuhn", "fr": "réduction de la pauvreté", "def": "The process of reducing the number or share of people living in poverty.", "ex": "Growth can support poverty reduction if it creates decent jobs."}, {"term": "income growth", "ipa": "/ˈɪnkʌm ɡrəʊθ/", "pron": "IN-kum growth", "fr": "croissance des revenus", "def": "An increase in people’s incomes.", "ex": "Income growth has been uneven across social groups."}, {"term": "wage growth", "ipa": "/ˈweɪdʒ ɡrəʊθ/", "pron": "wayj growth", "fr": "croissance des salaires", "def": "An increase in wages over time.", "ex": "Weak wage growth fuels frustration despite GDP gains."}, {"term": "real wage growth", "ipa": "/ˌrɪəl ˈweɪdʒ ɡrəʊθ/", "pron": "REE-uhl wayj growth", "fr": "croissance des salaires réels", "def": "Wage growth adjusted for inflation.", "ex": "Real wage growth determines purchasing power."}, {"term": "purchasing power", "ipa": "/ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "PUR-chuh-sing POW-uh", "fr": "pouvoir d’achat", "def": "The amount of goods and services money can buy.", "ex": "Inflation reduces purchasing power."}, {"term": "aggregate demand", "ipa": "/ˌæɡrɪɡət dɪˈmɑːnd/", "pron": "AG-ri-guht di-MAND", "fr": "demande globale", "def": "Total demand for goods and services in an economy.", "ex": "Weak aggregate demand can slow growth."}, {"term": "consumer spending", "ipa": "/kənˌsjuːmə ˈspendɪŋ/", "pron": "kuhn-SYOO-muh SPEN-ding", "fr": "dépenses de consommation", "def": "Money spent by households on goods and services.", "ex": "Consumer spending is a major driver of growth."}]}, {"title": "D. Demand, confidence, finance and macroeconomic policy", "entries": [{"term": "household consumption", "ipa": "/ˌhaʊshəʊld kənˈsʌmpʃən/", "pron": "HOWSS-hohld kuhn-SUMP-shuhn", "fr": "consommation des ménages", "def": "Spending by households on goods and services.", "ex": "Household consumption falls when confidence declines."}, {"term": "consumer confidence", "ipa": "/kənˌsjuːmə ˈkɒnfɪdəns/", "pron": "kuhn-SYOO-muh KON-fi-duhns", "fr": "confiance des consommateurs", "def": "How optimistic consumers feel about the economy and their finances.", "ex": "Consumer confidence affects spending and investment."}, {"term": "business confidence", "ipa": "/ˈbɪznəs ˈkɒnfɪdəns/", "pron": "BIZ-nuhs KON-fi-duhns", "fr": "confiance des entreprises", "def": "How optimistic firms feel about future economic conditions.", "ex": "Business confidence encourages hiring and investment."}, {"term": "animal spirits", "ipa": "/ˌænɪməl ˈspɪrɪts/", "pron": "AN-i-muhl SPIR-its", "fr": "esprits animaux ; confiance économique", "def": "Keynes’s term for confidence and emotions driving investment decisions.", "ex": "Animal spirits can influence booms and downturns."}, {"term": "savings rate", "ipa": "/ˈseɪvɪŋz reɪt/", "pron": "SAY-vingz rayt", "fr": "taux d’épargne", "def": "The share of income that households save.", "ex": "A high savings rate can finance investment but reduce short-term demand."}, {"term": "consumption-led growth", "ipa": "/kənˈsʌmpʃən led ɡrəʊθ/", "pron": "kuhn-SUMP-shuhn-led growth", "fr": "croissance tirée par la consommation", "def": "Growth driven mainly by household spending.", "ex": "Consumption-led growth may depend on debt."}, {"term": "investment-led growth", "ipa": "/ɪnˈvestmənt led ɡrəʊθ/", "pron": "in-VEST-muhnt-led growth", "fr": "croissance tirée par l’investissement", "def": "Growth driven mainly by investment.", "ex": "Investment-led growth can expand productive capacity."}, {"term": "export-led growth", "ipa": "/ˈekspɔːt led ɡrəʊθ/", "pron": "EK-sport-led growth", "fr": "croissance tirée par les exportations", "def": "Growth driven by selling goods and services abroad.", "ex": "Export-led growth helped several Asian economies industrialise."}, {"term": "credit", "ipa": "/ˈkredɪt/", "pron": "KRED-it", "fr": "crédit", "def": "Borrowed money used by households, firms or governments.", "ex": "Credit can support growth but create financial risk."}, {"term": "debt-fuelled growth", "ipa": "/ˈdet ˌfjuːəld ɡrəʊθ/", "pron": "det-FYOO-uhld growth", "fr": "croissance alimentée par la dette", "def": "Growth driven by rising borrowing rather than productivity or income.", "ex": "Debt-fuelled growth can be unstable."}, {"term": "financial stability", "ipa": "/faɪˌnænʃəl stəˈbɪləti/", "pron": "fy-NAN-shuhl stuh-BIL-uh-tee", "fr": "stabilité financière", "def": "A condition where the financial system can function without crisis.", "ex": "Financial stability is necessary for sustainable growth."}, {"term": "macroeconomic stability", "ipa": "/ˌmækrəʊiːkəˈnɒmɪk stəˈbɪləti/", "pron": "MAK-roh-ee-kuh-NOM-ik stuh-BIL-uh-tee", "fr": "stabilité macroéconomique", "def": "Stable inflation, employment, growth and public finances.", "ex": "Macroeconomic stability supports investment."}, {"term": "inflation", "ipa": "/ɪnˈfleɪʃən/", "pron": "in-FLAY-shuhn", "fr": "inflation", "def": "A general rise in prices.", "ex": "High inflation can undermine growth and purchasing power."}, {"term": "deflation", "ipa": "/diːˈfleɪʃən/", "pron": "dee-FLAY-shuhn", "fr": "déflation", "def": "A general fall in prices.", "ex": "Deflation can discourage spending and investment."}, {"term": "interest rate", "ipa": "/ˈɪntrəst reɪt/", "pron": "IN-truhst rayt", "fr": "taux d’intérêt", "def": "The cost of borrowing money, expressed as a percentage.", "ex": "Higher interest rates can slow growth."}, {"term": "monetary policy", "ipa": "/ˈmʌnɪtəri ˈpɒləsi/", "pron": "MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire", "def": "Central bank policy affecting interest rates and money supply.", "ex": "Monetary policy can support growth during downturns."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on taxation and spending.", "ex": "Fiscal policy can stimulate demand during a recession."}, {"term": "stimulus", "ipa": "/ˈstɪmjʊləs/", "pron": "STIM-yuh-luhs", "fr": "relance ; stimulus", "def": "Government or central bank action designed to boost economic activity.", "ex": "A stimulus package can support growth after a crisis."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies aimed at reducing public spending or deficits.", "ex": "Austerity can weaken demand and public services."}, {"term": "public debt", "ipa": "/ˌpʌblɪk ˈdet/", "pron": "PUB-lik det", "fr": "dette publique", "def": "Money owed by the government.", "ex": "Public debt is easier to manage when growth is strong."}, {"term": "budget deficit", "ipa": "/ˌbʌdʒɪt ˈdefɪsɪt/", "pron": "BUJ-it DEF-i-sit", "fr": "déficit budgétaire", "def": "When government spending exceeds revenue.", "ex": "A budget deficit can rise during a recession."}, {"term": "fiscal sustainability", "ipa": "/ˌfɪskəl səˌsteɪnəˈbɪləti/", "pron": "FIS-kuhl suh-stay-nuh-BIL-uh-tee", "fr": "soutenabilité budgétaire", "def": "The ability to maintain public finances over time.", "ex": "Growth improves fiscal sustainability by raising tax revenue."}, {"term": "tax revenue", "ipa": "/ˈtæks ˌrevənjuː/", "pron": "taks REV-uhn-yoo", "fr": "recettes fiscales", "def": "Money collected by the state through taxes.", "ex": "Higher growth can increase tax revenue."}, {"term": "supply-side policy", "ipa": "/səˈplaɪ saɪd ˈpɒləsi/", "pron": "suh-PLY-side POL-uh-see", "fr": "politique de l’offre", "def": "Policy aimed at improving productive capacity and efficiency.", "ex": "Supply-side policy includes education, infrastructure and deregulation."}, {"term": "deregulation", "ipa": "/ˌdiːreɡjʊˈleɪʃən/", "pron": "dee-reg-yuh-LAY-shuhn", "fr": "déréglementation", "def": "Reducing government rules on businesses or markets.", "ex": "Deregulation can boost business activity but increase risks."}, {"term": "red tape", "ipa": "/ˌred ˈteɪp/", "pron": "red tape", "fr": "lourdeurs administratives", "def": "Excessive bureaucracy or paperwork.", "ex": "Cutting red tape is often presented as pro-growth."}, {"term": "entrepreneurship", "ipa": "/ˌɒntrəprəˈnɜːʃɪp/", "pron": "on-truh-pruh-NUR-ship", "fr": "entrepreneuriat", "def": "The activity of starting and running businesses.", "ex": "Entrepreneurship can create jobs and innovation."}, {"term": "start-up", "ipa": "/ˈstɑːt ʌp/", "pron": "START-up", "fr": "start-up ; jeune pousse", "def": "A newly created business, often innovative and high-growth.", "ex": "Start-ups can disrupt established industries."}, {"term": "small and medium-sized enterprises", "ipa": "/ˌsmɔːl ənd ˌmiːdiəm saɪzd ˈentəpraɪzɪz/", "pron": "small and MEE-dee-uhm-sized EN-tuh-pry-ziz", "fr": "PME", "def": "Businesses that are not large corporations.", "ex": "Small and medium-sized enterprises create many jobs."}, {"term": "SMEs", "ipa": "/ˌes em ˈiːz/", "pron": "ess-em-eez", "fr": "PME", "def": "Abbreviation for small and medium-sized enterprises.", "ex": "SMEs often struggle to access finance."}, {"term": "competition", "ipa": "/ˌkɒmpəˈtɪʃən/", "pron": "kom-puh-TISH-uhn", "fr": "concurrence", "def": "Rivalry between firms or economies.", "ex": "Competition can lower prices and encourage innovation."}, {"term": "competitiveness", "ipa": "/kəmˈpetətɪvnəs/", "pron": "kuhm-PET-uh-tiv-nuhs", "fr": "compétitivité", "def": "The ability to compete successfully in markets.", "ex": "Competitiveness depends on skills, infrastructure and innovation."}, {"term": "market economy", "ipa": "/ˌmɑːkɪt iˈkɒnəmi/", "pron": "MAR-kit i-KON-uh-mee", "fr": "économie de marché", "def": "An economy where prices and production are largely determined by markets.", "ex": "A market economy relies on competition and private initiative."}]}, {"title": "E. Markets, inequality, green growth and high-value verbs", "entries": [{"term": "free market", "ipa": "/ˌfriː ˈmɑːkɪt/", "pron": "free MAR-kit", "fr": "libre marché", "def": "An economic system with limited government intervention.", "ex": "Free-market advocates argue that competition creates growth."}, {"term": "industrial policy", "ipa": "/ɪnˈdʌstriəl ˈpɒləsi/", "pron": "in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle", "def": "Government strategy to support selected sectors or industries.", "ex": "Industrial policy has returned in debates about green growth."}, {"term": "green industrial policy", "ipa": "/ˌɡriːn ɪnˈdʌstriəl ˈpɒləsi/", "pron": "green in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle verte", "def": "Industrial policy designed to support low-carbon industries.", "ex": "Green industrial policy can create jobs and reduce emissions."}, {"term": "pro-growth policy", "ipa": "/ˌprəʊ ˈɡrəʊθ ˈpɒləsi/", "pron": "proh-growth POL-uh-see", "fr": "politique favorable à la croissance", "def": "A policy designed to encourage economic expansion.", "ex": "Tax cuts are often presented as pro-growth policy."}, {"term": "trickle-down economics", "ipa": "/ˌtrɪkəl daʊn iːkəˈnɒmɪks/", "pron": "TRIK-uhl-down ee-kuh-NOM-iks", "fr": "théorie du ruissellement", "def": "The belief that benefits for the wealthy or firms will eventually help everyone.", "ex": "Trickle-down economics is widely criticised by opponents of inequality."}, {"term": "laissez-faire", "ipa": "/ˌleseɪ ˈfeə/", "pron": "less-ay FAIR", "fr": "laissez-faire", "def": "An approach favouring minimal government intervention in the economy.", "ex": "Laissez-faire policies trust markets to allocate resources efficiently."}, {"term": "state intervention", "ipa": "/ˌsteɪt ˌɪntəˈvenʃən/", "pron": "state in-tuh-VEN-shuhn", "fr": "intervention de l’État", "def": "Government action in the economy.", "ex": "State intervention can correct market failures."}, {"term": "market failure", "ipa": "/ˌmɑːkɪt ˈfeɪljə/", "pron": "MAR-kit FAIL-yuh", "fr": "défaillance du marché", "def": "A situation where markets do not allocate resources efficiently or fairly.", "ex": "Pollution is a classic example of market failure."}, {"term": "externality", "ipa": "/ˌekstɜːˈnæləti/", "pron": "ek-stur-NAL-uh-tee", "fr": "externalité", "def": "A cost or benefit affecting people not directly involved in an economic activity.", "ex": "Carbon emissions are a negative externality."}, {"term": "inequality", "ipa": "/ˌɪnɪˈkwɒləti/", "pron": "in-i-KWOL-uh-tee", "fr": "inégalité", "def": "Unequal distribution of resources, income or opportunities.", "ex": "Growth can coexist with rising inequality."}, {"term": "income inequality", "ipa": "/ˈɪnkʌm ˌɪnɪˈkwɒləti/", "pron": "IN-kum in-i-KWOL-uh-tee", "fr": "inégalité des revenus", "def": "Unequal distribution of income across society.", "ex": "Income inequality can weaken social cohesion."}, {"term": "wealth inequality", "ipa": "/ˈwelθ ˌɪnɪˈkwɒləti/", "pron": "welth in-i-KWOL-uh-tee", "fr": "inégalité patrimoniale", "def": "Unequal distribution of assets such as housing and savings.", "ex": "Wealth inequality often grows when asset prices rise."}, {"term": "regional inequality", "ipa": "/ˈriːdʒənəl ˌɪnɪˈkwɒləti/", "pron": "REE-juh-nuhl in-i-KWOL-uh-tee", "fr": "inégalité régionale", "def": "Economic gaps between regions.", "ex": "Regional inequality has fuelled political discontent."}, {"term": "left-behind areas", "ipa": "/ˌleft bɪˈhaɪnd ˈeəriəz/", "pron": "left-bi-HYND AIR-ee-uhz", "fr": "territoires laissés pour compte", "def": "Places that have not benefited from growth or globalisation.", "ex": "Left-behind areas often suffer from poor infrastructure."}, {"term": "levelling up", "ipa": "/ˌlevəlɪŋ ˈʌp/", "pron": "LEV-uh-ling up", "fr": "rééquilibrage territorial ; levelling up", "def": "UK phrase for reducing regional inequality and improving neglected areas.", "ex": "Levelling up requires investment in skills and transport."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes or income groups.", "ex": "Growth alone does not guarantee social mobility."}, {"term": "redistribution", "ipa": "/ˌriːdɪstrɪˈbjuːʃən/", "pron": "ree-dis-tri-BYOO-shuhn", "fr": "redistribution", "def": "The transfer of resources through taxes, benefits or public services.", "ex": "Redistribution can make growth more inclusive."}, {"term": "climate change", "ipa": "/ˈklaɪmət tʃeɪndʒ/", "pron": "KLY-muht chaynj", "fr": "changement climatique", "def": "Long-term changes in climate largely caused by human activity.", "ex": "Climate change challenges traditional growth models."}, {"term": "carbon emissions", "ipa": "/ˌkɑːbən ɪˈmɪʃənz/", "pron": "KAR-buhn i-MISH-uhnz", "fr": "émissions de carbone", "def": "Greenhouse gases released into the atmosphere, especially carbon dioxide.", "ex": "Growth based on fossil fuels increases carbon emissions."}, {"term": "decoupling", "ipa": "/ˌdiːˈkʌplɪŋ/", "pron": "dee-KUP-ling", "fr": "découplage", "def": "Separating economic growth from environmental damage or emissions.", "ex": "Green growth depends on decoupling GDP from emissions."}, {"term": "absolute decoupling", "ipa": "/ˌæbsəluːt ˌdiːˈkʌplɪŋ/", "pron": "AB-suh-loot dee-KUP-ling", "fr": "découplage absolu", "def": "When emissions fall while the economy grows.", "ex": "Absolute decoupling is essential for climate targets."}, {"term": "relative decoupling", "ipa": "/ˌrelətɪv ˌdiːˈkʌplɪŋ/", "pron": "REL-uh-tiv dee-KUP-ling", "fr": "découplage relatif", "def": "When emissions grow more slowly than the economy.", "ex": "Relative decoupling is not enough if total emissions still rise."}, {"term": "degrowth", "ipa": "/ˈdiːɡrəʊθ/", "pron": "DEE-growth", "fr": "décroissance", "def": "The idea that rich economies should reduce production and consumption to protect the planet.", "ex": "Degrowth challenges the assumption that more GDP is always desirable."}, {"term": "post-growth", "ipa": "/ˌpəʊst ˈɡrəʊθ/", "pron": "post-growth", "fr": "post-croissance", "def": "A perspective that looks beyond GDP growth as the main goal of policy.", "ex": "Post-growth thinkers prioritise well-being and ecological limits."}, {"term": "doughnut economics", "ipa": "/ˈdəʊnʌt iːkəˈnɒmɪks/", "pron": "DOH-nut ee-kuh-NOM-iks", "fr": "économie du donut", "def": "An economic model aiming to meet human needs within planetary boundaries.", "ex": "Doughnut economics offers an alternative to endless growth."}, {"term": "well-being economy", "ipa": "/ˌwel ˈbiːɪŋ iˌkɒnəmi/", "pron": "wel-BEE-ing i-KON-uh-mee", "fr": "économie du bien-être", "def": "An economy designed around health, happiness, equality and sustainability.", "ex": "A well-being economy shifts attention away from GDP alone."}, {"term": "planetary boundaries", "ipa": "/ˌplænətəri ˈbaʊndəriz/", "pron": "PLAN-uh-tuh-ree BOWN-duh-reez", "fr": "limites planétaires", "def": "Environmental limits within which humanity can safely operate.", "ex": "Growth must respect planetary boundaries."}, {"term": "resource depletion", "ipa": "/rɪˈzɔːs dɪˈpliːʃən/", "pron": "ri-ZORSS di-PLEE-shuhn", "fr": "épuisement des ressources", "def": "The exhaustion of natural resources through use.", "ex": "Resource depletion makes old growth models unsustainable."}, {"term": "to boost growth", "ipa": "/buːst ɡrəʊθ/", "pron": "boost growth", "fr": "stimuler la croissance", "def": "To increase economic growth.", "ex": "Governments use tax cuts or investment to boost growth."}, {"term": "to stimulate the economy", "ipa": "/ˈstɪmjʊleɪt ði iˈkɒnəmi/", "pron": "STIM-yuh-layt thee i-KON-uh-mee", "fr": "stimuler l’économie", "def": "To encourage economic activity.", "ex": "A stimulus package can stimulate the economy during a downturn."}, {"term": "to drive economic growth", "ipa": "/draɪv ˌiːkəˈnɒmɪk ɡrəʊθ/", "pron": "dryv ee-kuh-NOM-ik growth", "fr": "être moteur de la croissance économique", "def": "To be a major cause of growth.", "ex": "Innovation and investment drive economic growth."}, {"term": "to raise productivity", "ipa": "/reɪz ˌprɒdʌkˈtɪvəti/", "pron": "rayz prod-uk-TIV-uh-tee", "fr": "augmenter la productivité", "def": "To increase output per worker or input.", "ex": "Training and technology can raise productivity."}, {"term": "to invest in infrastructure", "ipa": "/ɪnˈvest ɪn ˈɪnfrəˌstrʌktʃə/", "pron": "in-VEST in IN-fruh-struk-chuh", "fr": "investir dans les infrastructures", "def": "To spend money on basic systems such as transport, energy or digital networks.", "ex": "Countries must invest in infrastructure to support long-term growth."}, {"term": "to foster innovation", "ipa": "/ˈfɒstə ˌɪnəˈveɪʃən/", "pron": "FOS-tuh in-uh-VAY-shuhn", "fr": "favoriser l’innovation", "def": "To encourage new ideas, technologies and methods.", "ex": "Universities and firms can foster innovation together."}, {"term": "to attract investment", "ipa": "/əˈtrækt ɪnˈvestmənt/", "pron": "uh-TRAKT in-VEST-muhnt", "fr": "attirer les investissements", "def": "To encourage investors to put money into a country or project.", "ex": "Stable institutions help attract investment."}, {"term": "to create jobs", "ipa": "/kriˈeɪt dʒɒbz/", "pron": "kree-AYT jobz", "fr": "créer des emplois", "def": "To generate employment.", "ex": "Green industries can create jobs."}, {"term": "to improve living standards", "ipa": "/ɪmˈpruːv ˈlɪvɪŋ ˌstændədz/", "pron": "im-PROOV LIV-ing STAN-duhdz", "fr": "améliorer le niveau de vie", "def": "To raise people’s material well-being.", "ex": "Growth should improve living standards for ordinary workers."}, {"term": "to reduce poverty", "ipa": "/rɪˈdjuːs ˈpɒvəti/", "pron": "ri-DYOOSS POV-uh-tee", "fr": "réduire la pauvreté", "def": "To lower the number or share of people living in poverty.", "ex": "Growth can reduce poverty if it is inclusive."}, {"term": "to widen inequality", "ipa": "/ˈwaɪdən ˌɪnɪˈkwɒləti/", "pron": "WY-duhn in-i-KWOL-uh-tee", "fr": "creuser les inégalités", "def": "To make inequality greater.", "ex": "Unequal growth can widen inequality."}, {"term": "to redistribute wealth", "ipa": "/ˌriːdɪˈstrɪbjuːt welθ/", "pron": "ree-dis-TRIB-yoot welth", "fr": "redistribuer les richesses", "def": "To transfer wealth through taxes, benefits or services.", "ex": "Progressive taxation can redistribute wealth."}, {"term": "to decouple growth from emissions", "ipa": "/ˌdiːˈkʌpəl ɡrəʊθ frəm ɪˈmɪʃənz/", "pron": "dee-KUP-uhl growth from i-MISH-uhnz", "fr": "découpler la croissance des émissions", "def": "To make the economy grow without increasing emissions.", "ex": "Green growth requires countries to decouple growth from emissions."}, {"term": "to transition to a green economy", "ipa": "/trænˈzɪʃən tə ə ˌɡriːn iˈkɒnəmi/", "pron": "tran-ZISH-uhn tuh uh green i-KON-uh-mee", "fr": "passer à une économie verte", "def": "To shift towards low-carbon and environmentally sustainable economic activity.", "ex": "Governments must help workers transition to a green economy."}, {"term": "to rethink growth", "ipa": "/ˌriːˈθɪŋk ɡrəʊθ/", "pron": "ree-THINK growth", "fr": "repenser la croissance", "def": "To reconsider what growth means and whether it should be the main goal.", "ex": "Climate change forces societies to rethink growth."}]}]}, {"id": "p5c41", "part": 5, "chapter": 41, "title": "Inflation", "file": "cpge_vocab_part5_chapter41_inflation_premium.html", "count": 141, "sections": [{"title": "A. Core inflation vocabulary and price measures", "entries": [{"term": "inflation", "ipa": "/ɪnˈfleɪʃən/", "pron": "in-FLAY-shuhn", "fr": "inflation", "def": "A general increase in prices across an economy over time.", "ex": "Inflation reduces purchasing power when wages do not keep up."}, {"term": "inflation rate", "ipa": "/ɪnˈfleɪʃən reɪt/", "pron": "in-FLAY-shuhn rayt", "fr": "taux d’inflation", "def": "The percentage rate at which prices rise over a given period.", "ex": "The inflation rate became a major political issue during the cost-of-living crisis."}, {"term": "price level", "ipa": "/ˈpraɪs ˌlevəl/", "pron": "price LEV-uhl", "fr": "niveau général des prix", "def": "The average level of prices in an economy.", "ex": "Inflation means the general price level is rising."}, {"term": "rising prices", "ipa": "/ˌraɪzɪŋ ˈpraɪsɪz/", "pron": "RY-zing PRY-siz", "fr": "hausse des prix", "def": "Prices that are increasing over time.", "ex": "Rising prices hit low-income households hardest."}, {"term": "price increase", "ipa": "/ˈpraɪs ˌɪnkriːs/", "pron": "price IN-kreess", "fr": "augmentation des prix", "def": "A rise in the price of a good or service.", "ex": "Food price increases can quickly become politically sensitive."}, {"term": "cost of living", "ipa": "/ˌkɒst əv ˈlɪvɪŋ/", "pron": "kost ov LIV-ing", "fr": "coût de la vie", "def": "The amount of money needed to pay for basic goods and services.", "ex": "The cost of living has risen faster than many wages."}, {"term": "cost-of-living crisis", "ipa": "/ˌkɒst əv ˈlɪvɪŋ ˈkraɪsɪs/", "pron": "kost-ov-LIV-ing KRY-sis", "fr": "crise du coût de la vie", "def": "A situation where essential costs rise faster than incomes.", "ex": "The cost-of-living crisis has reshaped political debate."}, {"term": "purchasing power", "ipa": "/ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "PUR-chuh-sing POW-uh", "fr": "pouvoir d’achat", "def": "The amount of goods and services money can buy.", "ex": "Inflation erodes purchasing power."}, {"term": "real income", "ipa": "/ˌrɪəl ˈɪnkʌm/", "pron": "REE-uhl IN-kum", "fr": "revenu réel", "def": "Income adjusted for inflation.", "ex": "Real income falls when wages rise more slowly than prices."}, {"term": "real wages", "ipa": "/ˌrɪəl ˈweɪdʒɪz/", "pron": "REE-uhl WAY-jiz", "fr": "salaires réels", "def": "Wages adjusted for inflation.", "ex": "Real wages declined during the inflation shock."}, {"term": "nominal wages", "ipa": "/ˌnɒmɪnəl ˈweɪdʒɪz/", "pron": "NOM-i-nuhl WAY-jiz", "fr": "salaires nominaux", "def": "Wages measured in current money, not adjusted for inflation.", "ex": "Nominal wages can rise while real wages fall."}, {"term": "consumer price index", "ipa": "/kənˌsjuːmə ˈpraɪs ˌɪndeks/", "pron": "kuhn-SYOO-muh price IN-deks", "fr": "indice des prix à la consommation", "def": "An index measuring changes in prices paid by consumers.", "ex": "The consumer price index is used to track inflation."}, {"term": "CPI", "ipa": "/ˌsiː piː ˈaɪ/", "pron": "see-pee-eye", "fr": "IPC ; indice des prix à la consommation", "def": "Abbreviation for consumer price index.", "ex": "CPI is one of the most common inflation measures."}, {"term": "retail price index", "ipa": "/ˈriːteɪl ˈpraɪs ˌɪndeks/", "pron": "REE-tayl price IN-deks", "fr": "indice des prix de détail", "def": "A price index historically used in the UK, often including housing costs.", "ex": "The retail price index is still used in some contracts."}, {"term": "RPI", "ipa": "/ˌɑː piː ˈaɪ/", "pron": "ar-pee-eye", "fr": "RPI ; indice britannique des prix de détail", "def": "Abbreviation for retail price index.", "ex": "RPI often gives a different figure from CPI."}, {"term": "core inflation", "ipa": "/ˌkɔːr ɪnˈfleɪʃən/", "pron": "kor in-FLAY-shuhn", "fr": "inflation sous-jacente", "def": "Inflation excluding volatile items such as food and energy.", "ex": "Central banks watch core inflation closely."}, {"term": "headline inflation", "ipa": "/ˌhedlaɪn ɪnˈfleɪʃən/", "pron": "HED-lyne in-FLAY-shuhn", "fr": "inflation globale", "def": "The overall inflation rate including all items.", "ex": "Headline inflation rose sharply when energy prices surged."}, {"term": "food inflation", "ipa": "/ˈfuːd ɪnˌfleɪʃən/", "pron": "food in-FLAY-shuhn", "fr": "inflation alimentaire", "def": "Inflation affecting food prices.", "ex": "Food inflation hurts poorer households disproportionately."}, {"term": "energy inflation", "ipa": "/ˈenədʒi ɪnˌfleɪʃən/", "pron": "EN-uh-jee in-FLAY-shuhn", "fr": "inflation énergétique", "def": "Inflation caused by rising energy prices.", "ex": "Energy inflation pushed up bills and production costs."}, {"term": "services inflation", "ipa": "/ˈsɜːvɪsɪz ɪnˌfleɪʃən/", "pron": "SUR-vis-iz in-FLAY-shuhn", "fr": "inflation des services", "def": "Inflation in services such as hospitality, transport or healthcare.", "ex": "Services inflation can be persistent because it is linked to wages."}, {"term": "goods inflation", "ipa": "/ˈɡʊdz ɪnˌfleɪʃən/", "pron": "goods in-FLAY-shuhn", "fr": "inflation des biens", "def": "Inflation in physical goods.", "ex": "Goods inflation rose when supply chains were disrupted."}, {"term": "housing costs", "ipa": "/ˈhaʊzɪŋ kɒsts/", "pron": "HOW-zing kosts", "fr": "coûts du logement", "def": "Costs related to rent, mortgage payments, maintenance and housing.", "ex": "Housing costs are central to the cost-of-living debate."}, {"term": "rent inflation", "ipa": "/ˈrent ɪnˌfleɪʃən/", "pron": "rent in-FLAY-shuhn", "fr": "inflation des loyers", "def": "Rising rents over time.", "ex": "Rent inflation has increased pressure on young people."}, {"term": "wage inflation", "ipa": "/ˈweɪdʒ ɪnˌfleɪʃən/", "pron": "wayj in-FLAY-shuhn", "fr": "inflation salariale", "def": "Rising wages that can contribute to rising costs and prices.", "ex": "Employers sometimes blame wage inflation for higher prices."}, {"term": "asset price inflation", "ipa": "/ˈæset praɪs ɪnˌfleɪʃən/", "pron": "AS-et price in-FLAY-shuhn", "fr": "inflation des prix des actifs", "def": "Rising prices of assets such as housing, stocks or land.", "ex": "Asset price inflation can worsen wealth inequality."}]}, {"title": "B. Causes of inflation and inflation dynamics", "entries": [{"term": "demand-pull inflation", "ipa": "/dɪˈmɑːnd pʊl ɪnˌfleɪʃən/", "pron": "di-MAND-puul in-FLAY-shuhn", "fr": "inflation par la demande", "def": "Inflation caused by demand rising faster than supply.", "ex": "Demand-pull inflation can occur when the economy overheats."}, {"term": "cost-push inflation", "ipa": "/ˈkɒst pʊʃ ɪnˌfleɪʃən/", "pron": "kost-push in-FLAY-shuhn", "fr": "inflation par les coûts", "def": "Inflation caused by rising production costs.", "ex": "Cost-push inflation can be triggered by energy price shocks."}, {"term": "imported inflation", "ipa": "/ɪmˈpɔːtɪd ɪnˌfleɪʃən/", "pron": "im-POR-tid in-FLAY-shuhn", "fr": "inflation importée", "def": "Inflation caused by rising prices of imported goods or a weaker currency.", "ex": "Imported inflation increased when the currency depreciated."}, {"term": "supply shock", "ipa": "/səˈplaɪ ʃɒk/", "pron": "suh-PLY shok", "fr": "choc d’offre", "def": "A sudden disruption to supply that affects prices or output.", "ex": "The war created a supply shock in energy markets."}, {"term": "demand shock", "ipa": "/dɪˈmɑːnd ʃɒk/", "pron": "di-MAND shok", "fr": "choc de demande", "def": "A sudden change in demand affecting the economy.", "ex": "A demand shock can trigger either recession or inflation."}, {"term": "energy price shock", "ipa": "/ˈenədʒi praɪs ʃɒk/", "pron": "EN-uh-jee price shok", "fr": "choc des prix de l’énergie", "def": "A sudden large rise in energy prices.", "ex": "The energy price shock pushed inflation higher."}, {"term": "oil shock", "ipa": "/ˈɔɪl ʃɒk/", "pron": "oil shok", "fr": "choc pétrolier", "def": "A sudden disruption or rise in oil prices affecting the economy.", "ex": "The 1970s oil shocks led to high inflation."}, {"term": "supply-chain disruption", "ipa": "/səˈplaɪ tʃeɪn dɪsˌrʌpʃən/", "pron": "suh-PLY chayn dis-RUP-shuhn", "fr": "perturbation de la chaîne d’approvisionnement", "def": "An interruption in the flow of goods, parts or materials.", "ex": "Supply-chain disruption contributed to goods inflation."}, {"term": "bottleneck", "ipa": "/ˈbɒtəlnek/", "pron": "BOT-uhl-nek", "fr": "goulot d’étranglement", "def": "A point of congestion or shortage that slows production or supply.", "ex": "Shipping bottlenecks increased prices."}, {"term": "shortage", "ipa": "/ˈʃɔːtɪdʒ/", "pron": "SHOR-tij", "fr": "pénurie", "def": "A lack of enough goods, workers or resources.", "ex": "Shortages can push prices upward."}, {"term": "scarcity", "ipa": "/ˈskeəsəti/", "pron": "SKAIR-suh-tee", "fr": "rareté", "def": "A situation where resources or goods are limited.", "ex": "Scarcity gives suppliers more power to raise prices."}, {"term": "price pressure", "ipa": "/ˈpraɪs ˌpreʃə/", "pron": "price PRESH-uh", "fr": "pression sur les prix", "def": "Forces causing prices to rise or fall.", "ex": "Energy costs created strong price pressure."}, {"term": "inflationary pressure", "ipa": "/ɪnˌfleɪʃənəri ˈpreʃə/", "pron": "in-FLAY-shuh-nuh-ree PRESH-uh", "fr": "pression inflationniste", "def": "Forces pushing inflation upward.", "ex": "Tight labour markets can create inflationary pressure."}, {"term": "inflation expectations", "ipa": "/ɪnˈfleɪʃən ˌekspekˈteɪʃənz/", "pron": "in-FLAY-shuhn ek-spek-TAY-shuhnz", "fr": "anticipations d’inflation", "def": "What people and firms expect future inflation to be.", "ex": "Inflation expectations can influence wage demands and pricing."}, {"term": "anchored expectations", "ipa": "/ˌæŋkəd ˌekspekˈteɪʃənz/", "pron": "ANG-kuhd ek-spek-TAY-shuhnz", "fr": "anticipations ancrées", "def": "Expectations that remain stable despite short-term shocks.", "ex": "Central banks try to keep inflation expectations anchored."}, {"term": "wage-price spiral", "ipa": "/ˈweɪdʒ praɪs ˌspaɪrəl/", "pron": "wayj-price SPY-ruhl", "fr": "spirale prix-salaires", "def": "A cycle where wages and prices push each other higher.", "ex": "A wage-price spiral was feared after inflation surged."}, {"term": "price-wage spiral", "ipa": "/ˈpraɪs weɪdʒ ˌspaɪrəl/", "pron": "price-wayj SPY-ruhl", "fr": "spirale prix-salaires", "def": "A self-reinforcing loop of rising prices and wages.", "ex": "The government warned against a price-wage spiral."}, {"term": "indexation", "ipa": "/ˌɪndekˈseɪʃən/", "pron": "in-dek-SAY-shuhn", "fr": "indexation", "def": "Automatic adjustment of payments or wages to inflation.", "ex": "Indexation protects incomes but can make inflation persistent."}, {"term": "cost-of-living adjustment", "ipa": "/ˌkɒst əv ˈlɪvɪŋ əˈdʒʌstmənt/", "pron": "kost-ov-LIV-ing uh-JUST-muhnt", "fr": "ajustement au coût de la vie", "def": "An increase in wages or benefits to match inflation.", "ex": "Cost-of-living adjustments protect retirees from inflation."}, {"term": "COLA", "ipa": "/ˈkəʊlə/", "pron": "KOH-luh", "fr": "ajustement automatique au coût de la vie", "def": "Abbreviation for cost-of-living adjustment.", "ex": "COLA increases are common in US Social Security."}, {"term": "price stability", "ipa": "/ˈpraɪs stəˌbɪləti/", "pron": "price stuh-BIL-uh-tee", "fr": "stabilité des prix", "def": "A situation where prices rise slowly and predictably.", "ex": "Price stability is a central bank objective."}, {"term": "central bank", "ipa": "/ˌsentrəl ˈbæŋk/", "pron": "SEN-truhl bank", "fr": "banque centrale", "def": "An institution managing monetary policy and currency stability.", "ex": "The central bank raised interest rates to fight inflation."}]}, {"title": "C. Central banks, interest rates and monetary policy", "entries": [{"term": "Bank of England", "ipa": "/ˌbæŋk əv ˈɪŋɡlənd/", "pron": "bank ov ING-gluhnd", "fr": "Banque d’Angleterre", "def": "The central bank of the United Kingdom.", "ex": "The Bank of England targets inflation."}, {"term": "Federal Reserve", "ipa": "/ˌfedərəl rɪˈzɜːv/", "pron": "FED-uh-ruhl ri-ZURV", "fr": "Réserve fédérale américaine", "def": "The central bank of the United States.", "ex": "The Federal Reserve tightened monetary policy."}, {"term": "Fed", "ipa": "/fed/", "pron": "fed", "fr": "Fed ; Réserve fédérale", "def": "Short form for the US Federal Reserve.", "ex": "The Fed raised rates to cool demand."}, {"term": "European Central Bank", "ipa": "/ˌjʊərəpiːən ˈsentrəl bæŋk/", "pron": "YOOR-uh-pee-uhn SEN-truhl bank", "fr": "Banque centrale européenne", "def": "The central bank of the eurozone.", "ex": "The European Central Bank aims to keep inflation under control."}, {"term": "ECB", "ipa": "/ˌiː siː ˈbiː/", "pron": "ee-see-bee", "fr": "BCE", "def": "Abbreviation for European Central Bank.", "ex": "The ECB increased rates after inflation rose."}, {"term": "monetary policy", "ipa": "/ˈmʌnɪtəri ˈpɒləsi/", "pron": "MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire", "def": "Central bank policy affecting interest rates and money supply.", "ex": "Monetary policy is the main tool used to fight inflation."}, {"term": "interest rate", "ipa": "/ˈɪntrəst reɪt/", "pron": "IN-truhst rayt", "fr": "taux d’intérêt", "def": "The cost of borrowing money, expressed as a percentage.", "ex": "Higher interest rates reduce borrowing and spending."}, {"term": "base rate", "ipa": "/ˈbeɪs reɪt/", "pron": "base rayt", "fr": "taux directeur", "def": "The main interest rate set by a central bank.", "ex": "The base rate affects mortgages and loans."}, {"term": "policy rate", "ipa": "/ˈpɒləsi reɪt/", "pron": "POL-uh-see rayt", "fr": "taux directeur", "def": "An interest rate set by a central bank to guide monetary conditions.", "ex": "A higher policy rate is meant to slow inflation."}, {"term": "rate hike", "ipa": "/ˈreɪt haɪk/", "pron": "rayt hyke", "fr": "hausse des taux", "def": "An increase in interest rates.", "ex": "Rate hikes make borrowing more expensive."}, {"term": "rate cut", "ipa": "/ˈreɪt kʌt/", "pron": "rayt kut", "fr": "baisse des taux", "def": "A decrease in interest rates.", "ex": "Rate cuts can stimulate growth after inflation falls."}, {"term": "tight monetary policy", "ipa": "/ˌtaɪt ˈmʌnɪtəri ˈpɒləsi/", "pron": "tyte MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire restrictive", "def": "Monetary policy designed to slow inflation by restricting credit and demand.", "ex": "Tight monetary policy can reduce inflation but risk recession."}, {"term": "loose monetary policy", "ipa": "/ˌluːs ˈmʌnɪtəri ˈpɒləsi/", "pron": "looss MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire accommodante", "def": "Monetary policy designed to stimulate borrowing and demand.", "ex": "Loose monetary policy can support growth but fuel inflation."}, {"term": "quantitative easing", "ipa": "/ˌkwɒntɪtətɪv ˈiːzɪŋ/", "pron": "KWON-ti-tuh-tiv EE-zing", "fr": "assouplissement quantitatif", "def": "Central bank asset purchases used to inject money into the economy.", "ex": "Quantitative easing was used after the financial crisis."}, {"term": "QE", "ipa": "/ˌkjuː ˈiː/", "pron": "kyoo-ee", "fr": "QE ; assouplissement quantitatif", "def": "Abbreviation for quantitative easing.", "ex": "QE can support demand but may raise asset prices."}, {"term": "quantitative tightening", "ipa": "/ˌkwɒntɪtətɪv ˈtaɪtənɪŋ/", "pron": "KWON-ti-tuh-tiv TY-tuhn-ing", "fr": "resserrement quantitatif", "def": "Central bank policy reducing its balance sheet or liquidity.", "ex": "Quantitative tightening can make financial conditions tighter."}, {"term": "QT", "ipa": "/ˌkjuː ˈtiː/", "pron": "kyoo-tee", "fr": "QT ; resserrement quantitatif", "def": "Abbreviation for quantitative tightening.", "ex": "QT is the opposite of QE."}, {"term": "money supply", "ipa": "/ˈmʌni səˌplaɪ/", "pron": "MUN-ee suh-PLY", "fr": "masse monétaire", "def": "The amount of money circulating in an economy.", "ex": "Rapid growth in the money supply can contribute to inflation."}, {"term": "liquidity", "ipa": "/lɪˈkwɪdəti/", "pron": "li-KWID-uh-tee", "fr": "liquidité", "def": "Availability of cash or easily usable funds in an economy or market.", "ex": "Central banks can inject liquidity during a crisis."}, {"term": "credit conditions", "ipa": "/ˈkredɪt kənˌdɪʃənz/", "pron": "KRED-it kuhn-DISH-uhnz", "fr": "conditions de crédit", "def": "The ease or difficulty of borrowing money.", "ex": "Tighter credit conditions slow business investment."}, {"term": "borrowing costs", "ipa": "/ˈbɒrəʊɪŋ kɒsts/", "pron": "BOR-oh-ing kosts", "fr": "coût de l’emprunt", "def": "The cost of taking out loans.", "ex": "Higher borrowing costs affect households and firms."}, {"term": "mortgage rates", "ipa": "/ˈmɔːɡɪdʒ reɪts/", "pron": "MOR-gij rayts", "fr": "taux des prêts immobiliers", "def": "Interest rates on home loans.", "ex": "Mortgage rates rose after central banks tightened policy."}, {"term": "inflation target", "ipa": "/ɪnˈfleɪʃən ˌtɑːɡɪt/", "pron": "in-FLAY-shuhn TAR-git", "fr": "objectif d’inflation", "def": "The inflation rate a central bank aims to achieve.", "ex": "Many central banks have a 2% inflation target."}, {"term": "target rate", "ipa": "/ˈtɑːɡɪt reɪt/", "pron": "TAR-git rayt", "fr": "taux cible", "def": "The rate a central bank or policy aims to reach.", "ex": "The target rate guides central bank decisions."}, {"term": "credibility", "ipa": "/ˌkredəˈbɪləti/", "pron": "kred-uh-BIL-uh-tee", "fr": "crédibilité", "def": "Trust that an institution will do what it promises.", "ex": "Central bank credibility helps anchor inflation expectations."}, {"term": "central bank independence", "ipa": "/ˌsentrəl bæŋk ˌɪndɪˈpendəns/", "pron": "SEN-truhl bank in-di-PEN-duhns", "fr": "indépendance de la banque centrale", "def": "The ability of a central bank to make decisions without direct political pressure.", "ex": "Central bank independence is meant to prevent political inflationary pressure."}, {"term": "hawkish", "ipa": "/ˈhɔːkɪʃ/", "pron": "HAW-kish", "fr": "restrictif ; faucon", "def": "Favouring higher interest rates to fight inflation.", "ex": "A hawkish central banker prioritises inflation control."}, {"term": "dovish", "ipa": "/ˈdʌvɪʃ/", "pron": "DUV-ish", "fr": "accommodant ; colombe", "def": "Favouring lower interest rates to support growth and employment.", "ex": "A dovish stance may worry inflation hawks."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on taxation and spending.", "ex": "Fiscal policy can either ease or worsen inflation."}, {"term": "government spending", "ipa": "/ˈɡʌvənmənt ˈspendɪŋ/", "pron": "GUV-uhn-muhnt SPEN-ding", "fr": "dépenses publiques", "def": "Money spent by the state.", "ex": "Government spending can support households during inflation shocks."}, {"term": "tax cuts", "ipa": "/ˈtæks kʌts/", "pron": "taks kuts", "fr": "baisses d’impôts", "def": "Reductions in taxes.", "ex": "Tax cuts can stimulate demand and fuel inflation."}, {"term": "subsidy", "ipa": "/ˈsʌbsɪdi/", "pron": "SUB-si-dee", "fr": "subvention", "def": "Government financial support to reduce costs or support firms and households.", "ex": "Energy subsidies can protect households but cost public money."}, {"term": "price cap", "ipa": "/ˈpraɪs kæp/", "pron": "price kap", "fr": "plafonnement des prix", "def": "A legal or policy limit on the price of a good or service.", "ex": "A price cap can protect consumers but distort markets."}, {"term": "energy price cap", "ipa": "/ˈenədʒi praɪs kæp/", "pron": "EN-uh-jee price kap", "fr": "plafonnement des prix de l’énergie", "def": "A limit on what energy suppliers can charge customers.", "ex": "The energy price cap became central to UK politics."}, {"term": "price control", "ipa": "/ˈpraɪs kənˌtrəʊl/", "pron": "price kuhn-TROHL", "fr": "contrôle des prix", "def": "Government regulation of prices.", "ex": "Price controls can reduce immediate pain but create shortages."}]}, {"title": "D. Fiscal policy, company behaviour and inflation types", "entries": [{"term": "windfall tax", "ipa": "/ˈwɪndfɔːl tæks/", "pron": "WIND-fawl taks", "fr": "taxe sur les superprofits", "def": "A tax on unexpectedly high profits.", "ex": "A windfall tax on energy firms was proposed during the crisis."}, {"term": "excess profits", "ipa": "/ˌekses ˈprɒfɪts/", "pron": "EK-sess PROF-its", "fr": "surprofits", "def": "Profits above normal levels, often due to unusual conditions.", "ex": "Energy companies were accused of making excess profits."}, {"term": "profit margins", "ipa": "/ˈprɒfɪt ˌmɑːdʒɪnz/", "pron": "PROF-it MAR-jinz", "fr": "marges bénéficiaires", "def": "The share of revenue kept as profit after costs.", "ex": "Rising profit margins can contribute to inflation."}, {"term": "greedflation", "ipa": "/ˌɡriːdˈfleɪʃən/", "pron": "greed-FLAY-shuhn", "fr": "inflation par avidité ; greedflation", "def": "A critical term claiming firms raise prices excessively to increase profits during inflation.", "ex": "Greedflation became a popular explanation for rising prices."}, {"term": "shrinkflation", "ipa": "/ʃrɪŋkˈfleɪʃən/", "pron": "shrink-FLAY-shuhn", "fr": "réduflation ; shrinkflation", "def": "Reducing product size while keeping the price the same.", "ex": "Shrinkflation makes inflation less visible to consumers."}, {"term": "skimpflation", "ipa": "/skɪmpˈfleɪʃən/", "pron": "skimp-FLAY-shuhn", "fr": "baisse de qualité masquée ; skimpflation", "def": "Reducing product or service quality while keeping prices similar.", "ex": "Skimpflation can make customers feel cheated."}, {"term": "stagflation", "ipa": "/stæɡˈfleɪʃən/", "pron": "stag-FLAY-shuhn", "fr": "stagflation", "def": "A situation with high inflation and weak growth or high unemployment.", "ex": "Stagflation is difficult because fighting inflation can worsen unemployment."}, {"term": "hyperinflation", "ipa": "/ˌhaɪpərɪnˈfleɪʃən/", "pron": "hy-puh-rin-FLAY-shuhn", "fr": "hyperinflation", "def": "Extremely rapid and uncontrolled inflation.", "ex": "Hyperinflation destroys trust in money."}, {"term": "deflation", "ipa": "/diːˈfleɪʃən/", "pron": "dee-FLAY-shuhn", "fr": "déflation", "def": "A general fall in prices across the economy.", "ex": "Deflation can be dangerous if consumers postpone spending."}, {"term": "disinflation", "ipa": "/ˌdɪsɪnˈfleɪʃən/", "pron": "dis-in-FLAY-shuhn", "fr": "désinflation", "def": "A fall in the inflation rate, while prices still rise.", "ex": "Disinflation means inflation is slowing, not that prices are falling."}, {"term": "reflation", "ipa": "/ˌriːˈfleɪʃən/", "pron": "ree-FLAY-shuhn", "fr": "reflation", "def": "Policies or recovery that push prices and demand up after weak growth.", "ex": "Reflation can help escape deflation but may overshoot."}, {"term": "devaluation", "ipa": "/ˌdiːvæljuˈeɪʃən/", "pron": "dee-val-yoo-AY-shuhn", "fr": "dévaluation", "def": "A deliberate reduction in the value of a currency under a fixed exchange-rate system.", "ex": "Devaluation can make imports more expensive."}, {"term": "depreciation", "ipa": "/dɪˌpriːʃiˈeɪʃən/", "pron": "di-pree-shee-AY-shuhn", "fr": "dépréciation", "def": "A fall in the value of a currency in the market.", "ex": "Currency depreciation can cause imported inflation."}, {"term": "exchange rate", "ipa": "/ɪksˈtʃeɪndʒ reɪt/", "pron": "iks-CHAYNJ rayt", "fr": "taux de change", "def": "The value of one currency in terms of another.", "ex": "Exchange-rate movements affect import prices."}, {"term": "weak currency", "ipa": "/ˌwiːk ˈkʌrənsi/", "pron": "week KUR-uhn-see", "fr": "monnaie faible", "def": "A currency that has lost value against others.", "ex": "A weak currency can raise the price of imports."}, {"term": "strong currency", "ipa": "/ˌstrɒŋ ˈkʌrənsi/", "pron": "strong KUR-uhn-see", "fr": "monnaie forte", "def": "A currency that has high or rising value against others.", "ex": "A strong currency can reduce imported inflation."}, {"term": "real interest rate", "ipa": "/ˌrɪəl ˈɪntrəst reɪt/", "pron": "REE-uhl IN-truhst rayt", "fr": "taux d’intérêt réel", "def": "The interest rate adjusted for inflation.", "ex": "Real interest rates influence saving and borrowing."}, {"term": "nominal interest rate", "ipa": "/ˌnɒmɪnəl ˈɪntrəst reɪt/", "pron": "NOM-i-nuhl IN-truhst rayt", "fr": "taux d’intérêt nominal", "def": "The stated interest rate before adjusting for inflation.", "ex": "Nominal interest rates may be high while real rates remain low."}, {"term": "savers", "ipa": "/ˈseɪvəz/", "pron": "SAY-vuhz", "fr": "épargnants", "def": "People who save money rather than spend it.", "ex": "Inflation hurts savers when interest rates are low."}, {"term": "borrowers", "ipa": "/ˈbɒrəʊəz/", "pron": "BOR-oh-uhz", "fr": "emprunteurs", "def": "People, firms or governments that borrow money.", "ex": "Inflation can reduce the real burden on borrowers."}, {"term": "fixed income", "ipa": "/ˌfɪkst ˈɪnkʌm/", "pron": "fikst IN-kum", "fr": "revenu fixe", "def": "Income that does not automatically rise with inflation.", "ex": "People on fixed incomes are vulnerable to inflation."}, {"term": "pensioner", "ipa": "/ˈpenʃənə/", "pron": "PEN-shuhn-uh", "fr": "retraité ; pensionné", "def": "A person receiving a pension.", "ex": "Pensioners may struggle if pensions are not indexed."}, {"term": "low-income household", "ipa": "/ˌləʊ ˈɪnkʌm ˈhaʊshəʊld/", "pron": "loh IN-kum HOWSS-hohld", "fr": "ménage à faible revenu", "def": "A household with limited income.", "ex": "Low-income households spend a larger share of income on essentials."}, {"term": "vulnerable households", "ipa": "/ˈvʌlnərəbəl ˈhaʊshəʊldz/", "pron": "VUL-nuh-ruh-buhl HOWSS-hohldz", "fr": "ménages vulnérables", "def": "Households at greater risk of hardship.", "ex": "Targeted support can protect vulnerable households."}, {"term": "living standards squeeze", "ipa": "/ˈlɪvɪŋ ˌstændədz skwiːz/", "pron": "LIV-ing STAN-duhdz skweez", "fr": "compression du niveau de vie", "def": "Pressure on quality of life caused by prices rising faster than income.", "ex": "The living standards squeeze damaged consumer confidence."}, {"term": "real-terms cut", "ipa": "/ˌrɪəl tɜːmz ˈkʌt/", "pron": "REE-uhl-termz kut", "fr": "baisse en termes réels", "def": "A reduction after adjusting for inflation.", "ex": "A pay rise below inflation is a real-terms cut."}, {"term": "pay rise", "ipa": "/ˈpeɪ raɪz/", "pron": "pay ryze", "fr": "augmentation de salaire", "def": "An increase in wages or salary.", "ex": "Workers demanded a pay rise to match inflation."}, {"term": "strike", "ipa": "/straɪk/", "pron": "stryke", "fr": "grève", "def": "A work stoppage used by workers to demand better pay or conditions.", "ex": "Inflation led to strikes over pay."}, {"term": "trade union", "ipa": "/ˌtreɪd ˈjuːniən/", "pron": "trade YOO-nee-uhn", "fr": "syndicat", "def": "An organisation representing workers’ interests.", "ex": "Trade unions called for wages to keep up with prices."}, {"term": "collective bargaining", "ipa": "/kəˌlektɪv ˈbɑːɡɪnɪŋ/", "pron": "kuh-LEK-tiv BAR-gi-ning", "fr": "négociation collective", "def": "Negotiation between workers’ representatives and employers.", "ex": "Collective bargaining can help workers protect real wages."}]}, {"title": "E. Social impact, wages and high-value verbs", "entries": [{"term": "price gouging", "ipa": "/ˈpraɪs ˌɡaʊdʒɪŋ/", "pron": "price GOW-jing", "fr": "prix abusifs ; exploitation par les prix", "def": "Charging excessively high prices during shortages or crises.", "ex": "Price gouging is often condemned during emergencies."}, {"term": "affordability", "ipa": "/əˌfɔːdəˈbɪləti/", "pron": "uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière", "def": "The extent to which people can afford goods, services or housing.", "ex": "Inflation worsens affordability for essentials."}, {"term": "essential goods", "ipa": "/ɪˌsenʃəl ˈɡʊdz/", "pron": "i-SEN-shuhl goods", "fr": "biens essentiels", "def": "Goods people need for basic living.", "ex": "Essential goods include food, energy and medicine."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford adequate heating or energy.", "ex": "Energy inflation pushed more households into fuel poverty."}, {"term": "food bank", "ipa": "/ˈfuːd bæŋk/", "pron": "food bank", "fr": "banque alimentaire", "def": "A charity or service providing food to people in need.", "ex": "Food bank use rose during the cost-of-living crisis."}, {"term": "household budget", "ipa": "/ˌhaʊshəʊld ˈbʌdʒɪt/", "pron": "HOWSS-hohld BUJ-it", "fr": "budget du ménage", "def": "The money a household has and how it is spent.", "ex": "Inflation forces families to rethink their household budget."}, {"term": "to rise", "ipa": "/raɪz/", "pron": "ryze", "fr": "augmenter ; monter", "def": "To go up or increase.", "ex": "Prices continued to rise throughout the year."}, {"term": "to soar", "ipa": "/sɔː/", "pron": "sor", "fr": "s’envoler ; grimper en flèche", "def": "To rise very quickly and sharply.", "ex": "Energy bills soared after the supply shock."}, {"term": "to surge", "ipa": "/sɜːdʒ/", "pron": "surj", "fr": "bondir ; augmenter fortement", "def": "To increase suddenly and strongly.", "ex": "Inflation surged after the pandemic."}, {"term": "to spike", "ipa": "/spaɪk/", "pron": "spyke", "fr": "monter en flèche ; pic", "def": "To rise sharply for a short period.", "ex": "Gas prices spiked during the crisis."}, {"term": "to ease", "ipa": "/iːz/", "pron": "eez", "fr": "s’atténuer", "def": "To become less severe or intense.", "ex": "Inflation eased after energy prices fell."}, {"term": "to slow down", "ipa": "/ˌsləʊ ˈdaʊn/", "pron": "sloh down", "fr": "ralentir", "def": "To become less fast.", "ex": "Price growth slowed down but remained positive."}, {"term": "to peak", "ipa": "/piːk/", "pron": "peek", "fr": "atteindre un pic", "def": "To reach the highest point.", "ex": "Inflation peaked before gradually falling."}, {"term": "to stabilise prices", "ipa": "/ˈsteɪbəlaɪz ˈpraɪsɪz/", "pron": "STAY-buh-lyz PRY-siz", "fr": "stabiliser les prix", "def": "To make prices steady or less volatile.", "ex": "Central banks aim to stabilise prices."}, {"term": "to curb inflation", "ipa": "/kɜːb ɪnˈfleɪʃən/", "pron": "kurb in-FLAY-shuhn", "fr": "freiner l’inflation", "def": "To limit or reduce inflation.", "ex": "Higher rates are meant to curb inflation."}, {"term": "to bring inflation down", "ipa": "/brɪŋ ɪnˈfleɪʃən daʊn/", "pron": "bring in-FLAY-shuhn down", "fr": "faire baisser l’inflation", "def": "To reduce the inflation rate.", "ex": "The central bank promised to bring inflation down."}, {"term": "to fight inflation", "ipa": "/faɪt ɪnˈfleɪʃən/", "pron": "fight in-FLAY-shuhn", "fr": "lutter contre l’inflation", "def": "To take action against rising prices.", "ex": "Governments and central banks used different tools to fight inflation."}, {"term": "to tame inflation", "ipa": "/teɪm ɪnˈfleɪʃən/", "pron": "taym in-FLAY-shuhn", "fr": "maîtriser l’inflation", "def": "To bring inflation under control.", "ex": "Taming inflation may require painful policy choices."}, {"term": "to raise interest rates", "ipa": "/reɪz ˈɪntrəst reɪts/", "pron": "rayz IN-truhst rayts", "fr": "augmenter les taux d’intérêt", "def": "To increase the cost of borrowing.", "ex": "Central banks raise interest rates to cool demand."}, {"term": "to tighten monetary policy", "ipa": "/ˈtaɪtən ˈmʌnɪtəri ˈpɒləsi/", "pron": "TY-tuhn MUN-i-tuh-ree POL-uh-see", "fr": "resserrer la politique monétaire", "def": "To make borrowing and money conditions stricter.", "ex": "The bank tightened monetary policy to control inflation."}, {"term": "to cool demand", "ipa": "/kuːl dɪˈmɑːnd/", "pron": "kool di-MAND", "fr": "refroidir la demande", "def": "To reduce spending pressure in the economy.", "ex": "Higher rates cool demand by discouraging borrowing."}, {"term": "to squeeze households", "ipa": "/skwiːz ˈhaʊshəʊldz/", "pron": "skweez HOWSS-hohldz", "fr": "mettre les ménages sous pression", "def": "To put financial pressure on families.", "ex": "Inflation squeezes households by raising essential costs."}, {"term": "to erode savings", "ipa": "/ɪˈrəʊd ˈseɪvɪŋz/", "pron": "i-ROHD SAY-vingz", "fr": "éroder l’épargne", "def": "To reduce the real value of savings over time.", "ex": "Inflation erodes savings when interest rates are low."}, {"term": "to protect purchasing power", "ipa": "/prəˈtekt ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "pruh-TEKT PUR-chuh-sing POW-uh", "fr": "protéger le pouvoir d’achat", "def": "To defend what people can buy with their income.", "ex": "Indexed benefits can protect purchasing power."}, {"term": "to index wages to inflation", "ipa": "/ˈɪndeks ˈweɪdʒɪz tə ɪnˈfleɪʃən/", "pron": "IN-deks WAY-jiz tuh in-FLAY-shuhn", "fr": "indexer les salaires sur l’inflation", "def": "To automatically adjust wages according to inflation.", "ex": "Indexing wages to inflation can protect workers but fuel persistence."}, {"term": "to pass costs on to consumers", "ipa": "/pɑːs kɒsts ɒn tə kənˈsjuːməz/", "pron": "pass kosts on tuh kuhn-SYOO-muhz", "fr": "répercuter les coûts sur les consommateurs", "def": "To make consumers pay for higher business costs through higher prices.", "ex": "Firms pass costs on to consumers when energy prices rise."}, {"term": "to absorb costs", "ipa": "/əbˈzɔːb kɒsts/", "pron": "uhb-ZORB kosts", "fr": "absorber les coûts", "def": "To accept higher costs without raising prices fully.", "ex": "Small businesses cannot always absorb costs."}, {"term": "to trigger a recession", "ipa": "/ˈtrɪɡər ə rɪˈseʃən/", "pron": "TRIG-uh uh ri-SESH-uhn", "fr": "déclencher une récession", "def": "To cause an economic downturn.", "ex": "Excessive rate hikes can trigger a recession."}, {"term": "to balance growth and inflation", "ipa": "/ˈbæləns ɡrəʊθ ənd ɪnˈfleɪʃən/", "pron": "BAL-uhns growth and in-FLAY-shuhn", "fr": "équilibrer croissance et inflation", "def": "To manage the tension between supporting growth and controlling prices.", "ex": "Policymakers must balance growth and inflation."}]}]}, {"id": "p5c42", "part": 5, "chapter": 42, "title": "Employment And Unemployment", "file": "cpge_vocab_part5_chapter42_employment_and_unemployment_premium.html", "count": 162, "sections": [{"title": "A. Core employment and labour-market vocabulary", "entries": [{"term": "employment", "ipa": "/ɪmˈplɔɪmənt/", "pron": "im-PLOY-muhnt", "fr": "emploi", "def": "The state of having paid work.", "ex": "Employment is central to income, dignity and social inclusion."}, {"term": "unemployment", "ipa": "/ˌʌnɪmˈplɔɪmənt/", "pron": "un-im-PLOY-muhnt", "fr": "chômage", "def": "The state of being without a job while available for work.", "ex": "Unemployment can damage both economic growth and mental health."}, {"term": "unemployment rate", "ipa": "/ˌʌnɪmˈplɔɪmənt reɪt/", "pron": "un-im-PLOY-muhnt rayt", "fr": "taux de chômage", "def": "The percentage of the labour force that is unemployed.", "ex": "The unemployment rate is closely watched by governments and economists."}, {"term": "joblessness", "ipa": "/ˈdʒɒbləsnəs/", "pron": "JOB-luhs-nuhs", "fr": "absence d’emploi ; chômage", "def": "The condition of having no paid job.", "ex": "Long-term joblessness can lead to social exclusion."}, {"term": "labour market", "ipa": "/ˈleɪbə ˌmɑːkɪt/", "pron": "LAY-buh MAR-kit", "fr": "marché du travail", "def": "The system in which workers seek jobs and employers seek workers.", "ex": "The labour market has been transformed by automation and remote work."}, {"term": "workforce", "ipa": "/ˈwɜːkfɔːs/", "pron": "WURK-force", "fr": "population active ; main-d’œuvre", "def": "All the people available for work in an economy or organisation.", "ex": "An ageing workforce can create labour shortages."}, {"term": "labour force", "ipa": "/ˈleɪbə fɔːs/", "pron": "LAY-buh force", "fr": "population active", "def": "People who are working or actively looking for work.", "ex": "Students and retirees are often outside the labour force."}, {"term": "labour force participation", "ipa": "/ˈleɪbə fɔːs pɑːˌtɪsɪˈpeɪʃən/", "pron": "LAY-buh force par-tis-i-PAY-shuhn", "fr": "taux d’activité", "def": "The share of working-age people who are working or looking for work.", "ex": "Higher labour force participation can support economic growth."}, {"term": "working-age population", "ipa": "/ˌwɜːkɪŋ eɪdʒ ˌpɒpjʊˈleɪʃən/", "pron": "WUR-king-ayj pop-yuh-LAY-shuhn", "fr": "population en âge de travailler", "def": "People old enough and young enough to be considered available for work.", "ex": "The working-age population is shrinking in many ageing societies."}, {"term": "economically active", "ipa": "/ˌiːkəˈnɒmɪkli ˈæktɪv/", "pron": "ee-kuh-NOM-ik-lee AK-tiv", "fr": "actif économiquement", "def": "Working or actively seeking work.", "ex": "Economically active people include both employed and unemployed workers."}, {"term": "economically inactive", "ipa": "/ˌiːkəˈnɒmɪkli ɪnˈæktɪv/", "pron": "ee-kuh-NOM-ik-lee in-AK-tiv", "fr": "inactif économiquement", "def": "Not working and not actively seeking work.", "ex": "Some people are economically inactive because of illness, study or caring duties."}, {"term": "job creation", "ipa": "/ˈdʒɒb kriˌeɪʃən/", "pron": "job kree-AY-shuhn", "fr": "création d’emplois", "def": "The process of creating new jobs.", "ex": "Job creation is a major political promise."}, {"term": "job destruction", "ipa": "/ˈdʒɒb dɪˌstrʌkʃən/", "pron": "job di-STRUK-shuhn", "fr": "destruction d’emplois", "def": "The disappearance of jobs, often through crisis, automation or restructuring.", "ex": "Automation can cause job destruction in routine occupations."}, {"term": "net job creation", "ipa": "/ˌnet ˈdʒɒb kriˌeɪʃən/", "pron": "net job kree-AY-shuhn", "fr": "création nette d’emplois", "def": "The number of jobs created minus the number of jobs lost.", "ex": "Net job creation can hide losses in specific sectors."}, {"term": "full employment", "ipa": "/ˌfʊl ɪmˈplɔɪmənt/", "pron": "full im-PLOY-muhnt", "fr": "plein emploi", "def": "A situation where nearly everyone who wants work can find it.", "ex": "Full employment does not necessarily mean every job is secure or well-paid."}, {"term": "underemployment", "ipa": "/ˌʌndərɪmˈplɔɪmənt/", "pron": "UN-duh-rim-PLOY-muhnt", "fr": "sous-emploi", "def": "Working fewer hours or in a lower-skilled job than desired.", "ex": "Underemployment is common among young graduates."}, {"term": "overemployment", "ipa": "/ˌəʊvərɪmˈplɔɪmənt/", "pron": "OH-vuh-rim-PLOY-muhnt", "fr": "suremploi ; surcharge de travail", "def": "Working more hours than one wants or can sustainably manage.", "ex": "Overemployment can contribute to burnout."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˌʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A lack of enough workers to fill available jobs.", "ex": "Healthcare and hospitality have faced labour shortages."}, {"term": "skills shortage", "ipa": "/ˈskɪlz ˌʃɔːtɪdʒ/", "pron": "skilz SHOR-tij", "fr": "pénurie de compétences", "def": "A lack of workers with the skills employers need.", "ex": "Skills shortages can slow economic growth."}, {"term": "skills gap", "ipa": "/ˈskɪlz ɡæp/", "pron": "skilz gap", "fr": "écart de compétences", "def": "A mismatch between workers’ skills and employers’ needs.", "ex": "The skills gap is often cited in debates on education and training."}, {"term": "labour supply", "ipa": "/ˈleɪbə səˌplaɪ/", "pron": "LAY-buh suh-PLY", "fr": "offre de travail", "def": "The number of workers available and willing to work.", "ex": "Immigration can increase labour supply."}, {"term": "labour demand", "ipa": "/ˈleɪbə dɪˌmɑːnd/", "pron": "LAY-buh di-MAND", "fr": "demande de travail", "def": "Employers’ demand for workers.", "ex": "Labour demand falls during recessions."}, {"term": "vacancy", "ipa": "/ˈveɪkənsi/", "pron": "VAY-kuhn-see", "fr": "poste vacant", "def": "An unfilled job position.", "ex": "A high number of vacancies may indicate a tight labour market."}, {"term": "job vacancy", "ipa": "/ˈdʒɒb ˌveɪkənsi/", "pron": "job VAY-kuhn-see", "fr": "offre d’emploi ; poste vacant", "def": "An available job that an employer wants to fill.", "ex": "Job vacancies rose after the pandemic."}, {"term": "tight labour market", "ipa": "/ˌtaɪt ˈleɪbə ˌmɑːkɪt/", "pron": "tyte LAY-buh MAR-kit", "fr": "marché du travail tendu", "def": "A labour market with low unemployment and many vacancies.", "ex": "A tight labour market can push wages up."}, {"term": "slack labour market", "ipa": "/ˌslæk ˈleɪbə ˌmɑːkɪt/", "pron": "slak LAY-buh MAR-kit", "fr": "marché du travail détendu", "def": "A labour market with high unemployment or weak demand for workers.", "ex": "A slack labour market weakens workers’ bargaining power."}, {"term": "jobseeker", "ipa": "/ˈdʒɒbˌsiːkə/", "pron": "JOB-see-kuh", "fr": "demandeur d’emploi", "def": "A person looking for a job.", "ex": "Jobseekers may need training and support."}, {"term": "applicant", "ipa": "/ˈæplɪkənt/", "pron": "AP-li-kuhnt", "fr": "candidat ; candidate", "def": "A person applying for a job.", "ex": "Employers received hundreds of applicants for the position."}, {"term": "candidate", "ipa": "/ˈkændɪdət/", "pron": "KAN-di-duht", "fr": "candidat ; candidate", "def": "A person being considered for a job or position.", "ex": "The strongest candidate had both experience and soft skills."}, {"term": "employer", "ipa": "/ɪmˈplɔɪə/", "pron": "im-PLOY-uh", "fr": "employeur", "def": "A person or organisation that gives people work.", "ex": "Employers complain about skills shortages."}, {"term": "employee", "ipa": "/ɪmˈplɔɪiː/", "pron": "im-PLOY-ee", "fr": "salarié ; employé", "def": "A person who works for an employer.", "ex": "Employees expect fair pay and safe conditions."}, {"term": "worker", "ipa": "/ˈwɜːkə/", "pron": "WUR-kuh", "fr": "travailleur ; travailleuse", "def": "A person who works, especially for wages.", "ex": "Workers have demanded better pay during inflation."}, {"term": "labourer", "ipa": "/ˈleɪbərə/", "pron": "LAY-buh-ruh", "fr": "ouvrier ; manœuvre", "def": "A person doing manual work, often physically demanding.", "ex": "Labourers are often exposed to insecure working conditions."}, {"term": "white-collar worker", "ipa": "/ˌwaɪt ˈkɒlə ˈwɜːkə/", "pron": "white KOL-uh WUR-kuh", "fr": "col blanc", "def": "A worker in office, professional or administrative employment.", "ex": "White-collar workers increasingly use digital tools."}, {"term": "blue-collar worker", "ipa": "/ˌbluː ˈkɒlə ˈwɜːkə/", "pron": "blue KOL-uh WUR-kuh", "fr": "col bleu ; ouvrier", "def": "A worker doing manual, industrial or trade work.", "ex": "Blue-collar workers were strongly affected by deindustrialisation."}]}, {"title": "B. Types of work, contracts and working conditions", "entries": [{"term": "pink-collar worker", "ipa": "/ˌpɪŋk ˈkɒlə ˈwɜːkə/", "pron": "pink KOL-uh WUR-kuh", "fr": "emploi féminisé ; travailleur du care", "def": "A worker in care, service or traditionally feminised jobs.", "ex": "Pink-collar workers are often underpaid despite essential roles."}, {"term": "self-employed", "ipa": "/ˌself ɪmˈplɔɪd/", "pron": "self-im-PLOYD", "fr": "indépendant ; à son compte", "def": "Working for oneself rather than for an employer.", "ex": "Self-employed workers may lack social protection."}, {"term": "freelancer", "ipa": "/ˈfriːˌlɑːnsə/", "pron": "FREE-lan-suh", "fr": "travailleur indépendant ; freelance", "def": "A self-employed person working for different clients.", "ex": "Freelancers have flexibility but irregular income."}, {"term": "contractor", "ipa": "/kənˈtræktə/", "pron": "kuhn-TRAK-tuh", "fr": "prestataire ; contractuel", "def": "A person or company hired to perform specific work under contract.", "ex": "Contractors may not receive the same benefits as employees."}, {"term": "gig worker", "ipa": "/ˈɡɪɡ ˌwɜːkə/", "pron": "gig WUR-kuh", "fr": "travailleur de plateforme ; gig worker", "def": "A worker doing short-term tasks through platforms or temporary arrangements.", "ex": "Gig workers often lack job security."}, {"term": "platform worker", "ipa": "/ˈplætfɔːm ˌwɜːkə/", "pron": "PLAT-form WUR-kuh", "fr": "travailleur de plateforme", "def": "A worker whose work is organised through a digital platform.", "ex": "Platform workers have fought for employee rights."}, {"term": "zero-hours contract", "ipa": "/ˌzɪərəʊ aʊəz ˈkɒntrækt/", "pron": "ZEER-oh-hours KON-trakt", "fr": "contrat zéro heure", "def": "A contract with no guaranteed working hours.", "ex": "Zero-hours contracts offer flexibility but create insecurity."}, {"term": "temporary contract", "ipa": "/ˈtempərəri ˈkɒntrækt/", "pron": "TEM-puh-ruh-ree KON-trakt", "fr": "contrat temporaire", "def": "A work contract for a limited period.", "ex": "Temporary contracts are common among young workers."}, {"term": "fixed-term contract", "ipa": "/ˌfɪkst tɜːm ˈkɒntrækt/", "pron": "fikst-term KON-trakt", "fr": "contrat à durée déterminée", "def": "A contract ending on a specified date.", "ex": "Fixed-term contracts may reduce job security."}, {"term": "permanent contract", "ipa": "/ˈpɜːmənənt ˈkɒntrækt/", "pron": "PUR-muh-nuhnt KON-trakt", "fr": "contrat à durée indéterminée", "def": "A contract without a fixed end date.", "ex": "A permanent contract gives workers more stability."}, {"term": "part-time work", "ipa": "/ˌpɑːt taɪm ˈwɜːk/", "pron": "part-time work", "fr": "travail à temps partiel", "def": "Work for fewer hours than a full-time job.", "ex": "Part-time work is often linked to care responsibilities."}, {"term": "full-time work", "ipa": "/ˌfʊl taɪm ˈwɜːk/", "pron": "full-time work", "fr": "travail à temps plein", "def": "Work for the standard number of hours in a week.", "ex": "Full-time work does not always guarantee a living wage."}, {"term": "shift work", "ipa": "/ˈʃɪft wɜːk/", "pron": "shift work", "fr": "travail posté", "def": "Work organised in shifts, often outside regular office hours.", "ex": "Shift work can disrupt sleep and family life."}, {"term": "night shift", "ipa": "/ˈnaɪt ʃɪft/", "pron": "nyte shift", "fr": "travail de nuit", "def": "A period of work during the night.", "ex": "Night shifts are common in hospitals and logistics."}, {"term": "remote work", "ipa": "/rɪˌməʊt ˈwɜːk/", "pron": "ri-MOHT work", "fr": "travail à distance", "def": "Work done away from the employer’s premises, often from home.", "ex": "Remote work expanded rapidly after the pandemic."}, {"term": "working from home", "ipa": "/ˌwɜːkɪŋ frəm ˈhəʊm/", "pron": "WUR-king from hohm", "fr": "télétravail ; travail à domicile", "def": "Doing one’s job from home rather than the workplace.", "ex": "Working from home can improve flexibility but blur boundaries."}, {"term": "hybrid work", "ipa": "/ˌhaɪbrɪd ˈwɜːk/", "pron": "HY-brid work", "fr": "travail hybride", "def": "A work arrangement combining remote and workplace-based work.", "ex": "Hybrid work has changed office culture."}, {"term": "flexible working", "ipa": "/ˌfleksəbəl ˈwɜːkɪŋ/", "pron": "FLEK-suh-buhl WUR-king", "fr": "travail flexible", "def": "Work arrangements with flexibility in hours or location.", "ex": "Flexible working can support parents and carers."}, {"term": "working conditions", "ipa": "/ˈwɜːkɪŋ kənˌdɪʃənz/", "pron": "WUR-king kuhn-DISH-uhnz", "fr": "conditions de travail", "def": "The environment, hours, pay and treatment experienced at work.", "ex": "Poor working conditions can cause burnout and turnover."}, {"term": "job security", "ipa": "/ˈdʒɒb sɪˌkjʊərəti/", "pron": "job si-KYOOR-uh-tee", "fr": "sécurité de l’emploi", "def": "Confidence that one will keep one’s job.", "ex": "Job security has declined in many sectors."}, {"term": "job insecurity", "ipa": "/ˈdʒɒb ˌɪnsɪˈkjʊərəti/", "pron": "job in-si-KYOOR-uh-tee", "fr": "insécurité de l’emploi", "def": "Fear or risk of losing one’s job or income.", "ex": "Job insecurity affects mental health."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "travail précaire", "def": "Work that is insecure, poorly paid or lacking protection.", "ex": "Precarious work is common in the gig economy."}, {"term": "precarity", "ipa": "/prɪˈkeərəti/", "pron": "pri-KAIR-uh-tee", "fr": "précarité", "def": "Insecurity and instability in work or life conditions.", "ex": "Precarity has become a defining issue for younger workers."}, {"term": "informal work", "ipa": "/ɪnˌfɔːməl ˈwɜːk/", "pron": "in-FOR-muhl work", "fr": "travail informel", "def": "Work not fully regulated, taxed or protected by labour law.", "ex": "Informal work provides income but little legal protection."}, {"term": "informal economy", "ipa": "/ɪnˌfɔːməl iˈkɒnəmi/", "pron": "in-FOR-muhl i-KON-uh-mee", "fr": "économie informelle", "def": "Economic activity outside formal regulation and taxation.", "ex": "The informal economy is large in many developing countries."}, {"term": "black market work", "ipa": "/ˌblæk ˈmɑːkɪt wɜːk/", "pron": "black MAR-kit work", "fr": "travail au noir", "def": "Illegal or undeclared work.", "ex": "Black market work deprives the state of tax revenue."}, {"term": "undeclared work", "ipa": "/ˌʌndɪˈkleəd ˈwɜːk/", "pron": "un-di-KLAIRD work", "fr": "travail non déclaré", "def": "Work not declared to tax or social security authorities.", "ex": "Undeclared work leaves workers vulnerable."}, {"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal hourly or monthly wage.", "ex": "Raising the minimum wage can reduce in-work poverty."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "A living wage is higher than some legal minimum wages."}, {"term": "low-paid work", "ipa": "/ˌləʊ peɪd ˈwɜːk/", "pron": "loh-paid work", "fr": "travail mal rémunéré", "def": "Work that pays poorly.", "ex": "Low-paid work is common in care and hospitality."}, {"term": "in-work poverty", "ipa": "/ˌɪn wɜːk ˈpɒvəti/", "pron": "in-work POV-uh-tee", "fr": "pauvreté laborieuse", "def": "Poverty affecting people who are employed.", "ex": "In-work poverty proves that employment alone is not enough."}, {"term": "wage stagnation", "ipa": "/ˈweɪdʒ stæɡˌneɪʃən/", "pron": "wayj stag-NAY-shuhn", "fr": "stagnation des salaires", "def": "A period when wages barely increase.", "ex": "Wage stagnation has fuelled political anger."}, {"term": "real wages", "ipa": "/ˌrɪəl ˈweɪdʒɪz/", "pron": "REE-uhl WAY-jiz", "fr": "salaires réels", "def": "Wages adjusted for inflation.", "ex": "Real wages fall when inflation exceeds pay rises."}, {"term": "pay rise", "ipa": "/ˈpeɪ raɪz/", "pron": "pay ryze", "fr": "augmentation de salaire", "def": "An increase in wages or salary.", "ex": "Workers demanded a pay rise during the cost-of-living crisis."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart salarial entre femmes et hommes", "def": "The difference between men’s and women’s average earnings.", "ex": "The gender pay gap reflects both discrimination and unequal care work."}, {"term": "collective bargaining", "ipa": "/kəˌlektɪv ˈbɑːɡɪnɪŋ/", "pron": "kuh-LEK-tiv BAR-gi-ning", "fr": "négociation collective", "def": "Negotiation between employers and workers’ representatives.", "ex": "Collective bargaining can strengthen workers’ pay and rights."}, {"term": "trade union", "ipa": "/ˌtreɪd ˈjuːniən/", "pron": "trade YOO-nee-uhn", "fr": "syndicat", "def": "An organisation representing workers’ interests.", "ex": "Trade unions campaign for better pay and working conditions."}, {"term": "unionisation", "ipa": "/ˌjuːniənaɪˈzeɪʃən/", "pron": "YOO-nee-uh-ny-ZAY-shuhn", "fr": "syndicalisation", "def": "The process or level of workers joining unions.", "ex": "Unionisation rates have declined in many countries."}]}, {"title": "C. Pay, rights, unions and workplace protection", "entries": [{"term": "strike", "ipa": "/straɪk/", "pron": "stryke", "fr": "grève", "def": "A work stoppage used to demand better pay or conditions.", "ex": "Strikes increased during the cost-of-living crisis."}, {"term": "industrial action", "ipa": "/ɪnˌdʌstriəl ˈækʃən/", "pron": "in-DUS-tree-uhl AK-shuhn", "fr": "action syndicale ; mouvement social", "def": "Action by workers, such as strikes, to pressure employers.", "ex": "Industrial action can disrupt transport, schools and hospitals."}, {"term": "workplace rights", "ipa": "/ˈwɜːkpleɪs raɪts/", "pron": "WURK-place rites", "fr": "droits au travail", "def": "Legal and social rights at work.", "ex": "Workplace rights include safety, pay and protection from discrimination."}, {"term": "labour rights", "ipa": "/ˈleɪbə raɪts/", "pron": "LAY-buh rites", "fr": "droits des travailleurs", "def": "Rights protecting workers’ pay, conditions and freedom to organise.", "ex": "Labour rights are often weaker in informal work."}, {"term": "employment law", "ipa": "/ɪmˈplɔɪmənt lɔː/", "pron": "im-PLOY-muhnt law", "fr": "droit du travail", "def": "Law governing work, hiring, dismissal and workplace rights.", "ex": "Employment law protects workers from unfair dismissal."}, {"term": "labour law", "ipa": "/ˈleɪbə lɔː/", "pron": "LAY-buh law", "fr": "droit du travail", "def": "Law concerning workers, unions and employment relations.", "ex": "Labour law varies sharply between countries."}, {"term": "unfair dismissal", "ipa": "/ˌʌnfeə dɪsˈmɪsəl/", "pron": "un-FAIR dis-MISS-uhl", "fr": "licenciement abusif", "def": "Losing a job without a fair or lawful reason.", "ex": "Unfair dismissal laws protect employees from arbitrary decisions."}, {"term": "redundancy", "ipa": "/rɪˈdʌndənsi/", "pron": "ri-DUN-duhn-see", "fr": "licenciement économique", "def": "Job loss because a role is no longer needed.", "ex": "Redundancy can follow restructuring or automation."}, {"term": "layoff", "ipa": "/ˈleɪɒf/", "pron": "LAY-off", "fr": "licenciement", "def": "A job loss, usually because of economic conditions or restructuring.", "ex": "Tech companies announced large layoffs."}, {"term": "downsizing", "ipa": "/ˈdaʊnsaɪzɪŋ/", "pron": "DOWN-sy-zing", "fr": "réduction d’effectifs", "def": "Reducing the number of workers in a company.", "ex": "Downsizing can raise profits but damage morale."}, {"term": "outsourcing", "ipa": "/ˈaʊtsɔːsɪŋ/", "pron": "OWT-sor-sing", "fr": "externalisation ; sous-traitance", "def": "Contracting work to another company, sometimes abroad.", "ex": "Outsourcing can reduce costs but weaken job security."}, {"term": "offshoring", "ipa": "/ˌɒfˈʃɔːrɪŋ/", "pron": "OFF-shor-ing", "fr": "délocalisation", "def": "Moving business activity to another country.", "ex": "Offshoring has contributed to job losses in manufacturing."}, {"term": "reshoring", "ipa": "/ˌriːˈʃɔːrɪŋ/", "pron": "ree-SHOR-ing", "fr": "relocalisation", "def": "Bringing production back to the home country.", "ex": "Reshoring is promoted as a way to rebuild industrial jobs."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "Technology performing tasks previously done by humans.", "ex": "Automation can destroy some jobs while creating others."}, {"term": "robotics", "ipa": "/rəʊˈbɒtɪks/", "pron": "roh-BOT-iks", "fr": "robotique", "def": "The design and use of robots.", "ex": "Robotics affects manufacturing, logistics and care."}, {"term": "artificial intelligence", "ipa": "/ˌɑːtɪfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks requiring human intelligence.", "ex": "Artificial intelligence may transform white-collar work."}, {"term": "AI-driven automation", "ipa": "/ˌeɪ ˈaɪ ˌdrɪvən ˌɔːtəˈmeɪʃən/", "pron": "ay-eye DRIV-uhn aw-tuh-MAY-shuhn", "fr": "automatisation par l’IA", "def": "Automation powered by artificial intelligence.", "ex": "AI-driven automation threatens some routine cognitive jobs."}, {"term": "technological unemployment", "ipa": "/ˌteknəˌlɒdʒɪkəl ˌʌnɪmˈplɔɪmənt/", "pron": "tek-nuh-LOJ-i-kuhl un-im-PLOY-muhnt", "fr": "chômage technologique", "def": "Unemployment caused by technology replacing workers.", "ex": "Technological unemployment is a recurring fear during innovation waves."}, {"term": "job displacement", "ipa": "/ˈdʒɒb dɪsˌpleɪsmənt/", "pron": "job dis-PLAYS-muhnt", "fr": "destruction ou déplacement d’emplois", "def": "Workers losing jobs because of economic or technological change.", "ex": "Job displacement requires retraining and support."}, {"term": "labour-saving technology", "ipa": "/ˈleɪbə ˌseɪvɪŋ tekˈnɒlədʒi/", "pron": "LAY-buh SAY-ving tek-NOL-uh-jee", "fr": "technologie économisant la main-d’œuvre", "def": "Technology reducing the need for human labour.", "ex": "Labour-saving technology can help ageing economies."}, {"term": "digitalisation", "ipa": "/ˌdɪdʒɪtəlaɪˈzeɪʃən/", "pron": "DIJ-i-tuh-ly-ZAY-shuhn", "fr": "numérisation", "def": "The spread of digital technologies in work and society.", "ex": "Digitalisation changes the skills workers need."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion ; requalification", "def": "Training workers to learn new skills for a different role.", "ex": "Reskilling is essential after job displacement."}, {"term": "upskilling", "ipa": "/ˌʌpˈskɪlɪŋ/", "pron": "up-SKIL-ing", "fr": "montée en compétences", "def": "Training workers to improve or update skills.", "ex": "Upskilling helps workers adapt to technological change."}, {"term": "retraining", "ipa": "/ˌriːˈtreɪnɪŋ/", "pron": "ree-TRAY-ning", "fr": "reconversion professionnelle", "def": "Training people for a new job or sector.", "ex": "Retraining can reduce long-term unemployment."}, {"term": "lifelong learning", "ipa": "/ˌlaɪflɒŋ ˈlɜːnɪŋ/", "pron": "life-long LUR-ning", "fr": "formation tout au long de la vie", "def": "Continuous learning throughout adult life.", "ex": "Lifelong learning is vital in a changing labour market."}, {"term": "vocational training", "ipa": "/vəʊˌkeɪʃənəl ˈtreɪnɪŋ/", "pron": "voh-KAY-shuh-nuhl TRAY-ning", "fr": "formation professionnelle", "def": "Practical training for a specific job or trade.", "ex": "Vocational training can improve employability."}, {"term": "apprenticeship", "ipa": "/əˈprentɪsʃɪp/", "pron": "uh-PREN-tis-ship", "fr": "apprentissage", "def": "Training that combines paid work and learning a trade or profession.", "ex": "Apprenticeships can help young people enter skilled jobs."}, {"term": "employability", "ipa": "/ɪmˌplɔɪəˈbɪləti/", "pron": "im-ploy-uh-BIL-uh-tee", "fr": "employabilité", "def": "A person’s ability to get and keep employment.", "ex": "Employability depends on skills, experience and networks."}, {"term": "soft skills", "ipa": "/ˌsɒft ˈskɪlz/", "pron": "soft skilz", "fr": "compétences transversales ; soft skills", "def": "Personal and interpersonal skills such as communication and teamwork.", "ex": "Employers increasingly value soft skills."}]}, {"title": "D. Job loss, automation, skills and training", "entries": [{"term": "hard skills", "ipa": "/ˌhɑːd ˈskɪlz/", "pron": "hard skilz", "fr": "compétences techniques", "def": "Technical or job-specific skills.", "ex": "Hard skills include coding, accounting and machine operation."}, {"term": "qualification", "ipa": "/ˌkwɒlɪfɪˈkeɪʃən/", "pron": "kwol-i-fi-KAY-shuhn", "fr": "qualification ; diplôme", "def": "An official record of education, training or competence.", "ex": "Qualifications can improve access to stable jobs."}, {"term": "credentialism", "ipa": "/krɪˈdenʃəlɪzəm/", "pron": "kri-DEN-shuhl-iz-uhm", "fr": "diplômisme ; inflation des diplômes", "def": "Overreliance on formal qualifications for access to jobs.", "ex": "Credentialism can exclude capable workers without degrees."}, {"term": "graduate unemployment", "ipa": "/ˈɡrædʒuət ˌʌnɪmˈplɔɪmənt/", "pron": "GRAJ-oo-uht un-im-PLOY-muhnt", "fr": "chômage des diplômés", "def": "Unemployment among university graduates.", "ex": "Graduate unemployment shows that degrees do not guarantee jobs."}, {"term": "youth unemployment", "ipa": "/ˈjuːθ ˌʌnɪmˈplɔɪmənt/", "pron": "yooth un-im-PLOY-muhnt", "fr": "chômage des jeunes", "def": "Unemployment among young people.", "ex": "Youth unemployment can scar a generation."}, {"term": "long-term unemployment", "ipa": "/ˌlɒŋ tɜːm ˌʌnɪmˈplɔɪmənt/", "pron": "long-term un-im-PLOY-muhnt", "fr": "chômage de longue durée", "def": "Being unemployed for a long period, often over a year.", "ex": "Long-term unemployment makes it harder to return to work."}, {"term": "short-term unemployment", "ipa": "/ˌʃɔːt tɜːm ˌʌnɪmˈplɔɪmənt/", "pron": "short-term un-im-PLOY-muhnt", "fr": "chômage de courte durée", "def": "Being unemployed for a brief period.", "ex": "Short-term unemployment may occur between jobs."}, {"term": "structural unemployment", "ipa": "/ˌstrʌktʃərəl ˌʌnɪmˈplɔɪmənt/", "pron": "STRUK-chuh-ruhl un-im-PLOY-muhnt", "fr": "chômage structurel", "def": "Unemployment caused by a mismatch between workers’ skills and available jobs.", "ex": "Structural unemployment can result from deindustrialisation."}, {"term": "cyclical unemployment", "ipa": "/ˌsaɪklɪkəl ˌʌnɪmˈplɔɪmənt/", "pron": "SY-kli-kuhl un-im-PLOY-muhnt", "fr": "chômage conjoncturel", "def": "Unemployment caused by economic downturns.", "ex": "Cyclical unemployment rises during recessions."}, {"term": "frictional unemployment", "ipa": "/ˌfrɪkʃənəl ˌʌnɪmˈplɔɪmənt/", "pron": "FRIK-shuh-nuhl un-im-PLOY-muhnt", "fr": "chômage frictionnel", "def": "Temporary unemployment while workers move between jobs.", "ex": "Frictional unemployment exists even in healthy economies."}, {"term": "seasonal unemployment", "ipa": "/ˌsiːzənəl ˌʌnɪmˈplɔɪmənt/", "pron": "SEE-zuh-nuhl un-im-PLOY-muhnt", "fr": "chômage saisonnier", "def": "Unemployment linked to seasonal work patterns.", "ex": "Tourism and agriculture often create seasonal unemployment."}, {"term": "hidden unemployment", "ipa": "/ˌhɪdən ˌʌnɪmˈplɔɪmənt/", "pron": "HID-uhn un-im-PLOY-muhnt", "fr": "chômage caché", "def": "Unemployment not fully captured by official statistics.", "ex": "Hidden unemployment includes discouraged workers."}, {"term": "discouraged worker", "ipa": "/dɪsˌkʌrɪdʒd ˈwɜːkə/", "pron": "dis-KUR-ijd WUR-kuh", "fr": "travailleur découragé", "def": "A person who has stopped looking for work because they believe no jobs are available.", "ex": "Discouraged workers are often missing from unemployment figures."}, {"term": "NEET", "ipa": "/niːt/", "pron": "neet", "fr": "NEET ; ni en emploi, ni en études, ni en formation", "def": "A young person not in education, employment or training.", "ex": "NEET rates are used to measure youth exclusion."}, {"term": "job centre", "ipa": "/ˈdʒɒb ˌsentə/", "pron": "job SEN-tuh", "fr": "agence pour l’emploi", "def": "A public office helping unemployed people find work.", "ex": "Job centres provide support and monitor jobseekers."}, {"term": "unemployment benefit", "ipa": "/ˌʌnɪmˈplɔɪmənt ˈbenɪfɪt/", "pron": "un-im-PLOY-muhnt BEN-i-fit", "fr": "allocation chômage", "def": "Money paid by the state to unemployed people.", "ex": "Unemployment benefits protect people during job loss."}, {"term": "welfare benefits", "ipa": "/ˈwelfeə ˌbenɪfɪts/", "pron": "WEL-fair BEN-i-fits", "fr": "prestations sociales", "def": "State payments to people needing financial support.", "ex": "Welfare benefits reduce poverty but are politically contested."}, {"term": "social safety net", "ipa": "/ˌsəʊʃəl ˈseɪfti net/", "pron": "SOH-shuhl SAYF-tee net", "fr": "filet de sécurité sociale", "def": "Policies protecting people from extreme poverty or hardship.", "ex": "A strong social safety net helps workers during transitions."}, {"term": "active labour market policy", "ipa": "/ˌæktɪv ˈleɪbə ˈmɑːkɪt ˈpɒləsi/", "pron": "AK-tiv LAY-buh MAR-kit POL-uh-see", "fr": "politique active du marché du travail", "def": "Policy helping unemployed people find work through training, support or incentives.", "ex": "Active labour market policies can reduce long-term unemployment."}, {"term": "job placement", "ipa": "/ˈdʒɒb ˌpleɪsmənt/", "pron": "job PLAYS-muhnt", "fr": "placement professionnel", "def": "Helping someone find a suitable job.", "ex": "Job placement services connect employers and jobseekers."}, {"term": "career guidance", "ipa": "/kəˈrɪə ˌɡaɪdəns/", "pron": "kuh-REER GY-duhns", "fr": "orientation professionnelle", "def": "Advice helping people choose jobs, training or career paths.", "ex": "Career guidance is essential for students and jobseekers."}, {"term": "labour mobility", "ipa": "/ˈleɪbə məʊˌbɪləti/", "pron": "LAY-buh moh-BIL-uh-tee", "fr": "mobilité du travail", "def": "The ability of workers to move between jobs, sectors or regions.", "ex": "Housing costs can reduce labour mobility."}, {"term": "geographical mobility", "ipa": "/ˌdʒiːəˈɡræfɪkəl məʊˌbɪləti/", "pron": "jee-uh-GRAF-i-kuhl moh-BIL-uh-tee", "fr": "mobilité géographique", "def": "The ability to move location for work.", "ex": "Geographical mobility is limited by family ties and housing prices."}, {"term": "occupational mobility", "ipa": "/ˌɒkjʊˈpeɪʃənəl məʊˌbɪləti/", "pron": "ok-yuh-PAY-shuh-nuhl moh-BIL-uh-tee", "fr": "mobilité professionnelle", "def": "The ability to move between occupations or sectors.", "ex": "Retraining improves occupational mobility."}, {"term": "migration for work", "ipa": "/maɪˈɡreɪʃən fə wɜːk/", "pron": "my-GRAY-shuhn for work", "fr": "migration de travail", "def": "Moving to another place or country to find employment.", "ex": "Migration for work can reduce labour shortages."}, {"term": "migrant worker", "ipa": "/ˈmaɪɡrənt ˌwɜːkə/", "pron": "MY-gruhnt WUR-kuh", "fr": "travailleur migrant", "def": "A person who moves to another place or country for work.", "ex": "Migrant workers are essential in care, agriculture and construction."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brayn drayn", "fr": "fuite des cerveaux", "def": "The emigration of skilled workers from one country to another.", "ex": "Brain drain can weaken poorer countries’ healthcare systems."}, {"term": "brain gain", "ipa": "/ˈbreɪn ɡeɪn/", "pron": "brayn gayn", "fr": "gain de cerveaux", "def": "The arrival of skilled workers from elsewhere.", "ex": "Skilled immigration can create brain gain."}, {"term": "work permit", "ipa": "/ˈwɜːk ˌpɜːmɪt/", "pron": "work PUR-mit", "fr": "permis de travail", "def": "Official permission to work in a country.", "ex": "Work permits shape access to labour markets."}, {"term": "employment visa", "ipa": "/ɪmˈplɔɪmənt ˈviːzə/", "pron": "im-PLOY-muhnt VEE-zuh", "fr": "visa de travail", "def": "A visa allowing someone to work in another country.", "ex": "Employment visas are often linked to skills shortages."}, {"term": "diversity hiring", "ipa": "/daɪˈvɜːsəti ˈhaɪərɪŋ/", "pron": "dy-VUR-suh-tee HY-uh-ring", "fr": "recrutement favorisant la diversité", "def": "Hiring practices aimed at improving workforce diversity.", "ex": "Diversity hiring can reduce underrepresentation."}, {"term": "workplace discrimination", "ipa": "/ˈwɜːkpleɪs dɪˌskrɪmɪˈneɪʃən/", "pron": "WURK-place dis-krim-i-NAY-shuhn", "fr": "discrimination au travail", "def": "Unfair treatment at work based on identity or status.", "ex": "Workplace discrimination affects pay, promotion and hiring."}, {"term": "age discrimination", "ipa": "/ˈeɪdʒ dɪˌskrɪmɪˈneɪʃən/", "pron": "ayj dis-krim-i-NAY-shuhn", "fr": "discrimination liée à l’âge", "def": "Unfair treatment because of age.", "ex": "Older workers often face age discrimination."}, {"term": "racial discrimination", "ipa": "/ˌreɪʃəl dɪˌskrɪmɪˈneɪʃən/", "pron": "RAY-shuhl dis-krim-i-NAY-shuhn", "fr": "discrimination raciale", "def": "Unfair treatment because of race or ethnicity.", "ex": "Racial discrimination can affect recruitment."}, {"term": "glass ceiling", "ipa": "/ˌɡlɑːs ˈsiːlɪŋ/", "pron": "glass SEE-ling", "fr": "plafond de verre", "def": "An invisible barrier preventing women or minorities from reaching top positions.", "ex": "The glass ceiling persists in corporate leadership."}, {"term": "occupational segregation", "ipa": "/ˌɒkjʊˈpeɪʃənəl ˌseɡrɪˈɡeɪʃən/", "pron": "ok-yuh-PAY-shuh-nuhl seg-ri-GAY-shuhn", "fr": "ségrégation professionnelle", "def": "The concentration of groups in different kinds of jobs.", "ex": "Occupational segregation contributes to wage inequality."}, {"term": "work-life balance", "ipa": "/ˌwɜːk laɪf ˈbæləns/", "pron": "work-life BAL-uhns", "fr": "équilibre vie professionnelle-vie personnelle", "def": "The balance between professional and personal life.", "ex": "Work-life balance has become a key concern for younger workers."}]}, {"title": "E. Unemployment types, mobility, discrimination and high-value verbs", "entries": [{"term": "burnout", "ipa": "/ˈbɜːnaʊt/", "pron": "BURN-owt", "fr": "épuisement professionnel ; burn-out", "def": "Physical and emotional exhaustion caused by long-term stress.", "ex": "Burnout is common in high-pressure workplaces."}, {"term": "workplace stress", "ipa": "/ˈwɜːkpleɪs stres/", "pron": "WURK-place stress", "fr": "stress au travail", "def": "Stress caused by working conditions or workload.", "ex": "Workplace stress can reduce productivity."}, {"term": "mental health at work", "ipa": "/ˌmentəl ˈhelθ ət wɜːk/", "pron": "MEN-tuhl helth at work", "fr": "santé mentale au travail", "def": "Mental well-being in the workplace.", "ex": "Mental health at work has become a major HR issue."}, {"term": "to create jobs", "ipa": "/kriˈeɪt dʒɒbz/", "pron": "kree-AYT jobz", "fr": "créer des emplois", "def": "To generate employment opportunities.", "ex": "Governments promise to create jobs through investment."}, {"term": "to destroy jobs", "ipa": "/dɪˈstrɔɪ dʒɒbz/", "pron": "di-STROY jobz", "fr": "détruire des emplois", "def": "To cause jobs to disappear.", "ex": "Automation may destroy jobs in some sectors."}, {"term": "to hire workers", "ipa": "/ˈhaɪə ˈwɜːkəz/", "pron": "HY-uh WUR-kuhz", "fr": "embaucher des travailleurs", "def": "To employ people.", "ex": "Firms hire workers when demand increases."}, {"term": "to lay off workers", "ipa": "/leɪ ɒf ˈwɜːkəz/", "pron": "lay off WUR-kuhz", "fr": "licencier des travailleurs", "def": "To dismiss workers because they are no longer needed.", "ex": "Companies lay off workers during downturns."}, {"term": "to make workers redundant", "ipa": "/meɪk ˈwɜːkəz rɪˈdʌndənt/", "pron": "mayk WUR-kuhz ri-DUN-duhnt", "fr": "licencier pour motif économique", "def": "To dismiss workers because their jobs no longer exist.", "ex": "Automation can make workers redundant."}, {"term": "to enter the labour market", "ipa": "/ˈentə ðə ˈleɪbə ˌmɑːkɪt/", "pron": "EN-tuh thuh LAY-buh MAR-kit", "fr": "entrer sur le marché du travail", "def": "To begin looking for or doing paid work.", "ex": "Graduates enter the labour market with different levels of advantage."}, {"term": "to leave the labour force", "ipa": "/liːv ðə ˈleɪbə fɔːs/", "pron": "leev thuh LAY-buh force", "fr": "sortir de la population active", "def": "To stop working or looking for work.", "ex": "Some older workers leave the labour force early."}, {"term": "to tackle unemployment", "ipa": "/ˈtækəl ˌʌnɪmˈplɔɪmənt/", "pron": "TAK-uhl un-im-PLOY-muhnt", "fr": "lutter contre le chômage", "def": "To take action to reduce unemployment.", "ex": "Training and investment can help tackle unemployment."}, {"term": "to reduce unemployment", "ipa": "/rɪˈdjuːs ˌʌnɪmˈplɔɪmənt/", "pron": "ri-DYOOSS un-im-PLOY-muhnt", "fr": "réduire le chômage", "def": "To lower the number or rate of unemployed people.", "ex": "Economic growth can reduce unemployment."}, {"term": "to boost employment", "ipa": "/buːst ɪmˈplɔɪmənt/", "pron": "boost im-PLOY-muhnt", "fr": "stimuler l’emploi", "def": "To increase the number of people in work.", "ex": "Public investment can boost employment."}, {"term": "to improve employability", "ipa": "/ɪmˈpruːv ɪmˌplɔɪəˈbɪləti/", "pron": "im-PROOV im-ploy-uh-BIL-uh-tee", "fr": "améliorer l’employabilité", "def": "To increase someone’s ability to get and keep a job.", "ex": "Internships can improve employability."}, {"term": "to reskill workers", "ipa": "/ˌriːˈskɪl ˈwɜːkəz/", "pron": "ree-SKIL WUR-kuhz", "fr": "reconvertir les travailleurs", "def": "To train workers for new types of jobs.", "ex": "Governments must reskill workers affected by automation."}, {"term": "to upskill the workforce", "ipa": "/ˌʌpˈskɪl ðə ˈwɜːkfɔːs/", "pron": "up-SKIL thuh WURK-force", "fr": "renforcer les compétences de la main-d’œuvre", "def": "To improve workers’ skills.", "ex": "Companies need to upskill the workforce for the digital economy."}, {"term": "to protect workers’ rights", "ipa": "/prəˈtekt ˈwɜːkəz raɪts/", "pron": "pruh-TEKT WUR-kuhz rites", "fr": "protéger les droits des travailleurs", "def": "To defend legal and social protections for workers.", "ex": "Labour law aims to protect workers’ rights."}, {"term": "to improve working conditions", "ipa": "/ɪmˈpruːv ˈwɜːkɪŋ kənˌdɪʃənz/", "pron": "im-PROOV WUR-king kuhn-DISH-uhnz", "fr": "améliorer les conditions de travail", "def": "To make work safer, fairer or more humane.", "ex": "Unions campaign to improve working conditions."}, {"term": "to raise the minimum wage", "ipa": "/reɪz ðə ˌmɪnɪməm ˈweɪdʒ/", "pron": "rayz thuh MIN-i-muhm wayj", "fr": "augmenter le salaire minimum", "def": "To increase the lowest legal wage.", "ex": "Raising the minimum wage can reduce in-work poverty."}, {"term": "to negotiate pay", "ipa": "/nɪˈɡəʊʃieɪt peɪ/", "pron": "ni-GOH-shee-ayt pay", "fr": "négocier les salaires", "def": "To discuss and agree wages or salary.", "ex": "Trade unions negotiate pay with employers."}, {"term": "to go on strike", "ipa": "/ɡəʊ ɒn straɪk/", "pron": "goh on stryke", "fr": "faire grève", "def": "To stop working as a form of protest.", "ex": "Workers went on strike over pay and staffing."}, {"term": "to automate tasks", "ipa": "/ˈɔːtəmeɪt tɑːsks/", "pron": "AW-tuh-mayt tasks", "fr": "automatiser des tâches", "def": "To make tasks performed by machines or software.", "ex": "AI can automate tasks once done by office workers."}, {"term": "to adapt to technological change", "ipa": "/əˈdæpt tə ˌteknəˈlɒdʒɪkəl tʃeɪndʒ/", "pron": "uh-DAPT tuh tek-nuh-LOJ-i-kuhl chaynj", "fr": "s’adapter au changement technologique", "def": "To adjust to new technologies at work.", "ex": "Workers need support to adapt to technological change."}]}]}, {"id": "p5c43", "part": 5, "chapter": 43, "title": "Globalisation", "file": "cpge_vocab_part5_chapter43_globalisation_premium.html", "count": 172, "sections": [{"title": "A. Core globalisation and integration vocabulary", "entries": [{"term": "globalisation", "ipa": "/ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation", "def": "The growing connection and interdependence of economies, societies and cultures across the world.", "ex": "Globalisation has increased trade, migration and cultural exchange."}, {"term": "globalization", "ipa": "/ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation", "def": "US spelling of globalisation.", "ex": "Globalization is often associated with free trade and multinational companies."}, {"term": "global economy", "ipa": "/ˌɡləʊbəl iˈkɒnəmi/", "pron": "GLOH-buhl i-KON-uh-mee", "fr": "économie mondiale", "def": "The world economy considered as an interconnected system.", "ex": "The global economy is vulnerable to financial crises and supply-chain shocks."}, {"term": "economic integration", "ipa": "/ˌiːkəˈnɒmɪk ˌɪntɪˈɡreɪʃən/", "pron": "ee-kuh-NOM-ik in-ti-GRAY-shuhn", "fr": "intégration économique", "def": "The process by which economies become more connected through trade, investment and common rules.", "ex": "Economic integration has deepened within the European Union."}, {"term": "interdependence", "ipa": "/ˌɪntədɪˈpendəns/", "pron": "IN-tuh-di-PEN-duhns", "fr": "interdépendance", "def": "A situation where countries, firms or people depend on each other.", "ex": "Global interdependence can promote cooperation but also spread crises."}, {"term": "economic interdependence", "ipa": "/ˌiːkəˈnɒmɪk ˌɪntədɪˈpendəns/", "pron": "ee-kuh-NOM-ik in-tuh-di-PEN-duhns", "fr": "interdépendance économique", "def": "Mutual economic reliance between countries or regions.", "ex": "Economic interdependence makes conflict costly but creates vulnerabilities."}, {"term": "global interconnectedness", "ipa": "/ˌɡləʊbəl ˌɪntəkəˈnektɪdnəs/", "pron": "GLOH-buhl in-tuh-kuh-NEK-tid-nuhs", "fr": "interconnexion mondiale", "def": "The condition of being connected across borders through trade, technology, migration and communication.", "ex": "The pandemic revealed the extent of global interconnectedness."}, {"term": "cross-border", "ipa": "/ˌkrɒs ˈbɔːdə/", "pron": "cross-BOR-duh", "fr": "transfrontalier", "def": "Taking place across national borders.", "ex": "Cross-border trade depends on transport and customs rules."}, {"term": "borderless world", "ipa": "/ˈbɔːdələs wɜːld/", "pron": "BOR-duh-luhs world", "fr": "monde sans frontières", "def": "The idea that globalisation weakens national borders.", "ex": "The borderless world is more myth than reality."}, {"term": "global village", "ipa": "/ˌɡləʊbəl ˈvɪlɪdʒ/", "pron": "GLOH-buhl VIL-ij", "fr": "village planétaire", "def": "The idea that communication technology makes the world feel smaller and more connected.", "ex": "The internet has strengthened the idea of a global village."}, {"term": "worldwide", "ipa": "/ˌwɜːldˈwaɪd/", "pron": "world-WYDE", "fr": "mondial ; à l’échelle mondiale", "def": "Existing or happening across the world.", "ex": "The company sells its products worldwide."}, {"term": "worldwide market", "ipa": "/ˌwɜːldwaɪd ˈmɑːkɪt/", "pron": "WORLD-wide MAR-kit", "fr": "marché mondial", "def": "A market that operates across the world.", "ex": "Digital platforms can reach a worldwide market."}, {"term": "global market", "ipa": "/ˌɡləʊbəl ˈmɑːkɪt/", "pron": "GLOH-buhl MAR-kit", "fr": "marché mondial", "def": "A market operating internationally.", "ex": "Global markets create opportunities and competition."}, {"term": "international trade", "ipa": "/ˌɪntəˈnæʃənəl treɪd/", "pron": "IN-tuh-NASH-uh-nuhl trade", "fr": "commerce international", "def": "The exchange of goods and services across national borders.", "ex": "International trade is one of the main drivers of globalisation."}, {"term": "free trade", "ipa": "/ˌfriː ˈtreɪd/", "pron": "free trade", "fr": "libre-échange", "def": "Trade with few or no tariffs, quotas or restrictions.", "ex": "Free trade can lower prices but expose workers to competition."}, {"term": "trade liberalisation", "ipa": "/ˈtreɪd ˌlɪbərəlaɪˈzeɪʃən/", "pron": "trade LIB-uh-ruh-ly-ZAY-shuhn", "fr": "libéralisation des échanges", "def": "The reduction of barriers to international trade.", "ex": "Trade liberalisation expanded after the Cold War."}, {"term": "capital flows", "ipa": "/ˈkæpɪtəl fləʊz/", "pron": "KAP-i-tuhl flohz", "fr": "flux de capitaux", "def": "Movements of money for investment across borders.", "ex": "Capital flows can finance growth but also create instability."}, {"term": "financial globalisation", "ipa": "/faɪˌnænʃəl ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "fy-NAN-shuhl GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation financière", "def": "The integration of financial markets across countries.", "ex": "Financial globalisation can spread crises rapidly."}, {"term": "foreign direct investment", "ipa": "/ˌfɒrən dəˌrekt ɪnˈvestmənt/", "pron": "FOR-uhn di-REKT in-VEST-muhnt", "fr": "investissement direct étranger", "def": "Investment by a foreign company in productive activity in another country.", "ex": "Foreign direct investment can bring jobs, technology and capital."}, {"term": "FDI", "ipa": "/ˌef diː ˈaɪ/", "pron": "eff-dee-eye", "fr": "IDE", "def": "Abbreviation for foreign direct investment.", "ex": "FDI often flows towards countries with stable institutions and cheap labour."}, {"term": "portfolio investment", "ipa": "/pɔːtˈfəʊliəʊ ɪnˈvestmənt/", "pron": "port-FOH-lee-oh in-VEST-muhnt", "fr": "investissement de portefeuille", "def": "Investment in financial assets such as stocks and bonds rather than direct business control.", "ex": "Portfolio investment can leave a country quickly during crises."}, {"term": "global supply chain", "ipa": "/ˌɡləʊbəl səˈplaɪ tʃeɪn/", "pron": "GLOH-buhl suh-PLY chayn", "fr": "chaîne d’approvisionnement mondiale", "def": "A worldwide network of suppliers, producers and transport used to make and deliver products.", "ex": "Global supply chains lowered costs but increased vulnerability."}, {"term": "supply chain", "ipa": "/səˈplaɪ tʃeɪn/", "pron": "suh-PLY chayn", "fr": "chaîne d’approvisionnement", "def": "The network involved in producing and delivering goods.", "ex": "Supply chains can be disrupted by war, disease or natural disasters."}, {"term": "value chain", "ipa": "/ˈvæljuː tʃeɪn/", "pron": "VAL-yoo chayn", "fr": "chaîne de valeur", "def": "The stages through which value is added to a product or service.", "ex": "Modern products are often made through complex value chains."}]}, {"title": "B. Trade, supply chains and international institutions", "entries": [{"term": "global value chain", "ipa": "/ˌɡləʊbəl ˈvæljuː tʃeɪn/", "pron": "GLOH-buhl VAL-yoo chayn", "fr": "chaîne de valeur mondiale", "def": "A production process spread across several countries.", "ex": "Global value chains make trade statistics harder to interpret."}, {"term": "outsourcing", "ipa": "/ˈaʊtsɔːsɪŋ/", "pron": "OWT-sor-sing", "fr": "externalisation ; sous-traitance", "def": "Contracting work to another company, often to reduce costs.", "ex": "Outsourcing can reduce costs but weaken job security."}, {"term": "offshoring", "ipa": "/ˌɒfˈʃɔːrɪŋ/", "pron": "OFF-shor-ing", "fr": "délocalisation", "def": "Moving production or services to another country.", "ex": "Offshoring shifted many manufacturing jobs abroad."}, {"term": "nearshoring", "ipa": "/ˌnɪəˈʃɔːrɪŋ/", "pron": "NEER-shor-ing", "fr": "délocalisation de proximité", "def": "Moving production closer to the home market.", "ex": "Nearshoring can reduce supply-chain risks."}, {"term": "reshoring", "ipa": "/ˌriːˈʃɔːrɪŋ/", "pron": "ree-SHOR-ing", "fr": "relocalisation", "def": "Bringing production back to the home country.", "ex": "Reshoring has become more attractive after supply-chain disruptions."}, {"term": "friend-shoring", "ipa": "/ˌfrend ˈʃɔːrɪŋ/", "pron": "friend-SHOR-ing", "fr": "relocalisation vers des pays alliés", "def": "Moving supply chains to politically allied or trusted countries.", "ex": "Friend-shoring aims to reduce geopolitical dependency."}, {"term": "just-in-time production", "ipa": "/ˌdʒʌst ɪn ˈtaɪm prəˈdʌkʃən/", "pron": "just-in-time pruh-DUK-shuhn", "fr": "production à flux tendu", "def": "A production system with minimal stocks and fast delivery of inputs.", "ex": "Just-in-time production is efficient but fragile."}, {"term": "inventory", "ipa": "/ˈɪnvəntri/", "pron": "IN-vuhn-tree", "fr": "stock ; inventaire", "def": "Stocks of goods, materials or products held by a firm.", "ex": "Firms increased inventory after supply chains became less reliable."}, {"term": "logistics", "ipa": "/ləˈdʒɪstɪks/", "pron": "luh-JIS-tiks", "fr": "logistique", "def": "The organisation of transport, storage and delivery of goods.", "ex": "Logistics is essential to global trade."}, {"term": "container shipping", "ipa": "/kənˈteɪnə ˈʃɪpɪŋ/", "pron": "kuhn-TAY-nuh SHIP-ing", "fr": "transport maritime par conteneurs", "def": "Transporting goods by standardised shipping containers.", "ex": "Container shipping made globalisation cheaper and faster."}, {"term": "freight", "ipa": "/freɪt/", "pron": "frayt", "fr": "fret ; marchandises transportées", "def": "Goods transported by ship, train, lorry or plane.", "ex": "Freight costs surged during the pandemic."}, {"term": "shipping cost", "ipa": "/ˈʃɪpɪŋ kɒst/", "pron": "SHIP-ing kost", "fr": "coût du transport", "def": "The cost of transporting goods.", "ex": "High shipping costs can feed inflation."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "Tariffs are used to protect domestic industries."}, {"term": "quota", "ipa": "/ˈkwəʊtə/", "pron": "KWOH-tuh", "fr": "quota", "def": "A limit on the quantity of goods that can be imported or exported.", "ex": "Import quotas restrict foreign competition."}, {"term": "trade barrier", "ipa": "/ˈtreɪd ˌbæriə/", "pron": "trade BARR-ee-uh", "fr": "barrière commerciale", "def": "A rule, tax or restriction that makes trade harder.", "ex": "Trade barriers can protect jobs but raise prices."}, {"term": "non-tariff barrier", "ipa": "/ˌnɒn ˈtærɪf ˌbæriə/", "pron": "non-TAR-if BARR-ee-uh", "fr": "barrière non tarifaire", "def": "A trade restriction that is not a tax, such as rules or standards.", "ex": "Non-tariff barriers include paperwork and technical standards."}, {"term": "trade agreement", "ipa": "/ˈtreɪd əˌɡriːmənt/", "pron": "trade uh-GREE-muhnt", "fr": "accord commercial", "def": "An agreement between countries setting trade rules.", "ex": "Trade agreements often reduce tariffs."}, {"term": "free trade agreement", "ipa": "/ˌfriː ˈtreɪd əˌɡriːmənt/", "pron": "free trade uh-GREE-muhnt", "fr": "accord de libre-échange", "def": "An agreement reducing barriers to trade between countries.", "ex": "Free trade agreements can boost exports."}, {"term": "customs union", "ipa": "/ˈkʌstəmz ˌjuːniən/", "pron": "KUS-tuhmz YOO-nee-uhn", "fr": "union douanière", "def": "An arrangement where countries remove internal tariffs and share an external tariff.", "ex": "A customs union requires more integration than a simple trade deal."}, {"term": "single market", "ipa": "/ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "SING-guhl MAR-kit", "fr": "marché unique", "def": "A market allowing free movement of goods, services, capital and people.", "ex": "The EU single market is one of the deepest forms of economic integration."}, {"term": "World Trade Organization", "ipa": "/ˌwɜːld ˈtreɪd ˌɔːɡənaɪˈzeɪʃən/", "pron": "world trade OR-guh-ny-ZAY-shuhn", "fr": "Organisation mondiale du commerce ; OMC", "def": "The international organisation overseeing global trade rules.", "ex": "The World Trade Organization has struggled with recent trade tensions."}, {"term": "WTO", "ipa": "/ˌdʌbəljuː tiː ˈəʊ/", "pron": "double-yoo tee oh", "fr": "OMC", "def": "Abbreviation for World Trade Organization.", "ex": "WTO rules aim to prevent unfair trade practices."}, {"term": "International Monetary Fund", "ipa": "/ˌɪntəˈnæʃənəl ˈmʌnɪtəri fʌnd/", "pron": "IN-tuh-NASH-uh-nuhl MUN-i-tuh-ree fund", "fr": "Fonds monétaire international ; FMI", "def": "An international institution promoting financial stability and lending to countries in crisis.", "ex": "The International Monetary Fund is often criticised for austerity conditions."}, {"term": "IMF", "ipa": "/ˌaɪ em ˈef/", "pron": "eye-em-eff", "fr": "FMI", "def": "Abbreviation for International Monetary Fund.", "ex": "The IMF provides loans and policy advice."}, {"term": "World Bank", "ipa": "/ˌwɜːld ˈbæŋk/", "pron": "world bank", "fr": "Banque mondiale", "def": "An international institution financing development projects and poverty reduction.", "ex": "The World Bank funds infrastructure and development programmes."}, {"term": "multinational corporation", "ipa": "/ˌmʌltiˈnæʃənəl ˌkɔːpəˈreɪʃən/", "pron": "MUL-tee-NASH-uh-nuhl kor-puh-RAY-shuhn", "fr": "multinationale", "def": "A company operating in several countries.", "ex": "Multinational corporations can shift production across borders."}, {"term": "MNC", "ipa": "/ˌem en ˈsiː/", "pron": "em-en-see", "fr": "multinationale", "def": "Abbreviation for multinational corporation.", "ex": "MNCs can have more power than some states."}, {"term": "transnational corporation", "ipa": "/trænzˌnæʃənəl ˌkɔːpəˈreɪʃən/", "pron": "tranz-NASH-uh-nuhl kor-puh-RAY-shuhn", "fr": "société transnationale", "def": "A company operating across national borders with global structures.", "ex": "Transnational corporations organise global value chains."}, {"term": "global firm", "ipa": "/ˌɡləʊbəl ˈfɜːm/", "pron": "GLOH-buhl firm", "fr": "entreprise mondiale", "def": "A company operating across many countries.", "ex": "Global firms benefit from economies of scale."}, {"term": "corporate power", "ipa": "/ˈkɔːpərət ˈpaʊə/", "pron": "KOR-puh-ruht POW-uh", "fr": "pouvoir des entreprises", "def": "The influence of large companies over politics, markets and society.", "ex": "Corporate power is a key criticism of globalisation."}, {"term": "tax avoidance", "ipa": "/ˈtæks əˌvɔɪdəns/", "pron": "taks uh-VOY-duhns", "fr": "optimisation fiscale", "def": "Legally reducing tax payments through loopholes or planning.", "ex": "Multinationals are often accused of tax avoidance."}]}, {"title": "C. Multinationals, taxation, labour and ethical issues", "entries": [{"term": "tax evasion", "ipa": "/ˈtæks ɪˌveɪʒən/", "pron": "taks i-VAY-zhuhn", "fr": "fraude fiscale", "def": "Illegal non-payment or underpayment of taxes.", "ex": "Tax evasion deprives states of revenue."}, {"term": "tax haven", "ipa": "/ˈtæks ˌheɪvən/", "pron": "taks HAY-vuhn", "fr": "paradis fiscal", "def": "A country or territory with very low taxes and secrecy.", "ex": "Tax havens help firms and wealthy individuals reduce tax bills."}, {"term": "profit shifting", "ipa": "/ˈprɒfɪt ˌʃɪftɪŋ/", "pron": "PROF-it SHIFT-ing", "fr": "transfert de bénéfices", "def": "Moving profits to low-tax jurisdictions to reduce taxes.", "ex": "Profit shifting is a major challenge for tax authorities."}, {"term": "race to the bottom", "ipa": "/ˌreɪs tə ðə ˈbɒtəm/", "pron": "race tuh thuh BOT-uhm", "fr": "course vers le bas", "def": "Competition that lowers wages, taxes or standards to attract business.", "ex": "Critics say globalisation can create a race to the bottom."}, {"term": "social dumping", "ipa": "/ˈsəʊʃəl ˌdʌmpɪŋ/", "pron": "SOH-shuhl DUMP-ing", "fr": "dumping social", "def": "Competing by using lower wages or weaker labour protections.", "ex": "Social dumping is a common fear in trade debates."}, {"term": "environmental dumping", "ipa": "/ɪnˌvaɪrənmentəl ˈdʌmpɪŋ/", "pron": "in-VY-ruhn-MEN-tuhl DUMP-ing", "fr": "dumping environnemental", "def": "Competing through weak environmental rules.", "ex": "Environmental dumping can undermine climate policy."}, {"term": "sweatshop", "ipa": "/ˈswetʃɒp/", "pron": "SWET-shop", "fr": "atelier de misère", "def": "A workplace with very poor pay and conditions, often in garment production.", "ex": "Sweatshops reveal the darker side of cheap consumer goods."}, {"term": "labour exploitation", "ipa": "/ˈleɪbər ˌeksplɔɪˈteɪʃən/", "pron": "LAY-buh ek-sploy-TAY-shuhn", "fr": "exploitation des travailleurs", "def": "Unfair use of workers through low pay, long hours or unsafe conditions.", "ex": "Labour exploitation can occur inside global supply chains."}, {"term": "child labour", "ipa": "/ˌtʃaɪld ˈleɪbə/", "pron": "CHYLD LAY-buh", "fr": "travail des enfants", "def": "Work done by children that harms their education, health or development.", "ex": "Child labour remains a major human-rights concern."}, {"term": "forced labour", "ipa": "/ˌfɔːst ˈleɪbə/", "pron": "forst LAY-buh", "fr": "travail forcé", "def": "Work people are forced to do under threat or coercion.", "ex": "Forced labour can be hidden in supply chains."}, {"term": "modern slavery", "ipa": "/ˌmɒdən ˈsleɪvəri/", "pron": "MOD-uhn SLAY-vuh-ree", "fr": "esclavage moderne", "def": "Severe exploitation including forced labour, trafficking and debt bondage.", "ex": "Modern slavery laws require firms to monitor supply chains."}, {"term": "decent work", "ipa": "/ˌdiːsənt ˈwɜːk/", "pron": "DEE-suhnt work", "fr": "travail décent", "def": "Work that is fairly paid, safe and respectful of rights.", "ex": "Decent work is a core goal of fair globalisation."}, {"term": "labour standards", "ipa": "/ˈleɪbə ˌstændədz/", "pron": "LAY-buh STAN-duhdz", "fr": "normes du travail", "def": "Rules protecting workers’ rights, pay and conditions.", "ex": "Trade agreements increasingly include labour standards."}, {"term": "environmental standards", "ipa": "/ɪnˌvaɪrənmentəl ˈstændədz/", "pron": "in-VY-ruhn-MEN-tuhl STAN-duhdz", "fr": "normes environnementales", "def": "Rules protecting the environment.", "ex": "Weak environmental standards can attract polluting industries."}, {"term": "corporate social responsibility", "ipa": "/ˈkɔːpərət ˈsəʊʃəl rɪˌspɒnsəˈbɪləti/", "pron": "KOR-puh-ruht SOH-shuhl ri-spon-suh-BIL-uh-tee", "fr": "responsabilité sociale des entreprises", "def": "A company’s responsibility to consider social and environmental impact.", "ex": "Corporate social responsibility can be genuine or just marketing."}, {"term": "CSR", "ipa": "/ˌsiː es ˈɑː/", "pron": "see-ess-ar", "fr": "RSE", "def": "Abbreviation for corporate social responsibility.", "ex": "CSR reports are meant to show ethical commitments."}, {"term": "ethical sourcing", "ipa": "/ˌeθɪkəl ˈsɔːsɪŋ/", "pron": "ETH-i-kuhl SOR-sing", "fr": "approvisionnement éthique", "def": "Buying goods from suppliers that meet ethical standards.", "ex": "Ethical sourcing aims to reduce exploitation."}, {"term": "fair trade", "ipa": "/ˌfeə ˈtreɪd/", "pron": "fair trade", "fr": "commerce équitable", "def": "Trade based on fair prices, decent conditions and ethical standards.", "ex": "Fair trade gives producers more stable income."}, {"term": "consumerism", "ipa": "/kənˈsjuːmərɪzəm/", "pron": "kuhn-SYOO-muh-riz-uhm", "fr": "consumérisme", "def": "A culture or system encouraging the purchase of goods and services.", "ex": "Globalisation has spread consumerism worldwide."}, {"term": "global consumer culture", "ipa": "/ˌɡləʊbəl kənˈsjuːmə ˈkʌltʃə/", "pron": "GLOH-buhl kuhn-SYOO-muh KUL-chuh", "fr": "culture consumériste mondiale", "def": "A worldwide culture shaped by similar brands, products and lifestyles.", "ex": "Global consumer culture can weaken local traditions."}, {"term": "cultural globalisation", "ipa": "/ˌkʌltʃərəl ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "KUL-chuh-ruhl GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation culturelle", "def": "The spread and mixing of cultural products, values and lifestyles across the world.", "ex": "Cultural globalisation is visible in music, food, fashion and media."}, {"term": "cultural homogenisation", "ipa": "/ˌkʌltʃərəl həˌmɒdʒənaɪˈzeɪʃən/", "pron": "KUL-chuh-ruhl huh-MOJ-uh-ny-ZAY-shuhn", "fr": "homogénéisation culturelle", "def": "The process by which cultures become more similar.", "ex": "Critics fear cultural homogenisation caused by global brands."}, {"term": "Americanisation", "ipa": "/əˌmerɪkənaɪˈzeɪʃən/", "pron": "uh-MERR-i-kuh-ny-ZAY-shuhn", "fr": "américanisation", "def": "The spread of American culture, products or values.", "ex": "Fast food is often cited as an example of Americanisation."}, {"term": "Westernisation", "ipa": "/ˌwestənaɪˈzeɪʃən/", "pron": "WES-tuh-ny-ZAY-shuhn", "fr": "occidentalisation", "def": "The spread of Western cultural, political or economic models.", "ex": "Westernisation is sometimes resisted as cultural domination."}, {"term": "local culture", "ipa": "/ˌləʊkəl ˈkʌltʃə/", "pron": "LOH-kuhl KUL-chuh", "fr": "culture locale", "def": "The traditions, values and practices of a specific place.", "ex": "Local culture can be threatened by mass tourism and global brands."}, {"term": "cultural diversity", "ipa": "/ˌkʌltʃərəl daɪˈvɜːsəti/", "pron": "KUL-chuh-ruhl dy-VUR-suh-tee", "fr": "diversité culturelle", "def": "The presence of different cultures and traditions.", "ex": "Cultural diversity can be enriched or weakened by globalisation."}, {"term": "hybridisation", "ipa": "/ˌhaɪbrɪdaɪˈzeɪʃən/", "pron": "HY-bri-dy-ZAY-shuhn", "fr": "hybridation", "def": "The mixing of cultural forms to create new combinations.", "ex": "Globalisation can produce cultural hybridisation rather than uniformity."}, {"term": "glocalisation", "ipa": "/ˌɡləʊkəlaɪˈzeɪʃən/", "pron": "GLOH-kuh-ly-ZAY-shuhn", "fr": "glocalisation", "def": "Adapting global products or ideas to local cultures.", "ex": "Fast-food chains use glocalisation to fit local tastes."}, {"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "The ability to influence others through culture, values and attraction.", "ex": "Cultural globalisation can strengthen a country’s soft power."}, {"term": "migration", "ipa": "/maɪˈɡreɪʃən/", "pron": "my-GRAY-shuhn", "fr": "migration", "def": "Movement of people from one place or country to another.", "ex": "Migration is both a cause and result of globalisation."}, {"term": "international migration", "ipa": "/ˌɪntəˈnæʃənəl maɪˈɡreɪʃən/", "pron": "IN-tuh-NASH-uh-nuhl my-GRAY-shuhn", "fr": "migration internationale", "def": "Migration across national borders.", "ex": "International migration connects labour markets and families."}, {"term": "migrant worker", "ipa": "/ˈmaɪɡrənt ˌwɜːkə/", "pron": "MY-gruhnt WUR-kuh", "fr": "travailleur migrant", "def": "A person who moves for work.", "ex": "Migrant workers are essential in agriculture, care and construction."}, {"term": "remittances", "ipa": "/rɪˈmɪtənsɪz/", "pron": "ri-MIT-uhn-siz", "fr": "transferts de fonds", "def": "Money sent by migrants to relatives in their home country.", "ex": "Remittances are a vital source of income for many families."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brayn drayn", "fr": "fuite des cerveaux", "def": "The emigration of skilled workers from one country to another.", "ex": "Brain drain can weaken public services in poorer countries."}]}, {"title": "D. Culture, migration, inequality and development", "entries": [{"term": "brain gain", "ipa": "/ˈbreɪn ɡeɪn/", "pron": "brayn gayn", "fr": "gain de cerveaux", "def": "The arrival of skilled workers from elsewhere.", "ex": "Skilled migration can create brain gain for host countries."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community living outside its ancestral homeland.", "ex": "Diasporas maintain economic and cultural links across borders."}, {"term": "transnationalism", "ipa": "/trænzˈnæʃənəlɪzəm/", "pron": "tranz-NASH-uh-nuhl-iz-uhm", "fr": "transnationalisme", "def": "Social, economic or political activity spanning multiple countries.", "ex": "Transnationalism is visible in migrant communities and global activism."}, {"term": "global city", "ipa": "/ˌɡləʊbəl ˈsɪti/", "pron": "GLOH-buhl SIT-ee", "fr": "ville mondiale", "def": "A city that is highly connected to global finance, culture and trade.", "ex": "London and New York are major global cities."}, {"term": "cosmopolitanism", "ipa": "/ˌkɒzməˈpɒlɪtənɪzəm/", "pron": "koz-muh-POL-i-tuhn-iz-uhm", "fr": "cosmopolitisme", "def": "An outlook open to different cultures and global belonging.", "ex": "Cosmopolitanism is often associated with global cities."}, {"term": "global elite", "ipa": "/ˌɡləʊbəl eɪˈliːt/", "pron": "GLOH-buhl ay-LEET", "fr": "élite mondiale", "def": "Powerful people who benefit from global networks of wealth, education and mobility.", "ex": "The global elite is often accused of being disconnected from ordinary citizens."}, {"term": "global middle class", "ipa": "/ˌɡləʊbəl ˈmɪdəl klɑːs/", "pron": "GLOH-buhl MID-uhl class", "fr": "classe moyenne mondiale", "def": "Middle-income consumers and workers across the world.", "ex": "A global middle class has expanded in emerging economies."}, {"term": "emerging markets", "ipa": "/ɪˈmɜːdʒɪŋ ˈmɑːkɪts/", "pron": "i-MUR-jing MAR-kits", "fr": "marchés émergents", "def": "Economies becoming more integrated into global markets.", "ex": "Emerging markets have benefited from trade and investment."}, {"term": "developing countries", "ipa": "/dɪˌveləpɪŋ ˈkʌntriz/", "pron": "di-VEL-uh-ping KUN-treez", "fr": "pays en développement", "def": "Countries with lower income levels and ongoing development needs.", "ex": "Developing countries can gain from export-led growth."}, {"term": "least developed countries", "ipa": "/ˌliːst dɪˌveləpt ˈkʌntriz/", "pron": "least di-VEL-uhpt KUN-treez", "fr": "pays les moins avancés", "def": "The poorest and most vulnerable developing countries.", "ex": "Least developed countries often remain marginal in global trade."}, {"term": "Global North", "ipa": "/ˌɡləʊbəl ˈnɔːθ/", "pron": "GLOH-buhl north", "fr": "Nord global", "def": "Wealthier, industrialised countries, mostly in North America, Europe and parts of Asia-Pacific.", "ex": "The Global North has historically dominated trade rules."}, {"term": "Global South", "ipa": "/ˌɡləʊbəl ˈsaʊθ/", "pron": "GLOH-buhl south", "fr": "Sud global", "def": "Less wealthy countries, often formerly colonised, mainly in Africa, Asia and Latin America.", "ex": "The Global South demands fairer global governance."}, {"term": "North-South divide", "ipa": "/ˌnɔːθ saʊθ dɪˈvaɪd/", "pron": "north-south di-VYDE", "fr": "fracture Nord-Sud", "def": "Economic and political inequality between richer and poorer regions of the world.", "ex": "Globalisation has not erased the North-South divide."}, {"term": "global inequality", "ipa": "/ˌɡləʊbəl ˌɪnɪˈkwɒləti/", "pron": "GLOH-buhl in-i-KWOL-uh-tee", "fr": "inégalités mondiales", "def": "Unequal distribution of wealth, income or power across the world.", "ex": "Global inequality remains high despite poverty reduction."}, {"term": "income convergence", "ipa": "/ˈɪnkʌm kənˌvɜːdʒəns/", "pron": "IN-kum kuhn-VUR-juhns", "fr": "convergence des revenus", "def": "The process by which poorer countries catch up with richer ones in income.", "ex": "Globalisation can support income convergence through trade and investment."}, {"term": "poverty reduction", "ipa": "/ˈpɒvəti rɪˌdʌkʃən/", "pron": "POV-uh-tee ri-DUK-shuhn", "fr": "réduction de la pauvreté", "def": "Reducing the number or share of people living in poverty.", "ex": "Globalisation has contributed to poverty reduction in some regions."}, {"term": "winners and losers", "ipa": "/ˌwɪnəz ənd ˈluːzəz/", "pron": "WIN-uhz and LOO-zuhz", "fr": "gagnants et perdants", "def": "People, groups or countries that benefit from or are harmed by a change.", "ex": "Globalisation creates winners and losers within countries."}, {"term": "left-behind communities", "ipa": "/ˌleft bɪˈhaɪnd kəˈmjuːnətiz/", "pron": "left-bi-HYND kuh-MYOO-nuh-teez", "fr": "communautés laissées pour compte", "def": "Communities that have not benefited from economic change.", "ex": "Left-behind communities often resent globalisation."}, {"term": "deindustrialisation", "ipa": "/ˌdiːɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "dee-in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "désindustrialisation", "def": "The decline of industrial activity and manufacturing employment.", "ex": "Deindustrialisation has fuelled backlash against globalisation."}, {"term": "job displacement", "ipa": "/ˈdʒɒb dɪsˌpleɪsmənt/", "pron": "job dis-PLAYS-muhnt", "fr": "destruction ou déplacement d’emplois", "def": "Workers losing jobs because of trade, technology or restructuring.", "ex": "Job displacement has political consequences."}, {"term": "wage pressure", "ipa": "/ˈweɪdʒ ˌpreʃə/", "pron": "wayj PRESH-uh", "fr": "pression sur les salaires", "def": "Pressure that pushes wages up or down.", "ex": "Global competition can create downward wage pressure."}, {"term": "comparative advantage", "ipa": "/kəmˌpærətɪv ədˈvɑːntɪdʒ/", "pron": "kuhm-PARR-uh-tiv ad-VAN-tij", "fr": "avantage comparatif", "def": "The ability to produce something at a lower opportunity cost than others.", "ex": "Comparative advantage is a key argument for free trade."}, {"term": "economies of scale", "ipa": "/ɪˈkɒnəmiz əv skeɪl/", "pron": "i-KON-uh-meez ov skayl", "fr": "économies d’échelle", "def": "Cost advantages gained by producing on a larger scale.", "ex": "Global markets help firms achieve economies of scale."}, {"term": "specialisation", "ipa": "/ˌspeʃəlaɪˈzeɪʃən/", "pron": "SPESH-uh-ly-ZAY-shuhn", "fr": "spécialisation", "def": "Focusing on what a country, firm or worker does best.", "ex": "Specialisation can raise efficiency but increase dependency."}, {"term": "efficiency", "ipa": "/ɪˈfɪʃənsi/", "pron": "i-FISH-uhn-see", "fr": "efficacité ; efficience", "def": "Using resources in a way that avoids waste and maximises output.", "ex": "Globalisation is often defended on efficiency grounds."}, {"term": "competitiveness", "ipa": "/kəmˈpetətɪvnəs/", "pron": "kuhm-PET-uh-tiv-nuhs", "fr": "compétitivité", "def": "The ability to compete successfully in markets.", "ex": "Countries try to improve competitiveness through education and infrastructure."}, {"term": "consumer choice", "ipa": "/kənˌsjuːmə ˈtʃɔɪs/", "pron": "kuhn-SYOO-muh choice", "fr": "choix du consommateur", "def": "The range of products available to consumers.", "ex": "Globalisation has increased consumer choice."}, {"term": "lower prices", "ipa": "/ˌləʊə ˈpraɪsɪz/", "pron": "LOH-uh PRY-siz", "fr": "prix plus bas", "def": "Reduced prices for consumers.", "ex": "Lower prices are one of the main benefits of global trade."}, {"term": "cheap labour", "ipa": "/ˌtʃiːp ˈleɪbə/", "pron": "cheap LAY-buh", "fr": "main-d’œuvre bon marché", "def": "Workers paid low wages, often in poorer countries.", "ex": "Global companies often seek cheap labour."}, {"term": "race for competitiveness", "ipa": "/ˌreɪs fə kəmˈpetətɪvnəs/", "pron": "race for kuhm-PET-uh-tiv-nuhs", "fr": "course à la compétitivité", "def": "Competition between countries to attract business by improving costs or conditions.", "ex": "A race for competitiveness can weaken labour protections."}, {"term": "protectionism", "ipa": "/prəˈtekʃənɪzəm/", "pron": "pruh-TEK-shuh-niz-uhm", "fr": "protectionnisme", "def": "Policies protecting domestic industries from foreign competition.", "ex": "Protectionism has returned as a response to globalisation."}, {"term": "anti-globalisation", "ipa": "/ˌænti ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "AN-tee GLOH-buh-ly-ZAY-shuhn", "fr": "altermondialisme ; opposition à la mondialisation", "def": "Opposition to globalisation or some of its effects.", "ex": "Anti-globalisation movements criticise corporate power and inequality."}, {"term": "alter-globalisation", "ipa": "/ˌɔːltə ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "AWL-tuh GLOH-buh-ly-ZAY-shuhn", "fr": "altermondialisme", "def": "A movement seeking a fairer and more democratic form of globalisation.", "ex": "Alter-globalisation activists do not reject global links entirely."}, {"term": "backlash against globalisation", "ipa": "/ˈbæklæʃ əˌɡenst ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "BAK-lash uh-GENST GLOH-buh-ly-ZAY-shuhn", "fr": "retour de bâton contre la mondialisation", "def": "A strong negative reaction against globalisation.", "ex": "The backlash against globalisation has shaped populist politics."}, {"term": "economic nationalism", "ipa": "/ˌiːkəˈnɒmɪk ˈnæʃənəlɪzəm/", "pron": "ee-kuh-NOM-ik NASH-uh-nuh-liz-uhm", "fr": "nationalisme économique", "def": "Policies prioritising national economic interests over global openness.", "ex": "Economic nationalism has challenged free-trade orthodoxy."}, {"term": "populism", "ipa": "/ˈpɒpjʊlɪzəm/", "pron": "POP-yuh-liz-uhm", "fr": "populisme", "def": "Politics claiming to defend ordinary people against elites and outsiders.", "ex": "Populism often exploits anger about globalisation."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "The authority of a state to govern itself.", "ex": "Globalisation can be seen as a threat to sovereignty."}]}, {"title": "E. Backlash, sovereignty, deglobalisation and high-value verbs", "entries": [{"term": "economic sovereignty", "ipa": "/ˌiːkəˈnɒmɪk ˈsɒvrənti/", "pron": "ee-kuh-NOM-ik SOV-ruhn-tee", "fr": "souveraineté économique", "def": "A country’s ability to control its economic choices.", "ex": "Economic sovereignty has become a key argument for industrial policy."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "The ability to act independently in key economic or security areas.", "ex": "The EU promotes strategic autonomy in response to dependency risks."}, {"term": "dependency", "ipa": "/dɪˈpendənsi/", "pron": "di-PEN-duhn-see", "fr": "dépendance", "def": "Reliance on another country, firm or system.", "ex": "Dependency on foreign suppliers can become dangerous."}, {"term": "dependency risk", "ipa": "/dɪˈpendənsi rɪsk/", "pron": "di-PEN-duhn-see risk", "fr": "risque de dépendance", "def": "The danger created by relying too much on one supplier, country or system.", "ex": "Dependency risk is high for energy and critical minerals."}, {"term": "critical minerals", "ipa": "/ˌkrɪtɪkəl ˈmɪnərəlz/", "pron": "KRIT-i-kuhl MIN-uh-ruhlz", "fr": "minerais critiques", "def": "Minerals essential for technology, energy or defence.", "ex": "Critical minerals are central to green technology supply chains."}, {"term": "semiconductors", "ipa": "/ˌsemikənˈdʌktəz/", "pron": "SEM-ee-kuhn-DUK-tuhz", "fr": "semi-conducteurs", "def": "Computer chips used in electronics and advanced technology.", "ex": "Semiconductors have become a strategic global issue."}, {"term": "economic security", "ipa": "/ˌiːkəˈnɒmɪk sɪˈkjʊərəti/", "pron": "ee-kuh-NOM-ik si-KYOOR-uh-tee", "fr": "sécurité économique", "def": "Protection from economic risks, coercion or strategic dependencies.", "ex": "Economic security now shapes trade policy."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "Protection of a country’s safety and vital interests.", "ex": "Trade restrictions are increasingly justified by national security."}, {"term": "geoeconomics", "ipa": "/ˌdʒiːəʊ iːkəˈnɒmɪks/", "pron": "jee-oh ee-kuh-NOM-iks", "fr": "géoéconomie", "def": "The use of economic tools for geopolitical power.", "ex": "Geoeconomics has become central to US-China rivalry."}, {"term": "trade war", "ipa": "/ˈtreɪd wɔː/", "pron": "trade war", "fr": "guerre commerciale", "def": "A conflict in which countries impose tariffs or restrictions on each other.", "ex": "Trade wars undermine trust and disrupt supply chains."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed on a country or actor.", "ex": "Sanctions show how economic interdependence can be weaponised."}, {"term": "weaponised interdependence", "ipa": "/ˈwepənaɪzd ˌɪntədɪˈpendəns/", "pron": "WEP-uh-nyzd in-tuh-di-PEN-duhns", "fr": "interdépendance instrumentalisée", "def": "The use of global networks and dependencies as instruments of power.", "ex": "Weaponised interdependence challenges the idea that globalisation is neutral."}, {"term": "decoupling", "ipa": "/ˌdiːˈkʌplɪŋ/", "pron": "dee-KUP-ling", "fr": "découplage", "def": "Separating economies, technologies or supply chains that were previously linked.", "ex": "US-China decoupling would reshape globalisation."}, {"term": "de-risking", "ipa": "/ˌdiːˈrɪskɪŋ/", "pron": "dee-RISK-ing", "fr": "réduction des risques ; dérisquage", "def": "Reducing risky dependencies without fully cutting ties.", "ex": "The EU prefers de-risking to full decoupling."}, {"term": "slowbalisation", "ipa": "/ˌsləʊbəlaɪˈzeɪʃən/", "pron": "SLOH-buh-ly-ZAY-shuhn", "fr": "ralentissement de la mondialisation", "def": "A slowdown in the pace of globalisation.", "ex": "Slowbalisation describes weaker growth in global trade."}, {"term": "deglobalisation", "ipa": "/ˌdiːˌɡləʊbəlaɪˈzeɪʃən/", "pron": "dee-GLOH-buh-ly-ZAY-shuhn", "fr": "démondialisation", "def": "The reversal or reduction of global economic integration.", "ex": "Deglobalisation is debated but not complete."}, {"term": "regionalisation", "ipa": "/ˌriːdʒənəlaɪˈzeɪʃən/", "pron": "REE-juh-nuh-ly-ZAY-shuhn", "fr": "régionalisation", "def": "The concentration of trade and production within regions rather than globally.", "ex": "Regionalisation may replace some global supply chains."}, {"term": "fragmentation", "ipa": "/ˌfræɡmenˈteɪʃən/", "pron": "frag-men-TAY-shuhn", "fr": "fragmentation", "def": "The breaking up of global systems into separate blocs or networks.", "ex": "Geopolitical fragmentation can reduce global growth."}, {"term": "trade bloc", "ipa": "/ˈtreɪd blɒk/", "pron": "trade blok", "fr": "bloc commercial", "def": "A group of countries with preferential trade arrangements.", "ex": "Trade blocs can strengthen regional integration."}, {"term": "global governance", "ipa": "/ˌɡləʊbəl ˈɡʌvənəns/", "pron": "GLOH-buhl GUV-uh-nuhns", "fr": "gouvernance mondiale", "def": "International rules and institutions managing global problems.", "ex": "Global governance struggles when great powers disagree."}, {"term": "multilateralism", "ipa": "/ˌmʌltiˈlætərəlɪzəm/", "pron": "MUL-tee-LAT-uh-ruhl-iz-uhm", "fr": "multilatéralisme", "def": "Cooperation between several countries through common rules and institutions.", "ex": "Multilateralism is under pressure from nationalism."}, {"term": "rules-based order", "ipa": "/ˌruːlz beɪst ˈɔːdə/", "pron": "roolz-bayst OR-duh", "fr": "ordre fondé sur des règles", "def": "An international system based on agreed rules rather than pure power.", "ex": "The rules-based order is challenged by trade wars and sanctions."}, {"term": "sustainable globalisation", "ipa": "/səˌsteɪnəbəl ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "suh-STAY-nuh-buhl GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation durable", "def": "Global integration that respects social and environmental limits.", "ex": "Sustainable globalisation requires labour and climate standards."}, {"term": "inclusive globalisation", "ipa": "/ɪnˌkluːsɪv ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "in-KLOO-siv GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation inclusive", "def": "Globalisation that benefits a broad range of people and countries.", "ex": "Inclusive globalisation aims to reduce backlash."}, {"term": "fair globalisation", "ipa": "/ˌfeə ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "fair GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation équitable", "def": "Globalisation designed to protect workers, communities and the environment.", "ex": "Fair globalisation requires stronger rules."}, {"term": "climate globalisation", "ipa": "/ˈklaɪmət ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "KLY-muht GLOH-buh-ly-ZAY-shuhn", "fr": "mondialisation climatique", "def": "Global links in climate policy, emissions, technology and responsibility.", "ex": "Climate change shows that global problems need global cooperation."}, {"term": "carbon footprint", "ipa": "/ˌkɑːbən ˈfʊtprɪnt/", "pron": "KAR-buhn FOOT-print", "fr": "empreinte carbone", "def": "The total greenhouse gas emissions caused by a person, product or organisation.", "ex": "Global supply chains can increase a product’s carbon footprint."}, {"term": "carbon leakage", "ipa": "/ˌkɑːbən ˈliːkɪdʒ/", "pron": "KAR-buhn LEE-kij", "fr": "fuite de carbone", "def": "When emissions shift abroad because production moves to countries with weaker climate rules.", "ex": "Carbon leakage undermines climate policy."}, {"term": "carbon border tax", "ipa": "/ˌkɑːbən ˈbɔːdə tæks/", "pron": "KAR-buhn BOR-duh taks", "fr": "taxe carbone aux frontières", "def": "A tax on imports based on their carbon emissions.", "ex": "A carbon border tax aims to make trade compatible with climate goals."}, {"term": "global commons", "ipa": "/ˌɡləʊbəl ˈkɒmənz/", "pron": "GLOH-buhl KOM-uhnz", "fr": "biens communs mondiaux", "def": "Shared resources such as the atmosphere, oceans or Antarctica.", "ex": "The global commons require international cooperation."}, {"term": "to integrate into the global economy", "ipa": "/ˈɪntɪɡreɪt ˈɪntuː ðə ˌɡləʊbəl iˈkɒnəmi/", "pron": "IN-ti-grayt IN-too thuh GLOH-buhl i-KON-uh-mee", "fr": "s’intégrer dans l’économie mondiale", "def": "To become connected to world trade, finance and production.", "ex": "Developing countries seek to integrate into the global economy."}, {"term": "to open up markets", "ipa": "/ˈəʊpən ʌp ˈmɑːkɪts/", "pron": "OH-puhn up MAR-kits", "fr": "ouvrir les marchés", "def": "To make markets accessible to foreign goods, services or firms.", "ex": "Trade liberalisation opened up markets."}, {"term": "to remove trade barriers", "ipa": "/rɪˈmuːv ˈtreɪd ˌbæriəz/", "pron": "ri-MOOV trade BARR-ee-uhz", "fr": "supprimer les barrières commerciales", "def": "To reduce or eliminate obstacles to trade.", "ex": "Free trade agreements remove trade barriers."}, {"term": "to attract foreign investment", "ipa": "/əˈtrækt ˈfɒrən ɪnˈvestmənt/", "pron": "uh-TRAKT FOR-uhn in-VEST-muhnt", "fr": "attirer les investissements étrangers", "def": "To encourage investors from abroad to invest.", "ex": "Stable institutions attract foreign investment."}, {"term": "to outsource production", "ipa": "/ˈaʊtsɔːs prəˈdʌkʃən/", "pron": "OWT-sors pruh-DUK-shuhn", "fr": "externaliser la production", "def": "To contract production to another company or country.", "ex": "Companies outsource production to reduce costs."}, {"term": "to offshore jobs", "ipa": "/ˌɒfˈʃɔː dʒɒbz/", "pron": "off-SHOR jobz", "fr": "délocaliser des emplois", "def": "To move jobs to another country.", "ex": "Firms offshore jobs to lower labour costs."}, {"term": "to reshore production", "ipa": "/ˌriːˈʃɔː prəˈdʌkʃən/", "pron": "ree-SHOR pruh-DUK-shuhn", "fr": "relocaliser la production", "def": "To bring production back to the home country.", "ex": "Governments encourage firms to reshore production."}, {"term": "to disrupt supply chains", "ipa": "/dɪsˈrʌpt səˈplaɪ tʃeɪnz/", "pron": "dis-RUPT suh-PLY chaynz", "fr": "perturber les chaînes d’approvisionnement", "def": "To interrupt the flow of goods and inputs.", "ex": "Pandemics and wars disrupt supply chains."}, {"term": "to lower consumer prices", "ipa": "/ˈləʊə kənˌsjuːmə ˈpraɪsɪz/", "pron": "LOH-uh kuhn-SYOO-muh PRY-siz", "fr": "faire baisser les prix à la consommation", "def": "To reduce prices paid by consumers.", "ex": "Global competition can lower consumer prices."}, {"term": "to create winners and losers", "ipa": "/kriˈeɪt ˌwɪnəz ənd ˈluːzəz/", "pron": "kree-AYT WIN-uhz and LOO-zuhz", "fr": "créer des gagnants et des perdants", "def": "To benefit some people while harming others.", "ex": "Globalisation creates winners and losers within the same country."}, {"term": "to fuel inequality", "ipa": "/ˈfjuːəl ˌɪnɪˈkwɒləti/", "pron": "FYOO-uhl in-i-KWOL-uh-tee", "fr": "alimenter les inégalités", "def": "To make inequality worse.", "ex": "Poorly regulated globalisation can fuel inequality."}, {"term": "to protect domestic industries", "ipa": "/prəˈtekt dəˌmestɪk ˈɪndəstriz/", "pron": "pruh-TEKT duh-MES-tik IN-duh-streez", "fr": "protéger les industries nationales", "def": "To defend national industries from foreign competition.", "ex": "Tariffs are used to protect domestic industries."}, {"term": "to reduce dependency", "ipa": "/rɪˈdjuːs dɪˈpendənsi/", "pron": "ri-DYOOSS di-PEN-duhn-see", "fr": "réduire la dépendance", "def": "To become less reliant on another country or supplier.", "ex": "Countries want to reduce dependency on strategic rivals."}, {"term": "to strengthen resilience", "ipa": "/ˈstreŋθən rɪˈzɪliəns/", "pron": "STRENG-thuhn ri-ZIL-ee-uhns", "fr": "renforcer la résilience", "def": "To make systems better able to withstand shocks.", "ex": "Diversified suppliers strengthen resilience."}, {"term": "to balance openness and security", "ipa": "/ˈbæləns ˈəʊpənnəs ənd sɪˈkjʊərəti/", "pron": "BAL-uhns OH-puhn-nuhs and si-KYOOR-uh-tee", "fr": "équilibrer ouverture et sécurité", "def": "To combine global exchange with protection against strategic risks.", "ex": "Modern trade policy must balance openness and security."}, {"term": "to regulate globalisation", "ipa": "/ˈreɡjʊleɪt ˌɡləʊbəlaɪˈzeɪʃən/", "pron": "REG-yuh-layt GLOH-buh-ly-ZAY-shuhn", "fr": "réguler la mondialisation", "def": "To create rules controlling global economic activity.", "ex": "States and institutions need to regulate globalisation."}]}]}, {"id": "p5c44", "part": 5, "chapter": 44, "title": "Trade And Protectionism", "file": "cpge_vocab_part5_chapter44_trade_and_protectionism_premium.html", "count": 142, "sections": [{"title": "A. Core trade and protectionism vocabulary", "entries": [{"term": "trade", "ipa": "/treɪd/", "pron": "trade", "fr": "commerce ; échanges commerciaux", "def": "The buying and selling of goods and services between people, companies or countries.", "ex": "Trade connects national economies and shapes global prosperity."}, {"term": "international trade", "ipa": "/ˌɪntəˈnæʃənəl treɪd/", "pron": "IN-tuh-NASH-uh-nuhl trade", "fr": "commerce international", "def": "The exchange of goods and services across national borders.", "ex": "International trade can lower prices but also expose workers to global competition."}, {"term": "global trade", "ipa": "/ˌɡləʊbəl ˈtreɪd/", "pron": "GLOH-buhl trade", "fr": "commerce mondial", "def": "Trade taking place across the world economy.", "ex": "Global trade has expanded through container shipping and digital technology."}, {"term": "free trade", "ipa": "/ˌfriː ˈtreɪd/", "pron": "free trade", "fr": "libre-échange", "def": "Trade with few or no tariffs, quotas or restrictions.", "ex": "Supporters of free trade argue that it increases efficiency and consumer choice."}, {"term": "protectionism", "ipa": "/prəˈtekʃənɪzəm/", "pron": "pruh-TEK-shuh-niz-uhm", "fr": "protectionnisme", "def": "Policies designed to protect domestic industries from foreign competition.", "ex": "Protectionism can defend jobs but may raise prices."}, {"term": "trade policy", "ipa": "/ˈtreɪd ˌpɒləsi/", "pron": "trade POL-uh-see", "fr": "politique commerciale", "def": "A government’s rules and strategy concerning imports, exports and trade agreements.", "ex": "Trade policy has become more political since the rise of China."}, {"term": "trade liberalisation", "ipa": "/ˈtreɪd ˌlɪbərəlaɪˈzeɪʃən/", "pron": "trade LIB-uh-ruh-ly-ZAY-shuhn", "fr": "libéralisation des échanges", "def": "The reduction of barriers to international trade.", "ex": "Trade liberalisation was a major feature of late twentieth-century globalisation."}, {"term": "open economy", "ipa": "/ˌəʊpən iˈkɒnəmi/", "pron": "OH-puhn i-KON-uh-mee", "fr": "économie ouverte", "def": "An economy strongly connected to international trade and investment.", "ex": "Small open economies depend heavily on foreign trade."}, {"term": "closed economy", "ipa": "/ˌkləʊzd iˈkɒnəmi/", "pron": "klohzd i-KON-uh-mee", "fr": "économie fermée", "def": "An economy with little trade or financial interaction with the outside world.", "ex": "A completely closed economy is rare in the modern world."}, {"term": "trade barrier", "ipa": "/ˈtreɪd ˌbæriə/", "pron": "trade BARR-ee-uh", "fr": "barrière commerciale", "def": "A rule, tax or restriction that makes trade more difficult.", "ex": "Trade barriers can protect producers but hurt consumers."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "Tariffs make imported goods more expensive."}, {"term": "import duty", "ipa": "/ˈɪmpɔːt ˌdjuːti/", "pron": "IM-port DYOO-tee", "fr": "droit d’importation", "def": "A tax charged on goods entering a country.", "ex": "Import duties can be used to protect domestic manufacturers."}, {"term": "customs duty", "ipa": "/ˈkʌstəmz ˌdjuːti/", "pron": "KUS-tuhmz DYOO-tee", "fr": "droit de douane", "def": "A tax paid on goods crossing a border.", "ex": "Customs duties are collected at borders."}, {"term": "quota", "ipa": "/ˈkwəʊtə/", "pron": "KWOH-tuh", "fr": "quota", "def": "A limit on the quantity of a good that can be imported or exported.", "ex": "Import quotas restrict the amount of foreign goods entering a market."}, {"term": "import quota", "ipa": "/ˈɪmpɔːt ˌkwəʊtə/", "pron": "IM-port KWOH-tuh", "fr": "quota d’importation", "def": "A limit on how much of a product can be imported.", "ex": "An import quota can protect domestic farmers."}, {"term": "export quota", "ipa": "/ˈekspɔːt ˌkwəʊtə/", "pron": "EK-sport KWOH-tuh", "fr": "quota d’exportation", "def": "A limit on how much of a product can be exported.", "ex": "Export quotas can be used to preserve domestic supply."}, {"term": "non-tariff barrier", "ipa": "/ˌnɒn ˈtærɪf ˌbæriə/", "pron": "non TAR-if BARR-ee-uh", "fr": "barrière non tarifaire", "def": "A trade restriction that is not a tax, such as paperwork, rules or standards.", "ex": "Non-tariff barriers can be more subtle than tariffs."}, {"term": "red tape", "ipa": "/ˌred ˈteɪp/", "pron": "red tape", "fr": "paperasserie ; lourdeurs administratives", "def": "Excessive bureaucracy or paperwork.", "ex": "Exporters complain that red tape slows trade."}, {"term": "customs checks", "ipa": "/ˈkʌstəmz tʃeks/", "pron": "KUS-tuhmz cheks", "fr": "contrôles douaniers", "def": "Inspections and paperwork for goods crossing borders.", "ex": "Customs checks can create delays for businesses."}, {"term": "border checks", "ipa": "/ˈbɔːdə tʃeks/", "pron": "BOR-duh cheks", "fr": "contrôles aux frontières", "def": "Inspections at a border to control goods or people.", "ex": "Border checks became a major issue after Brexit."}, {"term": "rules of origin", "ipa": "/ˌruːlz əv ˈɒrɪdʒɪn/", "pron": "roolz ov OR-i-jin", "fr": "règles d’origine", "def": "Rules determining where a product is considered to come from for trade purposes.", "ex": "Rules of origin can create complex paperwork for exporters."}, {"term": "regulatory standard", "ipa": "/ˌreɡjʊlətəri ˈstændəd/", "pron": "REG-yuh-luh-tuh-ree STAN-duhd", "fr": "norme réglementaire", "def": "An official rule setting requirements for products, services or industries.", "ex": "Different regulatory standards can act as trade barriers."}, {"term": "technical standard", "ipa": "/ˈteknɪkəl ˈstændəd/", "pron": "TEK-ni-kuhl STAN-duhd", "fr": "norme technique", "def": "A technical requirement that products must meet.", "ex": "Technical standards can protect consumers or restrict competition."}, {"term": "sanitary standard", "ipa": "/ˈsænɪtəri ˈstændəd/", "pron": "SAN-i-tuh-ree STAN-duhd", "fr": "norme sanitaire", "def": "A health and hygiene requirement for food or agricultural products.", "ex": "Sanitary standards are important in food trade."}, {"term": "phytosanitary measure", "ipa": "/ˌfaɪtəʊˈsænɪtəri ˈmeʒə/", "pron": "FY-toh-SAN-i-tuh-ree MEZH-uh", "fr": "mesure phytosanitaire", "def": "A measure protecting plants, animals or humans from pests or diseases in trade.", "ex": "Phytosanitary measures affect agricultural exports."}, {"term": "subsidy", "ipa": "/ˈsʌbsɪdi/", "pron": "SUB-si-dee", "fr": "subvention", "def": "Financial support given by government to a business or industry.", "ex": "Subsidies can support domestic industry but distort competition."}, {"term": "state aid", "ipa": "/ˌsteɪt ˈeɪd/", "pron": "state aid", "fr": "aide d’État", "def": "Government support for companies or sectors.", "ex": "State aid rules aim to prevent unfair competition."}, {"term": "export subsidy", "ipa": "/ˈekspɔːt ˌsʌbsɪdi/", "pron": "EK-sport SUB-si-dee", "fr": "subvention à l’exportation", "def": "Government support that helps domestic firms sell abroad.", "ex": "Export subsidies can provoke trade disputes."}, {"term": "dumping", "ipa": "/ˈdʌmpɪŋ/", "pron": "DUMP-ing", "fr": "dumping", "def": "Selling goods abroad at unfairly low prices, often below cost.", "ex": "Dumping can damage domestic producers."}, {"term": "anti-dumping duty", "ipa": "/ˌænti ˈdʌmpɪŋ ˌdjuːti/", "pron": "AN-tee DUMP-ing DYOO-tee", "fr": "droit antidumping", "def": "A tariff imposed to counter unfairly cheap imports.", "ex": "Anti-dumping duties are used to protect industries from unfair competition."}, {"term": "trade remedy", "ipa": "/ˈtreɪd ˌremədi/", "pron": "trade REM-uh-dee", "fr": "mesure de défense commerciale", "def": "A measure used to respond to unfair trade practices or import surges.", "ex": "Trade remedies include anti-dumping duties and safeguards."}, {"term": "safeguard measure", "ipa": "/ˈseɪfɡɑːd ˌmeʒə/", "pron": "SAYF-gard MEZH-uh", "fr": "mesure de sauvegarde", "def": "Temporary protection used when imports seriously harm domestic industry.", "ex": "Safeguard measures are allowed under certain trade rules."}, {"term": "retaliatory tariff", "ipa": "/rɪˌtæliətəri ˈtærɪf/", "pron": "ri-TAL-ee-uh-tuh-ree TAR-if", "fr": "tarif de représailles", "def": "A tariff imposed in response to another country’s tariff.", "ex": "Retaliatory tariffs can escalate into trade wars."}, {"term": "trade war", "ipa": "/ˈtreɪd wɔː/", "pron": "trade war", "fr": "guerre commerciale", "def": "A conflict in which countries impose tariffs or restrictions on each other.", "ex": "A trade war can disrupt supply chains and raise consumer prices."}, {"term": "trade dispute", "ipa": "/ˈtreɪd dɪˌspjuːt/", "pron": "trade di-SPYOOT", "fr": "différend commercial", "def": "A disagreement between countries about trade rules or practices.", "ex": "Trade disputes are often handled through international institutions."}]}, {"title": "B. Trade rules, agreements and market access", "entries": [{"term": "trade tension", "ipa": "/ˈtreɪd ˌtenʃən/", "pron": "trade TEN-shuhn", "fr": "tension commerciale", "def": "Strain or conflict between countries over trade.", "ex": "Trade tensions between the US and China affect global markets."}, {"term": "World Trade Organization", "ipa": "/ˌwɜːld ˈtreɪd ˌɔːɡənaɪˈzeɪʃən/", "pron": "world trade OR-guh-ny-ZAY-shuhn", "fr": "Organisation mondiale du commerce ; OMC", "def": "The international body that oversees global trade rules.", "ex": "The World Trade Organization provides a framework for resolving disputes."}, {"term": "WTO", "ipa": "/ˌdʌbəljuː tiː ˈəʊ/", "pron": "double-yoo tee oh", "fr": "OMC", "def": "Abbreviation for the World Trade Organization.", "ex": "WTO rules limit some forms of protectionism."}, {"term": "most-favoured-nation treatment", "ipa": "/ˌməʊst ˌfeɪvəd ˈneɪʃən ˈtriːtmənt/", "pron": "mohst FAY-vuhd NAY-shuhn TREET-muhnt", "fr": "traitement de la nation la plus favorisée", "def": "The WTO principle that trade advantages given to one member should be given to all.", "ex": "Most-favoured-nation treatment is a key WTO principle."}, {"term": "trade agreement", "ipa": "/ˈtreɪd əˌɡriːmənt/", "pron": "trade uh-GREE-muhnt", "fr": "accord commercial", "def": "An agreement between countries setting trade rules.", "ex": "Trade agreements can reduce tariffs and open markets."}, {"term": "free trade agreement", "ipa": "/ˌfriː ˈtreɪd əˌɡriːmənt/", "pron": "free trade uh-GREE-muhnt", "fr": "accord de libre-échange", "def": "An agreement reducing trade barriers between countries.", "ex": "Free trade agreements often cover goods, services and investment."}, {"term": "FTA", "ipa": "/ˌef tiː ˈeɪ/", "pron": "eff-tee-ay", "fr": "ALE ; accord de libre-échange", "def": "Abbreviation for free trade agreement.", "ex": "FTAs can deepen economic ties between countries."}, {"term": "bilateral agreement", "ipa": "/ˌbaɪˈlætərəl əˈɡriːmənt/", "pron": "by-LAT-uh-ruhl uh-GREE-muhnt", "fr": "accord bilatéral", "def": "An agreement between two countries.", "ex": "A bilateral agreement can be faster to negotiate than a multilateral deal."}, {"term": "multilateral agreement", "ipa": "/ˌmʌltiˈlætərəl əˈɡriːmənt/", "pron": "MUL-tee-LAT-uh-ruhl uh-GREE-muhnt", "fr": "accord multilatéral", "def": "An agreement involving several countries.", "ex": "Multilateral agreements can create wider common rules."}, {"term": "regional trade agreement", "ipa": "/ˌriːdʒənəl ˈtreɪd əˌɡriːmənt/", "pron": "REE-juh-nuhl trade uh-GREE-muhnt", "fr": "accord commercial régional", "def": "A trade agreement between countries in a region.", "ex": "Regional trade agreements can complement or challenge WTO rules."}, {"term": "customs union", "ipa": "/ˈkʌstəmz ˌjuːniən/", "pron": "KUS-tuhmz YOO-nee-uhn", "fr": "union douanière", "def": "An arrangement where members remove internal tariffs and apply a common external tariff.", "ex": "The EU is a customs union as well as a single market."}, {"term": "single market", "ipa": "/ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "SING-guhl MAR-kit", "fr": "marché unique", "def": "A market allowing free movement of goods, services, capital and people.", "ex": "The single market reduces barriers within the EU."}, {"term": "common market", "ipa": "/ˌkɒmən ˈmɑːkɪt/", "pron": "KOM-uhn MAR-kit", "fr": "marché commun", "def": "A market with reduced barriers and shared economic rules between countries.", "ex": "A common market requires more integration than a simple trade agreement."}, {"term": "economic integration", "ipa": "/ˌiːkəˈnɒmɪk ˌɪntɪˈɡreɪʃən/", "pron": "ee-kuh-NOM-ik in-ti-GRAY-shuhn", "fr": "intégration économique", "def": "The process of economies becoming more connected through trade and shared rules.", "ex": "Economic integration can increase efficiency but reduce national autonomy."}, {"term": "trade bloc", "ipa": "/ˈtreɪd blɒk/", "pron": "trade blok", "fr": "bloc commercial", "def": "A group of countries with preferential trade arrangements.", "ex": "The EU and USMCA are major trade blocs."}, {"term": "USMCA", "ipa": "/ˌjuː es em siː ˈeɪ/", "pron": "yoo-ess-em-see-ay", "fr": "USMCA ; accord États-Unis-Mexique-Canada", "def": "The United States-Mexico-Canada Agreement, replacing NAFTA.", "ex": "USMCA governs trade across North America."}, {"term": "NAFTA", "ipa": "/ˈnæftə/", "pron": "NAF-tuh", "fr": "ALENA ; NAFTA", "def": "The North American Free Trade Agreement, replaced by USMCA.", "ex": "NAFTA reshaped manufacturing across North America."}, {"term": "CPTPP", "ipa": "/ˌsiː piː tiː piː ˈpiː/", "pron": "see-pee-tee-pee-pee", "fr": "CPTPP ; accord transpacifique", "def": "A major trade agreement among Pacific-region countries.", "ex": "The UK joined the CPTPP after Brexit."}, {"term": "market access", "ipa": "/ˈmɑːkɪt ˌækses/", "pron": "MAR-kit AK-sess", "fr": "accès au marché", "def": "The ability to sell goods or services in another country’s market.", "ex": "Companies seek market access through trade agreements."}, {"term": "preferential access", "ipa": "/ˌprefəˈrenʃəl ˈækses/", "pron": "pref-uh-REN-shuhl AK-sess", "fr": "accès préférentiel", "def": "Better access to a market than other countries receive.", "ex": "Preferential access can give exporters a competitive advantage."}, {"term": "level playing field", "ipa": "/ˌlevəl ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl PLAY-ing field", "fr": "conditions de concurrence équitables", "def": "Fair competition rules preventing one side from gaining unfair advantage.", "ex": "The EU often insists on level playing field commitments."}, {"term": "fair trade", "ipa": "/ˌfeə ˈtreɪd/", "pron": "fair trade", "fr": "commerce équitable", "def": "Trade based on fair prices, labour rights and ethical standards.", "ex": "Fair trade aims to protect producers in poorer countries."}, {"term": "unfair competition", "ipa": "/ˌʌnfeə ˌkɒmpəˈtɪʃən/", "pron": "un-FAIR kom-puh-TISH-uhn", "fr": "concurrence déloyale", "def": "Competition seen as unjust because of subsidies, dumping or weak standards.", "ex": "Unfair competition is a common argument for protectionism."}, {"term": "comparative advantage", "ipa": "/kəmˌpærətɪv ədˈvɑːntɪdʒ/", "pron": "kuhm-PARR-uh-tiv ad-VAN-tij", "fr": "avantage comparatif", "def": "The ability to produce something at a lower opportunity cost than others.", "ex": "Comparative advantage is a key argument for free trade."}, {"term": "competitive advantage", "ipa": "/kəmˌpetɪtɪv ədˈvɑːntɪdʒ/", "pron": "kuhm-PET-i-tiv ad-VAN-tij", "fr": "avantage concurrentiel", "def": "An advantage that allows a company or country to compete successfully.", "ex": "Skilled workers can give a country a competitive advantage."}, {"term": "specialisation", "ipa": "/ˌspeʃəlaɪˈzeɪʃən/", "pron": "SPESH-uh-ly-ZAY-shuhn", "fr": "spécialisation", "def": "Focusing production on what one does best.", "ex": "Trade encourages countries to specialise."}, {"term": "division of labour", "ipa": "/dɪˌvɪʒən əv ˈleɪbə/", "pron": "di-VIZH-uhn ov LAY-buh", "fr": "division du travail", "def": "The splitting of production into specialised tasks.", "ex": "The division of labour can raise productivity."}, {"term": "economies of scale", "ipa": "/ɪˈkɒnəmiz əv skeɪl/", "pron": "i-KON-uh-meez ov skayl", "fr": "économies d’échelle", "def": "Cost advantages from producing on a larger scale.", "ex": "Global markets help firms achieve economies of scale."}, {"term": "productivity", "ipa": "/ˌprɒdʌkˈtɪvəti/", "pron": "prod-uk-TIV-uh-tee", "fr": "productivité", "def": "Output produced per worker or unit of input.", "ex": "Trade can raise productivity by increasing competition."}]}, {"title": "C. Free trade arguments, industry and supply chains", "entries": [{"term": "competitiveness", "ipa": "/kəmˈpetətɪvnəs/", "pron": "kuhm-PET-uh-tiv-nuhs", "fr": "compétitivité", "def": "The ability to compete successfully in markets.", "ex": "Countries invest in skills to improve competitiveness."}, {"term": "consumer choice", "ipa": "/kənˌsjuːmə ˈtʃɔɪs/", "pron": "kuhn-SYOO-muh choice", "fr": "choix du consommateur", "def": "The range of products available to consumers.", "ex": "Free trade often increases consumer choice."}, {"term": "consumer prices", "ipa": "/kənˌsjuːmə ˈpraɪsɪz/", "pron": "kuhn-SYOO-muh PRY-siz", "fr": "prix à la consommation", "def": "Prices paid by consumers for goods and services.", "ex": "Tariffs can increase consumer prices."}, {"term": "inflationary pressure", "ipa": "/ɪnˌfleɪʃənəri ˈpreʃə/", "pron": "in-FLAY-shuh-nuh-ree PRESH-uh", "fr": "pression inflationniste", "def": "Forces causing prices to rise.", "ex": "Import restrictions can create inflationary pressure."}, {"term": "domestic industry", "ipa": "/dəˌmestɪk ˈɪndəstri/", "pron": "duh-MES-tik IN-duh-stree", "fr": "industrie nationale", "def": "Industry operating within a country.", "ex": "Protectionism is often justified as a way to protect domestic industry."}, {"term": "infant industry", "ipa": "/ˌɪnfənt ˈɪndəstri/", "pron": "IN-fuhnt IN-duh-stree", "fr": "industrie naissante", "def": "A young industry that may need temporary protection to develop.", "ex": "The infant industry argument supports temporary tariffs."}, {"term": "strategic industry", "ipa": "/strəˌtiːdʒɪk ˈɪndəstri/", "pron": "struh-TEE-jik IN-duh-stree", "fr": "industrie stratégique", "def": "An industry considered important for national security or economic sovereignty.", "ex": "Semiconductors are now seen as a strategic industry."}, {"term": "manufacturing", "ipa": "/ˌmænjʊˈfæktʃərɪŋ/", "pron": "man-yuh-FAK-chuh-ring", "fr": "industrie manufacturière", "def": "The production of goods in factories.", "ex": "Manufacturing jobs have declined in many Western countries."}, {"term": "deindustrialisation", "ipa": "/ˌdiːɪnˌdʌstriəlaɪˈzeɪʃən/", "pron": "dee-in-DUS-tree-uh-ly-ZAY-shuhn", "fr": "désindustrialisation", "def": "The decline of industrial activity and manufacturing employment.", "ex": "Deindustrialisation has fuelled support for protectionism."}, {"term": "reshoring", "ipa": "/ˌriːˈʃɔːrɪŋ/", "pron": "ree-SHOR-ing", "fr": "relocalisation", "def": "Bringing production back to the home country.", "ex": "Reshoring is promoted as a way to rebuild domestic industry."}, {"term": "nearshoring", "ipa": "/ˌnɪəˈʃɔːrɪŋ/", "pron": "NEER-SHOR-ing", "fr": "délocalisation de proximité", "def": "Moving production closer to the home market.", "ex": "Nearshoring can reduce supply-chain risks."}, {"term": "offshoring", "ipa": "/ˌɒfˈʃɔːrɪŋ/", "pron": "OFF-SHOR-ing", "fr": "délocalisation", "def": "Moving production or services to another country to reduce costs.", "ex": "Offshoring has lowered costs but displaced some workers."}, {"term": "outsourcing", "ipa": "/ˈaʊtsɔːsɪŋ/", "pron": "OWT-sor-sing", "fr": "externalisation ; sous-traitance", "def": "Contracting work to an outside company, often abroad.", "ex": "Outsourcing can cut costs but weaken job security."}, {"term": "supply chain", "ipa": "/səˈplaɪ tʃeɪn/", "pron": "suh-PLY chayn", "fr": "chaîne d’approvisionnement", "def": "The network of producers, suppliers and transport involved in making and delivering goods.", "ex": "Global supply chains are vulnerable to shocks."}, {"term": "global value chain", "ipa": "/ˌɡləʊbəl ˈvæljuː tʃeɪn/", "pron": "GLOH-buhl VAL-yoo chayn", "fr": "chaîne de valeur mondiale", "def": "The worldwide stages of production that create a product’s value.", "ex": "Global value chains make trade more complex."}, {"term": "supply-chain disruption", "ipa": "/səˈplaɪ tʃeɪn dɪsˌrʌpʃən/", "pron": "suh-PLY chayn dis-RUP-shuhn", "fr": "perturbation de la chaîne d’approvisionnement", "def": "An interruption in the flow of goods, parts or materials.", "ex": "The pandemic caused severe supply-chain disruption."}, {"term": "economic resilience", "ipa": "/ˌiːkəˈnɒmɪk rɪˈzɪliəns/", "pron": "ee-kuh-NOM-ik ri-ZIL-ee-uhns", "fr": "résilience économique", "def": "The ability of an economy to withstand shocks.", "ex": "Resilience has become more important than maximum efficiency."}, {"term": "self-sufficiency", "ipa": "/ˌself səˈfɪʃənsi/", "pron": "self suh-FISH-uhn-see", "fr": "autosuffisance", "def": "The ability to produce what is needed without depending on others.", "ex": "Food and energy self-sufficiency are common protectionist arguments."}, {"term": "economic sovereignty", "ipa": "/ˌiːkəˈnɒmɪk ˈsɒvrənti/", "pron": "ee-kuh-NOM-ik SOV-ruhn-tee", "fr": "souveraineté économique", "def": "A country’s ability to control its own economic choices.", "ex": "Economic sovereignty is often invoked in trade debates."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "The ability to act independently in strategically important areas.", "ex": "The EU has promoted strategic autonomy in response to supply-chain risks."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "The protection of a country’s safety and vital interests.", "ex": "Trade restrictions are increasingly justified by national security."}, {"term": "economic security", "ipa": "/ˌiːkəˈnɒmɪk sɪˈkjʊərəti/", "pron": "ee-kuh-NOM-ik si-KYOOR-uh-tee", "fr": "sécurité économique", "def": "Protection from economic risks, shocks or dependencies.", "ex": "Economic security has become a key policy goal."}, {"term": "trade dependency", "ipa": "/ˈtreɪd dɪˌpendənsi/", "pron": "trade di-PEN-duhn-see", "fr": "dépendance commerciale", "def": "Reliance on another country for trade, goods or inputs.", "ex": "Trade dependency can become a geopolitical vulnerability."}, {"term": "dependency risk", "ipa": "/dɪˈpendənsi rɪsk/", "pron": "di-PEN-duhn-see risk", "fr": "risque de dépendance", "def": "The danger of relying too much on one supplier or country.", "ex": "Dependency risk is high for critical minerals."}, {"term": "critical minerals", "ipa": "/ˌkrɪtɪkəl ˈmɪnərəlz/", "pron": "KRIT-i-kuhl MIN-uh-ruhlz", "fr": "minerais critiques", "def": "Minerals essential for technology, energy or defence.", "ex": "Critical minerals are central to green technology and trade policy."}, {"term": "semiconductors", "ipa": "/ˌsemikənˈdʌktəz/", "pron": "SEM-ee-kuhn-DUK-tuhz", "fr": "semi-conducteurs", "def": "Computer chips used in electronic devices and advanced technology.", "ex": "Semiconductors have become a strategic trade issue."}, {"term": "industrial policy", "ipa": "/ɪnˈdʌstriəl ˌpɒləsi/", "pron": "in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle", "def": "Government strategy to support selected industries or economic sectors.", "ex": "Industrial policy has returned after decades of free-market thinking."}, {"term": "green industrial policy", "ipa": "/ˌɡriːn ɪnˈdʌstriəl ˌpɒləsi/", "pron": "green in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle verte", "def": "Industrial policy supporting clean energy and low-carbon industries.", "ex": "Green industrial policy can create jobs and reduce emissions."}, {"term": "carbon border tax", "ipa": "/ˌkɑːbən ˈbɔːdə tæks/", "pron": "KAR-buhn BOR-duh taks", "fr": "taxe carbone aux frontières", "def": "A tax on imports based on their carbon emissions.", "ex": "A carbon border tax aims to prevent carbon leakage."}, {"term": "carbon leakage", "ipa": "/ˌkɑːbən ˈliːkɪdʒ/", "pron": "KAR-buhn LEE-kij", "fr": "fuite de carbone", "def": "When emissions move abroad because firms relocate to countries with weaker climate rules.", "ex": "Carbon leakage undermines climate policy."}, {"term": "environmental standard", "ipa": "/ɪnˌvaɪrənmentəl ˈstændəd/", "pron": "in-VY-ruhn-men-tuhl STAN-duhd", "fr": "norme environnementale", "def": "A rule protecting the environment in production or trade.", "ex": "Environmental standards can become a source of trade conflict."}, {"term": "labour standard", "ipa": "/ˈleɪbə ˈstændəd/", "pron": "LAY-buh STAN-duhd", "fr": "norme sociale ; norme du travail", "def": "A rule protecting workers’ rights, wages or conditions.", "ex": "Trade agreements increasingly include labour standards."}, {"term": "race to the bottom", "ipa": "/ˌreɪs tə ðə ˈbɒtəm/", "pron": "race tuh thuh BOT-uhm", "fr": "course vers le bas", "def": "Competition that lowers wages, taxes or standards to attract business.", "ex": "Critics of free trade warn about a race to the bottom."}, {"term": "social dumping", "ipa": "/ˈsəʊʃəl ˌdʌmpɪŋ/", "pron": "SOH-shuhl DUMP-ing", "fr": "dumping social", "def": "Competing through lower labour standards or wages.", "ex": "Social dumping is a common concern in European trade debates."}]}, {"title": "D. Economic security, standards and trade balances", "entries": [{"term": "environmental dumping", "ipa": "/ɪnˌvaɪrənmentəl ˈdʌmpɪŋ/", "pron": "in-VY-ruhn-men-tuhl DUMP-ing", "fr": "dumping environnemental", "def": "Competing through weaker environmental rules.", "ex": "Environmental dumping can undermine climate action."}, {"term": "currency manipulation", "ipa": "/ˈkʌrənsi məˌnɪpjʊˈleɪʃən/", "pron": "KUR-uhn-see muh-nip-yuh-LAY-shuhn", "fr": "manipulation monétaire", "def": "Government action to keep a currency artificially cheap to boost exports.", "ex": "Currency manipulation can create unfair trade advantages."}, {"term": "exchange rate", "ipa": "/ɪksˈtʃeɪndʒ reɪt/", "pron": "iks-CHAYNJ rayt", "fr": "taux de change", "def": "The price of one currency in terms of another.", "ex": "Exchange rates affect export competitiveness."}, {"term": "trade balance", "ipa": "/ˈtreɪd ˌbæləns/", "pron": "trade BAL-uhns", "fr": "balance commerciale", "def": "The difference between a country’s exports and imports.", "ex": "A trade balance can be positive or negative."}, {"term": "trade deficit", "ipa": "/ˈtreɪd ˌdefɪsɪt/", "pron": "trade DEF-i-sit", "fr": "déficit commercial", "def": "When a country imports more than it exports.", "ex": "A trade deficit is often politically controversial."}, {"term": "trade surplus", "ipa": "/ˈtreɪd ˌsɜːpləs/", "pron": "trade SUR-pluhs", "fr": "excédent commercial", "def": "When a country exports more than it imports.", "ex": "Germany has often run a trade surplus."}, {"term": "current account", "ipa": "/ˌkʌrənt əˈkaʊnt/", "pron": "KUR-uhnt uh-KOWNT", "fr": "compte courant", "def": "A measure of trade in goods, services, income and transfers with the rest of the world.", "ex": "The current account gives a broader picture than goods trade alone."}, {"term": "exports", "ipa": "/ˈekspɔːts/", "pron": "EK-sports", "fr": "exportations", "def": "Goods or services sold to other countries.", "ex": "Exports support jobs in competitive industries."}, {"term": "imports", "ipa": "/ˈɪmpɔːts/", "pron": "IM-ports", "fr": "importations", "def": "Goods or services bought from other countries.", "ex": "Cheap imports benefit consumers but challenge domestic firms."}, {"term": "export-led growth", "ipa": "/ˈekspɔːt led ɡrəʊθ/", "pron": "EK-sport-led growth", "fr": "croissance tirée par les exportations", "def": "Economic growth driven by selling goods and services abroad.", "ex": "Export-led growth helped several Asian economies develop."}, {"term": "import substitution", "ipa": "/ˈɪmpɔːt ˌsʌbstɪˈtjuːʃən/", "pron": "IM-port sub-sti-TYOO-shuhn", "fr": "substitution aux importations", "def": "A strategy of replacing imports with domestic production.", "ex": "Import substitution was used by many developing countries."}, {"term": "trade openness", "ipa": "/ˈtreɪd ˌəʊpənnəs/", "pron": "trade OH-puhn-nuhs", "fr": "ouverture commerciale", "def": "The degree to which an economy is open to international trade.", "ex": "Trade openness can boost growth but increase vulnerability."}, {"term": "economic interdependence", "ipa": "/ˌiːkəˈnɒmɪk ˌɪntədɪˈpendəns/", "pron": "ee-kuh-NOM-ik in-tuh-di-PEN-duhns", "fr": "interdépendance économique", "def": "A situation where economies rely on each other.", "ex": "Economic interdependence can promote peace or create vulnerabilities."}, {"term": "decoupling", "ipa": "/ˌdiːˈkʌplɪŋ/", "pron": "dee-KUP-ling", "fr": "découplage", "def": "The separation of economies or supply chains that were previously connected.", "ex": "US-China decoupling would reshape global trade."}, {"term": "de-risking", "ipa": "/ˌdiːˈrɪskɪŋ/", "pron": "dee-RISK-ing", "fr": "réduction des risques ; dérisquage", "def": "Reducing risky dependencies without fully cutting ties.", "ex": "The EU prefers de-risking to full decoupling from China."}, {"term": "friend-shoring", "ipa": "/ˌfrend ˈʃɔːrɪŋ/", "pron": "friend-SHOR-ing", "fr": "relocalisation chez des pays alliés", "def": "Shifting supply chains to politically allied or trusted countries.", "ex": "Friend-shoring aims to reduce geopolitical risk."}, {"term": "trade sanctions", "ipa": "/ˈtreɪd ˌsæŋkʃənz/", "pron": "trade SANK-shuhnz", "fr": "sanctions commerciales", "def": "Restrictions on trade used to pressure a country politically.", "ex": "Trade sanctions are used as a foreign policy tool."}, {"term": "embargo", "ipa": "/ɪmˈbɑːɡəʊ/", "pron": "im-BAR-goh", "fr": "embargo", "def": "A ban on trade with a country or on a product.", "ex": "An embargo can isolate a target country economically."}, {"term": "export control", "ipa": "/ˈekspɔːt kənˌtrəʊl/", "pron": "EK-sport kuhn-TROHL", "fr": "contrôle des exportations", "def": "A restriction on selling certain goods or technologies abroad.", "ex": "Export controls are used for advanced chips and military technology."}, {"term": "dual-use technology", "ipa": "/ˌdjuːəl juːs tekˈnɒlədʒi/", "pron": "DYOO-uhl yooss tek-NOL-uh-jee", "fr": "technologie à double usage", "def": "Technology with both civilian and military uses.", "ex": "Dual-use technology is often subject to export controls."}, {"term": "geoeconomics", "ipa": "/ˌdʒiːəʊ iːkəˈnɒmɪks/", "pron": "jee-oh ee-kuh-NOM-iks", "fr": "géoéconomie", "def": "The use of economic tools for geopolitical power.", "ex": "Geoeconomics has become central to trade policy."}, {"term": "economic nationalism", "ipa": "/ˌiːkəˈnɒmɪk ˈnæʃənəlɪzəm/", "pron": "ee-kuh-NOM-ik NASH-uh-nuh-liz-uhm", "fr": "nationalisme économique", "def": "Policies prioritising national economic interests over global openness.", "ex": "Economic nationalism has fuelled protectionist policies."}, {"term": "America First", "ipa": "/əˌmerɪkə ˈfɜːst/", "pron": "uh-MERR-i-kuh first", "fr": "America First", "def": "A US political slogan prioritising American interests in trade and foreign policy.", "ex": "America First rhetoric challenged free-trade orthodoxy."}, {"term": "Buy American", "ipa": "/ˌbaɪ əˈmerɪkən/", "pron": "by uh-MERR-i-kuhn", "fr": "Buy American ; acheter américain", "def": "Policies encouraging or requiring purchase of US-made goods.", "ex": "Buy American rules support domestic producers."}, {"term": "Made in China 2025", "ipa": "/ˌmeɪd ɪn ˈtʃaɪnə ˌtwenti ˌtwenti ˈfaɪv/", "pron": "made in CHY-nuh twenty twenty five", "fr": "Made in China 2025", "def": "A Chinese industrial strategy to upgrade high-tech manufacturing.", "ex": "Made in China 2025 raised concerns in Western countries."}, {"term": "Belt and Road Initiative", "ipa": "/ˌbelt ənd ˈrəʊd ɪˌnɪʃətɪv/", "pron": "belt and rohd i-NISH-uh-tiv", "fr": "Nouvelles routes de la soie", "def": "China’s global infrastructure and trade investment strategy.", "ex": "The Belt and Road Initiative expands China’s economic influence."}, {"term": "to trade with", "ipa": "/treɪd wɪð/", "pron": "trade with", "fr": "commercer avec", "def": "To buy and sell goods or services with another country or company.", "ex": "Britain trades heavily with the European Union."}, {"term": "to export goods", "ipa": "/ekˈspɔːt ɡʊdz/", "pron": "ek-SPORT goods", "fr": "exporter des biens", "def": "To sell goods to another country.", "ex": "Manufacturers export goods to global markets."}, {"term": "to import goods", "ipa": "/ɪmˈpɔːt ɡʊdz/", "pron": "im-PORT goods", "fr": "importer des biens", "def": "To buy goods from another country.", "ex": "Consumers benefit when firms import goods cheaply."}, {"term": "to impose tariffs", "ipa": "/ɪmˈpəʊz ˈtærɪfs/", "pron": "im-POHZ TAR-ifs", "fr": "imposer des droits de douane", "def": "To put taxes on imports.", "ex": "Governments impose tariffs to protect domestic industries."}, {"term": "to lift tariffs", "ipa": "/lɪft ˈtærɪfs/", "pron": "lift TAR-ifs", "fr": "supprimer des droits de douane", "def": "To remove tariffs.", "ex": "A trade deal can lift tariffs on key products."}, {"term": "to raise tariffs", "ipa": "/reɪz ˈtærɪfs/", "pron": "rayz TAR-ifs", "fr": "augmenter les droits de douane", "def": "To increase taxes on imports.", "ex": "Raising tariffs can provoke retaliation."}, {"term": "to remove trade barriers", "ipa": "/rɪˈmuːv ˈtreɪd ˌbæriəz/", "pron": "ri-MOOV trade BARR-ee-uhz", "fr": "supprimer les barrières commerciales", "def": "To reduce or eliminate obstacles to trade.", "ex": "Free trade agreements remove trade barriers."}, {"term": "to protect domestic industry", "ipa": "/prəˈtekt dəˌmestɪk ˈɪndəstri/", "pron": "pruh-TEKT duh-MES-tik IN-duh-stree", "fr": "protéger l’industrie nationale", "def": "To defend national firms from foreign competition.", "ex": "Tariffs are often used to protect domestic industry."}]}, {"title": "E. Geopolitics, sanctions and high-value verbs", "entries": [{"term": "to shield jobs from competition", "ipa": "/ʃiːld dʒɒbz frəm ˌkɒmpəˈtɪʃən/", "pron": "sheeld jobz from kom-puh-TISH-uhn", "fr": "protéger les emplois de la concurrence", "def": "To protect employment from foreign rivals.", "ex": "Protectionists claim tariffs shield jobs from competition."}, {"term": "to distort competition", "ipa": "/dɪˈstɔːt ˌkɒmpəˈtɪʃən/", "pron": "di-STORE kom-puh-TISH-uhn", "fr": "fausser la concurrence", "def": "To make competition unfair or inefficient.", "ex": "Subsidies can distort competition."}, {"term": "to open up markets", "ipa": "/ˈəʊpən ʌp ˈmɑːkɪts/", "pron": "OH-puhn up MAR-kits", "fr": "ouvrir les marchés", "def": "To make markets accessible to foreign goods or firms.", "ex": "Trade agreements open up markets for exporters."}, {"term": "to retaliate", "ipa": "/rɪˈtælieɪt/", "pron": "ri-TAL-ee-ayt", "fr": "riposter ; prendre des représailles", "def": "To respond to another country’s trade restriction with similar action.", "ex": "Countries may retaliate when tariffs are imposed."}, {"term": "to trigger a trade war", "ipa": "/ˈtrɪɡə ə ˈtreɪd wɔː/", "pron": "TRIG-uh uh trade war", "fr": "déclencher une guerre commerciale", "def": "To start a cycle of retaliatory trade restrictions.", "ex": "Tariffs can trigger a trade war."}, {"term": "to disrupt supply chains", "ipa": "/dɪsˈrʌpt səˈplaɪ tʃeɪnz/", "pron": "dis-RUPT suh-PLY chaynz", "fr": "perturber les chaînes d’approvisionnement", "def": "To interrupt the flow of goods, parts or materials.", "ex": "Trade restrictions can disrupt supply chains."}, {"term": "to reduce dependency", "ipa": "/rɪˈdjuːs dɪˈpendənsi/", "pron": "ri-DYOOSS di-PEN-duhn-see", "fr": "réduire la dépendance", "def": "To become less reliant on another country or supplier.", "ex": "Governments want to reduce dependency on strategic rivals."}, {"term": "to strengthen economic resilience", "ipa": "/ˈstreŋθən ˌiːkəˈnɒmɪk rɪˈzɪliəns/", "pron": "STRENG-thuhn ee-kuh-NOM-ik ri-ZIL-ee-uhns", "fr": "renforcer la résilience économique", "def": "To make the economy better able to withstand shocks.", "ex": "Diversified supply chains strengthen economic resilience."}, {"term": "to pursue strategic autonomy", "ipa": "/pəˈsjuː strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "puh-SYOO struh-TEE-jik aw-TON-uh-mee", "fr": "poursuivre l’autonomie stratégique", "def": "To seek independent capacity in key economic or security areas.", "ex": "The EU aims to pursue strategic autonomy in key technologies."}, {"term": "to balance openness and security", "ipa": "/ˈbæləns ˈəʊpənnəs ənd sɪˈkjʊərəti/", "pron": "BAL-uhns OH-puhn-nuhs and si-KYOOR-uh-tee", "fr": "équilibrer ouverture et sécurité", "def": "To combine free trade with protection against strategic risks.", "ex": "Modern trade policy must balance openness and security."}]}]}, {"id": "p5c45", "part": 5, "chapter": 45, "title": "Public Debt", "file": "cpge_vocab_part5_chapter45_public_debt_premium.html", "count": 128, "sections": [{"title": "A. Core public debt and deficit vocabulary", "entries": [{"term": "public debt", "ipa": "/ˌpʌblɪk ˈdet/", "pron": "PUB-lik det", "fr": "dette publique", "def": "Money owed by the government to creditors.", "ex": "Public debt rises when governments borrow to finance deficits."}, {"term": "government debt", "ipa": "/ˈɡʌvənmənt det/", "pron": "GUV-uhn-muhnt det", "fr": "dette de l’État", "def": "Debt owed by the state or public authorities.", "ex": "Government debt increased after the financial crisis and the pandemic."}, {"term": "national debt", "ipa": "/ˌnæʃənəl ˈdet/", "pron": "NASH-uh-nuhl det", "fr": "dette nationale", "def": "The total debt owed by a national government.", "ex": "The national debt is often used as a political argument."}, {"term": "sovereign debt", "ipa": "/ˌsɒvrɪn ˈdet/", "pron": "SOV-rin det", "fr": "dette souveraine", "def": "Debt issued by a national government.", "ex": "A sovereign debt crisis can threaten financial stability."}, {"term": "debt stock", "ipa": "/ˈdet stɒk/", "pron": "det stok", "fr": "stock de dette", "def": "The total accumulated amount of debt at a given time.", "ex": "The debt stock reflects years of past borrowing."}, {"term": "debt burden", "ipa": "/ˈdet ˌbɜːdən/", "pron": "det BUR-duhn", "fr": "fardeau de la dette", "def": "The pressure created by having to repay or service debt.", "ex": "A high debt burden can limit public investment."}, {"term": "debt level", "ipa": "/ˈdet ˌlevəl/", "pron": "det LEV-uhl", "fr": "niveau de dette", "def": "The amount of debt owed.", "ex": "Debt levels vary widely between countries."}, {"term": "debt-to-GDP ratio", "ipa": "/ˌdet tə ˌdʒiː diː ˈpiː ˈreɪʃiəʊ/", "pron": "det-tuh-jee-dee-pee RAY-shee-oh", "fr": "ratio dette/PIB", "def": "Public debt expressed as a percentage of GDP.", "ex": "The debt-to-GDP ratio is a key measure of debt sustainability."}, {"term": "GDP", "ipa": "/ˌdʒiː diː ˈpiː/", "pron": "jee-dee-pee", "fr": "PIB", "def": "Gross Domestic Product: the total value of goods and services produced in a country.", "ex": "Public debt is often compared to GDP."}, {"term": "budget deficit", "ipa": "/ˌbʌdʒɪt ˈdefɪsɪt/", "pron": "BUJ-it DEF-i-sit", "fr": "déficit budgétaire", "def": "A situation where government spending exceeds revenue.", "ex": "A budget deficit adds to public debt."}, {"term": "fiscal deficit", "ipa": "/ˌfɪskəl ˈdefɪsɪt/", "pron": "FIS-kuhl DEF-i-sit", "fr": "déficit public", "def": "The shortfall between government revenue and spending.", "ex": "Persistent fiscal deficits increase debt over time."}, {"term": "primary deficit", "ipa": "/ˌpraɪməri ˈdefɪsɪt/", "pron": "PRY-muh-ree DEF-i-sit", "fr": "déficit primaire", "def": "A deficit excluding interest payments on existing debt.", "ex": "A primary deficit means the government borrows even before interest payments."}, {"term": "primary surplus", "ipa": "/ˌpraɪməri ˈsɜːpləs/", "pron": "PRY-muh-ree SUR-pluhs", "fr": "excédent primaire", "def": "A surplus before interest payments are included.", "ex": "A primary surplus can help stabilise debt."}, {"term": "budget surplus", "ipa": "/ˈbʌdʒɪt ˌsɜːpləs/", "pron": "BUJ-it SUR-pluhs", "fr": "excédent budgétaire", "def": "A situation where government revenue exceeds spending.", "ex": "A budget surplus can reduce debt."}, {"term": "balanced budget", "ipa": "/ˌbælənst ˈbʌdʒɪt/", "pron": "BAL-uhnst BUJ-it", "fr": "budget équilibré", "def": "A budget where spending equals revenue.", "ex": "A balanced budget is difficult during recessions."}, {"term": "public finances", "ipa": "/ˌpʌblɪk ˈfaɪnænsɪz/", "pron": "PUB-lik FY-nan-siz", "fr": "finances publiques", "def": "Government revenue, spending, borrowing and debt.", "ex": "Public finances are strained by ageing populations."}, {"term": "government borrowing", "ipa": "/ˈɡʌvənmənt ˈbɒrəʊɪŋ/", "pron": "GUV-uhn-muhnt BOR-oh-ing", "fr": "emprunt public", "def": "Money borrowed by the government to finance spending.", "ex": "Government borrowing usually rises in crises."}, {"term": "public borrowing", "ipa": "/ˌpʌblɪk ˈbɒrəʊɪŋ/", "pron": "PUB-lik BOR-oh-ing", "fr": "emprunt public", "def": "Borrowing by the public sector.", "ex": "Public borrowing can finance infrastructure or emergency support."}, {"term": "debt issuance", "ipa": "/ˈdet ˌɪʃuːəns/", "pron": "det ISH-oo-uhns", "fr": "émission de dette", "def": "The process of selling new government debt securities.", "ex": "Debt issuance increases when deficits are high."}, {"term": "bond", "ipa": "/bɒnd/", "pron": "bond", "fr": "obligation", "def": "A financial security representing a loan to a government or company.", "ex": "Governments sell bonds to borrow money."}, {"term": "government bond", "ipa": "/ˈɡʌvənmənt bɒnd/", "pron": "GUV-uhn-muhnt bond", "fr": "obligation d’État", "def": "A bond issued by a government.", "ex": "Government bonds are usually seen as safe assets."}, {"term": "sovereign bond", "ipa": "/ˌsɒvrɪn ˈbɒnd/", "pron": "SOV-rin bond", "fr": "obligation souveraine", "def": "A bond issued by a national government.", "ex": "Sovereign bonds are bought by investors worldwide."}]}, {"title": "B. Bonds, interest rates and debt servicing", "entries": [{"term": "Treasury bond", "ipa": "/ˈtreʒəri bɒnd/", "pron": "TREZH-uh-ree bond", "fr": "obligation du Trésor américain", "def": "A US government bond with a long maturity.", "ex": "Treasury bonds are central to global finance."}, {"term": "gilt", "ipa": "/ɡɪlt/", "pron": "gilt", "fr": "obligation d’État britannique", "def": "A UK government bond.", "ex": "Gilt yields rose during market turmoil."}, {"term": "bond market", "ipa": "/ˈbɒnd ˌmɑːkɪt/", "pron": "bond MAR-kit", "fr": "marché obligataire", "def": "The market where bonds are bought and sold.", "ex": "Bond markets judge the credibility of fiscal policy."}, {"term": "bond yield", "ipa": "/ˈbɒnd jiːld/", "pron": "bond yeeld", "fr": "rendement obligataire", "def": "The return investors receive on a bond.", "ex": "Bond yields rise when investors demand higher returns."}, {"term": "yield", "ipa": "/jiːld/", "pron": "yeeld", "fr": "rendement", "def": "The return on an investment, especially a bond.", "ex": "Higher yields make borrowing more expensive."}, {"term": "maturity", "ipa": "/məˈtjʊərəti/", "pron": "muh-TYOOR-uh-tee", "fr": "échéance", "def": "The date when a debt must be repaid.", "ex": "Longer maturity can reduce refinancing risk."}, {"term": "short-term debt", "ipa": "/ˌʃɔːt tɜːm ˈdet/", "pron": "short-term det", "fr": "dette à court terme", "def": "Debt that must be repaid soon.", "ex": "Short-term debt exposes governments to refinancing risk."}, {"term": "long-term debt", "ipa": "/ˌlɒŋ tɜːm ˈdet/", "pron": "long-term det", "fr": "dette à long terme", "def": "Debt with a long repayment period.", "ex": "Long-term debt gives governments more time to repay."}, {"term": "interest rate", "ipa": "/ˈɪntrəst reɪt/", "pron": "IN-truhst rayt", "fr": "taux d’intérêt", "def": "The cost of borrowing money.", "ex": "Higher interest rates increase debt-servicing costs."}, {"term": "debt servicing", "ipa": "/ˈdet ˌsɜːvɪsɪŋ/", "pron": "det SUR-vis-ing", "fr": "service de la dette", "def": "Paying interest and repayments on debt.", "ex": "Debt servicing can crowd out other spending."}, {"term": "interest payments", "ipa": "/ˈɪntrəst ˈpeɪmənts/", "pron": "IN-truhst PAY-muhnts", "fr": "paiements d’intérêts", "def": "Money paid as interest on borrowed funds.", "ex": "Interest payments reduce fiscal space."}, {"term": "debt service", "ipa": "/ˈdet ˌsɜːvɪs/", "pron": "det SUR-vis", "fr": "service de la dette", "def": "The total payments due on debt, including interest and principal.", "ex": "Debt service can become unsustainable for poor countries."}, {"term": "borrowing costs", "ipa": "/ˈbɒrəʊɪŋ kɒsts/", "pron": "BOR-oh-ing kosts", "fr": "coût de l’emprunt", "def": "The cost of borrowing, usually through interest rates.", "ex": "Borrowing costs rise when markets lose confidence."}, {"term": "risk premium", "ipa": "/ˈrɪsk ˌpriːmiəm/", "pron": "risk PREE-mee-uhm", "fr": "prime de risque", "def": "Extra return demanded by investors for taking risk.", "ex": "A higher risk premium increases bond yields."}, {"term": "credit rating", "ipa": "/ˈkredɪt ˌreɪtɪŋ/", "pron": "KRED-it RAY-ting", "fr": "notation de crédit", "def": "An assessment of a borrower’s ability to repay debt.", "ex": "A downgrade in credit rating can raise borrowing costs."}, {"term": "credit rating agency", "ipa": "/ˈkredɪt ˌreɪtɪŋ ˈeɪdʒənsi/", "pron": "KRED-it RAY-ting AY-juhn-see", "fr": "agence de notation", "def": "A company that assesses credit risk.", "ex": "Credit rating agencies influence investor confidence."}, {"term": "downgrade", "ipa": "/ˈdaʊnɡreɪd/", "pron": "DOWN-grayd", "fr": "dégradation de notation", "def": "A reduction in a borrower’s credit rating.", "ex": "A downgrade may alarm financial markets."}, {"term": "default", "ipa": "/dɪˈfɔːlt/", "pron": "di-FAWLT", "fr": "défaut de paiement", "def": "Failure to repay debt as agreed.", "ex": "A sovereign default can trigger financial panic."}, {"term": "sovereign default", "ipa": "/ˌsɒvrɪn dɪˈfɔːlt/", "pron": "SOV-rin di-FAWLT", "fr": "défaut souverain", "def": "A government’s failure to repay its debt.", "ex": "Sovereign default damages a country’s reputation."}, {"term": "debt restructuring", "ipa": "/ˈdet riːˌstrʌktʃərɪŋ/", "pron": "det ree-STRUK-chuh-ring", "fr": "restructuration de dette", "def": "Changing debt terms to make repayment easier.", "ex": "Debt restructuring may involve lower interest rates or longer maturities."}, {"term": "debt relief", "ipa": "/ˈdet rɪˌliːf/", "pron": "det ri-LEEF", "fr": "allègement de dette", "def": "Reduction or cancellation of debt to ease pressure on a borrower.", "ex": "Debt relief can help highly indebted poor countries."}, {"term": "debt cancellation", "ipa": "/ˈdet ˌkænsəˈleɪʃən/", "pron": "det kan-suh-LAY-shuhn", "fr": "annulation de dette", "def": "The cancellation of part or all of a debt.", "ex": "Debt cancellation is demanded by some campaigners."}, {"term": "debt forgiveness", "ipa": "/ˈdet fəˌɡɪvnəs/", "pron": "det fuh-GIV-nuhs", "fr": "remise de dette", "def": "A creditor’s decision not to require repayment.", "ex": "Debt forgiveness can give countries a fresh start."}, {"term": "bailout", "ipa": "/ˈbeɪlaʊt/", "pron": "BAYL-owt", "fr": "plan de sauvetage", "def": "Financial rescue of a country, bank or company in difficulty.", "ex": "A bailout may come with strict conditions."}, {"term": "rescue package", "ipa": "/ˈreskjuː ˌpækɪdʒ/", "pron": "RES-kyoo PAK-ij", "fr": "plan d’aide", "def": "Financial assistance designed to prevent collapse.", "ex": "The rescue package prevented immediate default."}, {"term": "IMF programme", "ipa": "/ˌaɪ em ˈef ˈprəʊɡræm/", "pron": "eye-em-eff PROH-gram", "fr": "programme du FMI", "def": "A financial assistance programme run by the International Monetary Fund.", "ex": "An IMF programme often requires reforms."}]}, {"title": "C. Crises, bailouts, austerity and sustainability", "entries": [{"term": "conditionality", "ipa": "/kənˌdɪʃəˈnæləti/", "pron": "kuhn-dish-uh-NAL-uh-tee", "fr": "conditionnalité", "def": "Conditions attached to loans or financial assistance.", "ex": "IMF conditionality is controversial."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies reducing public spending or deficits.", "ex": "Austerity can reduce deficits but damage public services."}, {"term": "spending cuts", "ipa": "/ˈspendɪŋ kʌts/", "pron": "SPEN-ding kuts", "fr": "coupes budgétaires", "def": "Reductions in government spending.", "ex": "Spending cuts are often unpopular."}, {"term": "tax rises", "ipa": "/ˈtæks ˌraɪzɪz/", "pron": "taks RY-ziz", "fr": "hausses d’impôts", "def": "Increases in taxes.", "ex": "Tax rises can improve public finances but hurt households."}, {"term": "fiscal consolidation", "ipa": "/ˌfɪskəl kənˌsɒlɪˈdeɪʃən/", "pron": "FIS-kuhl kuhn-sol-i-DAY-shuhn", "fr": "assainissement budgétaire", "def": "Policy aimed at reducing deficits and stabilising debt.", "ex": "Fiscal consolidation can combine tax increases and spending cuts."}, {"term": "fiscal discipline", "ipa": "/ˌfɪskəl ˈdɪsəplɪn/", "pron": "FIS-kuhl DIS-uh-plin", "fr": "discipline budgétaire", "def": "Control of government spending and borrowing.", "ex": "Markets reward fiscal discipline with lower borrowing costs."}, {"term": "fiscal responsibility", "ipa": "/ˌfɪskəl rɪˌspɒnsəˈbɪləti/", "pron": "FIS-kuhl ri-spon-suh-BIL-uh-tee", "fr": "responsabilité budgétaire", "def": "Responsible management of public finances.", "ex": "Politicians often promise fiscal responsibility."}, {"term": "fiscal rule", "ipa": "/ˈfɪskəl ruːl/", "pron": "FIS-kuhl rool", "fr": "règle budgétaire", "def": "A rule limiting deficits, debt or spending.", "ex": "Fiscal rules aim to prevent excessive borrowing."}, {"term": "debt ceiling", "ipa": "/ˈdet ˌsiːlɪŋ/", "pron": "det SEE-ling", "fr": "plafond de la dette", "def": "A legal limit on how much debt a government can issue.", "ex": "The US debt ceiling regularly causes political conflict."}, {"term": "fiscal space", "ipa": "/ˈfɪskəl speɪs/", "pron": "FIS-kuhl space", "fr": "marge de manœuvre budgétaire", "def": "Room a government has to spend or borrow without risking sustainability.", "ex": "High debt reduces fiscal space."}, {"term": "debt sustainability", "ipa": "/ˈdet səˌsteɪnəˈbɪləti/", "pron": "det suh-stay-nuh-BIL-uh-tee", "fr": "soutenabilité de la dette", "def": "The ability to manage debt without default or crisis.", "ex": "Debt sustainability depends on growth, interest rates and deficits."}, {"term": "fiscal sustainability", "ipa": "/ˈfɪskəl səˌsteɪnəˈbɪləti/", "pron": "FIS-kuhl suh-stay-nuh-BIL-uh-tee", "fr": "soutenabilité budgétaire", "def": "The ability to maintain public finances over time.", "ex": "Ageing populations threaten fiscal sustainability."}, {"term": "sustainable debt", "ipa": "/səˌsteɪnəbəl ˈdet/", "pron": "suh-STAY-nuh-buhl det", "fr": "dette soutenable", "def": "Debt that can be serviced without crisis or excessive cuts.", "ex": "Debt can be high but sustainable if growth is strong."}, {"term": "unsustainable debt", "ipa": "/ˌʌnsəˌsteɪnəbəl ˈdet/", "pron": "un-suh-STAY-nuh-buhl det", "fr": "dette insoutenable", "def": "Debt that cannot be managed without major adjustment or default.", "ex": "Unsustainable debt can trigger a crisis."}, {"term": "debt spiral", "ipa": "/ˈdet ˌspaɪrəl/", "pron": "det SPY-ruhl", "fr": "spirale de la dette", "def": "A self-reinforcing rise in debt due to interest and deficits.", "ex": "A debt spiral becomes difficult to escape."}, {"term": "snowball effect", "ipa": "/ˈsnəʊbɔːl ɪˌfekt/", "pron": "SNOH-ball i-FEKT", "fr": "effet boule de neige", "def": "A process where debt grows because interest adds to existing debt.", "ex": "The snowball effect worsens when interest rates exceed growth."}, {"term": "interest-growth differential", "ipa": "/ˈɪntrəst ɡrəʊθ ˌdɪfəˈrenʃəl/", "pron": "IN-truhst-growth dif-uh-REN-shuhl", "fr": "différentiel intérêt-croissance", "def": "The difference between the interest rate on debt and the economy’s growth rate.", "ex": "Debt is easier to manage when growth exceeds interest rates."}, {"term": "economic growth", "ipa": "/ˌiːkəˈnɒmɪk ɡrəʊθ/", "pron": "ee-kuh-NOM-ik growth", "fr": "croissance économique", "def": "An increase in economic output.", "ex": "Economic growth helps reduce the debt-to-GDP ratio."}, {"term": "inflation", "ipa": "/ɪnˈfleɪʃən/", "pron": "in-FLAY-shuhn", "fr": "inflation", "def": "A general rise in prices.", "ex": "Moderate inflation can reduce the real value of debt."}, {"term": "real value of debt", "ipa": "/ˌrɪəl ˈvæljuː əv det/", "pron": "REE-uhl VAL-yoo ov det", "fr": "valeur réelle de la dette", "def": "Debt value after adjusting for inflation.", "ex": "Inflation reduces the real value of fixed-rate debt."}, {"term": "monetisation of debt", "ipa": "/ˌmʌnɪtaɪˈzeɪʃən əv det/", "pron": "mun-i-ty-ZAY-shuhn ov det", "fr": "monétisation de la dette", "def": "Financing government debt by creating money.", "ex": "Monetisation of debt can risk inflation."}, {"term": "central bank financing", "ipa": "/ˌsentrəl bæŋk ˈfaɪnænsɪŋ/", "pron": "SEN-truhl bank FY-nan-sing", "fr": "financement par la banque centrale", "def": "Financing government spending through the central bank.", "ex": "Central bank financing is controversial."}, {"term": "quantitative easing", "ipa": "/ˌkwɒntɪtətɪv ˈiːzɪŋ/", "pron": "KWON-ti-tuh-tiv EE-zing", "fr": "assouplissement quantitatif", "def": "Central bank purchases of assets to inject money into the economy.", "ex": "Quantitative easing lowered government borrowing costs."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on taxation, spending and borrowing.", "ex": "Fiscal policy can support the economy during recessions."}, {"term": "monetary policy", "ipa": "/ˈmʌnɪtəri ˈpɒləsi/", "pron": "MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire", "def": "Central bank policy affecting interest rates and money supply.", "ex": "Monetary policy affects debt-servicing costs."}, {"term": "countercyclical policy", "ipa": "/ˌkaʊntəˈsɪklɪkəl ˈpɒləsi/", "pron": "KOWN-tuh-SIK-li-kuhl POL-uh-see", "fr": "politique contracyclique", "def": "Policy that supports the economy in downturns and restrains it in booms.", "ex": "Borrowing during recessions can be countercyclical."}, {"term": "automatic stabilisers", "ipa": "/ˌɔːtəmætɪk ˈsteɪbəlaɪzəz/", "pron": "aw-tuh-MAT-ik STAY-buh-ly-zuhz", "fr": "stabilisateurs automatiques", "def": "Taxes and benefits that automatically stabilise the economy during cycles.", "ex": "Automatic stabilisers increase deficits during downturns."}, {"term": "stimulus package", "ipa": "/ˈstɪmjʊləs ˌpækɪdʒ/", "pron": "STIM-yuh-luhs PAK-ij", "fr": "plan de relance", "def": "Government measures designed to boost economic activity.", "ex": "A stimulus package may require borrowing."}, {"term": "public investment", "ipa": "/ˌpʌblɪk ɪnˈvestmənt/", "pron": "PUB-lik in-VEST-muhnt", "fr": "investissement public", "def": "Government spending on long-term assets such as infrastructure or education.", "ex": "Debt-financed public investment can raise growth."}, {"term": "capital expenditure", "ipa": "/ˌkæpɪtəl ɪkˈspendɪtʃə/", "pron": "KAP-i-tuhl ik-SPEN-di-chuh", "fr": "dépenses d’investissement", "def": "Spending on long-term assets.", "ex": "Capital expenditure can support future productivity."}, {"term": "current expenditure", "ipa": "/ˌkʌrənt ɪkˈspendɪtʃə/", "pron": "KUR-uhnt ik-SPEN-di-chuh", "fr": "dépenses courantes", "def": "Day-to-day government spending.", "ex": "Current expenditure includes salaries and benefits."}, {"term": "welfare spending", "ipa": "/ˈwelfeə ˈspendɪŋ/", "pron": "WEL-fair SPEN-ding", "fr": "dépenses sociales", "def": "Government spending on social protection and benefits.", "ex": "Welfare spending rises during crises."}, {"term": "healthcare spending", "ipa": "/ˈhelθkeə ˈspendɪŋ/", "pron": "HELTH-care SPEN-ding", "fr": "dépenses de santé", "def": "Government or total spending on healthcare.", "ex": "Healthcare spending rises as populations age."}, {"term": "pension spending", "ipa": "/ˈpenʃən ˈspendɪŋ/", "pron": "PEN-shuhn SPEN-ding", "fr": "dépenses de retraite", "def": "Government spending on pensions.", "ex": "Pension spending puts pressure on budgets."}]}, {"title": "D. Fiscal policy, spending, taxation and public finance debates", "entries": [{"term": "military spending", "ipa": "/ˈmɪlɪtəri ˈspendɪŋ/", "pron": "MIL-i-tuh-ree SPEN-ding", "fr": "dépenses militaires", "def": "Government spending on defence.", "ex": "Military spending can increase public borrowing."}, {"term": "tax revenue", "ipa": "/ˈtæks ˌrevənjuː/", "pron": "taks REV-uhn-yoo", "fr": "recettes fiscales", "def": "Money collected by the state through taxes.", "ex": "Growth increases tax revenue."}, {"term": "tax base", "ipa": "/ˈtæks beɪs/", "pron": "taks bays", "fr": "assiette fiscale", "def": "The income, wealth or activity that can be taxed.", "ex": "A shrinking workforce weakens the tax base."}, {"term": "revenue shortfall", "ipa": "/ˈrevənjuː ˌʃɔːtfɔːl/", "pron": "REV-uhn-yoo SHORT-fawl", "fr": "manque à gagner fiscal", "def": "When tax revenue is lower than expected or needed.", "ex": "A revenue shortfall can widen the deficit."}, {"term": "tax evasion", "ipa": "/ˈtæks ɪˌveɪʒən/", "pron": "taks i-VAY-zhuhn", "fr": "fraude fiscale", "def": "Illegal non-payment or underpayment of taxes.", "ex": "Tax evasion reduces public revenue."}, {"term": "tax avoidance", "ipa": "/ˈtæks əˌvɔɪdəns/", "pron": "taks uh-VOY-duhns", "fr": "optimisation fiscale", "def": "Legal but controversial reduction of tax payments.", "ex": "Tax avoidance by multinationals weakens public finances."}, {"term": "crowding out", "ipa": "/ˌkraʊdɪŋ ˈaʊt/", "pron": "KROW-ding out", "fr": "effet d’éviction", "def": "When government borrowing reduces private investment by raising interest rates.", "ex": "Critics argue that public debt can crowd out private investment."}, {"term": "crowding in", "ipa": "/ˌkraʊdɪŋ ˈɪn/", "pron": "KROW-ding in", "fr": "effet d’entraînement", "def": "When public spending stimulates private investment.", "ex": "Infrastructure investment can crowd in private investment."}, {"term": "intergenerational fairness", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈfeənəs/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl FAIR-nuhs", "fr": "équité intergénérationnelle", "def": "Fairness between generations in costs, benefits and obligations.", "ex": "Public debt raises questions of intergenerational fairness."}, {"term": "intergenerational burden", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈbɜːdən/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl BUR-duhn", "fr": "fardeau intergénérationnel", "def": "A cost passed from one generation to another.", "ex": "Future taxpayers may inherit an intergenerational burden."}, {"term": "future generations", "ipa": "/ˌfjuːtʃə ˌdʒenəˈreɪʃənz/", "pron": "FYOO-chuh jen-uh-RAY-shuhnz", "fr": "générations futures", "def": "People who will live in the future.", "ex": "Borrowing for investment can benefit future generations."}, {"term": "fiscal illusion", "ipa": "/ˌfɪskəl ɪˈluːʒən/", "pron": "FIS-kuhl i-LOO-zhuhn", "fr": "illusion fiscale", "def": "When voters underestimate the real cost of public spending or debt.", "ex": "Fiscal illusion can encourage irresponsible borrowing."}, {"term": "moral hazard", "ipa": "/ˌmɒrəl ˈhæzəd/", "pron": "MOR-uhl HAZ-uhd", "fr": "aléa moral", "def": "A situation where protection from risk encourages risky behaviour.", "ex": "Bailouts can create moral hazard."}, {"term": "market confidence", "ipa": "/ˈmɑːkɪt ˈkɒnfɪdəns/", "pron": "MAR-kit KON-fi-duhns", "fr": "confiance des marchés", "def": "Trust by investors in a country’s economic management.", "ex": "Market confidence can collapse quickly."}, {"term": "investor confidence", "ipa": "/ɪnˌvestə ˈkɒnfɪdəns/", "pron": "in-VEST-uh KON-fi-duhns", "fr": "confiance des investisseurs", "def": "Trust by investors that debt will be repaid and policy is stable.", "ex": "Investor confidence affects bond yields."}, {"term": "fiscal credibility", "ipa": "/ˈfɪskəl ˌkredəˈbɪləti/", "pron": "FIS-kuhl kred-uh-BIL-uh-tee", "fr": "crédibilité budgétaire", "def": "Trust that a government can manage its budget and debt.", "ex": "Fiscal credibility can prevent market panic."}, {"term": "debt crisis", "ipa": "/ˈdet ˌkraɪsɪs/", "pron": "det KRY-sis", "fr": "crise de la dette", "def": "A situation where debt becomes difficult or impossible to manage.", "ex": "A debt crisis can force painful reforms."}, {"term": "sovereign debt crisis", "ipa": "/ˌsɒvrɪn ˈdet ˌkraɪsɪs/", "pron": "SOV-rin det KRY-sis", "fr": "crise de la dette souveraine", "def": "A crisis involving a government’s ability to repay debt.", "ex": "The eurozone faced a sovereign debt crisis after 2010."}, {"term": "eurozone crisis", "ipa": "/ˈjʊərəʊzəʊn ˌkraɪsɪs/", "pron": "YOOR-oh-zone KRY-sis", "fr": "crise de la zone euro", "def": "The debt and banking crisis affecting several eurozone countries after 2009.", "ex": "The eurozone crisis exposed flaws in monetary union."}, {"term": "fiscal union", "ipa": "/ˈfɪskəl ˌjuːniən/", "pron": "FIS-kuhl YOO-nee-uhn", "fr": "union budgétaire", "def": "A system where countries share budgetary resources or fiscal rules.", "ex": "Some economists argue that the eurozone needs a fiscal union."}, {"term": "debt mutualisation", "ipa": "/ˈdet ˌmjuːtʃuəlaɪˈzeɪʃən/", "pron": "det MYOO-choo-uh-ly-ZAY-shuhn", "fr": "mutualisation de la dette", "def": "Sharing debt responsibility among several states.", "ex": "Debt mutualisation is politically controversial in the EU."}, {"term": "common debt", "ipa": "/ˌkɒmən ˈdet/", "pron": "KOM-uhn det", "fr": "dette commune", "def": "Debt issued or guaranteed collectively by several states.", "ex": "EU common debt expanded after the pandemic."}, {"term": "safe asset", "ipa": "/ˈseɪf ˌæset/", "pron": "sayf AS-et", "fr": "actif sûr", "def": "An asset viewed as low-risk and highly reliable.", "ex": "Government bonds often serve as safe assets."}, {"term": "reserve currency", "ipa": "/rɪˈzɜːv ˌkʌrənsi/", "pron": "ri-ZURV KUR-uhn-see", "fr": "monnaie de réserve", "def": "A currency widely held by central banks and investors.", "ex": "The dollar’s reserve-currency status helps the US borrow cheaply."}, {"term": "Keynesian economics", "ipa": "/ˈkeɪnziən iːkəˈnɒmɪks/", "pron": "KAYN-zee-uhn ee-kuh-NOM-iks", "fr": "économie keynésienne", "def": "An approach supporting active fiscal policy to stabilise demand.", "ex": "Keynesian economics supports borrowing during downturns."}, {"term": "Modern Monetary Theory", "ipa": "/ˌmɒdən ˈmʌnɪtəri ˈθɪəri/", "pron": "MOD-uhn MUN-i-tuh-ree THEER-ee", "fr": "théorie monétaire moderne", "def": "A theory arguing that currency-issuing governments face different constraints from households.", "ex": "Modern Monetary Theory is highly controversial."}, {"term": "MMT", "ipa": "/ˌem em ˈtiː/", "pron": "em-em-tee", "fr": "MMT", "def": "Abbreviation for Modern Monetary Theory.", "ex": "MMT argues that inflation, not solvency, is the main constraint for currency issuers."}, {"term": "currency issuer", "ipa": "/ˈkʌrənsi ˌɪʃuːə/", "pron": "KUR-uhn-see ISH-oo-uh", "fr": "émetteur de monnaie", "def": "A government that issues its own currency.", "ex": "A currency issuer has more fiscal room than a household."}, {"term": "household analogy", "ipa": "/ˈhaʊshəʊld əˌnælədʒi/", "pron": "HOWSS-hohld uh-NAL-uh-jee", "fr": "analogie avec le budget des ménages", "def": "The comparison of government budgets to household budgets.", "ex": "Critics say the household analogy is misleading."}, {"term": "fiscal hawk", "ipa": "/ˈfɪskəl hɔːk/", "pron": "FIS-kuhl hawk", "fr": "partisan de la rigueur budgétaire", "def": "Someone who prioritises reducing deficits and debt.", "ex": "Fiscal hawks warn against excessive borrowing."}, {"term": "fiscal dove", "ipa": "/ˈfɪskəl dʌv/", "pron": "FIS-kuhl duv", "fr": "partisan d’une politique budgétaire souple", "def": "Someone more willing to use borrowing to support spending or growth.", "ex": "Fiscal doves defend borrowing for investment."}, {"term": "to borrow money", "ipa": "/ˈbɒrəʊ ˈmʌni/", "pron": "BOR-oh MUN-ee", "fr": "emprunter de l’argent", "def": "To take money with a promise to repay it.", "ex": "Governments borrow money by issuing bonds."}, {"term": "to issue bonds", "ipa": "/ˈɪʃuː bɒndz/", "pron": "ISH-oo bondz", "fr": "émettre des obligations", "def": "To sell bonds in order to borrow.", "ex": "The Treasury issues bonds to finance deficits."}, {"term": "to run a deficit", "ipa": "/rʌn ə ˈdefɪsɪt/", "pron": "run uh DEF-i-sit", "fr": "être en déficit", "def": "To spend more than revenue.", "ex": "Governments usually run a deficit during recessions."}, {"term": "to service debt", "ipa": "/ˈsɜːvɪs det/", "pron": "SUR-vis det", "fr": "assurer le service de la dette", "def": "To make interest and repayment payments on debt.", "ex": "Poor countries often struggle to service debt."}, {"term": "to repay debt", "ipa": "/rɪˈpeɪ det/", "pron": "ri-PAY det", "fr": "rembourser la dette", "def": "To pay back borrowed money.", "ex": "Growth makes it easier to repay debt."}, {"term": "to reduce public debt", "ipa": "/rɪˈdjuːs ˌpʌblɪk ˈdet/", "pron": "ri-DYOOSS PUB-lik det", "fr": "réduire la dette publique", "def": "To lower the amount of debt owed by the government.", "ex": "Reducing public debt can require higher taxes or lower spending."}, {"term": "to stabilise debt", "ipa": "/ˈsteɪbəlaɪz det/", "pron": "STAY-buh-lyz det", "fr": "stabiliser la dette", "def": "To stop debt from rising relative to GDP.", "ex": "A primary surplus can stabilise debt."}, {"term": "to bring debt under control", "ipa": "/brɪŋ det ˌʌndə kənˈtrəʊl/", "pron": "bring det UN-duh kuhn-TROHL", "fr": "maîtriser la dette", "def": "To make debt manageable.", "ex": "The government promised to bring debt under control."}, {"term": "to cut public spending", "ipa": "/kʌt ˌpʌblɪk ˈspendɪŋ/", "pron": "kut PUB-lik SPEN-ding", "fr": "réduire les dépenses publiques", "def": "To reduce government expenditure.", "ex": "Austerity aims to cut public spending."}]}, {"title": "E. Eurozone, theories, credibility and high-value verbs", "entries": [{"term": "to raise taxes", "ipa": "/reɪz ˈtæksɪz/", "pron": "rayz TAK-siz", "fr": "augmenter les impôts", "def": "To increase taxation.", "ex": "Governments may raise taxes to reduce deficits."}, {"term": "to restore fiscal credibility", "ipa": "/rɪˈstɔː ˈfɪskəl ˌkredəˈbɪləti/", "pron": "ri-STORE FIS-kuhl kred-uh-BIL-uh-tee", "fr": "rétablir la crédibilité budgétaire", "def": "To rebuild trust in public finances.", "ex": "Fiscal rules can restore fiscal credibility."}, {"term": "to reassure investors", "ipa": "/ˌriːəˈʃɔːr ɪnˈvestəz/", "pron": "ree-uh-SHOR in-VEST-uhz", "fr": "rassurer les investisseurs", "def": "To make investors feel confident.", "ex": "Clear policy can reassure investors."}, {"term": "to trigger a debt crisis", "ipa": "/ˈtrɪɡər ə ˈdet ˌkraɪsɪs/", "pron": "TRIG-uh uh det KRY-sis", "fr": "déclencher une crise de la dette", "def": "To cause a crisis of debt confidence or repayment.", "ex": "Loss of market confidence can trigger a debt crisis."}, {"term": "to crowd out investment", "ipa": "/kraʊd aʊt ɪnˈvestmənt/", "pron": "krowd out in-VEST-muhnt", "fr": "évincer l’investissement privé", "def": "To reduce private investment because public borrowing absorbs funds.", "ex": "High borrowing can crowd out investment."}, {"term": "to finance public investment", "ipa": "/ˈfaɪnæns ˌpʌblɪk ɪnˈvestmənt/", "pron": "FY-nans PUB-lik in-VEST-muhnt", "fr": "financer l’investissement public", "def": "To fund long-term government investment.", "ex": "Borrowing can finance public investment in infrastructure."}]}]}, {"id": "p5c46", "part": 5, "chapter": 46, "title": "Taxation", "file": "cpge_vocab_part5_chapter46_taxation_premium.html", "count": 153, "sections": [{"title": "A. Core taxation, revenue and tax-base vocabulary", "entries": [{"term": "taxation", "ipa": "/tækˈseɪʃən/", "pron": "tak-SAY-shuhn", "fr": "fiscalité ; imposition", "def": "The system or process by which a government collects money from people and organisations.", "ex": "Taxation funds public services, welfare and infrastructure."}, {"term": "tax", "ipa": "/tæks/", "pron": "taks", "fr": "impôt ; taxe", "def": "Money that individuals or businesses must pay to the government.", "ex": "Taxes are used to finance public spending."}, {"term": "tax system", "ipa": "/ˈtæks ˌsɪstəm/", "pron": "TAKS SIS-tuhm", "fr": "système fiscal", "def": "The set of rules and institutions used to collect taxes.", "ex": "A fair tax system should be efficient and progressive."}, {"term": "tax policy", "ipa": "/ˈtæks ˌpɒləsi/", "pron": "TAKS POL-uh-see", "fr": "politique fiscale", "def": "Government policy about which taxes to collect and how.", "ex": "Tax policy can reduce inequality or encourage investment."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on taxation, spending and borrowing.", "ex": "Taxation is a key part of fiscal policy."}, {"term": "public revenue", "ipa": "/ˌpʌblɪk ˈrevənjuː/", "pron": "PUB-lik REV-uhn-yoo", "fr": "recettes publiques", "def": "Money received by the government, mainly through taxes.", "ex": "Public revenue must cover essential services."}, {"term": "tax revenue", "ipa": "/ˈtæks ˌrevənjuː/", "pron": "TAKS REV-uhn-yoo", "fr": "recettes fiscales", "def": "Money collected by the government through taxes.", "ex": "Tax revenue rises when employment and profits increase."}, {"term": "government revenue", "ipa": "/ˈɡʌvənmənt ˈrevənjuː/", "pron": "GUV-uhn-muhnt REV-uhn-yoo", "fr": "recettes de l’État", "def": "All income received by the state.", "ex": "Government revenue fell during the recession."}, {"term": "tax base", "ipa": "/ˈtæks beɪs/", "pron": "TAKS bays", "fr": "assiette fiscale", "def": "The income, wealth, property or activity that can be taxed.", "ex": "A broad tax base can finance public services with lower rates."}, {"term": "tax rate", "ipa": "/ˈtæks reɪt/", "pron": "TAKS rayt", "fr": "taux d’imposition", "def": "The percentage or amount at which something is taxed.", "ex": "High tax rates can be politically controversial."}, {"term": "tax bracket", "ipa": "/ˈtæks ˌbrækɪt/", "pron": "TAKS BRAK-it", "fr": "tranche d’imposition", "def": "A range of income taxed at a particular rate.", "ex": "Higher earners may fall into a higher tax bracket."}, {"term": "tax threshold", "ipa": "/ˈtæks ˌθreʃhəʊld/", "pron": "TAKS THRESH-hohld", "fr": "seuil d’imposition", "def": "The income level at which a tax begins to apply.", "ex": "Raising the tax threshold can help low-income workers."}, {"term": "tax allowance", "ipa": "/ˈtæks əˌlaʊəns/", "pron": "TAKS uh-LOW-uhns", "fr": "abattement fiscal ; déduction", "def": "An amount of income that is not taxed.", "ex": "A tax allowance reduces taxable income."}, {"term": "tax deduction", "ipa": "/ˈtæks dɪˌdʌkʃən/", "pron": "TAKS di-DUK-shuhn", "fr": "déduction fiscale", "def": "An amount subtracted from taxable income.", "ex": "Tax deductions can encourage donations or investment."}, {"term": "tax credit", "ipa": "/ˈtæks ˌkredɪt/", "pron": "TAKS KRED-it", "fr": "crédit d’impôt", "def": "An amount subtracted from tax owed, or a payment to eligible households.", "ex": "Tax credits can support low-income families."}, {"term": "tax relief", "ipa": "/ˈtæks rɪˌliːf/", "pron": "TAKS ri-LEEF", "fr": "allègement fiscal", "def": "A reduction in tax owed.", "ex": "Tax relief can encourage saving or business investment."}, {"term": "tax exemption", "ipa": "/ˈtæks ɪɡˌzempʃən/", "pron": "TAKS ig-ZEMP-shuhn", "fr": "exonération fiscale", "def": "A situation where someone or something is not subject to a tax.", "ex": "Charities often receive tax exemptions."}, {"term": "taxable income", "ipa": "/ˌtæksəbəl ˈɪnkʌm/", "pron": "TAK-suh-buhl IN-kum", "fr": "revenu imposable", "def": "Income on which tax must be paid.", "ex": "Taxable income is calculated after allowances and deductions."}, {"term": "gross income", "ipa": "/ˌɡrəʊs ˈɪnkʌm/", "pron": "grohss IN-kum", "fr": "revenu brut", "def": "Income before taxes and deductions.", "ex": "Gross income is higher than take-home pay."}, {"term": "net income", "ipa": "/ˌnet ˈɪnkʌm/", "pron": "net IN-kum", "fr": "revenu net", "def": "Income after taxes and deductions.", "ex": "Net income determines actual purchasing power."}, {"term": "take-home pay", "ipa": "/ˌteɪk həʊm ˈpeɪ/", "pron": "take-home pay", "fr": "salaire net", "def": "Money received by a worker after tax and deductions.", "ex": "Tax rises reduce take-home pay."}, {"term": "direct tax", "ipa": "/dəˌrekt ˈtæks/", "pron": "di-REKT taks", "fr": "impôt direct", "def": "A tax paid directly by individuals or organisations to the government.", "ex": "Income tax is a direct tax."}, {"term": "indirect tax", "ipa": "/ˌɪndəˈrekt ˈtæks/", "pron": "in-di-REKT taks", "fr": "impôt indirect", "def": "A tax paid through the purchase of goods or services.", "ex": "VAT is an indirect tax."}]}, {"title": "B. Main types of taxes", "entries": [{"term": "income tax", "ipa": "/ˈɪnkʌm tæks/", "pron": "IN-kum taks", "fr": "impôt sur le revenu", "def": "A tax on personal income.", "ex": "Income tax is often progressive."}, {"term": "personal income tax", "ipa": "/ˈpɜːsənəl ˈɪnkʌm tæks/", "pron": "PUR-suh-nuhl IN-kum taks", "fr": "impôt sur le revenu des personnes physiques", "def": "A tax paid by individuals on their income.", "ex": "Personal income tax is a major source of public revenue."}, {"term": "corporation tax", "ipa": "/ˌkɔːpəˈreɪʃən tæks/", "pron": "kor-puh-RAY-shuhn taks", "fr": "impôt sur les sociétés", "def": "A tax on company profits.", "ex": "Corporation tax affects business investment decisions."}, {"term": "corporate tax", "ipa": "/ˈkɔːpərət tæks/", "pron": "KOR-puh-ruht taks", "fr": "impôt sur les sociétés", "def": "Tax paid by companies on profits.", "ex": "Corporate tax competition can reduce public revenue."}, {"term": "capital gains tax", "ipa": "/ˌkæpɪtəl ˈɡeɪnz tæks/", "pron": "KAP-i-tuhl gaynz taks", "fr": "impôt sur les plus-values", "def": "A tax on profit made from selling assets.", "ex": "Capital gains tax affects investors and homeowners."}, {"term": "wealth tax", "ipa": "/ˈwelθ tæks/", "pron": "welth taks", "fr": "impôt sur la fortune", "def": "A tax on a person’s total assets or net wealth.", "ex": "A wealth tax is often proposed to reduce inequality."}, {"term": "property tax", "ipa": "/ˈprɒpəti tæks/", "pron": "PROP-uh-tee taks", "fr": "taxe foncière ; impôt immobilier", "def": "A tax on land or buildings.", "ex": "Property tax can fund local government."}, {"term": "inheritance tax", "ipa": "/ɪnˈherɪtəns tæks/", "pron": "in-HERR-i-tuhns taks", "fr": "droits de succession", "def": "A tax on money or property inherited after someone dies.", "ex": "Inheritance tax is controversial because it affects family wealth."}, {"term": "estate tax", "ipa": "/ɪˈsteɪt tæks/", "pron": "i-STATE taks", "fr": "impôt successoral", "def": "US term for a tax on a deceased person’s estate.", "ex": "The estate tax is often called a tax on inherited wealth."}, {"term": "value-added tax", "ipa": "/ˌvæljuː ˈædɪd tæks/", "pron": "VAL-yoo AD-id taks", "fr": "TVA", "def": "A consumption tax added at each stage of production and sale.", "ex": "Value-added tax is paid by consumers through prices."}, {"term": "VAT", "ipa": "/ˌviː eɪ ˈtiː/", "pron": "vee-ay-tee", "fr": "TVA", "def": "Abbreviation for value-added tax.", "ex": "VAT is usually regressive unless essentials are exempt."}, {"term": "sales tax", "ipa": "/ˈseɪlz tæks/", "pron": "sales taks", "fr": "taxe sur les ventes", "def": "A tax added to the sale of goods and services.", "ex": "Sales tax is common in the United States."}, {"term": "excise duty", "ipa": "/ˈeksaɪz ˌdjuːti/", "pron": "EK-syze DYOO-tee", "fr": "droit d’accise", "def": "A tax on specific goods such as alcohol, tobacco or fuel.", "ex": "Excise duty can discourage harmful consumption."}, {"term": "fuel duty", "ipa": "/ˈfjuːəl ˌdjuːti/", "pron": "FYOO-uhl DYOO-tee", "fr": "taxe sur les carburants", "def": "A tax on petrol, diesel or other fuels.", "ex": "Fuel duty is politically sensitive in rural areas."}, {"term": "carbon tax", "ipa": "/ˈkɑːbən tæks/", "pron": "KAR-buhn taks", "fr": "taxe carbone", "def": "A tax on carbon emissions or fossil fuels.", "ex": "A carbon tax aims to make polluters pay."}, {"term": "green tax", "ipa": "/ˈɡriːn tæks/", "pron": "green taks", "fr": "taxe écologique", "def": "A tax designed to discourage environmentally harmful behaviour.", "ex": "Green taxes can support the transition to a low-carbon economy."}, {"term": "sin tax", "ipa": "/ˈsɪn tæks/", "pron": "sin taks", "fr": "taxe comportementale ; taxe sur les produits nocifs", "def": "A tax on goods considered harmful, such as tobacco or alcohol.", "ex": "Sin taxes can raise revenue and improve public health."}, {"term": "sugar tax", "ipa": "/ˈʃʊɡə tæks/", "pron": "SHUUG-uh taks", "fr": "taxe sur le sucre", "def": "A tax on sugary drinks or products.", "ex": "A sugar tax can reduce consumption of unhealthy drinks."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "Tariffs protect domestic industries but raise consumer prices."}, {"term": "customs duty", "ipa": "/ˈkʌstəmz ˌdjuːti/", "pron": "KUS-tuhmz DYOO-tee", "fr": "droit de douane", "def": "A tax paid on goods imported into a country.", "ex": "Customs duties affect international trade."}, {"term": "payroll tax", "ipa": "/ˈpeɪrəʊl tæks/", "pron": "PAY-rohl taks", "fr": "cotisation sociale ; taxe sur les salaires", "def": "A tax linked to wages, often used to finance social security.", "ex": "Payroll taxes can make hiring more expensive."}, {"term": "social security contributions", "ipa": "/ˌsəʊʃəl sɪˈkjʊərəti ˌkɒntrɪˈbjuːʃənz/", "pron": "SOH-shuhl si-KYOOR-uh-tee kon-tri-BYOO-shuhnz", "fr": "cotisations sociales", "def": "Payments by workers and employers to finance social protection.", "ex": "Social security contributions fund pensions and healthcare."}, {"term": "national insurance", "ipa": "/ˌnæʃənəl ɪnˈʃʊərəns/", "pron": "NASH-uh-nuhl in-SHOOR-uhns", "fr": "cotisations sociales britanniques", "def": "UK system of contributions financing benefits, pensions and healthcare.", "ex": "National Insurance affects workers and employers."}, {"term": "local tax", "ipa": "/ˌləʊkəl ˈtæks/", "pron": "LOH-kuhl taks", "fr": "impôt local", "def": "A tax collected by local government.", "ex": "Local taxes finance schools, roads and local services."}, {"term": "council tax", "ipa": "/ˈkaʊnsəl tæks/", "pron": "KOWN-suhl taks", "fr": "taxe d’habitation britannique", "def": "A UK local tax on residential property.", "ex": "Council tax is often criticised as unfair."}, {"term": "progressive tax", "ipa": "/prəˌɡresɪv ˈtæks/", "pron": "pruh-GRES-iv taks", "fr": "impôt progressif", "def": "A tax where richer people pay a higher share of income.", "ex": "Progressive taxation can reduce inequality."}, {"term": "regressive tax", "ipa": "/rɪˌɡresɪv ˈtæks/", "pron": "ri-GRES-iv taks", "fr": "impôt régressif", "def": "A tax that takes a larger share of income from poorer people.", "ex": "VAT can be regressive because poorer households spend more of their income."}, {"term": "proportional tax", "ipa": "/prəˌpɔːʃənəl ˈtæks/", "pron": "pruh-POR-shuh-nuhl taks", "fr": "impôt proportionnel", "def": "A tax taking the same percentage from everyone.", "ex": "A flat tax is a type of proportional tax."}, {"term": "flat tax", "ipa": "/ˌflæt ˈtæks/", "pron": "flat taks", "fr": "impôt à taux unique", "def": "A single tax rate applied to all taxpayers or income levels.", "ex": "Flat tax supporters claim it is simple."}]}, {"title": "C. Progressivity, fairness and redistribution", "entries": [{"term": "marginal tax rate", "ipa": "/ˌmɑːdʒɪnəl ˈtæks reɪt/", "pron": "MAR-ji-nuhl taks rayt", "fr": "taux marginal d’imposition", "def": "The tax rate paid on the next unit of income.", "ex": "High marginal tax rates may affect incentives."}, {"term": "average tax rate", "ipa": "/ˌævərɪdʒ ˈtæks reɪt/", "pron": "AV-uh-rij taks rayt", "fr": "taux moyen d’imposition", "def": "Total tax paid divided by total income.", "ex": "The average tax rate is usually lower than the top marginal rate."}, {"term": "effective tax rate", "ipa": "/ɪˌfektɪv ˈtæks reɪt/", "pron": "i-FEK-tiv taks rayt", "fr": "taux effectif d’imposition", "def": "The actual rate paid after deductions, exemptions and credits.", "ex": "Some corporations pay a low effective tax rate."}, {"term": "top tax rate", "ipa": "/ˌtɒp ˈtæks reɪt/", "pron": "top taks rayt", "fr": "taux marginal supérieur", "def": "The highest marginal tax rate in a tax system.", "ex": "Raising the top tax rate is often controversial."}, {"term": "tax progressivity", "ipa": "/ˈtæks prəʊˌɡresɪvəti/", "pron": "TAKS proh-gres-IV-uh-tee", "fr": "progressivité de l’impôt", "def": "The degree to which taxes rise with income or wealth.", "ex": "Tax progressivity can reduce income inequality."}, {"term": "tax burden", "ipa": "/ˈtæks ˌbɜːdən/", "pron": "TAKS BUR-duhn", "fr": "charge fiscale", "def": "The amount of tax paid by a person, group or economy.", "ex": "The tax burden is often debated during elections."}, {"term": "tax incidence", "ipa": "/ˈtæks ˌɪnsɪdəns/", "pron": "TAKS IN-si-duhns", "fr": "incidence fiscale", "def": "Who ultimately bears the cost of a tax.", "ex": "Tax incidence can differ from who legally pays the tax."}, {"term": "redistribution", "ipa": "/ˌriːdɪstrɪˈbjuːʃən/", "pron": "ree-dis-tri-BYOO-shuhn", "fr": "redistribution", "def": "The transfer of income or wealth through taxes and public spending.", "ex": "Redistribution reduces inequality when taxes fund public services."}, {"term": "income redistribution", "ipa": "/ˈɪnkʌm ˌriːdɪstrɪˈbjuːʃən/", "pron": "IN-kum ree-dis-tri-BYOO-shuhn", "fr": "redistribution des revenus", "def": "The redistribution of income between groups.", "ex": "Income redistribution is a central goal of progressive taxation."}, {"term": "wealth redistribution", "ipa": "/ˈwelθ ˌriːdɪstrɪˈbjuːʃən/", "pron": "welth ree-dis-tri-BYOO-shuhn", "fr": "redistribution des richesses", "def": "The redistribution of assets or wealth between groups.", "ex": "Wealth redistribution is politically sensitive."}, {"term": "inequality", "ipa": "/ˌɪnɪˈkwɒləti/", "pron": "in-i-KWOL-uh-tee", "fr": "inégalité", "def": "Unequal distribution of income, wealth or opportunities.", "ex": "Taxation can either reduce or worsen inequality."}, {"term": "income inequality", "ipa": "/ˈɪnkʌm ˌɪnɪˈkwɒləti/", "pron": "IN-kum in-i-KWOL-uh-tee", "fr": "inégalité des revenus", "def": "Unequal distribution of income.", "ex": "Progressive income tax can reduce income inequality."}, {"term": "wealth inequality", "ipa": "/ˈwelθ ˌɪnɪˈkwɒləti/", "pron": "welth in-i-KWOL-uh-tee", "fr": "inégalité patrimoniale", "def": "Unequal distribution of assets and wealth.", "ex": "Inheritance tax targets wealth inequality."}, {"term": "tax fairness", "ipa": "/ˈtæks ˌfeənəs/", "pron": "TAKS FAIR-nuhs", "fr": "justice fiscale", "def": "The idea that taxes should be distributed justly.", "ex": "Tax fairness is central to debates about the wealthy."}, {"term": "fiscal justice", "ipa": "/ˈfɪskəl ˌdʒʌstɪs/", "pron": "FIS-kuhl JUS-tis", "fr": "justice fiscale", "def": "Fairness in taxation and public finance.", "ex": "Campaigners demand fiscal justice from multinationals."}, {"term": "ability to pay", "ipa": "/əˌbɪləti tə ˈpeɪ/", "pron": "uh-BIL-uh-tee tuh pay", "fr": "capacité contributive", "def": "The principle that people with more resources should pay more tax.", "ex": "Progressive taxation is based on ability to pay."}, {"term": "benefit principle", "ipa": "/ˈbenɪfɪt ˌprɪnsəpəl/", "pron": "BEN-i-fit PRIN-suh-puhl", "fr": "principe du bénéfice reçu", "def": "The idea that people should pay taxes according to the benefits they receive.", "ex": "Road tolls reflect the benefit principle."}, {"term": "tax morale", "ipa": "/ˈtæks məˌrɑːl/", "pron": "TAKS muh-RAHL", "fr": "civisme fiscal", "def": "Citizens’ willingness to pay taxes voluntarily.", "ex": "Tax morale declines when people see corruption or unfairness."}, {"term": "tax compliance", "ipa": "/ˈtæks kəmˌplaɪəns/", "pron": "TAKS kuhm-PLY-uhns", "fr": "conformité fiscale", "def": "The extent to which taxpayers obey tax rules.", "ex": "Tax compliance improves when rules are simple and trusted."}, {"term": "taxpayer", "ipa": "/ˈtæksˌpeɪə/", "pron": "TAKS-pay-uh", "fr": "contribuable", "def": "A person or organisation that pays taxes.", "ex": "Taxpayers expect public money to be used responsibly."}, {"term": "tax return", "ipa": "/ˈtæks rɪˌtɜːn/", "pron": "TAKS ri-TURN", "fr": "déclaration d’impôts", "def": "A form reporting income and tax owed.", "ex": "Taxpayers file a tax return each year."}, {"term": "tax audit", "ipa": "/ˈtæks ˌɔːdɪt/", "pron": "TAKS AW-dit", "fr": "contrôle fiscal", "def": "An official examination of someone’s tax records.", "ex": "A tax audit can reveal fraud or errors."}, {"term": "tax collection", "ipa": "/ˈtæks kəˌlekʃən/", "pron": "TAKS kuh-LEK-shuhn", "fr": "recouvrement de l’impôt", "def": "The process of collecting taxes.", "ex": "Efficient tax collection strengthens public finances."}, {"term": "tax administration", "ipa": "/ˈtæks ədˌmɪnɪˈstreɪʃən/", "pron": "TAKS ad-min-i-STRAY-shuhn", "fr": "administration fiscale", "def": "The institutions and procedures used to manage taxation.", "ex": "Good tax administration reduces evasion."}]}, {"title": "D. Tax compliance, evasion, avoidance and havens", "entries": [{"term": "tax authority", "ipa": "/ˈtæks ɔːˌθɒrəti/", "pron": "TAKS aw-THOR-uh-tee", "fr": "administration fiscale", "def": "A public body responsible for collecting and enforcing taxes.", "ex": "Tax authorities investigate suspicious declarations."}, {"term": "HMRC", "ipa": "/ˌeɪtʃ em ɑː ˈsiː/", "pron": "aych-em-ar-see", "fr": "administration fiscale britannique", "def": "HM Revenue and Customs, the UK tax authority.", "ex": "HMRC collects taxes in the UK."}, {"term": "IRS", "ipa": "/ˌaɪ ɑːr ˈes/", "pron": "eye-ar-ess", "fr": "administration fiscale américaine", "def": "Internal Revenue Service, the US tax authority.", "ex": "The IRS processes federal tax returns."}, {"term": "tax enforcement", "ipa": "/ˈtæks ɪnˌfɔːsmənt/", "pron": "TAKS in-FORSS-muhnt", "fr": "application de la loi fiscale", "def": "Action to ensure taxes are paid correctly.", "ex": "Tax enforcement deters evasion."}, {"term": "tax evasion", "ipa": "/ˈtæks ɪˌveɪʒən/", "pron": "TAKS i-VAY-zhuhn", "fr": "fraude fiscale", "def": "Illegal non-payment or underpayment of taxes.", "ex": "Tax evasion deprives the state of revenue."}, {"term": "tax avoidance", "ipa": "/ˈtæks əˌvɔɪdəns/", "pron": "TAKS uh-VOY-duhns", "fr": "optimisation fiscale", "def": "Legal but often controversial reduction of tax liabilities.", "ex": "Tax avoidance by large companies causes public anger."}, {"term": "tax fraud", "ipa": "/ˈtæks frɔːd/", "pron": "TAKS fraud", "fr": "fraude fiscale", "def": "Deliberate deception to pay less tax illegally.", "ex": "Tax fraud can lead to fines or prison."}, {"term": "tax loophole", "ipa": "/ˈtæks ˌluːphəʊl/", "pron": "TAKS LOOP-hohl", "fr": "niche fiscale ; faille fiscale", "def": "A gap in tax law that allows people to reduce tax.", "ex": "Wealthy taxpayers often exploit tax loopholes."}, {"term": "loophole", "ipa": "/ˈluːphəʊl/", "pron": "LOOP-hohl", "fr": "faille juridique", "def": "An ambiguity or gap in rules that can be exploited.", "ex": "Closing loopholes can raise revenue."}, {"term": "tax shelter", "ipa": "/ˈtæks ˌʃeltə/", "pron": "TAKS SHEL-tuh", "fr": "abri fiscal", "def": "A legal arrangement used to reduce tax owed.", "ex": "Some tax shelters are legal but controversial."}, {"term": "tax haven", "ipa": "/ˈtæks ˌheɪvən/", "pron": "TAKS HAY-vuhn", "fr": "paradis fiscal", "def": "A country or territory with low taxes and secrecy.", "ex": "Tax havens help individuals and firms hide wealth."}, {"term": "offshore account", "ipa": "/ˌɒfʃɔːr əˈkaʊnt/", "pron": "OFF-shor uh-KOWNT", "fr": "compte offshore", "def": "A bank account held in another country, often for tax reasons.", "ex": "Offshore accounts can be used for legal or illegal purposes."}, {"term": "offshore finance", "ipa": "/ˌɒfʃɔː ˈfaɪnæns/", "pron": "OFF-shor FY-nans", "fr": "finance offshore", "def": "Financial activity located in low-tax jurisdictions.", "ex": "Offshore finance reduces transparency."}, {"term": "shell company", "ipa": "/ˈʃel ˌkʌmpəni/", "pron": "shel KUM-puh-nee", "fr": "société écran", "def": "A company with no real operations, often used to hold assets or hide ownership.", "ex": "Shell companies can conceal tax evasion."}, {"term": "beneficial owner", "ipa": "/ˌbenɪfɪʃəl ˈəʊnə/", "pron": "ben-i-FISH-uhl OH-nuh", "fr": "bénéficiaire effectif", "def": "The real person who ultimately owns or controls an asset or company.", "ex": "Transparency rules aim to identify beneficial owners."}, {"term": "profit shifting", "ipa": "/ˈprɒfɪt ˌʃɪftɪŋ/", "pron": "PROF-it SHIFT-ing", "fr": "transfert de bénéfices", "def": "Moving profits to low-tax jurisdictions to reduce taxes.", "ex": "Profit shifting reduces corporate tax revenue."}, {"term": "base erosion", "ipa": "/ˈbeɪs ɪˌrəʊʒən/", "pron": "bays i-ROH-zhuhn", "fr": "érosion de la base fiscale", "def": "The shrinking of a tax base through avoidance or deductions.", "ex": "Base erosion is a major concern in international taxation."}, {"term": "BEPS", "ipa": "/beps/", "pron": "beps", "fr": "BEPS ; érosion de la base d’imposition et transfert de bénéfices", "def": "Base Erosion and Profit Shifting, a term used in international tax reform.", "ex": "BEPS reforms aim to limit corporate tax avoidance."}, {"term": "transfer pricing", "ipa": "/ˈtrænsfɜː ˌpraɪsɪŋ/", "pron": "TRANS-fur PRY-sing", "fr": "prix de transfert", "def": "Pricing of transactions between related companies in different countries.", "ex": "Transfer pricing can be used to shift profits."}, {"term": "tax competition", "ipa": "/ˈtæks ˌkɒmpəˈtɪʃən/", "pron": "TAKS kom-puh-TISH-uhn", "fr": "concurrence fiscale", "def": "Competition between countries to attract business through lower taxes.", "ex": "Tax competition can create a race to the bottom."}, {"term": "race to the bottom", "ipa": "/ˌreɪs tə ðə ˈbɒtəm/", "pron": "race tuh thuh BOT-uhm", "fr": "course vers le bas", "def": "Competition that lowers taxes, wages or standards.", "ex": "Corporate tax cuts can create a race to the bottom."}, {"term": "global minimum tax", "ipa": "/ˌɡləʊbəl ˈmɪnɪməm tæks/", "pron": "GLOH-buhl MIN-i-muhm taks", "fr": "impôt minimum mondial", "def": "An international minimum tax rate on multinational profits.", "ex": "A global minimum tax aims to curb tax competition."}, {"term": "digital services tax", "ipa": "/ˌdɪdʒɪtəl ˈsɜːvɪsɪz tæks/", "pron": "DIJ-i-tuhl SUR-vis-iz taks", "fr": "taxe sur les services numériques", "def": "A tax on revenues generated by large digital companies.", "ex": "Digital services taxes target Big Tech revenues."}, {"term": "windfall tax", "ipa": "/ˈwɪndfɔːl tæks/", "pron": "WIND-fawl taks", "fr": "taxe sur les superprofits", "def": "A tax on unexpectedly high profits.", "ex": "A windfall tax was proposed for energy companies."}, {"term": "excess profits tax", "ipa": "/ˌekses ˈprɒfɪts tæks/", "pron": "EK-sess PROF-its taks", "fr": "taxe sur les profits exceptionnels", "def": "A tax on profits considered unusually high.", "ex": "An excess profits tax can be justified during crises."}, {"term": "tax reform", "ipa": "/ˈtæks rɪˌfɔːm/", "pron": "TAKS ri-FORM", "fr": "réforme fiscale", "def": "Changes to the tax system.", "ex": "Tax reform can simplify rules or shift the tax burden."}, {"term": "tax cut", "ipa": "/ˈtæks kʌt/", "pron": "TAKS kut", "fr": "baisse d’impôts", "def": "A reduction in taxes.", "ex": "Tax cuts can stimulate demand but reduce revenue."}, {"term": "tax rise", "ipa": "/ˈtæks raɪz/", "pron": "TAKS ryze", "fr": "hausse d’impôts", "def": "An increase in taxes.", "ex": "Tax rises are unpopular but may fund public services."}, {"term": "tax hike", "ipa": "/ˈtæks haɪk/", "pron": "TAKS hyke", "fr": "hausse d’impôts", "def": "Informal term for a tax increase.", "ex": "Opponents criticised the tax hike as anti-business."}, {"term": "tax break", "ipa": "/ˈtæks breɪk/", "pron": "TAKS brayk", "fr": "avantage fiscal", "def": "A reduction or exemption from tax.", "ex": "Tax breaks can encourage investment but reduce revenue."}, {"term": "fiscal incentive", "ipa": "/ˈfɪskəl ɪnˌsentɪv/", "pron": "FIS-kuhl in-SEN-tiv", "fr": "incitation fiscale", "def": "A tax or spending measure designed to encourage behaviour.", "ex": "Fiscal incentives can promote green investment."}, {"term": "investment incentive", "ipa": "/ɪnˈvestmənt ɪnˌsentɪv/", "pron": "in-VEST-muhnt in-SEN-tiv", "fr": "incitation à l’investissement", "def": "A measure encouraging businesses to invest.", "ex": "Tax incentives can support research and development."}, {"term": "business-friendly tax system", "ipa": "/ˌbɪznəs ˈfrendli ˈtæks ˌsɪstəm/", "pron": "BIZ-nuhs-FREND-lee TAKS SIS-tuhm", "fr": "système fiscal favorable aux entreprises", "def": "A tax system designed to attract or support businesses.", "ex": "A business-friendly tax system may increase investment."}, {"term": "tax burden on labour", "ipa": "/ˈtæks ˌbɜːdən ɒn ˈleɪbə/", "pron": "TAKS BUR-duhn on LAY-buh", "fr": "charge fiscale sur le travail", "def": "Taxes and contributions paid on wages or employment.", "ex": "A high tax burden on labour can discourage hiring."}, {"term": "tax burden on capital", "ipa": "/ˈtæks ˌbɜːdən ɒn ˈkæpɪtəl/", "pron": "TAKS BUR-duhn on KAP-i-tuhl", "fr": "charge fiscale sur le capital", "def": "Taxes on profits, investment income or wealth.", "ex": "Taxing capital is difficult in a globalised economy."}, {"term": "double taxation", "ipa": "/ˌdʌbəl tækˈseɪʃən/", "pron": "DUB-uhl tak-SAY-shuhn", "fr": "double imposition", "def": "Being taxed twice on the same income or profit.", "ex": "Tax treaties help avoid double taxation."}]}, {"title": "E. Tax reform, public services, fiscal debates and high-value verbs", "entries": [{"term": "tax treaty", "ipa": "/ˈtæks ˌtriːti/", "pron": "TAKS TREE-tee", "fr": "convention fiscale", "def": "An agreement between countries on taxation.", "ex": "Tax treaties allocate taxing rights between countries."}, {"term": "fiscal sovereignty", "ipa": "/ˈfɪskəl ˈsɒvrənti/", "pron": "FIS-kuhl SOV-ruhn-tee", "fr": "souveraineté fiscale", "def": "A state’s power to decide its own taxation policy.", "ex": "Global tax rules can limit fiscal sovereignty."}, {"term": "tax harmonisation", "ipa": "/ˈtæks ˌhɑːmənaɪˈzeɪʃən/", "pron": "TAKS har-muh-ny-ZAY-shuhn", "fr": "harmonisation fiscale", "def": "Making tax rules more similar across countries.", "ex": "Tax harmonisation can reduce harmful competition."}, {"term": "tax coordination", "ipa": "/ˈtæks kəʊˌɔːdɪˈneɪʃən/", "pron": "TAKS koh-or-di-NAY-shuhn", "fr": "coordination fiscale", "def": "Cooperation between governments on tax policy.", "ex": "Tax coordination is needed to tax multinationals effectively."}, {"term": "fiscal federalism", "ipa": "/ˈfɪskəl ˈfedərəlɪzəm/", "pron": "FIS-kuhl FED-uh-ruhl-iz-uhm", "fr": "fédéralisme fiscal", "def": "The division of tax and spending powers between levels of government.", "ex": "Fiscal federalism shapes local public services."}, {"term": "taxpayer-funded", "ipa": "/ˈtæksˌpeɪə ˌfʌndɪd/", "pron": "TAKS-pay-uh FUN-did", "fr": "financé par les contribuables", "def": "Paid for by public tax money.", "ex": "Taxpayer-funded services must be accountable."}, {"term": "public services", "ipa": "/ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "PUB-lik SUR-vis-iz", "fr": "services publics", "def": "Services provided or funded by the state.", "ex": "Taxation funds public services."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system providing social protection, healthcare, pensions and benefits.", "ex": "The welfare state depends on stable tax revenue."}, {"term": "social protection", "ipa": "/ˌsəʊʃəl prəˈtekʃən/", "pron": "SOH-shuhl pruh-TEK-shuhn", "fr": "protection sociale", "def": "Policies protecting people from poverty, illness, unemployment or old age.", "ex": "Taxes finance social protection."}, {"term": "public goods", "ipa": "/ˌpʌblɪk ˈɡʊdz/", "pron": "PUB-lik goods", "fr": "biens publics", "def": "Goods or services that benefit everyone and are hard to exclude people from.", "ex": "Defence and clean air are public goods."}, {"term": "infrastructure", "ipa": "/ˈɪnfrəˌstrʌktʃə/", "pron": "IN-fruh-struk-chuh", "fr": "infrastructures", "def": "Basic systems such as roads, schools, hospitals and networks.", "ex": "Taxation can finance infrastructure."}, {"term": "fiscal capacity", "ipa": "/ˈfɪskəl kəˌpæsəti/", "pron": "FIS-kuhl kuh-PAS-uh-tee", "fr": "capacité fiscale", "def": "The ability of a state to raise revenue effectively.", "ex": "Weak fiscal capacity limits development."}, {"term": "state capacity", "ipa": "/ˈsteɪt kəˌpæsəti/", "pron": "STATE kuh-PAS-uh-tee", "fr": "capacité de l’État", "def": "The ability of a state to implement policy and enforce rules.", "ex": "Tax collection depends on state capacity."}, {"term": "shadow economy", "ipa": "/ˈʃædəʊ iˌkɒnəmi/", "pron": "SHAD-oh i-KON-uh-mee", "fr": "économie souterraine", "def": "Economic activity hidden from official regulation or taxation.", "ex": "The shadow economy reduces tax revenue."}, {"term": "informal economy", "ipa": "/ɪnˌfɔːməl iˈkɒnəmi/", "pron": "in-FOR-muhl i-KON-uh-mee", "fr": "économie informelle", "def": "Economic activity outside formal regulation and taxation.", "ex": "Large informal economies make taxation harder."}, {"term": "undeclared work", "ipa": "/ˌʌndɪˈkleəd ˈwɜːk/", "pron": "un-di-KLAIRD work", "fr": "travail non déclaré", "def": "Work not reported to tax or social security authorities.", "ex": "Undeclared work weakens social protection systems."}, {"term": "tax gap", "ipa": "/ˈtæks ɡæp/", "pron": "TAKS gap", "fr": "manque à gagner fiscal", "def": "The difference between tax owed and tax actually collected.", "ex": "Reducing the tax gap can improve public finances."}, {"term": "compliance gap", "ipa": "/kəmˈplaɪəns ɡæp/", "pron": "kuhm-PLY-uhns gap", "fr": "écart de conformité fiscale", "def": "The gap caused by people not complying with tax rules.", "ex": "The compliance gap includes evasion and errors."}, {"term": "fiscal deficit", "ipa": "/ˌfɪskəl ˈdefɪsɪt/", "pron": "FIS-kuhl DEF-i-sit", "fr": "déficit public", "def": "The gap between government spending and revenue.", "ex": "Tax increases can reduce a fiscal deficit."}, {"term": "public debt", "ipa": "/ˌpʌblɪk ˈdet/", "pron": "PUB-lik det", "fr": "dette publique", "def": "Money owed by the government.", "ex": "Low tax revenue can increase public debt."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies reducing public spending or deficits.", "ex": "Tax rises can be part of an austerity package."}, {"term": "fiscal consolidation", "ipa": "/ˌfɪskəl kənˌsɒlɪˈdeɪʃən/", "pron": "FIS-kuhl kuhn-sol-i-DAY-shuhn", "fr": "assainissement budgétaire", "def": "Policy aimed at reducing deficits and stabilising debt.", "ex": "Fiscal consolidation often combines spending cuts and tax rises."}, {"term": "to tax", "ipa": "/tæks/", "pron": "taks", "fr": "taxer ; imposer", "def": "To make someone or something pay tax.", "ex": "Governments tax income, profits and consumption."}, {"term": "to collect taxes", "ipa": "/kəˈlekt ˈtæksɪz/", "pron": "kuh-LEKT TAK-siz", "fr": "collecter les impôts", "def": "To receive taxes from people or organisations.", "ex": "States need capacity to collect taxes effectively."}, {"term": "to raise taxes", "ipa": "/reɪz ˈtæksɪz/", "pron": "rayz TAK-siz", "fr": "augmenter les impôts", "def": "To increase taxes.", "ex": "Governments may raise taxes to fund healthcare."}, {"term": "to cut taxes", "ipa": "/kʌt ˈtæksɪz/", "pron": "kut TAK-siz", "fr": "baisser les impôts", "def": "To reduce taxes.", "ex": "Politicians often promise to cut taxes."}, {"term": "to broaden the tax base", "ipa": "/ˈbrɔːdən ðə ˈtæks beɪs/", "pron": "BRAW-duhn thuh TAKS bays", "fr": "élargir l’assiette fiscale", "def": "To increase the range of income, wealth or activity that is taxed.", "ex": "Broadening the tax base can raise revenue without higher rates."}, {"term": "to close loopholes", "ipa": "/kləʊz ˈluːphəʊlz/", "pron": "klohz LOOP-hohlz", "fr": "combler les niches fiscales", "def": "To remove gaps in tax rules that allow avoidance.", "ex": "Governments promise to close loopholes used by the wealthy."}, {"term": "to evade tax", "ipa": "/ɪˈveɪd tæks/", "pron": "i-VAYD taks", "fr": "frauder le fisc", "def": "To illegally avoid paying taxes owed.", "ex": "Taxpayers who evade tax can face penalties."}, {"term": "to avoid tax", "ipa": "/əˈvɔɪd tæks/", "pron": "uh-VOYD taks", "fr": "optimiser fiscalement", "def": "To legally reduce taxes, often through loopholes.", "ex": "Multinationals avoid tax by shifting profits."}, {"term": "to shift profits", "ipa": "/ʃɪft ˈprɒfɪts/", "pron": "shift PROF-its", "fr": "transférer les bénéfices", "def": "To move profits to another jurisdiction, often to reduce tax.", "ex": "Companies shift profits to low-tax countries."}, {"term": "to crack down on tax evasion", "ipa": "/kræk daʊn ɒn ˈtæks ɪˌveɪʒən/", "pron": "krak down on TAKS i-VAY-zhuhn", "fr": "sévir contre la fraude fiscale", "def": "To take strong action against illegal tax non-payment.", "ex": "Authorities want to crack down on tax evasion."}, {"term": "to fund public services", "ipa": "/fʌnd ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "fund PUB-lik SUR-vis-iz", "fr": "financer les services publics", "def": "To pay for public services through revenue.", "ex": "Taxes fund public services such as schools and hospitals."}, {"term": "to redistribute wealth", "ipa": "/ˌriːdɪˈstrɪbjuːt welθ/", "pron": "ree-dis-TRIB-yoot welth", "fr": "redistribuer les richesses", "def": "To transfer wealth through taxes, benefits or services.", "ex": "Progressive taxation can redistribute wealth."}, {"term": "to reduce inequality", "ipa": "/rɪˈdjuːs ˌɪnɪˈkwɒləti/", "pron": "ri-DYOOSS in-i-KWOL-uh-tee", "fr": "réduire les inégalités", "def": "To lessen unequal distribution of income or wealth.", "ex": "Taxation can reduce inequality when combined with public spending."}, {"term": "to incentivise investment", "ipa": "/ɪnˈsentɪvaɪz ɪnˈvestmənt/", "pron": "in-SEN-ti-vyze in-VEST-muhnt", "fr": "inciter à l’investissement", "def": "To encourage investment through incentives.", "ex": "Tax breaks can incentivise investment."}, {"term": "to discourage harmful behaviour", "ipa": "/dɪsˈkʌrɪdʒ ˈhɑːmfəl bɪˈheɪvjə/", "pron": "dis-KUR-ij HARM-fuhl bi-HAYV-yuh", "fr": "décourager les comportements nocifs", "def": "To make harmful behaviour less attractive.", "ex": "Sin taxes discourage harmful behaviour."}, {"term": "to make polluters pay", "ipa": "/meɪk pəˈluːtəz peɪ/", "pron": "mayk puh-LOO-tuhz pay", "fr": "faire payer les pollueurs", "def": "To impose costs on those who cause pollution.", "ex": "Carbon taxes make polluters pay."}, {"term": "to improve tax compliance", "ipa": "/ɪmˈpruːv ˈtæks kəmˌplaɪəns/", "pron": "im-PROOV TAKS kuhm-PLY-uhns", "fr": "améliorer la conformité fiscale", "def": "To increase respect for tax rules.", "ex": "Simpler rules can improve tax compliance."}, {"term": "to fight tax avoidance", "ipa": "/faɪt ˈtæks əˌvɔɪdəns/", "pron": "fight TAKS uh-VOY-duhns", "fr": "lutter contre l’optimisation fiscale abusive", "def": "To take action against legal but abusive tax minimisation.", "ex": "International cooperation is needed to fight tax avoidance."}, {"term": "to harmonise tax rules", "ipa": "/ˈhɑːmənaɪz ˈtæks ruːlz/", "pron": "HAR-muh-nyze TAKS roolz", "fr": "harmoniser les règles fiscales", "def": "To make tax rules more similar across countries.", "ex": "The EU has debated how to harmonise tax rules."}]}]}, {"id": "p5c47", "part": 5, "chapter": 47, "title": "Poverty And Welfare", "file": "cpge_vocab_part5_chapter47_poverty_and_welfare_premium.html", "count": 186, "sections": [{"title": "A. Core poverty vocabulary and measurement", "entries": [{"term": "poverty", "ipa": "/ˈpɒvəti/", "pron": "POV-uh-tee", "fr": "pauvreté", "def": "The state of lacking enough money or resources to meet basic needs.", "ex": "Poverty affects health, education, housing and life chances."}, {"term": "absolute poverty", "ipa": "/ˌæbsəluːt ˈpɒvəti/", "pron": "AB-suh-loot POV-uh-tee", "fr": "pauvreté absolue", "def": "Poverty measured against a fixed minimum standard needed for survival.", "ex": "Absolute poverty is often linked to lack of food, shelter or clean water."}, {"term": "relative poverty", "ipa": "/ˌrelətɪv ˈpɒvəti/", "pron": "REL-uh-tiv POV-uh-tee", "fr": "pauvreté relative", "def": "Poverty measured in relation to the living standards of the society around you.", "ex": "Relative poverty can exist even in wealthy countries."}, {"term": "extreme poverty", "ipa": "/ɪkˌstriːm ˈpɒvəti/", "pron": "ik-STREEM POV-uh-tee", "fr": "extrême pauvreté", "def": "Very severe poverty, usually involving inability to meet basic survival needs.", "ex": "Extreme poverty has fallen globally but remains widespread in some regions."}, {"term": "deep poverty", "ipa": "/ˌdiːp ˈpɒvəti/", "pron": "deep POV-uh-tee", "fr": "grande pauvreté", "def": "Severe poverty far below the poverty line.", "ex": "Deep poverty often affects people with multiple disadvantages."}, {"term": "persistent poverty", "ipa": "/pəˌsɪstənt ˈpɒvəti/", "pron": "puh-SIS-tuhnt POV-uh-tee", "fr": "pauvreté persistante", "def": "Poverty that lasts over a long period.", "ex": "Persistent poverty can trap families across generations."}, {"term": "intergenerational poverty", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈpɒvəti/", "pron": "IN-tuh-jen-uh-RAY-shuh-nuhl POV-uh-tee", "fr": "pauvreté intergénérationnelle", "def": "Poverty passed from one generation to the next.", "ex": "Intergenerational poverty is linked to unequal education and housing."}, {"term": "child poverty", "ipa": "/ˈtʃaɪld ˌpɒvəti/", "pron": "CHYLD POV-uh-tee", "fr": "pauvreté infantile", "def": "Poverty affecting children.", "ex": "Child poverty has long-term effects on health and achievement."}, {"term": "working poverty", "ipa": "/ˈwɜːkɪŋ ˌpɒvəti/", "pron": "WUR-king POV-uh-tee", "fr": "pauvreté laborieuse", "def": "Poverty affecting people who are employed.", "ex": "Working poverty shows that having a job is not always enough."}, {"term": "in-work poverty", "ipa": "/ˌɪn wɜːk ˈpɒvəti/", "pron": "in-work POV-uh-tee", "fr": "pauvreté au travail", "def": "Poverty experienced by people who work but earn too little.", "ex": "In-work poverty is linked to low wages and insecure hours."}, {"term": "rural poverty", "ipa": "/ˌrʊərəl ˈpɒvəti/", "pron": "ROOR-uhl POV-uh-tee", "fr": "pauvreté rurale", "def": "Poverty in countryside or non-urban areas.", "ex": "Rural poverty is often linked to poor transport and limited services."}, {"term": "urban poverty", "ipa": "/ˌɜːbən ˈpɒvəti/", "pron": "UR-buhn POV-uh-tee", "fr": "pauvreté urbaine", "def": "Poverty in towns and cities.", "ex": "Urban poverty can be hidden in wealthy cities."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford enough energy or heating.", "ex": "Fuel poverty worsened during the energy price shock."}, {"term": "energy poverty", "ipa": "/ˈenədʒi ˌpɒvəti/", "pron": "EN-uh-jee POV-uh-tee", "fr": "précarité énergétique", "def": "Lack of access to affordable, reliable energy.", "ex": "Energy poverty affects both developing and wealthy countries."}, {"term": "food poverty", "ipa": "/ˈfuːd ˌpɒvəti/", "pron": "food POV-uh-tee", "fr": "précarité alimentaire", "def": "Inability to afford adequate food.", "ex": "Food poverty has increased demand for food banks."}, {"term": "period poverty", "ipa": "/ˈpɪəriəd ˌpɒvəti/", "pron": "PEER-ee-uhd POV-uh-tee", "fr": "précarité menstruelle", "def": "Lack of access to menstrual products because of poverty.", "ex": "Period poverty can cause girls to miss school."}, {"term": "digital poverty", "ipa": "/ˈdɪdʒɪtəl ˌpɒvəti/", "pron": "DIJ-i-tuhl POV-uh-tee", "fr": "précarité numérique", "def": "Lack of access to digital tools, internet or skills.", "ex": "Digital poverty limits access to education and jobs."}, {"term": "poverty line", "ipa": "/ˈpɒvəti laɪn/", "pron": "POV-uh-tee line", "fr": "seuil de pauvreté", "def": "The income level below which someone is considered poor.", "ex": "The poverty line is used to measure poverty rates."}, {"term": "poverty threshold", "ipa": "/ˈpɒvəti ˌθreʃhəʊld/", "pron": "POV-uh-tee THRESH-hohld", "fr": "seuil de pauvreté", "def": "The minimum income level used to define poverty.", "ex": "Poverty thresholds vary across countries."}, {"term": "poverty rate", "ipa": "/ˈpɒvəti reɪt/", "pron": "POV-uh-tee rayt", "fr": "taux de pauvreté", "def": "The share of a population living in poverty.", "ex": "The poverty rate rose after welfare cuts."}, {"term": "material deprivation", "ipa": "/məˌtɪəriəl ˌdeprɪˈveɪʃən/", "pron": "muh-TEER-ee-uhl dep-ri-VAY-shuhn", "fr": "privation matérielle", "def": "Lack of goods or conditions considered necessary for a decent life.", "ex": "Material deprivation includes inability to heat a home or replace clothes."}, {"term": "severe material deprivation", "ipa": "/sɪˌvɪə məˌtɪəriəl ˌdeprɪˈveɪʃən/", "pron": "si-VEER muh-TEER-ee-uhl dep-ri-VAY-shuhn", "fr": "privation matérielle sévère", "def": "Serious lack of basic goods or living conditions.", "ex": "Severe material deprivation is a key social indicator."}, {"term": "deprivation", "ipa": "/ˌdeprɪˈveɪʃən/", "pron": "dep-ri-VAY-shuhn", "fr": "privation", "def": "Lack of things necessary for a decent life.", "ex": "Deprivation can affect housing, food, education and health."}, {"term": "social deprivation", "ipa": "/ˌsəʊʃəl ˌdeprɪˈveɪʃən/", "pron": "SOH-shuhl dep-ri-VAY-shuhn", "fr": "privation sociale", "def": "Lack of social opportunities, resources or participation.", "ex": "Social deprivation can isolate communities."}, {"term": "financial hardship", "ipa": "/faɪˌnænʃəl ˈhɑːdʃɪp/", "pron": "fy-NAN-shuhl HARD-ship", "fr": "difficultés financières", "def": "Serious difficulty caused by lack of money.", "ex": "Financial hardship can lead to debt and homelessness."}, {"term": "economic hardship", "ipa": "/ˌiːkəˈnɒmɪk ˈhɑːdʃɪp/", "pron": "ee-kuh-NOM-ik HARD-ship", "fr": "difficultés économiques", "def": "Difficulty caused by unemployment, low income or high prices.", "ex": "Economic hardship often increases during recessions."}, {"term": "destitution", "ipa": "/ˌdestɪˈtjuːʃən/", "pron": "des-ti-TYOO-shuhn", "fr": "dénuement ; misère", "def": "Extreme poverty involving lack of basic necessities.", "ex": "Destitution can mean having no food, shelter or income."}, {"term": "hardship", "ipa": "/ˈhɑːdʃɪp/", "pron": "HARD-ship", "fr": "difficulté ; épreuve", "def": "Severe suffering or difficulty, especially financial.", "ex": "Low-income households face hardship when prices rise."}, {"term": "social exclusion", "ipa": "/ˌsəʊʃəl ɪkˈskluːʒən/", "pron": "SOH-shuhl ik-SKLOO-zhuhn", "fr": "exclusion sociale", "def": "Being cut off from opportunities, services or participation in society.", "ex": "Poverty often leads to social exclusion."}, {"term": "marginalisation", "ipa": "/ˌmɑːdʒɪnəlaɪˈzeɪʃən/", "pron": "mar-ji-nuh-ly-ZAY-shuhn", "fr": "marginalisation", "def": "The process of pushing people or groups to the edge of society.", "ex": "Marginalisation makes it harder to escape poverty."}, {"term": "vulnerability", "ipa": "/ˌvʌlnərəˈbɪləti/", "pron": "vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité", "def": "Exposure to risk or harm because of weak protection or resources.", "ex": "Poverty increases vulnerability to crises."}, {"term": "vulnerable households", "ipa": "/ˈvʌlnərəbəl ˈhaʊshəʊldz/", "pron": "VUL-nuh-ruh-buhl HOWSS-hohldz", "fr": "ménages vulnérables", "def": "Households more likely to suffer hardship or crisis.", "ex": "Vulnerable households need targeted support."}]}, {"title": "B. Income, hardship, housing and food insecurity", "entries": [{"term": "low-income households", "ipa": "/ˌləʊ ˈɪnkʌm ˈhaʊshəʊldz/", "pron": "loh IN-kum HOWSS-hohldz", "fr": "ménages à faible revenu", "def": "Households with limited income.", "ex": "Low-income households spend more of their budget on essentials."}, {"term": "low-income families", "ipa": "/ˌləʊ ˈɪnkʌm ˈfæməliz/", "pron": "loh IN-kum FAM-uh-leez", "fr": "familles à faible revenu", "def": "Families with low earnings or benefits.", "ex": "Low-income families are vulnerable to food and fuel poverty."}, {"term": "the poor", "ipa": "/ðə ˈpʊə/", "pron": "thuh poor", "fr": "les pauvres", "def": "People living in poverty; use carefully as it can sound reductive.", "ex": "Policies should help poor people without stigmatising them."}, {"term": "working class", "ipa": "/ˌwɜːkɪŋ ˈklɑːs/", "pron": "WUR-king class", "fr": "classe ouvrière ; classes populaires", "def": "People in manual, service or lower-paid jobs, often with less economic power.", "ex": "The working class has been affected by deindustrialisation."}, {"term": "underclass", "ipa": "/ˈʌndəklɑːs/", "pron": "UN-duh-class", "fr": "sous-classe sociale", "def": "A controversial term for a group seen as permanently poor and excluded.", "ex": "The term underclass can be stigmatising."}, {"term": "disadvantaged", "ipa": "/ˌdɪsədˈvɑːntɪdʒd/", "pron": "dis-ad-VAN-tijd", "fr": "défavorisé", "def": "Having fewer opportunities or resources than others.", "ex": "Disadvantaged pupils often need extra support."}, {"term": "disadvantaged communities", "ipa": "/ˌdɪsədˈvɑːntɪdʒd kəˈmjuːnətiz/", "pron": "dis-ad-VAN-tijd kuh-MYOO-nuh-teez", "fr": "communautés défavorisées", "def": "Communities with fewer resources, services and opportunities.", "ex": "Disadvantaged communities may suffer from poor housing and schools."}, {"term": "left-behind communities", "ipa": "/ˌleft bɪˈhaɪnd kəˈmjuːnətiz/", "pron": "left-bi-HYND kuh-MYOO-nuh-teez", "fr": "communautés laissées pour compte", "def": "Communities that have not benefited from economic growth or globalisation.", "ex": "Left-behind communities often feel ignored by political elites."}, {"term": "income", "ipa": "/ˈɪnkʌm/", "pron": "IN-kum", "fr": "revenu", "def": "Money received from work, benefits, investment or other sources.", "ex": "Income determines access to housing and consumption."}, {"term": "household income", "ipa": "/ˌhaʊshəʊld ˈɪnkʌm/", "pron": "HOWSS-hohld IN-kum", "fr": "revenu du ménage", "def": "Total income received by all members of a household.", "ex": "Household income is used to measure poverty."}, {"term": "disposable income", "ipa": "/dɪˌspəʊzəbəl ˈɪnkʌm/", "pron": "di-SPOH-zuh-buhl IN-kum", "fr": "revenu disponible", "def": "Income left after taxes and transfers.", "ex": "Disposable income affects living standards."}, {"term": "real income", "ipa": "/ˌrɪəl ˈɪnkʌm/", "pron": "REE-uhl IN-kum", "fr": "revenu réel", "def": "Income adjusted for inflation.", "ex": "Real income falls when prices rise faster than wages."}, {"term": "wealth", "ipa": "/welθ/", "pron": "welth", "fr": "patrimoine ; richesse", "def": "Assets owned by a person or household, such as property or savings.", "ex": "Wealth inequality is often greater than income inequality."}, {"term": "assets", "ipa": "/ˈæsets/", "pron": "AS-ets", "fr": "actifs ; biens", "def": "Things owned that have value.", "ex": "Housing is a major asset for many families."}, {"term": "savings", "ipa": "/ˈseɪvɪŋz/", "pron": "SAY-vingz", "fr": "épargne", "def": "Money kept rather than spent.", "ex": "People without savings are vulnerable to shocks."}, {"term": "debt", "ipa": "/det/", "pron": "det", "fr": "dette", "def": "Money owed to another person, bank or institution.", "ex": "Household debt can worsen poverty."}, {"term": "household debt", "ipa": "/ˌhaʊshəʊld ˈdet/", "pron": "HOWSS-hohld det", "fr": "endettement des ménages", "def": "Debt owed by households.", "ex": "Household debt rises when wages cannot cover living costs."}, {"term": "personal debt", "ipa": "/ˌpɜːsənəl ˈdet/", "pron": "PUR-suh-nuhl det", "fr": "dette personnelle", "def": "Debt owed by an individual.", "ex": "Personal debt can spiral through interest charges."}, {"term": "debt trap", "ipa": "/ˈdet træp/", "pron": "det trap", "fr": "piège de l’endettement", "def": "A situation where debt becomes difficult to escape.", "ex": "Payday loans can create a debt trap."}, {"term": "payday loan", "ipa": "/ˈpeɪdeɪ ləʊn/", "pron": "PAY-day lohn", "fr": "prêt sur salaire", "def": "A short-term high-interest loan, often used by people in financial difficulty.", "ex": "Payday loans can worsen financial hardship."}, {"term": "loan shark", "ipa": "/ˈləʊn ʃɑːk/", "pron": "lohn shark", "fr": "usurier ; prêteur illégal", "def": "An illegal lender charging very high interest.", "ex": "Loan sharks exploit vulnerable borrowers."}, {"term": "cost of living", "ipa": "/ˌkɒst əv ˈlɪvɪŋ/", "pron": "kost ov LIV-ing", "fr": "coût de la vie", "def": "The money needed to pay for basic goods and services.", "ex": "The cost of living rose faster than wages."}, {"term": "cost-of-living crisis", "ipa": "/ˌkɒst əv ˈlɪvɪŋ ˈkraɪsɪs/", "pron": "kost-ov-LIV-ing KRY-sis", "fr": "crise du coût de la vie", "def": "A situation where essential costs rise faster than incomes.", "ex": "The cost-of-living crisis pushed more families into poverty."}, {"term": "inflation", "ipa": "/ɪnˈfleɪʃən/", "pron": "in-FLAY-shuhn", "fr": "inflation", "def": "A general increase in prices.", "ex": "Inflation hits poor households hardest."}, {"term": "purchasing power", "ipa": "/ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "PUR-chuh-sing POW-uh", "fr": "pouvoir d’achat", "def": "The amount of goods and services money can buy.", "ex": "Falling purchasing power creates hardship."}, {"term": "living standards", "ipa": "/ˈlɪvɪŋ ˌstændədz/", "pron": "LIV-ing STAN-duhdz", "fr": "niveau de vie", "def": "The material conditions in which people live.", "ex": "Living standards declined during the crisis."}, {"term": "standard of living", "ipa": "/ˌstændəd əv ˈlɪvɪŋ/", "pron": "STAN-duhd ov LIV-ing", "fr": "niveau de vie", "def": "The level of comfort and material well-being available to people.", "ex": "A decent standard of living requires stable income."}, {"term": "basic needs", "ipa": "/ˌbeɪsɪk ˈniːdz/", "pron": "BAY-sik needz", "fr": "besoins fondamentaux", "def": "Essential requirements such as food, shelter, warmth and healthcare.", "ex": "Welfare should ensure that basic needs are met."}, {"term": "essentials", "ipa": "/ɪˈsenʃəlz/", "pron": "i-SEN-shuhlz", "fr": "produits de première nécessité", "def": "Necessary goods or services.", "ex": "Poor households spend most of their income on essentials."}, {"term": "housing insecurity", "ipa": "/ˈhaʊzɪŋ ˌɪnsɪˈkjʊərəti/", "pron": "HOW-zing in-si-KYOOR-uh-tee", "fr": "insécurité résidentielle", "def": "Unstable, unsafe or unaffordable housing conditions.", "ex": "Housing insecurity affects children’s education."}, {"term": "homelessness", "ipa": "/ˈhəʊmləsnəs/", "pron": "HOHM-luhs-nuhs", "fr": "sans-abrisme ; absence de logement", "def": "The state of lacking a safe and stable home.", "ex": "Homelessness is an extreme form of social exclusion."}, {"term": "rough sleeping", "ipa": "/ˌrʌf ˈsliːpɪŋ/", "pron": "ruff SLEEP-ing", "fr": "sans-abrisme de rue", "def": "Sleeping outdoors because of homelessness.", "ex": "Rough sleeping is visible in many wealthy cities."}, {"term": "eviction", "ipa": "/ɪˈvɪkʃən/", "pron": "i-VIK-shuhn", "fr": "expulsion locative", "def": "Forced removal from a home, usually for unpaid rent.", "ex": "Eviction can push families into homelessness."}, {"term": "rent arrears", "ipa": "/ˈrent əˌrɪəz/", "pron": "rent uh-REERZ", "fr": "arriérés de loyer", "def": "Unpaid rent owed to a landlord.", "ex": "Rent arrears increased during the cost-of-living crisis."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Lack of reliable access to enough nutritious food.", "ex": "Food insecurity harms children’s health and concentration."}, {"term": "malnutrition", "ipa": "/ˌmælnjuːˈtrɪʃən/", "pron": "mal-nyoo-TRISH-uhn", "fr": "malnutrition", "def": "Poor health caused by too little or unbalanced food.", "ex": "Malnutrition can exist even in rich countries."}, {"term": "hunger", "ipa": "/ˈhʌŋɡə/", "pron": "HUNG-guh", "fr": "faim", "def": "The physical need or lack of food.", "ex": "No child should experience hunger in a wealthy society."}, {"term": "food bank", "ipa": "/ˈfuːd bæŋk/", "pron": "food bank", "fr": "banque alimentaire", "def": "A charity or organisation giving food to people in need.", "ex": "Food bank use has risen sharply."}]}, {"title": "C. Welfare state, benefits and social protection", "entries": [{"term": "free school meals", "ipa": "/ˌfriː skuːl ˈmiːlz/", "pron": "free school meelz", "fr": "repas scolaires gratuits", "def": "Meals provided free to children from low-income families.", "ex": "Free school meals can reduce child hunger."}, {"term": "welfare", "ipa": "/ˈwelfeə/", "pron": "WEL-fair", "fr": "aide sociale ; protection sociale", "def": "State support for people in need, often through benefits and services.", "ex": "Welfare protects citizens from poverty and hardship."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system in which the state provides social protection, healthcare, pensions and benefits.", "ex": "The welfare state reduces poverty through transfers and services."}, {"term": "social welfare", "ipa": "/ˌsəʊʃəl ˈwelfeə/", "pron": "SOH-shuhl WEL-fair", "fr": "aide sociale", "def": "Public support designed to improve well-being and protect people in need.", "ex": "Social welfare includes benefits, housing support and social services."}, {"term": "social protection", "ipa": "/ˌsəʊʃəl prəˈtekʃən/", "pron": "SOH-shuhl pruh-TEK-shuhn", "fr": "protection sociale", "def": "Policies protecting people from poverty, illness, unemployment or old age.", "ex": "Social protection is crucial during economic crises."}, {"term": "safety net", "ipa": "/ˈseɪfti net/", "pron": "SAYF-tee net", "fr": "filet de sécurité", "def": "Support that prevents people from falling into extreme hardship.", "ex": "A strong safety net prevents destitution."}, {"term": "social safety net", "ipa": "/ˌsəʊʃəl ˈseɪfti net/", "pron": "SOH-shuhl SAYF-tee net", "fr": "filet de sécurité sociale", "def": "A system of benefits and services protecting people from hardship.", "ex": "The social safety net was expanded during the pandemic."}, {"term": "benefits", "ipa": "/ˈbenɪfɪts/", "pron": "BEN-i-fits", "fr": "prestations ; allocations", "def": "Payments or support provided by the state or employer.", "ex": "Benefits help low-income households pay for essentials."}, {"term": "welfare benefits", "ipa": "/ˈwelfeə ˌbenɪfɪts/", "pron": "WEL-fair BEN-i-fits", "fr": "prestations sociales", "def": "State payments to people needing financial support.", "ex": "Welfare benefits are often politically contested."}, {"term": "social benefits", "ipa": "/ˈsəʊʃəl ˌbenɪfɪts/", "pron": "SOH-shuhl BEN-i-fits", "fr": "prestations sociales", "def": "Benefits provided through social protection systems.", "ex": "Social benefits reduce poverty rates."}, {"term": "cash transfer", "ipa": "/ˈkæʃ ˌtrænsfɜː/", "pron": "cash TRANS-fur", "fr": "transfert monétaire", "def": "Money paid directly to individuals or households.", "ex": "Cash transfers can reduce poverty efficiently."}, {"term": "means-tested benefit", "ipa": "/ˌmiːnz testɪd ˈbenɪfɪt/", "pron": "meenz-tested BEN-i-fit", "fr": "prestation sous condition de ressources", "def": "A benefit given only to people below a certain income or wealth level.", "ex": "Means-tested benefits target limited resources."}, {"term": "universal benefit", "ipa": "/ˌjuːnɪˈvɜːsəl ˈbenɪfɪt/", "pron": "yoo-ni-VUR-suhl BEN-i-fit", "fr": "prestation universelle", "def": "A benefit available to everyone in a category, regardless of income.", "ex": "Universal benefits reduce stigma but cost more."}, {"term": "child benefit", "ipa": "/ˈtʃaɪld ˌbenɪfɪt/", "pron": "CHYLD BEN-i-fit", "fr": "allocations familiales", "def": "A payment to families with children.", "ex": "Child benefit helps families cover costs."}, {"term": "housing benefit", "ipa": "/ˈhaʊzɪŋ ˌbenɪfɪt/", "pron": "HOW-zing BEN-i-fit", "fr": "aide au logement", "def": "Support helping low-income people pay rent.", "ex": "Housing benefit can prevent eviction."}, {"term": "unemployment benefit", "ipa": "/ˌʌnɪmˈplɔɪmənt ˈbenɪfɪt/", "pron": "un-im-PLOY-muhnt BEN-i-fit", "fr": "allocation chômage", "def": "Money paid to people who are unemployed.", "ex": "Unemployment benefit supports workers between jobs."}, {"term": "disability benefit", "ipa": "/ˌdɪsəˈbɪləti ˈbenɪfɪt/", "pron": "dis-uh-BIL-uh-tee BEN-i-fit", "fr": "allocation handicap ; prestation d’invalidité", "def": "Support for people with disabilities or health conditions.", "ex": "Disability benefits help cover additional living costs."}, {"term": "pension", "ipa": "/ˈpenʃən/", "pron": "PEN-shuhn", "fr": "retraite ; pension", "def": "Regular income paid to people after retirement.", "ex": "Pensions reduce poverty in old age."}, {"term": "state pension", "ipa": "/ˌsteɪt ˈpenʃən/", "pron": "state PEN-shuhn", "fr": "pension publique", "def": "A pension paid by the government.", "ex": "The state pension is a major welfare benefit."}, {"term": "universal basic income", "ipa": "/ˌjuːnɪˈvɜːsəl ˌbeɪsɪk ˈɪnkʌm/", "pron": "yoo-ni-VUR-suhl BAY-sik IN-kum", "fr": "revenu universel", "def": "A regular payment given to all citizens without conditions.", "ex": "Universal basic income is proposed as a response to automation."}, {"term": "UBI", "ipa": "/ˌjuː biː ˈaɪ/", "pron": "yoo-bee-eye", "fr": "RBI ; revenu universel", "def": "Abbreviation for universal basic income.", "ex": "UBI would simplify the welfare system."}, {"term": "minimum income", "ipa": "/ˌmɪnɪməm ˈɪnkʌm/", "pron": "MIN-i-muhm IN-kum", "fr": "revenu minimum", "def": "A guaranteed minimum level of income.", "ex": "A minimum income can prevent extreme poverty."}, {"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal wage employers can pay.", "ex": "Raising the minimum wage can reduce in-work poverty."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "A living wage is meant to cover essentials."}, {"term": "tax credit", "ipa": "/ˈtæks ˌkredɪt/", "pron": "TAKS KRED-it", "fr": "crédit d’impôt ; aide fiscale", "def": "A tax reduction or payment used to support low-income households.", "ex": "Tax credits can top up low wages."}, {"term": "negative income tax", "ipa": "/ˌneɡətɪv ˈɪnkʌm tæks/", "pron": "NEG-uh-tiv IN-kum taks", "fr": "impôt négatif sur le revenu", "def": "A system where people below a certain income receive money from the state.", "ex": "A negative income tax is an alternative to traditional welfare."}, {"term": "redistribution", "ipa": "/ˌriːdɪstrɪˈbjuːʃən/", "pron": "ree-dis-tri-BYOO-shuhn", "fr": "redistribution", "def": "The transfer of income or wealth through taxation and public spending.", "ex": "Redistribution can reduce poverty and inequality."}, {"term": "income redistribution", "ipa": "/ˈɪnkʌm ˌriːdɪstrɪˈbjuːʃən/", "pron": "IN-kum ree-dis-tri-BYOO-shuhn", "fr": "redistribution des revenus", "def": "Redistribution of income between groups.", "ex": "Income redistribution is a central role of the welfare state."}, {"term": "wealth redistribution", "ipa": "/ˈwelθ ˌriːdɪstrɪˈbjuːʃən/", "pron": "welth ree-dis-tri-BYOO-shuhn", "fr": "redistribution des richesses", "def": "Redistribution of assets or wealth.", "ex": "Wealth redistribution is controversial."}, {"term": "progressive taxation", "ipa": "/prəˌɡresɪv tækˈseɪʃən/", "pron": "pruh-GRES-iv tak-SAY-shuhn", "fr": "fiscalité progressive", "def": "Taxation where richer people pay a higher share of income.", "ex": "Progressive taxation helps finance redistribution."}, {"term": "tax-funded welfare", "ipa": "/ˈtæks ˌfʌndɪd ˈwelfeə/", "pron": "TAKS FUN-did WEL-fair", "fr": "protection sociale financée par l’impôt", "def": "Welfare paid for through taxation.", "ex": "Tax-funded welfare depends on public support."}, {"term": "public services", "ipa": "/ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "PUB-lik SUR-vis-iz", "fr": "services publics", "def": "Services provided or funded by the state.", "ex": "Public services reduce the cost of living for families."}, {"term": "healthcare access", "ipa": "/ˈhelθkeə ˌækses/", "pron": "HELTH-care AK-sess", "fr": "accès aux soins", "def": "The ability to obtain healthcare services.", "ex": "Healthcare access can reduce inequality."}, {"term": "education access", "ipa": "/ˌedjʊˈkeɪʃən ˌækses/", "pron": "ej-yoo-KAY-shuhn AK-sess", "fr": "accès à l’éducation", "def": "The ability to obtain education.", "ex": "Education access is key to social mobility."}, {"term": "social housing", "ipa": "/ˌsəʊʃəl ˈhaʊzɪŋ/", "pron": "SOH-shuhl HOW-zing", "fr": "logement social", "def": "Affordable housing provided or supported by the state.", "ex": "Social housing can reduce homelessness."}, {"term": "affordable housing", "ipa": "/əˌfɔːdəbəl ˈhaʊzɪŋ/", "pron": "uh-FOR-duh-buhl HOW-zing", "fr": "logement abordable", "def": "Housing that people can pay for without hardship.", "ex": "Affordable housing is essential to anti-poverty policy."}, {"term": "welfare reform", "ipa": "/ˈwelfeə rɪˌfɔːm/", "pron": "WEL-fair ri-FORM", "fr": "réforme de l’aide sociale", "def": "Changes to the welfare system.", "ex": "Welfare reform can either strengthen or weaken support."}, {"term": "benefit cap", "ipa": "/ˈbenɪfɪt kæp/", "pron": "BEN-i-fit kap", "fr": "plafonnement des aides", "def": "A limit on the total amount of benefits a household can receive.", "ex": "A benefit cap can push larger families into poverty."}, {"term": "benefit cut", "ipa": "/ˈbenɪfɪt kʌt/", "pron": "BEN-i-fit kut", "fr": "baisse des prestations", "def": "A reduction in welfare benefits.", "ex": "Benefit cuts can increase hardship."}, {"term": "benefit freeze", "ipa": "/ˈbenɪfɪt friːz/", "pron": "BEN-i-fit freez", "fr": "gel des prestations", "def": "A policy keeping benefits at the same cash level despite inflation.", "ex": "A benefit freeze reduces support in real terms."}]}, {"title": "D. Welfare reform, stigma, mobility and structural causes", "entries": [{"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions sur les prestations", "def": "Penalties reducing or stopping benefits for not meeting conditions.", "ex": "Benefit sanctions can cause severe hardship."}, {"term": "conditionality", "ipa": "/kənˌdɪʃəˈnæləti/", "pron": "kuhn-dish-uh-NAL-uh-tee", "fr": "conditionnalité", "def": "Conditions attached to receiving welfare support.", "ex": "Welfare conditionality is meant to encourage work."}, {"term": "work requirement", "ipa": "/ˈwɜːk rɪˌkwaɪəmənt/", "pron": "work ri-KWY-uh-muhnt", "fr": "obligation de recherche d’emploi", "def": "A rule requiring welfare recipients to seek or accept work.", "ex": "Work requirements are controversial."}, {"term": "welfare dependency", "ipa": "/ˈwelfeə dɪˌpendənsi/", "pron": "WEL-fair di-PEN-duhn-see", "fr": "dépendance aux aides sociales", "def": "A controversial idea that people may become reliant on benefits.", "ex": "The language of welfare dependency can stigmatise recipients."}, {"term": "benefit claimant", "ipa": "/ˈbenɪfɪt ˌkleɪmənt/", "pron": "BEN-i-fit KLAY-muhnt", "fr": "allocataire ; bénéficiaire d’aides", "def": "A person applying for or receiving welfare benefits.", "ex": "Benefit claimants often face bureaucracy."}, {"term": "recipient", "ipa": "/rɪˈsɪpiənt/", "pron": "ri-SIP-ee-uhnt", "fr": "bénéficiaire", "def": "A person receiving money, support or services.", "ex": "Recipients may receive cash or in-kind support."}, {"term": "stigma", "ipa": "/ˈstɪɡmə/", "pron": "STIG-muh", "fr": "stigmatisation", "def": "Shame or negative judgement attached to a condition or identity.", "ex": "Welfare stigma can prevent people from claiming support."}, {"term": "take-up rate", "ipa": "/ˈteɪk ʌp reɪt/", "pron": "take-up rayt", "fr": "taux de recours", "def": "The percentage of eligible people who actually claim a benefit.", "ex": "Low take-up rates mean support does not reach everyone."}, {"term": "non-take-up", "ipa": "/ˌnɒn teɪk ˈʌp/", "pron": "non-take-up", "fr": "non-recours", "def": "Failure to claim benefits or support despite eligibility.", "ex": "Non-take-up is often caused by stigma or complexity."}, {"term": "bureaucracy", "ipa": "/bjʊəˈrɒkrəsi/", "pron": "byoo-ROK-ruh-see", "fr": "bureaucratie", "def": "Complex administrative rules and procedures.", "ex": "Bureaucracy can discourage people from claiming benefits."}, {"term": "means test", "ipa": "/ˈmiːnz test/", "pron": "meenz test", "fr": "condition de ressources", "def": "An assessment of income or wealth to decide eligibility for support.", "ex": "A means test targets support but can create complexity."}, {"term": "eligibility", "ipa": "/ˌelɪdʒəˈbɪləti/", "pron": "el-i-juh-BIL-uh-tee", "fr": "éligibilité", "def": "The condition of meeting rules to receive support.", "ex": "Eligibility rules can exclude vulnerable people."}, {"term": "universalism", "ipa": "/ˌjuːnɪˈvɜːsəlɪzəm/", "pron": "yoo-ni-VUR-suh-liz-uhm", "fr": "universalisme", "def": "The principle that benefits or services should be available to everyone.", "ex": "Universalism can build public support for welfare."}, {"term": "targeting", "ipa": "/ˈtɑːɡɪtɪŋ/", "pron": "TAR-git-ing", "fr": "ciblage", "def": "Directing support at specific groups in need.", "ex": "Targeting can save money but miss some households."}, {"term": "social mobility", "ipa": "/ˌsəʊʃəl məʊˈbɪləti/", "pron": "SOH-shuhl moh-BIL-uh-tee", "fr": "mobilité sociale", "def": "Movement between social classes or income groups.", "ex": "Poverty reduces social mobility."}, {"term": "upward mobility", "ipa": "/ˌʌpwəd məʊˈbɪləti/", "pron": "UP-wuhd moh-BIL-uh-tee", "fr": "mobilité ascendante", "def": "Movement to a higher social or economic position.", "ex": "Education can promote upward mobility."}, {"term": "downward mobility", "ipa": "/ˌdaʊnwəd məʊˈbɪləti/", "pron": "DOWN-wuhd moh-BIL-uh-tee", "fr": "mobilité descendante", "def": "Movement to a lower social or economic position.", "ex": "Job loss can cause downward mobility."}, {"term": "life chances", "ipa": "/ˈlaɪf ˌtʃɑːnsɪz/", "pron": "life CHAN-siz", "fr": "chances dans la vie", "def": "Opportunities someone has for success, health and well-being.", "ex": "Poverty damages children’s life chances."}, {"term": "opportunity gap", "ipa": "/ˌɒpəˈtjuːnəti ɡæp/", "pron": "op-uh-TYOO-nuh-tee gap", "fr": "écart d’opportunités", "def": "Unequal access to opportunities.", "ex": "The opportunity gap begins early in childhood."}, {"term": "educational inequality", "ipa": "/ˌedjʊˈkeɪʃənəl ˌɪnɪˈkwɒləti/", "pron": "ej-yoo-KAY-shuh-nuhl in-i-KWOL-uh-tee", "fr": "inégalités scolaires", "def": "Unequal access to educational success or resources.", "ex": "Educational inequality reproduces poverty."}, {"term": "health inequality", "ipa": "/ˈhelθ ˌɪnɪˈkwɒləti/", "pron": "helth in-i-KWOL-uh-tee", "fr": "inégalités de santé", "def": "Unequal health outcomes between social groups.", "ex": "Poverty is a major driver of health inequality."}, {"term": "postcode lottery", "ipa": "/ˈpəʊstkəʊd ˌlɒtəri/", "pron": "POST-kohd LOT-uh-ree", "fr": "inégalité territoriale d’accès", "def": "Unequal access to services depending on where someone lives.", "ex": "Healthcare access can become a postcode lottery."}, {"term": "social determinants of health", "ipa": "/ˌsəʊʃəl dɪˌtɜːmɪnənts əv ˈhelθ/", "pron": "SOH-shuhl di-TUR-mi-nuhnts ov helth", "fr": "déterminants sociaux de la santé", "def": "Social conditions shaping health, such as income, housing and education.", "ex": "Poverty is one of the key social determinants of health."}, {"term": "cycle of poverty", "ipa": "/ˌsaɪkəl əv ˈpɒvəti/", "pron": "SY-kuhl ov POV-uh-tee", "fr": "cycle de la pauvreté", "def": "A self-reinforcing process that keeps people poor over time.", "ex": "Poor education and poor health can create a cycle of poverty."}, {"term": "poverty trap", "ipa": "/ˈpɒvəti træp/", "pron": "POV-uh-tee trap", "fr": "piège de la pauvreté", "def": "A situation where it is difficult to escape poverty because of structural barriers.", "ex": "High childcare costs can create a poverty trap."}, {"term": "benefit trap", "ipa": "/ˈbenɪfɪt træp/", "pron": "BEN-i-fit trap", "fr": "trappe à inactivité", "def": "A situation where taking work may not significantly improve income because benefits are withdrawn.", "ex": "A benefit trap can discourage low-paid work."}, {"term": "low-wage economy", "ipa": "/ˌləʊ weɪdʒ iˈkɒnəmi/", "pron": "loh-wayj i-KON-uh-mee", "fr": "économie de bas salaires", "def": "An economy relying heavily on low-paid jobs.", "ex": "A low-wage economy produces in-work poverty."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "travail précaire", "def": "Work that is insecure, poorly paid or lacking protection.", "ex": "Precarious work makes household income unstable."}, {"term": "job insecurity", "ipa": "/ˈdʒɒb ˌɪnsɪˈkjʊərəti/", "pron": "job in-si-KYOOR-uh-tee", "fr": "insécurité de l’emploi", "def": "Fear or risk of losing work or income.", "ex": "Job insecurity increases stress and debt."}, {"term": "unemployment", "ipa": "/ˌʌnɪmˈplɔɪmənt/", "pron": "un-im-PLOY-muhnt", "fr": "chômage", "def": "Being without work while available for work.", "ex": "Unemployment remains a major cause of poverty."}, {"term": "long-term unemployment", "ipa": "/ˌlɒŋ tɜːm ˌʌnɪmˈplɔɪmənt/", "pron": "long-term un-im-PLOY-muhnt", "fr": "chômage de longue durée", "def": "Unemployment lasting a long period, often over a year.", "ex": "Long-term unemployment reduces employability."}, {"term": "social investment", "ipa": "/ˌsəʊʃəl ɪnˈvestmənt/", "pron": "SOH-shuhl in-VEST-muhnt", "fr": "investissement social", "def": "Public spending designed to improve future opportunities and reduce risk.", "ex": "Early-childhood education is a form of social investment."}, {"term": "early childhood education", "ipa": "/ˌɜːli ˈtʃaɪldhʊd ˌedjʊˈkeɪʃən/", "pron": "UR-lee CHYLD-hood ej-yoo-KAY-shuhn", "fr": "éducation de la petite enfance", "def": "Education and care for young children before school age.", "ex": "Early childhood education can reduce inequality."}, {"term": "childcare", "ipa": "/ˈtʃaɪldkeə/", "pron": "CHYLD-care", "fr": "garde d’enfants", "def": "Care for children while parents work or study.", "ex": "Affordable childcare helps parents work."}, {"term": "affordable childcare", "ipa": "/əˌfɔːdəbəl ˈtʃaɪldkeə/", "pron": "uh-FOR-duh-buhl CHYLD-care", "fr": "garde d’enfants abordable", "def": "Childcare that families can pay for without hardship.", "ex": "Affordable childcare can reduce child poverty."}, {"term": "skills training", "ipa": "/ˈskɪlz ˌtreɪnɪŋ/", "pron": "skilz TRAY-ning", "fr": "formation professionnelle", "def": "Training that develops useful work skills.", "ex": "Skills training can help unemployed people find work."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion", "def": "Training people for new kinds of jobs.", "ex": "Reskilling helps workers adapt to economic change."}, {"term": "active labour market policy", "ipa": "/ˌæktɪv ˈleɪbə ˈmɑːkɪt ˈpɒləsi/", "pron": "AK-tiv LAY-buh MAR-kit POL-uh-see", "fr": "politique active du marché du travail", "def": "Policy helping unemployed people find work through training, support or incentives.", "ex": "Active labour market policies can reduce unemployment."}, {"term": "public assistance", "ipa": "/ˌpʌblɪk əˈsɪstəns/", "pron": "PUB-lik uh-SIS-tuhns", "fr": "aide publique ; assistance sociale", "def": "State support for people in financial need.", "ex": "Public assistance prevents destitution."}, {"term": "charity", "ipa": "/ˈtʃærəti/", "pron": "CHAR-uh-tee", "fr": "association caritative ; charité", "def": "An organisation helping people in need, or voluntary giving.", "ex": "Charity can help, but it cannot replace the welfare state."}, {"term": "philanthropy", "ipa": "/fɪˈlænθrəpi/", "pron": "fi-LAN-thruh-pee", "fr": "philanthropie", "def": "Private giving to support public or social causes.", "ex": "Philanthropy can fund innovation but is not democratically accountable."}, {"term": "mutual aid", "ipa": "/ˌmjuːtʃuəl ˈeɪd/", "pron": "MYOO-choo-uhl aid", "fr": "entraide", "def": "Community support based on people helping each other.", "ex": "Mutual aid networks expanded during the pandemic."}, {"term": "community support", "ipa": "/kəˌmjuːnəti səˈpɔːt/", "pron": "kuh-MYOO-nuh-tee suh-PORT", "fr": "soutien communautaire", "def": "Help provided by local groups, neighbours or organisations.", "ex": "Community support reduces isolation and hardship."}]}, {"title": "E. Anti-poverty policy, justice and high-value verbs", "entries": [{"term": "anti-poverty policy", "ipa": "/ˌænti ˈpɒvəti ˈpɒləsi/", "pron": "AN-tee POV-uh-tee POL-uh-see", "fr": "politique de lutte contre la pauvreté", "def": "Policy designed to reduce poverty.", "ex": "Anti-poverty policy must address housing, wages and benefits."}, {"term": "poverty reduction", "ipa": "/ˈpɒvəti rɪˌdʌkʃən/", "pron": "POV-uh-tee ri-DUK-shuhn", "fr": "réduction de la pauvreté", "def": "The process of reducing poverty.", "ex": "Poverty reduction requires both income support and opportunity."}, {"term": "poverty alleviation", "ipa": "/ˈpɒvəti əˌliːviˈeɪʃən/", "pron": "POV-uh-tee uh-lee-vee-AY-shuhn", "fr": "allègement de la pauvreté", "def": "Action that reduces the severity of poverty.", "ex": "Cash transfers can support poverty alleviation."}, {"term": "social justice", "ipa": "/ˌsəʊʃəl ˈdʒʌstɪs/", "pron": "SOH-shuhl JUS-tis", "fr": "justice sociale", "def": "Fairness in the distribution of rights, opportunities and resources.", "ex": "Poverty is a social justice issue."}, {"term": "economic justice", "ipa": "/ˌiːkəˈnɒmɪk ˈdʒʌstɪs/", "pron": "ee-kuh-NOM-ik JUS-tis", "fr": "justice économique", "def": "Fairness in economic opportunities, pay and resources.", "ex": "Economic justice requires fair wages and tax systems."}, {"term": "dignity", "ipa": "/ˈdɪɡnəti/", "pron": "DIG-nuh-tee", "fr": "dignité", "def": "The value and respect every person deserves.", "ex": "Welfare should protect human dignity."}, {"term": "solidarity", "ipa": "/ˌsɒlɪˈdærəti/", "pron": "sol-i-DARR-uh-tee", "fr": "solidarité", "def": "Mutual support within society.", "ex": "The welfare state is based on solidarity."}, {"term": "deserving poor", "ipa": "/dɪˌzɜːvɪŋ ˈpʊə/", "pron": "di-ZUR-ving poor", "fr": "pauvres méritants", "def": "A problematic distinction suggesting some poor people deserve help more than others.", "ex": "The idea of the deserving poor can stigmatise people."}, {"term": "undeserving poor", "ipa": "/ˌʌndɪˌzɜːvɪŋ ˈpʊə/", "pron": "un-di-ZUR-ving poor", "fr": "pauvres non méritants", "def": "A stigmatising term for poor people considered not to deserve help.", "ex": "The label undeserving poor is often used to justify cuts."}, {"term": "welfare stigma", "ipa": "/ˈwelfeə ˌstɪɡmə/", "pron": "WEL-fair STIG-muh", "fr": "stigmatisation des bénéficiaires d’aides", "def": "Shame or judgement attached to receiving benefits.", "ex": "Welfare stigma reduces take-up."}, {"term": "scapegoating", "ipa": "/ˈskeɪpɡəʊtɪŋ/", "pron": "SKAYP-goht-ing", "fr": "désignation d’un bouc émissaire", "def": "Unfairly blaming a group for wider problems.", "ex": "Scapegoating benefit claimants distracts from structural poverty."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies reducing public spending or deficits.", "ex": "Austerity can increase poverty if benefits and services are cut."}, {"term": "spending cuts", "ipa": "/ˈspendɪŋ kʌts/", "pron": "SPEN-ding kuts", "fr": "coupes budgétaires", "def": "Reductions in public expenditure.", "ex": "Spending cuts weakened local services."}, {"term": "public spending", "ipa": "/ˌpʌblɪk ˈspendɪŋ/", "pron": "PUB-lik SPEN-ding", "fr": "dépenses publiques", "def": "Money spent by the state.", "ex": "Public spending can reduce poverty."}, {"term": "fiscal constraint", "ipa": "/ˈfɪskəl kənˌstreɪnt/", "pron": "FIS-kuhl kuhn-STRAINT", "fr": "contrainte budgétaire", "def": "Budgetary limit on what the state can spend.", "ex": "Fiscal constraint shapes welfare policy."}, {"term": "to reduce poverty", "ipa": "/rɪˈdjuːs ˈpɒvəti/", "pron": "ri-DYOOSS POV-uh-tee", "fr": "réduire la pauvreté", "def": "To lower the number or share of people living in poverty.", "ex": "Governments can reduce poverty through wages, benefits and services."}, {"term": "to alleviate poverty", "ipa": "/əˈliːvieɪt ˈpɒvəti/", "pron": "uh-LEE-vee-ayt POV-uh-tee", "fr": "alléger la pauvreté", "def": "To make poverty less severe.", "ex": "Food banks alleviate poverty but do not solve its causes."}, {"term": "to tackle poverty", "ipa": "/ˈtækəl ˈpɒvəti/", "pron": "TAK-uhl POV-uh-tee", "fr": "lutter contre la pauvreté", "def": "To take action against poverty.", "ex": "A serious strategy must tackle poverty at its roots."}, {"term": "to lift people out of poverty", "ipa": "/lɪft ˈpiːpəl aʊt əv ˈpɒvəti/", "pron": "lift PEE-puhl out ov POV-uh-tee", "fr": "sortir les gens de la pauvreté", "def": "To help people escape poverty.", "ex": "Education and decent wages can lift people out of poverty."}, {"term": "to fall into poverty", "ipa": "/fɔːl ˈɪntuː ˈpɒvəti/", "pron": "fall IN-too POV-uh-tee", "fr": "tomber dans la pauvreté", "def": "To become poor.", "ex": "A job loss can make families fall into poverty."}, {"term": "to live below the poverty line", "ipa": "/lɪv bɪˌləʊ ðə ˈpɒvəti laɪn/", "pron": "liv bi-LOH thuh POV-uh-tee line", "fr": "vivre sous le seuil de pauvreté", "def": "To have income below the official poverty threshold.", "ex": "Millions of children live below the poverty line."}, {"term": "to make ends meet", "ipa": "/meɪk endz miːt/", "pron": "mayk endz meet", "fr": "joindre les deux bouts", "def": "To manage to pay for basic expenses.", "ex": "Many families struggle to make ends meet."}, {"term": "to struggle financially", "ipa": "/ˈstrʌɡəl faɪˈnænʃəli/", "pron": "STRUG-uhl fy-NAN-shuh-lee", "fr": "avoir des difficultés financières", "def": "To have difficulty managing money.", "ex": "Low-paid workers often struggle financially."}, {"term": "to rely on benefits", "ipa": "/rɪˈlaɪ ɒn ˈbenɪfɪts/", "pron": "ri-LY on BEN-i-fits", "fr": "dépendre des prestations sociales", "def": "To depend on welfare payments.", "ex": "Many disabled people rely on benefits."}, {"term": "to claim benefits", "ipa": "/kleɪm ˈbenɪfɪts/", "pron": "klaym BEN-i-fits", "fr": "demander des prestations", "def": "To apply for or receive welfare support.", "ex": "Some eligible people do not claim benefits."}, {"term": "to be eligible for support", "ipa": "/bi ˈelɪdʒəbəl fə səˈpɔːt/", "pron": "bee EL-i-juh-buhl for suh-PORT", "fr": "être éligible à une aide", "def": "To meet the conditions for help.", "ex": "Many households are eligible for support but do not apply."}, {"term": "to expand the safety net", "ipa": "/ɪkˈspænd ðə ˈseɪfti net/", "pron": "ik-SPAND thuh SAYF-tee net", "fr": "élargir le filet de sécurité sociale", "def": "To increase social protection.", "ex": "The pandemic forced governments to expand the safety net."}, {"term": "to cut benefits", "ipa": "/kʌt ˈbenɪfɪts/", "pron": "kut BEN-i-fits", "fr": "réduire les prestations", "def": "To reduce welfare payments.", "ex": "Cutting benefits can increase hardship."}, {"term": "to target support", "ipa": "/ˈtɑːɡɪt səˈpɔːt/", "pron": "TAR-git suh-PORT", "fr": "cibler les aides", "def": "To direct help to those who need it most.", "ex": "Targeting support can save money but increase complexity."}, {"term": "to provide universal support", "ipa": "/prəˈvaɪd ˌjuːnɪˈvɜːsəl səˈpɔːt/", "pron": "pruh-VYDE yoo-ni-VUR-suhl suh-PORT", "fr": "fournir une aide universelle", "def": "To offer help to everyone in a category.", "ex": "Universal support reduces stigma."}, {"term": "to break the cycle of poverty", "ipa": "/breɪk ðə ˈsaɪkəl əv ˈpɒvəti/", "pron": "brayk thuh SY-kuhl ov POV-uh-tee", "fr": "briser le cycle de la pauvreté", "def": "To stop poverty passing from one generation to another.", "ex": "Early education can help break the cycle of poverty."}, {"term": "to address root causes", "ipa": "/əˈdres ruːt ˈkɔːzɪz/", "pron": "uh-DRESS root KAW-ziz", "fr": "s’attaquer aux causes profondes", "def": "To deal with the underlying reasons for a problem.", "ex": "Anti-poverty policy must address root causes."}, {"term": "to protect vulnerable households", "ipa": "/prəˈtekt ˈvʌlnərəbəl ˈhaʊshəʊldz/", "pron": "pruh-TEKT VUL-nuh-ruh-buhl HOWSS-hohldz", "fr": "protéger les ménages vulnérables", "def": "To shield at-risk households from hardship.", "ex": "Energy subsidies can protect vulnerable households."}]}]}, {"id": "p5c48", "part": 5, "chapter": 48, "title": "Cost Of Living Crisis", "file": "cpge_vocab_part5_chapter48_cost_of_living_crisis_premium.html", "count": 165, "sections": [{"title": "A. Core cost-of-living vocabulary", "entries": [{"term": "cost-of-living crisis", "ipa": "/ˌkɒst əv ˈlɪvɪŋ ˈkraɪsɪs/", "pron": "kost-ov-LIV-ing KRY-sis", "fr": "crise du coût de la vie", "def": "A situation where essential costs rise faster than incomes.", "ex": "The cost-of-living crisis has pushed many households into financial hardship."}, {"term": "cost of living", "ipa": "/ˌkɒst əv ˈlɪvɪŋ/", "pron": "kost ov LIV-ing", "fr": "coût de la vie", "def": "The amount of money needed to pay for basic goods and services.", "ex": "The cost of living is higher in large cities."}, {"term": "living costs", "ipa": "/ˈlɪvɪŋ kɒsts/", "pron": "LIV-ing kosts", "fr": "coûts de la vie quotidienne", "def": "The costs of everyday life, such as food, housing, energy and transport.", "ex": "Living costs have risen faster than wages."}, {"term": "essential costs", "ipa": "/ɪˌsenʃəl ˈkɒsts/", "pron": "i-SEN-shuhl kosts", "fr": "dépenses essentielles", "def": "Costs linked to basic needs such as food, energy, rent and transport.", "ex": "Essential costs take up most of a low-income household’s budget."}, {"term": "household budget", "ipa": "/ˌhaʊshəʊld ˈbʌdʒɪt/", "pron": "HOWSS-hohld BUJ-it", "fr": "budget du ménage", "def": "The money a household has available and how it is spent.", "ex": "Inflation has put pressure on household budgets."}, {"term": "family budget", "ipa": "/ˌfæməli ˈbʌdʒɪt/", "pron": "FAM-uh-lee BUJ-it", "fr": "budget familial", "def": "The money available to a family and its planned expenses.", "ex": "Many families have had to cut non-essential items from the family budget."}, {"term": "squeezed households", "ipa": "/ˌskwiːzd ˈhaʊshəʊldz/", "pron": "skweezd HOWSS-hohldz", "fr": "ménages sous pression", "def": "Households under financial pressure because costs are rising faster than income.", "ex": "Squeezed households often reduce heating or leisure spending."}, {"term": "household finances", "ipa": "/ˌhaʊshəʊld ˈfaɪnænsɪz/", "pron": "HOWSS-hohld FY-nan-siz", "fr": "finances du ménage", "def": "The income, spending, debts and savings of a household.", "ex": "Household finances deteriorated during the energy crisis."}, {"term": "financial pressure", "ipa": "/faɪˌnænʃəl ˈpreʃə/", "pron": "fy-NAN-shuhl PRESH-uh", "fr": "pression financière", "def": "Stress caused by money difficulties.", "ex": "Financial pressure can damage mental health."}, {"term": "financial strain", "ipa": "/faɪˌnænʃəl ˈstreɪn/", "pron": "fy-NAN-shuhl strayn", "fr": "tension financière", "def": "Serious pressure on someone’s finances.", "ex": "Rent and energy bills create financial strain."}, {"term": "financial hardship", "ipa": "/faɪˌnænʃəl ˈhɑːdʃɪp/", "pron": "fy-NAN-shuhl HARD-ship", "fr": "difficultés financières", "def": "Severe difficulty caused by lack of money.", "ex": "Financial hardship forces families to make painful choices."}, {"term": "economic hardship", "ipa": "/ˌiːkəˈnɒmɪk ˈhɑːdʃɪp/", "pron": "ee-kuh-NOM-ik HARD-ship", "fr": "difficultés économiques", "def": "Difficulty caused by unemployment, low income or rising prices.", "ex": "Economic hardship has increased demand for welfare support."}, {"term": "hardship", "ipa": "/ˈhɑːdʃɪp/", "pron": "HARD-ship", "fr": "épreuve ; difficulté", "def": "Severe difficulty, especially financial suffering.", "ex": "Many pensioners face hardship during winter."}, {"term": "affordability", "ipa": "/əˌfɔːdəˈbɪləti/", "pron": "uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière", "def": "The extent to which people can pay for something without hardship.", "ex": "Housing affordability has become a major political issue."}, {"term": "unaffordable", "ipa": "/ˌʌnəˈfɔːdəbəl/", "pron": "un-uh-FOR-duh-buhl", "fr": "inabordable", "def": "Too expensive for someone to pay for.", "ex": "Childcare is unaffordable for many low-income families."}, {"term": "basic necessities", "ipa": "/ˌbeɪsɪk nəˈsesətiz/", "pron": "BAY-sik nuh-SES-uh-teez", "fr": "nécessités de base", "def": "Essential things people need to live, such as food, shelter and warmth.", "ex": "Some households struggle to afford basic necessities."}, {"term": "essentials", "ipa": "/ɪˈsenʃəlz/", "pron": "i-SEN-shuhlz", "fr": "produits de première nécessité", "def": "Necessary goods or services.", "ex": "Poor households spend most of their money on essentials."}, {"term": "non-essential spending", "ipa": "/ˌnɒn ɪˌsenʃəl ˈspendɪŋ/", "pron": "non-i-SEN-shuhl SPEN-ding", "fr": "dépenses non essentielles", "def": "Spending on things that are not basic needs.", "ex": "Non-essential spending is often cut first during a crisis."}, {"term": "discretionary spending", "ipa": "/dɪˈskreʃənəri ˈspendɪŋ/", "pron": "di-SKRESH-uh-nuh-ree SPEN-ding", "fr": "dépenses discrétionnaires", "def": "Money spent on non-essential goods and services.", "ex": "Discretionary spending falls when households are squeezed."}, {"term": "purchasing power", "ipa": "/ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "PUR-chuh-sing POW-uh", "fr": "pouvoir d’achat", "def": "The amount of goods and services money can buy.", "ex": "Inflation erodes purchasing power."}, {"term": "real income", "ipa": "/ˌrɪəl ˈɪnkʌm/", "pron": "REE-uhl IN-kum", "fr": "revenu réel", "def": "Income adjusted for inflation.", "ex": "Real income falls when wages lag behind prices."}, {"term": "real wages", "ipa": "/ˌrɪəl ˈweɪdʒɪz/", "pron": "REE-uhl WAY-jiz", "fr": "salaires réels", "def": "Wages adjusted for inflation.", "ex": "Real wages declined during the inflation shock."}, {"term": "nominal wages", "ipa": "/ˌnɒmɪnəl ˈweɪdʒɪz/", "pron": "NOM-i-nuhl WAY-jiz", "fr": "salaires nominaux", "def": "Wages before adjusting for inflation.", "ex": "Nominal wages may rise while real wages fall."}, {"term": "wage growth", "ipa": "/ˈweɪdʒ ɡrəʊθ/", "pron": "wayj growth", "fr": "croissance des salaires", "def": "An increase in wages over time.", "ex": "Wage growth has not always kept pace with inflation."}, {"term": "pay rise", "ipa": "/ˈpeɪ raɪz/", "pron": "pay ryze", "fr": "augmentation de salaire", "def": "An increase in wages or salary.", "ex": "Workers demanded a pay rise to match inflation."}, {"term": "below-inflation pay rise", "ipa": "/bɪˌləʊ ɪnˈfleɪʃən ˈpeɪ raɪz/", "pron": "bi-LOH in-FLAY-shuhn pay ryze", "fr": "augmentation inférieure à l’inflation", "def": "A wage increase smaller than the inflation rate.", "ex": "A below-inflation pay rise is a real-terms pay cut."}, {"term": "real-terms pay cut", "ipa": "/ˌrɪəl tɜːmz ˈpeɪ kʌt/", "pron": "REE-uhl-termz pay kut", "fr": "baisse de salaire en termes réels", "def": "A fall in pay after inflation is taken into account.", "ex": "Many public-sector workers experienced a real-terms pay cut."}, {"term": "income squeeze", "ipa": "/ˈɪnkʌm skwiːz/", "pron": "IN-kum skweez", "fr": "compression des revenus", "def": "Pressure on income caused by rising prices or stagnant wages.", "ex": "The income squeeze hit low-paid workers hardest."}, {"term": "living standards squeeze", "ipa": "/ˈlɪvɪŋ ˌstændədz skwiːz/", "pron": "LIV-ing STAN-duhdz skweez", "fr": "baisse sous pression du niveau de vie", "def": "A decline in material comfort because prices rise faster than income.", "ex": "The living standards squeeze became a major electoral issue."}, {"term": "inflation", "ipa": "/ɪnˈfleɪʃən/", "pron": "in-FLAY-shuhn", "fr": "inflation", "def": "A general rise in prices.", "ex": "Inflation is the main driver of the cost-of-living crisis."}]}, {"title": "B. Inflation, prices and corporate behaviour", "entries": [{"term": "inflation rate", "ipa": "/ɪnˈfleɪʃən reɪt/", "pron": "in-FLAY-shuhn rayt", "fr": "taux d’inflation", "def": "The speed at which prices rise.", "ex": "The inflation rate rose sharply after energy prices surged."}, {"term": "headline inflation", "ipa": "/ˌhedlaɪn ɪnˈfleɪʃən/", "pron": "HED-lyne in-FLAY-shuhn", "fr": "inflation globale", "def": "Overall inflation including all goods and services.", "ex": "Headline inflation can be driven by food and energy prices."}, {"term": "core inflation", "ipa": "/ˌkɔːr ɪnˈfleɪʃən/", "pron": "kor in-FLAY-shuhn", "fr": "inflation sous-jacente", "def": "Inflation excluding volatile items such as food and energy.", "ex": "Core inflation shows whether price pressures are persistent."}, {"term": "food inflation", "ipa": "/ˈfuːd ɪnˌfleɪʃən/", "pron": "food in-FLAY-shuhn", "fr": "inflation alimentaire", "def": "Rising food prices.", "ex": "Food inflation harms low-income households disproportionately."}, {"term": "energy inflation", "ipa": "/ˈenədʒi ɪnˌfleɪʃən/", "pron": "EN-uh-jee in-FLAY-shuhn", "fr": "inflation énergétique", "def": "Rising energy prices.", "ex": "Energy inflation increased heating bills."}, {"term": "rent inflation", "ipa": "/ˈrent ɪnˌfleɪʃən/", "pron": "rent in-FLAY-shuhn", "fr": "inflation des loyers", "def": "Rising rents over time.", "ex": "Rent inflation worsens housing insecurity."}, {"term": "price shock", "ipa": "/ˈpraɪs ʃɒk/", "pron": "price shok", "fr": "choc de prix", "def": "A sudden sharp rise in prices.", "ex": "A price shock can quickly reduce living standards."}, {"term": "energy price shock", "ipa": "/ˈenədʒi praɪs ʃɒk/", "pron": "EN-uh-jee price shok", "fr": "choc des prix de l’énergie", "def": "A sudden sharp rise in energy prices.", "ex": "The energy price shock increased fuel poverty."}, {"term": "supply shock", "ipa": "/səˈplaɪ ʃɒk/", "pron": "suh-PLY shok", "fr": "choc d’offre", "def": "A sudden disruption to supply that affects prices or output.", "ex": "The war created a supply shock in energy markets."}, {"term": "bottleneck", "ipa": "/ˈbɒtəlnek/", "pron": "BOT-uhl-nek", "fr": "goulot d’étranglement", "def": "A point where supply or production is blocked or slowed.", "ex": "Supply-chain bottlenecks pushed up goods prices."}, {"term": "shortage", "ipa": "/ˈʃɔːtɪdʒ/", "pron": "SHOR-tij", "fr": "pénurie", "def": "A lack of enough goods, workers or resources.", "ex": "Shortages can drive prices upward."}, {"term": "scarcity", "ipa": "/ˈskeəsəti/", "pron": "SKAIR-suh-tee", "fr": "rareté", "def": "Limited availability of resources or goods.", "ex": "Scarcity increases bargaining power for suppliers."}, {"term": "price gouging", "ipa": "/ˈpraɪs ˌɡaʊdʒɪŋ/", "pron": "price GOW-jing", "fr": "prix abusifs", "def": "Charging excessively high prices during a crisis or shortage.", "ex": "Price gouging is often condemned during emergencies."}, {"term": "greedflation", "ipa": "/ˌɡriːdˈfleɪʃən/", "pron": "greed-FLAY-shuhn", "fr": "inflation par avidité", "def": "A critical term claiming firms raise prices excessively to increase profits.", "ex": "Greedflation became a popular explanation for rising prices."}, {"term": "shrinkflation", "ipa": "/ʃrɪŋkˈfleɪʃən/", "pron": "shrink-FLAY-shuhn", "fr": "réduflation", "def": "Reducing product size while keeping the same price.", "ex": "Shrinkflation makes price increases less visible."}, {"term": "skimpflation", "ipa": "/skɪmpˈfleɪʃən/", "pron": "skimp-FLAY-shuhn", "fr": "baisse de qualité masquée", "def": "Reducing product or service quality while keeping the price similar.", "ex": "Skimpflation frustrates consumers."}, {"term": "profit margin", "ipa": "/ˈprɒfɪt ˌmɑːdʒɪn/", "pron": "PROF-it MAR-jin", "fr": "marge bénéficiaire", "def": "The share of revenue kept as profit.", "ex": "Rising profit margins fuelled accusations of greedflation."}, {"term": "excess profits", "ipa": "/ˌekses ˈprɒfɪts/", "pron": "EK-sess PROF-its", "fr": "surprofits", "def": "Profits considered unusually high.", "ex": "Energy firms were accused of making excess profits."}, {"term": "windfall profits", "ipa": "/ˈwɪndfɔːl ˌprɒfɪts/", "pron": "WIND-fawl PROF-its", "fr": "profits exceptionnels", "def": "Unexpectedly high profits caused by unusual circumstances.", "ex": "Windfall profits led to calls for a special tax."}, {"term": "energy bills", "ipa": "/ˈenədʒi bɪlz/", "pron": "EN-uh-jee bilz", "fr": "factures d’énergie", "def": "Bills for gas, electricity or other household energy.", "ex": "Energy bills rose dramatically."}]}, {"title": "C. Energy, food, housing, debt and everyday costs", "entries": [{"term": "utility bills", "ipa": "/juːˈtɪləti bɪlz/", "pron": "yoo-TIL-uh-tee bilz", "fr": "factures de services essentiels", "def": "Bills for essential services such as electricity, gas and water.", "ex": "Utility bills are difficult to avoid."}, {"term": "gas bill", "ipa": "/ˈɡæs bɪl/", "pron": "gas bil", "fr": "facture de gaz", "def": "A bill for gas used at home.", "ex": "The gas bill doubled in some households."}, {"term": "electricity bill", "ipa": "/ɪˌlekˈtrɪsəti bɪl/", "pron": "i-lek-TRIS-uh-tee bil", "fr": "facture d’électricité", "def": "A bill for electricity use.", "ex": "Electricity bills rose as wholesale prices increased."}, {"term": "heating costs", "ipa": "/ˈhiːtɪŋ kɒsts/", "pron": "HEE-ting kosts", "fr": "coûts de chauffage", "def": "The cost of heating a home.", "ex": "Heating costs are a major concern in winter."}, {"term": "fuel costs", "ipa": "/ˈfjuːəl kɒsts/", "pron": "FYOO-uhl kosts", "fr": "coûts du carburant", "def": "The cost of petrol, diesel or other fuels.", "ex": "Fuel costs affect commuting and transport."}, {"term": "petrol prices", "ipa": "/ˈpetrəl ˈpraɪsɪz/", "pron": "PET-ruhl PRY-siz", "fr": "prix de l’essence", "def": "Prices paid for petrol.", "ex": "Petrol prices affect rural households heavily."}, {"term": "transport costs", "ipa": "/ˈtrænspɔːt kɒsts/", "pron": "TRAN-sport kosts", "fr": "coûts de transport", "def": "Money spent on travel, commuting or transport.", "ex": "Transport costs can make low-paid work less worthwhile."}, {"term": "commuting costs", "ipa": "/kəˈmjuːtɪŋ kɒsts/", "pron": "kuh-MYOO-ting kosts", "fr": "coûts de trajet domicile-travail", "def": "The cost of travelling to and from work.", "ex": "Commuting costs squeeze workers who cannot work from home."}, {"term": "grocery bill", "ipa": "/ˈɡrəʊsəri bɪl/", "pron": "GROH-suh-ree bil", "fr": "ticket de courses ; facture alimentaire", "def": "The amount spent on food and household shopping.", "ex": "The weekly grocery bill rose sharply."}, {"term": "food prices", "ipa": "/ˈfuːd ˌpraɪsɪz/", "pron": "food PRY-siz", "fr": "prix alimentaires", "def": "Prices of food products.", "ex": "Food prices are highly visible to consumers."}, {"term": "staple foods", "ipa": "/ˌsteɪpəl ˈfuːdz/", "pron": "STAY-puhl foodz", "fr": "aliments de base", "def": "Basic foods eaten regularly, such as bread, rice or pasta.", "ex": "Rising staple foods prices hit poor families hardest."}, {"term": "rent", "ipa": "/rent/", "pron": "rent", "fr": "loyer", "def": "Money paid regularly to live in a property owned by someone else.", "ex": "Rent takes a large share of income for many tenants."}, {"term": "rent increase", "ipa": "/ˈrent ˌɪnkriːs/", "pron": "rent IN-kreess", "fr": "augmentation de loyer", "def": "A rise in rent.", "ex": "A rent increase can force tenants to move."}, {"term": "mortgage payment", "ipa": "/ˈmɔːɡɪdʒ ˌpeɪmənt/", "pron": "MOR-gij PAY-muhnt", "fr": "mensualité de prêt immobilier", "def": "A regular payment on a home loan.", "ex": "Mortgage payments rose with interest rates."}, {"term": "mortgage rate", "ipa": "/ˈmɔːɡɪdʒ reɪt/", "pron": "MOR-gij rayt", "fr": "taux de prêt immobilier", "def": "The interest rate on a mortgage.", "ex": "Higher mortgage rates affect homeowners and landlords."}, {"term": "housing costs", "ipa": "/ˈhaʊzɪŋ kɒsts/", "pron": "HOW-zing kosts", "fr": "coûts du logement", "def": "Costs linked to rent, mortgages, maintenance and housing.", "ex": "Housing costs are central to the cost-of-living crisis."}, {"term": "childcare costs", "ipa": "/ˈtʃaɪldkeə kɒsts/", "pron": "CHYLD-care kosts", "fr": "coûts de garde d’enfants", "def": "The cost of having children looked after while parents work.", "ex": "Childcare costs can prevent parents from working."}, {"term": "healthcare costs", "ipa": "/ˈhelθkeə kɒsts/", "pron": "HELTH-care kosts", "fr": "coûts de santé", "def": "The cost of medical care, treatment or insurance.", "ex": "Healthcare costs can push households into debt."}, {"term": "insurance premiums", "ipa": "/ɪnˈʃʊərəns ˈpriːmiəmz/", "pron": "in-SHOOR-uhns PREE-mee-uhmz", "fr": "primes d’assurance", "def": "Regular payments for insurance coverage.", "ex": "Insurance premiums have risen for many drivers."}, {"term": "household debt", "ipa": "/ˌhaʊshəʊld ˈdet/", "pron": "HOWSS-hohld det", "fr": "endettement des ménages", "def": "Debt owed by households.", "ex": "Household debt rises when incomes cannot cover costs."}, {"term": "credit card debt", "ipa": "/ˈkredɪt kɑːd det/", "pron": "KRED-it card det", "fr": "dette de carte de crédit", "def": "Debt owed on credit cards.", "ex": "Credit card debt can grow quickly because of high interest."}, {"term": "arrears", "ipa": "/əˈrɪəz/", "pron": "uh-REERZ", "fr": "arriérés", "def": "Money that is overdue and unpaid.", "ex": "Some tenants fell into rent arrears."}, {"term": "rent arrears", "ipa": "/ˈrent əˌrɪəz/", "pron": "rent uh-REERZ", "fr": "arriérés de loyer", "def": "Unpaid rent owed to a landlord.", "ex": "Rent arrears can lead to eviction."}, {"term": "debt spiral", "ipa": "/ˈdet ˌspaɪrəl/", "pron": "det SPY-ruhl", "fr": "spirale de la dette", "def": "A situation where debt keeps growing and becomes harder to repay.", "ex": "High-interest loans can create a debt spiral."}, {"term": "payday loan", "ipa": "/ˈpeɪdeɪ ləʊn/", "pron": "PAY-day lohn", "fr": "prêt sur salaire", "def": "A short-term high-interest loan.", "ex": "Payday loans can trap vulnerable borrowers."}, {"term": "savings buffer", "ipa": "/ˈseɪvɪŋz ˌbʌfə/", "pron": "SAY-vingz BUH-fuh", "fr": "épargne de précaution", "def": "Savings kept to cope with unexpected expenses.", "ex": "Many households have no savings buffer."}, {"term": "emergency savings", "ipa": "/ɪˈmɜːdʒənsi ˈseɪvɪŋz/", "pron": "i-MUR-juhn-see SAY-vingz", "fr": "épargne d’urgence", "def": "Money saved for unexpected crises.", "ex": "Emergency savings protect families from shocks."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Lack of reliable access to enough nutritious food.", "ex": "Food insecurity increased as grocery prices rose."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford adequate heating or energy.", "ex": "Fuel poverty worsens during cold winters."}, {"term": "energy poverty", "ipa": "/ˈenədʒi ˌpɒvəti/", "pron": "EN-uh-jee POV-uh-tee", "fr": "précarité énergétique", "def": "Lack of access to affordable and reliable energy.", "ex": "Energy poverty affects health and comfort."}, {"term": "heat or eat dilemma", "ipa": "/ˌhiːt ɔːr ˈiːt dɪˌlemə/", "pron": "heat-or-eat di-LEM-uh", "fr": "dilemme se chauffer ou manger", "def": "A situation where households must choose between heating and food.", "ex": "The heat or eat dilemma became a symbol of the crisis."}, {"term": "food bank", "ipa": "/ˈfuːd bæŋk/", "pron": "food bank", "fr": "banque alimentaire", "def": "A charity or organisation giving food to people in need.", "ex": "Food bank use increased during the crisis."}, {"term": "warm bank", "ipa": "/ˈwɔːm bæŋk/", "pron": "warm bank", "fr": "lieu chauffé solidaire", "def": "A public place where people can stay warm when they cannot afford heating.", "ex": "Warm banks opened during the winter energy crisis."}, {"term": "charitable aid", "ipa": "/ˈtʃærətəbəl eɪd/", "pron": "CHAR-uh-tuh-buhl aid", "fr": "aide caritative", "def": "Support provided by charities.", "ex": "Charitable aid cannot replace state support."}, {"term": "emergency support", "ipa": "/ɪˈmɜːdʒənsi səˈpɔːt/", "pron": "i-MUR-juhn-see suh-PORT", "fr": "aide d’urgence", "def": "Urgent help during a crisis.", "ex": "Emergency support was provided to vulnerable households."}, {"term": "cost-of-living payment", "ipa": "/ˌkɒst əv ˈlɪvɪŋ ˈpeɪmənt/", "pron": "kost-ov-LIV-ing PAY-muhnt", "fr": "aide exceptionnelle au coût de la vie", "def": "A government payment to help households cope with rising costs.", "ex": "Cost-of-living payments targeted low-income households."}]}, {"title": "D. Government support, wages, social impact and policy debates", "entries": [{"term": "energy subsidy", "ipa": "/ˈenədʒi ˈsʌbsɪdi/", "pron": "EN-uh-jee SUB-si-dee", "fr": "subvention énergétique", "def": "Government financial support reducing energy costs.", "ex": "Energy subsidies can protect households but cost public money."}, {"term": "energy price cap", "ipa": "/ˈenədʒi praɪs kæp/", "pron": "EN-uh-jee price kap", "fr": "plafonnement des prix de l’énergie", "def": "A limit on what energy suppliers can charge consumers.", "ex": "The energy price cap became central to UK politics."}, {"term": "price cap", "ipa": "/ˈpraɪs kæp/", "pron": "price kap", "fr": "plafonnement des prix", "def": "A legal or policy limit on a price.", "ex": "A price cap can reduce immediate hardship but distort markets."}, {"term": "price freeze", "ipa": "/ˈpraɪs friːz/", "pron": "price freez", "fr": "gel des prix", "def": "A policy keeping prices at a fixed level.", "ex": "A price freeze may protect consumers in the short term."}, {"term": "targeted support", "ipa": "/ˈtɑːɡɪtɪd səˈpɔːt/", "pron": "TAR-git-id suh-PORT", "fr": "aide ciblée", "def": "Support directed at groups most in need.", "ex": "Targeted support is cheaper than universal support."}, {"term": "universal support", "ipa": "/ˌjuːnɪˈvɜːsəl səˈpɔːt/", "pron": "yoo-ni-VUR-suhl suh-PORT", "fr": "aide universelle", "def": "Support provided to everyone in a category.", "ex": "Universal support is simple but expensive."}, {"term": "means-tested support", "ipa": "/ˌmiːnz testɪd səˈpɔːt/", "pron": "meenz-tested suh-PORT", "fr": "aide sous condition de ressources", "def": "Support available only to people below a certain income or wealth level.", "ex": "Means-tested support may miss some people in need."}, {"term": "welfare benefits", "ipa": "/ˈwelfeə ˌbenɪfɪts/", "pron": "WEL-fair BEN-i-fits", "fr": "prestations sociales", "def": "State payments to people needing financial support.", "ex": "Welfare benefits help households cope with rising costs."}, {"term": "benefit uprating", "ipa": "/ˈbenɪfɪt ʌpˌreɪtɪŋ/", "pron": "BEN-i-fit up-RAY-ting", "fr": "revalorisation des prestations", "def": "Increasing benefits, often to match inflation.", "ex": "Benefit uprating protects recipients from price rises."}, {"term": "indexation", "ipa": "/ˌɪndekˈseɪʃən/", "pron": "in-dek-SAY-shuhn", "fr": "indexation", "def": "Automatic adjustment of payments to inflation or another measure.", "ex": "Indexation can protect pensions and benefits."}, {"term": "minimum wage", "ipa": "/ˌmɪnɪməm ˈweɪdʒ/", "pron": "MIN-i-muhm wayj", "fr": "salaire minimum", "def": "The lowest legal wage employers can pay.", "ex": "Raising the minimum wage can support low-paid workers."}, {"term": "living wage", "ipa": "/ˈlɪvɪŋ weɪdʒ/", "pron": "LIV-ing wayj", "fr": "salaire décent", "def": "A wage high enough to cover basic living costs.", "ex": "A living wage is meant to reflect real living costs."}, {"term": "wage demand", "ipa": "/ˈweɪdʒ dɪˌmɑːnd/", "pron": "wayj di-MAND", "fr": "revendication salariale", "def": "A request for higher wages.", "ex": "Wage demands increased as inflation rose."}, {"term": "strike", "ipa": "/straɪk/", "pron": "stryke", "fr": "grève", "def": "A work stoppage used to demand better pay or conditions.", "ex": "Many workers went on strike over pay."}, {"term": "industrial action", "ipa": "/ɪnˌdʌstriəl ˈækʃən/", "pron": "in-DUS-tree-uhl AK-shuhn", "fr": "mouvement social ; action syndicale", "def": "Collective action by workers, including strikes.", "ex": "Industrial action reflected anger over falling real wages."}, {"term": "trade union", "ipa": "/ˌtreɪd ˈjuːniən/", "pron": "trade YOO-nee-uhn", "fr": "syndicat", "def": "An organisation representing workers.", "ex": "Trade unions demanded pay rises."}, {"term": "collective bargaining", "ipa": "/kəˌlektɪv ˈbɑːɡɪnɪŋ/", "pron": "kuh-LEK-tiv BAR-gi-ning", "fr": "négociation collective", "def": "Negotiation between employers and workers’ representatives.", "ex": "Collective bargaining can protect real wages."}, {"term": "public-sector pay", "ipa": "/ˌpʌblɪk sektə ˈpeɪ/", "pron": "PUB-lik SEK-tuh pay", "fr": "salaires du secteur public", "def": "Wages paid to public-sector workers.", "ex": "Public-sector pay became a major political issue."}, {"term": "private-sector pay", "ipa": "/ˌpraɪvət sektə ˈpeɪ/", "pron": "PRY-vuht SEK-tuh pay", "fr": "salaires du secteur privé", "def": "Wages paid by private employers.", "ex": "Private-sector pay rose faster in some industries."}, {"term": "social tariff", "ipa": "/ˈsəʊʃəl ˌtærɪf/", "pron": "SOH-shuhl TAR-if", "fr": "tarif social", "def": "A cheaper price for essential services offered to vulnerable customers.", "ex": "A social tariff can make energy or broadband more affordable."}, {"term": "public transport subsidy", "ipa": "/ˌpʌblɪk ˈtrænspɔːt ˈsʌbsɪdi/", "pron": "PUB-lik TRAN-sport SUB-si-dee", "fr": "subvention aux transports publics", "def": "Government support reducing public transport costs.", "ex": "Public transport subsidies can help commuters."}, {"term": "rent control", "ipa": "/ˈrent kənˌtrəʊl/", "pron": "rent kuhn-TROHL", "fr": "encadrement des loyers", "def": "Rules limiting how much landlords can raise rents.", "ex": "Rent control is controversial but can protect tenants."}, {"term": "social housing", "ipa": "/ˌsəʊʃəl ˈhaʊzɪŋ/", "pron": "SOH-shuhl HOW-zing", "fr": "logement social", "def": "Affordable housing provided or supported by the state.", "ex": "Social housing reduces exposure to private rent inflation."}, {"term": "affordable housing", "ipa": "/əˌfɔːdəbəl ˈhaʊzɪŋ/", "pron": "uh-FOR-duh-buhl HOW-zing", "fr": "logement abordable", "def": "Housing that people can pay for without hardship.", "ex": "Affordable housing is a key solution to the crisis."}, {"term": "tenant protection", "ipa": "/ˈtenənt prəˌtekʃən/", "pron": "TEN-uhnt pruh-TEK-shuhn", "fr": "protection des locataires", "def": "Legal protections for renters.", "ex": "Tenant protection can prevent unfair evictions."}, {"term": "eviction ban", "ipa": "/ɪˈvɪkʃən bæn/", "pron": "i-VIK-shuhn ban", "fr": "interdiction des expulsions", "def": "A temporary ban on removing tenants from their homes.", "ex": "An eviction ban can prevent homelessness during crises."}, {"term": "recession risk", "ipa": "/rɪˈseʃən rɪsk/", "pron": "ri-SESH-uhn risk", "fr": "risque de récession", "def": "The possibility of an economic downturn.", "ex": "Higher interest rates increased recession risk."}, {"term": "consumer confidence", "ipa": "/kənˌsjuːmə ˈkɒnfɪdəns/", "pron": "kuhn-SYOO-muh KON-fi-duhns", "fr": "confiance des consommateurs", "def": "How optimistic consumers feel about the economy and their finances.", "ex": "Consumer confidence fell as prices rose."}, {"term": "consumer spending", "ipa": "/kənˌsjuːmə ˈspendɪŋ/", "pron": "kuhn-SYOO-muh SPEN-ding", "fr": "dépenses de consommation", "def": "Money spent by households on goods and services.", "ex": "Consumer spending weakens when households are squeezed."}, {"term": "demand slowdown", "ipa": "/dɪˈmɑːnd ˈsləʊdaʊn/", "pron": "di-MAND SLOH-down", "fr": "ralentissement de la demande", "def": "A reduction in demand growth.", "ex": "A demand slowdown can hurt businesses."}, {"term": "small business", "ipa": "/ˌsmɔːl ˈbɪznəs/", "pron": "small BIZ-nuhs", "fr": "petite entreprise", "def": "A small company or enterprise.", "ex": "Small businesses faced higher energy and wage costs."}, {"term": "business costs", "ipa": "/ˈbɪznəs kɒsts/", "pron": "BIZ-nuhs kosts", "fr": "coûts des entreprises", "def": "Costs faced by firms, such as wages, rent and energy.", "ex": "Rising business costs can be passed on to consumers."}, {"term": "profit squeeze", "ipa": "/ˈprɒfɪt skwiːz/", "pron": "PROF-it skweez", "fr": "pression sur les bénéfices", "def": "Pressure on profits caused by rising costs or falling demand.", "ex": "Small firms experienced a profit squeeze."}, {"term": "bankruptcy", "ipa": "/ˈbæŋkrʌptsi/", "pron": "BANK-rupt-see", "fr": "faillite", "def": "The state of being unable to pay debts legally.", "ex": "Some businesses faced bankruptcy after costs soared."}, {"term": "interest rate hike", "ipa": "/ˈɪntrəst reɪt haɪk/", "pron": "IN-truhst rayt hyke", "fr": "hausse des taux d’intérêt", "def": "An increase in interest rates.", "ex": "Interest rate hikes increased mortgage payments."}, {"term": "borrowing costs", "ipa": "/ˈbɒrəʊɪŋ kɒsts/", "pron": "BOR-oh-ing kosts", "fr": "coût de l’emprunt", "def": "The cost of taking out loans.", "ex": "Higher borrowing costs affect families and firms."}, {"term": "central bank", "ipa": "/ˌsentrəl ˈbæŋk/", "pron": "SEN-truhl bank", "fr": "banque centrale", "def": "An institution managing monetary policy and currency stability.", "ex": "The central bank raised rates to curb inflation."}, {"term": "monetary policy", "ipa": "/ˈmʌnɪtəri ˈpɒləsi/", "pron": "MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire", "def": "Central bank policy affecting interest rates and money supply.", "ex": "Tighter monetary policy can reduce inflation but squeeze borrowers."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on taxation, spending and borrowing.", "ex": "Fiscal policy can shield households from price shocks."}, {"term": "tax cut", "ipa": "/ˈtæks kʌt/", "pron": "taks kut", "fr": "baisse d’impôts", "def": "A reduction in taxes.", "ex": "Tax cuts can support incomes but may fuel inflation."}, {"term": "windfall tax", "ipa": "/ˈwɪndfɔːl tæks/", "pron": "WIND-fawl taks", "fr": "taxe sur les superprofits", "def": "A tax on unexpectedly high profits.", "ex": "A windfall tax can fund support for households."}, {"term": "progressive taxation", "ipa": "/prəˌɡresɪv tækˈseɪʃən/", "pron": "pruh-GRES-iv tak-SAY-shuhn", "fr": "fiscalité progressive", "def": "Taxation where richer people pay a higher share of income.", "ex": "Progressive taxation can finance targeted support."}, {"term": "regressive impact", "ipa": "/rɪˌɡresɪv ˈɪmpækt/", "pron": "ri-GRES-iv IM-pakt", "fr": "effet régressif", "def": "An effect that hurts poorer people more than richer people.", "ex": "Energy price rises have a regressive impact."}, {"term": "distributional impact", "ipa": "/ˌdɪstrɪˈbjuːʃənəl ˈɪmpækt/", "pron": "dis-tri-BYOO-shuh-nuhl IM-pakt", "fr": "impact distributif", "def": "How a policy or event affects different income groups.", "ex": "The distributional impact of subsidies matters."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "inequality", "ipa": "/ˌɪnɪˈkwɒləti/", "pron": "in-i-KWOL-uh-tee", "fr": "inégalité", "def": "Unequal distribution of income, wealth or opportunities.", "ex": "The crisis widened inequality."}, {"term": "poverty", "ipa": "/ˈpɒvəti/", "pron": "POV-uh-tee", "fr": "pauvreté", "def": "Lack of enough money or resources to meet basic needs.", "ex": "Rising prices pushed more households into poverty."}, {"term": "relative poverty", "ipa": "/ˌrelətɪv ˈpɒvəti/", "pron": "REL-uh-tiv POV-uh-tee", "fr": "pauvreté relative", "def": "Poverty measured against the living standards of society.", "ex": "Relative poverty increased as low-income families fell behind."}, {"term": "absolute poverty", "ipa": "/ˌæbsəluːt ˈpɒvəti/", "pron": "AB-suh-loot POV-uh-tee", "fr": "pauvreté absolue", "def": "Poverty measured against a fixed basic standard.", "ex": "Absolute poverty rises when essential costs become unaffordable."}, {"term": "material deprivation", "ipa": "/məˌtɪəriəl ˌdeprɪˈveɪʃən/", "pron": "muh-TEER-ee-uhl dep-ri-VAY-shuhn", "fr": "privation matérielle", "def": "Lack of goods or conditions needed for a decent life.", "ex": "Material deprivation includes being unable to heat the home."}, {"term": "social exclusion", "ipa": "/ˌsəʊʃəl ɪkˈskluːʒən/", "pron": "SOH-shuhl ik-SKLOO-zhuhn", "fr": "exclusion sociale", "def": "Being cut off from opportunities or participation in society.", "ex": "Poverty and debt can lead to social exclusion."}, {"term": "middle-class squeeze", "ipa": "/ˌmɪdəl klɑːs skwiːz/", "pron": "MID-uhl class skweez", "fr": "pression sur les classes moyennes", "def": "Financial pressure affecting middle-income households.", "ex": "The crisis also created a middle-class squeeze."}, {"term": "low-income household", "ipa": "/ˌləʊ ˈɪnkʌm ˈhaʊshəʊld/", "pron": "loh IN-kum HOWSS-hohld", "fr": "ménage à faible revenu", "def": "A household with limited income.", "ex": "Low-income households need targeted help."}, {"term": "pensioner poverty", "ipa": "/ˈpenʃənə ˌpɒvəti/", "pron": "PEN-shuhn-uh POV-uh-tee", "fr": "pauvreté des retraités", "def": "Poverty affecting retired people.", "ex": "Pensioner poverty can rise when energy bills soar."}, {"term": "child poverty", "ipa": "/ˈtʃaɪld ˌpɒvəti/", "pron": "CHYLD POV-uh-tee", "fr": "pauvreté infantile", "def": "Poverty affecting children.", "ex": "Child poverty damages long-term life chances."}, {"term": "to make ends meet", "ipa": "/meɪk endz miːt/", "pron": "mayk endz meet", "fr": "joindre les deux bouts", "def": "To manage to pay for basic expenses.", "ex": "Many families struggle to make ends meet."}, {"term": "to struggle financially", "ipa": "/ˈstrʌɡəl faɪˈnænʃəli/", "pron": "STRUG-uhl fy-NAN-shuh-lee", "fr": "avoir des difficultés financières", "def": "To have difficulty managing money.", "ex": "Students and families struggle financially when costs rise."}, {"term": "to cut back on spending", "ipa": "/kʌt bæk ɒn ˈspendɪŋ/", "pron": "kut bak on SPEN-ding", "fr": "réduire ses dépenses", "def": "To reduce spending.", "ex": "Households cut back on spending to afford essentials."}, {"term": "to tighten one’s belt", "ipa": "/ˈtaɪtən wʌnz belt/", "pron": "TY-tuhn wunz belt", "fr": "se serrer la ceinture", "def": "To spend less because money is limited.", "ex": "Many households had to tighten their belts."}, {"term": "to fall behind on bills", "ipa": "/fɔːl bɪˈhaɪnd ɒn bɪlz/", "pron": "fall bi-HYND on bilz", "fr": "prendre du retard sur les factures", "def": "To fail to pay bills on time.", "ex": "Families may fall behind on bills during a crisis."}, {"term": "to go into debt", "ipa": "/ɡəʊ ˈɪntuː det/", "pron": "goh IN-too det", "fr": "s’endetter", "def": "To start owing money.", "ex": "People go into debt when income cannot cover expenses."}, {"term": "to rely on savings", "ipa": "/rɪˈlaɪ ɒn ˈseɪvɪŋz/", "pron": "ri-LY on SAY-vingz", "fr": "puiser dans son épargne", "def": "To use saved money to pay for expenses.", "ex": "Households relied on savings to pay bills."}, {"term": "to rely on food banks", "ipa": "/rɪˈlaɪ ɒn ˈfuːd bæŋks/", "pron": "ri-LY on food banks", "fr": "dépendre des banques alimentaires", "def": "To depend on food banks for food.", "ex": "More families relied on food banks."}, {"term": "to heat one’s home", "ipa": "/hiːt wʌnz həʊm/", "pron": "heat wunz hohm", "fr": "chauffer son logement", "def": "To warm one’s home.", "ex": "Some pensioners cannot afford to heat their homes."}, {"term": "to skip meals", "ipa": "/skɪp miːlz/", "pron": "skip meelz", "fr": "sauter des repas", "def": "To miss meals, often because of lack of money.", "ex": "Some parents skip meals to feed their children."}, {"term": "to erode purchasing power", "ipa": "/ɪˈrəʊd ˈpɜːtʃəsɪŋ ˌpaʊə/", "pron": "i-ROHD PUR-chuh-sing POW-uh", "fr": "éroder le pouvoir d’achat", "def": "To reduce what people can buy with their money.", "ex": "Inflation erodes purchasing power."}, {"term": "to squeeze household budgets", "ipa": "/skwiːz ˌhaʊshəʊld ˈbʌdʒɪts/", "pron": "skweez HOWSS-hohld BUJ-its", "fr": "mettre les budgets des ménages sous pression", "def": "To put pressure on household finances.", "ex": "Energy bills squeezed household budgets."}, {"term": "to push prices up", "ipa": "/pʊʃ ˈpraɪsɪz ʌp/", "pron": "push PRY-siz up", "fr": "faire monter les prix", "def": "To cause prices to rise.", "ex": "Supply shocks pushed prices up."}, {"term": "to pass costs on to consumers", "ipa": "/pɑːs kɒsts ɒn tə kənˈsjuːməz/", "pron": "pass kosts on tuh kuhn-SYOO-muhz", "fr": "répercuter les coûts sur les consommateurs", "def": "To make consumers pay for higher business costs through higher prices.", "ex": "Firms passed costs on to consumers."}, {"term": "to absorb costs", "ipa": "/əbˈzɔːb kɒsts/", "pron": "uhb-ZORB kosts", "fr": "absorber les coûts", "def": "To accept higher costs without fully raising prices.", "ex": "Small firms cannot always absorb costs."}, {"term": "to cap prices", "ipa": "/kæp ˈpraɪsɪz/", "pron": "kap PRY-siz", "fr": "plafonner les prix", "def": "To set a maximum price.", "ex": "Governments may cap prices during crises."}, {"term": "to subsidise energy bills", "ipa": "/ˈsʌbsɪdaɪz ˈenədʒi bɪlz/", "pron": "SUB-si-dyze EN-uh-jee bilz", "fr": "subventionner les factures d’énergie", "def": "To use public money to reduce energy bills.", "ex": "The government subsidised energy bills."}, {"term": "to target support", "ipa": "/ˈtɑːɡɪt səˈpɔːt/", "pron": "TAR-git suh-PORT", "fr": "cibler les aides", "def": "To direct help to those most in need.", "ex": "Targeting support can be efficient but complex."}, {"term": "to protect vulnerable households", "ipa": "/prəˈtekt ˈvʌlnərəbəl ˈhaʊshəʊldz/", "pron": "pruh-TEKT VUL-nuh-ruh-buhl HOWSS-hohldz", "fr": "protéger les ménages vulnérables", "def": "To shield at-risk households from hardship.", "ex": "Targeted payments protect vulnerable households."}, {"term": "to raise the minimum wage", "ipa": "/reɪz ðə ˌmɪnɪməm ˈweɪdʒ/", "pron": "rayz thuh MIN-i-muhm wayj", "fr": "augmenter le salaire minimum", "def": "To increase the lowest legal wage.", "ex": "Raising the minimum wage can help low-paid workers."}, {"term": "to demand higher pay", "ipa": "/dɪˈmɑːnd ˌhaɪə ˈpeɪ/", "pron": "di-MAND HY-uh pay", "fr": "réclamer de meilleurs salaires", "def": "To ask for higher wages.", "ex": "Workers demanded higher pay to keep up with inflation."}, {"term": "to go on strike", "ipa": "/ɡəʊ ɒn straɪk/", "pron": "goh on stryke", "fr": "faire grève", "def": "To stop working as a form of protest.", "ex": "Workers went on strike over pay."}, {"term": "to curb inflation", "ipa": "/kɜːb ɪnˈfleɪʃən/", "pron": "kurb in-FLAY-shuhn", "fr": "freiner l’inflation", "def": "To reduce or control inflation.", "ex": "Central banks raised rates to curb inflation."}, {"term": "to raise interest rates", "ipa": "/reɪz ˈɪntrəst reɪts/", "pron": "rayz IN-truhst rayts", "fr": "augmenter les taux d’intérêt", "def": "To increase the cost of borrowing.", "ex": "Raising interest rates can reduce demand but hurt borrowers."}, {"term": "to balance support and inflation", "ipa": "/ˈbæləns səˈpɔːt ənd ɪnˈfleɪʃən/", "pron": "BAL-uhns suh-PORT and in-FLAY-shuhn", "fr": "équilibrer soutien et lutte contre l’inflation", "def": "To help households without making price rises worse.", "ex": "Governments must balance support and inflation."}]}]}, {"id": "p5c49", "part": 5, "chapter": 49, "title": "Ai And Employment", "file": "cpge_vocab_part5_chapter49_ai_and_employment_premium.html", "count": 172, "sections": [{"title": "A. Core AI and automation vocabulary", "entries": [{"term": "artificial intelligence", "ipa": "/ˌɑːtɪˈfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks that normally require human intelligence.", "ex": "Artificial intelligence is transforming the labour market."}, {"term": "AI", "ipa": "/ˌeɪ ˈaɪ/", "pron": "ay-eye", "fr": "IA", "def": "Abbreviation for artificial intelligence.", "ex": "AI can automate routine tasks and support decision-making."}, {"term": "generative AI", "ipa": "/ˌdʒenərətɪv ˌeɪ ˈaɪ/", "pron": "JEN-uh-ruh-tiv ay-eye", "fr": "IA générative", "def": "AI that can create text, images, code, audio or other content.", "ex": "Generative AI has raised new questions about creative work."}, {"term": "machine learning", "ipa": "/məˌʃiːn ˈlɜːnɪŋ/", "pron": "muh-SHEEN LUR-ning", "fr": "apprentissage automatique", "def": "A type of AI in which systems learn patterns from data.", "ex": "Machine learning is used in recruitment, finance and healthcare."}, {"term": "algorithm", "ipa": "/ˈælɡərɪðəm/", "pron": "AL-guh-rith-uhm", "fr": "algorithme", "def": "A set of rules or instructions used by a computer to solve a problem.", "ex": "Algorithms increasingly shape hiring and management decisions."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "The use of technology to perform tasks with little or no human labour.", "ex": "Automation can raise productivity but threaten some jobs."}, {"term": "AI-driven automation", "ipa": "/ˌeɪ ˈaɪ ˌdrɪvən ˌɔːtəˈmeɪʃən/", "pron": "ay-eye DRIV-uhn aw-tuh-MAY-shuhn", "fr": "automatisation par l’IA", "def": "Automation powered by artificial intelligence.", "ex": "AI-driven automation may affect both blue-collar and white-collar jobs."}, {"term": "robotics", "ipa": "/rəʊˈbɒtɪks/", "pron": "roh-BOT-iks", "fr": "robotique", "def": "The design and use of robots.", "ex": "Robotics has transformed manufacturing and logistics."}, {"term": "software automation", "ipa": "/ˈsɒftweər ˌɔːtəˈmeɪʃən/", "pron": "SOFT-wair aw-tuh-MAY-shuhn", "fr": "automatisation logicielle", "def": "Automation of tasks through computer software.", "ex": "Software automation can replace administrative tasks."}, {"term": "digital transformation", "ipa": "/ˌdɪdʒɪtəl ˌtrænsfəˈmeɪʃən/", "pron": "DIJ-i-tuhl trans-fuh-MAY-shuhn", "fr": "transformation numérique", "def": "The integration of digital technologies into organisations and work.", "ex": "Digital transformation changes skills, jobs and business models."}, {"term": "technological change", "ipa": "/ˌteknəˈlɒdʒɪkəl tʃeɪndʒ/", "pron": "tek-nuh-LOJ-i-kuhl chaynj", "fr": "changement technologique", "def": "Change caused by new technology.", "ex": "Technological change creates winners and losers."}, {"term": "technological progress", "ipa": "/ˌteknəˈlɒdʒɪkəl ˈprəʊɡres/", "pron": "tek-nuh-LOJ-i-kuhl PROH-gress", "fr": "progrès technologique", "def": "Improvement in technology over time.", "ex": "Technological progress can increase productivity."}, {"term": "innovation", "ipa": "/ˌɪnəˈveɪʃən/", "pron": "in-uh-VAY-shuhn", "fr": "innovation", "def": "The creation or use of new ideas, tools or methods.", "ex": "Innovation can create new industries and jobs."}, {"term": "disruptive technology", "ipa": "/dɪsˌrʌptɪv tekˈnɒlədʒi/", "pron": "dis-RUP-tiv tek-NOL-uh-jee", "fr": "technologie disruptive", "def": "Technology that radically changes industries or markets.", "ex": "AI is often described as a disruptive technology."}, {"term": "general-purpose technology", "ipa": "/ˌdʒenərəl ˈpɜːpəs tekˈnɒlədʒi/", "pron": "JEN-uh-ruhl PUR-puhs tek-NOL-uh-jee", "fr": "technologie à usage général", "def": "A technology that affects many sectors of the economy.", "ex": "AI may become a general-purpose technology like electricity."}, {"term": "AI adoption", "ipa": "/ˌeɪ ˈaɪ əˈdɒpʃən/", "pron": "ay-eye uh-DOP-shuhn", "fr": "adoption de l’IA", "def": "The process by which organisations start using AI.", "ex": "AI adoption is faster in some sectors than others."}, {"term": "AI deployment", "ipa": "/ˌeɪ ˈaɪ dɪˈplɔɪmənt/", "pron": "ay-eye di-PLOY-muhnt", "fr": "déploiement de l’IA", "def": "The practical implementation of AI systems.", "ex": "AI deployment requires training and governance."}, {"term": "AI tools", "ipa": "/ˌeɪ ˈaɪ tuːlz/", "pron": "ay-eye toolz", "fr": "outils d’IA", "def": "Software or systems using artificial intelligence.", "ex": "AI tools can help workers write, code and analyse data."}, {"term": "chatbot", "ipa": "/ˈtʃætbɒt/", "pron": "CHAT-bot", "fr": "agent conversationnel ; chatbot", "def": "A computer program designed to converse with users.", "ex": "Chatbots are increasingly used in customer service."}, {"term": "large language model", "ipa": "/ˌlɑːdʒ ˈlæŋɡwɪdʒ ˌmɒdəl/", "pron": "larj LANG-gwij MOD-uhl", "fr": "grand modèle de langage", "def": "An AI model trained to process and generate language.", "ex": "Large language models can draft emails, summaries and reports."}, {"term": "LLM", "ipa": "/ˌel el ˈem/", "pron": "el-el-em", "fr": "LLM ; grand modèle de langage", "def": "Abbreviation for large language model.", "ex": "LLMs have changed debates about knowledge work."}, {"term": "data", "ipa": "/ˈdeɪtə/", "pron": "DAY-tuh", "fr": "données", "def": "Information used by computers, organisations or researchers.", "ex": "AI systems rely on large amounts of data."}, {"term": "dataset", "ipa": "/ˈdeɪtəset/", "pron": "DAY-tuh-set", "fr": "jeu de données", "def": "A structured collection of data.", "ex": "A biased dataset can produce biased results."}, {"term": "training data", "ipa": "/ˈtreɪnɪŋ ˌdeɪtə/", "pron": "TRAY-ning DAY-tuh", "fr": "données d’entraînement", "def": "Data used to train an AI model.", "ex": "Training data shapes how AI behaves."}, {"term": "data-driven", "ipa": "/ˈdeɪtə ˌdrɪvən/", "pron": "DAY-tuh DRIV-uhn", "fr": "fondé sur les données", "def": "Based on data analysis rather than intuition alone.", "ex": "Data-driven management can improve efficiency but reduce autonomy."}, {"term": "predictive analytics", "ipa": "/prɪˌdɪktɪv ˌænəˈlɪtɪks/", "pron": "pri-DIK-tiv an-uh-LIT-iks", "fr": "analyse prédictive", "def": "Using data to predict future events or behaviour.", "ex": "Predictive analytics is used to forecast demand and performance."}, {"term": "productivity", "ipa": "/ˌprɒdʌkˈtɪvəti/", "pron": "prod-uk-TIV-uh-tee", "fr": "productivité", "def": "Output produced per worker or per unit of input.", "ex": "AI could boost productivity if adopted effectively."}, {"term": "labour productivity", "ipa": "/ˈleɪbə ˌprɒdʌkˈtɪvəti/", "pron": "LAY-buh prod-uk-TIV-uh-tee", "fr": "productivité du travail", "def": "Output produced per worker or per hour worked.", "ex": "AI may raise labour productivity in office work."}]}, {"title": "B. Productivity, competitiveness and economic growth", "entries": [{"term": "efficiency gains", "ipa": "/ɪˈfɪʃənsi ɡeɪnz/", "pron": "i-FISH-uhn-see gaynz", "fr": "gains d’efficacité", "def": "Improvements that reduce waste, time or cost.", "ex": "Automation can create efficiency gains."}, {"term": "time-saving technology", "ipa": "/ˈtaɪm ˌseɪvɪŋ tekˈnɒlədʒi/", "pron": "time-SAY-ving tek-NOL-uh-jee", "fr": "technologie qui fait gagner du temps", "def": "Technology that reduces the time needed to complete tasks.", "ex": "AI can be a time-saving technology for administrative tasks."}, {"term": "labour-saving technology", "ipa": "/ˈleɪbə ˌseɪvɪŋ tekˈnɒlədʒi/", "pron": "LAY-buh SAY-ving tek-NOL-uh-jee", "fr": "technologie économisant la main-d’œuvre", "def": "Technology that reduces the need for human labour.", "ex": "Labour-saving technology can ease labour shortages."}, {"term": "cost reduction", "ipa": "/ˈkɒst rɪˌdʌkʃən/", "pron": "kost ri-DUK-shuhn", "fr": "réduction des coûts", "def": "A decrease in costs.", "ex": "Firms often adopt AI for cost reduction."}, {"term": "profitability", "ipa": "/ˌprɒfɪtəˈbɪləti/", "pron": "prof-it-uh-BIL-uh-tee", "fr": "rentabilité", "def": "The ability to make profit.", "ex": "AI may increase profitability by cutting labour costs."}, {"term": "competitiveness", "ipa": "/kəmˈpetətɪvnəs/", "pron": "kuhm-PET-uh-tiv-nuhs", "fr": "compétitivité", "def": "The ability to compete successfully.", "ex": "AI adoption may improve national competitiveness."}, {"term": "economic growth", "ipa": "/ˌiːkəˈnɒmɪk ɡrəʊθ/", "pron": "ee-kuh-NOM-ik growth", "fr": "croissance économique", "def": "An increase in economic output.", "ex": "AI could contribute to long-term economic growth."}, {"term": "new business model", "ipa": "/ˌnjuː ˈbɪznəs ˌmɒdəl/", "pron": "nyoo BIZ-nuhs MOD-uhl", "fr": "nouveau modèle économique", "def": "A new way for a company to create and capture value.", "ex": "AI enables new business models in many sectors."}, {"term": "start-up", "ipa": "/ˈstɑːt ʌp/", "pron": "START-up", "fr": "start-up ; jeune pousse", "def": "A newly created business, often innovative.", "ex": "AI start-ups attract large amounts of investment."}, {"term": "tech sector", "ipa": "/ˈtek ˌsektə/", "pron": "tek SEK-tuh", "fr": "secteur technologique", "def": "The part of the economy focused on technology.", "ex": "The tech sector benefits from AI investment."}, {"term": "digital economy", "ipa": "/ˌdɪdʒɪtəl iˈkɒnəmi/", "pron": "DIJ-i-tuhl i-KON-uh-mee", "fr": "économie numérique", "def": "Economic activity based on digital technologies and data.", "ex": "AI is becoming central to the digital economy."}, {"term": "knowledge economy", "ipa": "/ˈnɒlɪdʒ iˌkɒnəmi/", "pron": "NOL-ij i-KON-uh-mee", "fr": "économie de la connaissance", "def": "An economy based on information, skills and innovation.", "ex": "The knowledge economy is highly exposed to generative AI."}, {"term": "job", "ipa": "/dʒɒb/", "pron": "job", "fr": "emploi", "def": "Paid work or a position of employment.", "ex": "AI will change many jobs rather than simply eliminate them."}, {"term": "employment", "ipa": "/ɪmˈplɔɪmənt/", "pron": "im-PLOY-muhnt", "fr": "emploi", "def": "The state of having paid work.", "ex": "AI’s impact on employment is widely debated."}]}, {"title": "C. Employment, task automation and affected sectors", "entries": [{"term": "unemployment", "ipa": "/ˌʌnɪmˈplɔɪmənt/", "pron": "un-im-PLOY-muhnt", "fr": "chômage", "def": "The state of being without a job while available for work.", "ex": "Some fear that AI will increase unemployment."}, {"term": "technological unemployment", "ipa": "/ˌteknəˌlɒdʒɪkəl ˌʌnɪmˈplɔɪmənt/", "pron": "tek-nuh-LOJ-i-kuhl un-im-PLOY-muhnt", "fr": "chômage technologique", "def": "Unemployment caused by technology replacing workers.", "ex": "Technological unemployment has been feared since the Industrial Revolution."}, {"term": "job displacement", "ipa": "/ˈdʒɒb dɪsˌpleɪsmənt/", "pron": "job dis-PLAYS-muhnt", "fr": "destruction ou déplacement d’emplois", "def": "Workers losing jobs because of economic or technological change.", "ex": "Job displacement may affect routine white-collar work."}, {"term": "job destruction", "ipa": "/ˈdʒɒb dɪˌstrʌkʃən/", "pron": "job di-STRUK-shuhn", "fr": "destruction d’emplois", "def": "The disappearance of jobs.", "ex": "Automation can cause job destruction in some sectors."}, {"term": "job creation", "ipa": "/ˈdʒɒb kriˌeɪʃən/", "pron": "job kree-AY-shuhn", "fr": "création d’emplois", "def": "The creation of new employment opportunities.", "ex": "AI may also lead to job creation in new industries."}, {"term": "net job creation", "ipa": "/ˌnet ˈdʒɒb kriˌeɪʃən/", "pron": "net job kree-AY-shuhn", "fr": "création nette d’emplois", "def": "Jobs created minus jobs lost.", "ex": "The long-term issue is whether AI produces net job creation."}, {"term": "labour market", "ipa": "/ˈleɪbə ˌmɑːkɪt/", "pron": "LAY-buh MAR-kit", "fr": "marché du travail", "def": "The system where workers seek jobs and employers seek workers.", "ex": "The labour market will need to adapt to AI."}, {"term": "workforce", "ipa": "/ˈwɜːkfɔːs/", "pron": "WURK-force", "fr": "main-d’œuvre ; population active", "def": "All people available for work in an economy or organisation.", "ex": "The workforce needs training for the AI era."}, {"term": "human labour", "ipa": "/ˌhjuːmən ˈleɪbə/", "pron": "HYOO-muhn LAY-buh", "fr": "travail humain", "def": "Work performed by people.", "ex": "AI can complement or substitute human labour."}, {"term": "substitution", "ipa": "/ˌsʌbstɪˈtjuːʃən/", "pron": "sub-sti-TYOO-shuhn", "fr": "substitution", "def": "Replacement of one thing by another.", "ex": "AI may lead to substitution of human labour in routine tasks."}, {"term": "complementarity", "ipa": "/ˌkɒmplɪmenˈtærəti/", "pron": "kom-pli-men-TARR-uh-tee", "fr": "complémentarité", "def": "A relationship in which two things work better together.", "ex": "AI can create complementarity between humans and machines."}, {"term": "human-machine collaboration", "ipa": "/ˌhjuːmən məˈʃiːn kəˌlæbəˈreɪʃən/", "pron": "HYOO-muhn muh-SHEEN kuh-lab-uh-RAY-shuhn", "fr": "collaboration humain-machine", "def": "Work shared between humans and machines.", "ex": "Human-machine collaboration can improve decision-making."}, {"term": "human-in-the-loop", "ipa": "/ˌhjuːmən ɪn ðə ˈluːp/", "pron": "HYOO-muhn in thuh loop", "fr": "humain dans la boucle", "def": "A system where humans remain involved in AI decisions.", "ex": "Human-in-the-loop systems reduce the risk of blind automation."}, {"term": "augmentation", "ipa": "/ˌɔːɡmenˈteɪʃən/", "pron": "awg-men-TAY-shuhn", "fr": "augmentation des capacités", "def": "Using technology to enhance human abilities rather than replace them.", "ex": "AI augmentation can make workers more productive."}, {"term": "task automation", "ipa": "/ˈtɑːsk ˌɔːtəˈmeɪʃən/", "pron": "task aw-tuh-MAY-shuhn", "fr": "automatisation des tâches", "def": "Automation of specific tasks rather than whole jobs.", "ex": "Task automation is more common than full job automation."}, {"term": "routine task", "ipa": "/ruːˌtiːn ˈtɑːsk/", "pron": "roo-TEEN task", "fr": "tâche routinière", "def": "A repetitive and predictable task.", "ex": "Routine tasks are more vulnerable to automation."}, {"term": "non-routine task", "ipa": "/ˌnɒn ruːˈtiːn ˈtɑːsk/", "pron": "non-roo-TEEN task", "fr": "tâche non routinière", "def": "A task requiring judgement, creativity or adaptation.", "ex": "Non-routine tasks are harder to automate."}, {"term": "manual work", "ipa": "/ˌmænjuəl ˈwɜːk/", "pron": "MAN-yoo-uhl work", "fr": "travail manuel", "def": "Physical work done by people.", "ex": "Robotics affects some forms of manual work."}, {"term": "cognitive work", "ipa": "/ˈkɒɡnətɪv ˈwɜːk/", "pron": "KOG-nuh-tiv work", "fr": "travail cognitif", "def": "Work involving thinking, analysis or information processing.", "ex": "Generative AI can automate parts of cognitive work."}, {"term": "knowledge work", "ipa": "/ˈnɒlɪdʒ wɜːk/", "pron": "NOL-ij work", "fr": "travail intellectuel ; travail de la connaissance", "def": "Work based on information, expertise and problem-solving.", "ex": "Knowledge work is increasingly exposed to AI."}, {"term": "white-collar job", "ipa": "/ˌwaɪt ˈkɒlə dʒɒb/", "pron": "white KOL-uh job", "fr": "emploi de col blanc", "def": "An office, administrative or professional job.", "ex": "AI may affect white-collar jobs more than earlier automation."}, {"term": "blue-collar job", "ipa": "/ˌbluː ˈkɒlə dʒɒb/", "pron": "blue KOL-uh job", "fr": "emploi de col bleu", "def": "A manual, industrial or trade job.", "ex": "Robots have long affected blue-collar jobs."}, {"term": "creative work", "ipa": "/kriˌeɪtɪv ˈwɜːk/", "pron": "kree-AY-tiv work", "fr": "travail créatif", "def": "Work involving imagination, design or artistic production.", "ex": "Generative AI challenges assumptions about creative work."}, {"term": "administrative work", "ipa": "/ədˈmɪnɪstrətɪv ˈwɜːk/", "pron": "ad-MIN-i-struh-tiv work", "fr": "travail administratif", "def": "Office tasks involving organisation, records or paperwork.", "ex": "Administrative work is highly exposed to software automation."}, {"term": "customer service", "ipa": "/ˌkʌstəmə ˈsɜːvɪs/", "pron": "KUS-tuh-muh SUR-vis", "fr": "service client", "def": "Work involving support for customers.", "ex": "Chatbots are common in customer service."}, {"term": "call centre", "ipa": "/ˈkɔːl ˌsentə/", "pron": "call SEN-tuh", "fr": "centre d’appels", "def": "A workplace handling many phone or online customer contacts.", "ex": "Call centre jobs may be affected by AI chatbots."}, {"term": "manufacturing", "ipa": "/ˌmænjʊˈfæktʃərɪŋ/", "pron": "man-yuh-FAK-chuh-ring", "fr": "industrie manufacturière", "def": "Production of goods in factories.", "ex": "Manufacturing has already been transformed by robots."}, {"term": "logistics", "ipa": "/ləˈdʒɪstɪks/", "pron": "luh-JIS-tiks", "fr": "logistique", "def": "Organisation of transport, storage and delivery.", "ex": "AI optimises logistics and delivery routes."}, {"term": "healthcare", "ipa": "/ˈhelθkeə/", "pron": "HELTH-care", "fr": "soins de santé ; secteur de la santé", "def": "Services related to medical treatment and health.", "ex": "AI can support diagnosis but should not replace clinical judgement."}, {"term": "education", "ipa": "/ˌedjʊˈkeɪʃən/", "pron": "ej-yoo-KAY-shuhn", "fr": "éducation", "def": "Teaching, learning and training systems.", "ex": "AI tutoring tools may change education."}, {"term": "legal services", "ipa": "/ˈliːɡəl ˈsɜːvɪsɪz/", "pron": "LEE-guhl SUR-vis-iz", "fr": "services juridiques", "def": "Professional services related to law.", "ex": "AI can draft documents in legal services."}, {"term": "finance", "ipa": "/ˈfaɪnæns/", "pron": "FY-nans", "fr": "finance", "def": "The sector dealing with money, banking, investment and risk.", "ex": "AI is used in fraud detection and risk assessment."}, {"term": "journalism", "ipa": "/ˈdʒɜːnəlɪzəm/", "pron": "JUR-nuh-liz-uhm", "fr": "journalisme", "def": "The work of collecting and reporting news.", "ex": "AI-generated content raises questions for journalism."}, {"term": "labour shortage", "ipa": "/ˈleɪbə ˌʃɔːtɪdʒ/", "pron": "LAY-buh SHOR-tij", "fr": "pénurie de main-d’œuvre", "def": "A lack of enough workers to fill available jobs.", "ex": "AI may help address labour shortages in ageing societies."}, {"term": "skills shortage", "ipa": "/ˈskɪlz ˌʃɔːtɪdʒ/", "pron": "skilz SHOR-tij", "fr": "pénurie de compétences", "def": "A lack of workers with the skills employers need.", "ex": "AI can worsen skills shortages if training does not keep up."}, {"term": "skills gap", "ipa": "/ˈskɪlz ɡæp/", "pron": "skilz gap", "fr": "écart de compétences", "def": "A mismatch between workers’ skills and employers’ needs.", "ex": "The AI skills gap is becoming a policy concern."}]}, {"title": "D. Skills, training, inequality and labour-market adaptation", "entries": [{"term": "digital skills", "ipa": "/ˌdɪdʒɪtəl ˈskɪlz/", "pron": "DIJ-i-tuhl skilz", "fr": "compétences numériques", "def": "Skills needed to use digital technologies effectively.", "ex": "Digital skills are increasingly necessary at work."}, {"term": "AI literacy", "ipa": "/ˌeɪ ˈaɪ ˈlɪtərəsi/", "pron": "ay-eye LIT-uh-ruh-see", "fr": "maîtrise de l’IA ; culture de l’IA", "def": "The ability to understand and use AI critically.", "ex": "AI literacy should become part of education."}, {"term": "data literacy", "ipa": "/ˈdeɪtə ˈlɪtərəsi/", "pron": "DAY-tuh LIT-uh-ruh-see", "fr": "culture des données", "def": "The ability to understand and use data.", "ex": "Data literacy helps workers interpret AI outputs."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion", "def": "Training workers for new types of jobs.", "ex": "Reskilling is essential for workers displaced by AI."}, {"term": "upskilling", "ipa": "/ˌʌpˈskɪlɪŋ/", "pron": "up-SKIL-ing", "fr": "montée en compétences", "def": "Improving workers’ existing skills.", "ex": "Upskilling can help workers use AI tools effectively."}, {"term": "retraining", "ipa": "/ˌriːˈtreɪnɪŋ/", "pron": "ree-TRAY-ning", "fr": "reconversion professionnelle", "def": "Training people for a new job or sector.", "ex": "Retraining programmes can reduce technological unemployment."}, {"term": "lifelong learning", "ipa": "/ˌlaɪflɒŋ ˈlɜːnɪŋ/", "pron": "life-long LUR-ning", "fr": "formation tout au long de la vie", "def": "Continuous learning throughout adult life.", "ex": "Lifelong learning is vital in the AI economy."}, {"term": "vocational training", "ipa": "/vəʊˌkeɪʃənəl ˈtreɪnɪŋ/", "pron": "voh-KAY-shuh-nuhl TRAY-ning", "fr": "formation professionnelle", "def": "Practical training for specific jobs or trades.", "ex": "Vocational training must adapt to new technologies."}, {"term": "STEM skills", "ipa": "/ˌstem ˈskɪlz/", "pron": "stem skilz", "fr": "compétences STEM", "def": "Skills in science, technology, engineering and mathematics.", "ex": "STEM skills are valued in AI-related jobs."}, {"term": "soft skills", "ipa": "/ˌsɒft ˈskɪlz/", "pron": "soft skilz", "fr": "compétences relationnelles ; soft skills", "def": "Interpersonal and human skills such as communication and empathy.", "ex": "Soft skills may become more valuable as routine tasks are automated."}, {"term": "critical thinking", "ipa": "/ˌkrɪtɪkəl ˈθɪŋkɪŋ/", "pron": "KRIT-i-kuhl THINK-ing", "fr": "esprit critique", "def": "The ability to analyse information carefully and independently.", "ex": "Critical thinking is needed to assess AI outputs."}, {"term": "creativity", "ipa": "/ˌkriːeɪˈtɪvəti/", "pron": "kree-ay-TIV-uh-tee", "fr": "créativité", "def": "The ability to produce original ideas or solutions.", "ex": "Creativity may help workers complement AI."}, {"term": "adaptability", "ipa": "/əˌdæptəˈbɪləti/", "pron": "uh-dap-tuh-BIL-uh-tee", "fr": "adaptabilité", "def": "The ability to adjust to change.", "ex": "Adaptability is crucial in fast-changing labour markets."}, {"term": "employability", "ipa": "/ɪmˌplɔɪəˈbɪləti/", "pron": "im-ploy-uh-BIL-uh-tee", "fr": "employabilité", "def": "A person’s ability to get and keep work.", "ex": "AI skills may improve employability."}, {"term": "education system", "ipa": "/ˌedjʊˈkeɪʃən ˌsɪstəm/", "pron": "ej-yoo-KAY-shuhn SIS-tuhm", "fr": "système éducatif", "def": "The institutions and rules organising education.", "ex": "The education system must prepare students for AI."}, {"term": "training programme", "ipa": "/ˈtreɪnɪŋ ˌprəʊɡræm/", "pron": "TRAY-ning PROH-gram", "fr": "programme de formation", "def": "A structured course to develop skills.", "ex": "Training programmes should target vulnerable workers."}, {"term": "apprenticeship", "ipa": "/əˈprentɪsʃɪp/", "pron": "uh-PREN-tis-ship", "fr": "apprentissage", "def": "Training combining paid work and learning.", "ex": "Apprenticeships can help young workers enter tech-related jobs."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "The gap between those with and without access to digital tools and skills.", "ex": "The digital divide could widen inequality in the AI economy."}, {"term": "AI divide", "ipa": "/ˌeɪ ˈaɪ dɪˈvaɪd/", "pron": "ay-eye di-VYDE", "fr": "fracture de l’IA", "def": "The gap between people, firms or countries that can benefit from AI and those that cannot.", "ex": "An AI divide may emerge between skilled and unskilled workers."}, {"term": "income inequality", "ipa": "/ˈɪnkʌm ˌɪnɪˈkwɒləti/", "pron": "IN-kum in-i-KWOL-uh-tee", "fr": "inégalité des revenus", "def": "Unequal distribution of income.", "ex": "AI could widen income inequality."}, {"term": "wealth inequality", "ipa": "/ˈwelθ ˌɪnɪˈkwɒləti/", "pron": "welth in-i-KWOL-uh-tee", "fr": "inégalité patrimoniale", "def": "Unequal distribution of assets and wealth.", "ex": "AI profits may worsen wealth inequality."}, {"term": "wage polarisation", "ipa": "/ˈweɪdʒ ˌpəʊləraɪˈzeɪʃən/", "pron": "wayj poh-luh-ry-ZAY-shuhn", "fr": "polarisation des salaires", "def": "The widening gap between high-paid and low-paid workers.", "ex": "Automation can contribute to wage polarisation."}, {"term": "job polarisation", "ipa": "/ˈdʒɒb ˌpəʊləraɪˈzeɪʃən/", "pron": "job poh-luh-ry-ZAY-shuhn", "fr": "polarisation de l’emploi", "def": "Growth of high- and low-skill jobs while middle-skill jobs decline.", "ex": "Job polarisation can weaken the middle class."}, {"term": "winner-takes-all economy", "ipa": "/ˌwɪnə teɪks ˈɔːl iˌkɒnəmi/", "pron": "WIN-uh-tayks-all i-KON-uh-mee", "fr": "économie du gagnant rafle tout", "def": "An economy where a small number of firms or individuals capture most gains.", "ex": "AI could reinforce a winner-takes-all economy."}, {"term": "capital owner", "ipa": "/ˈkæpɪtəl ˌəʊnə/", "pron": "KAP-i-tuhl OH-nuh", "fr": "détenteur de capital", "def": "A person or firm owning productive assets.", "ex": "Capital owners may capture much of the value created by AI."}, {"term": "labour share", "ipa": "/ˈleɪbə ʃeə/", "pron": "LAY-buh share", "fr": "part du travail dans le revenu", "def": "The share of national income going to workers as wages.", "ex": "Automation may reduce the labour share."}, {"term": "capital share", "ipa": "/ˈkæpɪtəl ʃeə/", "pron": "KAP-i-tuhl share", "fr": "part du capital dans le revenu", "def": "The share of national income going to owners of capital.", "ex": "AI may increase the capital share."}, {"term": "market concentration", "ipa": "/ˈmɑːkɪt ˌkɒnsənˈtreɪʃən/", "pron": "MAR-kit kon-suhn-TRAY-shuhn", "fr": "concentration du marché", "def": "A situation where a few firms dominate a market.", "ex": "AI may increase market concentration around Big Tech."}, {"term": "Big Tech", "ipa": "/ˌbɪɡ ˈtek/", "pron": "big tek", "fr": "grandes entreprises technologiques", "def": "Large technology companies with major economic and social power.", "ex": "Big Tech controls much of the AI infrastructure."}, {"term": "monopoly power", "ipa": "/məˈnɒpəli ˈpaʊə/", "pron": "muh-NOP-uh-lee POW-uh", "fr": "pouvoir monopolistique", "def": "The power of a dominant firm to control prices or markets.", "ex": "AI could strengthen monopoly power."}, {"term": "platform economy", "ipa": "/ˈplætfɔːm iˌkɒnəmi/", "pron": "PLAT-form i-KON-uh-mee", "fr": "économie de plateforme", "def": "An economy organised through digital platforms.", "ex": "The platform economy may use AI to manage workers."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots ; gig economy", "def": "Labour market based on short-term, flexible tasks.", "ex": "AI can allocate tasks in the gig economy."}, {"term": "algorithmic management", "ipa": "/ˌælɡəˈrɪðmɪk ˈmænɪdʒmənt/", "pron": "al-guh-RITH-mik MAN-ij-muhnt", "fr": "management algorithmique", "def": "Management of workers through algorithms.", "ex": "Algorithmic management can reduce worker autonomy."}, {"term": "workplace surveillance", "ipa": "/ˈwɜːkpleɪs səˌveɪləns/", "pron": "WURK-place suh-VAY-luhns", "fr": "surveillance au travail", "def": "Monitoring of employees at work.", "ex": "AI can intensify workplace surveillance."}, {"term": "employee monitoring", "ipa": "/ɪmˈplɔɪiː ˈmɒnɪtərɪŋ/", "pron": "im-PLOY-ee MON-i-tuh-ring", "fr": "surveillance des salariés", "def": "Tracking employees’ activity or performance.", "ex": "Employee monitoring raises privacy concerns."}]}, {"title": "E. Governance, ethics, worker protection and high-value verbs", "entries": [{"term": "performance tracking", "ipa": "/pəˈfɔːməns ˈtrækɪŋ/", "pron": "puh-FOR-muhns TRAK-ing", "fr": "suivi de la performance", "def": "Measuring and recording workers’ performance.", "ex": "Performance tracking can create stress."}, {"term": "productivity monitoring", "ipa": "/ˌprɒdʌkˈtɪvəti ˈmɒnɪtərɪŋ/", "pron": "prod-uk-TIV-uh-tee MON-i-tuh-ring", "fr": "surveillance de la productivité", "def": "Tracking worker productivity through tools or software.", "ex": "Productivity monitoring may undermine trust."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "Protection of personal information and private life.", "ex": "AI in the workplace raises privacy issues."}, {"term": "data privacy", "ipa": "/ˈdeɪtə ˈprɪvəsi/", "pron": "DAY-tuh PRIV-uh-see", "fr": "confidentialité des données", "def": "Protection of personal data.", "ex": "Data privacy is essential in AI-driven workplaces."}, {"term": "bias", "ipa": "/ˈbaɪəs/", "pron": "BY-uhs", "fr": "biais", "def": "Unfair preference or prejudice in data, systems or decisions.", "ex": "AI systems can reproduce social bias."}, {"term": "algorithmic bias", "ipa": "/ˌælɡəˈrɪðmɪk ˈbaɪəs/", "pron": "al-guh-RITH-mik BY-uhs", "fr": "biais algorithmique", "def": "Unfair or discriminatory outcomes produced by algorithms.", "ex": "Algorithmic bias can affect recruitment."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity or status.", "ex": "AI hiring tools can reinforce discrimination."}, {"term": "automated decision-making", "ipa": "/ˈɔːtəmeɪtɪd dɪˈsɪʒən ˌmeɪkɪŋ/", "pron": "AW-tuh-may-tid di-SIZH-uhn MAY-king", "fr": "prise de décision automatisée", "def": "Decisions made by software or algorithms with limited human input.", "ex": "Automated decision-making needs accountability."}, {"term": "transparency", "ipa": "/trænˈspærənsi/", "pron": "tran-SPARR-uhn-see", "fr": "transparence", "def": "Openness and clarity about how decisions are made.", "ex": "Transparency is needed when AI affects workers."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité", "def": "Responsibility for decisions and their consequences.", "ex": "Accountability is difficult when AI systems are opaque."}, {"term": "explainability", "ipa": "/ɪkˌspleɪnəˈbɪləti/", "pron": "ik-splay-nuh-BIL-uh-tee", "fr": "explicabilité", "def": "The ability to explain how an AI system reaches an output.", "ex": "Explainability matters in hiring and finance."}, {"term": "black box", "ipa": "/ˌblæk ˈbɒks/", "pron": "black box", "fr": "boîte noire", "def": "A system whose internal workings are difficult to understand.", "ex": "Some AI systems operate like a black box."}, {"term": "human oversight", "ipa": "/ˌhjuːmən ˈəʊvəsaɪt/", "pron": "HYOO-muhn OH-vuh-syte", "fr": "supervision humaine", "def": "Human supervision of automated systems.", "ex": "Human oversight is needed for high-stakes AI decisions."}, {"term": "AI governance", "ipa": "/ˌeɪ ˈaɪ ˈɡʌvənəns/", "pron": "ay-eye GUV-uh-nuhns", "fr": "gouvernance de l’IA", "def": "Rules and processes for controlling the use of AI.", "ex": "AI governance must balance innovation and protection."}, {"term": "AI regulation", "ipa": "/ˌeɪ ˈaɪ ˌreɡjʊˈleɪʃən/", "pron": "ay-eye reg-yuh-LAY-shuhn", "fr": "réglementation de l’IA", "def": "Laws or rules controlling AI development and use.", "ex": "AI regulation is becoming a major political issue."}, {"term": "ethical AI", "ipa": "/ˌeθɪkəl ˌeɪ ˈaɪ/", "pron": "ETH-i-kuhl ay-eye", "fr": "IA éthique", "def": "AI designed and used according to ethical principles.", "ex": "Ethical AI should protect fairness and human dignity."}, {"term": "responsible AI", "ipa": "/rɪˌspɒnsəbəl ˌeɪ ˈaɪ/", "pron": "ri-SPON-suh-buhl ay-eye", "fr": "IA responsable", "def": "AI developed and used in safe, fair and accountable ways.", "ex": "Responsible AI requires regulation and transparency."}, {"term": "trustworthy AI", "ipa": "/ˈtrʌstwɜːði ˌeɪ ˈaɪ/", "pron": "TRUST-wur-thee ay-eye", "fr": "IA digne de confiance", "def": "AI that is reliable, safe, fair and accountable.", "ex": "Workers need trustworthy AI systems."}, {"term": "AI ethics", "ipa": "/ˌeɪ ˈaɪ ˈeθɪks/", "pron": "ay-eye ETH-iks", "fr": "éthique de l’IA", "def": "The study of moral issues linked to AI.", "ex": "AI ethics includes fairness, privacy and accountability."}, {"term": "labour rights", "ipa": "/ˈleɪbə raɪts/", "pron": "LAY-buh rites", "fr": "droits des travailleurs", "def": "Rights protecting workers’ pay, conditions and representation.", "ex": "AI should not undermine labour rights."}, {"term": "worker protection", "ipa": "/ˈwɜːkə prəˌtekʃən/", "pron": "WUR-kuh pruh-TEK-shuhn", "fr": "protection des travailleurs", "def": "Legal or social protection for workers.", "ex": "Worker protection must be updated for AI workplaces."}, {"term": "collective bargaining", "ipa": "/kəˌlektɪv ˈbɑːɡɪnɪŋ/", "pron": "kuh-LEK-tiv BAR-gi-ning", "fr": "négociation collective", "def": "Negotiation between employers and workers’ representatives.", "ex": "Collective bargaining can address AI at work."}, {"term": "trade union", "ipa": "/ˌtreɪd ˈjuːniən/", "pron": "trade YOO-nee-uhn", "fr": "syndicat", "def": "An organisation representing workers.", "ex": "Trade unions demand a voice in AI deployment."}, {"term": "social dialogue", "ipa": "/ˌsəʊʃəl ˈdaɪəlɒɡ/", "pron": "SOH-shuhl DY-uh-log", "fr": "dialogue social", "def": "Negotiation and discussion between employers, workers and governments.", "ex": "Social dialogue can make AI adoption fairer."}, {"term": "workplace democracy", "ipa": "/ˈwɜːkpleɪs dɪˌmɒkrəsi/", "pron": "WURK-place di-MOK-ruh-see", "fr": "démocratie au travail", "def": "Workers having a voice in workplace decisions.", "ex": "Workplace democracy matters when AI changes jobs."}, {"term": "universal basic income", "ipa": "/ˌjuːnɪˈvɜːsəl ˌbeɪsɪk ˈɪnkʌm/", "pron": "yoo-ni-VUR-suhl BAY-sik IN-kum", "fr": "revenu universel", "def": "A regular payment given to everyone without conditions.", "ex": "Universal basic income is proposed as a response to automation."}, {"term": "UBI", "ipa": "/ˌjuː biː ˈaɪ/", "pron": "yoo-bee-eye", "fr": "revenu universel ; RBI", "def": "Abbreviation for universal basic income.", "ex": "UBI would provide income security in an automated economy."}, {"term": "robot tax", "ipa": "/ˈrəʊbɒt tæks/", "pron": "ROH-bot taks", "fr": "taxe sur les robots", "def": "A proposed tax on automation or robots replacing human labour.", "ex": "A robot tax is meant to fund social protection."}, {"term": "social safety net", "ipa": "/ˌsəʊʃəl ˈseɪfti net/", "pron": "SOH-shuhl SAYF-tee net", "fr": "filet de sécurité sociale", "def": "A system protecting people from poverty and hardship.", "ex": "The social safety net may need strengthening in the AI era."}, {"term": "welfare state", "ipa": "/ˈwelfeə steɪt/", "pron": "WEL-fair state", "fr": "État-providence", "def": "A system providing social protection, healthcare and benefits.", "ex": "The welfare state must adapt to technological disruption."}, {"term": "just transition", "ipa": "/ˌdʒʌst trænˈzɪʃən/", "pron": "just tran-ZISH-uhn", "fr": "transition juste", "def": "A fair transition that protects workers and communities during major change.", "ex": "AI adoption requires a just transition for affected workers."}, {"term": "industrial policy", "ipa": "/ɪnˈdʌstriəl ˈpɒləsi/", "pron": "in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle", "def": "Government strategy to support selected industries or technologies.", "ex": "AI industrial policy can support national competitiveness."}, {"term": "public investment", "ipa": "/ˌpʌblɪk ɪnˈvestmənt/", "pron": "PUB-lik in-VEST-muhnt", "fr": "investissement public", "def": "Government spending on long-term assets such as education or infrastructure.", "ex": "Public investment is needed in AI skills and infrastructure."}, {"term": "research and development", "ipa": "/rɪˌsɜːtʃ ənd dɪˈveləpmənt/", "pron": "ri-SURCH and di-VEL-uhp-muhnt", "fr": "recherche et développement", "def": "Work aimed at creating new knowledge or technologies.", "ex": "AI requires major research and development investment."}, {"term": "R&D", "ipa": "/ˌɑːr ən ˈdiː/", "pron": "ar-and-dee", "fr": "R&D", "def": "Abbreviation for research and development.", "ex": "R&D spending can strengthen AI competitiveness."}, {"term": "digital infrastructure", "ipa": "/ˌdɪdʒɪtəl ˈɪnfrəˌstrʌktʃə/", "pron": "DIJ-i-tuhl IN-fruh-struk-chuh", "fr": "infrastructure numérique", "def": "Digital systems such as broadband, cloud computing and data centres.", "ex": "Digital infrastructure is essential for AI adoption."}, {"term": "cloud computing", "ipa": "/ˌklaʊd kəmˈpjuːtɪŋ/", "pron": "klowd kuhm-PYOO-ting", "fr": "informatique en nuage ; cloud", "def": "Computing services delivered through remote servers.", "ex": "Cloud computing supports AI tools."}, {"term": "data centre", "ipa": "/ˈdeɪtə ˌsentə/", "pron": "DAY-tuh SEN-tuh", "fr": "centre de données", "def": "A facility containing servers and computing infrastructure.", "ex": "AI increases demand for data centres."}, {"term": "energy consumption", "ipa": "/ˈenədʒi kənˌsʌmpʃən/", "pron": "EN-uh-jee kuhn-SUMP-shuhn", "fr": "consommation d’énergie", "def": "The amount of energy used.", "ex": "AI data centres raise concerns about energy consumption."}, {"term": "carbon footprint", "ipa": "/ˌkɑːbən ˈfʊtprɪnt/", "pron": "KAR-buhn FOOT-print", "fr": "empreinte carbone", "def": "The greenhouse gas emissions caused by an activity or product.", "ex": "AI systems can have a significant carbon footprint."}, {"term": "to automate tasks", "ipa": "/ˈɔːtəmeɪt tɑːsks/", "pron": "AW-tuh-mayt tasks", "fr": "automatiser des tâches", "def": "To make tasks performed by machines or software.", "ex": "AI can automate tasks such as drafting, sorting and summarising."}, {"term": "to replace workers", "ipa": "/rɪˈpleɪs ˈwɜːkəz/", "pron": "ri-PLAYS WUR-kuhz", "fr": "remplacer les travailleurs", "def": "To make workers unnecessary by using technology or other labour.", "ex": "Automation may replace workers in routine roles."}, {"term": "to displace workers", "ipa": "/dɪsˈpleɪs ˈwɜːkəz/", "pron": "dis-PLAYS WUR-kuhz", "fr": "déplacer / évincer des travailleurs", "def": "To cause workers to lose jobs because of change.", "ex": "AI may displace workers without adequate retraining."}, {"term": "to create jobs", "ipa": "/kriˈeɪt dʒɒbz/", "pron": "kree-AYT jobz", "fr": "créer des emplois", "def": "To generate employment opportunities.", "ex": "AI may create jobs in new sectors."}, {"term": "to destroy jobs", "ipa": "/dɪˈstrɔɪ dʒɒbz/", "pron": "di-STROY jobz", "fr": "détruire des emplois", "def": "To cause jobs to disappear.", "ex": "Automation can destroy jobs faster than new ones appear."}, {"term": "to boost productivity", "ipa": "/buːst ˌprɒdʌkˈtɪvəti/", "pron": "boost prod-uk-TIV-uh-tee", "fr": "stimuler la productivité", "def": "To increase output per worker or input.", "ex": "AI could boost productivity in services."}, {"term": "to cut labour costs", "ipa": "/kʌt ˈleɪbə kɒsts/", "pron": "kut LAY-buh kosts", "fr": "réduire les coûts de main-d’œuvre", "def": "To reduce spending on workers.", "ex": "Firms may use AI to cut labour costs."}, {"term": "to augment human work", "ipa": "/ɔːɡˈment ˌhjuːmən ˈwɜːk/", "pron": "awg-MENT HYOO-muhn work", "fr": "augmenter le travail humain", "def": "To improve human work with technology rather than replace it.", "ex": "AI can augment human work when used well."}, {"term": "to complement human skills", "ipa": "/ˈkɒmplɪment ˌhjuːmən skɪlz/", "pron": "KOM-pli-ment HYOO-muhn skilz", "fr": "compléter les compétences humaines", "def": "To work together with human abilities.", "ex": "AI should complement human skills, not simply replace them."}, {"term": "to reskill workers", "ipa": "/ˌriːˈskɪl ˈwɜːkəz/", "pron": "ree-SKIL WUR-kuhz", "fr": "reconvertir les travailleurs", "def": "To train workers for new types of jobs.", "ex": "Governments must reskill workers affected by automation."}, {"term": "to upskill the workforce", "ipa": "/ˌʌpˈskɪl ðə ˈwɜːkfɔːs/", "pron": "up-SKIL thuh WURK-force", "fr": "renforcer les compétences de la main-d’œuvre", "def": "To improve workers’ skills.", "ex": "Firms need to upskill the workforce."}, {"term": "to adapt to AI", "ipa": "/əˈdæpt tə ˌeɪ ˈaɪ/", "pron": "uh-DAPT tuh ay-eye", "fr": "s’adapter à l’IA", "def": "To adjust practices, skills or policies to artificial intelligence.", "ex": "Schools and workers must adapt to AI."}, {"term": "to regulate AI", "ipa": "/ˈreɡjʊleɪt ˌeɪ ˈaɪ/", "pron": "REG-yuh-layt ay-eye", "fr": "réglementer l’IA", "def": "To create rules controlling AI development and use.", "ex": "Governments are trying to regulate AI."}, {"term": "to protect workers’ rights", "ipa": "/prəˈtekt ˈwɜːkəz raɪts/", "pron": "pruh-TEKT WUR-kuhz rites", "fr": "protéger les droits des travailleurs", "def": "To defend legal and social protections for workers.", "ex": "AI policy must protect workers’ rights."}, {"term": "to ensure human oversight", "ipa": "/ɪnˈʃɔː ˌhjuːmən ˈəʊvəsaɪt/", "pron": "in-SHOR HYOO-muhn OH-vuh-syte", "fr": "garantir une supervision humaine", "def": "To make sure humans supervise AI systems.", "ex": "High-stakes AI decisions should ensure human oversight."}, {"term": "to reduce algorithmic bias", "ipa": "/rɪˈdjuːs ˌælɡəˈrɪðmɪk ˈbaɪəs/", "pron": "ri-DYOOSS al-guh-RITH-mik BY-uhs", "fr": "réduire les biais algorithmiques", "def": "To lessen unfair outcomes caused by algorithms.", "ex": "Audits can reduce algorithmic bias."}, {"term": "to share productivity gains", "ipa": "/ʃeə ˌprɒdʌkˈtɪvəti ɡeɪnz/", "pron": "share prod-uk-TIV-uh-tee gaynz", "fr": "partager les gains de productivité", "def": "To distribute the benefits of higher productivity fairly.", "ex": "Society must share productivity gains from AI."}, {"term": "to widen inequality", "ipa": "/ˈwaɪdən ˌɪnɪˈkwɒləti/", "pron": "WY-duhn in-i-KWOL-uh-tee", "fr": "creuser les inégalités", "def": "To make inequality worse.", "ex": "AI could widen inequality if gains are captured by a few firms."}, {"term": "to build a just transition", "ipa": "/bɪld ə ˌdʒʌst trænˈzɪʃən/", "pron": "bild uh just tran-ZISH-uhn", "fr": "construire une transition juste", "def": "To create a fair transition that protects affected workers.", "ex": "Policymakers need to build a just transition for the AI economy."}]}]}, {"id": "p6c50", "part": 6, "chapter": 50, "title": "Diplomacy", "file": "cpge_vocab_part6_chapter50_diplomacy_premium.html", "count": 154, "sections": [{"title": "A. Core diplomacy and diplomatic actors", "entries": [{"term": "diplomacy", "ipa": "/dɪˈpləʊməsi/", "pron": "di-PLOH-muh-see", "fr": "diplomatie", "def": "The practice of managing relations between countries through dialogue, negotiation and representation.", "ex": "Diplomacy is essential to prevent conflict and build cooperation."}, {"term": "diplomatic relations", "ipa": "/ˌdɪpləˈmætɪk rɪˈleɪʃənz/", "pron": "dip-luh-MAT-ik ri-LAY-shuhnz", "fr": "relations diplomatiques", "def": "Official relations between governments.", "ex": "The two countries restored diplomatic relations after years of tension."}, {"term": "foreign policy", "ipa": "/ˌfɒrən ˈpɒləsi/", "pron": "FOR-uhn POL-uh-see", "fr": "politique étrangère", "def": "A government’s strategy in dealing with other countries.", "ex": "Foreign policy reflects national interests and values."}, {"term": "international relations", "ipa": "/ˌɪntəˈnæʃənəl rɪˈleɪʃənz/", "pron": "IN-tuh-NASH-uh-nuhl ri-LAY-shuhnz", "fr": "relations internationales", "def": "The study or practice of relations between states and international actors.", "ex": "International relations are shaped by power, law, trade and diplomacy."}, {"term": "statecraft", "ipa": "/ˈsteɪtkrɑːft/", "pron": "STATE-kraft", "fr": "art de gouverner ; art diplomatique", "def": "The skill of governing and conducting foreign affairs.", "ex": "Statecraft requires strategy, patience and compromise."}, {"term": "diplomat", "ipa": "/ˈdɪpləmæt/", "pron": "DIP-luh-mat", "fr": "diplomate", "def": "An official representing a country abroad.", "ex": "A diplomat must defend national interests while maintaining dialogue."}, {"term": "ambassador", "ipa": "/æmˈbæsədə/", "pron": "am-BAS-uh-duh", "fr": "ambassadeur ; ambassadrice", "def": "The highest-ranking diplomatic representative of a country abroad.", "ex": "The ambassador met government officials to discuss the crisis."}, {"term": "embassy", "ipa": "/ˈembəsi/", "pron": "EM-buh-see", "fr": "ambassade", "def": "The official office of an ambassador in a foreign country.", "ex": "Citizens can seek assistance from their embassy abroad."}, {"term": "consulate", "ipa": "/ˈkɒnsjʊlət/", "pron": "KON-syuh-luht", "fr": "consulat", "def": "An office that helps citizens and promotes relations in another country.", "ex": "The consulate provides visas and assistance to nationals."}, {"term": "consul", "ipa": "/ˈkɒnsəl/", "pron": "KON-suhl", "fr": "consul", "def": "An official representing a country, often dealing with citizens and visas.", "ex": "The consul helped citizens affected by the emergency."}, {"term": "envoy", "ipa": "/ˈenvɔɪ/", "pron": "EN-voy", "fr": "émissaire ; envoyé", "def": "A person sent as a representative on a diplomatic mission.", "ex": "A special envoy was appointed to negotiate peace."}, {"term": "special envoy", "ipa": "/ˌspeʃəl ˈenvɔɪ/", "pron": "SPESH-uhl EN-voy", "fr": "envoyé spécial", "def": "A representative sent to deal with a specific diplomatic issue.", "ex": "The UN special envoy tried to mediate between the parties."}, {"term": "diplomatic mission", "ipa": "/ˌdɪpləˈmætɪk ˈmɪʃən/", "pron": "dip-luh-MAT-ik MISH-uhn", "fr": "mission diplomatique", "def": "A group or office representing a country abroad.", "ex": "The diplomatic mission remained open despite rising tensions."}, {"term": "foreign ministry", "ipa": "/ˌfɒrən ˈmɪnɪstri/", "pron": "FOR-uhn MIN-i-stree", "fr": "ministère des Affaires étrangères", "def": "A government department responsible for foreign affairs.", "ex": "The foreign ministry issued a statement condemning the attack."}, {"term": "foreign minister", "ipa": "/ˌfɒrən ˈmɪnɪstə/", "pron": "FOR-uhn MIN-i-stuh", "fr": "ministre des Affaires étrangères", "def": "A government official responsible for foreign policy.", "ex": "The foreign minister called for renewed negotiations."}, {"term": "secretary of state", "ipa": "/ˌsekrətəri əv ˈsteɪt/", "pron": "SEK-ruh-tuh-ree ov state", "fr": "secrétaire d’État américain", "def": "In the US, the minister responsible for foreign affairs.", "ex": "The Secretary of State travelled to the region for talks."}, {"term": "diplomatic corps", "ipa": "/ˌdɪpləˈmætɪk kɔː/", "pron": "dip-luh-MAT-ik kor", "fr": "corps diplomatique", "def": "All diplomats posted in a particular country.", "ex": "The diplomatic corps attended the official ceremony."}, {"term": "protocol", "ipa": "/ˈprəʊtəkɒl/", "pron": "PROH-tuh-kol", "fr": "protocole", "def": "Formal rules governing diplomatic behaviour and ceremonies.", "ex": "Diplomatic protocol matters during state visits."}, {"term": "diplomatic immunity", "ipa": "/ˌdɪpləˈmætɪk ɪˈmjuːnəti/", "pron": "dip-luh-MAT-ik im-YOO-nuh-tee", "fr": "immunité diplomatique", "def": "Legal protection granted to diplomats from certain host-country laws.", "ex": "Diplomatic immunity is meant to protect diplomats from political pressure."}, {"term": "persona non grata", "ipa": "/pəˌsəʊnə nɒn ˈɡrɑːtə/", "pron": "puh-SOH-nuh non GRAH-tuh", "fr": "persona non grata", "def": "A diplomat no longer accepted by a host country.", "ex": "The ambassador was declared persona non grata."}, {"term": "bilateral diplomacy", "ipa": "/ˌbaɪˈlætərəl dɪˈpləʊməsi/", "pron": "by-LAT-uh-ruhl di-PLOH-muh-see", "fr": "diplomatie bilatérale", "def": "Diplomacy between two countries.", "ex": "Bilateral diplomacy can solve practical disputes."}, {"term": "multilateral diplomacy", "ipa": "/ˌmʌltiˈlætərəl dɪˈpləʊməsi/", "pron": "MUL-tee-LAT-uh-ruhl di-PLOH-muh-see", "fr": "diplomatie multilatérale", "def": "Diplomacy involving several countries or international organisations.", "ex": "Climate change requires multilateral diplomacy."}, {"term": "regional diplomacy", "ipa": "/ˌriːdʒənəl dɪˈpləʊməsi/", "pron": "REE-juh-nuhl di-PLOH-muh-see", "fr": "diplomatie régionale", "def": "Diplomacy focused on a specific region.", "ex": "Regional diplomacy is crucial in the Middle East."}, {"term": "shuttle diplomacy", "ipa": "/ˈʃʌtəl dɪˌpləʊməsi/", "pron": "SHUT-uhl di-PLOH-muh-see", "fr": "navette diplomatique", "def": "Negotiation in which a mediator travels between parties who do not meet directly.", "ex": "Shuttle diplomacy helped keep communication open."}, {"term": "quiet diplomacy", "ipa": "/ˌkwaɪət dɪˈpləʊməsi/", "pron": "KWY-uht di-PLOH-muh-see", "fr": "diplomatie discrète", "def": "Discreet diplomacy conducted away from public attention.", "ex": "Quiet diplomacy can be more effective than public pressure."}, {"term": "public diplomacy", "ipa": "/ˌpʌblɪk dɪˈpləʊməsi/", "pron": "PUB-lik di-PLOH-muh-see", "fr": "diplomatie publique", "def": "Efforts to influence foreign publics and improve a country’s image.", "ex": "Public diplomacy uses culture, media and education."}, {"term": "digital diplomacy", "ipa": "/ˌdɪdʒɪtəl dɪˈpləʊməsi/", "pron": "DIJ-i-tuhl di-PLOH-muh-see", "fr": "diplomatie numérique", "def": "Diplomacy conducted or supported through digital tools and social media.", "ex": "Digital diplomacy allows governments to communicate directly with foreign audiences."}, {"term": "summit diplomacy", "ipa": "/ˈsʌmɪt dɪˌpləʊməsi/", "pron": "SUM-it di-PLOH-muh-see", "fr": "diplomatie de sommet", "def": "Diplomacy conducted through meetings between heads of state or government.", "ex": "Summit diplomacy can produce symbolic breakthroughs."}, {"term": "track-two diplomacy", "ipa": "/ˌtræk tuː dɪˈpləʊməsi/", "pron": "track-too di-PLOH-muh-see", "fr": "diplomatie parallèle", "def": "Informal diplomacy involving non-official actors such as experts or NGOs.", "ex": "Track-two diplomacy can prepare the ground for official talks."}, {"term": "back-channel diplomacy", "ipa": "/ˌbæk ˈtʃænəl dɪˈpləʊməsi/", "pron": "bak-CHAN-uhl di-PLOH-muh-see", "fr": "diplomatie de canal secret", "def": "Secret or unofficial communication between governments.", "ex": "Back-channel diplomacy can help when public talks are impossible."}]}, {"title": "B. Negotiation, agreements and peace processes", "entries": [{"term": "negotiation", "ipa": "/nɪˌɡəʊʃiˈeɪʃən/", "pron": "ni-GOH-shee-AY-shuhn", "fr": "négociation", "def": "Discussion aimed at reaching an agreement.", "ex": "Negotiation requires compromise and trust."}, {"term": "talks", "ipa": "/tɔːks/", "pron": "tawks", "fr": "pourparlers", "def": "Formal or informal discussions between parties.", "ex": "Peace talks resumed after months of deadlock."}, {"term": "peace talks", "ipa": "/ˈpiːs tɔːks/", "pron": "peace tawks", "fr": "pourparlers de paix", "def": "Negotiations aimed at ending a conflict.", "ex": "Peace talks collapsed after renewed fighting."}, {"term": "dialogue", "ipa": "/ˈdaɪəlɒɡ/", "pron": "DY-uh-log", "fr": "dialogue", "def": "Open discussion between parties.", "ex": "Dialogue is necessary even between rivals."}, {"term": "consultation", "ipa": "/ˌkɒnsəlˈteɪʃən/", "pron": "kon-suhl-TAY-shuhn", "fr": "consultation", "def": "Discussion before making a decision.", "ex": "The allies held consultations before responding."}, {"term": "mediation", "ipa": "/ˌmiːdiˈeɪʃən/", "pron": "mee-dee-AY-shuhn", "fr": "médiation", "def": "Intervention by a neutral third party to help resolve a dispute.", "ex": "Mediation can help parties reach a compromise."}, {"term": "mediator", "ipa": "/ˈmiːdieɪtə/", "pron": "MEE-dee-ay-tuh", "fr": "médiateur ; médiatrice", "def": "A neutral person or actor helping parties reach agreement.", "ex": "The mediator proposed a ceasefire plan."}, {"term": "arbitration", "ipa": "/ˌɑːbɪˈtreɪʃən/", "pron": "ar-bi-TRAY-shuhn", "fr": "arbitrage", "def": "Settlement of a dispute by a neutral authority whose decision may be binding.", "ex": "Arbitration is often used in legal or trade disputes."}, {"term": "compromise", "ipa": "/ˈkɒmprəmaɪz/", "pron": "KOM-pruh-myze", "fr": "compromis", "def": "An agreement in which each side gives up part of what it wants.", "ex": "Diplomacy often depends on compromise."}, {"term": "concession", "ipa": "/kənˈseʃən/", "pron": "kuhn-SESH-uhn", "fr": "concession", "def": "Something given up or granted during negotiation.", "ex": "Both sides made concessions to reach a deal."}, {"term": "deadlock", "ipa": "/ˈdedlɒk/", "pron": "DED-lok", "fr": "impasse", "def": "A situation where no progress is possible because sides cannot agree.", "ex": "Negotiations reached a deadlock."}, {"term": "breakthrough", "ipa": "/ˈbreɪkθruː/", "pron": "BRAYK-throo", "fr": "percée", "def": "A sudden important advance in negotiations.", "ex": "The prisoner exchange marked a diplomatic breakthrough."}, {"term": "stalemate", "ipa": "/ˈsteɪlmeɪt/", "pron": "STAYL-mayt", "fr": "impasse ; blocage", "def": "A situation where neither side can make progress.", "ex": "The talks ended in stalemate."}, {"term": "agreement", "ipa": "/əˈɡriːmənt/", "pron": "uh-GREE-muhnt", "fr": "accord", "def": "A shared decision or arrangement between parties.", "ex": "The agreement included security guarantees."}, {"term": "accord", "ipa": "/əˈkɔːd/", "pron": "uh-KORD", "fr": "accord", "def": "A formal agreement between countries or groups.", "ex": "The peace accord was signed after years of conflict."}, {"term": "treaty", "ipa": "/ˈtriːti/", "pron": "TREE-tee", "fr": "traité", "def": "A formal written agreement between states.", "ex": "The treaty was ratified by parliament."}, {"term": "pact", "ipa": "/pækt/", "pron": "pakt", "fr": "pacte", "def": "A formal agreement between countries or groups.", "ex": "The defence pact strengthened regional security."}, {"term": "deal", "ipa": "/diːl/", "pron": "deel", "fr": "accord", "def": "An agreement, often after negotiation.", "ex": "The trade deal reduced tariffs."}, {"term": "memorandum of understanding", "ipa": "/ˌmeməˈrændəm əv ˌʌndəˈstændɪŋ/", "pron": "mem-uh-RAN-duhm ov un-duh-STAN-ding", "fr": "protocole d’accord", "def": "A written statement of shared intentions, usually less binding than a treaty.", "ex": "The two countries signed a memorandum of understanding."}, {"term": "MOU", "ipa": "/ˌem əʊ ˈjuː/", "pron": "em-oh-yoo", "fr": "protocole d’accord", "def": "Abbreviation for memorandum of understanding.", "ex": "The MOU outlined future cooperation."}, {"term": "ratification", "ipa": "/ˌrætɪfɪˈkeɪʃən/", "pron": "rat-i-fi-KAY-shuhn", "fr": "ratification", "def": "Formal approval of a treaty or agreement.", "ex": "Ratification by parliament was required."}, {"term": "signatory", "ipa": "/ˈsɪɡnətəri/", "pron": "SIG-nuh-tuh-ree", "fr": "signataire", "def": "A state or actor that has signed an agreement.", "ex": "All signatories promised to respect the ceasefire."}, {"term": "clause", "ipa": "/klɔːz/", "pron": "klawz", "fr": "clause", "def": "A specific provision in a legal agreement.", "ex": "The treaty contains a mutual-defence clause."}, {"term": "framework agreement", "ipa": "/ˈfreɪmwɜːk əˌɡriːmənt/", "pron": "FRAYM-work uh-GREE-muhnt", "fr": "accord-cadre", "def": "An agreement setting broad principles for future cooperation.", "ex": "The framework agreement left details for later negotiations."}, {"term": "ceasefire", "ipa": "/ˈsiːsfaɪə/", "pron": "SEESS-fire", "fr": "cessez-le-feu", "def": "An agreement to stop fighting temporarily or permanently.", "ex": "The ceasefire allowed humanitarian aid to enter the area."}, {"term": "truce", "ipa": "/truːs/", "pron": "trooss", "fr": "trêve", "def": "A temporary stop in fighting.", "ex": "The truce was fragile but welcomed by civilians."}, {"term": "armistice", "ipa": "/ˈɑːmɪstɪs/", "pron": "AR-mi-stis", "fr": "armistice", "def": "A formal agreement to stop fighting, often before a peace treaty.", "ex": "The armistice ended active hostilities."}, {"term": "peace agreement", "ipa": "/ˈpiːs əˌɡriːmənt/", "pron": "peace uh-GREE-muhnt", "fr": "accord de paix", "def": "An agreement designed to end a conflict.", "ex": "The peace agreement created a power-sharing system."}, {"term": "peace process", "ipa": "/ˈpiːs ˌprəʊses/", "pron": "peace PROH-ses", "fr": "processus de paix", "def": "A series of negotiations aimed at ending conflict.", "ex": "The peace process remains vulnerable to spoilers."}, {"term": "conflict resolution", "ipa": "/ˈkɒnflɪkt ˌrezəˈluːʃən/", "pron": "KON-flikt rez-uh-LOO-shuhn", "fr": "résolution des conflits", "def": "Methods used to end or reduce conflict.", "ex": "Conflict resolution requires political will."}, {"term": "de-escalation", "ipa": "/ˌdiː eskəˈleɪʃən/", "pron": "dee-es-kuh-LAY-shuhn", "fr": "désescalade", "def": "Reduction of tension or violence.", "ex": "Diplomats called for immediate de-escalation."}, {"term": "escalation", "ipa": "/ˌeskəˈleɪʃən/", "pron": "es-kuh-LAY-shuhn", "fr": "escalade", "def": "An increase in tension, violence or conflict.", "ex": "Military escalation can undermine diplomacy."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "Preventing action by threatening serious consequences.", "ex": "Deterrence can prevent war but also increase tension."}, {"term": "appeasement", "ipa": "/əˈpiːzmənt/", "pron": "uh-PEEZ-muhnt", "fr": "apaisement ; politique de conciliation", "def": "Making concessions to an aggressor to avoid conflict; often used negatively.", "ex": "Critics accused the government of appeasement."}, {"term": "conciliation", "ipa": "/kənˌsɪliˈeɪʃən/", "pron": "kuhn-sil-ee-AY-shuhn", "fr": "conciliation", "def": "Efforts to reduce hostility and restore trust.", "ex": "Conciliation can rebuild communication after a crisis."}, {"term": "reconciliation", "ipa": "/ˌrekənsɪliˈeɪʃən/", "pron": "rek-uhn-sil-ee-AY-shuhn", "fr": "réconciliation", "def": "Restoring friendly relations after conflict.", "ex": "Reconciliation requires truth, justice and time."}, {"term": "normalisation", "ipa": "/ˌnɔːməlaɪˈzeɪʃən/", "pron": "NOR-muh-ly-ZAY-shuhn", "fr": "normalisation", "def": "The process of making relations normal again.", "ex": "Normalisation of relations followed years of hostility."}, {"term": "rapprochement", "ipa": "/ræˈprɒʃmɒ̃/", "pron": "ra-PROSH-mon", "fr": "rapprochement", "def": "An improvement in relations between countries.", "ex": "The summit signalled a rapprochement between former rivals."}, {"term": "recognition", "ipa": "/ˌrekəɡˈnɪʃən/", "pron": "rek-uhg-NISH-uhn", "fr": "reconnaissance", "def": "Official acceptance of a state or government as legitimate.", "ex": "Diplomatic recognition can be highly political."}, {"term": "non-recognition", "ipa": "/ˌnɒn rekəɡˈnɪʃən/", "pron": "non-rek-uhg-NISH-uhn", "fr": "non-reconnaissance", "def": "Refusal to officially recognise a state, government or claim.", "ex": "Non-recognition can isolate a regime."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "A state’s authority to govern itself.", "ex": "Diplomacy must respect national sovereignty."}, {"term": "territorial integrity", "ipa": "/ˌterɪˈtɔːriəl ɪnˈteɡrəti/", "pron": "terr-i-TOR-ee-uhl in-TEG-ruh-tee", "fr": "intégrité territoriale", "def": "The principle that a state’s borders should not be violated.", "ex": "The UN reaffirmed the country’s territorial integrity."}, {"term": "self-determination", "ipa": "/ˌself dɪˌtɜːmɪˈneɪʃən/", "pron": "self di-tur-mi-NAY-shuhn", "fr": "autodétermination", "def": "The right of people to decide their political status.", "ex": "Self-determination can clash with territorial integrity."}, {"term": "national interest", "ipa": "/ˌnæʃənəl ˈɪntrəst/", "pron": "NASH-uh-nuhl IN-truhst", "fr": "intérêt national", "def": "A country’s strategic, economic or political priorities.", "ex": "Governments justify foreign policy through national interest."}]}, {"title": "C. Power, sovereignty, sanctions and diplomatic tools", "entries": [{"term": "strategic interest", "ipa": "/strəˌtiːdʒɪk ˈɪntrəst/", "pron": "struh-TEE-jik IN-truhst", "fr": "intérêt stratégique", "def": "A long-term interest linked to security or power.", "ex": "Energy security is a strategic interest."}, {"term": "sphere of influence", "ipa": "/ˌsfɪər əv ˈɪnfluəns/", "pron": "sfeer ov IN-floo-uhns", "fr": "sphère d’influence", "def": "A region where a powerful state has strong influence.", "ex": "Great powers often try to maintain spheres of influence."}, {"term": "balance of power", "ipa": "/ˌbæləns əv ˈpaʊə/", "pron": "BAL-uhns ov POW-uh", "fr": "équilibre des puissances", "def": "A situation where power is distributed to prevent domination by one actor.", "ex": "The balance of power shaped European diplomacy."}, {"term": "power politics", "ipa": "/ˈpaʊə ˌpɒlətɪks/", "pron": "POW-uh POL-uh-tiks", "fr": "politique de puissance", "def": "International relations based mainly on power and national interest.", "ex": "Power politics often undermines international law."}, {"term": "realpolitik", "ipa": "/reɪˈɑːlpɒlɪtiːk/", "pron": "ray-AL-pol-i-teek", "fr": "realpolitik", "def": "Pragmatic politics based on power rather than ideals.", "ex": "Realpolitik prioritises interests over moral principles."}, {"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "Influence through attraction, culture and values.", "ex": "Cultural diplomacy can strengthen soft power."}, {"term": "hard power", "ipa": "/ˌhɑːd ˈpaʊə/", "pron": "hard POW-uh", "fr": "hard power ; puissance coercitive", "def": "Influence through military or economic pressure.", "ex": "Sanctions and military force are forms of hard power."}, {"term": "smart power", "ipa": "/ˌsmɑːt ˈpaʊə/", "pron": "smart POW-uh", "fr": "smart power ; puissance intelligente", "def": "A strategy combining soft and hard power.", "ex": "Smart power blends persuasion and pressure."}, {"term": "influence", "ipa": "/ˈɪnfluəns/", "pron": "IN-floo-uhns", "fr": "influence", "def": "The ability to affect decisions or behaviour.", "ex": "Diplomacy is a tool of influence."}, {"term": "leverage", "ipa": "/ˈliːvərɪdʒ/", "pron": "LEE-vuh-rij", "fr": "levier ; moyen de pression", "def": "Power or advantage used to influence negotiations.", "ex": "Sanctions gave negotiators leverage."}, {"term": "pressure", "ipa": "/ˈpreʃə/", "pron": "PRESH-uh", "fr": "pression", "def": "Force or persuasion used to influence someone.", "ex": "International pressure forced the regime to negotiate."}, {"term": "coercion", "ipa": "/kəʊˈɜːʃən/", "pron": "koh-UR-shuhn", "fr": "coercition", "def": "Forcing someone to act through threats or pressure.", "ex": "Coercion can backfire if it hardens resistance."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed to change behaviour.", "ex": "Sanctions are often used as a diplomatic tool."}, {"term": "economic sanctions", "ipa": "/ˌiːkəˈnɒmɪk ˈsæŋkʃənz/", "pron": "ee-kuh-NOM-ik SANK-shuhnz", "fr": "sanctions économiques", "def": "Economic restrictions imposed on a state, firm or individual.", "ex": "Economic sanctions can hurt civilians as well as leaders."}, {"term": "targeted sanctions", "ipa": "/ˈtɑːɡɪtɪd ˈsæŋkʃənz/", "pron": "TAR-git-id SANK-shuhnz", "fr": "sanctions ciblées", "def": "Sanctions aimed at specific individuals, firms or sectors.", "ex": "Targeted sanctions may freeze assets and restrict travel."}, {"term": "arms embargo", "ipa": "/ˈɑːmz emˌbɑːɡəʊ/", "pron": "armz em-BAR-goh", "fr": "embargo sur les armes", "def": "A ban on selling or supplying weapons.", "ex": "The UN imposed an arms embargo."}, {"term": "trade embargo", "ipa": "/ˈtreɪd emˌbɑːɡəʊ/", "pron": "trade em-BAR-goh", "fr": "embargo commercial", "def": "A ban or severe restriction on trade with a country.", "ex": "A trade embargo can isolate an economy."}, {"term": "travel ban", "ipa": "/ˈtrævəl bæn/", "pron": "TRAV-uhl ban", "fr": "interdiction de voyager", "def": "A restriction preventing people from travelling.", "ex": "Officials were placed under a travel ban."}, {"term": "asset freeze", "ipa": "/ˈæset friːz/", "pron": "AS-et freez", "fr": "gel des avoirs", "def": "A measure preventing people or entities from using their assets.", "ex": "The sanctions included an asset freeze."}, {"term": "diplomatic pressure", "ipa": "/ˌdɪpləˈmætɪk ˈpreʃə/", "pron": "dip-luh-MAT-ik PRESH-uh", "fr": "pression diplomatique", "def": "Pressure applied through diplomatic channels.", "ex": "Diplomatic pressure increased after the human-rights abuses."}, {"term": "condemnation", "ipa": "/ˌkɒndemˈneɪʃən/", "pron": "kon-dem-NAY-shuhn", "fr": "condamnation", "def": "Public criticism or denunciation.", "ex": "The attack drew international condemnation."}, {"term": "statement", "ipa": "/ˈsteɪtmənt/", "pron": "STATE-muhnt", "fr": "déclaration", "def": "An official public declaration.", "ex": "The foreign ministry released a statement."}, {"term": "joint statement", "ipa": "/ˌdʒɔɪnt ˈsteɪtmənt/", "pron": "joint STATE-muhnt", "fr": "déclaration commune", "def": "A statement issued together by several actors.", "ex": "The allies issued a joint statement."}, {"term": "communiqué", "ipa": "/kəˈmjuːnɪkeɪ/", "pron": "kuh-MYOO-ni-kay", "fr": "communiqué", "def": "An official diplomatic announcement.", "ex": "The summit ended with a final communiqué."}, {"term": "resolution", "ipa": "/ˌrezəˈluːʃən/", "pron": "rez-uh-LOO-shuhn", "fr": "résolution", "def": "A formal decision or statement, especially by an international body.", "ex": "The Security Council adopted a resolution."}, {"term": "veto", "ipa": "/ˈviːtəʊ/", "pron": "VEE-toh", "fr": "veto", "def": "The power to block a decision.", "ex": "A permanent member used its veto."}, {"term": "abstention", "ipa": "/əbˈstenʃən/", "pron": "uhb-STEN-shuhn", "fr": "abstention", "def": "Choosing not to vote for or against.", "ex": "Several states chose abstention during the vote."}, {"term": "international law", "ipa": "/ˌɪntəˈnæʃənəl lɔː/", "pron": "IN-tuh-NASH-uh-nuhl law", "fr": "droit international", "def": "Rules governing relations between states and international actors.", "ex": "International law prohibits aggression."}, {"term": "treaty law", "ipa": "/ˈtriːti lɔː/", "pron": "TREE-tee law", "fr": "droit des traités", "def": "International law based on treaties.", "ex": "Treaty law depends on consent and ratification."}, {"term": "customary international law", "ipa": "/ˌkʌstəməri ˌɪntəˈnæʃənəl lɔː/", "pron": "KUS-tuh-muh-ree IN-tuh-NASH-uh-nuhl law", "fr": "droit international coutumier", "def": "International law based on consistent state practice and legal belief.", "ex": "Customary international law can bind states even without a treaty."}, {"term": "rule-based order", "ipa": "/ˌruːl beɪst ˈɔːdə/", "pron": "rool-bayst OR-duh", "fr": "ordre fondé sur des règles", "def": "An international system governed by rules rather than brute force.", "ex": "Diplomats defended the rules-based order."}, {"term": "United Nations", "ipa": "/juːˌnaɪtɪd ˈneɪʃənz/", "pron": "yoo-NY-tid NAY-shuhnz", "fr": "Organisation des Nations unies", "def": "An international organisation created to promote peace, security and cooperation.", "ex": "The United Nations provides a forum for diplomacy."}, {"term": "UN", "ipa": "/ˌjuː ˈen/", "pron": "yoo-en", "fr": "ONU", "def": "Abbreviation for United Nations.", "ex": "The UN called for restraint."}, {"term": "Security Council", "ipa": "/sɪˈkjʊərəti ˈkaʊnsəl/", "pron": "si-KYOOR-uh-tee KOWN-suhl", "fr": "Conseil de sécurité", "def": "The UN body responsible for international peace and security.", "ex": "The Security Council debated sanctions."}, {"term": "General Assembly", "ipa": "/ˌdʒenərəl əˈsembli/", "pron": "JEN-uh-ruhl uh-SEM-blee", "fr": "Assemblée générale", "def": "The UN body where all member states are represented.", "ex": "The General Assembly passed a non-binding resolution."}, {"term": "NATO", "ipa": "/ˈneɪtəʊ/", "pron": "NAY-toh", "fr": "OTAN", "def": "A military alliance between North American and European states.", "ex": "NATO combines deterrence with diplomatic consultation."}, {"term": "European Union", "ipa": "/ˌjʊərəpiːən ˈjuːniən/", "pron": "YOOR-uh-pee-uhn YOO-nee-uhn", "fr": "Union européenne", "def": "A political and economic union of European countries.", "ex": "The European Union uses diplomacy, trade and sanctions."}, {"term": "African Union", "ipa": "/ˌæfrɪkən ˈjuːniən/", "pron": "AF-ri-kuhn YOO-nee-uhn", "fr": "Union africaine", "def": "A continental organisation of African states.", "ex": "The African Union supports regional mediation."}, {"term": "G7", "ipa": "/ˌdʒiː ˈsevən/", "pron": "jee-SEV-uhn", "fr": "G7", "def": "A group of major advanced economies.", "ex": "The G7 coordinated sanctions."}, {"term": "G20", "ipa": "/ˌdʒiː ˈtwenti/", "pron": "jee-TWEN-tee", "fr": "G20", "def": "A group of major advanced and emerging economies.", "ex": "The G20 discusses global economic governance."}, {"term": "international organisation", "ipa": "/ˌɪntəˈnæʃənəl ˌɔːɡənaɪˈzeɪʃən/", "pron": "IN-tuh-NASH-uh-nuhl OR-guh-ny-ZAY-shuhn", "fr": "organisation internationale", "def": "An organisation whose members are states or international actors.", "ex": "International organisations provide platforms for cooperation."}, {"term": "multilateralism", "ipa": "/ˌmʌltiˈlætərəlɪzəm/", "pron": "MUL-tee-LAT-uh-ruhl-iz-uhm", "fr": "multilatéralisme", "def": "Cooperation between several countries through institutions and rules.", "ex": "Multilateralism is under pressure from nationalism."}, {"term": "unilateralism", "ipa": "/ˌjuːnɪˈlætərəlɪzəm/", "pron": "yoo-ni-LAT-uh-ruhl-iz-uhm", "fr": "unilatéralisme", "def": "Acting alone without broad international agreement.", "ex": "Unilateralism can weaken alliances."}, {"term": "alliance", "ipa": "/əˈlaɪəns/", "pron": "uh-LY-uhns", "fr": "alliance", "def": "A formal relationship between states for cooperation or defence.", "ex": "The alliance was strengthened after the crisis."}, {"term": "ally", "ipa": "/ˈælaɪ/", "pron": "AL-eye", "fr": "allié", "def": "A state or actor that cooperates with another, often for security.", "ex": "Allies coordinated their diplomatic response."}, {"term": "partner", "ipa": "/ˈpɑːtnə/", "pron": "PART-nuh", "fr": "partenaire", "def": "A country or actor cooperating with another.", "ex": "The country is a key regional partner."}, {"term": "rival", "ipa": "/ˈraɪvəl/", "pron": "RY-vuhl", "fr": "rival", "def": "A competing state or actor.", "ex": "Diplomacy between rivals requires caution."}]}, {"title": "D. International organisations, alliances and diplomatic crises", "entries": [{"term": "adversary", "ipa": "/ˈædvəsəri/", "pron": "AD-vuh-suh-ree", "fr": "adversaire", "def": "An opponent or hostile actor.", "ex": "Negotiating with an adversary is difficult but sometimes necessary."}, {"term": "hostile state", "ipa": "/ˌhɒstaɪl ˈsteɪt/", "pron": "HOS-tyle state", "fr": "État hostile", "def": "A state considered unfriendly or threatening.", "ex": "Diplomacy can reduce risks with a hostile state."}, {"term": "friendly state", "ipa": "/ˌfrendli ˈsteɪt/", "pron": "FREND-lee state", "fr": "État ami", "def": "A state with good relations with another.", "ex": "Friendly states often coordinate votes."}, {"term": "strategic partner", "ipa": "/strəˌtiːdʒɪk ˈpɑːtnə/", "pron": "struh-TEE-jik PART-nuh", "fr": "partenaire stratégique", "def": "A partner important for long-term security or economic goals.", "ex": "India is often described as a strategic partner."}, {"term": "diplomatic crisis", "ipa": "/ˌdɪpləˈmætɪk ˈkraɪsɪs/", "pron": "dip-luh-MAT-ik KRY-sis", "fr": "crise diplomatique", "def": "A serious breakdown or tension in diplomatic relations.", "ex": "The incident triggered a diplomatic crisis."}, {"term": "diplomatic row", "ipa": "/ˌdɪpləˈmætɪk raʊ/", "pron": "dip-luh-MAT-ik row", "fr": "querelle diplomatique", "def": "A public diplomatic dispute.", "ex": "The spying allegations caused a diplomatic row."}, {"term": "dispute", "ipa": "/dɪˈspjuːt/", "pron": "di-SPYOOT", "fr": "différend ; litige", "def": "A disagreement or conflict.", "ex": "The border dispute lasted for decades."}, {"term": "border dispute", "ipa": "/ˈbɔːdə dɪˌspjuːt/", "pron": "BOR-duh di-SPYOOT", "fr": "différend frontalier", "def": "A disagreement over borders or territory.", "ex": "The border dispute required mediation."}, {"term": "territorial dispute", "ipa": "/ˌterɪˈtɔːriəl dɪˌspjuːt/", "pron": "terr-i-TOR-ee-uhl di-SPYOOT", "fr": "différend territorial", "def": "A disagreement over land or territory.", "ex": "Territorial disputes can become military conflicts."}, {"term": "crisis management", "ipa": "/ˈkraɪsɪs ˌmænɪdʒmənt/", "pron": "KRY-sis MAN-ij-muhnt", "fr": "gestion de crise", "def": "Actions taken to handle and reduce a crisis.", "ex": "Crisis management depends on communication."}, {"term": "hotline", "ipa": "/ˈhɒtlaɪn/", "pron": "HOT-line", "fr": "ligne directe", "def": "A direct communication line between governments or leaders during crises.", "ex": "A hotline can prevent misunderstandings."}, {"term": "diplomatic channel", "ipa": "/ˌdɪpləˈmætɪk ˈtʃænəl/", "pron": "dip-luh-MAT-ik CHAN-uhl", "fr": "canal diplomatique", "def": "A route or method for official diplomatic communication.", "ex": "Messages were sent through diplomatic channels."}, {"term": "breakdown in relations", "ipa": "/ˈbreɪkdaʊn ɪn rɪˈleɪʃənz/", "pron": "BRAYK-down in ri-LAY-shuhnz", "fr": "rupture des relations", "def": "A serious deterioration or collapse of relations.", "ex": "The scandal led to a breakdown in relations."}, {"term": "severing of ties", "ipa": "/ˈsevərɪŋ əv taɪz/", "pron": "SEV-uh-ring ov tyz", "fr": "rupture des liens", "def": "The act of cutting official relations.", "ex": "The severing of ties followed the attack."}, {"term": "expulsion", "ipa": "/ɪkˈspʌlʃən/", "pron": "ik-SPUL-shuhn", "fr": "expulsion", "def": "The removal of a diplomat or foreign representative from a country.", "ex": "The expulsion of diplomats worsened the crisis."}, {"term": "recall an ambassador", "ipa": "/rɪˈkɔːl ən æmˈbæsədə/", "pron": "ri-KAWL an am-BAS-uh-duh", "fr": "rappeler un ambassadeur", "def": "To call an ambassador back home as a diplomatic signal.", "ex": "The government recalled its ambassador for consultations."}, {"term": "summon an ambassador", "ipa": "/ˈsʌmən ən æmˈbæsədə/", "pron": "SUM-uhn an am-BAS-uh-duh", "fr": "convoquer un ambassadeur", "def": "To call an ambassador to a meeting, usually to protest.", "ex": "The foreign ministry summoned the ambassador."}, {"term": "to negotiate", "ipa": "/nɪˈɡəʊʃieɪt/", "pron": "ni-GOH-shee-ayt", "fr": "négocier", "def": "To discuss in order to reach an agreement.", "ex": "Both sides agreed to negotiate."}, {"term": "to mediate", "ipa": "/ˈmiːdieɪt/", "pron": "MEE-dee-ayt", "fr": "servir de médiateur", "def": "To help parties resolve a dispute as a neutral actor.", "ex": "The country offered to mediate."}, {"term": "to broker a deal", "ipa": "/ˈbrəʊkər ə diːl/", "pron": "BROH-kuh uh deel", "fr": "négocier / faciliter un accord", "def": "To help others reach an agreement.", "ex": "Diplomats brokered a deal after weeks of talks."}, {"term": "to reach an agreement", "ipa": "/riːtʃ ən əˈɡriːmənt/", "pron": "reech an uh-GREE-muhnt", "fr": "parvenir à un accord", "def": "To arrive at a shared decision or settlement.", "ex": "The parties finally reached an agreement."}, {"term": "to sign a treaty", "ipa": "/saɪn ə ˈtriːti/", "pron": "syne uh TREE-tee", "fr": "signer un traité", "def": "To formally approve a treaty by signing it.", "ex": "The leaders signed a treaty on security cooperation."}, {"term": "to ratify a treaty", "ipa": "/ˈrætɪfaɪ ə ˈtriːti/", "pron": "RAT-i-fy uh TREE-tee", "fr": "ratifier un traité", "def": "To formally approve a treaty according to legal procedure.", "ex": "Parliament must ratify the treaty."}, {"term": "to restore relations", "ipa": "/rɪˈstɔː rɪˈleɪʃənz/", "pron": "ri-STORE ri-LAY-shuhnz", "fr": "rétablir les relations", "def": "To rebuild official relations after a breakdown.", "ex": "The two states restored relations after the crisis."}, {"term": "to normalise relations", "ipa": "/ˈnɔːməlaɪz rɪˈleɪʃənz/", "pron": "NOR-muh-lyze ri-LAY-shuhnz", "fr": "normaliser les relations", "def": "To make relations normal again.", "ex": "The countries agreed to normalise relations."}, {"term": "to ease tensions", "ipa": "/iːz ˈtenʃənz/", "pron": "eez TEN-shuhnz", "fr": "apaiser les tensions", "def": "To reduce hostility or pressure.", "ex": "Diplomacy aims to ease tensions."}, {"term": "to de-escalate a crisis", "ipa": "/ˌdiː ˈeskəleɪt ə ˈkraɪsɪs/", "pron": "dee-ES-kuh-layt uh KRY-sis", "fr": "désamorcer / désescalader une crise", "def": "To reduce the intensity of a crisis.", "ex": "A hotline helped de-escalate the crisis."}, {"term": "to impose sanctions", "ipa": "/ɪmˈpəʊz ˈsæŋkʃənz/", "pron": "im-POHZ SANK-shuhnz", "fr": "imposer des sanctions", "def": "To officially apply penalties or restrictions.", "ex": "The EU imposed sanctions on officials."}, {"term": "to lift sanctions", "ipa": "/lɪft ˈsæŋkʃənz/", "pron": "lift SANK-shuhnz", "fr": "lever des sanctions", "def": "To remove sanctions.", "ex": "Sanctions were lifted after compliance."}, {"term": "to condemn an action", "ipa": "/kənˈdem ən ˈækʃən/", "pron": "kuhn-DEM an AK-shuhn", "fr": "condamner une action", "def": "To publicly criticise an action as wrong.", "ex": "Many governments condemned the attack."}, {"term": "to call for restraint", "ipa": "/kɔːl fə rɪˈstreɪnt/", "pron": "call for ri-STRAINT", "fr": "appeler à la retenue", "def": "To ask parties to avoid escalation.", "ex": "The UN called for restraint."}, {"term": "to seek a diplomatic solution", "ipa": "/siːk ə ˌdɪpləˈmætɪk səˈluːʃən/", "pron": "seek uh dip-luh-MAT-ik suh-LOO-shuhn", "fr": "chercher une solution diplomatique", "def": "To try to solve a problem through diplomacy.", "ex": "Leaders said they wanted to seek a diplomatic solution."}, {"term": "to keep communication channels open", "ipa": "/kiːp kəˌmjuːnɪˈkeɪʃən ˈtʃænəlz ˈəʊpən/", "pron": "keep kuh-myoo-ni-KAY-shuhn CHAN-uhlz OH-puhn", "fr": "maintenir les canaux de communication ouverts", "def": "To maintain dialogue even during tension.", "ex": "Even rivals should keep communication channels open."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p6c51", "part": 6, "chapter": 51, "title": "War And Conflict", "file": "cpge_vocab_part6_chapter51_war_and_conflict_premium.html", "count": 185, "sections": [{"title": "A. Types of war and conflict", "entries": [{"term": "war", "ipa": "/wɔː/", "pron": "war", "fr": "guerre", "def": "Armed conflict between states, groups or political communities.", "ex": "War causes destruction, displacement and long-term political instability."}, {"term": "conflict", "ipa": "/ˈkɒnflɪkt/", "pron": "KON-flikt", "fr": "conflit", "def": "A serious disagreement or struggle, often involving violence.", "ex": "Conflict can be local, regional or international."}, {"term": "armed conflict", "ipa": "/ˌɑːmd ˈkɒnflɪkt/", "pron": "armd KON-flikt", "fr": "conflit armé", "def": "A conflict involving organised violence and weapons.", "ex": "Armed conflict often creates humanitarian crises."}, {"term": "civil war", "ipa": "/ˌsɪvəl ˈwɔː/", "pron": "SIV-uhl war", "fr": "guerre civile", "def": "A war between groups within the same country.", "ex": "Civil war can tear societies apart for generations."}, {"term": "interstate war", "ipa": "/ˌɪntəsteɪt ˈwɔː/", "pron": "IN-tuh-state war", "fr": "guerre interétatique", "def": "A war between two or more states.", "ex": "Interstate war has become less common than internal conflict."}, {"term": "proxy war", "ipa": "/ˈprɒksi wɔː/", "pron": "PROK-see war", "fr": "guerre par procuration", "def": "A conflict in which outside powers support opposing sides without fighting directly.", "ex": "The Cold War involved many proxy wars."}, {"term": "hybrid war", "ipa": "/ˌhaɪbrɪd ˈwɔː/", "pron": "HY-brid war", "fr": "guerre hybride", "def": "Conflict combining conventional force, cyberattacks, disinformation and political pressure.", "ex": "Hybrid war blurs the line between peace and war."}, {"term": "total war", "ipa": "/ˌtəʊtəl ˈwɔː/", "pron": "TOH-tuhl war", "fr": "guerre totale", "def": "War involving the full mobilisation of society and economy.", "ex": "The Second World War is often described as total war."}, {"term": "limited war", "ipa": "/ˌlɪmɪtɪd ˈwɔː/", "pron": "LIM-i-tid war", "fr": "guerre limitée", "def": "War fought with limited aims, weapons or geographical scope.", "ex": "A limited war can still cause major destruction."}, {"term": "asymmetric warfare", "ipa": "/ˌeɪsɪˈmetrɪk ˈwɔːfeə/", "pron": "ay-si-MET-rik WAR-fair", "fr": "guerre asymétrique", "def": "Conflict between actors with very unequal military power.", "ex": "Guerrilla tactics are common in asymmetric warfare."}, {"term": "conventional warfare", "ipa": "/kənˌvenʃənəl ˈwɔːfeə/", "pron": "kuhn-VEN-shuh-nuhl WAR-fair", "fr": "guerre conventionnelle", "def": "War using traditional military forces and weapons.", "ex": "Conventional warfare involves armies, tanks and aircraft."}, {"term": "unconventional warfare", "ipa": "/ˌʌnkənˌvenʃənəl ˈwɔːfeə/", "pron": "un-kuhn-VEN-shuh-nuhl WAR-fair", "fr": "guerre non conventionnelle", "def": "Warfare using irregular tactics such as sabotage or guerrilla operations.", "ex": "Unconventional warfare can be difficult to counter."}, {"term": "guerrilla warfare", "ipa": "/ɡəˈrɪlə ˈwɔːfeə/", "pron": "guh-RIL-uh WAR-fair", "fr": "guérilla", "def": "Irregular warfare using small mobile groups and surprise attacks.", "ex": "Guerrilla warfare often relies on local support."}, {"term": "insurgency", "ipa": "/ɪnˈsɜːdʒənsi/", "pron": "in-SUR-juhn-see", "fr": "insurrection", "def": "An organised rebellion against a government or occupying power.", "ex": "An insurgency can last for years if grievances remain unresolved."}, {"term": "counterinsurgency", "ipa": "/ˌkaʊntərɪnˈsɜːdʒənsi/", "pron": "KOWN-tuh-rin-SUR-juhn-see", "fr": "contre-insurrection", "def": "Military and political action against an insurgency.", "ex": "Counterinsurgency requires security and political legitimacy."}, {"term": "rebellion", "ipa": "/rɪˈbeljən/", "pron": "ri-BEL-yuhn", "fr": "rébellion", "def": "An organised attempt to resist or overthrow authority.", "ex": "The rebellion began in the northern provinces."}, {"term": "uprising", "ipa": "/ˈʌpraɪzɪŋ/", "pron": "UP-ry-zing", "fr": "soulèvement", "def": "A revolt or rebellion against authority.", "ex": "The uprising was violently suppressed."}, {"term": "coup", "ipa": "/kuː/", "pron": "koo", "fr": "coup d’État", "def": "A sudden illegal seizure of power, usually by the military or political elites.", "ex": "The coup triggered international condemnation."}, {"term": "military junta", "ipa": "/ˌmɪlɪtəri ˈdʒʌntə/", "pron": "MIL-i-tuh-ree JUN-tuh", "fr": "junte militaire", "def": "A government led by military leaders after a coup.", "ex": "The military junta imposed martial law."}, {"term": "occupation", "ipa": "/ˌɒkjʊˈpeɪʃən/", "pron": "ok-yuh-PAY-shuhn", "fr": "occupation", "def": "Control of a territory by a foreign army.", "ex": "Military occupation often leads to resistance."}, {"term": "invasion", "ipa": "/ɪnˈveɪʒən/", "pron": "in-VAY-zhuhn", "fr": "invasion", "def": "The entry of armed forces into another country by force.", "ex": "The invasion violated international law."}, {"term": "annexation", "ipa": "/ˌænekˈseɪʃən/", "pron": "an-ek-SAY-shuhn", "fr": "annexion", "def": "The forcible or legal incorporation of territory into another state.", "ex": "The annexation was not recognised internationally."}, {"term": "territorial conquest", "ipa": "/ˌterɪˈtɔːriəl ˈkɒŋkwest/", "pron": "terr-i-TOR-ee-uhl KON-kwest", "fr": "conquête territoriale", "def": "The acquisition of territory by military force.", "ex": "Territorial conquest undermines the rules-based order."}, {"term": "border clash", "ipa": "/ˈbɔːdə klæʃ/", "pron": "BOR-duh clash", "fr": "affrontement frontalier", "def": "A violent incident between forces near a border.", "ex": "A border clash can escalate quickly."}, {"term": "skirmish", "ipa": "/ˈskɜːmɪʃ/", "pron": "SKUR-mish", "fr": "escarmouche", "def": "A small or brief fight between armed groups.", "ex": "The skirmish raised fears of wider war."}, {"term": "battle", "ipa": "/ˈbætəl/", "pron": "BAT-uhl", "fr": "bataille", "def": "A major fight between armed forces.", "ex": "The battle caused heavy casualties."}, {"term": "siege", "ipa": "/siːdʒ/", "pron": "seej", "fr": "siège", "def": "A military operation surrounding a place to force surrender.", "ex": "The siege created severe shortages."}, {"term": "front line", "ipa": "/ˌfrʌnt ˈlaɪn/", "pron": "front line", "fr": "ligne de front", "def": "The area where opposing forces face each other.", "ex": "Civilians living near the front line are at great risk."}, {"term": "battlefield", "ipa": "/ˈbætəlfiːld/", "pron": "BAT-uhl-feeld", "fr": "champ de bataille", "def": "The area where fighting takes place.", "ex": "Modern battlefields include drones and cyber operations."}, {"term": "theatre of war", "ipa": "/ˌθɪətər əv ˈwɔː/", "pron": "THEE-uh-tuh ov war", "fr": "théâtre d’opérations", "def": "A geographical area where military operations take place.", "ex": "The conflict opened a new theatre of war."}, {"term": "combat", "ipa": "/ˈkɒmbæt/", "pron": "KOM-bat", "fr": "combat", "def": "Fighting between armed forces.", "ex": "Combat operations continued overnight."}, {"term": "hostilities", "ipa": "/hɒˈstɪlətiz/", "pron": "hos-TIL-uh-teez", "fr": "hostilités", "def": "Acts of warfare or fighting.", "ex": "The ceasefire ended active hostilities."}, {"term": "military operation", "ipa": "/ˌmɪlɪtəri ˌɒpəˈreɪʃən/", "pron": "MIL-i-tuh-ree op-uh-RAY-shuhn", "fr": "opération militaire", "def": "A planned action by armed forces.", "ex": "The military operation targeted strategic infrastructure."}, {"term": "offensive", "ipa": "/əˈfensɪv/", "pron": "uh-FEN-siv", "fr": "offensive", "def": "A military attack or campaign intended to gain ground.", "ex": "The army launched a major offensive."}, {"term": "counteroffensive", "ipa": "/ˌkaʊntərəˈfensɪv/", "pron": "KOWN-tuh-ruh-FEN-siv", "fr": "contre-offensive", "def": "An attack launched in response to an enemy offensive.", "ex": "The counteroffensive aimed to retake lost territory."}, {"term": "retreat", "ipa": "/rɪˈtriːt/", "pron": "ri-TREET", "fr": "retraite ; repli", "def": "Withdrawal of forces from a position.", "ex": "The army was forced into retreat."}]}, {"title": "B. Armed forces, strategy and military tools", "entries": [{"term": "withdrawal", "ipa": "/wɪðˈdrɔːəl/", "pron": "with-DRAW-uhl", "fr": "retrait", "def": "The removal of troops from an area.", "ex": "The withdrawal of troops was part of the agreement."}, {"term": "deployment", "ipa": "/dɪˈplɔɪmənt/", "pron": "di-PLOY-muhnt", "fr": "déploiement", "def": "The movement of troops or equipment into position.", "ex": "The deployment of troops alarmed neighbouring states."}, {"term": "mobilisation", "ipa": "/ˌməʊbɪlaɪˈzeɪʃən/", "pron": "moh-bi-ly-ZAY-shuhn", "fr": "mobilisation", "def": "Preparing and organising troops or resources for war.", "ex": "Mass mobilisation changed the scale of the war."}, {"term": "conscription", "ipa": "/kənˈskrɪpʃən/", "pron": "kuhn-SKRIP-shuhn", "fr": "conscription ; service militaire obligatoire", "def": "Compulsory military service.", "ex": "Conscription is controversial in democratic societies."}, {"term": "draft", "ipa": "/drɑːft/", "pron": "draft", "fr": "conscription", "def": "US term for compulsory military recruitment.", "ex": "The draft sparked protests."}, {"term": "reservist", "ipa": "/rɪˈzɜːvɪst/", "pron": "ri-ZUR-vist", "fr": "réserviste", "def": "A member of reserve military forces who can be called up.", "ex": "Reservists were called up after the invasion."}, {"term": "troops", "ipa": "/truːps/", "pron": "troops", "fr": "troupes", "def": "Soldiers or military forces.", "ex": "More troops were sent to the border."}, {"term": "armed forces", "ipa": "/ˌɑːmd ˈfɔːsɪz/", "pron": "armd FOR-siz", "fr": "forces armées", "def": "A country’s military organisations.", "ex": "The armed forces were placed on high alert."}, {"term": "army", "ipa": "/ˈɑːmi/", "pron": "AR-mee", "fr": "armée de terre", "def": "The land branch of the armed forces.", "ex": "The army advanced towards the capital."}, {"term": "navy", "ipa": "/ˈneɪvi/", "pron": "NAY-vee", "fr": "marine", "def": "The branch of the armed forces operating at sea.", "ex": "The navy secured the shipping lanes."}, {"term": "air force", "ipa": "/ˈeə fɔːs/", "pron": "air force", "fr": "armée de l’air", "def": "The branch of the armed forces operating aircraft.", "ex": "The air force carried out strikes."}, {"term": "militia", "ipa": "/məˈlɪʃə/", "pron": "muh-LISH-uh", "fr": "milice", "def": "An armed group that is not always part of the official army.", "ex": "Local militias controlled several checkpoints."}, {"term": "paramilitary group", "ipa": "/ˌpærəˈmɪlɪtəri ɡruːp/", "pron": "par-uh-MIL-i-tuh-ree group", "fr": "groupe paramilitaire", "def": "An armed group organised like a military force but not part of regular armed forces.", "ex": "Paramilitary groups were accused of abuses."}, {"term": "mercenary", "ipa": "/ˈmɜːsənəri/", "pron": "MUR-suh-nuh-ree", "fr": "mercenaire", "def": "A soldier hired to fight for money rather than national service.", "ex": "The use of mercenaries complicates accountability."}, {"term": "private military company", "ipa": "/ˌpraɪvət ˈmɪlɪtəri ˈkʌmpəni/", "pron": "PRY-vuht MIL-i-tuh-ree KUM-puh-nee", "fr": "société militaire privée", "def": "A private company providing military or security services.", "ex": "Private military companies operate in several conflicts."}, {"term": "commander", "ipa": "/kəˈmɑːndə/", "pron": "kuh-MAN-duh", "fr": "commandant", "def": "An officer in charge of military forces.", "ex": "The commander ordered a withdrawal."}, {"term": "chain of command", "ipa": "/ˌtʃeɪn əv kəˈmɑːnd/", "pron": "chayn ov kuh-MAND", "fr": "chaîne de commandement", "def": "The hierarchy through which military orders pass.", "ex": "Violations can occur when the chain of command breaks down."}, {"term": "rules of engagement", "ipa": "/ˌruːlz əv ɪnˈɡeɪdʒmənt/", "pron": "roolz ov in-GAYJ-muhnt", "fr": "règles d’engagement", "def": "Rules defining when and how force may be used.", "ex": "Rules of engagement are meant to limit harm to civilians."}, {"term": "strategy", "ipa": "/ˈstrætədʒi/", "pron": "STRAT-uh-jee", "fr": "stratégie", "def": "A long-term plan to achieve military or political goals.", "ex": "Military strategy must serve political objectives."}, {"term": "tactics", "ipa": "/ˈtæktɪks/", "pron": "TAK-tiks", "fr": "tactique", "def": "Methods used to achieve immediate military goals.", "ex": "Urban warfare requires different tactics."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "Preventing attack by threatening retaliation.", "ex": "Nuclear deterrence shaped the Cold War."}, {"term": "defence", "ipa": "/dɪˈfens/", "pron": "di-FENS", "fr": "défense", "def": "Protection against attack.", "ex": "Defence spending rose after the invasion."}, {"term": "self-defence", "ipa": "/ˌself dɪˈfens/", "pron": "self di-FENS", "fr": "légitime défense", "def": "The use of force to protect oneself or one’s country from attack.", "ex": "The country invoked its right to self-defence."}, {"term": "collective defence", "ipa": "/kəˌlektɪv dɪˈfens/", "pron": "kuh-LEK-tiv di-FENS", "fr": "défense collective", "def": "Defence by allies in response to an attack on one member.", "ex": "NATO is based on collective defence."}, {"term": "security guarantee", "ipa": "/sɪˈkjʊərəti ˌɡærənˈtiː/", "pron": "si-KYOOR-uh-tee gar-uhn-TEE", "fr": "garantie de sécurité", "def": "A promise to protect another state’s security.", "ex": "Security guarantees were central to the negotiations."}, {"term": "military aid", "ipa": "/ˌmɪlɪtəri ˈeɪd/", "pron": "MIL-i-tuh-ree aid", "fr": "aide militaire", "def": "Weapons, training or support provided to armed forces.", "ex": "Military aid changed the balance on the battlefield."}, {"term": "lethal aid", "ipa": "/ˌliːθəl ˈeɪd/", "pron": "LEE-thuhl aid", "fr": "aide létale", "def": "Military assistance including weapons capable of killing.", "ex": "Lethal aid was controversial at the beginning of the conflict."}, {"term": "non-lethal aid", "ipa": "/ˌnɒn ˈliːθəl ˈeɪd/", "pron": "non-LEE-thuhl aid", "fr": "aide non létale", "def": "Military support that does not directly kill, such as helmets or medical supplies.", "ex": "Non-lethal aid included protective equipment."}, {"term": "arms delivery", "ipa": "/ˈɑːmz dɪˌlɪvəri/", "pron": "armz di-LIV-uh-ree", "fr": "livraison d’armes", "def": "The supply of weapons to a country or group.", "ex": "Arms deliveries intensified the diplomatic dispute."}, {"term": "arms embargo", "ipa": "/ˈɑːmz emˌbɑːɡəʊ/", "pron": "armz em-BAR-goh", "fr": "embargo sur les armes", "def": "A ban on selling or supplying weapons.", "ex": "The UN imposed an arms embargo."}, {"term": "arms race", "ipa": "/ˈɑːmz reɪs/", "pron": "armz race", "fr": "course aux armements", "def": "Competition between states to build up weapons.", "ex": "An arms race can increase insecurity."}, {"term": "arms control", "ipa": "/ˈɑːmz kənˌtrəʊl/", "pron": "armz kuhn-TROHL", "fr": "maîtrise des armements", "def": "Agreements limiting weapons or military capabilities.", "ex": "Arms control can reduce the risk of war."}, {"term": "disarmament", "ipa": "/dɪsˈɑːməmənt/", "pron": "dis-AR-muh-muhnt", "fr": "désarmement", "def": "Reduction or elimination of weapons.", "ex": "Nuclear disarmament remains a major diplomatic goal."}, {"term": "nuclear weapon", "ipa": "/ˌnjuːkliə ˈwepən/", "pron": "NYOO-klee-uh WEP-uhn", "fr": "arme nucléaire", "def": "A weapon using nuclear energy to cause massive destruction.", "ex": "Nuclear weapons create extreme deterrence and risk."}, {"term": "nuclear deterrence", "ipa": "/ˌnjuːkliə dɪˈterəns/", "pron": "NYOO-klee-uh di-TERR-uhns", "fr": "dissuasion nucléaire", "def": "Deterrence based on the threat of nuclear retaliation.", "ex": "Nuclear deterrence relies on credibility."}, {"term": "weapon of mass destruction", "ipa": "/ˌwepən əv mæs dɪˈstrʌkʃən/", "pron": "WEP-uhn ov mass di-STRUK-shuhn", "fr": "arme de destruction massive", "def": "A nuclear, chemical or biological weapon capable of mass harm.", "ex": "Weapons of mass destruction are heavily regulated."}, {"term": "WMD", "ipa": "/ˌdʌbəljuː em ˈdiː/", "pron": "double-yoo-em-dee", "fr": "ADM", "def": "Abbreviation for weapon of mass destruction.", "ex": "The accusation involved alleged WMD programmes."}, {"term": "missile", "ipa": "/ˈmɪsaɪl/", "pron": "MISS-ile", "fr": "missile", "def": "A self-propelled weapon launched at a target.", "ex": "Missile strikes hit critical infrastructure."}, {"term": "drone", "ipa": "/drəʊn/", "pron": "drohn", "fr": "drone", "def": "An unmanned aircraft or vehicle.", "ex": "Drones have transformed modern warfare."}, {"term": "air strike", "ipa": "/ˈeə straɪk/", "pron": "air strike", "fr": "frappe aérienne", "def": "An attack carried out by aircraft.", "ex": "The air strike caused civilian casualties."}, {"term": "shelling", "ipa": "/ˈʃelɪŋ/", "pron": "SHEL-ing", "fr": "bombardement d’artillerie", "def": "Bombardment with artillery shells.", "ex": "Shelling damaged hospitals and schools."}, {"term": "bombardment", "ipa": "/bɒmˈbɑːdmənt/", "pron": "bom-BARD-muhnt", "fr": "bombardement", "def": "Sustained attack with bombs or artillery.", "ex": "The bombardment forced residents to flee."}, {"term": "landmine", "ipa": "/ˈlændmaɪn/", "pron": "LAND-myne", "fr": "mine terrestre", "def": "An explosive hidden in or on the ground.", "ex": "Landmines remain dangerous long after war ends."}, {"term": "cluster munition", "ipa": "/ˌklʌstə mjuːˈnɪʃən/", "pron": "KLUS-tuh myoo-NISH-uhn", "fr": "munition à fragmentation", "def": "A weapon that releases many smaller explosive bomblets.", "ex": "Cluster munitions pose long-term risks to civilians."}, {"term": "chemical weapon", "ipa": "/ˌkemɪkəl ˈwepən/", "pron": "KEM-i-kuhl WEP-uhn", "fr": "arme chimique", "def": "A weapon using toxic chemicals.", "ex": "The use of chemical weapons is banned."}, {"term": "biological weapon", "ipa": "/ˌbaɪəˈlɒdʒɪkəl ˈwepən/", "pron": "by-oh-LOJ-i-kuhl WEP-uhn", "fr": "arme biologique", "def": "A weapon using disease-causing organisms or toxins.", "ex": "Biological weapons are prohibited under international law."}, {"term": "cyber warfare", "ipa": "/ˌsaɪbə ˈwɔːfeə/", "pron": "SY-buh WAR-fair", "fr": "cyberguerre", "def": "Use of cyberattacks as part of conflict.", "ex": "Cyber warfare can target infrastructure and communications."}, {"term": "cyberattack", "ipa": "/ˈsaɪbərətæk/", "pron": "SY-buh-uh-tak", "fr": "cyberattaque", "def": "An attack on computer systems or networks.", "ex": "The cyberattack disrupted government websites."}]}, {"title": "C. Weapons, hybrid warfare and information warfare", "entries": [{"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WAR-fair", "fr": "guerre de l’information", "def": "Use of information, propaganda and disinformation to influence conflict.", "ex": "Information warfare targets public opinion."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Biased information used to influence people politically.", "ex": "Propaganda can justify violence."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately.", "ex": "Disinformation can undermine trust during war."}, {"term": "civilian", "ipa": "/səˈvɪliən/", "pron": "suh-VIL-yuhn", "fr": "civil", "def": "A person who is not a member of the armed forces.", "ex": "Civilians must be protected under international law."}, {"term": "civilian casualties", "ipa": "/səˌvɪliən ˈkæʒuəltiz/", "pron": "suh-VIL-yuhn KAZH-oo-uhl-teez", "fr": "victimes civiles", "def": "Civilian deaths or injuries caused by conflict.", "ex": "Civilian casualties increased after urban bombardments."}, {"term": "casualty", "ipa": "/ˈkæʒuəlti/", "pron": "KAZH-oo-uhl-tee", "fr": "victime ; perte", "def": "A person killed or injured in war or an accident.", "ex": "The battle caused heavy casualties."}, {"term": "death toll", "ipa": "/ˈdeθ təʊl/", "pron": "death tohl", "fr": "bilan humain ; nombre de morts", "def": "The number of people killed.", "ex": "The death toll continued to rise."}, {"term": "collateral damage", "ipa": "/kəˌlætərəl ˈdæmɪdʒ/", "pron": "kuh-LAT-uh-ruhl DAM-ij", "fr": "dommages collatéraux", "def": "Unintended civilian harm caused by military action.", "ex": "The phrase collateral damage can hide human suffering."}, {"term": "atrocity", "ipa": "/əˈtrɒsəti/", "pron": "uh-TROS-uh-tee", "fr": "atrocité", "def": "An extremely cruel or violent act.", "ex": "Investigators documented atrocities against civilians."}, {"term": "massacre", "ipa": "/ˈmæsəkə/", "pron": "MASS-uh-kuh", "fr": "massacre", "def": "The killing of many people, especially civilians.", "ex": "The massacre shocked the international community."}, {"term": "war crime", "ipa": "/ˈwɔː kraɪm/", "pron": "war kryme", "fr": "crime de guerre", "def": "A serious violation of the laws of war.", "ex": "War crimes must be investigated and prosecuted."}, {"term": "crime against humanity", "ipa": "/ˌkraɪm əˌɡenst hjuːˈmænəti/", "pron": "kryme uh-GENST hyoo-MAN-uh-tee", "fr": "crime contre l’humanité", "def": "A widespread or systematic attack against civilians.", "ex": "Crimes against humanity can be prosecuted internationally."}, {"term": "genocide", "ipa": "/ˈdʒenəsaɪd/", "pron": "JEN-uh-syde", "fr": "génocide", "def": "The intentional destruction of a national, ethnic, racial or religious group.", "ex": "Genocide is one of the gravest international crimes."}, {"term": "ethnic cleansing", "ipa": "/ˌeθnɪk ˈklenzɪŋ/", "pron": "ETH-nik KLEN-zing", "fr": "nettoyage ethnique", "def": "Forced removal of an ethnic group from an area.", "ex": "Ethnic cleansing often involves violence and terror."}, {"term": "sexual violence", "ipa": "/ˌsekʃuəl ˈvaɪələns/", "pron": "SEK-shoo-uhl VY-uh-luhns", "fr": "violence sexuelle", "def": "Violence of a sexual nature, often used as a weapon of war.", "ex": "Sexual violence in conflict is a serious war crime."}, {"term": "torture", "ipa": "/ˈtɔːtʃə/", "pron": "TOR-chuh", "fr": "torture", "def": "Severe pain or suffering intentionally inflicted on someone.", "ex": "Torture is prohibited under international law."}, {"term": "prisoner of war", "ipa": "/ˌprɪzənər əv ˈwɔː/", "pron": "PRIZ-uh-nuh ov war", "fr": "prisonnier de guerre", "def": "A captured member of enemy armed forces.", "ex": "Prisoners of war must be treated humanely."}, {"term": "POW", "ipa": "/ˌpiː əʊ ˈdʌbəljuː/", "pron": "pee-oh-double-yoo", "fr": "prisonnier de guerre", "def": "Abbreviation for prisoner of war.", "ex": "POWs are protected by the Geneva Conventions."}, {"term": "humanitarian crisis", "ipa": "/hjuːˌmænɪˈteəriən ˈkraɪsɪs/", "pron": "hyoo-man-i-TAIR-ee-uhn KRY-sis", "fr": "crise humanitaire", "def": "A situation causing widespread human suffering and urgent need.", "ex": "The war created a humanitarian crisis."}, {"term": "humanitarian aid", "ipa": "/hjuːˌmænɪˈteəriən ˈeɪd/", "pron": "hyoo-man-i-TAIR-ee-uhn aid", "fr": "aide humanitaire", "def": "Assistance such as food, water, shelter or medicine.", "ex": "Humanitarian aid struggled to reach besieged cities."}, {"term": "humanitarian corridor", "ipa": "/hjuːˌmænɪˈteəriən ˈkɒrɪdɔː/", "pron": "hyoo-man-i-TAIR-ee-uhn KOR-i-dor", "fr": "couloir humanitaire", "def": "A safe route allowing civilians or aid to move during conflict.", "ex": "A humanitarian corridor was negotiated."}, {"term": "safe passage", "ipa": "/ˌseɪf ˈpæsɪdʒ/", "pron": "sayf PASS-ij", "fr": "passage sécurisé", "def": "Permission or protection to travel safely through a dangerous area.", "ex": "Civilians were promised safe passage."}, {"term": "displacement", "ipa": "/dɪsˈpleɪsmənt/", "pron": "dis-PLAYS-muhnt", "fr": "déplacement forcé", "def": "Forced movement of people from their homes.", "ex": "Conflict causes mass displacement."}, {"term": "displaced person", "ipa": "/dɪsˌpleɪst ˈpɜːsən/", "pron": "dis-PLAYST PUR-suhn", "fr": "personne déplacée", "def": "A person forced to leave home because of conflict or disaster.", "ex": "Displaced people need shelter and protection."}, {"term": "internally displaced person", "ipa": "/ɪnˌtɜːnəli dɪsˌpleɪst ˈpɜːsən/", "pron": "in-TUR-nuh-lee dis-PLAYST PUR-suhn", "fr": "personne déplacée interne", "def": "A displaced person who remains within their own country.", "ex": "Internally displaced people may receive less international protection."}, {"term": "IDP", "ipa": "/ˌaɪ diː ˈpiː/", "pron": "eye-dee-pee", "fr": "PDI ; personne déplacée interne", "def": "Abbreviation for internally displaced person.", "ex": "IDPs often live in camps or temporary shelters."}, {"term": "refugee", "ipa": "/ˌrefjʊˈdʒiː/", "pron": "REF-yoo-jee", "fr": "réfugié", "def": "A person forced to flee their country because of persecution, war or violence.", "ex": "Refugees crossed the border seeking safety."}]}, {"title": "D. Civilians, humanitarian crises and international law", "entries": [{"term": "asylum seeker", "ipa": "/əˈsaɪləm ˌsiːkə/", "pron": "uh-SY-luhm SEE-kuh", "fr": "demandeur d’asile", "def": "A person asking for international protection in another country.", "ex": "Asylum seekers must have their claims examined fairly."}, {"term": "evacuation", "ipa": "/ɪˌvækjuˈeɪʃən/", "pron": "i-vak-yoo-AY-shuhn", "fr": "évacuation", "def": "Moving people away from danger.", "ex": "The evacuation of civilians was delayed."}, {"term": "relief operation", "ipa": "/rɪˈliːf ˌɒpəˈreɪʃən/", "pron": "ri-LEEF op-uh-RAY-shuhn", "fr": "opération de secours", "def": "An operation delivering emergency aid.", "ex": "Relief operations were hampered by fighting."}, {"term": "famine", "ipa": "/ˈfæmɪn/", "pron": "FAM-in", "fr": "famine", "def": "Extreme shortage of food causing starvation.", "ex": "War can trigger famine by destroying food systems."}, {"term": "starvation", "ipa": "/stɑːˈveɪʃən/", "pron": "star-VAY-shuhn", "fr": "famine ; inanition", "def": "Severe suffering or death caused by lack of food.", "ex": "Using starvation as a weapon is illegal."}, {"term": "siege warfare", "ipa": "/ˈsiːdʒ ˌwɔːfeə/", "pron": "seej WAR-fair", "fr": "guerre de siège", "def": "Warfare involving surrounding a place to cut supplies and force surrender.", "ex": "Siege warfare often harms civilians."}, {"term": "critical infrastructure", "ipa": "/ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "infrastructures critiques", "def": "Essential systems such as energy, water, transport and communications.", "ex": "Attacks on critical infrastructure caused blackouts."}, {"term": "war economy", "ipa": "/ˈwɔːr iˌkɒnəmi/", "pron": "war i-KON-uh-mee", "fr": "économie de guerre", "def": "An economy reorganised to support war.", "ex": "A war economy prioritises military production."}, {"term": "defence spending", "ipa": "/dɪˈfens ˈspendɪŋ/", "pron": "di-FENS SPEN-ding", "fr": "dépenses de défense", "def": "Government spending on the military.", "ex": "Defence spending rose across Europe."}, {"term": "military budget", "ipa": "/ˌmɪlɪtəri ˈbʌdʒɪt/", "pron": "MIL-i-tuh-ree BUJ-it", "fr": "budget militaire", "def": "The amount of money allocated to the armed forces.", "ex": "The military budget increased sharply."}, {"term": "military-industrial complex", "ipa": "/ˌmɪlɪtəri ɪnˈdʌstriəl ˈkɒmpleks/", "pron": "MIL-i-tuh-ree in-DUS-tree-uhl KOM-pleks", "fr": "complexe militaro-industriel", "def": "The relationship between the military, arms industry and government.", "ex": "The military-industrial complex can influence policy."}, {"term": "arms industry", "ipa": "/ˈɑːmz ˌɪndəstri/", "pron": "armz IN-duh-stree", "fr": "industrie de l’armement", "def": "Companies producing weapons and military equipment.", "ex": "The arms industry benefited from higher defence spending."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed to change behaviour.", "ex": "Sanctions were imposed after the invasion."}, {"term": "economic warfare", "ipa": "/ˌiːkəˈnɒmɪk ˈwɔːfeə/", "pron": "ee-kuh-NOM-ik WAR-fair", "fr": "guerre économique", "def": "Use of economic tools such as sanctions to weaken an adversary.", "ex": "Economic warfare can target banks and exports."}, {"term": "blockade", "ipa": "/blɒˈkeɪd/", "pron": "blok-AYD", "fr": "blocus", "def": "An action preventing goods, people or ships from entering or leaving an area.", "ex": "The blockade caused severe shortages."}, {"term": "embargo", "ipa": "/ɪmˈbɑːɡəʊ/", "pron": "im-BAR-goh", "fr": "embargo", "def": "An official ban on trade with a country.", "ex": "The embargo targeted oil exports."}, {"term": "international law", "ipa": "/ˌɪntəˈnæʃənəl lɔː/", "pron": "IN-tuh-NASH-uh-nuhl law", "fr": "droit international", "def": "Rules governing relations between states and international actors.", "ex": "International law restricts the use of force."}, {"term": "law of war", "ipa": "/ˌlɔː əv ˈwɔː/", "pron": "law ov war", "fr": "droit de la guerre", "def": "Rules regulating conduct during armed conflict.", "ex": "The law of war protects civilians and prisoners."}, {"term": "international humanitarian law", "ipa": "/ˌɪntəˈnæʃənəl hjuːˌmænɪˈteəriən lɔː/", "pron": "IN-tuh-NASH-uh-nuhl hyoo-man-i-TAIR-ee-uhn law", "fr": "droit international humanitaire", "def": "Law regulating armed conflict and protecting people not taking part in hostilities.", "ex": "International humanitarian law applies in armed conflict."}, {"term": "IHL", "ipa": "/ˌaɪ eɪtʃ ˈel/", "pron": "eye-aych-el", "fr": "DIH", "def": "Abbreviation for international humanitarian law.", "ex": "IHL requires distinction between civilians and combatants."}, {"term": "Geneva Conventions", "ipa": "/dʒəˌniːvə kənˈvenʃənz/", "pron": "juh-NEE-vuh kuhn-VEN-shuhnz", "fr": "Conventions de Genève", "def": "Treaties setting rules for humanitarian treatment in war.", "ex": "The Geneva Conventions protect wounded soldiers and civilians."}, {"term": "principle of distinction", "ipa": "/ˈprɪnsəpəl əv dɪˈstɪŋkʃən/", "pron": "PRIN-suh-puhl ov di-STINK-shuhn", "fr": "principe de distinction", "def": "The rule requiring parties to distinguish civilians from combatants.", "ex": "The principle of distinction is central to IHL."}, {"term": "proportionality", "ipa": "/prəˌpɔːʃəˈnæləti/", "pron": "pruh-por-shuh-NAL-uh-tee", "fr": "proportionnalité", "def": "The rule that military action must not cause excessive civilian harm compared with its military advantage.", "ex": "Proportionality is difficult to assess in urban warfare."}, {"term": "military necessity", "ipa": "/ˌmɪlɪtəri nəˈsesəti/", "pron": "MIL-i-tuh-ree nuh-SES-uh-tee", "fr": "nécessité militaire", "def": "The principle allowing force necessary to achieve a legitimate military objective.", "ex": "Military necessity does not justify attacks on civilians."}, {"term": "combatant", "ipa": "/ˈkɒmbətənt/", "pron": "KOM-buh-tuhnt", "fr": "combattant", "def": "A person legally taking part in hostilities.", "ex": "Combatants may be targeted under the law of war."}, {"term": "non-combatant", "ipa": "/ˌnɒn ˈkɒmbətənt/", "pron": "non-KOM-buh-tuhnt", "fr": "non-combattant", "def": "A person not taking part in fighting.", "ex": "Non-combatants must be protected."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité", "def": "Responsibility for actions and consequences.", "ex": "Accountability for war crimes is essential."}, {"term": "impunity", "ipa": "/ɪmˈpjuːnəti/", "pron": "im-PYOO-nuh-tee", "fr": "impunité", "def": "Freedom from punishment for wrongdoing.", "ex": "Impunity encourages further abuses."}, {"term": "International Criminal Court", "ipa": "/ˌɪntəˈnæʃənəl ˈkrɪmɪnəl kɔːt/", "pron": "IN-tuh-NASH-uh-nuhl KRIM-i-nuhl court", "fr": "Cour pénale internationale", "def": "A court that prosecutes individuals for genocide, war crimes and crimes against humanity.", "ex": "The International Criminal Court opened an investigation."}, {"term": "ICC", "ipa": "/ˌaɪ siː ˈsiː/", "pron": "eye-see-see", "fr": "CPI", "def": "Abbreviation for International Criminal Court.", "ex": "The ICC prosecutes individuals, not states."}, {"term": "war tribunal", "ipa": "/ˈwɔː traɪˌbjuːnəl/", "pron": "war try-BYOO-nuhl", "fr": "tribunal de guerre", "def": "A court created to judge war crimes or related crimes.", "ex": "War tribunals can document atrocities."}, {"term": "peacekeeping", "ipa": "/ˈpiːsˌkiːpɪŋ/", "pron": "PEACE-kee-ping", "fr": "maintien de la paix", "def": "Deployment of international forces to help maintain peace.", "ex": "Peacekeeping missions require consent and resources."}, {"term": "peacekeeper", "ipa": "/ˈpiːsˌkiːpə/", "pron": "PEACE-kee-puh", "fr": "casque bleu ; force de paix", "def": "A member of an international force maintaining peace.", "ex": "Peacekeepers monitored the ceasefire."}, {"term": "peace enforcement", "ipa": "/ˈpiːs ɪnˌfɔːsmənt/", "pron": "peace in-FORSS-muhnt", "fr": "imposition de la paix", "def": "Use of force to impose peace or stop aggression.", "ex": "Peace enforcement is more coercive than peacekeeping."}, {"term": "peacebuilding", "ipa": "/ˈpiːsˌbɪldɪŋ/", "pron": "PEACE-bil-ding", "fr": "consolidation de la paix", "def": "Long-term efforts to rebuild peace after conflict.", "ex": "Peacebuilding includes justice, development and reconciliation."}, {"term": "post-war reconstruction", "ipa": "/ˌpəʊst wɔː ˌriːkənˈstrʌkʃən/", "pron": "post-war ree-kuhn-STRUK-shuhn", "fr": "reconstruction d’après-guerre", "def": "Rebuilding after a war.", "ex": "Post-war reconstruction requires huge investment."}, {"term": "reconciliation", "ipa": "/ˌrekənsɪliˈeɪʃən/", "pron": "rek-uhn-sil-ee-AY-shuhn", "fr": "réconciliation", "def": "Restoring relations after conflict.", "ex": "Reconciliation is difficult after atrocities."}, {"term": "truth commission", "ipa": "/ˈtruːθ kəˌmɪʃən/", "pron": "truth kuh-MISH-uhn", "fr": "commission vérité", "def": "A body investigating past abuses to support justice and reconciliation.", "ex": "A truth commission can help societies confront the past."}, {"term": "transitional justice", "ipa": "/trænˌzɪʃənəl ˈdʒʌstɪs/", "pron": "tran-ZISH-uh-nuhl JUS-tis", "fr": "justice transitionnelle", "def": "Justice processes after conflict or dictatorship.", "ex": "Transitional justice includes trials, reparations and truth-seeking."}, {"term": "reparations", "ipa": "/ˌrepəˈreɪʃənz/", "pron": "rep-uh-RAY-shuhnz", "fr": "réparations", "def": "Compensation or measures to repair harm caused by wrongdoing.", "ex": "Victims demanded reparations."}, {"term": "ceasefire", "ipa": "/ˈsiːsfaɪə/", "pron": "SEESS-fire", "fr": "cessez-le-feu", "def": "An agreement to stop fighting.", "ex": "The ceasefire remains fragile."}, {"term": "truce", "ipa": "/truːs/", "pron": "trooss", "fr": "trêve", "def": "A temporary stop in fighting.", "ex": "The truce allowed aid deliveries."}, {"term": "armistice", "ipa": "/ˈɑːmɪstɪs/", "pron": "AR-mi-stis", "fr": "armistice", "def": "A formal agreement to stop fighting.", "ex": "The armistice ended active hostilities."}, {"term": "surrender", "ipa": "/səˈrendə/", "pron": "suh-REN-duh", "fr": "capitulation ; reddition", "def": "The act of giving up and accepting defeat.", "ex": "The city’s surrender ended the siege."}, {"term": "capitulation", "ipa": "/kəˌpɪtʃʊˈleɪʃən/", "pron": "kuh-pit-choo-LAY-shuhn", "fr": "capitulation", "def": "Formal surrender under agreed conditions.", "ex": "The capitulation was signed at dawn."}, {"term": "peace agreement", "ipa": "/ˈpiːs əˌɡriːmənt/", "pron": "peace uh-GREE-muhnt", "fr": "accord de paix", "def": "An agreement designed to end a conflict.", "ex": "The peace agreement included power-sharing."}, {"term": "settlement", "ipa": "/ˈsetəlmənt/", "pron": "SET-uhl-muhnt", "fr": "règlement ; accord", "def": "An agreement resolving a dispute or conflict.", "ex": "A negotiated settlement is often more durable than military victory."}, {"term": "negotiated settlement", "ipa": "/nɪˌɡəʊʃieɪtɪd ˈsetəlmənt/", "pron": "ni-GOH-shee-ay-tid SET-uhl-muhnt", "fr": "règlement négocié", "def": "A conflict resolution reached through negotiation.", "ex": "A negotiated settlement requires concessions."}]}, {"title": "E. Ending war, reconstruction and high-value verbs", "entries": [{"term": "victory", "ipa": "/ˈvɪktəri/", "pron": "VIK-tuh-ree", "fr": "victoire", "def": "Success or defeat of an enemy in war or competition.", "ex": "Military victory does not guarantee peace."}, {"term": "defeat", "ipa": "/dɪˈfiːt/", "pron": "di-FEET", "fr": "défaite", "def": "Loss in war or competition.", "ex": "Defeat weakened the government."}, {"term": "stalemate", "ipa": "/ˈsteɪlmeɪt/", "pron": "STAYL-mayt", "fr": "impasse", "def": "A situation where neither side can win or make progress.", "ex": "The war settled into a bloody stalemate."}, {"term": "quagmire", "ipa": "/ˈkwæɡmaɪə/", "pron": "KWAG-my-uh", "fr": "bourbier", "def": "A difficult situation that is hard to escape, especially a prolonged conflict.", "ex": "The intervention became a quagmire."}, {"term": "war fatigue", "ipa": "/ˈwɔː fəˌtiːɡ/", "pron": "war fuh-TEEG", "fr": "lassitude de guerre", "def": "Public or political exhaustion with a long war.", "ex": "War fatigue can weaken support for military aid."}, {"term": "to wage war", "ipa": "/weɪdʒ wɔː/", "pron": "wayj war", "fr": "faire la guerre", "def": "To conduct or fight a war.", "ex": "States may wage war for territory, security or ideology."}, {"term": "to launch an invasion", "ipa": "/lɔːntʃ ən ɪnˈveɪʒən/", "pron": "launch an in-VAY-zhuhn", "fr": "lancer une invasion", "def": "To begin a military invasion.", "ex": "The regime launched an invasion at dawn."}, {"term": "to invade a country", "ipa": "/ɪnˈveɪd ə ˈkʌntri/", "pron": "in-VAYD uh KUN-tree", "fr": "envahir un pays", "def": "To enter another country by force.", "ex": "International law forbids states to invade a country without justification."}, {"term": "to occupy territory", "ipa": "/ˈɒkjʊpaɪ ˈterɪtəri/", "pron": "OK-yuh-py TERR-i-tuh-ree", "fr": "occuper un territoire", "def": "To control territory with military forces.", "ex": "The army occupied territory near the border."}, {"term": "to annex territory", "ipa": "/əˈneks ˈterɪtəri/", "pron": "uh-NEKS TERR-i-tuh-ree", "fr": "annexer un territoire", "def": "To incorporate territory into a state, often by force.", "ex": "The attempt to annex territory was widely condemned."}, {"term": "to launch an offensive", "ipa": "/lɔːntʃ ən əˈfensɪv/", "pron": "launch an uh-FEN-siv", "fr": "lancer une offensive", "def": "To begin a military attack or campaign.", "ex": "The army launched an offensive in the east."}, {"term": "to repel an attack", "ipa": "/rɪˈpel ən əˈtæk/", "pron": "ri-PEL an uh-TAK", "fr": "repousser une attaque", "def": "To drive back or stop an attack.", "ex": "Defenders managed to repel the attack."}, {"term": "to withdraw troops", "ipa": "/wɪðˈdrɔː truːps/", "pron": "with-DRAW troops", "fr": "retirer des troupes", "def": "To remove soldiers from an area.", "ex": "The agreement required both sides to withdraw troops."}, {"term": "to deploy forces", "ipa": "/dɪˈplɔɪ ˈfɔːsɪz/", "pron": "di-PLOY FOR-siz", "fr": "déployer des forces", "def": "To move military forces into position.", "ex": "The government deployed forces to the border."}, {"term": "to mobilise the army", "ipa": "/ˈməʊbɪlaɪz ði ˈɑːmi/", "pron": "MOH-bi-lyze thee AR-mee", "fr": "mobiliser l’armée", "def": "To prepare the army for action.", "ex": "The president decided to mobilise the army."}, {"term": "to impose a blockade", "ipa": "/ɪmˈpəʊz ə blɒˈkeɪd/", "pron": "im-POHZ uh blok-AYD", "fr": "imposer un blocus", "def": "To prevent goods or people from entering or leaving an area.", "ex": "The navy imposed a blockade."}, {"term": "to target civilians", "ipa": "/ˈtɑːɡɪt səˈvɪliənz/", "pron": "TAR-git suh-VIL-yuhnz", "fr": "prendre des civils pour cible", "def": "To attack civilians deliberately.", "ex": "It is illegal to target civilians."}, {"term": "to commit war crimes", "ipa": "/kəˈmɪt ˈwɔː kraɪmz/", "pron": "kuh-MIT war krymez", "fr": "commettre des crimes de guerre", "def": "To carry out serious violations of the laws of war.", "ex": "Commanders may be prosecuted if they commit war crimes."}, {"term": "to violate international law", "ipa": "/ˈvaɪəleɪt ˌɪntəˈnæʃənəl lɔː/", "pron": "VY-uh-layt IN-tuh-NASH-uh-nuhl law", "fr": "violer le droit international", "def": "To break international legal rules.", "ex": "The attack appeared to violate international law."}, {"term": "to protect civilians", "ipa": "/prəˈtekt səˈvɪliənz/", "pron": "pruh-TEKT suh-VIL-yuhnz", "fr": "protéger les civils", "def": "To keep civilians safe from harm.", "ex": "Parties to conflict must protect civilians."}, {"term": "to deliver humanitarian aid", "ipa": "/dɪˈlɪvər hjuːˌmænɪˈteəriən eɪd/", "pron": "di-LIV-uh hyoo-man-i-TAIR-ee-uhn aid", "fr": "acheminer l’aide humanitaire", "def": "To bring emergency assistance to people in need.", "ex": "Aid agencies tried to deliver humanitarian aid."}, {"term": "to flee the fighting", "ipa": "/fliː ðə ˈfaɪtɪŋ/", "pron": "flee thuh FIGHT-ing", "fr": "fuir les combats", "def": "To escape from a conflict zone.", "ex": "Thousands of civilians fled the fighting."}, {"term": "to broker a ceasefire", "ipa": "/ˈbrəʊkər ə ˈsiːsfaɪə/", "pron": "BROH-kuh uh SEESS-fire", "fr": "négocier un cessez-le-feu", "def": "To help parties agree to stop fighting.", "ex": "Mediators tried to broker a ceasefire."}, {"term": "to negotiate a settlement", "ipa": "/nɪˈɡəʊʃieɪt ə ˈsetəlmənt/", "pron": "ni-GOH-shee-ayt uh SET-uhl-muhnt", "fr": "négocier un règlement", "def": "To reach a conflict-ending agreement through talks.", "ex": "A negotiated settlement may be the only realistic option."}, {"term": "to end hostilities", "ipa": "/end hɒˈstɪlətiz/", "pron": "end hos-TIL-uh-teez", "fr": "mettre fin aux hostilités", "def": "To stop fighting.", "ex": "The ceasefire aimed to end hostilities."}, {"term": "to rebuild after war", "ipa": "/ˌriːˈbɪld ˈɑːftə wɔː/", "pron": "ree-BILD AF-tuh war", "fr": "reconstruire après la guerre", "def": "To reconstruct society, infrastructure and institutions after conflict.", "ex": "The country will need decades to rebuild after war."}]}]}, {"id": "p6c52", "part": 6, "chapter": 52, "title": "Terrorism", "file": "cpge_vocab_part6_chapter52_terrorism_premium.html", "count": 144, "sections": [{"title": "A. Core terrorism and extremism vocabulary", "entries": [{"term": "terrorism", "ipa": "/ˈterərɪzəm/", "pron": "TERR-uh-riz-uhm", "fr": "terrorisme", "def": "The use or threat of violence against civilians or symbolic targets to pursue political, ideological or religious aims.", "ex": "Terrorism aims to spread fear beyond the immediate victims."}, {"term": "terrorist attack", "ipa": "/ˈterərɪst əˌtæk/", "pron": "TERR-uh-rist uh-TAK", "fr": "attentat terroriste", "def": "A violent act carried out for terrorist purposes.", "ex": "The terrorist attack shocked the country and triggered a security response."}, {"term": "terrorist group", "ipa": "/ˈterərɪst ɡruːp/", "pron": "TERR-uh-rist group", "fr": "groupe terroriste", "def": "An organisation using terrorism to pursue its goals.", "ex": "The terrorist group claimed responsibility for the bombing."}, {"term": "terrorist cell", "ipa": "/ˈterərɪst sel/", "pron": "TERR-uh-rist sel", "fr": "cellule terroriste", "def": "A small organised group within a terrorist network.", "ex": "Police dismantled a terrorist cell before it could act."}, {"term": "terror network", "ipa": "/ˈterə ˌnetwɜːk/", "pron": "TERR-uh NET-work", "fr": "réseau terroriste", "def": "A connected system of terrorist actors, supporters and resources.", "ex": "The terror network operated across borders."}, {"term": "extremism", "ipa": "/ɪkˈstriːmɪzəm/", "pron": "ik-STREEM-iz-uhm", "fr": "extrémisme", "def": "Support for radical ideas that reject democratic norms or justify violence.", "ex": "Extremism can become dangerous when it legitimises violence."}, {"term": "violent extremism", "ipa": "/ˌvaɪələnt ɪkˈstriːmɪzəm/", "pron": "VY-uh-luhnt ik-STREEM-iz-uhm", "fr": "extrémisme violent", "def": "Extremism that supports or uses violence.", "ex": "Preventing violent extremism requires more than policing."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "The process by which someone adopts extreme beliefs, sometimes leading to violence.", "ex": "Online propaganda can accelerate radicalisation."}, {"term": "self-radicalisation", "ipa": "/ˌself rædɪkəlaɪˈzeɪʃən/", "pron": "self rad-i-kuh-ly-ZAY-shuhn", "fr": "auto-radicalisation", "def": "Radicalisation that occurs largely without direct personal contact with a group.", "ex": "Self-radicalisation is difficult for authorities to detect."}, {"term": "online radicalisation", "ipa": "/ˌɒnlaɪn rædɪkəlaɪˈzeɪʃən/", "pron": "ON-line rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation en ligne", "def": "Radicalisation through internet content, forums or social media.", "ex": "Online radicalisation has become a major security concern."}, {"term": "jihadism", "ipa": "/dʒɪˈhɑːdɪzəm/", "pron": "ji-HAH-diz-uhm", "fr": "djihadisme", "def": "A violent extremist ideology claiming to justify violence through a distorted interpretation of jihad.", "ex": "Jihadism has inspired transnational terrorist networks."}, {"term": "far-right terrorism", "ipa": "/ˌfɑː raɪt ˈterərɪzəm/", "pron": "far-right TERR-uh-riz-uhm", "fr": "terrorisme d’extrême droite", "def": "Terrorism motivated by far-right ideologies such as white supremacy or ultranationalism.", "ex": "Far-right terrorism has grown as a concern in many democracies."}, {"term": "white supremacism", "ipa": "/ˌwaɪt suːˈpreməsɪzəm/", "pron": "white soo-PREM-uh-siz-uhm", "fr": "suprémacisme blanc", "def": "The racist belief that white people are superior and should dominate society.", "ex": "White supremacism can fuel violent extremism."}, {"term": "religious extremism", "ipa": "/rɪˌlɪdʒəs ɪkˈstriːmɪzəm/", "pron": "ri-LIJ-uhs ik-STREEM-iz-uhm", "fr": "extrémisme religieux", "def": "Extremism justified through religious claims or identity.", "ex": "Religious extremism is not representative of a whole faith community."}, {"term": "political violence", "ipa": "/pəˌlɪtɪkəl ˈvaɪələns/", "pron": "puh-LIT-i-kuhl VY-uh-luhns", "fr": "violence politique", "def": "Violence used for political purposes.", "ex": "Terrorism is one form of political violence."}, {"term": "lone actor", "ipa": "/ˌləʊn ˈæktə/", "pron": "lohn AK-tuh", "fr": "acteur isolé", "def": "A person who carries out violence alone, without direct command from a group.", "ex": "Lone-actor attacks are hard to prevent."}, {"term": "lone wolf", "ipa": "/ˌləʊn ˈwʊlf/", "pron": "lohn wolf", "fr": "loup solitaire", "def": "Informal term for a lone actor; often avoided because it can romanticise violence.", "ex": "The phrase lone wolf can obscure online influence."}, {"term": "homegrown terrorism", "ipa": "/ˌhəʊmɡrəʊn ˈterərɪzəm/", "pron": "HOHM-grohn TERR-uh-riz-uhm", "fr": "terrorisme endogène", "def": "Terrorism carried out by people radicalised within the country where they act.", "ex": "Homegrown terrorism challenges traditional border-focused security."}, {"term": "transnational terrorism", "ipa": "/trænzˌnæʃənəl ˈterərɪzəm/", "pron": "tranz-NASH-uh-nuhl TERR-uh-riz-uhm", "fr": "terrorisme transnational", "def": "Terrorism involving networks, targets or operations across borders.", "ex": "Transnational terrorism requires international cooperation."}, {"term": "domestic terrorism", "ipa": "/dəˌmestɪk ˈterərɪzəm/", "pron": "duh-MES-tik TERR-uh-riz-uhm", "fr": "terrorisme intérieur", "def": "Terrorism carried out within a country by actors based there.", "ex": "Domestic terrorism can be politically sensitive to define."}, {"term": "state terrorism", "ipa": "/ˌsteɪt ˈterərɪzəm/", "pron": "state TERR-uh-riz-uhm", "fr": "terrorisme d’État", "def": "Use of terror by a state against populations or opponents.", "ex": "The term state terrorism is highly contested."}, {"term": "state-sponsored terrorism", "ipa": "/ˌsteɪt ˌspɒnsəd ˈterərɪzəm/", "pron": "state-SPON-suhd TERR-uh-riz-uhm", "fr": "terrorisme soutenu par un État", "def": "Terrorism supported by a government through funding, training or protection.", "ex": "State-sponsored terrorism can destabilise whole regions."}, {"term": "insurgency", "ipa": "/ɪnˈsɜːdʒənsi/", "pron": "in-SUR-juhn-see", "fr": "insurrection", "def": "An organised rebellion against a government or occupying power.", "ex": "Some insurgencies use terrorist tactics."}, {"term": "guerrilla tactics", "ipa": "/ɡəˈrɪlə ˈtæktɪks/", "pron": "guh-RIL-uh TAK-tiks", "fr": "tactiques de guérilla", "def": "Irregular warfare methods using small mobile groups and surprise attacks.", "ex": "Guerrilla tactics differ from indiscriminate attacks on civilians."}, {"term": "asymmetric warfare", "ipa": "/ˌeɪsɪˈmetrɪk ˈwɔːfeə/", "pron": "ay-si-MET-rik WAR-fair", "fr": "guerre asymétrique", "def": "Conflict between actors with very unequal military power.", "ex": "Terrorism is often used in asymmetric warfare."}, {"term": "suicide bombing", "ipa": "/ˈsuːɪsaɪd ˌbɒmɪŋ/", "pron": "SOO-i-syde BOM-ing", "fr": "attentat-suicide", "def": "An attack in which the attacker deliberately dies while detonating explosives.", "ex": "Suicide bombing is designed to maximise shock and fear."}]}, {"title": "B. Attack methods, targets and propaganda", "entries": [{"term": "bombing", "ipa": "/ˈbɒmɪŋ/", "pron": "BOM-ing", "fr": "attentat à la bombe ; bombardement", "def": "An attack using explosives.", "ex": "The bombing targeted a crowded market."}, {"term": "car bomb", "ipa": "/ˈkɑː bɒm/", "pron": "car bom", "fr": "voiture piégée", "def": "A bomb placed in a vehicle.", "ex": "A car bomb exploded outside the ministry."}, {"term": "improvised explosive device", "ipa": "/ˌɪmprəvaɪzd ɪkˌspləʊsɪv dɪˈvaɪs/", "pron": "IM-pruh-vyzd ik-SPLOH-siv di-VYSS", "fr": "engin explosif improvisé", "def": "A homemade bomb used by non-state actors or insurgents.", "ex": "Improvised explosive devices caused many casualties."}, {"term": "IED", "ipa": "/ˌaɪ iː ˈdiː/", "pron": "eye-ee-dee", "fr": "EEI ; engin explosif improvisé", "def": "Abbreviation for improvised explosive device.", "ex": "IEDs are often used in asymmetric conflicts."}, {"term": "hostage-taking", "ipa": "/ˈhɒstɪdʒ ˌteɪkɪŋ/", "pron": "HOS-tij TAY-king", "fr": "prise d’otages", "def": "The act of capturing people to force demands.", "ex": "Hostage-taking puts governments under intense pressure."}, {"term": "hijacking", "ipa": "/ˈhaɪdʒækɪŋ/", "pron": "HY-jak-ing", "fr": "détournement", "def": "Taking control of a vehicle, aircraft or ship by force.", "ex": "Aircraft hijacking reshaped aviation security."}, {"term": "assassination", "ipa": "/əˌsæsɪˈneɪʃən/", "pron": "uh-sas-i-NAY-shuhn", "fr": "assassinat", "def": "The deliberate killing of a political or public figure.", "ex": "Assassination can be used to destabilise a government."}, {"term": "mass shooting", "ipa": "/ˌmæs ˈʃuːtɪŋ/", "pron": "mass SHOO-ting", "fr": "fusillade de masse", "def": "An attack in which multiple people are shot.", "ex": "Some mass shootings are motivated by extremist ideology."}, {"term": "knife attack", "ipa": "/ˈnaɪf əˌtæk/", "pron": "knife uh-TAK", "fr": "attaque au couteau", "def": "An attack using a knife or blade.", "ex": "Knife attacks are low-tech but can spread fear."}, {"term": "vehicle-ramming attack", "ipa": "/ˈviːɪkəl ˌræmɪŋ əˌtæk/", "pron": "VEE-i-kuhl RAM-ing uh-TAK", "fr": "attaque au véhicule-bélier", "def": "An attack using a vehicle to hit people deliberately.", "ex": "Vehicle-ramming attacks are difficult to prevent in open spaces."}, {"term": "soft target", "ipa": "/ˌsɒft ˈtɑːɡɪt/", "pron": "soft TAR-git", "fr": "cible vulnérable", "def": "A civilian or poorly protected target such as a school, concert hall or market.", "ex": "Terrorists often choose soft targets to maximise fear."}, {"term": "hard target", "ipa": "/ˌhɑːd ˈtɑːɡɪt/", "pron": "hard TAR-git", "fr": "cible protégée", "def": "A protected target such as a military base or government building.", "ex": "Hard targets require greater planning and resources."}, {"term": "civilian target", "ipa": "/səˌvɪliən ˈtɑːɡɪt/", "pron": "suh-VIL-yuhn TAR-git", "fr": "cible civile", "def": "A non-military target involving civilians.", "ex": "Attacking civilian targets is morally and legally condemned."}, {"term": "symbolic target", "ipa": "/sɪmˌbɒlɪk ˈtɑːɡɪt/", "pron": "sim-BOL-ik TAR-git", "fr": "cible symbolique", "def": "A target chosen for its political, cultural or religious meaning.", "ex": "The monument was chosen as a symbolic target."}, {"term": "critical infrastructure", "ipa": "/ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "infrastructures critiques", "def": "Essential systems such as transport, energy, water and communications.", "ex": "Terrorists may target critical infrastructure."}, {"term": "cyberterrorism", "ipa": "/ˌsaɪbəˈterərɪzəm/", "pron": "SY-buh-TERR-uh-riz-uhm", "fr": "cyberterrorisme", "def": "Use of cyberattacks to cause fear, disruption or political pressure.", "ex": "Cyberterrorism could target hospitals or power grids."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Biased information used to promote a political cause or ideology.", "ex": "Terrorist propaganda glorifies violence and martyrdom."}, {"term": "extremist propaganda", "ipa": "/ɪkˌstriːmɪst ˌprɒpəˈɡændə/", "pron": "ik-STREEM-ist prop-uh-GAN-duh", "fr": "propagande extrémiste", "def": "Propaganda promoting extremist beliefs or violence.", "ex": "Extremist propaganda spreads rapidly online."}, {"term": "recruitment", "ipa": "/rɪˈkruːtmənt/", "pron": "ri-KROOT-muhnt", "fr": "recrutement", "def": "The process of attracting people to join a group or cause.", "ex": "Online recruitment can target isolated young people."}, {"term": "indoctrination", "ipa": "/ɪnˌdɒktrɪˈneɪʃən/", "pron": "in-dok-tri-NAY-shuhn", "fr": "endoctrinement", "def": "Teaching someone to accept beliefs uncritically.", "ex": "Indoctrination isolates individuals from alternative viewpoints."}, {"term": "incitement", "ipa": "/ɪnˈsaɪtmənt/", "pron": "in-SYTE-muhnt", "fr": "incitation", "def": "Encouragement to commit violence or illegal acts.", "ex": "Incitement to violence is punishable by law."}, {"term": "glorification of violence", "ipa": "/ˌɡlɔːrɪfɪˈkeɪʃən əv ˈvaɪələns/", "pron": "glor-i-fi-KAY-shuhn ov VY-uh-luhns", "fr": "glorification de la violence", "def": "Presenting violence as heroic or admirable.", "ex": "Glorification of violence can help radicalise vulnerable people."}, {"term": "martyrdom narrative", "ipa": "/ˈmɑːtədəm ˈnærətɪv/", "pron": "MAR-tuh-duhm NARR-uh-tiv", "fr": "récit de martyr", "def": "A story portraying death for a cause as heroic or sacred.", "ex": "Martyrdom narratives are used in extremist recruitment."}, {"term": "conspiracy theory", "ipa": "/kənˈspɪrəsi ˈθɪəri/", "pron": "kuhn-SPIR-uh-see THEER-ee", "fr": "théorie du complot", "def": "A belief that hidden groups secretly control events, often without evidence.", "ex": "Conspiracy theories can feed extremist worldviews."}, {"term": "grievance", "ipa": "/ˈɡriːvəns/", "pron": "GREE-vuhns", "fr": "grief ; ressentiment", "def": "A real or perceived injustice that causes resentment.", "ex": "Extremist recruiters exploit personal and political grievances."}, {"term": "alienation", "ipa": "/ˌeɪliəˈneɪʃən/", "pron": "ay-lee-uh-NAY-shuhn", "fr": "aliénation ; sentiment d’exclusion", "def": "A feeling of isolation or disconnection from society.", "ex": "Alienation can make extremist narratives more attractive."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "The division of society into opposing and hostile groups.", "ex": "Polarisation can create fertile ground for extremism."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity such as race, religion or ethnicity.", "ex": "Hate speech can normalise violence."}, {"term": "dehumanisation", "ipa": "/diːˌhjuːmənaɪˈzeɪʃən/", "pron": "dee-HYOO-muh-ny-ZAY-shuhn", "fr": "déshumanisation", "def": "Portraying people as less than human.", "ex": "Dehumanisation makes violence easier to justify."}, {"term": "counterterrorism", "ipa": "/ˌkaʊntəˈterərɪzəm/", "pron": "KOWN-tuh-TERR-uh-riz-uhm", "fr": "contre-terrorisme ; lutte antiterroriste", "def": "Policies and actions designed to prevent and respond to terrorism.", "ex": "Counterterrorism must balance security and civil liberties."}, {"term": "anti-terrorism", "ipa": "/ˌænti ˈterərɪzəm/", "pron": "AN-tee TERR-uh-riz-uhm", "fr": "antiterrorisme", "def": "Measures opposing terrorism.", "ex": "Anti-terrorism laws expanded after major attacks."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "Protection of a country’s safety and vital interests.", "ex": "Terrorism is often framed as a national security threat."}, {"term": "homeland security", "ipa": "/ˌhəʊmlænd sɪˈkjʊərəti/", "pron": "HOHM-land si-KYOOR-uh-tee", "fr": "sécurité intérieure", "def": "Domestic security against threats such as terrorism.", "ex": "Homeland security agencies coordinate emergency responses."}, {"term": "security services", "ipa": "/sɪˈkjʊərəti ˈsɜːvɪsɪz/", "pron": "si-KYOOR-uh-tee SUR-vis-iz", "fr": "services de sécurité", "def": "Agencies responsible for intelligence and internal security.", "ex": "Security services monitor extremist networks."}, {"term": "intelligence agency", "ipa": "/ɪnˈtelɪdʒəns ˌeɪdʒənsi/", "pron": "in-TEL-i-juhns AY-juhn-see", "fr": "service de renseignement", "def": "A government body that gathers and analyses information for security.", "ex": "Intelligence agencies help prevent attacks."}]}, {"title": "C. Counterterrorism, surveillance and prevention", "entries": [{"term": "surveillance", "ipa": "/səˈveɪləns/", "pron": "suh-VAY-luhns", "fr": "surveillance", "def": "Monitoring people, communications or places for security or control.", "ex": "Mass surveillance raises civil-liberty concerns."}, {"term": "mass surveillance", "ipa": "/ˌmæs səˈveɪləns/", "pron": "mass suh-VAY-luhns", "fr": "surveillance de masse", "def": "Large-scale monitoring of populations or communications.", "ex": "Mass surveillance is controversial in democracies."}, {"term": "targeted surveillance", "ipa": "/ˈtɑːɡɪtɪd səˈveɪləns/", "pron": "TAR-git-id suh-VAY-luhns", "fr": "surveillance ciblée", "def": "Monitoring specific individuals or groups based on suspicion.", "ex": "Targeted surveillance requires legal oversight."}, {"term": "intelligence gathering", "ipa": "/ɪnˈtelɪdʒəns ˌɡæðərɪŋ/", "pron": "in-TEL-i-juhns GATH-uh-ring", "fr": "collecte de renseignement", "def": "Collecting information to assess threats.", "ex": "Intelligence gathering can prevent attacks."}, {"term": "threat assessment", "ipa": "/ˈθret əˌsesmənt/", "pron": "thret uh-SESS-muhnt", "fr": "évaluation de la menace", "def": "Evaluation of the seriousness and likelihood of a threat.", "ex": "Threat assessment guides police priorities."}, {"term": "risk assessment", "ipa": "/ˈrɪsk əˌsesmənt/", "pron": "risk uh-SESS-muhnt", "fr": "évaluation des risques", "def": "Evaluation of possible risks and their impact.", "ex": "Risk assessment is used at airports and public events."}, {"term": "security threat", "ipa": "/sɪˈkjʊərəti θret/", "pron": "si-KYOOR-uh-tee thret", "fr": "menace sécuritaire", "def": "A danger to public or national security.", "ex": "The suspect was considered a security threat."}, {"term": "threat level", "ipa": "/ˈθret ˌlevəl/", "pron": "thret LEV-uhl", "fr": "niveau de menace", "def": "An official assessment of the likelihood of an attack.", "ex": "The threat level was raised after the attack."}, {"term": "early warning signs", "ipa": "/ˌɜːli ˈwɔːnɪŋ saɪnz/", "pron": "UR-lee WAR-ning synz", "fr": "signaux d’alerte précoces", "def": "Signs indicating a possible future threat.", "ex": "Teachers and social workers may notice early warning signs."}, {"term": "prevention", "ipa": "/prɪˈvenʃən/", "pron": "pri-VEN-shuhn", "fr": "prévention", "def": "Action taken to stop something from happening.", "ex": "Prevention is central to counterterrorism."}, {"term": "deradicalisation", "ipa": "/ˌdiːrædɪkəlaɪˈzeɪʃən/", "pron": "dee-rad-i-kuh-ly-ZAY-shuhn", "fr": "déradicalisation", "def": "The process of helping someone abandon extremist beliefs.", "ex": "Deradicalisation programmes are difficult to evaluate."}, {"term": "disengagement", "ipa": "/ˌdɪsɪnˈɡeɪdʒmənt/", "pron": "dis-in-GAYJ-muhnt", "fr": "désengagement", "def": "Stopping involvement in extremist activity, even if beliefs change slowly.", "ex": "Disengagement may be more realistic than full deradicalisation."}, {"term": "community policing", "ipa": "/kəˌmjuːnəti pəˈliːsɪŋ/", "pron": "kuh-MYOO-nuh-tee puh-LEE-sing", "fr": "police de proximité", "def": "Policing based on trust and cooperation with local communities.", "ex": "Community policing can improve trust and intelligence."}, {"term": "community engagement", "ipa": "/kəˌmjuːnəti ɪnˈɡeɪdʒmənt/", "pron": "kuh-MYOO-nuh-tee in-GAYJ-muhnt", "fr": "implication des communautés", "def": "Working with communities to build trust and prevent harm.", "ex": "Community engagement can help prevent radicalisation."}, {"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability of a society to recover from attacks or crises.", "ex": "Social resilience reduces the long-term impact of terrorism."}, {"term": "emergency response", "ipa": "/ɪˈmɜːdʒənsi rɪˌspɒns/", "pron": "i-MUR-juhn-see ri-SPONS", "fr": "réponse d’urgence", "def": "Immediate action taken after a crisis or attack.", "ex": "Emergency response saves lives after an attack."}, {"term": "first responders", "ipa": "/ˌfɜːst rɪˈspɒndəz/", "pron": "first ri-SPON-duhz", "fr": "premiers intervenants", "def": "Police, firefighters, paramedics and others who respond first to emergencies.", "ex": "First responders arrived within minutes."}, {"term": "evacuation", "ipa": "/ɪˌvækjuˈeɪʃən/", "pron": "i-vak-yoo-AY-shuhn", "fr": "évacuation", "def": "Moving people away from danger.", "ex": "The evacuation of the station was orderly."}, {"term": "lockdown", "ipa": "/ˈlɒkdaʊn/", "pron": "LOK-down", "fr": "confinement de sécurité ; verrouillage", "def": "A security measure preventing people from entering or leaving an area.", "ex": "The school went into lockdown after the alert."}, {"term": "state of emergency", "ipa": "/ˌsteɪt əv ɪˈmɜːdʒənsi/", "pron": "state ov i-MUR-juhn-see", "fr": "état d’urgence", "def": "A legal situation giving authorities special powers during a crisis.", "ex": "The government declared a state of emergency."}, {"term": "emergency powers", "ipa": "/ɪˈmɜːdʒənsi ˈpaʊəz/", "pron": "i-MUR-juhn-see POW-uhz", "fr": "pouvoirs d’urgence", "def": "Special powers granted to authorities during a crisis.", "ex": "Emergency powers must be limited and supervised."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected from government interference.", "ex": "Counterterrorism can threaten civil liberties."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Human rights must be protected even during security crises."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit", "def": "The principle that everyone, including the state, is subject to law.", "ex": "The rule of law limits counterterrorism powers."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "dyoo PROH-ses", "fr": "procédure régulière", "def": "Fair legal procedures before punishment or restriction.", "ex": "Suspects must be granted due process."}, {"term": "racial profiling", "ipa": "/ˌreɪʃəl ˈprəʊfaɪlɪŋ/", "pron": "RAY-shuhl PROH-fy-ling", "fr": "profilage racial", "def": "Targeting people based on race or ethnicity rather than evidence.", "ex": "Racial profiling damages trust in law enforcement."}, {"term": "religious profiling", "ipa": "/rɪˌlɪdʒəs ˈprəʊfaɪlɪŋ/", "pron": "ri-LIJ-uhs PROH-fy-ling", "fr": "profilage religieux", "def": "Targeting people based on religion rather than evidence.", "ex": "Religious profiling can stigmatise entire communities."}, {"term": "stigmatisation", "ipa": "/ˌstɪɡmətaɪˈzeɪʃən/", "pron": "stig-muh-ty-ZAY-shuhn", "fr": "stigmatisation", "def": "The process of unfairly marking a group as dangerous or shameful.", "ex": "Stigmatisation can worsen alienation and mistrust."}, {"term": "Islamophobia", "ipa": "/ɪzˌlæməˈfəʊbiə/", "pron": "iz-lam-uh-FOH-bee-uh", "fr": "islamophobie", "def": "Hostility, prejudice or discrimination against Muslims.", "ex": "Counterterrorism discourse can fuel Islamophobia if it generalises unfairly."}, {"term": "hate crime", "ipa": "/ˈheɪt kraɪm/", "pron": "hate kryme", "fr": "crime de haine", "def": "A crime motivated by prejudice against identity.", "ex": "Terrorist attacks can trigger hate crimes against minorities."}, {"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction.", "ex": "Security measures triggered a civil-liberties backlash."}, {"term": "collective punishment", "ipa": "/kəˌlektɪv ˈpʌnɪʃmənt/", "pron": "kuh-LEK-tiv PUN-ish-muhnt", "fr": "punition collective", "def": "Punishing a whole group for the actions of a few.", "ex": "Collective punishment is unjust and counterproductive."}, {"term": "foreign fighter", "ipa": "/ˌfɒrən ˈfaɪtə/", "pron": "FOR-uhn FY-tuh", "fr": "combattant étranger", "def": "A person who travels abroad to fight for an armed or extremist group.", "ex": "Foreign fighters posed challenges when they returned home."}, {"term": "returnee", "ipa": "/rɪˌtɜːˈniː/", "pron": "ri-tur-NEE", "fr": "revenant ; personne de retour", "def": "A person who returns from abroad, often from a conflict zone.", "ex": "Returnees may require prosecution, monitoring or rehabilitation."}, {"term": "financing of terrorism", "ipa": "/ˈfaɪnænsɪŋ əv ˈterərɪzəm/", "pron": "FY-nan-sing ov TERR-uh-riz-uhm", "fr": "financement du terrorisme", "def": "Providing or moving money to support terrorist activity.", "ex": "Banks must help detect financing of terrorism."}, {"term": "money laundering", "ipa": "/ˈmʌni ˌlɔːndərɪŋ/", "pron": "MUN-ee LAWN-duh-ring", "fr": "blanchiment d’argent", "def": "Disguising the illegal origin of money.", "ex": "Money laundering can fund criminal and terrorist networks."}, {"term": "asset freeze", "ipa": "/ˈæset friːz/", "pron": "AS-et freez", "fr": "gel des avoirs", "def": "A measure preventing people or groups from using financial assets.", "ex": "An asset freeze targeted the organisation’s leaders."}]}, {"title": "D. Rights, financing, international cooperation and victims", "entries": [{"term": "terrorist designation", "ipa": "/ˈterərɪst ˌdezɪɡˈneɪʃən/", "pron": "TERR-uh-rist dez-ig-NAY-shuhn", "fr": "désignation comme terroriste", "def": "Official listing of a person or group as terrorist.", "ex": "Terrorist designation can trigger sanctions."}, {"term": "blacklist", "ipa": "/ˈblæklɪst/", "pron": "BLAK-list", "fr": "liste noire", "def": "A list of banned or sanctioned people or organisations.", "ex": "The group was placed on a terrorism blacklist."}, {"term": "intelligence sharing", "ipa": "/ɪnˈtelɪdʒəns ˌʃeərɪŋ/", "pron": "in-TEL-i-juhns SHARE-ing", "fr": "partage de renseignement", "def": "Exchange of security information between agencies or countries.", "ex": "Intelligence sharing is essential against transnational terrorism."}, {"term": "international cooperation", "ipa": "/ˌɪntəˈnæʃənəl kəʊˌɒpəˈreɪʃən/", "pron": "IN-tuh-NASH-uh-nuhl koh-op-uh-RAY-shuhn", "fr": "coopération internationale", "def": "Working with other countries to achieve shared goals.", "ex": "International cooperation helps track cross-border networks."}, {"term": "extradition", "ipa": "/ˌekstrəˈdɪʃən/", "pron": "ek-struh-DISH-uhn", "fr": "extradition", "def": "The transfer of a suspect from one country to another for trial or punishment.", "ex": "The suspect faced extradition to the country where the attack occurred."}, {"term": "border security", "ipa": "/ˈbɔːdə sɪˌkjʊərəti/", "pron": "BOR-duh si-KYOOR-uh-tee", "fr": "sécurité des frontières", "def": "Measures protecting borders from threats or illegal movement.", "ex": "Border security tightened after the attacks."}, {"term": "airport security", "ipa": "/ˈeəpɔːt sɪˌkjʊərəti/", "pron": "AIR-port si-KYOOR-uh-tee", "fr": "sécurité aéroportuaire", "def": "Security checks and measures at airports.", "ex": "Airport security changed after hijacking attacks."}, {"term": "screening", "ipa": "/ˈskriːnɪŋ/", "pron": "SKREEN-ing", "fr": "contrôle ; filtrage", "def": "Checking people or items for risk.", "ex": "Passenger screening became more thorough."}, {"term": "watchlist", "ipa": "/ˈwɒtʃlɪst/", "pron": "WATCH-list", "fr": "liste de surveillance", "def": "A list of people monitored because they may pose a threat.", "ex": "Being on a watchlist can restrict travel."}, {"term": "no-fly list", "ipa": "/ˌnəʊ ˈflaɪ lɪst/", "pron": "no-fly list", "fr": "liste d’interdiction de vol", "def": "A list of people barred from boarding aircraft.", "ex": "The no-fly list expanded after security reforms."}, {"term": "security check", "ipa": "/sɪˈkjʊərəti tʃek/", "pron": "si-KYOOR-uh-tee chek", "fr": "contrôle de sécurité", "def": "A procedure to verify safety or identity.", "ex": "Security checks can slow down travel."}, {"term": "public safety", "ipa": "/ˌpʌblɪk ˈseɪfti/", "pron": "PUB-lik SAYF-tee", "fr": "sécurité publique", "def": "Protection of the public from harm.", "ex": "Public safety must be balanced with freedom."}, {"term": "victim", "ipa": "/ˈvɪktɪm/", "pron": "VIK-tim", "fr": "victime", "def": "A person harmed by an attack, crime or disaster.", "ex": "Victims need medical, psychological and legal support."}, {"term": "survivor", "ipa": "/səˈvaɪvə/", "pron": "suh-VY-vuh", "fr": "survivant ; survivante", "def": "A person who lives through an attack or traumatic event.", "ex": "Survivors often face long-term trauma."}, {"term": "trauma", "ipa": "/ˈtrɔːmə/", "pron": "TRAW-muh", "fr": "traumatisme", "def": "Deep psychological harm caused by a distressing event.", "ex": "Terrorist attacks leave trauma in communities."}, {"term": "memorial", "ipa": "/məˈmɔːriəl/", "pron": "muh-MOR-ee-uhl", "fr": "mémorial", "def": "A place or object created to remember victims.", "ex": "The memorial honours the victims of the attack."}, {"term": "commemoration", "ipa": "/kəˌmeməˈreɪʃən/", "pron": "kuh-mem-uh-RAY-shuhn", "fr": "commémoration", "def": "An act of remembering victims or events publicly.", "ex": "The commemoration emphasised unity and resilience."}, {"term": "national mourning", "ipa": "/ˌnæʃənəl ˈmɔːnɪŋ/", "pron": "NASH-uh-nuhl MOR-ning", "fr": "deuil national", "def": "A period of public grief after a tragedy.", "ex": "The government declared a day of national mourning."}, {"term": "solidarity", "ipa": "/ˌsɒlɪˈdærəti/", "pron": "sol-i-DARR-uh-tee", "fr": "solidarité", "def": "Unity and support for people affected by hardship or violence.", "ex": "Citizens showed solidarity with the victims."}, {"term": "resilience narrative", "ipa": "/rɪˈzɪliəns ˈnærətɪv/", "pron": "ri-ZIL-ee-uhns NARR-uh-tiv", "fr": "récit de résilience", "def": "A public story emphasising recovery and unity after attack.", "ex": "A resilience narrative can help communities heal."}, {"term": "media coverage", "ipa": "/ˈmiːdiə ˈkʌvərɪdʒ/", "pron": "MEE-dee-uh KUV-uh-rij", "fr": "couverture médiatique", "def": "Reporting of events by the media.", "ex": "Media coverage can inform the public but also amplify fear."}, {"term": "sensationalism", "ipa": "/senˈseɪʃənəlɪzəm/", "pron": "sen-SAY-shuh-nuhl-iz-uhm", "fr": "sensationnalisme", "def": "Reporting designed to shock or attract attention rather than inform responsibly.", "ex": "Sensationalism can give terrorists the attention they seek."}, {"term": "copycat attack", "ipa": "/ˈkɒpikæt əˌtæk/", "pron": "KOP-ee-kat uh-TAK", "fr": "attaque par imitation", "def": "An attack inspired by a previous attack.", "ex": "Excessive publicity may encourage copycat attacks."}, {"term": "public fear", "ipa": "/ˌpʌblɪk ˈfɪə/", "pron": "PUB-lik fear", "fr": "peur collective", "def": "Fear felt by the population after threats or attacks.", "ex": "Terrorism is designed to create public fear."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "Exaggerated public fear about a perceived threat.", "ex": "Moral panic can lead to rushed legislation."}, {"term": "security theatre", "ipa": "/sɪˈkjʊərəti ˈθɪətə/", "pron": "si-KYOOR-uh-tee THEE-uh-tuh", "fr": "sécurité spectacle", "def": "Visible security measures that create reassurance without greatly improving safety.", "ex": "Some airport measures are criticised as security theatre."}, {"term": "to radicalise", "ipa": "/ˈrædɪkəlaɪz/", "pron": "RAD-i-kuh-lyze", "fr": "radicaliser", "def": "To cause someone to adopt extremist views.", "ex": "Extremist content can radicalise vulnerable individuals."}, {"term": "to recruit followers", "ipa": "/rɪˈkruːt ˈfɒləʊəz/", "pron": "ri-KROOT FOL-oh-uhz", "fr": "recruter des partisans", "def": "To attract people to join a movement or group.", "ex": "Terrorist groups use social media to recruit followers."}, {"term": "to spread propaganda", "ipa": "/spred ˌprɒpəˈɡændə/", "pron": "spred prop-uh-GAN-duh", "fr": "diffuser de la propagande", "def": "To disseminate biased ideological material.", "ex": "Extremist networks spread propaganda online."}, {"term": "to incite violence", "ipa": "/ɪnˈsaɪt ˈvaɪələns/", "pron": "in-SYTE VY-uh-luhns", "fr": "inciter à la violence", "def": "To encourage people to commit violence.", "ex": "Leaders can be prosecuted if they incite violence."}, {"term": "to claim responsibility", "ipa": "/kleɪm rɪˌspɒnsəˈbɪləti/", "pron": "klaym ri-spon-suh-BIL-uh-tee", "fr": "revendiquer la responsabilité", "def": "To say that one carried out an attack.", "ex": "The group claimed responsibility for the attack."}, {"term": "to carry out an attack", "ipa": "/ˈkæri aʊt ən əˈtæk/", "pron": "KARR-ee out an uh-TAK", "fr": "mener une attaque", "def": "To perform or execute an attack.", "ex": "The attackers carried out an attack during rush hour."}, {"term": "to target civilians", "ipa": "/ˈtɑːɡɪt səˈvɪliənz/", "pron": "TAR-git suh-VIL-yuhnz", "fr": "prendre des civils pour cible", "def": "To choose civilians as victims.", "ex": "Terrorism often targets civilians to maximise fear."}, {"term": "to spread fear", "ipa": "/spred fɪə/", "pron": "spred fear", "fr": "répandre la peur", "def": "To cause fear across society.", "ex": "The aim was to spread fear beyond the attack site."}, {"term": "to prevent attacks", "ipa": "/prɪˈvent əˈtæks/", "pron": "pri-VENT uh-TAKS", "fr": "prévenir les attaques", "def": "To stop attacks before they happen.", "ex": "Security services work to prevent attacks."}, {"term": "to foil a plot", "ipa": "/fɔɪl ə plɒt/", "pron": "foyl uh plot", "fr": "déjouer un complot", "def": "To stop a planned attack from happening.", "ex": "Police foiled a plot against public transport."}, {"term": "to dismantle a cell", "ipa": "/dɪsˈmæntəl ə sel/", "pron": "dis-MAN-tuhl uh sel", "fr": "démanteler une cellule", "def": "To break up an organised terrorist cell.", "ex": "Investigators dismantled a cell after months of surveillance."}, {"term": "to monitor suspects", "ipa": "/ˈmɒnɪtə ˈsʌspekts/", "pron": "MON-i-tuh SUS-pekts", "fr": "surveiller des suspects", "def": "To watch suspected individuals.", "ex": "Authorities monitored suspects linked to extremist forums."}, {"term": "to gather intelligence", "ipa": "/ˈɡæðər ɪnˈtelɪdʒəns/", "pron": "GATH-uh in-TEL-i-juhns", "fr": "recueillir du renseignement", "def": "To collect security information.", "ex": "Agencies gather intelligence to assess threats."}]}, {"title": "E. Media, public fear and high-value verbs", "entries": [{"term": "to share intelligence", "ipa": "/ʃeər ɪnˈtelɪdʒəns/", "pron": "share in-TEL-i-juhns", "fr": "partager du renseignement", "def": "To exchange security information.", "ex": "Allies share intelligence on terrorist networks."}, {"term": "to tighten security", "ipa": "/ˈtaɪtən sɪˈkjʊərəti/", "pron": "TY-tuhn si-KYOOR-uh-tee", "fr": "renforcer la sécurité", "def": "To make security measures stricter.", "ex": "The government tightened security after the attack."}, {"term": "to declare a state of emergency", "ipa": "/dɪˈkleər ə steɪt əv ɪˈmɜːdʒənsi/", "pron": "di-KLAIR uh state ov i-MUR-juhn-see", "fr": "déclarer l’état d’urgence", "def": "To officially announce emergency powers.", "ex": "The president declared a state of emergency."}, {"term": "to balance security and freedom", "ipa": "/ˈbæləns sɪˈkjʊərəti ənd ˈfriːdəm/", "pron": "BAL-uhns si-KYOOR-uh-tee and FREE-duhm", "fr": "équilibrer sécurité et liberté", "def": "To protect people while preserving civil liberties.", "ex": "Democracies must balance security and freedom."}, {"term": "to protect civil liberties", "ipa": "/prəˈtekt ˌsɪvəl ˈlɪbətiz/", "pron": "pruh-TEKT SIV-uhl LIB-uh-teez", "fr": "protéger les libertés civiles", "def": "To defend basic freedoms from excessive state power.", "ex": "Counterterrorism laws must protect civil liberties."}, {"term": "to counter violent extremism", "ipa": "/ˈkaʊntə ˈvaɪələnt ɪkˈstriːmɪzəm/", "pron": "KOWN-tuh VY-uh-luhnt ik-STREEM-iz-uhm", "fr": "lutter contre l’extrémisme violent", "def": "To fight the causes and spread of violent extremism.", "ex": "Education and community work can counter violent extremism."}, {"term": "to build community resilience", "ipa": "/bɪld kəˌmjuːnəti rɪˈzɪliəns/", "pron": "bild kuh-MYOO-nuh-tee ri-ZIL-ee-uhns", "fr": "renforcer la résilience communautaire", "def": "To strengthen a community’s ability to resist and recover from extremism or attacks.", "ex": "Local initiatives can build community resilience."}]}]}, {"id": "p6c53", "part": 6, "chapter": 53, "title": "Nato", "file": "cpge_vocab_part6_chapter53_nato_premium.html", "count": 135, "sections": [{"title": "A. Core NATO and alliance vocabulary", "entries": [{"term": "NATO", "ipa": "/ˈneɪtəʊ/", "pron": "NAY-toh", "fr": "OTAN", "def": "The North Atlantic Treaty Organization, a military and political alliance between North American and European states.", "ex": "NATO is based on collective defence among its members."}, {"term": "North Atlantic Treaty Organization", "ipa": "/ˌnɔːθ ətˌlæntɪk ˈtriːti ˌɔːɡənaɪˈzeɪʃən/", "pron": "north-at-LAN-tik TREE-tee or-guh-ny-ZAY-shuhn", "fr": "Organisation du traité de l’Atlantique nord", "def": "The full name of NATO.", "ex": "The North Atlantic Treaty Organization was created after the Second World War."}, {"term": "alliance", "ipa": "/əˈlaɪəns/", "pron": "uh-LY-uhns", "fr": "alliance", "def": "A formal relationship between states for cooperation, usually on security or defence.", "ex": "An alliance can deter aggression by pooling military strength."}, {"term": "military alliance", "ipa": "/ˌmɪlɪtəri əˈlaɪəns/", "pron": "MIL-i-tuh-ree uh-LY-uhns", "fr": "alliance militaire", "def": "An alliance based on military cooperation and mutual defence.", "ex": "NATO is the world’s most powerful military alliance."}, {"term": "political alliance", "ipa": "/pəˌlɪtɪkəl əˈlaɪəns/", "pron": "puh-LIT-i-kuhl uh-LY-uhns", "fr": "alliance politique", "def": "An alliance based on shared political interests and commitments.", "ex": "NATO is also a political alliance built on consultation."}, {"term": "collective defence", "ipa": "/kəˌlektɪv dɪˈfens/", "pron": "kuh-LEK-tiv di-FENS", "fr": "défense collective", "def": "The principle that an attack on one member is treated as an attack on all.", "ex": "Collective defence is NATO’s core principle."}, {"term": "Article 5", "ipa": "/ˌɑːtɪkəl ˈfaɪv/", "pron": "AR-ti-kuhl five", "fr": "Article 5", "def": "The NATO treaty clause stating that an attack on one ally is considered an attack on all.", "ex": "Article 5 has been invoked only once, after the 9/11 attacks."}, {"term": "North Atlantic Treaty", "ipa": "/ˌnɔːθ ətˌlæntɪk ˈtriːti/", "pron": "north-at-LAN-tik TREE-tee", "fr": "traité de l’Atlantique nord", "def": "The founding treaty of NATO, signed in 1949.", "ex": "The North Atlantic Treaty created NATO."}, {"term": "Washington Treaty", "ipa": "/ˈwɒʃɪŋtən ˈtriːti/", "pron": "WOSH-ing-tuhn TREE-tee", "fr": "traité de Washington", "def": "Another name for the North Atlantic Treaty.", "ex": "The Washington Treaty sets out NATO’s founding principles."}, {"term": "member state", "ipa": "/ˈmembə steɪt/", "pron": "MEM-buh state", "fr": "État membre", "def": "A country that belongs to an organisation or alliance.", "ex": "Each NATO member state has a voice in decision-making."}, {"term": "ally", "ipa": "/ˈælaɪ/", "pron": "AL-eye", "fr": "allié", "def": "A country cooperating with another, especially in defence or security.", "ex": "NATO allies coordinate military planning."}, {"term": "transatlantic alliance", "ipa": "/ˌtrænzətˈlæntɪk əˈlaɪəns/", "pron": "tranz-at-LAN-tik uh-LY-uhns", "fr": "alliance transatlantique", "def": "The security partnership linking North America and Europe.", "ex": "The transatlantic alliance remains central to European security."}, {"term": "transatlantic relations", "ipa": "/ˌtrænzətˈlæntɪk rɪˈleɪʃənz/", "pron": "tranz-at-LAN-tik ri-LAY-shuhnz", "fr": "relations transatlantiques", "def": "Relations between North America and Europe.", "ex": "NATO is a pillar of transatlantic relations."}, {"term": "Euro-Atlantic security", "ipa": "/ˌjʊərəʊ ətˌlæntɪk sɪˈkjʊərəti/", "pron": "YOOR-oh at-LAN-tik si-KYOOR-uh-tee", "fr": "sécurité euro-atlantique", "def": "Security across Europe and North America.", "ex": "NATO presents itself as a guardian of Euro-Atlantic security."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "Preventing aggression by threatening credible consequences.", "ex": "Deterrence is meant to prevent war, not start it."}, {"term": "defence posture", "ipa": "/dɪˈfens ˈpɒstʃə/", "pron": "di-FENS POS-chuh", "fr": "dispositif de défense", "def": "The way military forces are organised and prepared for defence.", "ex": "NATO strengthened its defence posture after Russia’s invasion of Ukraine."}, {"term": "forward defence", "ipa": "/ˌfɔːwəd dɪˈfens/", "pron": "FOR-wuhd di-FENS", "fr": "défense avancée", "def": "Defence based on deploying forces near potential areas of conflict.", "ex": "Forward defence reassures exposed allies."}, {"term": "enhanced Forward Presence", "ipa": "/ɪnˌhɑːnst ˈfɔːwəd ˈprezəns/", "pron": "in-HANST FOR-wuhd PREZ-uhns", "fr": "présence avancée renforcée", "def": "NATO deployments in eastern member states to deter aggression.", "ex": "Enhanced Forward Presence was created after Russia’s annexation of Crimea."}, {"term": "tripwire force", "ipa": "/ˈtrɪpwaɪə fɔːs/", "pron": "TRIP-wire force", "fr": "force de déclenchement", "def": "A small force whose attack would trigger a wider allied response.", "ex": "A tripwire force signals alliance commitment."}, {"term": "rapid reaction force", "ipa": "/ˌræpɪd riˈækʃən fɔːs/", "pron": "RAP-id ree-AK-shuhn force", "fr": "force de réaction rapide", "def": "Military forces ready to deploy quickly in a crisis.", "ex": "A rapid reaction force improves NATO readiness."}, {"term": "NATO Response Force", "ipa": "/ˌneɪtəʊ rɪˈspɒns fɔːs/", "pron": "NAY-toh ri-SPONS force", "fr": "Force de réaction de l’OTAN", "def": "A multinational NATO force designed for rapid deployment.", "ex": "The NATO Response Force can be activated in crises."}, {"term": "readiness", "ipa": "/ˈredinəs/", "pron": "RED-ee-nuhs", "fr": "état de préparation", "def": "The state of being prepared for action.", "ex": "Military readiness is vital for deterrence."}, {"term": "military readiness", "ipa": "/ˌmɪlɪtəri ˈredinəs/", "pron": "MIL-i-tuh-ree RED-ee-nuhs", "fr": "préparation militaire", "def": "The ability of armed forces to respond effectively and quickly.", "ex": "NATO has increased military readiness on its eastern flank."}, {"term": "interoperability", "ipa": "/ˌɪntərɒpərəˈbɪləti/", "pron": "in-ter-op-uh-ruh-BIL-uh-tee", "fr": "interopérabilité", "def": "The ability of different armed forces to work together effectively.", "ex": "NATO exercises improve interoperability among allies."}, {"term": "standardisation", "ipa": "/ˌstændədaɪˈzeɪʃən/", "pron": "STAN-duh-dy-ZAY-shuhn", "fr": "standardisation", "def": "Making rules, equipment or procedures compatible.", "ex": "Standardisation helps NATO forces operate together."}, {"term": "joint exercise", "ipa": "/ˌdʒɔɪnt ˈeksəsaɪz/", "pron": "joint EK-suh-syze", "fr": "exercice conjoint", "def": "A military training operation involving several forces or countries.", "ex": "Joint exercises test NATO’s ability to respond."}, {"term": "military exercise", "ipa": "/ˌmɪlɪtəri ˈeksəsaɪz/", "pron": "MIL-i-tuh-ree EK-suh-syze", "fr": "exercice militaire", "def": "A training operation preparing forces for real missions.", "ex": "Large military exercises can also send strategic signals."}, {"term": "command structure", "ipa": "/kəˈmɑːnd ˌstrʌktʃə/", "pron": "kuh-MAND STRUK-chuh", "fr": "structure de commandement", "def": "The hierarchy through which military authority is organised.", "ex": "NATO’s command structure coordinates allied forces."}, {"term": "Supreme Allied Commander Europe", "ipa": "/suːˌpriːm ˈælaɪd kəˈmɑːndər ˈjʊərəp/", "pron": "soo-PREEM AL-eyed kuh-MAN-duh YOOR-uhp", "fr": "commandant suprême des forces alliées en Europe", "def": "The senior NATO commander responsible for military operations in Europe.", "ex": "The Supreme Allied Commander Europe is traditionally an American officer."}, {"term": "SACEUR", "ipa": "/ˈsækɜː/", "pron": "SAK-ur", "fr": "SACEUR", "def": "Abbreviation for Supreme Allied Commander Europe.", "ex": "SACEUR is one of NATO’s most important military roles."}, {"term": "Secretary General", "ipa": "/ˌsekrətəri ˈdʒenərəl/", "pron": "SEK-ruh-tuh-ree JEN-uh-ruhl", "fr": "secrétaire général", "def": "NATO’s chief political official and public representative.", "ex": "The Secretary General represents NATO in public diplomacy."}, {"term": "North Atlantic Council", "ipa": "/ˌnɔːθ ətˌlæntɪk ˈkaʊnsəl/", "pron": "north-at-LAN-tik KOWN-suhl", "fr": "Conseil de l’Atlantique nord", "def": "NATO’s principal political decision-making body.", "ex": "The North Atlantic Council makes decisions by consensus."}, {"term": "consensus", "ipa": "/kənˈsensəs/", "pron": "kuhn-SEN-suhs", "fr": "consensus", "def": "General agreement among all members.", "ex": "NATO decisions require consensus among allies."}, {"term": "consultation", "ipa": "/ˌkɒnsəlˈteɪʃən/", "pron": "kon-suhl-TAY-shuhn", "fr": "consultation", "def": "Discussion among allies before taking decisions.", "ex": "Article 4 allows NATO allies to request consultation."}, {"term": "Article 4", "ipa": "/ˌɑːtɪkəl ˈfɔː/", "pron": "AR-ti-kuhl four", "fr": "Article 4", "def": "The NATO clause allowing members to consult when their security is threatened.", "ex": "Article 4 can be invoked during a security crisis."}]}, {"title": "B. Defence, deterrence, readiness and burden-sharing", "entries": [{"term": "burden-sharing", "ipa": "/ˈbɜːdən ˌʃeərɪŋ/", "pron": "BUR-duhn SHARE-ing", "fr": "partage du fardeau", "def": "The distribution of costs and responsibilities among allies.", "ex": "Burden-sharing is a recurring source of tension within NATO."}, {"term": "defence spending", "ipa": "/dɪˈfens ˈspendɪŋ/", "pron": "di-FENS SPEN-ding", "fr": "dépenses de défense", "def": "Government spending on military defence.", "ex": "NATO allies are expected to increase defence spending."}, {"term": "two-percent target", "ipa": "/ˌtuː pəˈsent ˈtɑːɡɪt/", "pron": "two-puh-SENT TAR-git", "fr": "objectif des 2 %", "def": "NATO’s guideline that allies should spend 2% of GDP on defence.", "ex": "The two-percent target is debated in many NATO countries."}, {"term": "GDP", "ipa": "/ˌdʒiː diː ˈpiː/", "pron": "jee-dee-pee", "fr": "PIB", "def": "Gross Domestic Product, the value of goods and services produced in a country.", "ex": "Defence spending is often measured as a share of GDP."}, {"term": "defence budget", "ipa": "/dɪˈfens ˈbʌdʒɪt/", "pron": "di-FENS BUJ-it", "fr": "budget de défense", "def": "Money allocated by a government to defence.", "ex": "The defence budget rose after the invasion."}, {"term": "military capability", "ipa": "/ˌmɪlɪtəri ˌkeɪpəˈbɪləti/", "pron": "MIL-i-tuh-ree kay-puh-BIL-uh-tee", "fr": "capacité militaire", "def": "A country’s ability to perform military tasks.", "ex": "NATO depends on credible military capabilities."}, {"term": "capability gap", "ipa": "/ˌkeɪpəˈbɪləti ɡæp/", "pron": "kay-puh-BIL-uh-tee gap", "fr": "écart capacitaire", "def": "A shortfall in military equipment, skills or capacity.", "ex": "Capability gaps weaken alliance readiness."}, {"term": "strategic concept", "ipa": "/strəˌtiːdʒɪk ˈkɒnsept/", "pron": "struh-TEE-jik KON-sept", "fr": "concept stratégique", "def": "A NATO document defining threats, goals and priorities.", "ex": "NATO’s Strategic Concept identifies major security challenges."}, {"term": "security environment", "ipa": "/sɪˈkjʊərəti ɪnˌvaɪrənmənt/", "pron": "si-KYOOR-uh-tee in-VY-ruhn-muhnt", "fr": "environnement de sécurité", "def": "The overall context of threats and risks.", "ex": "The European security environment changed dramatically after 2022."}, {"term": "threat perception", "ipa": "/ˈθret pəˌsepʃən/", "pron": "thret puh-SEP-shuhn", "fr": "perception de la menace", "def": "How actors understand or interpret threats.", "ex": "Different allies may have different threat perceptions."}, {"term": "eastern flank", "ipa": "/ˌiːstən ˈflæŋk/", "pron": "EES-tuhn flank", "fr": "flanc oriental", "def": "NATO member states located near Russia and Belarus.", "ex": "NATO reinforced its eastern flank."}, {"term": "southern flank", "ipa": "/ˌsʌðən ˈflæŋk/", "pron": "SUTH-uhn flank", "fr": "flanc sud", "def": "NATO’s southern area of concern, including the Mediterranean and Middle East.", "ex": "The southern flank faces instability, terrorism and migration pressures."}, {"term": "Baltic states", "ipa": "/ˈbɔːltɪk steɪts/", "pron": "BALL-tik states", "fr": "États baltes", "def": "Estonia, Latvia and Lithuania.", "ex": "The Baltic states see NATO as essential to their security."}, {"term": "Black Sea region", "ipa": "/ˌblæk ˈsiː ˈriːdʒən/", "pron": "black sea REE-juhn", "fr": "région de la mer Noire", "def": "The strategic region around the Black Sea.", "ex": "The Black Sea region has become a major security concern."}, {"term": "Russia", "ipa": "/ˈrʌʃə/", "pron": "RUSH-uh", "fr": "Russie", "def": "A major Eurasian state often seen by NATO as a central security challenge.", "ex": "Russia’s actions have reshaped NATO strategy."}, {"term": "Russian aggression", "ipa": "/ˌrʌʃən əˈɡreʃən/", "pron": "RUSH-uhn uh-GRESH-uhn", "fr": "agression russe", "def": "Aggressive military or political action by Russia.", "ex": "Russian aggression revived NATO’s collective-defence role."}, {"term": "Ukraine", "ipa": "/juːˈkreɪn/", "pron": "yoo-KRAYN", "fr": "Ukraine", "def": "A European state invaded by Russia in 2022 and supported by NATO allies.", "ex": "Ukraine receives military and political support from NATO members."}, {"term": "Ukraine war", "ipa": "/juːˈkreɪn wɔː/", "pron": "yoo-KRAYN war", "fr": "guerre en Ukraine", "def": "The war following Russia’s full-scale invasion of Ukraine in 2022.", "ex": "The Ukraine war transformed European security debates."}, {"term": "military aid", "ipa": "/ˌmɪlɪtəri ˈeɪd/", "pron": "MIL-i-tuh-ree aid", "fr": "aide militaire", "def": "Military support such as weapons, training or intelligence.", "ex": "NATO countries have provided military aid to Ukraine."}, {"term": "security assistance", "ipa": "/sɪˈkjʊərəti əˈsɪstəns/", "pron": "si-KYOOR-uh-tee uh-SIS-tuhns", "fr": "assistance sécuritaire", "def": "Support to strengthen another country’s defence and security.", "ex": "Security assistance can include training and equipment."}, {"term": "training mission", "ipa": "/ˈtreɪnɪŋ ˌmɪʃən/", "pron": "TRAY-ning MISH-uhn", "fr": "mission de formation", "def": "A mission designed to train another country’s forces.", "ex": "Training missions improve partner forces’ capabilities."}, {"term": "partnership", "ipa": "/ˈpɑːtnəʃɪp/", "pron": "PART-nuh-ship", "fr": "partenariat", "def": "A structured relationship for cooperation without full membership.", "ex": "NATO maintains partnerships with non-member states."}, {"term": "Partnership for Peace", "ipa": "/ˈpɑːtnəʃɪp fə piːs/", "pron": "PART-nuh-ship for peace", "fr": "Partenariat pour la paix", "def": "A NATO programme for cooperation with non-member countries.", "ex": "Partnership for Peace was launched after the Cold War."}, {"term": "partner country", "ipa": "/ˈpɑːtnə ˈkʌntri/", "pron": "PART-nuh KUN-tree", "fr": "pays partenaire", "def": "A country cooperating with NATO without being a member.", "ex": "Partner countries may take part in NATO missions."}, {"term": "membership", "ipa": "/ˈmembəʃɪp/", "pron": "MEM-buh-ship", "fr": "adhésion ; appartenance", "def": "The status of belonging to an organisation.", "ex": "NATO membership gives security guarantees."}, {"term": "accession", "ipa": "/əkˈseʃən/", "pron": "ak-SESH-uhn", "fr": "adhésion", "def": "The process of formally joining an organisation or treaty.", "ex": "Accession to NATO requires approval by all allies."}, {"term": "enlargement", "ipa": "/ɪnˈlɑːdʒmənt/", "pron": "in-LARJ-muhnt", "fr": "élargissement", "def": "The expansion of an organisation by admitting new members.", "ex": "NATO enlargement is controversial in relations with Russia."}, {"term": "open-door policy", "ipa": "/ˌəʊpən ˈdɔː ˈpɒləsi/", "pron": "OH-puhn door POL-uh-see", "fr": "politique de la porte ouverte", "def": "NATO’s policy that European democracies may apply to join if they meet conditions.", "ex": "The open-door policy is defended as a sovereign choice."}, {"term": "aspirant country", "ipa": "/əˈspaɪərənt ˈkʌntri/", "pron": "uh-SPY-ruhant KUN-tree", "fr": "pays candidat", "def": "A country seeking to join NATO.", "ex": "Aspirant countries must meet political and military standards."}, {"term": "Membership Action Plan", "ipa": "/ˈmembəʃɪp ˈækʃən plæn/", "pron": "MEM-buh-ship AK-shuhn plan", "fr": "Plan d’action pour l’adhésion", "def": "A NATO programme helping countries prepare for possible membership.", "ex": "The Membership Action Plan guides reforms."}, {"term": "security guarantee", "ipa": "/sɪˈkjʊərəti ˌɡærənˈtiː/", "pron": "si-KYOOR-uh-tee gar-uhn-TEE", "fr": "garantie de sécurité", "def": "A promise to protect another state’s security.", "ex": "NATO membership provides a strong security guarantee."}, {"term": "neutrality", "ipa": "/njuːˈtræləti/", "pron": "nyoo-TRAL-uh-tee", "fr": "neutralité", "def": "A policy of not joining military alliances or taking sides in conflicts.", "ex": "Finland and Sweden moved away from long-standing neutrality."}, {"term": "non-alignment", "ipa": "/ˌnɒn əˈlaɪnmənt/", "pron": "non-uh-LYNE-muhnt", "fr": "non-alignement", "def": "A policy of not formally aligning with major military blocs.", "ex": "Non-alignment became harder to maintain after the Ukraine war."}, {"term": "Finland", "ipa": "/ˈfɪnlənd/", "pron": "FIN-luhnd", "fr": "Finlande", "def": "A Nordic country that joined NATO in 2023.", "ex": "Finland’s NATO membership doubled NATO’s border with Russia."}, {"term": "Sweden", "ipa": "/ˈswiːdən/", "pron": "SWEE-duhn", "fr": "Suède", "def": "A Nordic country that joined NATO in 2024.", "ex": "Sweden’s accession strengthened NATO in the Baltic region."}, {"term": "Cold War", "ipa": "/ˌkəʊld ˈwɔː/", "pron": "kohld war", "fr": "guerre froide", "def": "The geopolitical rivalry between the Western bloc and the Soviet bloc after 1945.", "ex": "NATO was created during the Cold War."}, {"term": "Soviet Union", "ipa": "/ˌsəʊviət ˈjuːniən/", "pron": "SOH-vee-uht YOO-nee-uhn", "fr": "Union soviétique", "def": "The communist state that existed from 1922 to 1991 and led the Eastern bloc.", "ex": "NATO originally deterred the Soviet Union."}]}, {"title": "C. Geography, Russia, Ukraine and NATO enlargement", "entries": [{"term": "Warsaw Pact", "ipa": "/ˌwɔːsɔː ˈpækt/", "pron": "WAR-saw pakt", "fr": "pacte de Varsovie", "def": "The Soviet-led military alliance created in 1955.", "ex": "The Warsaw Pact was NATO’s Cold War rival."}, {"term": "containment", "ipa": "/kənˈteɪnmənt/", "pron": "kuhn-TAYN-muhnt", "fr": "endiguement", "def": "A Cold War strategy to limit the spread of Soviet influence.", "ex": "NATO was part of the broader strategy of containment."}, {"term": "iron curtain", "ipa": "/ˌaɪən ˈkɜːtən/", "pron": "EYE-uhn KUR-tuhn", "fr": "rideau de fer", "def": "The symbolic division between Western and Eastern Europe during the Cold War.", "ex": "NATO stood on one side of the iron curtain."}, {"term": "post-Cold War era", "ipa": "/ˌpəʊst kəʊld ˈwɔː ˈɪərə/", "pron": "post-kohld-war EER-uh", "fr": "ère post-guerre froide", "def": "The period after the end of the Cold War.", "ex": "NATO had to redefine its role in the post-Cold War era."}, {"term": "out-of-area operation", "ipa": "/ˌaʊt əv ˈeəriə ˌɒpəˈreɪʃən/", "pron": "out-ov-AIR-ee-uh op-uh-RAY-shuhn", "fr": "opération hors zone", "def": "A military operation beyond NATO’s traditional territory.", "ex": "Out-of-area operations became important after the Cold War."}, {"term": "peacekeeping", "ipa": "/ˈpiːsˌkiːpɪŋ/", "pron": "PEACE-kee-ping", "fr": "maintien de la paix", "def": "Military or civilian activity to help maintain peace after conflict.", "ex": "NATO was involved in peacekeeping in the Balkans."}, {"term": "crisis management", "ipa": "/ˈkraɪsɪs ˌmænɪdʒmənt/", "pron": "KRY-sis MAN-ij-muhnt", "fr": "gestion de crise", "def": "Actions taken to handle and reduce a crisis.", "ex": "Crisis management is one of NATO’s core tasks."}, {"term": "collective security", "ipa": "/kəˌlektɪv sɪˈkjʊərəti/", "pron": "kuh-LEK-tiv si-KYOOR-uh-tee", "fr": "sécurité collective", "def": "A system where states cooperate to prevent aggression and maintain peace.", "ex": "Collective security is broader than collective defence."}, {"term": "cooperative security", "ipa": "/kəʊˌɒpərətɪv sɪˈkjʊərəti/", "pron": "koh-OP-uh-ruh-tiv si-KYOOR-uh-tee", "fr": "sécurité coopérative", "def": "Security built through partnerships, dialogue and cooperation.", "ex": "NATO promotes cooperative security with partners."}, {"term": "arms control", "ipa": "/ˈɑːmz kənˌtrəʊl/", "pron": "armz kuhn-TROHL", "fr": "maîtrise des armements", "def": "Agreements limiting weapons or military capabilities.", "ex": "Arms control reduced Cold War risks."}, {"term": "nuclear deterrence", "ipa": "/ˌnjuːkliə dɪˈterəns/", "pron": "NYOO-klee-uh di-TERR-uhns", "fr": "dissuasion nucléaire", "def": "Deterrence based on the threat of nuclear retaliation.", "ex": "NATO’s nuclear deterrence relies partly on US nuclear forces."}, {"term": "nuclear sharing", "ipa": "/ˌnjuːkliə ˈʃeərɪŋ/", "pron": "NYOO-klee-uh SHARE-ing", "fr": "partage nucléaire", "def": "NATO arrangements in which some allies host or train for nuclear missions.", "ex": "Nuclear sharing is controversial but central to NATO deterrence."}, {"term": "extended deterrence", "ipa": "/ɪkˌstendɪd dɪˈterəns/", "pron": "ik-STEN-did di-TERR-uhns", "fr": "dissuasion élargie", "def": "A nuclear or military guarantee protecting allies as well as one’s own territory.", "ex": "Extended deterrence reassures allies."}, {"term": "missile defence", "ipa": "/ˈmɪsaɪl dɪˌfens/", "pron": "MISS-ile di-FENS", "fr": "défense antimissile", "def": "Systems designed to detect, intercept or destroy missiles.", "ex": "Missile defence is part of NATO’s security architecture."}, {"term": "air policing", "ipa": "/ˈeə pəˌliːsɪŋ/", "pron": "air puh-LEE-sing", "fr": "police du ciel", "def": "NATO missions monitoring and protecting allied airspace.", "ex": "Air policing protects allies without their own full air-defence capacity."}, {"term": "Baltic air policing", "ipa": "/ˌbɔːltɪk ˈeə pəˌliːsɪŋ/", "pron": "BALL-tik air puh-LEE-sing", "fr": "police du ciel dans les États baltes", "def": "NATO air policing mission over the Baltic states.", "ex": "Baltic air policing reassures exposed allies."}, {"term": "hybrid threat", "ipa": "/ˌhaɪbrɪd ˈθret/", "pron": "HY-brid thret", "fr": "menace hybride", "def": "A threat combining military, cyber, economic and information tools.", "ex": "NATO warns about hybrid threats below the threshold of war."}, {"term": "cyber defence", "ipa": "/ˈsaɪbə dɪˌfens/", "pron": "SY-buh di-FENS", "fr": "cyberdéfense", "def": "Protection against cyberattacks.", "ex": "Cyber defence has become a NATO priority."}, {"term": "cyberattack", "ipa": "/ˈsaɪbərətæk/", "pron": "SY-buh-uh-tak", "fr": "cyberattaque", "def": "An attack on computer systems or networks.", "ex": "A major cyberattack can trigger allied consultations."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately.", "ex": "Disinformation campaigns can weaken public support for NATO."}, {"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WAR-fair", "fr": "guerre de l’information", "def": "Use of information and propaganda to influence conflict or politics.", "ex": "Information warfare targets societies as well as armies."}, {"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability to withstand and recover from shocks or attacks.", "ex": "NATO encourages allies to strengthen societal resilience."}, {"term": "critical infrastructure", "ipa": "/ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "infrastructures critiques", "def": "Essential systems such as energy, transport, communications and water.", "ex": "Protecting critical infrastructure is a major NATO concern."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy supplies.", "ex": "Energy security became more important after Russia’s energy pressure."}, {"term": "supply-chain security", "ipa": "/səˈplaɪ tʃeɪn sɪˌkjʊərəti/", "pron": "suh-PLY chayn si-KYOOR-uh-tee", "fr": "sécurité des chaînes d’approvisionnement", "def": "Protection of supply chains from disruption or dependency.", "ex": "Supply-chain security matters for defence industries."}, {"term": "defence industry", "ipa": "/dɪˈfens ˌɪndəstri/", "pron": "di-FENS IN-duh-stree", "fr": "industrie de défense", "def": "Companies producing military equipment and technology.", "ex": "NATO allies are expanding defence industry production."}, {"term": "ammunition production", "ipa": "/ˌæmjʊˈnɪʃən prəˈdʌkʃən/", "pron": "am-yuh-NISH-uhn pruh-DUK-shuhn", "fr": "production de munitions", "def": "Manufacturing of bullets, shells and other ammunition.", "ex": "The Ukraine war exposed shortages in ammunition production."}, {"term": "military procurement", "ipa": "/ˌmɪlɪtəri prəˈkjʊəmənt/", "pron": "MIL-i-tuh-ree pruh-KYOOR-muhnt", "fr": "acquisition / achat d’équipements militaires", "def": "The process of buying military equipment and services.", "ex": "Joint procurement can reduce costs and improve compatibility."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "The ability to act independently in strategic matters.", "ex": "European strategic autonomy is sometimes seen as complementary to NATO."}, {"term": "European defence", "ipa": "/ˌjʊərəpiːən dɪˈfens/", "pron": "YOOR-uh-pee-uhn di-FENS", "fr": "défense européenne", "def": "Defence cooperation among European states.", "ex": "European defence debates often focus on NATO dependence."}, {"term": "EU-NATO cooperation", "ipa": "/ˌiː juː ˈneɪtəʊ kəʊˌɒpəˈreɪʃən/", "pron": "ee-yoo NAY-toh koh-op-uh-RAY-shuhn", "fr": "coopération UE-OTAN", "def": "Cooperation between the European Union and NATO.", "ex": "EU-NATO cooperation has grown in response to hybrid threats."}]}, {"title": "D. Cold War legacy, nuclear deterrence and new threats", "entries": [{"term": "US leadership", "ipa": "/ˌjuː es ˈliːdəʃɪp/", "pron": "yoo-ess LEE-duh-ship", "fr": "leadership américain", "def": "The leading role of the United States in NATO.", "ex": "US leadership remains crucial to NATO’s credibility."}, {"term": "American security umbrella", "ipa": "/əˌmerɪkən sɪˈkjʊərəti ʌmˈbrelə/", "pron": "uh-MERR-i-kuhn si-KYOOR-uh-tee um-BREL-uh", "fr": "parapluie sécuritaire américain", "def": "US protection extended to allies through military and nuclear guarantees.", "ex": "Many European states rely on the American security umbrella."}, {"term": "dependency", "ipa": "/dɪˈpendənsi/", "pron": "di-PEN-duhn-see", "fr": "dépendance", "def": "Reliance on another actor for security, resources or support.", "ex": "European dependency on US military power is widely debated."}, {"term": "burden-sharing dispute", "ipa": "/ˈbɜːdən ˌʃeərɪŋ dɪˌspjuːt/", "pron": "BUR-duhn SHARE-ing di-SPYOOT", "fr": "désaccord sur le partage du fardeau", "def": "A disagreement over how alliance costs should be divided.", "ex": "Burden-sharing disputes often strain transatlantic relations."}, {"term": "free-riding", "ipa": "/ˌfriː ˈraɪdɪŋ/", "pron": "free RY-ding", "fr": "passager clandestin ; profiter sans contribuer", "def": "Benefiting from others’ contributions while contributing too little oneself.", "ex": "Some critics accuse low-spending allies of free-riding."}, {"term": "security dilemma", "ipa": "/sɪˈkjʊərəti dɪˌlemə/", "pron": "si-KYOOR-uh-tee di-LEM-uh", "fr": "dilemme de sécurité", "def": "A situation where one state’s defensive actions make others feel less secure.", "ex": "NATO enlargement is sometimes discussed through the security dilemma."}, {"term": "escalation", "ipa": "/ˌeskəˈleɪʃən/", "pron": "es-kuh-LAY-shuhn", "fr": "escalade", "def": "An increase in tension, violence or conflict.", "ex": "NATO must deter Russia while avoiding escalation."}, {"term": "de-escalation", "ipa": "/ˌdiː eskəˈleɪʃən/", "pron": "dee-es-kuh-LAY-shuhn", "fr": "désescalade", "def": "Reduction of tension or violence.", "ex": "Military communication can support de-escalation."}, {"term": "red line", "ipa": "/ˌred ˈlaɪn/", "pron": "red line", "fr": "ligne rouge", "def": "A limit that should not be crossed without consequences.", "ex": "Ambiguous red lines can weaken deterrence."}, {"term": "strategic ambiguity", "ipa": "/strəˌtiːdʒɪk ˌæmbɪˈɡjuːəti/", "pron": "struh-TEE-jik am-bi-GYOO-uh-tee", "fr": "ambiguïté stratégique", "def": "Deliberate uncertainty about intentions or responses.", "ex": "Strategic ambiguity can deter adversaries while preserving flexibility."}, {"term": "credible deterrent", "ipa": "/ˌkredəbəl dɪˈterənt/", "pron": "KRED-uh-buhl di-TERR-uhnt", "fr": "dissuasion crédible", "def": "A threat or capability that an adversary believes will be used if necessary.", "ex": "A credible deterrent depends on capability and political will."}, {"term": "security architecture", "ipa": "/sɪˈkjʊərəti ˈɑːkɪtektʃə/", "pron": "si-KYOOR-uh-tee AR-ki-tek-chuh", "fr": "architecture de sécurité", "def": "The institutions, alliances and rules organising regional or global security.", "ex": "NATO is central to Europe’s security architecture."}, {"term": "rules-based order", "ipa": "/ˌruːlz beɪst ˈɔːdə/", "pron": "roolz-bayst OR-duh", "fr": "ordre fondé sur des règles", "def": "An international system based on agreed rules rather than force.", "ex": "NATO claims to defend the rules-based order."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "A state’s authority to govern itself and choose its alliances.", "ex": "NATO argues that states have the sovereignty to choose their alliances."}, {"term": "territorial integrity", "ipa": "/ˌterɪˈtɔːriəl ɪnˈteɡrəti/", "pron": "terr-i-TOR-ee-uhl in-TEG-ruh-tee", "fr": "intégrité territoriale", "def": "The principle that a state’s borders should not be violated.", "ex": "NATO condemns violations of territorial integrity."}, {"term": "to deter aggression", "ipa": "/dɪˈter əˈɡreʃən/", "pron": "di-TERR uh-GRESH-uhn", "fr": "dissuader une agression", "def": "To prevent attack by threatening consequences.", "ex": "NATO aims to deter aggression against its members."}, {"term": "to defend allies", "ipa": "/dɪˈfend ˈælaɪz/", "pron": "di-FEND AL-eyez", "fr": "défendre les alliés", "def": "To protect allied states from attack.", "ex": "Article 5 commits NATO to defend allies."}, {"term": "to invoke Article 5", "ipa": "/ɪnˈvəʊk ˌɑːtɪkəl ˈfaɪv/", "pron": "in-VOHK AR-ti-kuhl five", "fr": "invoquer l’article 5", "def": "To formally activate NATO’s collective-defence clause.", "ex": "NATO invoked Article 5 after 9/11."}, {"term": "to request consultations", "ipa": "/rɪˈkwest ˌkɒnsəlˈteɪʃənz/", "pron": "ri-KWEST kon-suhl-TAY-shuhnz", "fr": "demander des consultations", "def": "To ask allies to discuss a security concern.", "ex": "A member can request consultations under Article 4."}, {"term": "to strengthen the eastern flank", "ipa": "/ˈstreŋθən ði ˌiːstən ˈflæŋk/", "pron": "STRENG-thuhn thee EES-tuhn flank", "fr": "renforcer le flanc oriental", "def": "To reinforce NATO’s eastern member states.", "ex": "NATO moved to strengthen the eastern flank."}, {"term": "to increase defence spending", "ipa": "/ɪnˈkriːs dɪˈfens ˈspendɪŋ/", "pron": "in-KREESS di-FENS SPEN-ding", "fr": "augmenter les dépenses de défense", "def": "To spend more public money on defence.", "ex": "Many allies pledged to increase defence spending."}, {"term": "to meet the two-percent target", "ipa": "/miːt ðə ˌtuː pəˈsent ˈtɑːɡɪt/", "pron": "meet thuh two-puh-SENT TAR-git", "fr": "atteindre l’objectif des 2 %", "def": "To spend 2% of GDP on defence.", "ex": "Some allies still struggle to meet the two-percent target."}, {"term": "to reassure allies", "ipa": "/ˌriːəˈʃɔːr ˈælaɪz/", "pron": "ree-uh-SHOR AL-eyez", "fr": "rassurer les alliés", "def": "To make allies feel protected and confident.", "ex": "Forward deployments reassure allies near Russia."}, {"term": "to signal resolve", "ipa": "/ˈsɪɡnəl rɪˈzɒlv/", "pron": "SIG-nuhl ri-ZOLV", "fr": "signaler sa détermination", "def": "To show determination to act if necessary.", "ex": "Military exercises signal resolve."}, {"term": "to avoid escalation", "ipa": "/əˈvɔɪd ˌeskəˈleɪʃən/", "pron": "uh-VOYD es-kuh-LAY-shuhn", "fr": "éviter l’escalade", "def": "To prevent a crisis from becoming more dangerous.", "ex": "NATO seeks to support Ukraine while avoiding escalation."}, {"term": "to support Ukraine", "ipa": "/səˈpɔːt juːˈkreɪn/", "pron": "suh-PORT yoo-KRAYN", "fr": "soutenir l’Ukraine", "def": "To provide political, military, economic or humanitarian help to Ukraine.", "ex": "NATO allies continue to support Ukraine."}, {"term": "to expand the alliance", "ipa": "/ɪkˈspænd ði əˈlaɪəns/", "pron": "ik-SPAND thee uh-LY-uhns", "fr": "élargir l’alliance", "def": "To admit new members to NATO.", "ex": "NATO’s decision to expand the alliance remains controversial."}, {"term": "to join NATO", "ipa": "/dʒɔɪn ˈneɪtəʊ/", "pron": "join NAY-toh", "fr": "rejoindre l’OTAN", "def": "To become a NATO member.", "ex": "Finland and Sweden decided to join NATO."}, {"term": "to modernise armed forces", "ipa": "/ˈmɒdənaɪz ˌɑːmd ˈfɔːsɪz/", "pron": "MOD-uh-nyze armd FOR-siz", "fr": "moderniser les forces armées", "def": "To update military equipment, organisation and doctrine.", "ex": "Allies need to modernise armed forces."}, {"term": "to maintain interoperability", "ipa": "/meɪnˈteɪn ˌɪntərɒpərəˈbɪləti/", "pron": "mayn-TAYN in-ter-op-uh-ruh-BIL-uh-tee", "fr": "maintenir l’interopérabilité", "def": "To preserve the ability of allied forces to work together.", "ex": "Joint exercises help maintain interoperability."}, {"term": "to counter hybrid threats", "ipa": "/ˈkaʊntə ˌhaɪbrɪd ˈθrets/", "pron": "KOWN-tuh HY-brid threats", "fr": "contrer les menaces hybrides", "def": "To respond to mixed military and non-military threats.", "ex": "NATO works with the EU to counter hybrid threats."}, {"term": "to protect critical infrastructure", "ipa": "/prəˈtekt ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "pruh-TEKT KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "protéger les infrastructures critiques", "def": "To defend essential systems from attack or disruption.", "ex": "Allies must protect critical infrastructure from sabotage and cyberattacks."}]}, {"title": "E. Strategic debates and high-value verbs", "entries": []}]}, {"id": "p6c54", "part": 6, "chapter": 54, "title": "China", "file": "cpge_vocab_part6_chapter54_china_premium.html", "count": 166, "sections": [{"title": "A. Core China, regime and human-rights vocabulary", "entries": [{"term": "China", "ipa": "/ˈtʃaɪnə/", "pron": "CHY-nuh", "fr": "Chine", "def": "A major East Asian power and the world’s second-largest economy.", "ex": "China has become central to debates about global power and economic dependency."}, {"term": "People’s Republic of China", "ipa": "/ˌpiːpəlz rɪˌpʌblɪk əv ˈtʃaɪnə/", "pron": "PEE-puhlz ri-PUB-lik ov CHY-nuh", "fr": "République populaire de Chine", "def": "The official name of mainland China, governed by the Chinese Communist Party.", "ex": "The People’s Republic of China was founded in 1949."}, {"term": "PRC", "ipa": "/ˌpiː ɑː ˈsiː/", "pron": "pee-ar-see", "fr": "RPC", "def": "Abbreviation for People’s Republic of China.", "ex": "The PRC claims Taiwan as part of its territory."}, {"term": "Chinese Communist Party", "ipa": "/ˌtʃaɪniːz ˈkɒmjʊnɪst ˈpɑːti/", "pron": "chy-NEEZ KOM-yuh-nist PAR-tee", "fr": "Parti communiste chinois", "def": "The ruling party of the People’s Republic of China.", "ex": "The Chinese Communist Party controls the state, army and key institutions."}, {"term": "CCP", "ipa": "/ˌsiː siː ˈpiː/", "pron": "see-see-pee", "fr": "PCC", "def": "Abbreviation for Chinese Communist Party.", "ex": "The CCP presents political stability as essential to national development."}, {"term": "one-party state", "ipa": "/ˌwʌn ˈpɑːti steɪt/", "pron": "wun PAR-tee state", "fr": "État à parti unique", "def": "A political system dominated by a single ruling party.", "ex": "China is a one-party state."}, {"term": "authoritarianism", "ipa": "/ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme", "def": "A system of government with limited political freedoms and strong central control.", "ex": "Chinese authoritarianism combines party control, nationalism and economic performance."}, {"term": "authoritarian regime", "ipa": "/ɔːˌθɒrɪˈteəriən reɪˈʒiːm/", "pron": "aw-thor-i-TAIR-ee-uhn ray-ZHEEM", "fr": "régime autoritaire", "def": "A government that restricts political pluralism and civil liberties.", "ex": "Critics describe China as an authoritarian regime."}, {"term": "party-state", "ipa": "/ˈpɑːti steɪt/", "pron": "PAR-tee state", "fr": "parti-État", "def": "A system in which the ruling party and state institutions are closely fused.", "ex": "In China, the party-state shapes political, economic and social life."}, {"term": "centralised power", "ipa": "/ˈsentrəlaɪzd ˈpaʊə/", "pron": "SEN-truh-lyzd POW-uh", "fr": "pouvoir centralisé", "def": "Power concentrated in central institutions or leaders.", "ex": "Centralised power allows rapid decisions but limits accountability."}, {"term": "political control", "ipa": "/pəˌlɪtɪkəl kənˈtrəʊl/", "pron": "puh-LIT-i-kuhl kuhn-TROHL", "fr": "contrôle politique", "def": "Control over political expression, institutions and opposition.", "ex": "Political control has tightened in recent years."}, {"term": "state censorship", "ipa": "/ˌsteɪt ˈsensəʃɪp/", "pron": "state SEN-suh-ship", "fr": "censure d’État", "def": "Government control or suppression of information.", "ex": "State censorship limits criticism of the government."}, {"term": "surveillance state", "ipa": "/səˈveɪləns steɪt/", "pron": "suh-VAY-luhns state", "fr": "État de surveillance", "def": "A state using extensive monitoring of citizens.", "ex": "China is often described as a surveillance state."}, {"term": "social credit system", "ipa": "/ˌsəʊʃəl ˈkredɪt ˌsɪstəm/", "pron": "SOH-shuhl KRED-it SIS-tuhm", "fr": "système de crédit social", "def": "A system using data and records to assess trustworthiness or compliance.", "ex": "The social credit system raises concerns about privacy and control."}, {"term": "Great Firewall", "ipa": "/ˌɡreɪt ˈfaɪəwɔːl/", "pron": "great FY-uh-wall", "fr": "Grand pare-feu chinois", "def": "The system controlling and filtering internet access in China.", "ex": "The Great Firewall blocks many foreign websites and platforms."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Human rights concerns shape Western policy towards China."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms such as speech, assembly and religion.", "ex": "Civil liberties are heavily restricted in China."}, {"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov speech", "fr": "liberté d’expression", "def": "The right to express opinions freely.", "ex": "Freedom of speech is limited by censorship."}, {"term": "freedom of the press", "ipa": "/ˌfriːdəm əv ðə ˈpres/", "pron": "FREE-duhm ov thuh press", "fr": "liberté de la presse", "def": "The right of media to report without censorship or intimidation.", "ex": "Freedom of the press is restricted by state control."}, {"term": "political dissident", "ipa": "/pəˌlɪtɪkəl ˈdɪsɪdənt/", "pron": "puh-LIT-i-kuhl DIS-i-duhnt", "fr": "dissident politique", "def": "A person who publicly disagrees with the government.", "ex": "Political dissidents may face surveillance or imprisonment."}, {"term": "crackdown", "ipa": "/ˈkrækdaʊn/", "pron": "KRAK-down", "fr": "répression", "def": "Strong official action to stop dissent, protest or illegal activity.", "ex": "The crackdown on dissent drew international criticism."}, {"term": "repression", "ipa": "/rɪˈpreʃən/", "pron": "ri-PRESH-uhn", "fr": "répression", "def": "Forceful control or suppression of people or opposition.", "ex": "Repression can silence civil society."}, {"term": "Xinjiang", "ipa": "/ˌʃɪnˈdʒæŋ/", "pron": "shin-JANG", "fr": "Xinjiang", "def": "A region in northwestern China with a large Uyghur population.", "ex": "Xinjiang has become a major human-rights issue."}, {"term": "Uyghurs", "ipa": "/ˈwiːɡʊəz/", "pron": "WEE-goorz", "fr": "Ouïghours", "def": "A mostly Muslim Turkic ethnic group living mainly in Xinjiang.", "ex": "Uyghurs have faced mass surveillance and repression."}, {"term": "re-education camp", "ipa": "/ˌriː edjʊˈkeɪʃən kæmp/", "pron": "ree-ej-yoo-KAY-shuhn camp", "fr": "camp de rééducation", "def": "A detention facility officially described as ideological or vocational training.", "ex": "Reports of re-education camps in Xinjiang have alarmed rights groups."}, {"term": "forced labour", "ipa": "/ˌfɔːst ˈleɪbə/", "pron": "forst LAY-buh", "fr": "travail forcé", "def": "Work imposed under threat or coercion.", "ex": "Forced labour allegations affect global supply chains."}, {"term": "Hong Kong", "ipa": "/ˌhɒŋ ˈkɒŋ/", "pron": "hong KONG", "fr": "Hong Kong", "def": "A Chinese special administrative region with a distinct legal and political history.", "ex": "Hong Kong’s freedoms have narrowed under the national security law."}, {"term": "one country, two systems", "ipa": "/ˌwʌn ˈkʌntri ˌtuː ˈsɪstəmz/", "pron": "wun KUN-tree too SIS-tuhmz", "fr": "un pays, deux systèmes", "def": "The principle meant to preserve Hong Kong’s autonomy within China.", "ex": "One country, two systems has been weakened in practice."}, {"term": "national security law", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti lɔː/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee law", "fr": "loi sur la sécurité nationale", "def": "A law aimed at protecting state security, often criticised when used against dissent.", "ex": "Hong Kong’s national security law has restricted opposition politics."}, {"term": "Tibet", "ipa": "/tɪˈbet/", "pron": "ti-BET", "fr": "Tibet", "def": "A region under Chinese control with a distinct culture and religious identity.", "ex": "Tibet remains a sensitive issue in Chinese politics."}, {"term": "economic rise", "ipa": "/ˌiːkəˈnɒmɪk raɪz/", "pron": "ee-kuh-NOM-ik ryze", "fr": "essor économique", "def": "Rapid growth in economic power and influence.", "ex": "China’s economic rise has reshaped global trade."}]}, {"title": "B. Economy, trade, technology and state capitalism", "entries": [{"term": "economic powerhouse", "ipa": "/ˌiːkəˈnɒmɪk ˈpaʊəhaʊs/", "pron": "ee-kuh-NOM-ik POW-uh-house", "fr": "puissance économique", "def": "A country or region with great economic strength.", "ex": "China is an economic powerhouse."}, {"term": "manufacturing hub", "ipa": "/ˌmænjʊˈfæktʃərɪŋ hʌb/", "pron": "man-yuh-FAK-chuh-ring hub", "fr": "centre manufacturier", "def": "A major centre for industrial production.", "ex": "China became the world’s manufacturing hub."}, {"term": "factory of the world", "ipa": "/ˌfæktəri əv ðə ˈwɜːld/", "pron": "FAK-tuh-ree ov thuh world", "fr": "usine du monde", "def": "A phrase describing China’s central role in global manufacturing.", "ex": "China was long called the factory of the world."}, {"term": "export-led growth", "ipa": "/ˌekspɔːt led ˈɡrəʊθ/", "pron": "EK-sport-led growth", "fr": "croissance tirée par les exportations", "def": "Economic growth driven by selling goods abroad.", "ex": "Export-led growth helped China develop rapidly."}, {"term": "global supply chain", "ipa": "/ˌɡləʊbəl səˈplaɪ tʃeɪn/", "pron": "GLOH-buhl suh-PLY chayn", "fr": "chaîne d’approvisionnement mondiale", "def": "A worldwide network used to produce and deliver goods.", "ex": "China is deeply embedded in global supply chains."}, {"term": "supply-chain dependency", "ipa": "/səˈplaɪ tʃeɪn dɪˈpendənsi/", "pron": "suh-PLY chayn di-PEN-duhn-see", "fr": "dépendance aux chaînes d’approvisionnement", "def": "Reliance on a supply chain controlled by or linked to another country.", "ex": "The pandemic exposed supply-chain dependency on China."}, {"term": "trade surplus", "ipa": "/ˈtreɪd ˌsɜːpləs/", "pron": "trade SUR-pluhs", "fr": "excédent commercial", "def": "A situation where a country exports more than it imports.", "ex": "China runs large trade surpluses with several countries."}, {"term": "trade deficit", "ipa": "/ˈtreɪd ˌdefɪsɪt/", "pron": "trade DEF-i-sit", "fr": "déficit commercial", "def": "A situation where a country imports more than it exports.", "ex": "The US trade deficit with China is politically sensitive."}, {"term": "foreign direct investment", "ipa": "/ˌfɒrən dəˌrekt ɪnˈvestmənt/", "pron": "FOR-uhn di-REKT in-VEST-muhnt", "fr": "investissement direct étranger", "def": "Investment by a company in productive activity abroad.", "ex": "Foreign direct investment helped China integrate into the global economy."}, {"term": "FDI", "ipa": "/ˌef diː ˈaɪ/", "pron": "eff-dee-eye", "fr": "IDE", "def": "Abbreviation for foreign direct investment.", "ex": "China attracted huge amounts of FDI."}, {"term": "state capitalism", "ipa": "/ˌsteɪt ˈkæpɪtəlɪzəm/", "pron": "state KAP-i-tuhl-iz-uhm", "fr": "capitalisme d’État", "def": "An economic system where the state plays a powerful role in markets and firms.", "ex": "Chinese state capitalism combines markets with party control."}, {"term": "state-owned enterprise", "ipa": "/ˌsteɪt əʊnd ˈentəpraɪz/", "pron": "state-ohnd EN-tuh-pryze", "fr": "entreprise publique", "def": "A company owned or controlled by the government.", "ex": "State-owned enterprises remain important in China."}, {"term": "SOE", "ipa": "/ˌes əʊ ˈiː/", "pron": "ess-oh-ee", "fr": "entreprise publique", "def": "Abbreviation for state-owned enterprise.", "ex": "SOEs receive strong state support."}, {"term": "industrial policy", "ipa": "/ɪnˈdʌstriəl ˈpɒləsi/", "pron": "in-DUS-tree-uhl POL-uh-see", "fr": "politique industrielle", "def": "Government strategy to develop selected industries.", "ex": "China uses industrial policy to support strategic sectors."}, {"term": "subsidy", "ipa": "/ˈsʌbsɪdi/", "pron": "SUB-si-dee", "fr": "subvention", "def": "Financial support from the state to firms or consumers.", "ex": "Chinese subsidies are a source of trade tension."}, {"term": "overcapacity", "ipa": "/ˌəʊvəkəˈpæsəti/", "pron": "OH-vuh-kuh-PAS-uh-tee", "fr": "surcapacité", "def": "Producing more than markets can absorb.", "ex": "Chinese overcapacity in some sectors worries Western governments."}, {"term": "dumping", "ipa": "/ˈdʌmpɪŋ/", "pron": "DUMP-ing", "fr": "dumping", "def": "Selling goods abroad at artificially low prices.", "ex": "Accusations of dumping fuel trade disputes."}, {"term": "technology transfer", "ipa": "/tekˈnɒlədʒi ˈtrænsfɜː/", "pron": "tek-NOL-uh-jee TRANS-fur", "fr": "transfert de technologie", "def": "The movement of knowledge, technology or know-how between actors.", "ex": "Forced technology transfer has been a major complaint from foreign firms."}, {"term": "intellectual property", "ipa": "/ˌɪntəˈlektʃuəl ˈprɒpəti/", "pron": "IN-tuh-LEK-choo-uhl PROP-uh-tee", "fr": "propriété intellectuelle", "def": "Legal rights over inventions, designs, brands or creative works.", "ex": "Intellectual property protection is central to trade disputes with China."}, {"term": "IP theft", "ipa": "/ˌaɪ ˈpiː θeft/", "pron": "eye-pee theft", "fr": "vol de propriété intellectuelle", "def": "The stealing of intellectual property.", "ex": "US officials have accused Chinese actors of IP theft."}, {"term": "innovation race", "ipa": "/ˌɪnəˈveɪʃən reɪs/", "pron": "in-uh-VAY-shuhn race", "fr": "course à l’innovation", "def": "Competition to lead in new technologies.", "ex": "The innovation race shapes US-China rivalry."}, {"term": "high-tech sector", "ipa": "/ˌhaɪ ˈtek ˌsektə/", "pron": "high-tek SEK-tuh", "fr": "secteur de haute technologie", "def": "Industries based on advanced technology.", "ex": "China has invested heavily in high-tech sectors."}, {"term": "semiconductors", "ipa": "/ˌsemikənˈdʌktəz/", "pron": "SEM-ee-kuhn-DUK-tuhz", "fr": "semi-conducteurs", "def": "Computer chips used in electronics and advanced technology.", "ex": "Semiconductors are central to US-China competition."}, {"term": "chip war", "ipa": "/ˈtʃɪp wɔː/", "pron": "chip war", "fr": "guerre des puces", "def": "Competition and restrictions over semiconductor technology.", "ex": "The chip war affects global technology supply chains."}, {"term": "artificial intelligence", "ipa": "/ˌɑːtɪˈfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks requiring human intelligence.", "ex": "Artificial intelligence is a strategic priority for China."}, {"term": "AI race", "ipa": "/ˌeɪ ˈaɪ reɪs/", "pron": "ay-eye race", "fr": "course à l’IA", "def": "Competition to lead in artificial intelligence.", "ex": "The AI race is part of wider great-power rivalry."}, {"term": "5G", "ipa": "/ˌfaɪv ˈdʒiː/", "pron": "five-gee", "fr": "5G", "def": "Fifth-generation mobile network technology.", "ex": "Chinese 5G technology triggered security concerns in the West."}, {"term": "Huawei", "ipa": "/ˈhwɑːweɪ/", "pron": "HWAH-way", "fr": "Huawei", "def": "A major Chinese telecommunications company.", "ex": "Huawei became a symbol of technology rivalry."}, {"term": "digital authoritarianism", "ipa": "/ˌdɪdʒɪtəl ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "DIJ-i-tuhl aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme numérique", "def": "Use of digital tools to support authoritarian control.", "ex": "Digital authoritarianism combines surveillance, censorship and data control."}, {"term": "cyber espionage", "ipa": "/ˌsaɪbər ˈespiənɑːʒ/", "pron": "SY-buh ES-pee-uh-nahzh", "fr": "cyberespionnage", "def": "Spying through cyber tools or attacks.", "ex": "Cyber espionage is a major issue in relations with China."}, {"term": "Belt and Road Initiative", "ipa": "/ˌbelt ənd ˈrəʊd ɪˈnɪʃətɪv/", "pron": "belt-and-road i-NISH-uh-tiv", "fr": "nouvelles routes de la soie", "def": "China’s global infrastructure and investment programme.", "ex": "The Belt and Road Initiative expands China’s global influence."}, {"term": "BRI", "ipa": "/ˌbiː ɑːr ˈaɪ/", "pron": "bee-ar-eye", "fr": "BRI ; nouvelles routes de la soie", "def": "Abbreviation for Belt and Road Initiative.", "ex": "BRI projects include ports, railways and energy infrastructure."}, {"term": "infrastructure diplomacy", "ipa": "/ˈɪnfrəˌstrʌktʃə dɪˈpləʊməsi/", "pron": "IN-fruh-struk-chuh di-PLOH-muh-see", "fr": "diplomatie des infrastructures", "def": "Use of infrastructure investment to build influence abroad.", "ex": "Infrastructure diplomacy is central to China’s global strategy."}, {"term": "debt diplomacy", "ipa": "/ˈdet dɪˌpləʊməsi/", "pron": "det di-PLOH-muh-see", "fr": "diplomatie de la dette", "def": "Using loans and debt to gain political influence; often used critically.", "ex": "Critics accuse China of debt diplomacy."}, {"term": "debt-trap diplomacy", "ipa": "/ˈdet træp dɪˌpləʊməsi/", "pron": "det-trap di-PLOH-muh-see", "fr": "diplomatie du piège de la dette", "def": "The disputed claim that China deliberately creates debt dependency for leverage.", "ex": "The idea of debt-trap diplomacy is debated by scholars."}, {"term": "port investment", "ipa": "/ˈpɔːt ɪnˌvestmənt/", "pron": "port in-VEST-muhnt", "fr": "investissement portuaire", "def": "Investment in port infrastructure.", "ex": "Chinese port investment can have strategic implications."}]}, {"title": "C. Global influence, Belt and Road and strategic resources", "entries": [{"term": "strategic foothold", "ipa": "/strəˌtiːdʒɪk ˈfʊthəʊld/", "pron": "struh-TEE-jik FOOT-hohld", "fr": "point d’appui stratégique", "def": "A position giving long-term strategic influence.", "ex": "A port can become a strategic foothold."}, {"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "Influence through attraction, culture and values.", "ex": "China has tried to expand its soft power."}, {"term": "sharp power", "ipa": "/ˌʃɑːp ˈpaʊə/", "pron": "sharp POW-uh", "fr": "sharp power ; pouvoir d’influence coercitif", "def": "Influence using manipulation, pressure or information control.", "ex": "Some analysts describe Chinese influence operations as sharp power."}, {"term": "influence operation", "ipa": "/ˈɪnfluəns ˌɒpəˈreɪʃən/", "pron": "IN-floo-uhns op-uh-RAY-shuhn", "fr": "opération d’influence", "def": "A coordinated effort to shape public opinion or decision-making.", "ex": "Influence operations can target universities, media or politicians."}, {"term": "Confucius Institute", "ipa": "/kənˈfjuːʃəs ˈɪnstɪtjuːt/", "pron": "kuhn-FYOO-shuhs IN-sti-tyoot", "fr": "Institut Confucius", "def": "A Chinese state-linked cultural and language institute abroad.", "ex": "Confucius Institutes have been criticised over academic freedom concerns."}, {"term": "Global South", "ipa": "/ˌɡləʊbəl ˈsaʊθ/", "pron": "GLOH-buhl south", "fr": "Sud global", "def": "Less wealthy countries, often formerly colonised, mainly in Africa, Asia and Latin America.", "ex": "China presents itself as a partner of the Global South."}, {"term": "South-South cooperation", "ipa": "/ˌsaʊθ saʊθ kəʊˌɒpəˈreɪʃən/", "pron": "south-south koh-op-uh-RAY-shuhn", "fr": "coopération Sud-Sud", "def": "Cooperation between developing or emerging countries.", "ex": "China frames some partnerships as South-South cooperation."}, {"term": "resource diplomacy", "ipa": "/rɪˈsɔːs dɪˌpləʊməsi/", "pron": "ri-SORSS di-PLOH-muh-see", "fr": "diplomatie des ressources", "def": "Foreign policy shaped by access to natural resources.", "ex": "Resource diplomacy is important in China-Africa relations."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable access to energy supplies.", "ex": "Energy security drives some Chinese foreign policy decisions."}, {"term": "rare earths", "ipa": "/ˌreər ˈɜːθs/", "pron": "rare earths", "fr": "terres rares", "def": "A group of minerals essential for electronics and green technologies.", "ex": "China dominates parts of the rare earths supply chain."}, {"term": "critical minerals", "ipa": "/ˌkrɪtɪkəl ˈmɪnərəlz/", "pron": "KRIT-i-kuhl MIN-uh-ruhlz", "fr": "minerais critiques", "def": "Minerals essential for technology, energy or defence.", "ex": "Critical minerals are a source of strategic dependency."}, {"term": "great-power rivalry", "ipa": "/ˌɡreɪt ˈpaʊə ˈraɪvəlri/", "pron": "great POW-uh RY-vuhl-ree", "fr": "rivalité entre grandes puissances", "def": "Competition between major global powers.", "ex": "US-China tensions are often described as great-power rivalry."}, {"term": "US-China rivalry", "ipa": "/ˌjuː es ˈtʃaɪnə ˈraɪvəlri/", "pron": "yoo-ess CHY-nuh RY-vuhl-ree", "fr": "rivalité sino-américaine", "def": "Strategic, economic and technological competition between the United States and China.", "ex": "US-China rivalry shapes the international order."}, {"term": "strategic competition", "ipa": "/strəˌtiːdʒɪk ˌkɒmpəˈtɪʃən/", "pron": "struh-TEE-jik kom-puh-TISH-uhn", "fr": "compétition stratégique", "def": "Long-term competition between powers across security, technology and economics.", "ex": "Strategic competition does not necessarily mean open war."}, {"term": "systemic rival", "ipa": "/sɪˌstemɪk ˈraɪvəl/", "pron": "sis-TEM-ik RY-vuhl", "fr": "rival systémique", "def": "A rival representing a different political and economic model.", "ex": "The EU has described China as a systemic rival."}, {"term": "strategic competitor", "ipa": "/strəˌtiːdʒɪk kəmˈpetɪtə/", "pron": "struh-TEE-jik kuhm-PET-i-tuh", "fr": "concurrent stratégique", "def": "A state competing with another in key strategic areas.", "ex": "China is often called a strategic competitor of the United States."}, {"term": "peer competitor", "ipa": "/ˈpɪə kəmˌpetɪtə/", "pron": "peer kuhm-PET-i-tuh", "fr": "concurrent de même rang", "def": "A rival with comparable power or capabilities.", "ex": "China is the closest peer competitor to the United States."}, {"term": "multipolar world", "ipa": "/ˌmʌltiˈpəʊlə wɜːld/", "pron": "MUL-tee-POH-luh world", "fr": "monde multipolaire", "def": "An international system with several major centres of power.", "ex": "China advocates a more multipolar world."}, {"term": "world order", "ipa": "/ˌwɜːld ˈɔːdə/", "pron": "world OR-duh", "fr": "ordre mondial", "def": "The structure of global power, rules and institutions.", "ex": "China seeks a greater role in shaping the world order."}, {"term": "rules-based order", "ipa": "/ˌruːlz beɪst ˈɔːdə/", "pron": "roolz-bayst OR-duh", "fr": "ordre fondé sur des règles", "def": "An international system based on agreed rules rather than force.", "ex": "Western leaders accuse China of challenging the rules-based order."}, {"term": "revisionist power", "ipa": "/rɪˈvɪʒənɪst ˈpaʊə/", "pron": "ri-VIZH-uh-nist POW-uh", "fr": "puissance révisionniste", "def": "A state seeking to change the existing international order.", "ex": "Some analysts describe China as a revisionist power."}, {"term": "status quo power", "ipa": "/ˌsteɪtəs ˈkwəʊ ˈpaʊə/", "pron": "STAY-tuhs kwoh POW-uh", "fr": "puissance du statu quo", "def": "A state seeking to preserve the existing order.", "ex": "China rejects the label of revisionist power and presents itself as peaceful."}, {"term": "peaceful rise", "ipa": "/ˌpiːsfəl ˈraɪz/", "pron": "PEACE-fuhl ryze", "fr": "ascension pacifique", "def": "The idea that China’s rise can happen without war or domination.", "ex": "The concept of peaceful rise is central to Chinese diplomacy."}, {"term": "national rejuvenation", "ipa": "/ˌnæʃənəl rɪˌdʒuːvəˈneɪʃən/", "pron": "NASH-uh-nuhl ri-joo-vuh-NAY-shuhn", "fr": "renouveau national", "def": "A Chinese political slogan about restoring national strength and status.", "ex": "National rejuvenation is a key theme in Chinese official discourse."}, {"term": "century of humiliation", "ipa": "/ˌsentʃəri əv hjuːˌmɪliˈeɪʃən/", "pron": "SEN-chuh-ree ov hyoo-mil-ee-AY-shuhn", "fr": "siècle d’humiliation", "def": "Chinese narrative of foreign domination and weakness from the 19th to mid-20th century.", "ex": "The century of humiliation shapes Chinese nationalism."}, {"term": "nationalism", "ipa": "/ˈnæʃənəlɪzəm/", "pron": "NASH-uh-nuh-liz-uhm", "fr": "nationalisme", "def": "Strong identification with and support for one’s nation.", "ex": "Chinese nationalism strengthens public support for the regime."}, {"term": "wolf-warrior diplomacy", "ipa": "/ˌwʊlf ˈwɒriə dɪˌpləʊməsi/", "pron": "wolf WOR-ee-uh di-PLOH-muh-see", "fr": "diplomatie du loup guerrier", "def": "A confrontational style of Chinese diplomacy.", "ex": "Wolf-warrior diplomacy has sometimes damaged China’s image abroad."}, {"term": "red line", "ipa": "/ˌred ˈlaɪn/", "pron": "red line", "fr": "ligne rouge", "def": "A limit that must not be crossed without consequences.", "ex": "Taiwan is a red line for Beijing."}, {"term": "Taiwan", "ipa": "/taɪˈwɑːn/", "pron": "ty-WAHN", "fr": "Taïwan", "def": "A self-governed democratic island claimed by China.", "ex": "Taiwan is the most dangerous flashpoint in US-China relations."}]}, {"title": "D. Great-power rivalry, Taiwan and regional security", "entries": [{"term": "Republic of China", "ipa": "/rɪˌpʌblɪk əv ˈtʃaɪnə/", "pron": "ri-PUB-lik ov CHY-nuh", "fr": "République de Chine", "def": "The official name of Taiwan’s government.", "ex": "The Republic of China governs Taiwan."}, {"term": "one-China policy", "ipa": "/ˌwʌn ˈtʃaɪnə ˈpɒləsi/", "pron": "wun CHY-nuh POL-uh-see", "fr": "politique d’une seule Chine", "def": "A policy recognising only one Chinese government, with varying interpretations.", "ex": "The one-China policy shapes diplomatic relations with Beijing."}, {"term": "one-China principle", "ipa": "/ˌwʌn ˈtʃaɪnə ˈprɪnsəpəl/", "pron": "wun CHY-nuh PRIN-suh-puhl", "fr": "principe d’une seule Chine", "def": "Beijing’s position that Taiwan is part of China.", "ex": "China insists on the one-China principle."}, {"term": "Taiwan Strait", "ipa": "/taɪˈwɑːn streɪt/", "pron": "ty-WAHN strait", "fr": "détroit de Taïwan", "def": "The sea passage between Taiwan and mainland China.", "ex": "The Taiwan Strait is a major geopolitical flashpoint."}, {"term": "cross-strait relations", "ipa": "/ˌkrɒs streɪt rɪˈleɪʃənz/", "pron": "cross-strait ri-LAY-shuhnz", "fr": "relations entre les deux rives du détroit", "def": "Relations between Taiwan and mainland China.", "ex": "Cross-strait relations have become more tense."}, {"term": "strategic ambiguity", "ipa": "/strəˌtiːdʒɪk ˌæmbɪˈɡjuːəti/", "pron": "struh-TEE-jik am-bi-GYOO-uh-tee", "fr": "ambiguïté stratégique", "def": "Deliberate uncertainty about how a state would respond in a crisis.", "ex": "US policy towards Taiwan relies partly on strategic ambiguity."}, {"term": "strategic clarity", "ipa": "/strəˌtiːdʒɪk ˈklærəti/", "pron": "struh-TEE-jik KLARR-uh-tee", "fr": "clarté stratégique", "def": "A clear statement of how a state would respond in a crisis.", "ex": "Some argue for strategic clarity to deter an attack on Taiwan."}, {"term": "reunification", "ipa": "/ˌriːjuːnɪfɪˈkeɪʃən/", "pron": "ree-yoo-ni-fi-KAY-shuhn", "fr": "réunification", "def": "The process of bringing divided territories or peoples under one state.", "ex": "Beijing says reunification with Taiwan is inevitable."}, {"term": "invasion scenario", "ipa": "/ɪnˈveɪʒən sɪˌnɑːriəʊ/", "pron": "in-VAY-zhuhn si-NAH-ree-oh", "fr": "scénario d’invasion", "def": "A possible future involving military invasion.", "ex": "An invasion scenario would have huge global consequences."}, {"term": "blockade", "ipa": "/blɒˈkeɪd/", "pron": "blok-AYD", "fr": "blocus", "def": "An action preventing ships, goods or people from entering or leaving an area.", "ex": "A blockade of Taiwan would disrupt global trade."}, {"term": "South China Sea", "ipa": "/ˌsaʊθ ˈtʃaɪnə siː/", "pron": "south CHY-nuh sea", "fr": "mer de Chine méridionale", "def": "A strategic sea where China and several neighbours have competing claims.", "ex": "The South China Sea is vital for global shipping."}, {"term": "maritime claim", "ipa": "/ˈmærɪtaɪm kleɪm/", "pron": "MARR-i-time claim", "fr": "revendication maritime", "def": "A claim over sea territory or rights.", "ex": "China’s maritime claims are disputed by neighbouring states."}, {"term": "nine-dash line", "ipa": "/ˌnaɪn dæʃ ˈlaɪn/", "pron": "nine-dash line", "fr": "ligne en neuf traits", "def": "China’s disputed line claiming large parts of the South China Sea.", "ex": "The nine-dash line is rejected by several countries."}, {"term": "freedom of navigation", "ipa": "/ˌfriːdəm əv ˌnævɪˈɡeɪʃən/", "pron": "FREE-duhm ov nav-i-GAY-shuhn", "fr": "liberté de navigation", "def": "The right of ships to move through international waters.", "ex": "The US conducts freedom of navigation operations."}, {"term": "island-building", "ipa": "/ˈaɪlənd ˌbɪldɪŋ/", "pron": "EYE-luhnd BIL-ding", "fr": "construction d’îles artificielles", "def": "Creating or expanding islands, often for strategic purposes.", "ex": "Island-building has militarised parts of the South China Sea."}, {"term": "militarisation", "ipa": "/ˌmɪlɪtəraɪˈzeɪʃən/", "pron": "mil-i-tuh-ry-ZAY-shuhn", "fr": "militarisation", "def": "The process of increasing military presence or control.", "ex": "The militarisation of disputed islands has raised tensions."}, {"term": "Indo-Pacific", "ipa": "/ˌɪndəʊ pəˈsɪfɪk/", "pron": "IN-doh puh-SIF-ik", "fr": "Indo-Pacifique", "def": "A strategic region linking the Indian and Pacific Oceans.", "ex": "The Indo-Pacific is central to China containment debates."}, {"term": "containment", "ipa": "/kənˈteɪnmənt/", "pron": "kuhn-TAYN-muhnt", "fr": "endiguement", "def": "A strategy to limit a rival’s expansion or influence.", "ex": "China accuses the US of containment."}, {"term": "encirclement", "ipa": "/ɪnˈsɜːkəlmənt/", "pron": "in-SUR-kuhl-muhnt", "fr": "encerclement", "def": "The feeling or strategy of being surrounded by rivals or hostile forces.", "ex": "Chinese officials often warn against encirclement."}, {"term": "AUKUS", "ipa": "/ˈɔːkəs/", "pron": "AW-kuhs", "fr": "AUKUS", "def": "A security partnership between Australia, the UK and the US.", "ex": "AUKUS is seen by China as part of US-led containment."}, {"term": "Quad", "ipa": "/kwɒd/", "pron": "kwod", "fr": "Quad", "def": "A strategic forum involving the US, India, Japan and Australia.", "ex": "The Quad focuses on Indo-Pacific security."}, {"term": "de-risking", "ipa": "/ˌdiːˈrɪskɪŋ/", "pron": "dee-RISK-ing", "fr": "réduction des risques ; dérisquage", "def": "Reducing risky dependencies without fully cutting ties.", "ex": "The EU prefers de-risking to full decoupling from China."}, {"term": "decoupling", "ipa": "/ˌdiːˈkʌplɪŋ/", "pron": "dee-KUP-ling", "fr": "découplage", "def": "Separating economies or technologies that were previously connected.", "ex": "Full decoupling from China would be extremely costly."}, {"term": "economic dependency", "ipa": "/ˌiːkəˈnɒmɪk dɪˈpendənsi/", "pron": "ee-kuh-NOM-ik di-PEN-duhn-see", "fr": "dépendance économique", "def": "Reliance on another economy for goods, markets or investment.", "ex": "Economic dependency can create political vulnerability."}, {"term": "strategic dependency", "ipa": "/strəˌtiːdʒɪk dɪˈpendənsi/", "pron": "struh-TEE-jik di-PEN-duhn-see", "fr": "dépendance stratégique", "def": "Reliance on another state for critical goods, technology or security.", "ex": "Strategic dependency on China worries European governments."}, {"term": "economic coercion", "ipa": "/ˌiːkəˈnɒmɪk kəʊˈɜːʃən/", "pron": "ee-kuh-NOM-ik koh-UR-shuhn", "fr": "coercition économique", "def": "Use of economic pressure to force political behaviour.", "ex": "China has been accused of economic coercion against smaller states."}, {"term": "trade war", "ipa": "/ˈtreɪd wɔː/", "pron": "trade war", "fr": "guerre commerciale", "def": "A conflict in which countries impose tariffs or trade restrictions on each other.", "ex": "The US-China trade war raised costs for firms and consumers."}, {"term": "tariff", "ipa": "/ˈtærɪf/", "pron": "TAR-if", "fr": "droit de douane", "def": "A tax on imported goods.", "ex": "Tariffs were used in the US-China trade war."}, {"term": "export control", "ipa": "/ˈekspɔːt kənˌtrəʊl/", "pron": "EK-sport kuhn-TROHL", "fr": "contrôle des exportations", "def": "A rule limiting exports of sensitive goods or technology.", "ex": "Export controls restrict China’s access to advanced chips."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed to change behaviour.", "ex": "Sanctions can target officials, firms or sectors."}, {"term": "investment screening", "ipa": "/ɪnˈvestmənt ˈskriːnɪŋ/", "pron": "in-VEST-muhnt SKREEN-ing", "fr": "filtrage des investissements", "def": "Government review of foreign investment for security risks.", "ex": "Investment screening can block strategic acquisitions."}, {"term": "reshoring", "ipa": "/ˌriːˈʃɔːrɪŋ/", "pron": "ree-SHOR-ing", "fr": "relocalisation", "def": "Bringing production back to the home country.", "ex": "Reshoring aims to reduce dependency on China."}, {"term": "friend-shoring", "ipa": "/ˌfrend ˈʃɔːrɪŋ/", "pron": "friend-SHOR-ing", "fr": "relocalisation vers des pays alliés", "def": "Moving supply chains to politically trusted countries.", "ex": "Friend-shoring is part of de-risking strategies."}, {"term": "nearshoring", "ipa": "/ˌnɪəˈʃɔːrɪŋ/", "pron": "NEER-shor-ing", "fr": "délocalisation de proximité", "def": "Moving production closer to the home market.", "ex": "Nearshoring can reduce exposure to geopolitical shocks."}, {"term": "supply-chain resilience", "ipa": "/səˈplaɪ tʃeɪn rɪˈzɪliəns/", "pron": "suh-PLY chayn ri-ZIL-ee-uhns", "fr": "résilience des chaînes d’approvisionnement", "def": "The ability of supply chains to withstand shocks.", "ex": "Supply-chain resilience is a key goal of China policy."}, {"term": "dual circulation", "ipa": "/ˌdjuːəl ˌsɜːkjʊˈleɪʃən/", "pron": "DYOO-uhl sur-kyuh-LAY-shuhn", "fr": "double circulation", "def": "China’s strategy of boosting domestic demand while maintaining global links.", "ex": "Dual circulation aims to reduce external vulnerability."}, {"term": "common prosperity", "ipa": "/ˌkɒmən prɒˈsperəti/", "pron": "KOM-uhn pros-PERR-uh-tee", "fr": "prospérité commune", "def": "A Chinese policy slogan about reducing inequality and sharing growth.", "ex": "Common prosperity has been used to justify regulation of major firms."}, {"term": "property crisis", "ipa": "/ˈprɒpəti ˈkraɪsɪs/", "pron": "PROP-uh-tee KRY-sis", "fr": "crise immobilière", "def": "A crisis linked to debt, falling sales or instability in real estate.", "ex": "China’s property crisis has weakened consumer confidence."}, {"term": "real estate sector", "ipa": "/ˈrɪəl ɪˌsteɪt ˌsektə/", "pron": "REE-uhl i-STATE SEK-tuh", "fr": "secteur immobilier", "def": "The part of the economy involving property and housing.", "ex": "China’s real estate sector has driven growth and debt."}, {"term": "local government debt", "ipa": "/ˌləʊkəl ˈɡʌvənmənt det/", "pron": "LOH-kuhl GUV-uhn-muhnt det", "fr": "dette des collectivités locales", "def": "Debt owed by local authorities.", "ex": "Local government debt is a concern for China’s economy."}, {"term": "ageing population", "ipa": "/ˈeɪdʒɪŋ ˌpɒpjʊˈleɪʃən/", "pron": "AY-jing pop-yuh-LAY-shuhn", "fr": "vieillissement de la population", "def": "A population with a rising share of older people.", "ex": "China faces an ageing population and a shrinking workforce."}, {"term": "demographic decline", "ipa": "/ˌdeməˈɡræfɪk dɪˈklaɪn/", "pron": "dem-uh-GRAF-ik di-KLYN", "fr": "déclin démographique", "def": "A fall or worsening trend in population size or structure.", "ex": "Demographic decline may reduce China’s long-term growth."}, {"term": "middle-income trap", "ipa": "/ˌmɪdəl ˈɪnkʌm træp/", "pron": "MID-uhl IN-kum trap", "fr": "piège du revenu intermédiaire", "def": "A situation where a country struggles to move from middle to high income.", "ex": "China is trying to avoid the middle-income trap."}]}, {"title": "E. De-risking, domestic challenges, climate and high-value verbs", "entries": [{"term": "environmental degradation", "ipa": "/ɪnˌvaɪrənmentəl ˌdeɡrəˈdeɪʃən/", "pron": "in-VY-ruhn-MEN-tuhl deg-ruh-DAY-shuhn", "fr": "dégradation environnementale", "def": "Damage to the environment.", "ex": "Rapid growth caused severe environmental degradation."}, {"term": "air pollution", "ipa": "/ˈeə pəˌluːʃən/", "pron": "air puh-LOO-shuhn", "fr": "pollution de l’air", "def": "Pollution of the air by harmful substances.", "ex": "Air pollution has become a major public concern in China."}, {"term": "carbon emissions", "ipa": "/ˈkɑːbən ɪˌmɪʃənz/", "pron": "KAR-buhn i-MISH-uhnz", "fr": "émissions de carbone", "def": "Greenhouse gas emissions from carbon-based energy.", "ex": "China is the world’s largest emitter of carbon emissions."}, {"term": "coal dependency", "ipa": "/ˈkəʊl dɪˌpendənsi/", "pron": "kohld di-PEN-duhn-see", "fr": "dépendance au charbon", "def": "Reliance on coal for energy.", "ex": "Coal dependency complicates China’s climate commitments."}, {"term": "green technology", "ipa": "/ˌɡriːn tekˈnɒlədʒi/", "pron": "green tek-NOL-uh-jee", "fr": "technologie verte", "def": "Technology designed to reduce environmental harm.", "ex": "China is a leader in some green technologies."}, {"term": "solar panels", "ipa": "/ˈsəʊlə ˌpænəlz/", "pron": "SOH-luh PAN-uhlz", "fr": "panneaux solaires", "def": "Devices that convert sunlight into electricity.", "ex": "Chinese firms dominate global solar panel production."}, {"term": "electric vehicles", "ipa": "/ɪˌlektrɪk ˈviːɪkəlz/", "pron": "i-LEK-trik VEE-i-kuhlz", "fr": "véhicules électriques", "def": "Vehicles powered by electricity.", "ex": "Chinese electric vehicles are increasingly competitive."}, {"term": "battery supply chain", "ipa": "/ˈbætəri səˌplaɪ tʃeɪn/", "pron": "BAT-uh-ree suh-PLY chayn", "fr": "chaîne d’approvisionnement des batteries", "def": "The network producing batteries and their components.", "ex": "China plays a key role in the battery supply chain."}, {"term": "climate diplomacy", "ipa": "/ˈklaɪmət dɪˌpləʊməsi/", "pron": "KLY-muht di-PLOH-muh-see", "fr": "diplomatie climatique", "def": "Diplomacy focused on climate cooperation and commitments.", "ex": "US-China climate diplomacy is vital for global climate policy."}, {"term": "to rise as a global power", "ipa": "/raɪz əz ə ˌɡləʊbəl ˈpaʊə/", "pron": "ryze az uh GLOH-buhl POW-uh", "fr": "s’imposer comme puissance mondiale", "def": "To become a major actor in world politics.", "ex": "China has risen as a global power."}, {"term": "to challenge US dominance", "ipa": "/ˈtʃælɪndʒ ˌjuː es ˈdɒmɪnəns/", "pron": "CHAL-inj yoo-ess DOM-i-nuhns", "fr": "contester la domination américaine", "def": "To contest American leadership or influence.", "ex": "China’s rise challenges US dominance."}, {"term": "to reshape the world order", "ipa": "/ˌriːˈʃeɪp ðə ˈwɜːld ˌɔːdə/", "pron": "ree-SHAYP thuh world OR-duh", "fr": "remodeler l’ordre mondial", "def": "To change the structure of global power and rules.", "ex": "China seeks to reshape the world order."}, {"term": "to project power", "ipa": "/prəˈdʒekt ˈpaʊə/", "pron": "pruh-JEKT POW-uh", "fr": "projeter sa puissance", "def": "To extend military, economic or political influence abroad.", "ex": "China uses trade, infrastructure and naval power to project power."}, {"term": "to assert sovereignty", "ipa": "/əˈsɜːt ˈsɒvrənti/", "pron": "uh-SURT SOV-ruhn-tee", "fr": "affirmer sa souveraineté", "def": "To insist on a state’s authority over territory or policy.", "ex": "Beijing asserts sovereignty over Taiwan and the South China Sea."}, {"term": "to tighten control", "ipa": "/ˈtaɪtən kənˈtrəʊl/", "pron": "TY-tuhn kuhn-TROHL", "fr": "renforcer le contrôle", "def": "To increase political or social control.", "ex": "The party has tightened control over civil society."}, {"term": "to censor information", "ipa": "/ˈsensər ˌɪnfəˈmeɪʃən/", "pron": "SEN-suh in-fuh-MAY-shuhn", "fr": "censurer l’information", "def": "To suppress or control information.", "ex": "The state can censor information online."}, {"term": "to monitor citizens", "ipa": "/ˈmɒnɪtə ˈsɪtɪzənz/", "pron": "MON-i-tuh SIT-i-zuhnz", "fr": "surveiller les citoyens", "def": "To watch or track citizens.", "ex": "Digital tools can monitor citizens."}, {"term": "to expand influence", "ipa": "/ɪkˈspænd ˈɪnfluəns/", "pron": "ik-SPAND IN-floo-uhns", "fr": "étendre son influence", "def": "To increase one’s ability to shape decisions or opinions.", "ex": "China has expanded influence through trade and investment."}, {"term": "to build infrastructure", "ipa": "/bɪld ˈɪnfrəˌstrʌktʃə/", "pron": "bild IN-fruh-struk-chuh", "fr": "construire des infrastructures", "def": "To construct essential systems such as ports, roads or railways.", "ex": "BRI projects build infrastructure abroad."}, {"term": "to create dependency", "ipa": "/kriˈeɪt dɪˈpendənsi/", "pron": "kree-AYT di-PEN-duhn-see", "fr": "créer une dépendance", "def": "To make another actor reliant on oneself.", "ex": "Loans and supply chains can create dependency."}, {"term": "to de-risk supply chains", "ipa": "/ˌdiːˈrɪsk səˈplaɪ tʃeɪnz/", "pron": "dee-RISK suh-PLY chaynz", "fr": "réduire les risques dans les chaînes d’approvisionnement", "def": "To reduce risky reliance in supply chains.", "ex": "Western governments seek to de-risk supply chains."}, {"term": "to decouple from China", "ipa": "/ˌdiːˈkʌpəl frəm ˈtʃaɪnə/", "pron": "dee-KUP-uhl from CHY-nuh", "fr": "se découpler de la Chine", "def": "To separate economic or technological links with China.", "ex": "Full decoupling from China would be difficult."}, {"term": "to impose export controls", "ipa": "/ɪmˈpəʊz ˈekspɔːt kənˌtrəʊlz/", "pron": "im-POHZ EK-sport kuhn-TROHLZ", "fr": "imposer des contrôles à l’exportation", "def": "To restrict exports of sensitive goods or technology.", "ex": "The US imposed export controls on advanced chips."}, {"term": "to defend human rights", "ipa": "/dɪˈfend ˌhjuːmən ˈraɪts/", "pron": "di-FEND HYOO-muhn rites", "fr": "défendre les droits humains", "def": "To protect basic rights and freedoms.", "ex": "Governments face pressure to defend human rights in China policy."}, {"term": "to avoid confrontation", "ipa": "/əˈvɔɪd ˌkɒnfrənˈteɪʃən/", "pron": "uh-VOYD kon-fruhn-TAY-shuhn", "fr": "éviter la confrontation", "def": "To prevent open conflict or hostility.", "ex": "Diplomats try to avoid confrontation while managing rivalry."}, {"term": "to manage rivalry", "ipa": "/ˈmænɪdʒ ˈraɪvəlri/", "pron": "MAN-ij RY-vuhl-ree", "fr": "gérer la rivalité", "def": "To control competition so it does not become conflict.", "ex": "The US and China must manage rivalry responsibly."}, {"term": "to cooperate on climate change", "ipa": "/kəʊˈɒpəreɪt ɒn ˈklaɪmət tʃeɪndʒ/", "pron": "koh-OP-uh-rayt on KLY-muht chaynj", "fr": "coopérer sur le changement climatique", "def": "To work together on climate policy.", "ex": "Even rivals need to cooperate on climate change."}]}]}, {"id": "p6c55", "part": 6, "chapter": 55, "title": "Russia", "file": "cpge_vocab_part6_chapter55_russia_premium.html", "count": 140, "sections": [{"title": "A. Core Russia, regime and domestic politics", "entries": [{"term": "Russia", "ipa": "/ˈrʌʃə/", "pron": "RUSH-uh", "fr": "Russie", "def": "A major Eurasian state with significant military, energy and geopolitical power.", "ex": "Russia remains a central actor in European and global security."}, {"term": "Russian Federation", "ipa": "/ˌrʌʃən ˌfedəˈreɪʃən/", "pron": "RUSH-uhn fed-uh-RAY-shuhn", "fr": "Fédération de Russie", "def": "The official name of Russia.", "ex": "The Russian Federation inherited much of the Soviet Union’s international status."}, {"term": "Kremlin", "ipa": "/ˈkremlɪn/", "pron": "KREM-lin", "fr": "Kremlin", "def": "The seat of Russian political power; often used to mean the Russian government.", "ex": "The Kremlin controls much of Russia’s political system."}, {"term": "Moscow", "ipa": "/ˈmɒskəʊ/", "pron": "MOS-koh", "fr": "Moscou", "def": "Russia’s capital; often used as shorthand for the Russian government.", "ex": "Moscow rejected the accusations."}, {"term": "Vladimir Putin", "ipa": "/ˌvlædɪmɪə ˈpuːtɪn/", "pron": "VLAD-i-meer POO-tin", "fr": "Vladimir Poutine", "def": "Russia’s long-serving president and dominant political figure.", "ex": "Vladimir Putin has reshaped Russia’s domestic politics and foreign policy."}, {"term": "Putinism", "ipa": "/ˈpuːtɪnɪzəm/", "pron": "POO-tin-iz-uhm", "fr": "poutinisme", "def": "A term describing Russia’s political system under Vladimir Putin.", "ex": "Putinism combines authoritarianism, nationalism and state control."}, {"term": "authoritarianism", "ipa": "/ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme", "def": "A system of government with limited political freedoms and strong central control.", "ex": "Russian authoritarianism has intensified over time."}, {"term": "authoritarian regime", "ipa": "/ɔːˌθɒrɪˈteəriən reɪˈʒiːm/", "pron": "aw-thor-i-TAIR-ee-uhn ray-ZHEEM", "fr": "régime autoritaire", "def": "A government that restricts opposition, pluralism and civil liberties.", "ex": "Many analysts describe Russia as an authoritarian regime."}, {"term": "managed democracy", "ipa": "/ˌmænɪdʒd dɪˈmɒkrəsi/", "pron": "MAN-ijd di-MOK-ruh-see", "fr": "démocratie dirigée", "def": "A political system with elections but heavy state control over outcomes.", "ex": "Russia is often described as a managed democracy."}, {"term": "illiberal democracy", "ipa": "/ɪˌlɪbərəl dɪˈmɒkrəsi/", "pron": "i-LIB-uh-ruhl di-MOK-ruh-see", "fr": "démocratie illibérale", "def": "A system with elections but weak checks, rights and freedoms.", "ex": "The term illiberal democracy does not fully capture Russia’s authoritarian drift."}, {"term": "centralised power", "ipa": "/ˈsentrəlaɪzd ˈpaʊə/", "pron": "SEN-truh-lyzd POW-uh", "fr": "pouvoir centralisé", "def": "Power concentrated in a central authority or leader.", "ex": "Centralised power allows the Kremlin to control institutions."}, {"term": "power vertical", "ipa": "/ˈpaʊə ˌvɜːtɪkəl/", "pron": "POW-uh VUR-ti-kuhl", "fr": "verticale du pouvoir", "def": "A term for Russia’s top-down system of political authority.", "ex": "The power vertical weakened regional autonomy."}, {"term": "oligarch", "ipa": "/ˈɒlɪɡɑːk/", "pron": "OL-i-gark", "fr": "oligarque", "def": "A very wealthy business figure with political influence.", "ex": "Russian oligarchs often depend on political connections."}, {"term": "oligarchy", "ipa": "/ˈɒlɪɡɑːki/", "pron": "OL-i-gar-kee", "fr": "oligarchie", "def": "A system where a small wealthy elite holds power.", "ex": "Post-Soviet privatisation created a powerful oligarchy."}, {"term": "elite capture", "ipa": "/ɪˌliːt ˈkæptʃə/", "pron": "i-LEET KAP-chuh", "fr": "captation par les élites", "def": "Control of institutions or resources by a small elite.", "ex": "Elite capture undermines accountability."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Abuse of power for private gain.", "ex": "Corruption is a major issue in Russian politics and business."}, {"term": "kleptocracy", "ipa": "/klepˈtɒkrəsi/", "pron": "klep-TOK-ruh-see", "fr": "kleptocratie", "def": "A system where leaders use power to steal national wealth.", "ex": "Critics describe Russia as a kleptocracy."}, {"term": "patronage network", "ipa": "/ˈpætrənɪdʒ ˌnetwɜːk/", "pron": "PAT-ruh-nij NET-work", "fr": "réseau clientéliste", "def": "A system of favours, loyalty and rewards linking powerful actors.", "ex": "Patronage networks help maintain political loyalty."}, {"term": "security services", "ipa": "/sɪˈkjʊərəti ˈsɜːvɪsɪz/", "pron": "si-KYOOR-uh-tee SUR-vis-iz", "fr": "services de sécurité", "def": "Agencies responsible for intelligence, surveillance and internal security.", "ex": "The security services play a central role in Russia."}, {"term": "FSB", "ipa": "/ˌef es ˈbiː/", "pron": "eff-ess-bee", "fr": "FSB", "def": "Russia’s Federal Security Service, successor to parts of the KGB.", "ex": "The FSB is central to internal security."}, {"term": "KGB", "ipa": "/ˌkeɪ dʒiː ˈbiː/", "pron": "kay-jee-bee", "fr": "KGB", "def": "The Soviet intelligence and security agency.", "ex": "Many figures in Putin’s circle have KGB backgrounds."}, {"term": "siloviki", "ipa": "/ˌsiːləˈviːki/", "pron": "see-luh-VEE-kee", "fr": "siloviki", "def": "Powerful Russian officials from security, military or intelligence backgrounds.", "ex": "The siloviki have gained influence in Russian politics."}, {"term": "state propaganda", "ipa": "/ˌsteɪt ˌprɒpəˈɡændə/", "pron": "state prop-uh-GAN-duh", "fr": "propagande d’État", "def": "Government-controlled information designed to influence opinion.", "ex": "State propaganda shapes public perceptions of the war."}, {"term": "state media", "ipa": "/ˌsteɪt ˈmiːdiə/", "pron": "state MEE-dee-uh", "fr": "médias d’État", "def": "Media controlled or strongly influenced by the government.", "ex": "Russian state media promotes the Kremlin’s narrative."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of information and expression.", "ex": "Censorship has increased since the invasion of Ukraine."}, {"term": "dissent", "ipa": "/dɪˈsent/", "pron": "di-SENT", "fr": "dissidence ; contestation", "def": "Public disagreement with official policy or authority.", "ex": "Dissent is often punished in authoritarian systems."}, {"term": "political opposition", "ipa": "/pəˌlɪtɪkəl ˌɒpəˈzɪʃən/", "pron": "puh-LIT-i-kuhl op-uh-ZISH-uhn", "fr": "opposition politique", "def": "Parties, movements or figures opposing the government.", "ex": "The political opposition has been weakened by repression."}, {"term": "crackdown", "ipa": "/ˈkrækdaʊn/", "pron": "KRAK-down", "fr": "répression", "def": "Strong official action to stop dissent or protest.", "ex": "The crackdown on civil society intensified."}, {"term": "repression", "ipa": "/rɪˈpreʃən/", "pron": "ri-PRESH-uhn", "fr": "répression", "def": "Forceful suppression of opposition, rights or freedoms.", "ex": "Repression makes independent politics extremely difficult."}, {"term": "political prisoner", "ipa": "/pəˌlɪtɪkəl ˈprɪzənə/", "pron": "puh-LIT-i-kuhl PRIZ-uh-nuh", "fr": "prisonnier politique", "def": "A person imprisoned for political reasons.", "ex": "Human-rights groups denounce the detention of political prisoners."}, {"term": "civil society", "ipa": "/ˌsɪvəl səˈsaɪəti/", "pron": "SIV-uhl suh-SY-uh-tee", "fr": "société civile", "def": "Independent organisations and groups outside the state and business.", "ex": "Civil society faces severe restrictions in Russia."}, {"term": "foreign agent law", "ipa": "/ˌfɒrən ˈeɪdʒənt lɔː/", "pron": "FOR-uhn AY-juhnt law", "fr": "loi sur les agents étrangers", "def": "A law labelling some organisations or individuals as foreign agents.", "ex": "The foreign agent law has been used to pressure NGOs and journalists."}]}, {"title": "B. Geopolitical worldview and the post-Soviet space", "entries": [{"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "A state’s authority to govern itself and control its territory.", "ex": "Russia often invokes sovereignty to reject Western criticism."}, {"term": "territorial integrity", "ipa": "/ˌterɪˈtɔːriəl ɪnˈteɡrəti/", "pron": "terr-i-TOR-ee-uhl in-TEG-ruh-tee", "fr": "intégrité territoriale", "def": "The principle that a state’s borders should not be violated.", "ex": "The invasion violated Ukraine’s territorial integrity."}, {"term": "sphere of influence", "ipa": "/ˌsfɪər əv ˈɪnfluəns/", "pron": "sfeer ov IN-floo-uhns", "fr": "sphère d’influence", "def": "A region where a powerful state seeks dominant influence.", "ex": "Russia seeks influence over parts of the former Soviet space."}, {"term": "near abroad", "ipa": "/ˌnɪər əˈbrɔːd/", "pron": "near uh-BRAWD", "fr": "étranger proche", "def": "Russian term for former Soviet republics near Russia.", "ex": "Moscow sees the near abroad as strategically vital."}, {"term": "post-Soviet space", "ipa": "/ˌpəʊst ˈsəʊviət speɪs/", "pron": "post SOH-vee-uht space", "fr": "espace post-soviétique", "def": "The region of former Soviet republics after 1991.", "ex": "The post-Soviet space remains a zone of geopolitical tension."}, {"term": "Eurasia", "ipa": "/jʊəˈreɪʒə/", "pron": "yoo-RAY-zhuh", "fr": "Eurasie", "def": "The combined landmass of Europe and Asia, often used in geopolitical discourse.", "ex": "Russia presents itself as a Eurasian power."}, {"term": "Eurasianism", "ipa": "/jʊəˈreɪʒənɪzəm/", "pron": "yoo-RAY-zhuh-niz-uhm", "fr": "eurasisme", "def": "An ideology emphasising Russia’s distinct Eurasian identity and destiny.", "ex": "Eurasianism rejects Western liberal universalism."}, {"term": "imperial nostalgia", "ipa": "/ɪmˌpɪəriəl nɒˈstældʒə/", "pron": "im-PEER-ee-uhl nos-TAL-juh", "fr": "nostalgie impériale", "def": "Longing for the power or status of a former empire.", "ex": "Imperial nostalgia shapes some Russian nationalist discourse."}, {"term": "Russian nationalism", "ipa": "/ˌrʌʃən ˈnæʃənəlɪzəm/", "pron": "RUSH-uhn NASH-uh-nuh-liz-uhm", "fr": "nationalisme russe", "def": "Strong identification with Russian nationhood, power and identity.", "ex": "Russian nationalism has been used to justify foreign policy claims."}, {"term": "great-power status", "ipa": "/ˌɡreɪt ˈpaʊə ˈsteɪtəs/", "pron": "great POW-uh STAY-tuhs", "fr": "statut de grande puissance", "def": "Recognition as a major global power.", "ex": "Russia seeks to preserve great-power status."}, {"term": "revisionist power", "ipa": "/rɪˈvɪʒənɪst ˈpaʊə/", "pron": "ri-VIZH-uh-nist POW-uh", "fr": "puissance révisionniste", "def": "A state seeking to change the existing international order.", "ex": "Russia is often described as a revisionist power."}, {"term": "rules-based order", "ipa": "/ˌruːlz beɪst ˈɔːdə/", "pron": "roolz-bayst OR-duh", "fr": "ordre fondé sur des règles", "def": "An international system based on agreed rules rather than force.", "ex": "Russia is accused of undermining the rules-based order."}, {"term": "multipolar world", "ipa": "/ˌmʌltiˈpəʊlə wɜːld/", "pron": "MUL-tee-POH-luh world", "fr": "monde multipolaire", "def": "An international order with several major centres of power.", "ex": "Russia calls for a multipolar world to challenge US dominance."}, {"term": "anti-Western rhetoric", "ipa": "/ˌænti ˈwestən ˈretərɪk/", "pron": "AN-tee WES-tuhn RET-uh-rik", "fr": "rhétorique anti-occidentale", "def": "Language attacking Western policies, values or institutions.", "ex": "Anti-Western rhetoric is common in Russian official discourse."}, {"term": "Western encirclement", "ipa": "/ˌwestən ɪnˈsɜːkəlmənt/", "pron": "WES-tuhn in-SUR-kuhl-muhnt", "fr": "encerclement occidental", "def": "The idea that the West is surrounding or threatening Russia.", "ex": "The Kremlin uses the narrative of Western encirclement."}, {"term": "NATO enlargement", "ipa": "/ˌneɪtəʊ ɪnˈlɑːdʒmənt/", "pron": "NAY-toh in-LARJ-muhnt", "fr": "élargissement de l’OTAN", "def": "The expansion of NATO through new member states.", "ex": "Russia has long opposed NATO enlargement."}, {"term": "security dilemma", "ipa": "/sɪˈkjʊərəti dɪˌlemə/", "pron": "si-KYOOR-uh-tee di-LEM-uh", "fr": "dilemme de sécurité", "def": "A situation where one state’s defensive actions make another feel threatened.", "ex": "NATO and Russia interpret the security dilemma differently."}, {"term": "Ukraine", "ipa": "/juːˈkreɪn/", "pron": "yoo-KRAYN", "fr": "Ukraine", "def": "A sovereign European state invaded by Russia in 2022.", "ex": "Ukraine is central to Russia-West tensions."}, {"term": "Ukraine war", "ipa": "/juːˈkreɪn wɔː/", "pron": "yoo-KRAYN war", "fr": "guerre en Ukraine", "def": "The war following Russia’s full-scale invasion of Ukraine.", "ex": "The Ukraine war transformed European security."}, {"term": "full-scale invasion", "ipa": "/ˌfʊl skeɪl ɪnˈveɪʒən/", "pron": "full-scale in-VAY-zhuhn", "fr": "invasion à grande échelle", "def": "A large military invasion involving major forces across multiple fronts.", "ex": "Russia launched a full-scale invasion of Ukraine in 2022."}, {"term": "annexation", "ipa": "/ˌænekˈseɪʃən/", "pron": "an-ek-SAY-shuhn", "fr": "annexion", "def": "The incorporation of territory into another state, often by force.", "ex": "The annexation of Crimea was widely condemned."}, {"term": "Crimea", "ipa": "/kraɪˈmɪə/", "pron": "kry-MEER-uh", "fr": "Crimée", "def": "A peninsula annexed by Russia from Ukraine in 2014.", "ex": "Crimea remains internationally recognised by many states as part of Ukraine."}, {"term": "Donbas", "ipa": "/dɒnˈbɑːs/", "pron": "don-BASS", "fr": "Donbass", "def": "A region in eastern Ukraine including Donetsk and Luhansk.", "ex": "The Donbas has been a major battlefield."}]}, {"title": "C. Ukraine war, hybrid warfare and military power", "entries": [{"term": "separatist", "ipa": "/ˈsepərətɪst/", "pron": "SEP-uh-ruh-tist", "fr": "séparatiste", "def": "A person or group seeking separation from a state.", "ex": "Russia backed separatist forces in eastern Ukraine."}, {"term": "proxy force", "ipa": "/ˈprɒksi fɔːs/", "pron": "PROK-see force", "fr": "force par procuration", "def": "A force supported by another power to fight indirectly.", "ex": "Proxy forces can hide direct responsibility."}, {"term": "hybrid warfare", "ipa": "/ˌhaɪbrɪd ˈwɔːfeə/", "pron": "HY-brid WAR-fair", "fr": "guerre hybride", "def": "Conflict combining military force, cyberattacks, disinformation and political pressure.", "ex": "Russia is often associated with hybrid warfare."}, {"term": "grey-zone tactics", "ipa": "/ˌɡreɪ zəʊn ˈtæktɪks/", "pron": "gray-zone TAK-tiks", "fr": "tactiques de zone grise", "def": "Actions below the threshold of open war.", "ex": "Grey-zone tactics create ambiguity and confusion."}, {"term": "little green men", "ipa": "/ˌlɪtəl ɡriːn ˈmen/", "pron": "LIT-uhl green men", "fr": "petits hommes verts", "def": "Unmarked soldiers associated with Russia’s seizure of Crimea.", "ex": "The phrase little green men symbolised plausible deniability."}, {"term": "plausible deniability", "ipa": "/ˌplɔːzəbəl dɪˌnaɪəˈbɪləti/", "pron": "PLAW-zuh-buhl di-ny-uh-BIL-uh-tee", "fr": "déni plausible", "def": "The ability to deny responsibility because evidence is ambiguous.", "ex": "Hybrid operations often rely on plausible deniability."}, {"term": "war of attrition", "ipa": "/ˌwɔːr əv əˈtrɪʃən/", "pron": "war ov uh-TRISH-uhn", "fr": "guerre d’usure", "def": "A conflict where each side tries to exhaust the other over time.", "ex": "The conflict has become a brutal war of attrition."}, {"term": "mobilisation", "ipa": "/ˌməʊbɪlaɪˈzeɪʃən/", "pron": "moh-bi-ly-ZAY-shuhn", "fr": "mobilisation", "def": "Preparing troops, resources or society for war.", "ex": "Mobilisation revealed tensions inside Russian society."}, {"term": "conscription", "ipa": "/kənˈskrɪpʃən/", "pron": "kuhn-SKRIP-shuhn", "fr": "conscription", "def": "Compulsory military service.", "ex": "Conscription can be politically sensitive."}, {"term": "mercenary", "ipa": "/ˈmɜːsənəri/", "pron": "MUR-suh-nuh-ree", "fr": "mercenaire", "def": "A fighter hired to fight for money.", "ex": "Mercenary groups have operated in Russian-linked conflicts."}, {"term": "Wagner Group", "ipa": "/ˈvæɡnə ɡruːp/", "pron": "VAG-nuh group", "fr": "groupe Wagner", "def": "A Russian private military company linked to conflicts abroad.", "ex": "The Wagner Group became a symbol of Russian shadow warfare."}, {"term": "private military company", "ipa": "/ˌpraɪvət ˈmɪlɪtəri ˈkʌmpəni/", "pron": "PRY-vuht MIL-i-tuh-ree KUM-puh-nee", "fr": "société militaire privée", "def": "A private company providing military or security services.", "ex": "Private military companies complicate accountability."}, {"term": "war crime", "ipa": "/ˈwɔː kraɪm/", "pron": "war kryme", "fr": "crime de guerre", "def": "A serious violation of the laws of war.", "ex": "Alleged war crimes require investigation and prosecution."}, {"term": "civilian casualties", "ipa": "/səˌvɪliən ˈkæʒuəltiz/", "pron": "suh-VIL-yuhn KAZH-oo-uhl-teez", "fr": "victimes civiles", "def": "Civilian deaths or injuries caused by conflict.", "ex": "Civilian casualties have shaped international reactions."}, {"term": "energy superpower", "ipa": "/ˈenədʒi ˈsuːpəpaʊə/", "pron": "EN-uh-jee SOO-puh-pow-uh", "fr": "superpuissance énergétique", "def": "A country with major influence due to energy resources.", "ex": "Russia has long been an energy superpower."}, {"term": "oil exporter", "ipa": "/ˈɔɪl ekˌspɔːtə/", "pron": "oil ek-SPORT-uh", "fr": "exportateur de pétrole", "def": "A country that sells oil abroad.", "ex": "Russia is a major oil exporter."}, {"term": "gas supplier", "ipa": "/ˈɡæs səˌplaɪə/", "pron": "gas suh-PLY-uh", "fr": "fournisseur de gaz", "def": "A country or company providing natural gas.", "ex": "Russia was a major gas supplier to Europe."}, {"term": "natural gas", "ipa": "/ˌnætʃərəl ˈɡæs/", "pron": "NAT-chuh-ruhl gas", "fr": "gaz naturel", "def": "Gas used as an energy source for heating, electricity and industry.", "ex": "Natural gas became a geopolitical weapon."}, {"term": "pipeline", "ipa": "/ˈpaɪplaɪn/", "pron": "PIPE-line", "fr": "gazoduc ; oléoduc", "def": "A pipe system transporting oil or gas over long distances.", "ex": "Pipelines link energy markets and geopolitics."}, {"term": "Nord Stream", "ipa": "/ˌnɔːd ˈstriːm/", "pron": "nord stream", "fr": "Nord Stream", "def": "Gas pipelines connecting Russia and Germany under the Baltic Sea.", "ex": "Nord Stream became highly controversial after the Ukraine crisis."}, {"term": "energy dependency", "ipa": "/ˈenədʒi dɪˌpendənsi/", "pron": "EN-uh-jee di-PEN-duhn-see", "fr": "dépendance énergétique", "def": "Reliance on another country for energy supplies.", "ex": "European energy dependency on Russia became a strategic vulnerability."}, {"term": "energy blackmail", "ipa": "/ˈenədʒi ˈblækmeɪl/", "pron": "EN-uh-jee BLAK-mayl", "fr": "chantage énergétique", "def": "Using energy supplies as political pressure.", "ex": "Critics accused Russia of energy blackmail."}, {"term": "weaponisation of energy", "ipa": "/ˌwepənaɪˈzeɪʃən əv ˈenədʒi/", "pron": "wep-uh-ny-ZAY-shuhn ov EN-uh-jee", "fr": "instrumentalisation de l’énergie", "def": "Use of energy supplies as a geopolitical weapon.", "ex": "The weaponisation of energy accelerated Europe’s diversification."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy.", "ex": "Energy security became central to European policy."}, {"term": "fossil fuels", "ipa": "/ˌfɒsəl ˈfjuːəlz/", "pron": "FOS-uhl FYOO-uhlz", "fr": "énergies fossiles", "def": "Coal, oil and gas used for energy.", "ex": "Russia’s economy depends heavily on fossil fuels."}, {"term": "resource curse", "ipa": "/rɪˈsɔːs kɜːs/", "pron": "ri-SORSS curse", "fr": "malédiction des ressources", "def": "The paradox that resource-rich countries may suffer from corruption or poor governance.", "ex": "The resource curse can weaken institutions."}, {"term": "rentier state", "ipa": "/ˈrɒntieɪ steɪt/", "pron": "RON-tee-ay state", "fr": "État rentier", "def": "A state relying heavily on income from natural resources.", "ex": "Russia has features of a rentier state."}]}, {"title": "D. Energy, sanctions, economy and international isolation", "entries": [{"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed to change behaviour.", "ex": "Sanctions targeted Russian banks, firms and officials."}, {"term": "economic sanctions", "ipa": "/ˌiːkəˈnɒmɪk ˈsæŋkʃənz/", "pron": "ee-kuh-NOM-ik SANK-shuhnz", "fr": "sanctions économiques", "def": "Economic restrictions imposed on a state, company or individual.", "ex": "Economic sanctions aim to weaken Russia’s war effort."}, {"term": "financial sanctions", "ipa": "/faɪˌnænʃəl ˈsæŋkʃənz/", "pron": "fy-NAN-shuhl SANK-shuhnz", "fr": "sanctions financières", "def": "Sanctions targeting banks, assets or financial transactions.", "ex": "Financial sanctions limited Russia’s access to global finance."}, {"term": "asset freeze", "ipa": "/ˈæset friːz/", "pron": "AS-et freez", "fr": "gel des avoirs", "def": "A measure preventing someone from using assets.", "ex": "Several oligarchs faced asset freezes."}, {"term": "travel ban", "ipa": "/ˈtrævəl bæn/", "pron": "TRAV-uhl ban", "fr": "interdiction de voyager", "def": "A restriction preventing someone from travelling.", "ex": "Officials were placed under travel bans."}, {"term": "export control", "ipa": "/ˈekspɔːt kənˌtrəʊl/", "pron": "EK-sport kuhn-TROHL", "fr": "contrôle des exportations", "def": "Rules restricting exports of sensitive goods or technology.", "ex": "Export controls targeted advanced technology."}, {"term": "technology embargo", "ipa": "/tekˈnɒlədʒi emˌbɑːɡəʊ/", "pron": "tek-NOL-uh-jee em-BAR-goh", "fr": "embargo technologique", "def": "A ban or restriction on technology exports.", "ex": "A technology embargo can limit military production."}, {"term": "price cap", "ipa": "/ˈpraɪs kæp/", "pron": "price kap", "fr": "plafonnement des prix", "def": "A limit on the price at which something can be sold.", "ex": "The oil price cap aimed to reduce Russian revenue."}, {"term": "sanctions evasion", "ipa": "/ˈsæŋkʃənz ɪˌveɪʒən/", "pron": "SANK-shuhnz i-VAY-zhuhn", "fr": "contournement des sanctions", "def": "Avoiding or bypassing sanctions.", "ex": "Sanctions evasion often uses third countries and shell companies."}, {"term": "shadow fleet", "ipa": "/ˈʃædəʊ fliːt/", "pron": "SHAD-oh fleet", "fr": "flotte fantôme", "def": "Tankers used to transport sanctioned oil outside normal systems.", "ex": "Russia’s shadow fleet helps bypass oil restrictions."}, {"term": "war economy", "ipa": "/ˈwɔːr iˌkɒnəmi/", "pron": "war i-KON-uh-mee", "fr": "économie de guerre", "def": "An economy reorganised to support war production.", "ex": "Russia has shifted towards a war economy."}, {"term": "import substitution", "ipa": "/ˈɪmpɔːt ˌsʌbstɪˈtjuːʃən/", "pron": "IM-port sub-sti-TYOO-shuhn", "fr": "substitution aux importations", "def": "Replacing imported goods with domestic production.", "ex": "Import substitution aims to reduce dependence on Western goods."}, {"term": "ruble", "ipa": "/ˈruːbəl/", "pron": "ROO-buhl", "fr": "rouble", "def": "Russia’s currency.", "ex": "The ruble is affected by sanctions, energy revenue and capital controls."}, {"term": "capital flight", "ipa": "/ˈkæpɪtəl flaɪt/", "pron": "KAP-i-tuhl flyt", "fr": "fuite des capitaux", "def": "Large movement of money out of a country.", "ex": "Capital flight can signal economic distrust."}, {"term": "brain drain", "ipa": "/ˈbreɪn dreɪn/", "pron": "brain drain", "fr": "fuite des cerveaux", "def": "Emigration of educated or skilled people.", "ex": "War and repression contributed to brain drain."}, {"term": "demographic decline", "ipa": "/ˌdeməˈɡræfɪk dɪˈklaɪn/", "pron": "dem-uh-GRAF-ik di-KLYN", "fr": "déclin démographique", "def": "A worsening population trend, often linked to ageing or falling birth rates.", "ex": "Demographic decline is a long-term challenge for Russia."}, {"term": "international isolation", "ipa": "/ˌɪntəˈnæʃənəl ˌaɪsəˈleɪʃən/", "pron": "IN-tuh-NASH-uh-nuhl eye-suh-LAY-shuhn", "fr": "isolement international", "def": "A situation where a country is cut off diplomatically or economically.", "ex": "Sanctions increased Russia’s international isolation from the West."}, {"term": "pariah state", "ipa": "/pəˈraɪə steɪt/", "pron": "puh-RY-uh state", "fr": "État paria", "def": "A state widely condemned and isolated by other countries.", "ex": "Some Western leaders describe Russia as a pariah state."}, {"term": "strategic partnership", "ipa": "/strəˌtiːdʒɪk ˈpɑːtnəʃɪp/", "pron": "struh-TEE-jik PART-nuh-ship", "fr": "partenariat stratégique", "def": "A long-term relationship based on shared strategic interests.", "ex": "Russia has deepened its strategic partnership with China."}, {"term": "China-Russia relations", "ipa": "/ˌtʃaɪnə ˈrʌʃə rɪˈleɪʃənz/", "pron": "CHY-nuh RUSH-uh ri-LAY-shuhnz", "fr": "relations sino-russes", "def": "Relations between China and Russia.", "ex": "China-Russia relations are shaped by shared opposition to US dominance."}, {"term": "Global South", "ipa": "/ˌɡləʊbəl ˈsaʊθ/", "pron": "GLOH-buhl south", "fr": "Sud global", "def": "Less wealthy countries, often in Africa, Asia and Latin America.", "ex": "Russia seeks support or neutrality in the Global South."}, {"term": "BRICS", "ipa": "/brɪks/", "pron": "briks", "fr": "BRICS", "def": "A grouping originally including Brazil, Russia, India, China and South Africa, later expanded.", "ex": "Russia uses BRICS to show it is not globally isolated."}, {"term": "United Nations Security Council", "ipa": "/juːˌnaɪtɪd ˈneɪʃənz sɪˈkjʊərəti ˈkaʊnsəl/", "pron": "yoo-NY-tid NAY-shuhnz si-KYOOR-uh-tee KOWN-suhl", "fr": "Conseil de sécurité de l’ONU", "def": "The UN body responsible for peace and security.", "ex": "Russia has a permanent seat on the UN Security Council."}, {"term": "veto power", "ipa": "/ˈviːtəʊ ˈpaʊə/", "pron": "VEE-toh POW-uh", "fr": "droit de veto", "def": "The power to block a decision.", "ex": "Russia’s veto power limits Security Council action."}, {"term": "nuclear power", "ipa": "/ˌnjuːkliə ˈpaʊə/", "pron": "NYOO-klee-uh POW-uh", "fr": "puissance nucléaire", "def": "A state possessing nuclear weapons or nuclear energy capability.", "ex": "Russia is a major nuclear power."}, {"term": "nuclear arsenal", "ipa": "/ˌnjuːkliə ˈɑːsənəl/", "pron": "NYOO-klee-uh AR-suh-nuhl", "fr": "arsenal nucléaire", "def": "A country’s stock of nuclear weapons.", "ex": "Russia has one of the world’s largest nuclear arsenals."}, {"term": "nuclear deterrence", "ipa": "/ˌnjuːkliə dɪˈterəns/", "pron": "NYOO-klee-uh di-TERR-uhns", "fr": "dissuasion nucléaire", "def": "Preventing attack through the threat of nuclear retaliation.", "ex": "Nuclear deterrence shapes Russia’s security policy."}, {"term": "nuclear sabre-rattling", "ipa": "/ˌnjuːkliə ˈseɪbə ˌrætlɪŋ/", "pron": "NYOO-klee-uh SAY-buh RAT-ling", "fr": "menaces nucléaires ; agitation nucléaire", "def": "Threatening language about possible nuclear use.", "ex": "Nuclear sabre-rattling is used to intimidate opponents."}, {"term": "arms control", "ipa": "/ˈɑːmz kənˌtrəʊl/", "pron": "armz kuhn-TROHL", "fr": "maîtrise des armements", "def": "Agreements limiting weapons or military capabilities.", "ex": "Arms control between Russia and the US has weakened."}, {"term": "strategic stability", "ipa": "/strəˌtiːdʒɪk stəˈbɪləti/", "pron": "struh-TEE-jik stuh-BIL-uh-tee", "fr": "stabilité stratégique", "def": "A situation where nuclear powers have incentives to avoid escalation.", "ex": "Strategic stability depends on communication and arms control."}, {"term": "escalation", "ipa": "/ˌeskəˈleɪʃən/", "pron": "es-kuh-LAY-shuhn", "fr": "escalade", "def": "An increase in tension, violence or conflict.", "ex": "Western governments worry about escalation with Russia."}, {"term": "de-escalation", "ipa": "/ˌdiː eskəˈleɪʃən/", "pron": "dee-es-kuh-LAY-shuhn", "fr": "désescalade", "def": "Reduction of tension or conflict.", "ex": "Diplomacy can support de-escalation."}, {"term": "red line", "ipa": "/ˌred ˈlaɪn/", "pron": "red line", "fr": "ligne rouge", "def": "A limit that should not be crossed without consequences.", "ex": "Russia often warns about red lines."}, {"term": "miscalculation", "ipa": "/ˌmɪskælkjʊˈleɪʃən/", "pron": "mis-kal-kyuh-LAY-shuhn", "fr": "erreur de calcul", "def": "A wrong judgement that can cause unintended escalation.", "ex": "Miscalculation between nuclear powers is extremely dangerous."}, {"term": "cyberattack", "ipa": "/ˈsaɪbərətæk/", "pron": "SY-buh-uh-tak", "fr": "cyberattaque", "def": "An attack on computer systems or networks.", "ex": "Russian-linked cyberattacks have targeted foreign institutions."}, {"term": "cyber espionage", "ipa": "/ˌsaɪbər ˈespiənɑːʒ/", "pron": "SY-buh ES-pee-uh-nahzh", "fr": "cyberespionnage", "def": "Spying through cyber tools.", "ex": "Cyber espionage is a major concern in Russia-West relations."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately.", "ex": "Disinformation aims to confuse and divide societies."}, {"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WAR-fair", "fr": "guerre de l’information", "def": "Use of information, propaganda or manipulation in conflict.", "ex": "Russia is often accused of information warfare."}, {"term": "election interference", "ipa": "/ɪˈlekʃən ˌɪntəˈfɪərəns/", "pron": "i-LEK-shuhn in-tuh-FEER-uhns", "fr": "ingérence électorale", "def": "Attempts to influence or manipulate elections in another country.", "ex": "Election interference can undermine trust in democracy."}]}, {"title": "E. Nuclear risks, cyber/information warfare and high-value verbs", "entries": [{"term": "influence operation", "ipa": "/ˈɪnfluəns ˌɒpəˈreɪʃən/", "pron": "IN-floo-uhns op-uh-RAY-shuhn", "fr": "opération d’influence", "def": "A coordinated effort to shape public opinion or political outcomes.", "ex": "Influence operations often use social media."}, {"term": "troll farm", "ipa": "/ˈtrɒl fɑːm/", "pron": "troll farm", "fr": "usine à trolls", "def": "An organisation employing people to post manipulative content online.", "ex": "Troll farms spread propaganda and polarisation."}, {"term": "bot network", "ipa": "/ˈbɒt ˌnetwɜːk/", "pron": "bot NET-work", "fr": "réseau de bots", "def": "A network of automated accounts used online.", "ex": "Bot networks can amplify false narratives."}, {"term": "malign influence", "ipa": "/məˈlaɪn ˈɪnfluəns/", "pron": "muh-LYNE IN-floo-uhns", "fr": "influence malveillante", "def": "Harmful or hostile influence by a foreign actor.", "ex": "Democracies try to counter malign influence."}, {"term": "to invade Ukraine", "ipa": "/ɪnˈveɪd juːˈkreɪn/", "pron": "in-VAYD yoo-KRAYN", "fr": "envahir l’Ukraine", "def": "To enter Ukraine with military force.", "ex": "Russia’s decision to invade Ukraine changed European security."}, {"term": "to annex territory", "ipa": "/əˈneks ˈterɪtəri/", "pron": "uh-NEKS TERR-i-tuh-ree", "fr": "annexer un territoire", "def": "To incorporate territory into another state, often by force.", "ex": "Attempts to annex territory violate international law."}, {"term": "to violate sovereignty", "ipa": "/ˈvaɪəleɪt ˈsɒvrənti/", "pron": "VY-uh-layt SOV-ruhn-tee", "fr": "violer la souveraineté", "def": "To break a state’s right to govern itself.", "ex": "The invasion violated Ukraine’s sovereignty."}, {"term": "to undermine democracy", "ipa": "/ˌʌndəˈmaɪn dɪˈmɒkrəsi/", "pron": "un-duh-MYNE di-MOK-ruh-see", "fr": "saper la démocratie", "def": "To weaken democratic institutions or trust.", "ex": "Disinformation can undermine democracy."}, {"term": "to spread disinformation", "ipa": "/spred ˌdɪsɪnfəˈmeɪʃən/", "pron": "spred dis-in-fuh-MAY-shuhn", "fr": "diffuser de la désinformation", "def": "To deliberately circulate false information.", "ex": "State-linked actors spread disinformation online."}, {"term": "to weaponise energy", "ipa": "/ˈwepənaɪz ˈenədʒi/", "pron": "WEP-uh-nyze EN-uh-jee", "fr": "instrumentaliser l’énergie", "def": "To use energy supplies as a political weapon.", "ex": "Russia has been accused of weaponising energy."}, {"term": "to impose sanctions", "ipa": "/ɪmˈpəʊz ˈsæŋkʃənz/", "pron": "im-POHZ SANK-shuhnz", "fr": "imposer des sanctions", "def": "To apply economic or political penalties.", "ex": "Western states imposed sanctions after the invasion."}, {"term": "to evade sanctions", "ipa": "/ɪˈveɪd ˈsæŋkʃənz/", "pron": "i-VAYD SANK-shuhnz", "fr": "contourner les sanctions", "def": "To bypass or avoid sanctions.", "ex": "Companies may use intermediaries to evade sanctions."}, {"term": "to deter Russia", "ipa": "/dɪˈter ˈrʌʃə/", "pron": "di-TERR RUSH-uh", "fr": "dissuader la Russie", "def": "To prevent Russian aggression by threatening consequences.", "ex": "NATO aims to deter Russia on its eastern flank."}, {"term": "to strengthen NATO’s eastern flank", "ipa": "/ˈstreŋθən ˌneɪtəʊz ˌiːstən ˈflæŋk/", "pron": "STRENG-thuhn NAY-tohz EES-tuhn flank", "fr": "renforcer le flanc oriental de l’OTAN", "def": "To reinforce NATO members close to Russia.", "ex": "Allies moved to strengthen NATO’s eastern flank."}, {"term": "to support Ukraine", "ipa": "/səˈpɔːt juːˈkreɪn/", "pron": "suh-PORT yoo-KRAYN", "fr": "soutenir l’Ukraine", "def": "To provide Ukraine with political, military, economic or humanitarian aid.", "ex": "European governments continue to support Ukraine."}, {"term": "to isolate Russia", "ipa": "/ˈaɪsəleɪt ˈrʌʃə/", "pron": "EYE-suh-layt RUSH-uh", "fr": "isoler la Russie", "def": "To cut Russia off diplomatically or economically.", "ex": "Sanctions were meant to isolate Russia from Western markets."}, {"term": "to manage escalation", "ipa": "/ˈmænɪdʒ ˌeskəˈleɪʃən/", "pron": "MAN-ij es-kuh-LAY-shuhn", "fr": "gérer l’escalade", "def": "To prevent conflict from becoming more dangerous.", "ex": "NATO must support Ukraine while managing escalation."}, {"term": "to seek a negotiated settlement", "ipa": "/siːk ə nɪˌɡəʊʃieɪtɪd ˈsetəlmənt/", "pron": "seek uh ni-GOH-shee-ay-tid SET-uhl-muhnt", "fr": "chercher un règlement négocié", "def": "To look for an agreement reached through negotiation.", "ex": "Some argue that the war will eventually require a negotiated settlement."}, {"term": "to rebuild European security", "ipa": "/ˌriːˈbɪld ˌjʊərəpiːən sɪˈkjʊərəti/", "pron": "ree-BILD YOOR-uh-pee-uhn si-KYOOR-uh-tee", "fr": "reconstruire la sécurité européenne", "def": "To create a new stable security order in Europe.", "ex": "The war has raised the question of how to rebuild European security."}]}]}, {"id": "p6c56", "part": 6, "chapter": 56, "title": "European Union", "file": "cpge_vocab_part6_chapter56_european_union_premium.html", "count": 149, "sections": [{"title": "A. Core EU, integration and institutions", "entries": [{"term": "European Union", "ipa": "/ˌjʊərəpiːən ˈjuːniən/", "pron": "YOOR-uh-pee-uhn YOO-nee-uhn", "fr": "Union européenne", "def": "A political and economic union of European countries that cooperate through shared institutions and laws.", "ex": "The European Union shapes trade, migration, regulation and geopolitics in Europe."}, {"term": "EU", "ipa": "/ˌiː ˈjuː/", "pron": "ee-yoo", "fr": "UE", "def": "Abbreviation for European Union.", "ex": "The EU is both a market and a political project."}, {"term": "European integration", "ipa": "/ˌjʊərəpiːən ˌɪntɪˈɡreɪʃən/", "pron": "YOOR-uh-pee-uhn in-ti-GRAY-shuhn", "fr": "intégration européenne", "def": "The process of European states becoming more politically, legally and economically connected.", "ex": "European integration began after the Second World War."}, {"term": "European project", "ipa": "/ˌjʊərəpiːən ˈprɒdʒekt/", "pron": "YOOR-uh-pee-uhn PROJ-ekt", "fr": "projet européen", "def": "The political idea of building cooperation and unity among European countries.", "ex": "The European project was designed to make war between members unthinkable."}, {"term": "supranational organisation", "ipa": "/ˌsuːprəˈnæʃənəl ˌɔːɡənaɪˈzeɪʃən/", "pron": "soo-pruh-NASH-uh-nuhl or-guh-ny-ZAY-shuhn", "fr": "organisation supranationale", "def": "An organisation with authority above national governments in some areas.", "ex": "The EU is more supranational than most international organisations."}, {"term": "supranationalism", "ipa": "/ˌsuːprəˈnæʃənəlɪzəm/", "pron": "soo-pruh-NASH-uh-nuhl-iz-uhm", "fr": "supranationalisme", "def": "The principle that some decisions are made above the national level.", "ex": "Supranationalism is central to the EU’s legal order."}, {"term": "intergovernmentalism", "ipa": "/ˌɪntəɡʌvənˈmentəlɪzəm/", "pron": "IN-tuh-gov-uhn-MEN-tuhl-iz-uhm", "fr": "intergouvernementalisme", "def": "Cooperation based on decisions made by national governments.", "ex": "Foreign policy in the EU remains largely intergovernmental."}, {"term": "member state", "ipa": "/ˈmembə steɪt/", "pron": "MEM-buh state", "fr": "État membre", "def": "A country belonging to the European Union.", "ex": "Each member state is represented in the Council."}, {"term": "candidate country", "ipa": "/ˈkændɪdət ˈkʌntri/", "pron": "KAN-di-duht KUN-tree", "fr": "pays candidat", "def": "A country officially seeking EU membership.", "ex": "Candidate countries must meet EU accession criteria."}, {"term": "accession", "ipa": "/əkˈseʃən/", "pron": "ak-SESH-uhn", "fr": "adhésion", "def": "The process of formally joining the EU or another organisation.", "ex": "Accession to the EU requires long negotiations."}, {"term": "enlargement", "ipa": "/ɪnˈlɑːdʒmənt/", "pron": "in-LARJ-muhnt", "fr": "élargissement", "def": "Expansion of the EU by admitting new member states.", "ex": "EU enlargement is both strategic and politically sensitive."}, {"term": "treaty", "ipa": "/ˈtriːti/", "pron": "TREE-tee", "fr": "traité", "def": "A formal legal agreement between states.", "ex": "EU treaties define the powers of the institutions."}, {"term": "Treaty of Rome", "ipa": "/ˌtriːti əv ˈrəʊm/", "pron": "TREE-tee ov ROHM", "fr": "traité de Rome", "def": "The 1957 treaty creating the European Economic Community.", "ex": "The Treaty of Rome laid the foundations of the common market."}, {"term": "Maastricht Treaty", "ipa": "/ˈmɑːstrɪxt ˌtriːti/", "pron": "MAH-strikt TREE-tee", "fr": "traité de Maastricht", "def": "The 1992 treaty that created the European Union and paved the way for the euro.", "ex": "The Maastricht Treaty deepened European integration."}, {"term": "Lisbon Treaty", "ipa": "/ˈlɪzbən ˌtriːti/", "pron": "LIZ-buhn TREE-tee", "fr": "traité de Lisbonne", "def": "The treaty that reformed EU institutions and rules, entering into force in 2009.", "ex": "The Lisbon Treaty strengthened the European Parliament."}, {"term": "founding fathers", "ipa": "/ˌfaʊndɪŋ ˈfɑːðəz/", "pron": "FOWN-ding FAR-thuhz", "fr": "pères fondateurs", "def": "The early political figures associated with European integration.", "ex": "The founding fathers saw integration as a peace project."}, {"term": "Schuman Declaration", "ipa": "/ˈʃuːmən ˌdekləˈreɪʃən/", "pron": "SHOO-muhn dek-luh-RAY-shuhn", "fr": "déclaration Schuman", "def": "The 1950 declaration proposing cooperation in coal and steel.", "ex": "The Schuman Declaration is often seen as the birth of European integration."}, {"term": "European Commission", "ipa": "/ˌjʊərəpiːən kəˈmɪʃən/", "pron": "YOOR-uh-pee-uhn kuh-MISH-uhn", "fr": "Commission européenne", "def": "The EU institution that proposes laws, enforces rules and represents the common European interest.", "ex": "The European Commission can launch infringement procedures."}, {"term": "Commissioner", "ipa": "/kəˈmɪʃənə/", "pron": "kuh-MISH-uh-nuh", "fr": "commissaire européen", "def": "A member of the European Commission responsible for a policy area.", "ex": "Each Commissioner manages a specific portfolio."}, {"term": "European Parliament", "ipa": "/ˌjʊərəpiːən ˈpɑːləmənt/", "pron": "YOOR-uh-pee-uhn PAR-luh-muhnt", "fr": "Parlement européen", "def": "The directly elected EU institution representing citizens.", "ex": "The European Parliament votes on legislation and the EU budget."}, {"term": "MEP", "ipa": "/ˌem iː ˈpiː/", "pron": "em-ee-pee", "fr": "député européen", "def": "Member of the European Parliament.", "ex": "MEPs are elected by citizens in EU member states."}, {"term": "Council of the European Union", "ipa": "/ˌkaʊnsəl əv ðə ˌjʊərəpiːən ˈjuːniən/", "pron": "KOWN-suhl ov thuh YOOR-uh-pee-uhn YOO-nee-uhn", "fr": "Conseil de l’Union européenne", "def": "EU institution where national ministers adopt laws and coordinate policies.", "ex": "The Council of the European Union represents member-state governments."}, {"term": "European Council", "ipa": "/ˌjʊərəpiːən ˈkaʊnsəl/", "pron": "YOOR-uh-pee-uhn KOWN-suhl", "fr": "Conseil européen", "def": "EU institution bringing together heads of state or government to set broad priorities.", "ex": "The European Council sets the EU’s political direction."}, {"term": "Court of Justice of the European Union", "ipa": "/ˌkɔːt əv ˈdʒʌstɪs əv ðə ˌjʊərəpiːən ˈjuːniən/", "pron": "court ov JUS-tis ov thuh YOOR-uh-pee-uhn YOO-nee-uhn", "fr": "Cour de justice de l’Union européenne", "def": "The EU court ensuring that EU law is interpreted and applied consistently.", "ex": "The Court of Justice protects the primacy of EU law."}, {"term": "CJEU", "ipa": "/ˌsiː dʒeɪ iː ˈjuː/", "pron": "see-jay-ee-yoo", "fr": "CJUE", "def": "Abbreviation for Court of Justice of the European Union.", "ex": "The CJEU can rule against member states that breach EU law."}, {"term": "European Central Bank", "ipa": "/ˌjʊərəpiːən ˈsentrəl bæŋk/", "pron": "YOOR-uh-pee-uhn SEN-truhl bank", "fr": "Banque centrale européenne", "def": "The central bank managing the euro and eurozone monetary policy.", "ex": "The European Central Bank sets interest rates for the eurozone."}, {"term": "ECB", "ipa": "/ˌiː siː ˈbiː/", "pron": "ee-see-bee", "fr": "BCE", "def": "Abbreviation for European Central Bank.", "ex": "The ECB fights inflation while supporting financial stability."}, {"term": "European Court of Auditors", "ipa": "/ˌjʊərəpiːən kɔːt əv ˈɔːdɪtəz/", "pron": "YOOR-uh-pee-uhn court ov AW-di-tuhz", "fr": "Cour des comptes européenne", "def": "EU institution checking whether EU funds are properly spent.", "ex": "The European Court of Auditors monitors EU spending."}, {"term": "qualified majority voting", "ipa": "/ˌkwɒlɪfaɪd məˈdʒɒrəti ˈvəʊtɪŋ/", "pron": "KWOL-i-fyd muh-JOR-uh-tee VOH-ting", "fr": "vote à la majorité qualifiée", "def": "A voting system where decisions pass if they meet population and member-state thresholds.", "ex": "Qualified majority voting prevents one state from blocking many decisions."}, {"term": "unanimity", "ipa": "/ˌjuːnəˈnɪməti/", "pron": "yoo-nuh-NIM-uh-tee", "fr": "unanimité", "def": "Agreement by all member states.", "ex": "Foreign policy and taxation often require unanimity."}, {"term": "veto", "ipa": "/ˈviːtəʊ/", "pron": "VEE-toh", "fr": "veto", "def": "The power to block a decision.", "ex": "A national veto can slow EU decision-making."}, {"term": "subsidiarity", "ipa": "/səbˌsɪdiˈærəti/", "pron": "suhb-sid-ee-ARR-uh-tee", "fr": "subsidiarité", "def": "The principle that decisions should be taken as close to citizens as possible.", "ex": "Subsidiarity limits unnecessary EU intervention."}, {"term": "proportionality", "ipa": "/prəˌpɔːʃəˈnæləti/", "pron": "pruh-por-shuh-NAL-uh-tee", "fr": "proportionnalité", "def": "The principle that EU action should not exceed what is necessary.", "ex": "Proportionality is a key legal principle in EU law."}, {"term": "EU law", "ipa": "/ˌiː ˈjuː lɔː/", "pron": "ee-yoo law", "fr": "droit de l’Union européenne", "def": "The body of law created by EU treaties, institutions and courts.", "ex": "EU law takes precedence in many areas."}, {"term": "primacy of EU law", "ipa": "/ˈpraɪməsi əv ˌiː ˈjuː lɔː/", "pron": "PRY-muh-see ov ee-yoo law", "fr": "primauté du droit de l’UE", "def": "The principle that EU law takes priority over conflicting national law.", "ex": "The primacy of EU law is central to the legal order."}, {"term": "direct effect", "ipa": "/dəˌrekt ɪˈfekt/", "pron": "di-REKT i-FEKT", "fr": "effet direct", "def": "The principle allowing individuals to invoke some EU rules before national courts.", "ex": "Direct effect makes EU law powerful for citizens."}, {"term": "regulation", "ipa": "/ˌreɡjʊˈleɪʃən/", "pron": "reg-yuh-LAY-shuhn", "fr": "règlement", "def": "An EU legal act directly applicable in all member states.", "ex": "An EU regulation applies without national transposition."}, {"term": "directive", "ipa": "/dəˈrektɪv/", "pron": "di-REK-tiv", "fr": "directive", "def": "An EU legal act setting goals that member states must transpose into national law.", "ex": "A directive gives states flexibility in implementation."}, {"term": "infringement procedure", "ipa": "/ɪnˈfrɪndʒmənt prəˌsiːdʒə/", "pron": "in-FRINJ-muhnt pruh-SEE-juh", "fr": "procédure d’infraction", "def": "A legal process against a member state that breaches EU law.", "ex": "The Commission launched an infringement procedure."}, {"term": "single market", "ipa": "/ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "SING-guhl MAR-kit", "fr": "marché unique", "def": "The EU area allowing free movement of goods, services, capital and people.", "ex": "The single market is one of the EU’s greatest achievements."}, {"term": "internal market", "ipa": "/ɪnˌtɜːnəl ˈmɑːkɪt/", "pron": "in-TUR-nuhl MAR-kit", "fr": "marché intérieur", "def": "Another term for the EU single market.", "ex": "The internal market reduces barriers between member states."}, {"term": "four freedoms", "ipa": "/ˌfɔː ˈfriːdəmz/", "pron": "four FREE-duhmz", "fr": "quatre libertés", "def": "Free movement of goods, services, capital and people in the EU.", "ex": "The four freedoms define the single market."}]}, {"title": "B. Law, single market, eurozone and budget", "entries": [{"term": "free movement of people", "ipa": "/ˌfriː ˈmuːvmənt əv ˈpiːpəl/", "pron": "free MOOV-muhnt ov PEE-puhl", "fr": "libre circulation des personnes", "def": "The right of EU citizens to live and work in other member states.", "ex": "Free movement of people is politically controversial."}, {"term": "free movement of goods", "ipa": "/ˌfriː ˈmuːvmənt əv ɡʊdz/", "pron": "free MOOV-muhnt ov goods", "fr": "libre circulation des marchandises", "def": "The removal of barriers to trade in goods between EU members.", "ex": "Free movement of goods supports cross-border trade."}, {"term": "free movement of services", "ipa": "/ˌfriː ˈmuːvmənt əv ˈsɜːvɪsɪz/", "pron": "free MOOV-muhnt ov SUR-vis-iz", "fr": "libre circulation des services", "def": "The right to provide services across EU borders.", "ex": "Free movement of services affects workers and firms."}, {"term": "free movement of capital", "ipa": "/ˌfriː ˈmuːvmənt əv ˈkæpɪtəl/", "pron": "free MOOV-muhnt ov KAP-i-tuhl", "fr": "libre circulation des capitaux", "def": "The right to move money and investment across EU borders.", "ex": "Free movement of capital supports investment."}, {"term": "customs union", "ipa": "/ˈkʌstəmz ˌjuːniən/", "pron": "KUS-tuhmz YOO-nee-uhn", "fr": "union douanière", "def": "An area with no internal tariffs and a common external tariff.", "ex": "The EU customs union simplifies trade inside the bloc."}, {"term": "common external tariff", "ipa": "/ˌkɒmən ɪkˈstɜːnəl ˈtærɪf/", "pron": "KOM-uhn ik-STUR-nuhl TAR-if", "fr": "tarif extérieur commun", "def": "A shared tariff applied to goods entering the EU from outside.", "ex": "The common external tariff is part of the customs union."}, {"term": "trade barrier", "ipa": "/ˈtreɪd ˌbæriə/", "pron": "trade BARR-ee-uh", "fr": "barrière commerciale", "def": "A rule or cost that restricts trade.", "ex": "The single market removes many trade barriers."}, {"term": "non-tariff barrier", "ipa": "/ˌnɒn ˈtærɪf ˌbæriə/", "pron": "non-TAR-if BARR-ee-uh", "fr": "barrière non tarifaire", "def": "A trade obstacle that is not a tariff, such as standards or paperwork.", "ex": "Regulatory divergence can create non-tariff barriers."}, {"term": "competition policy", "ipa": "/ˌkɒmpəˈtɪʃən ˈpɒləsi/", "pron": "kom-puh-TISH-uhn POL-uh-see", "fr": "politique de concurrence", "def": "Rules designed to prevent monopolies, cartels and unfair market practices.", "ex": "EU competition policy can fine major corporations."}, {"term": "state aid", "ipa": "/ˌsteɪt ˈeɪd/", "pron": "state aid", "fr": "aide d’État", "def": "Government support to companies that may distort competition.", "ex": "EU rules limit state aid to protect fair competition."}, {"term": "antitrust", "ipa": "/ˌæntiˈtrʌst/", "pron": "AN-tee-TRUST", "fr": "antitrust ; droit de la concurrence", "def": "Law or policy preventing monopolistic practices.", "ex": "The EU has used antitrust cases against Big Tech."}, {"term": "digital regulation", "ipa": "/ˌdɪdʒɪtəl ˌreɡjʊˈleɪʃən/", "pron": "DIJ-i-tuhl reg-yuh-LAY-shuhn", "fr": "réglementation numérique", "def": "Rules governing digital markets, platforms and data.", "ex": "The EU has become influential in digital regulation."}, {"term": "GDPR", "ipa": "/ˌdʒiː diː piː ˈɑː/", "pron": "jee-dee-pee-ar", "fr": "RGPD", "def": "General Data Protection Regulation, the EU’s major data-privacy law.", "ex": "GDPR strengthened data protection rights."}, {"term": "data protection", "ipa": "/ˈdeɪtə prəˌtekʃən/", "pron": "DAY-tuh pruh-TEK-shuhn", "fr": "protection des données", "def": "Rules protecting personal data and privacy.", "ex": "Data protection is a major EU regulatory strength."}, {"term": "Brussels effect", "ipa": "/ˈbrʌsəlz ɪˌfekt/", "pron": "BRUSS-uhlz i-FEKT", "fr": "effet Bruxelles", "def": "The EU’s ability to shape global rules through its market power.", "ex": "The Brussels effect makes EU regulation influential worldwide."}, {"term": "euro", "ipa": "/ˈjʊərəʊ/", "pron": "YOOR-oh", "fr": "euro", "def": "The common currency used by many EU member states.", "ex": "The euro is managed by the European Central Bank."}, {"term": "eurozone", "ipa": "/ˈjʊərəʊzəʊn/", "pron": "YOOR-oh-zone", "fr": "zone euro", "def": "The group of EU countries that use the euro.", "ex": "The eurozone shares monetary policy but not a full fiscal union."}, {"term": "monetary union", "ipa": "/ˈmʌnɪtəri ˈjuːniən/", "pron": "MUN-i-tuh-ree YOO-nee-uhn", "fr": "union monétaire", "def": "An arrangement where countries share a currency or monetary policy.", "ex": "The eurozone is a monetary union."}, {"term": "fiscal union", "ipa": "/ˈfɪskəl ˈjuːniən/", "pron": "FIS-kuhl YOO-nee-uhn", "fr": "union budgétaire", "def": "A system with shared budgetary powers or transfers between states.", "ex": "The eurozone lacks a complete fiscal union."}, {"term": "monetary policy", "ipa": "/ˈmʌnɪtəri ˈpɒləsi/", "pron": "MUN-i-tuh-ree POL-uh-see", "fr": "politique monétaire", "def": "Central bank policy on interest rates and money supply.", "ex": "The ECB controls eurozone monetary policy."}, {"term": "fiscal policy", "ipa": "/ˈfɪskəl ˈpɒləsi/", "pron": "FIS-kuhl POL-uh-see", "fr": "politique budgétaire", "def": "Government policy on spending, taxation and borrowing.", "ex": "Fiscal policy remains largely national in the EU."}, {"term": "sovereign debt crisis", "ipa": "/ˌsɒvrɪn ˈdet ˌkraɪsɪs/", "pron": "SOV-rin det KRY-sis", "fr": "crise de la dette souveraine", "def": "A crisis involving government debt sustainability.", "ex": "The eurozone faced a sovereign debt crisis after 2010."}, {"term": "bailout", "ipa": "/ˈbeɪlaʊt/", "pron": "BAYL-owt", "fr": "plan de sauvetage", "def": "Financial rescue of a state, bank or institution in difficulty.", "ex": "Bailouts during the eurozone crisis were politically divisive."}, {"term": "austerity", "ipa": "/ɒˈsterəti/", "pron": "aw-STAIR-uh-tee", "fr": "austérité", "def": "Policies reducing public spending or deficits.", "ex": "Austerity damaged trust in EU institutions in some countries."}, {"term": "banking union", "ipa": "/ˈbæŋkɪŋ ˌjuːniən/", "pron": "BANK-ing YOO-nee-uhn", "fr": "union bancaire", "def": "EU framework for supervising and resolving banks, especially in the eurozone.", "ex": "Banking union was created after the financial crisis."}, {"term": "NextGenerationEU", "ipa": "/nekst ˌdʒenəˈreɪʃən ˌiː ˈjuː/", "pron": "next jen-uh-RAY-shuhn ee-yoo", "fr": "NextGenerationEU", "def": "The EU recovery plan created after the COVID-19 crisis.", "ex": "NextGenerationEU marked a major step in common borrowing."}, {"term": "common borrowing", "ipa": "/ˌkɒmən ˈbɒrəʊɪŋ/", "pron": "KOM-uhn BOR-oh-ing", "fr": "emprunt commun", "def": "Debt issued collectively by several states or an institution.", "ex": "Common borrowing was controversial but symbolically important."}, {"term": "EU budget", "ipa": "/ˌiː ˈjuː ˈbʌdʒɪt/", "pron": "ee-yoo BUJ-it", "fr": "budget de l’UE", "def": "The financial plan funding EU policies and programmes.", "ex": "The EU budget funds agriculture, cohesion and research."}, {"term": "cohesion policy", "ipa": "/kəʊˈhiːʒən ˈpɒləsi/", "pron": "koh-HEE-zhuhn POL-uh-see", "fr": "politique de cohésion", "def": "EU policy reducing economic and regional disparities.", "ex": "Cohesion policy supports poorer regions."}, {"term": "structural funds", "ipa": "/ˈstrʌktʃərəl fʌndz/", "pron": "STRUK-chuh-ruhl fundz", "fr": "fonds structurels", "def": "EU funds supporting regional development and economic convergence.", "ex": "Structural funds finance infrastructure and training."}, {"term": "Common Agricultural Policy", "ipa": "/ˌkɒmən ˌæɡrɪˈkʌltʃərəl ˈpɒləsi/", "pron": "KOM-uhn ag-ri-KUL-chuh-ruhl POL-uh-see", "fr": "politique agricole commune", "def": "EU policy supporting farmers and rural areas.", "ex": "The Common Agricultural Policy is a major part of the EU budget."}, {"term": "CAP", "ipa": "/ˌsiː eɪ ˈpiː/", "pron": "see-ay-pee", "fr": "PAC", "def": "Abbreviation for Common Agricultural Policy.", "ex": "The CAP is often criticised for its cost and environmental impact."}, {"term": "Schengen Area", "ipa": "/ˈʃeŋən ˌeəriə/", "pron": "SHENG-uhn AIR-ee-uh", "fr": "espace Schengen", "def": "European area without routine internal border checks.", "ex": "The Schengen Area allows passport-free travel."}, {"term": "border control", "ipa": "/ˈbɔːdə kənˌtrəʊl/", "pron": "BOR-duh kuhn-TROHL", "fr": "contrôle aux frontières", "def": "Checks and controls at borders.", "ex": "Migration crises have led to temporary border controls."}, {"term": "external border", "ipa": "/ɪkˌstɜːnəl ˈbɔːdə/", "pron": "ik-STUR-nuhl BOR-duh", "fr": "frontière extérieure", "def": "The outer border of the EU or Schengen Area.", "ex": "Protecting the external border is a shared challenge."}, {"term": "Frontex", "ipa": "/ˈfrɒnteks/", "pron": "FRON-teks", "fr": "Frontex", "def": "The EU border and coast guard agency.", "ex": "Frontex supports member states at the EU’s external borders."}, {"term": "asylum policy", "ipa": "/əˈsaɪləm ˈpɒləsi/", "pron": "uh-SY-luhm POL-uh-see", "fr": "politique d’asile", "def": "Rules governing protection for people fleeing persecution or danger.", "ex": "EU asylum policy is politically divisive."}, {"term": "migration policy", "ipa": "/maɪˈɡreɪʃən ˈpɒləsi/", "pron": "my-GRAY-shuhn POL-uh-see", "fr": "politique migratoire", "def": "Rules and strategies managing migration.", "ex": "Migration policy tests EU solidarity."}, {"term": "refugee crisis", "ipa": "/ˌrefjʊˈdʒiː ˈkraɪsɪs/", "pron": "REF-yoo-jee KRY-sis", "fr": "crise des réfugiés", "def": "A situation involving large numbers of displaced people seeking protection.", "ex": "The refugee crisis exposed divisions between member states."}, {"term": "burden-sharing", "ipa": "/ˈbɜːdən ˌʃeərɪŋ/", "pron": "BUR-duhn SHARE-ing", "fr": "partage du fardeau", "def": "Distribution of responsibilities or costs among states.", "ex": "Burden-sharing is central to asylum debates."}, {"term": "relocation scheme", "ipa": "/ˌriːləʊˈkeɪʃən skiːm/", "pron": "ree-loh-KAY-shuhn skeem", "fr": "mécanisme de relocalisation", "def": "A plan to move asylum seekers from one country to others.", "ex": "Relocation schemes have met resistance."}, {"term": "solidarity mechanism", "ipa": "/ˌsɒlɪˈdærəti ˈmekənɪzəm/", "pron": "sol-i-DARR-uh-tee MEK-uh-niz-uhm", "fr": "mécanisme de solidarité", "def": "A system for sharing responsibilities among EU states.", "ex": "A solidarity mechanism can ease pressure on border states."}]}, {"title": "C. Migration, rule of law, sovereignty and Euroscepticism", "entries": [{"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit", "def": "The principle that everyone, including governments, is subject to law.", "ex": "The rule of law is a core EU value."}, {"term": "democratic backsliding", "ipa": "/ˌdeməkrætɪk ˈbækslaɪdɪŋ/", "pron": "dem-uh-KRAT-ik BAK-sly-ding", "fr": "recul démocratique", "def": "The weakening of democratic institutions and norms.", "ex": "Democratic backsliding has challenged EU unity."}, {"term": "judicial independence", "ipa": "/dʒuːˌdɪʃəl ˌɪndɪˈpendəns/", "pron": "joo-DISH-uhl in-di-PEN-duhns", "fr": "indépendance de la justice", "def": "The ability of courts to act without political pressure.", "ex": "Judicial independence is essential to the rule of law."}, {"term": "media freedom", "ipa": "/ˈmiːdiə ˈfriːdəm/", "pron": "MEE-dee-uh FREE-duhm", "fr": "liberté des médias", "def": "The ability of media to operate without censorship or intimidation.", "ex": "Media freedom is under pressure in some member states."}, {"term": "Article 7", "ipa": "/ˌɑːtɪkəl ˈsevən/", "pron": "AR-ti-kuhl SEV-uhn", "fr": "Article 7", "def": "EU treaty procedure for serious breaches of EU values.", "ex": "Article 7 can be used against rule-of-law violations."}, {"term": "conditionality mechanism", "ipa": "/kənˌdɪʃəˈnæləti ˈmekənɪzəm/", "pron": "kuhn-dish-uh-NAL-uh-tee MEK-uh-niz-uhm", "fr": "mécanisme de conditionnalité", "def": "A system linking EU funds to respect for certain rules or values.", "ex": "The conditionality mechanism can suspend EU funds."}, {"term": "populism", "ipa": "/ˈpɒpjʊlɪzəm/", "pron": "POP-yuh-liz-uhm", "fr": "populisme", "def": "Politics claiming to represent ordinary people against corrupt elites.", "ex": "Populism often attacks Brussels as distant and technocratic."}, {"term": "Euroscepticism", "ipa": "/ˌjʊərəʊˈskeptɪsɪzəm/", "pron": "YOOR-oh-SKEP-ti-siz-uhm", "fr": "euroscepticisme", "def": "Criticism of or opposition to European integration or the EU.", "ex": "Euroscepticism grew after the eurozone and migration crises."}, {"term": "hard Euroscepticism", "ipa": "/ˌhɑːd jʊərəʊˈskeptɪsɪzəm/", "pron": "hard YOOR-oh-SKEP-ti-siz-uhm", "fr": "euroscepticisme dur", "def": "Opposition to EU membership itself.", "ex": "Hard Euroscepticism led to Brexit."}, {"term": "soft Euroscepticism", "ipa": "/ˌsɒft jʊərəʊˈskeptɪsɪzəm/", "pron": "soft YOOR-oh-SKEP-ti-siz-uhm", "fr": "euroscepticisme modéré", "def": "Criticism of some EU policies without rejecting membership.", "ex": "Soft Euroscepticism calls for reform rather than exit."}, {"term": "democratic deficit", "ipa": "/ˌdeməkrætɪk ˈdefɪsɪt/", "pron": "dem-uh-KRAT-ik DEF-i-sit", "fr": "déficit démocratique", "def": "The claim that EU decision-making lacks sufficient democratic accountability.", "ex": "Critics argue that the EU suffers from a democratic deficit."}, {"term": "technocracy", "ipa": "/tekˈnɒkrəsi/", "pron": "tek-NOK-ruh-see", "fr": "technocratie", "def": "Rule or influence by technical experts rather than elected politicians.", "ex": "The EU is sometimes criticised as technocratic."}, {"term": "Brussels bureaucracy", "ipa": "/ˌbrʌsəlz bjʊəˈrɒkrəsi/", "pron": "BRUSS-uhlz byoo-ROK-ruh-see", "fr": "bureaucratie bruxelloise", "def": "A critical phrase for EU administration and regulation.", "ex": "Populists often attack Brussels bureaucracy."}, {"term": "Brexit", "ipa": "/ˈbreksɪt/", "pron": "BREK-sit", "fr": "Brexit", "def": "The United Kingdom’s withdrawal from the European Union.", "ex": "Brexit changed the EU and the UK’s place in Europe."}, {"term": "withdrawal agreement", "ipa": "/wɪðˈdrɔːəl əˌɡriːmənt/", "pron": "with-DRAW-uhl uh-GREE-muhnt", "fr": "accord de retrait", "def": "A legal agreement setting terms for leaving an organisation.", "ex": "The withdrawal agreement settled some Brexit issues."}, {"term": "sovereignty argument", "ipa": "/ˈsɒvrənti ˈɑːɡjʊmənt/", "pron": "SOV-ruhn-tee AR-gyuh-muhnt", "fr": "argument de souveraineté", "def": "The claim that national control is weakened by EU membership.", "ex": "The sovereignty argument was central to Brexit."}, {"term": "national sovereignty", "ipa": "/ˌnæʃənəl ˈsɒvrənti/", "pron": "NASH-uh-nuhl SOV-ruhn-tee", "fr": "souveraineté nationale", "def": "A state’s authority to govern itself.", "ex": "EU integration raises questions about national sovereignty."}, {"term": "shared sovereignty", "ipa": "/ˌʃeəd ˈsɒvrənti/", "pron": "shared SOV-ruhn-tee", "fr": "souveraineté partagée", "def": "Pooling some national powers to act jointly.", "ex": "Supporters say the EU creates shared sovereignty."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "The ability to act independently in strategic matters.", "ex": "Strategic autonomy is a major EU foreign-policy debate."}, {"term": "European sovereignty", "ipa": "/ˌjʊərəpiːən ˈsɒvrənti/", "pron": "YOOR-uh-pee-uhn SOV-ruhn-tee", "fr": "souveraineté européenne", "def": "The idea that Europe should have collective capacity to act independently.", "ex": "European sovereignty is often linked to defence, energy and technology."}, {"term": "Common Foreign and Security Policy", "ipa": "/ˌkɒmən ˈfɒrən ənd sɪˈkjʊərəti ˈpɒləsi/", "pron": "KOM-uhn FOR-uhn and si-KYOOR-uh-tee POL-uh-see", "fr": "politique étrangère et de sécurité commune", "def": "The EU framework for foreign and security policy.", "ex": "The Common Foreign and Security Policy often requires unanimity."}, {"term": "CFSP", "ipa": "/ˌsiː ef es ˈpiː/", "pron": "see-eff-ess-pee", "fr": "PESC", "def": "Abbreviation for Common Foreign and Security Policy.", "ex": "CFSP remains constrained by national interests."}, {"term": "Common Security and Defence Policy", "ipa": "/ˌkɒmən sɪˈkjʊərəti ənd dɪˈfens ˈpɒləsi/", "pron": "KOM-uhn si-KYOOR-uh-tee and di-FENS POL-uh-see", "fr": "politique de sécurité et de défense commune", "def": "The EU framework for defence and crisis-management missions.", "ex": "The Common Security and Defence Policy supports EU missions abroad."}, {"term": "CSDP", "ipa": "/ˌsiː es diː ˈpiː/", "pron": "see-ess-dee-pee", "fr": "PSDC", "def": "Abbreviation for Common Security and Defence Policy.", "ex": "CSDP is less integrated than NATO defence."}, {"term": "European defence", "ipa": "/ˌjʊərəpiːən dɪˈfens/", "pron": "YOOR-uh-pee-uhn di-FENS", "fr": "défense européenne", "def": "Defence cooperation among European countries.", "ex": "European defence gained urgency after Russia’s invasion of Ukraine."}, {"term": "EU-NATO cooperation", "ipa": "/ˌiː juː ˈneɪtəʊ kəʊˌɒpəˈreɪʃən/", "pron": "ee-yoo NAY-toh koh-op-uh-RAY-shuhn", "fr": "coopération UE-OTAN", "def": "Cooperation between the European Union and NATO.", "ex": "EU-NATO cooperation is vital for European security."}, {"term": "sanctions policy", "ipa": "/ˈsæŋkʃənz ˈpɒləsi/", "pron": "SANK-shuhnz POL-uh-see", "fr": "politique de sanctions", "def": "Use of sanctions to influence foreign actors.", "ex": "The EU sanctions policy became central after the Ukraine invasion."}, {"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "Influence through attraction, values and culture.", "ex": "The EU’s soft power comes from its market, values and model."}, {"term": "normative power", "ipa": "/ˈnɔːmətɪv ˈpaʊə/", "pron": "NOR-muh-tiv POW-uh", "fr": "puissance normative", "def": "Power based on shaping norms, rules and values.", "ex": "The EU is often described as a normative power."}, {"term": "civilian power", "ipa": "/səˈvɪliən ˈpaʊə/", "pron": "suh-VIL-yuhn POW-uh", "fr": "puissance civile", "def": "Influence based on diplomacy, trade, aid and law rather than military force.", "ex": "The EU has traditionally been seen as a civilian power."}, {"term": "geopolitical Europe", "ipa": "/ˌdʒiːəʊpəˈlɪtɪkəl ˈjʊərəp/", "pron": "jee-oh-puh-LIT-i-kuhl YOOR-uhp", "fr": "Europe géopolitique", "def": "The idea that the EU should act as a strategic power in world affairs.", "ex": "The Ukraine war strengthened calls for a geopolitical Europe."}, {"term": "trade policy", "ipa": "/ˈtreɪd ˈpɒləsi/", "pron": "trade POL-uh-see", "fr": "politique commerciale", "def": "A government or organisation’s rules and strategy on international trade.", "ex": "The EU negotiates trade deals as a bloc."}, {"term": "free trade agreement", "ipa": "/ˌfriː ˈtreɪd əˌɡriːmənt/", "pron": "free trade uh-GREE-muhnt", "fr": "accord de libre-échange", "def": "An agreement reducing barriers to trade between countries.", "ex": "EU free trade agreements can include environmental standards."}, {"term": "protectionism", "ipa": "/prəˈtekʃənɪzəm/", "pron": "pruh-TEK-shuh-niz-uhm", "fr": "protectionnisme", "def": "Policies protecting domestic firms from foreign competition.", "ex": "The EU balances openness with concerns about unfair competition."}, {"term": "industrial strategy", "ipa": "/ɪnˈdʌstriəl ˈstrætədʒi/", "pron": "in-DUS-tree-uhl STRAT-uh-jee", "fr": "stratégie industrielle", "def": "Long-term policy to strengthen strategic industries.", "ex": "The EU’s industrial strategy targets chips, batteries and green technology."}, {"term": "Green Deal", "ipa": "/ˌɡriːn ˈdiːl/", "pron": "green deal", "fr": "Pacte vert pour l’Europe", "def": "The EU plan to make Europe climate-neutral and transform the economy.", "ex": "The Green Deal is one of the EU’s flagship policies."}, {"term": "climate neutrality", "ipa": "/ˈklaɪmət njuːˈtræləti/", "pron": "KLY-muht nyoo-TRAL-uh-tee", "fr": "neutralité climatique", "def": "A balance between greenhouse gas emissions and removals.", "ex": "The EU aims for climate neutrality by 2050."}, {"term": "carbon border adjustment mechanism", "ipa": "/ˌkɑːbən ˈbɔːdə əˈdʒʌstmənt ˈmekənɪzəm/", "pron": "KAR-buhn BOR-duh uh-JUST-muhnt MEK-uh-niz-uhm", "fr": "mécanisme d’ajustement carbone aux frontières", "def": "An EU policy charging carbon-intensive imports to prevent carbon leakage.", "ex": "The carbon border adjustment mechanism links trade and climate policy."}, {"term": "CBAM", "ipa": "/ˌsiː biː eɪ ˈem/", "pron": "see-bee-ay-em", "fr": "MACF", "def": "Abbreviation for carbon border adjustment mechanism.", "ex": "CBAM has been criticised by some trade partners."}]}, {"title": "D. Foreign policy, defence, trade, climate and digital power", "entries": [{"term": "energy transition", "ipa": "/ˈenədʒi trænˌzɪʃən/", "pron": "EN-uh-jee tran-ZISH-uhn", "fr": "transition énergétique", "def": "The shift from fossil fuels to low-carbon energy.", "ex": "The energy transition is central to EU climate policy."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy.", "ex": "The Ukraine war made energy security a priority."}, {"term": "dependency on Russian gas", "ipa": "/dɪˈpendənsi ɒn ˌrʌʃən ˈɡæs/", "pron": "di-PEN-duhn-see on RUSH-uhn gas", "fr": "dépendance au gaz russe", "def": "Reliance on Russia for natural gas supplies.", "ex": "The EU reduced dependency on Russian gas after 2022."}, {"term": "diversification", "ipa": "/daɪˌvɜːsɪfɪˈkeɪʃən/", "pron": "dy-vur-si-fi-KAY-shuhn", "fr": "diversification", "def": "Reducing dependence by using different sources or partners.", "ex": "Energy diversification reduces vulnerability."}, {"term": "digital sovereignty", "ipa": "/ˌdɪdʒɪtəl ˈsɒvrənti/", "pron": "DIJ-i-tuhl SOV-ruhn-tee", "fr": "souveraineté numérique", "def": "The ability to control digital infrastructure, data and technology.", "ex": "Digital sovereignty is a growing EU priority."}, {"term": "AI Act", "ipa": "/ˌeɪ ˈaɪ ækt/", "pron": "ay-eye akt", "fr": "législation européenne sur l’IA", "def": "EU law regulating artificial intelligence according to risk levels.", "ex": "The AI Act reflects the EU’s regulatory approach."}, {"term": "platform regulation", "ipa": "/ˈplætfɔːm ˌreɡjʊˈleɪʃən/", "pron": "PLAT-form reg-yuh-LAY-shuhn", "fr": "réglementation des plateformes", "def": "Rules governing online platforms and digital services.", "ex": "Platform regulation targets Big Tech power."}, {"term": "strategic dependency", "ipa": "/strəˌtiːdʒɪk dɪˈpendənsi/", "pron": "struh-TEE-jik di-PEN-duhn-see", "fr": "dépendance stratégique", "def": "Reliance on external actors for critical goods or technologies.", "ex": "The EU wants to reduce strategic dependency."}, {"term": "open strategic autonomy", "ipa": "/ˌəʊpən strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "OH-puhn struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique ouverte", "def": "The EU idea of remaining open to trade while reducing strategic vulnerabilities.", "ex": "Open strategic autonomy tries to avoid protectionism."}, {"term": "de-risking", "ipa": "/ˌdiːˈrɪskɪŋ/", "pron": "dee-RISK-ing", "fr": "réduction des risques ; dérisquage", "def": "Reducing risky dependencies without cutting all ties.", "ex": "The EU promotes de-risking from China, not full decoupling."}, {"term": "decoupling", "ipa": "/ˌdiːˈkʌplɪŋ/", "pron": "dee-KUP-ling", "fr": "découplage", "def": "Separating economies or systems previously connected.", "ex": "Most EU leaders reject full decoupling from China."}, {"term": "to deepen integration", "ipa": "/ˈdiːpən ˌɪntɪˈɡreɪʃən/", "pron": "DEE-puhn in-ti-GRAY-shuhn", "fr": "approfondir l’intégration", "def": "To make EU cooperation more extensive or powerful.", "ex": "Crises have sometimes deepened integration."}, {"term": "to pool sovereignty", "ipa": "/puːl ˈsɒvrənti/", "pron": "pool SOV-ruhn-tee", "fr": "mettre en commun la souveraineté", "def": "To share national powers with others through common institutions.", "ex": "EU members pool sovereignty in selected areas."}, {"term": "to transfer powers to Brussels", "ipa": "/trænsˈfɜː ˈpaʊəz tə ˈbrʌsəlz/", "pron": "trans-FUR POW-uhz tuh BRUSS-uhlz", "fr": "transférer des compétences à Bruxelles", "def": "To give EU institutions more authority.", "ex": "Eurosceptics oppose transferring powers to Brussels."}, {"term": "to enforce EU law", "ipa": "/ɪnˈfɔːs ˌiː ˈjuː lɔː/", "pron": "in-FORSS ee-yoo law", "fr": "faire respecter le droit de l’UE", "def": "To make sure EU law is obeyed.", "ex": "The Commission can enforce EU law."}, {"term": "to launch infringement proceedings", "ipa": "/lɔːntʃ ɪnˈfrɪndʒmənt prəˈsiːdɪŋz/", "pron": "launch in-FRINJ-muhnt pruh-SEE-dingz", "fr": "lancer une procédure d’infraction", "def": "To start a legal procedure against a member state for breaching EU law.", "ex": "The Commission may launch infringement proceedings."}, {"term": "to remove trade barriers", "ipa": "/rɪˈmuːv ˈtreɪd ˌbæriəz/", "pron": "ri-MOOV trade BARR-ee-uhz", "fr": "supprimer les barrières commerciales", "def": "To eliminate obstacles to trade.", "ex": "The single market removes trade barriers."}, {"term": "to protect the single market", "ipa": "/prəˈtekt ðə ˌsɪŋɡəl ˈmɑːkɪt/", "pron": "pruh-TEKT thuh SING-guhl MAR-kit", "fr": "protéger le marché unique", "def": "To preserve fair and open conditions inside the EU market.", "ex": "EU rules protect the single market."}, {"term": "to uphold the rule of law", "ipa": "/ʌpˈhəʊld ðə ˌruːl əv ˈlɔː/", "pron": "up-HOHLD thuh rool ov law", "fr": "défendre l’État de droit", "def": "To defend legal and democratic principles.", "ex": "The EU must uphold the rule of law among its members."}, {"term": "to suspend EU funds", "ipa": "/səˈspend ˌiː ˈjuː fʌndz/", "pron": "suh-SPEND ee-yoo fundz", "fr": "suspendre les fonds européens", "def": "To stop payment of EU money.", "ex": "The EU can suspend funds over rule-of-law concerns."}, {"term": "to strengthen European defence", "ipa": "/ˈstreŋθən ˌjʊərəpiːən dɪˈfens/", "pron": "STRENG-thuhn YOOR-uh-pee-uhn di-FENS", "fr": "renforcer la défense européenne", "def": "To increase Europe’s defence capacity.", "ex": "The Ukraine war pushed states to strengthen European defence."}, {"term": "to reduce dependency", "ipa": "/rɪˈdjuːs dɪˈpendənsi/", "pron": "ri-DYOOSS di-PEN-duhn-see", "fr": "réduire la dépendance", "def": "To become less reliant on another actor.", "ex": "The EU seeks to reduce dependency on authoritarian suppliers."}, {"term": "to diversify energy supplies", "ipa": "/daɪˈvɜːsɪfaɪ ˈenədʒi səˈplaɪz/", "pron": "dy-VUR-si-fy EN-uh-jee suh-PLYZ", "fr": "diversifier les approvisionnements énergétiques", "def": "To obtain energy from a wider range of sources.", "ex": "Europe moved to diversify energy supplies."}, {"term": "to regulate Big Tech", "ipa": "/ˈreɡjʊleɪt ˌbɪɡ ˈtek/", "pron": "REG-yuh-layt big tek", "fr": "réglementer les géants du numérique", "def": "To impose rules on large technology companies.", "ex": "The EU has tried to regulate Big Tech."}, {"term": "to act as a geopolitical power", "ipa": "/ækt əz ə ˌdʒiːəʊpəˈlɪtɪkəl ˈpaʊə/", "pron": "akt az uh jee-oh-puh-LIT-i-kuhl POW-uh", "fr": "agir comme une puissance géopolitique", "def": "To behave as a strategic actor in world affairs.", "ex": "The EU wants to act as a geopolitical power."}, {"term": "to balance unity and diversity", "ipa": "/ˈbæləns ˈjuːnəti ənd daɪˈvɜːsəti/", "pron": "BAL-uhns YOO-nuh-tee and dy-VUR-suh-tee", "fr": "concilier unité et diversité", "def": "To reconcile common action with national differences.", "ex": "The EU must balance unity and diversity."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p6c57", "part": 6, "chapter": 57, "title": "Middle East", "file": "cpge_vocab_part6_chapter57_middle_east_premium.html", "count": 153, "sections": [{"title": "A. Core regional geography, energy and political systems", "entries": [{"term": "Middle East", "ipa": "/ˌmɪdəl ˈiːst/", "pron": "MID-uhl EAST", "fr": "Moyen-Orient", "def": "A geopolitical region usually including Western Asia and Egypt, though definitions vary.", "ex": "The Middle East is central to debates about energy, religion, war and great-power rivalry."}, {"term": "MENA", "ipa": "/ˈmiːnə/", "pron": "MEE-nuh", "fr": "MENA ; Moyen-Orient et Afrique du Nord", "def": "Abbreviation for Middle East and North Africa.", "ex": "The MENA region includes both Arab and non-Arab states."}, {"term": "Arab world", "ipa": "/ˌærəb ˈwɜːld/", "pron": "ARR-uhb world", "fr": "monde arabe", "def": "Countries where Arabic is widely spoken and Arab identity is politically or culturally important.", "ex": "The Arab world is diverse and cannot be reduced to a single political model."}, {"term": "Gulf states", "ipa": "/ˈɡʌlf steɪts/", "pron": "gulf states", "fr": "États du Golfe", "def": "States located around the Persian Gulf, often wealthy because of oil and gas.", "ex": "The Gulf states play a growing diplomatic and economic role."}, {"term": "Persian Gulf", "ipa": "/ˌpɜːʒən ˈɡʌlf/", "pron": "PUR-zhuhn gulf", "fr": "golfe Persique", "def": "A strategic body of water bordered by Iran and several Arab states.", "ex": "The Persian Gulf is vital for global energy flows."}, {"term": "Levant", "ipa": "/ləˈvænt/", "pron": "luh-VANT", "fr": "Levant", "def": "The eastern Mediterranean region, often including Syria, Lebanon, Jordan, Israel and Palestine.", "ex": "The Levant has been shaped by empires, borders and conflicts."}, {"term": "Maghreb", "ipa": "/ˈmʌɡrəb/", "pron": "MUG-ruhb", "fr": "Maghreb", "def": "North-western Africa, often including Morocco, Algeria, Tunisia and sometimes Libya and Mauritania.", "ex": "The Maghreb is linked to Europe through migration, trade and colonial history."}, {"term": "Mashriq", "ipa": "/ˈmæʃrɪk/", "pron": "MASH-rik", "fr": "Machrek", "def": "The eastern part of the Arab world.", "ex": "The Mashriq includes countries such as Iraq, Syria, Lebanon, Jordan and Palestine."}, {"term": "geopolitical hotspot", "ipa": "/ˌdʒiːəʊpəˈlɪtɪkəl ˈhɒtspɒt/", "pron": "jee-oh-puh-LIT-i-kuhl HOT-spot", "fr": "point chaud géopolitique", "def": "A region where tensions, conflicts or rivalries are especially intense.", "ex": "The Middle East is often described as a geopolitical hotspot."}, {"term": "strategic crossroads", "ipa": "/strəˌtiːdʒɪk ˈkrɒsrəʊdz/", "pron": "struh-TEE-jik CROSS-rohdz", "fr": "carrefour stratégique", "def": "A place connecting important regions, routes or interests.", "ex": "The Middle East is a strategic crossroads between Europe, Asia and Africa."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy supplies.", "ex": "Energy security explains much foreign interest in the Middle East."}, {"term": "oil reserves", "ipa": "/ˈɔɪl rɪˌzɜːvz/", "pron": "oil ri-ZURVZ", "fr": "réserves de pétrole", "def": "Known quantities of oil that can be extracted.", "ex": "The region contains some of the world’s largest oil reserves."}, {"term": "natural gas", "ipa": "/ˌnætʃərəl ˈɡæs/", "pron": "NAT-chuh-ruhl gas", "fr": "gaz naturel", "def": "Gas used as an energy source for heating, electricity and industry.", "ex": "Natural gas has made Qatar an influential energy exporter."}, {"term": "hydrocarbons", "ipa": "/ˌhaɪdrəʊˈkɑːbənz/", "pron": "HY-droh-KAR-buhnz", "fr": "hydrocarbures", "def": "Oil and gas resources.", "ex": "Hydrocarbons have shaped the economies of Gulf states."}, {"term": "petrodollar", "ipa": "/ˈpetrəʊˌdɒlə/", "pron": "PET-roh-DOL-uh", "fr": "pétrodollar", "def": "Money earned by oil-exporting countries through oil sales.", "ex": "Petrodollars have funded development and foreign investment."}, {"term": "rentier state", "ipa": "/ˈrɒntieɪ steɪt/", "pron": "RON-tee-ay state", "fr": "État rentier", "def": "A state relying heavily on income from natural resources rather than taxation.", "ex": "Rentier states may provide benefits while limiting political participation."}, {"term": "resource curse", "ipa": "/rɪˈsɔːs kɜːs/", "pron": "ri-SORSS curse", "fr": "malédiction des ressources", "def": "The paradox that resource-rich countries may suffer from corruption, dependency or weak institutions.", "ex": "The resource curse can affect oil-rich states."}, {"term": "OPEC", "ipa": "/ˈəʊpek/", "pron": "OH-pek", "fr": "OPEP", "def": "Organization of the Petroleum Exporting Countries.", "ex": "OPEC influences global oil markets."}, {"term": "oil price shock", "ipa": "/ˈɔɪl praɪs ʃɒk/", "pron": "oil price shok", "fr": "choc pétrolier", "def": "A sudden major rise or fall in oil prices.", "ex": "Oil price shocks can affect the global economy."}, {"term": "energy transition", "ipa": "/ˈenədʒi trænˌzɪʃən/", "pron": "EN-uh-jee tran-ZISH-uhn", "fr": "transition énergétique", "def": "The shift from fossil fuels to low-carbon energy.", "ex": "The energy transition challenges oil-dependent economies."}, {"term": "economic diversification", "ipa": "/ˌiːkəˈnɒmɪk daɪˌvɜːsɪfɪˈkeɪʃən/", "pron": "ee-kuh-NOM-ik dy-vur-si-fi-KAY-shuhn", "fr": "diversification économique", "def": "Reducing dependence on one sector by developing others.", "ex": "Saudi Arabia seeks economic diversification beyond oil."}, {"term": "Vision 2030", "ipa": "/ˌvɪʒən ˌtwenti ˈθɜːti/", "pron": "VIZH-uhn twenty-THUR-tee", "fr": "Vision 2030", "def": "Saudi Arabia’s economic and social reform programme.", "ex": "Vision 2030 aims to diversify the Saudi economy."}, {"term": "authoritarianism", "ipa": "/ɔːˌθɒrɪˈteəriənɪzəm/", "pron": "aw-thor-i-TAIR-ee-uh-niz-uhm", "fr": "autoritarisme", "def": "A system with limited political freedoms and strong central control.", "ex": "Authoritarianism remains common across the region."}, {"term": "monarchy", "ipa": "/ˈmɒnəki/", "pron": "MON-uh-kee", "fr": "monarchie", "def": "A political system headed by a king, queen, emir or similar ruler.", "ex": "Several Gulf states are monarchies."}, {"term": "absolute monarchy", "ipa": "/ˌæbsəluːt ˈmɒnəki/", "pron": "AB-suh-loot MON-uh-kee", "fr": "monarchie absolue", "def": "A monarchy where the ruler has very broad powers.", "ex": "Saudi Arabia is often described as an absolute monarchy."}, {"term": "constitutional monarchy", "ipa": "/ˌkɒnstɪˈtjuːʃənəl ˈmɒnəki/", "pron": "kon-sti-TYOO-shuh-nuhl MON-uh-kee", "fr": "monarchie constitutionnelle", "def": "A monarchy limited by laws, a constitution or representative institutions.", "ex": "Jordan and Morocco are constitutional monarchies."}, {"term": "republic", "ipa": "/rɪˈpʌblɪk/", "pron": "ri-PUB-lik", "fr": "république", "def": "A state without a monarch, usually led by elected or appointed officials.", "ex": "Some Middle Eastern republics are authoritarian in practice."}, {"term": "military regime", "ipa": "/ˌmɪlɪtəri reɪˈʒiːm/", "pron": "MIL-i-tuh-ree ray-ZHEEM", "fr": "régime militaire", "def": "A government dominated by the military.", "ex": "Military regimes often justify rule through stability and security."}, {"term": "security state", "ipa": "/sɪˈkjʊərəti steɪt/", "pron": "si-KYOOR-uh-tee state", "fr": "État sécuritaire", "def": "A state where security forces play a dominant role in governance.", "ex": "A security state can suppress dissent in the name of order."}, {"term": "political repression", "ipa": "/pəˌlɪtɪkəl rɪˈpreʃən/", "pron": "puh-LIT-i-kuhl ri-PRESH-uhn", "fr": "répression politique", "def": "Suppression of opposition, protest or political freedoms.", "ex": "Political repression intensified after many uprisings failed."}, {"term": "dissent", "ipa": "/dɪˈsent/", "pron": "di-SENT", "fr": "dissidence ; contestation", "def": "Public disagreement with authority or official policy.", "ex": "Dissent is often restricted by authoritarian regimes."}, {"term": "civil society", "ipa": "/ˌsɪvəl səˈsaɪəti/", "pron": "SIV-uhl suh-SY-uh-tee", "fr": "société civile", "def": "Independent organisations and associations outside the state and business.", "ex": "Civil society was active during the Arab Spring."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Human rights concerns affect relations with regional allies."}, {"term": "women’s rights", "ipa": "/ˌwɪmɪnz ˈraɪts/", "pron": "WIM-inz rites", "fr": "droits des femmes", "def": "Rights and freedoms concerning women’s equality and autonomy.", "ex": "Women’s rights vary widely across the Middle East."}, {"term": "minority rights", "ipa": "/maɪˌnɒrəti ˈraɪts/", "pron": "my-NOR-uh-tee rites", "fr": "droits des minorités", "def": "Rights protecting ethnic, religious or linguistic minorities.", "ex": "Minority rights are central in multi-confessional societies."}, {"term": "sectarianism", "ipa": "/sekˈteəriənɪzəm/", "pron": "sek-TAIR-ee-uh-niz-uhm", "fr": "sectarisme ; confessionnalisme", "def": "Political or social division based on religious sect or community.", "ex": "Sectarianism has fuelled violence in Iraq, Lebanon and Syria."}]}, {"title": "B. Religion, identity, Arab Spring and regional rivalries", "entries": [{"term": "Sunni", "ipa": "/ˈsʊni/", "pron": "SUUN-ee", "fr": "sunnite", "def": "A major branch of Islam.", "ex": "Sunni communities are diverse across the region."}, {"term": "Shia", "ipa": "/ˈʃiːə/", "pron": "SHEE-uh", "fr": "chiite", "def": "A major branch of Islam.", "ex": "Iran is a major Shia power."}, {"term": "Sunni-Shia divide", "ipa": "/ˌsʊni ˈʃiːə dɪˈvaɪd/", "pron": "SUUN-ee SHEE-uh di-VYDE", "fr": "division sunnites-chiites", "def": "Political and religious tensions between Sunni and Shia communities or states.", "ex": "The Sunni-Shia divide is often politicised."}, {"term": "confessional system", "ipa": "/kənˈfeʃənəl ˈsɪstəm/", "pron": "kuhn-FESH-uh-nuhl SIS-tuhm", "fr": "système confessionnel", "def": "A political system distributing power among religious communities.", "ex": "Lebanon’s confessional system aims to balance communities but can produce deadlock."}, {"term": "Islamism", "ipa": "/ˈɪzləmɪzəm/", "pron": "IZ-luh-miz-uhm", "fr": "islamisme", "def": "Political movements seeking to organise society or politics according to Islamic principles.", "ex": "Islamism includes many non-violent and violent movements."}, {"term": "political Islam", "ipa": "/pəˌlɪtɪkəl ˈɪzlɑːm/", "pron": "puh-LIT-i-kuhl IZ-lahm", "fr": "islam politique", "def": "The use of Islamic ideas in political movements and governance.", "ex": "Political Islam became prominent after the Arab Spring."}, {"term": "secularism", "ipa": "/ˈsekjʊlərɪzəm/", "pron": "SEK-yuh-luh-riz-uhm", "fr": "laïcité ; sécularisme", "def": "The separation of religion from state institutions or politics.", "ex": "Secularism is interpreted differently across the region."}, {"term": "Arab nationalism", "ipa": "/ˌærəb ˈnæʃənəlɪzəm/", "pron": "ARR-uhb NASH-uh-nuh-liz-uhm", "fr": "nationalisme arabe", "def": "A political ideology emphasising common Arab identity and unity.", "ex": "Arab nationalism was influential in the 20th century."}, {"term": "pan-Arabism", "ipa": "/ˌpæn ˈærəbɪzəm/", "pron": "pan-ARR-uh-biz-uhm", "fr": "panarabisme", "def": "The idea that Arab peoples should be politically united or closely aligned.", "ex": "Pan-Arabism declined after repeated political failures."}, {"term": "Zionism", "ipa": "/ˈzaɪənɪzəm/", "pron": "ZY-uh-niz-uhm", "fr": "sionisme", "def": "A movement supporting Jewish self-determination and the state of Israel.", "ex": "Zionism is central to the history of Israel."}, {"term": "anti-Zionism", "ipa": "/ˌænti ˈzaɪənɪzəm/", "pron": "AN-tee ZY-uh-niz-uhm", "fr": "antisionisme", "def": "Opposition to Zionism or to Israel as a Jewish state.", "ex": "Anti-Zionism must be distinguished carefully from antisemitism, though the two can overlap."}, {"term": "antisemitism", "ipa": "/ˌæntiˈsemɪtɪzəm/", "pron": "an-tee-SEM-i-tiz-uhm", "fr": "antisémitisme", "def": "Hostility, prejudice or discrimination against Jews.", "ex": "Antisemitism can rise during Middle East crises."}, {"term": "Islamophobia", "ipa": "/ɪzˌlæməˈfəʊbiə/", "pron": "iz-lam-uh-FOH-bee-uh", "fr": "islamophobie", "def": "Hostility, prejudice or discrimination against Muslims.", "ex": "Islamophobia can be fuelled by simplistic views of the region."}, {"term": "Arab Spring", "ipa": "/ˌærəb ˈsprɪŋ/", "pron": "ARR-uhb spring", "fr": "Printemps arabe", "def": "A wave of protests and uprisings across the Arab world from 2010 onwards.", "ex": "The Arab Spring raised hopes for democracy but led to mixed outcomes."}, {"term": "uprising", "ipa": "/ˈʌpraɪzɪŋ/", "pron": "UP-ry-zing", "fr": "soulèvement", "def": "A revolt or rebellion against authority.", "ex": "The uprising began with mass protests."}, {"term": "revolution", "ipa": "/ˌrevəˈluːʃən/", "pron": "rev-uh-LOO-shuhn", "fr": "révolution", "def": "A major political overthrow or transformation.", "ex": "The Egyptian revolution removed a long-standing ruler."}, {"term": "counter-revolution", "ipa": "/ˌkaʊntə revəˈluːʃən/", "pron": "KOWN-tuh rev-uh-LOO-shuhn", "fr": "contre-révolution", "def": "A movement or reaction against a revolution.", "ex": "Counter-revolutionary forces restored authoritarian control in some countries."}, {"term": "democratic transition", "ipa": "/ˌdeməkrætɪk trænˈzɪʃən/", "pron": "dem-uh-KRAT-ik tran-ZISH-uhn", "fr": "transition démocratique", "def": "A shift from authoritarian rule towards democracy.", "ex": "Tunisia initially seemed to offer a democratic transition."}, {"term": "failed state", "ipa": "/ˌfeɪld ˈsteɪt/", "pron": "failed state", "fr": "État failli", "def": "A state unable to provide basic security, services or authority.", "ex": "Yemen is often described as close to a failed state."}, {"term": "state collapse", "ipa": "/ˈsteɪt kəˌlæps/", "pron": "state kuh-LAPS", "fr": "effondrement de l’État", "def": "The breakdown of central state authority.", "ex": "State collapse creates space for militias and extremist groups."}, {"term": "civil war", "ipa": "/ˌsɪvəl ˈwɔː/", "pron": "SIV-uhl war", "fr": "guerre civile", "def": "A war between groups within the same country.", "ex": "Syria’s civil war became an internationalised conflict."}, {"term": "proxy war", "ipa": "/ˈprɒksi wɔː/", "pron": "PROK-see war", "fr": "guerre par procuration", "def": "A conflict where outside powers support opposing sides indirectly.", "ex": "Yemen became a proxy war involving regional powers."}, {"term": "regional rivalry", "ipa": "/ˌriːdʒənəl ˈraɪvəlri/", "pron": "REE-juh-nuhl RY-vuhl-ree", "fr": "rivalité régionale", "def": "Competition between powers within a region.", "ex": "The Saudi-Iranian rivalry shapes many conflicts."}, {"term": "Saudi Arabia", "ipa": "/ˌsaʊdi əˈreɪbiə/", "pron": "SOW-dee uh-RAY-bee-uh", "fr": "Arabie saoudite", "def": "A major Gulf monarchy and oil producer.", "ex": "Saudi Arabia is a key US partner and regional power."}, {"term": "Iran", "ipa": "/ɪˈrɑːn/", "pron": "i-RAHN", "fr": "Iran", "def": "A major regional power and Islamic republic.", "ex": "Iran competes with Saudi Arabia and opposes US influence."}, {"term": "Saudi-Iranian rivalry", "ipa": "/ˌsaʊdi ɪˈrɑːniən ˈraɪvəlri/", "pron": "SOW-dee i-RAH-nee-uhn RY-vuhl-ree", "fr": "rivalité saoudo-iranienne", "def": "The geopolitical rivalry between Saudi Arabia and Iran.", "ex": "The Saudi-Iranian rivalry has a sectarian and strategic dimension."}, {"term": "Israel", "ipa": "/ˈɪzreɪəl/", "pron": "IZ-ray-uhl", "fr": "Israël", "def": "A state in the eastern Mediterranean created in 1948.", "ex": "Israel is a central actor in Middle Eastern geopolitics."}, {"term": "Palestine", "ipa": "/ˈpælɪstaɪn/", "pron": "PAL-i-styne", "fr": "Palestine", "def": "A contested territory and national cause associated with Palestinian self-determination.", "ex": "Palestine remains at the heart of one of the region’s longest conflicts."}, {"term": "Palestinians", "ipa": "/ˌpælɪˈstɪniənz/", "pron": "pal-i-STIN-ee-uhnz", "fr": "Palestiniens", "def": "The Arab people associated with Palestine and Palestinian national identity.", "ex": "Palestinians seek statehood, rights and self-determination."}, {"term": "Israel-Palestine conflict", "ipa": "/ˌɪzreɪəl ˈpælɪstaɪn ˈkɒnflɪkt/", "pron": "IZ-ray-uhl PAL-i-styne KON-flikt", "fr": "conflit israélo-palestinien", "def": "The conflict between Israelis and Palestinians over land, rights, security and sovereignty.", "ex": "The Israel-Palestine conflict is both territorial and national."}, {"term": "two-state solution", "ipa": "/ˌtuː steɪt səˈluːʃən/", "pron": "two-state suh-LOO-shuhn", "fr": "solution à deux États", "def": "A proposed solution with Israel and a Palestinian state living side by side.", "ex": "The two-state solution remains widely supported diplomatically but difficult to implement."}, {"term": "one-state solution", "ipa": "/ˌwʌn steɪt səˈluːʃən/", "pron": "one-state suh-LOO-shuhn", "fr": "solution à un État", "def": "A proposed solution with one state for Israelis and Palestinians.", "ex": "The one-state solution raises difficult questions about equality and identity."}, {"term": "occupation", "ipa": "/ˌɒkjʊˈpeɪʃən/", "pron": "ok-yuh-PAY-shuhn", "fr": "occupation", "def": "Control of a territory by a foreign military power.", "ex": "The occupation of Palestinian territories is a major source of conflict."}, {"term": "occupied territories", "ipa": "/ˌɒkjʊpaɪd ˈterɪtəriz/", "pron": "OK-yuh-pyd TERR-i-tuh-reez", "fr": "territoires occupés", "def": "Territories under military occupation.", "ex": "The status of the occupied territories is disputed."}, {"term": "West Bank", "ipa": "/ˌwest ˈbæŋk/", "pron": "west bank", "fr": "Cisjordanie", "def": "A Palestinian territory west of the River Jordan.", "ex": "Settlements in the West Bank are a major obstacle to peace."}, {"term": "Gaza Strip", "ipa": "/ˈɡɑːzə strɪp/", "pron": "GAH-zuh strip", "fr": "bande de Gaza", "def": "A small Palestinian territory on the Mediterranean coast.", "ex": "The Gaza Strip has suffered repeated wars and blockades."}, {"term": "East Jerusalem", "ipa": "/ˌiːst dʒəˈruːsələm/", "pron": "east juh-ROO-suh-luhm", "fr": "Jérusalem-Est", "def": "The eastern part of Jerusalem, claimed by Palestinians as a future capital.", "ex": "East Jerusalem is central to final-status negotiations."}, {"term": "settlement", "ipa": "/ˈsetəlmənt/", "pron": "SET-uhl-muhnt", "fr": "colonie ; implantation", "def": "A community built by civilians in occupied or disputed territory.", "ex": "Israeli settlements are widely considered illegal under international law."}]}, {"title": "C. Israel-Palestine, armed groups and nuclear diplomacy", "entries": [{"term": "settler", "ipa": "/ˈsetlə/", "pron": "SET-luh", "fr": "colon", "def": "A person living in a settlement.", "ex": "Settler violence has increased tensions."}, {"term": "annexation", "ipa": "/ˌænekˈseɪʃən/", "pron": "an-ek-SAY-shuhn", "fr": "annexion", "def": "The incorporation of territory into another state, often by force.", "ex": "Annexation is rejected by many international actors."}, {"term": "blockade", "ipa": "/blɒˈkeɪd/", "pron": "blok-AYD", "fr": "blocus", "def": "An action restricting movement of goods or people into or out of an area.", "ex": "The blockade of Gaza has been criticised for humanitarian reasons."}, {"term": "siege", "ipa": "/siːdʒ/", "pron": "seej", "fr": "siège", "def": "A military operation surrounding an area to cut supplies or force surrender.", "ex": "A siege can create severe humanitarian suffering."}, {"term": "ceasefire", "ipa": "/ˈsiːsfaɪə/", "pron": "SEESS-fire", "fr": "cessez-le-feu", "def": "An agreement to stop fighting temporarily or permanently.", "ex": "Mediators called for an immediate ceasefire."}, {"term": "peace process", "ipa": "/ˈpiːs ˌprəʊses/", "pron": "peace PROH-ses", "fr": "processus de paix", "def": "A series of diplomatic efforts to end conflict.", "ex": "The peace process has repeatedly stalled."}, {"term": "Oslo Accords", "ipa": "/ˈɒzləʊ əˌkɔːdz/", "pron": "OZ-loh uh-KORDZ", "fr": "accords d’Oslo", "def": "Agreements signed in the 1990s between Israel and the PLO.", "ex": "The Oslo Accords created the Palestinian Authority."}, {"term": "Palestinian Authority", "ipa": "/ˌpælɪˈstɪniən ɔːˈθɒrəti/", "pron": "pal-i-STIN-ee-uhn aw-THOR-uh-tee", "fr": "Autorité palestinienne", "def": "The Palestinian self-government body created after the Oslo process.", "ex": "The Palestinian Authority governs parts of the West Bank."}, {"term": "PLO", "ipa": "/ˌpiː el ˈəʊ/", "pron": "pee-el-oh", "fr": "OLP", "def": "Palestine Liberation Organization.", "ex": "The PLO has represented Palestinian national aspirations."}, {"term": "Hamas", "ipa": "/həˈmæs/", "pron": "huh-MASS", "fr": "Hamas", "def": "A Palestinian Islamist movement and armed group controlling Gaza since 2007.", "ex": "Hamas is designated as a terrorist organisation by several countries."}, {"term": "Hezbollah", "ipa": "/ˌhezbəˈlɑː/", "pron": "HEZ-buh-LAH", "fr": "Hezbollah", "def": "A Lebanese Shia political and armed movement backed by Iran.", "ex": "Hezbollah is a major non-state actor in Lebanon and the region."}, {"term": "non-state actor", "ipa": "/ˌnɒn steɪt ˈæktə/", "pron": "non-state AK-tuh", "fr": "acteur non étatique", "def": "An influential actor that is not a government.", "ex": "Militias and armed groups are important non-state actors."}, {"term": "militia", "ipa": "/məˈlɪʃə/", "pron": "muh-LISH-uh", "fr": "milice", "def": "An armed group not always part of a regular army.", "ex": "Militias gained power during state collapse."}, {"term": "armed group", "ipa": "/ˌɑːmd ˈɡruːp/", "pron": "armd group", "fr": "groupe armé", "def": "A group using weapons for political, military or ideological goals.", "ex": "Armed groups often challenge state authority."}, {"term": "insurgency", "ipa": "/ɪnˈsɜːdʒənsi/", "pron": "in-SUR-juhn-see", "fr": "insurrection", "def": "An organised rebellion against a government or occupying power.", "ex": "Insurgency can merge with terrorism or guerrilla warfare."}, {"term": "terrorism", "ipa": "/ˈterərɪzəm/", "pron": "TERR-uh-riz-uhm", "fr": "terrorisme", "def": "The use or threat of violence against civilians for political aims.", "ex": "Terrorism has shaped security policies across the region."}, {"term": "counterterrorism", "ipa": "/ˌkaʊntəˈterərɪzəm/", "pron": "KOWN-tuh-TERR-uh-riz-uhm", "fr": "contre-terrorisme", "def": "Policies and actions designed to prevent and respond to terrorism.", "ex": "Counterterrorism cooperation can strengthen authoritarian security services."}, {"term": "Iran nuclear deal", "ipa": "/ɪˈrɑːn ˈnjuːkliə diːl/", "pron": "i-RAHN NYOO-klee-uh deal", "fr": "accord sur le nucléaire iranien", "def": "The 2015 agreement limiting Iran’s nuclear programme in exchange for sanctions relief.", "ex": "The Iran nuclear deal became a major diplomatic controversy."}, {"term": "JCPOA", "ipa": "/ˌdʒeɪ siː piː əʊ ˈeɪ/", "pron": "jay-see-pee-oh-ay", "fr": "JCPOA ; accord de Vienne", "def": "Joint Comprehensive Plan of Action, the formal name of the Iran nuclear deal.", "ex": "The JCPOA aimed to prevent Iran from developing nuclear weapons."}, {"term": "nuclear proliferation", "ipa": "/ˌnjuːkliə prəˌlɪfəˈreɪʃən/", "pron": "NYOO-klee-uh pruh-lif-uh-RAY-shuhn", "fr": "prolifération nucléaire", "def": "The spread of nuclear weapons or related technology.", "ex": "Nuclear proliferation is a major concern in the Middle East."}, {"term": "uranium enrichment", "ipa": "/jʊˌreɪniəm ɪnˈrɪtʃmənt/", "pron": "yoo-RAY-nee-uhm in-RICH-muhnt", "fr": "enrichissement de l’uranium", "def": "The process of increasing the concentration of uranium isotopes for nuclear use.", "ex": "Uranium enrichment is central to concerns about Iran’s nuclear programme."}, {"term": "sanctions", "ipa": "/ˈsæŋkʃənz/", "pron": "SANK-shuhnz", "fr": "sanctions", "def": "Economic or political penalties imposed to change behaviour.", "ex": "Sanctions have heavily affected Iran’s economy."}, {"term": "sanctions relief", "ipa": "/ˈsæŋkʃənz rɪˌliːf/", "pron": "SANK-shuhnz ri-LEEF", "fr": "allègement des sanctions", "def": "Reduction or removal of sanctions.", "ex": "Iran sought sanctions relief under the nuclear deal."}, {"term": "regional power", "ipa": "/ˌriːdʒənəl ˈpaʊə/", "pron": "REE-juh-nuhl POW-uh", "fr": "puissance régionale", "def": "A state with major influence in its region.", "ex": "Iran, Saudi Arabia, Turkey and Israel are regional powers."}, {"term": "Turkey", "ipa": "/ˈtɜːki/", "pron": "TUR-kee", "fr": "Turquie", "def": "A state linking Europe, the Middle East and Asia.", "ex": "Turkey plays a complex role in NATO, Syria and regional diplomacy."}, {"term": "Qatar", "ipa": "/kæˈtɑː/", "pron": "ka-TAR", "fr": "Qatar", "def": "A Gulf state with major gas wealth and diplomatic influence.", "ex": "Qatar often acts as a mediator in regional conflicts."}, {"term": "United Arab Emirates", "ipa": "/juːˌnaɪtɪd ˌærəb ˈemɪrəts/", "pron": "yoo-NY-tid ARR-uhb EM-i-ruhts", "fr": "Émirats arabes unis", "def": "A federation of Gulf emirates, including Abu Dhabi and Dubai.", "ex": "The United Arab Emirates has become an assertive regional actor."}, {"term": "UAE", "ipa": "/ˌjuː eɪ ˈiː/", "pron": "yoo-ay-ee", "fr": "EAU", "def": "Abbreviation for United Arab Emirates.", "ex": "The UAE invests heavily abroad."}, {"term": "Egypt", "ipa": "/ˈiːdʒɪpt/", "pron": "EE-jipt", "fr": "Égypte", "def": "A major Arab state in North Africa with strategic control of the Suez Canal.", "ex": "Egypt remains influential in Arab diplomacy."}, {"term": "Iraq", "ipa": "/ɪˈrɑːk/", "pron": "i-RAHK", "fr": "Irak", "def": "A state shaped by dictatorship, invasion, sectarian conflict and regional rivalry.", "ex": "Iraq became a battleground for regional and international influence."}, {"term": "Syria", "ipa": "/ˈsɪriə/", "pron": "SEER-ee-uh", "fr": "Syrie", "def": "A state devastated by civil war since 2011.", "ex": "Syria’s civil war drew in Russia, Iran, Turkey and Western powers."}, {"term": "Lebanon", "ipa": "/ˈlebənən/", "pron": "LEB-uh-nuhn", "fr": "Liban", "def": "A multi-confessional state facing political and economic crises.", "ex": "Lebanon’s political system is shaped by sectarian power-sharing."}, {"term": "Yemen", "ipa": "/ˈjemən/", "pron": "YEM-uhn", "fr": "Yémen", "def": "A state facing civil war, humanitarian crisis and regional intervention.", "ex": "Yemen has experienced one of the world’s worst humanitarian crises."}, {"term": "Suez Canal", "ipa": "/ˌsuːez kəˈnæl/", "pron": "SOO-ez kuh-NAL", "fr": "canal de Suez", "def": "A strategic waterway in Egypt connecting the Mediterranean and Red Seas.", "ex": "The Suez Canal is vital for global trade."}, {"term": "Strait of Hormuz", "ipa": "/ˌstreɪt əv hɔːˈmuːz/", "pron": "strait ov hor-MOOZ", "fr": "détroit d’Ormuz", "def": "A narrow waterway through which much of the world’s oil passes.", "ex": "The Strait of Hormuz is a strategic chokepoint."}, {"term": "Bab el-Mandeb", "ipa": "/ˌbæb el ˈmændeb/", "pron": "bab-el-MAN-deb", "fr": "Bab el-Mandeb", "def": "A strategic strait connecting the Red Sea and Gulf of Aden.", "ex": "Instability near Bab el-Mandeb threatens shipping."}, {"term": "strategic chokepoint", "ipa": "/strəˌtiːdʒɪk ˈtʃəʊkpɔɪnt/", "pron": "struh-TEE-jik CHOHK-point", "fr": "point de passage stratégique", "def": "A narrow route critical to trade or military movement.", "ex": "The region contains several strategic chokepoints."}, {"term": "shipping lane", "ipa": "/ˈʃɪpɪŋ leɪn/", "pron": "SHIP-ing lane", "fr": "voie maritime", "def": "A sea route used by commercial ships.", "ex": "Shipping lanes in the Red Sea are vital for world trade."}, {"term": "maritime security", "ipa": "/ˈmærɪtaɪm sɪˌkjʊərəti/", "pron": "MARR-i-time si-KYOOR-uh-tee", "fr": "sécurité maritime", "def": "Protection of sea routes, ports and shipping.", "ex": "Maritime security has become crucial in the Red Sea."}, {"term": "humanitarian crisis", "ipa": "/hjuːˌmænɪˈteəriən ˈkraɪsɪs/", "pron": "hyoo-man-i-TAIR-ee-uhn KRY-sis", "fr": "crise humanitaire", "def": "A situation causing widespread human suffering and urgent need.", "ex": "Wars in Syria, Gaza and Yemen have created humanitarian crises."}, {"term": "humanitarian aid", "ipa": "/hjuːˌmænɪˈteəriən ˈeɪd/", "pron": "hyoo-man-i-TAIR-ee-uhn aid", "fr": "aide humanitaire", "def": "Assistance such as food, water, medicine or shelter.", "ex": "Humanitarian aid is often blocked by fighting or siege conditions."}]}, {"title": "D. Regional powers, chokepoints, humanitarian crises and global involvement", "entries": [{"term": "displacement", "ipa": "/dɪsˈpleɪsmənt/", "pron": "dis-PLAYS-muhnt", "fr": "déplacement forcé", "def": "Forced movement of people from their homes.", "ex": "Conflict has caused mass displacement across the region."}, {"term": "refugee", "ipa": "/ˌrefjʊˈdʒiː/", "pron": "REF-yoo-jee", "fr": "réfugié", "def": "A person forced to flee their country because of war, persecution or violence.", "ex": "Syrian refugees transformed politics in neighbouring countries and Europe."}, {"term": "internally displaced person", "ipa": "/ɪnˌtɜːnəli dɪsˌpleɪst ˈpɜːsən/", "pron": "in-TUR-nuh-lee dis-PLAYST PUR-suhn", "fr": "personne déplacée interne", "def": "A person displaced within their own country.", "ex": "Internally displaced people often lack protection."}, {"term": "IDP", "ipa": "/ˌaɪ diː ˈpiː/", "pron": "eye-dee-pee", "fr": "PDI", "def": "Abbreviation for internally displaced person.", "ex": "IDPs may live in camps or informal shelters."}, {"term": "famine", "ipa": "/ˈfæmɪn/", "pron": "FAM-in", "fr": "famine", "def": "Extreme shortage of food causing hunger and death.", "ex": "War and blockade can contribute to famine."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Lack of reliable access to enough food.", "ex": "Food insecurity is severe in conflict zones."}, {"term": "water scarcity", "ipa": "/ˈwɔːtə ˌskeəsəti/", "pron": "WOR-tuh SKAIR-suh-tee", "fr": "pénurie d’eau", "def": "Lack of sufficient water resources.", "ex": "Water scarcity is a growing security issue."}, {"term": "climate stress", "ipa": "/ˈklaɪmət stres/", "pron": "KLY-muht stress", "fr": "stress climatique", "def": "Pressure caused by climate change or environmental degradation.", "ex": "Climate stress can worsen instability."}, {"term": "youth unemployment", "ipa": "/ˌjuːθ ˌʌnɪmˈplɔɪmənt/", "pron": "youth un-im-PLOY-muhnt", "fr": "chômage des jeunes", "def": "Unemployment affecting young people.", "ex": "Youth unemployment contributed to social frustration before the Arab Spring."}, {"term": "economic inequality", "ipa": "/ˌiːkəˈnɒmɪk ˌɪnɪˈkwɒləti/", "pron": "ee-kuh-NOM-ik in-i-KWOL-uh-tee", "fr": "inégalité économique", "def": "Unequal distribution of income, wealth or opportunities.", "ex": "Economic inequality fuels grievances."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Abuse of power for private gain.", "ex": "Corruption undermines trust in governments."}, {"term": "clientelism", "ipa": "/ˌklaɪənˈtelɪzəm/", "pron": "kly-uhn-TEL-iz-uhm", "fr": "clientélisme", "def": "A political system based on exchanging favours for loyalty.", "ex": "Clientelism weakens institutions and accountability."}, {"term": "great-power involvement", "ipa": "/ˌɡreɪt ˈpaʊə ɪnˈvɒlvmənt/", "pron": "great POW-uh in-VOLV-muhnt", "fr": "implication des grandes puissances", "def": "Intervention or influence by major world powers.", "ex": "Great-power involvement often internationalises local conflicts."}, {"term": "US influence", "ipa": "/ˌjuː es ˈɪnfluəns/", "pron": "yoo-ess IN-floo-uhns", "fr": "influence américaine", "def": "The political, military or economic influence of the United States.", "ex": "US influence in the Middle East has fluctuated."}, {"term": "Russian influence", "ipa": "/ˌrʌʃən ˈɪnfluəns/", "pron": "RUSH-uhn IN-floo-uhns", "fr": "influence russe", "def": "The influence of Russia in regional diplomacy or conflict.", "ex": "Russian influence grew through intervention in Syria."}, {"term": "Chinese investment", "ipa": "/ˌtʃaɪniːz ɪnˈvestmənt/", "pron": "chy-NEEZ in-VEST-muhnt", "fr": "investissement chinois", "def": "Investment by China or Chinese firms.", "ex": "Chinese investment focuses on infrastructure and energy."}, {"term": "normalisation", "ipa": "/ˌnɔːməlaɪˈzeɪʃən/", "pron": "NOR-muh-ly-ZAY-shuhn", "fr": "normalisation", "def": "The process of making diplomatic relations normal.", "ex": "Normalisation between Israel and Arab states reshaped diplomacy."}, {"term": "Abraham Accords", "ipa": "/ˈeɪbrəhæm əˌkɔːdz/", "pron": "AY-bruh-ham uh-KORDZ", "fr": "accords d’Abraham", "def": "Agreements normalising relations between Israel and several Arab states from 2020.", "ex": "The Abraham Accords reflected shifting regional priorities."}, {"term": "mediation", "ipa": "/ˌmiːdiˈeɪʃən/", "pron": "mee-dee-AY-shuhn", "fr": "médiation", "def": "Intervention by a neutral party to help resolve a dispute.", "ex": "Qatar has used mediation to raise its diplomatic profile."}, {"term": "back-channel diplomacy", "ipa": "/ˌbæk ˈtʃænəl dɪˈpləʊməsi/", "pron": "bak-CHAN-uhl di-PLOH-muh-see", "fr": "diplomatie de canal secret", "def": "Secret or unofficial communication between parties.", "ex": "Back-channel diplomacy is common in sensitive conflicts."}, {"term": "de-escalation", "ipa": "/ˌdiː eskəˈleɪʃən/", "pron": "dee-es-kuh-LAY-shuhn", "fr": "désescalade", "def": "Reduction of tension or violence.", "ex": "Regional rivals sometimes seek de-escalation through mediation."}, {"term": "deterrence", "ipa": "/dɪˈterəns/", "pron": "di-TERR-uhns", "fr": "dissuasion", "def": "Preventing action by threatening serious consequences.", "ex": "Deterrence shapes relations between Israel, Iran and the United States."}, {"term": "red line", "ipa": "/ˌred ˈlaɪn/", "pron": "red line", "fr": "ligne rouge", "def": "A limit that should not be crossed without consequences.", "ex": "Nuclear development is often described as a red line."}, {"term": "escalation ladder", "ipa": "/ˌeskəˈleɪʃən ˈlædə/", "pron": "es-kuh-LAY-shuhn LAD-uh", "fr": "échelle de l’escalade", "def": "A sequence of steps through which conflict becomes more intense.", "ex": "The escalation ladder can move quickly in regional crises."}, {"term": "to shape regional politics", "ipa": "/ʃeɪp ˌriːdʒənəl ˈpɒlətɪks/", "pron": "shayp REE-juh-nuhl POL-uh-tiks", "fr": "façonner la politique régionale", "def": "To influence political dynamics in a region.", "ex": "Sectarianism and energy shape regional politics."}, {"term": "to fuel instability", "ipa": "/ˈfjuːəl ˌɪnstəˈbɪləti/", "pron": "FYOO-uhl in-stuh-BIL-uh-tee", "fr": "alimenter l’instabilité", "def": "To make instability worse.", "ex": "Proxy wars fuel instability across the region."}, {"term": "to back a proxy", "ipa": "/bæk ə ˈprɒksi/", "pron": "bak uh PROK-see", "fr": "soutenir un proxy", "def": "To support an indirect ally or armed group.", "ex": "Regional powers often back proxies."}, {"term": "to broker a ceasefire", "ipa": "/ˈbrəʊkər ə ˈsiːsfaɪə/", "pron": "BROH-kuh uh SEESS-fire", "fr": "négocier un cessez-le-feu", "def": "To help parties agree to stop fighting.", "ex": "Mediators tried to broker a ceasefire."}, {"term": "to recognise a state", "ipa": "/ˈrekəɡnaɪz ə steɪt/", "pron": "REK-uhg-nyze uh state", "fr": "reconnaître un État", "def": "To officially accept a state’s legitimacy.", "ex": "Recognition of a Palestinian state remains debated."}, {"term": "to normalise relations", "ipa": "/ˈnɔːməlaɪz rɪˈleɪʃənz/", "pron": "NOR-muh-lyze ri-LAY-shuhnz", "fr": "normaliser les relations", "def": "To establish or restore normal diplomatic relations.", "ex": "Several Arab states normalised relations with Israel."}, {"term": "to impose a blockade", "ipa": "/ɪmˈpəʊz ə blɒˈkeɪd/", "pron": "im-POHZ uh blok-AYD", "fr": "imposer un blocus", "def": "To restrict movement into or out of an area.", "ex": "A blockade can create humanitarian hardship."}, {"term": "to launch air strikes", "ipa": "/lɔːntʃ ˈeə straɪks/", "pron": "launch air strikes", "fr": "lancer des frappes aériennes", "def": "To begin attacks from aircraft.", "ex": "States may launch air strikes against armed groups."}, {"term": "to displace civilians", "ipa": "/dɪsˈpleɪs səˈvɪliənz/", "pron": "dis-PLAYS suh-VIL-yuhnz", "fr": "déplacer des civils", "def": "To force civilians from their homes.", "ex": "War can displace civilians on a massive scale."}, {"term": "to deliver humanitarian aid", "ipa": "/dɪˈlɪvə hjuːˌmænɪˈteəriən eɪd/", "pron": "di-LIV-uh hyoo-man-i-TAIR-ee-uhn aid", "fr": "acheminer l’aide humanitaire", "def": "To bring emergency assistance to people in need.", "ex": "Aid agencies struggle to deliver humanitarian aid during fighting."}, {"term": "to address root causes", "ipa": "/əˈdres ruːt ˈkɔːzɪz/", "pron": "uh-DRESS root KAW-ziz", "fr": "s’attaquer aux causes profondes", "def": "To deal with underlying causes of a problem.", "ex": "Peace requires addressing root causes, not only stopping violence."}, {"term": "to pursue a two-state solution", "ipa": "/pəˈsjuː ə ˌtuː steɪt səˈluːʃən/", "pron": "puh-SYOO uh two-state suh-LOO-shuhn", "fr": "chercher une solution à deux États", "def": "To seek a peace settlement with two states.", "ex": "Many diplomats still claim to pursue a two-state solution."}, {"term": "to prevent nuclear proliferation", "ipa": "/prɪˈvent ˌnjuːkliə prəˌlɪfəˈreɪʃən/", "pron": "pri-VENT NYOO-klee-uh pruh-lif-uh-RAY-shuhn", "fr": "empêcher la prolifération nucléaire", "def": "To stop the spread of nuclear weapons.", "ex": "The JCPOA aimed to prevent nuclear proliferation."}, {"term": "to secure shipping lanes", "ipa": "/sɪˈkjʊə ˈʃɪpɪŋ leɪnz/", "pron": "si-KYOOR SHIP-ing laynz", "fr": "sécuriser les voies maritimes", "def": "To protect maritime trade routes.", "ex": "Naval patrols aim to secure shipping lanes."}]}, {"title": "E. Diplomacy, escalation and high-value verbs", "entries": []}]}, {"id": "p6c58", "part": 6, "chapter": 58, "title": "Soft Power Premium (1)", "file": "cpge_vocab_part6_chapter58_soft_power_premium (1).html", "count": 138, "sections": [{"title": "A. Core concepts: soft, hard, smart and sharp power", "entries": [{"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "The ability to influence others through attraction, culture, values and legitimacy rather than coercion.", "ex": "Soft power allows a country to shape preferences without using force."}, {"term": "hard power", "ipa": "/ˌhɑːd ˈpaʊə/", "pron": "hard POW-uh", "fr": "hard power ; puissance coercitive", "def": "Influence based on military force, economic pressure or coercion.", "ex": "Hard power can impose decisions but may create resentment."}, {"term": "smart power", "ipa": "/ˌsmɑːt ˈpaʊə/", "pron": "smart POW-uh", "fr": "smart power ; puissance intelligente", "def": "A strategy combining soft power and hard power effectively.", "ex": "Smart power blends diplomacy, culture, trade and military credibility."}, {"term": "sharp power", "ipa": "/ˌʃɑːp ˈpaʊə/", "pron": "sharp POW-uh", "fr": "sharp power ; pouvoir d’influence coercitif", "def": "Influence that uses manipulation, censorship, pressure or covert interference.", "ex": "Sharp power blurs the line between attraction and manipulation."}, {"term": "normative power", "ipa": "/ˈnɔːmətɪv ˈpaʊə/", "pron": "NOR-muh-tiv POW-uh", "fr": "puissance normative", "def": "Influence based on shaping norms, rules and values.", "ex": "The European Union is often described as a normative power."}, {"term": "civilian power", "ipa": "/səˈvɪliən ˈpaʊə/", "pron": "suh-VIL-yuhn POW-uh", "fr": "puissance civile", "def": "Influence based on diplomacy, trade, aid and law rather than military force.", "ex": "The EU has traditionally relied on civilian power."}, {"term": "cultural diplomacy", "ipa": "/ˌkʌltʃərəl dɪˈpləʊməsi/", "pron": "KUL-chuh-ruhl di-PLOH-muh-see", "fr": "diplomatie culturelle", "def": "The use of culture to build relationships and influence abroad.", "ex": "Cultural diplomacy includes language, cinema, museums and festivals."}, {"term": "public diplomacy", "ipa": "/ˌpʌblɪk dɪˈpləʊməsi/", "pron": "PUB-lik di-PLOH-muh-see", "fr": "diplomatie publique", "def": "Efforts by a state to communicate with foreign publics and shape its image.", "ex": "Public diplomacy targets societies, not only governments."}, {"term": "nation branding", "ipa": "/ˌneɪʃən ˈbrændɪŋ/", "pron": "NAY-shuhn BRAN-ding", "fr": "image de marque nationale", "def": "The strategy of shaping a country’s image abroad like a brand.", "ex": "Nation branding can attract tourists, investors and students."}, {"term": "country image", "ipa": "/ˌkʌntri ˈɪmɪdʒ/", "pron": "KUN-tree IM-ij", "fr": "image d’un pays", "def": "How a country is perceived by foreign publics.", "ex": "A positive country image strengthens soft power."}, {"term": "national image", "ipa": "/ˌnæʃənəl ˈɪmɪdʒ/", "pron": "NASH-uh-nuhl IM-ij", "fr": "image nationale", "def": "The reputation or perception of a nation.", "ex": "A national image can be damaged by war or human-rights abuses."}, {"term": "international image", "ipa": "/ˌɪntəˈnæʃənəl ˈɪmɪdʒ/", "pron": "IN-tuh-NASH-uh-nuhl IM-ij", "fr": "image internationale", "def": "The way a state is seen abroad.", "ex": "International image matters for diplomacy and trade."}, {"term": "global reputation", "ipa": "/ˌɡləʊbəl ˌrepjʊˈteɪʃən/", "pron": "GLOH-buhl rep-yuh-TAY-shuhn", "fr": "réputation mondiale", "def": "The overall reputation a country has around the world.", "ex": "A global reputation can take decades to build and years to lose."}, {"term": "prestige", "ipa": "/preˈstiːʒ/", "pron": "pre-STEEZH", "fr": "prestige", "def": "Respect and admiration gained through achievement or status.", "ex": "Scientific achievement can increase national prestige."}, {"term": "influence", "ipa": "/ˈɪnfluəns/", "pron": "IN-floo-uhns", "fr": "influence", "def": "The ability to affect opinions, behaviour or decisions.", "ex": "Soft power is a form of influence."}, {"term": "attraction", "ipa": "/əˈtrækʃən/", "pron": "uh-TRAK-shuhn", "fr": "attraction", "def": "The ability to make others admire or want to imitate something.", "ex": "Soft power relies on attraction rather than fear."}, {"term": "appeal", "ipa": "/əˈpiːl/", "pron": "uh-PEEL", "fr": "attrait", "def": "The quality of being attractive or persuasive.", "ex": "A country’s democratic model can have strong appeal."}, {"term": "legitimacy", "ipa": "/lɪˈdʒɪtɪməsi/", "pron": "li-JIT-i-muh-see", "fr": "légitimité", "def": "The perception that an actor’s power or actions are rightful and acceptable.", "ex": "Legitimacy makes international leadership easier."}, {"term": "credibility", "ipa": "/ˌkredəˈbɪləti/", "pron": "kred-uh-BIL-uh-tee", "fr": "crédibilité", "def": "The quality of being trusted and believed.", "ex": "Soft power depends on credibility."}, {"term": "trust", "ipa": "/trʌst/", "pron": "trust", "fr": "confiance", "def": "Confidence in someone’s honesty, reliability or intentions.", "ex": "Trust is essential in diplomacy."}, {"term": "moral authority", "ipa": "/ˌmɒrəl ɔːˈθɒrəti/", "pron": "MOR-uhl aw-THOR-uh-tee", "fr": "autorité morale", "def": "Influence gained from being seen as morally legitimate.", "ex": "Human-rights leadership can create moral authority."}, {"term": "values", "ipa": "/ˈvæljuːz/", "pron": "VAL-yooz", "fr": "valeurs", "def": "Principles or beliefs considered important by a society.", "ex": "Values can strengthen or weaken soft power."}, {"term": "liberal values", "ipa": "/ˌlɪbərəl ˈvæljuːz/", "pron": "LIB-uh-ruhl VAL-yooz", "fr": "valeurs libérales", "def": "Values such as individual rights, pluralism and the rule of law.", "ex": "Liberal values are often associated with Western soft power."}, {"term": "democratic values", "ipa": "/ˌdeməkrætɪk ˈvæljuːz/", "pron": "dem-uh-KRAT-ik VAL-yooz", "fr": "valeurs démocratiques", "def": "Values linked to democracy, rights and political participation.", "ex": "Democratic values can attract foreign publics."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Human rights can be a source of soft power when applied consistently."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit", "def": "The principle that everyone, including governments, is subject to law.", "ex": "The rule of law increases institutional credibility."}, {"term": "democracy promotion", "ipa": "/dɪˈmɒkrəsi prəˌməʊʃən/", "pron": "di-MOK-ruh-see pruh-MOH-shuhn", "fr": "promotion de la démocratie", "def": "Efforts to support democratic institutions abroad.", "ex": "Democracy promotion can be seen as idealistic or intrusive."}, {"term": "humanitarianism", "ipa": "/hjuːˌmænɪˈteəriənɪzəm/", "pron": "hyoo-man-i-TAIR-ee-uh-niz-uhm", "fr": "humanitarisme", "def": "Concern for human welfare and action to reduce suffering.", "ex": "Humanitarianism can strengthen a country’s image."}, {"term": "humanitarian aid", "ipa": "/hjuːˌmænɪˈteəriən ˈeɪd/", "pron": "hyoo-man-i-TAIR-ee-uhn aid", "fr": "aide humanitaire", "def": "Assistance such as food, medicine and shelter provided in crises.", "ex": "Humanitarian aid can save lives and improve international standing."}, {"term": "development aid", "ipa": "/dɪˈveləpmənt eɪd/", "pron": "di-VEL-uhp-muhnt aid", "fr": "aide au développement", "def": "Support given to poorer countries to promote development.", "ex": "Development aid is a tool of influence and solidarity."}, {"term": "foreign aid", "ipa": "/ˌfɒrən ˈeɪd/", "pron": "FOR-uhn aid", "fr": "aide étrangère", "def": "Money, goods or services given by one country to another.", "ex": "Foreign aid may serve both humanitarian and strategic goals."}, {"term": "official development assistance", "ipa": "/əˌfɪʃəl dɪˈveləpmənt əˈsɪstəns/", "pron": "uh-FISH-uhl di-VEL-uhp-muhnt uh-SIS-tuhns", "fr": "aide publique au développement", "def": "Government aid designed to promote development and welfare.", "ex": "Official development assistance supports health, education and infrastructure."}, {"term": "ODA", "ipa": "/ˌəʊ diː ˈeɪ/", "pron": "oh-dee-ay", "fr": "APD", "def": "Abbreviation for official development assistance.", "ex": "ODA can improve a donor country’s image."}, {"term": "cultural influence", "ipa": "/ˌkʌltʃərəl ˈɪnfluəns/", "pron": "KUL-chuh-ruhl IN-floo-uhns", "fr": "influence culturelle", "def": "Influence created through culture, arts, media and lifestyle.", "ex": "American cultural influence has long been global."}]}, {"title": "B. Culture, language, education and science diplomacy", "entries": [{"term": "popular culture", "ipa": "/ˌpɒpjʊlə ˈkʌltʃə/", "pron": "POP-yuh-luh KUL-chuh", "fr": "culture populaire", "def": "Culture enjoyed by large audiences, such as music, films and games.", "ex": "Popular culture can spread a country’s language and values."}, {"term": "pop culture", "ipa": "/ˈpɒp ˌkʌltʃə/", "pron": "pop KUL-chuh", "fr": "pop culture", "def": "Informal term for popular culture.", "ex": "Pop culture can reach audiences that formal diplomacy cannot."}, {"term": "film industry", "ipa": "/ˈfɪlm ˌɪndəstri/", "pron": "film IN-duh-stree", "fr": "industrie cinématographique", "def": "The sector producing and distributing films.", "ex": "The film industry contributes to soft power."}, {"term": "Hollywood", "ipa": "/ˈhɒliwʊd/", "pron": "HOL-ee-wood", "fr": "Hollywood", "def": "The US film industry, often used as a symbol of American cultural power.", "ex": "Hollywood has shaped global images of the United States."}, {"term": "Bollywood", "ipa": "/ˈbɒliwʊd/", "pron": "BOL-ee-wood", "fr": "Bollywood", "def": "The Hindi-language film industry based in India.", "ex": "Bollywood strengthens India’s cultural reach."}, {"term": "K-pop", "ipa": "/ˈkeɪ pɒp/", "pron": "kay-pop", "fr": "K-pop", "def": "South Korean popular music.", "ex": "K-pop has become a major source of South Korean soft power."}, {"term": "K-drama", "ipa": "/ˈkeɪ drɑːmə/", "pron": "kay-DRAH-muh", "fr": "drama coréen", "def": "South Korean television drama.", "ex": "K-dramas attract global audiences."}, {"term": "Korean Wave", "ipa": "/kəˌriːən ˈweɪv/", "pron": "kuh-REE-uhn wave", "fr": "vague coréenne ; Hallyu", "def": "The global spread of South Korean culture.", "ex": "The Korean Wave shows how culture can become geopolitical influence."}, {"term": "Hallyu", "ipa": "/ˈhæljuː/", "pron": "HAL-yoo", "fr": "Hallyu", "def": "Korean term for the Korean Wave.", "ex": "Hallyu has boosted tourism and exports."}, {"term": "anime", "ipa": "/ˈænɪmeɪ/", "pron": "AN-i-may", "fr": "anime", "def": "Japanese animated film and television.", "ex": "Anime contributes to Japan’s global cultural appeal."}, {"term": "manga", "ipa": "/ˈmæŋɡə/", "pron": "MAN-guh", "fr": "manga", "def": "Japanese comics and graphic novels.", "ex": "Manga has helped spread Japanese cultural influence."}, {"term": "video games", "ipa": "/ˈvɪdiəʊ ɡeɪmz/", "pron": "VID-ee-oh games", "fr": "jeux vidéo", "def": "Electronic games played on computers, consoles or phones.", "ex": "Video games can shape global perceptions of culture."}, {"term": "music industry", "ipa": "/ˈmjuːzɪk ˌɪndəstri/", "pron": "MYOO-zik IN-duh-stree", "fr": "industrie musicale", "def": "The sector producing and distributing music.", "ex": "The music industry is a major vehicle of soft power."}, {"term": "streaming platform", "ipa": "/ˈstriːmɪŋ ˌplætfɔːm/", "pron": "STREE-ming PLAT-form", "fr": "plateforme de streaming", "def": "An online service distributing films, music or series.", "ex": "Streaming platforms spread culture across borders."}, {"term": "global audience", "ipa": "/ˌɡləʊbəl ˈɔːdiəns/", "pron": "GLOH-buhl AW-dee-uhns", "fr": "public mondial", "def": "People around the world reached by media or culture.", "ex": "A global audience can amplify cultural diplomacy."}, {"term": "cultural export", "ipa": "/ˌkʌltʃərəl ˈekspɔːt/", "pron": "KUL-chuh-ruhl EK-sport", "fr": "exportation culturelle", "def": "A cultural product sold or spread abroad.", "ex": "Cultural exports include films, music and fashion."}, {"term": "creative industries", "ipa": "/kriˌeɪtɪv ˈɪndəstriz/", "pron": "kree-AY-tiv IN-duh-streez", "fr": "industries créatives", "def": "Sectors based on creativity, such as film, design, music and games.", "ex": "Creative industries can generate both revenue and influence."}, {"term": "language policy", "ipa": "/ˈlæŋɡwɪdʒ ˈpɒləsi/", "pron": "LANG-gwij POL-uh-see", "fr": "politique linguistique", "def": "Policies promoting or regulating language use.", "ex": "Language policy can support cultural influence."}, {"term": "language learning", "ipa": "/ˈlæŋɡwɪdʒ ˌlɜːnɪŋ/", "pron": "LANG-gwij LUR-ning", "fr": "apprentissage des langues", "def": "The process of learning a foreign language.", "ex": "Language learning can create long-term cultural connections."}, {"term": "English language", "ipa": "/ˌɪŋɡlɪʃ ˈlæŋɡwɪdʒ/", "pron": "ING-glish LANG-gwij", "fr": "langue anglaise", "def": "The English language, often linked to global communication.", "ex": "The English language strengthens British and American soft power."}, {"term": "Francophonie", "ipa": "/ˌfræŋkɒfəˈniː/", "pron": "fran-kof-uh-NEE", "fr": "Francophonie", "def": "The global community of French-speaking countries and institutions.", "ex": "Francophonie supports French cultural and diplomatic influence."}, {"term": "British Council", "ipa": "/ˌbrɪtɪʃ ˈkaʊnsəl/", "pron": "BRIT-ish KOWN-suhl", "fr": "British Council", "def": "UK organisation promoting British culture and English abroad.", "ex": "The British Council is a major soft-power institution."}, {"term": "Alliance Française", "ipa": "/ˌæliˌɒns frɒnˈseɪz/", "pron": "al-ee-ONS fron-SAYZ", "fr": "Alliance française", "def": "Organisation promoting French language and culture abroad.", "ex": "Alliance Française promotes French through classes and cultural events."}, {"term": "Goethe-Institut", "ipa": "/ˌɡɜːtə ˈɪnstɪtjuːt/", "pron": "GUR-tuh IN-sti-tyoot", "fr": "Goethe-Institut", "def": "German cultural institute promoting language and culture abroad.", "ex": "The Goethe-Institut supports German cultural diplomacy."}, {"term": "Confucius Institute", "ipa": "/kənˈfjuːʃəs ˈɪnstɪtjuːt/", "pron": "kuhn-FYOO-shuhs IN-sti-tyoot", "fr": "Institut Confucius", "def": "Chinese state-linked institute promoting Chinese language and culture abroad.", "ex": "Confucius Institutes are sometimes criticised over academic freedom concerns."}, {"term": "cultural institute", "ipa": "/ˌkʌltʃərəl ˈɪnstɪtjuːt/", "pron": "KUL-chuh-ruhl IN-sti-tyoot", "fr": "institut culturel", "def": "An organisation promoting a country’s culture and language abroad.", "ex": "Cultural institutes are long-term tools of soft power."}, {"term": "education diplomacy", "ipa": "/ˌedjʊˈkeɪʃən dɪˈpləʊməsi/", "pron": "ej-yoo-KAY-shuhn di-PLOH-muh-see", "fr": "diplomatie éducative", "def": "The use of education, universities and exchanges to build influence.", "ex": "Education diplomacy creates lasting personal ties."}, {"term": "academic exchange", "ipa": "/ˌækəˈdemɪk ɪksˈtʃeɪndʒ/", "pron": "ak-uh-DEM-ik iks-CHAYNJ", "fr": "échange universitaire", "def": "A programme allowing students or scholars to study or teach abroad.", "ex": "Academic exchanges build mutual understanding."}, {"term": "student exchange", "ipa": "/ˈstjuːdənt ɪksˌtʃeɪndʒ/", "pron": "STYOO-duhnt iks-CHAYNJ", "fr": "échange étudiant", "def": "A programme allowing students to study abroad temporarily.", "ex": "Student exchanges can create lifelong cultural affinity."}, {"term": "scholarship programme", "ipa": "/ˈskɒləʃɪp ˌprəʊɡræm/", "pron": "SKOL-uh-ship PROH-gram", "fr": "programme de bourses", "def": "A programme funding study or research.", "ex": "Scholarship programmes attract talented foreign students."}, {"term": "Fulbright Program", "ipa": "/ˈfʊlbraɪt ˌprəʊɡræm/", "pron": "FULL-bright PROH-gram", "fr": "programme Fulbright", "def": "US educational exchange programme.", "ex": "The Fulbright Program is a major instrument of US soft power."}, {"term": "Erasmus", "ipa": "/ɪˈræzməs/", "pron": "i-RAZ-muhs", "fr": "Erasmus", "def": "EU programme supporting study, training and youth exchanges.", "ex": "Erasmus has strengthened European identity among students."}, {"term": "international student", "ipa": "/ˌɪntəˈnæʃənəl ˈstjuːdənt/", "pron": "IN-tuh-NASH-uh-nuhl STYOO-duhnt", "fr": "étudiant international", "def": "A student studying in a foreign country.", "ex": "International students can become cultural ambassadors."}, {"term": "alumni network", "ipa": "/əˈlʌmnaɪ ˌnetwɜːk/", "pron": "uh-LUM-ny NET-work", "fr": "réseau d’anciens", "def": "A network of former students or participants.", "ex": "Alumni networks maintain long-term influence."}, {"term": "university ranking", "ipa": "/ˌjuːnɪˈvɜːsəti ˈræŋkɪŋ/", "pron": "yoo-ni-VUR-suh-tee RANG-king", "fr": "classement universitaire", "def": "A list comparing universities by reputation or performance.", "ex": "University rankings affect international attractiveness."}, {"term": "research excellence", "ipa": "/rɪˈsɜːtʃ ˈeksələns/", "pron": "ri-SURCH EK-suh-luhns", "fr": "excellence scientifique", "def": "High-quality research performance.", "ex": "Research excellence increases academic prestige."}, {"term": "science diplomacy", "ipa": "/ˈsaɪəns dɪˌpləʊməsi/", "pron": "SY-uhns di-PLOH-muh-see", "fr": "diplomatie scientifique", "def": "Using scientific cooperation to support international relations.", "ex": "Science diplomacy can continue even when political relations are tense."}, {"term": "medical diplomacy", "ipa": "/ˈmedɪkəl dɪˌpləʊməsi/", "pron": "MED-i-kuhl di-PLOH-muh-see", "fr": "diplomatie médicale", "def": "Using health aid, doctors, vaccines or medical cooperation to build influence.", "ex": "Medical diplomacy became visible during the pandemic."}, {"term": "vaccine diplomacy", "ipa": "/ˈvæksiːn dɪˌpləʊməsi/", "pron": "VAK-seen di-PLOH-muh-see", "fr": "diplomatie vaccinale", "def": "Using vaccine donations or sales to gain goodwill or influence.", "ex": "Vaccine diplomacy became a tool of influence during COVID-19."}, {"term": "sports diplomacy", "ipa": "/ˈspɔːts dɪˌpləʊməsi/", "pron": "sports di-PLOH-muh-see", "fr": "diplomatie sportive", "def": "Using sport to improve relations or national image.", "ex": "Sports diplomacy can bring rivals together or project prestige."}, {"term": "sporting event", "ipa": "/ˈspɔːtɪŋ ɪˌvent/", "pron": "SPOR-ting i-VENT", "fr": "événement sportif", "def": "A sports competition or event.", "ex": "Major sporting events can be used for nation branding."}]}, {"title": "C. Sport, tourism, diaspora, media and digital diplomacy", "entries": [{"term": "mega-event", "ipa": "/ˈmeɡə ɪˌvent/", "pron": "MEG-uh i-VENT", "fr": "méga-événement", "def": "A very large global event such as the Olympics or World Cup.", "ex": "Mega-events can showcase a country but also attract criticism."}, {"term": "Olympic Games", "ipa": "/əˌlɪmpɪk ˈɡeɪmz/", "pron": "uh-LIM-pik games", "fr": "Jeux olympiques", "def": "The international multi-sport event held every four years.", "ex": "The Olympic Games are a major stage for soft power."}, {"term": "World Cup", "ipa": "/ˌwɜːld ˈkʌp/", "pron": "world cup", "fr": "Coupe du monde", "def": "A major international sports tournament, especially in football.", "ex": "Hosting the World Cup can boost global visibility."}, {"term": "sportswashing", "ipa": "/ˈspɔːtsˌwɒʃɪŋ/", "pron": "SPORTS-wosh-ing", "fr": "sportswashing", "def": "Using sport to improve reputation and distract from criticism.", "ex": "Sportswashing is often discussed in relation to authoritarian states."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "écoblanchiment ; greenwashing", "def": "Making misleading environmental claims to improve reputation.", "ex": "Greenwashing can damage credibility when exposed."}, {"term": "artwashing", "ipa": "/ˈɑːtˌwɒʃɪŋ/", "pron": "ART-wosh-ing", "fr": "artwashing", "def": "Using art or culture to improve reputation and distract from wrongdoing.", "ex": "Critics accuse some governments of artwashing."}, {"term": "reputation laundering", "ipa": "/ˌrepjʊˈteɪʃən ˈlɔːndərɪŋ/", "pron": "rep-yuh-TAY-shuhn LAWN-duh-ring", "fr": "blanchiment de réputation", "def": "Trying to clean up a damaged image through publicity, culture or sponsorship.", "ex": "Reputation laundering can be part of authoritarian soft power."}, {"term": "tourism", "ipa": "/ˈtʊərɪzəm/", "pron": "TOOR-iz-uhm", "fr": "tourisme", "def": "Travel for leisure, culture or business.", "ex": "Tourism spreads images, stories and stereotypes of a country."}, {"term": "tourist appeal", "ipa": "/ˈtʊərɪst əˌpiːl/", "pron": "TOOR-ist uh-PEEL", "fr": "attrait touristique", "def": "The attractiveness of a place to visitors.", "ex": "Tourist appeal contributes to soft power."}, {"term": "heritage site", "ipa": "/ˈherɪtɪdʒ saɪt/", "pron": "HERR-i-tij site", "fr": "site patrimonial", "def": "A place valued for historical or cultural importance.", "ex": "Heritage sites strengthen cultural prestige."}, {"term": "UNESCO World Heritage Site", "ipa": "/juːˌneskəʊ ˌwɜːld ˈherɪtɪdʒ saɪt/", "pron": "yoo-NES-koh world HERR-i-tij site", "fr": "site du patrimoine mondial de l’UNESCO", "def": "A place recognised by UNESCO as having outstanding cultural or natural value.", "ex": "UNESCO World Heritage Sites attract global attention."}, {"term": "gastronomy", "ipa": "/ɡæˈstrɒnəmi/", "pron": "ga-STRON-uh-mee", "fr": "gastronomie", "def": "The culture and art of food and cuisine.", "ex": "Gastronomy is an underrated form of cultural diplomacy."}, {"term": "fashion industry", "ipa": "/ˈfæʃən ˌɪndəstri/", "pron": "FASH-uhn IN-duh-stree", "fr": "industrie de la mode", "def": "The sector designing and selling clothing and style.", "ex": "The fashion industry contributes to French and Italian soft power."}, {"term": "luxury goods", "ipa": "/ˌlʌkʃəri ˈɡʊdz/", "pron": "LUK-shuh-ree goods", "fr": "produits de luxe", "def": "High-end expensive products associated with prestige.", "ex": "Luxury goods can enhance a country’s image."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community living outside its ancestral homeland.", "ex": "Diasporas can connect countries through culture, business and politics."}, {"term": "diaspora diplomacy", "ipa": "/daɪˈæspərə dɪˌpləʊməsi/", "pron": "dy-AS-puh-ruh di-PLOH-muh-see", "fr": "diplomatie de la diaspora", "def": "Using diaspora communities to build influence and connections.", "ex": "Diaspora diplomacy can strengthen economic and cultural ties."}, {"term": "people-to-people ties", "ipa": "/ˌpiːpəl tə ˈpiːpəl taɪz/", "pron": "PEE-puhl tuh PEE-puhl ties", "fr": "liens entre populations", "def": "Direct relationships between citizens of different countries.", "ex": "People-to-people ties build durable trust."}, {"term": "civil-society links", "ipa": "/ˌsɪvəl səˈsaɪəti lɪŋks/", "pron": "SIV-uhl suh-SY-uh-tee links", "fr": "liens entre sociétés civiles", "def": "Connections between NGOs, associations and citizens across borders.", "ex": "Civil-society links can survive political tensions."}, {"term": "NGO", "ipa": "/ˌen dʒiː ˈəʊ/", "pron": "en-jee-oh", "fr": "ONG", "def": "Non-governmental organisation.", "ex": "NGOs can support soft power through humanitarian work."}, {"term": "international broadcaster", "ipa": "/ˌɪntəˈnæʃənəl ˈbrɔːdkɑːstə/", "pron": "IN-tuh-NASH-uh-nuhl BROD-kas-tuh", "fr": "média international", "def": "A media organisation broadcasting to foreign audiences.", "ex": "International broadcasters shape narratives abroad."}, {"term": "BBC World Service", "ipa": "/ˌbiː biː ˈsiː ˌwɜːld ˈsɜːvɪs/", "pron": "bee-bee-see world SUR-vis", "fr": "BBC World Service", "def": "The BBC’s international broadcasting service.", "ex": "The BBC World Service is a major British soft-power asset."}, {"term": "Voice of America", "ipa": "/ˌvɔɪs əv əˈmerɪkə/", "pron": "voice ov uh-MERR-i-kuh", "fr": "Voice of America", "def": "US international broadcaster.", "ex": "Voice of America broadcasts news and US perspectives abroad."}, {"term": "RT", "ipa": "/ˌɑː ˈtiː/", "pron": "ar-tee", "fr": "RT", "def": "Russian state-funded international broadcaster.", "ex": "RT has been accused of spreading disinformation."}, {"term": "Al Jazeera", "ipa": "/ˌæl dʒəˈzɪərə/", "pron": "al juh-ZEER-uh", "fr": "Al Jazeera", "def": "Qatar-based international broadcaster.", "ex": "Al Jazeera expanded Qatar’s global visibility."}, {"term": "global media", "ipa": "/ˌɡləʊbəl ˈmiːdiə/", "pron": "GLOH-buhl MEE-dee-uh", "fr": "médias mondiaux", "def": "Media with worldwide reach.", "ex": "Global media shape international perceptions."}, {"term": "narrative", "ipa": "/ˈnærətɪv/", "pron": "NARR-uh-tiv", "fr": "récit ; narration", "def": "A story or interpretation used to make sense of events.", "ex": "Controlling the narrative is central to public diplomacy."}, {"term": "strategic communication", "ipa": "/strəˌtiːdʒɪk kəˌmjuːnɪˈkeɪʃən/", "pron": "struh-TEE-jik kuh-myoo-ni-KAY-shuhn", "fr": "communication stratégique", "def": "Coordinated communication designed to influence audiences.", "ex": "Strategic communication is vital during crises."}, {"term": "message discipline", "ipa": "/ˈmesɪdʒ ˌdɪsəplɪn/", "pron": "MESS-ij DIS-uh-plin", "fr": "discipline de communication", "def": "Keeping communication consistent and controlled.", "ex": "Message discipline strengthens credibility."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to mislead.", "ex": "Disinformation can destroy trust in public diplomacy."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Biased or misleading information used to promote a political cause.", "ex": "Propaganda is less credible than genuine cultural attraction."}, {"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WAR-fair", "fr": "guerre de l’information", "def": "Use of information and media to influence conflict or politics.", "ex": "Information warfare can undermine democratic societies."}, {"term": "digital diplomacy", "ipa": "/ˌdɪdʒɪtəl dɪˈpləʊməsi/", "pron": "DIJ-i-tuhl di-PLOH-muh-see", "fr": "diplomatie numérique", "def": "Diplomacy conducted through digital tools and online platforms.", "ex": "Digital diplomacy allows governments to reach foreign publics directly."}, {"term": "social media diplomacy", "ipa": "/ˌsəʊʃəl ˈmiːdiə dɪˌpləʊməsi/", "pron": "SOH-shuhl MEE-dee-uh di-PLOH-muh-see", "fr": "diplomatie sur les réseaux sociaux", "def": "Using social media for diplomatic communication and influence.", "ex": "Social media diplomacy can be fast but risky."}, {"term": "hashtag diplomacy", "ipa": "/ˈhæʃtæɡ dɪˌpləʊməsi/", "pron": "HASH-tag di-PLOH-muh-see", "fr": "diplomatie du hashtag", "def": "Using hashtags and online campaigns for diplomatic messaging.", "ex": "Hashtag diplomacy can mobilise attention quickly."}, {"term": "influence operation", "ipa": "/ˈɪnfluəns ˌɒpəˈreɪʃən/", "pron": "IN-floo-uhns op-uh-RAY-shuhn", "fr": "opération d’influence", "def": "A coordinated attempt to shape opinions or decisions.", "ex": "Influence operations may be open or covert."}, {"term": "foreign interference", "ipa": "/ˌfɒrən ˌɪntəˈfɪərəns/", "pron": "FOR-uhn in-tuh-FEER-uhns", "fr": "ingérence étrangère", "def": "Improper foreign involvement in another country’s politics.", "ex": "Foreign interference undermines trust and sovereignty."}, {"term": "election interference", "ipa": "/ɪˈlekʃən ˌɪntəˈfɪərəns/", "pron": "i-LEK-shuhn in-tuh-FEER-uhns", "fr": "ingérence électorale", "def": "Attempts to influence or manipulate another country’s elections.", "ex": "Election interference is a form of hostile influence."}, {"term": "soft-power ranking", "ipa": "/ˌsɒft ˈpaʊə ˈræŋkɪŋ/", "pron": "soft POW-uh RANG-king", "fr": "classement de soft power", "def": "A ranking comparing countries’ attractiveness and influence.", "ex": "Soft-power rankings often measure culture, education and diplomacy."}, {"term": "global influence index", "ipa": "/ˌɡləʊbəl ˈɪnfluəns ˈɪndeks/", "pron": "GLOH-buhl IN-floo-uhns IN-deks", "fr": "indice d’influence mondiale", "def": "An index measuring international influence.", "ex": "A global influence index can oversimplify complex realities."}, {"term": "reputational damage", "ipa": "/ˌrepjʊˈteɪʃənəl ˈdæmɪdʒ/", "pron": "rep-yuh-TAY-shuh-nuhl DAM-ij", "fr": "atteinte à la réputation", "def": "Harm done to a country’s image or credibility.", "ex": "Human-rights scandals cause reputational damage."}, {"term": "credibility gap", "ipa": "/ˌkredəˈbɪləti ɡæp/", "pron": "kred-uh-BIL-uh-tee gap", "fr": "déficit de crédibilité", "def": "A gap between what an actor says and what it does.", "ex": "A credibility gap weakens soft power."}, {"term": "double standards", "ipa": "/ˌdʌbəl ˈstændədz/", "pron": "DUB-uhl STAN-duhdz", "fr": "deux poids deux mesures", "def": "Applying different principles to similar situations.", "ex": "Accusations of double standards damage Western soft power."}, {"term": "hypocrisy", "ipa": "/hɪˈpɒkrəsi/", "pron": "hi-POK-ruh-see", "fr": "hypocrisie", "def": "Pretending to have values that one does not apply consistently.", "ex": "Perceived hypocrisy undermines moral authority."}]}, {"title": "D. Reputation, credibility, backlash and contested influence", "entries": [{"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction.", "ex": "Aggressive public diplomacy can create a backlash."}, {"term": "anti-Americanism", "ipa": "/ˌænti əˈmerɪkənɪzəm/", "pron": "AN-tee uh-MERR-i-kuh-niz-uhm", "fr": "anti-américanisme", "def": "Hostility towards US power, culture or policies.", "ex": "Anti-Americanism can weaken US soft power."}, {"term": "anti-Western sentiment", "ipa": "/ˌænti ˈwestən ˈsentɪmənt/", "pron": "AN-tee WES-tuhn SEN-ti-muhnt", "fr": "sentiment anti-occidental", "def": "Negative feeling towards Western countries or values.", "ex": "Anti-Western sentiment can be fuelled by foreign policy decisions."}, {"term": "cultural imperialism", "ipa": "/ˌkʌltʃərəl ɪmˈpɪəriəlɪzəm/", "pron": "KUL-chuh-ruhl im-PEER-ee-uh-liz-uhm", "fr": "impérialisme culturel", "def": "The domination of one culture over others, often through media or markets.", "ex": "Critics see Hollywood’s global reach as cultural imperialism."}, {"term": "soft-power strategy", "ipa": "/ˌsɒft ˈpaʊə ˈstrætədʒi/", "pron": "soft POW-uh STRAT-uh-jee", "fr": "stratégie de soft power", "def": "A plan to increase attraction and influence abroad.", "ex": "A soft-power strategy must be credible and long-term."}, {"term": "to project a positive image", "ipa": "/prəˈdʒekt ə ˌpɒzətɪv ˈɪmɪdʒ/", "pron": "pruh-JEKT uh POZ-uh-tiv IM-ij", "fr": "projeter une image positive", "def": "To present an attractive image abroad.", "ex": "Countries use culture to project a positive image."}, {"term": "to shape perceptions", "ipa": "/ʃeɪp pəˈsepʃənz/", "pron": "shayp puh-SEP-shuhnz", "fr": "façonner les perceptions", "def": "To influence how people see an issue or country.", "ex": "Public diplomacy tries to shape perceptions."}, {"term": "to win hearts and minds", "ipa": "/wɪn hɑːts ənd maɪndz/", "pron": "win hearts and myndz", "fr": "gagner les cœurs et les esprits", "def": "To gain emotional and intellectual support.", "ex": "Soft power aims to win hearts and minds."}, {"term": "to attract foreign students", "ipa": "/əˈtrækt ˌfɒrən ˈstjuːdənts/", "pron": "uh-TRAKT FOR-uhn STYOO-duhnts", "fr": "attirer des étudiants étrangers", "def": "To draw students from other countries.", "ex": "Universities help attract foreign students."}, {"term": "to promote national culture", "ipa": "/prəˈməʊt ˌnæʃənəl ˈkʌltʃə/", "pron": "pruh-MOHT NASH-uh-nuhl KUL-chuh", "fr": "promouvoir la culture nationale", "def": "To spread awareness and appreciation of a country’s culture.", "ex": "Cultural institutes promote national culture."}, {"term": "to export culture", "ipa": "/ekˈspɔːt ˈkʌltʃə/", "pron": "ek-SPORT KUL-chuh", "fr": "exporter sa culture", "def": "To spread cultural products abroad.", "ex": "Streaming platforms help export culture."}, {"term": "to host a mega-event", "ipa": "/həʊst ə ˈmeɡə ɪˌvent/", "pron": "hohst uh MEG-uh i-VENT", "fr": "accueillir un méga-événement", "def": "To organise a major global event.", "ex": "States host mega-events to gain prestige."}, {"term": "to launder one’s reputation", "ipa": "/ˈlɔːndə wʌnz ˌrepjʊˈteɪʃən/", "pron": "LAWN-duh wunz rep-yuh-TAY-shuhn", "fr": "blanchir sa réputation", "def": "To try to clean up a damaged image through publicity or sponsorship.", "ex": "Critics accuse some regimes of trying to launder their reputation."}, {"term": "to build trust", "ipa": "/bɪld trʌst/", "pron": "bild trust", "fr": "instaurer la confiance", "def": "To create confidence and reliability.", "ex": "Educational exchanges build trust."}, {"term": "to gain legitimacy", "ipa": "/ɡeɪn lɪˈdʒɪtɪməsi/", "pron": "gayn li-JIT-i-muh-see", "fr": "gagner en légitimité", "def": "To become seen as rightful or acceptable.", "ex": "Humanitarian action can help a state gain legitimacy."}, {"term": "to lose credibility", "ipa": "/luːz ˌkredəˈbɪləti/", "pron": "looz kred-uh-BIL-uh-tee", "fr": "perdre en crédibilité", "def": "To become less trusted or believable.", "ex": "Double standards make countries lose credibility."}, {"term": "to undermine soft power", "ipa": "/ˌʌndəˈmaɪn ˌsɒft ˈpaʊə/", "pron": "un-duh-MYNE soft POW-uh", "fr": "saper le soft power", "def": "To weaken attraction and influence.", "ex": "War crimes undermine soft power."}, {"term": "to counter disinformation", "ipa": "/ˈkaʊntə ˌdɪsɪnfəˈmeɪʃən/", "pron": "KOWN-tuh dis-in-fuh-MAY-shuhn", "fr": "lutter contre la désinformation", "def": "To fight deliberately false information.", "ex": "Democracies must counter disinformation without censorship."}, {"term": "to amplify a narrative", "ipa": "/ˈæmplɪfaɪ ə ˈnærətɪv/", "pron": "AM-pli-fy uh NARR-uh-tiv", "fr": "amplifier un récit", "def": "To spread and strengthen a story or interpretation.", "ex": "Social media can amplify a narrative globally."}, {"term": "to exercise influence", "ipa": "/ˈeksəsaɪz ˈɪnfluəns/", "pron": "EK-suh-syze IN-floo-uhns", "fr": "exercer une influence", "def": "To use influence.", "ex": "Soft power allows states to exercise influence indirectly."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p6c58", "part": 6, "chapter": 58, "title": "Soft Power", "file": "cpge_vocab_part6_chapter58_soft_power_premium.html", "count": 138, "sections": [{"title": "A. Core concepts: soft, hard, smart and sharp power", "entries": [{"term": "soft power", "ipa": "/ˌsɒft ˈpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; puissance douce", "def": "The ability to influence others through attraction, culture, values and legitimacy rather than coercion.", "ex": "Soft power allows a country to shape preferences without using force."}, {"term": "hard power", "ipa": "/ˌhɑːd ˈpaʊə/", "pron": "hard POW-uh", "fr": "hard power ; puissance coercitive", "def": "Influence based on military force, economic pressure or coercion.", "ex": "Hard power can impose decisions but may create resentment."}, {"term": "smart power", "ipa": "/ˌsmɑːt ˈpaʊə/", "pron": "smart POW-uh", "fr": "smart power ; puissance intelligente", "def": "A strategy combining soft power and hard power effectively.", "ex": "Smart power blends diplomacy, culture, trade and military credibility."}, {"term": "sharp power", "ipa": "/ˌʃɑːp ˈpaʊə/", "pron": "sharp POW-uh", "fr": "sharp power ; pouvoir d’influence coercitif", "def": "Influence that uses manipulation, censorship, pressure or covert interference.", "ex": "Sharp power blurs the line between attraction and manipulation."}, {"term": "normative power", "ipa": "/ˈnɔːmətɪv ˈpaʊə/", "pron": "NOR-muh-tiv POW-uh", "fr": "puissance normative", "def": "Influence based on shaping norms, rules and values.", "ex": "The European Union is often described as a normative power."}, {"term": "civilian power", "ipa": "/səˈvɪliən ˈpaʊə/", "pron": "suh-VIL-yuhn POW-uh", "fr": "puissance civile", "def": "Influence based on diplomacy, trade, aid and law rather than military force.", "ex": "The EU has traditionally relied on civilian power."}, {"term": "cultural diplomacy", "ipa": "/ˌkʌltʃərəl dɪˈpləʊməsi/", "pron": "KUL-chuh-ruhl di-PLOH-muh-see", "fr": "diplomatie culturelle", "def": "The use of culture to build relationships and influence abroad.", "ex": "Cultural diplomacy includes language, cinema, museums and festivals."}, {"term": "public diplomacy", "ipa": "/ˌpʌblɪk dɪˈpləʊməsi/", "pron": "PUB-lik di-PLOH-muh-see", "fr": "diplomatie publique", "def": "Efforts by a state to communicate with foreign publics and shape its image.", "ex": "Public diplomacy targets societies, not only governments."}, {"term": "nation branding", "ipa": "/ˌneɪʃən ˈbrændɪŋ/", "pron": "NAY-shuhn BRAN-ding", "fr": "image de marque nationale", "def": "The strategy of shaping a country’s image abroad like a brand.", "ex": "Nation branding can attract tourists, investors and students."}, {"term": "country image", "ipa": "/ˌkʌntri ˈɪmɪdʒ/", "pron": "KUN-tree IM-ij", "fr": "image d’un pays", "def": "How a country is perceived by foreign publics.", "ex": "A positive country image strengthens soft power."}, {"term": "national image", "ipa": "/ˌnæʃənəl ˈɪmɪdʒ/", "pron": "NASH-uh-nuhl IM-ij", "fr": "image nationale", "def": "The reputation or perception of a nation.", "ex": "A national image can be damaged by war or human-rights abuses."}, {"term": "international image", "ipa": "/ˌɪntəˈnæʃənəl ˈɪmɪdʒ/", "pron": "IN-tuh-NASH-uh-nuhl IM-ij", "fr": "image internationale", "def": "The way a state is seen abroad.", "ex": "International image matters for diplomacy and trade."}, {"term": "global reputation", "ipa": "/ˌɡləʊbəl ˌrepjʊˈteɪʃən/", "pron": "GLOH-buhl rep-yuh-TAY-shuhn", "fr": "réputation mondiale", "def": "The overall reputation a country has around the world.", "ex": "A global reputation can take decades to build and years to lose."}, {"term": "prestige", "ipa": "/preˈstiːʒ/", "pron": "pre-STEEZH", "fr": "prestige", "def": "Respect and admiration gained through achievement or status.", "ex": "Scientific achievement can increase national prestige."}, {"term": "influence", "ipa": "/ˈɪnfluəns/", "pron": "IN-floo-uhns", "fr": "influence", "def": "The ability to affect opinions, behaviour or decisions.", "ex": "Soft power is a form of influence."}, {"term": "attraction", "ipa": "/əˈtrækʃən/", "pron": "uh-TRAK-shuhn", "fr": "attraction", "def": "The ability to make others admire or want to imitate something.", "ex": "Soft power relies on attraction rather than fear."}, {"term": "appeal", "ipa": "/əˈpiːl/", "pron": "uh-PEEL", "fr": "attrait", "def": "The quality of being attractive or persuasive.", "ex": "A country’s democratic model can have strong appeal."}, {"term": "legitimacy", "ipa": "/lɪˈdʒɪtɪməsi/", "pron": "li-JIT-i-muh-see", "fr": "légitimité", "def": "The perception that an actor’s power or actions are rightful and acceptable.", "ex": "Legitimacy makes international leadership easier."}, {"term": "credibility", "ipa": "/ˌkredəˈbɪləti/", "pron": "kred-uh-BIL-uh-tee", "fr": "crédibilité", "def": "The quality of being trusted and believed.", "ex": "Soft power depends on credibility."}, {"term": "trust", "ipa": "/trʌst/", "pron": "trust", "fr": "confiance", "def": "Confidence in someone’s honesty, reliability or intentions.", "ex": "Trust is essential in diplomacy."}, {"term": "moral authority", "ipa": "/ˌmɒrəl ɔːˈθɒrəti/", "pron": "MOR-uhl aw-THOR-uh-tee", "fr": "autorité morale", "def": "Influence gained from being seen as morally legitimate.", "ex": "Human-rights leadership can create moral authority."}, {"term": "values", "ipa": "/ˈvæljuːz/", "pron": "VAL-yooz", "fr": "valeurs", "def": "Principles or beliefs considered important by a society.", "ex": "Values can strengthen or weaken soft power."}, {"term": "liberal values", "ipa": "/ˌlɪbərəl ˈvæljuːz/", "pron": "LIB-uh-ruhl VAL-yooz", "fr": "valeurs libérales", "def": "Values such as individual rights, pluralism and the rule of law.", "ex": "Liberal values are often associated with Western soft power."}, {"term": "democratic values", "ipa": "/ˌdeməkrætɪk ˈvæljuːz/", "pron": "dem-uh-KRAT-ik VAL-yooz", "fr": "valeurs démocratiques", "def": "Values linked to democracy, rights and political participation.", "ex": "Democratic values can attract foreign publics."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Human rights can be a source of soft power when applied consistently."}, {"term": "rule of law", "ipa": "/ˌruːl əv ˈlɔː/", "pron": "rool ov law", "fr": "État de droit", "def": "The principle that everyone, including governments, is subject to law.", "ex": "The rule of law increases institutional credibility."}, {"term": "democracy promotion", "ipa": "/dɪˈmɒkrəsi prəˌməʊʃən/", "pron": "di-MOK-ruh-see pruh-MOH-shuhn", "fr": "promotion de la démocratie", "def": "Efforts to support democratic institutions abroad.", "ex": "Democracy promotion can be seen as idealistic or intrusive."}, {"term": "humanitarianism", "ipa": "/hjuːˌmænɪˈteəriənɪzəm/", "pron": "hyoo-man-i-TAIR-ee-uh-niz-uhm", "fr": "humanitarisme", "def": "Concern for human welfare and action to reduce suffering.", "ex": "Humanitarianism can strengthen a country’s image."}, {"term": "humanitarian aid", "ipa": "/hjuːˌmænɪˈteəriən ˈeɪd/", "pron": "hyoo-man-i-TAIR-ee-uhn aid", "fr": "aide humanitaire", "def": "Assistance such as food, medicine and shelter provided in crises.", "ex": "Humanitarian aid can save lives and improve international standing."}, {"term": "development aid", "ipa": "/dɪˈveləpmənt eɪd/", "pron": "di-VEL-uhp-muhnt aid", "fr": "aide au développement", "def": "Support given to poorer countries to promote development.", "ex": "Development aid is a tool of influence and solidarity."}, {"term": "foreign aid", "ipa": "/ˌfɒrən ˈeɪd/", "pron": "FOR-uhn aid", "fr": "aide étrangère", "def": "Money, goods or services given by one country to another.", "ex": "Foreign aid may serve both humanitarian and strategic goals."}, {"term": "official development assistance", "ipa": "/əˌfɪʃəl dɪˈveləpmənt əˈsɪstəns/", "pron": "uh-FISH-uhl di-VEL-uhp-muhnt uh-SIS-tuhns", "fr": "aide publique au développement", "def": "Government aid designed to promote development and welfare.", "ex": "Official development assistance supports health, education and infrastructure."}, {"term": "ODA", "ipa": "/ˌəʊ diː ˈeɪ/", "pron": "oh-dee-ay", "fr": "APD", "def": "Abbreviation for official development assistance.", "ex": "ODA can improve a donor country’s image."}, {"term": "cultural influence", "ipa": "/ˌkʌltʃərəl ˈɪnfluəns/", "pron": "KUL-chuh-ruhl IN-floo-uhns", "fr": "influence culturelle", "def": "Influence created through culture, arts, media and lifestyle.", "ex": "American cultural influence has long been global."}]}, {"title": "B. Culture, language, education and science diplomacy", "entries": [{"term": "popular culture", "ipa": "/ˌpɒpjʊlə ˈkʌltʃə/", "pron": "POP-yuh-luh KUL-chuh", "fr": "culture populaire", "def": "Culture enjoyed by large audiences, such as music, films and games.", "ex": "Popular culture can spread a country’s language and values."}, {"term": "pop culture", "ipa": "/ˈpɒp ˌkʌltʃə/", "pron": "pop KUL-chuh", "fr": "pop culture", "def": "Informal term for popular culture.", "ex": "Pop culture can reach audiences that formal diplomacy cannot."}, {"term": "film industry", "ipa": "/ˈfɪlm ˌɪndəstri/", "pron": "film IN-duh-stree", "fr": "industrie cinématographique", "def": "The sector producing and distributing films.", "ex": "The film industry contributes to soft power."}, {"term": "Hollywood", "ipa": "/ˈhɒliwʊd/", "pron": "HOL-ee-wood", "fr": "Hollywood", "def": "The US film industry, often used as a symbol of American cultural power.", "ex": "Hollywood has shaped global images of the United States."}, {"term": "Bollywood", "ipa": "/ˈbɒliwʊd/", "pron": "BOL-ee-wood", "fr": "Bollywood", "def": "The Hindi-language film industry based in India.", "ex": "Bollywood strengthens India’s cultural reach."}, {"term": "K-pop", "ipa": "/ˈkeɪ pɒp/", "pron": "kay-pop", "fr": "K-pop", "def": "South Korean popular music.", "ex": "K-pop has become a major source of South Korean soft power."}, {"term": "K-drama", "ipa": "/ˈkeɪ drɑːmə/", "pron": "kay-DRAH-muh", "fr": "drama coréen", "def": "South Korean television drama.", "ex": "K-dramas attract global audiences."}, {"term": "Korean Wave", "ipa": "/kəˌriːən ˈweɪv/", "pron": "kuh-REE-uhn wave", "fr": "vague coréenne ; Hallyu", "def": "The global spread of South Korean culture.", "ex": "The Korean Wave shows how culture can become geopolitical influence."}, {"term": "Hallyu", "ipa": "/ˈhæljuː/", "pron": "HAL-yoo", "fr": "Hallyu", "def": "Korean term for the Korean Wave.", "ex": "Hallyu has boosted tourism and exports."}, {"term": "anime", "ipa": "/ˈænɪmeɪ/", "pron": "AN-i-may", "fr": "anime", "def": "Japanese animated film and television.", "ex": "Anime contributes to Japan’s global cultural appeal."}, {"term": "manga", "ipa": "/ˈmæŋɡə/", "pron": "MAN-guh", "fr": "manga", "def": "Japanese comics and graphic novels.", "ex": "Manga has helped spread Japanese cultural influence."}, {"term": "video games", "ipa": "/ˈvɪdiəʊ ɡeɪmz/", "pron": "VID-ee-oh games", "fr": "jeux vidéo", "def": "Electronic games played on computers, consoles or phones.", "ex": "Video games can shape global perceptions of culture."}, {"term": "music industry", "ipa": "/ˈmjuːzɪk ˌɪndəstri/", "pron": "MYOO-zik IN-duh-stree", "fr": "industrie musicale", "def": "The sector producing and distributing music.", "ex": "The music industry is a major vehicle of soft power."}, {"term": "streaming platform", "ipa": "/ˈstriːmɪŋ ˌplætfɔːm/", "pron": "STREE-ming PLAT-form", "fr": "plateforme de streaming", "def": "An online service distributing films, music or series.", "ex": "Streaming platforms spread culture across borders."}, {"term": "global audience", "ipa": "/ˌɡləʊbəl ˈɔːdiəns/", "pron": "GLOH-buhl AW-dee-uhns", "fr": "public mondial", "def": "People around the world reached by media or culture.", "ex": "A global audience can amplify cultural diplomacy."}, {"term": "cultural export", "ipa": "/ˌkʌltʃərəl ˈekspɔːt/", "pron": "KUL-chuh-ruhl EK-sport", "fr": "exportation culturelle", "def": "A cultural product sold or spread abroad.", "ex": "Cultural exports include films, music and fashion."}, {"term": "creative industries", "ipa": "/kriˌeɪtɪv ˈɪndəstriz/", "pron": "kree-AY-tiv IN-duh-streez", "fr": "industries créatives", "def": "Sectors based on creativity, such as film, design, music and games.", "ex": "Creative industries can generate both revenue and influence."}, {"term": "language policy", "ipa": "/ˈlæŋɡwɪdʒ ˈpɒləsi/", "pron": "LANG-gwij POL-uh-see", "fr": "politique linguistique", "def": "Policies promoting or regulating language use.", "ex": "Language policy can support cultural influence."}, {"term": "language learning", "ipa": "/ˈlæŋɡwɪdʒ ˌlɜːnɪŋ/", "pron": "LANG-gwij LUR-ning", "fr": "apprentissage des langues", "def": "The process of learning a foreign language.", "ex": "Language learning can create long-term cultural connections."}, {"term": "English language", "ipa": "/ˌɪŋɡlɪʃ ˈlæŋɡwɪdʒ/", "pron": "ING-glish LANG-gwij", "fr": "langue anglaise", "def": "The English language, often linked to global communication.", "ex": "The English language strengthens British and American soft power."}, {"term": "Francophonie", "ipa": "/ˌfræŋkɒfəˈniː/", "pron": "fran-kof-uh-NEE", "fr": "Francophonie", "def": "The global community of French-speaking countries and institutions.", "ex": "Francophonie supports French cultural and diplomatic influence."}, {"term": "British Council", "ipa": "/ˌbrɪtɪʃ ˈkaʊnsəl/", "pron": "BRIT-ish KOWN-suhl", "fr": "British Council", "def": "UK organisation promoting British culture and English abroad.", "ex": "The British Council is a major soft-power institution."}, {"term": "Alliance Française", "ipa": "/ˌæliˌɒns frɒnˈseɪz/", "pron": "al-ee-ONS fron-SAYZ", "fr": "Alliance française", "def": "Organisation promoting French language and culture abroad.", "ex": "Alliance Française promotes French through classes and cultural events."}, {"term": "Goethe-Institut", "ipa": "/ˌɡɜːtə ˈɪnstɪtjuːt/", "pron": "GUR-tuh IN-sti-tyoot", "fr": "Goethe-Institut", "def": "German cultural institute promoting language and culture abroad.", "ex": "The Goethe-Institut supports German cultural diplomacy."}, {"term": "Confucius Institute", "ipa": "/kənˈfjuːʃəs ˈɪnstɪtjuːt/", "pron": "kuhn-FYOO-shuhs IN-sti-tyoot", "fr": "Institut Confucius", "def": "Chinese state-linked institute promoting Chinese language and culture abroad.", "ex": "Confucius Institutes are sometimes criticised over academic freedom concerns."}, {"term": "cultural institute", "ipa": "/ˌkʌltʃərəl ˈɪnstɪtjuːt/", "pron": "KUL-chuh-ruhl IN-sti-tyoot", "fr": "institut culturel", "def": "An organisation promoting a country’s culture and language abroad.", "ex": "Cultural institutes are long-term tools of soft power."}, {"term": "education diplomacy", "ipa": "/ˌedjʊˈkeɪʃən dɪˈpləʊməsi/", "pron": "ej-yoo-KAY-shuhn di-PLOH-muh-see", "fr": "diplomatie éducative", "def": "The use of education, universities and exchanges to build influence.", "ex": "Education diplomacy creates lasting personal ties."}, {"term": "academic exchange", "ipa": "/ˌækəˈdemɪk ɪksˈtʃeɪndʒ/", "pron": "ak-uh-DEM-ik iks-CHAYNJ", "fr": "échange universitaire", "def": "A programme allowing students or scholars to study or teach abroad.", "ex": "Academic exchanges build mutual understanding."}, {"term": "student exchange", "ipa": "/ˈstjuːdənt ɪksˌtʃeɪndʒ/", "pron": "STYOO-duhnt iks-CHAYNJ", "fr": "échange étudiant", "def": "A programme allowing students to study abroad temporarily.", "ex": "Student exchanges can create lifelong cultural affinity."}, {"term": "scholarship programme", "ipa": "/ˈskɒləʃɪp ˌprəʊɡræm/", "pron": "SKOL-uh-ship PROH-gram", "fr": "programme de bourses", "def": "A programme funding study or research.", "ex": "Scholarship programmes attract talented foreign students."}, {"term": "Fulbright Program", "ipa": "/ˈfʊlbraɪt ˌprəʊɡræm/", "pron": "FULL-bright PROH-gram", "fr": "programme Fulbright", "def": "US educational exchange programme.", "ex": "The Fulbright Program is a major instrument of US soft power."}, {"term": "Erasmus", "ipa": "/ɪˈræzməs/", "pron": "i-RAZ-muhs", "fr": "Erasmus", "def": "EU programme supporting study, training and youth exchanges.", "ex": "Erasmus has strengthened European identity among students."}, {"term": "international student", "ipa": "/ˌɪntəˈnæʃənəl ˈstjuːdənt/", "pron": "IN-tuh-NASH-uh-nuhl STYOO-duhnt", "fr": "étudiant international", "def": "A student studying in a foreign country.", "ex": "International students can become cultural ambassadors."}, {"term": "alumni network", "ipa": "/əˈlʌmnaɪ ˌnetwɜːk/", "pron": "uh-LUM-ny NET-work", "fr": "réseau d’anciens", "def": "A network of former students or participants.", "ex": "Alumni networks maintain long-term influence."}, {"term": "university ranking", "ipa": "/ˌjuːnɪˈvɜːsəti ˈræŋkɪŋ/", "pron": "yoo-ni-VUR-suh-tee RANG-king", "fr": "classement universitaire", "def": "A list comparing universities by reputation or performance.", "ex": "University rankings affect international attractiveness."}, {"term": "research excellence", "ipa": "/rɪˈsɜːtʃ ˈeksələns/", "pron": "ri-SURCH EK-suh-luhns", "fr": "excellence scientifique", "def": "High-quality research performance.", "ex": "Research excellence increases academic prestige."}, {"term": "science diplomacy", "ipa": "/ˈsaɪəns dɪˌpləʊməsi/", "pron": "SY-uhns di-PLOH-muh-see", "fr": "diplomatie scientifique", "def": "Using scientific cooperation to support international relations.", "ex": "Science diplomacy can continue even when political relations are tense."}, {"term": "medical diplomacy", "ipa": "/ˈmedɪkəl dɪˌpləʊməsi/", "pron": "MED-i-kuhl di-PLOH-muh-see", "fr": "diplomatie médicale", "def": "Using health aid, doctors, vaccines or medical cooperation to build influence.", "ex": "Medical diplomacy became visible during the pandemic."}, {"term": "vaccine diplomacy", "ipa": "/ˈvæksiːn dɪˌpləʊməsi/", "pron": "VAK-seen di-PLOH-muh-see", "fr": "diplomatie vaccinale", "def": "Using vaccine donations or sales to gain goodwill or influence.", "ex": "Vaccine diplomacy became a tool of influence during COVID-19."}, {"term": "sports diplomacy", "ipa": "/ˈspɔːts dɪˌpləʊməsi/", "pron": "sports di-PLOH-muh-see", "fr": "diplomatie sportive", "def": "Using sport to improve relations or national image.", "ex": "Sports diplomacy can bring rivals together or project prestige."}, {"term": "sporting event", "ipa": "/ˈspɔːtɪŋ ɪˌvent/", "pron": "SPOR-ting i-VENT", "fr": "événement sportif", "def": "A sports competition or event.", "ex": "Major sporting events can be used for nation branding."}]}, {"title": "C. Sport, tourism, diaspora, media and digital diplomacy", "entries": [{"term": "mega-event", "ipa": "/ˈmeɡə ɪˌvent/", "pron": "MEG-uh i-VENT", "fr": "méga-événement", "def": "A very large global event such as the Olympics or World Cup.", "ex": "Mega-events can showcase a country but also attract criticism."}, {"term": "Olympic Games", "ipa": "/əˌlɪmpɪk ˈɡeɪmz/", "pron": "uh-LIM-pik games", "fr": "Jeux olympiques", "def": "The international multi-sport event held every four years.", "ex": "The Olympic Games are a major stage for soft power."}, {"term": "World Cup", "ipa": "/ˌwɜːld ˈkʌp/", "pron": "world cup", "fr": "Coupe du monde", "def": "A major international sports tournament, especially in football.", "ex": "Hosting the World Cup can boost global visibility."}, {"term": "sportswashing", "ipa": "/ˈspɔːtsˌwɒʃɪŋ/", "pron": "SPORTS-wosh-ing", "fr": "sportswashing", "def": "Using sport to improve reputation and distract from criticism.", "ex": "Sportswashing is often discussed in relation to authoritarian states."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "écoblanchiment ; greenwashing", "def": "Making misleading environmental claims to improve reputation.", "ex": "Greenwashing can damage credibility when exposed."}, {"term": "artwashing", "ipa": "/ˈɑːtˌwɒʃɪŋ/", "pron": "ART-wosh-ing", "fr": "artwashing", "def": "Using art or culture to improve reputation and distract from wrongdoing.", "ex": "Critics accuse some governments of artwashing."}, {"term": "reputation laundering", "ipa": "/ˌrepjʊˈteɪʃən ˈlɔːndərɪŋ/", "pron": "rep-yuh-TAY-shuhn LAWN-duh-ring", "fr": "blanchiment de réputation", "def": "Trying to clean up a damaged image through publicity, culture or sponsorship.", "ex": "Reputation laundering can be part of authoritarian soft power."}, {"term": "tourism", "ipa": "/ˈtʊərɪzəm/", "pron": "TOOR-iz-uhm", "fr": "tourisme", "def": "Travel for leisure, culture or business.", "ex": "Tourism spreads images, stories and stereotypes of a country."}, {"term": "tourist appeal", "ipa": "/ˈtʊərɪst əˌpiːl/", "pron": "TOOR-ist uh-PEEL", "fr": "attrait touristique", "def": "The attractiveness of a place to visitors.", "ex": "Tourist appeal contributes to soft power."}, {"term": "heritage site", "ipa": "/ˈherɪtɪdʒ saɪt/", "pron": "HERR-i-tij site", "fr": "site patrimonial", "def": "A place valued for historical or cultural importance.", "ex": "Heritage sites strengthen cultural prestige."}, {"term": "UNESCO World Heritage Site", "ipa": "/juːˌneskəʊ ˌwɜːld ˈherɪtɪdʒ saɪt/", "pron": "yoo-NES-koh world HERR-i-tij site", "fr": "site du patrimoine mondial de l’UNESCO", "def": "A place recognised by UNESCO as having outstanding cultural or natural value.", "ex": "UNESCO World Heritage Sites attract global attention."}, {"term": "gastronomy", "ipa": "/ɡæˈstrɒnəmi/", "pron": "ga-STRON-uh-mee", "fr": "gastronomie", "def": "The culture and art of food and cuisine.", "ex": "Gastronomy is an underrated form of cultural diplomacy."}, {"term": "fashion industry", "ipa": "/ˈfæʃən ˌɪndəstri/", "pron": "FASH-uhn IN-duh-stree", "fr": "industrie de la mode", "def": "The sector designing and selling clothing and style.", "ex": "The fashion industry contributes to French and Italian soft power."}, {"term": "luxury goods", "ipa": "/ˌlʌkʃəri ˈɡʊdz/", "pron": "LUK-shuh-ree goods", "fr": "produits de luxe", "def": "High-end expensive products associated with prestige.", "ex": "Luxury goods can enhance a country’s image."}, {"term": "diaspora", "ipa": "/daɪˈæspərə/", "pron": "dy-AS-puh-ruh", "fr": "diaspora", "def": "A community living outside its ancestral homeland.", "ex": "Diasporas can connect countries through culture, business and politics."}, {"term": "diaspora diplomacy", "ipa": "/daɪˈæspərə dɪˌpləʊməsi/", "pron": "dy-AS-puh-ruh di-PLOH-muh-see", "fr": "diplomatie de la diaspora", "def": "Using diaspora communities to build influence and connections.", "ex": "Diaspora diplomacy can strengthen economic and cultural ties."}, {"term": "people-to-people ties", "ipa": "/ˌpiːpəl tə ˈpiːpəl taɪz/", "pron": "PEE-puhl tuh PEE-puhl ties", "fr": "liens entre populations", "def": "Direct relationships between citizens of different countries.", "ex": "People-to-people ties build durable trust."}, {"term": "civil-society links", "ipa": "/ˌsɪvəl səˈsaɪəti lɪŋks/", "pron": "SIV-uhl suh-SY-uh-tee links", "fr": "liens entre sociétés civiles", "def": "Connections between NGOs, associations and citizens across borders.", "ex": "Civil-society links can survive political tensions."}, {"term": "NGO", "ipa": "/ˌen dʒiː ˈəʊ/", "pron": "en-jee-oh", "fr": "ONG", "def": "Non-governmental organisation.", "ex": "NGOs can support soft power through humanitarian work."}, {"term": "international broadcaster", "ipa": "/ˌɪntəˈnæʃənəl ˈbrɔːdkɑːstə/", "pron": "IN-tuh-NASH-uh-nuhl BROD-kas-tuh", "fr": "média international", "def": "A media organisation broadcasting to foreign audiences.", "ex": "International broadcasters shape narratives abroad."}, {"term": "BBC World Service", "ipa": "/ˌbiː biː ˈsiː ˌwɜːld ˈsɜːvɪs/", "pron": "bee-bee-see world SUR-vis", "fr": "BBC World Service", "def": "The BBC’s international broadcasting service.", "ex": "The BBC World Service is a major British soft-power asset."}, {"term": "Voice of America", "ipa": "/ˌvɔɪs əv əˈmerɪkə/", "pron": "voice ov uh-MERR-i-kuh", "fr": "Voice of America", "def": "US international broadcaster.", "ex": "Voice of America broadcasts news and US perspectives abroad."}, {"term": "RT", "ipa": "/ˌɑː ˈtiː/", "pron": "ar-tee", "fr": "RT", "def": "Russian state-funded international broadcaster.", "ex": "RT has been accused of spreading disinformation."}, {"term": "Al Jazeera", "ipa": "/ˌæl dʒəˈzɪərə/", "pron": "al juh-ZEER-uh", "fr": "Al Jazeera", "def": "Qatar-based international broadcaster.", "ex": "Al Jazeera expanded Qatar’s global visibility."}, {"term": "global media", "ipa": "/ˌɡləʊbəl ˈmiːdiə/", "pron": "GLOH-buhl MEE-dee-uh", "fr": "médias mondiaux", "def": "Media with worldwide reach.", "ex": "Global media shape international perceptions."}, {"term": "narrative", "ipa": "/ˈnærətɪv/", "pron": "NARR-uh-tiv", "fr": "récit ; narration", "def": "A story or interpretation used to make sense of events.", "ex": "Controlling the narrative is central to public diplomacy."}, {"term": "strategic communication", "ipa": "/strəˌtiːdʒɪk kəˌmjuːnɪˈkeɪʃən/", "pron": "struh-TEE-jik kuh-myoo-ni-KAY-shuhn", "fr": "communication stratégique", "def": "Coordinated communication designed to influence audiences.", "ex": "Strategic communication is vital during crises."}, {"term": "message discipline", "ipa": "/ˈmesɪdʒ ˌdɪsəplɪn/", "pron": "MESS-ij DIS-uh-plin", "fr": "discipline de communication", "def": "Keeping communication consistent and controlled.", "ex": "Message discipline strengthens credibility."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to mislead.", "ex": "Disinformation can destroy trust in public diplomacy."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Biased or misleading information used to promote a political cause.", "ex": "Propaganda is less credible than genuine cultural attraction."}, {"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WAR-fair", "fr": "guerre de l’information", "def": "Use of information and media to influence conflict or politics.", "ex": "Information warfare can undermine democratic societies."}, {"term": "digital diplomacy", "ipa": "/ˌdɪdʒɪtəl dɪˈpləʊməsi/", "pron": "DIJ-i-tuhl di-PLOH-muh-see", "fr": "diplomatie numérique", "def": "Diplomacy conducted through digital tools and online platforms.", "ex": "Digital diplomacy allows governments to reach foreign publics directly."}, {"term": "social media diplomacy", "ipa": "/ˌsəʊʃəl ˈmiːdiə dɪˌpləʊməsi/", "pron": "SOH-shuhl MEE-dee-uh di-PLOH-muh-see", "fr": "diplomatie sur les réseaux sociaux", "def": "Using social media for diplomatic communication and influence.", "ex": "Social media diplomacy can be fast but risky."}, {"term": "hashtag diplomacy", "ipa": "/ˈhæʃtæɡ dɪˌpləʊməsi/", "pron": "HASH-tag di-PLOH-muh-see", "fr": "diplomatie du hashtag", "def": "Using hashtags and online campaigns for diplomatic messaging.", "ex": "Hashtag diplomacy can mobilise attention quickly."}, {"term": "influence operation", "ipa": "/ˈɪnfluəns ˌɒpəˈreɪʃən/", "pron": "IN-floo-uhns op-uh-RAY-shuhn", "fr": "opération d’influence", "def": "A coordinated attempt to shape opinions or decisions.", "ex": "Influence operations may be open or covert."}, {"term": "foreign interference", "ipa": "/ˌfɒrən ˌɪntəˈfɪərəns/", "pron": "FOR-uhn in-tuh-FEER-uhns", "fr": "ingérence étrangère", "def": "Improper foreign involvement in another country’s politics.", "ex": "Foreign interference undermines trust and sovereignty."}, {"term": "election interference", "ipa": "/ɪˈlekʃən ˌɪntəˈfɪərəns/", "pron": "i-LEK-shuhn in-tuh-FEER-uhns", "fr": "ingérence électorale", "def": "Attempts to influence or manipulate another country’s elections.", "ex": "Election interference is a form of hostile influence."}, {"term": "soft-power ranking", "ipa": "/ˌsɒft ˈpaʊə ˈræŋkɪŋ/", "pron": "soft POW-uh RANG-king", "fr": "classement de soft power", "def": "A ranking comparing countries’ attractiveness and influence.", "ex": "Soft-power rankings often measure culture, education and diplomacy."}, {"term": "global influence index", "ipa": "/ˌɡləʊbəl ˈɪnfluəns ˈɪndeks/", "pron": "GLOH-buhl IN-floo-uhns IN-deks", "fr": "indice d’influence mondiale", "def": "An index measuring international influence.", "ex": "A global influence index can oversimplify complex realities."}, {"term": "reputational damage", "ipa": "/ˌrepjʊˈteɪʃənəl ˈdæmɪdʒ/", "pron": "rep-yuh-TAY-shuh-nuhl DAM-ij", "fr": "atteinte à la réputation", "def": "Harm done to a country’s image or credibility.", "ex": "Human-rights scandals cause reputational damage."}, {"term": "credibility gap", "ipa": "/ˌkredəˈbɪləti ɡæp/", "pron": "kred-uh-BIL-uh-tee gap", "fr": "déficit de crédibilité", "def": "A gap between what an actor says and what it does.", "ex": "A credibility gap weakens soft power."}, {"term": "double standards", "ipa": "/ˌdʌbəl ˈstændədz/", "pron": "DUB-uhl STAN-duhdz", "fr": "deux poids deux mesures", "def": "Applying different principles to similar situations.", "ex": "Accusations of double standards damage Western soft power."}, {"term": "hypocrisy", "ipa": "/hɪˈpɒkrəsi/", "pron": "hi-POK-ruh-see", "fr": "hypocrisie", "def": "Pretending to have values that one does not apply consistently.", "ex": "Perceived hypocrisy undermines moral authority."}]}, {"title": "D. Reputation, credibility, backlash and contested influence", "entries": [{"term": "backlash", "ipa": "/ˈbæklæʃ/", "pron": "BAK-lash", "fr": "retour de bâton ; réaction hostile", "def": "A strong negative reaction.", "ex": "Aggressive public diplomacy can create a backlash."}, {"term": "anti-Americanism", "ipa": "/ˌænti əˈmerɪkənɪzəm/", "pron": "AN-tee uh-MERR-i-kuh-niz-uhm", "fr": "anti-américanisme", "def": "Hostility towards US power, culture or policies.", "ex": "Anti-Americanism can weaken US soft power."}, {"term": "anti-Western sentiment", "ipa": "/ˌænti ˈwestən ˈsentɪmənt/", "pron": "AN-tee WES-tuhn SEN-ti-muhnt", "fr": "sentiment anti-occidental", "def": "Negative feeling towards Western countries or values.", "ex": "Anti-Western sentiment can be fuelled by foreign policy decisions."}, {"term": "cultural imperialism", "ipa": "/ˌkʌltʃərəl ɪmˈpɪəriəlɪzəm/", "pron": "KUL-chuh-ruhl im-PEER-ee-uh-liz-uhm", "fr": "impérialisme culturel", "def": "The domination of one culture over others, often through media or markets.", "ex": "Critics see Hollywood’s global reach as cultural imperialism."}, {"term": "soft-power strategy", "ipa": "/ˌsɒft ˈpaʊə ˈstrætədʒi/", "pron": "soft POW-uh STRAT-uh-jee", "fr": "stratégie de soft power", "def": "A plan to increase attraction and influence abroad.", "ex": "A soft-power strategy must be credible and long-term."}, {"term": "to project a positive image", "ipa": "/prəˈdʒekt ə ˌpɒzətɪv ˈɪmɪdʒ/", "pron": "pruh-JEKT uh POZ-uh-tiv IM-ij", "fr": "projeter une image positive", "def": "To present an attractive image abroad.", "ex": "Countries use culture to project a positive image."}, {"term": "to shape perceptions", "ipa": "/ʃeɪp pəˈsepʃənz/", "pron": "shayp puh-SEP-shuhnz", "fr": "façonner les perceptions", "def": "To influence how people see an issue or country.", "ex": "Public diplomacy tries to shape perceptions."}, {"term": "to win hearts and minds", "ipa": "/wɪn hɑːts ənd maɪndz/", "pron": "win hearts and myndz", "fr": "gagner les cœurs et les esprits", "def": "To gain emotional and intellectual support.", "ex": "Soft power aims to win hearts and minds."}, {"term": "to attract foreign students", "ipa": "/əˈtrækt ˌfɒrən ˈstjuːdənts/", "pron": "uh-TRAKT FOR-uhn STYOO-duhnts", "fr": "attirer des étudiants étrangers", "def": "To draw students from other countries.", "ex": "Universities help attract foreign students."}, {"term": "to promote national culture", "ipa": "/prəˈməʊt ˌnæʃənəl ˈkʌltʃə/", "pron": "pruh-MOHT NASH-uh-nuhl KUL-chuh", "fr": "promouvoir la culture nationale", "def": "To spread awareness and appreciation of a country’s culture.", "ex": "Cultural institutes promote national culture."}, {"term": "to export culture", "ipa": "/ekˈspɔːt ˈkʌltʃə/", "pron": "ek-SPORT KUL-chuh", "fr": "exporter sa culture", "def": "To spread cultural products abroad.", "ex": "Streaming platforms help export culture."}, {"term": "to host a mega-event", "ipa": "/həʊst ə ˈmeɡə ɪˌvent/", "pron": "hohst uh MEG-uh i-VENT", "fr": "accueillir un méga-événement", "def": "To organise a major global event.", "ex": "States host mega-events to gain prestige."}, {"term": "to launder one’s reputation", "ipa": "/ˈlɔːndə wʌnz ˌrepjʊˈteɪʃən/", "pron": "LAWN-duh wunz rep-yuh-TAY-shuhn", "fr": "blanchir sa réputation", "def": "To try to clean up a damaged image through publicity or sponsorship.", "ex": "Critics accuse some regimes of trying to launder their reputation."}, {"term": "to build trust", "ipa": "/bɪld trʌst/", "pron": "bild trust", "fr": "instaurer la confiance", "def": "To create confidence and reliability.", "ex": "Educational exchanges build trust."}, {"term": "to gain legitimacy", "ipa": "/ɡeɪn lɪˈdʒɪtɪməsi/", "pron": "gayn li-JIT-i-muh-see", "fr": "gagner en légitimité", "def": "To become seen as rightful or acceptable.", "ex": "Humanitarian action can help a state gain legitimacy."}, {"term": "to lose credibility", "ipa": "/luːz ˌkredəˈbɪləti/", "pron": "looz kred-uh-BIL-uh-tee", "fr": "perdre en crédibilité", "def": "To become less trusted or believable.", "ex": "Double standards make countries lose credibility."}, {"term": "to undermine soft power", "ipa": "/ˌʌndəˈmaɪn ˌsɒft ˈpaʊə/", "pron": "un-duh-MYNE soft POW-uh", "fr": "saper le soft power", "def": "To weaken attraction and influence.", "ex": "War crimes undermine soft power."}, {"term": "to counter disinformation", "ipa": "/ˈkaʊntə ˌdɪsɪnfəˈmeɪʃən/", "pron": "KOWN-tuh dis-in-fuh-MAY-shuhn", "fr": "lutter contre la désinformation", "def": "To fight deliberately false information.", "ex": "Democracies must counter disinformation without censorship."}, {"term": "to amplify a narrative", "ipa": "/ˈæmplɪfaɪ ə ˈnærətɪv/", "pron": "AM-pli-fy uh NARR-uh-tiv", "fr": "amplifier un récit", "def": "To spread and strengthen a story or interpretation.", "ex": "Social media can amplify a narrative globally."}, {"term": "to exercise influence", "ipa": "/ˈeksəsaɪz ˈɪnfluəns/", "pron": "EK-suh-syze IN-floo-uhns", "fr": "exercer une influence", "def": "To use influence.", "ex": "Soft power allows states to exercise influence indirectly."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p7c59", "part": 7, "chapter": 59, "title": "Artificial Intelligence", "file": "cpge_vocab_part7_chapter59_artificial_intelligence_premium.html", "count": 145, "sections": [{"title": "A. Core AI concepts and technologies", "entries": [{"term": "artificial intelligence", "ipa": "/ˌɑːtɪˈfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks that normally require human intelligence.", "ex": "Artificial intelligence is reshaping science, business, education and politics."}, {"term": "AI", "ipa": "/ˌeɪ ˈaɪ/", "pron": "ay-eye", "fr": "IA", "def": "Abbreviation for artificial intelligence.", "ex": "AI can support decision-making but also raise ethical concerns."}, {"term": "AI system", "ipa": "/ˌeɪ ˈaɪ ˈsɪstəm/", "pron": "ay-eye SIS-tuhm", "fr": "système d’IA", "def": "A system using artificial intelligence to perform tasks or generate outputs.", "ex": "An AI system should be tested before being deployed."}, {"term": "algorithm", "ipa": "/ˈælɡərɪðəm/", "pron": "AL-guh-rith-uhm", "fr": "algorithme", "def": "A set of instructions used by a computer to solve a problem or make a decision.", "ex": "Algorithms increasingly influence what people see online."}, {"term": "machine learning", "ipa": "/məˌʃiːn ˈlɜːnɪŋ/", "pron": "muh-SHEEN LUR-ning", "fr": "apprentissage automatique", "def": "A type of AI in which systems learn patterns from data.", "ex": "Machine learning is used in finance, healthcare and advertising."}, {"term": "deep learning", "ipa": "/ˌdiːp ˈlɜːnɪŋ/", "pron": "deep LUR-ning", "fr": "apprentissage profond", "def": "A type of machine learning using layered neural networks.", "ex": "Deep learning has improved image and speech recognition."}, {"term": "neural network", "ipa": "/ˌnjʊərəl ˈnetwɜːk/", "pron": "NYOOR-uhl NET-work", "fr": "réseau de neurones", "def": "A computing system inspired by connections between neurons.", "ex": "A neural network can recognise patterns in large datasets."}, {"term": "artificial neural network", "ipa": "/ˌɑːtɪˈfɪʃəl ˌnjʊərəl ˈnetwɜːk/", "pron": "ar-ti-FISH-uhl NYOOR-uhl NET-work", "fr": "réseau de neurones artificiels", "def": "A model made of connected processing units used in deep learning.", "ex": "Artificial neural networks power many AI applications."}, {"term": "model", "ipa": "/ˈmɒdəl/", "pron": "MOD-uhl", "fr": "modèle", "def": "A computer system trained to make predictions or generate outputs.", "ex": "An AI model can be trained on millions of examples."}, {"term": "AI model", "ipa": "/ˌeɪ ˈaɪ ˈmɒdəl/", "pron": "ay-eye MOD-uhl", "fr": "modèle d’IA", "def": "A model using artificial intelligence techniques.", "ex": "The AI model performed well on the test data."}, {"term": "large language model", "ipa": "/ˌlɑːdʒ ˈlæŋɡwɪdʒ ˌmɒdəl/", "pron": "larj LANG-gwij MOD-uhl", "fr": "grand modèle de langage", "def": "An AI model trained to process and generate language.", "ex": "Large language models can write summaries, code and dialogue."}, {"term": "LLM", "ipa": "/ˌel el ˈem/", "pron": "el-el-em", "fr": "LLM ; grand modèle de langage", "def": "Abbreviation for large language model.", "ex": "LLMs have transformed debates about knowledge work."}, {"term": "generative AI", "ipa": "/ˌdʒenərətɪv ˌeɪ ˈaɪ/", "pron": "JEN-uh-ruh-tiv ay-eye", "fr": "IA générative", "def": "AI that creates text, images, music, code or other content.", "ex": "Generative AI has become a major issue in education."}, {"term": "chatbot", "ipa": "/ˈtʃætbɒt/", "pron": "CHAT-bot", "fr": "agent conversationnel ; chatbot", "def": "A program designed to hold conversations with users.", "ex": "Chatbots are used in customer service and learning tools."}, {"term": "virtual assistant", "ipa": "/ˌvɜːtʃuəl əˈsɪstənt/", "pron": "VUR-choo-uhl uh-SIS-tuhnt", "fr": "assistant virtuel", "def": "Software that helps users through voice or text interaction.", "ex": "A virtual assistant can schedule meetings and answer questions."}, {"term": "automation", "ipa": "/ˌɔːtəˈmeɪʃən/", "pron": "aw-tuh-MAY-shuhn", "fr": "automatisation", "def": "The use of technology to perform tasks with little human input.", "ex": "Automation can improve efficiency but threaten some jobs."}, {"term": "robotics", "ipa": "/rəʊˈbɒtɪks/", "pron": "roh-BOT-iks", "fr": "robotique", "def": "The design and use of robots.", "ex": "Robotics is increasingly combined with AI."}, {"term": "autonomous system", "ipa": "/ɔːˌtɒnəməs ˈsɪstəm/", "pron": "aw-TON-uh-muhs SIS-tuhm", "fr": "système autonome", "def": "A system able to operate with limited human control.", "ex": "Autonomous systems raise questions about responsibility."}, {"term": "autonomous vehicle", "ipa": "/ɔːˌtɒnəməs ˈviːɪkəl/", "pron": "aw-TON-uh-muhs VEE-i-kuhl", "fr": "véhicule autonome", "def": "A vehicle able to drive itself using sensors and software.", "ex": "Autonomous vehicles must make decisions in complex environments."}, {"term": "self-driving car", "ipa": "/ˌself ˈdraɪvɪŋ kɑː/", "pron": "self-DRY-ving car", "fr": "voiture autonome", "def": "A car designed to drive without human control.", "ex": "Self-driving cars could reduce accidents but create legal dilemmas."}, {"term": "computer vision", "ipa": "/kəmˌpjuːtə ˈvɪʒən/", "pron": "kuhm-PYOO-tuh VIZH-uhn", "fr": "vision par ordinateur", "def": "AI that enables computers to interpret images and video.", "ex": "Computer vision is used in medicine and surveillance."}, {"term": "facial recognition", "ipa": "/ˌfeɪʃəl ˌrekəɡˈnɪʃən/", "pron": "FAY-shuhl rek-uhg-NISH-uhn", "fr": "reconnaissance faciale", "def": "Technology identifying people from their faces.", "ex": "Facial recognition raises privacy and civil-liberty concerns."}, {"term": "speech recognition", "ipa": "/ˈspiːtʃ ˌrekəɡˈnɪʃən/", "pron": "speech rek-uhg-NISH-uhn", "fr": "reconnaissance vocale", "def": "Technology converting spoken language into text or commands.", "ex": "Speech recognition is used in smartphones and call centres."}, {"term": "natural language processing", "ipa": "/ˌnætʃərəl ˈlæŋɡwɪdʒ ˈprəʊsesɪŋ/", "pron": "NAT-chuh-ruhl LANG-gwij PROH-ses-ing", "fr": "traitement automatique du langage naturel", "def": "AI techniques used to understand and generate human language.", "ex": "Natural language processing powers translation tools."}, {"term": "NLP", "ipa": "/ˌen el ˈpiː/", "pron": "en-el-pee", "fr": "TAL ; NLP", "def": "Abbreviation for natural language processing.", "ex": "NLP is central to chatbots and search engines."}, {"term": "data", "ipa": "/ˈdeɪtə/", "pron": "DAY-tuh", "fr": "données", "def": "Information used by computers, organisations or researchers.", "ex": "AI systems depend on large amounts of data."}]}, {"title": "B. Data, prompts and model behaviour", "entries": [{"term": "dataset", "ipa": "/ˈdeɪtəset/", "pron": "DAY-tuh-set", "fr": "jeu de données", "def": "A structured collection of data.", "ex": "A biased dataset can lead to unfair results."}, {"term": "training data", "ipa": "/ˈtreɪnɪŋ ˌdeɪtə/", "pron": "TRAY-ning DAY-tuh", "fr": "données d’entraînement", "def": "Data used to train an AI model.", "ex": "Training data shapes the behaviour of AI models."}, {"term": "test data", "ipa": "/ˈtest ˌdeɪtə/", "pron": "test DAY-tuh", "fr": "données de test", "def": "Data used to evaluate a model after training.", "ex": "Test data helps measure whether a model generalises."}, {"term": "labelled data", "ipa": "/ˌleɪbəld ˈdeɪtə/", "pron": "LAY-buhld DAY-tuh", "fr": "données étiquetées", "def": "Data with human-provided categories or answers.", "ex": "Labelled data is useful for supervised learning."}, {"term": "unlabelled data", "ipa": "/ʌnˌleɪbəld ˈdeɪtə/", "pron": "un-LAY-buhld DAY-tuh", "fr": "données non étiquetées", "def": "Data without predefined labels or categories.", "ex": "Unlabelled data can be used in unsupervised learning."}, {"term": "big data", "ipa": "/ˌbɪɡ ˈdeɪtə/", "pron": "big DAY-tuh", "fr": "données massives ; big data", "def": "Extremely large datasets analysed by computers.", "ex": "Big data has made modern AI possible."}, {"term": "data mining", "ipa": "/ˈdeɪtə ˌmaɪnɪŋ/", "pron": "DAY-tuh MY-ning", "fr": "exploration de données", "def": "Finding patterns or information in large datasets.", "ex": "Data mining can reveal hidden trends."}, {"term": "data annotation", "ipa": "/ˈdeɪtə ˌænəˈteɪʃən/", "pron": "DAY-tuh an-uh-TAY-shuhn", "fr": "annotation de données", "def": "The process of labelling data for AI training.", "ex": "Data annotation is often repetitive and underpaid."}, {"term": "data privacy", "ipa": "/ˈdeɪtə ˈprɪvəsi/", "pron": "DAY-tuh PRIV-uh-see", "fr": "confidentialité des données", "def": "Protection of personal data from misuse.", "ex": "AI development must respect data privacy."}, {"term": "personal data", "ipa": "/ˌpɜːsənəl ˈdeɪtə/", "pron": "PUR-suh-nuhl DAY-tuh", "fr": "données personnelles", "def": "Information relating to an identifiable person.", "ex": "Personal data can be misused by AI systems."}, {"term": "sensitive data", "ipa": "/ˌsensɪtɪv ˈdeɪtə/", "pron": "SEN-si-tiv DAY-tuh", "fr": "données sensibles", "def": "Data requiring special protection, such as health or biometric data.", "ex": "Sensitive data must be handled carefully."}, {"term": "biometric data", "ipa": "/ˌbaɪəʊˈmetrɪk ˈdeɪtə/", "pron": "by-oh-MET-rik DAY-tuh", "fr": "données biométriques", "def": "Data based on physical or behavioural traits such as fingerprints or faces.", "ex": "Facial recognition relies on biometric data."}, {"term": "data scraping", "ipa": "/ˈdeɪtə ˌskreɪpɪŋ/", "pron": "DAY-tuh SKRAY-ping", "fr": "extraction automatisée de données", "def": "Automatically collecting data from websites or platforms.", "ex": "Data scraping raises copyright and privacy questions."}, {"term": "web scraping", "ipa": "/ˈweb ˌskreɪpɪŋ/", "pron": "web SKRAY-ping", "fr": "scraping web", "def": "Automatically extracting information from websites.", "ex": "Web scraping can be used to train AI models."}, {"term": "prompt", "ipa": "/prɒmpt/", "pron": "prompt", "fr": "prompt ; consigne", "def": "An instruction or input given to an AI system.", "ex": "A clear prompt often improves the output."}, {"term": "prompt engineering", "ipa": "/ˈprɒmpt ˌendʒɪˈnɪərɪŋ/", "pron": "PROMPT en-ji-NEER-ing", "fr": "ingénierie de prompt", "def": "The practice of designing effective prompts for AI systems.", "ex": "Prompt engineering became a new digital skill."}, {"term": "output", "ipa": "/ˈaʊtpʊt/", "pron": "OWT-put", "fr": "sortie ; résultat", "def": "The result produced by a computer or AI system.", "ex": "AI output should be checked before publication."}, {"term": "input", "ipa": "/ˈɪnpʊt/", "pron": "IN-put", "fr": "entrée ; donnée saisie", "def": "Information entered into a computer or AI system.", "ex": "The quality of the input affects the quality of the output."}, {"term": "hallucination", "ipa": "/həˌluːsɪˈneɪʃən/", "pron": "huh-loo-si-NAY-shuhn", "fr": "hallucination", "def": "A false or fabricated output produced confidently by an AI system.", "ex": "AI hallucination can spread false information."}, {"term": "bias", "ipa": "/ˈbaɪəs/", "pron": "BY-uhs", "fr": "biais", "def": "Unfair preference or prejudice in data, systems or decisions.", "ex": "Bias in AI can reinforce discrimination."}, {"term": "algorithmic bias", "ipa": "/ˌælɡəˈrɪðmɪk ˈbaɪəs/", "pron": "al-guh-RITH-mik BY-uhs", "fr": "biais algorithmique", "def": "Unfair outcomes produced or amplified by algorithms.", "ex": "Algorithmic bias can affect hiring, policing and lending."}, {"term": "fairness", "ipa": "/ˈfeənəs/", "pron": "FAIR-nuhs", "fr": "équité", "def": "The quality of treating people or groups justly.", "ex": "Fairness is difficult to define in AI systems."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity or status.", "ex": "AI tools can reproduce existing discrimination."}, {"term": "transparency", "ipa": "/trænˈspærənsi/", "pron": "tran-SPARR-uhn-see", "fr": "transparence", "def": "Openness about how a system works or makes decisions.", "ex": "Transparency helps users understand AI decisions."}]}, {"title": "C. Ethics, bias, transparency and regulation", "entries": [{"term": "explainability", "ipa": "/ɪkˌspleɪnəˈbɪləti/", "pron": "ik-splay-nuh-BIL-uh-tee", "fr": "explicabilité", "def": "The ability to explain how an AI system reaches a result.", "ex": "Explainability matters in healthcare and justice."}, {"term": "black box", "ipa": "/ˌblæk ˈbɒks/", "pron": "black box", "fr": "boîte noire", "def": "A system whose internal workings are hard to understand.", "ex": "Some AI models operate like a black box."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité", "def": "Responsibility for decisions and consequences.", "ex": "AI accountability is difficult when many actors are involved."}, {"term": "liability", "ipa": "/ˌlaɪəˈbɪləti/", "pron": "ly-uh-BIL-uh-tee", "fr": "responsabilité juridique", "def": "Legal responsibility for harm or damage.", "ex": "Liability becomes complex when autonomous systems cause harm."}, {"term": "human oversight", "ipa": "/ˌhjuːmən ˈəʊvəsaɪt/", "pron": "HYOO-muhn OH-vuh-syte", "fr": "supervision humaine", "def": "Human supervision of automated systems.", "ex": "Human oversight is essential in high-risk AI."}, {"term": "human-in-the-loop", "ipa": "/ˌhjuːmən ɪn ðə ˈluːp/", "pron": "HYOO-muhn in thuh loop", "fr": "humain dans la boucle", "def": "A system where humans remain involved in AI decisions.", "ex": "Human-in-the-loop systems reduce blind automation."}, {"term": "ethical AI", "ipa": "/ˌeθɪkəl ˌeɪ ˈaɪ/", "pron": "ETH-i-kuhl ay-eye", "fr": "IA éthique", "def": "AI designed and used according to ethical principles.", "ex": "Ethical AI should protect rights, fairness and safety."}, {"term": "responsible AI", "ipa": "/rɪˌspɒnsəbəl ˌeɪ ˈaɪ/", "pron": "ri-SPON-suh-buhl ay-eye", "fr": "IA responsable", "def": "AI developed and used in safe, fair and accountable ways.", "ex": "Responsible AI requires technical and legal safeguards."}, {"term": "trustworthy AI", "ipa": "/ˈtrʌstwɜːði ˌeɪ ˈaɪ/", "pron": "TRUST-wur-thee ay-eye", "fr": "IA digne de confiance", "def": "AI that is reliable, transparent, safe and fair.", "ex": "Trustworthy AI is a goal of many regulators."}, {"term": "AI ethics", "ipa": "/ˌeɪ ˈaɪ ˈeθɪks/", "pron": "ay-eye ETH-iks", "fr": "éthique de l’IA", "def": "The study of moral issues raised by artificial intelligence.", "ex": "AI ethics includes privacy, bias, accountability and human dignity."}, {"term": "AI governance", "ipa": "/ˌeɪ ˈaɪ ˈɡʌvənəns/", "pron": "ay-eye GUV-uh-nuhns", "fr": "gouvernance de l’IA", "def": "Rules, institutions and practices governing AI development and use.", "ex": "AI governance must balance innovation and protection."}, {"term": "AI regulation", "ipa": "/ˌeɪ ˈaɪ ˌreɡjʊˈleɪʃən/", "pron": "ay-eye reg-yuh-LAY-shuhn", "fr": "réglementation de l’IA", "def": "Laws and rules controlling AI systems.", "ex": "AI regulation is developing quickly around the world."}, {"term": "risk-based approach", "ipa": "/ˈrɪsk beɪst əˌprəʊtʃ/", "pron": "risk-bayst uh-PROHCH", "fr": "approche fondée sur le risque", "def": "A regulatory approach where stricter rules apply to higher-risk systems.", "ex": "The EU AI Act uses a risk-based approach."}, {"term": "high-risk AI", "ipa": "/ˌhaɪ rɪsk ˌeɪ ˈaɪ/", "pron": "high-risk ay-eye", "fr": "IA à haut risque", "def": "AI systems that may seriously affect rights, safety or opportunities.", "ex": "High-risk AI should face stricter oversight."}, {"term": "AI Act", "ipa": "/ˌeɪ ˈaɪ ækt/", "pron": "ay-eye akt", "fr": "législation sur l’IA", "def": "A law regulating artificial intelligence, especially associated with the EU.", "ex": "The AI Act aims to regulate AI according to risk."}, {"term": "innovation", "ipa": "/ˌɪnəˈveɪʃən/", "pron": "in-uh-VAY-shuhn", "fr": "innovation", "def": "The creation or adoption of new ideas, technologies or methods.", "ex": "AI is presented as a driver of innovation."}, {"term": "technological breakthrough", "ipa": "/ˌteknəˈlɒdʒɪkəl ˈbreɪkθruː/", "pron": "tek-nuh-LOJ-i-kuhl BRAYK-throo", "fr": "percée technologique", "def": "A major technological advance.", "ex": "Generative AI was seen as a technological breakthrough."}, {"term": "disruptive technology", "ipa": "/dɪsˌrʌptɪv tekˈnɒlədʒi/", "pron": "dis-RUP-tiv tek-NOL-uh-jee", "fr": "technologie disruptive", "def": "Technology that radically changes industries, markets or behaviour.", "ex": "AI is a disruptive technology in many sectors."}, {"term": "general-purpose technology", "ipa": "/ˌdʒenərəl ˈpɜːpəs tekˈnɒlədʒi/", "pron": "JEN-uh-ruhl PUR-puhs tek-NOL-uh-jee", "fr": "technologie à usage général", "def": "A technology affecting many sectors and uses.", "ex": "AI may become a general-purpose technology like electricity."}, {"term": "productivity", "ipa": "/ˌprɒdʌkˈtɪvəti/", "pron": "prod-uk-TIV-uh-tee", "fr": "productivité", "def": "Output produced per worker or unit of input.", "ex": "AI could boost productivity if used effectively."}, {"term": "efficiency", "ipa": "/ɪˈfɪʃənsi/", "pron": "i-FISH-uhn-see", "fr": "efficacité", "def": "The ability to produce results with little waste.", "ex": "AI can improve efficiency in routine tasks."}, {"term": "optimisation", "ipa": "/ˌɒptɪmaɪˈzeɪʃən/", "pron": "op-ti-my-ZAY-shuhn", "fr": "optimisation", "def": "Making a system or process as effective as possible.", "ex": "AI supports optimisation in logistics and energy use."}, {"term": "personalisation", "ipa": "/ˌpɜːsənəlaɪˈzeɪʃən/", "pron": "pur-suh-nuh-ly-ZAY-shuhn", "fr": "personnalisation", "def": "Adapting content or services to individual users.", "ex": "AI enables personalisation in education and marketing."}, {"term": "recommendation algorithm", "ipa": "/ˌrekəmenˈdeɪʃən ˈælɡərɪðəm/", "pron": "rek-uh-men-DAY-shuhn AL-guh-rith-uhm", "fr": "algorithme de recommandation", "def": "An algorithm suggesting content, products or information to users.", "ex": "Recommendation algorithms shape online attention."}, {"term": "predictive analytics", "ipa": "/prɪˌdɪktɪv ˌænəˈlɪtɪks/", "pron": "pri-DIK-tiv an-uh-LIT-iks", "fr": "analyse prédictive", "def": "Using data to predict future events or behaviour.", "ex": "Predictive analytics can be useful but intrusive."}]}, {"title": "D. Applications, risks and social impact", "entries": [{"term": "decision-making", "ipa": "/dɪˈsɪʒən ˌmeɪkɪŋ/", "pron": "di-SIZH-uhn MAY-king", "fr": "prise de décision", "def": "The process of choosing between options.", "ex": "AI increasingly supports decision-making."}, {"term": "automated decision-making", "ipa": "/ˈɔːtəmeɪtɪd dɪˈsɪʒən ˌmeɪkɪŋ/", "pron": "AW-tuh-may-tid di-SIZH-uhn MAY-king", "fr": "prise de décision automatisée", "def": "Decisions made by software with limited human input.", "ex": "Automated decision-making can affect access to loans or jobs."}, {"term": "AI-assisted diagnosis", "ipa": "/ˌeɪ ˈaɪ əˌsɪstɪd ˌdaɪəɡˈnəʊsɪs/", "pron": "ay-eye uh-SIS-tid dy-uhg-NOH-sis", "fr": "diagnostic assisté par IA", "def": "Medical diagnosis supported by AI tools.", "ex": "AI-assisted diagnosis can help doctors detect diseases earlier."}, {"term": "personalised medicine", "ipa": "/ˌpɜːsənəlaɪzd ˈmedsən/", "pron": "PUR-suh-nuh-lyzd MED-suhn", "fr": "médecine personnalisée", "def": "Medical treatment adapted to individual patients.", "ex": "AI can support personalised medicine."}, {"term": "drug discovery", "ipa": "/ˈdrʌɡ dɪˌskʌvəri/", "pron": "drug dis-KUV-uh-ree", "fr": "découverte de médicaments", "def": "The process of finding new medicines.", "ex": "AI can accelerate drug discovery."}, {"term": "scientific discovery", "ipa": "/ˌsaɪənˈtɪfɪk dɪˈskʌvəri/", "pron": "sy-uhn-TIF-ik dis-KUV-uh-ree", "fr": "découverte scientifique", "def": "The process of finding new scientific knowledge.", "ex": "AI may speed up scientific discovery."}, {"term": "climate modelling", "ipa": "/ˈklaɪmət ˌmɒdəlɪŋ/", "pron": "KLY-muht MOD-uhl-ing", "fr": "modélisation climatique", "def": "Computer modelling of climate systems.", "ex": "AI can improve climate modelling."}, {"term": "fraud detection", "ipa": "/ˈfrɔːd dɪˌtekʃən/", "pron": "fraud di-TEK-shuhn", "fr": "détection de fraude", "def": "Identifying dishonest or illegal activity.", "ex": "Banks use AI for fraud detection."}, {"term": "cybersecurity", "ipa": "/ˌsaɪbə sɪˈkjʊərəti/", "pron": "SY-buh si-KYOOR-uh-tee", "fr": "cybersécurité", "def": "Protection of computer systems and data.", "ex": "AI can help cybersecurity teams detect attacks."}, {"term": "AI arms race", "ipa": "/ˌeɪ ˈaɪ ˈɑːmz reɪs/", "pron": "ay-eye arms race", "fr": "course à l’IA", "def": "Competition between states or firms to develop powerful AI systems.", "ex": "An AI arms race may encourage risky deployment."}, {"term": "military AI", "ipa": "/ˌmɪlɪtəri ˌeɪ ˈaɪ/", "pron": "MIL-i-tuh-ree ay-eye", "fr": "IA militaire", "def": "AI used for military purposes.", "ex": "Military AI raises serious ethical and security concerns."}, {"term": "autonomous weapon", "ipa": "/ɔːˌtɒnəməs ˈwepən/", "pron": "aw-TON-uh-muhs WEP-uhn", "fr": "arme autonome", "def": "A weapon able to select or attack targets with limited human control.", "ex": "Autonomous weapons raise questions about accountability."}, {"term": "lethal autonomous weapon", "ipa": "/ˌliːθəl ɔːˌtɒnəməs ˈwepən/", "pron": "LEE-thuhl aw-TON-uh-muhs WEP-uhn", "fr": "arme létale autonome", "def": "An autonomous weapon capable of killing people.", "ex": "Many activists call for restrictions on lethal autonomous weapons."}, {"term": "surveillance", "ipa": "/səˈveɪləns/", "pron": "suh-VAY-luhns", "fr": "surveillance", "def": "Monitoring people, places or communications.", "ex": "AI can intensify surveillance."}, {"term": "mass surveillance", "ipa": "/ˌmæs səˈveɪləns/", "pron": "mass suh-VAY-luhns", "fr": "surveillance de masse", "def": "Large-scale monitoring of populations.", "ex": "Mass surveillance threatens privacy and freedom."}, {"term": "predictive policing", "ipa": "/prɪˌdɪktɪv pəˈliːsɪŋ/", "pron": "pri-DIK-tiv puh-LEE-sing", "fr": "police prédictive", "def": "Using data to predict crime or target policing.", "ex": "Predictive policing can reinforce biased policing patterns."}, {"term": "social scoring", "ipa": "/ˌsəʊʃəl ˈskɔːrɪŋ/", "pron": "SOH-shuhl SKOR-ing", "fr": "notation sociale", "def": "Rating people’s behaviour or trustworthiness through data systems.", "ex": "Social scoring raises major civil-liberty concerns."}, {"term": "deepfake", "ipa": "/ˈdiːpfeɪk/", "pron": "DEEP-fayk", "fr": "deepfake ; hypertrucage", "def": "AI-generated fake video, image or audio that appears real.", "ex": "Deepfakes can be used for satire, fraud or disinformation."}, {"term": "synthetic media", "ipa": "/sɪnˌθetɪk ˈmiːdiə/", "pron": "sin-THET-ik MEE-dee-uh", "fr": "médias synthétiques", "def": "Media created or altered by AI.", "ex": "Synthetic media makes verification harder."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending harm.", "ex": "AI can make misinformation easier to produce."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to mislead.", "ex": "AI-generated disinformation can spread quickly online."}, {"term": "copyright", "ipa": "/ˈkɒpiraɪt/", "pron": "KOP-ee-ryt", "fr": "droit d’auteur", "def": "Legal protection for creative works.", "ex": "AI training and outputs raise copyright disputes."}, {"term": "intellectual property", "ipa": "/ˌɪntəˈlektʃuəl ˈprɒpəti/", "pron": "IN-tuh-LEK-choo-uhl PROP-uh-tee", "fr": "propriété intellectuelle", "def": "Legal rights over inventions, creative works or brands.", "ex": "Intellectual property rules are being tested by AI."}, {"term": "plagiarism", "ipa": "/ˈpleɪdʒərɪzəm/", "pron": "PLAY-juh-riz-uhm", "fr": "plagiat", "def": "Presenting someone else’s work as one’s own.", "ex": "AI misuse can lead to plagiarism in education."}, {"term": "academic integrity", "ipa": "/ˌækəˈdemɪk ɪnˈteɡrəti/", "pron": "ak-uh-DEM-ik in-TEG-ruh-tee", "fr": "intégrité académique", "def": "Honesty and responsibility in academic work.", "ex": "Academic integrity policies must adapt to AI."}, {"term": "automation bias", "ipa": "/ˌɔːtəˈmeɪʃən ˈbaɪəs/", "pron": "aw-tuh-MAY-shuhn BY-uhs", "fr": "biais d’automatisation", "def": "The tendency to overtrust automated systems.", "ex": "Automation bias can make professionals ignore errors."}, {"term": "deskilling", "ipa": "/ˌdiːˈskɪlɪŋ/", "pron": "dee-SKIL-ing", "fr": "déqualification ; perte de compétences", "def": "Loss of skills because technology performs tasks instead.", "ex": "Overreliance on AI may lead to deskilling."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "The gap between those with and without digital access or skills.", "ex": "AI may deepen the digital divide."}, {"term": "AI divide", "ipa": "/ˌeɪ ˈaɪ dɪˈvaɪd/", "pron": "ay-eye di-VYDE", "fr": "fracture de l’IA", "def": "The gap between those able to benefit from AI and those left behind.", "ex": "The AI divide may widen global inequality."}, {"term": "technological unemployment", "ipa": "/ˌteknəˌlɒdʒɪkəl ˌʌnɪmˈplɔɪmənt/", "pron": "tek-nuh-LOJ-i-kuhl un-im-PLOY-muhnt", "fr": "chômage technologique", "def": "Unemployment caused by technology replacing workers.", "ex": "Technological unemployment is a recurring fear."}, {"term": "job displacement", "ipa": "/ˈdʒɒb dɪsˌpleɪsmənt/", "pron": "job dis-PLAYS-muhnt", "fr": "déplacement / destruction d’emplois", "def": "Workers losing jobs because of economic or technological change.", "ex": "AI may cause job displacement in routine office work."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion", "def": "Training workers for new jobs or tasks.", "ex": "Reskilling is essential in an AI-driven economy."}, {"term": "upskilling", "ipa": "/ˌʌpˈskɪlɪŋ/", "pron": "up-SKIL-ing", "fr": "montée en compétences", "def": "Improving existing skills to adapt to new demands.", "ex": "Workers need upskilling to use AI effectively."}, {"term": "AI literacy", "ipa": "/ˌeɪ ˈaɪ ˈlɪtərəsi/", "pron": "ay-eye LIT-uh-ruh-see", "fr": "culture de l’IA ; maîtrise de l’IA", "def": "The ability to understand and use AI critically.", "ex": "AI literacy should be taught in schools."}, {"term": "digital literacy", "ipa": "/ˌdɪdʒɪtəl ˈlɪtərəsi/", "pron": "DIJ-i-tuhl LIT-uh-ruh-see", "fr": "culture numérique", "def": "The ability to use digital tools critically and effectively.", "ex": "Digital literacy helps users evaluate AI outputs."}, {"term": "critical thinking", "ipa": "/ˌkrɪtɪkəl ˈθɪŋkɪŋ/", "pron": "KRIT-i-kuhl THINK-ing", "fr": "esprit critique", "def": "The ability to analyse information carefully and independently.", "ex": "Critical thinking is essential when using AI."}, {"term": "AI safety", "ipa": "/ˌeɪ ˈaɪ ˈseɪfti/", "pron": "ay-eye SAYF-tee", "fr": "sécurité de l’IA", "def": "Research and practice aimed at preventing harmful AI behaviour.", "ex": "AI safety focuses on reducing risks from powerful systems."}, {"term": "AI alignment", "ipa": "/ˌeɪ ˈaɪ əˈlaɪnmənt/", "pron": "ay-eye uh-LYNE-muhnt", "fr": "alignement de l’IA", "def": "Making AI systems behave according to human goals and values.", "ex": "AI alignment is difficult for highly capable systems."}, {"term": "existential risk", "ipa": "/ˌeɡzɪˈstenʃəl rɪsk/", "pron": "eg-zi-STEN-shuhl risk", "fr": "risque existentiel", "def": "A risk threatening humanity’s long-term survival or future.", "ex": "Some researchers worry about existential risk from advanced AI."}, {"term": "superintelligence", "ipa": "/ˌsuːpərɪnˈtelɪdʒəns/", "pron": "SOO-puh-rin-TEL-i-juhns", "fr": "superintelligence", "def": "Hypothetical AI far more intelligent than humans in many domains.", "ex": "Superintelligence remains speculative but influential in AI debates."}, {"term": "artificial general intelligence", "ipa": "/ˌɑːtɪˈfɪʃəl ˌdʒenərəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl JEN-uh-ruhl in-TEL-i-juhns", "fr": "intelligence artificielle générale", "def": "Hypothetical AI able to perform a wide range of intellectual tasks like or beyond humans.", "ex": "Artificial general intelligence is often abbreviated as AGI."}, {"term": "AGI", "ipa": "/ˌeɪ dʒiː ˈaɪ/", "pron": "ay-jee-eye", "fr": "IAG ; intelligence artificielle générale", "def": "Abbreviation for artificial general intelligence.", "ex": "AGI is still a contested and uncertain concept."}, {"term": "open-source AI", "ipa": "/ˌəʊpən sɔːs ˌeɪ ˈaɪ/", "pron": "OH-puhn source ay-eye", "fr": "IA open source", "def": "AI whose code or model components are publicly available.", "ex": "Open-source AI can encourage innovation but raise misuse risks."}, {"term": "closed-source AI", "ipa": "/ˌkləʊzd sɔːs ˌeɪ ˈaɪ/", "pron": "klohz-d source ay-eye", "fr": "IA propriétaire ; IA à code fermé", "def": "AI whose code or model details are not publicly available.", "ex": "Closed-source AI may be easier to control but less transparent."}, {"term": "foundation model", "ipa": "/faʊnˈdeɪʃən ˈmɒdəl/", "pron": "fown-DAY-shuhn MOD-uhl", "fr": "modèle de fondation", "def": "A large AI model adaptable to many tasks.", "ex": "Foundation models can be used in many applications."}, {"term": "multimodal AI", "ipa": "/ˌmʌltiˈməʊdəl ˌeɪ ˈaɪ/", "pron": "MUL-tee-MOH-duhl ay-eye", "fr": "IA multimodale", "def": "AI able to process multiple types of input, such as text, image and audio.", "ex": "Multimodal AI can analyse images and generate text."}]}, {"title": "E. Infrastructure, environment and high-value verbs", "entries": [{"term": "edge AI", "ipa": "/ˌedʒ eɪ ˈaɪ/", "pron": "edge ay-eye", "fr": "IA en périphérie", "def": "AI running locally on devices rather than in remote data centres.", "ex": "Edge AI can reduce latency and improve privacy."}, {"term": "cloud computing", "ipa": "/ˌklaʊd kəmˈpjuːtɪŋ/", "pron": "klowd kuhm-PYOO-ting", "fr": "informatique en nuage ; cloud", "def": "Computing services provided through remote servers.", "ex": "Cloud computing supports large AI models."}, {"term": "data centre", "ipa": "/ˈdeɪtə ˌsentə/", "pron": "DAY-tuh SEN-tuh", "fr": "centre de données", "def": "A facility containing servers and computing infrastructure.", "ex": "AI increases demand for data centres."}, {"term": "computing power", "ipa": "/kəmˈpjuːtɪŋ ˈpaʊə/", "pron": "kuhm-PYOO-ting POW-uh", "fr": "puissance de calcul", "def": "The processing capacity needed to run calculations.", "ex": "Advanced AI requires huge computing power."}, {"term": "chip", "ipa": "/tʃɪp/", "pron": "chip", "fr": "puce électronique", "def": "A small electronic component used for computing.", "ex": "AI depends on advanced chips."}, {"term": "semiconductor", "ipa": "/ˌsemikənˈdʌktə/", "pron": "SEM-ee-kuhn-DUK-tuh", "fr": "semi-conducteur", "def": "A material or device used in computer chips and electronics.", "ex": "Semiconductors are strategic for AI development."}, {"term": "GPU", "ipa": "/ˌdʒiː piː ˈjuː/", "pron": "jee-pee-yoo", "fr": "GPU ; processeur graphique", "def": "Graphics processing unit, a chip often used for AI computing.", "ex": "GPUs are essential for training many AI models."}, {"term": "energy consumption", "ipa": "/ˈenədʒi kənˌsʌmpʃən/", "pron": "EN-uh-jee kuhn-SUMP-shuhn", "fr": "consommation d’énergie", "def": "The amount of energy used.", "ex": "AI data centres raise concerns about energy consumption."}, {"term": "carbon footprint", "ipa": "/ˌkɑːbən ˈfʊtprɪnt/", "pron": "KAR-buhn FOOT-print", "fr": "empreinte carbone", "def": "Greenhouse gas emissions caused by an activity or product.", "ex": "Training large AI models can have a significant carbon footprint."}, {"term": "to train a model", "ipa": "/treɪn ə ˈmɒdəl/", "pron": "trayn uh MOD-uhl", "fr": "entraîner un modèle", "def": "To teach an AI model using data.", "ex": "Engineers train a model on large datasets."}, {"term": "to fine-tune a model", "ipa": "/ˌfaɪn ˈtjuːn ə ˈmɒdəl/", "pron": "fine-TYOON uh MOD-uhl", "fr": "affiner un modèle", "def": "To adapt a trained model to a specific task or domain.", "ex": "A model can be fine-tuned for medical documents."}, {"term": "to generate content", "ipa": "/ˈdʒenəreɪt ˈkɒntent/", "pron": "JEN-uh-rayt KON-tent", "fr": "générer du contenu", "def": "To create text, images, audio or other material.", "ex": "Generative AI can generate content in seconds."}, {"term": "to automate tasks", "ipa": "/ˈɔːtəmeɪt tɑːsks/", "pron": "AW-tuh-mayt tasks", "fr": "automatiser des tâches", "def": "To make tasks performed by machines or software.", "ex": "AI can automate tasks such as sorting emails."}, {"term": "to augment human intelligence", "ipa": "/ɔːɡˈment ˌhjuːmən ɪnˈtelɪdʒəns/", "pron": "awg-MENT HYOO-muhn in-TEL-i-juhns", "fr": "augmenter l’intelligence humaine", "def": "To enhance human thinking with AI tools.", "ex": "AI should augment human intelligence rather than replace judgement."}, {"term": "to replace human labour", "ipa": "/rɪˈpleɪs ˌhjuːmən ˈleɪbə/", "pron": "ri-PLAYS HYOO-muhn LAY-buh", "fr": "remplacer le travail humain", "def": "To substitute technology for human workers.", "ex": "Automation may replace human labour in some tasks."}, {"term": "to detect bias", "ipa": "/dɪˈtekt ˈbaɪəs/", "pron": "di-TEKT BY-uhs", "fr": "détecter les biais", "def": "To identify unfair patterns in a system.", "ex": "Audits can help detect bias."}, {"term": "to mitigate risks", "ipa": "/ˈmɪtɪɡeɪt rɪsks/", "pron": "MIT-i-gayt risks", "fr": "atténuer les risques", "def": "To reduce the likelihood or impact of risks.", "ex": "Regulation aims to mitigate risks."}, {"term": "to ensure transparency", "ipa": "/ɪnˈʃɔː trænsˈpærənsi/", "pron": "in-SHOR tran-SPARR-uhn-see", "fr": "garantir la transparence", "def": "To make a system or process open and understandable.", "ex": "AI governance should ensure transparency."}, {"term": "to protect privacy", "ipa": "/prəˈtekt ˈprɪvəsi/", "pron": "pruh-TEKT PRIV-uh-see", "fr": "protéger la vie privée", "def": "To safeguard personal information and private life.", "ex": "Developers must protect privacy when using personal data."}, {"term": "to regulate AI", "ipa": "/ˈreɡjʊleɪt ˌeɪ ˈaɪ/", "pron": "REG-yuh-layt ay-eye", "fr": "réglementer l’IA", "def": "To create rules controlling AI development and use.", "ex": "Governments are trying to regulate AI."}, {"term": "to hold developers accountable", "ipa": "/həʊld dɪˈveləpəz əˈkaʊntəbəl/", "pron": "hohld di-VEL-uh-puhz uh-KOWN-tuh-buhl", "fr": "tenir les développeurs responsables", "def": "To make developers responsible for harms or failures.", "ex": "Lawmakers want to hold developers accountable."}, {"term": "to verify AI outputs", "ipa": "/ˈverɪfaɪ ˌeɪ ˈaɪ ˈaʊtpʊts/", "pron": "VERR-i-fy ay-eye OWT-puts", "fr": "vérifier les résultats de l’IA", "def": "To check whether AI results are accurate and reliable.", "ex": "Students must verify AI outputs."}, {"term": "to rely blindly on AI", "ipa": "/rɪˈlaɪ ˈblaɪndli ɒn ˌeɪ ˈaɪ/", "pron": "ri-LY BLYND-lee on ay-eye", "fr": "faire aveuglément confiance à l’IA", "def": "To trust AI without critical checking.", "ex": "It is dangerous to rely blindly on AI."}, {"term": "to balance innovation and safety", "ipa": "/ˈbæləns ˌɪnəˈveɪʃən ənd ˈseɪfti/", "pron": "BAL-uhns in-uh-VAY-shuhn and SAYF-tee", "fr": "équilibrer innovation et sécurité", "def": "To encourage progress while reducing harm.", "ex": "AI policy must balance innovation and safety."}]}]}, {"id": "p7c60", "part": 7, "chapter": 60, "title": "Social Media", "file": "cpge_vocab_part7_chapter60_social_media_premium.html", "count": 164, "sections": [{"title": "A. Core social media vocabulary", "entries": [{"term": "social media", "ipa": "/ˌsəʊʃəl ˈmiːdiə/", "pron": "SOH-shuhl MEE-dee-uh", "fr": "réseaux sociaux", "def": "Websites and apps that allow users to create, share and interact with content.", "ex": "Social media has transformed communication, politics and journalism."}, {"term": "social network", "ipa": "/ˌsəʊʃəl ˈnetwɜːk/", "pron": "SOH-shuhl NET-work", "fr": "réseau social", "def": "An online platform connecting users through profiles, posts and interactions.", "ex": "A social network can spread information faster than traditional media."}, {"term": "platform", "ipa": "/ˈplætfɔːm/", "pron": "PLAT-form", "fr": "plateforme", "def": "A digital service that connects users, content, advertisers or businesses.", "ex": "Platforms shape what users see and how they interact."}, {"term": "digital platform", "ipa": "/ˌdɪdʒɪtəl ˈplætfɔːm/", "pron": "DIJ-i-tuhl PLAT-form", "fr": "plateforme numérique", "def": "An online system enabling communication, exchange or content distribution.", "ex": "Digital platforms have become powerful economic and political actors."}, {"term": "online platform", "ipa": "/ˌɒnlaɪn ˈplætfɔːm/", "pron": "ON-line PLAT-form", "fr": "plateforme en ligne", "def": "A platform accessed through the internet.", "ex": "Online platforms are central to public debate."}, {"term": "user", "ipa": "/ˈjuːzə/", "pron": "YOO-zuh", "fr": "utilisateur", "def": "A person who uses a digital service or platform.", "ex": "Users produce much of the content on social media."}, {"term": "account", "ipa": "/əˈkaʊnt/", "pron": "uh-KOWNT", "fr": "compte", "def": "A user profile on a digital platform.", "ex": "A fake account can be used to spread propaganda."}, {"term": "profile", "ipa": "/ˈprəʊfaɪl/", "pron": "PROH-fyle", "fr": "profil", "def": "A page or account representing a user online.", "ex": "A profile can reveal personal information."}, {"term": "feed", "ipa": "/fiːd/", "pron": "feed", "fr": "fil d’actualité", "def": "The stream of posts or content shown to a user.", "ex": "The feed is often organised by algorithms."}, {"term": "timeline", "ipa": "/ˈtaɪmlaɪn/", "pron": "TYME-line", "fr": "fil ; timeline", "def": "A chronological or algorithmic stream of posts.", "ex": "A user’s timeline can become politically polarised."}, {"term": "post", "ipa": "/pəʊst/", "pron": "pohst", "fr": "publication ; post", "def": "A piece of content shared online.", "ex": "A post can go viral within hours."}, {"term": "tweet", "ipa": "/twiːt/", "pron": "tweet", "fr": "tweet", "def": "A short post on X, formerly Twitter.", "ex": "A controversial tweet can trigger a public backlash."}, {"term": "thread", "ipa": "/θred/", "pron": "thread", "fr": "fil de discussion", "def": "A connected series of posts or comments.", "ex": "A thread can explain a complex issue."}, {"term": "comment", "ipa": "/ˈkɒment/", "pron": "KOM-ent", "fr": "commentaire", "def": "A written response to online content.", "ex": "Comments can encourage debate or harassment."}, {"term": "like", "ipa": "/laɪk/", "pron": "like", "fr": "like ; j’aime", "def": "A button showing approval or interest in online content.", "ex": "Likes can reward emotional or extreme content."}, {"term": "share", "ipa": "/ʃeə/", "pron": "share", "fr": "partage", "def": "A repost or act of distributing content to others.", "ex": "Shares help content spread quickly."}, {"term": "repost", "ipa": "/ˌriːˈpəʊst/", "pron": "ree-POHST", "fr": "republication ; repost", "def": "To share someone else’s content again.", "ex": "A repost can amplify misinformation."}, {"term": "hashtag", "ipa": "/ˈhæʃtæɡ/", "pron": "HASH-tag", "fr": "hashtag ; mot-dièse", "def": "A word or phrase preceded by # to group online content.", "ex": "A hashtag can organise a political campaign."}, {"term": "trend", "ipa": "/trend/", "pron": "trend", "fr": "tendance", "def": "A topic or hashtag that becomes popular online.", "ex": "A trend can influence news coverage."}, {"term": "viral", "ipa": "/ˈvaɪrəl/", "pron": "VY-ruhl", "fr": "viral", "def": "Spreading very quickly online.", "ex": "A viral video can shape public opinion."}, {"term": "virality", "ipa": "/vaɪˈræləti/", "pron": "vy-RAL-uh-tee", "fr": "viralisation", "def": "The quality of spreading rapidly online.", "ex": "Virality rewards content that triggers strong emotions."}, {"term": "meme", "ipa": "/miːm/", "pron": "meem", "fr": "mème", "def": "A humorous or symbolic image, video or phrase spread online.", "ex": "Memes can carry political messages."}, {"term": "GIF", "ipa": "/ɡɪf/", "pron": "gif", "fr": "GIF", "def": "A short looping animated image.", "ex": "GIFs are used to react quickly online."}, {"term": "short-form video", "ipa": "/ˌʃɔːt fɔːm ˈvɪdiəʊ/", "pron": "short-form VID-ee-oh", "fr": "vidéo courte", "def": "A brief video designed for quick consumption online.", "ex": "Short-form video dominates many social platforms."}, {"term": "livestream", "ipa": "/ˈlaɪvstriːm/", "pron": "LYVE-stream", "fr": "diffusion en direct", "def": "A live video broadcast online.", "ex": "A livestream can bypass traditional media."}, {"term": "influencer", "ipa": "/ˈɪnfluənsə/", "pron": "IN-floo-uhn-suh", "fr": "influenceur ; influenceuse", "def": "A person who shapes audiences’ opinions or purchases online.", "ex": "Influencers can affect politics, fashion and consumer behaviour."}, {"term": "content creator", "ipa": "/ˈkɒntent kriˌeɪtə/", "pron": "KON-tent kree-AY-tuh", "fr": "créateur de contenu", "def": "A person who produces online content for an audience.", "ex": "Content creators can build large communities."}, {"term": "follower", "ipa": "/ˈfɒləʊə/", "pron": "FOL-oh-uh", "fr": "abonné", "def": "A person who subscribes to another user’s updates.", "ex": "A large number of followers can create influence."}, {"term": "subscriber", "ipa": "/səbˈskraɪbə/", "pron": "suhb-SKRY-buh", "fr": "abonné", "def": "A person who signs up to receive content from a channel or creator.", "ex": "Subscribers can support creators financially."}, {"term": "audience", "ipa": "/ˈɔːdiəns/", "pron": "AW-dee-uhns", "fr": "public ; audience", "def": "The people who consume or follow content.", "ex": "Online audiences are fragmented and highly targeted."}, {"term": "engagement", "ipa": "/ɪnˈɡeɪdʒmənt/", "pron": "in-GAYJ-muhnt", "fr": "engagement", "def": "User interaction with content, such as likes, comments and shares.", "ex": "Platforms optimise for engagement."}, {"term": "reach", "ipa": "/riːtʃ/", "pron": "reech", "fr": "portée", "def": "The number of people who see content.", "ex": "A platform’s reach gives it political influence."}, {"term": "impression", "ipa": "/ɪmˈpreʃən/", "pron": "im-PRESH-uhn", "fr": "impression ; affichage", "def": "A single display of online content to a user.", "ex": "Advertisers pay for impressions."}, {"term": "algorithm", "ipa": "/ˈælɡərɪðəm/", "pron": "AL-guh-rith-uhm", "fr": "algorithme", "def": "A set of rules used by a computer to rank, recommend or filter content.", "ex": "Algorithms decide which posts users are likely to see."}, {"term": "recommendation algorithm", "ipa": "/ˌrekəmenˈdeɪʃən ˈælɡərɪðəm/", "pron": "rek-uh-men-DAY-shuhn AL-guh-rith-uhm", "fr": "algorithme de recommandation", "def": "An algorithm that suggests content to users.", "ex": "Recommendation algorithms can push users towards extreme content."}]}, {"title": "B. Algorithms, moderation and information disorder", "entries": [{"term": "algorithmic ranking", "ipa": "/ˌælɡəˈrɪðmɪk ˈræŋkɪŋ/", "pron": "al-guh-RITH-mik RANG-king", "fr": "classement algorithmique", "def": "The ordering of content by algorithms rather than chronology.", "ex": "Algorithmic ranking shapes public attention."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération de contenu", "def": "The process of reviewing, removing or limiting online content.", "ex": "Content moderation raises questions about free speech."}, {"term": "moderator", "ipa": "/ˈmɒdəreɪtə/", "pron": "MOD-uh-ray-tuh", "fr": "modérateur", "def": "A person or system that reviews online content or behaviour.", "ex": "Moderators are exposed to disturbing content."}, {"term": "community guidelines", "ipa": "/kəˌmjuːnəti ˈɡaɪdlaɪnz/", "pron": "kuh-MYOO-nuh-tee GYDE-lynz", "fr": "règles de la communauté", "def": "Rules defining acceptable behaviour on a platform.", "ex": "Users can be banned for violating community guidelines."}, {"term": "terms of service", "ipa": "/ˌtɜːmz əv ˈsɜːvɪs/", "pron": "terms ov SUR-vis", "fr": "conditions d’utilisation", "def": "The legal rules users accept when using a platform.", "ex": "Terms of service are often long and difficult to understand."}, {"term": "ban", "ipa": "/bæn/", "pron": "ban", "fr": "interdiction ; bannissement", "def": "A decision preventing a user from using a platform or service.", "ex": "A ban can be temporary or permanent."}, {"term": "shadow ban", "ipa": "/ˈʃædəʊ bæn/", "pron": "SHAD-oh ban", "fr": "shadow ban ; bannissement invisible", "def": "A hidden reduction in a user’s visibility on a platform.", "ex": "Users often suspect a shadow ban when engagement falls."}, {"term": "deplatforming", "ipa": "/ˌdiːˈplætfɔːmɪŋ/", "pron": "dee-PLAT-form-ing", "fr": "déplateformisation", "def": "Removing someone’s access to major online platforms.", "ex": "Deplatforming can limit extremist reach but raises free-speech concerns."}, {"term": "account suspension", "ipa": "/əˈkaʊnt səˌspenʃən/", "pron": "uh-KOWNT suh-SPEN-shuhn", "fr": "suspension de compte", "def": "Temporary or permanent disabling of a user account.", "ex": "Account suspension can follow repeated rule violations."}, {"term": "fact-checking", "ipa": "/ˈfækt ˌtʃekɪŋ/", "pron": "FAKT-chek-ing", "fr": "vérification des faits", "def": "Verifying whether claims are accurate.", "ex": "Fact-checking can slow the spread of false claims."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending harm.", "ex": "Misinformation can spread during elections or crises."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately to mislead.", "ex": "Disinformation campaigns can undermine trust."}, {"term": "fake news", "ipa": "/ˌfeɪk ˈnjuːz/", "pron": "fake news", "fr": "fausses informations ; fake news", "def": "False or misleading information presented as news.", "ex": "Fake news spreads easily on social media."}, {"term": "rumour", "ipa": "/ˈruːmə/", "pron": "ROO-muh", "fr": "rumeur", "def": "Unverified information passed from person to person.", "ex": "A rumour can become viral before it is checked."}, {"term": "conspiracy theory", "ipa": "/kənˈspɪrəsi ˈθɪəri/", "pron": "kuhn-SPIR-uh-see THEER-ee", "fr": "théorie du complot", "def": "A belief that hidden groups secretly control events, often without evidence.", "ex": "Conspiracy theories thrive in distrustful environments."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Biased or misleading information used to promote a political cause.", "ex": "Propaganda can be disguised as ordinary content."}, {"term": "information disorder", "ipa": "/ˌɪnfəˈmeɪʃən dɪsˈɔːdə/", "pron": "in-fuh-MAY-shuhn dis-OR-duh", "fr": "désordre informationnel", "def": "A broad term for misinformation, disinformation and harmful information flows.", "ex": "Information disorder makes public debate harder."}, {"term": "echo chamber", "ipa": "/ˈekəʊ ˌtʃeɪmbə/", "pron": "EK-oh CHAYM-buh", "fr": "chambre d’écho", "def": "An environment where people mainly encounter views similar to their own.", "ex": "Echo chambers can reinforce political beliefs."}, {"term": "filter bubble", "ipa": "/ˈfɪltə ˌbʌbəl/", "pron": "FIL-tuh BUB-uhl", "fr": "bulle de filtres", "def": "A personalised information environment shaped by algorithms.", "ex": "A filter bubble can narrow exposure to opposing views."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "The division of society into opposing hostile groups.", "ex": "Social media may intensify polarisation."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "The process of adopting extreme views, sometimes leading to violence.", "ex": "Online communities can accelerate radicalisation."}, {"term": "online extremism", "ipa": "/ˌɒnlaɪn ɪkˈstriːmɪzəm/", "pron": "ON-line ik-STREEM-iz-uhm", "fr": "extrémisme en ligne", "def": "Extremist ideology or activity spread through the internet.", "ex": "Online extremism poses challenges for platforms and governments."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity such as race, religion or gender.", "ex": "Hate speech can normalise discrimination."}, {"term": "harassment", "ipa": "/ˈhærəsmənt/", "pron": "HARR-uhs-muhnt", "fr": "harcèlement", "def": "Repeated abusive or threatening behaviour.", "ex": "Online harassment can silence journalists and activists."}, {"term": "cyberbullying", "ipa": "/ˈsaɪbəˌbʊliɪŋ/", "pron": "SY-buh-BULL-ee-ing", "fr": "cyberharcèlement", "def": "Bullying carried out through digital tools or platforms.", "ex": "Cyberbullying can seriously affect teenagers’ mental health."}, {"term": "trolling", "ipa": "/ˈtrəʊlɪŋ/", "pron": "TROHL-ing", "fr": "trolling ; provocation en ligne", "def": "Posting inflammatory content to provoke or upset people.", "ex": "Trolling can derail online discussions."}, {"term": "pile-on", "ipa": "/ˈpaɪl ɒn/", "pron": "PYLE-on", "fr": "déferlement de critiques ; meute numérique", "def": "A wave of online attacks or criticism by many users.", "ex": "A pile-on can become psychologically overwhelming."}, {"term": "cancel culture", "ipa": "/ˈkænsəl ˌkʌltʃə/", "pron": "KAN-suhl KUL-chuh", "fr": "cancel culture ; culture de l’annulation", "def": "Public shaming or boycotting of people for perceived wrongdoing.", "ex": "Cancel culture is debated as accountability or mob justice."}, {"term": "public shaming", "ipa": "/ˌpʌblɪk ˈʃeɪmɪŋ/", "pron": "PUB-lik SHAY-ming", "fr": "humiliation publique", "def": "Publicly humiliating someone for their behaviour or views.", "ex": "Public shaming can be disproportionate online."}, {"term": "doxxing", "ipa": "/ˈdɒksɪŋ/", "pron": "DOKS-ing", "fr": "doxxing", "def": "Publishing someone’s private information online without consent.", "ex": "Doxxing can endanger people in real life."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "Protection of personal life and information.", "ex": "Privacy is difficult to preserve on social media."}, {"term": "data privacy", "ipa": "/ˈdeɪtə ˈprɪvəsi/", "pron": "DAY-tuh PRIV-uh-see", "fr": "confidentialité des données", "def": "Protection of personal data from misuse.", "ex": "Data privacy is central to platform regulation."}, {"term": "personal data", "ipa": "/ˌpɜːsənəl ˈdeɪtə/", "pron": "PUR-suh-nuhl DAY-tuh", "fr": "données personnelles", "def": "Information relating to an identifiable person.", "ex": "Platforms collect huge amounts of personal data."}, {"term": "data collection", "ipa": "/ˈdeɪtə kəˌlekʃən/", "pron": "DAY-tuh kuh-LEK-shuhn", "fr": "collecte de données", "def": "The gathering of user information.", "ex": "Data collection powers targeted advertising."}, {"term": "data harvesting", "ipa": "/ˈdeɪtə ˌhɑːvɪstɪŋ/", "pron": "DAY-tuh HAR-vis-ting", "fr": "collecte massive de données", "def": "Large-scale collection of personal data, often for commercial or political use.", "ex": "Data harvesting can be opaque and intrusive."}, {"term": "surveillance capitalism", "ipa": "/səˈveɪləns ˈkæpɪtəlɪzəm/", "pron": "suh-VAY-luhns KAP-i-tuhl-iz-uhm", "fr": "capitalisme de surveillance", "def": "An economic model based on collecting and monetising personal data.", "ex": "Surveillance capitalism turns attention and behaviour into profit."}]}, {"title": "C. Privacy, attention economy and mental health", "entries": [{"term": "targeted advertising", "ipa": "/ˈtɑːɡɪtɪd ˈædvətaɪzɪŋ/", "pron": "TAR-git-id AD-vuh-ty-zing", "fr": "publicité ciblée", "def": "Advertising aimed at specific users based on data.", "ex": "Targeted advertising funds many social platforms."}, {"term": "microtargeting", "ipa": "/ˌmaɪkrəʊˈtɑːɡɪtɪŋ/", "pron": "MY-kroh-TAR-git-ing", "fr": "microciblage", "def": "Targeting very specific groups with tailored messages.", "ex": "Political microtargeting can manipulate voters."}, {"term": "behavioural advertising", "ipa": "/bɪˌheɪvjərəl ˈædvətaɪzɪŋ/", "pron": "bi-HAY-vyuh-ruhl AD-vuh-ty-zing", "fr": "publicité comportementale", "def": "Advertising based on users’ online behaviour.", "ex": "Behavioural advertising depends on tracking."}, {"term": "tracking", "ipa": "/ˈtrækɪŋ/", "pron": "TRAK-ing", "fr": "traçage ; suivi", "def": "Monitoring users’ activity across websites or apps.", "ex": "Tracking can happen without users fully understanding it."}, {"term": "cookie", "ipa": "/ˈkʊki/", "pron": "KUUK-ee", "fr": "cookie", "def": "A small file used to store information about a user’s online activity.", "ex": "Cookies are used for tracking and personalisation."}, {"term": "attention economy", "ipa": "/əˈtenʃən iˌkɒnəmi/", "pron": "uh-TEN-shuhn i-KON-uh-mee", "fr": "économie de l’attention", "def": "An economy in which human attention is treated as a scarce resource.", "ex": "Social media platforms compete in the attention economy."}, {"term": "addictive design", "ipa": "/əˈdɪktɪv dɪˈzaɪn/", "pron": "uh-DIK-tiv di-ZYNE", "fr": "design addictif", "def": "Design intended to keep users engaged for as long as possible.", "ex": "Infinite scroll is often criticised as addictive design."}, {"term": "infinite scroll", "ipa": "/ˌɪnfɪnət ˈskrəʊl/", "pron": "IN-fi-nuht skrohl", "fr": "défilement infini", "def": "A design feature that continuously loads content as users scroll.", "ex": "Infinite scroll encourages users to keep browsing."}, {"term": "dopamine loop", "ipa": "/ˈdəʊpəmiːn luːp/", "pron": "DOH-puh-meen loop", "fr": "boucle dopaminergique", "def": "A reward cycle that encourages repeated checking or engagement.", "ex": "Notifications can create a dopamine loop."}, {"term": "notification", "ipa": "/ˌnəʊtɪfɪˈkeɪʃən/", "pron": "noh-ti-fi-KAY-shuhn", "fr": "notification", "def": "An alert from an app or device.", "ex": "Notifications pull users back to platforms."}, {"term": "screen time", "ipa": "/ˈskriːn taɪm/", "pron": "screen time", "fr": "temps d’écran", "def": "Time spent using screens or digital devices.", "ex": "Excessive screen time worries parents and teachers."}, {"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl helth", "fr": "santé mentale", "def": "A person’s psychological and emotional wellbeing.", "ex": "Social media can affect young people’s mental health."}, {"term": "anxiety", "ipa": "/æŋˈzaɪəti/", "pron": "ang-ZY-uh-tee", "fr": "anxiété", "def": "A feeling of worry, fear or nervousness.", "ex": "Online comparison can increase anxiety."}, {"term": "depression", "ipa": "/dɪˈpreʃən/", "pron": "di-PRESH-uhn", "fr": "dépression", "def": "A mental health condition involving persistent sadness and loss of interest.", "ex": "Heavy social media use is sometimes linked to depression."}, {"term": "self-esteem", "ipa": "/ˌself ɪˈstiːm/", "pron": "self i-STEEM", "fr": "estime de soi", "def": "A person’s sense of self-worth.", "ex": "Filtered images can damage self-esteem."}, {"term": "body image", "ipa": "/ˈbɒdi ˌɪmɪdʒ/", "pron": "BOD-ee IM-ij", "fr": "image corporelle", "def": "How a person sees and feels about their body.", "ex": "Social media can worsen body image concerns."}, {"term": "social comparison", "ipa": "/ˌsəʊʃəl kəmˈpærɪsən/", "pron": "SOH-shuhl kuhm-PARR-i-suhn", "fr": "comparaison sociale", "def": "Comparing oneself with others.", "ex": "Social comparison is intensified by curated online lives."}, {"term": "fear of missing out", "ipa": "/ˌfɪər əv ˈmɪsɪŋ aʊt/", "pron": "fear ov MISS-ing out", "fr": "peur de rater quelque chose ; FOMO", "def": "Anxiety that others are having rewarding experiences without you.", "ex": "Fear of missing out keeps users checking their feeds."}, {"term": "FOMO", "ipa": "/ˈfəʊməʊ/", "pron": "FOH-moh", "fr": "FOMO", "def": "Abbreviation for fear of missing out.", "ex": "FOMO is common among teenagers."}, {"term": "digital wellbeing", "ipa": "/ˌdɪdʒɪtəl ˌwelˈbiːɪŋ/", "pron": "DIJ-i-tuhl wel-BEE-ing", "fr": "bien-être numérique", "def": "Healthy and balanced use of digital technology.", "ex": "Digital wellbeing tools can limit screen time."}, {"term": "online identity", "ipa": "/ˌɒnlaɪn aɪˈdentəti/", "pron": "ON-line eye-DEN-tuh-tee", "fr": "identité en ligne", "def": "The identity a person presents online.", "ex": "Online identity can differ from offline life."}, {"term": "digital footprint", "ipa": "/ˌdɪdʒɪtəl ˈfʊtprɪnt/", "pron": "DIJ-i-tuhl FOOT-print", "fr": "empreinte numérique", "def": "The trail of data a person leaves online.", "ex": "A digital footprint can affect future employment."}, {"term": "online reputation", "ipa": "/ˌɒnlaɪn ˌrepjʊˈteɪʃən/", "pron": "ON-line rep-yuh-TAY-shuhn", "fr": "réputation en ligne", "def": "How a person or organisation is perceived online.", "ex": "Online reputation can be difficult to repair."}, {"term": "authenticity", "ipa": "/ˌɔːθenˈtɪsəti/", "pron": "aw-then-TIS-uh-tee", "fr": "authenticité", "def": "The quality of seeming real, honest or genuine.", "ex": "Influencers often perform authenticity."}, {"term": "curated self", "ipa": "/ˌkjʊəreɪtɪd ˈself/", "pron": "KYOO-ray-tid self", "fr": "soi mis en scène", "def": "An edited and selective online version of oneself.", "ex": "The curated self can create pressure to appear perfect."}, {"term": "self-presentation", "ipa": "/ˌself ˌprezənˈteɪʃən/", "pron": "self prez-uhn-TAY-shuhn", "fr": "présentation de soi", "def": "The way people choose to show themselves to others.", "ex": "Social media encourages constant self-presentation."}, {"term": "influencer marketing", "ipa": "/ˈɪnfluənsə ˈmɑːkɪtɪŋ/", "pron": "IN-floo-uhn-suh MAR-kit-ing", "fr": "marketing d’influence", "def": "Marketing products through influencers.", "ex": "Influencer marketing blurs advertising and personal recommendation."}, {"term": "sponsored content", "ipa": "/ˈspɒnsəd ˈkɒntent/", "pron": "SPON-suhd KON-tent", "fr": "contenu sponsorisé", "def": "Content paid for by a brand or organisation.", "ex": "Sponsored content should be clearly labelled."}, {"term": "brand partnership", "ipa": "/ˈbrænd ˌpɑːtnəʃɪp/", "pron": "brand PART-nuh-ship", "fr": "partenariat de marque", "def": "A paid collaboration between a creator and a brand.", "ex": "Brand partnerships are a major income source for influencers."}, {"term": "monetisation", "ipa": "/ˌmʌnɪtaɪˈzeɪʃən/", "pron": "mun-i-ty-ZAY-shuhn", "fr": "monétisation", "def": "Turning content, attention or activity into money.", "ex": "Monetisation encourages creators to post regularly."}, {"term": "creator economy", "ipa": "/kriˌeɪtər iˈkɒnəmi/", "pron": "kree-AY-tuh i-KON-uh-mee", "fr": "économie des créateurs", "def": "The economy of people earning money through online content.", "ex": "The creator economy has produced new careers."}, {"term": "gig work", "ipa": "/ˈɡɪɡ wɜːk/", "pron": "gig work", "fr": "travail à la tâche", "def": "Short-term flexible work, often organised through platforms.", "ex": "Some online creators depend on unstable gig work."}, {"term": "platform economy", "ipa": "/ˈplætfɔːm iˌkɒnəmi/", "pron": "PLAT-form i-KON-uh-mee", "fr": "économie de plateforme", "def": "An economy organised through digital platforms.", "ex": "The platform economy concentrates power in a few companies."}, {"term": "Big Tech", "ipa": "/ˌbɪɡ ˈtek/", "pron": "big tek", "fr": "grandes entreprises technologiques", "def": "Large technology companies with major economic and political power.", "ex": "Big Tech owns many major social platforms."}, {"term": "network effect", "ipa": "/ˈnetwɜːk ɪˌfekt/", "pron": "NET-work i-FEKT", "fr": "effet de réseau", "def": "A situation where a service becomes more valuable as more people use it.", "ex": "Network effects make dominant platforms difficult to challenge."}, {"term": "monopoly power", "ipa": "/məˈnɒpəli ˈpaʊə/", "pron": "muh-NOP-uh-lee POW-uh", "fr": "pouvoir monopolistique", "def": "The power of a dominant company to control a market.", "ex": "Social media giants can develop monopoly power."}, {"term": "platform regulation", "ipa": "/ˈplætfɔːm ˌreɡjʊˈleɪʃən/", "pron": "PLAT-form reg-yuh-LAY-shuhn", "fr": "réglementation des plateformes", "def": "Rules governing online platforms and their responsibilities.", "ex": "Platform regulation is a major political debate."}, {"term": "Digital Services Act", "ipa": "/ˌdɪdʒɪtəl ˈsɜːvɪsɪz ækt/", "pron": "DIJ-i-tuhl SUR-vis-iz akt", "fr": "règlement européen sur les services numériques", "def": "EU law regulating online platforms and digital services.", "ex": "The Digital Services Act increases platform responsibilities."}, {"term": "DSA", "ipa": "/ˌdiː es ˈeɪ/", "pron": "dee-ess-ay", "fr": "DSA ; règlement sur les services numériques", "def": "Abbreviation for Digital Services Act.", "ex": "The DSA targets illegal content and systemic risks."}, {"term": "Digital Markets Act", "ipa": "/ˌdɪdʒɪtəl ˈmɑːkɪts ækt/", "pron": "DIJ-i-tuhl MAR-kits akt", "fr": "règlement européen sur les marchés numériques", "def": "EU law regulating large digital gatekeepers.", "ex": "The Digital Markets Act aims to limit Big Tech gatekeepers."}, {"term": "DMA", "ipa": "/ˌdiː em ˈeɪ/", "pron": "dee-em-ay", "fr": "DMA ; règlement sur les marchés numériques", "def": "Abbreviation for Digital Markets Act.", "ex": "The DMA promotes fairer digital competition."}]}, {"title": "D. Influencers, platform economy and regulation", "entries": [{"term": "gatekeeper", "ipa": "/ˈɡeɪtˌkiːpə/", "pron": "GATE-kee-puh", "fr": "contrôleur d’accès", "def": "A powerful platform controlling access to users or markets.", "ex": "Gatekeepers can privilege their own services."}, {"term": "antitrust", "ipa": "/ˌæntiˈtrʌst/", "pron": "AN-tee-TRUST", "fr": "droit de la concurrence ; antitrust", "def": "Law or policy preventing monopolistic behaviour.", "ex": "Antitrust authorities scrutinise social media mergers."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "The right to express opinions freely.", "ex": "Free speech online is difficult to balance with safety."}, {"term": "freedom of expression", "ipa": "/ˌfriːdəm əv ɪkˈspreʃən/", "pron": "FREE-duhm ov ik-SPRESH-uhn", "fr": "liberté d’expression", "def": "The right to express opinions, ideas and information.", "ex": "Freedom of expression includes unpopular views."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of speech or information.", "ex": "Some users see content moderation as censorship."}, {"term": "platform accountability", "ipa": "/ˈplætfɔːm əˌkaʊntəˈbɪləti/", "pron": "PLAT-form uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des plateformes", "def": "Responsibility of platforms for their rules, systems and harms.", "ex": "Platform accountability is central to regulation."}, {"term": "algorithmic transparency", "ipa": "/ˌælɡəˈrɪðmɪk trænˈspærənsi/", "pron": "al-guh-RITH-mik tran-SPARR-uhn-see", "fr": "transparence algorithmique", "def": "Openness about how algorithms rank or recommend content.", "ex": "Researchers demand more algorithmic transparency."}, {"term": "audit", "ipa": "/ˈɔːdɪt/", "pron": "AW-dit", "fr": "audit", "def": "An independent review of a system, process or organisation.", "ex": "Algorithmic audits can reveal platform risks."}, {"term": "online activism", "ipa": "/ˌɒnlaɪn ˈæktɪvɪzəm/", "pron": "ON-line AK-ti-viz-uhm", "fr": "activisme en ligne", "def": "Political or social activism conducted online.", "ex": "Online activism can mobilise large numbers quickly."}, {"term": "hashtag activism", "ipa": "/ˈhæʃtæɡ ˌæktɪvɪzəm/", "pron": "HASH-tag AK-ti-viz-uhm", "fr": "activisme par hashtag", "def": "Activism organised around hashtags.", "ex": "Hashtag activism can raise awareness but may remain symbolic."}, {"term": "slacktivism", "ipa": "/ˈslæktɪvɪzəm/", "pron": "SLAK-ti-viz-uhm", "fr": "slacktivisme ; militantisme de canapé", "def": "Low-effort online activism with limited real-world impact.", "ex": "Critics dismiss some online campaigns as slacktivism."}, {"term": "digital mobilisation", "ipa": "/ˌdɪdʒɪtəl ˌməʊbɪlaɪˈzeɪʃən/", "pron": "DIJ-i-tuhl moh-bi-ly-ZAY-shuhn", "fr": "mobilisation numérique", "def": "Using digital tools to organise political or social action.", "ex": "Digital mobilisation helped organise protests."}, {"term": "grassroots movement", "ipa": "/ˌɡrɑːsruːts ˈmuːvmənt/", "pron": "grass-roots MOOV-muhnt", "fr": "mouvement de base", "def": "A movement driven by ordinary citizens rather than elites.", "ex": "Social media can amplify grassroots movements."}, {"term": "petition", "ipa": "/pəˈtɪʃən/", "pron": "puh-TISH-uhn", "fr": "pétition", "def": "A formal request signed by many people.", "ex": "Online petitions can pressure governments."}, {"term": "boycott", "ipa": "/ˈbɔɪkɒt/", "pron": "BOY-kot", "fr": "boycott", "def": "A refusal to buy or support something as protest.", "ex": "Social media can spread calls for a boycott."}, {"term": "online campaign", "ipa": "/ˌɒnlaɪn kæmˈpeɪn/", "pron": "ON-line kam-PAYN", "fr": "campagne en ligne", "def": "A coordinated effort to achieve a goal through digital platforms.", "ex": "An online campaign can influence public debate."}, {"term": "political advertising", "ipa": "/pəˌlɪtɪkəl ˈædvətaɪzɪŋ/", "pron": "puh-LIT-i-kuhl AD-vuh-ty-zing", "fr": "publicité politique", "def": "Paid political messaging aimed at voters or publics.", "ex": "Political advertising online can be microtargeted."}, {"term": "election interference", "ipa": "/ɪˈlekʃən ˌɪntəˈfɪərəns/", "pron": "i-LEK-shuhn in-tuh-FEER-uhns", "fr": "ingérence électorale", "def": "Attempts to manipulate or influence another country’s elections.", "ex": "Social media can be used for election interference."}, {"term": "foreign interference", "ipa": "/ˌfɒrən ˌɪntəˈfɪərəns/", "pron": "FOR-uhn in-tuh-FEER-uhns", "fr": "ingérence étrangère", "def": "Improper involvement by a foreign actor in domestic politics.", "ex": "Foreign interference can exploit social media divisions."}, {"term": "bot", "ipa": "/bɒt/", "pron": "bot", "fr": "bot", "def": "An automated account or program online.", "ex": "Bots can amplify political messages."}, {"term": "bot network", "ipa": "/ˈbɒt ˌnetwɜːk/", "pron": "bot NET-work", "fr": "réseau de bots", "def": "A group of automated accounts working together.", "ex": "Bot networks can create false impressions of popularity."}, {"term": "troll farm", "ipa": "/ˈtrɒl fɑːm/", "pron": "troll farm", "fr": "usine à trolls", "def": "An organisation producing manipulative online posts at scale.", "ex": "Troll farms can target foreign elections."}, {"term": "astroturfing", "ipa": "/ˈæstrəʊˌtɜːfɪŋ/", "pron": "AS-troh-TURF-ing", "fr": "faux mouvement citoyen ; astroturfing", "def": "Creating fake grassroots support for a cause.", "ex": "Astroturfing misleads the public about genuine support."}, {"term": "coordinated inauthentic behaviour", "ipa": "/kəʊˌɔːdɪneɪtɪd ˌɪnɔːˈθentɪk bɪˈheɪvjə/", "pron": "koh-OR-di-nay-tid in-aw-THEN-tik bi-HAY-vyuh", "fr": "comportement inauthentique coordonné", "def": "Organised deceptive activity using fake accounts or networks.", "ex": "Platforms remove coordinated inauthentic behaviour."}, {"term": "online journalism", "ipa": "/ˌɒnlaɪn ˈdʒɜːnəlɪzəm/", "pron": "ON-line JUR-nuh-liz-uhm", "fr": "journalisme en ligne", "def": "Journalism produced or distributed through the internet.", "ex": "Online journalism competes with social media influencers."}, {"term": "citizen journalism", "ipa": "/ˌsɪtɪzən ˈdʒɜːnəlɪzəm/", "pron": "SIT-i-zuhn JUR-nuh-liz-uhm", "fr": "journalisme citoyen", "def": "News gathering and reporting by ordinary citizens.", "ex": "Citizen journalism can document events ignored by official media."}, {"term": "legacy media", "ipa": "/ˌleɡəsi ˈmiːdiə/", "pron": "LEG-uh-see MEE-dee-uh", "fr": "médias traditionnels", "def": "Traditional media such as newspapers, television and radio.", "ex": "Legacy media now rely on social platforms for distribution."}, {"term": "news feed", "ipa": "/ˈnjuːz fiːd/", "pron": "news feed", "fr": "fil d’actualité", "def": "A stream of news or posts shown online.", "ex": "A news feed can blur journalism and entertainment."}, {"term": "clickbait", "ipa": "/ˈklɪkbeɪt/", "pron": "KLIK-bayt", "fr": "piège à clics", "def": "Content designed mainly to attract clicks, often with exaggerated headlines.", "ex": "Clickbait can lower the quality of public debate."}, {"term": "headline", "ipa": "/ˈhedlaɪn/", "pron": "HED-line", "fr": "titre", "def": "The title of a news article or post.", "ex": "A misleading headline can spread a false impression."}, {"term": "attention-grabbing", "ipa": "/əˈtenʃən ˌɡræbɪŋ/", "pron": "uh-TEN-shuhn GRAB-ing", "fr": "accrocheur", "def": "Designed to attract attention quickly.", "ex": "Attention-grabbing content is often emotional."}, {"term": "outrage", "ipa": "/ˈaʊtreɪdʒ/", "pron": "OWT-rayj", "fr": "indignation", "def": "Strong anger or shock, often amplified online.", "ex": "Platforms can reward outrage."}, {"term": "outrage economy", "ipa": "/ˈaʊtreɪdʒ iˌkɒnəmi/", "pron": "OWT-rayj i-KON-uh-mee", "fr": "économie de l’indignation", "def": "An online system where anger and conflict generate attention and profit.", "ex": "The outrage economy benefits polarising content."}, {"term": "doomscrolling", "ipa": "/ˈduːmˌskrəʊlɪŋ/", "pron": "DOOM-skrohl-ing", "fr": "défilement anxiogène ; doomscrolling", "def": "Compulsively scrolling through negative news or content.", "ex": "Doomscrolling can worsen anxiety."}]}, {"title": "E. Activism, politics, journalism and high-value verbs", "entries": [{"term": "digital detox", "ipa": "/ˌdɪdʒɪtəl ˈdiːtɒks/", "pron": "DIJ-i-tuhl DEE-toks", "fr": "détox numérique", "def": "A break from digital devices or platforms.", "ex": "A digital detox can help restore attention."}, {"term": "to go viral", "ipa": "/ɡəʊ ˈvaɪrəl/", "pron": "goh VY-ruhl", "fr": "devenir viral", "def": "To spread very quickly online.", "ex": "A video can go viral overnight."}, {"term": "to amplify content", "ipa": "/ˈæmplɪfaɪ ˈkɒntent/", "pron": "AM-pli-fy KON-tent", "fr": "amplifier du contenu", "def": "To increase the visibility or reach of content.", "ex": "Algorithms can amplify content that provokes outrage."}, {"term": "to spread misinformation", "ipa": "/spred ˌmɪsɪnfəˈmeɪʃən/", "pron": "spred mis-in-fuh-MAY-shuhn", "fr": "diffuser de la mésinformation", "def": "To circulate false information.", "ex": "Users may spread misinformation without realising it."}, {"term": "to fact-check a claim", "ipa": "/ˈfækt tʃek ə kleɪm/", "pron": "FAKT-chek uh klaym", "fr": "vérifier une affirmation", "def": "To verify whether a statement is accurate.", "ex": "Journalists fact-check claims before publication."}, {"term": "to moderate content", "ipa": "/ˈmɒdəreɪt ˈkɒntent/", "pron": "MOD-uh-rayt KON-tent", "fr": "modérer du contenu", "def": "To review and manage online content according to rules.", "ex": "Platforms struggle to moderate content at scale."}, {"term": "to remove harmful content", "ipa": "/rɪˈmuːv ˈhɑːmfəl ˈkɒntent/", "pron": "ri-MOOV HARM-fuhl KON-tent", "fr": "supprimer les contenus nuisibles", "def": "To delete or restrict dangerous or abusive content.", "ex": "Regulators want platforms to remove harmful content faster."}, {"term": "to protect free speech", "ipa": "/prəˈtekt ˌfriː ˈspiːtʃ/", "pron": "pruh-TEKT free speech", "fr": "protéger la liberté d’expression", "def": "To defend the right to express opinions.", "ex": "Democracies must protect free speech online."}, {"term": "to regulate platforms", "ipa": "/ˈreɡjʊleɪt ˈplætfɔːmz/", "pron": "REG-yuh-layt PLAT-formz", "fr": "réglementer les plateformes", "def": "To impose rules on digital platforms.", "ex": "Governments are under pressure to regulate platforms."}, {"term": "to collect user data", "ipa": "/kəˈlekt ˈjuːzə ˈdeɪtə/", "pron": "kuh-LEKT YOO-zuh DAY-tuh", "fr": "collecter les données des utilisateurs", "def": "To gather information about platform users.", "ex": "Platforms collect user data for advertising."}, {"term": "to target voters", "ipa": "/ˈtɑːɡɪt ˈvəʊtəz/", "pron": "TAR-git VOH-tuhz", "fr": "cibler les électeurs", "def": "To direct political messages at specific voters.", "ex": "Campaigns use data to target voters."}, {"term": "to manipulate public opinion", "ipa": "/məˈnɪpjʊleɪt ˌpʌblɪk əˈpɪnjən/", "pron": "muh-NIP-yuh-layt PUB-lik uh-PIN-yuhn", "fr": "manipuler l’opinion publique", "def": "To influence public views dishonestly or unfairly.", "ex": "Disinformation campaigns seek to manipulate public opinion."}, {"term": "to foster polarisation", "ipa": "/ˈfɒstə ˌpəʊləraɪˈzeɪʃən/", "pron": "FOS-tuh poh-luh-ry-ZAY-shuhn", "fr": "favoriser la polarisation", "def": "To encourage division between groups.", "ex": "Platform design can foster polarisation."}, {"term": "to raise awareness", "ipa": "/reɪz əˈweənəs/", "pron": "rayz uh-WAIR-nuhs", "fr": "sensibiliser", "def": "To make people more aware of an issue.", "ex": "Online activism can raise awareness quickly."}, {"term": "to mobilise supporters", "ipa": "/ˈməʊbɪlaɪz səˈpɔːtəz/", "pron": "MOH-bi-lyze suh-PORT-uhz", "fr": "mobiliser les soutiens", "def": "To organise people to support a cause.", "ex": "Social media can mobilise supporters for protests."}, {"term": "to hold platforms accountable", "ipa": "/həʊld ˈplætfɔːmz əˈkaʊntəbəl/", "pron": "hohld PLAT-formz uh-KOWN-tuh-buhl", "fr": "tenir les plateformes responsables", "def": "To make platforms responsible for their impact.", "ex": "Civil society wants to hold platforms accountable."}, {"term": "to limit screen time", "ipa": "/ˈlɪmɪt ˈskriːn taɪm/", "pron": "LIM-it screen time", "fr": "limiter le temps d’écran", "def": "To reduce time spent using screens.", "ex": "Parents often try to limit screen time."}, {"term": "to leave a digital footprint", "ipa": "/liːv ə ˌdɪdʒɪtəl ˈfʊtprɪnt/", "pron": "leev uh DIJ-i-tuhl FOOT-print", "fr": "laisser une empreinte numérique", "def": "To create a trail of online data and activity.", "ex": "Every online action can leave a digital footprint."}]}]}, {"id": "p7c61", "part": 7, "chapter": 61, "title": "Big Tech", "file": "cpge_vocab_part7_chapter61_big_tech_premium.html", "count": 197, "sections": [{"title": "A. Core Big Tech, platforms and innovation vocabulary", "entries": [{"term": "Big Tech", "ipa": "/ˌbɪɡ ˈtek/", "pron": "big tek", "fr": "grandes entreprises technologiques ; Big Tech", "def": "The largest and most powerful technology companies, especially those dominating digital markets.", "ex": "Big Tech has become a central political and economic issue."}, {"term": "technology giant", "ipa": "/tekˈnɒlədʒi ˈdʒaɪənt/", "pron": "tek-NOL-uh-jee JY-uhnt", "fr": "géant technologique", "def": "A very large and influential technology company.", "ex": "Technology giants control key digital infrastructure."}, {"term": "tech company", "ipa": "/ˈtek ˌkʌmpəni/", "pron": "tek KUM-puh-nee", "fr": "entreprise technologique", "def": "A company producing or selling technology products or services.", "ex": "Tech companies increasingly shape everyday life."}, {"term": "platform company", "ipa": "/ˈplætfɔːm ˌkʌmpəni/", "pron": "PLAT-form KUM-puh-nee", "fr": "entreprise de plateforme", "def": "A company whose business relies on connecting users, sellers, advertisers or developers through a platform.", "ex": "Platform companies benefit from network effects."}, {"term": "digital platform", "ipa": "/ˌdɪdʒɪtəl ˈplætfɔːm/", "pron": "DIJ-i-tuhl PLAT-form", "fr": "plateforme numérique", "def": "An online system enabling communication, commerce, services or content distribution.", "ex": "Digital platforms organise markets and attention."}, {"term": "online platform", "ipa": "/ˌɒnlaɪn ˈplætfɔːm/", "pron": "ON-line PLAT-form", "fr": "plateforme en ligne", "def": "A digital platform accessed through the internet.", "ex": "Online platforms have become unavoidable intermediaries."}, {"term": "platform economy", "ipa": "/ˈplætfɔːm iˌkɒnəmi/", "pron": "PLAT-form i-KON-uh-mee", "fr": "économie de plateforme", "def": "An economy organised through digital platforms that connect users, workers or businesses.", "ex": "The platform economy changes work, trade and regulation."}, {"term": "digital economy", "ipa": "/ˌdɪdʒɪtəl iˈkɒnəmi/", "pron": "DIJ-i-tuhl i-KON-uh-mee", "fr": "économie numérique", "def": "Economic activity based on digital technologies, data and online services.", "ex": "The digital economy depends on data and connectivity."}, {"term": "tech ecosystem", "ipa": "/ˈtek ˌiːkəʊˌsɪstəm/", "pron": "tek EE-koh-SIS-tuhm", "fr": "écosystème technologique", "def": "A network of companies, investors, developers and users around technology.", "ex": "Silicon Valley is a famous tech ecosystem."}, {"term": "Silicon Valley", "ipa": "/ˌsɪlɪkən ˈvæli/", "pron": "SIL-i-kuhn VAL-ee", "fr": "Silicon Valley", "def": "The California region associated with major technology firms and start-ups.", "ex": "Silicon Valley symbolises innovation and venture capital."}, {"term": "start-up", "ipa": "/ˈstɑːt ʌp/", "pron": "START-up", "fr": "start-up ; jeune pousse", "def": "A young company designed for rapid growth, often in technology.", "ex": "Many Big Tech companies began as start-ups."}, {"term": "scale-up", "ipa": "/ˈskeɪl ʌp/", "pron": "SKAYL-up", "fr": "entreprise en forte croissance", "def": "A company growing rapidly after the start-up stage.", "ex": "A successful start-up can become a scale-up."}, {"term": "unicorn", "ipa": "/ˈjuːnɪkɔːn/", "pron": "YOO-ni-korn", "fr": "licorne", "def": "A privately held start-up valued at over one billion dollars.", "ex": "Unicorns attract major venture capital."}, {"term": "venture capital", "ipa": "/ˈventʃə ˌkæpɪtəl/", "pron": "VEN-chuh KAP-i-tuhl", "fr": "capital-risque", "def": "Investment in high-growth start-ups in exchange for equity.", "ex": "Venture capital fuels the tech industry."}, {"term": "VC", "ipa": "/ˌviː ˈsiː/", "pron": "vee-see", "fr": "capital-risque ; investisseur en capital-risque", "def": "Abbreviation for venture capital or venture capitalist.", "ex": "VC funding can help a platform grow quickly."}, {"term": "founder", "ipa": "/ˈfaʊndə/", "pron": "FOWN-duh", "fr": "fondateur ; fondatrice", "def": "A person who creates a company or organisation.", "ex": "Tech founders often become public figures."}, {"term": "entrepreneur", "ipa": "/ˌɒntrəprəˈnɜː/", "pron": "ON-truh-pruh-NUR", "fr": "entrepreneur", "def": "A person who creates and develops a business.", "ex": "Entrepreneurs are celebrated in start-up culture."}, {"term": "innovation", "ipa": "/ˌɪnəˈveɪʃən/", "pron": "in-uh-VAY-shuhn", "fr": "innovation", "def": "The creation or use of new ideas, technologies or methods.", "ex": "Big Tech presents itself as a driver of innovation."}, {"term": "disruption", "ipa": "/dɪsˈrʌpʃən/", "pron": "dis-RUP-shuhn", "fr": "disruption ; bouleversement", "def": "Radical change to an existing market, industry or practice.", "ex": "Tech companies often promise disruption."}, {"term": "disruptive innovation", "ipa": "/dɪsˌrʌptɪv ˌɪnəˈveɪʃən/", "pron": "dis-RUP-tiv in-uh-VAY-shuhn", "fr": "innovation disruptive", "def": "Innovation that transforms or replaces existing markets or models.", "ex": "Disruptive innovation can create winners and losers."}, {"term": "creative destruction", "ipa": "/kriˌeɪtɪv dɪˈstrʌkʃən/", "pron": "kree-AY-tiv di-STRUK-shuhn", "fr": "destruction créatrice", "def": "Economic change where innovation destroys older industries while creating new ones.", "ex": "Creative destruction is often used to describe technological change."}, {"term": "network effect", "ipa": "/ˈnetwɜːk ɪˌfekt/", "pron": "NET-work i-FEKT", "fr": "effet de réseau", "def": "A situation where a service becomes more valuable as more people use it.", "ex": "Network effects make it hard to compete with dominant platforms."}, {"term": "winner-takes-all market", "ipa": "/ˌwɪnə teɪks ˈɔːl ˌmɑːkɪt/", "pron": "WIN-uh-tayks-all MAR-kit", "fr": "marché où le gagnant rafle tout", "def": "A market where one or a few firms capture most users and profits.", "ex": "Digital markets often become winner-takes-all markets."}, {"term": "market dominance", "ipa": "/ˌmɑːkɪt ˈdɒmɪnəns/", "pron": "MAR-kit DOM-i-nuhns", "fr": "domination du marché", "def": "A company’s strong control over a market.", "ex": "Market dominance gives platforms bargaining power."}, {"term": "monopoly", "ipa": "/məˈnɒpəli/", "pron": "muh-NOP-uh-lee", "fr": "monopole", "def": "A market controlled by one seller or company.", "ex": "A monopoly can reduce competition and innovation."}]}, {"title": "B. Market power, competition and regulation", "entries": [{"term": "monopoly power", "ipa": "/məˈnɒpəli ˈpaʊə/", "pron": "muh-NOP-uh-lee POW-uh", "fr": "pouvoir monopolistique", "def": "The ability of a dominant firm to control prices, access or conditions.", "ex": "Regulators worry about Big Tech’s monopoly power."}, {"term": "oligopoly", "ipa": "/ˌɒlɪˈɡɒpəli/", "pron": "ol-i-GOP-uh-lee", "fr": "oligopole", "def": "A market dominated by a small number of large firms.", "ex": "The tech sector is often an oligopoly."}, {"term": "market concentration", "ipa": "/ˌmɑːkɪt ˌkɒnsənˈtreɪʃən/", "pron": "MAR-kit kon-suhn-TRAY-shuhn", "fr": "concentration du marché", "def": "A situation where a few firms control a large share of a market.", "ex": "Market concentration raises antitrust concerns."}, {"term": "gatekeeper", "ipa": "/ˈɡeɪtˌkiːpə/", "pron": "GATE-kee-puh", "fr": "contrôleur d’accès", "def": "A powerful platform controlling access to users, data or markets.", "ex": "Gatekeepers can favour their own services."}, {"term": "digital gatekeeper", "ipa": "/ˌdɪdʒɪtəl ˈɡeɪtˌkiːpə/", "pron": "DIJ-i-tuhl GATE-kee-puh", "fr": "contrôleur d’accès numérique", "def": "A large digital platform controlling access in online markets.", "ex": "The EU Digital Markets Act targets digital gatekeepers."}, {"term": "intermediary", "ipa": "/ˌɪntəˈmiːdiəri/", "pron": "IN-tuh-MEE-dee-uh-ree", "fr": "intermédiaire", "def": "An actor that connects two or more sides of a market or exchange.", "ex": "Platforms act as intermediaries between users and advertisers."}, {"term": "two-sided market", "ipa": "/ˌtuː saɪdɪd ˈmɑːkɪt/", "pron": "two-SY-did MAR-kit", "fr": "marché biface", "def": "A market where a platform connects two groups, such as users and advertisers.", "ex": "Social networks operate as two-sided markets."}, {"term": "multi-sided platform", "ipa": "/ˌmʌlti saɪdɪd ˈplætfɔːm/", "pron": "MUL-tee-SY-did PLAT-form", "fr": "plateforme multiface", "def": "A platform connecting several groups of users or businesses.", "ex": "App stores are multi-sided platforms."}, {"term": "ecosystem lock-in", "ipa": "/ˈiːkəʊˌsɪstəm ˈlɒk ɪn/", "pron": "EE-koh-SIS-tuhm LOK-in", "fr": "enfermement dans un écosystème", "def": "A situation where users are trapped within a company’s products and services.", "ex": "Ecosystem lock-in makes switching difficult."}, {"term": "lock-in effect", "ipa": "/ˈlɒk ɪn ɪˌfekt/", "pron": "LOK-in i-FEKT", "fr": "effet de verrouillage", "def": "A situation where users cannot easily leave a service or supplier.", "ex": "The lock-in effect protects dominant platforms."}, {"term": "switching cost", "ipa": "/ˈswɪtʃɪŋ kɒst/", "pron": "SWITCH-ing kost", "fr": "coût de changement", "def": "The cost or difficulty of moving from one service to another.", "ex": "High switching costs reduce competition."}, {"term": "data portability", "ipa": "/ˈdeɪtə ˌpɔːtəˈbɪləti/", "pron": "DAY-tuh por-tuh-BIL-uh-tee", "fr": "portabilité des données", "def": "The ability to move personal data from one service to another.", "ex": "Data portability can help users switch platforms."}, {"term": "interoperability", "ipa": "/ˌɪntərɒpərəˈbɪləti/", "pron": "in-ter-op-uh-ruh-BIL-uh-tee", "fr": "interopérabilité", "def": "The ability of systems or services to work together.", "ex": "Interoperability can reduce platform lock-in."}, {"term": "self-preferencing", "ipa": "/ˌself ˈprefərənsɪŋ/", "pron": "self-PREF-uh-ruhn-sing", "fr": "auto-préférence", "def": "A platform favouring its own services over competitors.", "ex": "Self-preferencing is a major antitrust concern."}, {"term": "preferential treatment", "ipa": "/ˌprefəˈrenʃəl ˈtriːtmənt/", "pron": "pref-uh-REN-shuhl TREET-muhnt", "fr": "traitement préférentiel", "def": "More favourable treatment given to one actor or product.", "ex": "Dominant platforms may give preferential treatment to their own products."}, {"term": "acquisition", "ipa": "/ˌækwɪˈzɪʃən/", "pron": "ak-wi-ZISH-uhn", "fr": "acquisition", "def": "The purchase of one company by another.", "ex": "Big Tech acquisitions can eliminate future rivals."}, {"term": "merger", "ipa": "/ˈmɜːdʒə/", "pron": "MUR-juh", "fr": "fusion", "def": "The combination of two companies into one.", "ex": "A merger can increase market power."}, {"term": "killer acquisition", "ipa": "/ˈkɪlər ˌækwɪˈzɪʃən/", "pron": "KIL-uh ak-wi-ZISH-uhn", "fr": "acquisition tueuse", "def": "An acquisition designed to eliminate a potential competitor.", "ex": "Regulators worry about killer acquisitions in tech."}, {"term": "antitrust", "ipa": "/ˌæntiˈtrʌst/", "pron": "AN-tee-TRUST", "fr": "droit de la concurrence ; antitrust", "def": "Law or policy designed to prevent monopolies and unfair competition.", "ex": "Antitrust cases against Big Tech have multiplied."}, {"term": "competition law", "ipa": "/ˌkɒmpəˈtɪʃən lɔː/", "pron": "kom-puh-TISH-uhn law", "fr": "droit de la concurrence", "def": "Law protecting fair competition between firms.", "ex": "Competition law tries to prevent abuse of dominance."}, {"term": "abuse of dominance", "ipa": "/əˈbjuːs əv ˈdɒmɪnəns/", "pron": "uh-BYOOSS ov DOM-i-nuhns", "fr": "abus de position dominante", "def": "Using a dominant market position unfairly against rivals or consumers.", "ex": "Abuse of dominance can lead to large fines."}, {"term": "antitrust investigation", "ipa": "/ˌæntiˈtrʌst ɪnˌvestɪˈɡeɪʃən/", "pron": "AN-tee-TRUST in-ves-ti-GAY-shuhn", "fr": "enquête antitrust", "def": "An official inquiry into possible anti-competitive behaviour.", "ex": "The company faced an antitrust investigation."}, {"term": "regulator", "ipa": "/ˈreɡjʊleɪtə/", "pron": "REG-yuh-lay-tuh", "fr": "régulateur", "def": "An authority responsible for enforcing rules in a sector.", "ex": "Regulators are trying to catch up with Big Tech."}, {"term": "regulation", "ipa": "/ˌreɡjʊˈleɪʃən/", "pron": "reg-yuh-LAY-shuhn", "fr": "réglementation", "def": "Rules made by authorities to control behaviour or markets.", "ex": "Tech regulation is now a global priority."}, {"term": "platform regulation", "ipa": "/ˈplætfɔːm ˌreɡjʊˈleɪʃən/", "pron": "PLAT-form reg-yuh-LAY-shuhn", "fr": "réglementation des plateformes", "def": "Rules governing digital platforms and their responsibilities.", "ex": "Platform regulation must balance innovation and accountability."}, {"term": "Digital Markets Act", "ipa": "/ˌdɪdʒɪtəl ˈmɑːkɪts ækt/", "pron": "DIJ-i-tuhl MAR-kits akt", "fr": "règlement européen sur les marchés numériques", "def": "EU law regulating large digital gatekeepers.", "ex": "The Digital Markets Act aims to curb gatekeeper power."}, {"term": "DMA", "ipa": "/ˌdiː em ˈeɪ/", "pron": "dee-em-ay", "fr": "DMA", "def": "Abbreviation for Digital Markets Act.", "ex": "The DMA imposes obligations on gatekeepers."}, {"term": "Digital Services Act", "ipa": "/ˌdɪdʒɪtəl ˈsɜːvɪsɪz ækt/", "pron": "DIJ-i-tuhl SUR-vis-iz akt", "fr": "règlement européen sur les services numériques", "def": "EU law regulating online platforms and digital services.", "ex": "The Digital Services Act addresses online harms."}, {"term": "DSA", "ipa": "/ˌdiː es ˈeɪ/", "pron": "dee-ess-ay", "fr": "DSA", "def": "Abbreviation for Digital Services Act.", "ex": "The DSA increases transparency obligations."}, {"term": "GDPR", "ipa": "/ˌdʒiː diː piː ˈɑː/", "pron": "jee-dee-pee-ar", "fr": "RGPD", "def": "General Data Protection Regulation, the EU’s data-privacy law.", "ex": "GDPR strengthened users’ control over personal data."}, {"term": "data protection", "ipa": "/ˈdeɪtə prəˌtekʃən/", "pron": "DAY-tuh pruh-TEK-shuhn", "fr": "protection des données", "def": "Rules and practices protecting personal data.", "ex": "Data protection is central to EU digital policy."}, {"term": "privacy law", "ipa": "/ˈprɪvəsi lɔː/", "pron": "PRIV-uh-see law", "fr": "droit de la vie privée", "def": "Law protecting personal information and private life.", "ex": "Privacy law limits how platforms use personal data."}, {"term": "compliance", "ipa": "/kəmˈplaɪəns/", "pron": "kuhm-PLY-uhns", "fr": "conformité", "def": "Respect for laws, rules or standards.", "ex": "Compliance costs can be high for digital companies."}, {"term": "transparency requirement", "ipa": "/trænˈspærənsi rɪˈkwaɪəmənt/", "pron": "tran-SPARR-uhn-see ri-KWY-uh-muhnt", "fr": "exigence de transparence", "def": "A legal or policy obligation to provide clear information.", "ex": "Transparency requirements apply to platform algorithms."}, {"term": "algorithmic transparency", "ipa": "/ˌælɡəˈrɪðmɪk trænˈspærənsi/", "pron": "al-guh-RITH-mik tran-SPARR-uhn-see", "fr": "transparence algorithmique", "def": "Openness about how algorithms rank, recommend or decide.", "ex": "Algorithmic transparency is hard because systems are complex."}, {"term": "algorithmic accountability", "ipa": "/ˌælɡəˈrɪðmɪk əˌkaʊntəˈbɪləti/", "pron": "al-guh-RITH-mik uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité algorithmique", "def": "Responsibility for the consequences of algorithmic systems.", "ex": "Algorithmic accountability requires audits and oversight."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération de contenu", "def": "Reviewing and managing online content according to rules.", "ex": "Big Tech platforms struggle with content moderation at scale."}, {"term": "platform accountability", "ipa": "/ˈplætfɔːm əˌkaʊntəˈbɪləti/", "pron": "PLAT-form uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des plateformes", "def": "Responsibility of platforms for their systems, rules and social effects.", "ex": "Platform accountability is a key democratic issue."}, {"term": "corporate accountability", "ipa": "/ˈkɔːpərət əˌkaʊntəˈbɪləti/", "pron": "KOR-puh-ruht uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des entreprises", "def": "Responsibility of companies for their actions and harms.", "ex": "Corporate accountability matters when firms affect public life."}, {"term": "corporate power", "ipa": "/ˈkɔːpərət ˈpaʊə/", "pron": "KOR-puh-ruht POW-uh", "fr": "pouvoir des entreprises", "def": "The influence of large companies over markets, politics and society.", "ex": "Big Tech has accumulated immense corporate power."}, {"term": "lobbying", "ipa": "/ˈlɒbiɪŋ/", "pron": "LOB-ee-ing", "fr": "lobbying", "def": "Trying to influence political decisions, often by companies or interest groups.", "ex": "Big Tech spends heavily on lobbying."}, {"term": "lobbyist", "ipa": "/ˈlɒbiɪst/", "pron": "LOB-ee-ist", "fr": "lobbyiste", "def": "A person paid to influence policymakers.", "ex": "Lobbyists can shape digital regulation."}, {"term": "revolving door", "ipa": "/rɪˌvɒlvɪŋ ˈdɔː/", "pron": "ri-VOL-ving door", "fr": "pantouflage ; portes tournantes", "def": "Movement of people between government roles and industry jobs.", "ex": "The revolving door raises conflict-of-interest concerns."}, {"term": "conflict of interest", "ipa": "/ˌkɒnflɪkt əv ˈɪntrəst/", "pron": "KON-flikt ov IN-truhst", "fr": "conflit d’intérêts", "def": "A situation where private interest may improperly influence public duty.", "ex": "Tech regulation must avoid conflicts of interest."}, {"term": "campaign donation", "ipa": "/kæmˈpeɪn dəʊˈneɪʃən/", "pron": "kam-PAYN doh-NAY-shuhn", "fr": "don de campagne", "def": "Money given to support a political campaign.", "ex": "Campaign donations can buy political access."}]}, {"title": "C. Digital sovereignty, infrastructure, data and advertising", "entries": [{"term": "political influence", "ipa": "/pəˌlɪtɪkəl ˈɪnfluəns/", "pron": "puh-LIT-i-kuhl IN-floo-uhns", "fr": "influence politique", "def": "The ability to affect political decisions or debate.", "ex": "Big Tech’s political influence worries lawmakers."}, {"term": "public policy", "ipa": "/ˌpʌblɪk ˈpɒləsi/", "pron": "PUB-lik POL-uh-see", "fr": "politique publique", "def": "Government decisions and rules affecting society.", "ex": "Public policy often lags behind technological change."}, {"term": "digital sovereignty", "ipa": "/ˌdɪdʒɪtəl ˈsɒvrənti/", "pron": "DIJ-i-tuhl SOV-ruhn-tee", "fr": "souveraineté numérique", "def": "A state or region’s ability to control digital infrastructure, data and technology.", "ex": "Europe seeks digital sovereignty in the face of US and Chinese tech power."}, {"term": "technological sovereignty", "ipa": "/ˌteknəˈlɒdʒɪkəl ˈsɒvrənti/", "pron": "tek-nuh-LOJ-i-kuhl SOV-ruhn-tee", "fr": "souveraineté technologique", "def": "Capacity to control essential technologies without excessive dependency.", "ex": "Technological sovereignty is linked to chips, cloud and AI."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "Ability to act independently in strategic areas.", "ex": "Digital strategic autonomy is a priority for the EU."}, {"term": "strategic dependency", "ipa": "/strəˌtiːdʒɪk dɪˈpendənsi/", "pron": "struh-TEE-jik di-PEN-duhn-see", "fr": "dépendance stratégique", "def": "Reliance on external actors for critical technologies or services.", "ex": "Cloud computing can create strategic dependency."}, {"term": "cloud computing", "ipa": "/ˌklaʊd kəmˈpjuːtɪŋ/", "pron": "klowd kuhm-PYOO-ting", "fr": "informatique en nuage ; cloud", "def": "Computing services provided through remote servers.", "ex": "Cloud computing is dominated by a few tech giants."}, {"term": "cloud provider", "ipa": "/ˈklaʊd prəˌvaɪdə/", "pron": "klowd pruh-VY-duh", "fr": "fournisseur de cloud", "def": "A company offering cloud computing services.", "ex": "Governments rely on cloud providers for digital services."}, {"term": "data centre", "ipa": "/ˈdeɪtə ˌsentə/", "pron": "DAY-tuh SEN-tuh", "fr": "centre de données", "def": "A facility housing servers and computing infrastructure.", "ex": "Data centres consume large amounts of energy."}, {"term": "server farm", "ipa": "/ˈsɜːvə fɑːm/", "pron": "SUR-vuh farm", "fr": "ferme de serveurs", "def": "A large group of computer servers used for digital services.", "ex": "Server farms power online platforms."}, {"term": "digital infrastructure", "ipa": "/ˌdɪdʒɪtəl ˈɪnfrəˌstrʌktʃə/", "pron": "DIJ-i-tuhl IN-fruh-struk-chuh", "fr": "infrastructure numérique", "def": "Technical systems supporting digital services, such as networks, servers and cloud.", "ex": "Digital infrastructure is now critical infrastructure."}, {"term": "critical infrastructure", "ipa": "/ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "infrastructures critiques", "def": "Essential systems needed for society and the economy.", "ex": "Big Tech increasingly controls parts of critical infrastructure."}, {"term": "cybersecurity", "ipa": "/ˌsaɪbə sɪˈkjʊərəti/", "pron": "SY-buh si-KYOOR-uh-tee", "fr": "cybersécurité", "def": "Protection of computer systems, networks and data.", "ex": "Cybersecurity failures can affect millions of users."}, {"term": "cyberattack", "ipa": "/ˈsaɪbərətæk/", "pron": "SY-buh-uh-tak", "fr": "cyberattaque", "def": "An attack on computer systems or networks.", "ex": "A cyberattack on a tech giant can disrupt global services."}, {"term": "data breach", "ipa": "/ˈdeɪtə briːtʃ/", "pron": "DAY-tuh breech", "fr": "violation de données", "def": "Unauthorised access to private or sensitive data.", "ex": "A data breach can expose millions of accounts."}, {"term": "encryption", "ipa": "/ɪnˈkrɪpʃən/", "pron": "in-KRIP-shuhn", "fr": "chiffrement", "def": "Technology that protects information by making it unreadable without a key.", "ex": "Encryption protects privacy but complicates law enforcement."}, {"term": "end-to-end encryption", "ipa": "/ˌend tuː end ɪnˈkrɪpʃən/", "pron": "end-to-end in-KRIP-shuhn", "fr": "chiffrement de bout en bout", "def": "Encryption where only sender and receiver can read messages.", "ex": "End-to-end encryption is debated by security agencies."}, {"term": "app store", "ipa": "/ˈæp stɔː/", "pron": "app store", "fr": "boutique d’applications", "def": "A platform for distributing mobile applications.", "ex": "App stores control access to mobile users."}, {"term": "commission fee", "ipa": "/kəˈmɪʃən fiː/", "pron": "kuh-MISH-uhn fee", "fr": "commission", "def": "A charge taken by a platform from transactions or sales.", "ex": "Developers criticise high app-store commission fees."}, {"term": "developer", "ipa": "/dɪˈveləpə/", "pron": "di-VEL-uh-puh", "fr": "développeur", "def": "A person or company that creates software or applications.", "ex": "Developers depend on platform rules."}, {"term": "API", "ipa": "/ˌeɪ piː ˈaɪ/", "pron": "ay-pee-eye", "fr": "API ; interface de programmation", "def": "Application programming interface, a tool allowing software systems to communicate.", "ex": "APIs let developers build services on top of platforms."}, {"term": "open-source software", "ipa": "/ˌəʊpən sɔːs ˈsɒftweə/", "pron": "OH-puhn source SOFT-wair", "fr": "logiciel libre ; logiciel open source", "def": "Software whose code is publicly available.", "ex": "Open-source software can reduce dependence on Big Tech."}, {"term": "proprietary software", "ipa": "/prəˌpraɪətəri ˈsɒftweə/", "pron": "pruh-PRY-uh-tuh-ree SOFT-wair", "fr": "logiciel propriétaire", "def": "Software owned and controlled by a company.", "ex": "Proprietary software can create lock-in."}, {"term": "closed ecosystem", "ipa": "/ˌkləʊzd ˈiːkəʊˌsɪstəm/", "pron": "klohz-d EE-koh-SIS-tuhm", "fr": "écosystème fermé", "def": "A controlled digital environment where one company sets rules and access.", "ex": "Closed ecosystems can improve quality but limit choice."}, {"term": "open ecosystem", "ipa": "/ˌəʊpən ˈiːkəʊˌsɪstəm/", "pron": "OH-puhn EE-koh-SIS-tuhm", "fr": "écosystème ouvert", "def": "A digital environment allowing more interoperability and external participation.", "ex": "Open ecosystems encourage competition."}, {"term": "user data", "ipa": "/ˈjuːzə ˈdeɪtə/", "pron": "YOO-zuh DAY-tuh", "fr": "données utilisateur", "def": "Information collected about users and their behaviour.", "ex": "User data is extremely valuable to platforms."}, {"term": "personal data", "ipa": "/ˌpɜːsənəl ˈdeɪtə/", "pron": "PUR-suh-nuhl DAY-tuh", "fr": "données personnelles", "def": "Information relating to an identifiable person.", "ex": "Big Tech collects vast amounts of personal data."}, {"term": "first-party data", "ipa": "/ˌfɜːst ˈpɑːti ˈdeɪtə/", "pron": "first-PAR-tee DAY-tuh", "fr": "données de première partie", "def": "Data collected directly from users by a company.", "ex": "First-party data gives platforms an advertising advantage."}, {"term": "third-party data", "ipa": "/ˌθɜːd ˈpɑːti ˈdeɪtə/", "pron": "third-PAR-tee DAY-tuh", "fr": "données tierces", "def": "Data collected or provided by external actors.", "ex": "Third-party data is increasingly restricted by privacy rules."}, {"term": "data broker", "ipa": "/ˈdeɪtə ˌbrəʊkə/", "pron": "DAY-tuh BROH-kuh", "fr": "courtier en données", "def": "A company that collects and sells personal data.", "ex": "Data brokers operate with limited public visibility."}, {"term": "data monetisation", "ipa": "/ˈdeɪtə ˌmʌnɪtaɪˈzeɪʃən/", "pron": "DAY-tuh mun-i-ty-ZAY-shuhn", "fr": "monétisation des données", "def": "Turning data into revenue.", "ex": "Data monetisation is central to many platform business models."}, {"term": "surveillance capitalism", "ipa": "/səˈveɪləns ˈkæpɪtəlɪzəm/", "pron": "suh-VAY-luhns KAP-i-tuhl-iz-uhm", "fr": "capitalisme de surveillance", "def": "An economic model based on collecting and monetising behavioural data.", "ex": "Surveillance capitalism turns behaviour into profit."}, {"term": "behavioural data", "ipa": "/bɪˌheɪvjərəl ˈdeɪtə/", "pron": "bi-HAY-vyuh-ruhl DAY-tuh", "fr": "données comportementales", "def": "Data about users’ actions, preferences and habits.", "ex": "Behavioural data helps predict user choices."}, {"term": "targeted advertising", "ipa": "/ˈtɑːɡɪtɪd ˈædvətaɪzɪŋ/", "pron": "TAR-git-id AD-vuh-ty-zing", "fr": "publicité ciblée", "def": "Advertising aimed at specific users based on data.", "ex": "Targeted advertising funds social media platforms."}, {"term": "adtech", "ipa": "/ˈædtek/", "pron": "AD-tek", "fr": "technologie publicitaire ; adtech", "def": "Technology used to manage and target online advertising.", "ex": "Adtech relies on tracking and user profiling."}, {"term": "tracking", "ipa": "/ˈtrækɪŋ/", "pron": "TRAK-ing", "fr": "traçage ; suivi", "def": "Monitoring users’ online behaviour.", "ex": "Tracking allows advertisers to follow users across the web."}, {"term": "profiling", "ipa": "/ˈprəʊfaɪlɪŋ/", "pron": "PROH-fy-ling", "fr": "profilage", "def": "Building a profile of someone based on data.", "ex": "Profiling can be used for advertising or political messaging."}, {"term": "personalisation", "ipa": "/ˌpɜːsənəlaɪˈzeɪʃən/", "pron": "pur-suh-nuh-ly-ZAY-shuhn", "fr": "personnalisation", "def": "Adapting content or services to individual users.", "ex": "Personalisation can improve service but narrow exposure."}, {"term": "recommender system", "ipa": "/ˌrekəˈmendə ˈsɪstəm/", "pron": "rek-uh-MEN-duh SIS-tuhm", "fr": "système de recommandation", "def": "A system suggesting content, products or services to users.", "ex": "Recommender systems keep users engaged."}, {"term": "attention economy", "ipa": "/əˈtenʃən iˌkɒnəmi/", "pron": "uh-TEN-shuhn i-KON-uh-mee", "fr": "économie de l’attention", "def": "An economy in which companies compete for human attention.", "ex": "Big Tech profits from the attention economy."}, {"term": "engagement metric", "ipa": "/ɪnˈɡeɪdʒmənt ˈmetrɪk/", "pron": "in-GAYJ-muhnt MET-rik", "fr": "indicateur d’engagement", "def": "A measurement of user interaction, such as likes, clicks or shares.", "ex": "Engagement metrics shape platform design."}, {"term": "addictive design", "ipa": "/əˈdɪktɪv dɪˈzaɪn/", "pron": "uh-DIK-tiv di-ZYNE", "fr": "design addictif", "def": "Design intended to keep users engaged compulsively.", "ex": "Addictive design raises mental-health concerns."}, {"term": "dark pattern", "ipa": "/ˈdɑːk ˌpætən/", "pron": "dark PAT-uhn", "fr": "interface trompeuse ; dark pattern", "def": "A manipulative design choice that pushes users into decisions they might not otherwise make.", "ex": "Dark patterns can make cancelling subscriptions difficult."}, {"term": "user consent", "ipa": "/ˈjuːzə kənˌsent/", "pron": "YOO-zuh kuhn-SENT", "fr": "consentement de l’utilisateur", "def": "A user’s permission for data use or a digital action.", "ex": "User consent must be informed and freely given."}, {"term": "terms and conditions", "ipa": "/ˌtɜːmz ənd kənˈdɪʃənz/", "pron": "terms and kuhn-DISH-uhnz", "fr": "conditions générales", "def": "Legal rules users accept when using a service.", "ex": "Few users read terms and conditions."}, {"term": "privacy policy", "ipa": "/ˈprɪvəsi ˌpɒləsi/", "pron": "PRIV-uh-see POL-uh-see", "fr": "politique de confidentialité", "def": "A document explaining how personal data is collected and used.", "ex": "Privacy policies are often difficult to understand."}, {"term": "artificial intelligence", "ipa": "/ˌɑːtɪˈfɪʃəl ɪnˈtelɪdʒəns/", "pron": "ar-ti-FISH-uhl in-TEL-i-juhns", "fr": "intelligence artificielle", "def": "Computer systems able to perform tasks requiring human intelligence.", "ex": "Big Tech invests heavily in artificial intelligence."}]}, {"title": "D. AI, work, rights, online harms and environmental costs", "entries": [{"term": "generative AI", "ipa": "/ˌdʒenərətɪv ˌeɪ ˈaɪ/", "pron": "JEN-uh-ruh-tiv ay-eye", "fr": "IA générative", "def": "AI that creates text, images, audio, video or code.", "ex": "Generative AI has intensified competition between tech giants."}, {"term": "large language model", "ipa": "/ˌlɑːdʒ ˈlæŋɡwɪdʒ ˌmɒdəl/", "pron": "larj LANG-gwij MOD-uhl", "fr": "grand modèle de langage", "def": "An AI model trained to process and generate language.", "ex": "Large language models require huge datasets and computing power."}, {"term": "foundation model", "ipa": "/faʊnˈdeɪʃən ˈmɒdəl/", "pron": "fown-DAY-shuhn MOD-uhl", "fr": "modèle de fondation", "def": "A large AI model adaptable to many tasks.", "ex": "Foundation models are controlled by a small number of firms."}, {"term": "AI race", "ipa": "/ˌeɪ ˈaɪ reɪs/", "pron": "ay-eye race", "fr": "course à l’IA", "def": "Competition to develop and deploy advanced AI systems.", "ex": "The AI race may increase pressure to release products quickly."}, {"term": "computing power", "ipa": "/kəmˈpjuːtɪŋ ˈpaʊə/", "pron": "kuhm-PYOO-ting POW-uh", "fr": "puissance de calcul", "def": "Processing capacity needed to run calculations or AI systems.", "ex": "Computing power is a strategic resource."}, {"term": "GPU", "ipa": "/ˌdʒiː piː ˈjuː/", "pron": "jee-pee-yoo", "fr": "GPU ; processeur graphique", "def": "Graphics processing unit, a chip widely used for AI computing.", "ex": "GPUs are essential for training AI models."}, {"term": "semiconductor", "ipa": "/ˌsemikənˈdʌktə/", "pron": "SEM-ee-kuhn-DUK-tuh", "fr": "semi-conducteur", "def": "A material or device used in computer chips.", "ex": "Semiconductors are vital for Big Tech and AI."}, {"term": "chip supply chain", "ipa": "/ˈtʃɪp səˌplaɪ tʃeɪn/", "pron": "chip suh-PLY chayn", "fr": "chaîne d’approvisionnement des puces", "def": "The network producing and distributing computer chips.", "ex": "Chip supply chains are geopolitically sensitive."}, {"term": "cloud AI", "ipa": "/ˌklaʊd eɪ ˈaɪ/", "pron": "cloud ay-eye", "fr": "IA dans le cloud", "def": "AI services delivered through cloud computing.", "ex": "Cloud AI gives major providers strong leverage."}, {"term": "AI governance", "ipa": "/ˌeɪ ˈaɪ ˈɡʌvənəns/", "pron": "ay-eye GUV-uh-nuhns", "fr": "gouvernance de l’IA", "def": "Rules and practices governing AI development and use.", "ex": "Big Tech is central to AI governance debates."}, {"term": "AI safety", "ipa": "/ˌeɪ ˈaɪ ˈseɪfti/", "pron": "ay-eye SAYF-tee", "fr": "sécurité de l’IA", "def": "Efforts to prevent harmful AI behaviour and misuse.", "ex": "AI safety should not be left entirely to corporations."}, {"term": "open-source AI", "ipa": "/ˌəʊpən sɔːs eɪ ˈaɪ/", "pron": "OH-puhn source ay-eye", "fr": "IA open source", "def": "AI whose code or model components are publicly available.", "ex": "Open-source AI can challenge Big Tech dominance."}, {"term": "closed-source AI", "ipa": "/ˌkləʊzd sɔːs eɪ ˈaɪ/", "pron": "klohz-d source ay-eye", "fr": "IA propriétaire ; IA fermée", "def": "AI whose code or model details are not publicly available.", "ex": "Closed-source AI may reduce transparency."}, {"term": "digital labour", "ipa": "/ˌdɪdʒɪtəl ˈleɪbə/", "pron": "DIJ-i-tuhl LAY-buh", "fr": "travail numérique", "def": "Work performed through or for digital platforms.", "ex": "Digital labour can be invisible and poorly paid."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots ; gig economy", "def": "An economy based on short-term, task-based work.", "ex": "Platforms helped expand the gig economy."}, {"term": "gig worker", "ipa": "/ˈɡɪɡ ˌwɜːkə/", "pron": "gig WUR-kuh", "fr": "travailleur de plateforme", "def": "A worker doing short-term platform-based tasks.", "ex": "Gig workers often lack stable protections."}, {"term": "platform worker", "ipa": "/ˈplætfɔːm ˌwɜːkə/", "pron": "PLAT-form WUR-kuh", "fr": "travailleur de plateforme", "def": "A worker whose labour is organised through a digital platform.", "ex": "Platform workers may be treated as independent contractors."}, {"term": "independent contractor", "ipa": "/ˌɪndɪˌpendənt kənˈtræktə/", "pron": "in-di-PEN-duhnt kuhn-TRAK-tuh", "fr": "travailleur indépendant ; prestataire", "def": "A self-employed worker hired for specific tasks rather than as an employee.", "ex": "Independent contractors usually receive fewer benefits."}, {"term": "algorithmic management", "ipa": "/ˌælɡəˈrɪðmɪk ˈmænɪdʒmənt/", "pron": "al-guh-RITH-mik MAN-ij-muhnt", "fr": "management algorithmique", "def": "Using algorithms to assign, monitor or evaluate workers.", "ex": "Algorithmic management can make work less transparent."}, {"term": "workplace surveillance", "ipa": "/ˈwɜːkpleɪs səˌveɪləns/", "pron": "WURK-place suh-VAY-luhns", "fr": "surveillance au travail", "def": "Monitoring employees’ activity at work.", "ex": "Workplace surveillance increased with digital tools."}, {"term": "remote work", "ipa": "/rɪˌməʊt ˈwɜːk/", "pron": "ri-MOHT work", "fr": "télétravail", "def": "Work done away from a central office, often online.", "ex": "Big Tech tools enabled remote work."}, {"term": "productivity tool", "ipa": "/ˌprɒdʌkˈtɪvəti tuːl/", "pron": "prod-uk-TIV-uh-tee tool", "fr": "outil de productivité", "def": "Software designed to help people work more efficiently.", "ex": "Productivity tools collect workplace data."}, {"term": "digital workplace", "ipa": "/ˌdɪdʒɪtəl ˈwɜːkpleɪs/", "pron": "DIJ-i-tuhl WURK-place", "fr": "espace de travail numérique", "def": "A work environment organised through digital tools.", "ex": "The digital workplace depends on cloud services."}, {"term": "content creator", "ipa": "/ˈkɒntent kriˌeɪtə/", "pron": "KON-tent kree-AY-tuh", "fr": "créateur de contenu", "def": "A person who produces online content for an audience.", "ex": "Content creators depend on platform algorithms."}, {"term": "creator economy", "ipa": "/kriˌeɪtər iˈkɒnəmi/", "pron": "kree-AY-tuh i-KON-uh-mee", "fr": "économie des créateurs", "def": "Economic activity based on creators earning money online.", "ex": "The creator economy is shaped by platform rules."}, {"term": "monetisation", "ipa": "/ˌmʌnɪtaɪˈzeɪʃən/", "pron": "mun-i-ty-ZAY-shuhn", "fr": "monétisation", "def": "Turning attention, data or content into revenue.", "ex": "Monetisation incentives affect what creators produce."}, {"term": "platform dependency", "ipa": "/ˈplætfɔːm dɪˌpendənsi/", "pron": "PLAT-form di-PEN-duhn-see", "fr": "dépendance aux plateformes", "def": "Reliance on a platform for income, visibility or access to users.", "ex": "Platform dependency makes creators vulnerable to rule changes."}, {"term": "demonetisation", "ipa": "/diːˌmʌnɪtaɪˈzeɪʃən/", "pron": "dee-mun-i-ty-ZAY-shuhn", "fr": "démonétisation", "def": "Removing the ability to earn money from content.", "ex": "Demonetisation can suddenly damage a creator’s income."}, {"term": "shadow economy", "ipa": "/ˈʃædəʊ iˌkɒnəmi/", "pron": "SHAD-oh i-KON-uh-mee", "fr": "économie informelle", "def": "Economic activity that is informal, hidden or poorly regulated.", "ex": "Some digital labour resembles a shadow economy."}, {"term": "digital divide", "ipa": "/ˌdɪdʒɪtəl dɪˈvaɪd/", "pron": "DIJ-i-tuhl di-VYDE", "fr": "fracture numérique", "def": "The gap between those with and without access to digital tools and skills.", "ex": "Big Tech can widen or reduce the digital divide."}, {"term": "digital inclusion", "ipa": "/ˌdɪdʒɪtəl ɪnˈkluːʒən/", "pron": "DIJ-i-tuhl in-KLOO-zhuhn", "fr": "inclusion numérique", "def": "Ensuring all people can access and benefit from digital technologies.", "ex": "Digital inclusion is essential for equal opportunity."}, {"term": "accessibility", "ipa": "/əkˌsesəˈbɪləti/", "pron": "ak-ses-uh-BIL-uh-tee", "fr": "accessibilité", "def": "Design that allows people with disabilities to use services or tools.", "ex": "Accessibility should be built into digital platforms."}, {"term": "net neutrality", "ipa": "/ˌnet njuːˈtræləti/", "pron": "net nyoo-TRAL-uh-tee", "fr": "neutralité du Net", "def": "The principle that internet providers should treat all data equally.", "ex": "Net neutrality protects open access online."}, {"term": "open internet", "ipa": "/ˌəʊpən ˈɪntənet/", "pron": "OH-puhn IN-tuh-net", "fr": "internet ouvert", "def": "An internet accessible without excessive restrictions or discrimination.", "ex": "Big Tech’s dominance raises questions about the open internet."}, {"term": "walled garden", "ipa": "/ˌwɔːld ˈɡɑːdən/", "pron": "wawld GAR-duhn", "fr": "jardin clos numérique", "def": "A closed digital environment controlled by one company.", "ex": "A walled garden can limit user choice."}, {"term": "digital rights", "ipa": "/ˌdɪdʒɪtəl ˈraɪts/", "pron": "DIJ-i-tuhl rites", "fr": "droits numériques", "def": "Rights relating to privacy, expression, access and fairness online.", "ex": "Digital rights groups challenge Big Tech practices."}, {"term": "right to privacy", "ipa": "/ˌraɪt tə ˈprɪvəsi/", "pron": "right tuh PRIV-uh-see", "fr": "droit à la vie privée", "def": "The right to control personal information and private life.", "ex": "The right to privacy is threatened by mass data collection."}, {"term": "right to explanation", "ipa": "/ˌraɪt tə ˌekspləˈneɪʃən/", "pron": "right tuh ek-spluh-NAY-shuhn", "fr": "droit à l’explication", "def": "The idea that people should understand automated decisions affecting them.", "ex": "The right to explanation is important in algorithmic decisions."}, {"term": "freedom of expression", "ipa": "/ˌfriːdəm əv ɪkˈspreʃən/", "pron": "FREE-duhm ov ik-SPRESH-uhn", "fr": "liberté d’expression", "def": "The right to express opinions and ideas.", "ex": "Platforms influence freedom of expression through moderation."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of speech or information.", "ex": "Some critics accuse platforms of private censorship."}, {"term": "private censorship", "ipa": "/ˌpraɪvət ˈsensəʃɪp/", "pron": "PRY-vuht SEN-suh-ship", "fr": "censure privée", "def": "Speech restriction by private companies rather than governments.", "ex": "Private censorship is controversial because platforms are not elected."}, {"term": "online harm", "ipa": "/ˌɒnlaɪn ˈhɑːm/", "pron": "ON-line harm", "fr": "préjudice en ligne", "def": "Damage caused by online content, behaviour or systems.", "ex": "Online harms include harassment, scams and radicalisation."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending harm.", "ex": "Platforms are criticised for amplifying misinformation."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to mislead.", "ex": "Disinformation can be profitable when it drives engagement."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hate speech", "fr": "discours de haine", "def": "Speech attacking people based on identity.", "ex": "Platforms must decide how to handle hate speech."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "The process of adopting extreme views, sometimes leading to violence.", "ex": "Recommendation systems can contribute to radicalisation."}, {"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl helth", "fr": "santé mentale", "def": "Psychological and emotional wellbeing.", "ex": "Big Tech faces criticism over teenage mental health."}, {"term": "screen time", "ipa": "/ˈskriːn taɪm/", "pron": "screen time", "fr": "temps d’écran", "def": "Time spent using digital screens.", "ex": "Screen time has become a public-health concern."}, {"term": "child safety", "ipa": "/ˌtʃaɪld ˈseɪfti/", "pron": "child SAYF-tee", "fr": "sécurité des enfants", "def": "Protection of children from harm.", "ex": "Child safety online is a major regulatory priority."}, {"term": "age verification", "ipa": "/ˈeɪdʒ ˌverɪfɪˈkeɪʃən/", "pron": "age verr-i-fi-KAY-shuhn", "fr": "vérification de l’âge", "def": "Checking a user’s age before granting access to content or services.", "ex": "Age verification raises privacy concerns."}, {"term": "digital addiction", "ipa": "/ˌdɪdʒɪtəl əˈdɪkʃən/", "pron": "DIJ-i-tuhl uh-DIK-shuhn", "fr": "addiction numérique", "def": "Compulsive or harmful use of digital services.", "ex": "Digital addiction is linked to addictive design."}, {"term": "sustainability", "ipa": "/səˌsteɪnəˈbɪləti/", "pron": "suh-stay-nuh-BIL-uh-tee", "fr": "durabilité", "def": "The ability to meet needs without damaging future generations.", "ex": "Big Tech’s sustainability claims face scrutiny."}, {"term": "carbon footprint", "ipa": "/ˌkɑːbən ˈfʊtprɪnt/", "pron": "KAR-buhn FOOT-print", "fr": "empreinte carbone", "def": "Greenhouse gas emissions caused by an activity or organisation.", "ex": "Data centres increase Big Tech’s carbon footprint."}, {"term": "energy consumption", "ipa": "/ˈenədʒi kənˌsʌmpʃən/", "pron": "EN-uh-jee kuhn-SUMP-shuhn", "fr": "consommation d’énergie", "def": "The amount of energy used.", "ex": "AI increases energy consumption."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "water consumption", "ipa": "/ˈwɔːtə kənˌsʌmpʃən/", "pron": "WOR-tuh kuhn-SUMP-shuhn", "fr": "consommation d’eau", "def": "The amount of water used.", "ex": "Data centres can have high water consumption."}, {"term": "e-waste", "ipa": "/ˈiː weɪst/", "pron": "ee-waste", "fr": "déchets électroniques", "def": "Discarded electronic devices and components.", "ex": "E-waste is a growing environmental problem."}, {"term": "planned obsolescence", "ipa": "/ˌplænd ˌɒbsəˈlesəns/", "pron": "pland ob-suh-LES-uhns", "fr": "obsolescence programmée", "def": "Designing products to become outdated or unusable sooner than necessary.", "ex": "Planned obsolescence encourages overconsumption."}, {"term": "right to repair", "ipa": "/ˌraɪt tə rɪˈpeə/", "pron": "right tuh ri-PAIR", "fr": "droit à la réparation", "def": "The right of consumers to repair products rather than replace them.", "ex": "The right to repair challenges closed hardware ecosystems."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "écoblanchiment ; greenwashing", "def": "Misleading environmental claims made to improve reputation.", "ex": "Tech companies can be accused of greenwashing."}, {"term": "supply chain", "ipa": "/səˈplaɪ tʃeɪn/", "pron": "suh-PLY chayn", "fr": "chaîne d’approvisionnement", "def": "The network producing and delivering goods or services.", "ex": "Tech supply chains are global and complex."}, {"term": "rare earths", "ipa": "/ˌreər ˈɜːθs/", "pron": "rare earths", "fr": "terres rares", "def": "Minerals used in electronics and green technologies.", "ex": "Rare earths are critical for many devices."}, {"term": "critical minerals", "ipa": "/ˌkrɪtɪkəl ˈmɪnərəlz/", "pron": "KRIT-i-kuhl MIN-uh-ruhlz", "fr": "minerais critiques", "def": "Minerals essential for technology, energy or defence.", "ex": "Critical minerals create geopolitical dependencies."}, {"term": "labour conditions", "ipa": "/ˈleɪbə kənˌdɪʃənz/", "pron": "LAY-buh kuhn-DISH-uhnz", "fr": "conditions de travail", "def": "The conditions under which workers do their jobs.", "ex": "Tech supply chains face scrutiny over labour conditions."}, {"term": "outsourcing", "ipa": "/ˈaʊtsɔːsɪŋ/", "pron": "OWT-sor-sing", "fr": "externalisation", "def": "Using external companies or workers to perform tasks.", "ex": "Outsourcing can hide poor working conditions."}, {"term": "content moderator trauma", "ipa": "/ˈkɒntent ˌmɒdəreɪtə ˈtrɔːmə/", "pron": "KON-tent MOD-uh-ray-tuh TRAW-muh", "fr": "traumatisme des modérateurs de contenu", "def": "Psychological harm suffered by moderators exposed to disturbing material.", "ex": "Content moderator trauma reveals the hidden cost of platforms."}, {"term": "to dominate a market", "ipa": "/ˈdɒmɪneɪt ə ˈmɑːkɪt/", "pron": "DOM-i-nayt uh MAR-kit", "fr": "dominer un marché", "def": "To control a large share of a market.", "ex": "Big Tech companies dominate digital markets."}, {"term": "to stifle competition", "ipa": "/ˈstaɪfəl ˌkɒmpəˈtɪʃən/", "pron": "STY-fuhl kom-puh-TISH-uhn", "fr": "étouffer la concurrence", "def": "To weaken or prevent competition.", "ex": "Self-preferencing can stifle competition."}, {"term": "to abuse market power", "ipa": "/əˈbjuːz ˈmɑːkɪt ˈpaʊə/", "pron": "uh-BYOOZ MAR-kit POW-uh", "fr": "abuser de son pouvoir de marché", "def": "To use dominance unfairly.", "ex": "Regulators accuse some platforms of abusing market power."}, {"term": "to acquire a rival", "ipa": "/əˈkwaɪər ə ˈraɪvəl/", "pron": "uh-KWY-uhr uh RY-vuhl", "fr": "acquérir un rival", "def": "To buy a competing company.", "ex": "A dominant firm may acquire a rival before it becomes a threat."}, {"term": "to regulate Big Tech", "ipa": "/ˈreɡjʊleɪt ˌbɪɡ ˈtek/", "pron": "REG-yuh-layt big tek", "fr": "réglementer Big Tech", "def": "To impose rules on major technology companies.", "ex": "Governments are trying to regulate Big Tech."}, {"term": "to enforce antitrust law", "ipa": "/ɪnˈfɔːs ˌæntiˈtrʌst lɔː/", "pron": "in-FORSS AN-tee-TRUST law", "fr": "faire appliquer le droit de la concurrence", "def": "To apply competition law against anti-competitive behaviour.", "ex": "Authorities must enforce antitrust law effectively."}, {"term": "to protect user privacy", "ipa": "/prəˈtekt ˈjuːzə ˈprɪvəsi/", "pron": "pruh-TEKT YOO-zuh PRIV-uh-see", "fr": "protéger la vie privée des utilisateurs", "def": "To safeguard users’ personal information.", "ex": "Regulation should protect user privacy."}, {"term": "to collect personal data", "ipa": "/kəˈlekt ˌpɜːsənəl ˈdeɪtə/", "pron": "kuh-LEKT PUR-suh-nuhl DAY-tuh", "fr": "collecter des données personnelles", "def": "To gather information about identifiable people.", "ex": "Platforms collect personal data for advertising."}, {"term": "to monetise attention", "ipa": "/ˈmʌnɪtaɪz əˈtenʃən/", "pron": "MUN-i-tyze uh-TEN-shuhn", "fr": "monétiser l’attention", "def": "To turn users’ attention into revenue.", "ex": "Social platforms monetise attention through advertising."}, {"term": "to lock users in", "ipa": "/lɒk ˈjuːzəz ɪn/", "pron": "lok YOO-zuhz in", "fr": "enfermer les utilisateurs", "def": "To make it difficult for users to leave a service or ecosystem.", "ex": "Closed ecosystems lock users in."}, {"term": "to increase transparency", "ipa": "/ɪnˈkriːs trænsˈpærənsi/", "pron": "in-KREESS tran-SPARR-uhn-see", "fr": "accroître la transparence", "def": "To make systems or decisions more open and understandable.", "ex": "Audits can increase transparency."}, {"term": "to hold companies accountable", "ipa": "/həʊld ˈkʌmpəniz əˈkaʊntəbəl/", "pron": "hohld KUM-puh-neez uh-KOWN-tuh-buhl", "fr": "tenir les entreprises responsables", "def": "To make companies responsible for their actions and harms.", "ex": "Lawmakers want to hold companies accountable."}, {"term": "to reduce digital dependency", "ipa": "/rɪˈdjuːs ˌdɪdʒɪtəl dɪˈpendənsi/", "pron": "ri-DYOOSS DIJ-i-tuhl di-PEN-duhn-see", "fr": "réduire la dépendance numérique", "def": "To become less reliant on external digital providers.", "ex": "Europe wants to reduce digital dependency."}, {"term": "to build digital sovereignty", "ipa": "/bɪld ˌdɪdʒɪtəl ˈsɒvrənti/", "pron": "bild DIJ-i-tuhl SOV-ruhn-tee", "fr": "construire la souveraineté numérique", "def": "To develop control over data, infrastructure and technology.", "ex": "Public investment can help build digital sovereignty."}, {"term": "to balance innovation and regulation", "ipa": "/ˈbæləns ˌɪnəˈveɪʃən ənd ˌreɡjʊˈleɪʃən/", "pron": "BAL-uhns in-uh-VAY-shuhn and reg-yuh-LAY-shuhn", "fr": "équilibrer innovation et réglementation", "def": "To encourage technological progress while imposing necessary rules.", "ex": "Democracies must balance innovation and regulation."}]}]}, {"id": "p7c62", "part": 7, "chapter": 62, "title": "Data Privacy", "file": "cpge_vocab_part7_chapter62_data_privacy_premium.html", "count": 141, "sections": [{"title": "A. Core data privacy concepts", "entries": [{"term": "data privacy", "ipa": "/ˈdeɪtə ˈprɪvəsi/", "pron": "DAY-tuh PRIV-uh-see", "fr": "confidentialité des données", "def": "The protection of personal information from misuse, excessive collection or unauthorised access.", "ex": "Data privacy has become a major concern in the digital economy."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "The right to control one’s personal life and information.", "ex": "Privacy is harder to protect when daily life is increasingly online."}, {"term": "personal data", "ipa": "/ˌpɜːsənəl ˈdeɪtə/", "pron": "PUR-suh-nuhl DAY-tuh", "fr": "données personnelles", "def": "Information relating to an identifiable person.", "ex": "Names, addresses and location history are personal data."}, {"term": "personally identifiable information", "ipa": "/ˌpɜːsənəli aɪˌdentɪfaɪəbəl ˌɪnfəˈmeɪʃən/", "pron": "PUR-suh-nuh-lee eye-DEN-ti-fy-uh-buhl in-fuh-MAY-shuhn", "fr": "informations personnellement identifiables", "def": "Information that can identify a specific person.", "ex": "Personally identifiable information must be protected carefully."}, {"term": "PII", "ipa": "/ˌpiː aɪ ˈaɪ/", "pron": "pee-eye-eye", "fr": "données identifiantes", "def": "Abbreviation for personally identifiable information.", "ex": "Companies must protect PII from leaks and misuse."}, {"term": "sensitive data", "ipa": "/ˌsensɪtɪv ˈdeɪtə/", "pron": "SEN-si-tiv DAY-tuh", "fr": "données sensibles", "def": "Personal data requiring special protection because misuse could cause harm.", "ex": "Health data and biometric data are sensitive data."}, {"term": "biometric data", "ipa": "/ˌbaɪəʊˈmetrɪk ˈdeɪtə/", "pron": "by-oh-MET-rik DAY-tuh", "fr": "données biométriques", "def": "Data based on physical or behavioural traits such as fingerprints, face or voice.", "ex": "Facial recognition systems rely on biometric data."}, {"term": "health data", "ipa": "/ˈhelθ ˌdeɪtə/", "pron": "health DAY-tuh", "fr": "données de santé", "def": "Personal information about someone’s health or medical history.", "ex": "Health data is especially sensitive."}, {"term": "financial data", "ipa": "/faɪˈnænʃəl ˈdeɪtə/", "pron": "fy-NAN-shuhl DAY-tuh", "fr": "données financières", "def": "Personal information about money, banking or transactions.", "ex": "Financial data can be used for fraud if stolen."}, {"term": "location data", "ipa": "/ləʊˈkeɪʃən ˈdeɪtə/", "pron": "loh-KAY-shuhn DAY-tuh", "fr": "données de localisation", "def": "Data showing where a person or device is or has been.", "ex": "Location data can reveal habits, beliefs and relationships."}, {"term": "browsing history", "ipa": "/ˈbraʊzɪŋ ˌhɪstəri/", "pron": "BROW-zing HIS-tuh-ree", "fr": "historique de navigation", "def": "A record of websites and pages visited online.", "ex": "Browsing history can reveal private interests."}, {"term": "search history", "ipa": "/ˈsɜːtʃ ˌhɪstəri/", "pron": "SURCH HIS-tuh-ree", "fr": "historique de recherche", "def": "A record of online searches made by a user.", "ex": "Search history can be highly revealing."}, {"term": "metadata", "ipa": "/ˈmetəˌdeɪtə/", "pron": "MET-uh-DAY-tuh", "fr": "métadonnées", "def": "Data about data, such as time, location, sender or device information.", "ex": "Metadata can reveal patterns even without message content."}, {"term": "data subject", "ipa": "/ˈdeɪtə ˌsʌbdʒekt/", "pron": "DAY-tuh SUB-jekt", "fr": "personne concernée", "def": "The person whose personal data is collected or processed.", "ex": "Under privacy law, data subjects have rights."}, {"term": "data controller", "ipa": "/ˈdeɪtə kənˌtrəʊlə/", "pron": "DAY-tuh kuhn-TROH-luh", "fr": "responsable du traitement", "def": "The organisation deciding why and how personal data is processed.", "ex": "A data controller must justify data collection."}, {"term": "data processor", "ipa": "/ˈdeɪtə ˌprəʊsesə/", "pron": "DAY-tuh PROH-ses-uh", "fr": "sous-traitant", "def": "An organisation processing data on behalf of a controller.", "ex": "A cloud provider may act as a data processor."}, {"term": "data processing", "ipa": "/ˈdeɪtə ˌprəʊsesɪŋ/", "pron": "DAY-tuh PROH-ses-ing", "fr": "traitement des données", "def": "Any operation performed on data, such as collection, storage, analysis or sharing.", "ex": "Data processing must have a legal basis."}, {"term": "data collection", "ipa": "/ˈdeɪtə kəˌlekʃən/", "pron": "DAY-tuh kuh-LEK-shuhn", "fr": "collecte de données", "def": "The gathering of information from users, devices or services.", "ex": "Data collection often happens invisibly in apps."}, {"term": "data storage", "ipa": "/ˈdeɪtə ˌstɔːrɪdʒ/", "pron": "DAY-tuh STOR-ij", "fr": "stockage des données", "def": "Keeping data in databases, servers or devices.", "ex": "Data storage creates security responsibilities."}, {"term": "data sharing", "ipa": "/ˈdeɪtə ˌʃeərɪŋ/", "pron": "DAY-tuh SHARE-ing", "fr": "partage de données", "def": "Providing data to another person, company or organisation.", "ex": "Data sharing can improve services but increase privacy risks."}, {"term": "data transfer", "ipa": "/ˈdeɪtə ˌtrænsfɜː/", "pron": "DAY-tuh TRANS-fur", "fr": "transfert de données", "def": "Moving data from one place, system or country to another.", "ex": "International data transfers are regulated."}, {"term": "cross-border data transfer", "ipa": "/ˌkrɒs bɔːdə ˈdeɪtə ˌtrænsfɜː/", "pron": "cross-BOR-duh DAY-tuh TRANS-fur", "fr": "transfert transfrontalier de données", "def": "Movement of data between countries.", "ex": "Cross-border data transfers raise sovereignty and privacy concerns."}, {"term": "data retention", "ipa": "/ˈdeɪtə rɪˌtenʃən/", "pron": "DAY-tuh ri-TEN-shuhn", "fr": "conservation des données", "def": "Keeping data for a certain period.", "ex": "Data retention should be limited to what is necessary."}, {"term": "data deletion", "ipa": "/ˈdeɪtə dɪˌliːʃən/", "pron": "DAY-tuh di-LEE-shuhn", "fr": "suppression des données", "def": "Removing data permanently from a system.", "ex": "Users may request data deletion."}, {"term": "data minimisation", "ipa": "/ˈdeɪtə ˌmɪnɪmaɪˈzeɪʃən/", "pron": "DAY-tuh min-i-my-ZAY-shuhn", "fr": "minimisation des données", "def": "The principle of collecting only the data that is necessary.", "ex": "Data minimisation reduces privacy risk."}, {"term": "purpose limitation", "ipa": "/ˈpɜːpəs ˌlɪmɪˈteɪʃən/", "pron": "PUR-puhs lim-i-TAY-shuhn", "fr": "limitation des finalités", "def": "The principle that data should be used only for specified purposes.", "ex": "Purpose limitation prevents data from being reused unfairly."}, {"term": "lawful basis", "ipa": "/ˈlɔːfəl ˈbeɪsɪs/", "pron": "LAW-fuhl BAY-sis", "fr": "base légale", "def": "A legal reason allowing personal data processing.", "ex": "Consent is one possible lawful basis."}, {"term": "consent", "ipa": "/kənˈsent/", "pron": "kuhn-SENT", "fr": "consentement", "def": "Permission given by a user for data use or processing.", "ex": "Consent must be informed and freely given."}, {"term": "informed consent", "ipa": "/ɪnˌfɔːmd kənˈsent/", "pron": "in-FORMD kuhn-SENT", "fr": "consentement éclairé", "def": "Consent given with clear understanding of what will happen.", "ex": "Informed consent requires clear explanations."}, {"term": "explicit consent", "ipa": "/ɪkˌsplɪsɪt kənˈsent/", "pron": "ik-SPLIS-it kuhn-SENT", "fr": "consentement explicite", "def": "Clear and direct permission, often required for sensitive data.", "ex": "Explicit consent may be needed for health data."}, {"term": "opt-in", "ipa": "/ˌɒpt ˈɪn/", "pron": "opt-in", "fr": "opt-in ; consentement actif", "def": "A choice to actively agree to something.", "ex": "Privacy-friendly systems often use opt-in settings."}, {"term": "opt-out", "ipa": "/ˌɒpt ˈaʊt/", "pron": "opt-out", "fr": "opt-out ; refus", "def": "A choice to refuse or withdraw from something.", "ex": "Users should be able to opt out of tracking."}, {"term": "withdraw consent", "ipa": "/wɪðˌdrɔː kənˈsent/", "pron": "with-DRAW kuhn-SENT", "fr": "retirer son consentement", "def": "To take back permission previously given.", "ex": "Users must be able to withdraw consent easily."}, {"term": "privacy policy", "ipa": "/ˈprɪvəsi ˌpɒləsi/", "pron": "PRIV-uh-see POL-uh-see", "fr": "politique de confidentialité", "def": "A document explaining how an organisation collects and uses personal data.", "ex": "Privacy policies are often too long and unclear."}, {"term": "terms of service", "ipa": "/ˌtɜːmz əv ˈsɜːvɪs/", "pron": "terms ov SUR-vis", "fr": "conditions d’utilisation", "def": "The legal conditions users accept when using a digital service.", "ex": "Few users read the terms of service."}, {"term": "cookie", "ipa": "/ˈkʊki/", "pron": "KUUK-ee", "fr": "cookie", "def": "A small file stored on a device to remember information about a user.", "ex": "Cookies can be used for login, analytics or tracking."}, {"term": "tracking cookie", "ipa": "/ˈtrækɪŋ ˌkʊki/", "pron": "TRAK-ing KUUK-ee", "fr": "cookie de suivi", "def": "A cookie used to follow users across websites.", "ex": "Tracking cookies support targeted advertising."}, {"term": "third-party cookie", "ipa": "/ˌθɜːd pɑːti ˈkʊki/", "pron": "third-PAR-tee KUUK-ee", "fr": "cookie tiers", "def": "A cookie set by a domain other than the website being visited.", "ex": "Third-party cookies have been central to online advertising."}, {"term": "cookie banner", "ipa": "/ˈkʊki ˌbænə/", "pron": "KUUK-ee BAN-uh", "fr": "bannière de cookies", "def": "A notice asking users to accept or reject cookies.", "ex": "Cookie banners often push users towards accepting tracking."}, {"term": "dark pattern", "ipa": "/ˈdɑːk ˌpætən/", "pron": "dark PAT-uhn", "fr": "interface trompeuse ; dark pattern", "def": "A manipulative design choice that nudges users into decisions.", "ex": "Dark patterns can make privacy choices confusing."}, {"term": "privacy by design", "ipa": "/ˌprɪvəsi baɪ dɪˈzaɪn/", "pron": "PRIV-uh-see by di-ZYNE", "fr": "protection de la vie privée dès la conception", "def": "Designing systems with privacy protections built in from the start.", "ex": "Privacy by design reduces risks before harm occurs."}, {"term": "privacy by default", "ipa": "/ˌprɪvəsi baɪ dɪˈfɔːlt/", "pron": "PRIV-uh-see by di-FAWLT", "fr": "protection de la vie privée par défaut", "def": "Using the most privacy-protective settings automatically.", "ex": "Privacy by default means users should not have to fight for privacy."}, {"term": "security by design", "ipa": "/sɪˌkjʊərəti baɪ dɪˈzaɪn/", "pron": "si-KYOOR-uh-tee by di-ZYNE", "fr": "sécurité dès la conception", "def": "Building security protections into systems from the start.", "ex": "Security by design reduces data breaches."}]}, {"title": "B. Consent, cookies, privacy by design and security breaches", "entries": [{"term": "data breach", "ipa": "/ˈdeɪtə briːtʃ/", "pron": "DAY-tuh breech", "fr": "violation de données", "def": "Unauthorised access to personal or confidential data.", "ex": "A data breach can expose millions of users."}, {"term": "security breach", "ipa": "/sɪˈkjʊərəti briːtʃ/", "pron": "si-KYOOR-uh-tee breech", "fr": "faille de sécurité", "def": "A failure allowing unauthorised access to systems or data.", "ex": "A security breach may lead to identity theft."}, {"term": "data leak", "ipa": "/ˈdeɪtə liːk/", "pron": "DAY-tuh leek", "fr": "fuite de données", "def": "Accidental or deliberate exposure of data.", "ex": "A data leak can damage public trust."}, {"term": "unauthorised access", "ipa": "/ʌnˌɔːθəraɪzd ˈækses/", "pron": "un-AW-thuh-ryzd AK-ses", "fr": "accès non autorisé", "def": "Access to systems or data without permission.", "ex": "Unauthorised access must be reported quickly."}, {"term": "identity theft", "ipa": "/aɪˈdentəti θeft/", "pron": "eye-DEN-tuh-tee theft", "fr": "usurpation d’identité", "def": "Using someone’s personal information fraudulently.", "ex": "Identity theft can follow a data breach."}, {"term": "phishing", "ipa": "/ˈfɪʃɪŋ/", "pron": "FISH-ing", "fr": "hameçonnage ; phishing", "def": "Fraudulent messages designed to steal information or credentials.", "ex": "Phishing emails often imitate trusted companies."}, {"term": "credential theft", "ipa": "/krɪˈdenʃəl θeft/", "pron": "kri-DEN-shuhl theft", "fr": "vol d’identifiants", "def": "Stealing usernames, passwords or login details.", "ex": "Credential theft can compromise many accounts."}, {"term": "password", "ipa": "/ˈpɑːswɜːd/", "pron": "PASS-word", "fr": "mot de passe", "def": "A secret word or phrase used to access an account.", "ex": "Weak passwords increase security risks."}, {"term": "passkey", "ipa": "/ˈpɑːskiː/", "pron": "PASS-key", "fr": "clé d’accès ; passkey", "def": "A passwordless login method using cryptographic keys.", "ex": "Passkeys can reduce phishing risks."}, {"term": "two-factor authentication", "ipa": "/ˌtuː fæktər ɔːˌθentɪˈkeɪʃən/", "pron": "two-FAK-tuh aw-then-ti-KAY-shuhn", "fr": "authentification à deux facteurs", "def": "A login method requiring two forms of verification.", "ex": "Two-factor authentication protects accounts."}, {"term": "2FA", "ipa": "/ˌtuː ef ˈeɪ/", "pron": "two-eff-ay", "fr": "2FA", "def": "Abbreviation for two-factor authentication.", "ex": "2FA is strongly recommended for sensitive accounts."}, {"term": "multi-factor authentication", "ipa": "/ˌmʌlti fæktər ɔːˌθentɪˈkeɪʃən/", "pron": "MUL-tee-FAK-tuh aw-then-ti-KAY-shuhn", "fr": "authentification multifacteur", "def": "Authentication requiring multiple verification factors.", "ex": "Multi-factor authentication improves security."}, {"term": "MFA", "ipa": "/ˌem ef ˈeɪ/", "pron": "em-eff-ay", "fr": "MFA", "def": "Abbreviation for multi-factor authentication.", "ex": "MFA reduces the impact of stolen passwords."}, {"term": "encryption", "ipa": "/ɪnˈkrɪpʃən/", "pron": "in-KRIP-shuhn", "fr": "chiffrement", "def": "Protecting information by making it unreadable without a key.", "ex": "Encryption protects data in transit and at rest."}, {"term": "end-to-end encryption", "ipa": "/ˌend tuː end ɪnˈkrɪpʃən/", "pron": "end-to-end in-KRIP-shuhn", "fr": "chiffrement de bout en bout", "def": "Encryption allowing only sender and receiver to read messages.", "ex": "End-to-end encryption protects private conversations."}, {"term": "encrypted data", "ipa": "/ɪnˌkrɪptɪd ˈdeɪtə/", "pron": "in-KRIP-tid DAY-tuh", "fr": "données chiffrées", "def": "Data protected through encryption.", "ex": "Encrypted data is harder to misuse if stolen."}, {"term": "anonymisation", "ipa": "/əˌnɒnɪmaɪˈzeɪʃən/", "pron": "uh-non-i-my-ZAY-shuhn", "fr": "anonymisation", "def": "Removing identifying information so data can no longer be linked to a person.", "ex": "True anonymisation is difficult to guarantee."}, {"term": "pseudonymisation", "ipa": "/ˌsuːdənɪmaɪˈzeɪʃən/", "pron": "soo-duh-ni-my-ZAY-shuhn", "fr": "pseudonymisation", "def": "Replacing identifying details with codes while keeping possible re-identification separate.", "ex": "Pseudonymisation lowers risk but is not full anonymisation."}, {"term": "de-identification", "ipa": "/ˌdiː aɪˌdentɪfɪˈkeɪʃən/", "pron": "dee-eye-den-ti-fi-KAY-shuhn", "fr": "désidentification", "def": "Removing or altering identifiers in data.", "ex": "De-identification helps protect research participants."}, {"term": "re-identification", "ipa": "/ˌriː aɪˌdentɪfɪˈkeɪʃən/", "pron": "ree-eye-den-ti-fi-KAY-shuhn", "fr": "réidentification", "def": "Linking supposedly anonymous data back to a person.", "ex": "Re-identification is a major privacy risk."}, {"term": "data aggregation", "ipa": "/ˈdeɪtə ˌæɡrɪˈɡeɪʃən/", "pron": "DAY-tuh ag-ri-GAY-shuhn", "fr": "agrégation de données", "def": "Combining data from many sources or people.", "ex": "Data aggregation can reveal patterns while hiding individuals."}, {"term": "data profiling", "ipa": "/ˈdeɪtə ˌprəʊfaɪlɪŋ/", "pron": "DAY-tuh PROH-fy-ling", "fr": "profilage de données", "def": "Building profiles of people based on collected data.", "ex": "Data profiling can affect advertising, loans and insurance."}, {"term": "user profiling", "ipa": "/ˈjuːzə ˌprəʊfaɪlɪŋ/", "pron": "YOO-zuh PROH-fy-ling", "fr": "profilage des utilisateurs", "def": "Creating a profile of a user’s behaviour, interests or traits.", "ex": "User profiling powers personalised feeds."}, {"term": "behavioural data", "ipa": "/bɪˌheɪvjərəl ˈdeɪtə/", "pron": "bi-HAY-vyuh-ruhl DAY-tuh", "fr": "données comportementales", "def": "Data about actions, habits and preferences.", "ex": "Behavioural data can predict future choices."}, {"term": "predictive analytics", "ipa": "/prɪˌdɪktɪv ˌænəˈlɪtɪks/", "pron": "pri-DIK-tiv an-uh-LIT-iks", "fr": "analyse prédictive", "def": "Using data to predict future behaviour or events.", "ex": "Predictive analytics can be useful but intrusive."}, {"term": "automated decision-making", "ipa": "/ˈɔːtəmeɪtɪd dɪˈsɪʒən ˌmeɪkɪŋ/", "pron": "AW-tuh-may-tid di-SIZH-uhn MAY-king", "fr": "prise de décision automatisée", "def": "Decisions made by software with limited human involvement.", "ex": "Automated decision-making can affect access to services."}, {"term": "algorithmic decision", "ipa": "/ˌælɡəˈrɪðmɪk dɪˈsɪʒən/", "pron": "al-guh-RITH-mik di-SIZH-uhn", "fr": "décision algorithmique", "def": "A decision produced or influenced by an algorithm.", "ex": "Algorithmic decisions should be explainable."}, {"term": "algorithmic transparency", "ipa": "/ˌælɡəˈrɪðmɪk trænˈspærənsi/", "pron": "al-guh-RITH-mik tran-SPARR-uhn-see", "fr": "transparence algorithmique", "def": "Openness about how algorithms use data and make decisions.", "ex": "Algorithmic transparency helps protect rights."}, {"term": "right to explanation", "ipa": "/ˌraɪt tə ˌekspləˈneɪʃən/", "pron": "right tuh ek-spluh-NAY-shuhn", "fr": "droit à l’explication", "def": "The idea that people should understand automated decisions affecting them.", "ex": "The right to explanation is debated in AI regulation."}, {"term": "digital footprint", "ipa": "/ˌdɪdʒɪtəl ˈfʊtprɪnt/", "pron": "DIJ-i-tuhl FOOT-print", "fr": "empreinte numérique", "def": "The trail of data someone leaves online.", "ex": "A digital footprint can last for years."}, {"term": "online tracking", "ipa": "/ˌɒnlaɪn ˈtrækɪŋ/", "pron": "ON-line TRAK-ing", "fr": "suivi en ligne", "def": "Monitoring users’ behaviour online.", "ex": "Online tracking funds much of the advertising economy."}]}, {"title": "C. Encryption, anonymisation, profiling and surveillance", "entries": [{"term": "device fingerprinting", "ipa": "/dɪˌvaɪs ˈfɪŋɡəprɪntɪŋ/", "pron": "di-VYSS FING-guh-print-ing", "fr": "empreinte numérique d’un appareil", "def": "Identifying a device through its technical characteristics.", "ex": "Device fingerprinting can track users without cookies."}, {"term": "surveillance", "ipa": "/səˈveɪləns/", "pron": "suh-VAY-luhns", "fr": "surveillance", "def": "Monitoring people, communications or behaviour.", "ex": "Digital surveillance can be carried out by states or companies."}, {"term": "mass surveillance", "ipa": "/ˌmæs səˈveɪləns/", "pron": "mass suh-VAY-luhns", "fr": "surveillance de masse", "def": "Large-scale monitoring of populations.", "ex": "Mass surveillance threatens civil liberties."}, {"term": "corporate surveillance", "ipa": "/ˈkɔːpərət səˌveɪləns/", "pron": "KOR-puh-ruht suh-VAY-luhns", "fr": "surveillance d’entreprise", "def": "Monitoring people by companies for profit or control.", "ex": "Corporate surveillance is central to targeted advertising."}, {"term": "state surveillance", "ipa": "/ˌsteɪt səˈveɪləns/", "pron": "state suh-VAY-luhns", "fr": "surveillance étatique", "def": "Monitoring people by government authorities.", "ex": "State surveillance can be justified by security but abused politically."}, {"term": "surveillance capitalism", "ipa": "/səˈveɪləns ˈkæpɪtəlɪzəm/", "pron": "suh-VAY-luhns KAP-i-tuhl-iz-uhm", "fr": "capitalisme de surveillance", "def": "An economic model based on collecting and monetising behavioural data.", "ex": "Surveillance capitalism turns private behaviour into profit."}, {"term": "data broker", "ipa": "/ˈdeɪtə ˌbrəʊkə/", "pron": "DAY-tuh BROH-kuh", "fr": "courtier en données", "def": "A company that collects, analyses and sells personal data.", "ex": "Data brokers often operate out of public view."}, {"term": "data marketplace", "ipa": "/ˈdeɪtə ˌmɑːkɪtpleɪs/", "pron": "DAY-tuh MAR-kit-place", "fr": "marché des données", "def": "A market where data is bought, sold or exchanged.", "ex": "Data marketplaces raise privacy and consent questions."}, {"term": "targeted advertising", "ipa": "/ˈtɑːɡɪtɪd ˈædvətaɪzɪŋ/", "pron": "TAR-git-id AD-vuh-ty-zing", "fr": "publicité ciblée", "def": "Advertising aimed at specific users based on data.", "ex": "Targeted advertising relies on personal data."}, {"term": "behavioural advertising", "ipa": "/bɪˌheɪvjərəl ˈædvətaɪzɪŋ/", "pron": "bi-HAY-vyuh-ruhl AD-vuh-ty-zing", "fr": "publicité comportementale", "def": "Advertising based on online behaviour.", "ex": "Behavioural advertising can feel invasive."}, {"term": "microtargeting", "ipa": "/ˌmaɪkrəʊˈtɑːɡɪtɪŋ/", "pron": "MY-kroh-TAR-git-ing", "fr": "microciblage", "def": "Targeting very specific groups with tailored messages.", "ex": "Political microtargeting can manipulate voters."}, {"term": "data monetisation", "ipa": "/ˈdeɪtə ˌmʌnɪtaɪˈzeɪʃən/", "pron": "DAY-tuh mun-i-ty-ZAY-shuhn", "fr": "monétisation des données", "def": "Turning data into money or business value.", "ex": "Data monetisation is central to many digital platforms."}, {"term": "data exploitation", "ipa": "/ˈdeɪtə ˌeksplɔɪˈteɪʃən/", "pron": "DAY-tuh ek-sploy-TAY-shuhn", "fr": "exploitation des données", "def": "Using data in ways that benefit one party, often unfairly.", "ex": "Data exploitation can harm vulnerable users."}, {"term": "consent fatigue", "ipa": "/kənˈsent fəˌtiːɡ/", "pron": "kuhn-SENT fuh-TEEG", "fr": "fatigue du consentement", "def": "Users becoming tired of repeated consent requests and accepting without reading.", "ex": "Cookie banners can create consent fatigue."}, {"term": "privacy fatigue", "ipa": "/ˈprɪvəsi fəˌtiːɡ/", "pron": "PRIV-uh-see fuh-TEEG", "fr": "fatigue liée à la vie privée", "def": "Feeling overwhelmed by privacy choices and risks.", "ex": "Privacy fatigue makes users less careful."}, {"term": "privacy paradox", "ipa": "/ˈprɪvəsi ˌpærədɒks/", "pron": "PRIV-uh-see PARR-uh-doks", "fr": "paradoxe de la vie privée", "def": "The gap between users saying they value privacy and still sharing data.", "ex": "The privacy paradox reflects convenience, pressure and lack of control."}, {"term": "digital rights", "ipa": "/ˌdɪdʒɪtəl ˈraɪts/", "pron": "DIJ-i-tuhl rites", "fr": "droits numériques", "def": "Rights relating to privacy, access, expression and fairness online.", "ex": "Digital rights groups defend privacy and transparency."}, {"term": "right to privacy", "ipa": "/ˌraɪt tə ˈprɪvəsi/", "pron": "right tuh PRIV-uh-see", "fr": "droit à la vie privée", "def": "The right to protect personal life and information.", "ex": "The right to privacy is challenged by mass data collection."}, {"term": "right of access", "ipa": "/ˌraɪt əv ˈækses/", "pron": "right ov AK-ses", "fr": "droit d’accès", "def": "The right to know what personal data an organisation holds about you.", "ex": "Users can exercise their right of access under GDPR."}, {"term": "right to rectification", "ipa": "/ˌraɪt tə ˌrektɪfɪˈkeɪʃən/", "pron": "right tuh rek-ti-fi-KAY-shuhn", "fr": "droit de rectification", "def": "The right to correct inaccurate personal data.", "ex": "The right to rectification protects people from errors."}, {"term": "right to erasure", "ipa": "/ˌraɪt tə ɪˈreɪʒə/", "pron": "right tuh i-RAY-zhuh", "fr": "droit à l’effacement", "def": "The right to have personal data deleted in certain circumstances.", "ex": "The right to erasure is also called the right to be forgotten."}, {"term": "right to be forgotten", "ipa": "/ˌraɪt tə bi fəˈɡɒtən/", "pron": "right tuh bee fuh-GOT-uhn", "fr": "droit à l’oubli", "def": "The right to have some personal information removed from search results or databases.", "ex": "The right to be forgotten protects reputation and privacy."}, {"term": "right to data portability", "ipa": "/ˌraɪt tə ˈdeɪtə ˌpɔːtəˈbɪləti/", "pron": "right tuh DAY-tuh por-tuh-BIL-uh-tee", "fr": "droit à la portabilité des données", "def": "The right to receive and move personal data between services.", "ex": "Data portability can reduce platform lock-in."}, {"term": "right to object", "ipa": "/ˌraɪt tə əbˈdʒekt/", "pron": "right tuh uhb-JEKT", "fr": "droit d’opposition", "def": "The right to oppose certain data processing.", "ex": "Users may object to direct marketing."}, {"term": "data protection authority", "ipa": "/ˈdeɪtə prəˌtekʃən ɔːˈθɒrəti/", "pron": "DAY-tuh pruh-TEK-shuhn aw-THOR-uh-tee", "fr": "autorité de protection des données", "def": "An independent body enforcing data protection rules.", "ex": "A data protection authority can fine companies."}, {"term": "DPA", "ipa": "/ˌdiː piː ˈeɪ/", "pron": "dee-pee-ay", "fr": "autorité de protection des données", "def": "Abbreviation for data protection authority.", "ex": "DPAs investigate privacy complaints."}, {"term": "Data Protection Officer", "ipa": "/ˈdeɪtə prəˌtekʃən ˈɒfɪsə/", "pron": "DAY-tuh pruh-TEK-shuhn OFF-i-suh", "fr": "délégué à la protection des données", "def": "A person responsible for overseeing data protection compliance.", "ex": "A Data Protection Officer advises organisations on privacy."}, {"term": "DPO", "ipa": "/ˌdiː piː ˈəʊ/", "pron": "dee-pee-oh", "fr": "DPO ; délégué à la protection des données", "def": "Abbreviation for Data Protection Officer.", "ex": "A DPO can be contacted by data subjects."}, {"term": "GDPR", "ipa": "/ˌdʒiː diː piː ˈɑː/", "pron": "jee-dee-pee-ar", "fr": "RGPD", "def": "General Data Protection Regulation, the EU’s major data privacy law.", "ex": "GDPR has influenced privacy laws around the world."}, {"term": "General Data Protection Regulation", "ipa": "/ˌdʒenərəl ˈdeɪtə prəˌtekʃən ˌreɡjʊˈleɪʃən/", "pron": "JEN-uh-ruhl DAY-tuh pruh-TEK-shuhn reg-yuh-LAY-shuhn", "fr": "Règlement général sur la protection des données", "def": "The full name of GDPR.", "ex": "The General Data Protection Regulation gives individuals stronger data rights."}, {"term": "CCPA", "ipa": "/ˌsiː siː piː ˈeɪ/", "pron": "see-see-pee-ay", "fr": "loi californienne sur la protection de la vie privée des consommateurs", "def": "California Consumer Privacy Act.", "ex": "The CCPA gives California residents privacy rights."}, {"term": "HIPAA", "ipa": "/ˈhɪpə/", "pron": "HIP-uh", "fr": "loi américaine de protection des données de santé", "def": "US law protecting certain health information.", "ex": "HIPAA protects medical privacy in the United States."}, {"term": "privacy regulation", "ipa": "/ˈprɪvəsi ˌreɡjʊˈleɪʃən/", "pron": "PRIV-uh-see reg-yuh-LAY-shuhn", "fr": "réglementation de la vie privée", "def": "Laws and rules protecting personal data and privacy.", "ex": "Privacy regulation has become stricter."}, {"term": "compliance", "ipa": "/kəmˈplaɪəns/", "pron": "kuhm-PLY-uhns", "fr": "conformité", "def": "Respect for laws, rules or standards.", "ex": "Compliance requires documentation and training."}, {"term": "privacy impact assessment", "ipa": "/ˈprɪvəsi ˈɪmpækt əˌsesmənt/", "pron": "PRIV-uh-see IM-pakt uh-SESS-muhnt", "fr": "analyse d’impact sur la vie privée", "def": "An evaluation of how a project may affect privacy.", "ex": "A privacy impact assessment identifies risks early."}, {"term": "data protection impact assessment", "ipa": "/ˈdeɪtə prəˌtekʃən ˈɪmpækt əˌsesmənt/", "pron": "DAY-tuh pruh-TEK-shuhn IM-pakt uh-SESS-muhnt", "fr": "analyse d’impact relative à la protection des données", "def": "A formal assessment of data protection risks, often required under GDPR.", "ex": "A data protection impact assessment is needed for high-risk processing."}, {"term": "DPIA", "ipa": "/ˌdiː piː aɪ ˈeɪ/", "pron": "dee-pee-eye-ay", "fr": "AIPD", "def": "Abbreviation for data protection impact assessment.", "ex": "A DPIA is required for some surveillance technologies."}, {"term": "privacy audit", "ipa": "/ˈprɪvəsi ˌɔːdɪt/", "pron": "PRIV-uh-see AW-dit", "fr": "audit de confidentialité", "def": "A review checking whether privacy rules and practices are respected.", "ex": "A privacy audit can reveal compliance gaps."}, {"term": "data breach notification", "ipa": "/ˈdeɪtə briːtʃ ˌnəʊtɪfɪˈkeɪʃən/", "pron": "DAY-tuh breech noh-ti-fi-KAY-shuhn", "fr": "notification de violation de données", "def": "A notice informing authorities or users about a data breach.", "ex": "Data breach notification is mandatory in many laws."}, {"term": "fine", "ipa": "/faɪn/", "pron": "fine", "fr": "amende", "def": "A financial penalty for breaking rules.", "ex": "Privacy violations can lead to heavy fines."}, {"term": "class action", "ipa": "/ˌklɑːs ˈækʃən/", "pron": "class AK-shuhn", "fr": "action collective", "def": "A lawsuit brought by a group of people with similar claims.", "ex": "A data breach can trigger a class action."}, {"term": "data sovereignty", "ipa": "/ˈdeɪtə ˈsɒvrənti/", "pron": "DAY-tuh SOV-ruhn-tee", "fr": "souveraineté des données", "def": "The idea that data is subject to the laws and control of the place where it is stored or collected.", "ex": "Data sovereignty is a strategic issue for governments."}]}, {"title": "D. Digital rights, regulation, compliance and sovereignty", "entries": [{"term": "digital sovereignty", "ipa": "/ˌdɪdʒɪtəl ˈsɒvrənti/", "pron": "DIJ-i-tuhl SOV-ruhn-tee", "fr": "souveraineté numérique", "def": "A state or region’s ability to control digital infrastructure, technology and data.", "ex": "Digital sovereignty includes cloud, chips and data protection."}, {"term": "data localisation", "ipa": "/ˈdeɪtə ˌləʊkəlaɪˈzeɪʃən/", "pron": "DAY-tuh loh-kuh-ly-ZAY-shuhn", "fr": "localisation des données", "def": "Requiring data to be stored within a country or region.", "ex": "Data localisation can protect sovereignty but raise costs."}, {"term": "cloud sovereignty", "ipa": "/ˈklaʊd ˈsɒvrənti/", "pron": "cloud SOV-ruhn-tee", "fr": "souveraineté du cloud", "def": "Control over cloud services, infrastructure and stored data.", "ex": "Cloud sovereignty is a major European concern."}, {"term": "trusted cloud", "ipa": "/ˌtrʌstɪd ˈklaʊd/", "pron": "TRUST-id cloud", "fr": "cloud de confiance", "def": "Cloud services designed to meet security, privacy and sovereignty requirements.", "ex": "A trusted cloud may limit foreign access to sensitive data."}, {"term": "government access", "ipa": "/ˈɡʌvənmənt ˈækses/", "pron": "GUV-uhn-muhnt AK-ses", "fr": "accès gouvernemental", "def": "Access to data by public authorities.", "ex": "Government access to data must be legally controlled."}, {"term": "law enforcement access", "ipa": "/ˌlɔː ɪnˈfɔːsmənt ˈækses/", "pron": "law in-FORSS-muhnt AK-ses", "fr": "accès des forces de l’ordre", "def": "Access to data by police or investigative authorities.", "ex": "Law enforcement access is debated in encrypted services."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "Protection of a country’s safety and vital interests.", "ex": "National security can conflict with privacy."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms protected from government interference.", "ex": "Mass surveillance threatens civil liberties."}, {"term": "privacy-invasive", "ipa": "/ˈprɪvəsi ɪnˌveɪsɪv/", "pron": "PRIV-uh-see in-VAY-siv", "fr": "intrusif pour la vie privée", "def": "Intruding excessively into private life or data.", "ex": "Facial recognition can be privacy-invasive."}, {"term": "to protect personal data", "ipa": "/prəˈtekt ˌpɜːsənəl ˈdeɪtə/", "pron": "pruh-TEKT PUR-suh-nuhl DAY-tuh", "fr": "protéger les données personnelles", "def": "To keep personal information safe from misuse or exposure.", "ex": "Organisations must protect personal data."}, {"term": "to collect data", "ipa": "/kəˈlekt ˈdeɪtə/", "pron": "kuh-LEKT DAY-tuh", "fr": "collecter des données", "def": "To gather information from users or systems.", "ex": "Apps collect data for analytics and advertising."}, {"term": "to process data", "ipa": "/ˈprəʊses ˈdeɪtə/", "pron": "PROH-ses DAY-tuh", "fr": "traiter des données", "def": "To use, store, analyse or transform data.", "ex": "Companies need a legal basis to process data."}, {"term": "to share data with third parties", "ipa": "/ʃeə ˈdeɪtə wɪð ˌθɜːd ˈpɑːtiz/", "pron": "share DAY-tuh with third PAR-teez", "fr": "partager des données avec des tiers", "def": "To provide data to external companies or organisations.", "ex": "Users often do not realise apps share data with third parties."}, {"term": "to give consent", "ipa": "/ɡɪv kənˈsent/", "pron": "giv kuhn-SENT", "fr": "donner son consentement", "def": "To allow data use or processing.", "ex": "Users should know what they give consent to."}, {"term": "to withdraw consent", "ipa": "/wɪðˌdrɔː kənˈsent/", "pron": "with-DRAW kuhn-SENT", "fr": "retirer son consentement", "def": "To take back permission for data processing.", "ex": "It should be easy to withdraw consent."}, {"term": "to track users", "ipa": "/træk ˈjuːzəz/", "pron": "trak YOO-zuhz", "fr": "suivre les utilisateurs", "def": "To monitor users’ online behaviour.", "ex": "Advertisers track users across websites."}, {"term": "to profile consumers", "ipa": "/ˈprəʊfaɪl kənˈsjuːməz/", "pron": "PROH-fyle kuhn-SYOO-muhz", "fr": "profiler les consommateurs", "def": "To build data-based profiles of consumers.", "ex": "Retailers profile consumers to target ads."}, {"term": "to monetise data", "ipa": "/ˈmʌnɪtaɪz ˈdeɪtə/", "pron": "MUN-i-tyze DAY-tuh", "fr": "monétiser les données", "def": "To turn data into financial value.", "ex": "Platforms monetise data through advertising."}, {"term": "to anonymise data", "ipa": "/əˈnɒnɪmaɪz ˈdeɪtə/", "pron": "uh-NON-i-myze DAY-tuh", "fr": "anonymiser les données", "def": "To remove identifying information from data.", "ex": "Researchers anonymise data before publication."}, {"term": "to encrypt data", "ipa": "/ɪnˈkrɪpt ˈdeɪtə/", "pron": "in-KRIPT DAY-tuh", "fr": "chiffrer les données", "def": "To protect data by converting it into unreadable form.", "ex": "Companies should encrypt data in transit and at rest."}, {"term": "to report a data breach", "ipa": "/rɪˈpɔːt ə ˈdeɪtə briːtʃ/", "pron": "ri-PORT uh DAY-tuh breech", "fr": "signaler une violation de données", "def": "To inform authorities or users that data has been exposed.", "ex": "Organisations may have to report a data breach within a strict deadline."}, {"term": "to comply with GDPR", "ipa": "/kəmˈplaɪ wɪð ˌdʒiː diː piː ˈɑː/", "pron": "kuhm-PLY with jee-dee-pee-ar", "fr": "se conformer au RGPD", "def": "To follow GDPR rules.", "ex": "Companies operating in Europe must comply with GDPR."}, {"term": "to exercise one’s rights", "ipa": "/ˈeksəsaɪz wʌnz ˈraɪts/", "pron": "EK-suh-syze wunz rites", "fr": "exercer ses droits", "def": "To use legal rights such as access, deletion or objection.", "ex": "Users can exercise their rights under data protection law."}, {"term": "to request data deletion", "ipa": "/rɪˈkwest ˈdeɪtə dɪˌliːʃən/", "pron": "ri-KWEST DAY-tuh di-LEE-shuhn", "fr": "demander la suppression des données", "def": "To ask an organisation to delete personal data.", "ex": "A user may request data deletion after closing an account."}, {"term": "to balance privacy and security", "ipa": "/ˈbæləns ˈprɪvəsi ənd sɪˈkjʊərəti/", "pron": "BAL-uhns PRIV-uh-see and si-KYOOR-uh-tee", "fr": "équilibrer vie privée et sécurité", "def": "To protect both private life and public safety.", "ex": "Governments must balance privacy and security."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p7c63", "part": 7, "chapter": 63, "title": "Cybersecurity", "file": "cpge_vocab_part7_chapter63_cybersecurity_premium.html", "count": 148, "sections": [{"title": "A. Core cybersecurity concepts and threat actors", "entries": [{"term": "cybersecurity", "ipa": "/ˌsaɪbə sɪˈkjʊərəti/", "pron": "SY-buh si-KYOOR-uh-tee", "fr": "cybersécurité", "def": "The protection of computer systems, networks, devices and data from digital attacks or misuse.", "ex": "Cybersecurity is now a national security and business priority."}, {"term": "cybersecurity threat", "ipa": "/ˌsaɪbə sɪˈkjʊərəti θret/", "pron": "SY-buh si-KYOOR-uh-tee thret", "fr": "menace de cybersécurité", "def": "A danger to digital systems, networks or data.", "ex": "Ransomware is a major cybersecurity threat."}, {"term": "cyber threat", "ipa": "/ˈsaɪbə θret/", "pron": "SY-buh thret", "fr": "cybermenace", "def": "A possible malicious action targeting digital systems.", "ex": "Cyber threats can come from criminals, states or insiders."}, {"term": "cyber risk", "ipa": "/ˈsaɪbə rɪsk/", "pron": "SY-buh risk", "fr": "cyber-risque", "def": "The likelihood and impact of harm caused by cyber incidents.", "ex": "Companies must assess cyber risk before launching new services."}, {"term": "cyberattack", "ipa": "/ˈsaɪbərətæk/", "pron": "SY-buh-uh-tak", "fr": "cyberattaque", "def": "A malicious attempt to damage, disrupt or gain unauthorised access to digital systems.", "ex": "A cyberattack can paralyse hospitals, banks or public services."}, {"term": "cyber incident", "ipa": "/ˈsaɪbər ˌɪnsɪdənt/", "pron": "SY-buh IN-si-duhnt", "fr": "incident cyber", "def": "An event that threatens the confidentiality, integrity or availability of systems or data.", "ex": "A cyber incident must be investigated quickly."}, {"term": "data breach", "ipa": "/ˈdeɪtə briːtʃ/", "pron": "DAY-tuh breech", "fr": "violation de données", "def": "Unauthorised access to or exposure of personal or confidential data.", "ex": "A data breach can damage trust and trigger fines."}, {"term": "security breach", "ipa": "/sɪˈkjʊərəti briːtʃ/", "pron": "si-KYOOR-uh-tee breech", "fr": "faille de sécurité", "def": "A failure allowing unauthorised access to a system or network.", "ex": "The security breach exposed customer records."}, {"term": "vulnerability", "ipa": "/ˌvʌlnərəˈbɪləti/", "pron": "vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité", "def": "A weakness in software, hardware, processes or behaviour that attackers can exploit.", "ex": "Unpatched software can create a vulnerability."}, {"term": "exploit", "ipa": "/ˈeksplɔɪt/", "pron": "EK-sployt", "fr": "exploit", "def": "Code or a technique used to take advantage of a vulnerability.", "ex": "Hackers used an exploit to access the system."}, {"term": "zero-day vulnerability", "ipa": "/ˌzɪərəʊ deɪ ˌvʌlnərəˈbɪləti/", "pron": "ZEER-oh-day vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité zero-day", "def": "A vulnerability unknown to the vendor and therefore not yet patched.", "ex": "Zero-day vulnerabilities are valuable to criminal groups and intelligence agencies."}, {"term": "zero-day exploit", "ipa": "/ˌzɪərəʊ deɪ ˈeksplɔɪt/", "pron": "ZEER-oh-day EK-sployt", "fr": "exploit zero-day", "def": "An exploit targeting a vulnerability before a fix is available.", "ex": "A zero-day exploit can be extremely dangerous."}, {"term": "patch", "ipa": "/pætʃ/", "pron": "patch", "fr": "correctif ; patch", "def": "A software update fixing a bug or vulnerability.", "ex": "Installing a security patch can prevent attacks."}, {"term": "software update", "ipa": "/ˈsɒftweər ˌʌpdeɪt/", "pron": "SOFT-wair UP-dayt", "fr": "mise à jour logicielle", "def": "A new version of software that improves function or security.", "ex": "Regular software updates reduce security risks."}, {"term": "patch management", "ipa": "/ˈpætʃ ˌmænɪdʒmənt/", "pron": "PATCH MAN-ij-muhnt", "fr": "gestion des correctifs", "def": "The process of identifying, testing and installing software patches.", "ex": "Patch management is essential for large organisations."}, {"term": "attack surface", "ipa": "/əˈtæk ˌsɜːfɪs/", "pron": "uh-TAK SUR-fis", "fr": "surface d’attaque", "def": "All the possible points where an attacker could enter or affect a system.", "ex": "Remote work expanded the attack surface."}, {"term": "threat actor", "ipa": "/ˈθret ˌæktə/", "pron": "thret AK-tuh", "fr": "acteur malveillant ; acteur de menace", "def": "A person, group or state responsible for a cyber threat or attack.", "ex": "Threat actors may be financially or politically motivated."}, {"term": "malicious actor", "ipa": "/məˈlɪʃəs ˈæktə/", "pron": "muh-LISH-uhs AK-tuh", "fr": "acteur malveillant", "def": "A person or group acting with harmful intent.", "ex": "Malicious actors target weak passwords."}, {"term": "hacker", "ipa": "/ˈhækə/", "pron": "HAK-uh", "fr": "hacker ; pirate informatique", "def": "A person skilled at using computers, sometimes legally, sometimes maliciously.", "ex": "Not every hacker is a criminal."}, {"term": "ethical hacker", "ipa": "/ˌeθɪkəl ˈhækə/", "pron": "ETH-i-kuhl HAK-uh", "fr": "hacker éthique", "def": "A security professional authorised to find vulnerabilities.", "ex": "Ethical hackers help organisations improve security."}, {"term": "black-hat hacker", "ipa": "/ˌblæk hæt ˈhækə/", "pron": "black-hat HAK-uh", "fr": "hacker malveillant", "def": "A hacker who breaks into systems illegally or maliciously.", "ex": "Black-hat hackers may steal data or money."}, {"term": "white-hat hacker", "ipa": "/ˌwaɪt hæt ˈhækə/", "pron": "white-hat HAK-uh", "fr": "hacker éthique", "def": "A hacker who works legally to improve security.", "ex": "White-hat hackers report vulnerabilities responsibly."}, {"term": "insider threat", "ipa": "/ˌɪnˈsaɪdə θret/", "pron": "in-SY-duh thret", "fr": "menace interne", "def": "A security risk caused by someone inside an organisation.", "ex": "An insider threat may be malicious or accidental."}, {"term": "cybercriminal", "ipa": "/ˌsaɪbəˈkrɪmɪnəl/", "pron": "SY-buh-KRIM-i-nuhl", "fr": "cybercriminel", "def": "A person who commits crimes using digital tools.", "ex": "Cybercriminals often target weakly protected organisations."}, {"term": "cybercrime", "ipa": "/ˈsaɪbəkraɪm/", "pron": "SY-buh-kryme", "fr": "cybercriminalité", "def": "Crime committed through or against computer systems.", "ex": "Cybercrime has become highly professionalised."}, {"term": "organised cybercrime", "ipa": "/ˌɔːɡənaɪzd ˈsaɪbəkraɪm/", "pron": "OR-guh-nyzd SY-buh-kryme", "fr": "cybercriminalité organisée", "def": "Cybercrime carried out by structured criminal groups.", "ex": "Organised cybercrime can operate like a business."}, {"term": "ransomware", "ipa": "/ˈrænsəmweə/", "pron": "RAN-suhm-wair", "fr": "rançongiciel", "def": "Malware that encrypts or blocks data until a ransom is paid.", "ex": "Ransomware attacks can shut down hospitals and schools."}]}, {"title": "B. Malware, phishing, identity theft and authentication", "entries": [{"term": "ransom", "ipa": "/ˈrænsəm/", "pron": "RAN-suhm", "fr": "rançon", "def": "Money demanded to restore access or stop harm.", "ex": "The attackers demanded a ransom in cryptocurrency."}, {"term": "malware", "ipa": "/ˈmælweə/", "pron": "MAL-wair", "fr": "logiciel malveillant", "def": "Malicious software designed to damage, disrupt or access systems.", "ex": "Malware can steal data or spy on users."}, {"term": "spyware", "ipa": "/ˈspaɪweə/", "pron": "SPY-wair", "fr": "logiciel espion", "def": "Malware designed to secretly monitor activity or collect data.", "ex": "Spyware can turn a phone into a surveillance tool."}, {"term": "trojan horse", "ipa": "/ˌtrəʊdʒən ˈhɔːs/", "pron": "TROH-juhn horse", "fr": "cheval de Troie", "def": "Malware disguised as legitimate software.", "ex": "A trojan horse may look like a normal app."}, {"term": "worm", "ipa": "/wɜːm/", "pron": "wurm", "fr": "ver informatique", "def": "Malware that spreads automatically across networks.", "ex": "A worm can infect thousands of machines quickly."}, {"term": "virus", "ipa": "/ˈvaɪrəs/", "pron": "VY-ruhs", "fr": "virus informatique", "def": "Malware that attaches to files or programs and spreads when executed.", "ex": "A virus can corrupt files."}, {"term": "botnet", "ipa": "/ˈbɒtnet/", "pron": "BOT-net", "fr": "réseau de bots ; botnet", "def": "A network of infected devices controlled by an attacker.", "ex": "A botnet can launch massive attacks."}, {"term": "phishing", "ipa": "/ˈfɪʃɪŋ/", "pron": "FISH-ing", "fr": "hameçonnage ; phishing", "def": "Fraudulent messages designed to trick people into revealing information or clicking links.", "ex": "Phishing remains one of the most common attack methods."}, {"term": "spear phishing", "ipa": "/ˈspɪə ˌfɪʃɪŋ/", "pron": "SPEER FISH-ing", "fr": "hameçonnage ciblé", "def": "Phishing targeted at a specific person or organisation.", "ex": "Spear phishing often uses personalised information."}, {"term": "whaling", "ipa": "/ˈweɪlɪŋ/", "pron": "WAY-ling", "fr": "hameçonnage de cadres dirigeants", "def": "Phishing targeting senior executives or important figures.", "ex": "Whaling attacks may target CEOs or finance directors."}, {"term": "social engineering", "ipa": "/ˌsəʊʃəl ˌendʒɪˈnɪərɪŋ/", "pron": "SOH-shuhl en-ji-NEER-ing", "fr": "ingénierie sociale", "def": "Manipulating people into revealing information or taking unsafe actions.", "ex": "Social engineering exploits trust and urgency."}, {"term": "scam", "ipa": "/skæm/", "pron": "skam", "fr": "arnaque", "def": "A dishonest scheme to steal money or information.", "ex": "Online scams often imitate trusted brands."}, {"term": "fraud", "ipa": "/frɔːd/", "pron": "fraud", "fr": "fraude", "def": "Deliberate deception for financial or personal gain.", "ex": "Cyber fraud can target bank accounts and identities."}, {"term": "identity theft", "ipa": "/aɪˈdentəti θeft/", "pron": "eye-DEN-tuh-tee theft", "fr": "usurpation d’identité", "def": "Using someone’s personal information fraudulently.", "ex": "Identity theft can follow a data breach."}, {"term": "credential theft", "ipa": "/krɪˈdenʃəl θeft/", "pron": "kri-DEN-shuhl theft", "fr": "vol d’identifiants", "def": "Stealing usernames, passwords or authentication details.", "ex": "Credential theft allows attackers to access accounts."}, {"term": "password", "ipa": "/ˈpɑːswɜːd/", "pron": "PASS-word", "fr": "mot de passe", "def": "A secret word or phrase used to access an account.", "ex": "Weak passwords are easy to guess."}, {"term": "passphrase", "ipa": "/ˈpɑːsfreɪz/", "pron": "PASS-frayz", "fr": "phrase de passe", "def": "A longer phrase used as a password.", "ex": "A passphrase can be stronger and easier to remember."}, {"term": "password manager", "ipa": "/ˈpɑːswɜːd ˌmænɪdʒə/", "pron": "PASS-word MAN-ij-uh", "fr": "gestionnaire de mots de passe", "def": "A tool that stores and generates secure passwords.", "ex": "A password manager helps users avoid reusing passwords."}, {"term": "multi-factor authentication", "ipa": "/ˌmʌlti fæktər ɔːˌθentɪˈkeɪʃən/", "pron": "MUL-tee FAK-tuh aw-then-ti-KAY-shuhn", "fr": "authentification multifacteur", "def": "Authentication requiring multiple verification factors.", "ex": "Multi-factor authentication reduces account takeover."}, {"term": "MFA", "ipa": "/ˌem ef ˈeɪ/", "pron": "em-eff-ay", "fr": "MFA", "def": "Abbreviation for multi-factor authentication.", "ex": "MFA should be enabled on sensitive accounts."}, {"term": "two-factor authentication", "ipa": "/ˌtuː fæktər ɔːˌθentɪˈkeɪʃən/", "pron": "two-FAK-tuh aw-then-ti-KAY-shuhn", "fr": "authentification à deux facteurs", "def": "Authentication requiring two different forms of verification.", "ex": "Two-factor authentication makes phishing less effective."}, {"term": "2FA", "ipa": "/ˌtuː ef ˈeɪ/", "pron": "two-eff-ay", "fr": "2FA", "def": "Abbreviation for two-factor authentication.", "ex": "2FA is a basic security measure."}, {"term": "biometric authentication", "ipa": "/ˌbaɪəʊˈmetrɪk ɔːˌθentɪˈkeɪʃən/", "pron": "by-oh-MET-rik aw-then-ti-KAY-shuhn", "fr": "authentification biométrique", "def": "Authentication using physical traits such as fingerprints or facial features.", "ex": "Biometric authentication is convenient but raises privacy issues."}, {"term": "access control", "ipa": "/ˈækses kənˌtrəʊl/", "pron": "AK-ses kuhn-TROHL", "fr": "contrôle d’accès", "def": "Rules and systems deciding who can access resources.", "ex": "Access control limits damage if an account is compromised."}, {"term": "least privilege", "ipa": "/ˌliːst ˈprɪvəlɪdʒ/", "pron": "least PRIV-uh-lij", "fr": "moindre privilège", "def": "The principle of giving users only the access they need.", "ex": "Least privilege reduces insider and attacker damage."}, {"term": "privileged account", "ipa": "/ˈprɪvəlɪdʒd əˌkaʊnt/", "pron": "PRIV-uh-lijd uh-KOWNT", "fr": "compte à privilèges", "def": "An account with elevated access rights.", "ex": "Privileged accounts require strict protection."}, {"term": "administrator account", "ipa": "/ədˈmɪnɪstreɪtə əˌkaʊnt/", "pron": "ad-MIN-i-stray-tuh uh-KOWNT", "fr": "compte administrateur", "def": "An account with broad control over systems.", "ex": "Attackers often try to compromise administrator accounts."}, {"term": "firewall", "ipa": "/ˈfaɪəwɔːl/", "pron": "FY-uh-wall", "fr": "pare-feu", "def": "A security system controlling network traffic according to rules.", "ex": "A firewall can block suspicious connections."}, {"term": "antivirus software", "ipa": "/ˈæntiˌvaɪrəs ˈsɒftweə/", "pron": "AN-tee-VY-ruhs SOFT-wair", "fr": "logiciel antivirus", "def": "Software designed to detect and remove malware.", "ex": "Antivirus software is only one layer of defence."}, {"term": "endpoint security", "ipa": "/ˈendpɔɪnt sɪˌkjʊərəti/", "pron": "END-point si-KYOOR-uh-tee", "fr": "sécurité des terminaux", "def": "Security for devices such as laptops, phones and servers.", "ex": "Endpoint security protects devices used by employees."}, {"term": "network security", "ipa": "/ˈnetwɜːk sɪˌkjʊərəti/", "pron": "NET-work si-KYOOR-uh-tee", "fr": "sécurité réseau", "def": "Measures protecting computer networks from threats.", "ex": "Network security includes firewalls and monitoring."}]}, {"title": "C. Defensive tools, monitoring, response and resilience", "entries": [{"term": "cloud security", "ipa": "/ˈklaʊd sɪˌkjʊərəti/", "pron": "cloud si-KYOOR-uh-tee", "fr": "sécurité du cloud", "def": "Security for cloud services, data and infrastructure.", "ex": "Cloud security is shared between provider and customer."}, {"term": "application security", "ipa": "/ˌæplɪˈkeɪʃən sɪˌkjʊərəti/", "pron": "ap-li-KAY-shuhn si-KYOOR-uh-tee", "fr": "sécurité applicative", "def": "Security practices protecting software applications.", "ex": "Application security must be considered during development."}, {"term": "secure coding", "ipa": "/sɪˌkjʊə ˈkəʊdɪŋ/", "pron": "si-KYOOR KOH-ding", "fr": "codage sécurisé", "def": "Writing software in ways that reduce vulnerabilities.", "ex": "Secure coding prevents common attacks."}, {"term": "penetration testing", "ipa": "/ˌpenɪˈtreɪʃən ˈtestɪŋ/", "pron": "pen-i-TRAY-shuhn TEST-ing", "fr": "test d’intrusion", "def": "Authorised testing of systems by simulating attacks.", "ex": "Penetration testing finds weaknesses before criminals do."}, {"term": "pen test", "ipa": "/ˈpen test/", "pron": "pen test", "fr": "test d’intrusion", "def": "Short form of penetration test.", "ex": "A pen test revealed several security gaps."}, {"term": "vulnerability assessment", "ipa": "/ˌvʌlnərəˈbɪləti əˌsesmənt/", "pron": "vul-nuh-ruh-BIL-uh-tee uh-SESS-muhnt", "fr": "évaluation des vulnérabilités", "def": "A systematic review of weaknesses in systems or processes.", "ex": "A vulnerability assessment should be repeated regularly."}, {"term": "security audit", "ipa": "/sɪˈkjʊərəti ˌɔːdɪt/", "pron": "si-KYOOR-uh-tee AW-dit", "fr": "audit de sécurité", "def": "A review checking whether security controls are effective.", "ex": "A security audit can reveal compliance problems."}, {"term": "security monitoring", "ipa": "/sɪˈkjʊərəti ˈmɒnɪtərɪŋ/", "pron": "si-KYOOR-uh-tee MON-i-tuh-ring", "fr": "surveillance de sécurité", "def": "Continuous observation of systems for suspicious activity.", "ex": "Security monitoring helps detect attacks early."}, {"term": "intrusion detection system", "ipa": "/ɪnˈtruːʒən dɪˌtekʃən ˈsɪstəm/", "pron": "in-TROO-zhuhn di-TEK-shuhn SIS-tuhm", "fr": "système de détection d’intrusion", "def": "A system that identifies suspicious network or system activity.", "ex": "An intrusion detection system can alert security teams."}, {"term": "IDS", "ipa": "/ˌaɪ diː ˈes/", "pron": "eye-dee-ess", "fr": "IDS", "def": "Abbreviation for intrusion detection system.", "ex": "An IDS detects potential attacks."}, {"term": "intrusion prevention system", "ipa": "/ɪnˈtruːʒən prɪˌvenʃən ˈsɪstəm/", "pron": "in-TROO-zhuhn pri-VEN-shuhn SIS-tuhm", "fr": "système de prévention d’intrusion", "def": "A system that blocks detected suspicious activity.", "ex": "An intrusion prevention system can stop malicious traffic."}, {"term": "IPS", "ipa": "/ˌaɪ piː ˈes/", "pron": "eye-pee-ess", "fr": "IPS", "def": "Abbreviation for intrusion prevention system.", "ex": "An IPS can automatically block attacks."}, {"term": "security operations centre", "ipa": "/sɪˌkjʊərəti ˌɒpəˈreɪʃənz ˈsentə/", "pron": "si-KYOOR-uh-tee op-uh-RAY-shuhnz SEN-tuh", "fr": "centre opérationnel de sécurité", "def": "A team and facility monitoring and responding to security incidents.", "ex": "A security operations centre monitors threats around the clock."}, {"term": "SOC", "ipa": "/ˌes əʊ ˈsiː/", "pron": "ess-oh-see", "fr": "SOC", "def": "Abbreviation for security operations centre.", "ex": "The SOC detected unusual network activity."}, {"term": "incident response", "ipa": "/ˈɪnsɪdənt rɪˌspɒns/", "pron": "IN-si-duhnt ri-SPONS", "fr": "réponse à incident", "def": "Actions taken to detect, contain and recover from a cyber incident.", "ex": "Incident response plans reduce panic during attacks."}, {"term": "incident response plan", "ipa": "/ˈɪnsɪdənt rɪˌspɒns plæn/", "pron": "IN-si-duhnt ri-SPONS plan", "fr": "plan de réponse à incident", "def": "A written plan for handling cyber incidents.", "ex": "Every organisation needs an incident response plan."}, {"term": "forensics", "ipa": "/fəˈrensɪks/", "pron": "fuh-REN-siks", "fr": "investigation numérique ; criminalistique numérique", "def": "The investigation of digital evidence after an incident or crime.", "ex": "Digital forensics can identify how attackers entered."}, {"term": "digital forensics", "ipa": "/ˌdɪdʒɪtəl fəˈrensɪks/", "pron": "DIJ-i-tuhl fuh-REN-siks", "fr": "forensique numérique", "def": "Forensic investigation of digital systems, devices or data.", "ex": "Digital forensics supports legal investigations."}, {"term": "log file", "ipa": "/ˈlɒɡ faɪl/", "pron": "log file", "fr": "journal ; fichier log", "def": "A record of system events and activities.", "ex": "Log files help investigators reconstruct an attack."}, {"term": "backup", "ipa": "/ˈbækʌp/", "pron": "BAK-up", "fr": "sauvegarde", "def": "A copy of data kept for recovery.", "ex": "Reliable backups are crucial against ransomware."}, {"term": "offline backup", "ipa": "/ˌɒflaɪn ˈbækʌp/", "pron": "OFF-line BAK-up", "fr": "sauvegarde hors ligne", "def": "A backup disconnected from the network.", "ex": "Offline backups are harder for ransomware to encrypt."}, {"term": "disaster recovery", "ipa": "/dɪˌzɑːstə rɪˈkʌvəri/", "pron": "di-ZAS-tuh ri-KUV-uh-ree", "fr": "reprise après sinistre", "def": "Restoring systems and operations after a major incident.", "ex": "Disaster recovery planning reduces downtime."}, {"term": "business continuity", "ipa": "/ˌbɪznəs ˌkɒntɪˈnjuːəti/", "pron": "BIZ-nuhs kon-ti-NYOO-uh-tee", "fr": "continuité d’activité", "def": "Maintaining essential operations during and after a disruption.", "ex": "Business continuity matters after cyberattacks."}, {"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability to withstand and recover from attacks or disruptions.", "ex": "Cyber resilience is more realistic than perfect security."}, {"term": "cyber resilience", "ipa": "/ˈsaɪbə rɪˈzɪliəns/", "pron": "SY-buh ri-ZIL-ee-uhns", "fr": "cyber-résilience", "def": "The ability of digital systems and organisations to resist, respond and recover.", "ex": "Cyber resilience requires preparation, backups and training."}, {"term": "encryption", "ipa": "/ɪnˈkrɪpʃən/", "pron": "in-KRIP-shuhn", "fr": "chiffrement", "def": "Protecting data by making it unreadable without a key.", "ex": "Encryption protects sensitive information."}, {"term": "end-to-end encryption", "ipa": "/ˌend tuː end ɪnˈkrɪpʃən/", "pron": "end-to-end in-KRIP-shuhn", "fr": "chiffrement de bout en bout", "def": "Encryption where only sender and receiver can read messages.", "ex": "End-to-end encryption protects private communication."}, {"term": "public key", "ipa": "/ˌpʌblɪk ˈkiː/", "pron": "PUB-lik key", "fr": "clé publique", "def": "A cryptographic key that can be shared publicly.", "ex": "A public key is used in encrypted communication."}, {"term": "private key", "ipa": "/ˌpraɪvət ˈkiː/", "pron": "PRY-vuht key", "fr": "clé privée", "def": "A cryptographic key that must be kept secret.", "ex": "If a private key is stolen, security is compromised."}, {"term": "certificate", "ipa": "/səˈtɪfɪkət/", "pron": "suh-TIF-i-kuht", "fr": "certificat", "def": "A digital document proving identity or enabling secure communication.", "ex": "A website certificate supports encrypted browsing."}, {"term": "VPN", "ipa": "/ˌviː piː ˈen/", "pron": "vee-pee-en", "fr": "VPN ; réseau privé virtuel", "def": "Virtual private network, a tool creating an encrypted connection through another network.", "ex": "A VPN can protect traffic on public Wi-Fi."}, {"term": "secure connection", "ipa": "/sɪˌkjʊə kəˈnekʃən/", "pron": "si-KYOOR kuh-NEK-shuhn", "fr": "connexion sécurisée", "def": "A protected connection between devices or services.", "ex": "Online banking requires a secure connection."}, {"term": "HTTPS", "ipa": "/ˌeɪtʃ tiː tiː piː ˈes/", "pron": "aych-tee-tee-pee-ess", "fr": "HTTPS", "def": "Secure version of HTTP used for encrypted web communication.", "ex": "HTTPS helps protect data sent to websites."}, {"term": "DDoS attack", "ipa": "/ˌdiː dɒs əˈtæk/", "pron": "dee-doss uh-TAK", "fr": "attaque DDoS ; déni de service distribué", "def": "Distributed denial-of-service attack that overwhelms a service with traffic.", "ex": "A DDoS attack can take a website offline."}, {"term": "denial-of-service attack", "ipa": "/dɪˌnaɪəl əv ˈsɜːvɪs əˌtæk/", "pron": "di-NY-uhl ov SUR-vis uh-TAK", "fr": "attaque par déni de service", "def": "An attack designed to make a service unavailable.", "ex": "A denial-of-service attack disrupts access for users."}, {"term": "man-in-the-middle attack", "ipa": "/ˌmæn ɪn ðə ˈmɪdəl əˌtæk/", "pron": "man-in-thuh-MID-uhl uh-TAK", "fr": "attaque de l’homme du milieu", "def": "An attack where a third party intercepts communication between two parties.", "ex": "A man-in-the-middle attack can steal login details."}, {"term": "SQL injection", "ipa": "/ˌes kjuː ˈel ɪnˌdʒekʃən/", "pron": "ess-kyoo-EL in-JEK-shuhn", "fr": "injection SQL", "def": "An attack injecting malicious database commands into an application.", "ex": "SQL injection can expose entire databases."}, {"term": "cross-site scripting", "ipa": "/ˌkrɒs saɪt ˈskrɪptɪŋ/", "pron": "cross-site SKRIP-ting", "fr": "script intersite ; XSS", "def": "An attack injecting malicious scripts into trusted websites.", "ex": "Cross-site scripting can steal session cookies."}, {"term": "XSS", "ipa": "/ˌeks es ˈes/", "pron": "eks-ess-ess", "fr": "XSS", "def": "Abbreviation for cross-site scripting.", "ex": "XSS is a common web security vulnerability."}, {"term": "supply-chain attack", "ipa": "/səˈplaɪ tʃeɪn əˌtæk/", "pron": "suh-PLY chayn uh-TAK", "fr": "attaque de la chaîne d’approvisionnement", "def": "An attack that compromises software, hardware or services through a supplier.", "ex": "Supply-chain attacks can affect many customers at once."}]}, {"title": "D. Encryption, attack methods, cyberwarfare and governance", "entries": [{"term": "third-party risk", "ipa": "/ˌθɜːd pɑːti ˈrɪsk/", "pron": "third-PAR-tee risk", "fr": "risque tiers", "def": "Risk created by suppliers, vendors or external partners.", "ex": "Third-party risk must be assessed in cybersecurity."}, {"term": "vendor", "ipa": "/ˈvendə/", "pron": "VEN-duh", "fr": "fournisseur", "def": "A supplier of products or services.", "ex": "A vendor’s weak security can create risks."}, {"term": "software supply chain", "ipa": "/ˈsɒftweə səˌplaɪ tʃeɪn/", "pron": "SOFT-wair suh-PLY chayn", "fr": "chaîne d’approvisionnement logicielle", "def": "The components, tools and vendors involved in software development and delivery.", "ex": "The software supply chain can include open-source libraries."}, {"term": "open-source dependency", "ipa": "/ˌəʊpən sɔːs dɪˈpendənsi/", "pron": "OH-puhn source di-PEN-duhn-see", "fr": "dépendance open source", "def": "An external open-source component used by software.", "ex": "Open-source dependencies must be monitored for vulnerabilities."}, {"term": "nation-state actor", "ipa": "/ˌneɪʃən steɪt ˈæktə/", "pron": "NAY-shuhn-state AK-tuh", "fr": "acteur étatique", "def": "A cyber actor linked to a government.", "ex": "Nation-state actors may conduct espionage or sabotage."}, {"term": "state-sponsored attack", "ipa": "/ˌsteɪt ˈspɒnsəd əˌtæk/", "pron": "state SPON-suhd uh-TAK", "fr": "cyberattaque soutenue par un État", "def": "A cyberattack supported or directed by a government.", "ex": "State-sponsored attacks often target critical infrastructure."}, {"term": "cyber espionage", "ipa": "/ˌsaɪbər ˈespiənɑːʒ/", "pron": "SY-buh ES-pee-uh-nahzh", "fr": "cyberespionnage", "def": "Spying using digital tools or cyber operations.", "ex": "Cyber espionage targets governments, companies and researchers."}, {"term": "cyber warfare", "ipa": "/ˈsaɪbə ˌwɔːfeə/", "pron": "SY-buh WAR-fair", "fr": "cyberguerre", "def": "Use of cyber operations as part of military or strategic conflict.", "ex": "Cyber warfare can disrupt communications and infrastructure."}, {"term": "hybrid warfare", "ipa": "/ˌhaɪbrɪd ˈwɔːfeə/", "pron": "HY-brid WAR-fair", "fr": "guerre hybride", "def": "Conflict combining military, cyber, information and economic tools.", "ex": "Cyberattacks are often part of hybrid warfare."}, {"term": "critical infrastructure", "ipa": "/ˌkrɪtɪkəl ˈɪnfrəˌstrʌktʃə/", "pron": "KRIT-i-kuhl IN-fruh-struk-chuh", "fr": "infrastructures critiques", "def": "Essential systems such as energy, water, health, transport and communications.", "ex": "Critical infrastructure is a prime target for cyberattacks."}, {"term": "power grid", "ipa": "/ˈpaʊə ɡrɪd/", "pron": "POW-uh grid", "fr": "réseau électrique", "def": "The network delivering electricity.", "ex": "A cyberattack on the power grid could have severe consequences."}, {"term": "hospital network", "ipa": "/ˈhɒspɪtəl ˌnetwɜːk/", "pron": "HOS-pi-tuhl NET-work", "fr": "réseau hospitalier", "def": "Digital systems used by hospitals and healthcare providers.", "ex": "Hospital networks are vulnerable to ransomware."}, {"term": "public services", "ipa": "/ˌpʌblɪk ˈsɜːvɪsɪz/", "pron": "PUB-lik SUR-vis-iz", "fr": "services publics", "def": "Services provided by government or public bodies.", "ex": "Cyberattacks can disrupt public services."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "Protection of a country’s safety and vital interests.", "ex": "Cybersecurity is part of national security."}, {"term": "cyber deterrence", "ipa": "/ˈsaɪbə dɪˈterəns/", "pron": "SY-buh di-TERR-uhns", "fr": "cyberdissuasion", "def": "Preventing cyberattacks by threatening consequences or increasing resilience.", "ex": "Cyber deterrence is difficult because attribution can be uncertain."}, {"term": "attribution", "ipa": "/ˌætrɪˈbjuːʃən/", "pron": "at-ri-BYOO-shuhn", "fr": "attribution", "def": "Identifying who is responsible for a cyberattack.", "ex": "Attribution is often politically and technically difficult."}, {"term": "retaliation", "ipa": "/rɪˌtæliˈeɪʃən/", "pron": "ri-tal-ee-AY-shuhn", "fr": "représailles", "def": "A response intended to punish an attack.", "ex": "Cyber retaliation can risk escalation."}, {"term": "escalation", "ipa": "/ˌeskəˈleɪʃən/", "pron": "es-kuh-LAY-shuhn", "fr": "escalade", "def": "An increase in tension or conflict.", "ex": "Cyber incidents can contribute to escalation between states."}, {"term": "cyber diplomacy", "ipa": "/ˈsaɪbə dɪˌpləʊməsi/", "pron": "SY-buh di-PLOH-muh-see", "fr": "cyberdiplomatie", "def": "Diplomacy focused on cyber norms, cooperation and conflict prevention.", "ex": "Cyber diplomacy aims to reduce dangerous behaviour online."}, {"term": "cyber norms", "ipa": "/ˈsaɪbə nɔːmz/", "pron": "SY-buh normz", "fr": "normes cyber", "def": "Shared expectations about acceptable behaviour in cyberspace.", "ex": "International cyber norms remain contested."}, {"term": "cyberspace", "ipa": "/ˈsaɪbəspeɪs/", "pron": "SY-buh-space", "fr": "cyberespace", "def": "The digital environment of networks, systems and online activity.", "ex": "Cyberspace has become a domain of conflict."}, {"term": "digital sovereignty", "ipa": "/ˌdɪdʒɪtəl ˈsɒvrənti/", "pron": "DIJ-i-tuhl SOV-ruhn-tee", "fr": "souveraineté numérique", "def": "A state’s ability to control digital infrastructure, data and technology.", "ex": "Cybersecurity is central to digital sovereignty."}, {"term": "data sovereignty", "ipa": "/ˈdeɪtə ˈsɒvrənti/", "pron": "DAY-tuh SOV-ruhn-tee", "fr": "souveraineté des données", "def": "The idea that data is subject to local laws and control.", "ex": "Data sovereignty shapes cloud security debates."}, {"term": "cyber insurance", "ipa": "/ˈsaɪbər ɪnˌʃʊərəns/", "pron": "SY-buh in-SHOR-uhns", "fr": "cyberassurance", "def": "Insurance covering losses from cyber incidents.", "ex": "Cyber insurance can encourage better risk management."}, {"term": "security awareness", "ipa": "/sɪˈkjʊərəti əˌweənəs/", "pron": "si-KYOOR-uh-tee uh-WAIR-nuhs", "fr": "sensibilisation à la sécurité", "def": "Knowledge of security risks and safe behaviour.", "ex": "Security awareness training helps prevent phishing."}, {"term": "security training", "ipa": "/sɪˈkjʊərəti ˈtreɪnɪŋ/", "pron": "si-KYOOR-uh-tee TRAY-ning", "fr": "formation à la sécurité", "def": "Training employees to recognise and reduce security risks.", "ex": "Security training should be practical and repeated."}, {"term": "cyber hygiene", "ipa": "/ˈsaɪbə ˈhaɪdʒiːn/", "pron": "SY-buh HY-jeen", "fr": "hygiène numérique", "def": "Basic safe practices such as updates, strong passwords and backups.", "ex": "Good cyber hygiene prevents many attacks."}, {"term": "risk assessment", "ipa": "/ˈrɪsk əˌsesmənt/", "pron": "risk uh-SESS-muhnt", "fr": "évaluation des risques", "def": "Evaluation of possible risks and their impact.", "ex": "Risk assessment helps prioritise security measures."}, {"term": "risk management", "ipa": "/ˈrɪsk ˌmænɪdʒmənt/", "pron": "risk MAN-ij-muhnt", "fr": "gestion des risques", "def": "Identifying, reducing and monitoring risks.", "ex": "Cybersecurity is a continuous risk management process."}, {"term": "compliance", "ipa": "/kəmˈplaɪəns/", "pron": "kuhm-PLY-uhns", "fr": "conformité", "def": "Respect for laws, rules or standards.", "ex": "Compliance does not guarantee real security."}, {"term": "security standard", "ipa": "/sɪˈkjʊərəti ˈstændəd/", "pron": "si-KYOOR-uh-tee STAN-duhd", "fr": "norme de sécurité", "def": "A recognised set of security requirements or best practices.", "ex": "Security standards help organisations structure their defences."}, {"term": "NIS2 Directive", "ipa": "/ˌen aɪ es ˈtuː dəˈrektɪv/", "pron": "en-eye-ess-two di-REK-tiv", "fr": "directive NIS2", "def": "EU cybersecurity law strengthening security and incident-reporting obligations.", "ex": "The NIS2 Directive increases obligations for essential sectors."}, {"term": "zero trust", "ipa": "/ˌzɪərəʊ ˈtrʌst/", "pron": "ZEER-oh trust", "fr": "confiance zéro ; zero trust", "def": "A security model that never automatically trusts users or devices.", "ex": "Zero trust assumes breaches can happen."}, {"term": "defence in depth", "ipa": "/dɪˌfens ɪn ˈdepθ/", "pron": "di-FENS in depth", "fr": "défense en profondeur", "def": "A layered security strategy using multiple protections.", "ex": "Defence in depth limits the impact of one failed control."}, {"term": "to protect systems", "ipa": "/prəˈtekt ˈsɪstəmz/", "pron": "pruh-TEKT SIS-tuhmz", "fr": "protéger les systèmes", "def": "To keep digital systems safe from attacks or misuse.", "ex": "Organisations must protect systems from evolving threats."}, {"term": "to detect threats", "ipa": "/dɪˈtekt θrets/", "pron": "di-TEKT threats", "fr": "détecter les menaces", "def": "To identify potential attacks or suspicious activity.", "ex": "Monitoring tools help detect threats."}, {"term": "to prevent attacks", "ipa": "/prɪˈvent əˈtæks/", "pron": "pri-VENT uh-TAKS", "fr": "prévenir les attaques", "def": "To stop attacks before they succeed.", "ex": "Good cyber hygiene can prevent attacks."}, {"term": "to respond to an incident", "ipa": "/rɪˈspɒnd tuː ən ˈɪnsɪdənt/", "pron": "ri-SPOND to an IN-si-duhnt", "fr": "répondre à un incident", "def": "To take action after a cyber incident is detected.", "ex": "Teams must respond to an incident quickly."}, {"term": "to contain a breach", "ipa": "/kənˈteɪn ə briːtʃ/", "pron": "kuhn-TAYN uh breech", "fr": "contenir une violation", "def": "To stop a breach from spreading or causing more harm.", "ex": "The first priority is to contain a breach."}, {"term": "to recover data", "ipa": "/rɪˈkʌvə ˈdeɪtə/", "pron": "ri-KUV-uh DAY-tuh", "fr": "récupérer des données", "def": "To restore lost or damaged data.", "ex": "Backups help recover data after ransomware."}, {"term": "to patch a vulnerability", "ipa": "/pætʃ ə ˌvʌlnərəˈbɪləti/", "pron": "patch uh vul-nuh-ruh-BIL-uh-tee", "fr": "corriger une vulnérabilité", "def": "To fix a security weakness with an update.", "ex": "Companies must patch a vulnerability before attackers exploit it."}, {"term": "to exploit a weakness", "ipa": "/ɪkˈsplɔɪt ə ˈwiːknəs/", "pron": "ik-SPLOYT uh WEEK-nuhs", "fr": "exploiter une faiblesse", "def": "To take advantage of a weakness for attack.", "ex": "Attackers exploit a weakness in outdated software."}, {"term": "to encrypt files", "ipa": "/ɪnˈkrɪpt faɪlz/", "pron": "in-KRIPT filez", "fr": "chiffrer des fichiers", "def": "To protect files by converting them into unreadable form.", "ex": "Ransomware encrypts files and demands payment."}, {"term": "to steal credentials", "ipa": "/stiːl krɪˈdenʃəlz/", "pron": "steel kri-DEN-shuhlz", "fr": "voler des identifiants", "def": "To take usernames, passwords or login details.", "ex": "Phishing is used to steal credentials."}, {"term": "to launch a ransomware attack", "ipa": "/lɔːntʃ ə ˈrænsəmweər əˌtæk/", "pron": "launch uh RAN-suhm-wair uh-TAK", "fr": "lancer une attaque par rançongiciel", "def": "To begin an attack using ransomware.", "ex": "Criminals launched a ransomware attack on the hospital."}, {"term": "to compromise an account", "ipa": "/ˈkɒmprəmaɪz ən əˌkaʊnt/", "pron": "KOM-pruh-myze an uh-KOWNT", "fr": "compromettre un compte", "def": "To gain unauthorised access to an account.", "ex": "A weak password can compromise an account."}, {"term": "to back up data", "ipa": "/bæk ʌp ˈdeɪtə/", "pron": "back-up DAY-tuh", "fr": "sauvegarder des données", "def": "To make a copy of data for recovery.", "ex": "Users should back up data regularly."}, {"term": "to strengthen cyber resilience", "ipa": "/ˈstreŋθən ˈsaɪbə rɪˈzɪliəns/", "pron": "STRENG-thuhn SY-buh ri-ZIL-ee-uhns", "fr": "renforcer la cyber-résilience", "def": "To improve the ability to resist and recover from cyber incidents.", "ex": "Training and backups strengthen cyber resilience."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "to report suspicious activity", "ipa": "/rɪˈpɔːt səˈspɪʃəs ækˈtɪvəti/", "pron": "ri-PORT suh-SPISH-uhs ak-TIV-uh-tee", "fr": "signaler une activité suspecte", "def": "To inform security staff about unusual or risky behaviour.", "ex": "Employees should report suspicious activity immediately."}, {"term": "to comply with cybersecurity rules", "ipa": "/kəmˈplaɪ wɪð ˌsaɪbə sɪˈkjʊərəti ruːlz/", "pron": "kuhm-PLY with SY-buh si-KYOOR-uh-tee roolz", "fr": "se conformer aux règles de cybersécurité", "def": "To follow cybersecurity laws, policies or standards.", "ex": "Essential services must comply with cybersecurity rules."}]}]}, {"id": "p7c64", "part": 7, "chapter": 64, "title": "Space Exploration", "file": "cpge_vocab_part7_chapter64_space_exploration_premium.html", "count": 130, "sections": [{"title": "A. Core space exploration and mission vocabulary", "entries": [{"term": "space exploration", "ipa": "/ˌspeɪs ekspləˈreɪʃən/", "pron": "space ek-spluh-RAY-shuhn", "fr": "exploration spatiale", "def": "The investigation of outer space through observation, spacecraft, probes and human missions.", "ex": "Space exploration raises scientific, economic and geopolitical questions."}, {"term": "outer space", "ipa": "/ˌaʊtə ˈspeɪs/", "pron": "OW-tuh space", "fr": "espace extra-atmosphérique", "def": "The region beyond Earth’s atmosphere.", "ex": "Outer space is governed by international treaties."}, {"term": "space race", "ipa": "/ˈspeɪs reɪs/", "pron": "space race", "fr": "course à l’espace", "def": "Competition between states to achieve superiority in space activities.", "ex": "The original space race opposed the United States and the Soviet Union."}, {"term": "new space race", "ipa": "/ˌnjuː ˈspeɪs reɪs/", "pron": "nyoo space race", "fr": "nouvelle course à l’espace", "def": "Contemporary competition between states and private companies in space.", "ex": "The new space race involves China, the United States, India and private firms."}, {"term": "space power", "ipa": "/ˈspeɪs ˌpaʊə/", "pron": "space POW-uh", "fr": "puissance spatiale", "def": "A country with major technological, military or economic capabilities in space.", "ex": "China has become a major space power."}, {"term": "space agency", "ipa": "/ˈspeɪs ˌeɪdʒənsi/", "pron": "space AY-juhn-see", "fr": "agence spatiale", "def": "An organisation responsible for a space programme.", "ex": "NASA and ESA are major space agencies."}, {"term": "NASA", "ipa": "/ˈnæsə/", "pron": "NASS-uh", "fr": "NASA", "def": "The United States space agency.", "ex": "NASA leads many scientific and human spaceflight missions."}, {"term": "ESA", "ipa": "/ˌiː es ˈeɪ/", "pron": "ee-ess-ay", "fr": "ESA ; Agence spatiale européenne", "def": "European Space Agency.", "ex": "ESA coordinates European space missions."}, {"term": "space programme", "ipa": "/ˈspeɪs ˌprəʊɡræm/", "pron": "space PROH-gram", "fr": "programme spatial", "def": "A planned set of space missions, research and technologies.", "ex": "A national space programme can project prestige."}, {"term": "space mission", "ipa": "/ˈspeɪs ˌmɪʃən/", "pron": "space MISH-uhn", "fr": "mission spatiale", "def": "A planned operation involving spacecraft, satellites, astronauts or probes.", "ex": "A space mission requires years of preparation."}, {"term": "launch", "ipa": "/lɔːntʃ/", "pron": "launch", "fr": "lancement", "def": "The act of sending a rocket, spacecraft or satellite into space.", "ex": "A launch can fail within seconds if the rocket malfunctions."}, {"term": "rocket", "ipa": "/ˈrɒkɪt/", "pron": "ROK-it", "fr": "fusée", "def": "A vehicle using powerful engines to travel into space.", "ex": "A rocket must escape Earth’s gravity."}, {"term": "launch vehicle", "ipa": "/ˈlɔːntʃ ˌviːɪkəl/", "pron": "launch VEE-i-kuhl", "fr": "lanceur", "def": "A rocket used to carry payloads into space.", "ex": "A reliable launch vehicle is essential for space access."}, {"term": "payload", "ipa": "/ˈpeɪləʊd/", "pron": "PAY-lohd", "fr": "charge utile", "def": "The cargo carried by a rocket, such as a satellite or probe.", "ex": "The payload was placed into orbit."}, {"term": "spacecraft", "ipa": "/ˈspeɪskrɑːft/", "pron": "SPACE-kraft", "fr": "engin spatial ; vaisseau spatial", "def": "A vehicle designed to travel or operate in space.", "ex": "A spacecraft must survive extreme temperatures."}, {"term": "space probe", "ipa": "/ˈspeɪs prəʊb/", "pron": "space probe", "fr": "sonde spatiale", "def": "An uncrewed spacecraft sent to study planets, moons or deep space.", "ex": "A space probe can send data back from distant worlds."}, {"term": "lander", "ipa": "/ˈlændə/", "pron": "LAN-duh", "fr": "atterrisseur", "def": "A spacecraft designed to land on a planet, moon or asteroid.", "ex": "A lander must slow down safely before touching the surface."}, {"term": "rover", "ipa": "/ˈrəʊvə/", "pron": "ROH-vuh", "fr": "rover ; astromobile", "def": "A robotic vehicle designed to move across a planet or moon.", "ex": "A rover can analyse rocks on Mars."}, {"term": "orbiter", "ipa": "/ˈɔːbɪtə/", "pron": "OR-bi-tuh", "fr": "orbiteur", "def": "A spacecraft designed to orbit a planet, moon or other body.", "ex": "An orbiter can map a planet’s surface."}, {"term": "satellite", "ipa": "/ˈsætəlaɪt/", "pron": "SAT-uh-lyte", "fr": "satellite", "def": "An object placed in orbit around Earth or another body.", "ex": "Satellites are used for communication, navigation and observation."}, {"term": "artificial satellite", "ipa": "/ˌɑːtɪˈfɪʃəl ˈsætəlaɪt/", "pron": "ar-ti-FISH-uhl SAT-uh-lyte", "fr": "satellite artificiel", "def": "A human-made object placed in orbit.", "ex": "Artificial satellites support modern life."}, {"term": "orbit", "ipa": "/ˈɔːbɪt/", "pron": "OR-bit", "fr": "orbite", "def": "The curved path of an object around a planet, star or moon.", "ex": "A satellite can remain in orbit for years."}, {"term": "low Earth orbit", "ipa": "/ˌləʊ ɜːθ ˈɔːbɪt/", "pron": "loh earth OR-bit", "fr": "orbite terrestre basse", "def": "An orbit relatively close to Earth.", "ex": "Low Earth orbit is becoming increasingly crowded."}, {"term": "LEO", "ipa": "/ˌel iː ˈəʊ/", "pron": "el-ee-oh", "fr": "LEO ; orbite basse", "def": "Abbreviation for low Earth orbit.", "ex": "Many internet satellites operate in LEO."}, {"term": "geostationary orbit", "ipa": "/ˌdʒiːəʊˈsteɪʃənəri ˈɔːbɪt/", "pron": "jee-oh-STAY-shuhn-uh-ree OR-bit", "fr": "orbite géostationnaire", "def": "An orbit where a satellite appears fixed above one point on Earth.", "ex": "Weather and communication satellites often use geostationary orbit."}, {"term": "microgravity", "ipa": "/ˌmaɪkrəʊˈɡrævəti/", "pron": "MY-kroh-GRAV-uh-tee", "fr": "microgravité", "def": "A condition in which people or objects appear almost weightless.", "ex": "Astronauts conduct experiments in microgravity."}, {"term": "weightlessness", "ipa": "/ˈweɪtləsnəs/", "pron": "WAIT-luhs-nuhs", "fr": "apesanteur", "def": "The feeling or condition of having no apparent weight.", "ex": "Weightlessness affects muscles and bones."}, {"term": "gravity", "ipa": "/ˈɡrævəti/", "pron": "GRAV-uh-tee", "fr": "gravité", "def": "The force that attracts objects towards each other.", "ex": "Gravity keeps planets in orbit around the Sun."}, {"term": "escape velocity", "ipa": "/ɪˈskeɪp vəˌlɒsəti/", "pron": "i-SKAYP vuh-LOSS-uh-tee", "fr": "vitesse de libération", "def": "The speed needed to escape a celestial body’s gravity.", "ex": "A rocket must reach escape velocity to leave Earth."}, {"term": "re-entry", "ipa": "/ˌriː ˈentri/", "pron": "ree-EN-tree", "fr": "rentrée atmosphérique", "def": "The return of a spacecraft into a planet’s atmosphere.", "ex": "Re-entry creates intense heat."}, {"term": "heat shield", "ipa": "/ˈhiːt ʃiːld/", "pron": "heat sheeld", "fr": "bouclier thermique", "def": "A protective layer preventing a spacecraft from burning during re-entry.", "ex": "The heat shield must survive extreme temperatures."}, {"term": "space station", "ipa": "/ˈspeɪs ˌsteɪʃən/", "pron": "space STAY-shuhn", "fr": "station spatiale", "def": "A large spacecraft where astronauts live and work in orbit.", "ex": "A space station supports long-term research."}, {"term": "International Space Station", "ipa": "/ˌɪntəˈnæʃənəl ˈspeɪs ˌsteɪʃən/", "pron": "IN-tuh-NASH-uh-nuhl space STAY-shuhn", "fr": "Station spatiale internationale", "def": "A multinational research station in low Earth orbit.", "ex": "The International Space Station is a symbol of scientific cooperation."}, {"term": "ISS", "ipa": "/ˌaɪ es ˈes/", "pron": "eye-ess-ess", "fr": "ISS", "def": "Abbreviation for International Space Station.", "ex": "The ISS has hosted astronauts from many countries."}, {"term": "astronaut", "ipa": "/ˈæstrənɔːt/", "pron": "AS-truh-nawt", "fr": "astronaute", "def": "A person trained to travel and work in space.", "ex": "Astronauts must train for emergencies."}]}, {"title": "B. Human spaceflight, commercial space and satellite services", "entries": [{"term": "cosmonaut", "ipa": "/ˈkɒzmənɔːt/", "pron": "KOZ-muh-nawt", "fr": "cosmonaute", "def": "A Russian or Soviet astronaut.", "ex": "The first human in space was a Soviet cosmonaut."}, {"term": "taikonaut", "ipa": "/ˈtaɪkənɔːt/", "pron": "TY-kuh-nawt", "fr": "taïkonaute", "def": "A Chinese astronaut.", "ex": "Chinese taikonauts work on China’s space station."}, {"term": "crew", "ipa": "/kruː/", "pron": "crew", "fr": "équipage", "def": "The group of people operating a spacecraft or mission.", "ex": "The crew spent six months in orbit."}, {"term": "mission control", "ipa": "/ˈmɪʃən kənˌtrəʊl/", "pron": "MISH-uhn kuhn-TROHL", "fr": "centre de contrôle de mission", "def": "The ground team that manages a space mission.", "ex": "Mission control monitors spacecraft systems."}, {"term": "spacewalk", "ipa": "/ˈspeɪswɔːk/", "pron": "SPACE-wawk", "fr": "sortie extravéhiculaire", "def": "An activity outside a spacecraft performed by an astronaut.", "ex": "A spacewalk can last several hours."}, {"term": "spacesuit", "ipa": "/ˈspeɪssuːt/", "pron": "SPACE-soot", "fr": "combinaison spatiale", "def": "A protective suit worn by astronauts in space.", "ex": "A spacesuit provides oxygen and pressure."}, {"term": "life-support system", "ipa": "/ˈlaɪf səˌpɔːt ˌsɪstəm/", "pron": "life-suh-PORT SIS-tuhm", "fr": "système de survie", "def": "A system providing air, water, pressure and temperature control for humans in space.", "ex": "Life-support systems are vital for crewed missions."}, {"term": "crewed mission", "ipa": "/ˌkruːd ˈmɪʃən/", "pron": "krood MISH-uhn", "fr": "mission habitée", "def": "A mission carrying human beings.", "ex": "Crewed missions are expensive and risky."}, {"term": "uncrewed mission", "ipa": "/ˌʌnˈkruːd ˈmɪʃən/", "pron": "un-KROOD MISH-uhn", "fr": "mission non habitée", "def": "A mission without humans on board.", "ex": "Uncrewed missions can explore dangerous environments."}, {"term": "human spaceflight", "ipa": "/ˌhjuːmən ˈspeɪsflaɪt/", "pron": "HYOO-muhn SPACE-flyte", "fr": "vol spatial habité", "def": "Space travel involving human beings.", "ex": "Human spaceflight is often linked to national prestige."}, {"term": "space tourism", "ipa": "/ˈspeɪs ˌtʊərɪzəm/", "pron": "space TOOR-iz-uhm", "fr": "tourisme spatial", "def": "Commercial travel into space for private individuals.", "ex": "Space tourism remains accessible only to the very wealthy."}, {"term": "commercial spaceflight", "ipa": "/kəˌmɜːʃəl ˈspeɪsflaɪt/", "pron": "kuh-MUR-shuhl SPACE-flyte", "fr": "vol spatial commercial", "def": "Space travel or launch services provided by private companies.", "ex": "Commercial spaceflight has reduced launch costs."}, {"term": "private space company", "ipa": "/ˌpraɪvət ˈspeɪs ˌkʌmpəni/", "pron": "PRY-vuht space KUM-puh-nee", "fr": "entreprise spatiale privée", "def": "A private firm involved in space activities.", "ex": "Private space companies now compete with state agencies."}, {"term": "NewSpace", "ipa": "/ˈnjuː speɪs/", "pron": "NYOO-space", "fr": "NewSpace", "def": "The modern private-sector-driven space industry.", "ex": "NewSpace has changed launch markets and satellite deployment."}, {"term": "reusable rocket", "ipa": "/ˌriːˈjuːzəbəl ˈrɒkɪt/", "pron": "ree-YOO-zuh-buhl ROK-it", "fr": "fusée réutilisable", "def": "A rocket designed to be launched, recovered and launched again.", "ex": "Reusable rockets can lower the cost of access to space."}, {"term": "launch cost", "ipa": "/ˈlɔːntʃ kɒst/", "pron": "launch kost", "fr": "coût de lancement", "def": "The cost of sending a payload into space.", "ex": "Lower launch costs make more missions possible."}, {"term": "space industry", "ipa": "/ˈspeɪs ˌɪndəstri/", "pron": "space IN-duh-stree", "fr": "industrie spatiale", "def": "The economic sector producing space technology and services.", "ex": "The space industry includes satellites, rockets and data services."}, {"term": "space economy", "ipa": "/ˈspeɪs iˌkɒnəmi/", "pron": "space i-KON-uh-mee", "fr": "économie spatiale", "def": "Economic activity linked to space technology and services.", "ex": "The space economy is growing quickly."}, {"term": "satellite constellation", "ipa": "/ˈsætəlaɪt ˌkɒnstəˈleɪʃən/", "pron": "SAT-uh-lyte kon-stuh-LAY-shuhn", "fr": "constellation de satellites", "def": "A group of satellites working together as a system.", "ex": "Satellite constellations can provide global internet access."}, {"term": "mega-constellation", "ipa": "/ˌmeɡə ˌkɒnstəˈleɪʃən/", "pron": "MEG-uh kon-stuh-LAY-shuhn", "fr": "méga-constellation", "def": "A very large constellation containing hundreds or thousands of satellites.", "ex": "Mega-constellations raise concerns about space debris."}, {"term": "satellite internet", "ipa": "/ˈsætəlaɪt ˌɪntənet/", "pron": "SAT-uh-lyte IN-tuh-net", "fr": "internet par satellite", "def": "Internet access provided through satellites.", "ex": "Satellite internet can connect remote areas."}, {"term": "Earth observation", "ipa": "/ˌɜːθ ˌɒbzəˈveɪʃən/", "pron": "earth ob-zuh-VAY-shuhn", "fr": "observation de la Terre", "def": "Monitoring Earth from space using satellites.", "ex": "Earth observation helps track climate change and disasters."}, {"term": "remote sensing", "ipa": "/rɪˌməʊt ˈsensɪŋ/", "pron": "ri-MOHT SEN-sing", "fr": "télédétection", "def": "Collecting information from a distance, often through satellites.", "ex": "Remote sensing is used in agriculture, defence and climate science."}, {"term": "weather satellite", "ipa": "/ˈweðə ˌsætəlaɪt/", "pron": "WETH-uh SAT-uh-lyte", "fr": "satellite météorologique", "def": "A satellite used to monitor weather and climate.", "ex": "Weather satellites improve forecasting."}, {"term": "navigation satellite", "ipa": "/ˌnævɪˈɡeɪʃən ˌsætəlaɪt/", "pron": "nav-i-GAY-shuhn SAT-uh-lyte", "fr": "satellite de navigation", "def": "A satellite used to determine position and time.", "ex": "Navigation satellites support transport and logistics."}, {"term": "GPS", "ipa": "/ˌdʒiː piː ˈes/", "pron": "jee-pee-ess", "fr": "GPS", "def": "Global Positioning System, a US satellite navigation system.", "ex": "GPS is essential for navigation and timing."}, {"term": "Galileo", "ipa": "/ˌɡælɪˈleɪəʊ/", "pron": "gal-i-LAY-oh", "fr": "Galileo", "def": "The European satellite navigation system.", "ex": "Galileo strengthens European strategic autonomy."}, {"term": "communication satellite", "ipa": "/kəˌmjuːnɪˈkeɪʃən ˌsætəlaɪt/", "pron": "kuh-myoo-ni-KAY-shuhn SAT-uh-lyte", "fr": "satellite de communication", "def": "A satellite used to transmit signals such as TV, internet or phone data.", "ex": "Communication satellites connect distant regions."}, {"term": "space debris", "ipa": "/ˈspeɪs ˌdebriː/", "pron": "space DEB-ree", "fr": "débris spatiaux", "def": "Defunct satellites, fragments and other objects orbiting Earth.", "ex": "Space debris can damage active satellites."}, {"term": "orbital debris", "ipa": "/ˌɔːbɪtəl ˈdebriː/", "pron": "OR-bi-tuhl DEB-ree", "fr": "débris orbitaux", "def": "Debris orbiting Earth.", "ex": "Orbital debris is a growing safety concern."}, {"term": "space junk", "ipa": "/ˈspeɪs dʒʌŋk/", "pron": "space junk", "fr": "déchets spatiaux", "def": "Informal term for space debris.", "ex": "Space junk can travel at extremely high speeds."}, {"term": "Kessler syndrome", "ipa": "/ˈkeslə ˌsɪndrəʊm/", "pron": "KESS-luh SIN-drohm", "fr": "syndrome de Kessler", "def": "A scenario where collisions create debris that causes more collisions in orbit.", "ex": "Kessler syndrome could make some orbits unusable."}, {"term": "collision avoidance", "ipa": "/kəˈlɪʒən əˌvɔɪdəns/", "pron": "kuh-LIZH-uhn uh-VOYD-uhns", "fr": "évitement de collision", "def": "Actions taken to prevent objects in space from colliding.", "ex": "Satellites may need collision avoidance manoeuvres."}, {"term": "space traffic management", "ipa": "/ˈspeɪs ˈtræfɪk ˌmænɪdʒmənt/", "pron": "space TRAF-ik MAN-ij-muhnt", "fr": "gestion du trafic spatial", "def": "Rules and systems used to manage the movement of objects in orbit.", "ex": "Space traffic management is becoming urgent."}, {"term": "space sustainability", "ipa": "/ˈspeɪs səˌsteɪnəˈbɪləti/", "pron": "space suh-stay-nuh-BIL-uh-tee", "fr": "durabilité spatiale", "def": "Ensuring space activities remain safe and usable for future generations.", "ex": "Space sustainability requires debris mitigation."}, {"term": "debris mitigation", "ipa": "/ˈdebriː ˌmɪtɪˈɡeɪʃən/", "pron": "DEB-ree mit-i-GAY-shuhn", "fr": "atténuation des débris spatiaux", "def": "Measures to reduce the creation of space debris.", "ex": "Debris mitigation includes deorbiting old satellites."}, {"term": "deorbit", "ipa": "/diːˈɔːbɪt/", "pron": "dee-OR-bit", "fr": "désorbiter", "def": "To remove an object from orbit, often so it burns up in the atmosphere.", "ex": "Satellites should deorbit at the end of their life."}, {"term": "space law", "ipa": "/ˈspeɪs lɔː/", "pron": "space law", "fr": "droit spatial", "def": "The body of law governing activities in outer space.", "ex": "Space law must adapt to private companies."}]}, {"title": "C. Space debris, law, security and strategic autonomy", "entries": [{"term": "Outer Space Treaty", "ipa": "/ˌaʊtə ˈspeɪs ˌtriːti/", "pron": "OW-tuh space TREE-tee", "fr": "Traité de l’espace", "def": "The 1967 treaty setting basic principles for peaceful use of outer space.", "ex": "The Outer Space Treaty bans national sovereignty claims in space."}, {"term": "peaceful use of space", "ipa": "/ˌpiːsfəl ˈjuːs əv ˈspeɪs/", "pron": "PEACE-fuhl yooss ov space", "fr": "utilisation pacifique de l’espace", "def": "The principle that space should be used for peaceful purposes.", "ex": "Peaceful use of space is a central legal principle."}, {"term": "weaponisation of space", "ipa": "/ˌwepənaɪˈzeɪʃən əv ˈspeɪs/", "pron": "wep-uh-ny-ZAY-shuhn ov space", "fr": "militarisation armée de l’espace", "def": "The deployment or use of weapons in or from space.", "ex": "The weaponisation of space could destabilise international security."}, {"term": "militarisation of space", "ipa": "/ˌmɪlɪtəraɪˈzeɪʃən əv ˈspeɪs/", "pron": "mil-i-tuh-ry-ZAY-shuhn ov space", "fr": "militarisation de l’espace", "def": "The use of space for military purposes, such as surveillance or navigation.", "ex": "The militarisation of space has already begun through satellites."}, {"term": "anti-satellite weapon", "ipa": "/ˌænti ˈsætəlaɪt ˈwepən/", "pron": "AN-tee SAT-uh-lyte WEP-uhn", "fr": "arme antisatellite", "def": "A weapon designed to disable or destroy satellites.", "ex": "Anti-satellite weapons can create dangerous debris."}, {"term": "ASAT", "ipa": "/ˈeɪsæt/", "pron": "AY-sat", "fr": "ASAT ; arme antisatellite", "def": "Abbreviation for anti-satellite weapon or test.", "ex": "ASAT tests are controversial because they create debris."}, {"term": "space security", "ipa": "/ˈspeɪs sɪˌkjʊərəti/", "pron": "space si-KYOOR-uh-tee", "fr": "sécurité spatiale", "def": "Protection of space systems from threats and conflict.", "ex": "Space security is essential for modern militaries."}, {"term": "dual-use technology", "ipa": "/ˌdjuːəl juːs tekˈnɒlədʒi/", "pron": "DYOO-uhl yooss tek-NOL-uh-jee", "fr": "technologie à double usage", "def": "Technology usable for both civilian and military purposes.", "ex": "Many space technologies are dual-use technologies."}, {"term": "strategic autonomy", "ipa": "/strəˌtiːdʒɪk ɔːˈtɒnəmi/", "pron": "struh-TEE-jik aw-TON-uh-mee", "fr": "autonomie stratégique", "def": "The ability to act independently in strategic areas.", "ex": "Independent launch capacity supports strategic autonomy."}, {"term": "space sovereignty", "ipa": "/ˈspeɪs ˈsɒvrənti/", "pron": "space SOV-ruhn-tee", "fr": "souveraineté spatiale", "def": "A state’s ability to control and secure its space capabilities.", "ex": "Space sovereignty depends on satellites, launchers and data."}, {"term": "lunar exploration", "ipa": "/ˈluːnə ˌekspləˈreɪʃən/", "pron": "LOO-nuh ek-spluh-RAY-shuhn", "fr": "exploration lunaire", "def": "Exploration of the Moon.", "ex": "Lunar exploration is again a priority for major space powers."}, {"term": "Moon landing", "ipa": "/ˈmuːn ˌlændɪŋ/", "pron": "moon LAN-ding", "fr": "alunissage", "def": "A mission that lands on the Moon.", "ex": "The first Moon landing was a symbolic moment in history."}, {"term": "lunar base", "ipa": "/ˈluːnə beɪs/", "pron": "LOO-nuh bayce", "fr": "base lunaire", "def": "A permanent or semi-permanent facility on the Moon.", "ex": "A lunar base would require water, power and radiation protection."}, {"term": "Artemis programme", "ipa": "/ˈɑːtəmɪs ˌprəʊɡræm/", "pron": "AR-tuh-mis PROH-gram", "fr": "programme Artemis", "def": "NASA-led programme aiming to return humans to the Moon and prepare for Mars.", "ex": "The Artemis programme involves international partners."}, {"term": "Mars exploration", "ipa": "/ˈmɑːz ˌekspləˈreɪʃən/", "pron": "marz ek-spluh-RAY-shuhn", "fr": "exploration de Mars", "def": "Scientific exploration of the planet Mars.", "ex": "Mars exploration searches for signs of past life."}, {"term": "Mars rover", "ipa": "/ˈmɑːz ˌrəʊvə/", "pron": "marz ROH-vuh", "fr": "rover martien", "def": "A robotic vehicle exploring the surface of Mars.", "ex": "A Mars rover can drill and analyse rocks."}, {"term": "sample return mission", "ipa": "/ˈsɑːmpəl rɪˌtɜːn ˌmɪʃən/", "pron": "SAHM-puhl ri-TURN MISH-uhn", "fr": "mission de retour d’échantillons", "def": "A mission bringing samples from another celestial body back to Earth.", "ex": "A sample return mission can transform planetary science."}, {"term": "asteroid", "ipa": "/ˈæstərɔɪd/", "pron": "AS-tuh-royd", "fr": "astéroïde", "def": "A small rocky body orbiting the Sun.", "ex": "Asteroids may contain valuable minerals."}, {"term": "comet", "ipa": "/ˈkɒmɪt/", "pron": "KOM-it", "fr": "comète", "def": "An icy body that can form a tail when close to the Sun.", "ex": "Comets contain clues about the early Solar System."}, {"term": "asteroid mining", "ipa": "/ˈæstərɔɪd ˌmaɪnɪŋ/", "pron": "AS-tuh-royd MY-ning", "fr": "exploitation minière des astéroïdes", "def": "Extracting resources from asteroids.", "ex": "Asteroid mining remains speculative but attracts investors."}, {"term": "space mining", "ipa": "/ˈspeɪs ˌmaɪnɪŋ/", "pron": "space MY-ning", "fr": "exploitation minière spatiale", "def": "Extracting resources from the Moon, asteroids or other bodies.", "ex": "Space mining raises legal and ethical questions."}, {"term": "in-situ resource utilisation", "ipa": "/ɪn ˌsɪtjuː rɪˈsɔːs ˌjuːtɪlaɪˈzeɪʃən/", "pron": "in-SIT-yoo ri-SORSS yoo-ti-ly-ZAY-shuhn", "fr": "utilisation des ressources in situ", "def": "Using local resources in space instead of bringing everything from Earth.", "ex": "In-situ resource utilisation could support lunar bases."}, {"term": "ISRU", "ipa": "/ˌaɪ es ɑːr ˈjuː/", "pron": "eye-ess-ar-yoo", "fr": "ISRU", "def": "Abbreviation for in-situ resource utilisation.", "ex": "ISRU may make long-term exploration more feasible."}, {"term": "extraterrestrial life", "ipa": "/ˌekstrətəˈrestriəl laɪf/", "pron": "ek-struh-tuh-RES-tree-uhl life", "fr": "vie extraterrestre", "def": "Life existing beyond Earth.", "ex": "The search for extraterrestrial life motivates many missions."}, {"term": "alien life", "ipa": "/ˌeɪliən ˈlaɪf/", "pron": "AY-lee-uhn life", "fr": "vie extraterrestre", "def": "Informal term for life beyond Earth.", "ex": "Scientists look for signs of alien life in extreme environments."}, {"term": "biosignature", "ipa": "/ˈbaɪəʊˌsɪɡnətʃə/", "pron": "BY-oh-SIG-nuh-chuh", "fr": "biosignature", "def": "A sign that may indicate the presence of life.", "ex": "A biosignature could be a chemical trace in an atmosphere."}, {"term": "exoplanet", "ipa": "/ˈeksəʊˌplænɪt/", "pron": "EK-soh-PLAN-it", "fr": "exoplanète", "def": "A planet orbiting a star outside our Solar System.", "ex": "Thousands of exoplanets have been discovered."}, {"term": "habitable zone", "ipa": "/ˈhæbɪtəbəl zəʊn/", "pron": "HAB-i-tuh-buhl zone", "fr": "zone habitable", "def": "The region around a star where conditions may allow liquid water.", "ex": "A planet in the habitable zone may still be hostile to life."}, {"term": "telescope", "ipa": "/ˈtelɪskəʊp/", "pron": "TEL-i-skohp", "fr": "télescope", "def": "An instrument used to observe distant objects.", "ex": "Space telescopes avoid atmospheric distortion."}, {"term": "space telescope", "ipa": "/ˈspeɪs ˌtelɪskəʊp/", "pron": "space TEL-i-skohp", "fr": "télescope spatial", "def": "A telescope placed in space.", "ex": "A space telescope can observe distant galaxies."}, {"term": "James Webb Space Telescope", "ipa": "/ˌdʒeɪmz web ˈspeɪs ˌtelɪskəʊp/", "pron": "jaymz-web space TEL-i-skohp", "fr": "télescope spatial James-Webb", "def": "A powerful space telescope observing infrared light.", "ex": "The James Webb Space Telescope studies early galaxies and exoplanets."}]}, {"title": "D. Moon, Mars, asteroids and scientific discovery", "entries": [{"term": "cosmology", "ipa": "/kɒzˈmɒlədʒi/", "pron": "koz-MOL-uh-jee", "fr": "cosmologie", "def": "The scientific study of the origin, structure and evolution of the universe.", "ex": "Cosmology asks how the universe began."}, {"term": "universe", "ipa": "/ˈjuːnɪvɜːs/", "pron": "YOO-ni-vurs", "fr": "univers", "def": "All of space, time, matter and energy.", "ex": "The universe contains billions of galaxies."}, {"term": "galaxy", "ipa": "/ˈɡæləksi/", "pron": "GAL-uhk-see", "fr": "galaxie", "def": "A huge system of stars, gas, dust and dark matter.", "ex": "The Milky Way is our galaxy."}, {"term": "black hole", "ipa": "/ˌblæk ˈhəʊl/", "pron": "black hole", "fr": "trou noir", "def": "A region of space with gravity so strong that not even light can escape.", "ex": "Black holes test our understanding of physics."}, {"term": "space science", "ipa": "/ˈspeɪs ˌsaɪəns/", "pron": "space SY-uhns", "fr": "sciences spatiales", "def": "Scientific study of space and celestial objects.", "ex": "Space science often requires international cooperation."}, {"term": "planetary science", "ipa": "/ˌplænɪtəri ˈsaɪəns/", "pron": "PLAN-i-tuh-ree SY-uhns", "fr": "planétologie", "def": "The study of planets, moons and planetary systems.", "ex": "Planetary science helps us understand Earth’s history."}, {"term": "astrophysics", "ipa": "/ˌæstrəʊˈfɪzɪks/", "pron": "AS-troh-FIZ-iks", "fr": "astrophysique", "def": "The branch of astronomy using physics to study celestial objects.", "ex": "Astrophysics studies stars, galaxies and black holes."}, {"term": "space weather", "ipa": "/ˈspeɪs ˌweðə/", "pron": "space WETH-uh", "fr": "météorologie spatiale", "def": "Conditions in space, especially solar activity, that can affect Earth and satellites.", "ex": "Space weather can disrupt satellites and power grids."}, {"term": "solar storm", "ipa": "/ˈsəʊlə stɔːm/", "pron": "SOH-luh storm", "fr": "tempête solaire", "def": "A disturbance caused by solar activity that can affect technology.", "ex": "A solar storm can damage satellites."}, {"term": "radiation", "ipa": "/ˌreɪdiˈeɪʃən/", "pron": "ray-dee-AY-shuhn", "fr": "rayonnement ; radiation", "def": "Energy emitted as waves or particles, which can be harmful in space.", "ex": "Radiation is a major risk for astronauts."}, {"term": "to launch a satellite", "ipa": "/lɔːntʃ ə ˈsætəlaɪt/", "pron": "launch uh SAT-uh-lyte", "fr": "lancer un satellite", "def": "To send a satellite into space.", "ex": "Several countries can now launch a satellite independently."}, {"term": "to reach orbit", "ipa": "/riːtʃ ˈɔːbɪt/", "pron": "reech OR-bit", "fr": "atteindre l’orbite", "def": "To enter a stable path around Earth or another body.", "ex": "The rocket successfully reached orbit."}, {"term": "to put a payload into orbit", "ipa": "/pʊt ə ˈpeɪləʊd ˈɪntu ˈɔːbɪt/", "pron": "put uh PAY-lohd into OR-bit", "fr": "placer une charge utile en orbite", "def": "To place cargo in orbit using a launch vehicle.", "ex": "The mission put a payload into orbit."}, {"term": "to conduct a space mission", "ipa": "/kənˈdʌkt ə ˈspeɪs ˌmɪʃən/", "pron": "kuhn-DUKT uh space MISH-uhn", "fr": "mener une mission spatiale", "def": "To carry out an organised operation in space.", "ex": "Agencies cooperate to conduct a space mission."}, {"term": "to explore Mars", "ipa": "/ɪkˈsplɔː ˈmɑːz/", "pron": "ik-SPLOR marz", "fr": "explorer Mars", "def": "To study Mars through probes, rovers or human missions.", "ex": "Scientists use rovers to explore Mars."}, {"term": "to return to the Moon", "ipa": "/rɪˈtɜːn tə ðə ˈmuːn/", "pron": "ri-TURN tuh thuh moon", "fr": "retourner sur la Lune", "def": "To send humans or missions back to the Moon.", "ex": "Several powers plan to return to the Moon."}, {"term": "to deploy a constellation", "ipa": "/dɪˈplɔɪ ə ˌkɒnstəˈleɪʃən/", "pron": "di-PLOY uh kon-stuh-LAY-shuhn", "fr": "déployer une constellation", "def": "To place a group of satellites into operation.", "ex": "Companies deploy a constellation to provide internet coverage."}, {"term": "to monitor climate change", "ipa": "/ˈmɒnɪtə ˈklaɪmət tʃeɪndʒ/", "pron": "MON-i-tuh KLY-muht chaynj", "fr": "surveiller le changement climatique", "def": "To observe and measure climate change over time.", "ex": "Earth observation satellites monitor climate change."}, {"term": "to track space debris", "ipa": "/træk ˈspeɪs ˌdebriː/", "pron": "trak space DEB-ree", "fr": "suivre les débris spatiaux", "def": "To observe and follow debris in orbit.", "ex": "Space agencies track space debris to avoid collisions."}, {"term": "to avoid collisions", "ipa": "/əˈvɔɪd kəˈlɪʒənz/", "pron": "uh-VOYD kuh-LIZH-uhnz", "fr": "éviter les collisions", "def": "To prevent objects from hitting each other.", "ex": "Satellites manoeuvre to avoid collisions."}, {"term": "to reduce launch costs", "ipa": "/rɪˈdjuːs ˈlɔːntʃ kɒsts/", "pron": "ri-DYOOSS launch kosts", "fr": "réduire les coûts de lancement", "def": "To make space launches cheaper.", "ex": "Reusable rockets reduce launch costs."}, {"term": "to privatise space exploration", "ipa": "/ˈpraɪvətaɪz ˈspeɪs ˌekspləˈreɪʃən/", "pron": "PRY-vuh-tyze space ek-spluh-RAY-shuhn", "fr": "privatiser l’exploration spatiale", "def": "To shift space activities from state agencies to private companies.", "ex": "Some critics worry about efforts to privatise space exploration."}, {"term": "to militarise space", "ipa": "/ˈmɪlɪtəraɪz ˈspeɪs/", "pron": "MIL-i-tuh-ryze space", "fr": "militariser l’espace", "def": "To use space increasingly for military purposes.", "ex": "States may militarise space through surveillance and navigation systems."}, {"term": "to weaponise space", "ipa": "/ˈwepənaɪz ˈspeɪs/", "pron": "WEP-uh-nyze space", "fr": "transformer l’espace en domaine d’armement", "def": "To place or use weapons in or from space.", "ex": "The weaponise-space debate worries diplomats."}, {"term": "to claim celestial resources", "ipa": "/kleɪm səˈlestiəl rɪˈsɔːsɪz/", "pron": "klaym suh-LES-tee-uhl ri-SOR-siz", "fr": "revendiquer des ressources célestes", "def": "To assert rights over resources on the Moon, asteroids or planets.", "ex": "Space mining raises the question of who can claim celestial resources."}, {"term": "to search for extraterrestrial life", "ipa": "/sɜːtʃ fə ˌekstrətəˈrestriəl laɪf/", "pron": "surch fuh ek-struh-tuh-RES-tree-uhl life", "fr": "chercher la vie extraterrestre", "def": "To look for life beyond Earth.", "ex": "Missions to icy moons search for extraterrestrial life."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p7c65", "part": 7, "chapter": 65, "title": "Biotechnology", "file": "cpge_vocab_part7_chapter65_biotechnology_premium.html", "count": 109, "sections": [{"title": "A. Core biotechnology, genetics and medical vocabulary", "entries": [{"term": "biotechnology", "ipa": "/ˌbaɪəʊtekˈnɒlədʒi/", "pron": "BY-oh-tek-NOL-uh-jee", "fr": "biotechnologie", "def": "The use of living organisms, cells or biological systems to develop products, treatments and technologies.", "ex": "Biotechnology is transforming medicine, agriculture and industry."}, {"term": "biotech", "ipa": "/ˈbaɪəʊtek/", "pron": "BY-oh-tek", "fr": "biotech", "def": "Short form of biotechnology, or a company working in biotechnology.", "ex": "Biotech firms often depend on research, patents and investment."}, {"term": "life sciences", "ipa": "/ˈlaɪf ˌsaɪənsɪz/", "pron": "life SY-uhn-siz", "fr": "sciences du vivant", "def": "Scientific fields studying living organisms, including biology, medicine and genetics.", "ex": "The life sciences sector attracts major public and private funding."}, {"term": "biomedical research", "ipa": "/ˌbaɪəʊˈmedɪkəl rɪˈsɜːtʃ/", "pron": "BY-oh-MED-i-kuhl ri-SURCH", "fr": "recherche biomédicale", "def": "Scientific research aimed at understanding health, disease and medical treatment.", "ex": "Biomedical research can lead to new therapies."}, {"term": "genetics", "ipa": "/dʒəˈnetɪks/", "pron": "juh-NET-iks", "fr": "génétique", "def": "The study of genes, heredity and variation in living organisms.", "ex": "Genetics helps explain inherited diseases."}, {"term": "genomics", "ipa": "/dʒɪˈnəʊmɪks/", "pron": "ji-NOH-miks", "fr": "génomique", "def": "The study of entire genomes and how genes interact.", "ex": "Genomics enables personalised medicine."}, {"term": "genome", "ipa": "/ˈdʒiːnəʊm/", "pron": "JEE-nohm", "fr": "génome", "def": "The complete set of genetic material in an organism.", "ex": "The human genome contains the instructions for building and maintaining the body."}, {"term": "gene", "ipa": "/dʒiːn/", "pron": "jeen", "fr": "gène", "def": "A unit of heredity made of DNA that influences traits or functions.", "ex": "A faulty gene can cause disease."}, {"term": "DNA", "ipa": "/ˌdiː en ˈeɪ/", "pron": "dee-en-ay", "fr": "ADN", "def": "Deoxyribonucleic acid, the molecule carrying genetic information.", "ex": "DNA stores genetic instructions."}, {"term": "RNA", "ipa": "/ˌɑːr en ˈeɪ/", "pron": "ar-en-ay", "fr": "ARN", "def": "Ribonucleic acid, a molecule involved in using genetic information to make proteins.", "ex": "RNA plays a key role in protein production."}, {"term": "protein", "ipa": "/ˈprəʊtiːn/", "pron": "PROH-teen", "fr": "protéine", "def": "A molecule made of amino acids that performs functions in cells and organisms.", "ex": "Proteins are essential for cell structure and activity."}, {"term": "cell", "ipa": "/sel/", "pron": "sel", "fr": "cellule", "def": "The basic structural and functional unit of living organisms.", "ex": "Biotechnology often works at the level of the cell."}, {"term": "stem cell", "ipa": "/ˈstem sel/", "pron": "stem sel", "fr": "cellule souche", "def": "A cell able to develop into different specialised cell types.", "ex": "Stem cells could help repair damaged tissues."}, {"term": "embryonic stem cell", "ipa": "/ˌembriˈɒnɪk ˈstem sel/", "pron": "em-bree-ON-ik stem sel", "fr": "cellule souche embryonnaire", "def": "A stem cell derived from an early embryo, able to form many cell types.", "ex": "Embryonic stem-cell research raises ethical questions."}, {"term": "adult stem cell", "ipa": "/ˌædʌlt ˈstem sel/", "pron": "AD-ult stem sel", "fr": "cellule souche adulte", "def": "A stem cell found in developed tissues, usually with more limited potential.", "ex": "Adult stem cells are used in some medical treatments."}, {"term": "cell therapy", "ipa": "/ˈsel ˌθerəpi/", "pron": "sel THERR-uh-pee", "fr": "thérapie cellulaire", "def": "Treatment using living cells to repair, replace or modify biological functions.", "ex": "Cell therapy offers hope for some cancers and degenerative diseases."}, {"term": "gene therapy", "ipa": "/ˈdʒiːn ˌθerəpi/", "pron": "jeen THERR-uh-pee", "fr": "thérapie génique", "def": "Treatment that modifies or replaces genes to treat disease.", "ex": "Gene therapy can target the genetic cause of some disorders."}, {"term": "genetic engineering", "ipa": "/dʒəˌnetɪk ˌendʒɪˈnɪərɪŋ/", "pron": "juh-NET-ik en-ji-NEER-ing", "fr": "génie génétique", "def": "The deliberate modification of an organism’s genetic material.", "ex": "Genetic engineering can produce crops resistant to pests."}, {"term": "genome editing", "ipa": "/ˈdʒiːnəʊm ˌedɪtɪŋ/", "pron": "JEE-nohm ED-it-ing", "fr": "édition du génome", "def": "Precise modification of DNA within a genome.", "ex": "Genome editing raises both medical hopes and ethical concerns."}, {"term": "gene editing", "ipa": "/ˈdʒiːn ˌedɪtɪŋ/", "pron": "jeen ED-it-ing", "fr": "édition génétique", "def": "Changing the DNA sequence of a gene.", "ex": "Gene editing could correct disease-causing mutations."}, {"term": "CRISPR", "ipa": "/ˈkrɪspə/", "pron": "KRIS-puh", "fr": "CRISPR", "def": "A gene-editing technology allowing targeted changes to DNA.", "ex": "CRISPR has made gene editing cheaper and more precise."}, {"term": "Cas9", "ipa": "/ˈkæs naɪn/", "pron": "cass-nine", "fr": "Cas9", "def": "An enzyme used in CRISPR to cut DNA at a targeted location.", "ex": "Cas9 acts like molecular scissors."}, {"term": "mutation", "ipa": "/mjuːˈteɪʃən/", "pron": "myoo-TAY-shuhn", "fr": "mutation", "def": "A change in DNA sequence.", "ex": "Some mutations are harmless, while others cause disease."}, {"term": "hereditary disease", "ipa": "/həˌredɪtəri dɪˈziːz/", "pron": "huh-RED-i-tuh-ree di-ZEEZ", "fr": "maladie héréditaire", "def": "A disease passed from parents to children through genes.", "ex": "Gene therapy may help treat hereditary diseases."}, {"term": "genetic disorder", "ipa": "/dʒəˌnetɪk dɪsˈɔːdə/", "pron": "juh-NET-ik dis-OR-duh", "fr": "maladie génétique", "def": "A disease or condition caused partly or entirely by genetic changes.", "ex": "Cystic fibrosis is a genetic disorder."}, {"term": "rare disease", "ipa": "/ˌreə dɪˈziːz/", "pron": "rare di-ZEEZ", "fr": "maladie rare", "def": "A disease affecting a small proportion of the population.", "ex": "Biotech companies often develop treatments for rare diseases."}, {"term": "diagnosis", "ipa": "/ˌdaɪəɡˈnəʊsɪs/", "pron": "dy-uhg-NOH-sis", "fr": "diagnostic", "def": "The identification of a disease or condition.", "ex": "Genetic testing can improve diagnosis."}, {"term": "genetic testing", "ipa": "/dʒəˌnetɪk ˈtestɪŋ/", "pron": "juh-NET-ik TEST-ing", "fr": "test génétique", "def": "Testing DNA to identify genetic traits, risks or disorders.", "ex": "Genetic testing can reveal inherited health risks."}, {"term": "screening", "ipa": "/ˈskriːnɪŋ/", "pron": "SCREEN-ing", "fr": "dépistage", "def": "Testing people to detect disease or risk before symptoms appear.", "ex": "Screening can identify disease earlier."}, {"term": "prenatal screening", "ipa": "/ˌpriːˈneɪtəl ˈskriːnɪŋ/", "pron": "pree-NAY-tuhl SCREEN-ing", "fr": "dépistage prénatal", "def": "Testing during pregnancy to assess fetal health or genetic risk.", "ex": "Prenatal screening raises ethical and personal decisions."}, {"term": "biomarker", "ipa": "/ˈbaɪəʊˌmɑːkə/", "pron": "BY-oh-MAR-kuh", "fr": "biomarqueur", "def": "A measurable biological sign of a condition, process or disease.", "ex": "Biomarkers can help doctors choose the right treatment."}, {"term": "personalised medicine", "ipa": "/ˌpɜːsənəlaɪzd ˈmedsən/", "pron": "PUR-suh-nuh-lyzd MED-suhn", "fr": "médecine personnalisée", "def": "Medical treatment adapted to an individual’s genes, biology or lifestyle.", "ex": "Personalised medicine can make treatment more effective."}, {"term": "precision medicine", "ipa": "/prɪˌsɪʒən ˈmedsən/", "pron": "pri-SIZH-uhn MED-suhn", "fr": "médecine de précision", "def": "A medical approach using detailed biological and genetic information.", "ex": "Precision medicine depends on data, biomarkers and genomics."}, {"term": "targeted therapy", "ipa": "/ˌtɑːɡɪtɪd ˈθerəpi/", "pron": "TAR-git-id THERR-uh-pee", "fr": "thérapie ciblée", "def": "A treatment designed to attack specific molecules or pathways involved in disease.", "ex": "Targeted therapy is common in modern cancer care."}, {"term": "immunotherapy", "ipa": "/ˌɪmjʊnəʊˈθerəpi/", "pron": "im-yoo-noh-THERR-uh-pee", "fr": "immunothérapie", "def": "Treatment that uses or modifies the immune system to fight disease.", "ex": "Immunotherapy has changed cancer treatment."}, {"term": "CAR T-cell therapy", "ipa": "/ˌkɑː tiː ˈsel ˌθerəpi/", "pron": "car-tee-sel THERR-uh-pee", "fr": "thérapie CAR-T", "def": "A cancer treatment using genetically modified immune cells.", "ex": "CAR T-cell therapy can treat some blood cancers."}, {"term": "vaccine", "ipa": "/ˈvæksiːn/", "pron": "VAK-seen", "fr": "vaccin", "def": "A biological preparation that trains the immune system to fight a disease.", "ex": "Vaccines are among the most successful public-health tools."}, {"term": "mRNA vaccine", "ipa": "/ˌem ɑːr en ˈeɪ ˈvæksiːn/", "pron": "em-ar-en-ay VAK-seen", "fr": "vaccin à ARN messager", "def": "A vaccine using messenger RNA to instruct cells to produce a harmless target protein.", "ex": "mRNA vaccines became widely known during the COVID-19 pandemic."}]}, {"title": "B. Clinical research, ethics, cells and regenerative medicine", "entries": [{"term": "clinical trial", "ipa": "/ˌklɪnɪkəl ˈtraɪəl/", "pron": "KLIN-i-kuhl TRY-uhl", "fr": "essai clinique", "def": "A research study testing a treatment in human participants.", "ex": "Clinical trials are required before a medicine is approved."}, {"term": "trial participant", "ipa": "/ˈtraɪəl pɑːˌtɪsɪpənt/", "pron": "TRY-uhl par-TIS-i-puhnt", "fr": "participant à un essai clinique", "def": "A person taking part in a clinical trial.", "ex": "Trial participants must give informed consent."}, {"term": "placebo", "ipa": "/pləˈsiːbəʊ/", "pron": "pluh-SEE-boh", "fr": "placebo", "def": "An inactive treatment used as a comparison in research.", "ex": "A placebo helps researchers measure treatment effects."}, {"term": "randomised controlled trial", "ipa": "/ˈrændəmaɪzd kənˌtrəʊld ˈtraɪəl/", "pron": "RAN-duh-myzd kuhn-TROHLD TRY-uhl", "fr": "essai contrôlé randomisé", "def": "A study where participants are randomly assigned to treatment or control groups.", "ex": "Randomised controlled trials are a gold standard in medicine."}, {"term": "informed consent", "ipa": "/ɪnˌfɔːmd kənˈsent/", "pron": "in-FORMD kuhn-SENT", "fr": "consentement éclairé", "def": "Permission given after understanding risks, benefits and alternatives.", "ex": "Informed consent is essential in biomedical research."}, {"term": "bioethics", "ipa": "/ˌbaɪəʊˈeθɪks/", "pron": "BY-oh-ETH-iks", "fr": "bioéthique", "def": "The study of ethical issues in biology, medicine and biotechnology.", "ex": "Bioethics addresses questions about embryos, cloning and genetic editing."}, {"term": "ethical concern", "ipa": "/ˌeθɪkəl kənˈsɜːn/", "pron": "ETH-i-kuhl kuhn-SURN", "fr": "préoccupation éthique", "def": "A moral worry about possible harm, fairness or responsibility.", "ex": "Human genome editing raises ethical concerns."}, {"term": "medical ethics", "ipa": "/ˌmedɪkəl ˈeθɪks/", "pron": "MED-i-kuhl ETH-iks", "fr": "éthique médicale", "def": "Moral principles guiding healthcare and medical research.", "ex": "Medical ethics protects patients and research participants."}, {"term": "biobank", "ipa": "/ˈbaɪəʊbæŋk/", "pron": "BY-oh-bank", "fr": "biobanque", "def": "A collection of biological samples and health data used for research.", "ex": "Biobanks require strong privacy safeguards."}, {"term": "biological sample", "ipa": "/ˌbaɪəˈlɒdʒɪkəl ˈsɑːmpəl/", "pron": "BY-uh-LOJ-i-kuhl SAHM-puhl", "fr": "échantillon biologique", "def": "A sample of tissue, blood, saliva or other biological material.", "ex": "Biological samples can reveal sensitive genetic information."}, {"term": "cell culture", "ipa": "/ˈsel ˌkʌltʃə/", "pron": "sel KUL-chuh", "fr": "culture cellulaire", "def": "The growth of cells in controlled laboratory conditions.", "ex": "Cell culture is used to test drugs."}, {"term": "tissue engineering", "ipa": "/ˈtɪʃuː ˌendʒɪˈnɪərɪŋ/", "pron": "TISH-oo en-ji-NEER-ing", "fr": "ingénierie tissulaire", "def": "The creation or repair of tissues using cells, materials and biological signals.", "ex": "Tissue engineering could help repair damaged organs."}, {"term": "regenerative medicine", "ipa": "/rɪˌdʒenərətɪv ˈmedsən/", "pron": "ri-JEN-uh-ruh-tiv MED-suhn", "fr": "médecine régénérative", "def": "Medicine aiming to repair, replace or regenerate damaged cells, tissues or organs.", "ex": "Regenerative medicine includes stem-cell therapies."}, {"term": "organ transplant", "ipa": "/ˈɔːɡən ˌtrænsplɑːnt/", "pron": "OR-guhn TRANS-plant", "fr": "greffe d’organe", "def": "The surgical replacement of a failing organ with a healthy one.", "ex": "Biotechnology may reduce the shortage of organs for transplant."}, {"term": "xenotransplantation", "ipa": "/ˌzenəʊtrænsplɑːnˈteɪʃən/", "pron": "ZEN-oh-trans-plan-TAY-shuhn", "fr": "xénogreffe ; xénotransplantation", "def": "Transplantation of organs, tissues or cells between different species.", "ex": "Xenotransplantation could use genetically modified pig organs."}, {"term": "cloning", "ipa": "/ˈkləʊnɪŋ/", "pron": "KLOH-ning", "fr": "clonage", "def": "Creating a genetically identical copy of an organism, cell or DNA sequence.", "ex": "Cloning remains ethically controversial."}, {"term": "reproductive cloning", "ipa": "/ˌriːprəˈdʌktɪv ˈkləʊnɪŋ/", "pron": "ree-pruh-DUK-tiv KLOH-ning", "fr": "clonage reproductif", "def": "Cloning intended to create a new organism.", "ex": "Human reproductive cloning is widely rejected."}, {"term": "therapeutic cloning", "ipa": "/ˌθerəˈpjuːtɪk ˈkləʊnɪŋ/", "pron": "THERR-uh-PYOO-tik KLOH-ning", "fr": "clonage thérapeutique", "def": "Cloning aimed at producing cells or tissues for treatment or research.", "ex": "Therapeutic cloning is discussed in regenerative medicine."}, {"term": "synthetic biology", "ipa": "/sɪnˌθetɪk baɪˈɒlədʒi/", "pron": "sin-THET-ik by-OL-uh-jee", "fr": "biologie synthétique", "def": "The design and construction of new biological systems or redesigned organisms.", "ex": "Synthetic biology can create microbes that produce useful chemicals."}, {"term": "bioengineering", "ipa": "/ˌbaɪəʊˌendʒɪˈnɪərɪŋ/", "pron": "BY-oh-en-ji-NEER-ing", "fr": "bio-ingénierie", "def": "Engineering applied to biological systems or medical problems.", "ex": "Bioengineering combines biology, technology and design."}, {"term": "biofabrication", "ipa": "/ˌbaɪəʊˌfæbrɪˈkeɪʃən/", "pron": "BY-oh-fab-ri-KAY-shuhn", "fr": "biofabrication", "def": "The production of biological products, tissues or materials using living cells or biomolecules.", "ex": "Biofabrication could help create artificial tissues."}, {"term": "3D bioprinting", "ipa": "/ˌθriː diː ˈbaɪəʊˌprɪntɪŋ/", "pron": "three-dee BY-oh-print-ing", "fr": "bio-impression 3D", "def": "Using 3D printing techniques with cells or biomaterials to create biological structures.", "ex": "3D bioprinting may one day produce transplantable tissues."}, {"term": "biomaterial", "ipa": "/ˌbaɪəʊməˈtɪəriəl/", "pron": "BY-oh-muh-TEER-ee-uhl", "fr": "biomatériau", "def": "A material designed to interact with biological systems.", "ex": "Biomaterials are used in implants and tissue engineering."}, {"term": "enzyme", "ipa": "/ˈenzaɪm/", "pron": "EN-zyme", "fr": "enzyme", "def": "A protein that speeds up a chemical reaction in living organisms.", "ex": "Enzymes are widely used in biotechnology and industry."}, {"term": "fermentation", "ipa": "/ˌfɜːmenˈteɪʃən/", "pron": "fur-men-TAY-shuhn", "fr": "fermentation", "def": "A biological process using microorganisms to produce substances such as food, fuel or medicine.", "ex": "Fermentation is used to make antibiotics, beer and biofuels."}, {"term": "microorganism", "ipa": "/ˌmaɪkrəʊˈɔːɡənɪzəm/", "pron": "MY-kroh-OR-guh-niz-uhm", "fr": "micro-organisme", "def": "A microscopic living organism such as a bacterium or yeast.", "ex": "Microorganisms can be engineered to produce insulin."}, {"term": "bacterium", "ipa": "/bækˈtɪəriəm/", "pron": "bak-TEER-ee-uhm", "fr": "bactérie", "def": "A single-celled microorganism.", "ex": "Some bacteria can be used to clean polluted environments."}, {"term": "yeast", "ipa": "/jiːst/", "pron": "yeest", "fr": "levure", "def": "A single-celled fungus used in fermentation and biotechnology.", "ex": "Yeast can be engineered to produce medicines."}, {"term": "bioreactor", "ipa": "/ˌbaɪəʊriˈæktə/", "pron": "BY-oh-ree-AK-tuh", "fr": "bioréacteur", "def": "A vessel where cells or microorganisms grow under controlled conditions.", "ex": "Bioreactors are used to manufacture vaccines and proteins."}, {"term": "biomanufacturing", "ipa": "/ˌbaɪəʊˌmænjʊˈfæktʃərɪŋ/", "pron": "BY-oh-man-yoo-FAK-chuh-ring", "fr": "biofabrication industrielle", "def": "The production of medicines, materials or chemicals using biological systems.", "ex": "Biomanufacturing can replace some fossil-based processes."}]}, {"title": "C. Industrial, agricultural and environmental biotechnology", "entries": [{"term": "biofuel", "ipa": "/ˈbaɪəʊˌfjuːəl/", "pron": "BY-oh-FYOO-uhl", "fr": "biocarburant", "def": "Fuel produced from biological material.", "ex": "Biofuels can reduce reliance on fossil fuels, but they also raise land-use concerns."}, {"term": "bioplastic", "ipa": "/ˌbaɪəʊˈplæstɪk/", "pron": "BY-oh-PLAS-tik", "fr": "bioplastique", "def": "Plastic made partly or entirely from biological sources.", "ex": "Bioplastics are promoted as a greener alternative."}, {"term": "bioremediation", "ipa": "/ˌbaɪəʊrɪˌmiːdiˈeɪʃən/", "pron": "BY-oh-ri-mee-dee-AY-shuhn", "fr": "bioremédiation", "def": "Using organisms to clean polluted environments.", "ex": "Bioremediation can help break down oil spills."}, {"term": "agricultural biotechnology", "ipa": "/ˌæɡrɪˈkʌltʃərəl ˌbaɪəʊtekˈnɒlədʒi/", "pron": "ag-ri-KUL-chuh-ruhl BY-oh-tek-NOL-uh-jee", "fr": "biotechnologie agricole", "def": "Biotechnology applied to farming, crops and livestock.", "ex": "Agricultural biotechnology can improve crop yields."}, {"term": "genetically modified organism", "ipa": "/dʒəˌnetɪkəli ˈmɒdɪfaɪd ˈɔːɡənɪzəm/", "pron": "juh-NET-i-kuh-lee MOD-i-fyd OR-guh-niz-uhm", "fr": "organisme génétiquement modifié", "def": "An organism whose DNA has been deliberately altered.", "ex": "A genetically modified organism may resist pests or drought."}, {"term": "GMO", "ipa": "/ˌdʒiː em ˈəʊ/", "pron": "jee-em-oh", "fr": "OGM", "def": "Abbreviation for genetically modified organism.", "ex": "GMOs are debated in agriculture and food policy."}, {"term": "GM crop", "ipa": "/ˌdʒiː em ˈkrɒp/", "pron": "jee-em crop", "fr": "culture génétiquement modifiée", "def": "A genetically modified crop.", "ex": "GM crops can reduce pesticide use in some cases."}, {"term": "crop yield", "ipa": "/ˈkrɒp jiːld/", "pron": "crop yeeld", "fr": "rendement agricole", "def": "The amount of crop produced per area of land.", "ex": "Biotechnology may increase crop yield."}, {"term": "drought-resistant crop", "ipa": "/ˈdraʊt rɪˌzɪstənt krɒp/", "pron": "drowt-ri-ZIS-tuhnt crop", "fr": "culture résistante à la sécheresse", "def": "A crop able to survive with less water.", "ex": "Drought-resistant crops could help farmers adapt to climate change."}, {"term": "pest-resistant crop", "ipa": "/ˈpest rɪˌzɪstənt krɒp/", "pron": "pest-ri-ZIS-tuhnt crop", "fr": "culture résistante aux nuisibles", "def": "A crop engineered or bred to resist pests.", "ex": "Pest-resistant crops may reduce chemical pesticide use."}, {"term": "food security", "ipa": "/ˈfuːd sɪˌkjʊərəti/", "pron": "food si-KYOOR-uh-tee", "fr": "sécurité alimentaire", "def": "Reliable access to enough safe and nutritious food.", "ex": "Biotechnology is often presented as a tool for food security."}, {"term": "biosafety", "ipa": "/ˌbaɪəʊˈseɪfti/", "pron": "BY-oh-SAYF-tee", "fr": "biosécurité sanitaire", "def": "Measures designed to prevent harm from biological agents or technologies.", "ex": "Biosafety rules protect researchers and the public."}, {"term": "biosecurity", "ipa": "/ˌbaɪəʊsɪˈkjʊərəti/", "pron": "BY-oh-si-KYOOR-uh-tee", "fr": "biosécurité ; sécurité biologique", "def": "Protection against misuse, theft or deliberate release of biological agents.", "ex": "Biosecurity concerns have grown with synthetic biology."}, {"term": "dual-use research", "ipa": "/ˌdjuːəl juːs rɪˈsɜːtʃ/", "pron": "DYOO-uhl yooss ri-SURCH", "fr": "recherche à double usage", "def": "Research that can be used for both beneficial and harmful purposes.", "ex": "Dual-use research creates dilemmas for scientists and regulators."}, {"term": "gain-of-function research", "ipa": "/ˌɡeɪn əv ˈfʌŋkʃən rɪˈsɜːtʃ/", "pron": "gayn ov FUNK-shuhn ri-SURCH", "fr": "recherche de gain de fonction", "def": "Research that gives an organism new or enhanced abilities.", "ex": "Gain-of-function research is controversial because of safety risks."}, {"term": "pathogen", "ipa": "/ˈpæθədʒən/", "pron": "PATH-uh-juhn", "fr": "agent pathogène", "def": "An organism or agent that can cause disease.", "ex": "A pathogen can spread through air, water or contact."}, {"term": "virus", "ipa": "/ˈvaɪrəs/", "pron": "VY-ruhs", "fr": "virus", "def": "A microscopic infectious agent that replicates inside living cells.", "ex": "Viruses are studied for vaccines and gene therapy."}, {"term": "pandemic preparedness", "ipa": "/pænˈdemɪk prɪˈpeərədnəs/", "pron": "pan-DEM-ik pri-PAIR-id-nuhs", "fr": "préparation aux pandémies", "def": "Planning and capacity-building to respond to future pandemics.", "ex": "Biotechnology is central to pandemic preparedness."}, {"term": "vaccine platform", "ipa": "/ˈvæksiːn ˌplætfɔːm/", "pron": "VAK-seen PLAT-form", "fr": "plateforme vaccinale", "def": "A technology base that can be adapted to create vaccines against different diseases.", "ex": "mRNA technology can serve as a vaccine platform."}, {"term": "antibiotic resistance", "ipa": "/ˌæntibaɪˈɒtɪk rɪˈzɪstəns/", "pron": "AN-tee-by-OT-ik ri-ZIS-tuhns", "fr": "résistance aux antibiotiques", "def": "The ability of bacteria to survive antibiotic treatment.", "ex": "Antibiotic resistance is a major global health threat."}, {"term": "superbug", "ipa": "/ˈsuːpəbʌɡ/", "pron": "SOO-puh-bug", "fr": "superbactérie", "def": "A bacterium resistant to several antibiotics.", "ex": "Superbugs can make common infections harder to treat."}, {"term": "patent", "ipa": "/ˈpætənt/", "pron": "PAT-uhnt", "fr": "brevet", "def": "A legal right protecting an invention from being copied without permission.", "ex": "Patents can reward innovation but increase drug prices."}, {"term": "intellectual property", "ipa": "/ˌɪntəˈlektʃuəl ˈprɒpəti/", "pron": "IN-tuh-LEK-choo-uhl PROP-uh-tee", "fr": "propriété intellectuelle", "def": "Legal rights over inventions, designs, creative works or discoveries.", "ex": "Intellectual property shapes access to biotechnology."}, {"term": "drug approval", "ipa": "/ˈdrʌɡ əˌpruːvəl/", "pron": "drug uh-PROO-vuhl", "fr": "autorisation de mise sur le marché", "def": "Official authorisation allowing a medicine to be marketed.", "ex": "Drug approval requires evidence of safety and effectiveness."}, {"term": "regulatory approval", "ipa": "/ˌreɡjʊlətəri əˈpruːvəl/", "pron": "REG-yuh-luh-tuh-ree uh-PROO-vuhl", "fr": "approbation réglementaire", "def": "Official permission from a regulator after standards are met.", "ex": "Biotech products need regulatory approval before use."}]}, {"title": "D. Biosafety, biosecurity, regulation and access", "entries": [{"term": "FDA", "ipa": "/ˌef diː ˈeɪ/", "pron": "eff-dee-ay", "fr": "FDA", "def": "US Food and Drug Administration.", "ex": "The FDA evaluates medicines, vaccines and medical devices."}, {"term": "EMA", "ipa": "/ˌiː em ˈeɪ/", "pron": "ee-em-ay", "fr": "Agence européenne des médicaments", "def": "European Medicines Agency.", "ex": "The EMA assesses medicines for the European market."}, {"term": "access to treatment", "ipa": "/ˌækses tə ˈtriːtmənt/", "pron": "AK-ses tuh TREET-muhnt", "fr": "accès au traitement", "def": "The ability of patients to receive medical care or therapy.", "ex": "High prices can limit access to treatment."}, {"term": "health inequality", "ipa": "/ˈhelθ ˌɪnɪˈkwɒləti/", "pron": "health in-i-KWOL-uh-tee", "fr": "inégalité de santé", "def": "Unequal health outcomes or access between groups.", "ex": "Expensive biotech therapies may widen health inequality."}, {"term": "genetic discrimination", "ipa": "/dʒəˌnetɪk dɪˌskrɪmɪˈneɪʃən/", "pron": "juh-NET-ik dis-krim-i-NAY-shuhn", "fr": "discrimination génétique", "def": "Unfair treatment based on genetic information.", "ex": "Genetic discrimination could affect insurance or employment."}, {"term": "genetic privacy", "ipa": "/dʒəˌnetɪk ˈprɪvəsi/", "pron": "juh-NET-ik PRIV-uh-see", "fr": "confidentialité génétique", "def": "Protection of a person’s genetic information.", "ex": "Genetic privacy is difficult because DNA also reveals information about relatives."}, {"term": "to edit a gene", "ipa": "/ˈedɪt ə dʒiːn/", "pron": "ED-it uh jeen", "fr": "modifier un gène", "def": "To modify a gene’s DNA sequence.", "ex": "Scientists may edit a gene to correct a mutation."}, {"term": "to sequence a genome", "ipa": "/ˈsiːkwəns ə ˈdʒiːnəʊm/", "pron": "SEE-kwuhns uh JEE-nohm", "fr": "séquencer un génome", "def": "To determine the order of DNA in a genome.", "ex": "Researchers sequence a genome to identify disease-related variants."}, {"term": "to develop a vaccine", "ipa": "/dɪˈveləp ə ˈvæksiːn/", "pron": "di-VEL-uhp uh VAK-seen", "fr": "développer un vaccin", "def": "To create and test a vaccine.", "ex": "Biotech companies develop a vaccine through laboratory and clinical research."}, {"term": "to run a clinical trial", "ipa": "/rʌn ə ˌklɪnɪkəl ˈtraɪəl/", "pron": "run uh KLIN-i-kuhl TRY-uhl", "fr": "mener un essai clinique", "def": "To organise and conduct a clinical trial.", "ex": "Researchers run a clinical trial to test safety and efficacy."}, {"term": "to obtain informed consent", "ipa": "/əbˈteɪn ɪnˌfɔːmd kənˈsent/", "pron": "uhb-TAYN in-FORMD kuhn-SENT", "fr": "obtenir le consentement éclairé", "def": "To receive permission after explaining risks and benefits.", "ex": "Doctors must obtain informed consent from participants."}, {"term": "to assess safety", "ipa": "/əˈses ˈseɪfti/", "pron": "uh-SESS SAYF-tee", "fr": "évaluer la sécurité", "def": "To evaluate whether something is safe.", "ex": "Regulators assess safety before approval."}, {"term": "to improve crop yields", "ipa": "/ɪmˈpruːv ˈkrɒp jiːldz/", "pron": "im-PROOV crop yeeldz", "fr": "améliorer les rendements agricoles", "def": "To increase agricultural production.", "ex": "Biotechnology may improve crop yields in harsh climates."}, {"term": "to raise ethical concerns", "ipa": "/reɪz ˌeθɪkəl kənˈsɜːnz/", "pron": "rayz ETH-i-kuhl kuhn-SURNZ", "fr": "soulever des préoccupations éthiques", "def": "To create moral worries or debate.", "ex": "Human gene editing raises ethical concerns."}, {"term": "to prevent misuse", "ipa": "/prɪˈvent mɪsˈjuːs/", "pron": "pri-VENT mis-YOOSS", "fr": "empêcher les abus", "def": "To stop a technology from being used harmfully.", "ex": "Biosecurity rules aim to prevent misuse."}, {"term": "to balance innovation and safety", "ipa": "/ˈbæləns ˌɪnəˈveɪʃən ənd ˈseɪfti/", "pron": "BAL-uhns in-uh-VAY-shuhn and SAYF-tee", "fr": "équilibrer innovation et sécurité", "def": "To encourage progress while reducing risks.", "ex": "Biotech regulation must balance innovation and safety."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p7c66", "part": 7, "chapter": 66, "title": "Genetic Engineering", "file": "cpge_vocab_part7_chapter66_genetic_engineering_premium.html", "count": 128, "sections": [{"title": "A. Core genetic engineering and DNA vocabulary", "entries": [{"term": "genetic engineering", "ipa": "/dʒəˌnetɪk ˌendʒɪˈnɪərɪŋ/", "pron": "juh-NET-ik en-ji-NEER-ing", "fr": "génie génétique", "def": "The deliberate modification of an organism’s genetic material to change its traits or functions.", "ex": "Genetic engineering can be used in medicine, agriculture and industry."}, {"term": "genome editing", "ipa": "/ˈdʒiːnəʊm ˌedɪtɪŋ/", "pron": "JEE-nohm ED-it-ing", "fr": "édition du génome", "def": "Precise modification of DNA within an organism’s genome.", "ex": "Genome editing could correct harmful mutations."}, {"term": "gene editing", "ipa": "/ˈdʒiːn ˌedɪtɪŋ/", "pron": "jeen ED-it-ing", "fr": "édition génétique", "def": "Changing the DNA sequence of a gene.", "ex": "Gene editing raises hopes for treating inherited diseases."}, {"term": "genetic modification", "ipa": "/dʒəˌnetɪk ˌmɒdɪfɪˈkeɪʃən/", "pron": "juh-NET-ik mod-i-fi-KAY-shuhn", "fr": "modification génétique", "def": "Changing the genetic material of an organism.", "ex": "Genetic modification is debated in food production."}, {"term": "genetically modified", "ipa": "/dʒəˌnetɪkəli ˈmɒdɪfaɪd/", "pron": "juh-NET-i-kuh-lee MOD-i-fyd", "fr": "génétiquement modifié", "def": "Having genetic material deliberately changed by biotechnology.", "ex": "Genetically modified crops are common in some countries."}, {"term": "genetically modified organism", "ipa": "/dʒəˌnetɪkəli ˈmɒdɪfaɪd ˈɔːɡənɪzəm/", "pron": "juh-NET-i-kuh-lee MOD-i-fyd OR-guh-niz-uhm", "fr": "organisme génétiquement modifié", "def": "An organism whose DNA has been deliberately altered.", "ex": "A genetically modified organism may resist disease or pests."}, {"term": "GMO", "ipa": "/ˌdʒiː em ˈəʊ/", "pron": "jee-em-oh", "fr": "OGM", "def": "Abbreviation for genetically modified organism.", "ex": "GMOs remain controversial in public debate."}, {"term": "transgenic organism", "ipa": "/trænzˌdʒenɪk ˈɔːɡənɪzəm/", "pron": "tranz-JEN-ik OR-guh-niz-uhm", "fr": "organisme transgénique", "def": "An organism containing genetic material from another species.", "ex": "A transgenic organism may produce a useful protein."}, {"term": "transgene", "ipa": "/ˈtrænzˌdʒiːn/", "pron": "TRANZ-jeen", "fr": "transgène", "def": "A gene transferred from one organism to another.", "ex": "A transgene can give a plant a new trait."}, {"term": "recombinant DNA", "ipa": "/rɪˈkɒmbɪnənt ˌdiː en ˈeɪ/", "pron": "ri-KOM-bi-nuhnt dee-en-ay", "fr": "ADN recombinant", "def": "DNA formed by combining genetic material from different sources.", "ex": "Recombinant DNA technology made modern biotechnology possible."}, {"term": "DNA", "ipa": "/ˌdiː en ˈeɪ/", "pron": "dee-en-ay", "fr": "ADN", "def": "Deoxyribonucleic acid, the molecule carrying genetic information.", "ex": "DNA contains the instructions inherited from parents."}, {"term": "RNA", "ipa": "/ˌɑːr en ˈeɪ/", "pron": "ar-en-ay", "fr": "ARN", "def": "Ribonucleic acid, a molecule involved in gene expression and protein production.", "ex": "RNA carries genetic messages inside cells."}, {"term": "gene", "ipa": "/dʒiːn/", "pron": "jeen", "fr": "gène", "def": "A unit of heredity made of DNA that influences traits or functions.", "ex": "A gene can affect eye colour or disease risk."}, {"term": "genome", "ipa": "/ˈdʒiːnəʊm/", "pron": "JEE-nohm", "fr": "génome", "def": "The complete set of genetic material in an organism.", "ex": "The genome can be edited with modern tools."}, {"term": "chromosome", "ipa": "/ˈkrəʊməsəʊm/", "pron": "KROH-muh-sohm", "fr": "chromosome", "def": "A DNA structure carrying many genes.", "ex": "Humans usually have 46 chromosomes."}, {"term": "allele", "ipa": "/əˈliːl/", "pron": "uh-LEEL", "fr": "allèle", "def": "A version of a gene.", "ex": "Different alleles can produce different traits."}, {"term": "trait", "ipa": "/treɪt/", "pron": "trayt", "fr": "caractère ; trait", "def": "A characteristic of an organism influenced by genes and environment.", "ex": "Height is a trait influenced by many genes."}, {"term": "phenotype", "ipa": "/ˈfiːnətaɪp/", "pron": "FEE-noh-type", "fr": "phénotype", "def": "The observable traits of an organism.", "ex": "The phenotype may change with the environment."}, {"term": "genotype", "ipa": "/ˈdʒenətaɪp/", "pron": "JEN-oh-type", "fr": "génotype", "def": "The genetic makeup of an organism.", "ex": "The genotype influences the phenotype."}, {"term": "mutation", "ipa": "/mjuːˈteɪʃən/", "pron": "myoo-TAY-shuhn", "fr": "mutation", "def": "A change in the DNA sequence.", "ex": "A mutation can be harmful, neutral or beneficial."}, {"term": "point mutation", "ipa": "/ˌpɔɪnt mjuːˈteɪʃən/", "pron": "point myoo-TAY-shuhn", "fr": "mutation ponctuelle", "def": "A mutation affecting a single DNA base.", "ex": "A point mutation can change a protein."}, {"term": "insertion", "ipa": "/ɪnˈsɜːʃən/", "pron": "in-SUR-shuhn", "fr": "insertion", "def": "A mutation where extra DNA is added.", "ex": "An insertion can disrupt a gene."}, {"term": "deletion", "ipa": "/dɪˈliːʃən/", "pron": "di-LEE-shuhn", "fr": "délétion", "def": "A mutation where DNA is removed.", "ex": "A deletion can cause a genetic disorder."}, {"term": "DNA sequencing", "ipa": "/ˌdiː en ˈeɪ ˈsiːkwənsɪŋ/", "pron": "dee-en-ay SEE-kwuhn-sing", "fr": "séquençage de l’ADN", "def": "Determining the order of DNA bases.", "ex": "DNA sequencing can identify mutations."}, {"term": "genome sequencing", "ipa": "/ˈdʒiːnəʊm ˈsiːkwənsɪŋ/", "pron": "JEE-nohm SEE-kwuhn-sing", "fr": "séquençage du génome", "def": "Determining the complete DNA sequence of a genome.", "ex": "Genome sequencing is used in research and medicine."}, {"term": "CRISPR", "ipa": "/ˈkrɪspə/", "pron": "KRIS-puh", "fr": "CRISPR", "def": "A gene-editing technology allowing targeted changes to DNA.", "ex": "CRISPR has made genetic engineering more precise."}, {"term": "CRISPR-Cas9", "ipa": "/ˈkrɪspə kæs naɪn/", "pron": "KRIS-puh cass-nine", "fr": "CRISPR-Cas9", "def": "A gene-editing system using Cas9 to cut DNA at a targeted location.", "ex": "CRISPR-Cas9 can cut DNA like molecular scissors."}, {"term": "Cas9", "ipa": "/ˈkæs naɪn/", "pron": "cass-nine", "fr": "Cas9", "def": "An enzyme used in CRISPR systems to cut DNA.", "ex": "Cas9 is guided to a specific DNA sequence."}, {"term": "guide RNA", "ipa": "/ˌɡaɪd ɑːr en ˈeɪ/", "pron": "guide ar-en-ay", "fr": "ARN guide", "def": "RNA that directs CRISPR machinery to a target DNA sequence.", "ex": "Guide RNA tells Cas9 where to cut."}, {"term": "molecular scissors", "ipa": "/məˌlekjʊlə ˈsɪzəz/", "pron": "muh-LEK-yuh-luh SIZ-uhz", "fr": "ciseaux moléculaires", "def": "A metaphor for tools that cut DNA at specific points.", "ex": "CRISPR is often described as molecular scissors."}, {"term": "target sequence", "ipa": "/ˈtɑːɡɪt ˈsiːkwəns/", "pron": "TAR-git SEE-kwuhns", "fr": "séquence cible", "def": "The DNA sequence selected for editing.", "ex": "The target sequence must be chosen carefully."}, {"term": "off-target effect", "ipa": "/ˌɒf ˈtɑːɡɪt ɪˌfekt/", "pron": "off-TAR-git i-FEKT", "fr": "effet hors cible", "def": "An unintended genetic change at the wrong location.", "ex": "Off-target effects are a safety concern."}]}, {"title": "B. CRISPR, editing tools and gene-function techniques", "entries": [{"term": "precision", "ipa": "/prɪˈsɪʒən/", "pron": "pri-SIZH-uhn", "fr": "précision", "def": "The quality of being exact or accurate.", "ex": "Greater precision reduces unintended genetic damage."}, {"term": "accuracy", "ipa": "/ˈækjʊrəsi/", "pron": "AK-yuh-ruh-see", "fr": "exactitude ; précision", "def": "The quality of being correct or reliable.", "ex": "Accuracy matters in medical gene editing."}, {"term": "base editing", "ipa": "/ˈbeɪs ˌedɪtɪŋ/", "pron": "bayce ED-it-ing", "fr": "édition de base", "def": "A gene-editing technique changing a single DNA base without cutting both DNA strands.", "ex": "Base editing may correct some point mutations."}, {"term": "prime editing", "ipa": "/ˈpraɪm ˌedɪtɪŋ/", "pron": "prime ED-it-ing", "fr": "prime editing ; édition primaire", "def": "A gene-editing technique able to make precise DNA changes without double-strand breaks.", "ex": "Prime editing is sometimes called a search-and-replace tool for DNA."}, {"term": "gene drive", "ipa": "/ˈdʒiːn draɪv/", "pron": "jeen dryv", "fr": "forçage génétique", "def": "A genetic system designed to spread a trait rapidly through a population.", "ex": "Gene drives could be used to control disease-carrying mosquitoes."}, {"term": "horizontal gene transfer", "ipa": "/ˌhɒrɪˈzɒntəl ˈdʒiːn ˌtrænsfɜː/", "pron": "hor-i-ZON-tuhl jeen TRANS-fur", "fr": "transfert horizontal de gènes", "def": "Transfer of genetic material between organisms outside reproduction.", "ex": "Horizontal gene transfer is common in bacteria."}, {"term": "vector", "ipa": "/ˈvektə/", "pron": "VEK-tuh", "fr": "vecteur", "def": "A carrier used to deliver genetic material into cells.", "ex": "Viruses can be used as vectors in gene therapy."}, {"term": "viral vector", "ipa": "/ˈvaɪrəl ˌvektə/", "pron": "VY-ruhl VEK-tuh", "fr": "vecteur viral", "def": "A virus modified to deliver genetic material safely.", "ex": "A viral vector can carry a therapeutic gene."}, {"term": "plasmid", "ipa": "/ˈplæzmɪd/", "pron": "PLAZ-mid", "fr": "plasmide", "def": "A small circular DNA molecule often used in genetic engineering.", "ex": "Scientists use plasmids to transfer genes into bacteria."}, {"term": "restriction enzyme", "ipa": "/rɪˈstrɪkʃən ˈenzaɪm/", "pron": "ri-STRIK-shuhn EN-zyme", "fr": "enzyme de restriction", "def": "An enzyme that cuts DNA at specific sequences.", "ex": "Restriction enzymes are important tools in molecular biology."}, {"term": "DNA ligase", "ipa": "/ˌdiː en ˈeɪ ˈlaɪɡeɪs/", "pron": "dee-en-ay LYE-gayz", "fr": "ADN ligase", "def": "An enzyme that joins DNA fragments together.", "ex": "DNA ligase helps build recombinant DNA."}, {"term": "polymerase chain reaction", "ipa": "/pəˈlɪməreɪz tʃeɪn riˈækʃən/", "pron": "puh-LIM-uh-rayz chain ree-AK-shuhn", "fr": "réaction en chaîne par polymérase", "def": "A laboratory technique used to amplify DNA.", "ex": "PCR can produce millions of copies of a DNA sequence."}, {"term": "PCR", "ipa": "/ˌpiː siː ˈɑː/", "pron": "pee-see-ar", "fr": "PCR", "def": "Abbreviation for polymerase chain reaction.", "ex": "PCR is widely used in testing and research."}, {"term": "gene expression", "ipa": "/ˈdʒiːn ɪkˌspreʃən/", "pron": "jeen ik-SPRESH-uhn", "fr": "expression génique", "def": "The process by which information in a gene is used to make a functional product.", "ex": "Gene expression can be turned up or down."}, {"term": "gene silencing", "ipa": "/ˈdʒiːn ˌsaɪlənsɪŋ/", "pron": "jeen SY-luhn-sing", "fr": "silencement génique", "def": "Reducing or stopping the activity of a gene.", "ex": "Gene silencing can block harmful protein production."}, {"term": "knockout", "ipa": "/ˈnɒkaʊt/", "pron": "NOK-owt", "fr": "inactivation d’un gène ; knockout", "def": "A genetic modification that disables a gene.", "ex": "A knockout mouse can help researchers study gene function."}, {"term": "knock-in", "ipa": "/ˈnɒk ɪn/", "pron": "NOK-in", "fr": "insertion ciblée ; knock-in", "def": "A genetic modification that inserts a gene or sequence into a genome.", "ex": "A knock-in can introduce a disease-related mutation."}, {"term": "gene therapy", "ipa": "/ˈdʒiːn ˌθerəpi/", "pron": "jeen THERR-uh-pee", "fr": "thérapie génique", "def": "Treatment that modifies, replaces or adds genes to treat disease.", "ex": "Gene therapy may cure some inherited disorders."}, {"term": "somatic gene therapy", "ipa": "/səʊˌmætɪk ˈdʒiːn ˌθerəpi/", "pron": "soh-MAT-ik jeen THERR-uh-pee", "fr": "thérapie génique somatique", "def": "Gene therapy targeting body cells, not reproductive cells.", "ex": "Somatic gene therapy affects only the treated patient."}, {"term": "germline editing", "ipa": "/ˈdʒɜːmlaɪn ˌedɪtɪŋ/", "pron": "JURM-line ED-it-ing", "fr": "édition de la lignée germinale", "def": "Editing genes in eggs, sperm or embryos so changes can be inherited.", "ex": "Germline editing is ethically controversial."}, {"term": "somatic cell", "ipa": "/səʊˌmætɪk ˈsel/", "pron": "soh-MAT-ik sel", "fr": "cellule somatique", "def": "A body cell that is not a reproductive cell.", "ex": "Somatic cells do not pass genetic changes to offspring."}, {"term": "germ cell", "ipa": "/ˈdʒɜːm sel/", "pron": "jurm sel", "fr": "cellule germinale", "def": "A reproductive cell or precursor cell involved in inheritance.", "ex": "Changes in germ cells can be inherited."}, {"term": "embryo", "ipa": "/ˈembriəʊ/", "pron": "EM-bree-oh", "fr": "embryon", "def": "An early stage of development after fertilisation.", "ex": "Editing an embryo raises major ethical concerns."}, {"term": "designer baby", "ipa": "/dɪˌzaɪnə ˈbeɪbi/", "pron": "di-ZY-nuh BAY-bee", "fr": "bébé sur mesure", "def": "A child whose genetic traits have been selected or modified, especially for non-medical reasons.", "ex": "The idea of designer babies worries many ethicists."}]}, {"title": "C. Human gene editing, ethics and social risks", "entries": [{"term": "enhancement", "ipa": "/ɪnˈhɑːnsmənt/", "pron": "in-HAHNS-muhnt", "fr": "amélioration ; enhancement", "def": "Improving traits beyond normal health or treatment.", "ex": "Genetic enhancement raises questions about fairness."}, {"term": "therapy versus enhancement", "ipa": "/ˈθerəpi ˈvɜːsəs ɪnˈhɑːnsmənt/", "pron": "THERR-uh-pee VUR-suhs in-HAHNS-muhnt", "fr": "thérapie contre amélioration", "def": "The distinction between treating disease and improving traits beyond normal function.", "ex": "The line between therapy and enhancement can be hard to draw."}, {"term": "eugenics", "ipa": "/juːˈdʒenɪks/", "pron": "yoo-JEN-iks", "fr": "eugénisme", "def": "The discredited practice or ideology of trying to improve human populations through selective breeding or genetic control.", "ex": "Genetic engineering revives fears of eugenics."}, {"term": "inherited change", "ipa": "/ɪnˌherɪtɪd ˈtʃeɪndʒ/", "pron": "in-HERR-i-tid chaynj", "fr": "changement héréditaire", "def": "A genetic change passed to future generations.", "ex": "Germline editing creates inherited changes."}, {"term": "informed consent", "ipa": "/ɪnˌfɔːmd kənˈsent/", "pron": "in-FORMD kuhn-SENT", "fr": "consentement éclairé", "def": "Permission given after understanding risks, benefits and alternatives.", "ex": "Future generations cannot give informed consent to germline editing."}, {"term": "bioethics", "ipa": "/ˌbaɪəʊˈeθɪks/", "pron": "BY-oh-ETH-iks", "fr": "bioéthique", "def": "The study of ethical issues in biology, medicine and biotechnology.", "ex": "Bioethics is central to debates over human gene editing."}, {"term": "ethical dilemma", "ipa": "/ˌeθɪkəl dɪˈlemə/", "pron": "ETH-i-kuhl di-LEM-uh", "fr": "dilemme éthique", "def": "A situation involving difficult moral choices.", "ex": "Editing embryos creates ethical dilemmas."}, {"term": "moral boundary", "ipa": "/ˌmɒrəl ˈbaʊndəri/", "pron": "MOR-uhl BOWN-duh-ree", "fr": "limite morale", "def": "A limit that society considers morally important.", "ex": "Human enhancement may cross a moral boundary."}, {"term": "slippery slope", "ipa": "/ˌslɪpəri ˈsləʊp/", "pron": "SLIP-uh-ree slohp", "fr": "pente glissante", "def": "A situation where one step may lead to more extreme consequences.", "ex": "Critics warn of a slippery slope from therapy to enhancement."}, {"term": "genetic privacy", "ipa": "/dʒəˌnetɪk ˈprɪvəsi/", "pron": "juh-NET-ik PRIV-uh-see", "fr": "confidentialité génétique", "def": "Protection of a person’s genetic information.", "ex": "Genetic privacy is difficult because DNA reveals family information."}, {"term": "genetic data", "ipa": "/dʒəˌnetɪk ˈdeɪtə/", "pron": "juh-NET-ik DAY-tuh", "fr": "données génétiques", "def": "Information derived from DNA or genetic testing.", "ex": "Genetic data must be protected carefully."}, {"term": "genetic discrimination", "ipa": "/dʒəˌnetɪk dɪˌskrɪmɪˈneɪʃən/", "pron": "juh-NET-ik dis-krim-i-NAY-shuhn", "fr": "discrimination génétique", "def": "Unfair treatment based on genetic information.", "ex": "Genetic discrimination could affect insurance or employment."}, {"term": "patent", "ipa": "/ˈpætənt/", "pron": "PAT-uhnt", "fr": "brevet", "def": "A legal right protecting an invention from being copied without permission.", "ex": "Patents can make therapies expensive."}, {"term": "intellectual property", "ipa": "/ˌɪntəˈlektʃuəl ˈprɒpəti/", "pron": "IN-tuh-LEK-choo-uhl PROP-uh-tee", "fr": "propriété intellectuelle", "def": "Legal rights over inventions, designs or discoveries.", "ex": "Intellectual property shapes access to gene-editing tools."}, {"term": "access to treatment", "ipa": "/ˌækses tə ˈtriːtmənt/", "pron": "AK-ses tuh TREET-muhnt", "fr": "accès au traitement", "def": "The ability of patients to receive medical care or therapy.", "ex": "Expensive gene therapies may limit access to treatment."}, {"term": "health inequality", "ipa": "/ˈhelθ ˌɪnɪˈkwɒləti/", "pron": "health in-i-KWOL-uh-tee", "fr": "inégalité de santé", "def": "Unequal health outcomes or access between groups.", "ex": "Genetic engineering could widen health inequality."}, {"term": "regulation", "ipa": "/ˌreɡjʊˈleɪʃən/", "pron": "reg-yuh-LAY-shuhn", "fr": "réglementation", "def": "Rules made by authorities to control activities or technologies.", "ex": "Regulation must keep pace with genetic engineering."}, {"term": "regulatory approval", "ipa": "/ˌreɡjʊlətəri əˈpruːvəl/", "pron": "REG-yuh-luh-tuh-ree uh-PROO-vuhl", "fr": "approbation réglementaire", "def": "Official permission after safety and quality standards are met.", "ex": "Gene therapies require regulatory approval."}, {"term": "clinical trial", "ipa": "/ˌklɪnɪkəl ˈtraɪəl/", "pron": "KLIN-i-kuhl TRY-uhl", "fr": "essai clinique", "def": "A research study testing a treatment in human participants.", "ex": "Clinical trials test whether gene therapy is safe and effective."}, {"term": "safety assessment", "ipa": "/ˈseɪfti əˌsesmənt/", "pron": "SAYF-tee uh-SESS-muhnt", "fr": "évaluation de la sécurité", "def": "Evaluation of possible risks and harms.", "ex": "A safety assessment must consider off-target effects."}, {"term": "risk assessment", "ipa": "/ˈrɪsk əˌsesmənt/", "pron": "risk uh-SESS-muhnt", "fr": "évaluation des risques", "def": "Evaluation of possible risks and their likelihood.", "ex": "Risk assessment is essential before release into the environment."}, {"term": "long-term effects", "ipa": "/ˌlɒŋ tɜːm ɪˈfekts/", "pron": "long-term i-FEKTS", "fr": "effets à long terme", "def": "Consequences that appear or continue over a long period.", "ex": "The long-term effects of germline editing are uncertain."}, {"term": "environmental impact", "ipa": "/ɪnˌvaɪrənˈmentəl ˈɪmpækt/", "pron": "in-vy-ruhn-MEN-tuhl IM-pakt", "fr": "impact environnemental", "def": "The effect of an activity or technology on the environment.", "ex": "GM crops require environmental impact assessment."}, {"term": "ecological risk", "ipa": "/ˌiːkəˈlɒdʒɪkəl rɪsk/", "pron": "ee-kuh-LOJ-i-kuhl risk", "fr": "risque écologique", "def": "A risk to ecosystems, species or natural balances.", "ex": "Gene drives could create ecological risks."}, {"term": "biodiversity", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti/", "pron": "BY-oh-dy-VUR-suh-tee", "fr": "biodiversité", "def": "The variety of living organisms in an ecosystem or on Earth.", "ex": "Genetic engineering could affect biodiversity."}, {"term": "cross-pollination", "ipa": "/ˌkrɒs ˌpɒlɪˈneɪʃən/", "pron": "cross-pol-i-NAY-shuhn", "fr": "pollinisation croisée", "def": "Transfer of pollen between different plants.", "ex": "Cross-pollination can spread engineered traits."}, {"term": "gene flow", "ipa": "/ˈdʒiːn fləʊ/", "pron": "jeen floh", "fr": "flux génétique", "def": "Movement of genes between populations.", "ex": "Gene flow from GM crops to wild relatives is debated."}, {"term": "containment", "ipa": "/kənˈteɪnmənt/", "pron": "kuhn-TAYN-muhnt", "fr": "confinement", "def": "Measures preventing organisms or genetic material from spreading.", "ex": "Containment is crucial in laboratory work."}, {"term": "biosafety", "ipa": "/ˌbaɪəʊˈseɪfti/", "pron": "BY-oh-SAYF-tee", "fr": "biosécurité sanitaire", "def": "Measures preventing accidental harm from biological agents or technologies.", "ex": "Biosafety rules reduce laboratory risks."}, {"term": "biosecurity", "ipa": "/ˌbaɪəʊsɪˈkjʊərəti/", "pron": "BY-oh-si-KYOOR-uh-tee", "fr": "biosécurité ; sécurité biologique", "def": "Protection against deliberate misuse of biological knowledge or materials.", "ex": "Gene editing creates biosecurity challenges."}, {"term": "dual-use research", "ipa": "/ˌdjuːəl juːs rɪˈsɜːtʃ/", "pron": "DYOO-uhl yooss ri-SURCH", "fr": "recherche à double usage", "def": "Research that can be used for both beneficial and harmful purposes.", "ex": "Dual-use research requires careful oversight."}, {"term": "misuse", "ipa": "/ˌmɪsˈjuːs/", "pron": "mis-YOOSS", "fr": "mauvais usage ; abus", "def": "Harmful or improper use of a technology.", "ex": "The misuse of genetic tools could have serious consequences."}, {"term": "bioterrorism", "ipa": "/ˌbaɪəʊˈterərɪzəm/", "pron": "BY-oh-TERR-uh-riz-uhm", "fr": "bioterrorisme", "def": "The use of biological agents to harm or terrorise people.", "ex": "Biosecurity aims to prevent bioterrorism."}, {"term": "synthetic biology", "ipa": "/sɪnˌθetɪk baɪˈɒlədʒi/", "pron": "sin-THET-ik by-OL-uh-jee", "fr": "biologie synthétique", "def": "The design and construction of new biological systems or redesigned organisms.", "ex": "Synthetic biology overlaps with genetic engineering."}]}, {"title": "D. GMOs, environment, agriculture and governance", "entries": [{"term": "engineered organism", "ipa": "/ˌendʒɪˈnɪəd ˈɔːɡənɪzəm/", "pron": "en-ji-NEERD OR-guh-niz-uhm", "fr": "organisme modifié ; organisme conçu", "def": "An organism deliberately modified by biotechnology.", "ex": "Engineered organisms can produce medicines or materials."}, {"term": "engineered microbe", "ipa": "/ˌendʒɪˈnɪəd ˈmaɪkrəʊb/", "pron": "en-ji-NEERD MY-krohb", "fr": "microbe modifié", "def": "A microorganism modified for a specific function.", "ex": "Engineered microbes can produce insulin."}, {"term": "biofactory", "ipa": "/ˈbaɪəʊˌfæktəri/", "pron": "BY-oh-FAK-tuh-ree", "fr": "bio-usine", "def": "A biological system used to produce useful substances.", "ex": "A modified cell can act as a biofactory."}, {"term": "biomanufacturing", "ipa": "/ˌbaɪəʊˌmænjʊˈfæktʃərɪŋ/", "pron": "BY-oh-man-yoo-FAK-chuh-ring", "fr": "biofabrication industrielle", "def": "Using biological systems to manufacture products.", "ex": "Biomanufacturing can produce enzymes and medicines."}, {"term": "industrial biotechnology", "ipa": "/ɪnˌdʌstriəl ˌbaɪəʊtekˈnɒlədʒi/", "pron": "in-DUS-tree-uhl BY-oh-tek-NOL-uh-jee", "fr": "biotechnologie industrielle", "def": "Biotechnology applied to industrial production.", "ex": "Industrial biotechnology may reduce fossil-resource use."}, {"term": "agricultural biotechnology", "ipa": "/ˌæɡrɪˈkʌltʃərəl ˌbaɪəʊtekˈnɒlədʒi/", "pron": "ag-ri-KUL-chuh-ruhl BY-oh-tek-NOL-uh-jee", "fr": "biotechnologie agricole", "def": "Biotechnology applied to crops, livestock and farming.", "ex": "Agricultural biotechnology can help crops resist pests."}, {"term": "GM crop", "ipa": "/ˌdʒiː em ˈkrɒp/", "pron": "jee-em crop", "fr": "culture génétiquement modifiée", "def": "A genetically modified crop.", "ex": "GM crops are widely grown in some regions."}, {"term": "herbicide-resistant crop", "ipa": "/ˈhɜːbɪsaɪd rɪˌzɪstənt krɒp/", "pron": "HUR-bi-syd-ri-ZIS-tuhnt crop", "fr": "culture résistante aux herbicides", "def": "A crop engineered to tolerate specific herbicides.", "ex": "Herbicide-resistant crops can change farming practices."}, {"term": "pest-resistant crop", "ipa": "/ˈpest rɪˌzɪstənt krɒp/", "pron": "pest-ri-ZIS-tuhnt crop", "fr": "culture résistante aux nuisibles", "def": "A crop engineered or bred to resist pests.", "ex": "Pest-resistant crops may reduce pesticide use."}, {"term": "drought-resistant crop", "ipa": "/ˈdraʊt rɪˌzɪstənt krɒp/", "pron": "drowt-ri-ZIS-tuhnt crop", "fr": "culture résistante à la sécheresse", "def": "A crop able to survive with less water.", "ex": "Drought-resistant crops may help adapt to climate change."}, {"term": "crop yield", "ipa": "/ˈkrɒp jiːld/", "pron": "crop yeeld", "fr": "rendement agricole", "def": "The amount of crop produced per area of land.", "ex": "Genetic engineering can improve crop yield."}, {"term": "food security", "ipa": "/ˈfuːd sɪˌkjʊərəti/", "pron": "food si-KYOOR-uh-tee", "fr": "sécurité alimentaire", "def": "Reliable access to enough safe and nutritious food.", "ex": "Supporters link GM crops to food security."}, {"term": "patented seed", "ipa": "/ˌpætəntɪd ˈsiːd/", "pron": "PAT-uhn-tid seed", "fr": "semence brevetée", "def": "A seed protected by intellectual property rights.", "ex": "Patented seeds create dependence on large companies."}, {"term": "seed monopoly", "ipa": "/ˈsiːd məˌnɒpəli/", "pron": "seed muh-NOP-uh-lee", "fr": "monopole des semences", "def": "Control of the seed market by one or a few companies.", "ex": "Critics fear a seed monopoly in GM agriculture."}, {"term": "corporate control", "ipa": "/ˈkɔːpərət kənˌtrəʊl/", "pron": "KOR-puh-ruht kuhn-TROHL", "fr": "contrôle des entreprises", "def": "Power held by companies over a market, technology or resource.", "ex": "Corporate control is a concern in agricultural biotechnology."}, {"term": "public trust", "ipa": "/ˌpʌblɪk ˈtrʌst/", "pron": "PUB-lik trust", "fr": "confiance du public", "def": "Confidence people have in institutions, science or technology.", "ex": "Public trust is essential for accepting genetic engineering."}, {"term": "public acceptance", "ipa": "/ˌpʌblɪk əkˈseptəns/", "pron": "PUB-lik ak-SEP-tuhns", "fr": "acceptation du public", "def": "The willingness of society to accept a technology or policy.", "ex": "Public acceptance depends on transparency and safety."}, {"term": "risk perception", "ipa": "/ˈrɪsk pəˌsepʃən/", "pron": "risk puh-SEP-shuhn", "fr": "perception du risque", "def": "How people understand and feel about risk.", "ex": "Risk perception differs between scientists and the public."}, {"term": "precautionary principle", "ipa": "/prɪˈkɔːʃənəri ˈprɪnsəpəl/", "pron": "pri-KAW-shuhn-uh-ree PRIN-suh-puhl", "fr": "principe de précaution", "def": "The idea that action should be cautious when risks are uncertain.", "ex": "The precautionary principle influences European GMO policy."}, {"term": "scientific uncertainty", "ipa": "/ˌsaɪənˈtɪfɪk ʌnˈsɜːtnti/", "pron": "sy-uhn-TIF-ik un-SUR-tn-tee", "fr": "incertitude scientifique", "def": "A lack of full certainty in scientific evidence.", "ex": "Scientific uncertainty does not always mean danger."}, {"term": "moratorium", "ipa": "/ˌmɒrəˈtɔːriəm/", "pron": "mor-uh-TOR-ee-uhm", "fr": "moratoire", "def": "A temporary ban or suspension of an activity.", "ex": "Some scientists have called for a moratorium on heritable genome editing."}, {"term": "oversight", "ipa": "/ˈəʊvəsaɪt/", "pron": "OH-vuh-syte", "fr": "surveillance ; contrôle", "def": "Supervision to ensure rules, safety and accountability.", "ex": "Strong oversight is needed for gene-editing research."}, {"term": "governance", "ipa": "/ˈɡʌvənəns/", "pron": "GUV-uh-nuhns", "fr": "gouvernance", "def": "The systems and rules used to manage a technology or institution.", "ex": "Global governance of gene editing remains uneven."}, {"term": "international guidelines", "ipa": "/ˌɪntəˈnæʃənəl ˈɡaɪdlaɪnz/", "pron": "IN-tuh-NASH-uh-nuhl GYDE-lynz", "fr": "directives internationales", "def": "Recommendations agreed across countries or organisations.", "ex": "International guidelines can reduce irresponsible research."}, {"term": "to modify DNA", "ipa": "/ˈmɒdɪfaɪ ˌdiː en ˈeɪ/", "pron": "MOD-i-fy dee-en-ay", "fr": "modifier l’ADN", "def": "To change DNA deliberately.", "ex": "Scientists can modify DNA to study gene function."}, {"term": "to insert a gene", "ipa": "/ɪnˈsɜːt ə dʒiːn/", "pron": "in-SURT uh jeen", "fr": "insérer un gène", "def": "To add a gene to an organism’s genome.", "ex": "Researchers insert a gene to produce a useful protein."}, {"term": "to delete a gene", "ipa": "/dɪˈliːt ə dʒiːn/", "pron": "di-LEET uh jeen", "fr": "supprimer un gène", "def": "To remove a gene from a genome.", "ex": "Scientists may delete a gene to understand its role."}, {"term": "to silence a gene", "ipa": "/ˈsaɪləns ə dʒiːn/", "pron": "SY-luhns uh jeen", "fr": "silencer un gène", "def": "To reduce or stop the activity of a gene.", "ex": "Therapies may silence a gene that produces a toxic protein."}, {"term": "to correct a mutation", "ipa": "/kəˈrekt ə mjuːˈteɪʃən/", "pron": "kuh-REKT uh myoo-TAY-shuhn", "fr": "corriger une mutation", "def": "To repair or change a harmful DNA mutation.", "ex": "Gene editing could correct a mutation causing disease."}, {"term": "to alter inherited traits", "ipa": "/ˈɔːltər ɪnˌherɪtɪd treɪts/", "pron": "AWL-tuh in-HERR-i-tid trayts", "fr": "modifier des traits héréditaires", "def": "To change traits passed from parents to offspring.", "ex": "Germline editing could alter inherited traits."}, {"term": "to enhance human abilities", "ipa": "/ɪnˈhɑːns ˌhjuːmən əˈbɪlətiz/", "pron": "in-HAHNS HYOO-muhn uh-BIL-uh-teez", "fr": "améliorer les capacités humaines", "def": "To improve human capacities beyond treatment.", "ex": "Using genetic tools to enhance human abilities is controversial."}, {"term": "to engineer a crop", "ipa": "/ˌendʒɪˈnɪər ə krɒp/", "pron": "en-ji-NEER uh crop", "fr": "modifier génétiquement une culture", "def": "To genetically modify a crop for a desired trait.", "ex": "Scientists engineer a crop to resist drought."}, {"term": "to release a GMO", "ipa": "/rɪˈliːs ə ˌdʒiː em ˈəʊ/", "pron": "ri-LEESS uh jee-em-oh", "fr": "libérer / commercialiser un OGM", "def": "To introduce a genetically modified organism into use or the environment.", "ex": "Regulators assess risks before releasing a GMO."}, {"term": "to assess environmental risks", "ipa": "/əˈses ɪnˌvaɪrənˈmentəl rɪsks/", "pron": "uh-SESS in-vy-ruhn-MEN-tuhl risks", "fr": "évaluer les risques environnementaux", "def": "To evaluate possible environmental harms.", "ex": "Authorities must assess environmental risks before approval."}, {"term": "to prevent genetic discrimination", "ipa": "/prɪˈvent dʒəˌnetɪk dɪˌskrɪmɪˈneɪʃən/", "pron": "pri-VENT juh-NET-ik dis-krim-i-NAY-shuhn", "fr": "empêcher la discrimination génétique", "def": "To stop unfair treatment based on genetic information.", "ex": "Laws should prevent genetic discrimination."}, {"term": "to regulate gene editing", "ipa": "/ˈreɡjʊleɪt ˈdʒiːn ˌedɪtɪŋ/", "pron": "REG-yuh-layt jeen ED-it-ing", "fr": "réglementer l’édition génétique", "def": "To create and enforce rules for gene editing.", "ex": "Governments must regulate gene editing carefully."}, {"term": "to draw a line between therapy and enhancement", "ipa": "/drɔː ə laɪn bɪˈtwiːn ˈθerəpi ənd ɪnˈhɑːnsmənt/", "pron": "draw uh line between THERR-uh-pee and in-HAHNS-muhnt", "fr": "tracer une limite entre thérapie et amélioration", "def": "To distinguish medical treatment from non-medical improvement.", "ex": "Societies must draw a line between therapy and enhancement."}, {"term": "to balance progress and precaution", "ipa": "/ˈbæləns ˈprəʊɡres ənd prɪˈkɔːʃən/", "pron": "BAL-uhns PROH-gress and pri-KAW-shuhn", "fr": "équilibrer progrès et précaution", "def": "To encourage innovation while acting carefully under uncertainty.", "ex": "Gene-editing policy must balance progress and precaution."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p8c67", "part": 8, "chapter": 67, "title": "Climate Change", "file": "cpge_vocab_part8_chapter67_climate_change_premium.html", "count": 133, "sections": [{"title": "A. Core climate science and emissions vocabulary", "entries": [{"term": "climate change", "ipa": "/ˈklaɪmət tʃeɪndʒ/", "pron": "KLY-muht chaynj", "fr": "changement climatique", "def": "Long-term changes in global or regional climate patterns, largely driven today by human greenhouse gas emissions.", "ex": "Climate change is one of the defining challenges of the 21st century."}, {"term": "global warming", "ipa": "/ˌɡləʊbəl ˈwɔːmɪŋ/", "pron": "GLOH-buhl WAR-ming", "fr": "réchauffement climatique", "def": "The long-term rise in Earth’s average temperature.", "ex": "Global warming increases the frequency of extreme heat."}, {"term": "climate crisis", "ipa": "/ˈklaɪmət ˌkraɪsɪs/", "pron": "KLY-muht KRY-sis", "fr": "crise climatique", "def": "A term stressing the urgency and seriousness of climate change.", "ex": "Activists use the term climate crisis to demand faster action."}, {"term": "climate emergency", "ipa": "/ˈklaɪmət ɪˌmɜːdʒənsi/", "pron": "KLY-muht i-MUR-juhn-see", "fr": "urgence climatique", "def": "A situation requiring urgent action to address climate change.", "ex": "Some cities have declared a climate emergency."}, {"term": "greenhouse effect", "ipa": "/ˈɡriːnhaʊs ɪˌfekt/", "pron": "GREEN-house i-FEKT", "fr": "effet de serre", "def": "The natural process by which gases trap heat in Earth’s atmosphere.", "ex": "The greenhouse effect makes Earth habitable, but human activity has intensified it."}, {"term": "greenhouse gas", "ipa": "/ˈɡriːnhaʊs ɡæs/", "pron": "GREEN-house gas", "fr": "gaz à effet de serre", "def": "A gas that traps heat in the atmosphere.", "ex": "Carbon dioxide and methane are greenhouse gases."}, {"term": "GHG", "ipa": "/ˌdʒiː eɪtʃ ˈdʒiː/", "pron": "jee-aych-jee", "fr": "GES", "def": "Abbreviation for greenhouse gas.", "ex": "GHG emissions must fall rapidly to limit warming."}, {"term": "carbon dioxide", "ipa": "/ˌkɑːbən daɪˈɒksaɪd/", "pron": "KAR-buhn dy-OK-syde", "fr": "dioxyde de carbone", "def": "A greenhouse gas released by burning fossil fuels and other processes.", "ex": "Carbon dioxide remains in the atmosphere for a long time."}, {"term": "CO2", "ipa": "/ˌsiː əʊ ˈtuː/", "pron": "see-oh-too", "fr": "CO2", "def": "Chemical formula for carbon dioxide.", "ex": "CO2 emissions are central to climate policy."}, {"term": "methane", "ipa": "/ˈmiːθeɪn/", "pron": "MEE-thayn", "fr": "méthane", "def": "A powerful greenhouse gas released by agriculture, fossil fuels and waste.", "ex": "Methane has a stronger warming effect than CO2 over the short term."}, {"term": "nitrous oxide", "ipa": "/ˌnaɪtrəs ˈɒksaɪd/", "pron": "NY-truhs OK-syde", "fr": "protoxyde d’azote", "def": "A greenhouse gas linked especially to agriculture and fertilisers.", "ex": "Nitrous oxide emissions are difficult to reduce."}, {"term": "emissions", "ipa": "/ɪˈmɪʃənz/", "pron": "i-MISH-uhnz", "fr": "émissions", "def": "Polluting gases released into the atmosphere.", "ex": "Transport and energy production create large emissions."}, {"term": "carbon emissions", "ipa": "/ˈkɑːbən ɪˌmɪʃənz/", "pron": "KAR-buhn i-MISH-uhnz", "fr": "émissions de carbone", "def": "Emissions of carbon dioxide or other carbon-based greenhouse gases.", "ex": "Carbon emissions must be cut to reach climate goals."}, {"term": "fossil fuels", "ipa": "/ˈfɒsəl ˌfjuːəlz/", "pron": "FOS-uhl FYOO-uhlz", "fr": "combustibles fossiles ; énergies fossiles", "def": "Coal, oil and gas formed from ancient organic matter.", "ex": "Fossil fuels are the main driver of climate change."}, {"term": "coal", "ipa": "/kəʊl/", "pron": "kohl", "fr": "charbon", "def": "A fossil fuel used for electricity and industry.", "ex": "Coal is the most carbon-intensive fossil fuel."}, {"term": "oil", "ipa": "/ɔɪl/", "pron": "oil", "fr": "pétrole", "def": "A fossil fuel used for transport, plastics and industry.", "ex": "Oil demand remains high despite climate commitments."}, {"term": "natural gas", "ipa": "/ˌnætʃərəl ˈɡæs/", "pron": "NAT-chuh-ruhl gas", "fr": "gaz naturel", "def": "A fossil fuel used for heating, electricity and industry.", "ex": "Natural gas emits less CO2 than coal but still contributes to warming."}, {"term": "energy transition", "ipa": "/ˈenədʒi trænˌzɪʃən/", "pron": "EN-uh-jee tran-ZISH-uhn", "fr": "transition énergétique", "def": "The shift from fossil fuels to low-carbon energy systems.", "ex": "The energy transition requires investment, regulation and public support."}, {"term": "renewable energy", "ipa": "/rɪˌnjuːəbəl ˈenədʒi/", "pron": "ri-NYOO-uh-buhl EN-uh-jee", "fr": "énergie renouvelable", "def": "Energy from sources naturally replenished, such as sun, wind and water.", "ex": "Renewable energy is expanding quickly."}, {"term": "solar power", "ipa": "/ˈsəʊlə ˌpaʊə/", "pron": "SOH-luh POW-uh", "fr": "énergie solaire", "def": "Electricity generated from sunlight.", "ex": "Solar power has become cheaper over time."}, {"term": "wind power", "ipa": "/ˈwɪnd ˌpaʊə/", "pron": "wind POW-uh", "fr": "énergie éolienne", "def": "Electricity generated from wind turbines.", "ex": "Wind power is central to many decarbonisation plans."}, {"term": "hydropower", "ipa": "/ˈhaɪdrəʊˌpaʊə/", "pron": "HY-droh-POW-uh", "fr": "hydroélectricité", "def": "Electricity generated from moving water.", "ex": "Hydropower is renewable but can affect ecosystems."}, {"term": "nuclear power", "ipa": "/ˈnjuːkliə ˌpaʊə/", "pron": "NYOO-klee-uh POW-uh", "fr": "énergie nucléaire", "def": "Electricity generated from nuclear reactions.", "ex": "Nuclear power is low-carbon but controversial."}, {"term": "low-carbon energy", "ipa": "/ˌləʊ ˈkɑːbən ˈenədʒi/", "pron": "loh-KAR-buhn EN-uh-jee", "fr": "énergie bas carbone", "def": "Energy that produces little greenhouse gas pollution.", "ex": "Low-carbon energy includes renewables and nuclear power."}, {"term": "decarbonisation", "ipa": "/ˌdiːkɑːbənaɪˈzeɪʃən/", "pron": "dee-kar-buh-ny-ZAY-shuhn", "fr": "décarbonation", "def": "Reducing or eliminating carbon emissions from the economy.", "ex": "Decarbonisation requires changes in energy, transport and industry."}, {"term": "carbon neutrality", "ipa": "/ˌkɑːbən njuːˈtræləti/", "pron": "KAR-buhn nyoo-TRAL-uh-tee", "fr": "neutralité carbone", "def": "Balancing emitted carbon with removed or offset carbon.", "ex": "Many countries have pledged carbon neutrality by mid-century."}, {"term": "net zero", "ipa": "/ˌnet ˈzɪərəʊ/", "pron": "net ZEER-oh", "fr": "zéro émission nette", "def": "A state where greenhouse gas emissions are balanced by removals.", "ex": "Net zero requires deep emissions cuts, not just offsets."}, {"term": "carbon footprint", "ipa": "/ˌkɑːbən ˈfʊtprɪnt/", "pron": "KAR-buhn FOOT-print", "fr": "empreinte carbone", "def": "The total greenhouse gas emissions caused by a person, product or activity.", "ex": "Flying increases a person’s carbon footprint."}, {"term": "carbon budget", "ipa": "/ˈkɑːbən ˌbʌdʒɪt/", "pron": "KAR-buhn BUJ-it", "fr": "budget carbone", "def": "The maximum amount of CO2 that can be emitted while keeping warming below a target.", "ex": "The remaining carbon budget is shrinking."}, {"term": "carbon sink", "ipa": "/ˈkɑːbən sɪŋk/", "pron": "KAR-buhn sink", "fr": "puits de carbone", "def": "A natural or artificial system that absorbs more carbon than it releases.", "ex": "Forests and oceans are major carbon sinks."}, {"term": "carbon capture", "ipa": "/ˈkɑːbən ˌkæptʃə/", "pron": "KAR-buhn KAP-chuh", "fr": "captage du carbone", "def": "Technology or process that captures CO2 before or after release.", "ex": "Carbon capture may help decarbonise heavy industry."}, {"term": "carbon capture and storage", "ipa": "/ˌkɑːbən ˈkæptʃər ənd ˈstɔːrɪdʒ/", "pron": "KAR-buhn KAP-chuh and STOR-ij", "fr": "captage et stockage du carbone", "def": "Capturing CO2 and storing it underground or elsewhere.", "ex": "Carbon capture and storage remains expensive."}, {"term": "CCS", "ipa": "/ˌsiː siː ˈes/", "pron": "see-see-ess", "fr": "CSC", "def": "Abbreviation for carbon capture and storage.", "ex": "CCS is promoted for hard-to-abate sectors."}, {"term": "offsetting", "ipa": "/ˈɒfsetɪŋ/", "pron": "OFF-set-ing", "fr": "compensation carbone", "def": "Compensating for emissions by funding reductions or removals elsewhere.", "ex": "Offsetting can be useful but should not replace emissions cuts."}, {"term": "carbon offset", "ipa": "/ˈkɑːbən ˌɒfset/", "pron": "KAR-buhn OFF-set", "fr": "crédit de compensation carbone", "def": "A reduction or removal of emissions used to compensate for emissions elsewhere.", "ex": "Carbon offsets are often criticised for weak verification."}, {"term": "carbon market", "ipa": "/ˈkɑːbən ˌmɑːkɪt/", "pron": "KAR-buhn MAR-kit", "fr": "marché du carbone", "def": "A market where carbon credits or emissions allowances are bought and sold.", "ex": "Carbon markets aim to make pollution costly."}, {"term": "carbon price", "ipa": "/ˈkɑːbən praɪs/", "pron": "KAR-buhn pryce", "fr": "prix du carbone", "def": "A cost placed on emitting carbon dioxide or greenhouse gases.", "ex": "A carbon price can encourage cleaner technologies."}, {"term": "carbon tax", "ipa": "/ˈkɑːbən tæks/", "pron": "KAR-buhn taks", "fr": "taxe carbone", "def": "A tax on carbon emissions or fossil fuel use.", "ex": "A carbon tax can be unpopular if it increases living costs."}, {"term": "emissions trading scheme", "ipa": "/ɪˈmɪʃənz ˈtreɪdɪŋ skiːm/", "pron": "i-MISH-uhnz TRAY-ding skeem", "fr": "système d’échange de quotas d’émission", "def": "A system where companies trade allowances to emit greenhouse gases.", "ex": "The EU has an emissions trading scheme."}, {"term": "cap and trade", "ipa": "/ˌkæp ən ˈtreɪd/", "pron": "cap and trade", "fr": "plafonnement et échange", "def": "A policy setting an emissions limit and allowing trading of permits.", "ex": "Cap and trade creates a market incentive to cut emissions."}, {"term": "climate mitigation", "ipa": "/ˈklaɪmət ˌmɪtɪˈɡeɪʃən/", "pron": "KLY-muht mit-i-GAY-shuhn", "fr": "atténuation du changement climatique", "def": "Actions to reduce or prevent greenhouse gas emissions.", "ex": "Climate mitigation includes renewable energy and efficiency."}, {"term": "climate adaptation", "ipa": "/ˈklaɪmət ˌædæpˈteɪʃən/", "pron": "KLY-muht ad-ap-TAY-shuhn", "fr": "adaptation au changement climatique", "def": "Adjusting systems and societies to climate impacts.", "ex": "Climate adaptation includes flood defences and heatwave plans."}]}, {"title": "B. Mitigation, adaptation and climate impacts", "entries": [{"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability to withstand and recover from shocks or stress.", "ex": "Climate resilience is essential for vulnerable communities."}, {"term": "climate resilience", "ipa": "/ˈklaɪmət rɪˌzɪliəns/", "pron": "KLY-muht ri-ZIL-ee-uhns", "fr": "résilience climatique", "def": "The ability to cope with and recover from climate impacts.", "ex": "Cities need climate resilience against floods and heatwaves."}, {"term": "vulnerability", "ipa": "/ˌvʌlnərəˈbɪləti/", "pron": "vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité", "def": "Exposure to harm because of limited resources, protection or capacity.", "ex": "Poor communities often face greater climate vulnerability."}, {"term": "climate vulnerability", "ipa": "/ˈklaɪmət ˌvʌlnərəˈbɪləti/", "pron": "KLY-muht vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité climatique", "def": "Susceptibility to damage from climate impacts.", "ex": "Small island states have high climate vulnerability."}, {"term": "extreme weather", "ipa": "/ɪkˌstriːm ˈweðə/", "pron": "ik-STREEM WETH-uh", "fr": "phénomènes météorologiques extrêmes", "def": "Severe weather events such as storms, heatwaves, floods or droughts.", "ex": "Extreme weather is becoming more frequent in many regions."}, {"term": "heatwave", "ipa": "/ˈhiːtweɪv/", "pron": "HEET-wave", "fr": "canicule", "def": "A prolonged period of unusually hot weather.", "ex": "Heatwaves can kill vulnerable people."}, {"term": "drought", "ipa": "/draʊt/", "pron": "drowt", "fr": "sécheresse", "def": "A long period of abnormally low rainfall causing water shortage.", "ex": "Drought threatens agriculture and water supplies."}, {"term": "flood", "ipa": "/flʌd/", "pron": "flud", "fr": "inondation", "def": "An overflow of water onto normally dry land.", "ex": "Floods can destroy homes and infrastructure."}, {"term": "wildfire", "ipa": "/ˈwaɪldfaɪə/", "pron": "WYLD-fire", "fr": "incendie de forêt", "def": "An uncontrolled fire in forests, grasslands or other natural areas.", "ex": "Wildfires are worsened by heat and drought."}, {"term": "storm surge", "ipa": "/ˈstɔːm sɜːdʒ/", "pron": "storm surj", "fr": "onde de tempête", "def": "A rise in sea level caused by a storm pushing water onto land.", "ex": "Storm surges can devastate coastal communities."}, {"term": "hurricane", "ipa": "/ˈhʌrɪkən/", "pron": "HUR-i-kuhn", "fr": "ouragan", "def": "A powerful tropical storm in the Atlantic or eastern Pacific.", "ex": "Warmer oceans can intensify hurricanes."}, {"term": "typhoon", "ipa": "/taɪˈfuːn/", "pron": "ty-FOON", "fr": "typhon", "def": "A powerful tropical storm in the western Pacific.", "ex": "Typhoons can cause major coastal damage."}, {"term": "sea-level rise", "ipa": "/ˈsiː levəl raɪz/", "pron": "SEE-LEV-uhl ryze", "fr": "élévation du niveau de la mer", "def": "The increase in average ocean level due to warming and melting ice.", "ex": "Sea-level rise threatens low-lying islands."}, {"term": "melting ice", "ipa": "/ˌmeltɪŋ ˈaɪs/", "pron": "MELT-ing ice", "fr": "fonte des glaces", "def": "Ice turning into water because of rising temperatures.", "ex": "Melting ice contributes to sea-level rise."}, {"term": "glacier retreat", "ipa": "/ˈɡlæsiə rɪˌtriːt/", "pron": "GLASS-ee-uh ri-TREET", "fr": "recul des glaciers", "def": "The shrinking of glaciers over time.", "ex": "Glacier retreat threatens water supplies."}, {"term": "ice sheet", "ipa": "/ˈaɪs ʃiːt/", "pron": "ice sheet", "fr": "calotte glaciaire", "def": "A huge mass of ice covering land.", "ex": "The Greenland ice sheet is losing mass."}, {"term": "permafrost", "ipa": "/ˈpɜːməfrɒst/", "pron": "PUR-muh-frost", "fr": "pergélisol", "def": "Permanently frozen ground found in polar and high-mountain regions.", "ex": "Thawing permafrost can release methane."}, {"term": "tipping point", "ipa": "/ˈtɪpɪŋ pɔɪnt/", "pron": "TIP-ing point", "fr": "point de bascule", "def": "A threshold beyond which a system changes rapidly and possibly irreversibly.", "ex": "Climate tipping points could trigger cascading effects."}, {"term": "feedback loop", "ipa": "/ˈfiːdbæk luːp/", "pron": "FEED-bak loop", "fr": "boucle de rétroaction", "def": "A process that amplifies or reduces change in a system.", "ex": "Melting ice creates a feedback loop by reducing reflectivity."}, {"term": "climate model", "ipa": "/ˈklaɪmət ˌmɒdəl/", "pron": "KLY-muht MOD-uhl", "fr": "modèle climatique", "def": "A computer simulation of the climate system.", "ex": "Climate models help project future warming."}, {"term": "climate projection", "ipa": "/ˈklaɪmət prəˌdʒekʃən/", "pron": "KLY-muht pruh-JEK-shuhn", "fr": "projection climatique", "def": "An estimate of future climate under specific assumptions.", "ex": "Climate projections depend on emissions scenarios."}, {"term": "emissions scenario", "ipa": "/ɪˈmɪʃənz sɪˌnɑːriəʊ/", "pron": "i-MISH-uhnz si-NAH-ree-oh", "fr": "scénario d’émissions", "def": "A possible future pathway of greenhouse gas emissions.", "ex": "High-emissions scenarios show severe warming."}, {"term": "scientific consensus", "ipa": "/ˌsaɪənˈtɪfɪk kənˈsensəs/", "pron": "sy-uhn-TIF-ik kuhn-SEN-suhs", "fr": "consensus scientifique", "def": "Broad agreement among scientists based on evidence.", "ex": "There is a strong scientific consensus on human-caused climate change."}, {"term": "IPCC", "ipa": "/ˌaɪ piː siː ˈsiː/", "pron": "eye-pee-see-see", "fr": "GIEC", "def": "Intergovernmental Panel on Climate Change.", "ex": "The IPCC assesses climate science for policymakers."}, {"term": "Intergovernmental Panel on Climate Change", "ipa": "/ˌɪntəɡʌvənˈmentəl ˈpænəl ɒn ˈklaɪmət tʃeɪndʒ/", "pron": "IN-tuh-gov-uhn-MEN-tuhl PAN-uhl on KLY-muht chaynj", "fr": "Groupe d’experts intergouvernemental sur l’évolution du climat", "def": "The UN body that evaluates scientific knowledge on climate change.", "ex": "The Intergovernmental Panel on Climate Change publishes major assessment reports."}, {"term": "climate science", "ipa": "/ˈklaɪmət ˌsaɪəns/", "pron": "KLY-muht SY-uhns", "fr": "science du climat", "def": "The scientific study of the climate system and climate change.", "ex": "Climate science combines physics, chemistry, biology and data."}, {"term": "climate denial", "ipa": "/ˈklaɪmət dɪˌnaɪəl/", "pron": "KLY-muht di-NY-uhl", "fr": "climatoscepticisme radical ; déni climatique", "def": "Rejection of well-established climate science.", "ex": "Climate denial has delayed action."}, {"term": "climate scepticism", "ipa": "/ˈklaɪmət ˌskeptɪsɪzəm/", "pron": "KLY-muht SKEP-ti-siz-uhm", "fr": "climatoscepticisme", "def": "Doubt or criticism about climate science or climate policy.", "ex": "Climate scepticism can range from scientific questioning to misinformation."}, {"term": "climate misinformation", "ipa": "/ˈklaɪmət ˌmɪsɪnfəˈmeɪʃən/", "pron": "KLY-muht mis-in-fuh-MAY-shuhn", "fr": "désinformation climatique ; mésinformation climatique", "def": "False or misleading information about climate change.", "ex": "Climate misinformation spreads online."}, {"term": "Paris Agreement", "ipa": "/ˈpærɪs əˌɡriːmənt/", "pron": "PARR-is uh-GREE-muhnt", "fr": "Accord de Paris", "def": "The 2015 international climate agreement aiming to limit global warming.", "ex": "The Paris Agreement aims to keep warming well below 2°C."}, {"term": "COP", "ipa": "/ˌsiː əʊ ˈpiː/", "pron": "see-oh-pee", "fr": "COP", "def": "Conference of the Parties, the annual UN climate summit.", "ex": "COP meetings bring together governments to negotiate climate action."}, {"term": "UNFCCC", "ipa": "/ˌjuː en ef siː siː ˈsiː/", "pron": "yoo-en-eff-see-see-see", "fr": "CCNUCC", "def": "United Nations Framework Convention on Climate Change.", "ex": "The UNFCCC provides the framework for global climate negotiations."}, {"term": "nationally determined contribution", "ipa": "/ˌnæʃənəli dɪˈtɜːmɪnd ˌkɒntrɪˈbjuːʃən/", "pron": "NASH-uh-nuh-lee di-TUR-mind kon-tri-BYOO-shuhn", "fr": "contribution déterminée au niveau national", "def": "A country’s climate action plan under the Paris Agreement.", "ex": "Countries must update their nationally determined contributions."}, {"term": "NDC", "ipa": "/ˌen diː ˈsiː/", "pron": "en-dee-see", "fr": "CDN", "def": "Abbreviation for nationally determined contribution.", "ex": "NDCs are often not ambitious enough."}, {"term": "climate diplomacy", "ipa": "/ˈklaɪmət dɪˌpləʊməsi/", "pron": "KLY-muht di-PLOH-muh-see", "fr": "diplomatie climatique", "def": "International negotiation and cooperation on climate change.", "ex": "Climate diplomacy requires trust between rich and poor countries."}, {"term": "climate finance", "ipa": "/ˈklaɪmət ˌfaɪnæns/", "pron": "KLY-muht FY-nans", "fr": "financement climatique", "def": "Funding to support mitigation and adaptation, especially in poorer countries.", "ex": "Climate finance is central to North-South negotiations."}, {"term": "loss and damage", "ipa": "/ˌlɒs ənd ˈdæmɪdʒ/", "pron": "loss and DAM-ij", "fr": "pertes et préjudices", "def": "Climate harms that cannot be avoided through mitigation or adaptation.", "ex": "Vulnerable countries demand funding for loss and damage."}, {"term": "climate justice", "ipa": "/ˈklaɪmət ˌdʒʌstɪs/", "pron": "KLY-muht JUS-tis", "fr": "justice climatique", "def": "The idea that climate action should address fairness, responsibility and inequality.", "ex": "Climate justice highlights the unequal burden of warming."}, {"term": "environmental justice", "ipa": "/ɪnˌvaɪrənˈmentəl ˈdʒʌstɪs/", "pron": "in-vy-ruhn-MEN-tuhl JUS-tis", "fr": "justice environnementale", "def": "Fair treatment regarding environmental harms and benefits.", "ex": "Environmental justice links pollution, race and poverty."}]}, {"title": "C. International climate politics and justice", "entries": [{"term": "just transition", "ipa": "/ˌdʒʌst trænˈzɪʃən/", "pron": "just tran-ZISH-uhn", "fr": "transition juste", "def": "A fair shift to a low-carbon economy protecting workers and communities.", "ex": "A just transition supports workers in fossil-fuel regions."}, {"term": "energy poverty", "ipa": "/ˈenədʒi ˌpɒvəti/", "pron": "EN-uh-jee POV-uh-tee", "fr": "précarité énergétique", "def": "Lack of affordable access to adequate energy.", "ex": "Energy poverty complicates climate policy."}, {"term": "climate refugee", "ipa": "/ˈklaɪmət ˌrefjʊˈdʒiː/", "pron": "KLY-muht REF-yoo-jee", "fr": "réfugié climatique", "def": "A person forced to move because of climate-related impacts, though not always a formal legal category.", "ex": "Climate refugees may increase as sea levels rise."}, {"term": "climate migration", "ipa": "/ˈklaɪmət maɪˌɡreɪʃən/", "pron": "KLY-muht my-GRAY-shuhn", "fr": "migration climatique", "def": "Movement of people linked to climate impacts.", "ex": "Climate migration can be internal or cross-border."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Lack of reliable access to enough food.", "ex": "Climate change worsens food insecurity."}, {"term": "water scarcity", "ipa": "/ˈwɔːtə ˌskeəsəti/", "pron": "WOR-tuh SKAIR-suh-tee", "fr": "pénurie d’eau", "def": "Lack of sufficient water resources.", "ex": "Water scarcity can fuel conflict and migration."}, {"term": "climate risk", "ipa": "/ˈklaɪmət rɪsk/", "pron": "KLY-muht risk", "fr": "risque climatique", "def": "Potential harm caused by climate change to people, assets or systems.", "ex": "Investors increasingly assess climate risk."}, {"term": "physical risk", "ipa": "/ˈfɪzɪkəl rɪsk/", "pron": "FIZ-i-kuhl risk", "fr": "risque physique", "def": "Climate risk from physical impacts such as floods, storms or heat.", "ex": "Physical risk threatens infrastructure and insurance."}, {"term": "transition risk", "ipa": "/trænˈzɪʃən rɪsk/", "pron": "tran-ZISH-uhn risk", "fr": "risque de transition", "def": "Financial or economic risk caused by the shift to a low-carbon economy.", "ex": "Coal companies face transition risk."}, {"term": "stranded asset", "ipa": "/ˌstrændɪd ˈæset/", "pron": "STRAN-did AS-et", "fr": "actif échoué", "def": "An asset that loses value because of market, regulatory or environmental change.", "ex": "Fossil fuel reserves may become stranded assets."}, {"term": "green investment", "ipa": "/ˌɡriːn ɪnˈvestmənt/", "pron": "green in-VEST-muhnt", "fr": "investissement vert", "def": "Investment supporting environmentally sustainable projects.", "ex": "Green investment is needed for decarbonisation."}, {"term": "green bond", "ipa": "/ˈɡriːn bɒnd/", "pron": "green bond", "fr": "obligation verte", "def": "A bond used to finance environmentally beneficial projects.", "ex": "Green bonds fund renewable energy and public transport."}, {"term": "sustainable finance", "ipa": "/səˌsteɪnəbəl ˈfaɪnæns/", "pron": "suh-STAY-nuh-buhl FY-nans", "fr": "finance durable", "def": "Finance that considers environmental and social sustainability.", "ex": "Sustainable finance can redirect capital towards climate action."}, {"term": "ESG", "ipa": "/ˌiː es ˈdʒiː/", "pron": "ee-ess-jee", "fr": "ESG ; critères environnementaux, sociaux et de gouvernance", "def": "Environmental, social and governance criteria used in investment and business assessment.", "ex": "ESG investing faces accusations of greenwashing."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "greenwashing ; écoblanchiment", "def": "Misleading environmental claims made to improve reputation.", "ex": "Greenwashing undermines public trust."}, {"term": "climate disclosure", "ipa": "/ˈklaɪmət dɪsˌkləʊʒə/", "pron": "KLY-muht dis-KLOH-zhuh", "fr": "publication d’informations climatiques", "def": "Reporting climate-related risks, emissions or strategies.", "ex": "Climate disclosure helps investors assess risks."}, {"term": "sustainability", "ipa": "/səˌsteɪnəˈbɪləti/", "pron": "suh-stay-nuh-BIL-uh-tee", "fr": "durabilité", "def": "The ability to meet present needs without harming future generations.", "ex": "Sustainability requires environmental, social and economic balance."}, {"term": "sustainable development", "ipa": "/səˌsteɪnəbəl dɪˈveləpmənt/", "pron": "suh-STAY-nuh-buhl di-VEL-uhp-muhnt", "fr": "développement durable", "def": "Development meeting present needs without compromising future generations.", "ex": "Climate action is part of sustainable development."}, {"term": "circular economy", "ipa": "/ˌsɜːkjʊlər iˈkɒnəmi/", "pron": "SUR-kyuh-luh i-KON-uh-mee", "fr": "économie circulaire", "def": "An economic model reducing waste by reusing, repairing and recycling resources.", "ex": "The circular economy reduces resource use and emissions."}, {"term": "degrowth", "ipa": "/ˌdiːˈɡrəʊθ/", "pron": "dee-GROHTH", "fr": "décroissance", "def": "A political and economic idea arguing for reduced production and consumption in wealthy societies.", "ex": "Degrowth challenges the assumption that growth can continue indefinitely."}, {"term": "green growth", "ipa": "/ˌɡriːn ˈɡrəʊθ/", "pron": "green grohth", "fr": "croissance verte", "def": "Economic growth compatible with environmental protection and lower emissions.", "ex": "Green growth is defended by many policymakers."}, {"term": "energy efficiency", "ipa": "/ˈenədʒi ɪˌfɪʃənsi/", "pron": "EN-uh-jee i-FISH-uhn-see", "fr": "efficacité énergétique", "def": "Using less energy to provide the same service.", "ex": "Energy efficiency lowers bills and emissions."}, {"term": "retrofitting", "ipa": "/ˈretrəʊˌfɪtɪŋ/", "pron": "RET-roh-FIT-ing", "fr": "rénovation énergétique ; modernisation", "def": "Upgrading buildings or systems to improve performance.", "ex": "Retrofitting homes can reduce heating emissions."}, {"term": "public transport", "ipa": "/ˌpʌblɪk ˈtrænspɔːt/", "pron": "PUB-lik TRANS-port", "fr": "transports publics", "def": "Transport systems available to the public, such as buses and trains.", "ex": "Public transport can reduce car dependency."}, {"term": "electric vehicle", "ipa": "/ɪˌlektrɪk ˈviːɪkəl/", "pron": "i-LEK-trik VEE-i-kuhl", "fr": "véhicule électrique", "def": "A vehicle powered by electricity rather than petrol or diesel.", "ex": "Electric vehicles reduce tailpipe emissions."}, {"term": "EV", "ipa": "/ˌiː ˈviː/", "pron": "ee-vee", "fr": "VE", "def": "Abbreviation for electric vehicle.", "ex": "EV adoption depends on charging infrastructure."}, {"term": "charging infrastructure", "ipa": "/ˈtʃɑːdʒɪŋ ˌɪnfrəˌstrʌktʃə/", "pron": "CHAR-jing IN-fruh-struk-chuh", "fr": "infrastructure de recharge", "def": "The network of chargers needed for electric vehicles.", "ex": "Charging infrastructure must expand rapidly."}, {"term": "heat pump", "ipa": "/ˈhiːt pʌmp/", "pron": "heat pump", "fr": "pompe à chaleur", "def": "A low-carbon technology that transfers heat for heating or cooling.", "ex": "Heat pumps can replace gas boilers."}, {"term": "insulation", "ipa": "/ˌɪnsjʊˈleɪʃən/", "pron": "in-syoo-LAY-shuhn", "fr": "isolation", "def": "Material or methods used to reduce heat loss.", "ex": "Better insulation cuts energy use."}, {"term": "lifestyle change", "ipa": "/ˈlaɪfstaɪl tʃeɪndʒ/", "pron": "LYFE-style chaynj", "fr": "changement de mode de vie", "def": "A change in personal habits or consumption patterns.", "ex": "Lifestyle change can complement policy measures."}]}, {"title": "D. Green economy, solutions, activism and policy", "entries": [{"term": "behavioural change", "ipa": "/bɪˌheɪvjərəl tʃeɪndʒ/", "pron": "bi-HAY-vyuh-ruhl chaynj", "fr": "changement comportemental", "def": "A change in how people act or consume.", "ex": "Behavioural change is easier when infrastructure supports it."}, {"term": "climate activism", "ipa": "/ˈklaɪmət ˌæktɪvɪzəm/", "pron": "KLY-muht AK-ti-viz-uhm", "fr": "activisme climatique", "def": "Campaigning for stronger action on climate change.", "ex": "Climate activism has pushed climate onto the political agenda."}, {"term": "climate activist", "ipa": "/ˈklaɪmət ˌæktɪvɪst/", "pron": "KLY-muht AK-ti-vist", "fr": "militant climatique", "def": "A person campaigning for climate action.", "ex": "Climate activists criticise slow government action."}, {"term": "civil disobedience", "ipa": "/ˌsɪvəl ˌdɪsəˈbiːdiəns/", "pron": "SIV-uhl dis-uh-BEE-dee-uhns", "fr": "désobéissance civile", "def": "Non-violent refusal to obey laws as protest.", "ex": "Some climate movements use civil disobedience."}, {"term": "climate strike", "ipa": "/ˈklaɪmət straɪk/", "pron": "KLY-muht strike", "fr": "grève pour le climat", "def": "A protest where people stop school or work to demand climate action.", "ex": "Youth climate strikes gained global attention."}, {"term": "climate litigation", "ipa": "/ˈklaɪmət ˌlɪtɪˈɡeɪʃən/", "pron": "KLY-muht lit-i-GAY-shuhn", "fr": "contentieux climatique", "def": "Legal action related to climate change.", "ex": "Climate litigation is increasingly used against governments and companies."}, {"term": "climate policy", "ipa": "/ˈklaɪmət ˌpɒləsi/", "pron": "KLY-muht POL-uh-see", "fr": "politique climatique", "def": "Government policy designed to address climate change.", "ex": "Climate policy affects energy, transport, housing and industry."}, {"term": "political will", "ipa": "/pəˌlɪtɪkəl ˈwɪl/", "pron": "puh-LIT-i-kuhl wil", "fr": "volonté politique", "def": "The determination of leaders to take action.", "ex": "Climate action often lacks political will."}, {"term": "vested interest", "ipa": "/ˌvestɪd ˈɪntrəst/", "pron": "VES-tid IN-truhst", "fr": "intérêt établi", "def": "A group or person benefiting from the current system and resisting change.", "ex": "Fossil fuel vested interests can oppose regulation."}, {"term": "fossil fuel lobby", "ipa": "/ˌfɒsəl ˈfjuːəl ˌlɒbi/", "pron": "FOS-uhl FYOO-uhl LOB-ee", "fr": "lobby des énergies fossiles", "def": "Groups seeking to influence policy in favour of fossil fuel interests.", "ex": "The fossil fuel lobby has shaped climate policy debates."}, {"term": "to cut emissions", "ipa": "/kʌt ɪˈmɪʃənz/", "pron": "cut i-MISH-uhnz", "fr": "réduire les émissions", "def": "To reduce greenhouse gas emissions.", "ex": "Governments must cut emissions quickly."}, {"term": "to curb global warming", "ipa": "/kɜːb ˌɡləʊbəl ˈwɔːmɪŋ/", "pron": "kurb GLOH-buhl WAR-ming", "fr": "freiner le réchauffement climatique", "def": "To limit or slow global warming.", "ex": "Climate policy aims to curb global warming."}, {"term": "to phase out fossil fuels", "ipa": "/feɪz aʊt ˈfɒsəl ˌfjuːəlz/", "pron": "fayz out FOS-uhl FYOO-uhlz", "fr": "sortir progressivement des énergies fossiles", "def": "To gradually stop using fossil fuels.", "ex": "Many scientists call for phasing out fossil fuels."}, {"term": "to transition to renewable energy", "ipa": "/trænˈzɪʃən tə rɪˌnjuːəbəl ˈenədʒi/", "pron": "tran-ZISH-uhn tuh ri-NYOO-uh-buhl EN-uh-jee", "fr": "passer aux énergies renouvelables", "def": "To shift from fossil fuels to renewable energy.", "ex": "Countries need to transition to renewable energy."}, {"term": "to reach net zero", "ipa": "/riːtʃ ˌnet ˈzɪərəʊ/", "pron": "reech net ZEER-oh", "fr": "atteindre le zéro net", "def": "To achieve a balance between emissions and removals.", "ex": "Many countries aim to reach net zero by 2050."}, {"term": "to adapt to climate impacts", "ipa": "/əˈdæpt tə ˈklaɪmət ˈɪmpækts/", "pron": "uh-DAPT tuh KLY-muht IM-pakts", "fr": "s’adapter aux impacts climatiques", "def": "To adjust to the effects of climate change.", "ex": "Coastal cities must adapt to climate impacts."}, {"term": "to build climate resilience", "ipa": "/bɪld ˈklaɪmət rɪˌzɪliəns/", "pron": "bild KLY-muht ri-ZIL-ee-uhns", "fr": "renforcer la résilience climatique", "def": "To strengthen the ability to cope with climate shocks.", "ex": "Communities need to build climate resilience."}, {"term": "to finance adaptation", "ipa": "/ˈfaɪnæns ˌædæpˈteɪʃən/", "pron": "FY-nans ad-ap-TAY-shuhn", "fr": "financer l’adaptation", "def": "To fund measures that help societies adjust to climate impacts.", "ex": "Rich countries are under pressure to finance adaptation."}, {"term": "to compensate for loss and damage", "ipa": "/ˈkɒmpenseɪt fə ˌlɒs ənd ˈdæmɪdʒ/", "pron": "KOM-pen-sayt fuh loss and DAM-ij", "fr": "compenser les pertes et préjudices", "def": "To provide money or support for unavoidable climate harms.", "ex": "Vulnerable countries demand compensation for loss and damage."}, {"term": "to hold polluters accountable", "ipa": "/həʊld pəˈluːtəz əˈkaʊntəbəl/", "pron": "hohld puh-LOO-tuhz uh-KOWN-tuh-buhl", "fr": "tenir les pollueurs responsables", "def": "To make polluters responsible for their environmental harm.", "ex": "Climate litigation seeks to hold polluters accountable."}, {"term": "to greenwash a product", "ipa": "/ˈɡriːnwɒʃ ə ˈprɒdʌkt/", "pron": "GREEN-wosh uh PROD-ukt", "fr": "faire du greenwashing sur un produit", "def": "To make misleading environmental claims about a product.", "ex": "Companies may greenwash a product to attract consumers."}, {"term": "to balance growth and sustainability", "ipa": "/ˈbæləns ˈɡrəʊθ ənd səˌsteɪnəˈbɪləti/", "pron": "BAL-uhns grohth and suh-stay-nuh-BIL-uh-tee", "fr": "équilibrer croissance et durabilité", "def": "To reconcile economic development with environmental protection.", "ex": "Policymakers must balance growth and sustainability."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p8c68", "part": 8, "chapter": 68, "title": "Renewable Energy", "file": "cpge_vocab_part8_chapter68_renewable_energy_premium.html", "count": 114, "sections": [{"title": "A. Core renewable energy and grid vocabulary", "entries": [{"term": "renewable energy", "ipa": "/rɪˌnjuːəbəl ˈenədʒi/", "pron": "ri-NYOO-uh-buhl EN-uh-jee", "fr": "énergie renouvelable", "def": "Energy from sources that are naturally replenished, such as sun, wind, water and biomass.", "ex": "Renewable energy is central to decarbonisation."}, {"term": "renewables", "ipa": "/rɪˈnjuːəbəlz/", "pron": "ri-NYOO-uh-buhlz", "fr": "énergies renouvelables", "def": "Short form for renewable energy sources or technologies.", "ex": "Renewables are expanding rapidly in many countries."}, {"term": "clean energy", "ipa": "/ˌkliːn ˈenədʒi/", "pron": "kleen EN-uh-jee", "fr": "énergie propre", "def": "Energy that produces little pollution or greenhouse gas emissions.", "ex": "Clean energy can reduce air pollution and carbon emissions."}, {"term": "green energy", "ipa": "/ˌɡriːn ˈenədʒi/", "pron": "green EN-uh-jee", "fr": "énergie verte", "def": "Energy presented as environmentally friendly.", "ex": "Green energy is often used in political and marketing language."}, {"term": "low-carbon energy", "ipa": "/ˌləʊ ˈkɑːbən ˈenədʒi/", "pron": "loh-KAR-buhn EN-uh-jee", "fr": "énergie bas carbone", "def": "Energy that emits little greenhouse gas over its life cycle.", "ex": "Low-carbon energy includes renewables and nuclear power."}, {"term": "energy transition", "ipa": "/ˈenədʒi trænˌzɪʃən/", "pron": "EN-uh-jee tran-ZISH-uhn", "fr": "transition énergétique", "def": "The shift from fossil-fuel energy systems to low-carbon energy systems.", "ex": "The energy transition requires investment and public support."}, {"term": "decarbonisation", "ipa": "/ˌdiːkɑːbənaɪˈzeɪʃən/", "pron": "dee-kar-buh-ny-ZAY-shuhn", "fr": "décarbonation", "def": "Reducing or eliminating carbon emissions from energy, transport and industry.", "ex": "Renewables are a major tool for decarbonisation."}, {"term": "electrification", "ipa": "/ɪˌlektrɪfɪˈkeɪʃən/", "pron": "i-lek-tri-fi-KAY-shuhn", "fr": "électrification", "def": "Replacing fossil-fuel uses with electricity, ideally from low-carbon sources.", "ex": "Electrification can cut emissions from cars and heating."}, {"term": "energy mix", "ipa": "/ˈenədʒi mɪks/", "pron": "EN-uh-jee miks", "fr": "mix énergétique", "def": "The combination of energy sources used by a country or region.", "ex": "A country’s energy mix reflects geography, policy and history."}, {"term": "power generation", "ipa": "/ˈpaʊə ˌdʒenəˈreɪʃən/", "pron": "POW-uh jen-uh-RAY-shuhn", "fr": "production d’électricité", "def": "The production of electricity.", "ex": "Renewables are changing power generation."}, {"term": "electricity grid", "ipa": "/ɪˌlekˈtrɪsəti ɡrɪd/", "pron": "i-lek-TRIS-uh-tee grid", "fr": "réseau électrique", "def": "The network that transmits and distributes electricity.", "ex": "The electricity grid must adapt to renewable energy."}, {"term": "power grid", "ipa": "/ˈpaʊə ɡrɪd/", "pron": "POW-uh grid", "fr": "réseau électrique", "def": "The system delivering electricity from producers to consumers.", "ex": "A modern power grid needs flexibility and storage."}, {"term": "grid capacity", "ipa": "/ˈɡrɪd kəˌpæsəti/", "pron": "grid kuh-PASS-uh-tee", "fr": "capacité du réseau", "def": "The ability of the grid to carry electricity.", "ex": "Grid capacity can limit renewable projects."}, {"term": "grid connection", "ipa": "/ˈɡrɪd kəˌnekʃən/", "pron": "grid kuh-NEK-shuhn", "fr": "raccordement au réseau", "def": "The link allowing a power project to deliver electricity to the grid.", "ex": "Many renewable projects wait for grid connection."}, {"term": "smart grid", "ipa": "/ˈsmɑːt ɡrɪd/", "pron": "smart grid", "fr": "réseau intelligent", "def": "An electricity grid using digital technology to manage supply and demand.", "ex": "A smart grid can balance variable renewable energy."}, {"term": "energy storage", "ipa": "/ˈenədʒi ˌstɔːrɪdʒ/", "pron": "EN-uh-jee STOR-ij", "fr": "stockage de l’énergie", "def": "Systems that store energy for later use.", "ex": "Energy storage helps manage solar and wind variability."}, {"term": "battery storage", "ipa": "/ˈbætəri ˌstɔːrɪdʒ/", "pron": "BAT-uh-ree STOR-ij", "fr": "stockage par batterie", "def": "Storing electricity in batteries.", "ex": "Battery storage can supply power when the sun is not shining."}, {"term": "lithium-ion battery", "ipa": "/ˌlɪθiəm ˈaɪən ˈbætəri/", "pron": "LITH-ee-uhm EYE-uhn BAT-uh-ree", "fr": "batterie lithium-ion", "def": "A rechargeable battery widely used in electronics, vehicles and grid storage.", "ex": "Lithium-ion batteries are essential to electric vehicles."}, {"term": "pumped hydro storage", "ipa": "/ˌpʌmpt ˈhaɪdrəʊ ˌstɔːrɪdʒ/", "pron": "pumpt HY-droh STOR-ij", "fr": "stockage par pompage-turbinage", "def": "Energy storage using water pumped uphill and released to generate electricity.", "ex": "Pumped hydro storage can balance the grid."}, {"term": "intermittency", "ipa": "/ˌɪntəˈmɪtənsi/", "pron": "in-tuh-MIT-uhn-see", "fr": "intermittence", "def": "The fact that some energy sources do not produce continuously.", "ex": "Intermittency is a challenge for solar and wind power."}, {"term": "variable renewable energy", "ipa": "/ˈveəriəbəl rɪˌnjuːəbəl ˈenədʒi/", "pron": "VAIR-ee-uh-buhl ri-NYOO-uh-buhl EN-uh-jee", "fr": "énergie renouvelable variable", "def": "Renewable energy whose output changes with weather or time.", "ex": "Solar and wind are variable renewable energy sources."}, {"term": "baseload power", "ipa": "/ˈbeɪsləʊd ˌpaʊə/", "pron": "BAYSS-lohd POW-uh", "fr": "production de base", "def": "Electricity supply that can run continuously to meet minimum demand.", "ex": "Debates over baseload power shape energy policy."}, {"term": "dispatchable power", "ipa": "/dɪˈspætʃəbəl ˌpaʊə/", "pron": "di-SPATCH-uh-buhl POW-uh", "fr": "énergie pilotable", "def": "Power that can be turned on or adjusted when needed.", "ex": "Hydropower can provide dispatchable power."}, {"term": "peak demand", "ipa": "/ˌpiːk dɪˈmɑːnd/", "pron": "peek di-MAHND", "fr": "pic de demande", "def": "The highest level of electricity demand in a period.", "ex": "Peak demand often occurs during heatwaves or cold spells."}, {"term": "demand response", "ipa": "/dɪˈmɑːnd rɪˌspɒns/", "pron": "di-MAHND ri-SPONS", "fr": "effacement ; réponse à la demande", "def": "Adjusting electricity use to match supply or reduce peak demand.", "ex": "Demand response can reduce pressure on the grid."}, {"term": "solar energy", "ipa": "/ˈsəʊlər ˈenədʒi/", "pron": "SOH-luh EN-uh-jee", "fr": "énergie solaire", "def": "Energy from sunlight.", "ex": "Solar energy can be used for electricity or heating."}]}, {"title": "B. Solar, wind, hydro, geothermal, biomass and hydrogen", "entries": [{"term": "solar power", "ipa": "/ˈsəʊlə ˌpaʊə/", "pron": "SOH-luh POW-uh", "fr": "électricité solaire", "def": "Electricity generated from sunlight.", "ex": "Solar power has become increasingly affordable."}, {"term": "solar panel", "ipa": "/ˈsəʊlə ˌpænəl/", "pron": "SOH-luh PAN-uhl", "fr": "panneau solaire", "def": "A device that converts sunlight into electricity or heat.", "ex": "Solar panels can be installed on rooftops."}, {"term": "photovoltaic", "ipa": "/ˌfəʊtəʊvɒlˈteɪɪk/", "pron": "FOH-toh-vol-TAY-ik", "fr": "photovoltaïque", "def": "Converting light directly into electricity.", "ex": "Photovoltaic cells generate electricity from sunlight."}, {"term": "PV", "ipa": "/ˌpiː ˈviː/", "pron": "pee-vee", "fr": "PV ; photovoltaïque", "def": "Abbreviation for photovoltaic.", "ex": "PV capacity is growing worldwide."}, {"term": "solar farm", "ipa": "/ˈsəʊlə fɑːm/", "pron": "SOH-luh farm", "fr": "ferme solaire", "def": "A large installation of solar panels producing electricity.", "ex": "Solar farms require land and grid access."}, {"term": "rooftop solar", "ipa": "/ˌruːftɒp ˈsəʊlə/", "pron": "ROOF-top SOH-luh", "fr": "solaire en toiture", "def": "Solar panels installed on building roofs.", "ex": "Rooftop solar can reduce household electricity bills."}, {"term": "concentrated solar power", "ipa": "/ˈkɒnsəntreɪtɪd ˈsəʊlə ˌpaʊə/", "pron": "KON-suhn-tray-tid SOH-luh POW-uh", "fr": "énergie solaire concentrée", "def": "Solar power using mirrors to concentrate sunlight and produce heat.", "ex": "Concentrated solar power can include thermal storage."}, {"term": "wind energy", "ipa": "/ˈwɪnd ˌenədʒi/", "pron": "wind EN-uh-jee", "fr": "énergie éolienne", "def": "Energy generated from moving air.", "ex": "Wind energy is a key renewable source."}, {"term": "wind power", "ipa": "/ˈwɪnd ˌpaʊə/", "pron": "wind POW-uh", "fr": "électricité éolienne", "def": "Electricity generated by wind turbines.", "ex": "Wind power can be produced onshore or offshore."}, {"term": "wind turbine", "ipa": "/ˈwɪnd ˌtɜːbaɪn/", "pron": "wind TUR-byne", "fr": "éolienne", "def": "A machine that converts wind into electricity.", "ex": "Wind turbines are becoming taller and more powerful."}, {"term": "onshore wind", "ipa": "/ˌɒnʃɔː ˈwɪnd/", "pron": "ON-shor wind", "fr": "éolien terrestre", "def": "Wind power generated on land.", "ex": "Onshore wind is relatively cheap but sometimes opposed locally."}, {"term": "offshore wind", "ipa": "/ˌɒfʃɔː ˈwɪnd/", "pron": "OFF-shor wind", "fr": "éolien en mer", "def": "Wind power generated at sea.", "ex": "Offshore wind can produce large amounts of electricity."}, {"term": "floating wind farm", "ipa": "/ˌfləʊtɪŋ ˈwɪnd fɑːm/", "pron": "FLOH-ting wind farm", "fr": "parc éolien flottant", "def": "An offshore wind farm using floating platforms.", "ex": "Floating wind farms can operate in deeper waters."}, {"term": "turbine blade", "ipa": "/ˈtɜːbaɪn bleɪd/", "pron": "TUR-byne blade", "fr": "pale de turbine", "def": "A long part of a turbine moved by wind or water.", "ex": "Turbine blades must be strong and lightweight."}, {"term": "hydropower", "ipa": "/ˈhaɪdrəʊˌpaʊə/", "pron": "HY-droh-POW-uh", "fr": "hydroélectricité", "def": "Electricity generated from moving water.", "ex": "Hydropower is one of the oldest renewable energy sources."}, {"term": "hydroelectric dam", "ipa": "/ˌhaɪdrəʊɪˈlektrɪk dæm/", "pron": "HY-droh-i-LEK-trik dam", "fr": "barrage hydroélectrique", "def": "A dam that generates electricity using water flow.", "ex": "Hydroelectric dams can affect rivers and communities."}, {"term": "run-of-river hydropower", "ipa": "/ˌrʌn əv ˈrɪvə ˈhaɪdrəʊˌpaʊə/", "pron": "run-ov-RIV-uh HY-droh-POW-uh", "fr": "hydroélectricité au fil de l’eau", "def": "Hydropower using river flow with little or no reservoir.", "ex": "Run-of-river hydropower has a smaller reservoir impact."}, {"term": "reservoir", "ipa": "/ˈrezəvwɑː/", "pron": "REZ-uh-vwar", "fr": "réservoir", "def": "An artificial or natural lake used to store water.", "ex": "Reservoirs can store water and energy."}, {"term": "tidal power", "ipa": "/ˈtaɪdəl ˌpaʊə/", "pron": "TY-duhl POW-uh", "fr": "énergie marémotrice", "def": "Electricity generated from tides.", "ex": "Tidal power is predictable but location-dependent."}, {"term": "wave energy", "ipa": "/ˈweɪv ˌenədʒi/", "pron": "wave EN-uh-jee", "fr": "énergie houlomotrice", "def": "Energy generated from ocean waves.", "ex": "Wave energy remains less mature than wind or solar."}, {"term": "geothermal energy", "ipa": "/ˌdʒiːəʊˈθɜːməl ˈenədʒi/", "pron": "jee-oh-THUR-muhl EN-uh-jee", "fr": "énergie géothermique", "def": "Energy from heat inside the Earth.", "ex": "Geothermal energy can provide heating and electricity."}, {"term": "geothermal heating", "ipa": "/ˌdʒiːəʊˈθɜːməl ˈhiːtɪŋ/", "pron": "jee-oh-THUR-muhl HEET-ing", "fr": "chauffage géothermique", "def": "Heating buildings using heat from the ground.", "ex": "Geothermal heating can reduce fossil fuel use."}, {"term": "heat pump", "ipa": "/ˈhiːt pʌmp/", "pron": "heat pump", "fr": "pompe à chaleur", "def": "A device that moves heat for heating or cooling, often using electricity.", "ex": "Heat pumps are important for building decarbonisation."}, {"term": "biomass", "ipa": "/ˈbaɪəʊmæs/", "pron": "BY-oh-mass", "fr": "biomasse", "def": "Organic material used as fuel or raw material.", "ex": "Biomass can be renewable if managed sustainably."}, {"term": "bioenergy", "ipa": "/ˌbaɪəʊˈenədʒi/", "pron": "BY-oh-EN-uh-jee", "fr": "bioénergie", "def": "Energy produced from biological material.", "ex": "Bioenergy can come from wood, crops or waste."}, {"term": "biofuel", "ipa": "/ˈbaɪəʊˌfjuːəl/", "pron": "BY-oh-FYOO-uhl", "fr": "biocarburant", "def": "Fuel produced from biological material.", "ex": "Biofuels can replace some petrol or diesel."}, {"term": "biogas", "ipa": "/ˈbaɪəʊɡæs/", "pron": "BY-oh-gas", "fr": "biogaz", "def": "Gas produced from the breakdown of organic matter.", "ex": "Biogas can be made from agricultural waste."}, {"term": "anaerobic digestion", "ipa": "/ˌæneəˈrəʊbɪk daɪˈdʒestʃən/", "pron": "an-air-ROH-bik dy-JES-chuhn", "fr": "méthanisation", "def": "A process where microorganisms break down organic matter without oxygen, producing biogas.", "ex": "Anaerobic digestion can turn waste into energy."}, {"term": "sustainable biomass", "ipa": "/səˌsteɪnəbəl ˈbaɪəʊmæs/", "pron": "suh-STAY-nuh-buhl BY-oh-mass", "fr": "biomasse durable", "def": "Biomass produced without damaging ecosystems or food security.", "ex": "Sustainable biomass is controversial and hard to verify."}, {"term": "green hydrogen", "ipa": "/ˌɡriːn ˈhaɪdrədʒən/", "pron": "green HY-druh-juhn", "fr": "hydrogène vert", "def": "Hydrogen produced using renewable electricity.", "ex": "Green hydrogen may help decarbonise heavy industry."}, {"term": "hydrogen economy", "ipa": "/ˈhaɪdrədʒən iˌkɒnəmi/", "pron": "HY-druh-juhn i-KON-uh-mee", "fr": "économie de l’hydrogène", "def": "An energy system using hydrogen as a major fuel or storage medium.", "ex": "The hydrogen economy still requires infrastructure and cheap clean electricity."}, {"term": "electrolyser", "ipa": "/ɪˈlektrəlaɪzə/", "pron": "i-LEK-truh-ly-zuh", "fr": "électrolyseur", "def": "A device that uses electricity to split water into hydrogen and oxygen.", "ex": "Electrolysers are needed to produce green hydrogen."}, {"term": "fuel cell", "ipa": "/ˈfjuːəl sel/", "pron": "FYOO-uhl sel", "fr": "pile à combustible", "def": "A device that converts hydrogen or another fuel into electricity through a chemical reaction.", "ex": "Fuel cells can power vehicles or buildings."}, {"term": "renewable capacity", "ipa": "/rɪˌnjuːəbəl kəˈpæsəti/", "pron": "ri-NYOO-uh-buhl kuh-PASS-uh-tee", "fr": "capacité renouvelable installée", "def": "The maximum amount of renewable power that can be produced.", "ex": "Renewable capacity has grown strongly."}, {"term": "installed capacity", "ipa": "/ɪnˌstɔːld kəˈpæsəti/", "pron": "in-STAWLD kuh-PASS-uh-tee", "fr": "capacité installée", "def": "The maximum output a power plant or system can produce.", "ex": "Installed capacity does not equal actual production."}, {"term": "capacity factor", "ipa": "/kəˈpæsəti ˌfæktə/", "pron": "kuh-PASS-uh-tee FAK-tuh", "fr": "facteur de charge", "def": "The ratio between actual energy produced and maximum possible production.", "ex": "Offshore wind often has a higher capacity factor than solar."}, {"term": "levelised cost of electricity", "ipa": "/ˈlevəlaɪzd kɒst əv ɪˌlekˈtrɪsəti/", "pron": "LEV-uhl-yzd kost ov i-lek-TRIS-uh-tee", "fr": "coût actualisé de l’électricité", "def": "The average cost of producing electricity over a plant’s lifetime.", "ex": "The levelised cost of electricity helps compare technologies."}, {"term": "LCOE", "ipa": "/ˌel siː əʊ ˈiː/", "pron": "el-see-oh-ee", "fr": "LCOE", "def": "Abbreviation for levelised cost of electricity.", "ex": "LCOE for solar and wind has fallen sharply."}, {"term": "subsidy", "ipa": "/ˈsʌbsɪdi/", "pron": "SUB-si-dee", "fr": "subvention", "def": "Financial support from government to reduce costs or encourage activity.", "ex": "Subsidies can accelerate renewable deployment."}, {"term": "feed-in tariff", "ipa": "/ˈfiːd ɪn ˌtærɪf/", "pron": "feed-in TARR-if", "fr": "tarif de rachat", "def": "A policy guaranteeing renewable producers a fixed price for electricity.", "ex": "Feed-in tariffs helped early solar deployment."}, {"term": "power purchase agreement", "ipa": "/ˈpaʊə ˈpɜːtʃəs əˌɡriːmənt/", "pron": "POW-uh PUR-chuhs uh-GREE-muhnt", "fr": "contrat d’achat d’électricité", "def": "A long-term contract to buy electricity from a producer.", "ex": "Companies sign power purchase agreements to buy renewable electricity."}, {"term": "PPA", "ipa": "/ˌpiː piː ˈeɪ/", "pron": "pee-pee-ay", "fr": "PPA", "def": "Abbreviation for power purchase agreement.", "ex": "A PPA can finance a renewable project."}, {"term": "auction", "ipa": "/ˈɔːkʃən/", "pron": "AWK-shuhn", "fr": "enchère", "def": "A competitive process where projects bid to supply energy at a price.", "ex": "Renewable auctions can lower costs."}]}, {"title": "C. Costs, policy, energy security and supply chains", "entries": [{"term": "investment certainty", "ipa": "/ɪnˈvestmənt ˈsɜːtnti/", "pron": "in-VEST-muhnt SUR-tn-tee", "fr": "certitude pour les investisseurs", "def": "Confidence investors have that rules and returns will be stable.", "ex": "Investment certainty helps renewable projects attract funding."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy.", "ex": "Renewables can improve energy security by reducing fuel imports."}, {"term": "energy independence", "ipa": "/ˈenədʒi ˌɪndɪˈpendəns/", "pron": "EN-uh-jee in-di-PEN-duhns", "fr": "indépendance énergétique", "def": "A country’s ability to meet energy needs without relying heavily on imports.", "ex": "Renewables can support energy independence."}, {"term": "import dependency", "ipa": "/ˈɪmpɔːt dɪˌpendənsi/", "pron": "IM-port di-PEN-duhn-see", "fr": "dépendance aux importations", "def": "Reliance on imported energy or materials.", "ex": "Fossil fuel import dependency creates geopolitical vulnerability."}, {"term": "critical minerals", "ipa": "/ˌkrɪtɪkəl ˈmɪnərəlz/", "pron": "KRIT-i-kuhl MIN-uh-ruhlz", "fr": "minerais critiques", "def": "Minerals essential for technologies, energy and defence.", "ex": "Renewable technologies require critical minerals."}, {"term": "rare earths", "ipa": "/ˌreər ˈɜːθs/", "pron": "rare earths", "fr": "terres rares", "def": "A group of minerals used in electronics, magnets and clean technologies.", "ex": "Rare earths are important for some wind turbines."}, {"term": "lithium", "ipa": "/ˈlɪθiəm/", "pron": "LITH-ee-uhm", "fr": "lithium", "def": "A metal used in many rechargeable batteries.", "ex": "Lithium demand has risen with electric vehicles."}, {"term": "cobalt", "ipa": "/ˈkəʊbɒlt/", "pron": "KOH-bolt", "fr": "cobalt", "def": "A metal used in some batteries and industrial processes.", "ex": "Cobalt mining raises ethical concerns."}, {"term": "supply chain", "ipa": "/səˈplaɪ tʃeɪn/", "pron": "suh-PLY chayn", "fr": "chaîne d’approvisionnement", "def": "The network producing and delivering materials, parts or products.", "ex": "Clean-energy supply chains can create new dependencies."}, {"term": "recycling", "ipa": "/ˌriːˈsaɪklɪŋ/", "pron": "ree-SY-kling", "fr": "recyclage", "def": "Processing used materials so they can be used again.", "ex": "Battery recycling can reduce mineral demand."}, {"term": "circular economy", "ipa": "/ˌsɜːkjʊlər iˈkɒnəmi/", "pron": "SUR-kyuh-luh i-KON-uh-mee", "fr": "économie circulaire", "def": "An economy that reduces waste through reuse, repair and recycling.", "ex": "A circular economy can support cleaner energy systems."}, {"term": "life-cycle emissions", "ipa": "/ˈlaɪf ˌsaɪkəl ɪˈmɪʃənz/", "pron": "life-SY-kuhl i-MISH-uhnz", "fr": "émissions sur le cycle de vie", "def": "Emissions produced across a product’s full life, from production to disposal.", "ex": "Renewables have low life-cycle emissions compared with fossil fuels."}, {"term": "land use", "ipa": "/ˈlænd juːs/", "pron": "land yooss", "fr": "utilisation des terres", "def": "The way land is used for agriculture, housing, energy or nature.", "ex": "Solar farms and bioenergy raise land-use questions."}, {"term": "visual impact", "ipa": "/ˈvɪʒuəl ˈɪmpækt/", "pron": "VIZH-oo-uhl IM-pakt", "fr": "impact visuel", "def": "The effect of infrastructure on the appearance of a landscape.", "ex": "Wind turbines can face opposition because of visual impact."}, {"term": "noise pollution", "ipa": "/ˈnɔɪz pəˌluːʃən/", "pron": "noyz puh-LOO-shuhn", "fr": "pollution sonore", "def": "Unwanted or harmful noise.", "ex": "Some residents worry about noise pollution from turbines."}, {"term": "biodiversity impact", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti ˈɪmpækt/", "pron": "BY-oh-dy-VUR-suh-tee IM-pakt", "fr": "impact sur la biodiversité", "def": "The effect of a project on species and ecosystems.", "ex": "Renewable projects must assess biodiversity impact."}, {"term": "bird strike", "ipa": "/ˈbɜːd straɪk/", "pron": "bird strike", "fr": "collision aviaire", "def": "A collision between a bird and human-made infrastructure, such as a wind turbine.", "ex": "Bird strikes are a concern for some wind farms."}, {"term": "community acceptance", "ipa": "/kəˌmjuːnəti əkˈseptəns/", "pron": "kuh-MYOO-nuh-tee ak-SEP-tuhns", "fr": "acceptation locale", "def": "Local support or tolerance for a project.", "ex": "Community acceptance is crucial for renewable deployment."}, {"term": "NIMBYism", "ipa": "/ˈnɪmbiɪzəm/", "pron": "NIM-bee-iz-uhm", "fr": "syndrome NIMBY ; pas dans mon jardin", "def": "Opposition to developments near one’s home, even if generally supported.", "ex": "NIMBYism can slow wind and solar projects."}, {"term": "planning permission", "ipa": "/ˈplænɪŋ pəˌmɪʃən/", "pron": "PLAN-ing puh-MISH-uhn", "fr": "permis de construire ; autorisation d’urbanisme", "def": "Official approval to build or develop something.", "ex": "Planning permission can delay renewable projects."}, {"term": "permitting", "ipa": "/pəˈmɪtɪŋ/", "pron": "puh-MIT-ing", "fr": "procédures d’autorisation", "def": "The process of obtaining official authorisations for a project.", "ex": "Slow permitting is a barrier to renewable energy."}, {"term": "environmental assessment", "ipa": "/ɪnˌvaɪrənˈmentəl əˈsesmənt/", "pron": "in-vy-ruhn-MEN-tuhl uh-SESS-muhnt", "fr": "évaluation environnementale", "def": "A study of a project’s likely environmental effects.", "ex": "Environmental assessment can reduce harm."}, {"term": "just transition", "ipa": "/ˌdʒʌst trænˈzɪʃən/", "pron": "just tran-ZISH-uhn", "fr": "transition juste", "def": "A fair shift to a low-carbon economy that protects workers and communities.", "ex": "A just transition matters for coal and oil regions."}, {"term": "green jobs", "ipa": "/ˌɡriːn ˈdʒɒbz/", "pron": "green jobz", "fr": "emplois verts", "def": "Jobs that support environmental protection or low-carbon development.", "ex": "Renewable energy can create green jobs."}, {"term": "skills gap", "ipa": "/ˈskɪlz ɡæp/", "pron": "skilz gap", "fr": "déficit de compétences", "def": "A shortage of workers with the skills needed for certain jobs.", "ex": "The renewable sector faces a skills gap."}, {"term": "reskilling", "ipa": "/ˌriːˈskɪlɪŋ/", "pron": "ree-SKIL-ing", "fr": "reconversion", "def": "Training workers for new jobs or sectors.", "ex": "Reskilling can help fossil-fuel workers move into green jobs."}, {"term": "energy poverty", "ipa": "/ˈenədʒi ˌpɒvəti/", "pron": "EN-uh-jee POV-uh-tee", "fr": "précarité énergétique", "def": "Lack of affordable access to adequate energy.", "ex": "Energy poverty must be considered in climate policy."}, {"term": "energy affordability", "ipa": "/ˈenədʒi əˌfɔːdəbɪləti/", "pron": "EN-uh-jee uh-FOR-duh-BIL-uh-tee", "fr": "accessibilité financière de l’énergie", "def": "The ability of households and businesses to pay for energy.", "ex": "Energy affordability affects public support for the transition."}, {"term": "energy bill", "ipa": "/ˈenədʒi bɪl/", "pron": "EN-uh-jee bill", "fr": "facture énergétique", "def": "The amount paid for electricity, gas or heating.", "ex": "Renewables can reduce exposure to volatile energy bills."}, {"term": "fuel poverty", "ipa": "/ˈfjuːəl ˌpɒvəti/", "pron": "FYOO-uhl POV-uh-tee", "fr": "précarité énergétique", "def": "Inability to afford adequate heating or energy services.", "ex": "Fuel poverty rises when energy prices spike."}, {"term": "to generate electricity", "ipa": "/ˈdʒenəreɪt ɪˌlekˈtrɪsəti/", "pron": "JEN-uh-rayt i-lek-TRIS-uh-tee", "fr": "produire de l’électricité", "def": "To produce electricity.", "ex": "Wind turbines generate electricity from moving air."}, {"term": "to expand renewable capacity", "ipa": "/ɪkˈspænd rɪˌnjuːəbəl kəˈpæsəti/", "pron": "ik-SPAND ri-NYOO-uh-buhl kuh-PASS-uh-tee", "fr": "augmenter la capacité renouvelable", "def": "To increase the amount of renewable power that can be produced.", "ex": "Governments aim to expand renewable capacity."}]}, {"title": "D. Environmental, social and political challenges", "entries": [{"term": "to connect to the grid", "ipa": "/kəˈnekt tə ðə ɡrɪd/", "pron": "kuh-NEKT tuh thuh grid", "fr": "se raccorder au réseau", "def": "To link a power project to the electricity network.", "ex": "Solar farms need to connect to the grid."}, {"term": "to store surplus energy", "ipa": "/stɔː ˈsɜːpləs ˈenədʒi/", "pron": "stor SUR-pluhs EN-uh-jee", "fr": "stocker l’énergie excédentaire", "def": "To keep extra energy for later use.", "ex": "Batteries can store surplus energy."}, {"term": "to balance supply and demand", "ipa": "/ˈbæləns səˈplaɪ ənd dɪˈmɑːnd/", "pron": "BAL-uhns suh-PLY and di-MAHND", "fr": "équilibrer l’offre et la demande", "def": "To match energy production with energy use.", "ex": "Smart grids help balance supply and demand."}, {"term": "to reduce reliance on fossil fuels", "ipa": "/rɪˈdjuːs rɪˈlaɪəns ɒn ˈfɒsəl ˌfjuːəlz/", "pron": "ri-DYOOSS ri-LY-uhns on FOS-uhl FYOO-uhlz", "fr": "réduire la dépendance aux énergies fossiles", "def": "To become less dependent on coal, oil and gas.", "ex": "Renewables reduce reliance on fossil fuels."}, {"term": "to phase in renewables", "ipa": "/feɪz ɪn rɪˈnjuːəbəlz/", "pron": "fayz in ri-NYOO-uh-buhlz", "fr": "introduire progressivement les renouvelables", "def": "To gradually introduce renewable energy.", "ex": "Countries phase in renewables through policy and investment."}, {"term": "to phase out coal", "ipa": "/feɪz aʊt kəʊl/", "pron": "fayz out kohl", "fr": "sortir progressivement du charbon", "def": "To gradually stop using coal.", "ex": "Phasing out coal is essential for climate goals."}, {"term": "to lower energy bills", "ipa": "/ˈləʊə ˈenədʒi bɪlz/", "pron": "LOH-uh EN-uh-jee billz", "fr": "faire baisser les factures d’énergie", "def": "To reduce the amount paid for energy.", "ex": "Efficiency and renewables can lower energy bills."}, {"term": "to secure supply chains", "ipa": "/sɪˈkjʊə səˈplaɪ tʃeɪnz/", "pron": "si-KYOOR suh-PLY chaynz", "fr": "sécuriser les chaînes d’approvisionnement", "def": "To make supply chains more reliable and less vulnerable.", "ex": "Clean-energy policy must secure supply chains."}, {"term": "to overcome local opposition", "ipa": "/ˌəʊvəˈkʌm ˈləʊkəl ˌɒpəˈzɪʃən/", "pron": "oh-vuh-KUM LOH-kuhl op-uh-ZISH-uhn", "fr": "surmonter l’opposition locale", "def": "To deal successfully with resistance from local communities.", "ex": "Developers must overcome local opposition through consultation."}, {"term": "to accelerate permitting", "ipa": "/əkˈseləreɪt pəˈmɪtɪŋ/", "pron": "ak-SEL-uh-rayt puh-MIT-ing", "fr": "accélérer les autorisations", "def": "To make authorisation procedures faster.", "ex": "Governments want to accelerate permitting for renewables."}, {"term": "to modernise the grid", "ipa": "/ˈmɒdənaɪz ðə ɡrɪd/", "pron": "MOD-uh-nyze thuh grid", "fr": "moderniser le réseau", "def": "To upgrade the electricity network.", "ex": "Renewables require countries to modernise the grid."}, {"term": "to ensure a just transition", "ipa": "/ɪnˈʃɔːr ə ˌdʒʌst trænˈzɪʃən/", "pron": "in-SHOR uh just tran-ZISH-uhn", "fr": "garantir une transition juste", "def": "To make the energy transition fair for workers and communities.", "ex": "Policy must ensure a just transition."}, {"term": "to decarbonise the power sector", "ipa": "/ˌdiːˈkɑːbənaɪz ðə ˈpaʊə ˌsektə/", "pron": "dee-KAR-buh-nyze thuh POW-uh SEK-tuh", "fr": "décarboner le secteur électrique", "def": "To remove carbon emissions from electricity production.", "ex": "Renewables help decarbonise the power sector."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p8c69", "part": 8, "chapter": 69, "title": "Fossil Fuels", "file": "cpge_vocab_part8_chapter69_fossil_fuels_premium.html", "count": 98, "sections": [{"title": "A. Core fossil fuel vocabulary", "entries": [{"term": "fossil fuels", "ipa": "/ˈfɒsəl ˌfjuːəlz/", "pron": "FOS-uhl FYOO-uhlz", "fr": "combustibles fossiles ; énergies fossiles", "def": "Energy sources formed from ancient organic matter, mainly coal, oil and natural gas.", "ex": "Fossil fuels still dominate the global energy system."}, {"term": "coal", "ipa": "/kəʊl/", "pron": "kohl", "fr": "charbon", "def": "A black or brown fossil fuel burned for electricity, heat and industry.", "ex": "Coal is the most carbon-intensive major fossil fuel."}, {"term": "oil", "ipa": "/ɔɪl/", "pron": "oil", "fr": "pétrole", "def": "A liquid fossil fuel refined into petrol, diesel, jet fuel and petrochemical products.", "ex": "Oil remains central to transport and global trade."}, {"term": "crude oil", "ipa": "/ˌkruːd ˈɔɪl/", "pron": "krood oil", "fr": "pétrole brut", "def": "Unrefined oil extracted from underground reservoirs.", "ex": "Crude oil prices influence the global economy."}, {"term": "natural gas", "ipa": "/ˌnætʃərəl ˈɡæs/", "pron": "NAT-chuh-ruhl gas", "fr": "gaz naturel", "def": "A fossil fuel made mostly of methane, used for heating, electricity and industry.", "ex": "Natural gas emits CO2 and can leak methane."}, {"term": "methane", "ipa": "/ˈmiːθeɪn/", "pron": "MEE-thayn", "fr": "méthane", "def": "A powerful greenhouse gas and the main component of natural gas.", "ex": "Methane leaks make gas more climate-damaging."}, {"term": "hydrocarbon", "ipa": "/ˌhaɪdrəʊˈkɑːbən/", "pron": "HY-droh-KAR-buhn", "fr": "hydrocarbure", "def": "A chemical compound made of hydrogen and carbon, found in fossil fuels.", "ex": "Oil and gas are hydrocarbons."}, {"term": "petroleum", "ipa": "/pəˈtrəʊliəm/", "pron": "puh-TROH-lee-uhm", "fr": "pétrole", "def": "A broad term for crude oil and products made from it.", "ex": "Petroleum products include petrol, diesel and plastics."}, {"term": "gasoline", "ipa": "/ˈɡæsəliːn/", "pron": "GAS-uh-leen", "fr": "essence", "def": "US term for petrol, a fuel used in cars.", "ex": "Gasoline demand remains high in car-dependent societies."}, {"term": "petrol", "ipa": "/ˈpetrəl/", "pron": "PET-ruhl", "fr": "essence", "def": "UK term for gasoline, a fuel used in cars.", "ex": "Petrol cars are being phased out in some countries."}, {"term": "diesel", "ipa": "/ˈdiːzəl/", "pron": "DEE-zuhl", "fr": "diesel ; gazole", "def": "A fuel used in many cars, trucks, ships and generators.", "ex": "Diesel engines emit pollutants harmful to health."}, {"term": "jet fuel", "ipa": "/ˈdʒet ˌfjuːəl/", "pron": "jet FYOO-uhl", "fr": "kérosène ; carburant aviation", "def": "Fuel used by aircraft.", "ex": "Jet fuel is difficult to replace at scale."}, {"term": "liquefied natural gas", "ipa": "/ˈlɪkwɪfaɪd ˌnætʃərəl ˈɡæs/", "pron": "LIK-wi-fyd NAT-chuh-ruhl gas", "fr": "gaz naturel liquéfié", "def": "Natural gas cooled into liquid form for transport by ship.", "ex": "Liquefied natural gas has reshaped energy geopolitics."}, {"term": "LNG", "ipa": "/ˌel en ˈdʒiː/", "pron": "el-en-jee", "fr": "GNL", "def": "Abbreviation for liquefied natural gas.", "ex": "LNG imports can reduce dependence on pipelines."}, {"term": "shale gas", "ipa": "/ˈʃeɪl ɡæs/", "pron": "shayl gas", "fr": "gaz de schiste", "def": "Natural gas extracted from shale rock, often using fracking.", "ex": "Shale gas transformed the US energy market."}, {"term": "shale oil", "ipa": "/ˈʃeɪl ɔɪl/", "pron": "shayl oil", "fr": "pétrole de schiste", "def": "Oil extracted from shale formations, often through hydraulic fracturing.", "ex": "Shale oil increased US oil production."}, {"term": "tar sands", "ipa": "/ˈtɑː sændz/", "pron": "tar sandz", "fr": "sables bitumineux", "def": "Deposits of sand mixed with heavy oil, also called oil sands.", "ex": "Tar sands extraction has a high environmental impact."}, {"term": "oil sands", "ipa": "/ˈɔɪl sændz/", "pron": "oil sandz", "fr": "sables bitumineux", "def": "Deposits of sand, clay and bitumen used to produce oil.", "ex": "Oil sands are carbon-intensive to exploit."}]}, {"title": "B. Extraction, transport, refining and combustion", "entries": [{"term": "fossil fuel extraction", "ipa": "/ˈfɒsəl ˌfjuːəl ɪkˈstrækʃən/", "pron": "FOS-uhl FYOO-uhl ik-STRAK-shuhn", "fr": "extraction des combustibles fossiles", "def": "The process of removing coal, oil or gas from the ground.", "ex": "Fossil fuel extraction damages landscapes and ecosystems."}, {"term": "mining", "ipa": "/ˈmaɪnɪŋ/", "pron": "MY-ning", "fr": "exploitation minière", "def": "Removing minerals, coal or other resources from the ground.", "ex": "Coal mining can be dangerous for workers."}, {"term": "coal mining", "ipa": "/ˈkəʊl ˌmaɪnɪŋ/", "pron": "kohl MY-ning", "fr": "extraction du charbon", "def": "The extraction of coal from underground or surface mines.", "ex": "Coal mining shaped many industrial regions."}, {"term": "open-cast mining", "ipa": "/ˌəʊpən kɑːst ˈmaɪnɪŋ/", "pron": "OH-puhn-kast MY-ning", "fr": "exploitation à ciel ouvert", "def": "Mining from a large open pit at the surface.", "ex": "Open-cast mining scars landscapes."}, {"term": "underground mining", "ipa": "/ˌʌndəɡraʊnd ˈmaɪnɪŋ/", "pron": "UN-duh-ground MY-ning", "fr": "exploitation souterraine", "def": "Mining carried out below the surface.", "ex": "Underground mining creates serious safety risks."}, {"term": "drilling", "ipa": "/ˈdrɪlɪŋ/", "pron": "DRIL-ing", "fr": "forage", "def": "Making wells to extract oil or gas.", "ex": "Offshore drilling is technically complex and risky."}, {"term": "oil rig", "ipa": "/ˈɔɪl rɪɡ/", "pron": "oil rig", "fr": "plateforme pétrolière ; appareil de forage", "def": "A structure used to drill for oil or gas.", "ex": "An oil rig can operate offshore or on land."}, {"term": "offshore drilling", "ipa": "/ˌɒfʃɔː ˈdrɪlɪŋ/", "pron": "OFF-shor DRIL-ing", "fr": "forage offshore", "def": "Drilling for oil or gas beneath the seabed.", "ex": "Offshore drilling can cause major oil spills."}, {"term": "fracking", "ipa": "/ˈfrækɪŋ/", "pron": "FRAK-ing", "fr": "fracturation hydraulique", "def": "Hydraulic fracturing, a method of extracting oil or gas by cracking rock with pressurised fluid.", "ex": "Fracking is controversial because of water use, earthquakes and pollution."}, {"term": "hydraulic fracturing", "ipa": "/haɪˌdrɔːlɪk ˈfræktʃərɪŋ/", "pron": "hy-DRAW-lik FRAK-chuh-ring", "fr": "fracturation hydraulique", "def": "The full term for fracking.", "ex": "Hydraulic fracturing opened new fossil fuel reserves."}, {"term": "pipeline", "ipa": "/ˈpaɪplaɪn/", "pron": "PYPE-line", "fr": "oléoduc ; gazoduc", "def": "A long pipe used to transport oil or gas.", "ex": "Pipelines create strategic dependencies."}, {"term": "refinery", "ipa": "/rɪˈfaɪnəri/", "pron": "ri-FY-nuh-ree", "fr": "raffinerie", "def": "An industrial facility that turns crude oil into usable products.", "ex": "Refineries produce petrol, diesel and jet fuel."}, {"term": "petrochemical industry", "ipa": "/ˌpetrəʊˈkemɪkəl ˈɪndəstri/", "pron": "PET-roh-KEM-i-kuhl IN-duh-stree", "fr": "industrie pétrochimique", "def": "The industry producing chemicals from fossil fuels.", "ex": "The petrochemical industry links fossil fuels to consumer goods."}, {"term": "combustion", "ipa": "/kəmˈbʌstʃən/", "pron": "kuhm-BUS-chuhn", "fr": "combustion", "def": "Burning fuel to release energy.", "ex": "Combustion of fossil fuels releases CO2."}, {"term": "coal-fired power plant", "ipa": "/ˈkəʊl faɪəd ˈpaʊə plɑːnt/", "pron": "kohl-fy-uhrd POW-uh plant", "fr": "centrale à charbon", "def": "A power plant that burns coal to generate electricity.", "ex": "Coal-fired power plants are being closed in some countries."}, {"term": "gas-fired power plant", "ipa": "/ˈɡæs faɪəd ˈpaʊə plɑːnt/", "pron": "gas-fy-uhrd POW-uh plant", "fr": "centrale à gaz", "def": "A power plant that burns natural gas.", "ex": "Gas-fired power plants can respond quickly to demand."}]}, {"title": "C. Climate, pollution and environmental damage", "entries": [{"term": "carbon emissions", "ipa": "/ˈkɑːbən ɪˌmɪʃənz/", "pron": "KAR-buhn i-MISH-uhnz", "fr": "émissions de carbone", "def": "Emissions of carbon dioxide or carbon-based greenhouse gases.", "ex": "Carbon emissions must fall quickly."}, {"term": "greenhouse gas emissions", "ipa": "/ˈɡriːnhaʊs ɡæs ɪˌmɪʃənz/", "pron": "GREEN-house gas i-MISH-uhnz", "fr": "émissions de gaz à effet de serre", "def": "Emissions of gases that trap heat in the atmosphere.", "ex": "Fossil fuels are the main source of greenhouse gas emissions."}, {"term": "carbon intensity", "ipa": "/ˈkɑːbən ɪnˌtensəti/", "pron": "KAR-buhn in-TEN-suh-tee", "fr": "intensité carbone", "def": "The amount of carbon emitted per unit of energy or output.", "ex": "Coal has a high carbon intensity."}, {"term": "air pollution", "ipa": "/ˈeə pəˌluːʃən/", "pron": "air puh-LOO-shuhn", "fr": "pollution de l’air", "def": "Harmful substances in the air.", "ex": "Air pollution from fossil fuels harms health."}, {"term": "particulate matter", "ipa": "/pɑːˌtɪkjʊlət ˈmætə/", "pron": "par-TIK-yuh-luht MAT-uh", "fr": "particules fines", "def": "Tiny particles in the air that can damage lungs and hearts.", "ex": "Particulate matter is linked to premature deaths."}, {"term": "PM2.5", "ipa": "/ˌpiː em tuː pɔɪnt ˈfaɪv/", "pron": "pee-em two-point-five", "fr": "PM2,5 ; particules fines", "def": "Fine particulate matter smaller than 2.5 micrometres.", "ex": "PM2.5 can penetrate deep into the lungs."}, {"term": "sulphur dioxide", "ipa": "/ˌsʌlfə daɪˈɒksaɪd/", "pron": "SUL-fuh dy-OK-syde", "fr": "dioxyde de soufre", "def": "A pollutant produced by burning sulphur-containing fuels.", "ex": "Sulphur dioxide contributes to acid rain."}, {"term": "nitrogen oxides", "ipa": "/ˌnaɪtrədʒən ˈɒksaɪdz/", "pron": "NY-truh-juhn OK-sydz", "fr": "oxydes d’azote", "def": "Air pollutants produced by combustion.", "ex": "Nitrogen oxides worsen urban air pollution."}, {"term": "acid rain", "ipa": "/ˌæsɪd ˈreɪn/", "pron": "ASS-id rayn", "fr": "pluie acide", "def": "Rain made acidic by pollutants such as sulphur dioxide and nitrogen oxides.", "ex": "Acid rain damages forests, lakes and buildings."}, {"term": "oil spill", "ipa": "/ˈɔɪl spɪl/", "pron": "oil spill", "fr": "marée noire ; déversement de pétrole", "def": "A release of oil into the environment, especially water.", "ex": "Oil spills can devastate marine ecosystems."}, {"term": "methane leak", "ipa": "/ˈmiːθeɪn liːk/", "pron": "MEE-thayn leek", "fr": "fuite de méthane", "def": "An unintended release of methane into the atmosphere.", "ex": "Methane leaks undermine the climate case for gas."}, {"term": "flaring", "ipa": "/ˈfleərɪŋ/", "pron": "FLAIR-ing", "fr": "torchage", "def": "Burning unwanted gas during oil or gas extraction.", "ex": "Flaring wastes energy and emits CO2."}, {"term": "venting", "ipa": "/ˈventɪŋ/", "pron": "VEN-ting", "fr": "rejet direct ; dégazage", "def": "Releasing gas directly into the atmosphere.", "ex": "Venting methane is highly damaging for the climate."}, {"term": "environmental degradation", "ipa": "/ɪnˌvaɪrənˈmentəl ˌdeɡrəˈdeɪʃən/", "pron": "in-vy-ruhn-MEN-tuhl deg-ruh-DAY-shuhn", "fr": "dégradation environnementale", "def": "Damage to ecosystems, land, water or air.", "ex": "Fossil fuel extraction causes environmental degradation."}, {"term": "water contamination", "ipa": "/ˈwɔːtə kənˌtæmɪˈneɪʃən/", "pron": "WOR-tuh kuhn-tam-i-NAY-shuhn", "fr": "contamination de l’eau", "def": "Pollution of water by harmful substances.", "ex": "Fracking can raise concerns about water contamination."}]}, {"title": "D. Energy security, geopolitics and fossil fuel economics", "entries": [{"term": "fossil fuel dependency", "ipa": "/ˈfɒsəl ˌfjuːəl dɪˌpendənsi/", "pron": "FOS-uhl FYOO-uhl di-PEN-duhn-see", "fr": "dépendance aux énergies fossiles", "def": "Reliance on coal, oil and gas for energy or revenue.", "ex": "Fossil fuel dependency slows the energy transition."}, {"term": "energy security", "ipa": "/ˈenədʒi sɪˌkjʊərəti/", "pron": "EN-uh-jee si-KYOOR-uh-tee", "fr": "sécurité énergétique", "def": "Reliable and affordable access to energy.", "ex": "Energy security became urgent after gas supply shocks."}, {"term": "energy crisis", "ipa": "/ˈenədʒi ˌkraɪsɪs/", "pron": "EN-uh-jee KRY-sis", "fr": "crise énergétique", "def": "A severe disruption in energy supply, affordability or stability.", "ex": "An energy crisis can trigger inflation and social unrest."}, {"term": "price volatility", "ipa": "/ˈpraɪs ˌvɒləˈtɪləti/", "pron": "pryce vol-uh-TIL-uh-tee", "fr": "volatilité des prix", "def": "Frequent and unpredictable changes in prices.", "ex": "Oil and gas markets are prone to price volatility."}, {"term": "oil shock", "ipa": "/ˈɔɪl ʃɒk/", "pron": "oil shok", "fr": "choc pétrolier", "def": "A sudden disruption or surge in oil prices.", "ex": "Oil shocks can damage economic growth."}, {"term": "global energy demand", "ipa": "/ˌɡləʊbəl ˈenədʒi dɪˌmɑːnd/", "pron": "GLOH-buhl EN-uh-jee di-MAHND", "fr": "demande énergétique mondiale", "def": "Worldwide demand for energy.", "ex": "Global energy demand continues to rise."}, {"term": "energy-intensive industry", "ipa": "/ˈenədʒi ɪnˌtensɪv ˈɪndəstri/", "pron": "EN-uh-jee in-TEN-siv IN-duh-stree", "fr": "industrie énergivore", "def": "An industry requiring large amounts of energy.", "ex": "Steel and cement are energy-intensive industries."}, {"term": "hard-to-abate sector", "ipa": "/ˌhɑːd tuː əˈbeɪt ˈsektə/", "pron": "hard-to-uh-BAYT SEK-tuh", "fr": "secteur difficile à décarboner", "def": "A sector where emissions are difficult to reduce.", "ex": "Aviation and cement are hard-to-abate sectors."}, {"term": "petrostate", "ipa": "/ˈpetrəʊsteɪt/", "pron": "PET-roh-state", "fr": "État pétrolier", "def": "A state whose economy and politics depend heavily on oil or gas revenues.", "ex": "Petrostates face transition risks."}, {"term": "resource curse", "ipa": "/rɪˈsɔːs kɜːs/", "pron": "ri-SORSS curse", "fr": "malédiction des ressources", "def": "The paradox that resource-rich countries may suffer corruption, conflict or weak development.", "ex": "Oil wealth can create a resource curse."}, {"term": "rentier state", "ipa": "/ˈrentieɪ steɪt/", "pron": "REN-tee-ay state", "fr": "État rentier", "def": "A state relying on external rents such as oil revenues rather than broad taxation.", "ex": "Rentier states may be less accountable to citizens."}, {"term": "OPEC", "ipa": "/ˈəʊpek/", "pron": "OH-pek", "fr": "OPEP", "def": "Organization of the Petroleum Exporting Countries.", "ex": "OPEC influences global oil supply and prices."}, {"term": "energy geopolitics", "ipa": "/ˈenədʒi ˌdʒiːəʊˈpɒlətɪks/", "pron": "EN-uh-jee jee-oh-POL-uh-tiks", "fr": "géopolitique de l’énergie", "def": "The geopolitical power relations linked to energy resources and supply.", "ex": "Fossil fuels have long shaped energy geopolitics."}, {"term": "pipeline politics", "ipa": "/ˈpaɪplaɪn ˌpɒlətɪks/", "pron": "PYPE-line POL-uh-tiks", "fr": "politique des pipelines", "def": "Political conflicts and power relations linked to pipelines.", "ex": "Pipeline politics can divide allies."}, {"term": "energy weapon", "ipa": "/ˈenədʒi ˌwepən/", "pron": "EN-uh-jee WEP-uhn", "fr": "arme énergétique", "def": "Energy supplies used as political pressure.", "ex": "Gas exports can become an energy weapon."}, {"term": "supply disruption", "ipa": "/səˈplaɪ dɪsˌrʌpʃən/", "pron": "suh-PLY dis-RUP-shuhn", "fr": "rupture d’approvisionnement", "def": "An interruption in the availability of goods or energy.", "ex": "Supply disruption can push energy prices up."}, {"term": "fossil fuel subsidy", "ipa": "/ˈfɒsəl ˌfjuːəl ˈsʌbsɪdi/", "pron": "FOS-uhl FYOO-uhl SUB-si-dee", "fr": "subvention aux énergies fossiles", "def": "Government support that lowers fossil fuel production or consumption costs.", "ex": "Fossil fuel subsidies make clean energy less competitive."}, {"term": "carbon lock-in", "ipa": "/ˈkɑːbən ˌlɒk ɪn/", "pron": "KAR-buhn LOK-in", "fr": "verrouillage carbone", "def": "Dependence on high-carbon infrastructure that is difficult to change.", "ex": "New gas infrastructure can create carbon lock-in."}, {"term": "stranded asset", "ipa": "/ˌstrændɪd ˈæset/", "pron": "STRAN-did AS-et", "fr": "actif échoué", "def": "An asset that loses value because of policy, market or environmental change.", "ex": "Coal plants may become stranded assets."}, {"term": "transition risk", "ipa": "/trænˈzɪʃən rɪsk/", "pron": "tran-ZISH-uhn risk", "fr": "risque de transition", "def": "Risk created by the shift to a low-carbon economy.", "ex": "Fossil fuel firms face transition risk."}, {"term": "divestment", "ipa": "/daɪˈvestmənt/", "pron": "dy-VEST-muhnt", "fr": "désinvestissement", "def": "Selling investments for ethical, political or financial reasons.", "ex": "Universities have faced pressure for fossil fuel divestment."}, {"term": "fossil fuel divestment", "ipa": "/ˈfɒsəl ˌfjuːəl daɪˈvestmənt/", "pron": "FOS-uhl FYOO-uhl dy-VEST-muhnt", "fr": "désinvestissement des énergies fossiles", "def": "Selling investments in fossil fuel companies.", "ex": "Fossil fuel divestment is a climate activism strategy."}, {"term": "polluter pays principle", "ipa": "/pəˈluːtə peɪz ˈprɪnsəpəl/", "pron": "puh-LOO-tuh payz PRIN-suh-puhl", "fr": "principe pollueur-payeur", "def": "The principle that those causing pollution should pay for the damage.", "ex": "The polluter pays principle supports climate accountability."}, {"term": "climate liability", "ipa": "/ˈklaɪmət ˌlaɪəˈbɪləti/", "pron": "KLY-muht ly-uh-BIL-uh-tee", "fr": "responsabilité climatique", "def": "Legal responsibility for climate-related harm.", "ex": "Climate liability could reshape corporate behaviour."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "greenwashing ; écoblanchiment", "def": "Misleading environmental claims made to improve reputation.", "ex": "Oil companies are often accused of greenwashing."}, {"term": "carbon capture and storage", "ipa": "/ˌkɑːbən ˈkæptʃər ənd ˈstɔːrɪdʒ/", "pron": "KAR-buhn KAP-chuh and STOR-ij", "fr": "captage et stockage du carbone", "def": "Capturing CO2 and storing it underground or elsewhere.", "ex": "Carbon capture and storage is promoted by some fossil fuel companies."}, {"term": "CCS", "ipa": "/ˌsiː siː ˈes/", "pron": "see-see-ess", "fr": "CSC", "def": "Abbreviation for carbon capture and storage.", "ex": "CCS may help some industries but cannot justify unlimited fossil fuel use."}, {"term": "blue hydrogen", "ipa": "/ˌbluː ˈhaɪdrədʒən/", "pron": "blue HY-druh-juhn", "fr": "hydrogène bleu", "def": "Hydrogen produced from natural gas with carbon capture.", "ex": "Blue hydrogen depends on gas and effective carbon capture."}]}, {"title": "E. Transition, accountability and high-value verbs", "entries": [{"term": "grey hydrogen", "ipa": "/ˌɡreɪ ˈhaɪdrədʒən/", "pron": "grey HY-druh-juhn", "fr": "hydrogène gris", "def": "Hydrogen produced from fossil fuels without carbon capture.", "ex": "Grey hydrogen has high emissions."}, {"term": "coal phase-out", "ipa": "/ˈkəʊl ˌfeɪz aʊt/", "pron": "kohl fayz-out", "fr": "sortie progressive du charbon", "def": "The gradual end of coal use.", "ex": "Coal phase-out is vital for climate goals."}, {"term": "fossil fuel phase-out", "ipa": "/ˈfɒsəl ˌfjuːəl ˌfeɪz aʊt/", "pron": "FOS-uhl FYOO-uhl fayz-out", "fr": "sortie progressive des énergies fossiles", "def": "The gradual end of fossil fuel use.", "ex": "A fossil fuel phase-out is politically difficult."}, {"term": "managed decline", "ipa": "/ˌmænɪdʒd dɪˈklaɪn/", "pron": "MAN-ijd di-KLYNE", "fr": "déclin organisé", "def": "A planned reduction of an industry or activity over time.", "ex": "Some experts call for a managed decline of fossil fuel production."}, {"term": "demand reduction", "ipa": "/dɪˈmɑːnd rɪˌdʌkʃən/", "pron": "di-MAHND ri-DUK-shuhn", "fr": "réduction de la demande", "def": "Lowering the amount of energy or resources used.", "ex": "Demand reduction can reduce pressure on energy systems."}, {"term": "electrification", "ipa": "/ɪˌlektrɪfɪˈkeɪʃən/", "pron": "i-lek-tri-fi-KAY-shuhn", "fr": "électrification", "def": "Replacing fossil fuel uses with electricity.", "ex": "Electrification can reduce oil and gas demand."}, {"term": "to burn fossil fuels", "ipa": "/bɜːn ˈfɒsəl ˌfjuːəlz/", "pron": "burn FOS-uhl FYOO-uhlz", "fr": "brûler des combustibles fossiles", "def": "To use coal, oil or gas as fuel.", "ex": "Burning fossil fuels releases greenhouse gases."}, {"term": "to extract oil and gas", "ipa": "/ɪkˈstrækt ɔɪl ənd ɡæs/", "pron": "ik-STRAKT oil and gas", "fr": "extraire du pétrole et du gaz", "def": "To remove oil and gas from the ground or seabed.", "ex": "Companies extract oil and gas from offshore fields."}, {"term": "to drill for oil", "ipa": "/drɪl fər ɔɪl/", "pron": "dril fuh oil", "fr": "forer pour chercher du pétrole", "def": "To make wells to search for or extract oil.", "ex": "Firms drill for oil in remote regions."}, {"term": "to leak methane", "ipa": "/liːk ˈmiːθeɪn/", "pron": "leek MEE-thayn", "fr": "laisser fuir du méthane", "def": "To release methane unintentionally.", "ex": "Poor infrastructure can leak methane."}, {"term": "to flare gas", "ipa": "/fleə ɡæs/", "pron": "flair gas", "fr": "torcher du gaz", "def": "To burn unwanted gas during extraction.", "ex": "Oil producers may flare gas at extraction sites."}, {"term": "to subsidise fossil fuels", "ipa": "/ˈsʌbsɪdaɪz ˈfɒsəl ˌfjuːəlz/", "pron": "SUB-si-dyze FOS-uhl FYOO-uhlz", "fr": "subventionner les énergies fossiles", "def": "To support fossil fuels financially through public policy.", "ex": "Governments still subsidise fossil fuels."}, {"term": "to phase out coal", "ipa": "/feɪz aʊt kəʊl/", "pron": "fayz out kohl", "fr": "sortir progressivement du charbon", "def": "To gradually stop using coal.", "ex": "Countries must phase out coal to meet climate goals."}, {"term": "to phase out fossil fuels", "ipa": "/feɪz aʊt ˈfɒsəl ˌfjuːəlz/", "pron": "fayz out FOS-uhl FYOO-uhlz", "fr": "sortir progressivement des énergies fossiles", "def": "To gradually stop using coal, oil and gas.", "ex": "A fossil fuel phase-out requires alternatives and political will."}, {"term": "to reduce fossil fuel dependence", "ipa": "/rɪˈdjuːs ˈfɒsəl ˌfjuːəl dɪˌpendəns/", "pron": "ri-DYOOSS FOS-uhl FYOO-uhl di-PEN-duhns", "fr": "réduire la dépendance aux énergies fossiles", "def": "To become less reliant on fossil fuels.", "ex": "Renewables help reduce fossil fuel dependence."}, {"term": "to diversify the energy mix", "ipa": "/daɪˈvɜːsɪfaɪ ði ˈenədʒi mɪks/", "pron": "dy-VUR-si-fy thee EN-uh-jee miks", "fr": "diversifier le mix énergétique", "def": "To use a wider range of energy sources.", "ex": "Countries diversify the energy mix for security and climate reasons."}, {"term": "to create stranded assets", "ipa": "/kriˈeɪt ˌstrændɪd ˈæsets/", "pron": "kree-AYT STRAN-did AS-ets", "fr": "créer des actifs échoués", "def": "To make assets lose value because of the transition or regulation.", "ex": "Strict climate policy may create stranded assets."}, {"term": "to hold polluters accountable", "ipa": "/həʊld pəˈluːtəz əˈkaʊntəbəl/", "pron": "hohld puh-LOO-tuhz uh-KOWN-tuh-buhl", "fr": "tenir les pollueurs responsables", "def": "To make polluters responsible for environmental harm.", "ex": "Climate litigation seeks to hold polluters accountable."}, {"term": "to invest in clean energy", "ipa": "/ɪnˈvest ɪn ˌkliːn ˈenədʒi/", "pron": "in-VEST in kleen EN-uh-jee", "fr": "investir dans l’énergie propre", "def": "To put money into low-pollution energy systems.", "ex": "Oil companies claim to invest in clean energy."}, {"term": "to manage the transition", "ipa": "/ˈmænɪdʒ ðə trænˈzɪʃən/", "pron": "MAN-ij thuh tran-ZISH-uhn", "fr": "gérer la transition", "def": "To organise the shift to a new energy system.", "ex": "Governments must manage the transition fairly."}, {"term": "to balance energy security and climate goals", "ipa": "/ˈbæləns ˈenədʒi sɪˌkjʊərəti ənd ˈklaɪmət ɡəʊlz/", "pron": "BAL-uhns EN-uh-jee si-KYOOR-uh-tee and KLY-muht gohlz", "fr": "équilibrer sécurité énergétique et objectifs climatiques", "def": "To protect energy supply while reducing emissions.", "ex": "Policymakers must balance energy security and climate goals."}]}]}, {"id": "p8c70", "part": 8, "chapter": 70, "title": "Biodiversity", "file": "cpge_vocab_part8_chapter70_biodiversity_premium.html", "count": 121, "sections": [{"title": "A. Core biodiversity and ecosystem vocabulary", "entries": [{"term": "biodiversity", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti/", "pron": "BY-oh-dy-VUR-suh-tee", "fr": "biodiversité", "def": "The variety of life on Earth, including species, genes and ecosystems.", "ex": "Biodiversity is essential for stable ecosystems and human survival."}, {"term": "biological diversity", "ipa": "/ˌbaɪəˈlɒdʒɪkəl daɪˈvɜːsəti/", "pron": "BY-uh-LOJ-i-kuhl dy-VUR-suh-tee", "fr": "diversité biologique", "def": "The full term for biodiversity.", "ex": "Biological diversity is declining at an alarming rate."}, {"term": "species diversity", "ipa": "/ˈspiːʃiːz daɪˌvɜːsəti/", "pron": "SPEE-sheez dy-VUR-suh-tee", "fr": "diversité des espèces", "def": "The variety of species in a habitat or ecosystem.", "ex": "Tropical rainforests have high species diversity."}, {"term": "genetic diversity", "ipa": "/dʒəˌnetɪk daɪˈvɜːsəti/", "pron": "juh-NET-ik dy-VUR-suh-tee", "fr": "diversité génétique", "def": "The variety of genes within a species or population.", "ex": "Genetic diversity helps species adapt to change."}, {"term": "ecosystem diversity", "ipa": "/ˈiːkəʊˌsɪstəm daɪˈvɜːsəti/", "pron": "EE-koh-SIS-tuhm dy-VUR-suh-tee", "fr": "diversité des écosystèmes", "def": "The variety of ecosystems in a region or on Earth.", "ex": "Ecosystem diversity includes forests, wetlands, oceans and grasslands."}, {"term": "ecosystem", "ipa": "/ˈiːkəʊˌsɪstəm/", "pron": "EE-koh-SIS-tuhm", "fr": "écosystème", "def": "A community of living organisms interacting with their physical environment.", "ex": "An ecosystem can be disrupted by pollution or climate change."}, {"term": "habitat", "ipa": "/ˈhæbɪtæt/", "pron": "HAB-i-tat", "fr": "habitat", "def": "The natural place where a plant, animal or organism lives.", "ex": "Habitat destruction is a major cause of extinction."}, {"term": "habitat loss", "ipa": "/ˈhæbɪtæt lɒs/", "pron": "HAB-i-tat loss", "fr": "perte d’habitat", "def": "The destruction or degradation of natural habitats.", "ex": "Habitat loss threatens thousands of species."}, {"term": "habitat fragmentation", "ipa": "/ˈhæbɪtæt ˌfræɡmənˈteɪʃən/", "pron": "HAB-i-tat frag-muhn-TAY-shuhn", "fr": "fragmentation des habitats", "def": "The breaking of habitats into smaller isolated patches.", "ex": "Roads and urban sprawl cause habitat fragmentation."}, {"term": "ecosystem services", "ipa": "/ˈiːkəʊˌsɪstəm ˈsɜːvɪsɪz/", "pron": "EE-koh-SIS-tuhm SUR-vis-iz", "fr": "services écosystémiques", "def": "Benefits humans obtain from ecosystems, such as pollination, clean water and carbon storage.", "ex": "Ecosystem services are often invisible until they collapse."}, {"term": "pollination", "ipa": "/ˌpɒlɪˈneɪʃən/", "pron": "pol-i-NAY-shuhn", "fr": "pollinisation", "def": "The transfer of pollen enabling plants to reproduce.", "ex": "Pollination is vital for many crops."}, {"term": "pollinator", "ipa": "/ˈpɒlɪneɪtə/", "pron": "POL-i-nay-tuh", "fr": "pollinisateur", "def": "An animal that carries pollen, such as a bee, butterfly or bird.", "ex": "Pollinators are threatened by pesticides and habitat loss."}, {"term": "food chain", "ipa": "/ˈfuːd tʃeɪn/", "pron": "food chayn", "fr": "chaîne alimentaire", "def": "A sequence of organisms where each is eaten by the next.", "ex": "Removing one species can disrupt the food chain."}, {"term": "food web", "ipa": "/ˈfuːd web/", "pron": "food web", "fr": "réseau trophique", "def": "A network of feeding relationships in an ecosystem.", "ex": "A food web is more complex than a simple food chain."}, {"term": "keystone species", "ipa": "/ˈkiːstəʊn ˌspiːʃiːz/", "pron": "KEY-stohn SPEE-sheez", "fr": "espèce clé de voûte", "def": "A species with a crucial role in maintaining an ecosystem.", "ex": "The loss of a keystone species can transform an ecosystem."}, {"term": "indicator species", "ipa": "/ˈɪndɪkeɪtə ˌspiːʃiːz/", "pron": "IN-di-kay-tuh SPEE-sheez", "fr": "espèce indicatrice", "def": "A species that reveals the health of an ecosystem.", "ex": "Frogs are often indicator species because they are sensitive to pollution."}, {"term": "endemic species", "ipa": "/enˈdemɪk ˌspiːʃiːz/", "pron": "en-DEM-ik SPEE-sheez", "fr": "espèce endémique", "def": "A species found naturally only in one geographic area.", "ex": "Island ecosystems often contain many endemic species."}, {"term": "native species", "ipa": "/ˈneɪtɪv ˌspiːʃiːz/", "pron": "NAY-tiv SPEE-sheez", "fr": "espèce indigène", "def": "A species that naturally belongs to a region.", "ex": "Native species can be threatened by invasive species."}, {"term": "invasive species", "ipa": "/ɪnˈveɪsɪv ˌspiːʃiːz/", "pron": "in-VAY-siv SPEE-sheez", "fr": "espèce invasive", "def": "A non-native species that spreads and harms ecosystems, economies or health.", "ex": "Invasive species can outcompete native plants and animals."}, {"term": "alien species", "ipa": "/ˈeɪliən ˌspiːʃiːz/", "pron": "AY-lee-uhn SPEE-sheez", "fr": "espèce exotique", "def": "A species introduced outside its natural range.", "ex": "Not every alien species becomes invasive."}, {"term": "threatened species", "ipa": "/ˈθretənd ˌspiːʃiːz/", "pron": "THRET-uhnd SPEE-sheez", "fr": "espèce menacée", "def": "A species likely to become endangered if pressures continue.", "ex": "Threatened species need protection before it is too late."}, {"term": "endangered species", "ipa": "/ɪnˈdeɪndʒəd ˌspiːʃiːz/", "pron": "in-DAYN-juhd SPEE-sheez", "fr": "espèce en voie de disparition", "def": "A species at serious risk of extinction.", "ex": "The tiger is an endangered species."}, {"term": "critically endangered", "ipa": "/ˌkrɪtɪkəli ɪnˈdeɪndʒəd/", "pron": "KRIT-i-kuh-lee in-DAYN-juhd", "fr": "en danger critique d’extinction", "def": "Facing an extremely high risk of extinction in the wild.", "ex": "Critically endangered species require urgent action."}, {"term": "extinction", "ipa": "/ɪkˈstɪŋkʃən/", "pron": "ik-STINK-shuhn", "fr": "extinction", "def": "The permanent disappearance of a species.", "ex": "Extinction is irreversible."}, {"term": "mass extinction", "ipa": "/ˌmæs ɪkˈstɪŋkʃən/", "pron": "mass ik-STINK-shuhn", "fr": "extinction de masse", "def": "A period when many species disappear in a relatively short time.", "ex": "Scientists warn that humans may be driving a sixth mass extinction."}, {"term": "biodiversity loss", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti lɒs/", "pron": "BY-oh-dy-VUR-suh-tee loss", "fr": "perte de biodiversité", "def": "The decline in the variety and abundance of life.", "ex": "Biodiversity loss undermines food security and ecosystem resilience."}, {"term": "species decline", "ipa": "/ˈspiːʃiːz dɪˌklaɪn/", "pron": "SPEE-sheez di-KLYNE", "fr": "déclin des espèces", "def": "A reduction in the number or range of a species.", "ex": "Species decline is often caused by habitat destruction."}, {"term": "population decline", "ipa": "/ˌpɒpjʊˈleɪʃən dɪˌklaɪn/", "pron": "pop-yuh-LAY-shuhn di-KLYNE", "fr": "déclin d’une population", "def": "A fall in the number of individuals in a population.", "ex": "Bird population decline is visible in many farming landscapes."}, {"term": "ecosystem collapse", "ipa": "/ˈiːkəʊˌsɪstəm kəˌlæps/", "pron": "EE-koh-SIS-tuhm kuh-LAPS", "fr": "effondrement d’un écosystème", "def": "A breakdown in the structure and function of an ecosystem.", "ex": "Ecosystem collapse can affect water, food and livelihoods."}, {"term": "ecological balance", "ipa": "/ˌiːkəˈlɒdʒɪkəl ˈbæləns/", "pron": "ee-kuh-LOJ-i-kuhl BAL-uhns", "fr": "équilibre écologique", "def": "A stable relationship between organisms and their environment.", "ex": "Human activity can disrupt ecological balance."}, {"term": "ecological resilience", "ipa": "/ˌiːkəˈlɒdʒɪkəl rɪˈzɪliəns/", "pron": "ee-kuh-LOJ-i-kuhl ri-ZIL-ee-uhns", "fr": "résilience écologique", "def": "The ability of an ecosystem to resist and recover from disturbance.", "ex": "Biodiversity increases ecological resilience."}, {"term": "conservation", "ipa": "/ˌkɒnsəˈveɪʃən/", "pron": "kon-suh-VAY-shuhn", "fr": "conservation ; protection de la nature", "def": "Protection and management of nature, species and ecosystems.", "ex": "Conservation requires science, funding and local support."}]}, {"title": "B. Conservation, restoration and protected areas", "entries": [{"term": "wildlife conservation", "ipa": "/ˈwaɪldlaɪf ˌkɒnsəˈveɪʃən/", "pron": "WYLD-life kon-suh-VAY-shuhn", "fr": "conservation de la faune sauvage", "def": "Protection of wild animals and their habitats.", "ex": "Wildlife conservation can conflict with development pressures."}, {"term": "nature conservation", "ipa": "/ˈneɪtʃə ˌkɒnsəˈveɪʃən/", "pron": "NAY-chuh kon-suh-VAY-shuhn", "fr": "conservation de la nature", "def": "Protection of natural environments and species.", "ex": "Nature conservation is essential for future generations."}, {"term": "protected area", "ipa": "/prəˌtektɪd ˈeəriə/", "pron": "pruh-TEK-tid AIR-ee-uh", "fr": "aire protégée", "def": "A legally protected place for nature conservation.", "ex": "Protected areas can preserve habitats and species."}, {"term": "national park", "ipa": "/ˌnæʃənəl ˈpɑːk/", "pron": "NASH-uh-nuhl park", "fr": "parc national", "def": "A protected natural area managed for conservation and public enjoyment.", "ex": "National parks can protect iconic landscapes."}, {"term": "nature reserve", "ipa": "/ˈneɪtʃə rɪˌzɜːv/", "pron": "NAY-chuh ri-ZURV", "fr": "réserve naturelle", "def": "An area protected for wildlife or habitats.", "ex": "Nature reserves can protect rare species."}, {"term": "marine protected area", "ipa": "/məˈriːn prəˌtektɪd ˈeəriə/", "pron": "muh-REEN pruh-TEK-tid AIR-ee-uh", "fr": "aire marine protégée", "def": "A protected area in the ocean or sea.", "ex": "Marine protected areas can help fish populations recover."}, {"term": "wildlife corridor", "ipa": "/ˈwaɪldlaɪf ˌkɒrɪdɔː/", "pron": "WYLD-life KOR-i-dor", "fr": "corridor écologique", "def": "A strip of habitat connecting separated wildlife areas.", "ex": "Wildlife corridors reduce habitat fragmentation."}, {"term": "ecological corridor", "ipa": "/ˌiːkəˈlɒdʒɪkəl ˈkɒrɪdɔː/", "pron": "ee-kuh-LOJ-i-kuhl KOR-i-dor", "fr": "corridor écologique", "def": "A connection allowing species to move between habitats.", "ex": "Ecological corridors help animals migrate and reproduce."}, {"term": "rewilding", "ipa": "/ˌriːˈwaɪldɪŋ/", "pron": "ree-WYLD-ing", "fr": "réensauvagement", "def": "Restoring natural processes, often by reintroducing species or reducing human control.", "ex": "Rewilding can restore damaged ecosystems."}, {"term": "reintroduction", "ipa": "/ˌriːɪntrəˈdʌkʃən/", "pron": "ree-in-truh-DUK-shuhn", "fr": "réintroduction", "def": "The return of a species to an area where it once lived.", "ex": "The reintroduction of predators can rebalance ecosystems."}, {"term": "restoration", "ipa": "/ˌrestəˈreɪʃən/", "pron": "res-tuh-RAY-shuhn", "fr": "restauration écologique", "def": "The process of repairing damaged ecosystems.", "ex": "Wetland restoration can reduce flood risk."}, {"term": "ecological restoration", "ipa": "/ˌiːkəˈlɒdʒɪkəl ˌrestəˈreɪʃən/", "pron": "ee-kuh-LOJ-i-kuhl res-tuh-RAY-shuhn", "fr": "restauration écologique", "def": "Repairing ecosystems so they regain function and biodiversity.", "ex": "Ecological restoration can bring back native species."}, {"term": "afforestation", "ipa": "/əˌfɒrɪˈsteɪʃən/", "pron": "uh-for-i-STAY-shuhn", "fr": "boisement", "def": "Planting trees where there was no recent forest.", "ex": "Afforestation can store carbon but may harm grassland ecosystems."}, {"term": "reforestation", "ipa": "/ˌriːfɒrɪˈsteɪʃən/", "pron": "ree-for-i-STAY-shuhn", "fr": "reboisement", "def": "Replanting trees in a previously forested area.", "ex": "Reforestation can restore habitats if done carefully."}, {"term": "deforestation", "ipa": "/diːˌfɒrɪˈsteɪʃən/", "pron": "dee-for-i-STAY-shuhn", "fr": "déforestation", "def": "The clearing or destruction of forests.", "ex": "Deforestation is a major driver of biodiversity loss."}, {"term": "forest degradation", "ipa": "/ˈfɒrɪst ˌdeɡrəˈdeɪʃən/", "pron": "FOR-ist deg-ruh-DAY-shuhn", "fr": "dégradation des forêts", "def": "The decline in forest quality and ecological function.", "ex": "Forest degradation can occur even when trees remain."}, {"term": "rainforest", "ipa": "/ˈreɪnˌfɒrɪst/", "pron": "RAYN-for-ist", "fr": "forêt tropicale humide", "def": "A dense forest in a wet tropical or temperate region.", "ex": "Rainforests contain exceptional biodiversity."}, {"term": "tropical forest", "ipa": "/ˌtrɒpɪkəl ˈfɒrɪst/", "pron": "TROP-i-kuhl FOR-ist", "fr": "forêt tropicale", "def": "A forest found in tropical regions.", "ex": "Tropical forests store carbon and host many species."}, {"term": "wetland", "ipa": "/ˈwetlənd/", "pron": "WET-land", "fr": "zone humide", "def": "Land such as marshes or swamps that is saturated with water.", "ex": "Wetlands filter water and store carbon."}, {"term": "mangrove", "ipa": "/ˈmæŋɡrəʊv/", "pron": "MAN-grohv", "fr": "mangrove", "def": "A coastal forest growing in salty water in tropical regions.", "ex": "Mangroves protect coasts and provide fish nurseries."}, {"term": "coral reef", "ipa": "/ˈkɒrəl riːf/", "pron": "KOR-uhl reef", "fr": "récif corallien", "def": "A marine ecosystem built by corals, rich in biodiversity.", "ex": "Coral reefs are threatened by warming and ocean acidification."}, {"term": "grassland", "ipa": "/ˈɡrɑːslænd/", "pron": "GRASS-land", "fr": "prairie ; savane herbeuse", "def": "An ecosystem dominated by grasses.", "ex": "Grasslands support many grazing animals and birds."}, {"term": "soil biodiversity", "ipa": "/ˈsɔɪl ˌbaɪəʊdaɪˈvɜːsəti/", "pron": "soil BY-oh-dy-VUR-suh-tee", "fr": "biodiversité des sols", "def": "The variety of organisms living in soil.", "ex": "Soil biodiversity is essential for fertile land."}, {"term": "microbial diversity", "ipa": "/maɪˌkrəʊbiəl daɪˈvɜːsəti/", "pron": "my-KROH-bee-uhl dy-VUR-suh-tee", "fr": "diversité microbienne", "def": "The variety of microorganisms in an ecosystem.", "ex": "Microbial diversity is crucial for nutrient cycles."}, {"term": "insect decline", "ipa": "/ˈɪnsekt dɪˌklaɪn/", "pron": "IN-sekt di-KLYNE", "fr": "déclin des insectes", "def": "A reduction in insect populations and diversity.", "ex": "Insect decline threatens pollination and food webs."}]}, {"title": "C. Threats to biodiversity", "entries": [{"term": "pollinator decline", "ipa": "/ˈpɒlɪneɪtə dɪˌklaɪn/", "pron": "POL-i-nay-tuh di-KLYNE", "fr": "déclin des pollinisateurs", "def": "A reduction in pollinator populations.", "ex": "Pollinator decline threatens fruit and vegetable production."}, {"term": "overexploitation", "ipa": "/ˌəʊvərˌeksplɔɪˈteɪʃən/", "pron": "oh-vuh-ek-sploy-TAY-shuhn", "fr": "surexploitation", "def": "Unsustainable use of natural resources or species.", "ex": "Overexploitation can push species towards extinction."}, {"term": "overfishing", "ipa": "/ˌəʊvəˈfɪʃɪŋ/", "pron": "oh-vuh-FISH-ing", "fr": "surpêche", "def": "Catching fish faster than populations can recover.", "ex": "Overfishing damages marine ecosystems."}, {"term": "poaching", "ipa": "/ˈpəʊtʃɪŋ/", "pron": "POH-ching", "fr": "braconnage", "def": "Illegal hunting, capturing or killing of wildlife.", "ex": "Poaching threatens elephants and rhinos."}, {"term": "illegal wildlife trade", "ipa": "/ɪˈliːɡəl ˈwaɪldlaɪf treɪd/", "pron": "i-LEE-guhl WYLD-life trade", "fr": "trafic illégal d’espèces sauvages", "def": "The illegal buying and selling of wild animals or plants.", "ex": "Illegal wildlife trade fuels organised crime."}, {"term": "bushmeat", "ipa": "/ˈbʊʃmiːt/", "pron": "BUUSH-meet", "fr": "viande de brousse", "def": "Meat from wild animals, often hunted in forests.", "ex": "Unsustainable bushmeat hunting can reduce wildlife populations."}, {"term": "bycatch", "ipa": "/ˈbaɪkætʃ/", "pron": "BY-katch", "fr": "prises accessoires", "def": "Animals unintentionally caught during fishing.", "ex": "Dolphins and turtles can die as bycatch."}, {"term": "bottom trawling", "ipa": "/ˌbɒtəm ˈtrɔːlɪŋ/", "pron": "BOT-uhm TRAWL-ing", "fr": "chalutage de fond", "def": "Fishing by dragging heavy nets along the seabed.", "ex": "Bottom trawling destroys seafloor habitats."}, {"term": "pesticide", "ipa": "/ˈpestɪsaɪd/", "pron": "PES-ti-syde", "fr": "pesticide", "def": "A chemical used to kill pests.", "ex": "Pesticides can harm insects and birds."}, {"term": "herbicide", "ipa": "/ˈhɜːbɪsaɪd/", "pron": "HUR-bi-syde", "fr": "herbicide", "def": "A chemical used to kill unwanted plants.", "ex": "Herbicides can reduce plant diversity."}, {"term": "fertiliser runoff", "ipa": "/ˈfɜːtəlaɪzə ˈrʌnɒf/", "pron": "FUR-tuh-ly-zuh RUN-off", "fr": "ruissellement d’engrais", "def": "Fertiliser washed from land into rivers or seas.", "ex": "Fertiliser runoff can cause algal blooms."}, {"term": "eutrophication", "ipa": "/juːˌtrɒfɪˈkeɪʃən/", "pron": "yoo-trof-i-KAY-shuhn", "fr": "eutrophisation", "def": "Excess nutrients in water causing algal growth and oxygen loss.", "ex": "Eutrophication can create dead zones."}, {"term": "dead zone", "ipa": "/ˈded zəʊn/", "pron": "dead zone", "fr": "zone morte", "def": "A water area with too little oxygen to support most marine life.", "ex": "Dead zones often result from fertiliser runoff."}, {"term": "plastic pollution", "ipa": "/ˈplæstɪk pəˌluːʃən/", "pron": "PLAS-tik puh-LOO-shuhn", "fr": "pollution plastique", "def": "Pollution caused by plastic waste.", "ex": "Plastic pollution harms marine animals."}, {"term": "microplastic", "ipa": "/ˌmaɪkrəʊˈplæstɪk/", "pron": "MY-kroh-PLAS-tik", "fr": "microplastique", "def": "Tiny plastic particles that persist in the environment.", "ex": "Microplastics have been found in oceans, soil and animals."}, {"term": "chemical pollution", "ipa": "/ˈkemɪkəl pəˌluːʃən/", "pron": "KEM-i-kuhl puh-LOO-shuhn", "fr": "pollution chimique", "def": "Pollution caused by harmful chemicals.", "ex": "Chemical pollution can damage reproduction in wildlife."}, {"term": "light pollution", "ipa": "/ˈlaɪt pəˌluːʃən/", "pron": "light puh-LOO-shuhn", "fr": "pollution lumineuse", "def": "Excess artificial light disrupting ecosystems and night skies.", "ex": "Light pollution affects insects, birds and bats."}, {"term": "noise pollution", "ipa": "/ˈnɔɪz pəˌluːʃən/", "pron": "noyz puh-LOO-shuhn", "fr": "pollution sonore", "def": "Unwanted or harmful noise in the environment.", "ex": "Noise pollution can disturb marine mammals."}, {"term": "climate change", "ipa": "/ˈklaɪmət tʃeɪndʒ/", "pron": "KLY-muht chaynj", "fr": "changement climatique", "def": "Long-term changes in climate, largely driven today by greenhouse gas emissions.", "ex": "Climate change is a major driver of biodiversity loss."}, {"term": "global warming", "ipa": "/ˌɡləʊbəl ˈwɔːmɪŋ/", "pron": "GLOH-buhl WAR-ming", "fr": "réchauffement climatique", "def": "The rise in Earth’s average temperature.", "ex": "Global warming pushes species out of their usual ranges."}, {"term": "ocean acidification", "ipa": "/ˈəʊʃən əˌsɪdɪfɪˈkeɪʃən/", "pron": "OH-shuhn uh-sid-i-fi-KAY-shuhn", "fr": "acidification des océans", "def": "The decrease in ocean pH caused by absorbed CO2.", "ex": "Ocean acidification weakens coral reefs and shellfish."}, {"term": "range shift", "ipa": "/ˈreɪndʒ ʃɪft/", "pron": "raynj shift", "fr": "déplacement de l’aire de répartition", "def": "A change in the geographic area where a species lives.", "ex": "Climate change causes range shifts in many species."}, {"term": "migration pattern", "ipa": "/maɪˈɡreɪʃən ˌpætən/", "pron": "my-GRAY-shuhn PAT-uhn", "fr": "schéma migratoire", "def": "The regular movement pattern of animals between areas.", "ex": "Climate change can disrupt migration patterns."}, {"term": "phenology", "ipa": "/fɪˈnɒlədʒi/", "pron": "fi-NOL-uh-jee", "fr": "phénologie", "def": "The timing of seasonal biological events, such as flowering or migration.", "ex": "Climate change alters phenology."}, {"term": "phenological mismatch", "ipa": "/ˌfiːnəˈlɒdʒɪkəl ˈmɪsmætʃ/", "pron": "FEE-noh-LOJ-i-kuhl MIS-match", "fr": "désynchronisation phénologique", "def": "A timing mismatch between interacting species caused by environmental change.", "ex": "Phenological mismatch can reduce breeding success."}, {"term": "nature-based solution", "ipa": "/ˈneɪtʃə beɪst səˌluːʃən/", "pron": "NAY-chuh-bayst suh-LOO-shuhn", "fr": "solution fondée sur la nature", "def": "Using natural systems to address environmental or social problems.", "ex": "Mangrove restoration is a nature-based solution."}, {"term": "biodiversity hotspot", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti ˈhɒtspɒt/", "pron": "BY-oh-dy-VUR-suh-tee HOT-spot", "fr": "point chaud de biodiversité", "def": "A region with exceptional biodiversity under serious threat.", "ex": "Biodiversity hotspots are conservation priorities."}, {"term": "IUCN Red List", "ipa": "/ˌaɪ juː siː ˈen red lɪst/", "pron": "eye-yoo-see-en red list", "fr": "liste rouge de l’UICN", "def": "A global list assessing species’ extinction risk.", "ex": "The IUCN Red List tracks endangered species."}, {"term": "IUCN", "ipa": "/ˌaɪ juː siː ˈen/", "pron": "eye-yoo-see-en", "fr": "UICN", "def": "International Union for Conservation of Nature.", "ex": "The IUCN provides conservation assessments and guidance."}, {"term": "Convention on Biological Diversity", "ipa": "/kənˌvenʃən ɒn ˌbaɪəˈlɒdʒɪkəl daɪˈvɜːsəti/", "pron": "kuhn-VEN-shuhn on BY-uh-LOJ-i-kuhl dy-VUR-suh-tee", "fr": "Convention sur la diversité biologique", "def": "An international treaty for conserving biodiversity and using it sustainably.", "ex": "The Convention on Biological Diversity guides global biodiversity policy."}, {"term": "CBD", "ipa": "/ˌsiː biː ˈdiː/", "pron": "see-bee-dee", "fr": "CDB", "def": "Abbreviation for Convention on Biological Diversity.", "ex": "The CBD sets international biodiversity goals."}, {"term": "Kunming-Montreal Global Biodiversity Framework", "ipa": "/ˌkʊnmɪŋ ˌmɒntriˈɔːl ˈɡləʊbəl ˌbaɪəʊdaɪˈvɜːsəti ˈfreɪmwɜːk/", "pron": "KOON-ming mon-tree-AWL GLOH-buhl BY-oh-dy-VUR-suh-tee FRAYM-work", "fr": "cadre mondial de la biodiversité de Kunming-Montréal", "def": "A global agreement adopted to halt and reverse biodiversity loss.", "ex": "The Kunming-Montreal Framework includes the 30 by 30 target."}, {"term": "30 by 30", "ipa": "/ˌθɜːti baɪ ˈθɜːti/", "pron": "thirty-by-thirty", "fr": "objectif 30 x 30", "def": "A target to protect 30% of land and sea by 2030.", "ex": "30 by 30 is a major conservation goal."}, {"term": "natural capital", "ipa": "/ˌnætʃərəl ˈkæpɪtəl/", "pron": "NAT-chuh-ruhl KAP-i-tuhl", "fr": "capital naturel", "def": "The world’s stock of natural resources and ecosystems seen as economic assets.", "ex": "Natural capital accounting tries to value nature’s contribution."}]}, {"title": "D. Policy, monitoring and sustainable use", "entries": [{"term": "ecological footprint", "ipa": "/ˌiːkəˈlɒdʒɪkəl ˈfʊtprɪnt/", "pron": "ee-kuh-LOJ-i-kuhl FOOT-print", "fr": "empreinte écologique", "def": "The environmental impact of human consumption and activity.", "ex": "Wealthy countries often have a high ecological footprint."}, {"term": "land-use change", "ipa": "/ˈlænd juːs tʃeɪndʒ/", "pron": "land-yooss chaynj", "fr": "changement d’usage des terres", "def": "Conversion of land from one use to another, such as forest to agriculture.", "ex": "Land-use change is a leading driver of biodiversity loss."}, {"term": "urban sprawl", "ipa": "/ˌɜːbən ˈsprɔːl/", "pron": "UR-buhn sprawl", "fr": "étalement urbain", "def": "The uncontrolled expansion of urban areas.", "ex": "Urban sprawl fragments habitats."}, {"term": "intensive farming", "ipa": "/ɪnˌtensɪv ˈfɑːmɪŋ/", "pron": "in-TEN-siv FAR-ming", "fr": "agriculture intensive", "def": "Farming using high inputs to maximise production.", "ex": "Intensive farming can reduce biodiversity."}, {"term": "monoculture", "ipa": "/ˈmɒnəʊˌkʌltʃə/", "pron": "MON-oh-KUL-chuh", "fr": "monoculture", "def": "Growing a single crop over a large area.", "ex": "Monoculture reduces habitat variety."}, {"term": "agroecology", "ipa": "/ˌæɡrəʊiˈkɒlədʒi/", "pron": "AG-roh-ee-KOL-uh-jee", "fr": "agroécologie", "def": "Farming based on ecological principles and biodiversity.", "ex": "Agroecology can support biodiversity and farmers."}, {"term": "sustainable agriculture", "ipa": "/səˌsteɪnəbəl ˈæɡrɪkʌltʃə/", "pron": "suh-STAY-nuh-buhl AG-ri-kul-chuh", "fr": "agriculture durable", "def": "Farming that protects resources, ecosystems and future production.", "ex": "Sustainable agriculture reduces pressure on ecosystems."}, {"term": "regenerative agriculture", "ipa": "/rɪˌdʒenərətɪv ˈæɡrɪkʌltʃə/", "pron": "ri-JEN-uh-ruh-tiv AG-ri-kul-chuh", "fr": "agriculture régénératrice", "def": "Farming aimed at restoring soil health and ecosystems.", "ex": "Regenerative agriculture can improve soil biodiversity."}, {"term": "sustainable fishing", "ipa": "/səˌsteɪnəbəl ˈfɪʃɪŋ/", "pron": "suh-STAY-nuh-buhl FISH-ing", "fr": "pêche durable", "def": "Fishing that does not deplete fish populations or damage ecosystems.", "ex": "Sustainable fishing requires quotas and monitoring."}, {"term": "fishing quota", "ipa": "/ˈfɪʃɪŋ ˌkwəʊtə/", "pron": "FISH-ing KWOH-tuh", "fr": "quota de pêche", "def": "A limit on how much fish can be caught.", "ex": "Fishing quotas can prevent overexploitation."}, {"term": "conservation biology", "ipa": "/ˌkɒnsəˈveɪʃən baɪˈɒlədʒi/", "pron": "kon-suh-VAY-shuhn by-OL-uh-jee", "fr": "biologie de la conservation", "def": "The scientific study of protecting biodiversity.", "ex": "Conservation biology combines ecology, genetics and policy."}, {"term": "citizen science", "ipa": "/ˌsɪtɪzən ˈsaɪəns/", "pron": "SIT-i-zuhn SY-uhns", "fr": "science participative", "def": "Scientific research involving members of the public.", "ex": "Citizen science helps monitor birds, insects and plants."}, {"term": "biodiversity monitoring", "ipa": "/ˌbaɪəʊdaɪˈvɜːsəti ˈmɒnɪtərɪŋ/", "pron": "BY-oh-dy-VUR-suh-tee MON-i-tuh-ring", "fr": "suivi de la biodiversité", "def": "Tracking changes in species, habitats or ecosystems over time.", "ex": "Biodiversity monitoring is essential for conservation policy."}, {"term": "environmental DNA", "ipa": "/ɪnˌvaɪrənˈmentəl ˌdiː en ˈeɪ/", "pron": "in-vy-ruhn-MEN-tuhl dee-en-ay", "fr": "ADN environnemental", "def": "DNA collected from environmental samples such as water or soil.", "ex": "Environmental DNA can detect rare species."}, {"term": "eDNA", "ipa": "/ˌiː diː en ˈeɪ/", "pron": "ee-dee-en-ay", "fr": "ADNe", "def": "Abbreviation for environmental DNA.", "ex": "eDNA is useful for biodiversity monitoring."}, {"term": "satellite monitoring", "ipa": "/ˈsætəlaɪt ˈmɒnɪtərɪŋ/", "pron": "SAT-uh-lyte MON-i-tuh-ring", "fr": "suivi par satellite", "def": "Using satellites to observe environmental change.", "ex": "Satellite monitoring can detect deforestation."}, {"term": "remote sensing", "ipa": "/rɪˌməʊt ˈsensɪŋ/", "pron": "ri-MOHT SEN-sing", "fr": "télédétection", "def": "Collecting information from a distance, often by satellite or aircraft.", "ex": "Remote sensing supports conservation planning."}, {"term": "to protect biodiversity", "ipa": "/prəˈtekt ˌbaɪəʊdaɪˈvɜːsəti/", "pron": "pruh-TEKT BY-oh-dy-VUR-suh-tee", "fr": "protéger la biodiversité", "def": "To safeguard the variety of life on Earth.", "ex": "Governments must protect biodiversity through law and policy."}, {"term": "to preserve habitats", "ipa": "/prɪˈzɜːv ˈhæbɪtæts/", "pron": "pri-ZURV HAB-i-tats", "fr": "préserver les habitats", "def": "To keep natural habitats safe from damage.", "ex": "Protected areas help preserve habitats."}, {"term": "to restore ecosystems", "ipa": "/rɪˈstɔːr ˈiːkəʊˌsɪstəmz/", "pron": "ri-STOR EE-koh-SIS-tuhmz", "fr": "restaurer les écosystèmes", "def": "To repair damaged ecosystems.", "ex": "Wetland projects restore ecosystems and reduce flooding."}, {"term": "to halt biodiversity loss", "ipa": "/hɔːlt ˌbaɪəʊdaɪˈvɜːsəti lɒs/", "pron": "hawlt BY-oh-dy-VUR-suh-tee loss", "fr": "mettre fin à la perte de biodiversité", "def": "To stop the decline of biodiversity.", "ex": "Global agreements aim to halt biodiversity loss."}, {"term": "to reverse biodiversity loss", "ipa": "/rɪˈvɜːs ˌbaɪəʊdaɪˈvɜːsəti lɒs/", "pron": "ri-VURS BY-oh-dy-VUR-suh-tee loss", "fr": "inverser la perte de biodiversité", "def": "To make biodiversity recover after decline.", "ex": "The goal is not only to halt but to reverse biodiversity loss."}, {"term": "to drive species extinction", "ipa": "/draɪv ˈspiːʃiːz ɪkˌstɪŋkʃən/", "pron": "dryv SPEE-sheez ik-STINK-shuhn", "fr": "provoquer l’extinction d’espèces", "def": "To cause species to disappear.", "ex": "Habitat loss can drive species extinction."}, {"term": "to threaten wildlife", "ipa": "/ˈθretən ˈwaɪldlaɪf/", "pron": "THRET-uhn WYLD-life", "fr": "menacer la faune et la flore sauvages", "def": "To put wild animals or plants at risk.", "ex": "Pollution and poaching threaten wildlife."}, {"term": "to combat poaching", "ipa": "/ˈkɒmbæt ˈpəʊtʃɪŋ/", "pron": "KOM-bat POH-ching", "fr": "lutter contre le braconnage", "def": "To fight illegal hunting or capture of wildlife.", "ex": "Rangers and communities combat poaching."}, {"term": "to curb overfishing", "ipa": "/kɜːb ˌəʊvəˈfɪʃɪŋ/", "pron": "kurb oh-vuh-FISH-ing", "fr": "freiner la surpêche", "def": "To limit or reduce excessive fishing.", "ex": "Fishing quotas can curb overfishing."}, {"term": "to reduce pesticide use", "ipa": "/rɪˈdjuːs ˈpestɪsaɪd juːs/", "pron": "ri-DYOOSS PES-ti-syde yooss", "fr": "réduire l’usage des pesticides", "def": "To use fewer pesticides.", "ex": "Agroecology can reduce pesticide use."}, {"term": "to reconnect habitats", "ipa": "/ˌriːkəˈnekt ˈhæbɪtæts/", "pron": "ree-kuh-NEKT HAB-i-tats", "fr": "reconnecter les habitats", "def": "To link separated habitats again.", "ex": "Wildlife corridors reconnect habitats."}, {"term": "to value ecosystem services", "ipa": "/ˈvæljuː ˈiːkəʊˌsɪstəm ˈsɜːvɪsɪz/", "pron": "VAL-yoo EE-koh-SIS-tuhm SUR-vis-iz", "fr": "valoriser les services écosystémiques", "def": "To recognise the benefits ecosystems provide.", "ex": "Policymakers increasingly value ecosystem services."}, {"term": "to balance conservation and development", "ipa": "/ˈbæləns ˌkɒnsəˈveɪʃən ənd dɪˈveləpmənt/", "pron": "BAL-uhns kon-suh-VAY-shuhn and di-VEL-uhp-muhnt", "fr": "équilibrer conservation et développement", "def": "To protect nature while allowing economic and social progress.", "ex": "Countries must balance conservation and development."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p8c71", "part": 8, "chapter": 71, "title": "Pollution", "file": "cpge_vocab_part8_chapter71_pollution_premium.html", "count": 110, "sections": [{"title": "A. Core pollution and waste vocabulary", "entries": [{"term": "pollution", "ipa": "/pəˈluːʃən/", "pron": "puh-LOO-shuhn", "fr": "pollution", "def": "The introduction of harmful substances, energy or waste into the environment.", "ex": "Pollution harms ecosystems, public health and the economy."}, {"term": "pollutant", "ipa": "/pəˈluːtənt/", "pron": "puh-LOO-tuhnt", "fr": "polluant", "def": "A substance or form of energy that contaminates air, water or soil.", "ex": "Some pollutants persist in the environment for decades."}, {"term": "contamination", "ipa": "/kənˌtæmɪˈneɪʃən/", "pron": "kuhn-tam-i-NAY-shuhn", "fr": "contamination", "def": "The presence of harmful or unwanted substances in a place, material or organism.", "ex": "Water contamination can make communities sick."}, {"term": "toxic substance", "ipa": "/ˌtɒksɪk ˈsʌbstəns/", "pron": "TOK-sik SUB-stuhns", "fr": "substance toxique", "def": "A substance that can poison or harm living organisms.", "ex": "Toxic substances can accumulate in food chains."}, {"term": "hazardous waste", "ipa": "/ˌhæzədəs ˈweɪst/", "pron": "HAZ-uh-duhs wayst", "fr": "déchet dangereux", "def": "Waste that is dangerous to health or the environment.", "ex": "Hazardous waste requires strict handling."}, {"term": "industrial waste", "ipa": "/ɪnˌdʌstriəl ˈweɪst/", "pron": "in-DUS-tree-uhl wayst", "fr": "déchet industriel", "def": "Waste produced by factories and industrial activity.", "ex": "Industrial waste can pollute rivers and soil."}, {"term": "household waste", "ipa": "/ˈhaʊshəʊld weɪst/", "pron": "HOWS-hohld wayst", "fr": "déchet ménager", "def": "Waste produced by homes and consumers.", "ex": "Household waste increases with consumer culture."}, {"term": "municipal waste", "ipa": "/mjuːˌnɪsɪpəl ˈweɪst/", "pron": "myoo-NIS-i-puhl wayst", "fr": "déchet municipal", "def": "Waste collected by local authorities from homes, shops and offices.", "ex": "Municipal waste management is a major urban challenge."}, {"term": "solid waste", "ipa": "/ˌsɒlɪd ˈweɪst/", "pron": "SOL-id wayst", "fr": "déchet solide", "def": "Non-liquid waste materials.", "ex": "Solid waste must be collected, treated or recycled."}, {"term": "chemical waste", "ipa": "/ˈkemɪkəl weɪst/", "pron": "KEM-i-kuhl wayst", "fr": "déchet chimique", "def": "Waste containing harmful chemicals.", "ex": "Chemical waste can poison soil and water."}, {"term": "radioactive waste", "ipa": "/ˌreɪdiəʊˈæktɪv weɪst/", "pron": "ray-dee-oh-AK-tiv wayst", "fr": "déchet radioactif", "def": "Waste containing radioactive material.", "ex": "Radioactive waste must be stored safely for long periods."}, {"term": "e-waste", "ipa": "/ˈiː weɪst/", "pron": "ee-wayst", "fr": "déchets électroniques", "def": "Discarded electronic devices and components.", "ex": "E-waste contains valuable metals but also toxic substances."}, {"term": "waste management", "ipa": "/ˈweɪst ˌmænɪdʒmənt/", "pron": "wayst MAN-ij-muhnt", "fr": "gestion des déchets", "def": "The collection, treatment, recycling and disposal of waste.", "ex": "Waste management requires infrastructure and regulation."}, {"term": "waste disposal", "ipa": "/ˈweɪst dɪˌspəʊzəl/", "pron": "wayst di-SPOH-zuhl", "fr": "élimination des déchets", "def": "The process of getting rid of waste.", "ex": "Unsafe waste disposal can contaminate land."}, {"term": "landfill", "ipa": "/ˈlændfɪl/", "pron": "LAND-fil", "fr": "décharge", "def": "A site where waste is buried.", "ex": "Landfills can produce methane and leachate."}, {"term": "incineration", "ipa": "/ɪnˌsɪnəˈreɪʃən/", "pron": "in-sin-uh-RAY-shuhn", "fr": "incinération", "def": "Burning waste at high temperatures.", "ex": "Incineration reduces waste volume but can create emissions."}, {"term": "recycling", "ipa": "/ˌriːˈsaɪklɪŋ/", "pron": "ree-SY-kling", "fr": "recyclage", "def": "Processing used materials so they can be used again.", "ex": "Recycling reduces waste but cannot solve overconsumption alone."}, {"term": "upcycling", "ipa": "/ˈʌpˌsaɪklɪŋ/", "pron": "UP-sy-kling", "fr": "surcyclage", "def": "Reusing waste materials to create higher-value products.", "ex": "Upcycling turns waste into useful objects."}, {"term": "circular economy", "ipa": "/ˌsɜːkjʊlər iˈkɒnəmi/", "pron": "SUR-kyuh-luh i-KON-uh-mee", "fr": "économie circulaire", "def": "An economic model based on reducing waste through reuse, repair and recycling.", "ex": "A circular economy aims to keep materials in use."}, {"term": "throwaway culture", "ipa": "/ˈθrəʊəweɪ ˌkʌltʃə/", "pron": "THROH-uh-way KUL-chuh", "fr": "culture du jetable", "def": "A culture of buying, using briefly and discarding products.", "ex": "Throwaway culture fuels pollution."}, {"term": "single-use plastic", "ipa": "/ˌsɪŋɡəl juːs ˈplæstɪk/", "pron": "SIN-guhl yooss PLAS-tik", "fr": "plastique à usage unique", "def": "Plastic designed to be used once and thrown away.", "ex": "Single-use plastic is a major source of marine pollution."}, {"term": "plastic pollution", "ipa": "/ˈplæstɪk pəˌluːʃən/", "pron": "PLAS-tik puh-LOO-shuhn", "fr": "pollution plastique", "def": "Pollution caused by plastic waste.", "ex": "Plastic pollution harms oceans, rivers and wildlife."}, {"term": "microplastic", "ipa": "/ˌmaɪkrəʊˈplæstɪk/", "pron": "MY-kroh-PLAS-tik", "fr": "microplastique", "def": "Tiny plastic particles that persist in the environment.", "ex": "Microplastics have been found in water, soil and human bodies."}, {"term": "nanoplastic", "ipa": "/ˌnænəʊˈplæstɪk/", "pron": "NAN-oh-PLAS-tik", "fr": "nanoplastique", "def": "Extremely small plastic particles at the nanometre scale.", "ex": "Nanoplastics may enter tissues and cells."}, {"term": "marine litter", "ipa": "/məˈriːn ˈlɪtə/", "pron": "muh-REEN LIT-uh", "fr": "déchets marins", "def": "Waste found in seas and oceans.", "ex": "Marine litter threatens fish, birds and turtles."}, {"term": "ocean garbage patch", "ipa": "/ˈəʊʃən ˈɡɑːbɪdʒ pætʃ/", "pron": "OH-shuhn GAR-bij patch", "fr": "zone d’accumulation de déchets océaniques", "def": "A large area where floating waste accumulates in the ocean.", "ex": "The ocean garbage patch is a symbol of plastic pollution."}, {"term": "air pollution", "ipa": "/ˈeə pəˌluːʃən/", "pron": "air puh-LOO-shuhn", "fr": "pollution de l’air", "def": "The presence of harmful substances in the air.", "ex": "Air pollution causes millions of premature deaths."}]}, {"title": "B. Air, water and soil pollution", "entries": [{"term": "particulate matter", "ipa": "/pɑːˌtɪkjʊlət ˈmætə/", "pron": "par-TIK-yuh-luht MAT-uh", "fr": "particules fines", "def": "Tiny particles in the air that can damage health.", "ex": "Particulate matter can enter the lungs and bloodstream."}, {"term": "PM2.5", "ipa": "/ˌpiː em tuː pɔɪnt ˈfaɪv/", "pron": "pee-em two-point-five", "fr": "PM2,5", "def": "Fine particles smaller than 2.5 micrometres.", "ex": "PM2.5 is especially dangerous because it penetrates deep into the lungs."}, {"term": "PM10", "ipa": "/ˌpiː em ˈten/", "pron": "pee-em-ten", "fr": "PM10", "def": "Particles smaller than 10 micrometres.", "ex": "PM10 pollution can irritate the respiratory system."}, {"term": "nitrogen dioxide", "ipa": "/ˌnaɪtrədʒən daɪˈɒksaɪd/", "pron": "NY-truh-juhn dy-OK-syde", "fr": "dioxyde d’azote", "def": "An air pollutant produced by combustion, especially traffic.", "ex": "Nitrogen dioxide is high near busy roads."}, {"term": "NO2", "ipa": "/ˌen əʊ ˈtuː/", "pron": "en-oh-too", "fr": "NO2", "def": "Chemical formula for nitrogen dioxide.", "ex": "NO2 levels are monitored in cities."}, {"term": "sulphur dioxide", "ipa": "/ˌsʌlfə daɪˈɒksaɪd/", "pron": "SUL-fuh dy-OK-syde", "fr": "dioxyde de soufre", "def": "A pollutant produced by burning sulphur-containing fuels.", "ex": "Sulphur dioxide contributes to acid rain."}, {"term": "SO2", "ipa": "/ˌes əʊ ˈtuː/", "pron": "ess-oh-too", "fr": "SO2", "def": "Chemical formula for sulphur dioxide.", "ex": "SO2 emissions fell after cleaner-fuel policies."}, {"term": "carbon monoxide", "ipa": "/ˌkɑːbən məˈnɒksaɪd/", "pron": "KAR-buhn muh-NOK-syde", "fr": "monoxyde de carbone", "def": "A poisonous gas produced by incomplete combustion.", "ex": "Carbon monoxide can be deadly indoors."}, {"term": "ground-level ozone", "ipa": "/ˌɡraʊnd levəl ˈəʊzəʊn/", "pron": "ground-LEV-uhl OH-zohn", "fr": "ozone troposphérique", "def": "Ozone pollution near the ground, harmful to health and crops.", "ex": "Ground-level ozone forms in sunlight from other pollutants."}, {"term": "smog", "ipa": "/smɒɡ/", "pron": "smog", "fr": "smog", "def": "Polluted air that forms a visible haze.", "ex": "Smog can make breathing difficult."}, {"term": "acid rain", "ipa": "/ˌæsɪd ˈreɪn/", "pron": "ASS-id rayn", "fr": "pluie acide", "def": "Rain made acidic by air pollutants.", "ex": "Acid rain damages forests, lakes and buildings."}, {"term": "vehicle emissions", "ipa": "/ˈviːɪkəl ɪˌmɪʃənz/", "pron": "VEE-i-kuhl i-MISH-uhnz", "fr": "émissions des véhicules", "def": "Pollutants released by cars, trucks and buses.", "ex": "Vehicle emissions are a major urban problem."}, {"term": "exhaust fumes", "ipa": "/ɪɡˈzɔːst fjuːmz/", "pron": "ig-ZAWST fyoomz", "fr": "gaz d’échappement", "def": "Smoke or gases released by engines.", "ex": "Exhaust fumes harm pedestrians and cyclists."}, {"term": "water pollution", "ipa": "/ˈwɔːtə pəˌluːʃən/", "pron": "WOR-tuh puh-LOO-shuhn", "fr": "pollution de l’eau", "def": "Pollution of rivers, lakes, groundwater or oceans.", "ex": "Water pollution threatens drinking water and wildlife."}, {"term": "freshwater pollution", "ipa": "/ˈfreʃwɔːtə pəˌluːʃən/", "pron": "FRESH-wor-tuh puh-LOO-shuhn", "fr": "pollution des eaux douces", "def": "Pollution of rivers, lakes and groundwater.", "ex": "Freshwater pollution affects people and ecosystems."}, {"term": "groundwater contamination", "ipa": "/ˈɡraʊndwɔːtə kənˌtæmɪˈneɪʃən/", "pron": "GROUND-wor-tuh kuhn-tam-i-NAY-shuhn", "fr": "contamination des eaux souterraines", "def": "Pollution of underground water sources.", "ex": "Groundwater contamination can last for decades."}, {"term": "sewage", "ipa": "/ˈsuːɪdʒ/", "pron": "SOO-ij", "fr": "eaux usées", "def": "Wastewater and human waste carried through sewers.", "ex": "Untreated sewage can pollute rivers and beaches."}, {"term": "wastewater", "ipa": "/ˈweɪstˌwɔːtə/", "pron": "WAYST-wor-tuh", "fr": "eaux usées", "def": "Used water from homes, industry or agriculture.", "ex": "Wastewater treatment protects public health."}, {"term": "wastewater treatment", "ipa": "/ˈweɪstˌwɔːtə ˈtriːtmənt/", "pron": "WAYST-wor-tuh TREET-muhnt", "fr": "traitement des eaux usées", "def": "Processes used to clean wastewater before release or reuse.", "ex": "Wastewater treatment reduces disease and pollution."}, {"term": "oil spill", "ipa": "/ˈɔɪl spɪl/", "pron": "oil spill", "fr": "marée noire ; déversement de pétrole", "def": "A release of oil into the environment, especially water.", "ex": "Oil spills devastate marine ecosystems."}, {"term": "chemical spill", "ipa": "/ˈkemɪkəl spɪl/", "pron": "KEM-i-kuhl spill", "fr": "déversement chimique", "def": "An accidental release of chemicals.", "ex": "A chemical spill can poison water and soil."}, {"term": "fertiliser runoff", "ipa": "/ˈfɜːtəlaɪzə ˈrʌnɒf/", "pron": "FUR-tuh-ly-zuh RUN-off", "fr": "ruissellement d’engrais", "def": "Fertiliser washed from fields into water bodies.", "ex": "Fertiliser runoff causes algal blooms."}, {"term": "agricultural runoff", "ipa": "/ˌæɡrɪˈkʌltʃərəl ˈrʌnɒf/", "pron": "ag-ri-KUL-chuh-ruhl RUN-off", "fr": "ruissellement agricole", "def": "Water carrying pesticides, fertilisers or waste from farms.", "ex": "Agricultural runoff pollutes rivers."}, {"term": "pesticide contamination", "ipa": "/ˈpestɪsaɪd kənˌtæmɪˈneɪʃən/", "pron": "PES-ti-syde kuhn-tam-i-NAY-shuhn", "fr": "contamination par les pesticides", "def": "Pollution by chemicals used to kill pests.", "ex": "Pesticide contamination affects insects, birds and humans."}, {"term": "eutrophication", "ipa": "/juːˌtrɒfɪˈkeɪʃən/", "pron": "yoo-trof-i-KAY-shuhn", "fr": "eutrophisation", "def": "Excess nutrients in water causing algal growth and oxygen loss.", "ex": "Eutrophication can create dead zones."}, {"term": "algal bloom", "ipa": "/ˈælɡəl bluːm/", "pron": "AL-guhl bloom", "fr": "prolifération d’algues", "def": "Rapid growth of algae, often due to nutrient pollution.", "ex": "Algal blooms can produce toxins."}, {"term": "dead zone", "ipa": "/ˈded zəʊn/", "pron": "dead zone", "fr": "zone morte", "def": "A water area with too little oxygen to support most life.", "ex": "Dead zones are expanding in some coastal waters."}, {"term": "soil pollution", "ipa": "/ˈsɔɪl pəˌluːʃən/", "pron": "soil puh-LOO-shuhn", "fr": "pollution des sols", "def": "Contamination of soil by harmful substances.", "ex": "Soil pollution can enter the food chain."}, {"term": "soil contamination", "ipa": "/ˈsɔɪl kənˌtæmɪˈneɪʃən/", "pron": "soil kuhn-tam-i-NAY-shuhn", "fr": "contamination des sols", "def": "The presence of toxic substances in soil.", "ex": "Soil contamination can make land unsafe for farming."}, {"term": "heavy metal", "ipa": "/ˌhevi ˈmetəl/", "pron": "HEV-ee MET-uhl", "fr": "métal lourd", "def": "A toxic metal such as lead, mercury or cadmium.", "ex": "Heavy metals can accumulate in organisms."}, {"term": "lead", "ipa": "/led/", "pron": "led", "fr": "plomb", "def": "A toxic metal that can damage the brain and nervous system.", "ex": "Lead pollution is especially dangerous for children."}, {"term": "mercury", "ipa": "/ˈmɜːkjəri/", "pron": "MUR-kyuh-ree", "fr": "mercure", "def": "A toxic metal that can accumulate in fish and humans.", "ex": "Mercury pollution affects marine food chains."}, {"term": "persistent organic pollutant", "ipa": "/pəˌsɪstənt ɔːˌɡænɪk pəˈluːtənt/", "pron": "puh-SIS-tuhnt or-GAN-ik puh-LOO-tuhnt", "fr": "polluant organique persistant", "def": "A toxic chemical that persists, travels and accumulates in living organisms.", "ex": "Persistent organic pollutants can move across borders."}, {"term": "POP", "ipa": "/ˌpiː əʊ ˈpiː/", "pron": "pee-oh-pee", "fr": "POP", "def": "Abbreviation for persistent organic pollutant.", "ex": "POPs are regulated internationally."}, {"term": "PFAS", "ipa": "/ˌpiː ef eɪ ˈes/", "pron": "pee-eff-ay-ess", "fr": "PFAS ; polluants éternels", "def": "A group of persistent chemicals often called forever chemicals.", "ex": "PFAS are difficult to remove from water."}, {"term": "forever chemicals", "ipa": "/fəˈrevə ˈkemɪkəlz/", "pron": "fuh-REV-uh KEM-i-kuhlz", "fr": "polluants éternels", "def": "Informal term for persistent chemicals such as PFAS.", "ex": "Forever chemicals raise serious health concerns."}, {"term": "bioaccumulation", "ipa": "/ˌbaɪəʊəkjuːmjʊˈleɪʃən/", "pron": "BY-oh-uh-kyoo-myoo-LAY-shuhn", "fr": "bioaccumulation", "def": "The build-up of a substance in an organism over time.", "ex": "Mercury can bioaccumulate in fish."}, {"term": "biomagnification", "ipa": "/ˌbaɪəʊmæɡnɪfɪˈkeɪʃən/", "pron": "BY-oh-mag-ni-fi-KAY-shuhn", "fr": "bioamplification", "def": "Increasing concentration of a pollutant higher up the food chain.", "ex": "Biomagnification makes top predators vulnerable."}, {"term": "noise pollution", "ipa": "/ˈnɔɪz pəˌluːʃən/", "pron": "noyz puh-LOO-shuhn", "fr": "pollution sonore", "def": "Harmful or unwanted noise in the environment.", "ex": "Noise pollution affects sleep and mental health."}, {"term": "light pollution", "ipa": "/ˈlaɪt pəˌluːʃən/", "pron": "light puh-LOO-shuhn", "fr": "pollution lumineuse", "def": "Excess artificial light that disrupts ecosystems and night skies.", "ex": "Light pollution affects insects, birds and bats."}, {"term": "thermal pollution", "ipa": "/ˈθɜːməl pəˌluːʃən/", "pron": "THUR-muhl puh-LOO-shuhn", "fr": "pollution thermique", "def": "Damage caused by releasing heat into the environment, especially water.", "ex": "Thermal pollution can reduce oxygen levels in rivers."}, {"term": "visual pollution", "ipa": "/ˈvɪʒuəl pəˌluːʃən/", "pron": "VIZH-oo-uhl puh-LOO-shuhn", "fr": "pollution visuelle", "def": "Visual degradation of landscapes by intrusive structures or waste.", "ex": "Billboards and litter contribute to visual pollution."}]}, {"title": "C. Other forms of pollution and health impacts", "entries": [{"term": "urban pollution", "ipa": "/ˈɜːbən pəˌluːʃən/", "pron": "UR-buhn puh-LOO-shuhn", "fr": "pollution urbaine", "def": "Pollution found in cities, often from traffic, heating and industry.", "ex": "Urban pollution disproportionately affects poorer neighbourhoods."}, {"term": "indoor air pollution", "ipa": "/ˈɪndɔː eə pəˌluːʃən/", "pron": "IN-door air puh-LOO-shuhn", "fr": "pollution de l’air intérieur", "def": "Pollution inside buildings.", "ex": "Indoor air pollution can come from cooking, heating or chemicals."}, {"term": "environmental health", "ipa": "/ɪnˌvaɪrənˈmentəl helθ/", "pron": "in-vy-ruhn-MEN-tuhl health", "fr": "santé environnementale", "def": "The link between environmental conditions and human health.", "ex": "Pollution is a major environmental health issue."}, {"term": "public health", "ipa": "/ˌpʌblɪk ˈhelθ/", "pron": "PUB-lik health", "fr": "santé publique", "def": "The health of populations and communities.", "ex": "Pollution control is a public health priority."}, {"term": "respiratory disease", "ipa": "/rɪˈspɪrətəri dɪˌziːz/", "pron": "ri-SPIR-uh-tuh-ree di-ZEEZ", "fr": "maladie respiratoire", "def": "Disease affecting breathing and the lungs.", "ex": "Air pollution increases respiratory disease."}, {"term": "asthma", "ipa": "/ˈæsmə/", "pron": "ASS-muh", "fr": "asthme", "def": "A condition causing breathing difficulty due to airway inflammation.", "ex": "Traffic pollution can worsen asthma."}, {"term": "cardiovascular disease", "ipa": "/ˌkɑːdiəʊˈvæskjʊlə dɪˌziːz/", "pron": "kar-dee-oh-VAS-kyuh-luh di-ZEEZ", "fr": "maladie cardiovasculaire", "def": "Disease affecting the heart and blood vessels.", "ex": "Fine particles increase cardiovascular disease risk."}, {"term": "premature death", "ipa": "/ˌpremətʃə ˈdeθ/", "pron": "PREM-uh-chuh death", "fr": "décès prématuré", "def": "Death occurring earlier than expected because of disease or risk factors.", "ex": "Air pollution causes premature deaths."}, {"term": "environmental injustice", "ipa": "/ɪnˌvaɪrənˈmentəl ɪnˈdʒʌstɪs/", "pron": "in-vy-ruhn-MEN-tuhl in-JUS-tis", "fr": "injustice environnementale", "def": "Unfair exposure to environmental harms.", "ex": "Environmental injustice often affects low-income communities."}, {"term": "environmental racism", "ipa": "/ɪnˌvaɪrənˈmentəl ˈreɪsɪzəm/", "pron": "in-vy-ruhn-MEN-tuhl RAY-siz-uhm", "fr": "racisme environnemental", "def": "Unequal environmental harm affecting racial or ethnic groups.", "ex": "Environmental racism links pollution to structural inequality."}, {"term": "sacrifice zone", "ipa": "/ˈsækrɪfaɪs zəʊn/", "pron": "SAK-ri-fyce zone", "fr": "zone sacrifiée", "def": "An area heavily polluted or damaged for economic activity.", "ex": "Industrial sacrifice zones are often home to marginalised communities."}, {"term": "pollution control", "ipa": "/pəˈluːʃən kənˌtrəʊl/", "pron": "puh-LOO-shuhn kuhn-TROHL", "fr": "lutte contre la pollution", "def": "Measures used to reduce or prevent pollution.", "ex": "Pollution control includes filters, regulation and monitoring."}, {"term": "emissions standard", "ipa": "/ɪˈmɪʃənz ˈstændəd/", "pron": "i-MISH-uhnz STAN-duhd", "fr": "norme d’émission", "def": "A legal limit on pollutant emissions.", "ex": "Emissions standards forced cleaner vehicles."}, {"term": "air quality standard", "ipa": "/ˈeə ˌkwɒləti ˈstændəd/", "pron": "air KWOL-uh-tee STAN-duhd", "fr": "norme de qualité de l’air", "def": "A legal or scientific benchmark for air pollution levels.", "ex": "Air quality standards protect public health."}, {"term": "water quality standard", "ipa": "/ˈwɔːtə ˌkwɒləti ˈstændəd/", "pron": "WOR-tuh KWOL-uh-tee STAN-duhd", "fr": "norme de qualité de l’eau", "def": "A benchmark for safe or acceptable water pollution levels.", "ex": "Water quality standards guide monitoring and regulation."}, {"term": "polluter pays principle", "ipa": "/pəˈluːtə peɪz ˈprɪnsəpəl/", "pron": "puh-LOO-tuh payz PRIN-suh-puhl", "fr": "principe pollueur-payeur", "def": "The principle that polluters should pay for the damage they cause.", "ex": "The polluter pays principle supports environmental accountability."}, {"term": "extended producer responsibility", "ipa": "/ɪkˌstendɪd prəˈdjuːsə rɪˌspɒnsəˈbɪləti/", "pron": "ik-STEN-did pruh-DYOO-suh ri-spon-suh-BIL-uh-tee", "fr": "responsabilité élargie du producteur", "def": "A policy making producers responsible for products after use.", "ex": "Extended producer responsibility can reduce packaging waste."}, {"term": "EPR", "ipa": "/ˌiː piː ˈɑː/", "pron": "ee-pee-ar", "fr": "REP", "def": "Abbreviation for extended producer responsibility.", "ex": "EPR schemes can finance recycling."}, {"term": "deposit return scheme", "ipa": "/dɪˈpɒzɪt rɪˈtɜːn skiːm/", "pron": "di-POZ-it ri-TURN skeem", "fr": "système de consigne", "def": "A system where consumers pay a deposit and get it back when returning containers.", "ex": "Deposit return schemes increase bottle recycling."}, {"term": "ban", "ipa": "/bæn/", "pron": "ban", "fr": "interdiction", "def": "An official prohibition of something.", "ex": "A ban on single-use plastic bags can reduce waste."}, {"term": "regulation", "ipa": "/ˌreɡjʊˈleɪʃən/", "pron": "reg-yuh-LAY-shuhn", "fr": "réglementation", "def": "Rules made by authorities to control behaviour or industry.", "ex": "Pollution regulation can protect health."}, {"term": "monitoring", "ipa": "/ˈmɒnɪtərɪŋ/", "pron": "MON-i-tuh-ring", "fr": "surveillance ; suivi", "def": "Regular observation or measurement of conditions.", "ex": "Air pollution monitoring informs public warnings."}]}, {"title": "D. Regulation, monitoring and clean-up", "entries": [{"term": "environmental monitoring", "ipa": "/ɪnˌvaɪrənˈmentəl ˈmɒnɪtərɪŋ/", "pron": "in-vy-ruhn-MEN-tuhl MON-i-tuh-ring", "fr": "surveillance environnementale", "def": "Tracking environmental quality or change.", "ex": "Environmental monitoring can detect illegal dumping."}, {"term": "sensor", "ipa": "/ˈsensə/", "pron": "SEN-suh", "fr": "capteur", "def": "A device that measures physical or chemical conditions.", "ex": "Low-cost sensors can monitor air quality."}, {"term": "remediation", "ipa": "/rɪˌmiːdiˈeɪʃən/", "pron": "ri-mee-dee-AY-shuhn", "fr": "dépollution ; assainissement", "def": "Cleaning or repairing polluted environments.", "ex": "Soil remediation can make land safe again."}, {"term": "decontamination", "ipa": "/ˌdiːkənˌtæmɪˈneɪʃən/", "pron": "dee-kuhn-tam-i-NAY-shuhn", "fr": "décontamination", "def": "Removing or neutralising contamination.", "ex": "Decontamination is necessary after chemical accidents."}, {"term": "clean-up operation", "ipa": "/ˈkliːn ʌp ˌɒpəˈreɪʃən/", "pron": "clean-up op-uh-RAY-shuhn", "fr": "opération de nettoyage", "def": "An organised effort to remove pollution or waste.", "ex": "Oil spills require major clean-up operations."}, {"term": "to pollute", "ipa": "/pəˈluːt/", "pron": "puh-LOOT", "fr": "polluer", "def": "To contaminate the environment with harmful substances.", "ex": "Factories may pollute rivers if regulation is weak."}, {"term": "to contaminate water", "ipa": "/kənˈtæmɪneɪt ˈwɔːtə/", "pron": "kuhn-TAM-i-nayt WOR-tuh", "fr": "contaminer l’eau", "def": "To make water unsafe or polluted.", "ex": "Chemicals can contaminate water supplies."}, {"term": "to release pollutants", "ipa": "/rɪˈliːs pəˈluːtənts/", "pron": "ri-LEESS puh-LOO-tuhnts", "fr": "rejeter des polluants", "def": "To emit or discharge harmful substances.", "ex": "Vehicles release pollutants into the air."}, {"term": "to discharge waste", "ipa": "/dɪsˈtʃɑːdʒ weɪst/", "pron": "dis-CHARJ wayst", "fr": "rejeter des déchets", "def": "To release waste into the environment.", "ex": "Factories must not discharge waste into rivers."}, {"term": "to dump waste", "ipa": "/dʌmp weɪst/", "pron": "dump wayst", "fr": "déverser / jeter des déchets", "def": "To leave waste illegally or carelessly.", "ex": "Illegal operators dump waste to avoid costs."}, {"term": "to leak chemicals", "ipa": "/liːk ˈkemɪkəlz/", "pron": "leek KEM-i-kuhlz", "fr": "laisser fuir des produits chimiques", "def": "To release chemicals accidentally.", "ex": "Old storage tanks can leak chemicals."}, {"term": "to monitor air quality", "ipa": "/ˈmɒnɪtə eə ˌkwɒləti/", "pron": "MON-i-tuh air KWOL-uh-tee", "fr": "surveiller la qualité de l’air", "def": "To measure pollution levels in the air.", "ex": "Cities monitor air quality near roads."}, {"term": "to enforce environmental standards", "ipa": "/ɪnˈfɔːs ɪnˌvaɪrənˈmentəl ˈstændədz/", "pron": "in-FORSS in-vy-ruhn-MEN-tuhl STAN-duhdz", "fr": "faire appliquer les normes environnementales", "def": "To make sure environmental rules are respected.", "ex": "Governments must enforce environmental standards."}, {"term": "to reduce plastic waste", "ipa": "/rɪˈdjuːs ˈplæstɪk weɪst/", "pron": "ri-DYOOSS PLAS-tik wayst", "fr": "réduire les déchets plastiques", "def": "To cut the amount of plastic discarded.", "ex": "Reusable packaging can reduce plastic waste."}, {"term": "to phase out single-use plastics", "ipa": "/feɪz aʊt ˌsɪŋɡəl juːs ˈplæstɪks/", "pron": "fayz out SIN-guhl-yooss PLAS-tiks", "fr": "supprimer progressivement les plastiques à usage unique", "def": "To gradually stop using disposable plastics.", "ex": "Many countries want to phase out single-use plastics."}, {"term": "to clean up polluted sites", "ipa": "/kliːn ʌp pəˈluːtɪd saɪts/", "pron": "clean up puh-LOO-tid sytes", "fr": "dépolluer des sites contaminés", "def": "To remove pollution from contaminated places.", "ex": "Public funds are often needed to clean up polluted sites."}, {"term": "to hold polluters accountable", "ipa": "/həʊld pəˈluːtəz əˈkaʊntəbəl/", "pron": "hohld puh-LOO-tuhz uh-KOWN-tuh-buhl", "fr": "tenir les pollueurs responsables", "def": "To make polluters responsible for the harm they cause.", "ex": "Communities demand that authorities hold polluters accountable."}, {"term": "to protect public health", "ipa": "/prəˈtekt ˌpʌblɪk ˈhelθ/", "pron": "pruh-TEKT PUB-lik health", "fr": "protéger la santé publique", "def": "To safeguard the health of the population.", "ex": "Reducing pollution protects public health."}, {"term": "to balance industry and environmental protection", "ipa": "/ˈbæləns ˈɪndəstri ənd ɪnˌvaɪrənˈmentəl prəˈtekʃən/", "pron": "BAL-uhns IN-duh-stree and in-vy-ruhn-MEN-tuhl pruh-TEK-shuhn", "fr": "équilibrer industrie et protection de l’environnement", "def": "To reconcile economic activity with environmental safeguards.", "ex": "Governments must balance industry and environmental protection."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p8c72", "part": 8, "chapter": 72, "title": "Environmental Activism", "file": "cpge_vocab_part8_chapter72_environmental_activism_premium.html", "count": 115, "sections": [{"title": "A. Core environmental activism vocabulary", "entries": [{"term": "environmental activism", "ipa": "/ɪnˌvaɪrənˈmentəl ˈæktɪvɪzəm/", "pron": "in-vy-ruhn-MEN-tuhl AK-ti-viz-uhm", "fr": "activisme environnemental", "def": "Campaigning to protect the environment or demand stronger ecological policies.", "ex": "Environmental activism has become more visible as climate impacts intensify."}, {"term": "environmentalist", "ipa": "/ɪnˌvaɪrənˈmentəlɪst/", "pron": "in-vy-ruhn-MEN-tuhl-ist", "fr": "écologiste ; défenseur de l’environnement", "def": "A person who works to protect the environment.", "ex": "Environmentalists often campaign against pollution and deforestation."}, {"term": "environmental movement", "ipa": "/ɪnˌvaɪrənˈmentəl ˈmuːvmənt/", "pron": "in-vy-ruhn-MEN-tuhl MOOV-muhnt", "fr": "mouvement écologiste", "def": "The broad social and political movement defending environmental protection.", "ex": "The environmental movement includes NGOs, scientists, citizens and activists."}, {"term": "climate activism", "ipa": "/ˈklaɪmət ˌæktɪvɪzəm/", "pron": "KLY-muht AK-ti-viz-uhm", "fr": "activisme climatique", "def": "Campaigning for stronger action on climate change.", "ex": "Climate activism has pushed climate change into mainstream politics."}, {"term": "climate activist", "ipa": "/ˈklaɪmət ˌæktɪvɪst/", "pron": "KLY-muht AK-ti-vist", "fr": "militant pour le climat", "def": "A person campaigning for climate action.", "ex": "Climate activists criticise governments for delaying action."}, {"term": "grassroots activism", "ipa": "/ˈɡrɑːsruːts ˌæktɪvɪzəm/", "pron": "GRASS-roots AK-ti-viz-uhm", "fr": "militantisme de terrain", "def": "Activism organised by ordinary people at local level.", "ex": "Grassroots activism can pressure local authorities."}, {"term": "grassroots movement", "ipa": "/ˈɡrɑːsruːts ˈmuːvmənt/", "pron": "GRASS-roots MOOV-muhnt", "fr": "mouvement de terrain", "def": "A movement driven by local citizens rather than elites.", "ex": "Grassroots movements can grow into national campaigns."}, {"term": "citizen mobilisation", "ipa": "/ˈsɪtɪzən ˌməʊbɪlaɪˈzeɪʃən/", "pron": "SIT-i-zuhn moh-bi-ly-ZAY-shuhn", "fr": "mobilisation citoyenne", "def": "The organisation of citizens to support a cause or protest.", "ex": "Citizen mobilisation can influence environmental policy."}, {"term": "advocacy", "ipa": "/ˈædvəkəsi/", "pron": "AD-vuh-kuh-see", "fr": "plaidoyer ; défense d’une cause", "def": "Public support or argument for a cause or policy.", "ex": "Environmental advocacy often combines science and storytelling."}, {"term": "campaign", "ipa": "/kæmˈpeɪn/", "pron": "kam-PAYN", "fr": "campagne", "def": "An organised effort to achieve a political, social or environmental goal.", "ex": "The campaign called for a ban on single-use plastic."}, {"term": "awareness campaign", "ipa": "/əˈweənəs kæmˌpeɪn/", "pron": "uh-WAIR-nuhs kam-PAYN", "fr": "campagne de sensibilisation", "def": "A campaign designed to inform people about an issue.", "ex": "Awareness campaigns can change public behaviour."}, {"term": "pressure group", "ipa": "/ˈpreʃə ɡruːp/", "pron": "PRESH-uh group", "fr": "groupe de pression", "def": "An organisation that tries to influence policy without seeking office.", "ex": "Pressure groups lobby for stronger environmental laws."}, {"term": "NGO", "ipa": "/ˌen dʒiː ˈəʊ/", "pron": "en-jee-oh", "fr": "ONG", "def": "Non-governmental organisation.", "ex": "Environmental NGOs monitor governments and corporations."}, {"term": "civil society", "ipa": "/ˌsɪvəl səˈsaɪəti/", "pron": "SIV-uhl suh-SY-uh-tee", "fr": "société civile", "def": "Organisations and citizens outside government and business.", "ex": "Civil society plays a role in environmental governance."}, {"term": "coalition", "ipa": "/ˌkəʊəˈlɪʃən/", "pron": "koh-uh-LISH-uhn", "fr": "coalition", "def": "A temporary alliance of groups working towards a common goal.", "ex": "A coalition of NGOs opposed the pipeline."}, {"term": "community organising", "ipa": "/kəˌmjuːnəti ˈɔːɡənaɪzɪŋ/", "pron": "kuh-MYOO-nuh-tee OR-guh-ny-zing", "fr": "organisation communautaire", "def": "Building local collective power to demand change.", "ex": "Community organising helps residents fight pollution."}]}, {"title": "B. Protest tactics, youth mobilisation and climate justice", "entries": [{"term": "protest", "ipa": "/ˈprəʊtest/", "pron": "PROH-test", "fr": "manifestation ; protestation", "def": "A public action showing opposition or demand for change.", "ex": "The protest called for urgent climate action."}, {"term": "demonstration", "ipa": "/ˌdemənˈstreɪʃən/", "pron": "dem-uhn-STRAY-shuhn", "fr": "manifestation", "def": "A public gathering to express a political or social demand.", "ex": "Thousands joined the environmental demonstration."}, {"term": "march", "ipa": "/mɑːtʃ/", "pron": "march", "fr": "marche ; manifestation", "def": "A protest where people walk together publicly.", "ex": "The climate march attracted students and families."}, {"term": "rally", "ipa": "/ˈræli/", "pron": "RAL-ee", "fr": "rassemblement", "def": "A large public meeting in support of a cause.", "ex": "Activists held a rally outside parliament."}, {"term": "sit-in", "ipa": "/ˈsɪt ɪn/", "pron": "SIT-in", "fr": "sit-in", "def": "A protest where people sit in a place and refuse to leave.", "ex": "Students organised a sit-in to demand fossil fuel divestment."}, {"term": "blockade", "ipa": "/blɒˈkeɪd/", "pron": "blok-AYD", "fr": "blocage ; blocus", "def": "An action preventing access to a place, road or facility.", "ex": "The blockade stopped trucks from entering the site."}, {"term": "occupation", "ipa": "/ˌɒkjʊˈpeɪʃən/", "pron": "ok-yuh-PAY-shuhn", "fr": "occupation", "def": "Taking control of a place as a form of protest.", "ex": "The occupation of the building lasted several days."}, {"term": "direct action", "ipa": "/dəˌrekt ˈækʃən/", "pron": "di-REKT AK-shuhn", "fr": "action directe", "def": "Immediate protest action, often outside normal political channels.", "ex": "Direct action is controversial but can attract attention."}, {"term": "non-violent protest", "ipa": "/ˌnɒn vaɪələnt ˈprəʊtest/", "pron": "non-VY-uh-luhnt PROH-test", "fr": "manifestation non violente", "def": "Protest that avoids physical violence.", "ex": "Non-violent protest can still disrupt public life."}, {"term": "civil disobedience", "ipa": "/ˌsɪvəl ˌdɪsəˈbiːdiəns/", "pron": "SIV-uhl dis-uh-BEE-dee-uhns", "fr": "désobéissance civile", "def": "Deliberate non-violent breaking of laws considered unjust.", "ex": "Civil disobedience raises debates about legality and legitimacy."}, {"term": "symbolic action", "ipa": "/sɪmˌbɒlɪk ˈækʃən/", "pron": "sim-BOL-ik AK-shuhn", "fr": "action symbolique", "def": "An action designed to create a powerful image or message.", "ex": "The action was intended as a symbolic warning."}, {"term": "disruptive protest", "ipa": "/dɪsˌrʌptɪv ˈprəʊtest/", "pron": "dis-RUP-tiv PROH-test", "fr": "manifestation perturbatrice", "def": "A protest that interrupts normal activity to draw attention.", "ex": "Disruptive protest divides public opinion."}, {"term": "roadblock", "ipa": "/ˈrəʊdblɒk/", "pron": "ROHD-blok", "fr": "barrage routier", "def": "A barrier or protest blocking a road.", "ex": "A roadblock can create public anger as well as media attention."}, {"term": "climate strike", "ipa": "/ˈklaɪmət straɪk/", "pron": "KLY-muht strike", "fr": "grève pour le climat", "def": "A strike or school walkout demanding climate action.", "ex": "Youth climate strikes spread around the world."}, {"term": "school strike", "ipa": "/ˈskuːl straɪk/", "pron": "school strike", "fr": "grève scolaire", "def": "A student strike from school to protest or demand change.", "ex": "The school strike movement inspired many young activists."}, {"term": "youth activism", "ipa": "/ˈjuːθ ˌæktɪvɪzəm/", "pron": "yooth AK-ti-viz-uhm", "fr": "militantisme des jeunes", "def": "Activism led by young people.", "ex": "Youth activism has reshaped climate politics."}, {"term": "intergenerational justice", "ipa": "/ˌɪntədʒenəˈreɪʃənəl ˈdʒʌstɪs/", "pron": "IN-tuh-jen-uh-RAY-shuhn-uhl JUS-tis", "fr": "justice intergénérationnelle", "def": "Fairness between generations, especially regarding future impacts.", "ex": "Climate activism often appeals to intergenerational justice."}, {"term": "future generations", "ipa": "/ˌfjuːtʃə ˌdʒenəˈreɪʃənz/", "pron": "FYOO-chuh jen-uh-RAY-shuhnz", "fr": "générations futures", "def": "People who will live in the future.", "ex": "Environmental policy affects future generations."}, {"term": "climate justice", "ipa": "/ˈklaɪmət ˌdʒʌstɪs/", "pron": "KLY-muht JUS-tis", "fr": "justice climatique", "def": "The idea that climate action should address fairness and responsibility.", "ex": "Climate justice links emissions, inequality and historical responsibility."}, {"term": "environmental justice", "ipa": "/ɪnˌvaɪrənˈmentəl ˈdʒʌstɪs/", "pron": "in-vy-ruhn-MEN-tuhl JUS-tis", "fr": "justice environnementale", "def": "Fair treatment regarding environmental benefits and harms.", "ex": "Environmental justice highlights unequal exposure to pollution."}, {"term": "eco-anxiety", "ipa": "/ˌiːkəʊ æŋˈzaɪəti/", "pron": "EE-koh ang-ZY-uh-tee", "fr": "éco-anxiété", "def": "Anxiety caused by environmental crisis or climate change.", "ex": "Eco-anxiety is common among young people."}, {"term": "climate grief", "ipa": "/ˈklaɪmət ɡriːf/", "pron": "KLY-muht grief", "fr": "deuil climatique", "def": "Sadness linked to environmental destruction or climate loss.", "ex": "Climate grief can motivate activism or despair."}, {"term": "doomism", "ipa": "/ˈduːmɪzəm/", "pron": "DOOM-iz-uhm", "fr": "fatalisme écologique", "def": "The belief that ecological collapse is inevitable and action is pointless.", "ex": "Doomism can discourage political action."}, {"term": "climate communication", "ipa": "/ˈklaɪmət kəˌmjuːnɪˈkeɪʃən/", "pron": "KLY-muht kuh-myoo-ni-KAY-shuhn", "fr": "communication climatique", "def": "How climate information is explained to the public.", "ex": "Effective climate communication avoids both denial and despair."}]}, {"title": "C. Communication, consumer activism and political strategy", "entries": [{"term": "media coverage", "ipa": "/ˈmiːdiə ˌkʌvərɪdʒ/", "pron": "MEE-dee-uh KUV-uh-rij", "fr": "couverture médiatique", "def": "How much and how an issue is reported in the media.", "ex": "Activists use dramatic actions to gain media coverage."}, {"term": "social media campaign", "ipa": "/ˌsəʊʃəl ˈmiːdiə kæmˌpeɪn/", "pron": "SOH-shuhl MEE-dee-uh kam-PAYN", "fr": "campagne sur les réseaux sociaux", "def": "A campaign spread through social media platforms.", "ex": "A social media campaign can mobilise people quickly."}, {"term": "hashtag activism", "ipa": "/ˈhæʃtæɡ ˌæktɪvɪzəm/", "pron": "HASH-tag AK-ti-viz-uhm", "fr": "activisme par hashtag", "def": "Online activism organised around hashtags.", "ex": "Hashtag activism can raise awareness but may remain superficial."}, {"term": "slacktivism", "ipa": "/ˈslæktɪvɪzəm/", "pron": "SLAK-ti-viz-uhm", "fr": "militantisme paresseux ; slacktivisme", "def": "Low-effort online activism with limited real-world impact.", "ex": "Critics dismiss some online campaigns as slacktivism."}, {"term": "petition", "ipa": "/pəˈtɪʃən/", "pron": "puh-TISH-uhn", "fr": "pétition", "def": "A formal written request signed by many people.", "ex": "The petition demanded stronger air quality rules."}, {"term": "boycott", "ipa": "/ˈbɔɪkɒt/", "pron": "BOY-kot", "fr": "boycott", "def": "Refusing to buy or use something as protest.", "ex": "Consumers organised a boycott of the polluting company."}, {"term": "consumer activism", "ipa": "/kənˈsjuːmər ˌæktɪvɪzəm/", "pron": "kuhn-SYOO-muh AK-ti-viz-uhm", "fr": "activisme consommateur", "def": "Using buying choices to support political or ethical goals.", "ex": "Consumer activism can pressure brands."}, {"term": "ethical consumption", "ipa": "/ˌeθɪkəl kənˈsʌmpʃən/", "pron": "ETH-i-kuhl kuhn-SUMP-shuhn", "fr": "consommation éthique", "def": "Buying goods according to moral or environmental values.", "ex": "Ethical consumption has limits when sustainable options are expensive."}, {"term": "green consumerism", "ipa": "/ˌɡriːn kənˈsjuːmərɪzəm/", "pron": "green kuhn-SYOO-muh-riz-uhm", "fr": "consommation verte", "def": "Buying environmentally friendly products as a way to act.", "ex": "Green consumerism can shift blame from companies to individuals."}, {"term": "lobbying", "ipa": "/ˈlɒbiɪŋ/", "pron": "LOB-ee-ing", "fr": "lobbying", "def": "Trying to influence political decisions.", "ex": "Environmental lobbying competes with fossil fuel lobbying."}, {"term": "policy advocacy", "ipa": "/ˈpɒləsi ˈædvəkəsi/", "pron": "POL-uh-see AD-vuh-kuh-see", "fr": "plaidoyer politique", "def": "Arguing for specific policy changes.", "ex": "Policy advocacy requires evidence and political strategy."}, {"term": "environmental regulation", "ipa": "/ɪnˌvaɪrənˈmentəl ˌreɡjʊˈleɪʃən/", "pron": "in-vy-ruhn-MEN-tuhl reg-yuh-LAY-shuhn", "fr": "réglementation environnementale", "def": "Rules protecting the environment from harm.", "ex": "Environmental regulation can limit pollution."}, {"term": "political will", "ipa": "/pəˌlɪtɪkəl ˈwɪl/", "pron": "puh-LIT-i-kuhl wil", "fr": "volonté politique", "def": "The determination of leaders to take action.", "ex": "Activists argue that the problem is political will, not technology."}, {"term": "green party", "ipa": "/ˈɡriːn ˌpɑːti/", "pron": "green PAR-tee", "fr": "parti écologiste", "def": "A political party focused on environmental issues.", "ex": "Green parties have influenced European politics."}, {"term": "green politics", "ipa": "/ˌɡriːn ˈpɒlətɪks/", "pron": "green POL-uh-tiks", "fr": "politique écologiste", "def": "Political ideas and movements focused on ecology and sustainability.", "ex": "Green politics connects climate, biodiversity and social justice."}, {"term": "degrowth", "ipa": "/ˌdiːˈɡrəʊθ/", "pron": "dee-GROHTH", "fr": "décroissance", "def": "The idea that wealthy societies should reduce production and consumption.", "ex": "Degrowth challenges growth-based economic models."}, {"term": "green growth", "ipa": "/ˌɡriːn ˈɡrəʊθ/", "pron": "green grohth", "fr": "croissance verte", "def": "Economic growth compatible with environmental protection.", "ex": "Green growth is defended by many governments and businesses."}, {"term": "system change", "ipa": "/ˈsɪstəm tʃeɪndʒ/", "pron": "SIS-tuhm chaynj", "fr": "changement systémique", "def": "Deep transformation of economic, political or social structures.", "ex": "Many activists argue that system change is needed."}, {"term": "individual action", "ipa": "/ˌɪndɪˈvɪdʒuəl ˈækʃən/", "pron": "in-di-VIJ-oo-uhl AK-shuhn", "fr": "action individuelle", "def": "Action taken by individuals, such as reducing consumption.", "ex": "Individual action matters, but cannot replace policy change."}, {"term": "collective action", "ipa": "/kəˌlektɪv ˈækʃən/", "pron": "kuh-LEK-tiv AK-shuhn", "fr": "action collective", "def": "Action taken together by groups or societies.", "ex": "Collective action can change laws and markets."}, {"term": "structural change", "ipa": "/ˌstrʌktʃərəl ˈtʃeɪndʒ/", "pron": "STRUK-chuh-ruhl chaynj", "fr": "changement structurel", "def": "Deep change in systems, institutions or economic structures.", "ex": "Structural change is needed to reduce emissions at scale."}, {"term": "right to protest", "ipa": "/ˌraɪt tə ˈprəʊtest/", "pron": "right tuh PROH-test", "fr": "droit de manifester", "def": "The right to publicly oppose or demand change.", "ex": "The right to protest is central to democracy."}, {"term": "freedom of assembly", "ipa": "/ˌfriːdəm əv əˈsembli/", "pron": "FREE-duhm ov uh-SEM-blee", "fr": "liberté de réunion", "def": "The right to gather peacefully in public.", "ex": "Freedom of assembly protects demonstrations."}]}, {"title": "D. Rights, backlash, litigation and frontline struggles", "entries": [{"term": "public order", "ipa": "/ˌpʌblɪk ˈɔːdə/", "pron": "PUB-lik OR-duh", "fr": "ordre public", "def": "Social peace and lawful behaviour in public spaces.", "ex": "Governments often invoke public order to restrict protests."}, {"term": "criminalisation of protest", "ipa": "/ˌkrɪmɪnəlaɪˈzeɪʃən əv ˈprəʊtest/", "pron": "krim-i-nuh-ly-ZAY-shuhn ov PROH-test", "fr": "criminalisation de la contestation", "def": "Treating protest actions as criminal offences.", "ex": "Activists warn against the criminalisation of protest."}, {"term": "public backlash", "ipa": "/ˌpʌblɪk ˈbæklæʃ/", "pron": "PUB-lik BAK-lash", "fr": "réaction hostile du public", "def": "A strong negative reaction from the public.", "ex": "Disruptive tactics can trigger public backlash."}, {"term": "legitimacy", "ipa": "/lɪˈdʒɪtɪməsi/", "pron": "li-JIT-i-muh-see", "fr": "légitimité", "def": "The quality of being accepted as reasonable, lawful or justified.", "ex": "The legitimacy of civil disobedience is debated."}, {"term": "radicalisation", "ipa": "/ˌrædɪkəlaɪˈzeɪʃən/", "pron": "rad-i-kuh-ly-ZAY-shuhn", "fr": "radicalisation", "def": "Becoming more extreme in beliefs or tactics.", "ex": "Government inaction can fuel activist radicalisation."}, {"term": "eco-sabotage", "ipa": "/ˌiːkəʊ ˈsæbətɑːʒ/", "pron": "EE-koh SAB-uh-tahzh", "fr": "éco-sabotage", "def": "Sabotage carried out for environmental aims.", "ex": "Eco-sabotage is illegal and highly controversial."}, {"term": "radical flank", "ipa": "/ˌrædɪkəl ˈflæŋk/", "pron": "RAD-i-kuhl flank", "fr": "aile radicale", "def": "The more radical part of a movement.", "ex": "A radical flank can affect how moderates are perceived."}, {"term": "greenwashing", "ipa": "/ˈɡriːnˌwɒʃɪŋ/", "pron": "GREEN-wosh-ing", "fr": "greenwashing ; écoblanchiment", "def": "Misleading environmental claims made to improve reputation.", "ex": "Activists expose corporate greenwashing."}, {"term": "corporate accountability", "ipa": "/ˈkɔːpərət əˌkaʊntəˈbɪləti/", "pron": "KOR-puh-ruht uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des entreprises", "def": "Responsibility of companies for their actions and harm.", "ex": "Environmental activism demands corporate accountability."}, {"term": "shareholder activism", "ipa": "/ˈʃeəhəʊldə ˌæktɪvɪzəm/", "pron": "SHARE-hohl-duh AK-ti-viz-uhm", "fr": "activisme actionnarial", "def": "Using shareholder power to pressure companies.", "ex": "Shareholder activism can push companies to cut emissions."}, {"term": "divestment", "ipa": "/daɪˈvestmənt/", "pron": "dy-VEST-muhnt", "fr": "désinvestissement", "def": "Selling investments for ethical, political or financial reasons.", "ex": "Divestment campaigns target fossil fuel companies."}, {"term": "fossil fuel divestment", "ipa": "/ˈfɒsəl ˌfjuːəl daɪˈvestmənt/", "pron": "FOS-uhl FYOO-uhl dy-VEST-muhnt", "fr": "désinvestissement des énergies fossiles", "def": "Selling investments in fossil fuel companies.", "ex": "Universities have faced fossil fuel divestment campaigns."}, {"term": "climate litigation", "ipa": "/ˈklaɪmət ˌlɪtɪˈɡeɪʃən/", "pron": "KLY-muht lit-i-GAY-shuhn", "fr": "contentieux climatique", "def": "Legal action related to climate change.", "ex": "Climate litigation is increasingly used by activists."}, {"term": "strategic litigation", "ipa": "/strəˌtiːdʒɪk ˌlɪtɪˈɡeɪʃən/", "pron": "struh-TEE-jik lit-i-GAY-shuhn", "fr": "contentieux stratégique", "def": "Legal action used to create broader political or social change.", "ex": "Strategic litigation can force governments to strengthen policy."}, {"term": "lawsuit", "ipa": "/ˈlɔːsuːt/", "pron": "LAW-soot", "fr": "procès ; action en justice", "def": "A legal case brought to court.", "ex": "The lawsuit accused the government of climate inaction."}, {"term": "legal challenge", "ipa": "/ˈliːɡəl ˌtʃælɪndʒ/", "pron": "LEE-guhl CHAL-inj", "fr": "recours juridique", "def": "A legal attempt to question or overturn a decision.", "ex": "Activists filed a legal challenge against the project."}, {"term": "environmental impact assessment", "ipa": "/ɪnˌvaɪrənˈmentəl ˈɪmpækt əˌsesmənt/", "pron": "in-vy-ruhn-MEN-tuhl IM-pakt uh-SESS-muhnt", "fr": "étude d’impact environnemental", "def": "A study of a project’s likely environmental effects.", "ex": "Campaigners criticised the environmental impact assessment."}, {"term": "public consultation", "ipa": "/ˌpʌblɪk ˌkɒnsəlˈteɪʃən/", "pron": "PUB-lik kon-suhl-TAY-shuhn", "fr": "consultation publique", "def": "A process where citizens can comment on a project or policy.", "ex": "Public consultation can improve democratic legitimacy."}, {"term": "participatory democracy", "ipa": "/pɑːˌtɪsɪpətəri dɪˈmɒkrəsi/", "pron": "par-TIS-i-puh-tuh-ree di-MOK-ruh-see", "fr": "démocratie participative", "def": "Democracy involving direct citizen participation in decisions.", "ex": "Environmental conflicts often call for participatory democracy."}, {"term": "citizens’ assembly", "ipa": "/ˈsɪtɪzənz əˌsembli/", "pron": "SIT-i-zuhnz uh-SEM-blee", "fr": "assemblée citoyenne", "def": "A group of randomly selected citizens deliberating on policy.", "ex": "A citizens’ assembly can discuss climate policy fairly."}, {"term": "green backlash", "ipa": "/ˌɡriːn ˈbæklæʃ/", "pron": "green BAK-lash", "fr": "retour de bâton anti-écologique", "def": "Public or political reaction against environmental policies.", "ex": "Green backlash can slow climate policy."}, {"term": "climate delay", "ipa": "/ˈklaɪmət dɪˌleɪ/", "pron": "KLY-muht di-LAY", "fr": "stratégies de retardement climatique", "def": "Discourses or tactics that accept climate change but delay action.", "ex": "Climate delay can be more subtle than denial."}, {"term": "science communication", "ipa": "/ˈsaɪəns kəˌmjuːnɪˈkeɪʃən/", "pron": "SY-uhns kuh-myoo-ni-KAY-shuhn", "fr": "communication scientifique", "def": "Explaining science clearly to non-specialists.", "ex": "Science communication is crucial in environmental debates."}, {"term": "citizen science", "ipa": "/ˌsɪtɪzən ˈsaɪəns/", "pron": "SIT-i-zuhn SY-uhns", "fr": "science participative", "def": "Scientific research involving ordinary citizens.", "ex": "Citizen science can document pollution or biodiversity loss."}, {"term": "watchdog", "ipa": "/ˈwɒtʃdɒɡ/", "pron": "WATCH-dog", "fr": "chien de garde ; organisme de surveillance", "def": "A person or organisation monitoring wrongdoing or abuse.", "ex": "Environmental watchdogs investigate illegal pollution."}, {"term": "whistleblower", "ipa": "/ˈwɪsəlˌbləʊə/", "pron": "WIS-uhl-bloh-uh", "fr": "lanceur d’alerte", "def": "A person who exposes wrongdoing inside an organisation.", "ex": "Whistleblowers can reveal environmental crimes."}, {"term": "environmental defender", "ipa": "/ɪnˌvaɪrənˈmentəl dɪˈfendə/", "pron": "in-vy-ruhn-MEN-tuhl di-FEN-duh", "fr": "défenseur de l’environnement", "def": "A person protecting land, nature or environmental rights, often at personal risk.", "ex": "Environmental defenders can face intimidation and violence."}, {"term": "Indigenous activism", "ipa": "/ɪnˈdɪdʒənəs ˌæktɪvɪzəm/", "pron": "in-DIJ-uh-nuhs AK-ti-viz-uhm", "fr": "militantisme autochtone", "def": "Activism led by Indigenous peoples to protect land, rights and ecosystems.", "ex": "Indigenous activism is central to many anti-extraction struggles."}, {"term": "land rights", "ipa": "/ˈlænd raɪts/", "pron": "land rights", "fr": "droits fonciers", "def": "Rights to own, use or control land.", "ex": "Land rights are often linked to environmental protection."}, {"term": "land defender", "ipa": "/ˈlænd dɪˌfendə/", "pron": "land di-FEN-duh", "fr": "défenseur des terres", "def": "A person defending land from exploitation or destruction.", "ex": "Land defenders often oppose mining or deforestation."}, {"term": "extractivism", "ipa": "/ɪkˈstræktɪvɪzəm/", "pron": "ik-STRAK-ti-viz-uhm", "fr": "extractivisme", "def": "An economic model based on large-scale extraction of natural resources.", "ex": "Environmental activists criticise extractivism."}, {"term": "anti-extraction movement", "ipa": "/ˌænti ɪkˈstrækʃən ˈmuːvmənt/", "pron": "AN-tee ik-STRAK-shuhn MOOV-muhnt", "fr": "mouvement anti-extraction", "def": "A movement opposing mining, drilling or resource extraction.", "ex": "Anti-extraction movements often defend land and water."}, {"term": "pipeline protest", "ipa": "/ˈpaɪplaɪn ˌprəʊtest/", "pron": "PYPE-line PROH-test", "fr": "manifestation contre un pipeline", "def": "A protest against oil or gas pipeline projects.", "ex": "Pipeline protests can become national political issues."}, {"term": "forest protection", "ipa": "/ˈfɒrɪst prəˌtekʃən/", "pron": "FOR-ist pruh-TEK-shuhn", "fr": "protection des forêts", "def": "Action to protect forests from destruction or degradation.", "ex": "Forest protection campaigns target illegal logging."}, {"term": "anti-deforestation campaign", "ipa": "/ˌænti diːˌfɒrɪˈsteɪʃən kæmˌpeɪn/", "pron": "AN-tee dee-for-i-STAY-shuhn kam-PAYN", "fr": "campagne contre la déforestation", "def": "A campaign against forest destruction.", "ex": "Anti-deforestation campaigns often target supply chains."}, {"term": "animal rights activism", "ipa": "/ˈænɪməl raɪts ˌæktɪvɪzəm/", "pron": "AN-i-muhl rites AK-ti-viz-uhm", "fr": "militantisme pour les droits des animaux", "def": "Activism defending animals from exploitation or cruelty.", "ex": "Animal rights activism overlaps with environmental ethics."}, {"term": "vegan activism", "ipa": "/ˈviːɡən ˌæktɪvɪzəm/", "pron": "VEE-guhn AK-ti-viz-uhm", "fr": "militantisme végan", "def": "Activism promoting veganism for ethical, environmental or health reasons.", "ex": "Vegan activism criticises industrial animal farming."}, {"term": "anti-consumerism", "ipa": "/ˌænti kənˈsjuːmərɪzəm/", "pron": "AN-tee kuhn-SYOO-muh-riz-uhm", "fr": "anticonsumérisme", "def": "Opposition to excessive consumption and consumer culture.", "ex": "Anti-consumerism challenges throwaway culture."}, {"term": "zero waste", "ipa": "/ˌzɪərəʊ ˈweɪst/", "pron": "ZEER-oh wayst", "fr": "zéro déchet", "def": "A lifestyle or policy goal aiming to produce no waste.", "ex": "Zero waste activism promotes repair and reuse."}, {"term": "planned obsolescence", "ipa": "/ˌplænd ˌɒbsəˈlesəns/", "pron": "pland ob-suh-LES-uhns", "fr": "obsolescence programmée", "def": "Designing products to become outdated or unusable quickly.", "ex": "Activists criticise planned obsolescence as wasteful."}, {"term": "to campaign for climate action", "ipa": "/kæmˈpeɪn fə ˈklaɪmət ˈækʃən/", "pron": "kam-PAYN fuh KLY-muht AK-shuhn", "fr": "faire campagne pour l’action climatique", "def": "To organise public efforts demanding climate policy.", "ex": "Students campaign for climate action."}, {"term": "to raise awareness", "ipa": "/reɪz əˈweənəs/", "pron": "rayz uh-WAIR-nuhs", "fr": "sensibiliser", "def": "To make people more informed about an issue.", "ex": "Activists raise awareness about plastic pollution."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "to mobilise citizens", "ipa": "/ˈməʊbɪlaɪz ˈsɪtɪzənz/", "pron": "MOH-bi-lyze SIT-i-zuhnz", "fr": "mobiliser les citoyens", "def": "To organise citizens to act collectively.", "ex": "Social media can mobilise citizens quickly."}, {"term": "to stage a protest", "ipa": "/steɪdʒ ə ˈprəʊtest/", "pron": "stayj uh PROH-test", "fr": "organiser une manifestation", "def": "To organise a public protest.", "ex": "Activists staged a protest outside the ministry."}, {"term": "to engage in civil disobedience", "ipa": "/ɪnˈɡeɪdʒ ɪn ˌsɪvəl ˌdɪsəˈbiːdiəns/", "pron": "in-GAYJ in SIV-uhl dis-uh-BEE-dee-uhns", "fr": "pratiquer la désobéissance civile", "def": "To deliberately break laws non-violently for political reasons.", "ex": "Activists engage in civil disobedience when legal channels seem ineffective."}, {"term": "to lobby lawmakers", "ipa": "/ˈlɒbi ˈlɔːˌmeɪkəz/", "pron": "LOB-ee LAW-may-kuhz", "fr": "faire pression sur les législateurs", "def": "To try to influence elected representatives.", "ex": "NGOs lobby lawmakers for stronger environmental rules."}, {"term": "to file a lawsuit", "ipa": "/faɪl ə ˈlɔːsuːt/", "pron": "fyle uh LAW-soot", "fr": "intenter une action en justice", "def": "To bring a legal case to court.", "ex": "Campaigners filed a lawsuit against the government."}, {"term": "to expose greenwashing", "ipa": "/ɪkˈspəʊz ˈɡriːnˌwɒʃɪŋ/", "pron": "ik-SPOHZ GREEN-wosh-ing", "fr": "dénoncer le greenwashing", "def": "To reveal misleading environmental claims.", "ex": "Journalists and activists expose greenwashing."}, {"term": "to hold corporations accountable", "ipa": "/həʊld ˌkɔːpəˈreɪʃənz əˈkaʊntəbəl/", "pron": "hohld kor-puh-RAY-shuhnz uh-KOWN-tuh-buhl", "fr": "tenir les entreprises responsables", "def": "To make companies responsible for harm or misconduct.", "ex": "Activists seek to hold corporations accountable."}, {"term": "to demand systemic change", "ipa": "/dɪˈmɑːnd sɪˌstemɪk tʃeɪndʒ/", "pron": "di-MAHND sis-TEM-ik chaynj", "fr": "exiger un changement systémique", "def": "To call for deep changes in systems and institutions.", "ex": "Many environmental activists demand systemic change."}, {"term": "to defend the right to protest", "ipa": "/dɪˈfend ðə raɪt tə ˈprəʊtest/", "pron": "di-FEND thuh right tuh PROH-test", "fr": "défendre le droit de manifester", "def": "To protect the freedom to protest publicly.", "ex": "Civil liberties groups defend the right to protest."}, {"term": "to balance disruption and legitimacy", "ipa": "/ˈbæləns dɪsˈrʌpʃən ənd lɪˈdʒɪtɪməsi/", "pron": "BAL-uhns dis-RUP-shuhn and li-JIT-i-muh-see", "fr": "équilibrer perturbation et légitimité", "def": "To weigh disruptive tactics against public acceptance.", "ex": "Movements must balance disruption and legitimacy."}]}]}, {"id": "p8c73", "part": 8, "chapter": 73, "title": "Climate Migration", "file": "cpge_vocab_part8_chapter73_climate_migration_premium.html", "count": 116, "sections": [{"title": "A. Core climate migration vocabulary", "entries": [{"term": "climate migration", "ipa": "/ˈklaɪmət maɪˌɡreɪʃən/", "pron": "KLY-muht my-GRAY-shuhn", "fr": "migration climatique", "def": "The movement of people linked to climate change and environmental pressures.", "ex": "Climate migration can be temporary, permanent, internal or cross-border."}, {"term": "climate migrant", "ipa": "/ˈklaɪmət ˌmaɪɡrənt/", "pron": "KLY-muht MY-gruhnt", "fr": "migrant climatique", "def": "A person who moves partly or mainly because of climate-related factors.", "ex": "The term climate migrant covers many different situations."}, {"term": "environmental migration", "ipa": "/ɪnˌvaɪrənˈmentəl maɪˌɡreɪʃən/", "pron": "in-vy-ruhn-MEN-tuhl my-GRAY-shuhn", "fr": "migration environnementale", "def": "Migration caused or influenced by environmental change.", "ex": "Environmental migration is not always caused by climate change alone."}, {"term": "environmental migrant", "ipa": "/ɪnˌvaɪrənˈmentəl ˌmaɪɡrənt/", "pron": "in-vy-ruhn-MEN-tuhl MY-gruhnt", "fr": "migrant environnemental", "def": "A person who moves because environmental conditions affect life or livelihood.", "ex": "Environmental migrants may move because of drought, floods or land degradation."}, {"term": "climate refugee", "ipa": "/ˈklaɪmət ˌrefjʊˈdʒiː/", "pron": "KLY-muht REF-yoo-jee", "fr": "réfugié climatique", "def": "A widely used but legally contested term for someone displaced by climate impacts.", "ex": "Climate refugee is powerful politically, but it is not a formal legal status in most contexts."}, {"term": "environmental refugee", "ipa": "/ɪnˌvaɪrənˈmentəl ˌrefjʊˈdʒiː/", "pron": "in-vy-ruhn-MEN-tuhl REF-yoo-jee", "fr": "réfugié environnemental", "def": "A contested term for a person forced to move because of environmental harm.", "ex": "Environmental refugee is often used in media debates."}, {"term": "displacement", "ipa": "/dɪsˈpleɪsmənt/", "pron": "dis-PLAYS-muhnt", "fr": "déplacement forcé", "def": "Forced movement from home because of danger, crisis or loss of livelihood.", "ex": "Displacement can follow floods, storms or conflict."}, {"term": "climate displacement", "ipa": "/ˈklaɪmət dɪsˌpleɪsmənt/", "pron": "KLY-muht dis-PLAYS-muhnt", "fr": "déplacement climatique", "def": "Forced movement caused or worsened by climate impacts.", "ex": "Climate displacement is expected to increase in vulnerable regions."}, {"term": "internal displacement", "ipa": "/ɪnˌtɜːnəl dɪsˈpleɪsmənt/", "pron": "in-TUR-nuhl dis-PLAYS-muhnt", "fr": "déplacement interne", "def": "Forced movement within a country’s borders.", "ex": "Most climate-related displacement is internal."}, {"term": "internally displaced person", "ipa": "/ɪnˌtɜːnəli dɪsˌpleɪst ˈpɜːsən/", "pron": "in-TUR-nuh-lee dis-PLAYST PUR-suhn", "fr": "personne déplacée interne", "def": "A person forced to move within their own country.", "ex": "Internally displaced people may not receive international protection."}, {"term": "IDP", "ipa": "/ˌaɪ diː ˈpiː/", "pron": "eye-dee-pee", "fr": "PDI", "def": "Abbreviation for internally displaced person.", "ex": "IDPs often need shelter, food and legal assistance."}, {"term": "cross-border migration", "ipa": "/ˌkrɒs bɔːdə maɪˈɡreɪʃən/", "pron": "cross-BOR-duh my-GRAY-shuhn", "fr": "migration transfrontalière", "def": "Movement from one country to another.", "ex": "Cross-border migration raises legal and diplomatic questions."}, {"term": "forced migration", "ipa": "/ˌfɔːst maɪˈɡreɪʃən/", "pron": "forst my-GRAY-shuhn", "fr": "migration forcée", "def": "Movement caused by coercion, danger or lack of viable alternatives.", "ex": "Forced migration can result from war, persecution or environmental collapse."}, {"term": "voluntary migration", "ipa": "/ˈvɒləntəri maɪˌɡreɪʃən/", "pron": "VOL-uhn-tuh-ree my-GRAY-shuhn", "fr": "migration volontaire", "def": "Migration chosen by individuals, though often under pressure.", "ex": "The line between voluntary and forced migration can be blurred."}, {"term": "planned relocation", "ipa": "/ˌplænd ˌriːləʊˈkeɪʃən/", "pron": "pland ree-loh-KAY-shuhn", "fr": "réinstallation planifiée", "def": "Organised movement of communities away from high-risk areas.", "ex": "Planned relocation can protect lives but may damage identity and livelihoods."}, {"term": "relocation", "ipa": "/ˌriːləʊˈkeɪʃən/", "pron": "ree-loh-KAY-shuhn", "fr": "réinstallation ; relocalisation", "def": "Moving people or communities to another place.", "ex": "Relocation is difficult when communities have deep ties to land."}, {"term": "resettlement", "ipa": "/ˌriːˈsetəlmənt/", "pron": "ree-SET-uhl-muhnt", "fr": "réinstallation", "def": "The process of settling people in a new place after displacement.", "ex": "Resettlement requires housing, jobs and social support."}, {"term": "evacuation", "ipa": "/ɪˌvækjuˈeɪʃən/", "pron": "i-vak-yoo-AY-shuhn", "fr": "évacuation", "def": "Moving people away from immediate danger.", "ex": "Evacuation saves lives during hurricanes and wildfires."}, {"term": "temporary migration", "ipa": "/ˌtempərəri maɪˈɡreɪʃən/", "pron": "TEM-puh-ruh-ree my-GRAY-shuhn", "fr": "migration temporaire", "def": "Migration for a limited period before returning or moving on.", "ex": "Temporary migration can help families cope with drought."}, {"term": "permanent migration", "ipa": "/ˌpɜːmənənt maɪˈɡreɪʃən/", "pron": "PUR-muh-nuhnt my-GRAY-shuhn", "fr": "migration permanente", "def": "Migration intended to last indefinitely.", "ex": "Sea-level rise may force permanent migration."}, {"term": "seasonal migration", "ipa": "/ˌsiːzənəl maɪˈɡreɪʃən/", "pron": "SEE-zuh-nuhl my-GRAY-shuhn", "fr": "migration saisonnière", "def": "Migration that happens during particular seasons.", "ex": "Seasonal migration may increase when farming becomes unreliable."}, {"term": "rural exodus", "ipa": "/ˌrʊərəl ˈeksədəs/", "pron": "ROOR-uhl EK-suh-duhs", "fr": "exode rural", "def": "Large-scale movement from rural areas to cities.", "ex": "Drought can accelerate rural exodus."}, {"term": "urban migration", "ipa": "/ˈɜːbən maɪˌɡreɪʃən/", "pron": "UR-buhn my-GRAY-shuhn", "fr": "migration urbaine", "def": "Movement of people towards towns and cities.", "ex": "Climate stress may increase urban migration."}, {"term": "rural-to-urban migration", "ipa": "/ˌrʊərəl tə ˈɜːbən maɪˌɡreɪʃən/", "pron": "ROOR-uhl tuh UR-buhn my-GRAY-shuhn", "fr": "migration rurale-urbaine", "def": "Movement from the countryside to cities.", "ex": "Rural-to-urban migration can strain housing and infrastructure."}, {"term": "migration pressure", "ipa": "/maɪˈɡreɪʃən ˌpreʃə/", "pron": "my-GRAY-shuhn PRESH-uh", "fr": "pression migratoire", "def": "Factors that increase people’s need or desire to migrate.", "ex": "Climate impacts can intensify migration pressure."}, {"term": "push factor", "ipa": "/ˈpʊʃ ˌfæktə/", "pron": "push FAK-tuh", "fr": "facteur de répulsion", "def": "A factor that drives people to leave a place.", "ex": "Drought can be a push factor."}, {"term": "pull factor", "ipa": "/ˈpʊl ˌfæktə/", "pron": "pull FAK-tuh", "fr": "facteur d’attraction", "def": "A factor that attracts people to a new place.", "ex": "Jobs and safety are pull factors."}, {"term": "livelihood", "ipa": "/ˈlaɪvlihʊd/", "pron": "LYVE-lee-hood", "fr": "moyen de subsistance", "def": "The way people earn a living and meet basic needs.", "ex": "Climate change threatens rural livelihoods."}, {"term": "loss of livelihood", "ipa": "/ˌlɒs əv ˈlaɪvlihʊd/", "pron": "loss ov LYVE-lee-hood", "fr": "perte de moyens de subsistance", "def": "The loss of income, work or means of survival.", "ex": "Loss of livelihood can force families to move."}, {"term": "subsistence farming", "ipa": "/səbˈsɪstəns ˌfɑːmɪŋ/", "pron": "suhb-SIS-tuhns FAR-ming", "fr": "agriculture de subsistance", "def": "Farming mainly to feed one’s family rather than sell crops.", "ex": "Subsistence farming is vulnerable to drought and crop failure."}]}, {"title": "B. Climate drivers and environmental pressures", "entries": [{"term": "crop failure", "ipa": "/ˈkrɒp ˌfeɪljə/", "pron": "crop FAYL-yuh", "fr": "mauvaise récolte ; perte de récolte", "def": "The failure of crops to grow or produce food.", "ex": "Repeated crop failure can push farmers to migrate."}, {"term": "food insecurity", "ipa": "/ˈfuːd ˌɪnsɪˈkjʊərəti/", "pron": "food in-si-KYOOR-uh-tee", "fr": "insécurité alimentaire", "def": "Lack of reliable access to enough food.", "ex": "Food insecurity can contribute to displacement."}, {"term": "water scarcity", "ipa": "/ˈwɔːtə ˌskeəsəti/", "pron": "WOR-tuh SKAIR-suh-tee", "fr": "pénurie d’eau", "def": "Lack of sufficient water resources.", "ex": "Water scarcity can make regions less habitable."}, {"term": "drought", "ipa": "/draʊt/", "pron": "drowt", "fr": "sécheresse", "def": "A long period with too little rainfall.", "ex": "Drought can destroy crops and force migration."}, {"term": "desertification", "ipa": "/dɪˌzɜːtɪfɪˈkeɪʃən/", "pron": "di-zur-ti-fi-KAY-shuhn", "fr": "désertification", "def": "Land degradation that turns fertile land into desert-like conditions.", "ex": "Desertification threatens livelihoods in dry regions."}, {"term": "land degradation", "ipa": "/ˈlænd ˌdeɡrəˈdeɪʃən/", "pron": "land deg-ruh-DAY-shuhn", "fr": "dégradation des terres", "def": "Decline in land quality and productivity.", "ex": "Land degradation can reduce farming income."}, {"term": "soil erosion", "ipa": "/ˈsɔɪl ɪˌrəʊʒən/", "pron": "soil i-ROH-zhuhn", "fr": "érosion des sols", "def": "The loss of fertile soil by wind, water or human activity.", "ex": "Soil erosion makes agriculture more difficult."}, {"term": "flood", "ipa": "/flʌd/", "pron": "flud", "fr": "inondation", "def": "An overflow of water onto normally dry land.", "ex": "Floods can displace thousands of people in a few hours."}, {"term": "flash flood", "ipa": "/ˈflæʃ flʌd/", "pron": "flash flud", "fr": "crue soudaine", "def": "A sudden and fast flood.", "ex": "Flash floods leave little time for evacuation."}, {"term": "coastal flooding", "ipa": "/ˌkəʊstəl ˈflʌdɪŋ/", "pron": "KOH-stuhl FLUD-ing", "fr": "inondation côtière", "def": "Flooding in coastal areas caused by storms or sea-level rise.", "ex": "Coastal flooding threatens low-lying cities."}, {"term": "sea-level rise", "ipa": "/ˈsiː levəl raɪz/", "pron": "SEE-LEV-uhl ryze", "fr": "élévation du niveau de la mer", "def": "The increase in average ocean level.", "ex": "Sea-level rise may make some islands uninhabitable."}, {"term": "coastal erosion", "ipa": "/ˌkəʊstəl ɪˈrəʊʒən/", "pron": "KOH-stuhl i-ROH-zhuhn", "fr": "érosion côtière", "def": "The wearing away of land along coasts.", "ex": "Coastal erosion can force communities to relocate."}, {"term": "storm surge", "ipa": "/ˈstɔːm sɜːdʒ/", "pron": "storm surj", "fr": "onde de tempête", "def": "A rise in sea level caused by a storm pushing water inland.", "ex": "Storm surges can devastate coastal settlements."}, {"term": "hurricane", "ipa": "/ˈhʌrɪkən/", "pron": "HUR-i-kuhn", "fr": "ouragan", "def": "A powerful tropical storm in the Atlantic or eastern Pacific.", "ex": "Hurricanes often cause temporary and permanent displacement."}, {"term": "cyclone", "ipa": "/ˈsaɪkləʊn/", "pron": "SY-klohn", "fr": "cyclone", "def": "A powerful rotating storm, especially in the Indian Ocean or South Pacific.", "ex": "Cyclones can destroy homes and infrastructure."}, {"term": "typhoon", "ipa": "/taɪˈfuːn/", "pron": "ty-FOON", "fr": "typhon", "def": "A powerful tropical storm in the western Pacific.", "ex": "Typhoons can trigger mass evacuations."}, {"term": "wildfire", "ipa": "/ˈwaɪldfaɪə/", "pron": "WYLD-fire", "fr": "incendie de forêt", "def": "An uncontrolled fire in forests, grasslands or settlements.", "ex": "Wildfires can force communities to evacuate."}, {"term": "heatwave", "ipa": "/ˈhiːtweɪv/", "pron": "HEET-wave", "fr": "canicule", "def": "A prolonged period of unusually high temperatures.", "ex": "Extreme heat can make outdoor work dangerous."}, {"term": "extreme weather", "ipa": "/ɪkˌstriːm ˈweðə/", "pron": "ik-STREEM WETH-uh", "fr": "phénomènes météorologiques extrêmes", "def": "Severe weather events such as floods, heatwaves, droughts and storms.", "ex": "Extreme weather increasingly drives displacement."}, {"term": "slow-onset disaster", "ipa": "/ˌsləʊ ˈɒnset dɪˌzɑːstə/", "pron": "sloh-ON-set di-ZAH-stuh", "fr": "catastrophe à évolution lente", "def": "A gradual crisis such as sea-level rise, desertification or drought.", "ex": "Slow-onset disasters may push people to migrate over years."}, {"term": "sudden-onset disaster", "ipa": "/ˌsʌdən ˈɒnset dɪˌzɑːstə/", "pron": "SUD-uhn-ON-set di-ZAH-stuh", "fr": "catastrophe soudaine", "def": "A rapid disaster such as a flood, cyclone or wildfire.", "ex": "Sudden-onset disasters often cause emergency displacement."}, {"term": "natural hazard", "ipa": "/ˌnætʃərəl ˈhæzəd/", "pron": "NAT-chuh-ruhl HAZ-uhd", "fr": "aléa naturel", "def": "A natural process that can threaten people or property.", "ex": "Climate change can intensify natural hazards."}, {"term": "disaster risk", "ipa": "/dɪˈzɑːstə rɪsk/", "pron": "di-ZAH-stuh risk", "fr": "risque de catastrophe", "def": "The likelihood of harm from hazards combined with vulnerability and exposure.", "ex": "Disaster risk is higher where infrastructure is weak."}, {"term": "disaster risk reduction", "ipa": "/dɪˈzɑːstə rɪsk rɪˌdʌkʃən/", "pron": "di-ZAH-stuh risk ri-DUK-shuhn", "fr": "réduction des risques de catastrophe", "def": "Measures to reduce harm from disasters.", "ex": "Disaster risk reduction can prevent displacement."}, {"term": "DRR", "ipa": "/ˌdiː ɑːr ˈɑː/", "pron": "dee-ar-ar", "fr": "RRC", "def": "Abbreviation for disaster risk reduction.", "ex": "DRR includes early warning systems and safer infrastructure."}, {"term": "early warning system", "ipa": "/ˌɜːli ˈwɔːnɪŋ ˌsɪstəm/", "pron": "UR-lee WOR-ning SIS-tuhm", "fr": "système d’alerte précoce", "def": "A system that warns people before hazards strike.", "ex": "Early warning systems save lives during storms."}, {"term": "climate adaptation", "ipa": "/ˈklaɪmət ˌædæpˈteɪʃən/", "pron": "KLY-muht ad-ap-TAY-shuhn", "fr": "adaptation au changement climatique", "def": "Adjusting to climate impacts to reduce harm.", "ex": "Climate adaptation can reduce forced migration."}, {"term": "adaptation strategy", "ipa": "/ˌædæpˈteɪʃən ˈstrætədʒi/", "pron": "ad-ap-TAY-shuhn STRAT-uh-jee", "fr": "stratégie d’adaptation", "def": "A plan to reduce vulnerability to climate impacts.", "ex": "Migration can be part of an adaptation strategy."}]}, {"title": "C. Adaptation, vulnerability and receiving communities", "entries": [{"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability to withstand and recover from shocks.", "ex": "Resilience reduces the need for emergency displacement."}, {"term": "climate resilience", "ipa": "/ˈklaɪmət rɪˌzɪliəns/", "pron": "KLY-muht ri-ZIL-ee-uhns", "fr": "résilience climatique", "def": "The ability to cope with and recover from climate impacts.", "ex": "Climate resilience requires infrastructure, finance and social support."}, {"term": "vulnerability", "ipa": "/ˌvʌlnərəˈbɪləti/", "pron": "vul-nuh-ruh-BIL-uh-tee", "fr": "vulnérabilité", "def": "Susceptibility to harm because of exposure or limited resources.", "ex": "Poverty increases vulnerability to climate displacement."}, {"term": "exposure", "ipa": "/ɪkˈspəʊʒə/", "pron": "ik-SPOH-zhuh", "fr": "exposition", "def": "The presence of people or assets in places that could be harmed.", "ex": "Coastal exposure increases risk from sea-level rise."}, {"term": "adaptive capacity", "ipa": "/əˌdæptɪv kəˈpæsəti/", "pron": "uh-DAP-tiv kuh-PASS-uh-tee", "fr": "capacité d’adaptation", "def": "The ability to adjust to environmental change.", "ex": "Low adaptive capacity makes migration more likely."}, {"term": "trapped population", "ipa": "/ˌtræpt pɒpjʊˈleɪʃən/", "pron": "trapt pop-yuh-LAY-shuhn", "fr": "population piégée", "def": "People unable to move despite serious risk.", "ex": "The poorest may become trapped populations."}, {"term": "immobility", "ipa": "/ˌɪməʊˈbɪləti/", "pron": "im-oh-BIL-uh-tee", "fr": "immobilité", "def": "The condition of not moving, sometimes because movement is impossible.", "ex": "Climate debates often forget immobility."}, {"term": "migration as adaptation", "ipa": "/maɪˈɡreɪʃən əz ˌædæpˈteɪʃən/", "pron": "my-GRAY-shuhn az ad-ap-TAY-shuhn", "fr": "migration comme adaptation", "def": "The idea that migration can help people cope with climate change.", "ex": "Migration as adaptation challenges the idea that movement is always failure."}, {"term": "managed retreat", "ipa": "/ˌmænɪdʒd rɪˈtriːt/", "pron": "MAN-ijd ri-TREET", "fr": "retrait planifié", "def": "Planned movement away from areas at high environmental risk.", "ex": "Managed retreat is politically sensitive in coastal areas."}, {"term": "host community", "ipa": "/ˈhəʊst kəˌmjuːnəti/", "pron": "hohst kuh-MYOO-nuh-tee", "fr": "communauté d’accueil", "def": "A community receiving displaced people or migrants.", "ex": "Host communities need resources to avoid tensions."}, {"term": "receiving area", "ipa": "/rɪˈsiːvɪŋ ˈeəriə/", "pron": "ri-SEE-ving AIR-ee-uh", "fr": "zone d’accueil", "def": "A place where migrants or displaced people arrive.", "ex": "Receiving areas may face pressure on services."}, {"term": "urban slum", "ipa": "/ˈɜːbən slʌm/", "pron": "UR-buhn slum", "fr": "bidonville urbain", "def": "A poor, overcrowded urban area with inadequate housing and services.", "ex": "Climate migrants may end up in urban slums."}, {"term": "informal settlement", "ipa": "/ɪnˌfɔːməl ˈsetəlmənt/", "pron": "in-FOR-muhl SET-uhl-muhnt", "fr": "habitat informel", "def": "Housing built without formal planning or legal recognition.", "ex": "Informal settlements are often exposed to floods."}, {"term": "infrastructure strain", "ipa": "/ˈɪnfrəˌstrʌktʃə streɪn/", "pron": "IN-fruh-struk-chuh strayn", "fr": "pression sur les infrastructures", "def": "Pressure placed on roads, housing, water, schools or hospitals.", "ex": "Rapid migration can create infrastructure strain."}, {"term": "social cohesion", "ipa": "/ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "SOH-shuhl koh-HEE-zhuhn", "fr": "cohésion sociale", "def": "The strength of relationships and trust within a society.", "ex": "Good planning protects social cohesion."}, {"term": "resource conflict", "ipa": "/rɪˈsɔːs ˌkɒnflɪkt/", "pron": "ri-SORSS KON-flikt", "fr": "conflit lié aux ressources", "def": "Conflict over access to water, land, food or energy.", "ex": "Resource conflict can be worsened by climate stress."}, {"term": "water conflict", "ipa": "/ˈwɔːtə ˌkɒnflɪkt/", "pron": "WOR-tuh KON-flikt", "fr": "conflit lié à l’eau", "def": "Conflict over access to water.", "ex": "Water conflict may increase during prolonged drought."}, {"term": "land conflict", "ipa": "/ˈlænd ˌkɒnflɪkt/", "pron": "land KON-flikt", "fr": "conflit foncier", "def": "Conflict over land ownership, use or access.", "ex": "Relocation can create land conflict."}, {"term": "border control", "ipa": "/ˈbɔːdə kənˌtrəʊl/", "pron": "BOR-duh kuhn-TROHL", "fr": "contrôle des frontières", "def": "Government measures controlling entry into a country.", "ex": "Climate migration may intensify debates about border control."}, {"term": "asylum", "ipa": "/əˈsaɪləm/", "pron": "uh-SY-luhm", "fr": "asile", "def": "Protection granted by a country to someone fleeing persecution or serious danger.", "ex": "Current asylum systems rarely cover climate-related movement."}, {"term": "refugee status", "ipa": "/ˌrefjʊˈdʒiː ˈsteɪtəs/", "pron": "REF-yoo-jee STAY-tuhs", "fr": "statut de réfugié", "def": "Legal recognition as a refugee.", "ex": "Climate migrants usually do not qualify for refugee status."}, {"term": "1951 Refugee Convention", "ipa": "/ˌnaɪntiːn fɪfti wʌn ˌrefjʊˈdʒiː kənˈvenʃən/", "pron": "nineteen-fifty-one REF-yoo-jee kuhn-VEN-shuhn", "fr": "Convention de 1951 relative aux réfugiés", "def": "The main international treaty defining refugee protection.", "ex": "The 1951 Refugee Convention does not explicitly mention climate change."}, {"term": "legal gap", "ipa": "/ˈliːɡəl ɡæp/", "pron": "LEE-guhl gap", "fr": "vide juridique", "def": "An area where the law does not provide clear protection or rules.", "ex": "Climate displacement exposes a legal gap."}, {"term": "protection gap", "ipa": "/prəˈtekʃən ɡæp/", "pron": "pruh-TEK-shuhn gap", "fr": "lacune de protection", "def": "A lack of adequate protection for vulnerable people.", "ex": "A protection gap leaves many displaced people without rights."}, {"term": "human rights", "ipa": "/ˌhjuːmən ˈraɪts/", "pron": "HYOO-muhn rites", "fr": "droits humains", "def": "Basic rights and freedoms belonging to all people.", "ex": "Climate displacement threatens human rights."}]}, {"title": "D. Law, justice, security and international responsibility", "entries": [{"term": "right to housing", "ipa": "/ˌraɪt tə ˈhaʊzɪŋ/", "pron": "right tuh HOW-zing", "fr": "droit au logement", "def": "The right to adequate housing.", "ex": "Relocated communities need the right to housing respected."}, {"term": "right to water", "ipa": "/ˌraɪt tə ˈwɔːtə/", "pron": "right tuh WOR-tuh", "fr": "droit à l’eau", "def": "The right to safe and sufficient water.", "ex": "Water scarcity threatens the right to water."}, {"term": "statelessness", "ipa": "/ˈsteɪtləsnəs/", "pron": "STATE-luhs-nuhs", "fr": "apatridie", "def": "The condition of not being recognised as a citizen by any state.", "ex": "Sea-level rise raises fears of statelessness for some island populations."}, {"term": "sovereignty", "ipa": "/ˈsɒvrənti/", "pron": "SOV-ruhn-tee", "fr": "souveraineté", "def": "A state’s authority and independence over its territory and people.", "ex": "Disappearing territory raises questions of sovereignty."}, {"term": "small island developing state", "ipa": "/ˌsmɔːl ˈaɪlənd dɪˌveləpɪŋ steɪt/", "pron": "small EYE-luhnd di-VEL-uh-ping state", "fr": "petit État insulaire en développement", "def": "A small island country facing development and climate vulnerabilities.", "ex": "Small island developing states are highly exposed to sea-level rise."}, {"term": "SIDS", "ipa": "/ˌes aɪ diː ˈes/", "pron": "ess-eye-dee-ess", "fr": "PEID", "def": "Abbreviation for small island developing states.", "ex": "SIDS have demanded stronger climate action and finance."}, {"term": "Pacific island states", "ipa": "/pəˌsɪfɪk ˈaɪlənd steɪts/", "pron": "puh-SIF-ik EYE-luhnd states", "fr": "États insulaires du Pacifique", "def": "Island countries in the Pacific region.", "ex": "Pacific island states face existential climate threats."}, {"term": "loss and damage", "ipa": "/ˌlɒs ənd ˈdæmɪdʒ/", "pron": "loss and DAM-ij", "fr": "pertes et préjudices", "def": "Climate harms that cannot be avoided through mitigation or adaptation.", "ex": "Loss and damage debates include displacement and cultural loss."}, {"term": "climate finance", "ipa": "/ˈklaɪmət ˌfaɪnæns/", "pron": "KLY-muht FY-nans", "fr": "financement climatique", "def": "Funding for mitigation, adaptation and climate-related loss and damage.", "ex": "Climate finance can help communities adapt before they are forced to move."}, {"term": "adaptation finance", "ipa": "/ˌædæpˈteɪʃən ˈfaɪnæns/", "pron": "ad-ap-TAY-shuhn FY-nans", "fr": "financement de l’adaptation", "def": "Funding specifically for adaptation measures.", "ex": "Adaptation finance can support flood defences and drought-resistant farming."}, {"term": "humanitarian aid", "ipa": "/hjuːˌmænɪˈteəriən eɪd/", "pron": "hyoo-man-i-TAIR-ee-uhn aid", "fr": "aide humanitaire", "def": "Emergency assistance for people in crisis.", "ex": "Humanitarian aid is essential after climate disasters."}, {"term": "humanitarian crisis", "ipa": "/hjuːˌmænɪˈteəriən ˈkraɪsɪs/", "pron": "hyoo-man-i-TAIR-ee-uhn KRY-sis", "fr": "crise humanitaire", "def": "A crisis causing major human suffering and requiring urgent help.", "ex": "Climate disasters can trigger humanitarian crises."}, {"term": "disaster response", "ipa": "/dɪˈzɑːstə rɪˌspɒns/", "pron": "di-ZAH-stuh ri-SPONS", "fr": "réponse aux catastrophes", "def": "Actions taken immediately after a disaster.", "ex": "Disaster response includes evacuation, shelter and medical care."}, {"term": "emergency shelter", "ipa": "/ɪˈmɜːdʒənsi ˈʃeltə/", "pron": "i-MUR-juhn-see SHEL-tuh", "fr": "abri d’urgence", "def": "Temporary shelter provided during or after a crisis.", "ex": "Emergency shelter is needed after floods and storms."}, {"term": "climate security", "ipa": "/ˈklaɪmət sɪˌkjʊərəti/", "pron": "KLY-muht si-KYOOR-uh-tee", "fr": "sécurité climatique", "def": "The links between climate change and security risks.", "ex": "Climate security debates can overstate migration as a threat."}, {"term": "securitisation of migration", "ipa": "/sɪˌkjʊərɪtaɪˈzeɪʃən əv maɪˈɡreɪʃən/", "pron": "si-kyoor-i-ty-ZAY-shuhn ov my-GRAY-shuhn", "fr": "sécuritisation de la migration", "def": "Framing migration mainly as a security threat.", "ex": "The securitisation of migration can undermine human rights."}, {"term": "xenophobia", "ipa": "/ˌzenəˈfəʊbiə/", "pron": "ZEN-uh-FOH-bee-uh", "fr": "xénophobie", "def": "Hostility towards foreigners or migrants.", "ex": "Climate migration narratives can fuel xenophobia if handled badly."}, {"term": "solidarity", "ipa": "/ˌsɒlɪˈdærəti/", "pron": "sol-i-DAR-uh-tee", "fr": "solidarité", "def": "Support and shared responsibility between people or groups.", "ex": "Climate justice requires international solidarity."}, {"term": "burden-sharing", "ipa": "/ˈbɜːdən ˌʃeərɪŋ/", "pron": "BUR-duhn SHARE-ing", "fr": "partage du fardeau", "def": "Fair distribution of responsibility or costs among states or groups.", "ex": "Climate migration requires burden-sharing between countries."}, {"term": "common but differentiated responsibilities", "ipa": "/ˌkɒmən bət ˌdɪfərenʃieɪtɪd rɪˌspɒnsəˈbɪlətiz/", "pron": "KOM-uhn but dif-uh-REN-shee-ay-tid ri-spon-suh-BIL-uh-teez", "fr": "responsabilités communes mais différenciées", "def": "Principle that all states have responsibilities, but richer/high-emitting countries bear more.", "ex": "This principle is central to climate justice debates."}, {"term": "historical responsibility", "ipa": "/hɪˌstɒrɪkəl rɪˌspɒnsəˈbɪləti/", "pron": "his-TOR-i-kuhl ri-spon-suh-BIL-uh-tee", "fr": "responsabilité historique", "def": "Responsibility based on past emissions or actions.", "ex": "Historical responsibility shapes debates about climate finance."}, {"term": "to flee a climate disaster", "ipa": "/fliː ə ˈklaɪmət dɪˌzɑːstə/", "pron": "flee uh KLY-muht di-ZAH-stuh", "fr": "fuir une catastrophe climatique", "def": "To escape from a climate-related disaster.", "ex": "Families may flee a climate disaster with little warning."}, {"term": "to be displaced by flooding", "ipa": "/bi dɪsˈpleɪst baɪ ˈflʌdɪŋ/", "pron": "bee dis-PLAYST by FLUD-ing", "fr": "être déplacé par des inondations", "def": "To be forced to leave home because of floods.", "ex": "Thousands were displaced by flooding."}, {"term": "to relocate communities", "ipa": "/ˌriːləʊˈkeɪt kəˈmjuːnətiz/", "pron": "ree-loh-KAYT kuh-MYOO-nuh-teez", "fr": "relocaliser des communautés", "def": "To move communities to safer places.", "ex": "Governments may need to relocate communities from eroding coasts."}, {"term": "to lose one’s livelihood", "ipa": "/luːz wʌnz ˈlaɪvlihʊd/", "pron": "looz wunz LYVE-lee-hood", "fr": "perdre ses moyens de subsistance", "def": "To lose the means of earning a living.", "ex": "Farmers may lose their livelihood after repeated droughts."}, {"term": "to adapt in place", "ipa": "/əˈdæpt ɪn pleɪs/", "pron": "uh-DAPT in place", "fr": "s’adapter sur place", "def": "To adjust to climate impacts without moving away.", "ex": "Some communities prefer to adapt in place rather than relocate."}, {"term": "to build resilience", "ipa": "/bɪld rɪˈzɪliəns/", "pron": "bild ri-ZIL-ee-uhns", "fr": "renforcer la résilience", "def": "To strengthen the ability to withstand shocks.", "ex": "Investment can build resilience before disasters strike."}, {"term": "to reduce vulnerability", "ipa": "/rɪˈdjuːs ˌvʌlnərəˈbɪləti/", "pron": "ri-DYOOSS vul-nuh-ruh-BIL-uh-tee", "fr": "réduire la vulnérabilité", "def": "To make people or places less exposed to harm.", "ex": "Social protection can reduce vulnerability."}, {"term": "to create a protection gap", "ipa": "/kriˈeɪt ə prəˈtekʃən ɡæp/", "pron": "kree-AYT uh pruh-TEK-shuhn gap", "fr": "créer une lacune de protection", "def": "To leave people without adequate legal or social protection.", "ex": "Current law can create a protection gap for climate migrants."}, {"term": "to grant legal status", "ipa": "/ɡrɑːnt ˈliːɡəl ˈsteɪtəs/", "pron": "grant LEE-guhl STAY-tuhs", "fr": "accorder un statut juridique", "def": "To officially recognise someone’s legal position or rights.", "ex": "Some argue that climate migrants should be granted legal status."}, {"term": "to fund adaptation", "ipa": "/fʌnd ˌædæpˈteɪʃən/", "pron": "fund ad-ap-TAY-shuhn", "fr": "financer l’adaptation", "def": "To provide money for adaptation measures.", "ex": "Rich countries are urged to fund adaptation."}, {"term": "to prevent forced displacement", "ipa": "/prɪˈvent ˌfɔːst dɪsˈpleɪsmənt/", "pron": "pri-VENT forst dis-PLAYS-muhnt", "fr": "prévenir les déplacements forcés", "def": "To stop people being forced to leave their homes.", "ex": "Adaptation can prevent forced displacement."}, {"term": "to manage migration humanely", "ipa": "/ˈmænɪdʒ maɪˈɡreɪʃən hjuːˈmeɪnli/", "pron": "MAN-ij my-GRAY-shuhn hyoo-MAYN-lee", "fr": "gérer la migration humainement", "def": "To handle migration with respect for dignity and rights.", "ex": "States must manage migration humanely."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p9c74", "part": 9, "chapter": 74, "title": "Journalism", "file": "cpge_vocab_part9_chapter74_journalism_premium.html", "count": 126, "sections": [{"title": "A. Core journalism and media vocabulary", "entries": [{"term": "journalism", "ipa": "/ˈdʒɜːnəlɪzəm/", "pron": "JUR-nuh-liz-uhm", "fr": "journalisme", "def": "The work of collecting, verifying, writing and publishing news for the public.", "ex": "Journalism is essential to democratic accountability."}, {"term": "journalist", "ipa": "/ˈdʒɜːnəlɪst/", "pron": "JUR-nuh-list", "fr": "journaliste", "def": "A person who researches, writes or reports news stories.", "ex": "A journalist must verify information before publication."}, {"term": "reporter", "ipa": "/rɪˈpɔːtə/", "pron": "ri-POR-tuh", "fr": "reporter", "def": "A journalist who gathers and reports news, often from the scene.", "ex": "The reporter interviewed witnesses after the flood."}, {"term": "correspondent", "ipa": "/ˌkɒrəˈspɒndənt/", "pron": "kor-uh-SPON-duhnt", "fr": "correspondant", "def": "A journalist reporting from a particular place or on a specific topic.", "ex": "The foreign correspondent reported from Washington."}, {"term": "editor", "ipa": "/ˈedɪtə/", "pron": "ED-i-tuh", "fr": "rédacteur en chef ; éditeur", "def": "A person who selects, revises and approves material for publication.", "ex": "The editor decided to run the story."}, {"term": "newsroom", "ipa": "/ˈnjuːzruːm/", "pron": "NYOOZ-room", "fr": "rédaction", "def": "The place or team where journalists produce news.", "ex": "The newsroom worked through the night."}, {"term": "press", "ipa": "/pres/", "pron": "press", "fr": "presse", "def": "Newspapers, journalists and news organisations collectively.", "ex": "The press scrutinises those in power."}, {"term": "media outlet", "ipa": "/ˈmiːdiə ˌaʊtlet/", "pron": "MEE-dee-uh OUT-let", "fr": "média ; organe de presse", "def": "A newspaper, website, TV channel or radio station publishing news.", "ex": "Different media outlets framed the story differently."}, {"term": "legacy media", "ipa": "/ˈleɡəsi ˌmiːdiə/", "pron": "LEG-uh-see MEE-dee-uh", "fr": "médias traditionnels", "def": "Traditional media organisations such as newspapers, TV and radio.", "ex": "Legacy media face competition from digital platforms."}, {"term": "mainstream media", "ipa": "/ˈmeɪnstriːm ˌmiːdiə/", "pron": "MAYN-streem MEE-dee-uh", "fr": "grands médias ; médias dominants", "def": "Large, widely recognised media organisations.", "ex": "Mainstream media are often accused of bias."}, {"term": "independent media", "ipa": "/ˌɪndɪˈpendənt ˈmiːdiə/", "pron": "in-di-PEN-duhnt MEE-dee-uh", "fr": "médias indépendants", "def": "Media organisations not controlled by governments or major corporate interests.", "ex": "Independent media can expose corruption."}, {"term": "public service broadcasting", "ipa": "/ˌpʌblɪk ˈsɜːvɪs ˈbrɔːdkɑːstɪŋ/", "pron": "PUB-lik SUR-vis BROD-kast-ing", "fr": "audiovisuel public", "def": "Broadcasting intended to serve the public interest rather than profit alone.", "ex": "Public service broadcasting aims to inform citizens."}, {"term": "tabloid", "ipa": "/ˈtæblɔɪd/", "pron": "TAB-loyd", "fr": "tabloïd", "def": "A newspaper or style of journalism using sensational stories.", "ex": "Tabloids often focus on scandals."}, {"term": "broadsheet", "ipa": "/ˈbrɔːdʃiːt/", "pron": "BROD-sheet", "fr": "journal de référence", "def": "A serious newspaper traditionally printed on large pages.", "ex": "Broadsheets usually provide detailed political analysis."}, {"term": "digital journalism", "ipa": "/ˈdɪdʒɪtəl ˌdʒɜːnəlɪzəm/", "pron": "DIJ-i-tuhl JUR-nuh-liz-uhm", "fr": "journalisme numérique", "def": "Journalism produced and distributed online.", "ex": "Digital journalism allows rapid updates."}, {"term": "breaking news", "ipa": "/ˌbreɪkɪŋ ˈnjuːz/", "pron": "BRAY-king NYOOZ", "fr": "information de dernière minute", "def": "Newly received information about an important event.", "ex": "Breaking news can be fast but incomplete."}, {"term": "headline", "ipa": "/ˈhedlaɪn/", "pron": "HED-lyne", "fr": "titre", "def": "The title of a news story.", "ex": "A misleading headline can distort the article."}, {"term": "lead", "ipa": "/liːd/", "pron": "leed", "fr": "attaque ; introduction d’article", "def": "The opening sentence or paragraph of a news story.", "ex": "A good lead gives the key facts immediately."}, {"term": "byline", "ipa": "/ˈbaɪlaɪn/", "pron": "BY-lyne", "fr": "signature d’un article", "def": "The line naming the journalist who wrote an article.", "ex": "The byline identified the investigative reporter."}, {"term": "front page", "ipa": "/ˌfrʌnt ˈpeɪdʒ/", "pron": "front payj", "fr": "une ; première page", "def": "The first page of a newspaper, featuring major stories.", "ex": "The scandal made the front page."}, {"term": "scoop", "ipa": "/skuːp/", "pron": "skoop", "fr": "scoop", "def": "An exclusive news story published before competitors.", "ex": "The newspaper got a scoop."}, {"term": "exclusive", "ipa": "/ɪkˈskluːsɪv/", "pron": "ik-SKLOO-siv", "fr": "exclusivité", "def": "A story or interview obtained by one media outlet only.", "ex": "The interview was an exclusive."}, {"term": "source", "ipa": "/sɔːs/", "pron": "sorss", "fr": "source", "def": "A person, document or organisation providing information to journalists.", "ex": "Journalists must protect sensitive sources."}, {"term": "anonymous source", "ipa": "/əˌnɒnɪməs ˈsɔːs/", "pron": "uh-NON-i-muhs sorss", "fr": "source anonyme", "def": "A source whose identity is not revealed.", "ex": "Anonymous sources must be handled carefully."}, {"term": "whistleblower", "ipa": "/ˈwɪsəlˌbləʊə/", "pron": "WIS-uhl-bloh-uh", "fr": "lanceur d’alerte", "def": "A person who exposes wrongdoing inside an organisation.", "ex": "Whistleblowers often rely on journalists."}, {"term": "leak", "ipa": "/liːk/", "pron": "leek", "fr": "fuite", "def": "Secret information given to the press without official permission.", "ex": "The leak embarrassed the government."}, {"term": "leaked document", "ipa": "/ˌliːkt ˈdɒkjʊmənt/", "pron": "leekt DOK-yuh-muhnt", "fr": "document divulgué", "def": "A confidential document released to journalists or the public.", "ex": "The leaked document contradicted the minister."}, {"term": "press release", "ipa": "/ˈpres rɪˌliːs/", "pron": "press ri-LEESS", "fr": "communiqué de presse", "def": "An official statement sent to journalists by an organisation.", "ex": "The company issued a press release."}, {"term": "press conference", "ipa": "/ˈpres ˌkɒnfərəns/", "pron": "press KON-fuh-ruhns", "fr": "conférence de presse", "def": "A meeting where officials answer journalists’ questions.", "ex": "The prime minister held a press conference."}, {"term": "interview", "ipa": "/ˈɪntəvjuː/", "pron": "IN-tuh-vyoo", "fr": "interview ; entretien", "def": "A conversation in which a journalist asks questions to obtain information.", "ex": "The interview revealed contradictions."}, {"term": "eyewitness account", "ipa": "/ˈaɪˌwɪtnəs əˌkaʊnt/", "pron": "EYE-wit-nuhs uh-KOWNT", "fr": "témoignage oculaire", "def": "A description of an event by someone who saw it.", "ex": "Eyewitness accounts can be powerful but unreliable."}, {"term": "fact-checking", "ipa": "/ˈfækt ˌtʃekɪŋ/", "pron": "FAKT-chek-ing", "fr": "vérification des faits", "def": "The process of verifying claims, facts and statements.", "ex": "Fact-checking is crucial during elections."}, {"term": "verification", "ipa": "/ˌverɪfɪˈkeɪʃən/", "pron": "ver-i-fi-KAY-shuhn", "fr": "vérification", "def": "The process of confirming whether information is true or accurate.", "ex": "Verification prevents rumours from becoming news."}, {"term": "corroboration", "ipa": "/kəˌrɒbəˈreɪʃən/", "pron": "kuh-rob-uh-RAY-shuhn", "fr": "corroboration", "def": "Evidence from another source confirming information.", "ex": "A serious allegation needs corroboration."}, {"term": "evidence", "ipa": "/ˈevɪdəns/", "pron": "EV-i-duhns", "fr": "preuves ; éléments probants", "def": "Information or material supporting a claim.", "ex": "The article presented documentary evidence."}]}, {"title": "B. Verification, ethics and journalistic formats", "entries": [{"term": "accuracy", "ipa": "/ˈækjʊrəsi/", "pron": "AK-yuh-ruh-see", "fr": "exactitude", "def": "The quality of being correct and reliable.", "ex": "Accuracy matters more than speed."}, {"term": "reliability", "ipa": "/rɪˌlaɪəˈbɪləti/", "pron": "ri-ly-uh-BIL-uh-tee", "fr": "fiabilité", "def": "The quality of being trustworthy and dependable.", "ex": "The reliability of the source was questioned."}, {"term": "credibility", "ipa": "/ˌkredəˈbɪləti/", "pron": "kred-uh-BIL-uh-tee", "fr": "crédibilité", "def": "The quality of being believable and trusted.", "ex": "Credibility is a journalist’s most valuable asset."}, {"term": "transparency", "ipa": "/trænˈspærənsi/", "pron": "tran-SPARR-uhn-see", "fr": "transparence", "def": "Openness about methods, sources or interests.", "ex": "Transparency can build trust with readers."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "Responsibility for actions and decisions.", "ex": "Journalism holds powerful people accountable."}, {"term": "public interest", "ipa": "/ˌpʌblɪk ˈɪntrəst/", "pron": "PUB-lik IN-truhst", "fr": "intérêt public", "def": "What benefits society or citizens, especially in democratic debate.", "ex": "Publishing the information was justified by public interest."}, {"term": "watchdog journalism", "ipa": "/ˈwɒtʃdɒɡ ˌdʒɜːnəlɪzəm/", "pron": "WATCH-dog JUR-nuh-liz-uhm", "fr": "journalisme de surveillance ; contre-pouvoir", "def": "Journalism that monitors power and exposes wrongdoing.", "ex": "Watchdog journalism is vital in a democracy."}, {"term": "investigative journalism", "ipa": "/ɪnˈvestɪɡətɪv ˌdʒɜːnəlɪzəm/", "pron": "in-VES-ti-guh-tiv JUR-nuh-liz-uhm", "fr": "journalisme d’investigation", "def": "In-depth reporting that uncovers hidden information or wrongdoing.", "ex": "Investigative journalism can take months."}, {"term": "data journalism", "ipa": "/ˈdeɪtə ˌdʒɜːnəlɪzəm/", "pron": "DAY-tuh JUR-nuh-liz-uhm", "fr": "journalisme de données", "def": "Journalism using data analysis to find and explain stories.", "ex": "Data journalism can reveal hidden patterns."}, {"term": "solutions journalism", "ipa": "/səˈluːʃənz ˌdʒɜːnəlɪzəm/", "pron": "suh-LOO-shuhnz JUR-nuh-liz-uhm", "fr": "journalisme de solutions", "def": "Journalism that reports on responses to social problems.", "ex": "Solutions journalism avoids pure doom."}, {"term": "explanatory journalism", "ipa": "/ɪkˈsplænətəri ˌdʒɜːnəlɪzəm/", "pron": "ik-SPLAN-uh-tuh-ree JUR-nuh-liz-uhm", "fr": "journalisme explicatif", "def": "Journalism that explains complex issues clearly.", "ex": "Explanatory journalism helps readers understand policy."}, {"term": "long-form journalism", "ipa": "/ˈlɒŋ fɔːm ˌdʒɜːnəlɪzəm/", "pron": "long-form JUR-nuh-liz-uhm", "fr": "journalisme long format", "def": "Extended, detailed journalism often using narrative techniques.", "ex": "Long-form journalism gives space for nuance."}, {"term": "opinion piece", "ipa": "/əˈpɪnjən piːs/", "pron": "uh-PIN-yuhn peess", "fr": "tribune ; article d’opinion", "def": "An article expressing a personal or institutional viewpoint.", "ex": "An opinion piece should not be confused with news."}, {"term": "editorial", "ipa": "/ˌedɪˈtɔːriəl/", "pron": "ed-i-TOR-ee-uhl", "fr": "éditorial", "def": "An article expressing the official view of a publication.", "ex": "The editorial criticised the government."}, {"term": "column", "ipa": "/ˈkɒləm/", "pron": "KOL-uhm", "fr": "chronique", "def": "A regular opinion article written by the same journalist or commentator.", "ex": "The columnist writes a weekly column."}, {"term": "feature article", "ipa": "/ˈfiːtʃər ˌɑːtɪkəl/", "pron": "FEE-chuh AR-ti-kuhl", "fr": "article de fond", "def": "A longer article focusing on context, people or analysis.", "ex": "The feature article explored rural poverty."}, {"term": "profile", "ipa": "/ˈprəʊfaɪl/", "pron": "PROH-fyle", "fr": "portrait", "def": "An article describing a person in depth.", "ex": "The profile examined the billionaire’s influence."}, {"term": "news report", "ipa": "/ˈnjuːz rɪˌpɔːt/", "pron": "NYOOZ ri-PORT", "fr": "reportage ; article d’information", "def": "A factual account of a news event.", "ex": "A news report should separate fact from opinion."}, {"term": "analysis", "ipa": "/əˈnæləsɪs/", "pron": "uh-NAL-uh-sis", "fr": "analyse", "def": "A piece explaining causes, consequences or meaning of events.", "ex": "The analysis placed the election in context."}, {"term": "commentary", "ipa": "/ˈkɒməntəri/", "pron": "KOM-uhn-tuh-ree", "fr": "commentaire", "def": "Opinion or interpretation of events.", "ex": "Commentary should be clearly labelled."}, {"term": "editorial line", "ipa": "/ˌedɪˈtɔːriəl laɪn/", "pron": "ed-i-TOR-ee-uhl lyne", "fr": "ligne éditoriale", "def": "The general political or ideological orientation of a publication.", "ex": "The newspaper’s editorial line is centre-left."}, {"term": "angle", "ipa": "/ˈæŋɡəl/", "pron": "ANG-guhl", "fr": "angle", "def": "The perspective or focus chosen for a story.", "ex": "The journalist chose a human-interest angle."}, {"term": "framing", "ipa": "/ˈfreɪmɪŋ/", "pron": "FRAY-ming", "fr": "cadrage", "def": "The way information is presented, shaping interpretation.", "ex": "Framing can influence how readers understand migration."}, {"term": "narrative", "ipa": "/ˈnærətɪv/", "pron": "NARR-uh-tiv", "fr": "récit ; narration", "def": "A storyline or interpretation used to make sense of events.", "ex": "Political narratives shape news coverage."}, {"term": "spin", "ipa": "/spɪn/", "pron": "spin", "fr": "présentation orientée ; spin", "def": "A biased presentation of information to influence public perception.", "ex": "Politicians use spin to control damaging stories."}, {"term": "bias", "ipa": "/ˈbaɪəs/", "pron": "BY-uhs", "fr": "biais", "def": "A tendency to favour one side or perspective unfairly.", "ex": "Media bias can appear in word choice."}, {"term": "political bias", "ipa": "/pəˌlɪtɪkəl ˈbaɪəs/", "pron": "puh-LIT-i-kuhl BY-uhs", "fr": "biais politique", "def": "Bias linked to political opinions or interests.", "ex": "The outlet was accused of political bias."}, {"term": "confirmation bias", "ipa": "/ˌkɒnfəˈmeɪʃən ˈbaɪəs/", "pron": "kon-fuh-MAY-shuhn BY-uhs", "fr": "biais de confirmation", "def": "The tendency to accept information that confirms existing beliefs.", "ex": "Confirmation bias affects audiences and journalists."}, {"term": "false balance", "ipa": "/ˌfɔːls ˈbæləns/", "pron": "false BAL-uhns", "fr": "faux équilibre", "def": "Giving equal weight to positions not equally supported by evidence.", "ex": "False balance once distorted climate reporting."}, {"term": "sensationalism", "ipa": "/senˈseɪʃənəlɪzəm/", "pron": "sen-SAY-shuhn-uh-liz-uhm", "fr": "sensationnalisme", "def": "Presenting stories in an exaggerated way to attract attention.", "ex": "Sensationalism can undermine trust."}, {"term": "clickbait", "ipa": "/ˈklɪkbeɪt/", "pron": "KLIK-bayt", "fr": "piège à clics", "def": "Online content with a misleading or exaggerated title designed to attract clicks.", "ex": "Clickbait rewards curiosity rather than understanding."}, {"term": "outrage bait", "ipa": "/ˈaʊtreɪdʒ beɪt/", "pron": "OWT-rayj bayt", "fr": "contenu conçu pour provoquer l’indignation", "def": "Content designed to provoke anger and engagement.", "ex": "Outrage bait spreads quickly on social media."}, {"term": "infotainment", "ipa": "/ˌɪnfəʊˈteɪnmənt/", "pron": "IN-foh-TAYN-muhnt", "fr": "infodivertissement", "def": "Media content mixing information and entertainment.", "ex": "Infotainment can make politics feel like a show."}, {"term": "human-interest story", "ipa": "/ˌhjuːmən ˈɪntrəst ˌstɔːri/", "pron": "HYOO-muhn IN-truhst STOR-ee", "fr": "article à dimension humaine", "def": "A story focusing on personal experience and emotion.", "ex": "Human-interest stories make abstract issues relatable."}, {"term": "agenda-setting", "ipa": "/əˈdʒendə ˌsetɪŋ/", "pron": "uh-JEN-duh SET-ing", "fr": "mise à l’agenda", "def": "The media’s ability to influence which issues people consider important.", "ex": "Agenda-setting gives media political power."}, {"term": "gatekeeping", "ipa": "/ˈɡeɪtˌkiːpɪŋ/", "pron": "GAYT-kee-ping", "fr": "filtrage de l’information", "def": "The process of deciding which information is published or excluded.", "ex": "Editors perform gatekeeping every day."}, {"term": "newsworthiness", "ipa": "/ˈnjuːzˌwɜːðinəs/", "pron": "NYOOZ-wur-thee-nuhs", "fr": "valeur journalistique", "def": "The quality of being important or interesting enough to be reported.", "ex": "Conflict and novelty increase newsworthiness."}, {"term": "news cycle", "ipa": "/ˈnjuːz ˌsaɪkəl/", "pron": "NYOOZ SY-kuhl", "fr": "cycle de l’information", "def": "The period during which a story dominates media coverage.", "ex": "The news cycle pressures journalists to publish quickly."}, {"term": "media storm", "ipa": "/ˈmiːdiə stɔːm/", "pron": "MEE-dee-uh storm", "fr": "tempête médiatique", "def": "Intense media attention and controversy.", "ex": "The minister resigned after a media storm."}, {"term": "trial by media", "ipa": "/ˌtraɪəl baɪ ˈmiːdiə/", "pron": "TRY-uhl by MEE-dee-uh", "fr": "procès médiatique", "def": "Public judgement of someone through media coverage before legal judgement.", "ex": "Trial by media can damage the presumption of innocence."}, {"term": "right of reply", "ipa": "/ˌraɪt əv rɪˈplaɪ/", "pron": "right ov ri-PLY", "fr": "droit de réponse", "def": "The right to respond to criticism or allegations in the media.", "ex": "The newspaper offered a right of reply."}]}, {"title": "C. Bias, framing, news values and media effects", "entries": [{"term": "correction", "ipa": "/kəˈrekʃən/", "pron": "kuh-REK-shuhn", "fr": "rectificatif ; correction", "def": "A notice fixing an error in published material.", "ex": "The paper issued a correction."}, {"term": "retraction", "ipa": "/rɪˈtrækʃən/", "pron": "ri-TRAK-shuhn", "fr": "rétractation", "def": "Withdrawal of a published story or claim.", "ex": "A retraction may be necessary after serious errors."}, {"term": "media ethics", "ipa": "/ˈmiːdiə ˌeθɪks/", "pron": "MEE-dee-uh ETH-iks", "fr": "éthique des médias", "def": "Moral principles guiding journalism and media practice.", "ex": "Media ethics includes accuracy, privacy and fairness."}, {"term": "journalistic ethics", "ipa": "/ˌdʒɜːnəlɪstɪk ˈeθɪks/", "pron": "JUR-nuh-lis-tik ETH-iks", "fr": "déontologie journalistique", "def": "Professional ethics guiding journalists.", "ex": "Journalistic ethics require independence."}, {"term": "conflict of interest", "ipa": "/ˌkɒnflɪkt əv ˈɪntrəst/", "pron": "KON-flikt ov IN-truhst", "fr": "conflit d’intérêts", "def": "A situation where personal or financial interests may affect judgement.", "ex": "Journalists must disclose conflicts of interest."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "The right to keep personal life or information private.", "ex": "Journalists must balance privacy with public interest."}, {"term": "invasion of privacy", "ipa": "/ɪnˌveɪʒən əv ˈprɪvəsi/", "pron": "in-VAY-zhuhn ov PRIV-uh-see", "fr": "atteinte à la vie privée", "def": "Unjustified intrusion into someone’s private life.", "ex": "Celebrity reporting can become invasion of privacy."}, {"term": "defamation", "ipa": "/ˌdefəˈmeɪʃən/", "pron": "def-uh-MAY-shuhn", "fr": "diffamation", "def": "False statements damaging someone’s reputation.", "ex": "Defamation laws can protect reputations."}, {"term": "libel", "ipa": "/ˈlaɪbəl/", "pron": "LY-buhl", "fr": "diffamation écrite", "def": "Written defamation.", "ex": "The newspaper faced a libel lawsuit."}, {"term": "slander", "ipa": "/ˈslɑːndə/", "pron": "SLAN-duh", "fr": "diffamation orale", "def": "Spoken defamation.", "ex": "Slander can occur in broadcast interviews."}, {"term": "presumption of innocence", "ipa": "/prɪˌzʌmpʃən əv ˈɪnəsəns/", "pron": "pri-ZUMP-shuhn ov IN-uh-suhns", "fr": "présomption d’innocence", "def": "The principle that someone is considered innocent until proven guilty.", "ex": "Journalists should respect the presumption of innocence."}, {"term": "freedom of the press", "ipa": "/ˌfriːdəm əv ðə ˈpres/", "pron": "FREE-duhm ov thuh press", "fr": "liberté de la presse", "def": "The right of media to report without censorship or undue interference.", "ex": "Freedom of the press is a cornerstone of democracy."}, {"term": "press freedom", "ipa": "/ˈpres ˌfriːdəm/", "pron": "press FREE-duhm", "fr": "liberté de la presse", "def": "Freedom of journalists and media organisations to report news.", "ex": "Press freedom is under pressure in many countries."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of information by authorities or institutions.", "ex": "Censorship prevents citizens from accessing information."}, {"term": "self-censorship", "ipa": "/ˌself ˈsensəʃɪp/", "pron": "self SEN-suh-ship", "fr": "autocensure", "def": "Avoiding publication because of fear, pressure or internal restraint.", "ex": "Threats can lead to self-censorship."}, {"term": "chilling effect", "ipa": "/ˈtʃɪlɪŋ ɪˌfekt/", "pron": "CHIL-ing i-FEKT", "fr": "effet dissuasif", "def": "When people avoid lawful expression because of fear of consequences.", "ex": "Aggressive lawsuits can have a chilling effect."}, {"term": "press intimidation", "ipa": "/ˈpres ɪnˌtɪmɪˈdeɪʃən/", "pron": "press in-tim-i-DAY-shuhn", "fr": "intimidation de la presse", "def": "Threats or pressure used to silence journalists.", "ex": "Press intimidation undermines democracy."}, {"term": "media capture", "ipa": "/ˈmiːdiə ˌkæptʃə/", "pron": "MEE-dee-uh KAP-chuh", "fr": "capture des médias", "def": "Control or influence of media by political or economic interests.", "ex": "Media capture reduces independence."}, {"term": "state media", "ipa": "/ˌsteɪt ˈmiːdiə/", "pron": "state MEE-dee-uh", "fr": "médias d’État", "def": "Media owned or controlled by the state.", "ex": "State media can become propaganda tools."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Information designed to influence people, often biased or misleading.", "ex": "Propaganda shapes public opinion."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information spread deliberately to deceive.", "ex": "Disinformation campaigns target elections."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending to deceive.", "ex": "Misinformation spreads quickly during crises."}, {"term": "malinformation", "ipa": "/ˌmælɪnfəˈmeɪʃən/", "pron": "mal-in-fuh-MAY-shuhn", "fr": "information malveillante", "def": "True information used maliciously or out of context to cause harm.", "ex": "Leaked private data can become malinformation."}, {"term": "deepfake", "ipa": "/ˈdiːpfeɪk/", "pron": "DEEP-fayk", "fr": "hypertrucage ; deepfake", "def": "AI-generated fake audio, video or image designed to look real.", "ex": "Deepfakes make verification harder."}, {"term": "information disorder", "ipa": "/ˌɪnfəˈmeɪʃən dɪsˌɔːdə/", "pron": "in-fuh-MAY-shuhn dis-OR-duh", "fr": "désordre informationnel", "def": "The ecosystem of misinformation, disinformation and malinformation.", "ex": "Information disorder damages trust in journalism."}, {"term": "echo chamber", "ipa": "/ˈekəʊ ˌtʃeɪmbə/", "pron": "EK-oh CHAYM-buh", "fr": "chambre d’écho", "def": "An environment where people mostly encounter views they already agree with.", "ex": "Social media can create echo chambers."}, {"term": "filter bubble", "ipa": "/ˈfɪltə ˌbʌbəl/", "pron": "FIL-tuh BUH-buhl", "fr": "bulle de filtres", "def": "Personalised online environment limiting exposure to diverse viewpoints.", "ex": "Algorithms can trap users in filter bubbles."}, {"term": "algorithmic amplification", "ipa": "/ˌælɡəˈrɪðmɪk ˌæmplɪfɪˈkeɪʃən/", "pron": "al-guh-RITH-mik am-pli-fi-KAY-shuhn", "fr": "amplification algorithmique", "def": "The process by which algorithms make certain content more visible.", "ex": "Algorithmic amplification can reward outrage."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération des contenus", "def": "Rules and actions used by platforms to manage user content.", "ex": "Content moderation raises free speech questions."}, {"term": "paywall", "ipa": "/ˈpeɪwɔːl/", "pron": "PAY-wall", "fr": "mur payant ; paywall", "def": "A system requiring payment to access online content.", "ex": "Paywalls can fund journalism but restrict access."}, {"term": "subscription model", "ipa": "/səbˈskrɪpʃən ˌmɒdəl/", "pron": "suhb-SKRIP-shuhn MOD-uhl", "fr": "modèle par abonnement", "def": "A business model where users pay regularly for content.", "ex": "The subscription model helped some newspapers survive."}, {"term": "advertising revenue", "ipa": "/ˈædvətaɪzɪŋ ˈrevənjuː/", "pron": "AD-vuh-ty-zing REV-uhn-yoo", "fr": "recettes publicitaires", "def": "Money earned from selling advertising space.", "ex": "Advertising revenue moved from newspapers to platforms."}, {"term": "media ownership", "ipa": "/ˈmiːdiə ˈəʊnəʃɪp/", "pron": "MEE-dee-uh OH-nuh-ship", "fr": "propriété des médias", "def": "Who owns and controls media organisations.", "ex": "Media ownership affects independence."}, {"term": "media concentration", "ipa": "/ˈmiːdiə ˌkɒnsənˈtreɪʃən/", "pron": "MEE-dee-uh kon-suhn-TRAY-shuhn", "fr": "concentration des médias", "def": "Control of many media outlets by a small number of owners.", "ex": "Media concentration can reduce pluralism."}, {"term": "editorial independence", "ipa": "/ˌedɪˈtɔːriəl ˌɪndɪˈpendəns/", "pron": "ed-i-TOR-ee-uhl in-di-PEN-duhns", "fr": "indépendance éditoriale", "def": "Freedom from owners, advertisers or political pressure.", "ex": "Editorial independence protects credibility."}]}, {"title": "D. Press freedom, disinformation and media business models", "entries": [{"term": "to report on an issue", "ipa": "/rɪˈpɔːt ɒn ən ˈɪʃuː/", "pron": "ri-PORT on uhn ISH-oo", "fr": "traiter d’un sujet ; couvrir un sujet", "def": "To cover or write about a topic.", "ex": "Journalists report on issues that affect citizens."}, {"term": "to cover a story", "ipa": "/ˈkʌvə ə ˈstɔːri/", "pron": "KUV-uh uh STOR-ee", "fr": "couvrir une histoire / un sujet", "def": "To report on a news event or topic.", "ex": "The newspaper covered the strike extensively."}, {"term": "to break a story", "ipa": "/breɪk ə ˈstɔːri/", "pron": "brayk uh STOR-ee", "fr": "révéler une affaire", "def": "To be the first to publish important news.", "ex": "The outlet broke the story before its rivals."}, {"term": "to verify information", "ipa": "/ˈverɪfaɪ ˌɪnfəˈmeɪʃən/", "pron": "VER-i-fy in-fuh-MAY-shuhn", "fr": "vérifier l’information", "def": "To check whether information is accurate.", "ex": "Journalists must verify information before publishing."}, {"term": "to fact-check a claim", "ipa": "/ˈfækt tʃek ə kleɪm/", "pron": "FAKT-chek uh klaym", "fr": "vérifier une affirmation", "def": "To test whether a statement is true.", "ex": "The team fact-checked the minister’s claim."}, {"term": "to protect a source", "ipa": "/prəˈtekt ə ˈsɔːs/", "pron": "pruh-TEKT uh sorss", "fr": "protéger une source", "def": "To keep a source safe or anonymous.", "ex": "Investigative journalists protect sources."}, {"term": "to expose wrongdoing", "ipa": "/ɪkˈspəʊz ˈrɒŋˌduːɪŋ/", "pron": "ik-SPOHZ RONG-doo-ing", "fr": "révéler des méfaits", "def": "To reveal illegal, unethical or harmful behaviour.", "ex": "Watchdog journalism exposes wrongdoing."}, {"term": "to hold power to account", "ipa": "/həʊld ˈpaʊə tʊ əˈkaʊnt/", "pron": "hohld POW-uh too uh-KOWNT", "fr": "demander des comptes au pouvoir", "def": "To make powerful people answer for their actions.", "ex": "Journalism should hold power to account."}, {"term": "to shape public opinion", "ipa": "/ʃeɪp ˌpʌblɪk əˈpɪnjən/", "pron": "shayp PUB-lik uh-PIN-yuhn", "fr": "façonner l’opinion publique", "def": "To influence what the public thinks.", "ex": "Media framing can shape public opinion."}, {"term": "to frame a debate", "ipa": "/freɪm ə dɪˈbeɪt/", "pron": "fraym uh di-BAYT", "fr": "cadrer un débat", "def": "To present an issue in a way that influences discussion.", "ex": "Headlines can frame a debate."}, {"term": "to issue a correction", "ipa": "/ˈɪʃuː ə kəˈrekʃən/", "pron": "ISH-oo uh kuh-REK-shuhn", "fr": "publier un rectificatif", "def": "To publish a notice correcting an error.", "ex": "Responsible outlets issue corrections quickly."}, {"term": "to undermine trust", "ipa": "/ˌʌndəˈmaɪn trʌst/", "pron": "UN-duh-myne trust", "fr": "saper la confiance", "def": "To weaken confidence or credibility.", "ex": "Sensationalism can undermine trust."}, {"term": "to censor the press", "ipa": "/ˈsensə ðə pres/", "pron": "SEN-suh thuh press", "fr": "censurer la presse", "def": "To suppress or control news reporting.", "ex": "Authoritarian governments may censor the press."}, {"term": "to spread disinformation", "ipa": "/spred ˌdɪsɪnfəˈmeɪʃən/", "pron": "spred dis-in-fuh-MAY-shuhn", "fr": "diffuser de la désinformation", "def": "To deliberately distribute false information.", "ex": "Disinformation campaigns spread disinformation online."}, {"term": "to monetise attention", "ipa": "/ˈmʌnɪtaɪz əˈtenʃən/", "pron": "MUN-i-tyze uh-TEN-shuhn", "fr": "monétiser l’attention", "def": "To make money from attracting and keeping people’s attention.", "ex": "Platforms monetise attention through advertising."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p9c75", "part": 9, "chapter": 75, "title": "Fake News", "file": "cpge_vocab_part9_chapter75_fake_news_premium.html", "count": 101, "sections": [{"title": "A. Core fake news and information disorder vocabulary", "entries": [{"term": "fake news", "ipa": "/ˌfeɪk ˈnjuːz/", "pron": "fayk NYOOZ", "fr": "fausses nouvelles ; infox", "def": "False or misleading information presented as news.", "ex": "Fake news can spread faster than corrections."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending to deceive.", "ex": "Misinformation spreads quickly during crises."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to deceive or manipulate.", "ex": "Disinformation campaigns can target elections."}, {"term": "malinformation", "ipa": "/ˌmælɪnfəˈmeɪʃən/", "pron": "mal-in-fuh-MAY-shuhn", "fr": "information malveillante", "def": "True information used maliciously or out of context to harm someone.", "ex": "Leaked private data can become malinformation."}, {"term": "information disorder", "ipa": "/ˌɪnfəˈmeɪʃən dɪsˌɔːdə/", "pron": "in-fuh-MAY-shuhn dis-OR-duh", "fr": "désordre informationnel", "def": "The ecosystem of false, misleading or harmful information.", "ex": "Information disorder weakens democratic debate."}, {"term": "rumour", "ipa": "/ˈruːmə/", "pron": "ROO-muh", "fr": "rumeur", "def": "Unverified information circulating among people.", "ex": "Rumours often spread after disasters."}, {"term": "hoax", "ipa": "/həʊks/", "pron": "hohks", "fr": "canular", "def": "A deliberately fabricated story designed to trick people.", "ex": "The viral story turned out to be a hoax."}, {"term": "fabrication", "ipa": "/ˌfæbrɪˈkeɪʃən/", "pron": "fab-ri-KAY-shuhn", "fr": "invention ; fabrication", "def": "Something invented rather than based on fact.", "ex": "The article was a complete fabrication."}, {"term": "false claim", "ipa": "/ˌfɔːls ˈkleɪm/", "pron": "false klaym", "fr": "affirmation fausse", "def": "An assertion that is not true.", "ex": "The politician repeated a false claim."}, {"term": "misleading claim", "ipa": "/ˌmɪsˈliːdɪŋ kleɪm/", "pron": "mis-LEE-ding klaym", "fr": "affirmation trompeuse", "def": "A claim that gives a false impression.", "ex": "A true statistic can still be misleading."}, {"term": "baseless claim", "ipa": "/ˌbeɪsləs ˈkleɪm/", "pron": "BAYSS-luhs klaym", "fr": "affirmation sans fondement", "def": "A claim with no evidence.", "ex": "Baseless claims can influence voters."}, {"term": "unverified claim", "ipa": "/ʌnˌverɪfaɪd ˈkleɪm/", "pron": "un-VER-i-fyd klaym", "fr": "affirmation non vérifiée", "def": "A claim that has not been checked or confirmed.", "ex": "Unverified claims should be labelled clearly."}, {"term": "conspiracy theory", "ipa": "/kənˈspɪrəsi ˌθɪəri/", "pron": "kuhn-SPIR-uh-see THEE-uh-ree", "fr": "théorie du complot", "def": "A belief that hidden groups secretly control events, often without evidence.", "ex": "Conspiracy theories flourish when trust is low."}, {"term": "conspiracist", "ipa": "/kənˈspɪrəsɪst/", "pron": "kuhn-SPIR-uh-sist", "fr": "complotiste", "def": "A person who believes or spreads conspiracy theories.", "ex": "Conspiracists often reject mainstream evidence."}, {"term": "denialism", "ipa": "/dɪˈnaɪəlɪzəm/", "pron": "di-NY-uh-liz-uhm", "fr": "déni organisé", "def": "The rejection of established facts or scientific consensus.", "ex": "Denialism can delay public action."}, {"term": "climate denial", "ipa": "/ˈklaɪmət dɪˌnaɪəl/", "pron": "KLY-muht di-NY-uhl", "fr": "déni climatique", "def": "Rejection of well-established climate science.", "ex": "Climate denial has slowed policy responses."}, {"term": "science denial", "ipa": "/ˈsaɪəns dɪˌnaɪəl/", "pron": "SY-uhns di-NY-uhl", "fr": "déni de la science", "def": "Rejection of scientific evidence or consensus.", "ex": "Science denial can be politically profitable."}, {"term": "health misinformation", "ipa": "/ˈhelθ ˌmɪsɪnfəˈmeɪʃən/", "pron": "health mis-in-fuh-MAY-shuhn", "fr": "mésinformation sanitaire", "def": "False or inaccurate health-related information.", "ex": "Health misinformation can put lives at risk."}, {"term": "anti-vaccine misinformation", "ipa": "/ˌænti ˈvæksiːn ˌmɪsɪnfəˈmeɪʃən/", "pron": "AN-tee VAK-seen mis-in-fuh-MAY-shuhn", "fr": "désinformation antivaccin", "def": "False or misleading information about vaccines.", "ex": "Anti-vaccine misinformation undermines public health."}, {"term": "election misinformation", "ipa": "/ɪˈlekʃən ˌmɪsɪnfəˈmeɪʃən/", "pron": "i-LEK-shuhn mis-in-fuh-MAY-shuhn", "fr": "mésinformation électorale", "def": "False or misleading information about elections or voting.", "ex": "Election misinformation can suppress turnout."}, {"term": "propaganda", "ipa": "/ˌprɒpəˈɡændə/", "pron": "prop-uh-GAN-duh", "fr": "propagande", "def": "Information designed to influence people, often biased or misleading.", "ex": "Propaganda can be used by states or political groups."}, {"term": "state propaganda", "ipa": "/ˌsteɪt ˌprɒpəˈɡændə/", "pron": "state prop-uh-GAN-duh", "fr": "propagande d’État", "def": "Propaganda produced or promoted by a government.", "ex": "State propaganda can justify repression."}, {"term": "influence operation", "ipa": "/ˈɪnfluəns ˌɒpəˈreɪʃən/", "pron": "IN-floo-uhns op-uh-RAY-shuhn", "fr": "opération d’influence", "def": "A coordinated attempt to shape public opinion covertly.", "ex": "Influence operations can target elections."}, {"term": "information warfare", "ipa": "/ˌɪnfəˈmeɪʃən ˈwɔːfeə/", "pron": "in-fuh-MAY-shuhn WOR-fair", "fr": "guerre informationnelle", "def": "The strategic use of information to disrupt or weaken opponents.", "ex": "Information warfare is part of modern conflict."}, {"term": "troll", "ipa": "/trɒl/", "pron": "trol", "fr": "troll", "def": "A person or account posting inflammatory content to provoke or disrupt.", "ex": "Trolls try to derail online debate."}, {"term": "troll farm", "ipa": "/ˈtrɒl fɑːm/", "pron": "trol farm", "fr": "usine à trolls", "def": "An organised group producing manipulative online comments or posts.", "ex": "Troll farms can amplify propaganda."}, {"term": "bot", "ipa": "/bɒt/", "pron": "bot", "fr": "bot", "def": "An automated account or program posting online content.", "ex": "Bots can boost hashtags artificially."}, {"term": "bot network", "ipa": "/ˈbɒt ˌnetwɜːk/", "pron": "bot NET-work", "fr": "réseau de bots", "def": "A coordinated group of automated accounts.", "ex": "A bot network can make a fringe idea appear popular."}]}, {"title": "B. Digital manipulation, bias and viral dynamics", "entries": [{"term": "sock puppet account", "ipa": "/ˈsɒk ˌpʌpɪt əˌkaʊnt/", "pron": "sok PUP-it uh-kownt", "fr": "faux compte", "def": "A fake online identity used to deceive or manipulate.", "ex": "Sock puppet accounts can fake grassroots support."}, {"term": "astroturfing", "ipa": "/ˈæstrəʊˌtɜːfɪŋ/", "pron": "AS-troh-TURF-ing", "fr": "faux mouvement citoyen", "def": "Fake grassroots campaigning designed to look spontaneous.", "ex": "Astroturfing hides who is behind a campaign."}, {"term": "deepfake", "ipa": "/ˈdiːpfeɪk/", "pron": "DEEP-fayk", "fr": "hypertrucage ; deepfake", "def": "AI-generated fake audio, video or image designed to look real.", "ex": "Deepfakes make visual evidence harder to trust."}, {"term": "synthetic media", "ipa": "/sɪnˌθetɪk ˈmiːdiə/", "pron": "sin-THET-ik MEE-dee-uh", "fr": "média synthétique", "def": "Media generated or manipulated by artificial intelligence.", "ex": "Synthetic media can be creative or deceptive."}, {"term": "cheapfake", "ipa": "/ˈtʃiːpfeɪk/", "pron": "CHEEP-fayk", "fr": "faux contenu manipulé simplement", "def": "Low-tech manipulated media, such as misleadingly edited video.", "ex": "Cheapfakes can be persuasive."}, {"term": "doctored image", "ipa": "/ˌdɒktəd ˈɪmɪdʒ/", "pron": "DOK-tuhd IM-ij", "fr": "image truquée", "def": "An image altered to deceive.", "ex": "A doctored image went viral."}, {"term": "manipulated video", "ipa": "/məˌnɪpjʊleɪtɪd ˈvɪdiəʊ/", "pron": "muh-NIP-yuh-lay-tid VID-ee-oh", "fr": "vidéo manipulée", "def": "A video edited or altered to mislead viewers.", "ex": "Manipulated videos can distort what someone said."}, {"term": "out-of-context clip", "ipa": "/ˌaʊt əv ˈkɒntekst klɪp/", "pron": "out-ov-KON-tekst klip", "fr": "extrait sorti de son contexte", "def": "A short extract presented without necessary context.", "ex": "Out-of-context clips can damage reputations."}, {"term": "cherry-picking", "ipa": "/ˈtʃeri ˌpɪkɪŋ/", "pron": "CHERR-ee PIK-ing", "fr": "sélection biaisée des données", "def": "Selecting only evidence that supports one’s argument.", "ex": "Cherry-picking statistics misleads readers."}, {"term": "misleading statistics", "ipa": "/ˌmɪsˈliːdɪŋ stəˈtɪstɪks/", "pron": "mis-LEE-ding stuh-TIS-tiks", "fr": "statistiques trompeuses", "def": "Statistics presented in a way that creates a false impression.", "ex": "Misleading statistics can distort a debate."}, {"term": "false equivalence", "ipa": "/ˌfɔːls ɪˈkwɪvələns/", "pron": "false i-KWIV-uh-luhns", "fr": "fausse équivalence", "def": "Treating two things as equal when they are not comparable.", "ex": "False equivalence can distort political debate."}, {"term": "false balance", "ipa": "/ˌfɔːls ˈbæləns/", "pron": "false BAL-uhns", "fr": "faux équilibre", "def": "Giving equal weight to unequal evidence or positions.", "ex": "False balance can make fringe claims appear credible."}, {"term": "confirmation bias", "ipa": "/ˌkɒnfəˈmeɪʃən ˈbaɪəs/", "pron": "kon-fuh-MAY-shuhn BY-uhs", "fr": "biais de confirmation", "def": "The tendency to accept information that confirms existing beliefs.", "ex": "Confirmation bias helps fake news spread."}, {"term": "cognitive bias", "ipa": "/ˌkɒɡnɪtɪv ˈbaɪəs/", "pron": "KOG-ni-tiv BY-uhs", "fr": "biais cognitif", "def": "A systematic pattern of thinking that can distort judgement.", "ex": "Cognitive bias makes people vulnerable to manipulation."}, {"term": "motivated reasoning", "ipa": "/ˌməʊtɪveɪtɪd ˈriːzənɪŋ/", "pron": "MOH-ti-vay-tid REE-zuh-ning", "fr": "raisonnement motivé", "def": "Reasoning shaped by what someone wants to believe.", "ex": "Motivated reasoning makes corrections less effective."}, {"term": "illusory truth effect", "ipa": "/ɪˌluːsəri ˈtruːθ ɪˌfekt/", "pron": "i-LOO-suh-ree trooth i-FEKT", "fr": "effet de vérité illusoire", "def": "The tendency to believe repeated claims are true.", "ex": "Repeated lies can start to feel true."}, {"term": "emotional manipulation", "ipa": "/ɪˌməʊʃənəl məˌnɪpjʊˈleɪʃən/", "pron": "i-MOH-shuhn-uhl muh-nip-yuh-LAY-shuhn", "fr": "manipulation émotionnelle", "def": "Using emotions to influence belief or behaviour deceptively.", "ex": "Fake news often relies on emotional manipulation."}, {"term": "fearmongering", "ipa": "/ˈfɪəmʌŋɡərɪŋ/", "pron": "FEER-mung-guh-ring", "fr": "exploitation de la peur", "def": "Spreading frightening claims to influence people.", "ex": "Fearmongering can drive clicks and votes."}, {"term": "outrage bait", "ipa": "/ˈaʊtreɪdʒ beɪt/", "pron": "OWT-rayj bayt", "fr": "contenu conçu pour provoquer l’indignation", "def": "Content designed to provoke anger and engagement.", "ex": "Outrage bait performs well online."}, {"term": "clickbait", "ipa": "/ˈklɪkbeɪt/", "pron": "KLIK-bayt", "fr": "piège à clics", "def": "Misleading or exaggerated content designed to attract clicks.", "ex": "Clickbait rewards attention rather than accuracy."}, {"term": "viral content", "ipa": "/ˈvaɪrəl ˈkɒntent/", "pron": "VY-ruhl KON-tent", "fr": "contenu viral", "def": "Content that spreads rapidly online.", "ex": "Viral content is not necessarily reliable."}, {"term": "virality", "ipa": "/vaɪˈræləti/", "pron": "vy-RAL-uh-tee", "fr": "viralisation", "def": "The quality of spreading rapidly online.", "ex": "Virality can reward shock over truth."}, {"term": "algorithm", "ipa": "/ˈælɡərɪðəm/", "pron": "AL-guh-rith-uhm", "fr": "algorithme", "def": "A set of rules used by platforms to rank or recommend content.", "ex": "Algorithms influence what people see online."}, {"term": "algorithmic amplification", "ipa": "/ˌælɡəˈrɪðmɪk ˌæmplɪfɪˈkeɪʃən/", "pron": "al-guh-RITH-mik am-pli-fi-KAY-shuhn", "fr": "amplification algorithmique", "def": "The process by which algorithms make certain content more visible.", "ex": "Algorithmic amplification can reward outrage."}, {"term": "recommendation system", "ipa": "/ˌrekəmenˈdeɪʃən ˈsɪstəm/", "pron": "rek-uh-men-DAY-shuhn SIS-tuhm", "fr": "système de recommandation", "def": "An algorithm suggesting content to users.", "ex": "Recommendation systems can push extreme content."}, {"term": "engagement", "ipa": "/ɪnˈɡeɪdʒmənt/", "pron": "in-GAYJ-muhnt", "fr": "engagement", "def": "User interaction such as clicks, likes, comments and shares.", "ex": "Platforms often optimise for engagement."}, {"term": "attention economy", "ipa": "/əˈtenʃən iˌkɒnəmi/", "pron": "uh-TEN-shuhn i-KON-uh-mee", "fr": "économie de l’attention", "def": "An economy where human attention is captured and monetised.", "ex": "Fake news thrives in the attention economy."}, {"term": "echo chamber", "ipa": "/ˈekəʊ ˌtʃeɪmbə/", "pron": "EK-oh CHAYM-buh", "fr": "chambre d’écho", "def": "A space where people mostly hear views they already agree with.", "ex": "Echo chambers can radicalise opinions."}, {"term": "filter bubble", "ipa": "/ˈfɪltə ˌbʌbəl/", "pron": "FIL-tuh BUH-buhl", "fr": "bulle de filtres", "def": "A personalised online environment limiting exposure to diverse views.", "ex": "Filter bubbles can narrow understanding."}, {"term": "polarisation", "ipa": "/ˌpəʊləraɪˈzeɪʃən/", "pron": "poh-luh-ry-ZAY-shuhn", "fr": "polarisation", "def": "Growing division between opposing groups or views.", "ex": "Misinformation can deepen polarisation."}, {"term": "trust deficit", "ipa": "/ˈtrʌst ˌdefɪsɪt/", "pron": "trust DEF-i-sit", "fr": "déficit de confiance", "def": "A lack of trust in institutions, media or experts.", "ex": "Fake news exploits a trust deficit."}, {"term": "media literacy", "ipa": "/ˈmiːdiə ˌlɪtərəsi/", "pron": "MEE-dee-uh LIT-uh-ruh-see", "fr": "éducation aux médias", "def": "The ability to understand and evaluate media critically.", "ex": "Media literacy helps citizens resist manipulation."}, {"term": "digital literacy", "ipa": "/ˈdɪdʒɪtəl ˌlɪtərəsi/", "pron": "DIJ-i-tuhl LIT-uh-ruh-see", "fr": "littératie numérique", "def": "The ability to use and evaluate digital information effectively.", "ex": "Digital literacy is crucial online."}]}, {"title": "C. Media literacy, verification and fact-checking", "entries": [{"term": "critical thinking", "ipa": "/ˌkrɪtɪkəl ˈθɪŋkɪŋ/", "pron": "KRIT-i-kuhl THINK-ing", "fr": "esprit critique", "def": "The ability to analyse information carefully and logically.", "ex": "Critical thinking is a defence against fake news."}, {"term": "source evaluation", "ipa": "/ˈsɔːs ɪˌvæljʊˈeɪʃən/", "pron": "sorss i-val-yoo-AY-shuhn", "fr": "évaluation des sources", "def": "Assessing whether a source is reliable and relevant.", "ex": "Source evaluation should be taught in schools."}, {"term": "fact-checking", "ipa": "/ˈfækt ˌtʃekɪŋ/", "pron": "FAKT-chek-ing", "fr": "vérification des faits", "def": "The process of checking whether claims are true.", "ex": "Fact-checking can slow misinformation."}, {"term": "fact-checker", "ipa": "/ˈfækt ˌtʃekə/", "pron": "FAKT-chek-uh", "fr": "vérificateur des faits", "def": "A person or organisation that verifies claims.", "ex": "Fact-checkers rated the claim as false."}, {"term": "debunking", "ipa": "/ˌdiːˈbʌŋkɪŋ/", "pron": "dee-BUNK-ing", "fr": "réfutation", "def": "Showing that a claim is false or misleading.", "ex": "Debunking works best when it is clear and timely."}, {"term": "prebunking", "ipa": "/ˌpriːˈbʌŋkɪŋ/", "pron": "pree-BUNK-ing", "fr": "pré-réfutation", "def": "Warning people about manipulation techniques before they encounter them.", "ex": "Prebunking can build resistance to disinformation."}, {"term": "verification", "ipa": "/ˌverɪfɪˈkeɪʃən/", "pron": "ver-i-fi-KAY-shuhn", "fr": "vérification", "def": "Confirming whether information is accurate or authentic.", "ex": "Verification is essential before sharing news."}, {"term": "reverse image search", "ipa": "/rɪˌvɜːs ˈɪmɪdʒ sɜːtʃ/", "pron": "ri-VURS IM-ij surch", "fr": "recherche d’image inversée", "def": "Searching an image online to find its origin or earlier uses.", "ex": "Reverse image search can expose old images reused as new."}, {"term": "metadata", "ipa": "/ˈmetəˌdeɪtə/", "pron": "MET-uh-DAY-tuh", "fr": "métadonnées", "def": "Data giving information about a file, image or document.", "ex": "Metadata can help verify a photo."}, {"term": "geolocation", "ipa": "/ˌdʒiːəʊləʊˈkeɪʃən/", "pron": "jee-oh-loh-KAY-shuhn", "fr": "géolocalisation", "def": "Identifying the real-world location of an image, video or device.", "ex": "Geolocation helps verify war footage."}, {"term": "OSINT", "ipa": "/ˌəʊ es aɪ en ˈtiː/", "pron": "oh-ess-eye-en-tee", "fr": "OSINT ; renseignement de sources ouvertes", "def": "Open-source intelligence gathered from publicly available sources.", "ex": "OSINT investigators analyse videos and satellite images."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération des contenus", "def": "Rules and actions used by platforms to manage user content.", "ex": "Content moderation is politically controversial."}, {"term": "platform accountability", "ipa": "/ˈplætfɔːm əˌkaʊntəˈbɪləti/", "pron": "PLAT-form uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des plateformes", "def": "Responsibility of digital platforms for online harms.", "ex": "Platform accountability is central to disinformation debates."}, {"term": "content removal", "ipa": "/ˈkɒntent rɪˌmuːvəl/", "pron": "KON-tent ri-MOO-vuhl", "fr": "suppression de contenu", "def": "Deleting or taking down online content.", "ex": "Content removal can reduce harm but raises concerns."}, {"term": "deplatforming", "ipa": "/ˌdiːˈplætfɔːmɪŋ/", "pron": "dee-PLAT-form-ing", "fr": "déplateformisation", "def": "Removing someone from a platform or denying them an audience.", "ex": "Deplatforming can limit extremist reach."}, {"term": "labelling", "ipa": "/ˈleɪbəlɪŋ/", "pron": "LAY-buhl-ing", "fr": "étiquetage", "def": "Adding a warning or context label to online content.", "ex": "Labelling can warn users about disputed claims."}, {"term": "warning label", "ipa": "/ˈwɔːnɪŋ ˌleɪbəl/", "pron": "WOR-ning LAY-buhl", "fr": "avertissement", "def": "A label warning users about misleading or harmful content.", "ex": "Warning labels can reduce sharing."}, {"term": "transparency report", "ipa": "/trænˈspærənsi rɪˌpɔːt/", "pron": "tran-SPARR-uhn-see ri-PORT", "fr": "rapport de transparence", "def": "A report explaining platform moderation and enforcement.", "ex": "Transparency reports help researchers."}]}, {"title": "D. Regulation, free speech and democratic consequences", "entries": [{"term": "regulation", "ipa": "/ˌreɡjʊˈleɪʃən/", "pron": "reg-yuh-LAY-shuhn", "fr": "réglementation", "def": "Rules made by authorities to control platforms or behaviour.", "ex": "Regulation must balance safety and free speech."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of information.", "ex": "Anti-fake-news laws can become censorship tools."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "The right to express opinions without undue censorship.", "ex": "Free speech is often invoked in moderation debates."}, {"term": "freedom of expression", "ipa": "/ˌfriːdəm əv ɪkˈspreʃən/", "pron": "FREE-duhm ov ik-SPRESH-uhn", "fr": "liberté d’expression", "def": "The right to express ideas and information.", "ex": "Freedom of expression is not absolute."}, {"term": "chilling effect", "ipa": "/ˈtʃɪlɪŋ ɪˌfekt/", "pron": "CHIL-ing i-FEKT", "fr": "effet dissuasif", "def": "When people avoid lawful expression because of fear of consequences.", "ex": "Overbroad regulation can create a chilling effect."}, {"term": "public sphere", "ipa": "/ˌpʌblɪk ˈsfɪə/", "pron": "PUB-lik sfeer", "fr": "espace public", "def": "The space where citizens discuss public issues.", "ex": "Fake news pollutes the public sphere."}, {"term": "democratic debate", "ipa": "/ˌdeməˈkrætɪk dɪˈbeɪt/", "pron": "dem-uh-KRAT-ik di-BAYT", "fr": "débat démocratique", "def": "Open discussion necessary for democracy.", "ex": "Disinformation damages democratic debate."}, {"term": "post-truth politics", "ipa": "/ˌpəʊst truːθ ˈpɒlətɪks/", "pron": "post-trooth POL-uh-tiks", "fr": "politique post-vérité", "def": "Politics where emotions and beliefs matter more than facts.", "ex": "Post-truth politics rewards simple narratives."}, {"term": "truth decay", "ipa": "/ˈtruːθ dɪˌkeɪ/", "pron": "trooth di-KAY", "fr": "érosion de la vérité", "def": "The erosion of agreement about facts and evidence.", "ex": "Truth decay weakens democratic institutions."}, {"term": "information ecosystem", "ipa": "/ˌɪnfəˈmeɪʃən ˈiːkəʊˌsɪstəm/", "pron": "in-fuh-MAY-shuhn EE-koh-SIS-tuhm", "fr": "écosystème informationnel", "def": "The network of sources, platforms and audiences through which information circulates.", "ex": "The information ecosystem has become fragmented."}, {"term": "to spread fake news", "ipa": "/spred ˌfeɪk ˈnjuːz/", "pron": "spred fayk NYOOZ", "fr": "diffuser des fausses nouvelles", "def": "To circulate false information presented as news.", "ex": "Fake accounts spread fake news."}, {"term": "to debunk a rumour", "ipa": "/ˌdiːˈbʌŋk ə ˈruːmə/", "pron": "dee-BUNK uh ROO-muh", "fr": "réfuter une rumeur", "def": "To show that a rumour is false.", "ex": "Fact-checkers debunked the rumour."}, {"term": "to verify a source", "ipa": "/ˈverɪfaɪ ə ˈsɔːs/", "pron": "VER-i-fy uh sorss", "fr": "vérifier une source", "def": "To check whether a source is reliable or authentic.", "ex": "Students should verify a source before citing it."}, {"term": "to fact-check a claim", "ipa": "/ˈfækt tʃek ə kleɪm/", "pron": "FAKT-chek uh klaym", "fr": "vérifier une affirmation", "def": "To check whether a statement is true.", "ex": "Journalists fact-check claims by politicians."}, {"term": "to manipulate public opinion", "ipa": "/məˈnɪpjʊleɪt ˌpʌblɪk əˈpɪnjən/", "pron": "muh-NIP-yuh-layt PUB-lik uh-PIN-yuhn", "fr": "manipuler l’opinion publique", "def": "To influence people deceptively.", "ex": "Disinformation can manipulate public opinion."}, {"term": "to amplify a false claim", "ipa": "/ˈæmplɪfaɪ ə ˌfɔːls ˈkleɪm/", "pron": "AM-pli-fy uh false klaym", "fr": "amplifier une fausse affirmation", "def": "To make a false claim more visible.", "ex": "Algorithms can amplify a false claim."}, {"term": "to go viral", "ipa": "/ɡəʊ ˈvaɪrəl/", "pron": "goh VY-ruhl", "fr": "devenir viral", "def": "To spread rapidly online.", "ex": "The misleading video went viral."}, {"term": "to sow distrust", "ipa": "/səʊ dɪsˈtrʌst/", "pron": "soh dis-TRUST", "fr": "semer la méfiance", "def": "To create suspicion and reduce trust.", "ex": "Propaganda aims to sow distrust."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "to undermine democracy", "ipa": "/ˌʌndəˈmaɪn dɪˈmɒkrəsi/", "pron": "UN-duh-myne di-MOK-ruh-see", "fr": "affaiblir la démocratie", "def": "To weaken democratic institutions or debate.", "ex": "Fake news can undermine democracy."}, {"term": "to regulate online platforms", "ipa": "/ˈreɡjʊleɪt ˌɒnlaɪn ˈplætfɔːmz/", "pron": "REG-yuh-layt ON-lyne PLAT-formz", "fr": "réglementer les plateformes en ligne", "def": "To create rules governing digital platforms.", "ex": "Governments are trying to regulate online platforms."}, {"term": "to protect free speech", "ipa": "/prəˈtekt ˌfriː ˈspiːtʃ/", "pron": "pruh-TEKT free speech", "fr": "protéger la liberté d’expression", "def": "To defend the right to express ideas.", "ex": "Laws must protect free speech while fighting manipulation."}, {"term": "to rebuild trust", "ipa": "/ˌriːˈbɪld trʌst/", "pron": "ree-BILD trust", "fr": "rétablir la confiance", "def": "To restore confidence in institutions, media or information.", "ex": "Transparent journalism can rebuild trust."}]}]}, {"id": "p9c76", "part": 9, "chapter": 76, "title": "Freedom Of Speech", "file": "cpge_vocab_part9_chapter76_freedom_of_speech_premium.html", "count": 94, "sections": [{"title": "A. Core free speech and democratic principles", "entries": [{"term": "freedom of speech", "ipa": "/ˌfriːdəm əv ˈspiːtʃ/", "pron": "FREE-duhm ov SPEECH", "fr": "liberté d’expression", "def": "The right to express opinions and ideas without undue censorship or punishment.", "ex": "Freedom of speech is a cornerstone of liberal democracy."}, {"term": "free speech", "ipa": "/ˌfriː ˈspiːtʃ/", "pron": "free speech", "fr": "liberté d’expression", "def": "Short form for freedom of speech.", "ex": "Free speech debates often intensify on university campuses."}, {"term": "freedom of expression", "ipa": "/ˌfriːdəm əv ɪkˈspreʃən/", "pron": "FREE-duhm ov ik-SPRESH-uhn", "fr": "liberté d’expression", "def": "The right to express ideas, opinions, beliefs and information.", "ex": "Freedom of expression protects unpopular views as well as popular ones."}, {"term": "civil liberty", "ipa": "/ˌsɪvəl ˈlɪbəti/", "pron": "SIV-uhl LIB-uh-tee", "fr": "liberté civile", "def": "A basic freedom protected from excessive government interference.", "ex": "Free speech is a civil liberty."}, {"term": "civil liberties", "ipa": "/ˌsɪvəl ˈlɪbətiz/", "pron": "SIV-uhl LIB-uh-teez", "fr": "libertés civiles", "def": "Basic freedoms such as speech, assembly, religion and privacy.", "ex": "Civil liberties can be restricted during crises."}, {"term": "constitutional right", "ipa": "/ˌkɒnstɪˈtjuːʃənəl raɪt/", "pron": "kon-sti-TYOO-shuhn-uhl right", "fr": "droit constitutionnel", "def": "A right protected by a constitution.", "ex": "Freedom of speech is a constitutional right in many democracies."}, {"term": "fundamental right", "ipa": "/ˌfʌndəˈmentəl raɪt/", "pron": "fun-duh-MEN-tuhl right", "fr": "droit fondamental", "def": "A basic right considered essential to human dignity or democracy.", "ex": "Freedom of expression is often treated as a fundamental right."}, {"term": "human right", "ipa": "/ˌhjuːmən ˈraɪt/", "pron": "HYOO-muhn right", "fr": "droit humain", "def": "A basic right belonging to all people.", "ex": "Freedom of expression is recognised as a human right."}, {"term": "First Amendment", "ipa": "/ˌfɜːst əˈmendmənt/", "pron": "first uh-MEND-muhnt", "fr": "Premier amendement", "def": "The part of the US Constitution protecting speech, religion, press, assembly and petition.", "ex": "The First Amendment strongly protects political speech."}, {"term": "Article 10", "ipa": "/ˌɑːtɪkəl ˈten/", "pron": "AR-ti-kuhl ten", "fr": "article 10", "def": "Article of the European Convention on Human Rights protecting freedom of expression.", "ex": "Article 10 allows restrictions when they are necessary and proportionate."}, {"term": "public debate", "ipa": "/ˌpʌblɪk dɪˈbeɪt/", "pron": "PUB-lik di-BAYT", "fr": "débat public", "def": "Open discussion of issues that matter to society.", "ex": "Free speech enables public debate."}, {"term": "democratic debate", "ipa": "/ˌdeməˈkrætɪk dɪˈbeɪt/", "pron": "dem-uh-KRAT-ik di-BAYT", "fr": "débat démocratique", "def": "Discussion necessary for citizens to make democratic choices.", "ex": "Censorship can impoverish democratic debate."}, {"term": "marketplace of ideas", "ipa": "/ˈmɑːkɪtpleɪs əv aɪˈdɪəz/", "pron": "MAR-kit-place ov eye-DEE-uhz", "fr": "marché des idées", "def": "The idea that truth emerges from open competition between ideas.", "ex": "The marketplace of ideas is a classic defence of free speech."}, {"term": "pluralism", "ipa": "/ˈplʊərəlɪzəm/", "pron": "PLOOR-uh-liz-uhm", "fr": "pluralisme", "def": "The coexistence of diverse opinions, beliefs and groups.", "ex": "Pluralism is essential to democratic life."}, {"term": "dissent", "ipa": "/dɪˈsent/", "pron": "di-SENT", "fr": "dissidence ; désaccord", "def": "Public disagreement with official or dominant views.", "ex": "Free societies must protect dissent."}, {"term": "dissenter", "ipa": "/dɪˈsentə/", "pron": "di-SEN-tuh", "fr": "dissident", "def": "A person who publicly disagrees with an official or dominant view.", "ex": "Dissenters often test the limits of free speech."}, {"term": "minority opinion", "ipa": "/maɪˌnɒrəti əˈpɪnjən/", "pron": "my-NOR-uh-tee uh-PIN-yuhn", "fr": "opinion minoritaire", "def": "A view held by a smaller group of people.", "ex": "Minority opinions need protection from majority pressure."}, {"term": "unpopular opinion", "ipa": "/ʌnˌpɒpjʊlər əˈpɪnjən/", "pron": "un-POP-yuh-luh uh-PIN-yuhn", "fr": "opinion impopulaire", "def": "A view many people dislike or reject.", "ex": "Free speech matters most when opinions are unpopular."}, {"term": "offensive speech", "ipa": "/əˌfensɪv ˈspiːtʃ/", "pron": "uh-FEN-siv speech", "fr": "propos offensants", "def": "Speech that insults, shocks or upsets people.", "ex": "Offensive speech is not always illegal."}, {"term": "controversial speech", "ipa": "/ˌkɒntrəˈvɜːʃəl ˈspiːtʃ/", "pron": "kon-truh-VUR-shuhl speech", "fr": "propos controversés", "def": "Speech that causes strong disagreement.", "ex": "Universities often host controversial speech."}, {"term": "political speech", "ipa": "/pəˌlɪtɪkəl ˈspiːtʃ/", "pron": "puh-LIT-i-kuhl speech", "fr": "discours politique", "def": "Speech about politics, government or public affairs.", "ex": "Political speech receives strong protection."}, {"term": "artistic expression", "ipa": "/ɑːˌtɪstɪk ɪkˈspreʃən/", "pron": "ar-TIS-tik ik-SPRESH-uhn", "fr": "expression artistique", "def": "Expression through art, literature, music, theatre or film.", "ex": "Artistic expression may provoke controversy."}, {"term": "religious expression", "ipa": "/rɪˌlɪdʒəs ɪkˈspreʃən/", "pron": "ri-LIJ-uhs ik-SPRESH-uhn", "fr": "expression religieuse", "def": "Expression of religious belief or identity.", "ex": "Religious expression may conflict with secular norms."}, {"term": "academic freedom", "ipa": "/ˌækəˈdemɪk ˈfriːdəm/", "pron": "ak-uh-DEM-ik FREE-duhm", "fr": "liberté académique", "def": "The freedom of scholars to teach, research and debate without undue interference.", "ex": "Academic freedom protects controversial research."}, {"term": "campus speech", "ipa": "/ˈkæmpəs spiːtʃ/", "pron": "KAM-puhs speech", "fr": "expression sur les campus", "def": "Speech and debate taking place on university campuses.", "ex": "Campus speech has become politically contentious."}, {"term": "no-platforming", "ipa": "/ˌnəʊ ˈplætfɔːmɪŋ/", "pron": "noh-PLAT-form-ing", "fr": "refus de tribune ; déplateformisation", "def": "Refusing to give someone a platform to speak because their views are considered harmful.", "ex": "No-platforming is defended by some and criticised by others."}, {"term": "deplatforming", "ipa": "/ˌdiːˈplætfɔːmɪŋ/", "pron": "dee-PLAT-form-ing", "fr": "déplateformisation", "def": "Removing someone from a platform or denying them access to an audience.", "ex": "Deplatforming can reduce extremist reach but raises free speech concerns."}, {"term": "cancel culture", "ipa": "/ˈkænsəl ˌkʌltʃə/", "pron": "KAN-suhl KUL-chuh", "fr": "cancel culture ; culture de l’annulation", "def": "A contested term for public pressure to punish people for offensive or controversial behaviour.", "ex": "Cancel culture is often used as a political weapon in debates."}, {"term": "public shaming", "ipa": "/ˌpʌblɪk ˈʃeɪmɪŋ/", "pron": "PUB-lik SHAY-ming", "fr": "humiliation publique", "def": "Public criticism or humiliation of someone for perceived wrongdoing.", "ex": "Public shaming can silence people."}, {"term": "online mob", "ipa": "/ˌɒnlaɪn ˈmɒb/", "pron": "ON-lyne mob", "fr": "foule en ligne ; meute numérique", "def": "A large group attacking someone online.", "ex": "An online mob can destroy reputations quickly."}]}, {"title": "B. Censorship, harm, hate speech and legal limits", "entries": [{"term": "pile-on", "ipa": "/ˈpaɪl ɒn/", "pron": "PYLE-on", "fr": "déferlement de critiques", "def": "A wave of criticism or abuse directed at someone online.", "ex": "A pile-on can intimidate ordinary users."}, {"term": "chilling effect", "ipa": "/ˈtʃɪlɪŋ ɪˌfekt/", "pron": "CHIL-ing i-FEKT", "fr": "effet dissuasif", "def": "A situation where people avoid lawful expression because of fear of consequences.", "ex": "Fear of backlash can create a chilling effect."}, {"term": "self-censorship", "ipa": "/ˌself ˈsensəʃɪp/", "pron": "self SEN-suh-ship", "fr": "autocensure", "def": "Avoiding expression because of fear, pressure or social consequences.", "ex": "Self-censorship can be invisible but powerful."}, {"term": "censorship", "ipa": "/ˈsensəʃɪp/", "pron": "SEN-suh-ship", "fr": "censure", "def": "Suppression or control of speech, information or art.", "ex": "Censorship can be imposed by states or institutions."}, {"term": "state censorship", "ipa": "/ˌsteɪt ˈsensəʃɪp/", "pron": "state SEN-suh-ship", "fr": "censure d’État", "def": "Censorship imposed by government authorities.", "ex": "State censorship is common in authoritarian regimes."}, {"term": "speech restriction", "ipa": "/ˈspiːtʃ rɪˌstrɪkʃən/", "pron": "speech ri-STRIK-shuhn", "fr": "restriction de la parole", "def": "A rule limiting what can be said or expressed.", "ex": "Speech restrictions must be justified carefully."}, {"term": "proportionate restriction", "ipa": "/prəˈpɔːʃənət rɪˌstrɪkʃən/", "pron": "pruh-POR-shuh-nuht ri-STRIK-shuhn", "fr": "restriction proportionnée", "def": "A restriction that is limited and appropriate to the harm prevented.", "ex": "Human rights law often requires proportionate restrictions."}, {"term": "legitimate aim", "ipa": "/lɪˌdʒɪtɪmət ˈeɪm/", "pron": "li-JIT-i-muht aim", "fr": "objectif légitime", "def": "A valid public interest reason for limiting a right.", "ex": "Protecting national security can be a legitimate aim."}, {"term": "public order", "ipa": "/ˌpʌblɪk ˈɔːdə/", "pron": "PUB-lik OR-duh", "fr": "ordre public", "def": "Social peace and safety in public spaces.", "ex": "Public order is often invoked to limit demonstrations."}, {"term": "national security", "ipa": "/ˌnæʃənəl sɪˈkjʊərəti/", "pron": "NASH-uh-nuhl si-KYOOR-uh-tee", "fr": "sécurité nationale", "def": "The protection of a country from threats.", "ex": "National security can justify some secrecy."}, {"term": "incitement", "ipa": "/ɪnˈsaɪtmənt/", "pron": "in-SYTE-muhnt", "fr": "incitation", "def": "Encouraging others to commit violence, hatred or illegal acts.", "ex": "Incitement to violence is not protected in many legal systems."}, {"term": "incitement to violence", "ipa": "/ɪnˈsaɪtmənt tə ˈvaɪələns/", "pron": "in-SYTE-muhnt tuh VY-uh-luhns", "fr": "incitation à la violence", "def": "Speech encouraging people to commit violent acts.", "ex": "Incitement to violence can be criminalised."}, {"term": "hate speech", "ipa": "/ˈheɪt spiːtʃ/", "pron": "hayt speech", "fr": "discours de haine", "def": "Speech attacking people because of identity such as race, religion, gender or sexuality.", "ex": "Hate speech laws differ sharply between the US and Europe."}, {"term": "hateful rhetoric", "ipa": "/ˌheɪtfəl ˈretərɪk/", "pron": "HAYT-fuhl RET-uh-rik", "fr": "rhétorique haineuse", "def": "Language expressing or encouraging hostility towards a group.", "ex": "Hateful rhetoric can normalise discrimination."}, {"term": "harassment", "ipa": "/ˈhærəsmənt/", "pron": "HARR-uhs-muhnt", "fr": "harcèlement", "def": "Repeated behaviour intended to intimidate, humiliate or distress someone.", "ex": "Online harassment can silence women and minorities."}, {"term": "online harassment", "ipa": "/ˌɒnlaɪn ˈhærəsmənt/", "pron": "ON-lyne HARR-uhs-muhnt", "fr": "harcèlement en ligne", "def": "Harassment occurring through digital platforms.", "ex": "Online harassment is a major free speech issue."}, {"term": "threat", "ipa": "/θret/", "pron": "thret", "fr": "menace", "def": "A statement or action showing intent to harm someone.", "ex": "True threats may be punished by law."}, {"term": "defamation", "ipa": "/ˌdefəˈmeɪʃən/", "pron": "def-uh-MAY-shuhn", "fr": "diffamation", "def": "False statements damaging someone’s reputation.", "ex": "Defamation law can protect reputations but chill journalism."}, {"term": "libel", "ipa": "/ˈlaɪbəl/", "pron": "LY-buhl", "fr": "diffamation écrite", "def": "Written defamation.", "ex": "The newspaper faced a libel lawsuit."}, {"term": "privacy", "ipa": "/ˈprɪvəsi/", "pron": "PRIV-uh-see", "fr": "vie privée", "def": "The right to keep personal life and information private.", "ex": "Privacy may conflict with press freedom."}, {"term": "blasphemy", "ipa": "/ˈblæsfəmi/", "pron": "BLAS-fuh-mee", "fr": "blasphème", "def": "Speech or action considered insulting to religion or sacred things.", "ex": "Blasphemy remains a sensitive issue in free speech debates."}, {"term": "satire", "ipa": "/ˈsætaɪə/", "pron": "SAT-eye-uh", "fr": "satire", "def": "Humour or irony used to criticise people, politics or society.", "ex": "Satire often pushes the boundaries of acceptable speech."}, {"term": "parody", "ipa": "/ˈpærədi/", "pron": "PARR-uh-dee", "fr": "parodie", "def": "Imitation for humorous or critical effect.", "ex": "Parody is often protected as expression."}, {"term": "political cartoon", "ipa": "/pəˌlɪtɪkəl kɑːˈtuːn/", "pron": "puh-LIT-i-kuhl kar-TOON", "fr": "dessin politique", "def": "A cartoon commenting on politics or public affairs.", "ex": "Political cartoons are a classic form of free expression."}, {"term": "offence", "ipa": "/əˈfens/", "pron": "uh-FENS", "fr": "offense", "def": "The feeling of being insulted, upset or outraged.", "ex": "A right not to be offended would severely limit debate."}, {"term": "harm", "ipa": "/hɑːm/", "pron": "harm", "fr": "préjudice ; tort", "def": "Damage or injury caused to a person or group.", "ex": "Free speech debates often distinguish offence from harm."}, {"term": "harm principle", "ipa": "/ˈhɑːm ˌprɪnsəpəl/", "pron": "HARM PRIN-suh-puhl", "fr": "principe de non-nuisance", "def": "The idea that liberty should be limited only to prevent harm to others.", "ex": "The harm principle is often used to defend broad free speech."}, {"term": "dignity", "ipa": "/ˈdɪɡnəti/", "pron": "DIG-nuh-tee", "fr": "dignité", "def": "The inherent worth and respect owed to every person.", "ex": "Hate speech laws often invoke human dignity."}, {"term": "equality", "ipa": "/ɪˈkwɒləti/", "pron": "i-KWOL-uh-tee", "fr": "égalité", "def": "The principle that people should have equal rights and respect.", "ex": "Equality can sometimes conflict with unrestricted speech."}, {"term": "tolerance", "ipa": "/ˈtɒlərəns/", "pron": "TOL-uh-ruhns", "fr": "tolérance", "def": "Willingness to accept views or behaviour one dislikes.", "ex": "Free speech requires tolerance of disagreement."}, {"term": "safe space", "ipa": "/ˈseɪf speɪs/", "pron": "sayf spayss", "fr": "espace sûr", "def": "A place intended to protect people from hostility or discrimination.", "ex": "Critics argue that safe spaces can reduce open debate."}, {"term": "trigger warning", "ipa": "/ˈtrɪɡə ˌwɔːnɪŋ/", "pron": "TRIG-uh WOR-ning", "fr": "avertissement de contenu sensible", "def": "A notice warning that content may be distressing.", "ex": "Trigger warnings are debated in universities."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération des contenus", "def": "Rules and actions used by platforms to manage user content.", "ex": "Content moderation raises free speech questions."}, {"term": "community guidelines", "ipa": "/kəˌmjuːnəti ˈɡaɪdlaɪnz/", "pron": "kuh-MYOO-nuh-tee GYDE-lynes", "fr": "règles de communauté", "def": "Rules set by platforms for acceptable user behaviour.", "ex": "Community guidelines define what users may post."}, {"term": "terms of service", "ipa": "/ˌtɜːmz əv ˈsɜːvɪs/", "pron": "turmz ov SUR-vis", "fr": "conditions d’utilisation", "def": "Rules users accept when using a platform.", "ex": "Terms of service can restrict speech beyond the law."}]}, {"title": "C. Online speech, platforms and moderation", "entries": [{"term": "content removal", "ipa": "/ˈkɒntent rɪˌmuːvəl/", "pron": "KON-tent ri-MOO-vuhl", "fr": "suppression de contenu", "def": "Taking down online content.", "ex": "Content removal can reduce harm but fuel censorship claims."}, {"term": "account suspension", "ipa": "/əˈkaʊnt səˌspenʃən/", "pron": "uh-KOWNT suh-SPEN-shuhn", "fr": "suspension de compte", "def": "Temporary blocking of a user account.", "ex": "Account suspension is a common moderation tool."}, {"term": "permanent ban", "ipa": "/ˌpɜːmənənt ˈbæn/", "pron": "PUR-muh-nuhnt ban", "fr": "bannissement définitif", "def": "A lasting ban from a platform or space.", "ex": "A permanent ban can be controversial for public figures."}, {"term": "shadow banning", "ipa": "/ˈʃædəʊ ˌbænɪŋ/", "pron": "SHAD-oh BAN-ing", "fr": "bannissement furtif", "def": "Reducing visibility without clearly notifying the user.", "ex": "Shadow banning is hard to prove."}, {"term": "algorithmic moderation", "ipa": "/ˌælɡəˈrɪðmɪk ˌmɒdəˈreɪʃən/", "pron": "al-guh-RITH-mik mod-uh-RAY-shuhn", "fr": "modération algorithmique", "def": "Automated systems used to detect or limit content.", "ex": "Algorithmic moderation can make serious mistakes."}, {"term": "platform accountability", "ipa": "/ˈplætfɔːm əˌkaʊntəˈbɪləti/", "pron": "PLAT-form uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité des plateformes", "def": "Responsibility of platforms for speech-related harms and decisions.", "ex": "Platform accountability is central to online speech debates."}, {"term": "digital rights", "ipa": "/ˌdɪdʒɪtəl ˈraɪts/", "pron": "DIJ-i-tuhl rights", "fr": "droits numériques", "def": "Rights related to internet access, privacy and online expression.", "ex": "Digital rights groups monitor online censorship."}, {"term": "whistleblower", "ipa": "/ˈwɪsəlˌbləʊə/", "pron": "WIS-uhl-bloh-uh", "fr": "lanceur d’alerte", "def": "A person who exposes wrongdoing inside an organisation.", "ex": "Whistleblowers often need legal protection."}, {"term": "public interest disclosure", "ipa": "/ˌpʌblɪk ˈɪntrəst dɪsˌkləʊʒə/", "pron": "PUB-lik IN-truhst dis-KLOH-zhuh", "fr": "divulgation d’intérêt public", "def": "Revealing information because it serves the public interest.", "ex": "Public interest disclosure can expose corruption."}, {"term": "classified information", "ipa": "/ˌklæsɪfaɪd ˌɪnfəˈmeɪʃən/", "pron": "KLAS-i-fyd in-fuh-MAY-shuhn", "fr": "information classifiée", "def": "Official information kept secret for security reasons.", "ex": "Publishing classified information can create legal risks."}, {"term": "press freedom", "ipa": "/ˈpres ˌfriːdəm/", "pron": "press FREE-duhm", "fr": "liberté de la presse", "def": "The freedom of journalists and media organisations to report news.", "ex": "Press freedom protects democratic scrutiny."}, {"term": "source protection", "ipa": "/ˈsɔːs prəˌtekʃən/", "pron": "sorss pruh-TEK-shuhn", "fr": "protection des sources", "def": "Keeping journalistic sources confidential and safe.", "ex": "Source protection is essential for investigative journalism."}, {"term": "public interest defence", "ipa": "/ˌpʌblɪk ˈɪntrəst dɪˌfens/", "pron": "PUB-lik IN-truhst di-FENS", "fr": "défense fondée sur l’intérêt public", "def": "An argument that publication was justified because it served society.", "ex": "The public interest defence is vital in investigative reporting."}, {"term": "extremist speech", "ipa": "/ɪkˈstriːmɪst ˈspiːtʃ/", "pron": "ik-STREE-mist speech", "fr": "discours extrémiste", "def": "Speech promoting extreme political or religious views, sometimes violence.", "ex": "Extremist speech creates hard moderation dilemmas."}]}, {"title": "D. Press freedom, whistleblowing and contested harms", "entries": [{"term": "terrorist content", "ipa": "/ˈterərɪst ˈkɒntent/", "pron": "TERR-uh-rist KON-tent", "fr": "contenu terroriste", "def": "Content promoting, praising or instructing terrorism.", "ex": "Platforms are pressured to remove terrorist content quickly."}, {"term": "misinformation", "ipa": "/ˌmɪsɪnfəˈmeɪʃən/", "pron": "mis-in-fuh-MAY-shuhn", "fr": "mésinformation", "def": "False information spread without necessarily intending to deceive.", "ex": "Misinformation complicates free speech debates."}, {"term": "disinformation", "ipa": "/ˌdɪsɪnfəˈmeɪʃən/", "pron": "dis-in-fuh-MAY-shuhn", "fr": "désinformation", "def": "False information deliberately spread to deceive.", "ex": "Disinformation can undermine elections."}, {"term": "to defend free speech", "ipa": "/dɪˈfend ˌfriː ˈspiːtʃ/", "pron": "di-FEND free speech", "fr": "défendre la liberté d’expression", "def": "To protect freedom of expression.", "ex": "Civil liberties groups defend free speech."}, {"term": "to restrict speech", "ipa": "/rɪˈstrɪkt ˈspiːtʃ/", "pron": "ri-STRIKT speech", "fr": "restreindre la parole", "def": "To limit what people may say or publish.", "ex": "States may restrict speech to prevent harm."}, {"term": "to censor dissent", "ipa": "/ˈsensə dɪˈsent/", "pron": "SEN-suh di-SENT", "fr": "censurer la dissidence", "def": "To suppress disagreement with authority.", "ex": "Authoritarian regimes censor dissent."}, {"term": "to silence critics", "ipa": "/ˈsaɪləns ˈkrɪtɪks/", "pron": "SY-luhns KRIT-iks", "fr": "faire taire les critiques", "def": "To prevent critics from speaking or being heard.", "ex": "Powerful actors may try to silence critics."}, {"term": "to draw the line", "ipa": "/drɔː ðə laɪn/", "pron": "draw thuh lyne", "fr": "fixer la limite", "def": "To decide the limit between acceptable and unacceptable speech.", "ex": "Societies disagree about where to draw the line."}, {"term": "to incite violence", "ipa": "/ɪnˈsaɪt ˈvaɪələns/", "pron": "in-SYTE VY-uh-luhns", "fr": "inciter à la violence", "def": "To encourage violent acts.", "ex": "Speech that incites violence may be criminalised."}, {"term": "to spread hatred", "ipa": "/spred ˈheɪtrɪd/", "pron": "spred HAY-trid", "fr": "propager la haine", "def": "To circulate hostile messages against people or groups.", "ex": "Hate speech spreads hatred."}, {"term": "to cause offence", "ipa": "/kɔːz əˈfens/", "pron": "kawz uh-FENS", "fr": "offenser", "def": "To upset, insult or shock people.", "ex": "Satire may cause offence."}, {"term": "to foster open debate", "ipa": "/ˈfɒstə ˌəʊpən dɪˈbeɪt/", "pron": "FOS-tuh OH-puhn di-BAYT", "fr": "favoriser le débat ouvert", "def": "To encourage free and honest discussion.", "ex": "Universities should foster open debate."}]}, {"title": "E. High-value verbs and exam collocations", "entries": [{"term": "to balance rights and responsibilities", "ipa": "/ˈbæləns raɪts ənd rɪˌspɒnsəˈbɪlətiz/", "pron": "BAL-uhns rights and ri-spon-suh-BIL-uh-teez", "fr": "équilibrer droits et responsabilités", "def": "To reconcile freedom with duties and possible harm.", "ex": "Democracies must balance rights and responsibilities."}, {"term": "to moderate content", "ipa": "/ˈmɒdəreɪt ˈkɒntent/", "pron": "MOD-uh-rayt KON-tent", "fr": "modérer les contenus", "def": "To apply rules to online posts or material.", "ex": "Platforms moderate content at massive scale."}, {"term": "to protect press freedom", "ipa": "/prəˈtekt ˈpres ˌfriːdəm/", "pron": "pruh-TEKT press FREE-duhm", "fr": "protéger la liberté de la presse", "def": "To defend the independence of journalism.", "ex": "Democracies must protect press freedom."}]}]}, {"id": "p9c77", "part": 9, "chapter": 77, "title": "Cancel Culture", "file": "cpge_vocab_part9_chapter77_cancel_culture_premium.html", "count": 124, "sections": [{"title": "A. Core cancel culture vocabulary", "entries": [{"term": "cancel culture", "ipa": "/ˈkænsəl ˌkʌltʃə/", "pron": "KAN-suhl KUL-chuh", "fr": "cancel culture ; culture de l’annulation", "def": "A contested term for public pressure to punish people for offensive, harmful or controversial words or actions.", "ex": "Cancel culture is often used as a weapon in culture-war debates."}, {"term": "cancellation", "ipa": "/ˌkænsəˈleɪʃən/", "pron": "kan-suh-LAY-shuhn", "fr": "annulation ; mise à l’écart", "def": "The act of withdrawing support, invitations, jobs or platforms from someone after controversy.", "ex": "The cancellation of the speaker sparked a free speech debate."}, {"term": "to be cancelled", "ipa": "/bi ˈkænsəld/", "pron": "bee KAN-suhld", "fr": "être cancel ; être mis à l’écart", "def": "To face public backlash and loss of reputation, platform or opportunities.", "ex": "The actor claimed he had been cancelled after his comments."}, {"term": "public backlash", "ipa": "/ˌpʌblɪk ˈbæklæʃ/", "pron": "PUB-lik BAK-lash", "fr": "retour de bâton ; réaction hostile du public", "def": "A strong negative public reaction.", "ex": "A public backlash followed the influencer’s remarks."}, {"term": "online backlash", "ipa": "/ˌɒnlaɪn ˈbæklæʃ/", "pron": "ON-lyne BAK-lash", "fr": "réaction hostile en ligne", "def": "A wave of criticism on the internet.", "ex": "Online backlash can escalate within hours."}, {"term": "public shaming", "ipa": "/ˌpʌblɪk ˈʃeɪmɪŋ/", "pron": "PUB-lik SHAY-ming", "fr": "humiliation publique", "def": "Publicly humiliating or condemning someone for perceived wrongdoing.", "ex": "Public shaming can feel disproportionate."}, {"term": "naming and shaming", "ipa": "/ˌneɪmɪŋ ənd ˈʃeɪmɪŋ/", "pron": "NAY-ming and SHAY-ming", "fr": "dénonciation publique", "def": "Publicly identifying someone in order to criticise or pressure them.", "ex": "Naming and shaming can expose abuse but also fuel mob justice."}, {"term": "call-out culture", "ipa": "/ˈkɔːl aʊt ˌkʌltʃə/", "pron": "CALL-out KUL-chuh", "fr": "culture de la dénonciation", "def": "A culture of publicly criticising people for problematic behaviour or speech.", "ex": "Call-out culture can hold people accountable, but it can also become punitive."}, {"term": "calling out", "ipa": "/ˌkɔːlɪŋ ˈaʊt/", "pron": "CALL-ing out", "fr": "dénonciation publique", "def": "Publicly criticising someone’s behaviour, words or attitudes.", "ex": "Calling out racism can be necessary."}, {"term": "calling in", "ipa": "/ˌkɔːlɪŋ ˈɪn/", "pron": "CALL-ing in", "fr": "interpellation constructive", "def": "Privately or constructively challenging someone to learn rather than publicly shame them.", "ex": "Calling in is often presented as an alternative to calling out."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "Responsibility for one’s actions and their consequences.", "ex": "Supporters argue that cancel culture is simply accountability."}, {"term": "social accountability", "ipa": "/ˌsəʊʃəl əˌkaʊntəˈbɪləti/", "pron": "SOH-shuhl uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité sociale", "def": "Accountability enforced by society or public opinion rather than formal institutions.", "ex": "Social accountability can fill gaps left by institutions."}, {"term": "consequence culture", "ipa": "/ˈkɒnsɪkwəns ˌkʌltʃə/", "pron": "KON-si-kwuhns KUL-chuh", "fr": "culture des conséquences", "def": "A term used to argue that people are facing consequences, not censorship.", "ex": "Some activists prefer the term consequence culture."}, {"term": "mob justice", "ipa": "/ˌmɒb ˈdʒʌstɪs/", "pron": "mob JUS-tis", "fr": "justice expéditive de la foule", "def": "Punishment driven by a crowd rather than fair process.", "ex": "Critics say cancel culture resembles mob justice."}, {"term": "trial by social media", "ipa": "/ˌtraɪəl baɪ ˌsəʊʃəl ˈmiːdiə/", "pron": "TRY-uhl by SOH-shuhl MEE-dee-uh", "fr": "procès sur les réseaux sociaux", "def": "Public judgement of someone through social media before facts are fully established.", "ex": "Trial by social media can destroy reputations without due process."}, {"term": "trial by media", "ipa": "/ˌtraɪəl baɪ ˈmiːdiə/", "pron": "TRY-uhl by MEE-dee-uh", "fr": "procès médiatique", "def": "Public judgement through media coverage before any formal process.", "ex": "Trial by media can undermine the presumption of innocence."}, {"term": "online mob", "ipa": "/ˌɒnlaɪn ˈmɒb/", "pron": "ON-lyne mob", "fr": "meute numérique", "def": "A large group attacking someone online.", "ex": "An online mob can overwhelm an individual."}, {"term": "digital mob", "ipa": "/ˌdɪdʒɪtəl ˈmɒb/", "pron": "DIJ-i-tuhl mob", "fr": "foule numérique", "def": "A crowd of internet users collectively attacking or pressuring someone.", "ex": "A digital mob can punish faster than institutions."}, {"term": "pile-on", "ipa": "/ˈpaɪl ɒn/", "pron": "PYLE-on", "fr": "déferlement de critiques", "def": "A sudden wave of criticism or abuse directed at someone.", "ex": "The pile-on began after a screenshot went viral."}, {"term": "dogpiling", "ipa": "/ˈdɒɡpaɪlɪŋ/", "pron": "DOG-py-ling", "fr": "acharnement collectif en ligne", "def": "Mass online criticism or harassment by many users at once.", "ex": "Dogpiling can turn criticism into harassment."}, {"term": "witch hunt", "ipa": "/ˈwɪtʃ hʌnt/", "pron": "witch hunt", "fr": "chasse aux sorcières", "def": "A campaign against someone seen as unfair, exaggerated or politically motivated.", "ex": "The politician described the investigation as a witch hunt."}, {"term": "social sanction", "ipa": "/ˌsəʊʃəl ˈsæŋkʃən/", "pron": "SOH-shuhl SANK-shuhn", "fr": "sanction sociale", "def": "A social penalty imposed for violating norms.", "ex": "Social sanctions can enforce norms without courts."}, {"term": "reputational damage", "ipa": "/ˌrepjʊˈteɪʃənəl ˈdæmɪdʒ/", "pron": "rep-yuh-TAY-shuhn-uhl DAM-ij", "fr": "atteinte à la réputation", "def": "Harm to someone’s public image or credibility.", "ex": "Reputational damage can affect careers."}, {"term": "career consequences", "ipa": "/kəˈrɪə ˈkɒnsɪkwənsɪz/", "pron": "kuh-REER KON-si-kwen-siz", "fr": "conséquences professionnelles", "def": "Professional effects following controversy or misconduct.", "ex": "Cancel culture debates often focus on career consequences."}, {"term": "reputational risk", "ipa": "/ˌrepjʊˈteɪʃənəl rɪsk/", "pron": "rep-yuh-TAY-shuhn-uhl risk", "fr": "risque réputationnel", "def": "The risk of damage to reputation.", "ex": "Companies fear reputational risk during controversies."}, {"term": "social media storm", "ipa": "/ˌsəʊʃəl ˈmiːdiə stɔːm/", "pron": "SOH-shuhl MEE-dee-uh storm", "fr": "tempête sur les réseaux sociaux", "def": "A sudden intense controversy on social media.", "ex": "The social media storm forced the brand to apologise."}, {"term": "viral outrage", "ipa": "/ˈvaɪrəl ˈaʊtreɪdʒ/", "pron": "VY-ruhl OWT-rayj", "fr": "indignation virale", "def": "Anger spreading rapidly online.", "ex": "Viral outrage can be amplified by algorithms."}, {"term": "outrage cycle", "ipa": "/ˈaʊtreɪdʒ ˌsaɪkəl/", "pron": "OWT-rayj SY-kuhl", "fr": "cycle de l’indignation", "def": "The repeated pattern of online scandal, anger and replacement by a new controversy.", "ex": "The outrage cycle leaves little room for reflection."}, {"term": "outrage economy", "ipa": "/ˈaʊtreɪdʒ iˌkɒnəmi/", "pron": "OWT-rayj i-KON-uh-mee", "fr": "économie de l’indignation", "def": "A media environment where anger attracts attention and profit.", "ex": "Cancel culture thrives in the outrage economy."}, {"term": "attention economy", "ipa": "/əˈtenʃən iˌkɒnəmi/", "pron": "uh-TEN-shuhn i-KON-uh-mee", "fr": "économie de l’attention", "def": "An economy where attention is captured and monetised.", "ex": "The attention economy rewards extreme reactions."}, {"term": "algorithmic amplification", "ipa": "/ˌælɡəˈrɪðmɪk ˌæmplɪfɪˈkeɪʃən/", "pron": "al-guh-RITH-mik am-pli-fi-KAY-shuhn", "fr": "amplification algorithmique", "def": "The process by which algorithms make certain content more visible.", "ex": "Algorithmic amplification can intensify outrage."}, {"term": "context collapse", "ipa": "/ˈkɒntekst kəˌlæps/", "pron": "KON-tekst kuh-LAPS", "fr": "effondrement du contexte", "def": "When content intended for one audience is seen by different audiences lacking the original context.", "ex": "Context collapse can turn old jokes into public scandals."}, {"term": "out-of-context quote", "ipa": "/ˌaʊt əv ˈkɒntekst kwəʊt/", "pron": "out-ov-KON-tekst kwoht", "fr": "citation sortie de son contexte", "def": "A quotation presented without the context needed to understand it fairly.", "ex": "An out-of-context quote can trigger backlash."}, {"term": "screenshots", "ipa": "/ˈskriːnʃɒts/", "pron": "SCREEN-shots", "fr": "captures d’écran", "def": "Images capturing what appeared on a screen.", "ex": "Screenshots can preserve evidence but also remove context."}, {"term": "receipts", "ipa": "/rɪˈsiːts/", "pron": "ri-SEETS", "fr": "preuves ; captures compromettantes", "def": "Informal term for screenshots or evidence used to prove a claim online.", "ex": "Online users demanded receipts before believing the accusation."}]}, {"title": "B. Accountability, apology, redemption and due process", "entries": [{"term": "receipts culture", "ipa": "/rɪˈsiːts ˌkʌltʃə/", "pron": "ri-SEETS KUL-chuh", "fr": "culture des preuves numériques", "def": "A culture of demanding screenshots or evidence in online disputes.", "ex": "Receipts culture can support accountability but also surveillance."}, {"term": "digital footprint", "ipa": "/ˌdɪdʒɪtəl ˈfʊtprɪnt/", "pron": "DIJ-i-tuhl FOOT-print", "fr": "empreinte numérique", "def": "The trail of data and content a person leaves online.", "ex": "A teenager’s digital footprint can resurface years later."}, {"term": "old posts", "ipa": "/ˌəʊld ˈpəʊsts/", "pron": "ohld posts", "fr": "anciens posts", "def": "Past social media posts that may resurface later.", "ex": "Old posts can be judged by today’s standards."}, {"term": "resurfacing", "ipa": "/ˌriːˈsɜːfɪsɪŋ/", "pron": "ree-SUR-fi-sing", "fr": "réapparition", "def": "The reappearance of old content, often causing controversy.", "ex": "The resurfacing of old tweets damaged his campaign."}, {"term": "apology", "ipa": "/əˈpɒlədʒi/", "pron": "uh-POL-uh-jee", "fr": "excuses", "def": "A statement expressing regret or responsibility.", "ex": "A sincere apology can reduce public anger."}, {"term": "public apology", "ipa": "/ˌpʌblɪk əˈpɒlədʒi/", "pron": "PUB-lik uh-POL-uh-jee", "fr": "excuses publiques", "def": "An apology made openly to the public.", "ex": "The CEO issued a public apology."}, {"term": "non-apology apology", "ipa": "/ˌnɒn əˈpɒlədʒi əˈpɒlədʒi/", "pron": "non-uh-POL-uh-jee uh-POL-uh-jee", "fr": "fausses excuses", "def": "A statement that sounds like an apology but avoids responsibility.", "ex": "A non-apology apology often makes backlash worse."}, {"term": "performative apology", "ipa": "/pəˌfɔːmətɪv əˈpɒlədʒi/", "pron": "puh-FOR-muh-tiv uh-POL-uh-jee", "fr": "excuses performatives", "def": "An apology made mainly to look good rather than to repair harm.", "ex": "Critics dismissed the statement as a performative apology."}, {"term": "remorse", "ipa": "/rɪˈmɔːs/", "pron": "ri-MORSS", "fr": "remords", "def": "Deep regret for wrongdoing.", "ex": "People are more willing to forgive when they see remorse."}, {"term": "forgiveness", "ipa": "/fəˈɡɪvnəs/", "pron": "fuh-GIV-nuhs", "fr": "pardon", "def": "The act of no longer blaming or resenting someone.", "ex": "Cancel culture debates often ask whether forgiveness is possible."}, {"term": "redemption", "ipa": "/rɪˈdempʃən/", "pron": "ri-DEMP-shuhn", "fr": "rédemption", "def": "The possibility of moral recovery after wrongdoing.", "ex": "A healthy society needs paths to redemption."}, {"term": "second chance", "ipa": "/ˌsekənd ˈtʃɑːns/", "pron": "SEK-uhnd chanss", "fr": "seconde chance", "def": "An opportunity to recover after a mistake.", "ex": "Critics say cancel culture leaves no room for second chances."}, {"term": "rehabilitation", "ipa": "/ˌriːhəˌbɪlɪˈteɪʃən/", "pron": "ree-huh-bil-i-TAY-shuhn", "fr": "réhabilitation", "def": "The process of restoring someone’s reputation or behaviour after wrongdoing.", "ex": "Rehabilitation requires time and accountability."}, {"term": "restorative justice", "ipa": "/rɪˌstɒrətɪv ˈdʒʌstɪs/", "pron": "ri-STOR-uh-tiv JUS-tis", "fr": "justice réparatrice", "def": "An approach focused on repairing harm rather than only punishing wrongdoing.", "ex": "Restorative justice offers an alternative to punitive cancellation."}, {"term": "punitive culture", "ipa": "/ˈpjuːnɪtɪv ˌkʌltʃə/", "pron": "PYOO-ni-tiv KUL-chuh", "fr": "culture punitive", "def": "A culture focused on punishment rather than repair or learning.", "ex": "Cancel culture is often criticised as punitive culture."}, {"term": "proportionality", "ipa": "/prəˌpɔːʃəˈnæləti/", "pron": "pruh-por-shuh-NAL-uh-tee", "fr": "proportionnalité", "def": "The principle that punishment or response should match the seriousness of the wrongdoing.", "ex": "Proportionality is central to debates about cancellation."}, {"term": "due process", "ipa": "/ˌdjuː ˈprəʊses/", "pron": "dyoo PROH-sess", "fr": "procédure régulière ; garanties procédurales", "def": "Fair procedures before punishment or judgement.", "ex": "Critics argue that online cancellation lacks due process."}, {"term": "presumption of innocence", "ipa": "/prɪˌzʌmpʃən əv ˈɪnəsəns/", "pron": "pri-ZUMP-shuhn ov IN-uh-suhns", "fr": "présomption d’innocence", "def": "The principle that someone is considered innocent until proven guilty.", "ex": "Trial by social media can weaken the presumption of innocence."}, {"term": "evidence", "ipa": "/ˈevɪdəns/", "pron": "EV-i-duhns", "fr": "preuves ; éléments probants", "def": "Information or material supporting a claim.", "ex": "Serious accusations require evidence."}, {"term": "allegation", "ipa": "/ˌælɪˈɡeɪʃən/", "pron": "al-i-GAY-shuhn", "fr": "allégation", "def": "A claim that someone has done something wrong, not yet proven.", "ex": "The allegation was investigated by the employer."}, {"term": "accusation", "ipa": "/ˌækjʊˈzeɪʃən/", "pron": "ak-yuh-ZAY-shuhn", "fr": "accusation", "def": "A statement blaming someone for wrongdoing.", "ex": "Accusations can spread faster than corrections."}, {"term": "misconduct", "ipa": "/ˌmɪsˈkɒndʌkt/", "pron": "mis-KON-dukt", "fr": "faute ; comportement répréhensible", "def": "Unacceptable or improper behaviour.", "ex": "Workplace misconduct should be investigated fairly."}, {"term": "accountability process", "ipa": "/əˌkaʊntəˈbɪləti ˈprəʊses/", "pron": "uh-kown-tuh-BIL-uh-tee PROH-sess", "fr": "processus de responsabilisation", "def": "A procedure for examining wrongdoing and deciding consequences.", "ex": "An accountability process should be transparent."}, {"term": "investigation", "ipa": "/ɪnˌvestɪˈɡeɪʃən/", "pron": "in-ves-ti-GAY-shuhn", "fr": "enquête", "def": "A formal examination of facts.", "ex": "An investigation can distinguish rumours from evidence."}, {"term": "context", "ipa": "/ˈkɒntekst/", "pron": "KON-tekst", "fr": "contexte", "def": "The circumstances needed to understand something properly.", "ex": "Context matters when judging old statements."}, {"term": "intent", "ipa": "/ɪnˈtent/", "pron": "in-TENT", "fr": "intention", "def": "What someone meant or planned to do.", "ex": "Intent does not erase harm, but it matters."}, {"term": "impact", "ipa": "/ˈɪmpækt/", "pron": "IM-pakt", "fr": "impact ; effet", "def": "The effect or consequence of words or actions.", "ex": "Free speech debates often oppose intent and impact."}, {"term": "intent versus impact", "ipa": "/ɪnˈtent ˈvɜːsəs ˈɪmpækt/", "pron": "in-TENT VUR-suhs IM-pakt", "fr": "intention contre impact", "def": "The tension between what someone meant and how it affected others.", "ex": "Intent versus impact is central to call-out debates."}, {"term": "harm", "ipa": "/hɑːm/", "pron": "harm", "fr": "préjudice ; tort", "def": "Damage or injury caused to a person or group.", "ex": "Some speech can cause real harm."}, {"term": "offence", "ipa": "/əˈfens/", "pron": "uh-FENS", "fr": "offense", "def": "The feeling of being upset, insulted or outraged.", "ex": "Offence and harm are not always the same."}, {"term": "microaggression", "ipa": "/ˌmaɪkrəʊəˈɡreʃən/", "pron": "MY-kroh-uh-GRESH-uhn", "fr": "microagression", "def": "A subtle comment or action that may express prejudice towards a marginalised group.", "ex": "Microaggressions can accumulate over time."}, {"term": "structural inequality", "ipa": "/ˌstrʌktʃərəl ˌɪnɪˈkwɒləti/", "pron": "STRUK-chuh-ruhl in-i-KWOL-uh-tee", "fr": "inégalité structurelle", "def": "Inequality built into institutions and social systems.", "ex": "Supporters link call-out culture to structural inequality."}, {"term": "marginalised group", "ipa": "/ˈmɑːdʒɪnəlaɪzd ɡruːp/", "pron": "MAR-ji-nuh-lyzd group", "fr": "groupe marginalisé", "def": "A group pushed to the edges of power or recognition.", "ex": "Cancel culture debates often involve marginalised groups."}, {"term": "power imbalance", "ipa": "/ˈpaʊər ɪmˌbæləns/", "pron": "POW-uh im-BAL-uhns", "fr": "rapport de force inégal", "def": "Unequal power between people or groups.", "ex": "Calling out can challenge a power imbalance."}, {"term": "speaking truth to power", "ipa": "/ˌspiːkɪŋ truːθ tə ˈpaʊə/", "pron": "SPEE-king trooth tuh POW-uh", "fr": "dire la vérité au pouvoir", "def": "Telling uncomfortable truths to powerful people or institutions.", "ex": "Activists describe call-outs as speaking truth to power."}, {"term": "punching up", "ipa": "/ˌpʌntʃɪŋ ˈʌp/", "pron": "PUN-ching up", "fr": "critiquer les puissants", "def": "Criticising those with more power.", "ex": "Satire is often defended when it is punching up."}, {"term": "punching down", "ipa": "/ˌpʌntʃɪŋ ˈdaʊn/", "pron": "PUN-ching down", "fr": "s’en prendre aux plus vulnérables", "def": "Mocking or attacking those with less power.", "ex": "A joke may be criticised for punching down."}]}, {"title": "C. Power, identity, culture wars and social norms", "entries": [{"term": "culture war", "ipa": "/ˈkʌltʃə wɔː/", "pron": "KUL-chuh war", "fr": "guerre culturelle", "def": "A conflict over values, identity and social norms.", "ex": "Cancel culture is a major theme in culture-war politics."}, {"term": "moral panic", "ipa": "/ˌmɒrəl ˈpænɪk/", "pron": "MOR-uhl PAN-ik", "fr": "panique morale", "def": "Exaggerated public fear about a perceived social threat.", "ex": "Some see cancel culture discourse as a moral panic."}, {"term": "political correctness", "ipa": "/pəˌlɪtɪkəl kəˈrektnəs/", "pron": "puh-LIT-i-kuhl kuh-REKT-nuhs", "fr": "politiquement correct", "def": "Language or behaviour intended to avoid offending marginalised groups, often used critically.", "ex": "Political correctness is often framed as limiting free speech."}, {"term": "wokeness", "ipa": "/ˈwəʊknəs/", "pron": "WOHK-nuhs", "fr": "wokisme ; conscience des injustices", "def": "A contested term for awareness of social injustice, often used critically.", "ex": "Wokeness is frequently attacked in culture-war rhetoric."}, {"term": "anti-woke backlash", "ipa": "/ˌænti ˈwəʊk ˈbæklæʃ/", "pron": "AN-tee WOHK BAK-lash", "fr": "réaction anti-woke", "def": "A reaction against progressive social justice language or politics.", "ex": "Anti-woke backlash has shaped electoral politics."}, {"term": "identity politics", "ipa": "/aɪˌdentəti ˈpɒlətɪks/", "pron": "eye-DEN-tuh-tee POL-uh-tiks", "fr": "politique identitaire", "def": "Politics focused on the interests and experiences of identity groups.", "ex": "Cancel culture is often linked to identity politics."}, {"term": "victimhood", "ipa": "/ˈvɪktɪmhʊd/", "pron": "VIK-tim-hood", "fr": "statut de victime ; victimisation", "def": "The state or identity of being a victim, sometimes used critically.", "ex": "Critics accuse cancel culture of rewarding victimhood."}, {"term": "moral purity", "ipa": "/ˌmɒrəl ˈpjʊərəti/", "pron": "MOR-uhl PYOO-ruh-tee", "fr": "pureté morale", "def": "The desire to appear morally flawless or ideologically pure.", "ex": "Moral purity can make compromise difficult."}, {"term": "purity test", "ipa": "/ˈpjʊərəti test/", "pron": "PYOO-ruh-tee test", "fr": "test de pureté idéologique", "def": "A demand that someone prove ideological or moral correctness.", "ex": "Political movements can become obsessed with purity tests."}, {"term": "groupthink", "ipa": "/ˈɡruːpθɪŋk/", "pron": "GROUP-think", "fr": "pensée de groupe", "def": "Pressure to conform to the opinions of a group.", "ex": "Groupthink can suppress dissent."}, {"term": "orthodoxy", "ipa": "/ˈɔːθədɒksi/", "pron": "OR-thuh-dok-see", "fr": "orthodoxie", "def": "An accepted or dominant belief system.", "ex": "Free speech allows people to challenge orthodoxy."}, {"term": "heresy", "ipa": "/ˈherəsi/", "pron": "HERR-uh-see", "fr": "hérésie", "def": "A belief that goes against accepted doctrine or norms.", "ex": "In culture wars, disagreement can be treated as heresy."}, {"term": "dissenting voice", "ipa": "/dɪˌsentɪŋ ˈvɔɪs/", "pron": "di-SEN-ting voys", "fr": "voix dissidente", "def": "A person or opinion disagreeing with the dominant view.", "ex": "Dissenting voices may fear cancellation."}, {"term": "chilling climate", "ipa": "/ˈtʃɪlɪŋ ˌklaɪmət/", "pron": "CHIL-ing KLY-muht", "fr": "climat dissuasif", "def": "An atmosphere discouraging people from speaking freely.", "ex": "A chilling climate can reduce open discussion."}, {"term": "self-policing", "ipa": "/ˌself pəˈliːsɪŋ/", "pron": "self puh-LEE-sing", "fr": "autocontrôle", "def": "Monitoring one’s own words or behaviour to avoid social punishment.", "ex": "Self-policing can become exhausting."}, {"term": "social conformity", "ipa": "/ˌsəʊʃəl kənˈfɔːməti/", "pron": "SOH-shuhl kuhn-FOR-muh-tee", "fr": "conformisme social", "def": "Pressure to fit dominant social expectations.", "ex": "Cancel culture may increase social conformity."}, {"term": "free speech absolutism", "ipa": "/ˌfriː ˈspiːtʃ ˈæbsəluːtɪzəm/", "pron": "free speech AB-suh-loo-tiz-uhm", "fr": "absolutisme de la liberté d’expression", "def": "The view that speech should almost never be restricted.", "ex": "Free speech absolutism is difficult to apply online."}, {"term": "harm reduction", "ipa": "/ˈhɑːm rɪˌdʌkʃən/", "pron": "HARM ri-DUK-shuhn", "fr": "réduction des risques", "def": "Policies or actions aimed at reducing harm rather than eliminating all risk.", "ex": "Moderation can be framed as harm reduction."}, {"term": "speech norms", "ipa": "/ˈspiːtʃ nɔːmz/", "pron": "speech normz", "fr": "normes discursives", "def": "Social expectations about what can be said and how.", "ex": "Speech norms change over time."}, {"term": "social norms", "ipa": "/ˌsəʊʃəl ˈnɔːmz/", "pron": "SOH-shuhl normz", "fr": "normes sociales", "def": "Shared expectations about acceptable behaviour.", "ex": "Cancel culture reflects changing social norms."}, {"term": "norm enforcement", "ipa": "/ˈnɔːm ɪnˌfɔːsmənt/", "pron": "norm in-FORSS-muhnt", "fr": "application des normes sociales", "def": "The process of making people follow social rules.", "ex": "Call-outs are a form of norm enforcement."}, {"term": "institutional response", "ipa": "/ˌɪnstɪˈtjuːʃənəl rɪˈspɒns/", "pron": "in-sti-TYOO-shuhn-uhl ri-SPONS", "fr": "réponse institutionnelle", "def": "How an organisation reacts to controversy or wrongdoing.", "ex": "A weak institutional response can intensify online anger."}, {"term": "corporate response", "ipa": "/ˈkɔːpərət rɪˈspɒns/", "pron": "KOR-puh-ruht ri-SPONS", "fr": "réponse d’entreprise", "def": "How a company reacts to controversy.", "ex": "The corporate response tried to calm the backlash."}, {"term": "brand safety", "ipa": "/ˈbrænd ˌseɪfti/", "pron": "brand SAYF-tee", "fr": "sécurité de marque", "def": "Protecting a brand from association with harmful or controversial content.", "ex": "Advertisers care about brand safety."}, {"term": "sponsor withdrawal", "ipa": "/ˈspɒnsə wɪðˌdrɔːəl/", "pron": "SPON-suh with-DRAW-uhl", "fr": "retrait de sponsor", "def": "Sponsors pulling support after controversy.", "ex": "Sponsor withdrawal can follow public outrage."}, {"term": "boycott", "ipa": "/ˈbɔɪkɒt/", "pron": "BOY-kot", "fr": "boycott", "def": "Refusing to buy or support something as protest.", "ex": "Consumers called for a boycott of the company."}, {"term": "consumer pressure", "ipa": "/kənˈsjuːmə ˈpreʃə/", "pron": "kuhn-SYOO-muh PRESH-uh", "fr": "pression des consommateurs", "def": "Pressure from customers on companies or public figures.", "ex": "Consumer pressure can force brands to act."}, {"term": "platform ban", "ipa": "/ˈplætfɔːm bæn/", "pron": "PLAT-form ban", "fr": "bannissement de plateforme", "def": "A ban from a digital platform.", "ex": "A platform ban can cut off access to an audience."}, {"term": "content moderation", "ipa": "/ˈkɒntent ˌmɒdəˈreɪʃən/", "pron": "KON-tent mod-uh-RAY-shuhn", "fr": "modération des contenus", "def": "Rules and actions used by platforms to manage user content.", "ex": "Content moderation can be seen as either protection or censorship."}, {"term": "community guidelines", "ipa": "/kəˌmjuːnəti ˈɡaɪdlaɪnz/", "pron": "kuh-MYOO-nuh-tee GYDE-lynes", "fr": "règles de communauté", "def": "Rules set by platforms or communities for acceptable behaviour.", "ex": "Community guidelines shape what can be said online."}, {"term": "terms of service", "ipa": "/ˌtɜːmz əv ˈsɜːvɪs/", "pron": "turmz ov SUR-vis", "fr": "conditions d’utilisation", "def": "Rules users accept when joining a platform.", "ex": "Platforms enforce terms of service rather than constitutional law."}, {"term": "content removal", "ipa": "/ˈkɒntent rɪˌmuːvəl/", "pron": "KON-tent ri-MOO-vuhl", "fr": "suppression de contenu", "def": "Taking down posts, videos or other online material.", "ex": "Content removal can trigger censorship accusations."}, {"term": "shadow banning", "ipa": "/ˈʃædəʊ ˌbænɪŋ/", "pron": "SHAD-oh BAN-ing", "fr": "bannissement furtif", "def": "Reducing visibility without clearly notifying the user.", "ex": "Shadow banning is difficult to prove."}, {"term": "platform governance", "ipa": "/ˈplætfɔːm ˈɡʌvənəns/", "pron": "PLAT-form GUV-uh-nuhns", "fr": "gouvernance des plateformes", "def": "How platforms set, apply and justify rules.", "ex": "Platform governance affects democratic debate."}, {"term": "transparency", "ipa": "/trænˈspærənsi/", "pron": "tran-SPARR-uhn-see", "fr": "transparence", "def": "Openness about decisions, rules or procedures.", "ex": "Moderation requires transparency to be trusted."}, {"term": "appeal process", "ipa": "/əˈpiːl ˈprəʊses/", "pron": "uh-PEEL PROH-sess", "fr": "procédure d’appel", "def": "A procedure for challenging a decision.", "ex": "Users need an appeal process after account bans."}]}, {"title": "D. Corporate, platform and institutional responses", "entries": [{"term": "proportional response", "ipa": "/prəˌpɔːʃənəl rɪˈspɒns/", "pron": "pruh-POR-shuh-nuhl ri-SPONS", "fr": "réponse proportionnée", "def": "A response that matches the seriousness of the offence.", "ex": "A proportional response avoids excessive punishment."}, {"term": "to cancel someone", "ipa": "/ˈkænsəl ˈsʌmwʌn/", "pron": "KAN-suhl SUM-wun", "fr": "cancel quelqu’un ; mettre quelqu’un à l’écart", "def": "To withdraw support from someone and pressure others to do the same.", "ex": "Online users tried to cancel the comedian."}, {"term": "to call someone out", "ipa": "/kɔːl ˈsʌmwʌn aʊt/", "pron": "call SUM-wun out", "fr": "interpeller publiquement quelqu’un", "def": "To publicly criticise someone’s behaviour or words.", "ex": "Activists called the company out for hypocrisy."}, {"term": "to hold someone accountable", "ipa": "/həʊld ˈsʌmwʌn əˈkaʊntəbəl/", "pron": "hohld SUM-wun uh-KOWN-tuh-buhl", "fr": "tenir quelqu’un responsable", "def": "To make someone take responsibility for their actions.", "ex": "Supporters say call-outs hold people accountable."}, {"term": "to face backlash", "ipa": "/feɪs ˈbæklæʃ/", "pron": "fays BAK-lash", "fr": "faire face à une réaction hostile", "def": "To receive strong negative public reaction.", "ex": "The brand faced backlash after the advertisement."}, {"term": "to issue an apology", "ipa": "/ˈɪʃuː ən əˈpɒlədʒi/", "pron": "ISH-oo uhn uh-POL-uh-jee", "fr": "présenter des excuses", "def": "To make a formal apology.", "ex": "The presenter issued an apology."}, {"term": "to demand an apology", "ipa": "/dɪˈmɑːnd ən əˈpɒlədʒi/", "pron": "di-MAHND uhn uh-POL-uh-jee", "fr": "exiger des excuses", "def": "To ask publicly for someone to apologise.", "ex": "Users demanded an apology from the author."}, {"term": "to lose one’s platform", "ipa": "/luːz wʌnz ˈplætfɔːm/", "pron": "looz wunz PLAT-form", "fr": "perdre sa tribune", "def": "To lose access to an audience or public space.", "ex": "Deplatformed figures may lose their platform."}, {"term": "to damage someone’s reputation", "ipa": "/ˈdæmɪdʒ ˈsʌmwʌnz ˌrepjʊˈteɪʃən/", "pron": "DAM-ij SUM-wunz rep-yuh-TAY-shuhn", "fr": "nuire à la réputation de quelqu’un", "def": "To harm someone’s public image.", "ex": "False accusations can damage someone’s reputation."}, {"term": "to take something out of context", "ipa": "/teɪk ˈsʌmθɪŋ aʊt əv ˈkɒntekst/", "pron": "tayk SUM-thing out-ov KON-tekst", "fr": "sortir quelque chose de son contexte", "def": "To present something without the surrounding information needed to understand it.", "ex": "Old jokes can be taken out of context."}, {"term": "to leave room for redemption", "ipa": "/liːv ruːm fə rɪˈdempʃən/", "pron": "leev room fuh ri-DEMP-shuhn", "fr": "laisser une place à la rédemption", "def": "To allow people to change and recover after wrongdoing.", "ex": "A fair culture should leave room for redemption."}, {"term": "to distinguish harm from offence", "ipa": "/dɪˈstɪŋɡwɪʃ hɑːm frəm əˈfens/", "pron": "di-STING-gwish harm from uh-FENS", "fr": "distinguer le préjudice de l’offense", "def": "To separate real damage from the feeling of being upset.", "ex": "Free speech debates must distinguish harm from offence."}, {"term": "to amplify outrage", "ipa": "/ˈæmplɪfaɪ ˈaʊtreɪdʒ/", "pron": "AM-pli-fy OWT-rayj", "fr": "amplifier l’indignation", "def": "To make anger spread further or faster.", "ex": "Algorithms can amplify outrage."}, {"term": "to enforce social norms", "ipa": "/ɪnˈfɔːs ˌsəʊʃəl ˈnɔːmz/", "pron": "in-FORSS SOH-shuhl normz", "fr": "faire respecter les normes sociales", "def": "To make people follow shared social expectations.", "ex": "Call-outs enforce social norms."}, {"term": "to silence dissent", "ipa": "/ˈsaɪləns dɪˈsent/", "pron": "SY-luhns di-SENT", "fr": "faire taire la dissidence", "def": "To prevent disagreement from being expressed.", "ex": "Critics argue that cancel culture can silence dissent."}, {"term": "to chill debate", "ipa": "/tʃɪl dɪˈbeɪt/", "pron": "chil di-BAYT", "fr": "refroidir / freiner le débat", "def": "To discourage open discussion.", "ex": "Fear of cancellation can chill debate."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p9c78", "part": 9, "chapter": 78, "title": "Entertainment Streaming", "file": "cpge_vocab_part9_chapter78_entertainment_streaming_premium.html", "count": 148, "sections": [{"title": "A. Core entertainment and streaming vocabulary", "entries": [{"term": "entertainment", "ipa": "/ˌentəˈteɪnmənt/", "pron": "EN-tuh-TAYN-muhnt", "fr": "divertissement", "def": "Activities, media or performances designed to amuse, inform or engage audiences.", "ex": "Entertainment has become a global industry."}, {"term": "streaming", "ipa": "/ˈstriːmɪŋ/", "pron": "STREE-ming", "fr": "streaming ; diffusion en continu", "def": "Delivering audio or video content over the internet without downloading it first.", "ex": "Streaming has transformed how people watch films and series."}, {"term": "streaming platform", "ipa": "/ˈstriːmɪŋ ˌplætfɔːm/", "pron": "STREE-ming PLAT-form", "fr": "plateforme de streaming", "def": "An online service providing streamed films, series, music or live content.", "ex": "Streaming platforms compete for subscribers."}, {"term": "streaming service", "ipa": "/ˈstriːmɪŋ ˌsɜːvɪs/", "pron": "STREE-ming SUR-vis", "fr": "service de streaming", "def": "A company or platform offering streamed media content.", "ex": "Many households subscribe to several streaming services."}, {"term": "subscription video on demand", "ipa": "/səbˈskrɪpʃən ˈvɪdiəʊ ɒn dɪˈmɑːnd/", "pron": "suhb-SKRIP-shuhn VID-ee-oh on di-MAHND", "fr": "vidéo à la demande par abonnement", "def": "A model where users pay regularly to access video content on demand.", "ex": "Subscription video on demand has challenged traditional television."}, {"term": "SVOD", "ipa": "/ˌes viː əʊ ˈdiː/", "pron": "ess-vee-oh-dee", "fr": "SVOD", "def": "Abbreviation for subscription video on demand.", "ex": "SVOD platforms depend on recurring subscriptions."}, {"term": "video on demand", "ipa": "/ˌvɪdiəʊ ɒn dɪˈmɑːnd/", "pron": "VID-ee-oh on di-MAHND", "fr": "vidéo à la demande", "def": "A system allowing users to watch chosen video content whenever they want.", "ex": "Video on demand changed audience habits."}, {"term": "VOD", "ipa": "/ˌviː əʊ ˈdiː/", "pron": "vee-oh-dee", "fr": "VOD", "def": "Abbreviation for video on demand.", "ex": "VOD gives viewers more control."}, {"term": "broadcast television", "ipa": "/ˈbrɔːdkɑːst ˌtelɪvɪʒən/", "pron": "BROD-kast TEL-i-vizh-uhn", "fr": "télévision diffusée ; télévision linéaire", "def": "Television transmitted according to a fixed schedule.", "ex": "Broadcast television has lost younger audiences."}, {"term": "linear television", "ipa": "/ˌlɪniə ˈtelɪvɪʒən/", "pron": "LIN-ee-uh TEL-i-vizh-uhn", "fr": "télévision linéaire", "def": "Traditional scheduled television where viewers watch at set times.", "ex": "Linear television still matters for live sport and news."}, {"term": "cable television", "ipa": "/ˈkeɪbəl ˌtelɪvɪʒən/", "pron": "KAY-buhl TEL-i-vizh-uhn", "fr": "télévision câblée", "def": "Television delivered through cable networks, often by subscription.", "ex": "Cable television has declined in the streaming era."}, {"term": "cord-cutting", "ipa": "/ˈkɔːd ˌkʌtɪŋ/", "pron": "KORD-cut-ing", "fr": "abandon du câble", "def": "Cancelling traditional cable or satellite TV in favour of streaming.", "ex": "Cord-cutting reshaped the US media market."}, {"term": "pay TV", "ipa": "/ˌpeɪ tiː ˈviː/", "pron": "pay tee-vee", "fr": "télévision payante", "def": "Television channels or services available through paid subscription.", "ex": "Pay TV faces pressure from cheaper streaming offers."}, {"term": "public broadcaster", "ipa": "/ˌpʌblɪk ˈbrɔːdkɑːstə/", "pron": "PUB-lik BROD-kast-uh", "fr": "radiodiffuseur public ; service public audiovisuel", "def": "A broadcaster funded to serve the public interest.", "ex": "Public broadcasters must compete with global platforms."}, {"term": "audience", "ipa": "/ˈɔːdiəns/", "pron": "AW-dee-uhns", "fr": "public ; audience", "def": "The people who watch, listen to or consume media content.", "ex": "Streaming platforms track audience behaviour closely."}, {"term": "viewer", "ipa": "/ˈvjuːə/", "pron": "VYOO-uh", "fr": "spectateur ; téléspectateur", "def": "A person who watches television, video or online content.", "ex": "Viewers expect personalised recommendations."}, {"term": "subscriber", "ipa": "/səbˈskraɪbə/", "pron": "suhb-SKRY-buh", "fr": "abonné", "def": "A person who pays regularly for access to a service.", "ex": "Platforms try to keep subscribers from cancelling."}, {"term": "subscription", "ipa": "/səbˈskrɪpʃən/", "pron": "suhb-SKRIP-shuhn", "fr": "abonnement", "def": "Regular payment for access to a service.", "ex": "Subscription fatigue is becoming a problem."}, {"term": "subscription fatigue", "ipa": "/səbˈskrɪpʃən fəˌtiːɡ/", "pron": "suhb-SKRIP-shuhn fuh-TEEG", "fr": "fatigue des abonnements", "def": "Tiredness or frustration caused by too many paid subscriptions.", "ex": "Subscription fatigue may push viewers back towards piracy or free platforms."}, {"term": "churn", "ipa": "/tʃɜːn/", "pron": "churn", "fr": "désabonnement ; taux d’attrition", "def": "The rate at which subscribers cancel a service.", "ex": "High churn is a major concern for streaming platforms."}, {"term": "user retention", "ipa": "/ˈjuːzə rɪˌtenʃən/", "pron": "YOO-zuh ri-TEN-shuhn", "fr": "fidélisation des utilisateurs", "def": "Keeping users or subscribers over time.", "ex": "Exclusive content helps user retention."}, {"term": "content library", "ipa": "/ˈkɒntent ˌlaɪbrəri/", "pron": "KON-tent LY-bruh-ree", "fr": "catalogue de contenus", "def": "The catalogue of films, series or programmes offered by a platform.", "ex": "A large content library can attract subscribers."}, {"term": "catalogue", "ipa": "/ˈkætəlɒɡ/", "pron": "KAT-uh-log", "fr": "catalogue", "def": "A collection of available content.", "ex": "The platform removed several films from its catalogue."}, {"term": "original content", "ipa": "/əˌrɪdʒənəl ˈkɒntent/", "pron": "uh-RIJ-uh-nuhl KON-tent", "fr": "contenu original", "def": "Films, series or programmes produced or commissioned by a platform.", "ex": "Original content is used to differentiate platforms."}, {"term": "exclusive content", "ipa": "/ɪkˌskluːsɪv ˈkɒntent/", "pron": "ik-SKLOO-siv KON-tent", "fr": "contenu exclusif", "def": "Content available only through one platform or provider.", "ex": "Exclusive content can attract new subscribers."}, {"term": "licensed content", "ipa": "/ˈlaɪsənst ˈkɒntent/", "pron": "LY-suhnst KON-tent", "fr": "contenu sous licence", "def": "Content made by another company and legally distributed under licence.", "ex": "Licensed content can disappear when contracts expire."}, {"term": "franchise", "ipa": "/ˈfræntʃaɪz/", "pron": "FRAN-chyze", "fr": "franchise", "def": "A series of related films, shows, games or products built around a shared brand or universe.", "ex": "Major studios rely on franchises to reduce financial risk."}, {"term": "intellectual property", "ipa": "/ˌɪntəˈlektʃuəl ˈprɒpəti/", "pron": "IN-tuh-LEK-choo-uhl PROP-uh-tee", "fr": "propriété intellectuelle", "def": "Creations protected by law, such as stories, characters, music or brands.", "ex": "Streaming companies invest heavily in intellectual property."}, {"term": "IP", "ipa": "/ˌaɪ ˈpiː/", "pron": "eye-pee", "fr": "PI ; propriété intellectuelle", "def": "Abbreviation for intellectual property.", "ex": "Hollywood increasingly depends on well-known IP."}, {"term": "adaptation", "ipa": "/ˌædæpˈteɪʃən/", "pron": "ad-ap-TAY-shuhn", "fr": "adaptation", "def": "A film, series or programme based on a book, game, comic or other work.", "ex": "The adaptation attracted fans of the original novel."}, {"term": "remake", "ipa": "/ˈriːmeɪk/", "pron": "REE-mayk", "fr": "remake ; nouvelle version", "def": "A new version of an older film, series or programme.", "ex": "Remakes are often criticised for lacking originality."}, {"term": "reboot", "ipa": "/ˈriːbuːt/", "pron": "REE-boot", "fr": "redémarrage ; reboot", "def": "A fresh start for an existing franchise, often with new actors or continuity.", "ex": "The studio planned a reboot of the franchise."}]}, {"title": "B. Film, television, franchises and fandom", "entries": [{"term": "sequel", "ipa": "/ˈsiːkwəl/", "pron": "SEE-kwuhl", "fr": "suite", "def": "A work continuing the story of an earlier one.", "ex": "The sequel performed better than expected."}, {"term": "prequel", "ipa": "/ˈpriːkwəl/", "pron": "PREE-kwuhl", "fr": "préquelle", "def": "A work set before the events of an earlier one.", "ex": "The prequel explains the villain’s origins."}, {"term": "spin-off", "ipa": "/ˈspɪn ɒf/", "pron": "SPIN-off", "fr": "série dérivée ; spin-off", "def": "A new work derived from an existing work, often focused on a secondary character.", "ex": "The spin-off targeted loyal fans."}, {"term": "cinematic universe", "ipa": "/ˌsɪnəˈmætɪk ˈjuːnɪvɜːs/", "pron": "sin-uh-MAT-ik YOO-ni-vurs", "fr": "univers cinématographique", "def": "A shared fictional world across several films or series.", "ex": "Cinematic universes encourage long-term fan engagement."}, {"term": "fandom", "ipa": "/ˈfændəm/", "pron": "FAN-duhm", "fr": "communauté de fans", "def": "A community of fans around a cultural product, celebrity or franchise.", "ex": "Fandom can turn entertainment into identity."}, {"term": "fanbase", "ipa": "/ˈfænbeɪs/", "pron": "FAN-bayss", "fr": "base de fans", "def": "The group of people who strongly support an artist, show or franchise.", "ex": "A loyal fanbase can make a series profitable."}, {"term": "fan engagement", "ipa": "/ˈfæn ɪnˌɡeɪdʒmənt/", "pron": "FAN in-GAYJ-muhnt", "fr": "engagement des fans", "def": "Interaction between fans and cultural products, creators or communities.", "ex": "Studios monitor fan engagement online."}, {"term": "shipping", "ipa": "/ˈʃɪpɪŋ/", "pron": "SHIP-ing", "fr": "shipping", "def": "Fans imagining or supporting a romantic relationship between characters.", "ex": "Shipping can shape online fandom debates."}, {"term": "fan fiction", "ipa": "/ˈfæn ˌfɪkʃən/", "pron": "FAN FIK-shuhn", "fr": "fanfiction", "def": "Stories written by fans using existing characters or worlds.", "ex": "Fan fiction shows how audiences become creators."}, {"term": "participatory culture", "ipa": "/pɑːˌtɪsɪpətəri ˈkʌltʃə/", "pron": "par-TIS-i-puh-tuh-ree KUL-chuh", "fr": "culture participative", "def": "A culture where audiences actively create, share and respond to media.", "ex": "Participatory culture blurs the line between consumers and creators."}, {"term": "creator economy", "ipa": "/kriˈeɪtə iˌkɒnəmi/", "pron": "kree-AY-tuh i-KON-uh-mee", "fr": "économie des créateurs", "def": "The economy built around independent online content creators.", "ex": "The creator economy challenges traditional entertainment industries."}, {"term": "content creator", "ipa": "/ˈkɒntent kriˌeɪtə/", "pron": "KON-tent kree-AY-tuh", "fr": "créateur de contenu", "def": "A person producing content for online platforms.", "ex": "Content creators can build large audiences without studios."}, {"term": "influencer", "ipa": "/ˈɪnfluənsə/", "pron": "IN-floo-uhn-suh", "fr": "influenceur", "def": "A person who shapes audience behaviour or opinion through online presence.", "ex": "Influencers increasingly compete with traditional celebrities."}, {"term": "celebrity culture", "ipa": "/səˈlebrəti ˌkʌltʃə/", "pron": "suh-LEB-ruh-tee KUL-chuh", "fr": "culture de la célébrité", "def": "A culture focused on famous people and their private lives.", "ex": "Celebrity culture fuels entertainment media."}, {"term": "star power", "ipa": "/ˈstɑː ˌpaʊə/", "pron": "star POW-uh", "fr": "pouvoir d’attraction d’une star", "def": "The ability of a famous actor or performer to attract audiences.", "ex": "Star power no longer guarantees box-office success."}, {"term": "box office", "ipa": "/ˈbɒks ˌɒfɪs/", "pron": "BOKS OFF-is", "fr": "box-office", "def": "Ticket sales and revenue from cinema releases.", "ex": "The film dominated the box office."}, {"term": "blockbuster", "ipa": "/ˈblɒkˌbʌstə/", "pron": "BLOK-bus-tuh", "fr": "blockbuster ; gros succès commercial", "def": "A very successful and expensive mainstream film or entertainment product.", "ex": "Blockbusters depend on global audiences."}, {"term": "independent film", "ipa": "/ˌɪndɪˈpendənt ˈfɪlm/", "pron": "in-di-PEN-duhnt film", "fr": "film indépendant", "def": "A film produced outside major studio systems.", "ex": "Independent films often take more artistic risks."}, {"term": "arthouse cinema", "ipa": "/ˈɑːthaʊs ˌsɪnəmə/", "pron": "ART-house SIN-uh-muh", "fr": "cinéma d’auteur", "def": "Films aimed at artistic or niche audiences rather than mass markets.", "ex": "Arthouse cinema struggles for visibility on platforms."}, {"term": "mainstream entertainment", "ipa": "/ˈmeɪnstriːm ˌentəˈteɪnmənt/", "pron": "MAYN-streem EN-tuh-TAYN-muhnt", "fr": "divertissement grand public", "def": "Popular entertainment aimed at large audiences.", "ex": "Mainstream entertainment often avoids political risk."}, {"term": "niche audience", "ipa": "/ˌniːʃ ˈɔːdiəns/", "pron": "neesh AW-dee-uhns", "fr": "public de niche", "def": "A small, specific audience with particular interests.", "ex": "Streaming platforms can serve niche audiences."}, {"term": "mass audience", "ipa": "/ˌmæs ˈɔːdiəns/", "pron": "mass AW-dee-uhns", "fr": "grand public", "def": "A very large general audience.", "ex": "Traditional TV was built around mass audiences."}, {"term": "global audience", "ipa": "/ˌɡləʊbəl ˈɔːdiəns/", "pron": "GLOH-buhl AW-dee-uhns", "fr": "public mondial", "def": "Viewers or listeners spread across many countries.", "ex": "Streaming platforms target a global audience."}, {"term": "local content", "ipa": "/ˌləʊkəl ˈkɒntent/", "pron": "LOH-kuhl KON-tent", "fr": "contenu local", "def": "Content produced for or rooted in a specific country, language or culture.", "ex": "Platforms invest in local content to reach new markets."}, {"term": "globalisation of culture", "ipa": "/ˌɡləʊbəlaɪˈzeɪʃən əv ˈkʌltʃə/", "pron": "gloh-buh-ly-ZAY-shuhn ov KUL-chuh", "fr": "mondialisation de la culture", "def": "The worldwide circulation and influence of cultural products.", "ex": "Streaming accelerates the globalisation of culture."}, {"term": "cultural homogenisation", "ipa": "/ˌkʌltʃərəl həˌmɒdʒənaɪˈzeɪʃən/", "pron": "KUL-chuh-ruhl huh-moj-uh-ny-ZAY-shuhn", "fr": "homogénéisation culturelle", "def": "The process by which cultures become more similar.", "ex": "Critics fear cultural homogenisation under global platforms."}, {"term": "cultural diversity", "ipa": "/ˌkʌltʃərəl daɪˈvɜːsəti/", "pron": "KUL-chuh-ruhl dy-VUR-suh-tee", "fr": "diversité culturelle", "def": "The existence of varied cultural expressions, languages and traditions.", "ex": "Public policy can protect cultural diversity."}, {"term": "cultural exception", "ipa": "/ˌkʌltʃərəl ɪkˈsepʃən/", "pron": "KUL-chuh-ruhl ik-SEP-shuhn", "fr": "exception culturelle", "def": "The idea that cultural goods should not be treated like ordinary commercial goods.", "ex": "France defends the cultural exception."}, {"term": "soft power", "ipa": "/ˈsɒft ˌpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; pouvoir d’influence", "def": "The ability to influence others through attraction, culture and values.", "ex": "Entertainment can be a powerful tool of soft power."}, {"term": "cultural influence", "ipa": "/ˌkʌltʃərəl ˈɪnfluəns/", "pron": "KUL-chuh-ruhl IN-floo-uhns", "fr": "influence culturelle", "def": "The power of culture to shape ideas, tastes and identities.", "ex": "Korean dramas have expanded South Korea’s cultural influence."}, {"term": "K-drama", "ipa": "/ˈkeɪ ˌdrɑːmə/", "pron": "kay-DRAH-muh", "fr": "drama coréen", "def": "A South Korean television drama series.", "ex": "K-dramas have found large international audiences."}, {"term": "anime", "ipa": "/ˈænɪmeɪ/", "pron": "AN-i-may", "fr": "anime ; animation japonaise", "def": "Japanese animated film or television content.", "ex": "Anime has become globally mainstream."}, {"term": "reality television", "ipa": "/riˈælɪti ˌtelɪvɪʒən/", "pron": "ree-AL-uh-tee TEL-i-vizh-uhn", "fr": "téléréalité", "def": "Television based on supposedly unscripted real people and situations.", "ex": "Reality television blurs authenticity and performance."}, {"term": "talent show", "ipa": "/ˈtælənt ʃəʊ/", "pron": "TAL-uhnt show", "fr": "émission de talents", "def": "A competition programme where people perform skills.", "ex": "Talent shows manufacture celebrity quickly."}, {"term": "game show", "ipa": "/ˈɡeɪm ʃəʊ/", "pron": "game show", "fr": "jeu télévisé", "def": "A programme where contestants play games or answer questions for prizes.", "ex": "Game shows are cheap and popular."}, {"term": "documentary", "ipa": "/ˌdɒkjʊˈmentəri/", "pron": "dok-yuh-MEN-tuh-ree", "fr": "documentaire", "def": "A film or programme presenting factual information about real events or issues.", "ex": "Documentaries can shape public opinion."}, {"term": "docuseries", "ipa": "/ˈdɒkjʊˌsɪəriːz/", "pron": "DOK-yuh-seer-eez", "fr": "série documentaire", "def": "A documentary series across several episodes.", "ex": "True-crime docuseries are popular on platforms."}, {"term": "true crime", "ipa": "/ˌtruː ˈkraɪm/", "pron": "troo kryme", "fr": "true crime ; affaires criminelles réelles", "def": "Entertainment based on real crimes and investigations.", "ex": "True crime raises ethical questions about victims."}, {"term": "stand-up comedy", "ipa": "/ˌstænd ʌp ˈkɒmədi/", "pron": "stand-up KOM-uh-dee", "fr": "stand-up", "def": "Comedy performed live by a comedian speaking directly to an audience.", "ex": "Stand-up comedy often tests social boundaries."}, {"term": "sitcom", "ipa": "/ˈsɪtkɒm/", "pron": "SIT-kom", "fr": "sitcom ; comédie de situation", "def": "A situation comedy, usually centred on recurring characters.", "ex": "Sitcoms remain popular comfort viewing."}, {"term": "drama series", "ipa": "/ˈdrɑːmə ˌsɪəriːz/", "pron": "DRAH-muh SEER-eez", "fr": "série dramatique", "def": "A fictional series focused on serious or emotional stories.", "ex": "Drama series often build long-term audience attachment."}, {"term": "limited series", "ipa": "/ˌlɪmɪtɪd ˈsɪəriːz/", "pron": "LIM-i-tid SEER-eez", "fr": "mini-série ; série limitée", "def": "A series with a fixed, usually short number of episodes.", "ex": "Limited series attract film actors."}, {"term": "binge-watching", "ipa": "/ˈbɪndʒ ˌwɒtʃɪŋ/", "pron": "BINJ-wotch-ing", "fr": "visionnage compulsif ; binge-watching", "def": "Watching many episodes in one sitting or over a short period.", "ex": "Binge-watching changed the rhythm of television storytelling."}]}, {"title": "C. Genres, storytelling and production", "entries": [{"term": "bingeable", "ipa": "/ˈbɪndʒəbəl/", "pron": "BINJ-uh-buhl", "fr": "qui se regarde en rafale", "def": "Easy or tempting to watch in large quantities.", "ex": "Short cliffhanger episodes make a show bingeable."}, {"term": "cliffhanger", "ipa": "/ˈklɪfˌhæŋə/", "pron": "KLIF-hang-uh", "fr": "fin à suspense ; cliffhanger", "def": "A suspenseful ending designed to make viewers continue watching.", "ex": "Cliffhangers encourage binge-watching."}, {"term": "spoiler", "ipa": "/ˈspɔɪlə/", "pron": "SPOY-luh", "fr": "spoiler ; divulgâcheur", "def": "Information that reveals important plot details before someone watches or reads the work.", "ex": "Spoilers can anger fans."}, {"term": "spoiler alert", "ipa": "/ˈspɔɪlər əˌlɜːt/", "pron": "SPOY-luh uh-LURT", "fr": "alerte spoiler", "def": "A warning that plot details will be revealed.", "ex": "Reviewers often include spoiler alerts."}, {"term": "plot twist", "ipa": "/ˈplɒt twɪst/", "pron": "plot twist", "fr": "rebondissement", "def": "An unexpected change in the direction of a story.", "ex": "A good plot twist changes how viewers understand the story."}, {"term": "character arc", "ipa": "/ˈkærəktər ɑːk/", "pron": "KARR-uhk-tuh ark", "fr": "évolution d’un personnage", "def": "The development of a character over a story.", "ex": "Viewers loved the protagonist’s character arc."}, {"term": "screenplay", "ipa": "/ˈskriːnpleɪ/", "pron": "SCREEN-play", "fr": "scénario", "def": "The written script for a film or television programme.", "ex": "The screenplay won several awards."}, {"term": "showrunner", "ipa": "/ˈʃəʊˌrʌnə/", "pron": "SHOW-run-uh", "fr": "showrunner ; responsable artistique", "def": "The person with overall creative control of a television series.", "ex": "The showrunner defended the controversial ending."}, {"term": "production budget", "ipa": "/prəˈdʌkʃən ˈbʌdʒɪt/", "pron": "pruh-DUK-shuhn BUJ-it", "fr": "budget de production", "def": "The money allocated to make a film, series or programme.", "ex": "Streaming series can have huge production budgets."}, {"term": "visual effects", "ipa": "/ˌvɪʒuəl ɪˈfekts/", "pron": "VIZH-oo-uhl i-FEKTS", "fr": "effets visuels", "def": "Digitally or practically created images used in film and TV.", "ex": "Visual effects are central to superhero films."}, {"term": "CGI", "ipa": "/ˌsiː dʒiː ˈaɪ/", "pron": "see-jee-eye", "fr": "images de synthèse", "def": "Computer-generated imagery.", "ex": "CGI can create spectacular worlds."}, {"term": "soundtrack", "ipa": "/ˈsaʊndtræk/", "pron": "SOWND-trak", "fr": "bande originale", "def": "The music used in a film, series or game.", "ex": "The soundtrack went viral."}, {"term": "dubbing", "ipa": "/ˈdʌbɪŋ/", "pron": "DUB-ing", "fr": "doublage", "def": "Replacing original dialogue with a voice track in another language.", "ex": "Dubbing helps content travel internationally."}, {"term": "subtitles", "ipa": "/ˈsʌbˌtaɪtəlz/", "pron": "SUB-ty-tuhlz", "fr": "sous-titres", "def": "Written translation or transcription displayed on screen.", "ex": "Subtitles helped foreign-language series reach global audiences."}, {"term": "accessibility", "ipa": "/əkˌsesəˈbɪləti/", "pron": "ak-sess-uh-BIL-uh-tee", "fr": "accessibilité", "def": "Design that enables people with disabilities to access content or services.", "ex": "Streaming platforms must improve accessibility."}, {"term": "audio description", "ipa": "/ˈɔːdiəʊ dɪˌskrɪpʃən/", "pron": "AW-dee-oh di-SKRIP-shuhn", "fr": "audiodescription", "def": "Narration describing visual elements for blind or visually impaired viewers.", "ex": "Audio description makes films more accessible."}, {"term": "closed captions", "ipa": "/ˌkləʊzd ˈkæpʃənz/", "pron": "klohz-d KAP-shuhnz", "fr": "sous-titres pour sourds et malentendants", "def": "Text showing dialogue and sound information for deaf or hard-of-hearing viewers.", "ex": "Closed captions include sound effects."}, {"term": "recommendation algorithm", "ipa": "/ˌrekəmenˈdeɪʃən ˈælɡərɪðəm/", "pron": "rek-uh-men-DAY-shuhn AL-guh-rith-uhm", "fr": "algorithme de recommandation", "def": "An algorithm suggesting content based on user data.", "ex": "Recommendation algorithms shape what viewers discover."}, {"term": "personalisation", "ipa": "/ˌpɜːsənəlaɪˈzeɪʃən/", "pron": "pur-suh-nuh-ly-ZAY-shuhn", "fr": "personnalisation", "def": "Tailoring content or recommendations to individual users.", "ex": "Personalisation can be convenient but narrowing."}, {"term": "algorithmic curation", "ipa": "/ˌælɡəˈrɪðmɪk kjʊəˈreɪʃən/", "pron": "al-guh-RITH-mik kyoo-uh-RAY-shuhn", "fr": "curation algorithmique", "def": "The selection of content by algorithms.", "ex": "Algorithmic curation affects cultural visibility."}, {"term": "discoverability", "ipa": "/dɪˌskʌvərəˈbɪləti/", "pron": "di-SKUV-uh-ruh-BIL-uh-tee", "fr": "découvrabilité", "def": "The ability of content to be found by audiences.", "ex": "Small productions struggle with discoverability."}, {"term": "user data", "ipa": "/ˈjuːzə ˌdeɪtə/", "pron": "YOO-zuh DAY-tuh", "fr": "données utilisateur", "def": "Information collected about users’ behaviour and preferences.", "ex": "User data drives recommendations."}, {"term": "viewing habits", "ipa": "/ˈvjuːɪŋ ˌhæbɪts/", "pron": "VYOO-ing HAB-its", "fr": "habitudes de visionnage", "def": "Patterns in how people watch content.", "ex": "Platforms analyse viewing habits."}, {"term": "watch time", "ipa": "/ˈwɒtʃ taɪm/", "pron": "wotch time", "fr": "temps de visionnage", "def": "The amount of time users spend watching content.", "ex": "Watch time is a key metric."}, {"term": "engagement metric", "ipa": "/ɪnˈɡeɪdʒmənt ˈmetrɪk/", "pron": "in-GAYJ-muhnt MET-rik", "fr": "indicateur d’engagement", "def": "A measurement of user interaction or attention.", "ex": "Engagement metrics influence production decisions."}, {"term": "attention economy", "ipa": "/əˈtenʃən iˌkɒnəmi/", "pron": "uh-TEN-shuhn i-KON-uh-mee", "fr": "économie de l’attention", "def": "An economy where human attention is captured and monetised.", "ex": "Entertainment competes in the attention economy."}, {"term": "screen time", "ipa": "/ˈskriːn taɪm/", "pron": "SCREEN time", "fr": "temps d’écran", "def": "Time spent using screens or watching digital content.", "ex": "Parents worry about children’s screen time."}, {"term": "addictive design", "ipa": "/əˌdɪktɪv dɪˈzaɪn/", "pron": "uh-DIK-tiv di-ZYNE", "fr": "conception addictive", "def": "Design choices intended to keep users engaged for as long as possible.", "ex": "Autoplay can be seen as addictive design."}, {"term": "autoplay", "ipa": "/ˈɔːtəʊpleɪ/", "pron": "AW-toh-play", "fr": "lecture automatique", "def": "Automatic playback of the next video or episode.", "ex": "Autoplay encourages binge-watching."}, {"term": "viewer retention", "ipa": "/ˈvjuːə rɪˌtenʃən/", "pron": "VYOO-uh ri-TEN-shuhn", "fr": "rétention des spectateurs", "def": "Keeping viewers watching content over time.", "ex": "Cliffhangers improve viewer retention."}, {"term": "content overload", "ipa": "/ˈkɒntent ˌəʊvələʊd/", "pron": "KON-tent OH-vuh-lohd", "fr": "surcharge de contenus", "def": "The feeling of having too much content to choose from.", "ex": "Content overload can make viewers feel lost."}, {"term": "choice paralysis", "ipa": "/ˈtʃɔɪs pəˌræləsɪs/", "pron": "CHOYSS puh-RAL-uh-sis", "fr": "paralysie du choix", "def": "Difficulty choosing because there are too many options.", "ex": "Streaming menus can create choice paralysis."}, {"term": "piracy", "ipa": "/ˈpaɪrəsi/", "pron": "PY-ruh-see", "fr": "piratage", "def": "Illegal copying, downloading or streaming of copyrighted content.", "ex": "Fragmented subscriptions may increase piracy."}, {"term": "illegal streaming", "ipa": "/ɪˌliːɡəl ˈstriːmɪŋ/", "pron": "i-LEE-guhl STREE-ming", "fr": "streaming illégal", "def": "Watching streamed content through unauthorised sources.", "ex": "Illegal streaming damages revenue."}, {"term": "copyright", "ipa": "/ˈkɒpiraɪt/", "pron": "KOP-ee-right", "fr": "droit d’auteur ; copyright", "def": "Legal protection for creative works.", "ex": "Copyright protects creators and studios."}, {"term": "royalties", "ipa": "/ˈrɔɪəltiz/", "pron": "ROY-uhl-teez", "fr": "droits d’auteur ; redevances", "def": "Payments made to creators or rights holders for use of their work.", "ex": "Musicians depend on royalties."}]}, {"title": "D. Algorithms, attention, labour and representation", "entries": [{"term": "residuals", "ipa": "/rɪˈzɪdʒuəlz/", "pron": "ri-ZIJ-oo-uhlz", "fr": "revenus résiduels", "def": "Payments to actors, writers or creators when work is reused or rebroadcast.", "ex": "Streaming residuals became a labour issue."}, {"term": "creative labour", "ipa": "/kriˈeɪtɪv ˈleɪbə/", "pron": "kree-AY-tiv LAY-buh", "fr": "travail créatif", "def": "Work involved in producing cultural or artistic content.", "ex": "Creative labour is often precarious."}, {"term": "gig economy", "ipa": "/ˈɡɪɡ iˌkɒnəmi/", "pron": "gig i-KON-uh-mee", "fr": "économie des petits boulots", "def": "A labour market based on short-term, freelance or task-based work.", "ex": "Many creators work in the gig economy."}, {"term": "precarious work", "ipa": "/prɪˌkeəriəs ˈwɜːk/", "pron": "pri-KAIR-ee-uhs work", "fr": "travail précaire", "def": "Work that is insecure, unstable or poorly protected.", "ex": "Entertainment workers often face precarious work."}, {"term": "writers’ strike", "ipa": "/ˈraɪtəz straɪk/", "pron": "RY-tuhz strike", "fr": "grève des scénaristes", "def": "A strike by screenwriters demanding better pay or conditions.", "ex": "The writers’ strike highlighted tensions over streaming and AI."}, {"term": "actors’ strike", "ipa": "/ˈæktəz straɪk/", "pron": "AK-tuhz strike", "fr": "grève des acteurs", "def": "A strike by actors over pay, rights or working conditions.", "ex": "The actors’ strike raised questions about digital replicas."}, {"term": "AI-generated content", "ipa": "/ˌeɪ aɪ ˌdʒenəreɪtɪd ˈkɒntent/", "pron": "ay-eye JEN-uh-ray-tid KON-tent", "fr": "contenu généré par IA", "def": "Content created partly or fully by artificial intelligence.", "ex": "AI-generated content worries many creators."}, {"term": "digital replica", "ipa": "/ˌdɪdʒɪtəl ˈreplɪkə/", "pron": "DIJ-i-tuhl REP-li-kuh", "fr": "réplique numérique", "def": "A digital copy of a performer’s voice or likeness.", "ex": "Actors want control over digital replicas."}, {"term": "deepfake actor", "ipa": "/ˈdiːpfeɪk ˈæktə/", "pron": "DEEP-fayk AK-tuh", "fr": "acteur deepfake ; acteur généré numériquement", "def": "A digitally generated or altered version of an actor.", "ex": "Deepfake actors raise ethical and legal questions."}, {"term": "representation", "ipa": "/ˌreprɪzenˈteɪʃən/", "pron": "rep-ri-zen-TAY-shuhn", "fr": "représentation", "def": "How people, groups or identities are shown in media.", "ex": "Representation matters because entertainment shapes norms."}, {"term": "diversity on screen", "ipa": "/daɪˌvɜːsəti ɒn ˈskriːn/", "pron": "dy-VUR-suh-tee on SCREEN", "fr": "diversité à l’écran", "def": "The presence of varied identities and experiences in media content.", "ex": "Diversity on screen has become a major issue."}, {"term": "inclusion", "ipa": "/ɪnˈkluːʒən/", "pron": "in-KLOO-zhuhn", "fr": "inclusion", "def": "The meaningful participation and visibility of different groups.", "ex": "Inclusion is more than token presence."}, {"term": "tokenism", "ipa": "/ˈtəʊkənɪzəm/", "pron": "TOH-kuh-niz-uhm", "fr": "diversité de façade ; tokenisme", "def": "Superficial inclusion of minority groups to appear diverse.", "ex": "Tokenism can create backlash."}, {"term": "stereotype", "ipa": "/ˈsteriətaɪp/", "pron": "STERR-ee-oh-type", "fr": "stéréotype", "def": "A simplified and often unfair image of a group.", "ex": "Entertainment can reinforce stereotypes."}, {"term": "typecasting", "ipa": "/ˈtaɪpkɑːstɪŋ/", "pron": "TYPE-kast-ing", "fr": "distribution stéréotypée", "def": "Repeatedly casting actors in similar roles because of identity or image.", "ex": "Typecasting limits actors’ careers."}, {"term": "cultural appropriation", "ipa": "/ˌkʌltʃərəl əˌprəʊpriˈeɪʃən/", "pron": "KUL-chuh-ruhl uh-proh-pree-AY-shuhn", "fr": "appropriation culturelle", "def": "Using elements of another culture without respect, context or permission.", "ex": "Cultural appropriation debates often involve music and fashion."}, {"term": "whitewashing", "ipa": "/ˈwaɪtwɒʃɪŋ/", "pron": "WHITE-wosh-ing", "fr": "blanchiment ; whitewashing", "def": "Casting white actors in roles meant for non-white characters or sanitising history.", "ex": "Whitewashing has been criticised in Hollywood."}, {"term": "male gaze", "ipa": "/ˌmeɪl ˈɡeɪz/", "pron": "mayl gayz", "fr": "regard masculin", "def": "A way of depicting women from a heterosexual male perspective.", "ex": "The male gaze remains a key concept in film criticism."}, {"term": "escapism", "ipa": "/ɪˈskeɪpɪzəm/", "pron": "i-SKAY-piz-uhm", "fr": "évasion ; escapisme", "def": "Using entertainment to escape reality or stress.", "ex": "Escapism is one reason audiences love fantasy."}, {"term": "comfort viewing", "ipa": "/ˈkʌmfət ˌvjuːɪŋ/", "pron": "KUM-fuht VYOO-ing", "fr": "visionnage réconfortant", "def": "Watching familiar content for reassurance or relaxation.", "ex": "Sitcoms often become comfort viewing."}, {"term": "cultural consumption", "ipa": "/ˌkʌltʃərəl kənˈsʌmpʃən/", "pron": "KUL-chuh-ruhl kuhn-SUMP-shuhn", "fr": "consommation culturelle", "def": "The way people consume cultural products.", "ex": "Streaming has changed cultural consumption."}, {"term": "shared cultural experience", "ipa": "/ˌʃeəd ˈkʌltʃərəl ɪkˈspɪəriəns/", "pron": "shaird KUL-chuh-ruhl ik-SPEER-ee-uhns", "fr": "expérience culturelle partagée", "def": "A cultural moment experienced collectively by many people.", "ex": "Fragmented media may reduce shared cultural experiences."}, {"term": "water-cooler moment", "ipa": "/ˈwɔːtə ˌkuːlə ˈməʊmənt/", "pron": "WOR-tuh KOO-luh MOH-muhnt", "fr": "moment dont tout le monde parle", "def": "A widely discussed media moment.", "ex": "Streaming can make water-cooler moments rarer."}, {"term": "to stream a series", "ipa": "/striːm ə ˈsɪəriːz/", "pron": "streem uh SEER-eez", "fr": "regarder une série en streaming", "def": "To watch a series online through a streaming service.", "ex": "Millions streamed the series in its first week."}, {"term": "to binge-watch a show", "ipa": "/ˈbɪndʒ wɒtʃ ə ʃəʊ/", "pron": "BINJ-wotch uh show", "fr": "regarder une série en rafale", "def": "To watch many episodes in a short time.", "ex": "Viewers binge-watched the entire season."}, {"term": "to subscribe to a platform", "ipa": "/səbˈskraɪb tə ə ˈplætfɔːm/", "pron": "suhb-SKRYB tuh uh PLAT-form", "fr": "s’abonner à une plateforme", "def": "To pay regularly for access to a platform.", "ex": "Many users subscribe to more than one platform."}, {"term": "to cancel a subscription", "ipa": "/ˈkænsəl ə səbˈskrɪpʃən/", "pron": "KAN-suhl uh suhb-SKRIP-shuhn", "fr": "résilier un abonnement", "def": "To stop paying for a subscription.", "ex": "Users cancel subscriptions when prices rise."}, {"term": "to compete for attention", "ipa": "/kəmˈpiːt fər əˈtenʃən/", "pron": "kuhm-PEET fuh uh-TEN-shuhn", "fr": "se disputer l’attention", "def": "To try to attract people’s limited time and focus.", "ex": "Platforms compete for attention."}, {"term": "to recommend content", "ipa": "/ˌrekəˈmend ˈkɒntent/", "pron": "rek-uh-MEND KON-tent", "fr": "recommander du contenu", "def": "To suggest films, shows or media to users.", "ex": "Algorithms recommend content based on viewing habits."}, {"term": "to collect user data", "ipa": "/kəˈlekt ˈjuːzə ˌdeɪtə/", "pron": "kuh-LEKT YOO-zuh DAY-tuh", "fr": "collecter des données utilisateur", "def": "To gather information about users’ behaviour.", "ex": "Platforms collect user data to personalise recommendations."}, {"term": "to shape viewing habits", "ipa": "/ʃeɪp ˈvjuːɪŋ ˌhæbɪts/", "pron": "shayp VYOO-ing HAB-its", "fr": "façonner les habitudes de visionnage", "def": "To influence how people watch content.", "ex": "Autoplay shapes viewing habits."}, {"term": "to disrupt traditional television", "ipa": "/dɪsˈrʌpt trəˌdɪʃənəl ˈtelɪvɪʒən/", "pron": "dis-RUPT truh-DISH-uh-nuhl TEL-i-vizh-uhn", "fr": "bouleverser la télévision traditionnelle", "def": "To radically change the traditional TV industry.", "ex": "Streaming disrupted traditional television."}, {"term": "to invest in original content", "ipa": "/ɪnˈvest ɪn əˌrɪdʒənəl ˈkɒntent/", "pron": "in-VEST in uh-RIJ-uh-nuhl KON-tent", "fr": "investir dans du contenu original", "def": "To spend money producing exclusive new shows or films.", "ex": "Platforms invest in original content to attract subscribers."}, {"term": "to build a franchise", "ipa": "/bɪld ə ˈfræntʃaɪz/", "pron": "bild uh FRAN-chyze", "fr": "construire une franchise", "def": "To create a long-term series of connected media products.", "ex": "Studios build franchises to reduce risk."}, {"term": "to monetise content", "ipa": "/ˈmʌnɪtaɪz ˈkɒntent/", "pron": "MUN-i-tyze KON-tent", "fr": "monétiser le contenu", "def": "To make money from media content.", "ex": "Creators monetise content through ads and subscriptions."}, {"term": "to challenge stereotypes", "ipa": "/ˈtʃælɪndʒ ˈsteriətaɪps/", "pron": "CHAL-inj STERR-ee-oh-types", "fr": "remettre en cause les stéréotypes", "def": "To question or undermine simplified images of groups.", "ex": "Inclusive storytelling can challenge stereotypes."}, {"term": "to reflect society", "ipa": "/rɪˈflekt səˈsaɪəti/", "pron": "ri-FLEKT suh-SY-uh-tee", "fr": "refléter la société", "def": "To represent social realities, values or tensions.", "ex": "Entertainment both reflects society and shapes it."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p9c79", "part": 9, "chapter": 79, "title": "Sport And Society", "file": "cpge_vocab_part9_chapter79_sport_and_society_premium.html", "count": 147, "sections": [{"title": "A. Core sport, health and community vocabulary", "entries": [{"term": "sport", "ipa": "/spɔːt/", "pron": "sport", "fr": "sport", "def": "Physical activity, usually competitive, governed by rules and often watched by audiences.", "ex": "Sport is both a cultural practice and a global industry."}, {"term": "sports", "ipa": "/spɔːts/", "pron": "sports", "fr": "sports", "def": "Athletic activities considered collectively.", "ex": "Sports can unite communities but also expose social inequalities."}, {"term": "athlete", "ipa": "/ˈæθliːt/", "pron": "ATH-leet", "fr": "athlète", "def": "A person who trains and competes in sport.", "ex": "Elite athletes often face intense public pressure."}, {"term": "professional athlete", "ipa": "/prəˌfeʃənəl ˈæθliːt/", "pron": "pruh-FESH-uh-nuhl ATH-leet", "fr": "athlète professionnel", "def": "An athlete paid to compete in sport.", "ex": "Professional athletes are also public figures."}, {"term": "amateur sport", "ipa": "/ˈæmətə spɔːt/", "pron": "AM-uh-tuh sport", "fr": "sport amateur", "def": "Sport played without professional payment.", "ex": "Amateur sport is essential for local communities."}, {"term": "elite sport", "ipa": "/ɪˈliːt spɔːt/", "pron": "i-LEET sport", "fr": "sport de haut niveau", "def": "Sport at the highest competitive level.", "ex": "Elite sport requires major investment."}, {"term": "grassroots sport", "ipa": "/ˈɡrɑːsruːts spɔːt/", "pron": "GRASS-roots sport", "fr": "sport de base ; sport amateur local", "def": "Local, community-based sport accessible to ordinary people.", "ex": "Grassroots sport improves health and social cohesion."}, {"term": "community sport", "ipa": "/kəˌmjuːnəti spɔːt/", "pron": "kuh-MYOO-nuh-tee sport", "fr": "sport communautaire", "def": "Sport organised within local communities.", "ex": "Community sport can reduce isolation."}, {"term": "school sport", "ipa": "/ˈskuːl spɔːt/", "pron": "school sport", "fr": "sport scolaire", "def": "Sport practised in schools.", "ex": "School sport can promote teamwork and confidence."}, {"term": "physical education", "ipa": "/ˌfɪzɪkəl ˌedjʊˈkeɪʃən/", "pron": "FIZ-i-kuhl ed-yoo-KAY-shuhn", "fr": "éducation physique", "def": "School subject focused on physical activity and sport.", "ex": "Physical education can encourage lifelong fitness."}, {"term": "PE", "ipa": "/ˌpiː ˈiː/", "pron": "pee-ee", "fr": "EPS", "def": "Abbreviation for physical education.", "ex": "PE is sometimes undervalued in schools."}, {"term": "fitness", "ipa": "/ˈfɪtnəs/", "pron": "FIT-nuhs", "fr": "forme physique", "def": "Physical health, strength and ability to exercise.", "ex": "Fitness is linked to long-term health."}, {"term": "physical activity", "ipa": "/ˌfɪzɪkəl ækˈtɪvəti/", "pron": "FIZ-i-kuhl ak-TIV-uh-tee", "fr": "activité physique", "def": "Movement using energy, including sport, walking or exercise.", "ex": "Physical activity reduces the risk of chronic disease."}, {"term": "sedentary lifestyle", "ipa": "/ˈsedəntəri ˈlaɪfstaɪl/", "pron": "SED-uhn-tuh-ree LYFE-style", "fr": "mode de vie sédentaire", "def": "A lifestyle involving too much sitting and little physical activity.", "ex": "Sport can counter a sedentary lifestyle."}, {"term": "public health", "ipa": "/ˌpʌblɪk ˈhelθ/", "pron": "PUB-lik health", "fr": "santé publique", "def": "The health of the population as a whole.", "ex": "Sport policy can be part of public health strategy."}, {"term": "well-being", "ipa": "/ˌwel ˈbiːɪŋ/", "pron": "wel-BEE-ing", "fr": "bien-être", "def": "Physical, mental and social health.", "ex": "Sport can improve well-being."}, {"term": "mental health", "ipa": "/ˌmentəl ˈhelθ/", "pron": "MEN-tuhl health", "fr": "santé mentale", "def": "Emotional and psychological well-being.", "ex": "Athletes increasingly speak about mental health."}, {"term": "resilience", "ipa": "/rɪˈzɪliəns/", "pron": "ri-ZIL-ee-uhns", "fr": "résilience", "def": "The ability to recover from difficulty or pressure.", "ex": "Sport is often said to build resilience."}, {"term": "teamwork", "ipa": "/ˈtiːmwɜːk/", "pron": "TEEM-work", "fr": "travail d’équipe", "def": "Working effectively with others towards a shared goal.", "ex": "Teamwork is a key value in sport."}, {"term": "discipline", "ipa": "/ˈdɪsəplɪn/", "pron": "DIS-uh-plin", "fr": "discipline", "def": "Self-control and regular effort.", "ex": "Training requires discipline."}, {"term": "fair play", "ipa": "/ˌfeə ˈpleɪ/", "pron": "fair play", "fr": "fair-play ; esprit sportif", "def": "Respectful and honest behaviour in sport.", "ex": "Fair play is central to sporting ethics."}, {"term": "sportsmanship", "ipa": "/ˈspɔːtsmənʃɪp/", "pron": "SPORTS-muhn-ship", "fr": "esprit sportif", "def": "Respectful behaviour towards opponents, referees and rules.", "ex": "Sportsmanship matters as much as winning."}, {"term": "competition", "ipa": "/ˌkɒmpəˈtɪʃən/", "pron": "kom-puh-TISH-uhn", "fr": "compétition", "def": "A contest between individuals or teams.", "ex": "Competition can motivate but also create pressure."}, {"term": "competitiveness", "ipa": "/kəmˈpetɪtɪvnəs/", "pron": "kuhm-PET-i-tiv-nuhs", "fr": "esprit de compétition", "def": "The desire or ability to compete successfully.", "ex": "Competitiveness is valued in many societies."}, {"term": "performance", "ipa": "/pəˈfɔːməns/", "pron": "puh-FOR-muhns", "fr": "performance", "def": "How well an athlete, team or organisation performs.", "ex": "Elite sport is obsessed with performance."}, {"term": "high performance", "ipa": "/ˌhaɪ pəˈfɔːməns/", "pron": "high puh-FOR-muhns", "fr": "haute performance", "def": "Exceptional sporting achievement at elite level.", "ex": "High performance programmes are expensive."}, {"term": "training", "ipa": "/ˈtreɪnɪŋ/", "pron": "TRAY-ning", "fr": "entraînement", "def": "Preparation through practice and exercise.", "ex": "Training improves strength and technique."}, {"term": "coach", "ipa": "/kəʊtʃ/", "pron": "kohch", "fr": "entraîneur", "def": "A person who trains and guides athletes or teams.", "ex": "A good coach supports both performance and well-being."}, {"term": "referee", "ipa": "/ˌrefəˈriː/", "pron": "ref-uh-REE", "fr": "arbitre", "def": "An official enforcing the rules during a match.", "ex": "Referees often face abuse from fans."}, {"term": "match", "ipa": "/mætʃ/", "pron": "match", "fr": "match", "def": "A sports contest between teams or players.", "ex": "The match attracted millions of viewers."}, {"term": "tournament", "ipa": "/ˈtʊənəmənt/", "pron": "TOOR-nuh-muhnt", "fr": "tournoi", "def": "A series of contests leading to a winner.", "ex": "The tournament boosted tourism."}, {"term": "championship", "ipa": "/ˈtʃæmpiənʃɪp/", "pron": "CHAM-pee-uhn-ship", "fr": "championnat", "def": "A major competition to decide the best team or athlete.", "ex": "The championship became a national event."}, {"term": "league", "ipa": "/liːɡ/", "pron": "leeg", "fr": "ligue ; championnat", "def": "An organised group of teams competing over a season.", "ex": "The league signed a lucrative broadcasting deal."}, {"term": "club", "ipa": "/klʌb/", "pron": "klub", "fr": "club", "def": "An organisation where people train, play or support a sport.", "ex": "Local clubs are vital for grassroots sport."}, {"term": "supporter", "ipa": "/səˈpɔːtə/", "pron": "suh-POR-tuh", "fr": "supporter", "def": "A person who supports a team or athlete.", "ex": "Supporters create atmosphere and identity."}, {"term": "fan", "ipa": "/fæn/", "pron": "fan", "fr": "fan ; supporter", "def": "An enthusiastic supporter of a team, athlete or sport.", "ex": "Fans are emotionally attached to their teams."}, {"term": "fandom", "ipa": "/ˈfændəm/", "pron": "FAN-duhm", "fr": "communauté de fans", "def": "A community of fans around a team, athlete or sport.", "ex": "Football fandom can become a form of identity."}, {"term": "spectator", "ipa": "/spekˈteɪtə/", "pron": "spek-TAY-tuh", "fr": "spectateur", "def": "A person who watches a sporting event.", "ex": "Spectators generate revenue for clubs."}, {"term": "stadium", "ipa": "/ˈsteɪdiəm/", "pron": "STAY-dee-uhm", "fr": "stade", "def": "A large venue for sports events.", "ex": "Stadiums can transform urban areas."}, {"term": "sports venue", "ipa": "/ˈspɔːts ˌvenjuː/", "pron": "sports VEN-yoo", "fr": "enceinte sportive", "def": "A place where sport is played or watched.", "ex": "Major sports venues are expensive to build."}, {"term": "mega-event", "ipa": "/ˈmeɡə ɪˌvent/", "pron": "MEG-uh i-VENT", "fr": "méga-événement", "def": "A very large international event such as the Olympics or World Cup.", "ex": "Mega-events can bring prestige but also huge costs."}, {"term": "Olympic Games", "ipa": "/əˌlɪmpɪk ˈɡeɪmz/", "pron": "uh-LIM-pik games", "fr": "Jeux olympiques", "def": "The international multi-sport event held every four years.", "ex": "The Olympic Games combine sport, politics and business."}]}, {"title": "B. Mega-events, politics and national identity", "entries": [{"term": "Paralympic Games", "ipa": "/ˌpærəˈlɪmpɪk ˈɡeɪmz/", "pron": "par-uh-LIM-pik games", "fr": "Jeux paralympiques", "def": "The international multi-sport event for athletes with disabilities.", "ex": "The Paralympic Games challenge stereotypes about disability."}, {"term": "World Cup", "ipa": "/ˌwɜːld ˈkʌp/", "pron": "world cup", "fr": "Coupe du monde", "def": "A major international sports tournament, especially in football.", "ex": "The World Cup attracts a global audience."}, {"term": "host country", "ipa": "/ˈhəʊst ˌkʌntri/", "pron": "hohst KUN-tree", "fr": "pays hôte", "def": "The country organising a major event.", "ex": "The host country hopes to benefit from tourism."}, {"term": "host city", "ipa": "/ˈhəʊst ˌsɪti/", "pron": "hohst SIT-ee", "fr": "ville hôte", "def": "A city organising a major sporting event.", "ex": "Host cities often face infrastructure costs."}, {"term": "legacy", "ipa": "/ˈleɡəsi/", "pron": "LEG-uh-see", "fr": "héritage", "def": "Long-term effects left by a sports event.", "ex": "Olympic legacy is often debated."}, {"term": "white elephant", "ipa": "/ˌwaɪt ˈelɪfənt/", "pron": "white EL-i-fuhnt", "fr": "éléphant blanc", "def": "An expensive facility that becomes useless or too costly after an event.", "ex": "Some Olympic stadiums become white elephants."}, {"term": "sportswashing", "ipa": "/ˈspɔːtsˌwɒʃɪŋ/", "pron": "SPORTS-wosh-ing", "fr": "sportswashing", "def": "Using sport to improve the reputation of a country, company or regime.", "ex": "Sportswashing is a major issue in global sport."}, {"term": "soft power", "ipa": "/ˈsɒft ˌpaʊə/", "pron": "soft POW-uh", "fr": "soft power ; pouvoir d’influence", "def": "Influence gained through attraction, culture and image rather than force.", "ex": "Sport can be a tool of soft power."}, {"term": "national pride", "ipa": "/ˌnæʃənəl ˈpraɪd/", "pron": "NASH-uh-nuhl pride", "fr": "fierté nationale", "def": "Positive feeling towards one’s country.", "ex": "Sport can generate national pride."}, {"term": "national identity", "ipa": "/ˌnæʃənəl aɪˈdentəti/", "pron": "NASH-uh-nuhl eye-DEN-tuh-tee", "fr": "identité nationale", "def": "A sense of belonging to a nation.", "ex": "National teams often symbolise national identity."}, {"term": "patriotism", "ipa": "/ˈpætriətɪzəm/", "pron": "PAT-ree-uh-tiz-uhm", "fr": "patriotisme", "def": "Love or loyalty towards one’s country.", "ex": "Sporting events can intensify patriotism."}, {"term": "national anthem", "ipa": "/ˌnæʃənəl ˈænθəm/", "pron": "NASH-uh-nuhl AN-thuhm", "fr": "hymne national", "def": "A country’s official patriotic song.", "ex": "Athletes often stand for the national anthem."}, {"term": "flag", "ipa": "/flæɡ/", "pron": "flag", "fr": "drapeau", "def": "A national symbol often displayed at sports events.", "ex": "Flags are everywhere during international tournaments."}, {"term": "diplomatic boycott", "ipa": "/ˌdɪpləˈmætɪk ˈbɔɪkɒt/", "pron": "dip-luh-MAT-ik BOY-kot", "fr": "boycott diplomatique", "def": "A boycott where officials refuse to attend an event for political reasons.", "ex": "A diplomatic boycott can protest human rights abuses."}, {"term": "boycott", "ipa": "/ˈbɔɪkɒt/", "pron": "BOY-kot", "fr": "boycott", "def": "Refusing to participate in or support something as protest.", "ex": "Some activists called for a boycott of the tournament."}, {"term": "protest", "ipa": "/ˈprəʊtest/", "pron": "PROH-test", "fr": "manifestation ; protestation", "def": "Public opposition or demand for change.", "ex": "Athletes have used sport as a platform for protest."}, {"term": "athlete activism", "ipa": "/ˈæθliːt ˌæktɪvɪzəm/", "pron": "ATH-leet AK-ti-viz-uhm", "fr": "activisme des athlètes", "def": "Political or social activism carried out by athletes.", "ex": "Athlete activism can challenge the idea that sport is apolitical."}, {"term": "taking a knee", "ipa": "/ˌteɪkɪŋ ə ˈniː/", "pron": "TAY-king uh nee", "fr": "mettre un genou à terre", "def": "Kneeling as a symbolic protest, especially against racism.", "ex": "Taking a knee became a global anti-racism gesture."}, {"term": "symbolic protest", "ipa": "/sɪmˌbɒlɪk ˈprəʊtest/", "pron": "sim-BOL-ik PROH-test", "fr": "protestation symbolique", "def": "A protest action designed to send a public message.", "ex": "Symbolic protest can be powerful at sports events."}, {"term": "politicisation of sport", "ipa": "/pəˌlɪtɪsaɪˈzeɪʃən əv spɔːt/", "pron": "puh-lit-i-sy-ZAY-shuhn ov sport", "fr": "politisation du sport", "def": "The process by which sport becomes linked to political debates.", "ex": "The politicisation of sport is not new."}, {"term": "apolitical sport", "ipa": "/ˌeɪpəˈlɪtɪkəl spɔːt/", "pron": "ay-puh-LIT-i-kuhl sport", "fr": "sport apolitique", "def": "The idea that sport should remain separate from politics.", "ex": "The idea of apolitical sport is often challenged."}, {"term": "social justice", "ipa": "/ˌsəʊʃəl ˈdʒʌstɪs/", "pron": "SOH-shuhl JUS-tis", "fr": "justice sociale", "def": "Fairness in rights, opportunities and treatment.", "ex": "Sport can become a platform for social justice."}, {"term": "racial equality", "ipa": "/ˌreɪʃəl iˈkwɒləti/", "pron": "RAY-shuhl i-KWOL-uh-tee", "fr": "égalité raciale", "def": "Equal rights and treatment regardless of race.", "ex": "Athletes have campaigned for racial equality."}, {"term": "racism in sport", "ipa": "/ˈreɪsɪzəm ɪn spɔːt/", "pron": "RAY-siz-uhm in sport", "fr": "racisme dans le sport", "def": "Racist behaviour, discrimination or structures in sport.", "ex": "Racism in sport remains widespread."}, {"term": "racial abuse", "ipa": "/ˌreɪʃəl əˈbjuːs/", "pron": "RAY-shuhl uh-BYOOSS", "fr": "injures racistes", "def": "Insults or harassment based on race.", "ex": "Players often face racial abuse online."}, {"term": "discrimination", "ipa": "/dɪˌskrɪmɪˈneɪʃən/", "pron": "dis-krim-i-NAY-shuhn", "fr": "discrimination", "def": "Unfair treatment based on identity or status.", "ex": "Discrimination can limit access to sport."}, {"term": "inclusion", "ipa": "/ɪnˈkluːʒən/", "pron": "in-KLOO-zhuhn", "fr": "inclusion", "def": "Meaningful participation and belonging for different groups.", "ex": "Inclusion is a major goal of modern sport."}, {"term": "diversity", "ipa": "/daɪˈvɜːsəti/", "pron": "dy-VUR-suh-tee", "fr": "diversité", "def": "The presence of varied identities and backgrounds.", "ex": "Diversity in leadership remains limited."}, {"term": "accessibility", "ipa": "/əkˌsesəˈbɪləti/", "pron": "ak-sess-uh-BIL-uh-tee", "fr": "accessibilité", "def": "The extent to which sport is accessible to everyone, including disabled people.", "ex": "Accessibility is essential for inclusive sport."}, {"term": "disability sport", "ipa": "/ˌdɪsəˈbɪləti spɔːt/", "pron": "dis-uh-BIL-uh-tee sport", "fr": "handisport", "def": "Sport practised by people with disabilities.", "ex": "Disability sport challenges stereotypes."}, {"term": "adaptive sport", "ipa": "/əˌdæptɪv spɔːt/", "pron": "uh-DAP-tiv sport", "fr": "sport adapté", "def": "Sport modified to suit people with disabilities.", "ex": "Adaptive sport makes participation possible."}, {"term": "gender equality", "ipa": "/ˌdʒendər iˈkwɒləti/", "pron": "JEN-duh i-KWOL-uh-tee", "fr": "égalité des sexes", "def": "Equal rights and opportunities regardless of gender.", "ex": "Gender equality in sport remains unfinished."}]}, {"title": "C. Equality, inclusion, doping and governance", "entries": [{"term": "women’s sport", "ipa": "/ˈwɪmɪnz spɔːt/", "pron": "WIM-inz sport", "fr": "sport féminin", "def": "Sport played by women or girls.", "ex": "Women’s sport has gained visibility."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart de rémunération entre les sexes", "def": "The difference in pay between men and women.", "ex": "The gender pay gap in sport can be huge."}, {"term": "equal pay", "ipa": "/ˌiːkwəl ˈpeɪ/", "pron": "EE-kwuhl pay", "fr": "égalité salariale", "def": "Equal payment for comparable work or performance.", "ex": "Women footballers have fought for equal pay."}, {"term": "media coverage", "ipa": "/ˈmiːdiə ˌkʌvərɪdʒ/", "pron": "MEE-dee-uh KUV-uh-rij", "fr": "couverture médiatique", "def": "The amount and type of media attention given to something.", "ex": "Women’s sport receives less media coverage."}, {"term": "sexualisation", "ipa": "/ˌsekʃuəlaɪˈzeɪʃən/", "pron": "sek-shoo-uh-ly-ZAY-shuhn", "fr": "sexualisation", "def": "Presenting athletes in an overly sexual way.", "ex": "Female athletes often criticise sexualisation."}, {"term": "body image", "ipa": "/ˈbɒdi ˌɪmɪdʒ/", "pron": "BOD-ee IM-ij", "fr": "image corporelle", "def": "How people perceive their own body.", "ex": "Sport can improve or damage body image."}, {"term": "transgender athlete", "ipa": "/trænzˌdʒendər ˈæθliːt/", "pron": "tranz-JEN-duh ATH-leet", "fr": "athlète transgenre", "def": "An athlete whose gender identity differs from their sex assigned at birth.", "ex": "Transgender athletes are at the centre of fairness debates."}, {"term": "sex testing", "ipa": "/ˈseks ˌtestɪŋ/", "pron": "seks TEST-ing", "fr": "test de féminité ; contrôle du sexe", "def": "Testing athletes’ biological sex characteristics, often controversial.", "ex": "Sex testing has been criticised as invasive."}, {"term": "fair competition", "ipa": "/ˌfeə ˌkɒmpəˈtɪʃən/", "pron": "fair kom-puh-TISH-uhn", "fr": "compétition équitable", "def": "Competition considered equal and just.", "ex": "Sport governing bodies try to ensure fair competition."}, {"term": "level playing field", "ipa": "/ˌlevəl ˈpleɪɪŋ fiːld/", "pron": "LEV-uhl PLAY-ing field", "fr": "égalité des chances ; règles du jeu équitables", "def": "A situation where competitors have equal chances.", "ex": "Doping undermines a level playing field."}, {"term": "doping", "ipa": "/ˈdəʊpɪŋ/", "pron": "DOH-ping", "fr": "dopage", "def": "Using banned substances or methods to improve performance.", "ex": "Doping damages trust in sport."}, {"term": "performance-enhancing drug", "ipa": "/pəˈfɔːməns ɪnˌhɑːnsɪŋ drʌɡ/", "pron": "puh-FOR-muhns in-HAN-sing drug", "fr": "produit dopant", "def": "A substance used to improve athletic performance.", "ex": "Performance-enhancing drugs are banned."}, {"term": "PED", "ipa": "/ˌpiː iː ˈdiː/", "pron": "pee-ee-dee", "fr": "produit dopant", "def": "Abbreviation for performance-enhancing drug.", "ex": "PED use can lead to bans."}, {"term": "anti-doping agency", "ipa": "/ˌænti ˈdəʊpɪŋ ˈeɪdʒənsi/", "pron": "AN-tee DOH-ping AY-juhn-see", "fr": "agence antidopage", "def": "An organisation fighting doping in sport.", "ex": "Anti-doping agencies test athletes."}, {"term": "drug test", "ipa": "/ˈdrʌɡ test/", "pron": "drug test", "fr": "test antidopage", "def": "A test checking for banned substances.", "ex": "Athletes may face random drug tests."}, {"term": "ban", "ipa": "/bæn/", "pron": "ban", "fr": "interdiction ; suspension", "def": "An official prohibition or suspension.", "ex": "A doping ban can end a career."}, {"term": "match-fixing", "ipa": "/ˈmætʃ ˌfɪksɪŋ/", "pron": "match FIK-sing", "fr": "match truqué", "def": "Illegally arranging the outcome of a sports match.", "ex": "Match-fixing threatens the integrity of sport."}, {"term": "corruption", "ipa": "/kəˈrʌpʃən/", "pron": "kuh-RUP-shuhn", "fr": "corruption", "def": "Dishonest or illegal behaviour by people in power.", "ex": "Corruption scandals have affected sports organisations."}, {"term": "governing body", "ipa": "/ˈɡʌvənɪŋ ˌbɒdi/", "pron": "GUV-uh-ning BOD-ee", "fr": "instance dirigeante", "def": "An organisation that controls and regulates a sport.", "ex": "Governing bodies set rules and organise competitions."}, {"term": "sports federation", "ipa": "/ˈspɔːts ˌfedəˈreɪʃən/", "pron": "sports fed-uh-RAY-shuhn", "fr": "fédération sportive", "def": "An organisation governing a sport nationally or internationally.", "ex": "Sports federations face pressure to become more transparent."}, {"term": "transparency", "ipa": "/trænˈspærənsi/", "pron": "tran-SPARR-uhn-see", "fr": "transparence", "def": "Openness about decisions, finances and governance.", "ex": "Transparency can reduce corruption."}, {"term": "accountability", "ipa": "/əˌkaʊntəˈbɪləti/", "pron": "uh-kown-tuh-BIL-uh-tee", "fr": "responsabilité ; redevabilité", "def": "Responsibility for actions and decisions.", "ex": "Sports leaders should face accountability."}, {"term": "commercialisation", "ipa": "/kəˌmɜːʃəlaɪˈzeɪʃən/", "pron": "kuh-MUR-shuh-ly-ZAY-shuhn", "fr": "commercialisation", "def": "The process of making sport more focused on profit and business.", "ex": "Commercialisation has transformed football."}, {"term": "commodification", "ipa": "/kəˌmɒdɪfɪˈkeɪʃən/", "pron": "kuh-mod-i-fi-KAY-shuhn", "fr": "marchandisation", "def": "Turning something into a product to be bought and sold.", "ex": "Critics denounce the commodification of athletes."}, {"term": "sports industry", "ipa": "/ˈspɔːts ˌɪndəstri/", "pron": "sports IN-duh-stree", "fr": "industrie du sport", "def": "The economic sector linked to sport, media, sponsorship and events.", "ex": "The sports industry is worth billions."}, {"term": "sponsorship", "ipa": "/ˈspɒnsəʃɪp/", "pron": "SPON-suh-ship", "fr": "sponsoring ; parrainage", "def": "Financial support by a brand in exchange for visibility.", "ex": "Sponsorship is crucial for professional sport."}, {"term": "sponsor", "ipa": "/ˈspɒnsə/", "pron": "SPON-suh", "fr": "sponsor ; parrain", "def": "A company or person funding a team, athlete or event.", "ex": "Sponsors care about image and exposure."}, {"term": "endorsement deal", "ipa": "/ɪnˈdɔːsmənt diːl/", "pron": "in-DORS-muhnt deel", "fr": "contrat de sponsoring", "def": "A contract where an athlete promotes a product or brand.", "ex": "Star athletes sign lucrative endorsement deals."}, {"term": "broadcasting rights", "ipa": "/ˈbrɔːdkɑːstɪŋ raɪts/", "pron": "BROD-kast-ing rights", "fr": "droits de diffusion", "def": "Rights to show sports events on TV or online.", "ex": "Broadcasting rights fund major leagues."}, {"term": "TV rights", "ipa": "/ˌtiː ˈviː raɪts/", "pron": "tee-vee rights", "fr": "droits télévisés", "def": "Rights to broadcast events on television.", "ex": "TV rights changed the economics of football."}, {"term": "streaming rights", "ipa": "/ˈstriːmɪŋ raɪts/", "pron": "STREE-ming rights", "fr": "droits de streaming", "def": "Rights to show events through streaming platforms.", "ex": "Streaming rights are increasingly valuable."}, {"term": "pay-per-view", "ipa": "/ˌpeɪ pə ˈvjuː/", "pron": "pay-puh-VYOO", "fr": "paiement à la séance", "def": "A system where viewers pay for a single event.", "ex": "Boxing often uses pay-per-view."}, {"term": "merchandising", "ipa": "/ˈmɜːtʃəndaɪzɪŋ/", "pron": "MUR-chuhn-dy-zing", "fr": "produits dérivés ; merchandising", "def": "Selling branded products linked to a team, athlete or event.", "ex": "Merchandising strengthens fan loyalty."}, {"term": "ticket prices", "ipa": "/ˈtɪkɪt ˌpraɪsɪz/", "pron": "TIK-it PRY-siz", "fr": "prix des billets", "def": "The cost of attending sports events.", "ex": "Rising ticket prices can exclude working-class fans."}, {"term": "gentrification of sport", "ipa": "/ˌdʒentrɪfɪˈkeɪʃən əv spɔːt/", "pron": "jen-tri-fi-KAY-shuhn ov sport", "fr": "gentrification du sport", "def": "The process by which sport becomes less accessible to ordinary or working-class fans.", "ex": "Some fans resent the gentrification of sport."}, {"term": "fan ownership", "ipa": "/ˈfæn ˌəʊnəʃɪp/", "pron": "fan OH-nuh-ship", "fr": "propriété par les supporters", "def": "A model where supporters own or partly control a club.", "ex": "Fan ownership can strengthen democratic governance."}, {"term": "financial fair play", "ipa": "/faɪˌnænʃəl ˌfeə ˈpleɪ/", "pron": "fy-NAN-shuhl fair play", "fr": "fair-play financier", "def": "Rules intended to prevent clubs from spending beyond their means.", "ex": "Financial fair play remains controversial."}, {"term": "transfer market", "ipa": "/ˈtrænsfɜː ˌmɑːkɪt/", "pron": "TRANS-fur MAR-kit", "fr": "marché des transferts", "def": "The system of buying and selling players between clubs.", "ex": "The transfer market has become highly inflated."}, {"term": "salary cap", "ipa": "/ˈsæləri kæp/", "pron": "SAL-uh-ree kap", "fr": "plafond salarial", "def": "A limit on how much teams can spend on player salaries.", "ex": "Salary caps aim to preserve competitive balance."}, {"term": "competitive balance", "ipa": "/kəmˌpetɪtɪv ˈbæləns/", "pron": "kuhm-PET-i-tiv BAL-uhns", "fr": "équilibre compétitif", "def": "A situation where teams have relatively equal chances of success.", "ex": "Leagues need competitive balance to remain exciting."}, {"term": "sports betting", "ipa": "/ˈspɔːts ˌbetɪŋ/", "pron": "sports BET-ing", "fr": "paris sportifs", "def": "Gambling on sports results or events.", "ex": "Sports betting raises addiction and integrity concerns."}, {"term": "gambling", "ipa": "/ˈɡæmblɪŋ/", "pron": "GAM-bling", "fr": "jeu d’argent", "def": "Betting money on uncertain outcomes.", "ex": "Gambling sponsorship is controversial in sport."}]}, {"title": "D. Commercialisation, welfare, technology and e-sports", "entries": [{"term": "gambling addiction", "ipa": "/ˈɡæmblɪŋ əˌdɪkʃən/", "pron": "GAM-bling uh-DIK-shuhn", "fr": "addiction aux jeux d’argent", "def": "Compulsive gambling causing harm.", "ex": "Sports betting can worsen gambling addiction."}, {"term": "safeguarding", "ipa": "/ˈseɪfɡɑːdɪŋ/", "pron": "SAYF-gar-ding", "fr": "protection des personnes vulnérables", "def": "Protecting children and vulnerable people from harm.", "ex": "Safeguarding failures have damaged sports institutions."}, {"term": "abuse in sport", "ipa": "/əˈbjuːs ɪn spɔːt/", "pron": "uh-BYOOSS in sport", "fr": "abus dans le sport", "def": "Physical, emotional or sexual abuse within sporting contexts.", "ex": "Abuse in sport must be taken seriously."}, {"term": "concussion", "ipa": "/kənˈkʌʃən/", "pron": "kuhn-KUSH-uhn", "fr": "commotion cérébrale", "def": "A brain injury caused by a blow or impact.", "ex": "Concussion has become a major issue in contact sports."}, {"term": "head injury", "ipa": "/ˈhed ˌɪndʒəri/", "pron": "hed IN-juh-ree", "fr": "traumatisme crânien", "def": "Injury to the head or brain.", "ex": "Head injuries can have long-term effects."}, {"term": "player welfare", "ipa": "/ˈpleɪə ˈwelfeə/", "pron": "PLAY-uh WEL-fair", "fr": "bien-être des joueurs", "def": "The physical and mental well-being of athletes.", "ex": "Player welfare is often sacrificed for profit."}, {"term": "burnout", "ipa": "/ˈbɜːnaʊt/", "pron": "BURN-out", "fr": "épuisement ; burn-out", "def": "Physical or mental exhaustion caused by prolonged pressure.", "ex": "Young athletes can suffer burnout."}, {"term": "overtraining", "ipa": "/ˌəʊvəˈtreɪnɪŋ/", "pron": "OH-vuh-TRAY-ning", "fr": "surentraînement", "def": "Training too much without enough recovery.", "ex": "Overtraining increases injury risk."}, {"term": "injury prevention", "ipa": "/ˈɪndʒəri prɪˌvenʃən/", "pron": "IN-juh-ree pri-VEN-shuhn", "fr": "prévention des blessures", "def": "Measures to reduce the risk of injury.", "ex": "Injury prevention is part of athlete welfare."}, {"term": "sports science", "ipa": "/ˈspɔːts ˌsaɪəns/", "pron": "sports SY-uhns", "fr": "sciences du sport", "def": "Scientific study of performance, training and health in sport.", "ex": "Sports science has transformed training."}, {"term": "sports medicine", "ipa": "/ˈspɔːts ˌmedsən/", "pron": "sports MED-suhn", "fr": "médecine du sport", "def": "Medical care and research focused on sport and exercise.", "ex": "Sports medicine helps athletes recover safely."}, {"term": "sports psychology", "ipa": "/ˈspɔːts saɪˌkɒlədʒi/", "pron": "sports sy-KOL-uh-jee", "fr": "psychologie du sport", "def": "Psychology applied to sport, performance and well-being.", "ex": "Sports psychology helps athletes handle pressure."}, {"term": "data analytics", "ipa": "/ˈdeɪtə ˌænəˈlɪtɪks/", "pron": "DAY-tuh an-uh-LIT-iks", "fr": "analyse de données", "def": "Using data to analyse performance and decisions.", "ex": "Data analytics now influences recruitment."}, {"term": "wearable technology", "ipa": "/ˌweərəbəl tekˈnɒlədʒi/", "pron": "WAIR-uh-buhl tek-NOL-uh-jee", "fr": "technologie portable ; objets connectés", "def": "Devices worn to track physical data.", "ex": "Wearable technology monitors performance and fatigue."}, {"term": "VAR", "ipa": "/ˌviː eɪ ˈɑː/", "pron": "vee-ay-ar", "fr": "assistance vidéo à l’arbitrage", "def": "Video Assistant Referee, used to review decisions in football.", "ex": "VAR has changed football debates."}, {"term": "technology in sport", "ipa": "/tekˈnɒlədʒi ɪn spɔːt/", "pron": "tek-NOL-uh-jee in sport", "fr": "technologie dans le sport", "def": "Use of tools, data and devices in sporting contexts.", "ex": "Technology in sport raises fairness questions."}, {"term": "e-sports", "ipa": "/ˈiːspɔːts/", "pron": "EE-sports", "fr": "e-sport", "def": "Competitive video gaming watched by audiences.", "ex": "E-sports challenge traditional definitions of sport."}, {"term": "to promote public health", "ipa": "/prəˈməʊt ˌpʌblɪk ˈhelθ/", "pron": "pruh-MOHT PUB-lik health", "fr": "promouvoir la santé publique", "def": "To improve population health.", "ex": "Grassroots sport can promote public health."}, {"term": "to foster social cohesion", "ipa": "/ˈfɒstə ˌsəʊʃəl kəʊˈhiːʒən/", "pron": "FOS-tuh SOH-shuhl koh-HEE-zhuhn", "fr": "favoriser la cohésion sociale", "def": "To strengthen trust and unity within society.", "ex": "Sport can foster social cohesion."}, {"term": "to challenge discrimination", "ipa": "/ˈtʃælɪndʒ dɪˌskrɪmɪˈneɪʃən/", "pron": "CHAL-inj dis-krim-i-NAY-shuhn", "fr": "combattre la discrimination", "def": "To oppose unfair treatment.", "ex": "Athletes can challenge discrimination."}, {"term": "to take a knee", "ipa": "/teɪk ə ˈniː/", "pron": "tayk uh nee", "fr": "mettre un genou à terre", "def": "To kneel as a symbolic protest.", "ex": "Players took a knee before the match."}, {"term": "to host a mega-event", "ipa": "/həʊst ə ˈmeɡə ɪˌvent/", "pron": "hohst uh MEG-uh i-VENT", "fr": "accueillir un méga-événement", "def": "To organise a very large international event.", "ex": "Countries compete to host mega-events."}, {"term": "to boost national pride", "ipa": "/buːst ˌnæʃənəl ˈpraɪd/", "pron": "boost NASH-uh-nuhl pride", "fr": "renforcer la fierté nationale", "def": "To increase patriotic feeling.", "ex": "Sporting victories can boost national pride."}, {"term": "to generate revenue", "ipa": "/ˈdʒenəreɪt ˈrevənjuː/", "pron": "JEN-uh-rayt REV-uhn-yoo", "fr": "générer des revenus", "def": "To produce income.", "ex": "Broadcasting rights generate revenue."}, {"term": "to secure sponsorship", "ipa": "/sɪˈkjʊə ˈspɒnsəʃɪp/", "pron": "si-KYOOR SPON-suh-ship", "fr": "obtenir un sponsoring", "def": "To obtain financial support from sponsors.", "ex": "Clubs try to secure sponsorship."}, {"term": "to ensure fair competition", "ipa": "/ɪnˈʃʊə ˌfeə ˌkɒmpəˈtɪʃən/", "pron": "in-SHOOR fair kom-puh-TISH-uhn", "fr": "garantir une compétition équitable", "def": "To make competition equal and just.", "ex": "Anti-doping rules ensure fair competition."}, {"term": "to combat doping", "ipa": "/ˈkɒmbæt ˈdəʊpɪŋ/", "pron": "KOM-bat DOH-ping", "fr": "lutter contre le dopage", "def": "To fight the use of banned performance-enhancing substances.", "ex": "Sports bodies must combat doping."}, {"term": "to protect player welfare", "ipa": "/prəˈtekt ˈpleɪə ˈwelfeə/", "pron": "pruh-TEKT PLAY-uh WEL-fair", "fr": "protéger le bien-être des joueurs", "def": "To safeguard athletes’ health and well-being.", "ex": "Leagues must protect player welfare."}, {"term": "to commercialise sport", "ipa": "/kəˈmɜːʃəlaɪz spɔːt/", "pron": "kuh-MUR-shuh-lyze sport", "fr": "commercialiser le sport", "def": "To make sport more profit-driven.", "ex": "Media deals have commercialised sport."}, {"term": "to price out fans", "ipa": "/praɪs aʊt fænz/", "pron": "pryss out fanz", "fr": "exclure les fans par les prix", "def": "To make tickets too expensive for ordinary supporters.", "ex": "Rising ticket prices price out fans."}, {"term": "to inspire young people", "ipa": "/ɪnˈspaɪə jʌŋ ˈpiːpəl/", "pron": "in-SPY-uh young PEE-puhl", "fr": "inspirer les jeunes", "def": "To motivate young people through example.", "ex": "Successful athletes can inspire young people."}]}, {"title": "E. High-value verbs and exam collocations", "entries": []}]}, {"id": "p10c80", "part": 10, "chapter": 80, "title": "Essential Verbs For Essays", "file": "cpge_vocab_part10_chapter80_essential_verbs_for_essays_premium.html", "count": 122, "sections": [{"title": "A. Presenting an argument", "entries": [{"term": "to argue", "ipa": "/ˈɑːɡjuː/", "pron": "AR-gyoo", "fr": "soutenir ; faire valoir", "def": "To present reasons supporting a point of view.", "ex": "The author argues that democracy is under pressure."}, {"term": "to claim", "ipa": "/kleɪm/", "pron": "klaym", "fr": "affirmer ; prétendre", "def": "To state that something is true, sometimes without proving it fully.", "ex": "The article claims that social media has changed political debate."}, {"term": "to assert", "ipa": "/əˈsɜːt/", "pron": "uh-SURT", "fr": "affirmer avec force", "def": "To state something firmly and confidently.", "ex": "The columnist asserts that reform is urgently needed."}, {"term": "to contend", "ipa": "/kənˈtend/", "pron": "kuhn-TEND", "fr": "soutenir ; avancer", "def": "To argue or maintain a position, especially in formal writing.", "ex": "Critics contend that the policy will increase inequality."}, {"term": "to maintain", "ipa": "/meɪnˈteɪn/", "pron": "mayn-TAYN", "fr": "soutenir ; maintenir", "def": "To continue to argue that something is true.", "ex": "The government maintains that the reform is fair."}, {"term": "to suggest", "ipa": "/səˈdʒest/", "pron": "suh-JEST", "fr": "suggérer", "def": "To imply or propose an idea without stating it too strongly.", "ex": "The figures suggest that poverty is rising."}, {"term": "to imply", "ipa": "/ɪmˈplaɪ/", "pron": "im-PLY", "fr": "impliquer ; sous-entendre", "def": "To suggest something indirectly.", "ex": "The headline implies that immigration is the main problem."}, {"term": "to indicate", "ipa": "/ˈɪndɪkeɪt/", "pron": "IN-di-kayt", "fr": "indiquer", "def": "To show or point to something.", "ex": "Recent polls indicate a loss of trust in institutions."}, {"term": "to reveal", "ipa": "/rɪˈviːl/", "pron": "ri-VEEL", "fr": "révéler", "def": "To show something previously hidden or unclear.", "ex": "The report reveals deep regional inequalities."}, {"term": "to demonstrate", "ipa": "/ˈdemənstreɪt/", "pron": "DEM-uhn-strayt", "fr": "démontrer", "def": "To show clearly through evidence or reasoning.", "ex": "This example demonstrates the limits of state intervention."}, {"term": "to highlight", "ipa": "/ˈhaɪlaɪt/", "pron": "HY-light", "fr": "mettre en évidence", "def": "To draw attention to an important point.", "ex": "The article highlights the cost of political polarisation."}, {"term": "to underline", "ipa": "/ˌʌndəˈlaɪn/", "pron": "UN-duh-lyne", "fr": "souligner", "def": "To emphasise the importance of something.", "ex": "The scandal underlines the need for transparency."}, {"term": "to emphasise", "ipa": "/ˈemfəsaɪz/", "pron": "EM-fuh-syze", "fr": "mettre l’accent sur", "def": "To give special importance to something.", "ex": "The author emphasises the role of education."}, {"term": "to stress", "ipa": "/stres/", "pron": "stress", "fr": "insister sur ; souligner", "def": "To strongly emphasise something.", "ex": "The journalist stresses the urgency of climate action."}, {"term": "to point out", "ipa": "/pɔɪnt ˈaʊt/", "pron": "point out", "fr": "faire remarquer", "def": "To mention or draw attention to a fact.", "ex": "The article points out that the reform may hurt low-income families."}, {"term": "to note", "ipa": "/nəʊt/", "pron": "noht", "fr": "noter ; faire observer", "def": "To mention or observe something.", "ex": "The author notes that public opinion remains divided."}]}, {"title": "B. Analysing and evaluating", "entries": [{"term": "to examine", "ipa": "/ɪɡˈzæmɪn/", "pron": "ig-ZAM-in", "fr": "examiner", "def": "To study or analyse something closely.", "ex": "This essay examines the causes of democratic backsliding."}, {"term": "to analyse", "ipa": "/ˈænəlaɪz/", "pron": "AN-uh-lyze", "fr": "analyser", "def": "To study something in detail to understand it.", "ex": "We must analyse the economic consequences of the crisis."}, {"term": "to assess", "ipa": "/əˈses/", "pron": "uh-SESS", "fr": "évaluer", "def": "To judge the value, importance or extent of something.", "ex": "The essay assesses the effectiveness of gun control."}, {"term": "to evaluate", "ipa": "/ɪˈvæljueɪt/", "pron": "i-VAL-yoo-ayt", "fr": "évaluer", "def": "To judge something carefully according to criteria.", "ex": "The article evaluates the impact of Brexit on trade."}, {"term": "to explore", "ipa": "/ɪkˈsplɔː/", "pron": "ik-SPLOR", "fr": "explorer", "def": "To examine an issue in an open or detailed way.", "ex": "This question explores the relationship between freedom and security."}, {"term": "to investigate", "ipa": "/ɪnˈvestɪɡeɪt/", "pron": "in-VES-ti-gayt", "fr": "enquêter sur ; étudier", "def": "To examine facts in order to discover the truth.", "ex": "Journalists investigated the lobbying scandal."}, {"term": "to consider", "ipa": "/kənˈsɪdə/", "pron": "kuhn-SID-uh", "fr": "considérer ; envisager", "def": "To think about a point, factor or possibility.", "ex": "We should consider the social effects of automation."}, {"term": "to address", "ipa": "/əˈdres/", "pron": "uh-DRESS", "fr": "traiter ; s’attaquer à", "def": "To deal with a problem, question or issue.", "ex": "The government failed to address housing inequality."}, {"term": "to tackle", "ipa": "/ˈtækəl/", "pron": "TAK-uhl", "fr": "s’attaquer à", "def": "To deal with a difficult problem actively.", "ex": "The policy aims to tackle unemployment."}, {"term": "to confront", "ipa": "/kənˈfrʌnt/", "pron": "kuhn-FRUNT", "fr": "affronter", "def": "To face a problem directly.", "ex": "Societies must confront structural racism."}, {"term": "to challenge", "ipa": "/ˈtʃælɪndʒ/", "pron": "CHAL-inj", "fr": "remettre en cause ; contester", "def": "To question, oppose or test something.", "ex": "The movement challenges traditional gender roles."}, {"term": "to question", "ipa": "/ˈkwestʃən/", "pron": "KWES-chuhn", "fr": "remettre en question", "def": "To doubt or examine critically.", "ex": "The article questions the fairness of the system."}]}, {"title": "C. Criticising, defending and proposing", "entries": [{"term": "to criticise", "ipa": "/ˈkrɪtɪsaɪz/", "pron": "KRIT-i-syze", "fr": "critiquer", "def": "To express disapproval or point out faults.", "ex": "The opposition criticised the government’s response."}, {"term": "to condemn", "ipa": "/kənˈdem/", "pron": "kuhn-DEM", "fr": "condamner", "def": "To strongly criticise something as wrong or unacceptable.", "ex": "Human rights groups condemned the crackdown."}, {"term": "to denounce", "ipa": "/dɪˈnaʊns/", "pron": "di-NOWNSS", "fr": "dénoncer", "def": "To publicly condemn or expose wrongdoing.", "ex": "Activists denounced corporate greenwashing."}, {"term": "to expose", "ipa": "/ɪkˈspəʊz/", "pron": "ik-SPOHZ", "fr": "révéler ; exposer", "def": "To reveal something hidden, wrong or unfair.", "ex": "The investigation exposed corruption."}, {"term": "to debunk", "ipa": "/ˌdiːˈbʌŋk/", "pron": "dee-BUNK", "fr": "démystifier ; réfuter", "def": "To show that a claim or belief is false.", "ex": "Fact-checkers debunked the conspiracy theory."}, {"term": "to refute", "ipa": "/rɪˈfjuːt/", "pron": "ri-FYOOT", "fr": "réfuter", "def": "To prove that an argument or claim is wrong.", "ex": "The evidence refutes the minister’s claim."}, {"term": "to reject", "ipa": "/rɪˈdʒekt/", "pron": "ri-JEKT", "fr": "rejeter", "def": "To refuse to accept an idea, claim or proposal.", "ex": "The court rejected the appeal."}, {"term": "to oppose", "ipa": "/əˈpəʊz/", "pron": "uh-POHZ", "fr": "s’opposer à", "def": "To be against an idea, policy or action.", "ex": "Many voters oppose tax increases."}, {"term": "to defend", "ipa": "/dɪˈfend/", "pron": "di-FEND", "fr": "défendre", "def": "To support or protect an idea, policy or person.", "ex": "The article defends freedom of speech."}, {"term": "to justify", "ipa": "/ˈdʒʌstɪfaɪ/", "pron": "JUS-ti-fy", "fr": "justifier", "def": "To give reasons why something is acceptable or necessary.", "ex": "The government tried to justify the restrictions."}, {"term": "to support", "ipa": "/səˈpɔːt/", "pron": "suh-PORT", "fr": "soutenir", "def": "To back an idea, argument or policy.", "ex": "The data support the author’s argument."}, {"term": "to advocate", "ipa": "/ˈædvəkeɪt/", "pron": "AD-vuh-kayt", "fr": "préconiser ; défendre", "def": "To publicly support or recommend a policy or cause.", "ex": "The NGO advocates stronger climate laws."}, {"term": "to call for", "ipa": "/ˈkɔːl fɔː/", "pron": "call for", "fr": "appeler à ; réclamer", "def": "To publicly demand or request something.", "ex": "The report calls for urgent reform."}, {"term": "to demand", "ipa": "/dɪˈmɑːnd/", "pron": "di-MAHND", "fr": "exiger", "def": "To ask for something firmly.", "ex": "Protesters demanded equal rights."}, {"term": "to urge", "ipa": "/ɜːdʒ/", "pron": "urj", "fr": "exhorter ; pousser à", "def": "To strongly encourage someone to act.", "ex": "Scientists urged governments to cut emissions."}, {"term": "to propose", "ipa": "/prəˈpəʊz/", "pron": "pruh-POHZ", "fr": "proposer", "def": "To suggest a plan or idea.", "ex": "The minister proposed a new immigration law."}, {"term": "to implement", "ipa": "/ˈɪmplɪment/", "pron": "IM-pli-ment", "fr": "mettre en œuvre", "def": "To put a policy or plan into practice.", "ex": "The policy was implemented too slowly."}, {"term": "to enforce", "ipa": "/ɪnˈfɔːs/", "pron": "in-FORSS", "fr": "faire appliquer", "def": "To make sure rules or laws are obeyed.", "ex": "Authorities must enforce environmental standards."}, {"term": "to regulate", "ipa": "/ˈreɡjʊleɪt/", "pron": "REG-yuh-layt", "fr": "réglementer", "def": "To control something through rules.", "ex": "Governments struggle to regulate online platforms."}, {"term": "to ban", "ipa": "/bæn/", "pron": "ban", "fr": "interdire", "def": "To officially forbid something.", "ex": "Several countries banned single-use plastics."}, {"term": "to restrict", "ipa": "/rɪˈstrɪkt/", "pron": "ri-STRIKT", "fr": "restreindre", "def": "To limit something.", "ex": "The law restricts hate speech."}, {"term": "to curb", "ipa": "/kɜːb/", "pron": "kurb", "fr": "freiner ; limiter", "def": "To control or limit something harmful.", "ex": "New rules aim to curb misinformation."}]}, {"title": "D. Causes, consequences and evidence", "entries": [{"term": "to reduce", "ipa": "/rɪˈdjuːs/", "pron": "ri-DYOOSS", "fr": "réduire", "def": "To make something smaller or lower.", "ex": "The policy could reduce inequality."}, {"term": "to increase", "ipa": "/ɪnˈkriːs/", "pron": "in-KREESS", "fr": "augmenter", "def": "To make or become greater.", "ex": "Inflation increased pressure on households."}, {"term": "to boost", "ipa": "/buːst/", "pron": "boost", "fr": "stimuler ; renforcer", "def": "To increase or improve something.", "ex": "Investment can boost economic growth."}, {"term": "to strengthen", "ipa": "/ˈstreŋθən/", "pron": "STRENG-thuhn", "fr": "renforcer", "def": "To make something stronger or more effective.", "ex": "The reform aims to strengthen democratic institutions."}, {"term": "to weaken", "ipa": "/ˈwiːkən/", "pron": "WEE-kuhn", "fr": "affaiblir", "def": "To make something less strong or effective.", "ex": "Corruption weakens public trust."}, {"term": "to undermine", "ipa": "/ˌʌndəˈmaɪn/", "pron": "UN-duh-myne", "fr": "saper ; miner", "def": "To gradually weaken or damage something.", "ex": "Disinformation undermines democracy."}, {"term": "to threaten", "ipa": "/ˈθretən/", "pron": "THRET-uhn", "fr": "menacer", "def": "To put something at risk.", "ex": "Climate change threatens food security."}, {"term": "to harm", "ipa": "/hɑːm/", "pron": "harm", "fr": "nuire à", "def": "To damage or hurt someone or something.", "ex": "Austerity can harm vulnerable groups."}, {"term": "to fuel", "ipa": "/ˈfjuːəl/", "pron": "FYOO-uhl", "fr": "alimenter", "def": "To make something stronger or more intense.", "ex": "Social media can fuel polarisation."}, {"term": "to trigger", "ipa": "/ˈtrɪɡə/", "pron": "TRIG-uh", "fr": "déclencher", "def": "To cause something to start.", "ex": "The decision triggered protests."}, {"term": "to spark", "ipa": "/spɑːk/", "pron": "spark", "fr": "susciter ; déclencher", "def": "To cause a sudden reaction or debate.", "ex": "The ruling sparked national controversy."}, {"term": "to lead to", "ipa": "/liːd tə/", "pron": "leed tuh", "fr": "conduire à", "def": "To cause or result in something.", "ex": "The crisis led to new regulations."}, {"term": "to result in", "ipa": "/rɪˈzʌlt ɪn/", "pron": "ri-ZULT in", "fr": "entraîner ; aboutir à", "def": "To have something as a consequence.", "ex": "The policy resulted in higher costs."}, {"term": "to contribute to", "ipa": "/kənˈtrɪbjuːt tə/", "pron": "kuhn-TRIB-yoot tuh", "fr": "contribuer à", "def": "To be one cause among others.", "ex": "Housing shortages contribute to inequality."}, {"term": "to stem from", "ipa": "/stem frəm/", "pron": "stem from", "fr": "provenir de ; découler de", "def": "To originate from or be caused by something.", "ex": "Political distrust stems from repeated scandals."}, {"term": "to be rooted in", "ipa": "/bi ˈruːtɪd ɪn/", "pron": "bee ROO-tid in", "fr": "être enraciné dans", "def": "To have deep origins in something.", "ex": "The crisis is rooted in long-term neglect."}, {"term": "to reflect", "ipa": "/rɪˈflekt/", "pron": "ri-FLEKT", "fr": "refléter", "def": "To show or express a wider reality.", "ex": "The vote reflects growing frustration."}, {"term": "to illustrate", "ipa": "/ˈɪləstreɪt/", "pron": "IL-uh-strayt", "fr": "illustrer", "def": "To give an example that makes something clear.", "ex": "This case illustrates the limits of free speech."}, {"term": "to exemplify", "ipa": "/ɪɡˈzemplɪfaɪ/", "pron": "ig-ZEM-pli-fy", "fr": "illustrer parfaitement", "def": "To be a clear example of something.", "ex": "The scandal exemplifies institutional failure."}, {"term": "to embody", "ipa": "/ɪmˈbɒdi/", "pron": "im-BOD-ee", "fr": "incarner", "def": "To represent an idea or quality in a concrete form.", "ex": "The protest embodies democratic dissent."}, {"term": "to symbolise", "ipa": "/ˈsɪmbəlaɪz/", "pron": "SIM-buh-lyze", "fr": "symboliser", "def": "To represent an idea or value.", "ex": "The wall symbolised division."}, {"term": "to shed light on", "ipa": "/ʃed laɪt ɒn/", "pron": "shed light on", "fr": "éclairer ; faire la lumière sur", "def": "To help explain or clarify something.", "ex": "The survey sheds light on voters’ fears."}, {"term": "to draw attention to", "ipa": "/drɔː əˈtenʃən tə/", "pron": "draw uh-TEN-shuhn tuh", "fr": "attirer l’attention sur", "def": "To make people notice something.", "ex": "The article draws attention to rural poverty."}, {"term": "to raise awareness", "ipa": "/reɪz əˈweənəs/", "pron": "rayz uh-WAIR-nuhs", "fr": "sensibiliser", "def": "To increase public knowledge of an issue.", "ex": "Campaigns raise awareness about mental health."}, {"term": "to frame", "ipa": "/freɪm/", "pron": "fraym", "fr": "cadrer ; présenter", "def": "To present an issue in a particular way.", "ex": "The media framed migration as a security issue."}, {"term": "to portray", "ipa": "/pɔːˈtreɪ/", "pron": "por-TRAY", "fr": "dépeindre ; représenter", "def": "To represent someone or something in a particular way.", "ex": "The article portrays young people as politically engaged."}, {"term": "to depict", "ipa": "/dɪˈpɪkt/", "pron": "di-PIKT", "fr": "dépeindre", "def": "To describe or show something.", "ex": "The cartoon depicts politicians as out of touch."}]}, {"title": "E. Comparison, society and power relations", "entries": [{"term": "to define", "ipa": "/dɪˈfaɪn/", "pron": "di-FYNE", "fr": "définir", "def": "To explain the meaning or boundaries of something.", "ex": "The essay defines populism as anti-elite politics."}, {"term": "to distinguish", "ipa": "/dɪˈstɪŋɡwɪʃ/", "pron": "di-STING-gwish", "fr": "distinguer", "def": "To recognise or explain the difference between things.", "ex": "We must distinguish legal migration from asylum."}, {"term": "to compare", "ipa": "/kəmˈpeə/", "pron": "kuhm-PAIR", "fr": "comparer", "def": "To examine similarities and differences.", "ex": "The article compares the US and UK systems."}, {"term": "to contrast", "ipa": "/kənˈtrɑːst/", "pron": "kuhn-TRAST", "fr": "opposer ; mettre en contraste", "def": "To highlight differences between things.", "ex": "The writer contrasts urban wealth with rural poverty."}, {"term": "to link", "ipa": "/lɪŋk/", "pron": "link", "fr": "lier", "def": "To connect two ideas or facts.", "ex": "The author links poverty to educational inequality."}, {"term": "to connect", "ipa": "/kəˈnekt/", "pron": "kuh-NEKT", "fr": "relier", "def": "To show a relationship between ideas or events.", "ex": "The report connects climate change and migration."}, {"term": "to divide", "ipa": "/dɪˈvaɪd/", "pron": "di-VYDE", "fr": "diviser", "def": "To split people, groups or opinions.", "ex": "The issue divides public opinion."}, {"term": "to polarise", "ipa": "/ˈpəʊləraɪz/", "pron": "POH-luh-ryze", "fr": "polariser", "def": "To make opinions more extreme and opposed.", "ex": "Culture wars polarise voters."}, {"term": "to unite", "ipa": "/juːˈnaɪt/", "pron": "yoo-NYTE", "fr": "unir", "def": "To bring people together.", "ex": "Sport can unite a nation."}, {"term": "to mobilise", "ipa": "/ˈməʊbɪlaɪz/", "pron": "MOH-bi-lyze", "fr": "mobiliser", "def": "To organise people to act collectively.", "ex": "Social media can mobilise protesters."}, {"term": "to empower", "ipa": "/ɪmˈpaʊə/", "pron": "im-POW-uh", "fr": "donner du pouvoir ; autonomiser", "def": "To give people power, confidence or agency.", "ex": "Education can empower disadvantaged groups."}, {"term": "to marginalise", "ipa": "/ˈmɑːdʒɪnəlaɪz/", "pron": "MAR-ji-nuh-lyze", "fr": "marginaliser", "def": "To push a group to the edge of society or power.", "ex": "Minorities may be marginalised by the system."}, {"term": "to exclude", "ipa": "/ɪkˈskluːd/", "pron": "ik-SKLOOD", "fr": "exclure", "def": "To leave someone or something out.", "ex": "High costs exclude poorer families."}, {"term": "to include", "ipa": "/ɪnˈkluːd/", "pron": "in-KLOOD", "fr": "inclure", "def": "To make someone part of something.", "ex": "Inclusive policies include vulnerable groups."}, {"term": "to discriminate against", "ipa": "/dɪˈskrɪmɪneɪt əˌɡenst/", "pron": "dis-KRIM-i-nayt uh-GENST", "fr": "discriminer", "def": "To treat someone unfairly because of identity or status.", "ex": "The law discriminates against minorities."}, {"term": "to exploit", "ipa": "/ɪkˈsplɔɪt/", "pron": "ik-SPLOYT", "fr": "exploiter", "def": "To use someone or something unfairly for benefit.", "ex": "Gig platforms may exploit workers."}, {"term": "to protect", "ipa": "/prəˈtekt/", "pron": "pruh-TEKT", "fr": "protéger", "def": "To keep someone or something safe.", "ex": "The law protects freedom of expression."}, {"term": "to safeguard", "ipa": "/ˈseɪfɡɑːd/", "pron": "SAYF-gard", "fr": "préserver ; protéger", "def": "To protect something important from harm.", "ex": "Institutions must safeguard democratic norms."}, {"term": "to preserve", "ipa": "/prɪˈzɜːv/", "pron": "pri-ZURV", "fr": "préserver", "def": "To keep something safe or unchanged.", "ex": "Policy should preserve cultural diversity."}, {"term": "to promote", "ipa": "/prəˈməʊt/", "pron": "pruh-MOHT", "fr": "promouvoir", "def": "To encourage or support the development of something.", "ex": "Schools should promote critical thinking."}, {"term": "to foster", "ipa": "/ˈfɒstə/", "pron": "FOS-tuh", "fr": "favoriser", "def": "To encourage the development of something positive.", "ex": "Community sport fosters social cohesion."}, {"term": "to encourage", "ipa": "/ɪnˈkʌrɪdʒ/", "pron": "in-KUR-ij", "fr": "encourager", "def": "To give support or confidence to someone or something.", "ex": "Tax incentives encourage investment."}, {"term": "to discourage", "ipa": "/dɪsˈkʌrɪdʒ/", "pron": "dis-KUR-ij", "fr": "décourager", "def": "To make someone less likely to do something.", "ex": "High prices discourage public transport use."}, {"term": "to enable", "ipa": "/ɪˈneɪbəl/", "pron": "i-NAY-buhl", "fr": "permettre", "def": "To make something possible.", "ex": "Technology enables remote work."}, {"term": "to prevent", "ipa": "/prɪˈvent/", "pron": "pri-VENT", "fr": "empêcher ; prévenir", "def": "To stop something from happening.", "ex": "Regulation can prevent abuse."}, {"term": "to hinder", "ipa": "/ˈhɪndə/", "pron": "HIN-duh", "fr": "entraver", "def": "To make something more difficult.", "ex": "Bureaucracy hinders innovation."}, {"term": "to exacerbate", "ipa": "/ɪɡˈzæsəbeɪt/", "pron": "ig-ZAS-uh-bayt", "fr": "aggraver", "def": "To make a problem worse.", "ex": "Inflation exacerbates poverty."}, {"term": "to alleviate", "ipa": "/əˈliːvieɪt/", "pron": "uh-LEE-vee-ayt", "fr": "atténuer ; soulager", "def": "To make suffering or a problem less severe.", "ex": "Welfare can alleviate hardship."}]}, {"title": "F. Policy, change and nuance", "entries": [{"term": "to mitigate", "ipa": "/ˈmɪtɪɡeɪt/", "pron": "MIT-i-gayt", "fr": "atténuer", "def": "To reduce the severity of something harmful.", "ex": "Adaptation can mitigate climate impacts."}, {"term": "to adapt", "ipa": "/əˈdæpt/", "pron": "uh-DAPT", "fr": "s’adapter", "def": "To adjust to new conditions.", "ex": "Cities must adapt to heatwaves."}, {"term": "to transform", "ipa": "/trænsˈfɔːm/", "pron": "trans-FORM", "fr": "transformer", "def": "To change something deeply.", "ex": "AI may transform the labour market."}, {"term": "to reshape", "ipa": "/ˌriːˈʃeɪp/", "pron": "ree-SHAYP", "fr": "remodeler", "def": "To change the form or character of something.", "ex": "Streaming reshaped entertainment."}, {"term": "to redefine", "ipa": "/ˌriːdɪˈfaɪn/", "pron": "ree-di-FYNE", "fr": "redéfinir", "def": "To change the meaning or nature of something.", "ex": "Remote work has redefined the office."}, {"term": "to pave the way for", "ipa": "/peɪv ðə weɪ fɔː/", "pron": "payv thuh way for", "fr": "ouvrir la voie à", "def": "To make future change possible.", "ex": "The ruling paved the way for further reforms."}, {"term": "to give rise to", "ipa": "/ɡɪv raɪz tə/", "pron": "giv ryze tuh", "fr": "donner naissance à ; engendrer", "def": "To cause something to appear or develop.", "ex": "Economic insecurity gave rise to populist anger."}, {"term": "to play a role in", "ipa": "/pleɪ ə rəʊl ɪn/", "pron": "play uh rohl in", "fr": "jouer un rôle dans", "def": "To contribute to a situation or outcome.", "ex": "Education plays a role in social mobility."}, {"term": "to raise questions about", "ipa": "/reɪz ˈkwestʃənz əˌbaʊt/", "pron": "rayz KWES-chuhnz uh-bowt", "fr": "soulever des questions sur", "def": "To make people question or debate something.", "ex": "AI raises questions about employment."}, {"term": "to cast doubt on", "ipa": "/kɑːst daʊt ɒn/", "pron": "kast dowt on", "fr": "jeter le doute sur", "def": "To make something seem uncertain.", "ex": "The scandal cast doubt on the minister’s honesty."}, {"term": "to take into account", "ipa": "/teɪk ˈɪntə əˈkaʊnt/", "pron": "tayk IN-tuh uh-KOWNT", "fr": "prendre en compte", "def": "To consider something when judging or deciding.", "ex": "Policy must take local conditions into account."}, {"term": "to overlook", "ipa": "/ˌəʊvəˈlʊk/", "pron": "OH-vuh-look", "fr": "négliger ; passer sous silence", "def": "To fail to notice or consider something.", "ex": "The article overlooks the economic dimension."}, {"term": "to acknowledge", "ipa": "/əkˈnɒlɪdʒ/", "pron": "ak-NOL-ij", "fr": "reconnaître", "def": "To admit or recognise something as true.", "ex": "The author acknowledges the limits of the argument."}, {"term": "to concede", "ipa": "/kənˈsiːd/", "pron": "kuhn-SEED", "fr": "concéder", "def": "To admit something is true despite weakening one’s argument.", "ex": "The writer concedes that regulation may be difficult."}, {"term": "to qualify", "ipa": "/ˈkwɒlɪfaɪ/", "pron": "KWOL-i-fy", "fr": "nuancer", "def": "To make a statement less absolute or more precise.", "ex": "This claim must be qualified."}, {"term": "to nuance", "ipa": "/ˈnjuːɑːns/", "pron": "NYOO-ahns", "fr": "nuancer", "def": "To make an argument more subtle and balanced.", "ex": "A good essay nuances the opposition between freedom and security."}, {"term": "to conclude", "ipa": "/kənˈkluːd/", "pron": "kuhn-KLOOD", "fr": "conclure", "def": "To end by reaching a final judgement.", "ex": "We may conclude that reform is necessary but insufficient."}]}]}, {"id": "p10c81", "part": 10, "chapter": 81, "title": "Linking Words", "file": "cpge_vocab_part10_chapter81_linking_words_premium.html", "count": 121, "sections": [{"title": "A. Ordering ideas and structuring paragraphs", "entries": [{"term": "firstly", "ipa": "/ˈfɜːstli/", "pron": "FURST-lee", "fr": "premièrement", "def": "Used to introduce the first point in a sequence.", "ex": "Firstly, the policy may reduce inequality."}, {"term": "first of all", "ipa": "/ˌfɜːst əv ˈɔːl/", "pron": "first-ov-AWL", "fr": "tout d’abord", "def": "Used to introduce the first and often most basic point.", "ex": "First of all, the article highlights a major social divide."}, {"term": "to begin with", "ipa": "/tə bɪˈɡɪn wɪð/", "pron": "tuh bi-GIN with", "fr": "pour commencer", "def": "Used to open an argument or explanation.", "ex": "To begin with, the figures reveal a worrying trend."}, {"term": "at the outset", "ipa": "/æt ði ˈaʊtset/", "pron": "at thee OWT-set", "fr": "d’emblée ; au départ", "def": "At the beginning; used in formal writing.", "ex": "At the outset, it is important to define populism."}, {"term": "in the first place", "ipa": "/ɪn ðə ˈfɜːst pleɪs/", "pron": "in thuh FIRST place", "fr": "en premier lieu", "def": "Used to introduce an initial reason or argument.", "ex": "In the first place, democracy requires trust."}, {"term": "secondly", "ipa": "/ˈsekəndli/", "pron": "SEK-uhnd-lee", "fr": "deuxièmement", "def": "Used to introduce a second point.", "ex": "Secondly, the reform may be costly."}, {"term": "thirdly", "ipa": "/ˈθɜːdli/", "pron": "THURD-lee", "fr": "troisièmement", "def": "Used to introduce a third point.", "ex": "Thirdly, public opinion remains divided."}, {"term": "finally", "ipa": "/ˈfaɪnəli/", "pron": "FY-nuh-lee", "fr": "enfin", "def": "Used to introduce the last point in a sequence.", "ex": "Finally, the article raises ethical questions."}, {"term": "lastly", "ipa": "/ˈlɑːstli/", "pron": "LAHST-lee", "fr": "en dernier lieu", "def": "Used to introduce the last element in a list.", "ex": "Lastly, the measure could deepen regional inequalities."}, {"term": "above all", "ipa": "/əˌbʌv ˈɔːl/", "pron": "uh-BUV awl", "fr": "surtout ; avant tout", "def": "Most importantly.", "ex": "Above all, the crisis is political."}, {"term": "more importantly", "ipa": "/mɔːr ɪmˈpɔːtəntli/", "pron": "more im-POR-tuhnt-lee", "fr": "plus important encore", "def": "Used to introduce a more significant point.", "ex": "More importantly, the law may undermine civil liberties."}, {"term": "significantly", "ipa": "/sɪɡˈnɪfɪkəntli/", "pron": "sig-NIF-i-kuhnt-lee", "fr": "de manière significative", "def": "In a meaningful or important way.", "ex": "Significantly, young voters reject both major parties."}, {"term": "notably", "ipa": "/ˈnəʊtəbli/", "pron": "NOH-tuh-blee", "fr": "notamment", "def": "Used to mention something important or remarkable.", "ex": "Notably, the article focuses on rural voters."}, {"term": "in particular", "ipa": "/ɪn pəˈtɪkjʊlə/", "pron": "in puh-TIK-yuh-luh", "fr": "en particulier", "def": "Especially; specifically.", "ex": "This affects young people in particular."}, {"term": "particularly", "ipa": "/pəˈtɪkjʊləli/", "pron": "puh-TIK-yuh-luh-lee", "fr": "particulièrement", "def": "Especially or to a great degree.", "ex": "This issue is particularly relevant to democracies."}, {"term": "especially", "ipa": "/ɪˈspeʃəli/", "pron": "i-SPESH-uh-lee", "fr": "surtout ; particulièrement", "def": "More than usual or more than others.", "ex": "The policy affects poorer households especially."}, {"term": "moreover", "ipa": "/mɔːrˈəʊvə/", "pron": "mor-OH-vuh", "fr": "de plus ; qui plus est", "def": "In addition; used to add a strong point.", "ex": "Moreover, the reform lacks public support."}]}, {"title": "B. Adding, comparing and reinforcing", "entries": [{"term": "furthermore", "ipa": "/ˌfɜːðəˈmɔː/", "pron": "FUR-thuh-more", "fr": "en outre ; de plus", "def": "In addition; formal connector.", "ex": "Furthermore, the measure could prove ineffective."}, {"term": "in addition", "ipa": "/ɪn əˈdɪʃən/", "pron": "in uh-DISH-uhn", "fr": "en outre ; de plus", "def": "Used to add information.", "ex": "In addition, social media has amplified polarisation."}, {"term": "additionally", "ipa": "/əˈdɪʃənəli/", "pron": "uh-DISH-uh-nuh-lee", "fr": "de plus", "def": "Also; used to add another point.", "ex": "Additionally, the evidence is incomplete."}, {"term": "as well as", "ipa": "/æz ˈwel æz/", "pron": "az WEL az", "fr": "ainsi que ; en plus de", "def": "In addition to.", "ex": "The crisis affects workers as well as students."}, {"term": "besides", "ipa": "/bɪˈsaɪdz/", "pron": "bi-SYDZ", "fr": "d’ailleurs ; en outre", "def": "In addition; sometimes used to add a practical point.", "ex": "Besides, the proposal is unlikely to pass."}, {"term": "also", "ipa": "/ˈɔːlsəʊ/", "pron": "AWL-soh", "fr": "aussi ; également", "def": "In addition.", "ex": "The article also mentions economic insecurity."}, {"term": "too", "ipa": "/tuː/", "pron": "too", "fr": "aussi", "def": "Also; usually placed at the end.", "ex": "This matters for democracy too."}, {"term": "as well", "ipa": "/æz ˈwel/", "pron": "az WEL", "fr": "aussi ; également", "def": "Also; placed at the end.", "ex": "The issue affects rural areas as well."}, {"term": "not only... but also", "ipa": "/nɒt ˈəʊnli bət ˈɔːlsəʊ/", "pron": "not OHN-lee but AWL-soh", "fr": "non seulement... mais aussi", "def": "Used to add and intensify two linked ideas.", "ex": "The policy is not only expensive but also unfair."}, {"term": "both... and", "ipa": "/bəʊθ ænd/", "pron": "bohth and", "fr": "à la fois... et", "def": "Used to link two equally important elements.", "ex": "The crisis is both economic and political."}, {"term": "equally", "ipa": "/ˈiːkwəli/", "pron": "EE-kwuh-lee", "fr": "également ; tout aussi", "def": "In the same way or to the same extent.", "ex": "Equally, citizens must be informed."}, {"term": "similarly", "ipa": "/ˈsɪmələli/", "pron": "SIM-uh-luh-lee", "fr": "de même ; pareillement", "def": "In a similar way.", "ex": "Similarly, the UK faces a housing shortage."}, {"term": "likewise", "ipa": "/ˈlaɪkwaɪz/", "pron": "LYK-wyz", "fr": "de même", "def": "In the same way; formal.", "ex": "Likewise, the policy could affect small businesses."}, {"term": "by the same token", "ipa": "/baɪ ðə seɪm ˈtəʊkən/", "pron": "by thuh same TOH-kuhn", "fr": "pour la même raison", "def": "For the same reason.", "ex": "By the same token, schools need more funding."}, {"term": "in the same vein", "ipa": "/ɪn ðə seɪm veɪn/", "pron": "in thuh same vayn", "fr": "dans le même esprit", "def": "In a similar style or argument.", "ex": "In the same vein, the article criticises austerity."}, {"term": "however", "ipa": "/haʊˈevə/", "pron": "how-EV-uh", "fr": "cependant ; toutefois", "def": "Used to introduce contrast.", "ex": "However, the evidence remains limited."}, {"term": "nevertheless", "ipa": "/ˌnevəðəˈles/", "pron": "nev-uh-thuh-LESS", "fr": "néanmoins", "def": "Despite what has just been said.", "ex": "Nevertheless, the reform may be necessary."}]}, {"title": "C. Contrast and concession", "entries": [{"term": "nonetheless", "ipa": "/ˌnʌnðəˈles/", "pron": "nun-thuh-LESS", "fr": "néanmoins", "def": "Nevertheless; formal.", "ex": "Nonetheless, the risks should not be ignored."}, {"term": "yet", "ipa": "/jet/", "pron": "yet", "fr": "pourtant ; cependant", "def": "But; used to introduce contrast.", "ex": "The economy is growing, yet inequality persists."}, {"term": "still", "ipa": "/stɪl/", "pron": "stil", "fr": "pourtant ; malgré cela", "def": "Despite this; used to introduce a remaining point.", "ex": "Still, many voters remain sceptical."}, {"term": "even so", "ipa": "/ˌiːvən ˈsəʊ/", "pron": "EE-vuhn soh", "fr": "malgré tout", "def": "Despite that.", "ex": "Even so, the proposal deserves attention."}, {"term": "on the other hand", "ipa": "/ɒn ði ˈʌðə hænd/", "pron": "on thee UTH-uh hand", "fr": "d’un autre côté", "def": "Used to introduce a contrasting point.", "ex": "On the other hand, regulation may threaten free speech."}, {"term": "by contrast", "ipa": "/baɪ ˈkɒntrɑːst/", "pron": "by KON-trast", "fr": "par contraste", "def": "Used to emphasise difference.", "ex": "By contrast, younger voters support the reform."}, {"term": "in contrast", "ipa": "/ɪn ˈkɒntrɑːst/", "pron": "in KON-trast", "fr": "en revanche ; par contraste", "def": "Used to compare differences.", "ex": "In contrast, the US system is more decentralised."}, {"term": "unlike", "ipa": "/ˌʌnˈlaɪk/", "pron": "un-LYK", "fr": "contrairement à", "def": "Different from.", "ex": "Unlike France, the UK has no written constitution."}, {"term": "whereas", "ipa": "/ˌweərˈæz/", "pron": "wair-AZ", "fr": "tandis que ; alors que", "def": "While; used to compare contrasting facts.", "ex": "The rich benefit, whereas the poor lose support."}, {"term": "while", "ipa": "/waɪl/", "pron": "wyle", "fr": "tandis que ; alors que", "def": "Although or whereas.", "ex": "While the policy is popular, it may be ineffective."}, {"term": "whereby", "ipa": "/weəˈbaɪ/", "pron": "wair-BY", "fr": "par lequel", "def": "By which; through which.", "ex": "The system creates a process whereby citizens can appeal."}, {"term": "whereas by comparison", "ipa": "/weərˈæz baɪ kəmˈpærɪsən/", "pron": "wair-AZ by kuhm-PAR-i-suhn", "fr": "alors que, par comparaison", "def": "Used to sharpen a comparison.", "ex": "Whereas by comparison, the British system relies on convention."}, {"term": "conversely", "ipa": "/ˈkɒnvɜːsli/", "pron": "KON-vurss-lee", "fr": "inversement", "def": "In the opposite way.", "ex": "Conversely, local policies may be more effective."}, {"term": "instead", "ipa": "/ɪnˈsted/", "pron": "in-STED", "fr": "à la place ; au contraire", "def": "Rather than something else.", "ex": "Instead, the government chose tax cuts."}, {"term": "rather", "ipa": "/ˈrɑːðə/", "pron": "RAH-thuh", "fr": "plutôt", "def": "Used to correct or clarify.", "ex": "The issue is not legal but rather political."}, {"term": "rather than", "ipa": "/ˈrɑːðə ðæn/", "pron": "RAH-thuh than", "fr": "plutôt que", "def": "Instead of.", "ex": "The article focuses on causes rather than solutions."}, {"term": "instead of", "ipa": "/ɪnˈsted əv/", "pron": "in-STED ov", "fr": "au lieu de", "def": "In place of.", "ex": "Instead of reforming the system, leaders blamed migrants."}, {"term": "although", "ipa": "/ɔːlˈðəʊ/", "pron": "awl-THOH", "fr": "bien que", "def": "Despite the fact that.", "ex": "Although the reform is popular, it is expensive."}, {"term": "though", "ipa": "/ðəʊ/", "pron": "thoh", "fr": "bien que ; cependant", "def": "Although; often less formal.", "ex": "The policy is ambitious, though difficult to implement."}, {"term": "even though", "ipa": "/ˈiːvən ðəʊ/", "pron": "EE-vuhn thoh", "fr": "même si ; bien que", "def": "Despite the fact that.", "ex": "Even though inflation has fallen, prices remain high."}, {"term": "despite", "ipa": "/dɪˈspaɪt/", "pron": "di-SPYT", "fr": "malgré", "def": "In spite of; followed by a noun or -ing form.", "ex": "Despite public anger, the bill passed."}, {"term": "in spite of", "ipa": "/ɪn ˈspaɪt əv/", "pron": "in SPYT ov", "fr": "malgré", "def": "Despite; followed by a noun or -ing form.", "ex": "In spite of criticism, the policy survived."}, {"term": "for all that", "ipa": "/fɔːr ɔːl ðæt/", "pron": "for awl that", "fr": "malgré tout", "def": "Despite everything; formal.", "ex": "For all that, the argument remains convincing."}, {"term": "admittedly", "ipa": "/ədˈmɪtɪdli/", "pron": "ad-MIT-id-lee", "fr": "certes ; il faut l’admettre", "def": "Used to concede a point before qualifying it.", "ex": "Admittedly, the proposal is costly."}, {"term": "granted", "ipa": "/ˈɡrɑːntɪd/", "pron": "GRAHN-tid", "fr": "certes", "def": "Used to accept a point before making a contrast.", "ex": "Granted, the reform is imperfect."}, {"term": "to some extent", "ipa": "/tə səm ɪkˈstent/", "pron": "tuh sum ik-STENT", "fr": "dans une certaine mesure", "def": "Partly, but not completely.", "ex": "To some extent, the criticism is justified."}, {"term": "up to a point", "ipa": "/ˌʌp tə ə ˈpɔɪnt/", "pron": "up tuh uh POINT", "fr": "jusqu’à un certain point", "def": "Partly true, but limited.", "ex": "The argument is convincing up to a point."}, {"term": "in part", "ipa": "/ɪn ˈpɑːt/", "pron": "in PART", "fr": "en partie", "def": "Partly.", "ex": "The crisis is in part due to poor governance."}, {"term": "partly", "ipa": "/ˈpɑːtli/", "pron": "PART-lee", "fr": "partiellement ; en partie", "def": "Not completely; to some degree.", "ex": "The rise in prices is partly explained by energy costs."}, {"term": "arguably", "ipa": "/ˈɑːɡjuəbli/", "pron": "AR-gyoo-uh-blee", "fr": "on peut soutenir que", "def": "It can be argued that; used to express cautious judgement.", "ex": "Arguably, this is the greatest challenge facing democracies."}, {"term": "presumably", "ipa": "/prɪˈzjuːməbli/", "pron": "pri-ZYOO-muh-blee", "fr": "vraisemblablement", "def": "Probably, based on what is known.", "ex": "Presumably, voters were reacting to inflation."}, {"term": "apparently", "ipa": "/əˈpærəntli/", "pron": "uh-PARR-uhnt-lee", "fr": "apparemment", "def": "It seems that; according to available evidence.", "ex": "Apparently, the reform failed to convince young voters."}, {"term": "seemingly", "ipa": "/ˈsiːmɪŋli/", "pron": "SEE-ming-lee", "fr": "apparemment", "def": "Apparently; in appearance.", "ex": "Seemingly neutral rules can have unequal effects."}]}, {"title": "D. Clarification, causes and consequences", "entries": [{"term": "apparently paradoxically", "ipa": "/əˈpærəntli ˌpærəˈdɒksɪkəli/", "pron": "uh-PARR-uhnt-lee par-uh-DOK-si-kuh-lee", "fr": "paradoxalement en apparence", "def": "Used to introduce a point that seems contradictory.", "ex": "Apparently paradoxically, more information can create more confusion."}, {"term": "in fact", "ipa": "/ɪn ˈfækt/", "pron": "in fakt", "fr": "en fait", "def": "Used to correct, emphasise or add truth.", "ex": "In fact, the policy may worsen inequality."}, {"term": "indeed", "ipa": "/ɪnˈdiːd/", "pron": "in-DEED", "fr": "en effet ; effectivement", "def": "Used to strengthen or confirm a point.", "ex": "Indeed, the figures confirm this trend."}, {"term": "actually", "ipa": "/ˈæktʃuəli/", "pron": "AK-choo-uh-lee", "fr": "en réalité", "def": "In reality; used to correct an assumption.", "ex": "Actually, the problem predates the pandemic."}, {"term": "as a matter of fact", "ipa": "/æz ə ˈmætər əv fækt/", "pron": "az uh MAT-uh ov fakt", "fr": "en réalité ; de fait", "def": "In fact; used to introduce factual clarification.", "ex": "As a matter of fact, turnout increased."}, {"term": "in reality", "ipa": "/ɪn riˈæləti/", "pron": "in ree-AL-uh-tee", "fr": "en réalité", "def": "What is actually true.", "ex": "In reality, the reform benefits only a minority."}, {"term": "in practice", "ipa": "/ɪn ˈpræktɪs/", "pron": "in PRAK-tis", "fr": "en pratique", "def": "In real situations, not theory.", "ex": "In practice, the law is difficult to enforce."}, {"term": "in theory", "ipa": "/ɪn ˈθɪəri/", "pron": "in THEE-uh-ree", "fr": "en théorie", "def": "According to an idea, not necessarily reality.", "ex": "In theory, the system is fair."}, {"term": "therefore", "ipa": "/ˈðeəfɔː/", "pron": "THAIR-for", "fr": "donc ; par conséquent", "def": "For that reason; as a result.", "ex": "Therefore, reform is unavoidable."}, {"term": "thus", "ipa": "/ðʌs/", "pron": "thus", "fr": "ainsi ; donc", "def": "Therefore; formal.", "ex": "Thus, the policy may fail."}, {"term": "hence", "ipa": "/hens/", "pron": "hens", "fr": "d’où ; par conséquent", "def": "For this reason; formal.", "ex": "Hence the need for stricter regulation."}, {"term": "consequently", "ipa": "/ˈkɒnsɪkwəntli/", "pron": "KON-si-kwent-lee", "fr": "par conséquent", "def": "As a result.", "ex": "Consequently, public trust declined."}, {"term": "as a result", "ipa": "/æz ə rɪˈzʌlt/", "pron": "az uh ri-ZULT", "fr": "par conséquent", "def": "Because of this.", "ex": "As a result, many families moved away."}, {"term": "as a consequence", "ipa": "/æz ə ˈkɒnsɪkwəns/", "pron": "az uh KON-si-kwens", "fr": "en conséquence", "def": "Because of this; formal.", "ex": "As a consequence, inequality widened."}, {"term": "for this reason", "ipa": "/fə ðɪs ˈriːzən/", "pron": "fuh this REE-zuhn", "fr": "pour cette raison", "def": "Because of this.", "ex": "For this reason, the reform is controversial."}, {"term": "this is why", "ipa": "/ðɪs ɪz ˈwaɪ/", "pron": "this iz why", "fr": "c’est pourquoi", "def": "This explains the reason.", "ex": "This is why voters are sceptical."}, {"term": "that is why", "ipa": "/ðæt ɪz ˈwaɪ/", "pron": "that iz why", "fr": "c’est pourquoi", "def": "That explains the reason.", "ex": "That is why the issue matters."}, {"term": "because", "ipa": "/bɪˈkɒz/", "pron": "bi-KOZ", "fr": "parce que", "def": "For the reason that.", "ex": "The policy failed because it lacked funding."}, {"term": "since", "ipa": "/sɪns/", "pron": "sins", "fr": "puisque ; étant donné que", "def": "Because; given that.", "ex": "Since inequality is rising, reform is necessary."}, {"term": "as", "ipa": "/æz/", "pron": "az", "fr": "comme ; puisque", "def": "Because; used to introduce a reason.", "ex": "As trust is low, leaders must act carefully."}, {"term": "given that", "ipa": "/ˈɡɪvən ðæt/", "pron": "GIV-uhn that", "fr": "étant donné que", "def": "Considering the fact that.", "ex": "Given that prices remain high, voters are angry."}, {"term": "considering that", "ipa": "/kənˈsɪdərɪŋ ðæt/", "pron": "kuhn-SID-uh-ring that", "fr": "étant donné que", "def": "Taking into account the fact that.", "ex": "Considering that wages stagnated, the backlash is unsurprising."}, {"term": "owing to", "ipa": "/ˈəʊɪŋ tə/", "pron": "OH-ing tuh", "fr": "en raison de", "def": "Because of; formal.", "ex": "Owing to inflation, households reduced spending."}, {"term": "due to", "ipa": "/ˈdjuː tə/", "pron": "dyoo tuh", "fr": "en raison de", "def": "Because of.", "ex": "The delay was due to political opposition."}, {"term": "thanks to", "ipa": "/ˈθæŋks tə/", "pron": "thanks tuh", "fr": "grâce à", "def": "Because of something positive.", "ex": "Thanks to investment, unemployment fell."}, {"term": "because of", "ipa": "/bɪˈkɒz əv/", "pron": "bi-KOZ ov", "fr": "à cause de ; en raison de", "def": "For the reason of.", "ex": "Because of drought, farmers left the region."}, {"term": "for instance", "ipa": "/fər ˈɪnstəns/", "pron": "fur IN-stuhns", "fr": "par exemple", "def": "For example.", "ex": "For instance, young voters prioritise climate policy."}, {"term": "for example", "ipa": "/fər ɪɡˈzɑːmpəl/", "pron": "fur ig-ZAM-puhl", "fr": "par exemple", "def": "Used to introduce an example.", "ex": "For example, the UK has seen rising food bank use."}, {"term": "such as", "ipa": "/sʌtʃ æz/", "pron": "such az", "fr": "comme ; tel que", "def": "Used to introduce examples.", "ex": "Issues such as housing and healthcare dominate the debate."}, {"term": "including", "ipa": "/ɪnˈkluːdɪŋ/", "pron": "in-KLOO-ding", "fr": "y compris ; notamment", "def": "Containing as part of a group.", "ex": "Several groups, including students, opposed the measure."}, {"term": "namely", "ipa": "/ˈneɪmli/", "pron": "NAYM-lee", "fr": "à savoir", "def": "That is to say; specifically.", "ex": "Three factors matter, namely wages, housing and debt."}, {"term": "to illustrate", "ipa": "/tə ˈɪləstreɪt/", "pron": "tuh IL-uh-strayt", "fr": "pour illustrer", "def": "Used to introduce an example that clarifies a point.", "ex": "To illustrate, the article mentions rural hospitals."}, {"term": "a case in point", "ipa": "/ə keɪs ɪn ˈpɔɪnt/", "pron": "uh kays in POINT", "fr": "un exemple probant", "def": "A clear example of what has just been mentioned.", "ex": "A case in point is the rise of food insecurity."}, {"term": "in other words", "ipa": "/ɪn ˈʌðə wɜːdz/", "pron": "in UTH-uh wurdz", "fr": "autrement dit", "def": "Used to rephrase more clearly.", "ex": "In other words, the reform shifts costs onto families."}]}, {"title": "E. Examples, reformulation and conclusion", "entries": [{"term": "that is to say", "ipa": "/ðæt ɪz tə ˈseɪ/", "pron": "that iz tuh SAY", "fr": "c’est-à-dire", "def": "Used to explain or clarify.", "ex": "That is to say, democracy depends on trust."}, {"term": "namely", "ipa": "/ˈneɪmli/", "pron": "NAYM-lee", "fr": "à savoir", "def": "Specifically; used to identify something exactly.", "ex": "The problem concerns two groups, namely renters and students."}, {"term": "in short", "ipa": "/ɪn ˈʃɔːt/", "pron": "in short", "fr": "en bref", "def": "Briefly; to summarise.", "ex": "In short, the policy is popular but risky."}, {"term": "in brief", "ipa": "/ɪn ˈbriːf/", "pron": "in brief", "fr": "en bref", "def": "Briefly; in summary.", "ex": "In brief, the article criticises government inaction."}, {"term": "to put it simply", "ipa": "/tə pʊt ɪt ˈsɪmpli/", "pron": "tuh put it SIM-plee", "fr": "pour le dire simplement", "def": "Used to simplify an idea.", "ex": "To put it simply, prices rose faster than wages."}, {"term": "more precisely", "ipa": "/mɔː prɪˈsaɪsli/", "pron": "more pri-SYSS-lee", "fr": "plus précisément", "def": "Used to make a statement more exact.", "ex": "More precisely, the issue concerns working-class voters."}, {"term": "to be more precise", "ipa": "/tə bi mɔː prɪˈsaɪs/", "pron": "tuh bee more pri-SYSS", "fr": "pour être plus précis", "def": "Used to clarify a point.", "ex": "To be more precise, the data cover only England."}, {"term": "in conclusion", "ipa": "/ɪn kənˈkluːʒən/", "pron": "in kuhn-KLOO-zhuhn", "fr": "en conclusion", "def": "Used to introduce the final part of an essay.", "ex": "In conclusion, free speech must be defended carefully."}, {"term": "to conclude", "ipa": "/tə kənˈkluːd/", "pron": "tuh kuhn-KLOOD", "fr": "pour conclure", "def": "Used to introduce a final judgement.", "ex": "To conclude, the reform is necessary but insufficient."}, {"term": "overall", "ipa": "/ˌəʊvərˈɔːl/", "pron": "OH-vuh-rawl", "fr": "dans l’ensemble", "def": "Considering everything.", "ex": "Overall, the article offers a balanced view."}, {"term": "on the whole", "ipa": "/ɒn ðə ˈhəʊl/", "pron": "on thuh HOHL", "fr": "dans l’ensemble", "def": "Generally; considering all aspects.", "ex": "On the whole, the proposal is convincing."}, {"term": "all in all", "ipa": "/ˌɔːl ɪn ˈɔːl/", "pron": "awl-in-AWL", "fr": "tout compte fait", "def": "Considering everything.", "ex": "All in all, the reform is risky but necessary."}, {"term": "ultimately", "ipa": "/ˈʌltɪmətli/", "pron": "UL-ti-muht-lee", "fr": "en fin de compte", "def": "In the end; after considering everything.", "ex": "Ultimately, the issue is one of trust."}, {"term": "in the final analysis", "ipa": "/ɪn ðə ˌfaɪnəl əˈnæləsɪs/", "pron": "in thuh FY-nuhl uh-NAL-uh-sis", "fr": "en dernière analyse", "def": "After considering all arguments; formal.", "ex": "In the final analysis, institutions must regain legitimacy."}, {"term": "it follows that", "ipa": "/ɪt ˈfɒləʊz ðæt/", "pron": "it FOL-ohz that", "fr": "il s’ensuit que", "def": "The logical consequence is that.", "ex": "It follows that reform must be gradual."}, {"term": "we may conclude that", "ipa": "/wi meɪ kənˈkluːd ðæt/", "pron": "wee may kuhn-KLOOD that", "fr": "nous pouvons conclure que", "def": "A formal way to introduce a conclusion.", "ex": "We may conclude that democracy depends on informed citizens."}, {"term": "this suggests that", "ipa": "/ðɪs səˈdʒests ðæt/", "pron": "this suh-JESTS that", "fr": "cela suggère que", "def": "This indicates a likely conclusion.", "ex": "This suggests that voters want change."}, {"term": "this points to", "ipa": "/ðɪs pɔɪnts tə/", "pron": "this points tuh", "fr": "cela indique ; cela renvoie à", "def": "This indicates or suggests.", "ex": "This points to a deeper crisis of representation."}, {"term": "the evidence suggests", "ipa": "/ði ˈevɪdəns səˈdʒests/", "pron": "the EV-i-duhns suh-JESTS", "fr": "les éléments suggèrent", "def": "The available facts point towards a conclusion.", "ex": "The evidence suggests that inequality has widened."}, {"term": "on balance", "ipa": "/ɒn ˈbæləns/", "pron": "on BAL-uhns", "fr": "tout bien considéré", "def": "After weighing both sides.", "ex": "On balance, the benefits outweigh the risks."}]}]}, {"id": "p10c82", "part": 10, "chapter": 82, "title": "Nuance And Concession", "file": "cpge_vocab_part10_chapter82_nuance_and_concession_premium.html", "count": 126, "sections": [{"title": "A. Core vocabulary of nuance", "entries": [{"term": "nuance", "ipa": "/ˈnjuːɑːns/", "pron": "NYOO-ahns", "fr": "nuance", "def": "A small but important difference in meaning, judgement or interpretation.", "ex": "A strong essay needs nuance, not slogans."}, {"term": "to nuance", "ipa": "/ˈnjuːɑːns/", "pron": "NYOO-ahns", "fr": "nuancer", "def": "To make an argument more subtle and less absolute.", "ex": "You should nuance the opposition between freedom and security."}, {"term": "nuanced", "ipa": "/ˈnjuːɑːnst/", "pron": "NYOO-ahnst", "fr": "nuancé", "def": "Showing subtle differences and complexity.", "ex": "The article offers a nuanced view of immigration."}, {"term": "subtle", "ipa": "/ˈsʌtəl/", "pron": "SUT-uhl", "fr": "subtil", "def": "Not obvious, simple or extreme; involving fine distinctions.", "ex": "There is a subtle difference between criticism and censorship."}, {"term": "subtlety", "ipa": "/ˈsʌtəlti/", "pron": "SUT-uhl-tee", "fr": "subtilité", "def": "The quality of being nuanced or delicate in meaning.", "ex": "The debate requires subtlety."}, {"term": "complexity", "ipa": "/kəmˈpleksəti/", "pron": "kuhm-PLEK-suh-tee", "fr": "complexité", "def": "The fact that something has many connected parts and is not simple.", "ex": "The issue’s complexity should not be ignored."}, {"term": "ambivalence", "ipa": "/æmˈbɪvələns/", "pron": "am-BIV-uh-luhns", "fr": "ambivalence", "def": "Mixed feelings or contradictory attitudes towards something.", "ex": "Public ambivalence about AI reflects both hope and fear."}, {"term": "ambiguity", "ipa": "/ˌæmbɪˈɡjuːəti/", "pron": "am-bi-GYOO-uh-tee", "fr": "ambiguïté", "def": "Uncertainty or openness to more than one interpretation.", "ex": "The speech contains deliberate ambiguity."}, {"term": "qualification", "ipa": "/ˌkwɒlɪfɪˈkeɪʃən/", "pron": "kwol-i-fi-KAY-shuhn", "fr": "nuance ; réserve", "def": "A limitation or condition added to make a statement more precise.", "ex": "The argument needs qualification."}, {"term": "to qualify a statement", "ipa": "/ˈkwɒlɪfaɪ ə ˈsteɪtmənt/", "pron": "KWOL-i-fy uh STAYT-muhnt", "fr": "nuancer une affirmation", "def": "To make a statement less absolute or more precise.", "ex": "The claim must be qualified by economic context."}, {"term": "to avoid oversimplification", "ipa": "/əˈvɔɪd ˌəʊvəsɪmplɪfɪˈkeɪʃən/", "pron": "uh-VOID OH-vuh-sim-pli-fi-KAY-shuhn", "fr": "éviter la simplification excessive", "def": "To avoid making a complex issue too simple.", "ex": "Good essays avoid oversimplification."}, {"term": "oversimplification", "ipa": "/ˌəʊvəsɪmplɪfɪˈkeɪʃən/", "pron": "OH-vuh-sim-pli-fi-KAY-shuhn", "fr": "simplification excessive", "def": "A version of an issue that is too simple and ignores complexity.", "ex": "The headline is an oversimplification."}, {"term": "simplistic", "ipa": "/sɪmˈplɪstɪk/", "pron": "sim-PLIS-tik", "fr": "simpliste", "def": "Too simple, ignoring complexity.", "ex": "A simplistic answer would blame only social media."}, {"term": "reductive", "ipa": "/rɪˈdʌktɪv/", "pron": "ri-DUK-tiv", "fr": "réducteur", "def": "Reducing a complex issue to one overly simple explanation.", "ex": "The argument is reductive because it ignores class."}, {"term": "one-sided", "ipa": "/ˌwʌn ˈsaɪdɪd/", "pron": "wun-SY-did", "fr": "partial ; à sens unique", "def": "Considering only one side of an issue.", "ex": "A one-sided essay loses credibility."}, {"term": "balanced", "ipa": "/ˈbælənst/", "pron": "BAL-uhnst", "fr": "équilibré", "def": "Considering different sides fairly.", "ex": "A balanced answer acknowledges both risks and benefits."}, {"term": "a balanced view", "ipa": "/ə ˌbælənst ˈvjuː/", "pron": "uh BAL-uhnst vyoo", "fr": "un point de vue équilibré", "def": "An opinion that considers several sides of an issue.", "ex": "The article provides a balanced view of free speech."}, {"term": "a middle ground", "ipa": "/ə ˈmɪdəl ɡraʊnd/", "pron": "uh MID-uhl grownd", "fr": "un terrain d’entente ; position intermédiaire", "def": "A position between two opposing views.", "ex": "There may be a middle ground between censorship and laissez-faire."}, {"term": "a grey area", "ipa": "/ə ˈɡreɪ ˌeəriə/", "pron": "uh GRAY AIR-ee-uh", "fr": "zone grise", "def": "A situation where rules or moral judgements are unclear.", "ex": "Online speech often falls into a grey area."}, {"term": "it depends", "ipa": "/ɪt dɪˈpendz/", "pron": "it di-PENDZ", "fr": "cela dépend", "def": "A cautious answer showing that context matters.", "ex": "When asked whether regulation is good, the honest answer is: it depends."}, {"term": "context matters", "ipa": "/ˈkɒntekst ˈmætəz/", "pron": "KON-tekst MAT-uhz", "fr": "le contexte compte", "def": "The circumstances are important for judging something.", "ex": "Context matters when judging controversial speech."}, {"term": "depending on the context", "ipa": "/dɪˈpendɪŋ ɒn ðə ˈkɒntekst/", "pron": "di-PEN-ding on thuh KON-tekst", "fr": "selon le contexte", "def": "Used to show that the answer changes with circumstances.", "ex": "Depending on the context, protest can be legitimate or disruptive."}, {"term": "under certain circumstances", "ipa": "/ˈʌndə ˈsɜːtən ˈsɜːkəmstənsɪz/", "pron": "UN-duh SUR-tuhn SUR-kuhm-stan-siz", "fr": "dans certaines circonstances", "def": "In some specific situations.", "ex": "Under certain circumstances, restrictions may be justified."}, {"term": "to some extent", "ipa": "/tə səm ɪkˈstent/", "pron": "tuh sum ik-STENT", "fr": "dans une certaine mesure", "def": "Partly, but not completely.", "ex": "To some extent, the criticism is justified."}]}, {"title": "B. Softening claims and avoiding overstatement", "entries": [{"term": "to a certain extent", "ipa": "/tə ə ˈsɜːtən ɪkˈstent/", "pron": "tuh uh SUR-tuhn ik-STENT", "fr": "dans une certaine mesure", "def": "Partly; within limits.", "ex": "To a certain extent, social media amplifies polarisation."}, {"term": "up to a point", "ipa": "/ˌʌp tə ə ˈpɔɪnt/", "pron": "up tuh uh POINT", "fr": "jusqu’à un certain point", "def": "Partly true, but limited.", "ex": "The argument is convincing up to a point."}, {"term": "partly", "ipa": "/ˈpɑːtli/", "pron": "PART-lee", "fr": "en partie", "def": "Not completely; to some degree.", "ex": "The crisis is partly economic."}, {"term": "in part", "ipa": "/ɪn ˈpɑːt/", "pron": "in PART", "fr": "en partie", "def": "Partly; to some degree.", "ex": "The backlash is in part caused by inflation."}, {"term": "partially", "ipa": "/ˈpɑːʃəli/", "pron": "PAR-shuh-lee", "fr": "partiellement", "def": "Not fully; only in part.", "ex": "The reform was only partially successful."}, {"term": "not entirely", "ipa": "/nɒt ɪnˈtaɪəli/", "pron": "not in-TY-uh-lee", "fr": "pas entièrement", "def": "Not completely.", "ex": "The claim is not entirely convincing."}, {"term": "not necessarily", "ipa": "/nɒt ˌnesəˈserəli/", "pron": "not ness-uh-SAIR-uh-lee", "fr": "pas nécessairement", "def": "Not always or not automatically.", "ex": "Economic growth does not necessarily reduce inequality."}, {"term": "not always", "ipa": "/nɒt ˈɔːlweɪz/", "pron": "not AWL-wayz", "fr": "pas toujours", "def": "Used to avoid generalisation.", "ex": "Technology is not always liberating."}, {"term": "not simply", "ipa": "/nɒt ˈsɪmpli/", "pron": "not SIM-plee", "fr": "pas simplement", "def": "Used to reject a too-simple interpretation.", "ex": "The issue is not simply about individual choice."}, {"term": "not merely", "ipa": "/nɒt ˈmɪəli/", "pron": "not MEER-lee", "fr": "pas seulement", "def": "Not only; more than just.", "ex": "Fake news is not merely a technological issue."}, {"term": "not just... but also", "ipa": "/nɒt dʒʌst bət ˈɔːlsəʊ/", "pron": "not just but AWL-soh", "fr": "pas seulement... mais aussi", "def": "Used to add complexity to a claim.", "ex": "The crisis is not just economic but also political."}, {"term": "rather than", "ipa": "/ˈrɑːðə ðæn/", "pron": "RAH-thuh than", "fr": "plutôt que", "def": "Used to correct or refine an interpretation.", "ex": "The problem is cultural rather than purely legal."}, {"term": "more than", "ipa": "/mɔː ðæn/", "pron": "more than", "fr": "plus que", "def": "Used to show an issue exceeds one category.", "ex": "Populism is more than simple anger."}, {"term": "less... than...", "ipa": "/les ðæn/", "pron": "less than", "fr": "moins... que...", "def": "Used to reframe a comparison.", "ex": "The debate is less about facts than about trust."}, {"term": "not so much... as...", "ipa": "/nɒt səʊ mʌtʃ æz/", "pron": "not soh much az", "fr": "moins... que...", "def": "Used to correct what an issue is really about.", "ex": "The crisis is not so much institutional as cultural."}, {"term": "arguably", "ipa": "/ˈɑːɡjuəbli/", "pron": "AR-gyoo-uh-blee", "fr": "on peut soutenir que", "def": "It can be argued that; cautious judgement.", "ex": "Arguably, this is the greatest challenge facing democracies."}, {"term": "perhaps", "ipa": "/pəˈhæps/", "pron": "puh-HAPS", "fr": "peut-être", "def": "Possibly; used to soften a claim.", "ex": "Perhaps the reform failed because it came too late."}, {"term": "possibly", "ipa": "/ˈpɒsəbli/", "pron": "POSS-uh-blee", "fr": "peut-être ; possiblement", "def": "Maybe; used for cautious possibility.", "ex": "The policy could possibly reduce inequality."}, {"term": "probably", "ipa": "/ˈprɒbəbli/", "pron": "PROB-uh-blee", "fr": "probablement", "def": "Likely, but not certain.", "ex": "The decision will probably trigger protests."}, {"term": "presumably", "ipa": "/prɪˈzjuːməbli/", "pron": "pri-ZYOO-muh-blee", "fr": "vraisemblablement", "def": "Probably, based on available evidence.", "ex": "Presumably, voters were reacting to high prices."}, {"term": "seemingly", "ipa": "/ˈsiːmɪŋli/", "pron": "SEE-ming-lee", "fr": "apparemment", "def": "Apparently, but not necessarily in reality.", "ex": "Seemingly neutral rules can have unequal effects."}, {"term": "apparently", "ipa": "/əˈpærəntli/", "pron": "uh-PARR-uhnt-lee", "fr": "apparemment", "def": "It seems that; according to available evidence.", "ex": "Apparently, the proposal failed to convince young voters."}, {"term": "it seems that", "ipa": "/ɪt siːmz ðæt/", "pron": "it seemz that", "fr": "il semble que", "def": "Used to introduce a cautious interpretation.", "ex": "It seems that trust has become the central issue."}, {"term": "it appears that", "ipa": "/ɪt əˈpɪəz ðæt/", "pron": "it uh-PEERZ that", "fr": "il apparaît que", "def": "Used to introduce a cautious observation.", "ex": "It appears that the reform widened existing divisions."}, {"term": "one might argue that", "ipa": "/wʌn maɪt ˈɑːɡjuː ðæt/", "pron": "wun might AR-gyoo that", "fr": "on pourrait soutenir que", "def": "A cautious way to introduce an argument.", "ex": "One might argue that free speech is under pressure."}, {"term": "one could argue that", "ipa": "/wʌn kʊd ˈɑːɡjuː ðæt/", "pron": "wun could AR-gyoo that", "fr": "on pourrait soutenir que", "def": "A cautious way to present a possible argument.", "ex": "One could argue that the policy is both bold and risky."}, {"term": "it could be argued that", "ipa": "/ɪt kʊd bi ˈɑːɡjuːd ðæt/", "pron": "it could bee AR-gyood that", "fr": "on pourrait soutenir que", "def": "Formal way to introduce a debatable claim.", "ex": "It could be argued that the media helped polarise the debate."}, {"term": "this may suggest that", "ipa": "/ðɪs meɪ səˈdʒest ðæt/", "pron": "this may suh-JEST that", "fr": "cela pourrait suggérer que", "def": "This possibly indicates something.", "ex": "This may suggest that voters feel ignored."}, {"term": "this seems to indicate that", "ipa": "/ðɪs siːmz tʊ ˈɪndɪkeɪt ðæt/", "pron": "this seemz to IN-di-kayt that", "fr": "cela semble indiquer que", "def": "This appears to show something.", "ex": "This seems to indicate that institutions have lost credibility."}, {"term": "it would be misleading to say that", "ipa": "/ɪt wʊd bi mɪsˈliːdɪŋ tə seɪ ðæt/", "pron": "it would bee mis-LEE-ding tuh say that", "fr": "il serait trompeur de dire que", "def": "Used to reject an oversimplified claim.", "ex": "It would be misleading to say that immigration alone explains the result."}, {"term": "it would be simplistic to argue that", "ipa": "/ɪt wʊd bi sɪmˈplɪstɪk tʊ ˈɑːɡjuː ðæt/", "pron": "it would bee sim-PLIS-tik to AR-gyoo that", "fr": "il serait simpliste de soutenir que", "def": "Used to criticise an overly simple interpretation.", "ex": "It would be simplistic to argue that technology is always harmful."}, {"term": "it would be unfair to claim that", "ipa": "/ɪt wʊd bi ʌnˈfeə tə kleɪm ðæt/", "pron": "it would bee un-FAIR tuh klaym that", "fr": "il serait injuste d’affirmer que", "def": "Used to reject an unfair generalisation.", "ex": "It would be unfair to claim that all voters were motivated by fear."}, {"term": "we should be wary of", "ipa": "/wi ʃʊd bi ˈweəri əv/", "pron": "wee should bee WAIR-ee ov", "fr": "il faut se méfier de", "def": "We should be cautious about.", "ex": "We should be wary of simple explanations."}, {"term": "one should avoid", "ipa": "/wʌn ʃʊd əˈvɔɪd/", "pron": "wun should uh-VOID", "fr": "il faut éviter de", "def": "A formal way to warn against something.", "ex": "One should avoid reducing the debate to identity politics."}, {"term": "we must distinguish between", "ipa": "/wi mʌst dɪˈstɪŋɡwɪʃ bɪˈtwiːn/", "pron": "wee must di-STING-gwish bi-TWEEN", "fr": "il faut distinguer entre", "def": "We must separate two ideas clearly.", "ex": "We must distinguish between offence and harm."}]}, {"title": "C. Looking beyond first impressions", "entries": [{"term": "it is important to distinguish", "ipa": "/ɪt ɪz ɪmˈpɔːtənt tə dɪˈstɪŋɡwɪʃ/", "pron": "it iz im-POR-tuhnt tuh di-STING-gwish", "fr": "il est important de distinguer", "def": "Used to make a key analytical distinction.", "ex": "It is important to distinguish legal rights from social norms."}, {"term": "a distinction should be drawn between", "ipa": "/ə dɪˈstɪŋkʃən ʃʊd bi drɔːn bɪˈtwiːn/", "pron": "uh di-STINK-shuhn should bee drawn bi-TWEEN", "fr": "il convient d’établir une distinction entre", "def": "Formal phrase for separating two concepts.", "ex": "A distinction should be drawn between criticism and harassment."}, {"term": "this distinction matters because", "ipa": "/ðɪs dɪˈstɪŋkʃən ˈmætəz bɪˈkɒz/", "pron": "this di-STINK-shuhn MAT-uhz bi-KOZ", "fr": "cette distinction est importante car", "def": "Used to explain why a distinction is important.", "ex": "This distinction matters because law and morality do not always overlap."}, {"term": "at first sight", "ipa": "/æt ˌfɜːst ˈsaɪt/", "pron": "at first SYT", "fr": "à première vue", "def": "At first glance; before deeper analysis.", "ex": "At first sight, the policy seems fair."}, {"term": "at first glance", "ipa": "/æt ˌfɜːst ˈɡlɑːns/", "pron": "at first glahns", "fr": "à première vue", "def": "Initially, before closer examination.", "ex": "At first glance, the figures look encouraging."}, {"term": "on closer inspection", "ipa": "/ɒn ˌkləʊsər ɪnˈspekʃən/", "pron": "on KLOH-zuh in-SPEK-shuhn", "fr": "à y regarder de plus près", "def": "After examining more carefully.", "ex": "On closer inspection, the policy favours wealthier households."}, {"term": "upon closer examination", "ipa": "/əˌpɒn ˌkləʊsər ɪɡˌzæmɪˈneɪʃən/", "pron": "uh-PON KLOH-zuh ig-zam-i-NAY-shuhn", "fr": "à l’examen approfondi", "def": "After careful analysis; formal.", "ex": "Upon closer examination, the argument becomes less convincing."}, {"term": "beneath the surface", "ipa": "/bɪˌniːθ ðə ˈsɜːfɪs/", "pron": "bi-NEETH thuh SUR-fis", "fr": "sous la surface", "def": "Below the obvious or visible level.", "ex": "Beneath the surface, the debate is about belonging."}, {"term": "behind the apparent consensus", "ipa": "/bɪˈhaɪnd ði əˈpærənt kənˈsensəs/", "pron": "bi-HYND thee uh-PARR-uhnt kuhn-SEN-suhs", "fr": "derrière le consensus apparent", "def": "Beyond what looks like agreement.", "ex": "Behind the apparent consensus, deep tensions remain."}, {"term": "the picture is more complicated", "ipa": "/ðə ˈpɪktʃə ɪz mɔː ˈkɒmplɪkeɪtɪd/", "pron": "thuh PIK-chuh iz more KOM-pli-kay-tid", "fr": "la situation est plus complexe", "def": "Used to reject a simple view.", "ex": "The picture is more complicated than the headline suggests."}, {"term": "the reality is more complex", "ipa": "/ðə riˈæləti ɪz mɔː ˈkɒmpleks/", "pron": "thuh ree-AL-uh-tee iz more KOM-pleks", "fr": "la réalité est plus complexe", "def": "Used to nuance a simple claim.", "ex": "The reality is more complex than a left-right divide."}, {"term": "this is only part of the story", "ipa": "/ðɪs ɪz ˈəʊnli pɑːt əv ðə ˈstɔːri/", "pron": "this iz OHN-lee part ov thuh STOR-ee", "fr": "ce n’est qu’une partie de l’histoire", "def": "Used to show that an explanation is incomplete.", "ex": "Economic insecurity is only part of the story."}, {"term": "there is more to it than that", "ipa": "/ðeər ɪz mɔː tʊ ɪt ðæn ðæt/", "pron": "thair iz more to it than that", "fr": "c’est plus compliqué que cela", "def": "Used to reject an incomplete explanation.", "ex": "There is more to it than that: identity also matters."}, {"term": "this does not mean that", "ipa": "/ðɪs dʌz nɒt miːn ðæt/", "pron": "this duz not meen that", "fr": "cela ne signifie pas que", "def": "Used to prevent a wrong conclusion.", "ex": "This does not mean that regulation is always dangerous."}, {"term": "this is not to say that", "ipa": "/ðɪs ɪz nɒt tə seɪ ðæt/", "pron": "this iz not tuh say that", "fr": "cela ne veut pas dire que", "def": "Used to clarify what you are not arguing.", "ex": "This is not to say that social media has no benefits."}, {"term": "that being said", "ipa": "/ðæt ˈbiːɪŋ sed/", "pron": "that BEE-ing sed", "fr": "cela dit", "def": "Used to concede before adding a contrast.", "ex": "That being said, the reform remains risky."}, {"term": "having said that", "ipa": "/ˈhævɪŋ sed ðæt/", "pron": "HAV-ing sed that", "fr": "cela dit", "def": "Used to add a counterpoint after a claim.", "ex": "Having said that, the policy may still be necessary."}, {"term": "be that as it may", "ipa": "/bi ðæt æz ɪt meɪ/", "pron": "bee that az it may", "fr": "quoi qu’il en soit", "def": "Even if that is true; formal concession.", "ex": "Be that as it may, the law must be applied fairly."}, {"term": "even so", "ipa": "/ˌiːvən ˈsəʊ/", "pron": "EE-vuhn soh", "fr": "malgré tout", "def": "Despite that.", "ex": "Even so, the risks cannot be ignored."}, {"term": "nevertheless", "ipa": "/ˌnevəðəˈles/", "pron": "nev-uh-thuh-LESS", "fr": "néanmoins", "def": "Despite what has just been said.", "ex": "Nevertheless, the article raises a valid point."}, {"term": "nonetheless", "ipa": "/ˌnʌnðəˈles/", "pron": "nun-thuh-LESS", "fr": "néanmoins", "def": "Nevertheless; formal.", "ex": "Nonetheless, public anger is understandable."}, {"term": "however", "ipa": "/haʊˈevə/", "pron": "how-EV-uh", "fr": "cependant", "def": "Used to introduce contrast.", "ex": "However, the evidence remains limited."}, {"term": "yet", "ipa": "/jet/", "pron": "yet", "fr": "pourtant", "def": "But; used for contrast.", "ex": "The reform is popular, yet it may be ineffective."}, {"term": "still", "ipa": "/stɪl/", "pron": "stil", "fr": "malgré cela", "def": "Despite this; used to add a remaining point.", "ex": "Still, the proposal deserves attention."}, {"term": "all the same", "ipa": "/ˌɔːl ðə ˈseɪm/", "pron": "awl thuh same", "fr": "tout de même", "def": "Despite this; nevertheless.", "ex": "All the same, the criticism should be taken seriously."}, {"term": "despite this", "ipa": "/dɪˈspaɪt ðɪs/", "pron": "di-SPYT this", "fr": "malgré cela", "def": "In spite of this.", "ex": "Despite this, the government refused to change course."}]}, {"title": "D. Concession and counterargument", "entries": [{"term": "in spite of this", "ipa": "/ɪn ˈspaɪt əv ðɪs/", "pron": "in SPYT ov this", "fr": "malgré cela", "def": "Despite this.", "ex": "In spite of this, voters remained divided."}, {"term": "although", "ipa": "/ɔːlˈðəʊ/", "pron": "awl-THOH", "fr": "bien que", "def": "Despite the fact that.", "ex": "Although the policy is ambitious, it may be unrealistic."}, {"term": "even though", "ipa": "/ˈiːvən ðəʊ/", "pron": "EE-vuhn thoh", "fr": "même si ; bien que", "def": "Despite the fact that; stronger than although.", "ex": "Even though the economy is growing, inequality persists."}, {"term": "while", "ipa": "/waɪl/", "pron": "wyle", "fr": "bien que ; tandis que", "def": "Although; whereas.", "ex": "While the reform has merits, it lacks funding."}, {"term": "whereas", "ipa": "/ˌweərˈæz/", "pron": "wair-AZ", "fr": "tandis que ; alors que", "def": "While; used to contrast two facts.", "ex": "The rich benefit, whereas the poor pay more."}, {"term": "wherever one stands", "ipa": "/weərˈevə wʌn stændz/", "pron": "wair-EV-uh wun standz", "fr": "quelle que soit sa position", "def": "Whatever one’s opinion may be.", "ex": "Wherever one stands, the debate reveals deep anxiety."}, {"term": "whether one agrees or not", "ipa": "/ˈweðə wʌn əˈɡriːz ɔː nɒt/", "pron": "WETH-uh wun uh-GREEZ or not", "fr": "que l’on soit d’accord ou non", "def": "Regardless of one’s opinion.", "ex": "Whether one agrees or not, the issue cannot be dismissed."}, {"term": "whatever the case may be", "ipa": "/wɒtˈevə ðə keɪs meɪ bi/", "pron": "wot-EV-uh thuh kays may bee", "fr": "quoi qu’il en soit", "def": "In any case; whatever is true.", "ex": "Whatever the case may be, the crisis demands attention."}, {"term": "regardless of", "ipa": "/rɪˈɡɑːdləs əv/", "pron": "ri-GARD-luhs ov", "fr": "indépendamment de ; quelle que soit", "def": "Without being affected by something.", "ex": "Rights should apply regardless of income."}, {"term": "irrespective of", "ipa": "/ˌɪrɪˈspektɪv əv/", "pron": "ir-i-SPEK-tiv ov", "fr": "indépendamment de", "def": "Regardless of; formal.", "ex": "Protection should apply irrespective of nationality."}, {"term": "admittedly", "ipa": "/ədˈmɪtɪdli/", "pron": "ad-MIT-id-lee", "fr": "certes", "def": "Used to accept a point before qualifying it.", "ex": "Admittedly, the policy is expensive."}, {"term": "granted", "ipa": "/ˈɡrɑːntɪd/", "pron": "GRAHN-tid", "fr": "certes", "def": "Used to concede something before making a contrast.", "ex": "Granted, regulation is difficult."}, {"term": "it is true that", "ipa": "/ɪt ɪz ˈtruː ðæt/", "pron": "it iz troo that", "fr": "il est vrai que", "def": "Used to concede a fact.", "ex": "It is true that technology creates opportunities."}, {"term": "one must admit that", "ipa": "/wʌn mʌst ədˈmɪt ðæt/", "pron": "wun must ad-MIT that", "fr": "il faut reconnaître que", "def": "Used to acknowledge a point honestly.", "ex": "One must admit that the reform has some merit."}, {"term": "it cannot be denied that", "ipa": "/ɪt ˈkænɒt bi dɪˈnaɪd ðæt/", "pron": "it KAN-ot bee di-NYED that", "fr": "on ne peut nier que", "def": "Used to acknowledge an undeniable fact.", "ex": "It cannot be denied that inequality has increased."}, {"term": "there is no denying that", "ipa": "/ðeər ɪz nəʊ dɪˈnaɪɪŋ ðæt/", "pron": "thair iz noh di-NY-ing that", "fr": "on ne peut nier que", "def": "It is impossible to deny that.", "ex": "There is no denying that the crisis is serious."}, {"term": "needless to say", "ipa": "/ˈniːdləs tə seɪ/", "pron": "NEED-luhs tuh say", "fr": "il va sans dire que", "def": "Obviously; used cautiously in formal argument.", "ex": "Needless to say, democracy requires informed citizens."}, {"term": "of course", "ipa": "/əv ˈkɔːs/", "pron": "ov korss", "fr": "bien sûr", "def": "Naturally; used to acknowledge an obvious point.", "ex": "Of course, free speech has limits."}, {"term": "naturally", "ipa": "/ˈnætʃərəli/", "pron": "NAT-chuh-ruh-lee", "fr": "naturellement", "def": "As expected; used to concede an obvious point.", "ex": "Naturally, voters are concerned about prices."}, {"term": "without denying", "ipa": "/wɪðˈaʊt dɪˈnaɪɪŋ/", "pron": "with-OUT di-NY-ing", "fr": "sans nier", "def": "Used to acknowledge a point while moving beyond it.", "ex": "Without denying the risks, one should consider the benefits."}, {"term": "while acknowledging", "ipa": "/waɪl əkˈnɒlɪdʒɪŋ/", "pron": "wyle ak-NOL-ij-ing", "fr": "tout en reconnaissant", "def": "Used to recognise a point before qualifying it.", "ex": "While acknowledging the problem, the article questions the solution."}, {"term": "while conceding that", "ipa": "/waɪl kənˈsiːdɪŋ ðæt/", "pron": "wyle kuhn-SEED-ing that", "fr": "tout en concédant que", "def": "Used to admit something while keeping a broader argument.", "ex": "While conceding that the policy is flawed, one may defend its aim."}, {"term": "although it may seem", "ipa": "/ɔːlˈðəʊ ɪt meɪ siːm/", "pron": "awl-THOH it may seem", "fr": "bien qu’il puisse sembler", "def": "Used to introduce a surprising or counterintuitive point.", "ex": "Although it may seem restrictive, the law protects vulnerable groups."}, {"term": "paradoxically", "ipa": "/ˌpærəˈdɒksɪkəli/", "pron": "par-uh-DOK-si-kuh-lee", "fr": "paradoxalement", "def": "In a way that seems contradictory but may be true.", "ex": "Paradoxically, more information can create more confusion."}, {"term": "counterintuitively", "ipa": "/ˌkaʊntərɪnˈtjuːɪtɪvli/", "pron": "kown-tuh-rin-TYOO-i-tiv-lee", "fr": "contre-intuitivement", "def": "In a way that goes against what one would expect.", "ex": "Counterintuitively, restrictions may sometimes protect debate."}, {"term": "at the same time", "ipa": "/æt ðə seɪm ˈtaɪm/", "pron": "at thuh same time", "fr": "en même temps", "def": "Used to hold two ideas together.", "ex": "The policy is necessary; at the same time, it is risky."}, {"term": "simultaneously", "ipa": "/ˌsɪməlˈteɪniəsli/", "pron": "sim-uhl-TAY-nee-uhs-lee", "fr": "simultanément", "def": "At the same time; formal.", "ex": "The platform empowers users and simultaneously exploits their data."}, {"term": "on the one hand", "ipa": "/ɒn ðə wʌn hænd/", "pron": "on thuh one hand", "fr": "d’une part", "def": "Used to introduce one side of an argument.", "ex": "On the one hand, regulation protects users."}, {"term": "on the other hand", "ipa": "/ɒn ði ˈʌðə hænd/", "pron": "on thee UTH-uh hand", "fr": "d’autre part", "def": "Used to introduce the contrasting side.", "ex": "On the other hand, it may restrict free speech."}, {"term": "there is a tension between", "ipa": "/ðeər ɪz ə ˈtenʃən bɪˈtwiːn/", "pron": "thair iz uh TEN-shuhn bi-TWEEN", "fr": "il existe une tension entre", "def": "Used to describe a conflict between two values.", "ex": "There is a tension between security and liberty."}, {"term": "the dilemma lies in", "ipa": "/ðə dɪˈlemə laɪz ɪn/", "pron": "thuh di-LEM-uh lyz in", "fr": "le dilemme réside dans", "def": "The difficult choice consists in.", "ex": "The dilemma lies in protecting both speech and dignity."}, {"term": "the challenge is to", "ipa": "/ðə ˈtʃælɪndʒ ɪz tə/", "pron": "thuh CHAL-inj iz tuh", "fr": "le défi est de", "def": "Used to frame a balanced conclusion.", "ex": "The challenge is to regulate platforms without silencing debate."}, {"term": "a trade-off", "ipa": "/ə ˈtreɪd ɒf/", "pron": "uh TRAYD-off", "fr": "compromis ; arbitrage", "def": "A compromise where gaining one thing means losing another.", "ex": "There is a trade-off between privacy and security."}, {"term": "to strike a balance", "ipa": "/straɪk ə ˈbæləns/", "pron": "stryke uh BAL-uhns", "fr": "trouver un équilibre", "def": "To find a reasonable middle position.", "ex": "Democracies must strike a balance between freedom and safety."}, {"term": "to reconcile", "ipa": "/ˈrekənsaɪl/", "pron": "REK-uhn-syle", "fr": "concilier", "def": "To make two conflicting ideas compatible.", "ex": "Policy must reconcile growth with sustainability."}]}, {"title": "E. Tension, balance and final judgement", "entries": [{"term": "to balance", "ipa": "/ˈbæləns/", "pron": "BAL-uhns", "fr": "équilibrer", "def": "To give appropriate weight to different factors.", "ex": "Courts must balance rights and responsibilities."}, {"term": "to weigh", "ipa": "/weɪ/", "pron": "way", "fr": "peser ; évaluer", "def": "To consider carefully before judging.", "ex": "We must weigh the benefits against the risks."}, {"term": "to weigh up", "ipa": "/weɪ ˈʌp/", "pron": "way up", "fr": "soupeser ; évaluer", "def": "To compare factors before deciding.", "ex": "The essay weighs up freedom and equality."}, {"term": "on balance", "ipa": "/ɒn ˈbæləns/", "pron": "on BAL-uhns", "fr": "tout bien considéré", "def": "After considering both sides.", "ex": "On balance, the benefits outweigh the risks."}, {"term": "all things considered", "ipa": "/ɔːl θɪŋz kənˈsɪdəd/", "pron": "awl thingz kuhn-SID-uhd", "fr": "tout bien considéré", "def": "After considering everything.", "ex": "All things considered, the policy is flawed but necessary."}, {"term": "in the final analysis", "ipa": "/ɪn ðə ˌfaɪnəl əˈnæləsɪs/", "pron": "in thuh FY-nuhl uh-NAL-uh-sis", "fr": "en dernière analyse", "def": "After considering all arguments.", "ex": "In the final analysis, trust is the central issue."}]}]}, {"id": "p10c83", "part": 10, "chapter": 83, "title": "Expressing Certainty And Doubt", "file": "cpge_vocab_part10_chapter83_expressing_certainty_and_doubt_premium.html", "count": 136, "sections": [{"title": "A. Core certainty and doubt vocabulary", "entries": [{"term": "certainty", "ipa": "/ˈsɜːtənti/", "pron": "SUR-tuhn-tee", "fr": "certitude", "def": "The state of being sure that something is true.", "ex": "Certainty is rare in political analysis."}, {"term": "doubt", "ipa": "/daʊt/", "pron": "dowt", "fr": "doute", "def": "A feeling of uncertainty about something.", "ex": "Doubt is useful when evidence is incomplete."}, {"term": "uncertainty", "ipa": "/ʌnˈsɜːtənti/", "pron": "un-SUR-tuhn-tee", "fr": "incertitude", "def": "The state of not knowing what will happen or what is true.", "ex": "Economic uncertainty can affect voting behaviour."}, {"term": "probability", "ipa": "/ˌprɒbəˈbɪləti/", "pron": "prob-uh-BIL-uh-tee", "fr": "probabilité", "def": "How likely something is to happen or be true.", "ex": "The probability of reform depends on public support."}, {"term": "likelihood", "ipa": "/ˈlaɪklihʊd/", "pron": "LYK-lee-hood", "fr": "probabilité ; vraisemblance", "def": "The chance that something will happen.", "ex": "The likelihood of a recession has increased."}, {"term": "possibility", "ipa": "/ˌpɒsəˈbɪləti/", "pron": "poss-uh-BIL-uh-tee", "fr": "possibilité", "def": "Something that may happen or may be true.", "ex": "The article raises the possibility of political realignment."}, {"term": "plausibility", "ipa": "/ˌplɔːzəˈbɪləti/", "pron": "plaw-zuh-BIL-uh-tee", "fr": "plausibilité", "def": "The quality of seeming reasonable or believable.", "ex": "The plausibility of the claim depends on the evidence."}, {"term": "certainty gap", "ipa": "/ˈsɜːtənti ɡæp/", "pron": "SUR-tuhn-tee gap", "fr": "écart de certitude", "def": "A gap between what is claimed and what can be known for sure.", "ex": "The article leaves a certainty gap between prediction and proof."}, {"term": "evidence", "ipa": "/ˈevɪdəns/", "pron": "EV-i-duhns", "fr": "preuves ; éléments probants", "def": "Facts or information supporting a claim.", "ex": "Evidence should guide the level of certainty."}, {"term": "available evidence", "ipa": "/əˌveɪləbəl ˈevɪdəns/", "pron": "uh-VAY-luh-buhl EV-i-duhns", "fr": "éléments disponibles", "def": "The evidence currently accessible.", "ex": "The available evidence suggests that inequality is rising."}, {"term": "limited evidence", "ipa": "/ˌlɪmɪtɪd ˈevɪdəns/", "pron": "LIM-i-tid EV-i-duhns", "fr": "éléments limités", "def": "Evidence that is incomplete or insufficient.", "ex": "Limited evidence makes strong conclusions risky."}, {"term": "conclusive evidence", "ipa": "/kənˌkluːsɪv ˈevɪdəns/", "pron": "kuhn-KLOO-siv EV-i-duhns", "fr": "preuve concluante", "def": "Evidence strong enough to settle a question.", "ex": "There is no conclusive evidence that the policy worked."}, {"term": "solid evidence", "ipa": "/ˌsɒlɪd ˈevɪdəns/", "pron": "SOL-id EV-i-duhns", "fr": "preuves solides", "def": "Reliable and convincing evidence.", "ex": "The claim is backed by solid evidence."}, {"term": "anecdotal evidence", "ipa": "/ˌænɪkˈdəʊtəl ˈevɪdəns/", "pron": "an-ik-DOH-tuhl EV-i-duhns", "fr": "preuves anecdotiques", "def": "Evidence based on personal stories rather than systematic data.", "ex": "Anecdotal evidence can be vivid but misleading."}, {"term": "data", "ipa": "/ˈdeɪtə/", "pron": "DAY-tuh", "fr": "données", "def": "Facts, figures or information used for analysis.", "ex": "The data point to a long-term trend."}, {"term": "to prove", "ipa": "/pruːv/", "pron": "proov", "fr": "prouver", "def": "To show that something is definitely true.", "ex": "The article does not prove that social media caused the result."}, {"term": "to demonstrate", "ipa": "/ˈdemənstreɪt/", "pron": "DEM-uhn-strayt", "fr": "démontrer", "def": "To show something clearly through evidence or reasoning.", "ex": "The figures demonstrate a clear rise in inequality."}, {"term": "to establish", "ipa": "/ɪˈstæblɪʃ/", "pron": "i-STAB-lish", "fr": "établir", "def": "To show something as true or certain.", "ex": "The report establishes a link between poverty and health."}, {"term": "to confirm", "ipa": "/kənˈfɜːm/", "pron": "kuhn-FURM", "fr": "confirmer", "def": "To show that something is true or correct.", "ex": "The latest data confirm the trend."}, {"term": "to verify", "ipa": "/ˈverɪfaɪ/", "pron": "VER-i-fy", "fr": "vérifier", "def": "To check whether something is true or accurate.", "ex": "Journalists must verify the claim."}, {"term": "to substantiate", "ipa": "/səbˈstænʃieɪt/", "pron": "suhb-STAN-shee-ayt", "fr": "étayer ; corroborer", "def": "To provide evidence that supports a claim.", "ex": "The accusation must be substantiated."}, {"term": "to corroborate", "ipa": "/kəˈrɒbəreɪt/", "pron": "kuh-ROB-uh-rayt", "fr": "corroborer", "def": "To support a claim with additional evidence.", "ex": "Witnesses corroborated the journalist’s account."}]}, {"title": "B. Expressing strong certainty", "entries": [{"term": "to validate", "ipa": "/ˈvælɪdeɪt/", "pron": "VAL-i-dayt", "fr": "valider", "def": "To show that something is reasonable, true or acceptable.", "ex": "The survey validates some public concerns."}, {"term": "to support a claim", "ipa": "/səˈpɔːt ə kleɪm/", "pron": "suh-PORT uh klaym", "fr": "étayer une affirmation", "def": "To provide reasons or evidence for a statement.", "ex": "The statistics support the claim that wages have stagnated."}, {"term": "to back up", "ipa": "/bæk ˈʌp/", "pron": "bak up", "fr": "étayer ; appuyer", "def": "To support a claim with evidence.", "ex": "The author backs up his argument with polling data."}, {"term": "to make a strong case", "ipa": "/meɪk ə strɒŋ keɪs/", "pron": "mayk uh strong kays", "fr": "présenter des arguments solides", "def": "To present convincing reasons for something.", "ex": "The article makes a strong case for reform."}, {"term": "to be certain", "ipa": "/bi ˈsɜːtən/", "pron": "bee SUR-tuhn", "fr": "être certain", "def": "To be sure that something is true.", "ex": "We cannot be certain that the policy will succeed."}, {"term": "to be sure", "ipa": "/bi ˈʃʊə/", "pron": "bee shoor", "fr": "être sûr", "def": "To be confident that something is true.", "ex": "It is too early to be sure."}, {"term": "to be convinced", "ipa": "/bi kənˈvɪnst/", "pron": "bee kuhn-VINST", "fr": "être convaincu", "def": "To strongly believe something after considering evidence.", "ex": "Many voters are convinced that institutions have failed."}, {"term": "to be beyond doubt", "ipa": "/bi bɪˌjɒnd ˈdaʊt/", "pron": "bee bi-YOND dowt", "fr": "ne faire aucun doute", "def": "To be certain and not reasonably questioned.", "ex": "It is beyond doubt that the crisis has social roots."}, {"term": "to be undeniable", "ipa": "/bi ˌʌndɪˈnaɪəbəl/", "pron": "bee un-di-NY-uh-buhl", "fr": "être indéniable", "def": "To be impossible to deny.", "ex": "The pressure on hospitals is undeniable."}, {"term": "to be indisputable", "ipa": "/bi ˌɪndɪˈspjuːtəbəl/", "pron": "bee in-di-SPYOO-tuh-buhl", "fr": "être incontestable", "def": "To be impossible to dispute seriously.", "ex": "The rise in costs is indisputable."}, {"term": "clearly", "ipa": "/ˈklɪəli/", "pron": "KLEER-lee", "fr": "clairement", "def": "In a clear and obvious way.", "ex": "Clearly, the system needs reform."}, {"term": "obviously", "ipa": "/ˈɒbviəsli/", "pron": "OB-vee-uhs-lee", "fr": "évidemment", "def": "In a way that is easy to see or understand.", "ex": "Obviously, this argument has limits."}, {"term": "undoubtedly", "ipa": "/ʌnˈdaʊtɪdli/", "pron": "un-DOW-tid-lee", "fr": "sans aucun doute", "def": "Without doubt.", "ex": "Undoubtedly, social media has changed politics."}, {"term": "unquestionably", "ipa": "/ʌnˈkwestʃənəbli/", "pron": "un-KWES-chuh-nuh-blee", "fr": "indiscutablement", "def": "Without being open to serious question.", "ex": "Unquestionably, the scandal damaged trust."}, {"term": "without doubt", "ipa": "/wɪðˈaʊt daʊt/", "pron": "with-OUT dowt", "fr": "sans aucun doute", "def": "Certainly.", "ex": "Without doubt, housing is a central issue."}, {"term": "there is no doubt that", "ipa": "/ðeər ɪz nəʊ daʊt ðæt/", "pron": "thair iz noh dowt that", "fr": "il ne fait aucun doute que", "def": "Used to express strong certainty.", "ex": "There is no doubt that inequality has widened."}, {"term": "it is clear that", "ipa": "/ɪt ɪz klɪə ðæt/", "pron": "it iz kleer that", "fr": "il est clair que", "def": "Used to present something as evident.", "ex": "It is clear that public trust has fallen."}, {"term": "it is evident that", "ipa": "/ɪt ɪz ˈevɪdənt ðæt/", "pron": "it iz EV-i-duhnt that", "fr": "il est évident que", "def": "Used to present something as obvious from evidence.", "ex": "It is evident that the reform failed to convince voters."}, {"term": "it is apparent that", "ipa": "/ɪt ɪz əˈpærənt ðæt/", "pron": "it iz uh-PARR-uhnt that", "fr": "il apparaît que", "def": "It seems clear from the evidence.", "ex": "It is apparent that the crisis is not temporary."}, {"term": "the evidence clearly shows that", "ipa": "/ði ˈevɪdəns ˈklɪəli ʃəʊz ðæt/", "pron": "the EV-i-duhns KLEER-lee showz that", "fr": "les éléments montrent clairement que", "def": "Used to express certainty based on evidence.", "ex": "The evidence clearly shows that poverty has increased."}, {"term": "there is strong evidence that", "ipa": "/ðeər ɪz strɒŋ ˈevɪdəns ðæt/", "pron": "thair iz strong EV-i-duhns that", "fr": "il existe de solides preuves que", "def": "Used to express high confidence.", "ex": "There is strong evidence that education affects social mobility."}, {"term": "all the evidence points to", "ipa": "/ɔːl ði ˈevɪdəns pɔɪnts tə/", "pron": "awl thee EV-i-duhns points tuh", "fr": "tous les éléments indiquent", "def": "The evidence leads towards one conclusion.", "ex": "All the evidence points to a loss of confidence."}, {"term": "everything suggests that", "ipa": "/ˈevriθɪŋ səˈdʒests ðæt/", "pron": "EV-ree-thing suh-JESTS that", "fr": "tout porte à croire que", "def": "Many signs indicate something.", "ex": "Everything suggests that the election will be close."}, {"term": "it seems certain that", "ipa": "/ɪt siːmz ˈsɜːtən ðæt/", "pron": "it seemz SUR-tuhn that", "fr": "il semble certain que", "def": "It appears almost sure.", "ex": "It seems certain that AI will affect employment."}, {"term": "it is highly likely that", "ipa": "/ɪt ɪz ˈhaɪli ˈlaɪkli ðæt/", "pron": "it iz HY-lee LYK-lee that", "fr": "il est très probable que", "def": "It is very probable.", "ex": "It is highly likely that prices will remain high."}]}, {"title": "C. Expressing likelihood and probability", "entries": [{"term": "it is very likely that", "ipa": "/ɪt ɪz ˈveri ˈlaɪkli ðæt/", "pron": "it iz VERY LYK-lee that", "fr": "il est très probable que", "def": "It is very probable.", "ex": "It is very likely that the reform will be challenged."}, {"term": "it is likely that", "ipa": "/ɪt ɪz ˈlaɪkli ðæt/", "pron": "it iz LYK-lee that", "fr": "il est probable que", "def": "It will probably happen or is probably true.", "ex": "It is likely that voters will demand change."}, {"term": "it is probable that", "ipa": "/ɪt ɪz ˈprɒbəbəl ðæt/", "pron": "it iz PROB-uh-buhl that", "fr": "il est probable que", "def": "It is likely to be true or happen.", "ex": "It is probable that inflation influenced the result."}, {"term": "probably", "ipa": "/ˈprɒbəbli/", "pron": "PROB-uh-blee", "fr": "probablement", "def": "Very likely, but not certain.", "ex": "The decision will probably trigger debate."}, {"term": "most likely", "ipa": "/məʊst ˈlaɪkli/", "pron": "mohst LYK-lee", "fr": "très probablement", "def": "Probably.", "ex": "Most likely, the issue will dominate the campaign."}, {"term": "in all likelihood", "ipa": "/ɪn ɔːl ˈlaɪklihʊd/", "pron": "in awl LYK-lee-hood", "fr": "selon toute vraisemblance", "def": "Very probably; formal.", "ex": "In all likelihood, the reform will be delayed."}, {"term": "the chances are that", "ipa": "/ðə ˈtʃɑːnsɪz ɑː ðæt/", "pron": "thuh CHAN-siz ar that", "fr": "il y a de fortes chances que", "def": "It is likely that.", "ex": "The chances are that the issue will return."}, {"term": "there is a good chance that", "ipa": "/ðeər ɪz ə ɡʊd tʃɑːns ðæt/", "pron": "thair iz uh good chans that", "fr": "il y a de bonnes chances que", "def": "Something is reasonably likely.", "ex": "There is a good chance that the bill will pass."}, {"term": "it may well be that", "ipa": "/ɪt meɪ wel bi ðæt/", "pron": "it may wel bee that", "fr": "il se pourrait bien que", "def": "It is quite possible that.", "ex": "It may well be that trust is the real issue."}, {"term": "it is plausible that", "ipa": "/ɪt ɪz ˈplɔːzəbəl ðæt/", "pron": "it iz PLAW-zuh-buhl that", "fr": "il est plausible que", "def": "It seems reasonable or believable.", "ex": "It is plausible that inequality fuelled resentment."}, {"term": "plausibly", "ipa": "/ˈplɔːzəbli/", "pron": "PLAW-zuh-blee", "fr": "de manière plausible", "def": "In a reasonable or believable way.", "ex": "Plausibly, the result reflects economic anxiety."}, {"term": "it stands to reason that", "ipa": "/ɪt stændz tə ˈriːzən ðæt/", "pron": "it standz tuh REE-zuhn that", "fr": "il va de soi que ; il est logique que", "def": "It is logical to think that.", "ex": "It stands to reason that voters resent broken promises."}, {"term": "one can reasonably assume that", "ipa": "/wʌn kæn ˈriːzənəbli əˈsjuːm ðæt/", "pron": "wun kan REE-zuh-nuh-blee uh-SYOOM that", "fr": "on peut raisonnablement supposer que", "def": "One may make a careful assumption.", "ex": "One can reasonably assume that wages mattered."}, {"term": "reasonable assumption", "ipa": "/ˈriːzənəbəl əˈsʌmpʃən/", "pron": "REE-zuh-nuh-buhl uh-SUMP-shuhn", "fr": "hypothèse raisonnable", "def": "A belief that is sensible but not proven.", "ex": "It is a reasonable assumption, not a certainty."}, {"term": "strong likelihood", "ipa": "/strɒŋ ˈlaɪklihʊd/", "pron": "strong LYK-lee-hood", "fr": "forte probabilité", "def": "High probability.", "ex": "There is a strong likelihood of legal challenges."}, {"term": "high probability", "ipa": "/ˌhaɪ ˌprɒbəˈbɪləti/", "pron": "high prob-uh-BIL-uh-tee", "fr": "forte probabilité", "def": "A strong chance that something is true or will happen.", "ex": "There is a high probability that turnout will fall."}, {"term": "to seem", "ipa": "/siːm/", "pron": "seem", "fr": "sembler", "def": "To appear to be true without full certainty.", "ex": "The policy seems ineffective."}, {"term": "to appear", "ipa": "/əˈpɪə/", "pron": "uh-PEER", "fr": "paraître ; sembler", "def": "To seem, based on available evidence.", "ex": "The economy appears to be slowing."}, {"term": "to look likely", "ipa": "/lʊk ˈlaɪkli/", "pron": "look LYK-lee", "fr": "sembler probable", "def": "To seem probable.", "ex": "A compromise looks likely."}, {"term": "to be likely to", "ipa": "/bi ˈlaɪkli tə/", "pron": "bee LYK-lee tuh", "fr": "être susceptible de", "def": "To have a strong chance of happening.", "ex": "The bill is likely to pass."}, {"term": "to be expected to", "ipa": "/bi ɪkˈspektɪd tə/", "pron": "bee ik-SPEK-tid tuh", "fr": "être censé ; on s’attend à ce que", "def": "To be predicted or anticipated.", "ex": "Inflation is expected to fall."}, {"term": "to be bound to", "ipa": "/bi baʊnd tə/", "pron": "bee bound tuh", "fr": "être voué à ; ne pas manquer de", "def": "To be certain or very likely to happen.", "ex": "The decision is bound to be controversial."}, {"term": "to be set to", "ipa": "/bi set tə/", "pron": "bee set tuh", "fr": "être sur le point de", "def": "To be expected or scheduled to happen.", "ex": "The government is set to announce reforms."}, {"term": "to be poised to", "ipa": "/bi pɔɪzd tə/", "pron": "bee poyzd tuh", "fr": "être sur le point de", "def": "To be ready or likely to do something soon.", "ex": "The party is poised to win the election."}, {"term": "to be on the verge of", "ipa": "/bi ɒn ðə vɜːdʒ əv/", "pron": "bee on thuh vurj ov", "fr": "être au bord de", "def": "To be very close to something happening.", "ex": "The country is on the verge of a constitutional crisis."}, {"term": "to be unlikely to", "ipa": "/bi ʌnˈlaɪkli tə/", "pron": "bee un-LYK-lee tuh", "fr": "avoir peu de chances de", "def": "To have little chance of happening.", "ex": "The proposal is unlikely to satisfy everyone."}, {"term": "it is unlikely that", "ipa": "/ɪt ɪz ʌnˈlaɪkli ðæt/", "pron": "it iz un-LYK-lee that", "fr": "il est peu probable que", "def": "It probably will not happen or is probably not true.", "ex": "It is unlikely that the crisis will disappear soon."}, {"term": "it is doubtful that", "ipa": "/ɪt ɪz ˈdaʊtfəl ðæt/", "pron": "it iz DOWT-fuhl that", "fr": "il est douteux que", "def": "It is uncertain or unlikely.", "ex": "It is doubtful that the measure will be enough."}]}, {"title": "D. Expressing uncertainty and possibility", "entries": [{"term": "there is little chance that", "ipa": "/ðeər ɪz ˈlɪtəl tʃɑːns ðæt/", "pron": "thair iz LIT-uhl chans that", "fr": "il y a peu de chances que", "def": "Something is unlikely.", "ex": "There is little chance that the opposition will accept it."}, {"term": "there is no guarantee that", "ipa": "/ðeər ɪz nəʊ ˌɡærənˈtiː ðæt/", "pron": "thair iz noh gar-uhn-TEE that", "fr": "rien ne garantit que", "def": "Something is not certain.", "ex": "There is no guarantee that regulation will work."}, {"term": "it remains uncertain whether", "ipa": "/ɪt rɪˈmeɪnz ʌnˈsɜːtən ˈweðə/", "pron": "it ri-MAYNZ un-SUR-tuhn WETH-uh", "fr": "on ignore encore si", "def": "We still do not know if something is true or will happen.", "ex": "It remains uncertain whether voters will support the reform."}, {"term": "it remains to be seen whether", "ipa": "/ɪt rɪˈmeɪnz tə bi siːn ˈweðə/", "pron": "it ri-MAYNZ tuh bee seen WETH-uh", "fr": "reste à savoir si", "def": "The outcome is not yet known.", "ex": "It remains to be seen whether the policy will succeed."}, {"term": "it is unclear whether", "ipa": "/ɪt ɪz ʌnˈklɪə ˈweðə/", "pron": "it iz un-KLEER WETH-uh", "fr": "on ne sait pas clairement si", "def": "It is not known if something is true.", "ex": "It is unclear whether the reform will reduce poverty."}, {"term": "it is hard to tell", "ipa": "/ɪt ɪz hɑːd tə tel/", "pron": "it iz hard tuh tel", "fr": "il est difficile de savoir", "def": "It is difficult to know.", "ex": "It is hard to tell whether voters have changed permanently."}, {"term": "one cannot know for sure", "ipa": "/wʌn ˈkænɒt nəʊ fə ʃʊə/", "pron": "wun KAN-ot noh fuh shoor", "fr": "on ne peut pas savoir avec certitude", "def": "There is no complete certainty.", "ex": "One cannot know for sure what motivated every voter."}, {"term": "we cannot rule out", "ipa": "/wi ˈkænɒt ruːl aʊt/", "pron": "wee KAN-ot rool out", "fr": "on ne peut pas exclure", "def": "We cannot exclude a possibility.", "ex": "We cannot rule out a rise in abstention."}, {"term": "it cannot be ruled out that", "ipa": "/ɪt ˈkænɒt bi ruːld aʊt ðæt/", "pron": "it KAN-ot bee roold out that", "fr": "on ne peut exclure que", "def": "It is possible and cannot be excluded.", "ex": "It cannot be ruled out that prices will rise again."}, {"term": "it is possible that", "ipa": "/ɪt ɪz ˈpɒsəbəl ðæt/", "pron": "it iz POSS-uh-buhl that", "fr": "il est possible que", "def": "Something may be true or happen.", "ex": "It is possible that the reform will fail."}, {"term": "it may be that", "ipa": "/ɪt meɪ bi ðæt/", "pron": "it may bee that", "fr": "il se peut que", "def": "Perhaps; it is possible that.", "ex": "It may be that the issue is cultural as much as economic."}, {"term": "it might be that", "ipa": "/ɪt maɪt bi ðæt/", "pron": "it might bee that", "fr": "il se pourrait que", "def": "It is possible, with more uncertainty than may.", "ex": "It might be that voters are simply exhausted."}, {"term": "perhaps", "ipa": "/pəˈhæps/", "pron": "puh-HAPS", "fr": "peut-être", "def": "Maybe; used to soften a claim.", "ex": "Perhaps the article underestimates class divisions."}, {"term": "possibly", "ipa": "/ˈpɒsəbli/", "pron": "POSS-uh-blee", "fr": "peut-être ; possiblement", "def": "Maybe; not certainly.", "ex": "The decision could possibly backfire."}, {"term": "conceivably", "ipa": "/kənˈsiːvəbli/", "pron": "kuhn-SEE-vuh-blee", "fr": "éventuellement ; concevablement", "def": "It is possible to imagine that.", "ex": "Conceivably, the reform could unite both parties."}, {"term": "in theory", "ipa": "/ɪn ˈθɪəri/", "pron": "in THEE-uh-ree", "fr": "en théorie", "def": "According to possibility or principle, not necessarily reality.", "ex": "In theory, the proposal could work."}, {"term": "hypothetically", "ipa": "/ˌhaɪpəˈθetɪkəli/", "pron": "hy-puh-THET-i-kuh-lee", "fr": "hypothétiquement", "def": "As a possible but imagined situation.", "ex": "Hypothetically, a new party could change the system."}, {"term": "a possibility worth considering", "ipa": "/ə ˌpɒsəˈbɪləti wɜːθ kənˈsɪdərɪŋ/", "pron": "uh poss-uh-BIL-uh-tee wurth kuhn-SID-uh-ring", "fr": "une possibilité à envisager", "def": "An option or explanation that deserves attention.", "ex": "This is a possibility worth considering."}, {"term": "one possible explanation is", "ipa": "/wʌn ˈpɒsəbəl ˌekspləˈneɪʃən ɪz/", "pron": "wun POSS-uh-buhl ek-spluh-NAY-shuhn iz", "fr": "une explication possible est", "def": "Used to introduce a cautious explanation.", "ex": "One possible explanation is political fatigue."}, {"term": "a likely explanation is", "ipa": "/ə ˈlaɪkli ˌekspləˈneɪʃən ɪz/", "pron": "uh LYK-lee ek-spluh-NAY-shuhn iz", "fr": "une explication probable est", "def": "Used to introduce a probable reason.", "ex": "A likely explanation is the cost-of-living crisis."}, {"term": "a plausible explanation is", "ipa": "/ə ˈplɔːzəbəl ˌekspləˈneɪʃən ɪz/", "pron": "uh PLAW-zuh-buhl ek-spluh-NAY-shuhn iz", "fr": "une explication plausible est", "def": "Used to introduce a reasonable but not proven explanation.", "ex": "A plausible explanation is distrust of elites."}, {"term": "this may be due to", "ipa": "/ðɪs meɪ bi djuː tə/", "pron": "this may bee dyoo tuh", "fr": "cela peut être dû à", "def": "This might be caused by.", "ex": "This may be due to economic insecurity."}, {"term": "this could stem from", "ipa": "/ðɪs kʊd stem frəm/", "pron": "this could stem from", "fr": "cela pourrait provenir de", "def": "This might originate in.", "ex": "This could stem from long-term regional decline."}, {"term": "to cast doubt on", "ipa": "/kɑːst daʊt ɒn/", "pron": "kast dowt on", "fr": "jeter le doute sur", "def": "To make something seem uncertain.", "ex": "The scandal cast doubt on the minister’s honesty."}, {"term": "to call into question", "ipa": "/kɔːl ˈɪntə ˈkwestʃən/", "pron": "call IN-tuh KWES-chuhn", "fr": "remettre en question", "def": "To make something doubtful or problematic.", "ex": "The crisis calls into question the legitimacy of the system."}, {"term": "to raise doubts about", "ipa": "/reɪz daʊts əˈbaʊt/", "pron": "rayz dowts uh-BOWT", "fr": "soulever des doutes sur", "def": "To create uncertainty about something.", "ex": "The report raises doubts about the policy’s effectiveness."}, {"term": "to question the reliability of", "ipa": "/ˈkwestʃən ðə rɪˌlaɪəˈbɪləti əv/", "pron": "KWES-chuhn thuh ri-ly-uh-BIL-uh-tee ov", "fr": "mettre en doute la fiabilité de", "def": "To doubt whether something can be trusted.", "ex": "The article questions the reliability of the figures."}, {"term": "to challenge the assumption that", "ipa": "/ˈtʃælɪndʒ ði əˈsʌmpʃən ðæt/", "pron": "CHAL-inj thee uh-SUMP-shuhn that", "fr": "remettre en cause l’hypothèse selon laquelle", "def": "To question a belief taken for granted.", "ex": "The data challenge the assumption that growth benefits everyone."}, {"term": "to remain sceptical", "ipa": "/rɪˈmeɪn ˈskeptɪkəl/", "pron": "ri-MAYN SKEP-ti-kuhl", "fr": "rester sceptique", "def": "To continue to doubt something.", "ex": "Many experts remain sceptical about the proposal."}, {"term": "sceptical", "ipa": "/ˈskeptɪkəl/", "pron": "SKEP-ti-kuhl", "fr": "sceptique", "def": "Doubtful and not easily convinced.", "ex": "A sceptical approach is useful when evidence is weak."}]}, {"title": "E. Questioning claims and evidence", "entries": [{"term": "scepticism", "ipa": "/ˈskeptɪsɪzəm/", "pron": "SKEP-ti-siz-uhm", "fr": "scepticisme", "def": "An attitude of doubt or questioning.", "ex": "Public scepticism towards institutions is growing."}, {"term": "doubtful", "ipa": "/ˈdaʊtfəl/", "pron": "DOWT-fuhl", "fr": "douteux ; incertain", "def": "Uncertain or unlikely.", "ex": "It is doubtful that the reform will be enough."}, {"term": "questionable", "ipa": "/ˈkwestʃənəbəl/", "pron": "KWES-chuh-nuh-buhl", "fr": "contestable ; douteux", "def": "Open to doubt or criticism.", "ex": "The evidence is questionable."}, {"term": "debatable", "ipa": "/dɪˈbeɪtəbəl/", "pron": "di-BAY-tuh-buhl", "fr": "discutable", "def": "Open to discussion or disagreement.", "ex": "Whether the policy is fair remains debatable."}, {"term": "unclear", "ipa": "/ʌnˈklɪə/", "pron": "un-KLEER", "fr": "peu clair", "def": "Not clear or certain.", "ex": "The causes of the backlash remain unclear."}, {"term": "ambiguous", "ipa": "/æmˈbɪɡjuəs/", "pron": "am-BIG-yoo-uhs", "fr": "ambigu", "def": "Open to more than one interpretation.", "ex": "The message was deliberately ambiguous."}, {"term": "inconclusive", "ipa": "/ˌɪnkənˈkluːsɪv/", "pron": "in-kuhn-KLOO-siv", "fr": "non concluant", "def": "Not leading to a definite conclusion.", "ex": "The survey results are inconclusive."}, {"term": "tentative", "ipa": "/ˈtentətɪv/", "pron": "TEN-tuh-tiv", "fr": "provisoire ; prudent", "def": "Not final or certain; cautious.", "ex": "The conclusion must remain tentative."}, {"term": "provisional", "ipa": "/prəˈvɪʒənəl/", "pron": "pruh-VIZH-uh-nuhl", "fr": "provisoire", "def": "Temporary and subject to change.", "ex": "These are only provisional findings."}, {"term": "speculative", "ipa": "/ˈspekjʊlətɪv/", "pron": "SPEK-yuh-luh-tiv", "fr": "spéculatif", "def": "Based on guesses rather than firm evidence.", "ex": "The claim is interesting but speculative."}, {"term": "unsubstantiated", "ipa": "/ˌʌnsəbˈstænʃieɪtɪd/", "pron": "un-suhb-STAN-shee-ay-tid", "fr": "non étayé", "def": "Not supported by evidence.", "ex": "The accusation remains unsubstantiated."}, {"term": "unsupported", "ipa": "/ˌʌnsəˈpɔːtɪd/", "pron": "un-suh-POR-tid", "fr": "non étayé", "def": "Not backed by evidence.", "ex": "The claim is unsupported by data."}, {"term": "unproven", "ipa": "/ˌʌnˈpruːvən/", "pron": "un-PROO-vuhn", "fr": "non prouvé", "def": "Not proved.", "ex": "The link between the two events remains unproven."}, {"term": "unverified", "ipa": "/ʌnˈverɪfaɪd/", "pron": "un-VER-i-fyd", "fr": "non vérifié", "def": "Not checked or confirmed.", "ex": "The rumour is unverified."}, {"term": "to hedge", "ipa": "/hedʒ/", "pron": "hej", "fr": "nuancer ; se couvrir", "def": "To avoid being too definite by using cautious language.", "ex": "Academic writing often hedges strong claims."}, {"term": "hedging", "ipa": "/ˈhedʒɪŋ/", "pron": "HEJ-ing", "fr": "atténuation ; prudence argumentative", "def": "Using cautious language to avoid overstatement.", "ex": "Hedging makes an argument more credible."}, {"term": "cautious wording", "ipa": "/ˌkɔːʃəs ˈwɜːdɪŋ/", "pron": "KAW-shuhs WUR-ding", "fr": "formulation prudente", "def": "Careful language that avoids overcertainty.", "ex": "Cautious wording is useful when evidence is limited."}, {"term": "strong claim", "ipa": "/strɒŋ kleɪm/", "pron": "strong klaym", "fr": "affirmation forte", "def": "A firm statement requiring solid evidence.", "ex": "A strong claim needs strong evidence."}, {"term": "overstatement", "ipa": "/ˈəʊvəˌsteɪtmənt/", "pron": "OH-vuh-STAYT-muhnt", "fr": "exagération", "def": "A claim that is stronger than the evidence justifies.", "ex": "Avoid overstatement in essays."}, {"term": "to overstate", "ipa": "/ˌəʊvəˈsteɪt/", "pron": "OH-vuh-stayt", "fr": "exagérer", "def": "To express something too strongly.", "ex": "The article overstates the role of social media."}, {"term": "to understate", "ipa": "/ˌʌndəˈsteɪt/", "pron": "UN-duh-stayt", "fr": "minimiser", "def": "To make something seem less important than it is.", "ex": "The government understates the scale of poverty."}, {"term": "to be cautious about", "ipa": "/bi ˈkɔːʃəs əˌbaʊt/", "pron": "bee KAW-shuhs uh-BOWT", "fr": "être prudent au sujet de", "def": "To avoid making strong claims too quickly.", "ex": "We should be cautious about drawing conclusions."}, {"term": "to avoid jumping to conclusions", "ipa": "/əˈvɔɪd ˈdʒʌmpɪŋ tə kənˈkluːʒənz/", "pron": "uh-VOID JUMP-ing tuh kuhn-KLOO-zhuhnz", "fr": "éviter de tirer des conclusions hâtives", "def": "To avoid deciding too quickly without enough evidence.", "ex": "Analysts should avoid jumping to conclusions."}, {"term": "to avoid overgeneralising", "ipa": "/əˈvɔɪd ˌəʊvəˈdʒenərəlaɪzɪŋ/", "pron": "uh-VOID OH-vuh-JEN-uh-ruh-ly-zing", "fr": "éviter de généraliser abusivement", "def": "To avoid making a claim too broad.", "ex": "One should avoid overgeneralising from one poll."}, {"term": "to draw a cautious conclusion", "ipa": "/drɔː ə ˈkɔːʃəs kənˈkluːʒən/", "pron": "draw uh KAW-shuhs kuhn-KLOO-zhuhn", "fr": "tirer une conclusion prudente", "def": "To reach a careful, limited judgement.", "ex": "We can draw a cautious conclusion from the data."}, {"term": "to remain open to interpretation", "ipa": "/rɪˈmeɪn ˈəʊpən tʊ ɪnˌtɜːprɪˈteɪʃən/", "pron": "ri-MAYN OH-puhn too in-tur-pri-TAY-shuhn", "fr": "rester ouvert à interprétation", "def": "To be not fully settled in meaning.", "ex": "The figures remain open to interpretation."}, {"term": "the picture is unclear", "ipa": "/ðə ˈpɪktʃə ɪz ʌnˈklɪə/", "pron": "thuh PIK-chuh iz un-KLEER", "fr": "la situation est floue", "def": "The situation is not easy to understand.", "ex": "The picture is unclear because the data are incomplete."}, {"term": "the evidence is mixed", "ipa": "/ði ˈevɪdəns ɪz mɪkst/", "pron": "the EV-i-duhns iz mikst", "fr": "les éléments sont mitigés", "def": "Some evidence supports one view, some another.", "ex": "The evidence is mixed on the effects of the policy."}]}, {"title": "F. Hedging, caution and academic precision", "entries": [{"term": "the data are ambiguous", "ipa": "/ðə ˈdeɪtə ɑːr æmˈbɪɡjuəs/", "pron": "thuh DAY-tuh ar am-BIG-yoo-uhs", "fr": "les données sont ambiguës", "def": "The data can be interpreted in several ways.", "ex": "The data are ambiguous and require caution."}, {"term": "there is insufficient evidence", "ipa": "/ðeər ɪz ˌɪnsəˈfɪʃənt ˈevɪdəns/", "pron": "thair iz in-suh-FISH-uhnt EV-i-duhns", "fr": "les preuves sont insuffisantes", "def": "There is not enough evidence.", "ex": "There is insufficient evidence to prove causation."}, {"term": "correlation does not imply causation", "ipa": "/ˌkɒrəˈleɪʃən dʌz nɒt ɪmˈplaɪ kɔːˈzeɪʃən/", "pron": "kor-uh-LAY-shuhn duz not im-PLY kaw-ZAY-shuhn", "fr": "corrélation n’implique pas causalité", "def": "A relationship between two facts does not prove one causes the other.", "ex": "Correlation does not imply causation, especially in social science."}]}]}, {"id": "p10c84", "part": 10, "chapter": 84, "title": "Comparing And Contrasting", "file": "cpge_vocab_part10_chapter84_comparing_and_contrasting_premium.html", "count": 158, "sections": [{"title": "A. Core comparison vocabulary", "entries": [{"term": "comparison", "ipa": "/kəmˈpærɪsən/", "pron": "kuhm-PAR-i-suhn", "fr": "comparaison", "def": "The act of examining similarities and differences between two or more things.", "ex": "A comparison between the US and the UK reveals different political traditions."}, {"term": "contrast", "ipa": "/ˈkɒntrɑːst/", "pron": "KON-trast", "fr": "contraste ; opposition", "def": "A clear difference between two things.", "ex": "The contrast between urban and rural voters is striking."}, {"term": "to compare", "ipa": "/kəmˈpeə/", "pron": "kuhm-PAIR", "fr": "comparer", "def": "To examine similarities and differences.", "ex": "The article compares American and British institutions."}, {"term": "to contrast", "ipa": "/kənˈtrɑːst/", "pron": "kuhn-TRAST", "fr": "opposer ; mettre en contraste", "def": "To emphasise differences between two things.", "ex": "The writer contrasts political promises with economic reality."}, {"term": "comparative", "ipa": "/kəmˈpærətɪv/", "pron": "kuhm-PAR-uh-tiv", "fr": "comparatif", "def": "Based on comparison.", "ex": "A comparative approach helps students avoid narrow analysis."}, {"term": "comparatively", "ipa": "/kəmˈpærətɪvli/", "pron": "kuhm-PAR-uh-tiv-lee", "fr": "comparativement", "def": "Compared with something else.", "ex": "Comparatively, the British system is more flexible."}, {"term": "relative", "ipa": "/ˈrelətɪv/", "pron": "REL-uh-tiv", "fr": "relatif", "def": "Considered in relation to something else.", "ex": "The relative success of the policy depends on the criteria used."}, {"term": "relatively", "ipa": "/ˈrelətɪvli/", "pron": "REL-uh-tiv-lee", "fr": "relativement", "def": "Compared with others; to a moderate degree.", "ex": "The reform was relatively popular among older voters."}, {"term": "similarity", "ipa": "/ˌsɪməˈlærəti/", "pron": "sim-uh-LARR-uh-tee", "fr": "similarité", "def": "A feature shared by two or more things.", "ex": "There are similarities between the two political crises."}, {"term": "difference", "ipa": "/ˈdɪfrəns/", "pron": "DIF-ruhns", "fr": "différence", "def": "A point on which things are not the same.", "ex": "The difference lies in the role of the constitution."}, {"term": "parallel", "ipa": "/ˈpærəlel/", "pron": "PARR-uh-lel", "fr": "parallèle", "def": "A similarity between two situations or developments.", "ex": "There is a parallel between today’s populism and earlier anti-elite movements."}, {"term": "analogy", "ipa": "/əˈnælədʒi/", "pron": "uh-NAL-uh-jee", "fr": "analogie", "def": "A comparison used to explain something by relating it to something similar.", "ex": "The analogy between the press and a watchdog is common."}, {"term": "equivalence", "ipa": "/ɪˈkwɪvələns/", "pron": "i-KWIV-uh-luhns", "fr": "équivalence", "def": "The state of being equal or comparable in value or meaning.", "ex": "The essay questions the equivalence between free speech and platform access."}, {"term": "false equivalence", "ipa": "/ˌfɔːls ɪˈkwɪvələns/", "pron": "false i-KWIV-uh-luhns", "fr": "fausse équivalence", "def": "A misleading comparison between things that are not truly equivalent.", "ex": "False equivalence can distort debates about climate science."}, {"term": "counterpart", "ipa": "/ˈkaʊntəpɑːt/", "pron": "KOWN-tuh-part", "fr": "homologue ; équivalent", "def": "A person or thing with a similar role in another system or country.", "ex": "The British prime minister has no exact American counterpart."}, {"term": "equivalent", "ipa": "/ɪˈkwɪvələnt/", "pron": "i-KWIV-uh-luhnt", "fr": "équivalent", "def": "Having a similar function, value or meaning.", "ex": "The House of Commons is not equivalent to the US House in every respect."}, {"term": "respectively", "ipa": "/rɪˈspektɪvli/", "pron": "ri-SPEK-tiv-lee", "fr": "respectivement", "def": "In the order already mentioned.", "ex": "The US and UK systems are presidential and parliamentary, respectively."}, {"term": "likewise", "ipa": "/ˈlaɪkwaɪz/", "pron": "LYK-wyz", "fr": "de même", "def": "In the same way; similarly.", "ex": "Likewise, Canada has faced debates over immigration."}, {"term": "similarly", "ipa": "/ˈsɪmələli/", "pron": "SIM-uh-luh-lee", "fr": "de même ; pareillement", "def": "In a similar way.", "ex": "Similarly, social media has changed British politics."}, {"term": "in the same way", "ipa": "/ɪn ðə seɪm weɪ/", "pron": "in thuh same way", "fr": "de la même manière", "def": "Used to introduce a similarity.", "ex": "In the same way, streaming has disrupted traditional television."}]}, {"title": "B. Expressing similarity", "entries": [{"term": "by the same token", "ipa": "/baɪ ðə seɪm ˈtəʊkən/", "pron": "by thuh same TOH-kuhn", "fr": "pour la même raison", "def": "For the same reason.", "ex": "By the same token, digital platforms should face scrutiny."}, {"term": "in the same vein", "ipa": "/ɪn ðə seɪm veɪn/", "pron": "in thuh same vayn", "fr": "dans le même esprit", "def": "In a similar style or line of argument.", "ex": "In the same vein, the article criticises media concentration."}, {"term": "along similar lines", "ipa": "/əˈlɒŋ ˈsɪmələ laɪnz/", "pron": "uh-LONG SIM-uh-luh lynz", "fr": "dans le même ordre d’idées", "def": "In a similar way or following a similar argument.", "ex": "Along similar lines, the report calls for regulation."}, {"term": "like", "ipa": "/laɪk/", "pron": "lyk", "fr": "comme ; à l’instar de", "def": "Similar to; used before a noun or pronoun.", "ex": "Like Britain, the United States faces political polarisation."}, {"term": "as with", "ipa": "/æz wɪð/", "pron": "az with", "fr": "comme pour", "def": "In the same situation as.", "ex": "As with climate policy, immigration debates are emotionally charged."}, {"term": "as in", "ipa": "/æz ɪn/", "pron": "az in", "fr": "comme dans", "def": "As happens in or as seen in.", "ex": "As in the US, British politics has become more fragmented."}, {"term": "as is the case with", "ipa": "/æz ɪz ðə keɪs wɪð/", "pron": "az iz thuh kays with", "fr": "comme c’est le cas pour", "def": "As also happens with.", "ex": "As is the case with many democracies, trust is declining."}, {"term": "to resemble", "ipa": "/rɪˈzembəl/", "pron": "ri-ZEM-buhl", "fr": "ressembler à", "def": "To be similar to something.", "ex": "The current crisis resembles earlier periods of instability."}, {"term": "to be similar to", "ipa": "/bi ˈsɪmələ tə/", "pron": "bee SIM-uh-luh tuh", "fr": "être similaire à", "def": "To share features with something.", "ex": "The British debate is similar to the American one in some respects."}, {"term": "to be comparable to", "ipa": "/bi ˈkɒmpərəbəl tə/", "pron": "bee KOM-puh-ruh-buhl tuh", "fr": "être comparable à", "def": "To be similar enough to compare.", "ex": "The situation is comparable to the 1970s in some ways."}, {"term": "to have something in common", "ipa": "/hæv ˈsʌmθɪŋ ɪn ˈkɒmən/", "pron": "hav SUM-thing in KOM-uhn", "fr": "avoir quelque chose en commun", "def": "To share a feature.", "ex": "Both movements have distrust of elites in common."}, {"term": "to share", "ipa": "/ʃeə/", "pron": "shair", "fr": "partager", "def": "To have the same feature, quality or experience.", "ex": "The two countries share a tradition of parliamentary debate."}, {"term": "to overlap", "ipa": "/ˌəʊvəˈlæp/", "pron": "OH-vuh-lap", "fr": "se chevaucher", "def": "To partly cover the same area, ideas or groups.", "ex": "Economic and cultural grievances often overlap."}, {"term": "overlap", "ipa": "/ˈəʊvəlæp/", "pron": "OH-vuh-lap", "fr": "chevauchement", "def": "An area of similarity or shared features.", "ex": "There is an overlap between economic insecurity and populist voting."}, {"term": "common ground", "ipa": "/ˌkɒmən ˈɡraʊnd/", "pron": "KOM-uhn grownd", "fr": "terrain d’entente", "def": "Shared beliefs or interests between opposing sides.", "ex": "The debate leaves little common ground."}, {"term": "convergence", "ipa": "/kənˈvɜːdʒəns/", "pron": "kuhn-VUR-juhns", "fr": "convergence", "def": "The process of becoming more similar.", "ex": "There has been convergence between mainstream parties on economic policy."}, {"term": "divergence", "ipa": "/daɪˈvɜːdʒəns/", "pron": "dy-VUR-juhns", "fr": "divergence", "def": "The process of becoming more different.", "ex": "The divergence between rich and poor regions is widening."}, {"term": "to converge", "ipa": "/kənˈvɜːdʒ/", "pron": "kuhn-VURJ", "fr": "converger", "def": "To become more similar or come together.", "ex": "The two parties have converged on immigration."}, {"term": "to diverge", "ipa": "/daɪˈvɜːdʒ/", "pron": "dy-VURJ", "fr": "diverger", "def": "To become different or move apart.", "ex": "Public attitudes diverge sharply by age."}, {"term": "whereas", "ipa": "/ˌweərˈæz/", "pron": "wair-AZ", "fr": "tandis que ; alors que", "def": "Used to compare contrasting facts.", "ex": "Older voters favoured stability, whereas younger voters wanted change."}]}, {"title": "C. Expressing contrast", "entries": [{"term": "while", "ipa": "/waɪl/", "pron": "wyle", "fr": "tandis que ; alors que", "def": "Used to contrast two ideas or facts.", "ex": "While the US has a written constitution, the UK relies on conventions."}, {"term": "unlike", "ipa": "/ˌʌnˈlaɪk/", "pron": "un-LYK", "fr": "contrairement à", "def": "Different from.", "ex": "Unlike the UK, the US has a presidential system."}, {"term": "contrary to", "ipa": "/ˈkɒntrəri tə/", "pron": "KON-truh-ree tuh", "fr": "contrairement à", "def": "In opposition to what is expected or believed.", "ex": "Contrary to expectations, turnout rose."}, {"term": "as opposed to", "ipa": "/æz əˈpəʊzd tə/", "pron": "az uh-POHZD tuh", "fr": "par opposition à", "def": "In contrast with.", "ex": "The policy targets renters as opposed to homeowners."}, {"term": "rather than", "ipa": "/ˈrɑːðə ðæn/", "pron": "RAH-thuh than", "fr": "plutôt que", "def": "Instead of; used to contrast alternatives.", "ex": "The crisis is political rather than purely economic."}, {"term": "instead of", "ipa": "/ɪnˈsted əv/", "pron": "in-STED ov", "fr": "au lieu de", "def": "In place of.", "ex": "Instead of addressing poverty, leaders blamed immigration."}, {"term": "instead", "ipa": "/ɪnˈsted/", "pron": "in-STED", "fr": "à la place ; au contraire", "def": "As an alternative or contrast.", "ex": "Instead, the government chose deregulation."}, {"term": "by contrast", "ipa": "/baɪ ˈkɒntrɑːst/", "pron": "by KON-trast", "fr": "par contraste", "def": "Used to emphasise difference.", "ex": "By contrast, Scandinavian countries have stronger welfare systems."}, {"term": "in contrast", "ipa": "/ɪn ˈkɒntrɑːst/", "pron": "in KON-trast", "fr": "en revanche ; par contraste", "def": "Used to introduce a difference.", "ex": "In contrast, the American system is more polarised."}, {"term": "on the contrary", "ipa": "/ɒn ðə ˈkɒntrəri/", "pron": "on thuh KON-truh-ree", "fr": "au contraire", "def": "Used to reject a previous idea and assert the opposite.", "ex": "The reform did not reduce inequality; on the contrary, it widened it."}, {"term": "conversely", "ipa": "/ˈkɒnvɜːsli/", "pron": "KON-vurss-lee", "fr": "inversement", "def": "In the opposite way.", "ex": "Conversely, local policies may be more flexible."}, {"term": "however", "ipa": "/haʊˈevə/", "pron": "how-EV-uh", "fr": "cependant", "def": "Used to introduce a contrast.", "ex": "However, the comparison has limits."}, {"term": "nevertheless", "ipa": "/ˌnevəðəˈles/", "pron": "nev-uh-thuh-LESS", "fr": "néanmoins", "def": "Despite that; introduces contrast after concession.", "ex": "Nevertheless, the two systems share some weaknesses."}, {"term": "yet", "ipa": "/jet/", "pron": "yet", "fr": "pourtant", "def": "But; used to show contrast.", "ex": "The reform is popular, yet ineffective."}, {"term": "still", "ipa": "/stɪl/", "pron": "stil", "fr": "malgré cela ; pourtant", "def": "Despite this.", "ex": "Still, the analogy remains useful."}, {"term": "on the one hand", "ipa": "/ɒn ðə wʌn hænd/", "pron": "on thuh one hand", "fr": "d’une part", "def": "Used to introduce one side of a comparison or argument.", "ex": "On the one hand, regulation protects users."}, {"term": "on the other hand", "ipa": "/ɒn ði ˈʌðə hænd/", "pron": "on thee UTH-uh hand", "fr": "d’autre part", "def": "Used to introduce the contrasting side.", "ex": "On the other hand, it may threaten free speech."}, {"term": "where", "ipa": "/weə/", "pron": "wair", "fr": "là où ; tandis que", "def": "Used in formal comparison to mean whereas.", "ex": "Where the US stresses individual rights, Europe often stresses dignity."}, {"term": "whereby", "ipa": "/weəˈbaɪ/", "pron": "wair-BY", "fr": "par lequel", "def": "By which; through which.", "ex": "The system creates a mechanism whereby citizens may appeal."}, {"term": "the former", "ipa": "/ðə ˈfɔːmə/", "pron": "thuh FOR-muh", "fr": "le premier", "def": "The first of two things mentioned.", "ex": "The former emphasises liberty, the latter equality."}, {"term": "the latter", "ipa": "/ðə ˈlætə/", "pron": "thuh LAT-uh", "fr": "le second ; ce dernier", "def": "The second of two things mentioned.", "ex": "The latter is more decentralised."}, {"term": "respectively", "ipa": "/rɪˈspektɪvli/", "pron": "ri-SPEK-tiv-lee", "fr": "respectivement", "def": "In the same order as previously mentioned.", "ex": "The former and latter refer to the US and UK, respectively."}, {"term": "both", "ipa": "/bəʊθ/", "pron": "bohth", "fr": "les deux ; tous deux", "def": "The two together.", "ex": "Both systems face legitimacy crises."}, {"term": "neither", "ipa": "/ˈnaɪðə/", "pron": "NY-thuh", "fr": "ni l’un ni l’autre", "def": "Not one and not the other.", "ex": "Neither solution fully addresses poverty."}, {"term": "either", "ipa": "/ˈaɪðə/", "pron": "EYE-thuh", "fr": "l’un ou l’autre", "def": "One or the other of two options.", "ex": "Either interpretation may be valid."}, {"term": "both... and", "ipa": "/bəʊθ ænd/", "pron": "bohth and", "fr": "à la fois... et", "def": "Used to connect two equal elements.", "ex": "The crisis is both economic and cultural."}, {"term": "neither... nor", "ipa": "/ˈnaɪðə nɔː/", "pron": "NY-thuh nor", "fr": "ni... ni", "def": "Used to reject two options.", "ex": "The policy is neither fair nor efficient."}, {"term": "either... or", "ipa": "/ˈaɪðər ɔː/", "pron": "EYE-thuh or", "fr": "soit... soit", "def": "Used to present two alternatives.", "ex": "The government must either reform the system or face more unrest."}, {"term": "not only... but also", "ipa": "/nɒt ˈəʊnli bət ˈɔːlsəʊ/", "pron": "not OHN-lee but AWL-soh", "fr": "non seulement... mais aussi", "def": "Used to add a second stronger idea.", "ex": "The reform is not only costly but also unpopular."}, {"term": "more... than", "ipa": "/mɔː ðæn/", "pron": "more than", "fr": "plus... que", "def": "Used for comparison of degree.", "ex": "The problem is more political than technical."}]}, {"title": "D. Comparing degree, scope and perspective", "entries": [{"term": "less... than", "ipa": "/les ðæn/", "pron": "less than", "fr": "moins... que", "def": "Used to show lower degree.", "ex": "The reform is less radical than critics claim."}, {"term": "as... as", "ipa": "/æz æz/", "pron": "az az", "fr": "aussi... que", "def": "Used to show equality of degree.", "ex": "The crisis is as cultural as it is economic."}, {"term": "not as... as", "ipa": "/nɒt æz æz/", "pron": "not az az", "fr": "pas aussi... que", "def": "Used to show inequality of degree.", "ex": "The policy is not as effective as promised."}, {"term": "no less... than", "ipa": "/nəʊ les ðæn/", "pron": "noh less than", "fr": "tout aussi... que", "def": "Used to emphasise equal importance.", "ex": "Housing is no less important than healthcare."}, {"term": "more or less", "ipa": "/mɔːr ɔː les/", "pron": "more or less", "fr": "plus ou moins", "def": "Approximately; almost.", "ex": "The two parties offer more or less the same economic policy."}, {"term": "to a greater extent than", "ipa": "/tə ə ˈɡreɪtər ɪkˈstent ðæn/", "pron": "tuh uh GRAY-tuh ik-STENT than", "fr": "dans une plus grande mesure que", "def": "More than; in a stronger degree.", "ex": "The crisis affects renters to a greater extent than homeowners."}, {"term": "to a lesser extent than", "ipa": "/tə ə ˈlesər ɪkˈstent ðæn/", "pron": "tuh uh LES-uh ik-STENT than", "fr": "dans une moindre mesure que", "def": "Less than; in a weaker degree.", "ex": "Older voters are affected to a lesser extent than younger workers."}, {"term": "compared with", "ipa": "/kəmˈpeəd wɪð/", "pron": "kuhm-PAIRD with", "fr": "comparé à", "def": "When examined in relation to.", "ex": "Compared with previous elections, turnout was low."}, {"term": "compared to", "ipa": "/kəmˈpeəd tə/", "pron": "kuhm-PAIRD tuh", "fr": "comparé à", "def": "When likened to or compared with.", "ex": "Compared to its rivals, the party looks moderate."}, {"term": "in comparison with", "ipa": "/ɪn kəmˈpærɪsən wɪð/", "pron": "in kuhm-PAR-i-suhn with", "fr": "en comparaison avec", "def": "Compared with; formal.", "ex": "In comparison with the US, Britain has stricter gun laws."}, {"term": "relative to", "ipa": "/ˈrelətɪv tə/", "pron": "REL-uh-tiv tuh", "fr": "par rapport à", "def": "Compared with or in relation to.", "ex": "Wages have fallen relative to housing costs."}, {"term": "vis-à-vis", "ipa": "/ˌviːz ɑː ˈviː/", "pron": "veez-ah-VEE", "fr": "vis-à-vis de ; par rapport à", "def": "In relation to; compared with; formal.", "ex": "The UK’s position vis-à-vis the EU remains contested."}, {"term": "against", "ipa": "/əˈɡenst/", "pron": "uh-GENST", "fr": "par rapport à ; face à", "def": "Compared with a background or standard.", "ex": "The figures look worse against the European average."}, {"term": "measured against", "ipa": "/ˈmeʒəd əˌɡenst/", "pron": "MEZH-uhd uh-GENST", "fr": "mesuré à l’aune de", "def": "Judged in comparison with a standard.", "ex": "Measured against its promises, the reform failed."}, {"term": "when set against", "ipa": "/wen set əˌɡenst/", "pron": "wen set uh-GENST", "fr": "mis en regard de", "def": "When compared with a background or standard.", "ex": "When set against rising rents, wage growth seems weak."}, {"term": "in relation to", "ipa": "/ɪn rɪˈleɪʃən tə/", "pron": "in ri-LAY-shuhn tuh", "fr": "par rapport à", "def": "With reference to; compared with.", "ex": "The policy must be analysed in relation to inequality."}, {"term": "with regard to", "ipa": "/wɪð rɪˈɡɑːd tə/", "pron": "with ri-GARD tuh", "fr": "en ce qui concerne", "def": "Concerning; in relation to.", "ex": "With regard to healthcare, the two countries differ sharply."}, {"term": "with respect to", "ipa": "/wɪð rɪˈspekt tə/", "pron": "with ri-SPEKT tuh", "fr": "en ce qui concerne", "def": "Concerning; formal.", "ex": "With respect to education, the article is less convincing."}, {"term": "as regards", "ipa": "/æz rɪˈɡɑːdz/", "pron": "az ri-GARDZ", "fr": "en ce qui concerne", "def": "Concerning; regarding.", "ex": "As regards climate policy, the parties differ little."}, {"term": "in terms of", "ipa": "/ɪn tɜːmz əv/", "pron": "in turmz ov", "fr": "en termes de", "def": "With respect to a particular aspect.", "ex": "In terms of social mobility, the results are disappointing."}, {"term": "from the standpoint of", "ipa": "/frəm ðə ˈstændpɔɪnt əv/", "pron": "from thuh STAND-point ov", "fr": "du point de vue de", "def": "From a particular perspective.", "ex": "From the standpoint of voters, the reform seems remote."}, {"term": "from the perspective of", "ipa": "/frəm ðə pəˈspektɪv əv/", "pron": "from thuh puh-SPEK-tiv ov", "fr": "du point de vue de", "def": "From a particular point of view.", "ex": "From the perspective of young people, housing is the main issue."}, {"term": "similar in that", "ipa": "/ˈsɪmələr ɪn ðæt/", "pron": "SIM-uh-luh in that", "fr": "similaire en ce que", "def": "Similar because.", "ex": "The two movements are similar in that they attack elites."}, {"term": "different in that", "ipa": "/ˈdɪfrənt ɪn ðæt/", "pron": "DIF-ruhnt in that", "fr": "différent en ce que", "def": "Different because.", "ex": "The UK is different in that its constitution is uncodified."}, {"term": "what they have in common is", "ipa": "/wɒt ðeɪ hæv ɪn ˈkɒmən ɪz/", "pron": "wot thay hav in KOM-uhn iz", "fr": "ce qu’ils ont en commun, c’est", "def": "Used to identify shared features.", "ex": "What they have in common is distrust of institutions."}, {"term": "what sets them apart is", "ipa": "/wɒt sets ðem əˈpɑːt ɪz/", "pron": "wot sets them uh-PART iz", "fr": "ce qui les distingue, c’est", "def": "Used to identify a key difference.", "ex": "What sets them apart is their attitude to the state."}, {"term": "the key difference lies in", "ipa": "/ðə kiː ˈdɪfrəns laɪz ɪn/", "pron": "thuh kee DIF-ruhns lyz in", "fr": "la différence principale réside dans", "def": "The main difference is found in.", "ex": "The key difference lies in the role of courts."}, {"term": "the main similarity is that", "ipa": "/ðə meɪn ˌsɪməˈlærəti ɪz ðæt/", "pron": "thuh mayn sim-uh-LARR-uh-tee iz that", "fr": "la principale similarité est que", "def": "Used to introduce the main shared point.", "ex": "The main similarity is that both systems face distrust."}, {"term": "the crucial contrast is between", "ipa": "/ðə ˈkruːʃəl ˈkɒntrɑːst ɪz bɪˈtwiːn/", "pron": "thuh KROO-shuhl KON-trast iz bi-TWEEN", "fr": "le contraste essentiel oppose", "def": "Used to introduce a major opposition.", "ex": "The crucial contrast is between formal rights and real access."}, {"term": "a useful comparison can be made between", "ipa": "/ə ˈjuːsfəl kəmˈpærɪsən kæn bi meɪd bɪˈtwiːn/", "pron": "uh YOOSS-fuhl kuhm-PAR-i-suhn kan bee mayd bi-TWEEN", "fr": "on peut établir une comparaison utile entre", "def": "Used to introduce a relevant comparison.", "ex": "A useful comparison can be made between Brexit and Trumpism."}, {"term": "the analogy is useful because", "ipa": "/ði əˈnælədʒi ɪz ˈjuːsfəl bɪˈkɒz/", "pron": "the uh-NAL-uh-jee iz YOOSS-fuhl bi-KOZ", "fr": "l’analogie est utile car", "def": "Used to explain why a comparison helps.", "ex": "The analogy is useful because both cases involve distrust."}, {"term": "the comparison has limits", "ipa": "/ðə kəmˈpærɪsən hæz ˈlɪmɪts/", "pron": "thuh kuhm-PAR-i-suhn haz LIM-its", "fr": "la comparaison a des limites", "def": "Used to avoid overextending a comparison.", "ex": "The comparison has limits because the institutions differ."}, {"term": "the analogy breaks down when", "ipa": "/ði əˈnælədʒi breɪks daʊn wen/", "pron": "the uh-NAL-uh-jee brayks down wen", "fr": "l’analogie cesse d’être valable lorsque", "def": "The comparison stops working when.", "ex": "The analogy breaks down when we consider legal structures."}]}, {"title": "E. Building strong comparative analysis", "entries": [{"term": "one should not equate", "ipa": "/wʌn ʃʊd nɒt ɪˈkweɪt/", "pron": "wun should not i-KWAYT", "fr": "il ne faut pas assimiler", "def": "One should not treat two things as the same.", "ex": "One should not equate criticism with censorship."}, {"term": "to draw a parallel between", "ipa": "/drɔː ə ˈpærəlel bɪˈtwiːn/", "pron": "draw uh PARR-uh-lel bi-TWEEN", "fr": "établir un parallèle entre", "def": "To identify a similarity between two situations.", "ex": "The article draws a parallel between populism and nationalism."}, {"term": "to draw a distinction between", "ipa": "/drɔː ə dɪˈstɪŋkʃən bɪˈtwiːn/", "pron": "draw uh di-STINK-shuhn bi-TWEEN", "fr": "établir une distinction entre", "def": "To make a difference clear.", "ex": "We must draw a distinction between equality and uniformity."}, {"term": "to blur the distinction between", "ipa": "/blɜː ðə dɪˈstɪŋkʃən bɪˈtwiːn/", "pron": "blur thuh di-STINK-shuhn bi-TWEEN", "fr": "brouiller la distinction entre", "def": "To make a difference less clear.", "ex": "Social media blurs the distinction between private and public speech."}, {"term": "to bridge the gap between", "ipa": "/brɪdʒ ðə ɡæp bɪˈtwiːn/", "pron": "brij thuh gap bi-TWEEN", "fr": "combler le fossé entre", "def": "To reduce a difference or division.", "ex": "Education can bridge the gap between social classes."}, {"term": "to widen the gap between", "ipa": "/ˈwaɪdən ðə ɡæp bɪˈtwiːn/", "pron": "WY-duhn thuh gap bi-TWEEN", "fr": "creuser l’écart entre", "def": "To increase a difference or division.", "ex": "The crisis widened the gap between rich and poor."}, {"term": "to narrow the gap between", "ipa": "/ˈnærəʊ ðə ɡæp bɪˈtwiːn/", "pron": "NAR-oh thuh gap bi-TWEEN", "fr": "réduire l’écart entre", "def": "To reduce a difference or division.", "ex": "Redistribution can narrow the gap between regions."}, {"term": "to stand in sharp contrast to", "ipa": "/stænd ɪn ʃɑːp ˈkɒntrɑːst tə/", "pron": "stand in sharp KON-trast tuh", "fr": "contraster fortement avec", "def": "To be very different from.", "ex": "The promise stands in sharp contrast to reality."}, {"term": "to be worlds apart", "ipa": "/bi wɜːldz əˈpɑːt/", "pron": "bee worlds uh-PART", "fr": "être aux antipodes", "def": "To be extremely different.", "ex": "The two visions of society are worlds apart."}, {"term": "apples and oranges", "ipa": "/ˌæpəlz ənd ˈɒrɪndʒɪz/", "pron": "AP-uhlz and OR-in-jiz", "fr": "des choses incomparables", "def": "Things too different to compare fairly.", "ex": "Comparing local councils and national governments can be apples and oranges."}, {"term": "like-for-like comparison", "ipa": "/ˌlaɪk fə laɪk kəmˈpærɪsən/", "pron": "lyk-fuh-lyk kuhm-PAR-i-suhn", "fr": "comparaison à périmètre comparable", "def": "A fair comparison between similar things.", "ex": "A like-for-like comparison gives a clearer picture."}, {"term": "benchmark", "ipa": "/ˈbentʃmɑːk/", "pron": "BENCH-mark", "fr": "référence ; étalon", "def": "A standard used for comparison.", "ex": "The OECD average is often used as a benchmark."}, {"term": "baseline", "ipa": "/ˈbeɪslaɪn/", "pron": "BAYSS-lyne", "fr": "niveau de référence", "def": "A starting point used for comparison.", "ex": "The pre-crisis level provides a baseline."}, {"term": "yardstick", "ipa": "/ˈjɑːdstɪk/", "pron": "YARD-stik", "fr": "critère ; étalon", "def": "A standard used to judge or compare something.", "ex": "GDP is a limited yardstick for well-being."}, {"term": "frame of reference", "ipa": "/ˌfreɪm əv ˈrefərəns/", "pron": "fraym ov REF-uh-ruhns", "fr": "cadre de référence", "def": "The context or standard used to interpret something.", "ex": "The comparison depends on the frame of reference."}, {"term": "to benchmark against", "ipa": "/ˈbentʃmɑːk əˌɡenst/", "pron": "BENCH-mark uh-GENST", "fr": "comparer à un référentiel", "def": "To compare with a standard or competitor.", "ex": "Countries benchmark their schools against international rankings."}, {"term": "to measure against", "ipa": "/ˈmeʒər əˌɡenst/", "pron": "MEZH-uh uh-GENST", "fr": "mesurer à l’aune de", "def": "To judge in relation to a standard.", "ex": "The policy should be measured against its aims."}, {"term": "to put side by side", "ipa": "/pʊt saɪd baɪ saɪd/", "pron": "put side by side", "fr": "mettre côte à côte", "def": "To compare directly.", "ex": "Putting the two speeches side by side reveals a shift in tone."}, {"term": "side-by-side comparison", "ipa": "/ˌsaɪd baɪ saɪd kəmˈpærɪsən/", "pron": "side-by-side kuhm-PAR-i-suhn", "fr": "comparaison côte à côte", "def": "A direct comparison of two things.", "ex": "A side-by-side comparison helps clarify the differences."}, {"term": "point of comparison", "ipa": "/ˌpɔɪnt əv kəmˈpærɪsən/", "pron": "point ov kuhm-PAR-i-suhn", "fr": "point de comparaison", "def": "A specific aspect used to compare things.", "ex": "Institutional design is a useful point of comparison."}, {"term": "basis for comparison", "ipa": "/ˈbeɪsɪs fə kəmˈpærɪsən/", "pron": "BAY-sis fuh kuhm-PAR-i-suhn", "fr": "base de comparaison", "def": "The criterion or ground on which things are compared.", "ex": "Income alone is not a sufficient basis for comparison."}, {"term": "to compare like with like", "ipa": "/kəmˈpeə laɪk wɪð laɪk/", "pron": "kuhm-PAIR lyk with lyk", "fr": "comparer ce qui est comparable", "def": "To compare things that are genuinely similar.", "ex": "We must compare like with like before drawing conclusions."}, {"term": "to compare apples with oranges", "ipa": "/kəmˈpeə ˈæpəlz wɪð ˈɒrɪndʒɪz/", "pron": "kuhm-PAIR AP-uhlz with OR-in-jiz", "fr": "comparer des choux et des carottes", "def": "To compare things that are too different.", "ex": "The article compares apples with oranges."}, {"term": "to avoid false equivalence", "ipa": "/əˈvɔɪd ˌfɔːls ɪˈkwɪvələns/", "pron": "uh-VOID false i-KWIV-uh-luhns", "fr": "éviter les fausses équivalences", "def": "To avoid treating unequal things as equal.", "ex": "Good analysis avoids false equivalence."}, {"term": "to compare favourably with", "ipa": "/kəmˈpeə ˈfeɪvərəbli wɪð/", "pron": "kuhm-PAIR FAY-vuh-ruh-blee with", "fr": "soutenir avantageusement la comparaison avec", "def": "To be better than something in comparison.", "ex": "The policy compares favourably with earlier reforms."}, {"term": "to compare unfavourably with", "ipa": "/kəmˈpeə ʌnˈfeɪvərəbli wɪð/", "pron": "kuhm-PAIR un-FAY-vuh-ruh-blee with", "fr": "souffrir de la comparaison avec", "def": "To be worse than something in comparison.", "ex": "The UK compares unfavourably with Nordic welfare states."}, {"term": "to be in line with", "ipa": "/bi ɪn laɪn wɪð/", "pron": "bee in line with", "fr": "être conforme à ; s’inscrire dans", "def": "To correspond to or be consistent with.", "ex": "The results are in line with earlier polls."}, {"term": "to be at odds with", "ipa": "/bi æt ɒdz wɪð/", "pron": "bee at odz with", "fr": "être en contradiction avec", "def": "To conflict with or differ strongly from.", "ex": "The policy is at odds with the government’s promises."}, {"term": "to be consistent with", "ipa": "/bi kənˈsɪstənt wɪð/", "pron": "bee kuhn-SIS-tuhnt with", "fr": "être cohérent avec", "def": "To agree with or match something.", "ex": "The evidence is consistent with long-term decline."}, {"term": "to be incompatible with", "ipa": "/bi ˌɪnkəmˈpætəbəl wɪð/", "pron": "bee in-kuhm-PAT-uh-buhl with", "fr": "être incompatible avec", "def": "To be unable to exist or agree with something.", "ex": "Mass surveillance is incompatible with privacy."}, {"term": "to be aligned with", "ipa": "/bi əˈlaɪnd wɪð/", "pron": "bee uh-LYND with", "fr": "être aligné sur", "def": "To be in agreement or correspondence with.", "ex": "The policy is aligned with international standards."}, {"term": "to differ from", "ipa": "/ˈdɪfə frəm/", "pron": "DIF-uh from", "fr": "différer de", "def": "To be different from.", "ex": "The British system differs from the American one."}, {"term": "to differ in terms of", "ipa": "/ˈdɪfər ɪn tɜːmz əv/", "pron": "DIF-uh in turmz ov", "fr": "différer en termes de", "def": "To be different regarding a specific aspect.", "ex": "The two countries differ in terms of welfare provision."}, {"term": "to vary across", "ipa": "/ˈveəri əˈkrɒs/", "pron": "VAIR-ee uh-KROSS", "fr": "varier selon", "def": "To be different in different places or groups.", "ex": "Attitudes vary across regions and generations."}]}, {"title": "F. Nuanced comparison and exam-ready phrases", "entries": [{"term": "to range from... to...", "ipa": "/reɪndʒ frəm tə/", "pron": "raynj from tuh", "fr": "aller de... à...", "def": "To cover a span between two extremes.", "ex": "Responses range from enthusiasm to hostility."}, {"term": "spectrum", "ipa": "/ˈspektrəm/", "pron": "SPEK-truhm", "fr": "spectre ; éventail", "def": "A range of different positions or degrees.", "ex": "Political opinion exists on a spectrum."}, {"term": "continuum", "ipa": "/kənˈtɪnjuəm/", "pron": "kuhn-TIN-yoo-uhm", "fr": "continuum", "def": "A continuous range of variation.", "ex": "Identity can be understood as a continuum."}, {"term": "degree", "ipa": "/dɪˈɡriː/", "pron": "di-GREE", "fr": "degré", "def": "The amount, level or extent of something.", "ex": "The difference is one of degree, not kind."}, {"term": "a matter of degree", "ipa": "/ə ˈmætər əv dɪˈɡriː/", "pron": "uh MAT-uh ov di-GREE", "fr": "une question de degré", "def": "A difference in intensity, not in nature.", "ex": "The disagreement is a matter of degree."}, {"term": "a matter of kind", "ipa": "/ə ˈmætər əv kaɪnd/", "pron": "uh MAT-uh ov kynd", "fr": "une différence de nature", "def": "A difference in nature or category.", "ex": "This is not just a matter of degree but of kind."}, {"term": "qualitative difference", "ipa": "/ˈkwɒlɪtətɪv ˈdɪfrəns/", "pron": "KWOL-i-tuh-tiv DIF-ruhns", "fr": "différence qualitative", "def": "A difference in nature or quality.", "ex": "There is a qualitative difference between criticism and harassment."}, {"term": "quantitative difference", "ipa": "/ˈkwɒntɪtətɪv ˈdɪfrəns/", "pron": "KWON-ti-tuh-tiv DIF-ruhns", "fr": "différence quantitative", "def": "A difference in amount or number.", "ex": "The difference is quantitative rather than qualitative."}, {"term": "more nuanced than", "ipa": "/mɔː ˈnjuːɑːnst ðæn/", "pron": "more NYOO-ahnst than", "fr": "plus nuancé que", "def": "More subtle or complex than.", "ex": "The issue is more nuanced than the headline suggests."}, {"term": "less clear-cut than", "ipa": "/les ˌklɪə ˈkʌt ðæn/", "pron": "less KLEER-cut than", "fr": "moins tranché que", "def": "Less simple or definite than.", "ex": "The distinction is less clear-cut than it first appears."}, {"term": "not identical to", "ipa": "/nɒt aɪˈdentɪkəl tə/", "pron": "not eye-DEN-ti-kuhl tuh", "fr": "pas identique à", "def": "Not exactly the same as.", "ex": "Equality is not identical to sameness."}, {"term": "not equivalent to", "ipa": "/nɒt ɪˈkwɪvələnt tə/", "pron": "not i-KWIV-uh-luhnt tuh", "fr": "pas équivalent à", "def": "Not equal or interchangeable with.", "ex": "Criticism is not equivalent to censorship."}, {"term": "not comparable to", "ipa": "/nɒt ˈkɒmpərəbəl tə/", "pron": "not KOM-puh-ruh-buhl tuh", "fr": "pas comparable à", "def": "Too different to compare fairly.", "ex": "The two cases are not directly comparable."}, {"term": "broadly similar", "ipa": "/ˌbrɔːdli ˈsɪmələ/", "pron": "BROD-lee SIM-uh-luh", "fr": "globalement similaire", "def": "Similar in general, though not in every detail.", "ex": "The two systems are broadly similar in purpose."}, {"term": "roughly equivalent", "ipa": "/ˌrʌfli ɪˈkwɪvələnt/", "pron": "RUF-lee i-KWIV-uh-luhnt", "fr": "à peu près équivalent", "def": "Approximately equal or similar.", "ex": "The two measures are roughly equivalent."}, {"term": "fundamentally different", "ipa": "/ˌfʌndəˈmentəli ˈdɪfrənt/", "pron": "fun-duh-MEN-tuh-lee DIF-ruhnt", "fr": "fondamentalement différent", "def": "Different in a basic or essential way.", "ex": "The two models are fundamentally different."}, {"term": "strikingly similar", "ipa": "/ˈstraɪkɪŋli ˈsɪmələ/", "pron": "STRY-king-lee SIM-uh-luh", "fr": "étonnamment similaire", "def": "Very noticeably similar.", "ex": "The rhetoric is strikingly similar."}, {"term": "markedly different", "ipa": "/ˈmɑːkɪdli ˈdɪfrənt/", "pron": "MAR-kid-lee DIF-ruhnt", "fr": "nettement différent", "def": "Clearly and noticeably different.", "ex": "Outcomes are markedly different across regions."}, {"term": "sharply contrasting", "ipa": "/ˈʃɑːpli kənˈtrɑːstɪŋ/", "pron": "SHARP-lee kuhn-TRAST-ing", "fr": "fortement contrasté", "def": "Very different and strongly opposed.", "ex": "The two speeches offer sharply contrasting visions."}, {"term": "a sharper divide", "ipa": "/ə ʃɑːpə dɪˈvaɪd/", "pron": "uh SHARP-uh di-VYDE", "fr": "un clivage plus net", "def": "A clearer or stronger division.", "ex": "The election revealed a sharper divide between age groups."}, {"term": "a deeper divide", "ipa": "/ə ˈdiːpə dɪˈvaɪd/", "pron": "uh DEEP-uh di-VYDE", "fr": "un fossé plus profond", "def": "A more serious division.", "ex": "The crisis exposed a deeper divide between regions."}]}]}, {"id": "p10c85", "part": 10, "chapter": 85, "title": "Analysing Statistics", "file": "cpge_vocab_part10_chapter85_analysing_statistics_premium.html", "count": 126, "sections": [{"title": "A. Core statistical vocabulary", "entries": [{"term": "statistics", "ipa": "/stəˈtɪstɪks/", "pron": "stuh-TIS-tiks", "fr": "statistiques", "def": "Numerical information collected and analysed to understand a situation or trend.", "ex": "Statistics can clarify social problems, but they can also be misleading."}, {"term": "data", "ipa": "/ˈdeɪtə/", "pron": "DAY-tuh", "fr": "données", "def": "Facts, figures or information used for analysis.", "ex": "The data suggest that inequality has increased."}, {"term": "dataset", "ipa": "/ˈdeɪtəset/", "pron": "DAY-tuh-set", "fr": "jeu de données", "def": "A structured collection of data.", "ex": "The dataset covers ten years of unemployment figures."}, {"term": "figure", "ipa": "/ˈfɪɡə/", "pron": "FIG-uh", "fr": "chiffre", "def": "A number or statistic used as evidence.", "ex": "The latest figures show a rise in inflation."}, {"term": "figures", "ipa": "/ˈfɪɡəz/", "pron": "FIG-uhz", "fr": "chiffres", "def": "Numerical data or statistics.", "ex": "The figures must be interpreted cautiously."}, {"term": "indicator", "ipa": "/ˈɪndɪkeɪtə/", "pron": "IN-di-kay-tuh", "fr": "indicateur", "def": "A measure used to show the state or development of something.", "ex": "The unemployment rate is an important economic indicator."}, {"term": "index", "ipa": "/ˈɪndeks/", "pron": "IN-deks", "fr": "indice", "def": "A measure combining several indicators into one figure.", "ex": "The consumer price index measures inflation."}, {"term": "survey", "ipa": "/ˈsɜːveɪ/", "pron": "SUR-vay", "fr": "enquête ; sondage", "def": "A study based on questions asked to a sample of people.", "ex": "The survey reveals growing concern about housing."}, {"term": "poll", "ipa": "/pəʊl/", "pron": "pohl", "fr": "sondage", "def": "A survey measuring public opinion.", "ex": "The poll shows a narrow lead for the opposition."}, {"term": "opinion poll", "ipa": "/əˈpɪnjən pəʊl/", "pron": "uh-PIN-yuhn pohl", "fr": "sondage d’opinion", "def": "A poll measuring what people think about politics or social issues.", "ex": "Opinion polls can influence campaigns."}, {"term": "sample", "ipa": "/ˈsɑːmpəl/", "pron": "SAHM-puhl", "fr": "échantillon", "def": "A smaller group studied to represent a larger population.", "ex": "The sample may not represent the whole population."}, {"term": "sample size", "ipa": "/ˈsɑːmpəl saɪz/", "pron": "SAHM-puhl syze", "fr": "taille de l’échantillon", "def": "The number of people or cases included in a study.", "ex": "A small sample size weakens the reliability of the poll."}, {"term": "representative sample", "ipa": "/ˌreprɪˈzentətɪv ˈsɑːmpəl/", "pron": "rep-ri-ZEN-tuh-tiv SAHM-puhl", "fr": "échantillon représentatif", "def": "A sample that reflects the wider population.", "ex": "A representative sample is essential for reliable conclusions."}, {"term": "respondent", "ipa": "/rɪˈspɒndənt/", "pron": "ri-SPON-duhnt", "fr": "répondant", "def": "A person who answers a survey or poll.", "ex": "Many respondents said they distrusted politicians."}, {"term": "margin of error", "ipa": "/ˌmɑːdʒɪn əv ˈerə/", "pron": "MAR-jin ov ERR-uh", "fr": "marge d’erreur", "def": "The expected range of possible error in survey results.", "ex": "The candidate’s lead is within the margin of error."}, {"term": "confidence interval", "ipa": "/ˈkɒnfɪdəns ˌɪntəvəl/", "pron": "KON-fi-duhns IN-tuh-vuhl", "fr": "intervalle de confiance", "def": "A range within which a true value is likely to fall.", "ex": "The confidence interval is wide because the sample is small."}, {"term": "reliability", "ipa": "/rɪˌlaɪəˈbɪləti/", "pron": "ri-ly-uh-BIL-uh-tee", "fr": "fiabilité", "def": "The extent to which data or results can be trusted.", "ex": "The reliability of the figures depends on the method."}, {"term": "validity", "ipa": "/vəˈlɪdəti/", "pron": "vuh-LID-uh-tee", "fr": "validité", "def": "The extent to which a measure really measures what it claims to measure.", "ex": "GDP has limited validity as a measure of well-being."}, {"term": "bias", "ipa": "/ˈbaɪəs/", "pron": "BY-uhs", "fr": "biais", "def": "A systematic distortion in data, questions or interpretation.", "ex": "Sampling bias can distort the results."}, {"term": "sampling bias", "ipa": "/ˈsɑːmplɪŋ ˌbaɪəs/", "pron": "SAHM-pling BY-uhs", "fr": "biais d’échantillonnage", "def": "Bias caused by a sample that does not represent the population.", "ex": "Sampling bias may overrepresent older voters."}, {"term": "response bias", "ipa": "/rɪˈspɒns ˌbaɪəs/", "pron": "ri-SPONS BY-uhs", "fr": "biais de réponse", "def": "Bias caused by the way respondents answer questions.", "ex": "Response bias may affect sensitive questions."}, {"term": "selection bias", "ipa": "/sɪˈlekʃən ˌbaɪəs/", "pron": "si-LEK-shuhn BY-uhs", "fr": "biais de sélection", "def": "Bias caused by who is included or excluded from a study.", "ex": "Selection bias can make a programme look more effective."}, {"term": "trend", "ipa": "/trend/", "pron": "trend", "fr": "tendance", "def": "A general direction of change over time.", "ex": "The trend points to rising political polarisation."}]}, {"title": "B. Trends, changes and intensity", "entries": [{"term": "pattern", "ipa": "/ˈpætən/", "pron": "PAT-uhn", "fr": "schéma ; tendance", "def": "A repeated or recognisable form in data.", "ex": "The pattern is visible across several regions."}, {"term": "tendency", "ipa": "/ˈtendənsi/", "pron": "TEN-duhn-see", "fr": "tendance", "def": "A general movement or inclination.", "ex": "There is a tendency for younger voters to abstain."}, {"term": "long-term trend", "ipa": "/ˌlɒŋ tɜːm trend/", "pron": "long-term trend", "fr": "tendance de long terme", "def": "A pattern developing over a long period.", "ex": "The long-term trend shows declining home ownership."}, {"term": "short-term fluctuation", "ipa": "/ˌʃɔːt tɜːm ˌflʌktʃuˈeɪʃən/", "pron": "short-term fluk-choo-AY-shuhn", "fr": "fluctuation de court terme", "def": "A temporary change over a short period.", "ex": "The fall may be only a short-term fluctuation."}, {"term": "increase", "ipa": "/ˈɪnkriːs/", "pron": "IN-kreess", "fr": "augmentation", "def": "A rise in number, amount or level.", "ex": "There was an increase in energy prices."}, {"term": "decrease", "ipa": "/ˈdiːkriːs/", "pron": "DEE-kreess", "fr": "diminution", "def": "A fall in number, amount or level.", "ex": "The data show a decrease in unemployment."}, {"term": "rise", "ipa": "/raɪz/", "pron": "ryze", "fr": "hausse", "def": "An increase.", "ex": "The rise in rents has hit young workers."}, {"term": "fall", "ipa": "/fɔːl/", "pron": "fall", "fr": "baisse", "def": "A decrease.", "ex": "The fall in turnout worries analysts."}, {"term": "growth", "ipa": "/ɡrəʊθ/", "pron": "grohth", "fr": "croissance", "def": "An increase or expansion.", "ex": "Economic growth slowed last year."}, {"term": "decline", "ipa": "/dɪˈklaɪn/", "pron": "di-KLYN", "fr": "déclin ; baisse", "def": "A gradual decrease or deterioration.", "ex": "The decline in trust is worrying."}, {"term": "drop", "ipa": "/drɒp/", "pron": "drop", "fr": "chute ; baisse", "def": "A fall, often sudden.", "ex": "There was a sharp drop in support."}, {"term": "surge", "ipa": "/sɜːdʒ/", "pron": "surj", "fr": "forte hausse ; flambée", "def": "A sudden large increase.", "ex": "A surge in applications overwhelmed the system."}, {"term": "spike", "ipa": "/spaɪk/", "pron": "spyke", "fr": "pic ; flambée", "def": "A sudden sharp increase, often temporary.", "ex": "There was a spike in hate crimes after the attack."}, {"term": "slump", "ipa": "/slʌmp/", "pron": "slump", "fr": "effondrement ; chute", "def": "A sudden or severe fall.", "ex": "The housing market experienced a slump."}, {"term": "plateau", "ipa": "/ˈplætəʊ/", "pron": "PLAT-oh", "fr": "plateau ; stabilisation", "def": "A period when a figure stops rising or falling significantly.", "ex": "Inflation reached a plateau."}, {"term": "stagnation", "ipa": "/stæɡˈneɪʃən/", "pron": "stag-NAY-shuhn", "fr": "stagnation", "def": "A lack of growth or progress.", "ex": "Wage stagnation fuels frustration."}, {"term": "stability", "ipa": "/stəˈbɪləti/", "pron": "stuh-BIL-uh-tee", "fr": "stabilité", "def": "The state of staying relatively unchanged.", "ex": "Price stability is a central goal of monetary policy."}, {"term": "volatility", "ipa": "/ˌvɒləˈtɪləti/", "pron": "vol-uh-TIL-uh-tee", "fr": "volatilité", "def": "Frequent or sharp changes.", "ex": "Market volatility increased after the announcement."}, {"term": "steady", "ipa": "/ˈstedi/", "pron": "STED-ee", "fr": "régulier", "def": "Regular and gradual, not sudden.", "ex": "There has been a steady rise in rents."}, {"term": "gradual", "ipa": "/ˈɡrædʒuəl/", "pron": "GRAJ-oo-uhl", "fr": "progressif", "def": "Happening slowly over time.", "ex": "The decline was gradual rather than sudden."}, {"term": "sharp", "ipa": "/ʃɑːp/", "pron": "sharp", "fr": "brutal ; net", "def": "Sudden and large.", "ex": "There was a sharp increase in inflation."}, {"term": "dramatic", "ipa": "/drəˈmætɪk/", "pron": "druh-MAT-ik", "fr": "spectaculaire ; considérable", "def": "Very large or striking.", "ex": "The chart shows a dramatic fall in support."}, {"term": "significant", "ipa": "/sɪɡˈnɪfɪkənt/", "pron": "sig-NIF-i-kuhnt", "fr": "significatif", "def": "Large or important enough to matter.", "ex": "The difference is statistically significant."}, {"term": "marginal", "ipa": "/ˈmɑːdʒɪnəl/", "pron": "MAR-ji-nuhl", "fr": "marginal", "def": "Very small or limited.", "ex": "The increase was only marginal."}, {"term": "slight", "ipa": "/slaɪt/", "pron": "slyt", "fr": "léger", "def": "Small in degree.", "ex": "There was a slight improvement."}, {"term": "modest", "ipa": "/ˈmɒdɪst/", "pron": "MOD-ist", "fr": "modeste", "def": "Limited but real.", "ex": "The reform produced modest gains."}, {"term": "substantial", "ipa": "/səbˈstænʃəl/", "pron": "suhb-STAN-shuhl", "fr": "important ; considérable", "def": "Large or important.", "ex": "There was a substantial rise in poverty."}, {"term": "considerable", "ipa": "/kənˈsɪdərəbəl/", "pron": "kuhn-SID-uh-ruh-buhl", "fr": "considérable", "def": "Large in amount or importance.", "ex": "The gap remains considerable."}, {"term": "proportion", "ipa": "/prəˈpɔːʃən/", "pron": "pruh-POR-shuhn", "fr": "proportion", "def": "A part or share of a whole.", "ex": "A large proportion of respondents support reform."}, {"term": "percentage", "ipa": "/pəˈsentɪdʒ/", "pron": "puh-SEN-tij", "fr": "pourcentage", "def": "A proportion out of one hundred.", "ex": "The percentage of homeowners has fallen."}]}, {"title": "C. Proportions, averages and gaps", "entries": [{"term": "percentage point", "ipa": "/pəˈsentɪdʒ pɔɪnt/", "pron": "puh-SEN-tij point", "fr": "point de pourcentage", "def": "The difference between two percentages.", "ex": "Support rose by three percentage points."}, {"term": "rate", "ipa": "/reɪt/", "pron": "rayt", "fr": "taux", "def": "A measure showing how often something happens or how much changes.", "ex": "The unemployment rate fell slightly."}, {"term": "ratio", "ipa": "/ˈreɪʃiəʊ/", "pron": "RAY-shee-oh", "fr": "rapport ; ratio", "def": "A relationship between two numbers.", "ex": "The dependency ratio is rising."}, {"term": "share", "ipa": "/ʃeə/", "pron": "shair", "fr": "part", "def": "A part of a whole amount.", "ex": "The richest households own a large share of wealth."}, {"term": "majority", "ipa": "/məˈdʒɒrəti/", "pron": "muh-JOR-uh-tee", "fr": "majorité", "def": "More than half of a group.", "ex": "A majority of voters support the measure."}, {"term": "minority", "ipa": "/maɪˈnɒrəti/", "pron": "my-NOR-uh-tee", "fr": "minorité", "def": "Less than half of a group.", "ex": "A minority of respondents opposed the reform."}, {"term": "one in three", "ipa": "/wʌn ɪn θriː/", "pron": "wun in three", "fr": "un sur trois", "def": "One out of every three people or cases.", "ex": "One in three students reported financial stress."}, {"term": "two-thirds", "ipa": "/ˌtuː ˈθɜːdz/", "pron": "too thurdz", "fr": "deux tiers", "def": "Two parts out of three.", "ex": "Two-thirds of respondents supported the ban."}, {"term": "half", "ipa": "/hɑːf/", "pron": "hahf", "fr": "la moitié", "def": "One part out of two.", "ex": "Half of young adults struggle with rent."}, {"term": "a quarter", "ipa": "/ə ˈkwɔːtə/", "pron": "uh KWOR-tuh", "fr": "un quart", "def": "One part out of four.", "ex": "A quarter of households reported energy poverty."}, {"term": "average", "ipa": "/ˈævərɪdʒ/", "pron": "AV-uh-rij", "fr": "moyenne", "def": "A typical value, often the mean.", "ex": "The average income rose, but inequality widened."}, {"term": "mean", "ipa": "/miːn/", "pron": "meen", "fr": "moyenne arithmétique", "def": "The total divided by the number of values.", "ex": "The mean can be distorted by extreme values."}, {"term": "median", "ipa": "/ˈmiːdiən/", "pron": "MEE-dee-uhn", "fr": "médiane", "def": "The middle value when numbers are ordered.", "ex": "Median income is often more informative than mean income."}, {"term": "mode", "ipa": "/məʊd/", "pron": "mohd", "fr": "mode", "def": "The most frequent value in a dataset.", "ex": "The mode is useful for categorical data."}, {"term": "distribution", "ipa": "/ˌdɪstrɪˈbjuːʃən/", "pron": "dis-tri-BYOO-shuhn", "fr": "distribution ; répartition", "def": "The way values are spread across a population.", "ex": "The distribution of wealth is highly unequal."}, {"term": "outlier", "ipa": "/ˈaʊtlaɪə/", "pron": "OWT-ly-uh", "fr": "valeur aberrante", "def": "A value very different from the others.", "ex": "Outliers can distort averages."}, {"term": "range", "ipa": "/reɪndʒ/", "pron": "raynj", "fr": "étendue ; fourchette", "def": "The distance between the highest and lowest values.", "ex": "The range of incomes is very wide."}, {"term": "gap", "ipa": "/ɡæp/", "pron": "gap", "fr": "écart ; fossé", "def": "A difference between groups, levels or outcomes.", "ex": "The gender pay gap remains significant."}, {"term": "gender pay gap", "ipa": "/ˌdʒendə ˈpeɪ ɡæp/", "pron": "JEN-duh pay gap", "fr": "écart salarial entre les sexes", "def": "The difference in average pay between men and women.", "ex": "The gender pay gap narrowed slowly."}, {"term": "wealth gap", "ipa": "/welθ ɡæp/", "pron": "welth gap", "fr": "écart de patrimoine", "def": "The difference in wealth between groups.", "ex": "The wealth gap is wider than the income gap."}, {"term": "income gap", "ipa": "/ˈɪnkʌm ɡæp/", "pron": "IN-kuhm gap", "fr": "écart de revenus", "def": "The difference in income between groups.", "ex": "The income gap widened after the crisis."}, {"term": "disparity", "ipa": "/dɪˈspærəti/", "pron": "di-SPARR-uh-tee", "fr": "disparité", "def": "A significant difference, often unfair.", "ex": "Regional disparities remain large."}, {"term": "inequality", "ipa": "/ˌɪnɪˈkwɒləti/", "pron": "in-i-KWOL-uh-tee", "fr": "inégalité", "def": "Unequal distribution of resources, rights or opportunities.", "ex": "The statistics reveal rising inequality."}, {"term": "correlation", "ipa": "/ˌkɒrəˈleɪʃən/", "pron": "kor-uh-LAY-shuhn", "fr": "corrélation", "def": "A relationship between two variables.", "ex": "There is a correlation between income and life expectancy."}, {"term": "causation", "ipa": "/kɔːˈzeɪʃən/", "pron": "kaw-ZAY-shuhn", "fr": "causalité", "def": "A relationship where one thing causes another.", "ex": "Correlation does not prove causation."}, {"term": "causal link", "ipa": "/ˌkɔːzəl ˈlɪŋk/", "pron": "KAW-zuhl link", "fr": "lien causal", "def": "A connection where one factor causes another.", "ex": "The study does not establish a causal link."}, {"term": "variable", "ipa": "/ˈveəriəbəl/", "pron": "VAIR-ee-uh-buhl", "fr": "variable", "def": "A factor that can change and be measured.", "ex": "Age is an important variable in voting behaviour."}, {"term": "factor", "ipa": "/ˈfæktə/", "pron": "FAK-tuh", "fr": "facteur", "def": "An element that contributes to a result.", "ex": "Education is a key factor in social mobility."}, {"term": "driver", "ipa": "/ˈdraɪvə/", "pron": "DRY-vuh", "fr": "moteur ; facteur déterminant", "def": "A factor causing or pushing a trend.", "ex": "Housing costs are a major driver of poverty."}, {"term": "to rise", "ipa": "/raɪz/", "pron": "ryze", "fr": "augmenter ; monter", "def": "To increase.", "ex": "Inflation rose sharply."}, {"term": "to fall", "ipa": "/fɔːl/", "pron": "fall", "fr": "baisser ; chuter", "def": "To decrease.", "ex": "Turnout fell among young voters."}, {"term": "to increase", "ipa": "/ɪnˈkriːs/", "pron": "in-KREESS", "fr": "augmenter", "def": "To become larger or greater.", "ex": "Prices increased by 8%."}]}, {"title": "D. Correlation, causation and movement verbs", "entries": [{"term": "to decrease", "ipa": "/dɪˈkriːs/", "pron": "di-KREESS", "fr": "diminuer", "def": "To become smaller or lower.", "ex": "Unemployment decreased slightly."}, {"term": "to grow", "ipa": "/ɡrəʊ/", "pron": "groh", "fr": "croître", "def": "To increase over time.", "ex": "The population grew steadily."}, {"term": "to decline", "ipa": "/dɪˈklaɪn/", "pron": "di-KLYN", "fr": "décliner ; baisser", "def": "To fall gradually.", "ex": "Trust in government declined."}, {"term": "to drop", "ipa": "/drɒp/", "pron": "drop", "fr": "chuter", "def": "To fall, often suddenly.", "ex": "Support dropped after the scandal."}, {"term": "to surge", "ipa": "/sɜːdʒ/", "pron": "surj", "fr": "bondir ; flamber", "def": "To rise suddenly and strongly.", "ex": "Applications surged after the announcement."}, {"term": "to spike", "ipa": "/spaɪk/", "pron": "spyke", "fr": "atteindre un pic", "def": "To rise sharply and temporarily.", "ex": "Prices spiked during the crisis."}, {"term": "to slump", "ipa": "/slʌmp/", "pron": "slump", "fr": "s’effondrer", "def": "To fall sharply.", "ex": "Sales slumped after the boycott."}, {"term": "to plateau", "ipa": "/ˈplætəʊ/", "pron": "PLAT-oh", "fr": "atteindre un plateau ; stagner", "def": "To stop rising or falling significantly.", "ex": "Inflation plateaued in the second quarter."}, {"term": "to stagnate", "ipa": "/stæɡˈneɪt/", "pron": "stag-NAYT", "fr": "stagner", "def": "To stop growing or developing.", "ex": "Wages stagnated for years."}, {"term": "to fluctuate", "ipa": "/ˈflʌktʃueɪt/", "pron": "FLUK-choo-ayt", "fr": "fluctuer", "def": "To rise and fall irregularly.", "ex": "Poll numbers fluctuated throughout the campaign."}, {"term": "to peak", "ipa": "/piːk/", "pron": "peek", "fr": "atteindre un pic", "def": "To reach the highest point.", "ex": "Inflation peaked in October."}, {"term": "to bottom out", "ipa": "/ˌbɒtəm ˈaʊt/", "pron": "BOT-uhm out", "fr": "atteindre son plus bas niveau", "def": "To reach the lowest point before improving.", "ex": "Support bottomed out after the scandal."}, {"term": "to outpace", "ipa": "/ˌaʊtˈpeɪs/", "pron": "owt-PAYSS", "fr": "dépasser ; croître plus vite que", "def": "To grow or move faster than something else.", "ex": "Rents outpaced wages."}, {"term": "to lag behind", "ipa": "/læɡ bɪˈhaɪnd/", "pron": "lag bi-HYND", "fr": "être à la traîne", "def": "To progress more slowly than others.", "ex": "Wages lagged behind inflation."}, {"term": "to account for", "ipa": "/əˈkaʊnt fɔː/", "pron": "uh-KOWNT for", "fr": "représenter ; compter pour", "def": "To represent a proportion of a total.", "ex": "Young voters account for a smaller share of turnout."}, {"term": "to make up", "ipa": "/meɪk ˈʌp/", "pron": "mayk up", "fr": "constituer ; représenter", "def": "To constitute a part of a whole.", "ex": "Women make up 52% of the population."}, {"term": "to represent", "ipa": "/ˌreprɪˈzent/", "pron": "rep-ri-ZENT", "fr": "représenter", "def": "To amount to or stand for something.", "ex": "The poorest fifth represents a small share of wealth."}, {"term": "to amount to", "ipa": "/əˈmaʊnt tə/", "pron": "uh-MOWNT tuh", "fr": "s’élever à ; représenter", "def": "To be equal to a total or quantity.", "ex": "Public debt amounts to over 100% of GDP."}, {"term": "to exceed", "ipa": "/ɪkˈsiːd/", "pron": "ik-SEED", "fr": "dépasser", "def": "To be greater than a number or limit.", "ex": "Demand exceeded supply."}, {"term": "to fall below", "ipa": "/fɔːl bɪˈləʊ/", "pron": "fall bi-LOH", "fr": "passer sous", "def": "To become lower than a level.", "ex": "Inflation fell below 3%."}, {"term": "to reach", "ipa": "/riːtʃ/", "pron": "reech", "fr": "atteindre", "def": "To arrive at a level or number.", "ex": "Unemployment reached 8%."}, {"term": "to stand at", "ipa": "/stænd æt/", "pron": "stand at", "fr": "s’établir à", "def": "To be at a particular level.", "ex": "Inflation stood at 4.2%."}, {"term": "to be estimated at", "ipa": "/bi ˈestɪmeɪtɪd æt/", "pron": "bee ES-ti-may-tid at", "fr": "être estimé à", "def": "To be approximately calculated as.", "ex": "The cost is estimated at £2 billion."}, {"term": "to project", "ipa": "/prəˈdʒekt/", "pron": "pruh-JEKT", "fr": "prévoir ; projeter", "def": "To estimate a future value.", "ex": "The population is projected to age rapidly."}, {"term": "to forecast", "ipa": "/ˈfɔːkɑːst/", "pron": "FOR-kast", "fr": "prévoir", "def": "To predict a future trend or value.", "ex": "Economists forecast slower growth."}, {"term": "to interpret data", "ipa": "/ɪnˈtɜːprɪt ˈdeɪtə/", "pron": "in-TUR-prit DAY-tuh", "fr": "interpréter des données", "def": "To explain what data mean.", "ex": "Students must interpret data carefully."}, {"term": "to analyse figures", "ipa": "/ˈænəlaɪz ˈfɪɡəz/", "pron": "AN-uh-lyze FIG-uhz", "fr": "analyser des chiffres", "def": "To study statistics in detail.", "ex": "The essay analyses figures on social mobility."}, {"term": "to compare figures", "ipa": "/kəmˈpeə ˈfɪɡəz/", "pron": "kuhm-PAIR FIG-uhz", "fr": "comparer des chiffres", "def": "To examine numerical differences or similarities.", "ex": "We should compare figures across regions."}, {"term": "to put figures into perspective", "ipa": "/pʊt ˈfɪɡəz ˈɪntə pəˈspektɪv/", "pron": "put FIG-uhz IN-tuh puh-SPEK-tiv", "fr": "mettre les chiffres en perspective", "def": "To place data in a wider context.", "ex": "Historical data put the figures into perspective."}, {"term": "to draw conclusions from data", "ipa": "/drɔː kənˈkluːʒənz frəm ˈdeɪtə/", "pron": "draw kuhn-KLOO-zhuhnz from DAY-tuh", "fr": "tirer des conclusions des données", "def": "To form judgements based on data.", "ex": "We should not draw conclusions from one poll."}, {"term": "to support an argument", "ipa": "/səˈpɔːt ən ˈɑːɡjʊmənt/", "pron": "suh-PORT uhn AR-gyoo-muhnt", "fr": "étayer un argument", "def": "To provide evidence for a claim.", "ex": "The figures support the argument that poverty has risen."}, {"term": "to challenge an assumption", "ipa": "/ˈtʃælɪndʒ ən əˈsʌmpʃən/", "pron": "CHAL-inj uhn uh-SUMP-shuhn", "fr": "remettre en cause une hypothèse", "def": "To question a belief taken for granted.", "ex": "The data challenge the assumption that growth helps everyone."}, {"term": "to reveal a trend", "ipa": "/rɪˈviːl ə trend/", "pron": "ri-VEEL uh trend", "fr": "révéler une tendance", "def": "To show a pattern over time.", "ex": "The chart reveals a trend towards abstention."}, {"term": "to show a correlation", "ipa": "/ʃəʊ ə ˌkɒrəˈleɪʃən/", "pron": "show uh kor-uh-LAY-shuhn", "fr": "montrer une corrélation", "def": "To indicate a relationship between variables.", "ex": "The data show a correlation, not necessarily causation."}]}, {"title": "E. High-value verbs for analysing figures", "entries": [{"term": "to establish causation", "ipa": "/ɪˈstæblɪʃ kɔːˈzeɪʃən/", "pron": "i-STAB-lish kaw-ZAY-shuhn", "fr": "établir une causalité", "def": "To prove that one thing causes another.", "ex": "The study fails to establish causation."}, {"term": "to misrepresent data", "ipa": "/ˌmɪsreprɪˈzent ˈdeɪtə/", "pron": "mis-rep-ri-ZENT DAY-tuh", "fr": "déformer les données", "def": "To present data inaccurately or misleadingly.", "ex": "The graph misrepresents data by changing the scale."}, {"term": "to cherry-pick figures", "ipa": "/ˈtʃeri pɪk ˈfɪɡəz/", "pron": "CHERR-ee-pik FIG-uhz", "fr": "sélectionner les chiffres de façon biaisée", "def": "To select only figures that support one’s argument.", "ex": "Politicians often cherry-pick figures."}, {"term": "to distort the picture", "ipa": "/dɪˈstɔːt ðə ˈpɪktʃə/", "pron": "di-STORT thuh PIK-chuh", "fr": "déformer la réalité", "def": "To give a misleading impression.", "ex": "Averages can distort the picture."}, {"term": "to be statistically significant", "ipa": "/bi stəˌtɪstɪkəli sɪɡˈnɪfɪkənt/", "pron": "bee stuh-TIS-ti-kuh-lee sig-NIF-i-kuhnt", "fr": "être statistiquement significatif", "def": "To be unlikely to be due to chance.", "ex": "The difference is statistically significant."}, {"term": "to be within the margin of error", "ipa": "/bi wɪˈðɪn ðə ˈmɑːdʒɪn əv ˈerə/", "pron": "bee with-IN thuh MAR-jin ov ERR-uh", "fr": "être dans la marge d’erreur", "def": "To be too close to treat as clearly different.", "ex": "The candidates are within the margin of error."}, {"term": "correlation does not imply causation", "ipa": "/ˌkɒrəˈleɪʃən dʌz nɒt ɪmˈplaɪ kɔːˈzeɪʃən/", "pron": "kor-uh-LAY-shuhn duz not im-PLY kaw-ZAY-shuhn", "fr": "corrélation n’implique pas causalité", "def": "A relationship between two variables does not prove one causes the other.", "ex": "Correlation does not imply causation, so the claim must be qualified."}]}]}, {"id": "p10c86", "part": 10, "chapter": 86, "title": "Describing Graphs And Charts", "file": "cpge_vocab_part10_chapter86_describing_graphs_and_charts_premium.html", "count": 112, "sections": [{"title": "A. Types of graphs and visual elements", "entries": [{"term": "graph", "ipa": "/ɡrɑːf/", "pron": "grahf", "fr": "graphique", "def": "A visual representation of data showing relationships or changes.", "ex": "The graph shows a steady rise in energy prices."}, {"term": "chart", "ipa": "/tʃɑːt/", "pron": "chart", "fr": "graphique ; diagramme", "def": "A visual display of data using bars, lines or sectors.", "ex": "The chart compares income levels across regions."}, {"term": "bar chart", "ipa": "/ˈbɑː tʃɑːt/", "pron": "bar chart", "fr": "diagramme en barres", "def": "A chart using bars to compare quantities.", "ex": "The bar chart compares voting intentions by age."}, {"term": "line graph", "ipa": "/ˈlaɪn ɡrɑːf/", "pron": "line graf", "fr": "graphique en courbe", "def": "A graph using a line to show change over time.", "ex": "The line graph shows inflation between 2010 and 2025."}, {"term": "pie chart", "ipa": "/ˈpaɪ tʃɑːt/", "pron": "pie chart", "fr": "camembert ; diagramme circulaire", "def": "A circular chart divided into sectors showing proportions.", "ex": "The pie chart shows the share of household spending."}, {"term": "scatter plot", "ipa": "/ˈskætə plɒt/", "pron": "SKAT-uh plot", "fr": "nuage de points", "def": "A graph using dots to show the relationship between two variables.", "ex": "The scatter plot suggests a correlation between income and life expectancy."}, {"term": "axis", "ipa": "/ˈæksɪs/", "pron": "AK-sis", "fr": "axe", "def": "A reference line on a graph.", "ex": "The vertical axis shows the unemployment rate."}, {"term": "x-axis", "ipa": "/ˈeks ˌæksɪs/", "pron": "EX AK-sis", "fr": "axe des abscisses", "def": "The horizontal axis of a graph.", "ex": "The x-axis represents time."}, {"term": "y-axis", "ipa": "/ˈwaɪ ˌæksɪs/", "pron": "WHY AK-sis", "fr": "axe des ordonnées", "def": "The vertical axis of a graph.", "ex": "The y-axis shows percentage growth."}, {"term": "scale", "ipa": "/skeɪl/", "pron": "skayl", "fr": "échelle", "def": "The range and intervals used to measure values on a graph.", "ex": "The scale makes the increase look dramatic."}, {"term": "legend", "ipa": "/ˈledʒənd/", "pron": "LEJ-uhnd", "fr": "légende", "def": "A key explaining symbols, colours or lines on a chart.", "ex": "The legend identifies each age group."}, {"term": "label", "ipa": "/ˈleɪbəl/", "pron": "LAY-buhl", "fr": "étiquette ; libellé", "def": "A word or phrase identifying part of a graph.", "ex": "The axis labels are clear."}, {"term": "source", "ipa": "/sɔːs/", "pron": "sorss", "fr": "source", "def": "Where the data come from.", "ex": "The source of the data is a government survey."}, {"term": "unit", "ipa": "/ˈjuːnɪt/", "pron": "YOO-nit", "fr": "unité", "def": "The measurement used, such as pounds, euros or percentages.", "ex": "The unit is percentage of total income."}, {"term": "time period", "ipa": "/ˈtaɪm ˌpɪəriəd/", "pron": "time PEER-ee-uhd", "fr": "période", "def": "The dates or years covered by the data.", "ex": "The time period runs from 1990 to 2024."}, {"term": "data point", "ipa": "/ˈdeɪtə pɔɪnt/", "pron": "DAY-tuh point", "fr": "point de données", "def": "One individual value shown on a graph.", "ex": "Each data point represents one country."}, {"term": "trend line", "ipa": "/ˈtrend laɪn/", "pron": "trend lyne", "fr": "courbe de tendance", "def": "A line showing the general direction of data.", "ex": "The trend line points upwards."}, {"term": "baseline", "ipa": "/ˈbeɪslaɪn/", "pron": "BAYSS-lyne", "fr": "niveau de référence", "def": "A starting point used for comparison.", "ex": "The baseline is the pre-pandemic level."}]}, {"title": "B. Trends, changes and movement verbs", "entries": [{"term": "trend", "ipa": "/trend/", "pron": "trend", "fr": "tendance", "def": "A general direction of change over time.", "ex": "The trend points to rising political polarisation."}, {"term": "upward trend", "ipa": "/ˌʌpwəd ˈtrend/", "pron": "UP-wuhd trend", "fr": "tendance à la hausse", "def": "A general increase over time.", "ex": "The graph shows an upward trend in rents."}, {"term": "downward trend", "ipa": "/ˌdaʊnwəd ˈtrend/", "pron": "DOWN-wuhd trend", "fr": "tendance à la baisse", "def": "A general decrease over time.", "ex": "There is a downward trend in newspaper readership."}, {"term": "stable trend", "ipa": "/ˌsteɪbəl ˈtrend/", "pron": "STAY-buhl trend", "fr": "tendance stable", "def": "A pattern with little change over time.", "ex": "The unemployment rate remained broadly stable."}, {"term": "fluctuation", "ipa": "/ˌflʌktʃuˈeɪʃən/", "pron": "fluk-choo-AY-shuhn", "fr": "fluctuation", "def": "An irregular rise and fall.", "ex": "The graph shows repeated fluctuations."}, {"term": "variation", "ipa": "/ˌveəriˈeɪʃən/", "pron": "vair-ee-AY-shuhn", "fr": "variation", "def": "A difference or change in amount.", "ex": "There is wide regional variation."}, {"term": "peak", "ipa": "/piːk/", "pron": "peek", "fr": "pic ; sommet", "def": "The highest point reached by a figure.", "ex": "Inflation reached a peak in 2022."}, {"term": "trough", "ipa": "/trɒf/", "pron": "trof", "fr": "creux ; point bas", "def": "The lowest point reached by a figure.", "ex": "Support hit a trough after the scandal."}, {"term": "turning point", "ipa": "/ˈtɜːnɪŋ pɔɪnt/", "pron": "TUR-ning point", "fr": "point de bascule", "def": "A moment when a trend changes direction.", "ex": "The financial crisis was a turning point."}, {"term": "rise", "ipa": "/raɪz/", "pron": "ryze", "fr": "hausse", "def": "An increase.", "ex": "The rise in prices is visible on the chart."}, {"term": "fall", "ipa": "/fɔːl/", "pron": "fall", "fr": "baisse", "def": "A decrease.", "ex": "The fall in turnout is worrying."}, {"term": "drop", "ipa": "/drɒp/", "pron": "drop", "fr": "chute ; baisse", "def": "A fall, often sudden.", "ex": "The graph shows a sudden drop in support."}, {"term": "surge", "ipa": "/sɜːdʒ/", "pron": "surj", "fr": "forte hausse ; flambée", "def": "A sudden strong increase.", "ex": "There was a surge in online sales."}, {"term": "spike", "ipa": "/spaɪk/", "pron": "spyke", "fr": "pic ; flambée", "def": "A sharp, often temporary increase.", "ex": "The chart shows a spike in energy costs."}, {"term": "decline", "ipa": "/dɪˈklaɪn/", "pron": "di-KLYN", "fr": "déclin ; baisse", "def": "A gradual fall or deterioration.", "ex": "The decline begins after 2016."}, {"term": "slump", "ipa": "/slʌmp/", "pron": "slump", "fr": "effondrement", "def": "A sudden or severe fall.", "ex": "The graph shows a slump in tourism."}, {"term": "rebound", "ipa": "/rɪˈbaʊnd/", "pron": "ri-BOUND", "fr": "rebond", "def": "A recovery after a fall.", "ex": "There was a rebound after lockdown."}, {"term": "plateau", "ipa": "/ˈplætəʊ/", "pron": "PLAT-oh", "fr": "plateau ; stabilisation", "def": "A period when a figure stops rising or falling.", "ex": "The curve reaches a plateau."}, {"term": "stagnation", "ipa": "/stæɡˈneɪʃən/", "pron": "stag-NAY-shuhn", "fr": "stagnation", "def": "A lack of growth or movement.", "ex": "The chart points to wage stagnation."}, {"term": "acceleration", "ipa": "/əkˌseləˈreɪʃən/", "pron": "ak-sel-uh-RAY-shuhn", "fr": "accélération", "def": "A faster rate of increase or change.", "ex": "There is a clear acceleration after 2019."}, {"term": "slowdown", "ipa": "/ˈsləʊdaʊn/", "pron": "SLOH-down", "fr": "ralentissement", "def": "A reduction in speed or growth.", "ex": "The data show an economic slowdown."}, {"term": "to rise", "ipa": "/raɪz/", "pron": "ryze", "fr": "augmenter ; monter", "def": "To increase.", "ex": "Prices rose sharply in 2022."}, {"term": "to fall", "ipa": "/fɔːl/", "pron": "fall", "fr": "baisser ; chuter", "def": "To decrease.", "ex": "Turnout fell among younger voters."}, {"term": "to climb", "ipa": "/klaɪm/", "pron": "klym", "fr": "grimper ; augmenter", "def": "To rise gradually or steadily.", "ex": "Rents climbed throughout the decade."}, {"term": "to soar", "ipa": "/sɔː/", "pron": "sor", "fr": "s’envoler ; grimper en flèche", "def": "To rise very quickly and strongly.", "ex": "Energy prices soared."}, {"term": "to plunge", "ipa": "/plʌndʒ/", "pron": "plunj", "fr": "s’effondrer ; chuter brutalement", "def": "To fall suddenly and sharply.", "ex": "Approval ratings plunged after the scandal."}, {"term": "to level off", "ipa": "/ˈlevəl ɒf/", "pron": "LEV-uhl off", "fr": "se stabiliser", "def": "To stop rising or falling and become stable.", "ex": "Prices levelled off after 2023."}, {"term": "to fluctuate", "ipa": "/ˈflʌktʃueɪt/", "pron": "FLUK-choo-ayt", "fr": "fluctuer", "def": "To rise and fall irregularly.", "ex": "Poll numbers fluctuated throughout the campaign."}, {"term": "to peak", "ipa": "/piːk/", "pron": "peek", "fr": "atteindre un pic", "def": "To reach the highest point.", "ex": "Inflation peaked in late 2022."}, {"term": "to recover", "ipa": "/rɪˈkʌvə/", "pron": "ri-KUV-uh", "fr": "se redresser ; se rétablir", "def": "To improve after a fall.", "ex": "The economy recovered slowly."}]}, {"title": "C. Describing intensity and time periods", "entries": [{"term": "sharp rise", "ipa": "/ʃɑːp raɪz/", "pron": "sharp ryze", "fr": "forte hausse", "def": "A sudden large increase.", "ex": "The chart shows a sharp rise in food prices."}, {"term": "steep increase", "ipa": "/stiːp ˈɪnkriːs/", "pron": "steep IN-kreess", "fr": "hausse marquée", "def": "A very strong increase.", "ex": "There was a steep increase in rents."}, {"term": "dramatic fall", "ipa": "/drəˌmætɪk ˈfɔːl/", "pron": "druh-MAT-ik fall", "fr": "chute spectaculaire", "def": "A very large and striking fall.", "ex": "The graph shows a dramatic fall in trust."}, {"term": "slight decline", "ipa": "/slaɪt dɪˈklaɪn/", "pron": "slyt di-KLYN", "fr": "légère baisse", "def": "A small fall.", "ex": "There was a slight decline in support."}, {"term": "steady growth", "ipa": "/ˌstedi ˈɡrəʊθ/", "pron": "STED-ee grohth", "fr": "croissance régulière", "def": "Regular and gradual growth.", "ex": "The data show steady growth."}, {"term": "gradual decrease", "ipa": "/ˌɡrædʒuəl ˈdiːkriːs/", "pron": "GRAJ-oo-uhl DEE-kreess", "fr": "diminution progressive", "def": "A slow fall over time.", "ex": "There was a gradual decrease in newspaper readership."}, {"term": "modest increase", "ipa": "/ˌmɒdɪst ˈɪnkriːs/", "pron": "MOD-ist IN-kreess", "fr": "augmentation modeste", "def": "A limited but real increase.", "ex": "The reform led to a modest increase."}, {"term": "significant drop", "ipa": "/sɪɡˌnɪfɪkənt ˈdrɒp/", "pron": "sig-NIF-i-kuhnt drop", "fr": "baisse significative", "def": "A meaningful fall.", "ex": "There was a significant drop in youth turnout."}, {"term": "roughly stable", "ipa": "/ˌrʌfli ˈsteɪbəl/", "pron": "RUF-lee STAY-buhl", "fr": "globalement stable", "def": "Approximately unchanged.", "ex": "The rate remained roughly stable."}, {"term": "broadly unchanged", "ipa": "/ˌbrɔːdli ʌnˈtʃeɪndʒd/", "pron": "BROD-lee un-CHAYNJD", "fr": "globalement inchangé", "def": "Generally the same.", "ex": "The figures were broadly unchanged."}, {"term": "almost doubled", "ipa": "/ˈɔːlməʊst ˈdʌbəld/", "pron": "AWL-mohst DUB-uhld", "fr": "a presque doublé", "def": "Nearly became twice as high.", "ex": "The number almost doubled in ten years."}, {"term": "more than doubled", "ipa": "/mɔː ðən ˈdʌbəld/", "pron": "more than DUB-uhld", "fr": "a plus que doublé", "def": "Became more than twice as high.", "ex": "Online subscriptions more than doubled."}, {"term": "halved", "ipa": "/hɑːvd/", "pron": "hahvd", "fr": "a diminué de moitié", "def": "Reduced by half.", "ex": "The rate halved over the period."}, {"term": "tripled", "ipa": "/ˈtrɪpəld/", "pron": "TRIP-uhld", "fr": "a triplé", "def": "Became three times as high.", "ex": "The cost tripled in two decades."}, {"term": "from... to...", "ipa": "/frəm tə/", "pron": "from tuh", "fr": "de... à...", "def": "Used to describe a change between two values.", "ex": "Unemployment rose from 5% to 8%."}, {"term": "by", "ipa": "/baɪ/", "pron": "by", "fr": "de ; à hauteur de", "def": "Used to describe the amount of change.", "ex": "Prices increased by 10%."}, {"term": "to", "ipa": "/tuː/", "pron": "too", "fr": "à ; jusqu’à", "def": "Used to indicate the final value reached.", "ex": "Inflation rose to 7%."}, {"term": "at", "ipa": "/æt/", "pron": "at", "fr": "à", "def": "Used to indicate a specific level.", "ex": "Unemployment stood at 6%."}, {"term": "over the period", "ipa": "/ˈəʊvə ðə ˈpɪəriəd/", "pron": "OH-vuh thuh PEER-ee-uhd", "fr": "sur la période", "def": "During the whole time shown.", "ex": "Over the period, prices rose steadily."}, {"term": "throughout the period", "ipa": "/θruːˈaʊt ðə ˈpɪəriəd/", "pron": "throo-OUT thuh PEER-ee-uhd", "fr": "tout au long de la période", "def": "From beginning to end of the period.", "ex": "Throughout the period, support remained low."}, {"term": "at the beginning", "ipa": "/æt ðə bɪˈɡɪnɪŋ/", "pron": "at thuh bi-GIN-ing", "fr": "au début", "def": "At the start of the time period.", "ex": "At the beginning, the rate was below 3%."}, {"term": "at the end", "ipa": "/æt ði end/", "pron": "at thee end", "fr": "à la fin", "def": "At the close of the time period.", "ex": "At the end, the figure reached 12%."}, {"term": "in the early years", "ipa": "/ɪn ði ˈɜːli jɪəz/", "pron": "in thee UR-lee yeerz", "fr": "dans les premières années", "def": "At the beginning of the period shown.", "ex": "In the early years, the figure remained stable."}, {"term": "in the later years", "ipa": "/ɪn ðə ˈleɪtə jɪəz/", "pron": "in thuh LAY-tuh yeerz", "fr": "dans les dernières années", "def": "Towards the end of the period shown.", "ex": "In the later years, growth accelerated."}]}, {"title": "D. Comparing groups and proportions", "entries": [{"term": "compared with", "ipa": "/kəmˈpeəd wɪð/", "pron": "kuhm-PAIRD with", "fr": "comparé à", "def": "Used to compare one value with another.", "ex": "Compared with 2010, the rate is much higher."}, {"term": "compared to", "ipa": "/kəmˈpeəd tə/", "pron": "kuhm-PAIRD tuh", "fr": "comparé à", "def": "Used to compare one value with another.", "ex": "Compared to older voters, young voters abstained more."}, {"term": "relative to", "ipa": "/ˈrelətɪv tə/", "pron": "REL-uh-tiv tuh", "fr": "par rapport à", "def": "In relation to another value or standard.", "ex": "Wages fell relative to housing costs."}, {"term": "whereas", "ipa": "/ˌweərˈæz/", "pron": "wair-AZ", "fr": "alors que ; tandis que", "def": "Used to contrast two values or groups.", "ex": "Urban support rose, whereas rural support fell."}, {"term": "while", "ipa": "/waɪl/", "pron": "wyle", "fr": "tandis que ; alors que", "def": "Used to compare or contrast.", "ex": "While rents increased, wages stagnated."}, {"term": "in contrast", "ipa": "/ɪn ˈkɒntrɑːst/", "pron": "in KON-trast", "fr": "en revanche ; par contraste", "def": "Used to introduce a contrasting value or trend.", "ex": "In contrast, the rate fell among older workers."}, {"term": "by contrast", "ipa": "/baɪ ˈkɒntrɑːst/", "pron": "by KON-trast", "fr": "par contraste", "def": "Used to emphasise difference.", "ex": "By contrast, rural areas saw little change."}, {"term": "respectively", "ipa": "/rɪˈspektɪvli/", "pron": "ri-SPEK-tiv-lee", "fr": "respectivement", "def": "In the same order as the items already mentioned.", "ex": "Men and women earned £30,000 and £25,000, respectively."}, {"term": "gap", "ipa": "/ɡæp/", "pron": "gap", "fr": "écart ; fossé", "def": "A difference between groups, levels or outcomes.", "ex": "The gap widened over the period."}, {"term": "narrowing gap", "ipa": "/ˈnærəʊɪŋ ɡæp/", "pron": "NAR-oh-ing gap", "fr": "écart qui se réduit", "def": "A difference that is getting smaller.", "ex": "The chart shows a narrowing gap between regions."}, {"term": "widening gap", "ipa": "/ˈwaɪdənɪŋ ɡæp/", "pron": "WY-duh-ning gap", "fr": "écart qui se creuse", "def": "A difference that is getting larger.", "ex": "There is a widening gap between rich and poor."}, {"term": "to widen", "ipa": "/ˈwaɪdən/", "pron": "WY-duhn", "fr": "s’élargir ; creuser", "def": "To become larger or make a gap larger.", "ex": "The wealth gap widened."}, {"term": "to narrow", "ipa": "/ˈnærəʊ/", "pron": "NAR-oh", "fr": "se réduire ; réduire", "def": "To become smaller or make a gap smaller.", "ex": "The gender gap narrowed."}, {"term": "to overtake", "ipa": "/ˌəʊvəˈteɪk/", "pron": "OH-vuh-tayk", "fr": "dépasser", "def": "To become higher than another figure.", "ex": "Online news overtook print newspapers."}, {"term": "to remain above", "ipa": "/rɪˈmeɪn əˈbʌv/", "pron": "ri-MAYN uh-BUV", "fr": "rester au-dessus de", "def": "To stay higher than a level.", "ex": "Inflation remained above 5%."}, {"term": "to remain below", "ipa": "/rɪˈmeɪn bɪˈləʊ/", "pron": "ri-MAYN bi-LOH", "fr": "rester en dessous de", "def": "To stay lower than a level.", "ex": "Unemployment remained below the EU average."}, {"term": "to account for", "ipa": "/əˈkaʊnt fɔː/", "pron": "uh-KOWNT for", "fr": "représenter", "def": "To represent a proportion of a total.", "ex": "Transport accounts for a large share of emissions."}, {"term": "to make up", "ipa": "/meɪk ˈʌp/", "pron": "mayk up", "fr": "constituer ; représenter", "def": "To constitute part of a whole.", "ex": "Rent makes up a third of household spending."}, {"term": "largest share", "ipa": "/ˈlɑːdʒɪst ʃeə/", "pron": "LAR-jist shair", "fr": "part la plus importante", "def": "The biggest proportion.", "ex": "Housing takes the largest share of spending."}, {"term": "smallest share", "ipa": "/ˈsmɔːlɪst ʃeə/", "pron": "SMALL-ist shair", "fr": "part la plus faible", "def": "The smallest proportion.", "ex": "Culture accounts for the smallest share."}, {"term": "roughly half", "ipa": "/ˌrʌfli hɑːf/", "pron": "RUF-lee hahf", "fr": "environ la moitié", "def": "Approximately 50%.", "ex": "Roughly half of respondents were undecided."}, {"term": "nearly two-thirds", "ipa": "/ˈnɪəli ˌtuː ˈθɜːdz/", "pron": "NEER-lee too thurdz", "fr": "près des deux tiers", "def": "Almost two out of three.", "ex": "Nearly two-thirds supported regulation."}, {"term": "just over", "ipa": "/dʒʌst ˈəʊvə/", "pron": "just OH-vuh", "fr": "un peu plus de", "def": "Slightly more than.", "ex": "Just over 40% agreed."}, {"term": "just under", "ipa": "/dʒʌst ˈʌndə/", "pron": "just UN-duh", "fr": "un peu moins de", "def": "Slightly less than.", "ex": "Just under 30% disagreed."}]}, {"title": "E. Exam-ready graph commentary phrases", "entries": [{"term": "the graph shows", "ipa": "/ðə ɡrɑːf ʃəʊz/", "pron": "thuh graf showz", "fr": "le graphique montre", "def": "Used to introduce the main information in a graph.", "ex": "The graph shows a steady rise in prices."}, {"term": "the chart illustrates", "ipa": "/ðə tʃɑːt ˈɪləstreɪts/", "pron": "thuh chart IL-uh-strayts", "fr": "le graphique illustre", "def": "Used to describe what a chart visually explains.", "ex": "The chart illustrates regional disparities."}, {"term": "the table presents", "ipa": "/ðə ˈteɪbəl prɪˈzents/", "pron": "thuh TAY-buhl pri-ZENTS", "fr": "le tableau présente", "def": "Used to introduce data in a table.", "ex": "The table presents income by age group."}, {"term": "the figures suggest", "ipa": "/ðə ˈfɪɡəz səˈdʒest/", "pron": "thuh FIG-uhz suh-JEST", "fr": "les chiffres suggèrent", "def": "Used to draw a cautious conclusion from data.", "ex": "The figures suggest growing insecurity."}, {"term": "the data indicate", "ipa": "/ðə ˈdeɪtə ˈɪndɪkeɪt/", "pron": "thuh DAY-tuh IN-di-kayt", "fr": "les données indiquent", "def": "Used to state what data point to.", "ex": "The data indicate a long-term decline."}, {"term": "the trend points to", "ipa": "/ðə trend pɔɪnts tə/", "pron": "thuh trend points tuh", "fr": "la tendance indique", "def": "Used to interpret the direction of data.", "ex": "The trend points to rising inequality."}, {"term": "the most striking feature is", "ipa": "/ðə məʊst ˈstraɪkɪŋ ˈfiːtʃə ɪz/", "pron": "thuh most STRY-king FEE-chuh iz", "fr": "l’élément le plus frappant est", "def": "Used to identify the key visual element.", "ex": "The most striking feature is the sudden fall after 2020."}, {"term": "what stands out is", "ipa": "/wɒt stændz aʊt ɪz/", "pron": "wot standz out iz", "fr": "ce qui ressort, c’est", "def": "Used to identify what is most noticeable.", "ex": "What stands out is the gap between regions."}, {"term": "overall", "ipa": "/ˌəʊvərˈɔːl/", "pron": "OH-vuh-rawl", "fr": "dans l’ensemble", "def": "Considering the graph as a whole.", "ex": "Overall, the trend is upward."}, {"term": "broadly speaking", "ipa": "/ˌbrɔːdli ˈspiːkɪŋ/", "pron": "BROD-lee SPEE-king", "fr": "globalement", "def": "Generally speaking.", "ex": "Broadly speaking, prices increased throughout the period."}, {"term": "at first glance", "ipa": "/æt ˌfɜːst ˈɡlɑːns/", "pron": "at first glahns", "fr": "à première vue", "def": "On initial viewing.", "ex": "At first glance, the chart suggests progress."}, {"term": "on closer inspection", "ipa": "/ɒn ˌkləʊsər ɪnˈspekʃən/", "pron": "on KLOH-zuh in-SPEK-shuhn", "fr": "à y regarder de plus près", "def": "After looking more carefully.", "ex": "On closer inspection, the improvement is uneven."}, {"term": "the scale may be misleading", "ipa": "/ðə skeɪl meɪ bi mɪsˈliːdɪŋ/", "pron": "thuh skayl may bee mis-LEE-ding", "fr": "l’échelle peut être trompeuse", "def": "Used when the axis exaggerates or minimises change.", "ex": "The scale may be misleading because it does not start at zero."}, {"term": "the chart does not show", "ipa": "/ðə tʃɑːt dʌz nɒt ʃəʊ/", "pron": "thuh chart duz not show", "fr": "le graphique ne montre pas", "def": "Used to point out missing information.", "ex": "The chart does not show regional differences."}, {"term": "the data should be treated with caution", "ipa": "/ðə ˈdeɪtə ʃʊd bi ˈtriːtɪd wɪð ˈkɔːʃən/", "pron": "thuh DAY-tuh should bee TREE-tid with KAW-shuhn", "fr": "les données doivent être interprétées avec prudence", "def": "Used to warn that the data may be limited.", "ex": "The data should be treated with caution because the sample is small."}, {"term": "the figures do not prove causation", "ipa": "/ðə ˈfɪɡəz duː nɒt pruːv kɔːˈzeɪʃən/", "pron": "thuh FIG-uhz do not proov kaw-ZAY-shuhn", "fr": "les chiffres ne prouvent pas une causalité", "def": "Used to avoid false causal claims.", "ex": "The figures do not prove causation."}]}]}], "parts": {"1": "Politics & Government", "2": "The United States", "3": "The United Kingdom", "4": "Society", "5": "Economics", "6": "International Relations", "7": "Science & Technology", "8": "Environment", "9": "Media & Culture", "10": "Concours Toolkit"}};
